// Deep-dive content loaded before the main Oracle app.
// ── DEEP DIVES DATA ──────────────────────────────────────────────────────
const DEEP_DIVES = {
  // === SCIENCE ===
  's1': {
    fr:["Un seul orage peut libérer autant d'énergie qu'une bombe atomique de 20 kilotonnes — répartie sur des milliers d'éclairs.","La Terre est frappée par environ 100 éclairs par seconde, soit plus de 8 millions par jour.","Le Venezuela possède un endroit unique, le lac Maracaibo, où des éclairs frappent 300 nuits par an — le record mondial."],
    en:["A single thunderstorm can release as much energy as a 20-kiloton atomic bomb — spread across thousands of strikes.","Earth is struck by about 100 lightning bolts per second, or more than 8 million per day.","Venezuela has a unique spot, Lake Maracaibo, where lightning strikes 300 nights a year — a world record."],
    es:["Una sola tormenta puede liberar tanta energía como una bomba atómica de 20 kilotones — repartida en miles de rayos.","La Tierra recibe unos 100 rayos por segundo, más de 8 millones al día.","Venezuela tiene un lugar único, el lago Maracaibo, donde caen rayos 300 noches al año — el récord mundial."]
  },
  's2': {
    fr:["Le calcium de tes os provient d'explosions de supernovae qui ont eu lieu il y a plus de 5 milliards d'années.","Le fer dans ton sang et l'or dans tes bijoux ont été créés au même endroit : dans le cœur d'étoiles mourantes.","L'hydrogène de l'eau que tu bois est le seul élément de ton corps qui ne vient pas d'une étoile — il date du Big Bang lui-même."],
    en:["The calcium in your bones comes from supernova explosions over 5 billion years ago.","The iron in your blood and the gold in your jewelry were created in the same place: inside dying stars.","The hydrogen in the water you drink is the only element in your body that didn't come from a star — it dates back to the Big Bang itself."],
    es:["El calcio de tus huesos proviene de explosiones de supernovas ocurridas hace más de 5 000 millones de años.","El hierro de tu sangre y el oro de tus joyas se crearon en el mismo lugar: en el corazón de estrellas moribundas.","El hidrógeno del agua que bebes es el único elemento de tu cuerpo que no proviene de una estrella — data del Big Bang."]
  },
  's3': {
    fr:["Cette capacité repose sur une protéine appelée cryptochrome, située dans la rétine, qui réagit au champ magnétique terrestre.","Les pigeons voyageurs possèdent aussi des cristaux de magnétite dans leur bec, agissant comme une seconde boussole biologique.","Certaines tortues marines utilisent un système similaire pour traverser des océans entiers et revenir à leur lieu de naissance."],
    en:["This ability relies on a protein called cryptochrome, located in the retina, which reacts to Earth's magnetic field.","Homing pigeons also have magnetite crystals in their beaks, acting as a second biological compass.","Some sea turtles use a similar system to cross entire oceans and return to their birthplace."],
    es:["Esta capacidad se basa en una proteína llamada criptocromo, situada en la retina, que reacciona al campo magnético terrestre.","Las palomas mensajeras también poseen cristales de magnetita en el pico, que actúan como una segunda brújula biológica.","Algunas tortugas marinas usan un sistema similar para cruzar océanos enteros y volver a su lugar de nacimiento."]
  },
  's4': {
    fr:["Un seul gramme de sol forestier contient environ 10 000 espèces de bactéries différentes, dont la majorité n'ont jamais été étudiées.","Certaines bactéries du sol produisent la géosmine, cette molécule responsable de l'odeur caractéristique de la terre après la pluie.","Les scientifiques estiment qu'on a identifié moins de 1 % des espèces microbiennes vivant dans le sol terrestre."],
    en:["A single gram of forest soil contains about 10,000 different bacterial species, most never studied.","Some soil bacteria produce geosmin, the molecule responsible for the characteristic smell of earth after rain.","Scientists estimate we've identified less than 1% of microbial species living in Earth's soil."],
    es:["Un solo gramo de suelo forestal contiene unas 10 000 especies de bacterias, la mayoría nunca estudiadas.","Algunas bacterias del suelo producen geosmina, la molécula responsable del olor característico de la tierra tras la lluvia.","Los científicos estiman que hemos identificado menos del 1 % de las especies microbianas del suelo terrestre."]
  },
  's5': {
    fr:["Les trois espèces connues sont le milan noir, le milan siffleur et le faucon bérigora — les aborigènes australiens les appellent « oiseaux de feu ».","Cette technique de chasse a été observée par les peuples autochtones depuis des millénaires avant d'être confirmée par la science en 2017.","Ces oiseaux transportent des brindilles enflammées sur plus d'un kilomètre pour allumer de nouveaux foyers et débusquer lézards et insectes."],
    en:["The three known species are the black kite, whistling kite and brown falcon — Australian Aboriginals call them 'firehawks'.","This hunting technique was observed by indigenous peoples for millennia before being scientifically confirmed in 2017.","These birds carry burning sticks over a kilometer to start new fires and flush out lizards and insects."],
    es:["Las tres especies conocidas que usan fuego son el milano negro, el milano silbador y el halcón berigora, todos de Australia.","Llevan ramas encendidas a zonas de hierba seca para provocar incendios que ahuyentan a sus presas.","Los bomberos y ecólogos australianos conocen este comportamiento desde hace décadas, pero la ciencia lo confirmó en 2017."]
  },
  's6': {
    fr:["Les icebergs peuvent aussi avoir des rayures bleues (eau pure regelée), noires (sédiments volcaniques) et blanches (air emprisonné).","Un iceberg ne montre que 10 % de sa masse totale au-dessus de l'eau — la partie immergée peut s'étendre sur des centaines de mètres.","Le plus grand iceberg jamais observé, le B-15, mesurait 295 km de long — plus grand que la Jamaïque."],
    en:["Icebergs can also have blue stripes (pure refrozen water), black stripes (volcanic sediment) and white stripes (trapped air).","An iceberg only shows 10% of its total mass above water — the submerged part can extend hundreds of meters.","The largest iceberg ever observed, B-15, measured 295 km long — larger than Jamaica."],
    es:["Los icebergs pueden tener rayas azules (agua pura recongelada), negras (sedimentos) o verdes (algas marinas).","El color azul intenso aparece cuando el hielo se comprime tanto que las burbujas de aire son expulsadas, dejando cristales puros.","Estas rayas son un archivo geológico: cada capa cuenta la historia de las condiciones ambientales en que se formó."]
  },
  's7': {
    fr:["Le Prochlorococcus, une cyanobactérie marine découverte en 1986, est l'organisme photosynthétique le plus abondant de la planète.","Si tout le phytoplancton disparaissait, le taux d'oxygène atmosphérique chuterait de moitié en quelques siècles.","Le phytoplancton absorbe aussi environ 40 % du CO₂ mondial, jouant un rôle climatique aussi important que toutes les forêts réunies."],
    en:["Prochlorococcus, a marine cyanobacterium discovered in 1986, is the most abundant photosynthetic organism on the planet.","If all phytoplankton disappeared, atmospheric oxygen levels would drop by half within a few centuries.","Phytoplankton also absorbs about 40% of global CO₂, playing a climate role as important as all forests combined."],
    es:["El Prochlorococcus, descubierto en 1986, es la cianobacteria marina más abundante y el organismo fotosintético más pequeño conocido.","Produce entre el 5 y el 10 % del oxígeno mundial — más que todos los bosques tropicales juntos, gramo por gramo.","Su descubrimiento tardío demuestra lo poco que conocemos los océanos: el organismo más importante del planeta pasó desapercibido hasta finales del siglo XX."]
  },
  's8': {
    fr:["Les fulgurites les plus longues jamais trouvées mesuraient plus de 5 mètres et avaient pénétré le sol en un réseau de branches vitrifiées.","La température à l'intérieur du canal de foudre dépasse 1 800 °C — suffisante pour transformer le quartz du sable en verre pur.","Les collectionneurs et géologues recherchent les fulgurites comme témoins naturels de l'impact de la foudre — certaines ont des milliers d'années."],
    en:["The longest fulgurites ever found measured over 5 meters and penetrated the ground in a network of vitrified branches.","The temperature inside the lightning channel exceeds 1,800°C — enough to turn sand quartz into pure glass.","Collectors and geologists seek fulgurites as natural witnesses of lightning strikes — some are thousands of years old."],
    es:["Las fulgurites más largas encontradas miden más de 5 metros y conservan la forma exacta del canal del rayo en la arena.","Se forman cuando un rayo (30 000 °C) funde instantáneamente los granos de arena (sílice), creando un tubo de vidrio natural.","Las fulgurites son una prueba geológica de tormentas pasadas y se han usado para estimar la frecuencia de rayos en eras prehistóricas."]
  },
  's9': {
    fr:["Malgré ce chiffre impressionnant, la Terre a perdu 46 % de ses arbres depuis le début de la civilisation humaine.","Chaque année, environ 15 milliards d'arbres sont coupés dans le monde, mais seulement 5 milliards sont replantés.","L'arbre le plus vieux du monde, un pin Bristlecone en Californie nommé Mathusalem, a plus de 4 850 ans."],
    en:["Despite this impressive number, Earth has lost 46% of its trees since the beginning of human civilization.","Each year, about 15 billion trees are cut down worldwide, but only 5 billion are replanted.","The oldest tree in the world, a Bristlecone pine in California named Methuselah, is over 4,850 years old."],
    es:["A pesar de sus 3 billones de árboles, la Tierra ha perdido el 46 % de su cobertura arbórea desde el inicio de la civilización humana.","Cada año desaparecen unos 15 000 millones de árboles por deforestación, incendios y uso agrícola.","Se plantan unos 5 000 millones al año — un déficit neto de 10 000 millones que programas de reforestación intentan revertir."]
  },
  's10': {
    fr:["Les scientifiques estiment que plus de 800 millions de virus se déposent par mètre carré chaque jour à la surface terrestre.","Ces virus voyagent attachés à des particules de poussière et des gouttelettes, propulsés à des altitudes de 2 500 à 3 000 mètres.","La plupart de ces virus sont des bactériophages — ils infectent uniquement des bactéries et sont inoffensifs pour les humains."],
    en:["Scientists estimate over 800 million viruses settle per square meter every day on Earth's surface.","These viruses travel attached to dust particles and droplets, propelled to altitudes of 2,500 to 3,000 meters.","Most of these viruses are bacteriophages — they only infect bacteria and are harmless to humans."],
    es:["Más de 800 millones de virus se depositan por metro cuadrado de superficie terrestre cada día, arrastrados por las corrientes de aire de la troposfera.","La mayoría son bacteriófagos (virus que infectan bacterias), no peligrosos para los humanos — regulan las poblaciones bacterianas del planeta.","La virosfera es la entidad biológica más abundante de la Tierra: hay más virus que estrellas en el universo observable."]
  },
  's11': {
    fr:["Les arbres « mères » les plus anciens distribuent des nutriments aux jeunes pousses voisines via ce réseau — même à celles d'espèces différentes.","Un seul arbre peut être connecté à des centaines d'autres par des filaments fongiques qui s'étendent sur des dizaines de mètres.","Quand un arbre est attaqué par des insectes, il envoie des signaux chimiques à travers le réseau pour prévenir ses voisins de produire des défenses."],
    en:["The oldest 'mother trees' distribute nutrients to neighboring seedlings through this network — even to those of different species.","A single tree can be connected to hundreds of others by fungal filaments extending tens of meters.","When a tree is attacked by insects, it sends chemical signals through the network to warn its neighbors to produce defenses."],
    es:["Los árboles madre más antiguos distribuyen nutrientes a los brotes jóvenes a través de redes de micorrizas — el llamado Wood Wide Web.","Suzanne Simard demostró en 1997 que los abedules y abetos comparten carbono a través de hongos subterráneos.","Cuando un árbol madre muere, libera sus recursos a la red, alimentando a los árboles vecinos — un legado biológico póstumo."]
  },
  's12': {
    fr:["Ce phénomène a été redécouvert en 1963 par Erasto Mpemba, un lycéen tanzanien qui l'a remarqué en faisant des glaces en cours de cuisine.","Plusieurs hypothèses existent : évaporation, convection, liaisons hydrogène — mais aucune n'a été unanimement acceptée.","Aristote mentionnait déjà ce phénomène au IVe siècle av. J.-C., et René Descartes l'a également décrit au XVIIe siècle."],
    en:["This phenomenon was rediscovered in 1963 by Erasto Mpemba, a Tanzanian student who noticed it while making ice cream in cooking class.","Several hypotheses exist: evaporation, convection, hydrogen bonds — but none has been unanimously accepted.","Aristotle already mentioned this phenomenon in the 4th century BC, and René Descartes also described it in the 17th century."],
    es:["Erasto Mpemba redescubrió el efecto en 1963 siendo estudiante de secundaria en Tanzania: su mezcla caliente de helado se congeló antes que la fría.","Las hipótesis incluyen la evaporación, la convección, los enlaces de hidrógeno y los gases disueltos — ninguna ha logrado consenso.","En 2020, un estudio propuso que los enlaces de hidrógeno del agua caliente almacenan menos energía, acelerando el enfriamiento."]
  },
  's13': {
    fr:["Dans l'eau, le son voyage environ 4,3 fois plus vite que dans l'air — c'est pourquoi les baleines communiquent sur des centaines de kilomètres.","Dans le diamant, le son atteint 12 000 m/s — le matériau solide où il se propage le plus rapidement.","À −273 °C (zéro absolu), le son cesserait théoriquement de se propager car les atomes n'ont plus d'énergie pour vibrer."],
    en:["In water, sound travels about 4.3 times faster than in air — that's why whales communicate over hundreds of kilometers.","In diamond, sound reaches 12,000 m/s — the solid material where it propagates fastest.","At −273°C (absolute zero), sound would theoretically stop propagating because atoms no longer have energy to vibrate."],
    es:["En el agua, el sonido viaja unas 4,3 veces más rápido que en el aire — por eso las ballenas pueden comunicarse a miles de kilómetros.","La velocidad del sonido depende de la densidad y la elasticidad del medio: más denso y más rígido significa más rápido.","En el acero, el sonido viaja a 5 960 m/s — casi 18 veces más rápido que en el aire."]
  },
  's14': {
    fr:["Si on mettait bout à bout l'ADN de toutes tes cellules, il couvrirait la distance Terre-Soleil environ 600 fois.","99,9 % de ton ADN est identique à celui de n'importe quel autre être humain — toute la diversité humaine tient dans 0,1 %.","Tu partages environ 60 % de ton ADN avec une banane et 85 % avec une souris."],
    en:["If you lined up the DNA from all your cells, it would cover the Earth-Sun distance about 600 times.","99.9% of your DNA is identical to any other human — all human diversity fits in 0.1%.","You share about 60% of your DNA with a banana and 85% with a mouse."],
    es:["Si se pusiera en fila el ADN de todas tus células, cubriría la distancia del Sol a Plutón ida y vuelta varias veces.","Todo ese ADN cabe en un núcleo celular de 6 micrómetros gracias a las histonas, proteínas alrededor de las cuales se enrolla.","El genoma humano fue secuenciado por primera vez en 2003 por el Proyecto Genoma Humano — un hito de la biología."]
  },
  's15': {
    fr:["À l'intérieur d'un noyau atomique, le neutron est parfaitement stable — il ne se désintègre que lorsqu'il est isolé.","Cette désintégration est gouvernée par la force nucléaire faible, l'une des quatre forces fondamentales de l'univers.","Les neutrons libres sont utilisés dans les réacteurs nucléaires : leur capture par l'uranium déclenche la fission en chaîne."],
    en:["Inside an atomic nucleus, the neutron is perfectly stable — it only decays when isolated.","This decay is governed by the weak nuclear force, one of the four fundamental forces of the universe.","Free neutrons are used in nuclear reactors: their capture by uranium triggers chain fission."],
    es:["Dentro del núcleo atómico, el neutrón es perfectamente estable — solo se desintegra cuando está libre, con una vida media de 14 minutos y 40 segundos.","Esta inestabilidad del neutrón libre fue crucial en los primeros minutos del universo: permitió la formación de hidrógeno y helio primordiales.","La desintegración beta del neutrón produce un protón, un electrón y un antineutrino — un proceso fundamental de la física nuclear."]
  },
  's16': {
    fr:["En 2019, un vaisseau israélien s'est écrasé sur la Lune avec des tardigrades à bord — ils ont probablement survécu à l'impact.","Pour survivre, le tardigrade entre en état de « tun » : il expulse toute son eau et réduit son métabolisme à 0,01 % de la normale.","Des tardigrades ont été réanimés avec succès après avoir été congelés pendant 30 ans dans de la mousse antarctique."],
    en:["In 2019, an Israeli spacecraft crashed on the Moon with tardigrades on board — they likely survived the impact.","To survive, the tardigrade enters a 'tun' state: it expels all its water and reduces its metabolism to 0.01% of normal.","Tardigrades were successfully revived after being frozen for 30 years in Antarctic moss."],
    es:["En 2019, la sonda israelí Beresheet se estrelló en la Luna con tardígrados deshidratados a bordo — podrían haber sobrevivido al impacto.","Los tardígrados resisten entrando en criptobiosis: se deshidratan hasta el 1 % de su agua y suspenden todo metabolismo.","Si sobrevivieron, serían los primeros organismos terrestres en colonizar la Luna — aunque en estado latente y sin capacidad de reproducirse."]
  },
  's17': {
    fr:["Le cerveau traite les images en seulement 13 millisecondes — bien plus vite que le clignement d'un œil qui prend 300 ms.","Pendant le sommeil paradoxal, le cerveau est aussi actif que pendant l'éveil — il consomme presque autant d'énergie.","Le cerveau humain peut stocker l'équivalent de 2,5 pétaoctets de données — environ 3 millions d'heures de vidéo."],
    en:["The brain processes images in just 13 milliseconds — much faster than an eye blink which takes 300 ms.","During REM sleep, the brain is as active as when awake — it consumes almost as much energy.","The human brain can store the equivalent of 2.5 petabytes of data — about 3 million hours of video."],
    es:["El cerebro procesa imágenes en solo 13 milisegundos — mucho más rápido de lo que se creía posible hasta un estudio del MIT en 2014.","Este procesamiento ultrarrápido es esencial para la supervivencia: detectar un depredador en una fracción de segundo marcaba la diferencia en la evolución.","La velocidad de procesamiento visual supera a la de la consciencia: vemos antes de ser conscientes de lo que vemos."]
  },
  's18': {
    fr:["Les pieuvres peuvent modifier leur ARN à la volée pour s'adapter à leur environnement — un talent unique dans le règne animal.","Deux des trois cœurs s'arrêtent quand la pieuvre nage, ce qui l'épuise rapidement — c'est pourquoi elle préfère ramper.","La pieuvre mimétique d'Indonésie peut imiter la forme et les mouvements d'au moins 15 espèces différentes."],
    en:["Octopuses can edit their RNA on the fly to adapt to their environment — a unique talent in the animal kingdom.","Two of the three hearts stop when the octopus swims, which exhausts it quickly — that's why it prefers crawling.","The mimic octopus from Indonesia can imitate the shape and movements of at least 15 different species."],
    es:["Los pulpos pueden modificar su ARN sobre la marcha para adaptarse a su entorno — una capacidad llamada edición de ARN que es extremadamente rara en el reino animal.","Esta edición les permite ajustar las proteínas de sus neuronas según la temperatura del agua, manteniendo la función cerebral en condiciones cambiantes.","El precio de esta flexibilidad es una evolución genómica más lenta: los pulpos sacrifican mutaciones del ADN a favor de la edición del ARN."]
  },
  's19': {
    fr:["En 2012, des chercheurs de Harvard ont réussi à encoder un livre entier de 53 000 mots dans un fragment d'ADN synthétique.","L'ADN conserve les données pendant des milliers d'années sans énergie — des génomes de mammouths ont été lus après 1 million d'années.","Microsoft et l'université de Washington travaillent sur un système de stockage ADN automatisé capable de lire et écrire des données."],
    en:["In 2012, Harvard researchers successfully encoded an entire 53,000-word book into a fragment of synthetic DNA.","DNA preserves data for thousands of years without energy — mammoth genomes have been read after 1 million years.","Microsoft and the University of Washington are working on an automated DNA storage system capable of reading and writing data."],
    es:["En 2012, investigadores de Harvard codificaron un libro de 53 000 palabras en ADN sintético, demostrando su potencial como medio de almacenamiento.","El ADN puede almacenar 215 petabytes por gramo — millones de veces más denso que cualquier disco duro existente.","El desafío es la velocidad de lectura/escritura: hoy es demasiado lenta y cara para uso práctico, pero la tecnología avanza rápidamente."]
  },
  's20': {
    fr:["Il existe au moins 20 formes différentes de glace connues, chacune avec une structure cristalline unique.","Sur certaines exoplanètes géantes, de la « glace chaude » pourrait exister en permanence — solide mais à des centaines de degrés.","La glace VII, une forme ultra-comprimée, a été découverte piégée dans un diamant naturel en 2018 — preuve qu'elle existe dans le manteau terrestre."],
    en:["There are at least 20 known different forms of ice, each with a unique crystal structure.","On some giant exoplanets, 'hot ice' could permanently exist under colossal pressures — solid but at hundreds of degrees.","Ice VII, an ultra-compressed form, was found trapped in a natural diamond in 2018 — proof it exists in Earth's mantle."],
    es:["Existen al menos 20 formas conocidas de hielo, cada una con una estructura cristalina diferente según la presión y la temperatura.","El hielo común (Ih) es hexagonal, pero a presiones extremas el hielo puede ser cúbico, tetragonal o incluso superiónico.","El hielo VII, que existe a altas presiones, ha sido encontrado en el interior de diamantes naturales — prueba de las condiciones extremas del manto terrestre."]
  },
  // === ANIMALS ===
  'a1': {
    fr:["Le sang bleu des pieuvres est moins efficace que le sang rouge pour transporter l'oxygène — c'est pourquoi elles s'épuisent vite en nageant.","Une pieuvre a environ 500 millions de neurones, autant qu'un chien — dont les deux tiers sont dans ses tentacules.","Les pieuvres peuvent goûter ce qu'elles touchent grâce à des milliers de ventouses équipées de chimiorécepteurs."],
    en:["Octopus blue blood is less efficient than red blood at carrying oxygen — that's why they tire quickly when swimming.","An octopus has about 500 million neurons, as many as a dog — two-thirds of which are in its tentacles.","Octopuses can taste what they touch through thousands of suckers equipped with chemoreceptors."],
    es:["La sangre azul de los pulpos es menos eficiente que la sangre roja para transportar oxígeno, lo que explica que necesiten tres corazones.","La hemocianina (basada en cobre) funciona mejor en aguas frías y con poco oxígeno — una adaptación a las profundidades oceánicas.","Cuando un pulpo nada, su corazón sistémico se detiene — por eso prefieren caminar por el fondo marino a nadar."]
  },
  'a2': {
    fr:["Les dauphins s'appellent par leur sifflement personnel même après des séparations de plus de 20 ans.","Ils se regardent dans un miroir et reconnaissent leur propre reflet — un signe d'intelligence très rare dans le règne animal.","Les dauphins utilisent des éponges marines comme protection sur leur museau quand ils fouillent le fond sableux — un outil transmis de mère en fille."],
    en:["Dolphins call each other by their personal whistle even after separations of over 20 years.","They look in mirrors and recognize their own reflection — a sign of intelligence very rare in the animal kingdom.","Dolphins use sea sponges as protection on their snouts when foraging sandy bottoms — a tool passed from mother to daughter."],
    es:["Los delfines se llaman por su silbido personal incluso después de separaciones de años — una memoria social extraordinaria.","Cada delfín desarrolla un silbido firma único durante su primer año de vida que conserva toda su vida.","Los delfines pueden recordar el silbido de un compañero durante al menos 20 años — una de las memorias sociales más largas del reino animal."]
  },
  'a3': {
    fr:["Les tardigrades ont survécu aux cinq grandes extinctions de masse que la Terre a connues en 500 millions d'années.","Ils possèdent une protéine unique, Dsup, qui protège leur ADN des radiations en formant un bouclier autour des chromosomes.","On a recensé plus de 1 300 espèces de tardigrades — ils vivent partout, des sommets himalayens aux fosses océaniques."],
    en:["Tardigrades survived all five mass extinctions Earth has experienced in 500 million years.","They have a unique protein, Dsup, that shields their DNA from radiation by forming a shield around chromosomes.","Over 1,300 species of tardigrades have been identified — they live everywhere, from Himalayan peaks to ocean trenches."],
    es:["Los tardígrados han sobrevivido a las cinco grandes extinciones masivas que ha sufrido la Tierra — más de 500 millones de años de supervivencia.","Su secreto es la criptobiosis: suspenden todo metabolismo y resisten condiciones que matarían a cualquier otro animal.","Son tan resistentes que incluso un impacto de asteroide o una supernova cercana no podrían extinguirlos — los verdaderos supervivientes del planeta."]
  },
  'a4': {
    fr:["Les corbeaux fabriquent des outils à partir de brindilles pour extraire des larves — une capacité cognitive comparable à celle des grands singes.","Ils organisent de véritables « funérailles » : quand un corbeau meurt, les autres se rassemblent autour du corps en silence.","Les corbeaux peuvent planifier l'avenir — ils cachent de la nourriture dans des endroits variés et se souviennent de chaque emplacement."],
    en:["Crows craft tools from twigs to extract larvae — a cognitive ability comparable to great apes.","They hold actual 'funerals': when a crow dies, others gather around the body in silence.","Crows can plan for the future — they hide food in various spots and remember every location."],
    es:["Los cuervos fabrican herramientas a partir de ramitas para extraer larvas de los agujeros de los árboles — un comportamiento antes atribuido solo a los primates.","Los cuervos de Nueva Caledonia fabrican ganchos a partir de ramas, un proceso que requiere planificación y conocimiento de los materiales.","Transmiten estas técnicas a sus crías mediante aprendizaje social — una forma de cultura tecnológica en el reino animal."]
  },
  'a5': {
    fr:["L'escargot produit un mucus si résistant qu'il peut ramper sur une lame de rasoir sans se couper.","Les escargots de Bourgogne peuvent vivre jusqu'à 10 ans — bien plus que la plupart des invertébrés terrestres.","Certaines espèces d'escargots possèdent jusqu'à 20 000 dents microscopiques sur leur langue râpeuse appelée radula."],
    en:["The snail produces mucus so strong it can crawl over a razor blade without cutting itself.","Burgundy snails can live up to 10 years — much longer than most terrestrial invertebrates.","Some snail species have up to 20,000 microscopic teeth on their raspy tongue called a radula."],
    es:["El caracol produce un moco tan resistente que puede deslizarse sobre una cuchilla de afeitar sin cortarse.","El moco tiene propiedades tixotrópicas: es sólido en reposo pero se vuelve líquido bajo presión — permitiendo el movimiento sin fricción.","La baba de caracol se usa en cosmética por su contenido en alantoína, colágeno y ácido glicólico — propiedades regeneradoras para la piel."]
  },
  'a6': {
    fr:["Le processus s'appelle la transdifférenciation : les cellules adultes se reprogramment en cellules souches et reconstruisent un organisme neuf.","Les scientifiques étudient cette méduse pour percer les secrets du vieillissement humain et développer des thérapies régénératives.","Malgré son immortalité biologique, la méduse reste vulnérable aux maladies, aux prédateurs et aux changements de son environnement."],
    en:["The process is called transdifferentiation: adult cells reprogram into stem cells and rebuild a new organism.","Scientists study this jellyfish to unlock the secrets of human aging and develop regenerative therapies.","Despite its biological immortality, the jellyfish remains vulnerable to disease, predators, and environmental changes."],
    es:["El proceso se llama transdiferenciación: las células adultas se reprograman a sí mismas para convertirse en otro tipo de célula.","Las medusas inmortales (Turritopsis dohrnii) son las campeonas de la transdiferenciación: pueden revertir su ciclo vital indefinidamente.","Los científicos estudian estos mecanismos para la medicina regenerativa: si pudiéramos reprogramar nuestras células, podríamos regenerar órganos dañados."]
  },
  'a7': {
    fr:["Le claquement de la pince crée un flash de lumière visible — un phénomène rare appelé sonoluminescence.","L'onde de choc générée se déplace à 100 km/h et peut assommer ou tuer un petit poisson à distance.","Ces crevettes sont si bruyantes que la marine américaine les utilisait comme couverture sonore pour ses sous-marins pendant la Guerre froide."],
    en:["The snap creates a visible flash of light — a rare phenomenon called sonoluminescence.","The shockwave travels at 100 km/h and can stun or kill small fish at a distance.","These shrimp are so loud the US Navy used them as sonar cover for submarines during the Cold War."],
    es:["El chasquido de la pinza de la gamba mantis crea un destello de luz visible — un fenómeno raro llamado sonoluminiscencia.","La burbuja de cavitación generada alcanza momentáneamente temperaturas de 4 700 °C — casi tan caliente como la superficie del Sol.","El golpe de la gamba mantis es el movimiento más rápido del reino animal: acelera a 23 m/s en menos de 3 milisegundos."]
  },
  'a8': {
    fr:["Les colonies de fourmis coupe-feuilles comptent jusqu'à 8 millions d'individus avec des castes spécialisées : coupeuses, transporteuses, jardinières.","Le champignon qu'elles cultivent n'existe nulle part ailleurs dans la nature — il est devenu entièrement dépendant des fourmis pour survivre.","Elles produisent aussi des antibiotiques naturels pour protéger leurs cultures fongiques contre les parasites."],
    en:["Leafcutter ant colonies number up to 8 million with specialized castes: cutters, carriers, and gardeners.","The fungus they cultivate exists nowhere else in nature — it has become entirely dependent on ants to survive.","They also produce natural antibiotics to protect their fungal crops from parasites."],
    es:["Las colonias de hormigas cortadoras de hojas alcanzan 8 millones de individuos y construyen nidos subterráneos de hasta 30 metros de diámetro.","No comen las hojas: las usan como sustrato para cultivar un hongo específico (Leucoagaricus gongylophorus) que es su único alimento.","Esta agricultura fúngica tiene 50 millones de años de antigüedad — las hormigas fueron agricultoras 45 millones de años antes que los humanos."]
  },
  'a9': {
    fr:["Les vaches produisent plus de lait quand on leur donne des prénoms — une étude de l'université de Newcastle l'a confirmé en 2009.","Elles peuvent sentir les émotions des autres vaches : quand une compagne est stressée, les vaches voisines montrent des signes d'anxiété.","Les vaches dorment debout mais ne rêvent que couchées — elles ne passent en sommeil paradoxal que dans cette position."],
    en:["Cows produce more milk when given individual names — a Newcastle University study confirmed this in 2009.","They can sense other cows' emotions: when a companion is stressed, neighboring cows show signs of anxiety.","Cows sleep standing but only dream while lying down — they only enter REM sleep in that position."],
    es:["Las vacas producen más leche cuando se les pone nombre — un estudio de la Universidad de Newcastle (2009) demostró un aumento del 3,5 %.","El efecto se atribuye al trato más individualizado: los granjeros que nombran a sus vacas les prestan más atención y las estresan menos.","El estrés reduce la producción de leche al inhibir la oxitocina — la hormona que permite la eyección de la leche."]
  },
  'a10': {
    fr:["Les loutres de mer enveloppent aussi leurs bébés dans du kelp comme un berceau flottant pendant qu'elles plongent chercher de la nourriture.","Elles utilisent des pierres comme outils pour ouvrir les coquillages — et gardent leur pierre préférée dans une poche de peau sous leur bras.","Leur fourrure est la plus dense du règne animal : environ 150 000 poils par centimètre carré, ce qui les isole du froid de l'eau."],
    en:["Sea otters also wrap their babies in kelp like a floating cradle while they dive for food.","They use rocks as tools to open shellfish — and keep their favorite rock in a skin pouch under their arm.","Their fur is the densest in the animal kingdom: about 150,000 hairs per square centimeter, insulating them from cold water."],
    es:["Las nutrias marinas envuelven a sus crías en kelp como un arnés flotante para que no se las lleve la corriente mientras bucean.","También duermen flotando boca arriba cogidas de la mano para no separarse — un comportamiento llamado rafting.","Las nutrias marinas tienen el pelo más denso del reino animal: 150 000 pelos por cm², 1 000 veces más que un humano."]
  },
  'a11': {
    fr:["Les papillons monarques migrent sur 4 000 km entre le Canada et le Mexique — un voyage qu'aucun individu ne fait en entier puisqu'il faut 4 générations.","Certaines espèces de papillons boivent les larmes de crocodiles pour obtenir du sodium, un minéral rare dans leur alimentation.","Les ailes des papillons sont transparentes — les couleurs viennent de milliers d'écailles microscopiques qui réfractent la lumière."],
    en:["Monarch butterflies migrate 4,000 km between Canada and Mexico — a journey no single individual completes as it takes 4 generations.","Some butterfly species drink crocodile tears to obtain sodium, a rare mineral in their diet.","Butterfly wings are transparent — the colors come from thousands of microscopic scales that refract light."],
    es:["Las mariposas monarca migran 4 000 km entre Canadá y México — un viaje que requiere cuatro generaciones para completarse en sentido inverso.","La generación migratoria vive 8 meses (frente a 4-6 semanas habituales) y navega usando una brújula solar en sus antenas.","Los santuarios de monarca en Michoacán (México) reciben millones de ejemplares cada invierno — un espectáculo amenazado por la deforestación."]
  },
  'a12': {
    fr:["Les éléphants sont les seuls animaux connus à avoir un rituel face à la mort : ils revisitent les ossements de leurs proches et les touchent avec leur trompe.","Un éléphant peut boire jusqu'à 200 litres d'eau par jour et sa trompe contient plus de 40 000 muscles.","Les éléphanteaux sucent leur trompe comme les bébés humains sucent leur pouce — un geste de réconfort."],
    en:["Elephants are the only animals known to have a ritual around death: they revisit bones of relatives and touch them with their trunks.","An elephant can drink up to 200 liters of water per day and its trunk contains over 40,000 muscles.","Baby elephants suck their trunks just like human babies suck their thumbs — a comfort gesture."],
    es:["Los elefantes son los únicos animales conocidos que tienen un ritual ante la muerte: se detienen, tocan al difunto con la trompa y permanecen en silencio.","Vuelven a los lugares donde murieron sus familiares años después y tocan los huesos con sus trompas — un comportamiento de duelo documentado.","Los elefantes también muestran signos de empatía hacia miembros heridos del grupo, ayudándolos a levantarse y protegiéndolos de depredadores."]
  },
  'a13': {
    fr:["Le battement du cœur d'une baleine bleue peut être détecté à plus de 3 km de distance.","Un bébé baleine bleue prend environ 90 kg par jour pendant sa première année — il boit 380 litres de lait maternel quotidiennement.","La langue d'une baleine bleue pèse autant qu'un éléphant adulte — environ 2,7 tonnes."],
    en:["A blue whale's heartbeat can be detected from over 3 km away.","A baby blue whale gains about 90 kg per day during its first year — drinking 380 liters of milk daily.","A blue whale's tongue weighs as much as an adult elephant — about 2.7 tons."],
    es:["El latido del corazón de una ballena azul puede detectarse a más de 3 km de distancia con hidrófonos sensibles.","Su corazón pesa unos 180 kg (del tamaño de un coche pequeño) y late solo 2-8 veces por minuto durante las inmersiones profundas.","La aorta de una ballena azul es tan grande que un niño podría gatear por ella — el sistema circulatorio más voluminoso del reino animal."]
  },
  'a14': {
    fr:["Les abeilles communiquent par une danse en forme de huit qui indique la direction et la distance d'une source de nectar aux autres ouvrières.","Une reine des abeilles peut pondre jusqu'à 2 000 œufs par jour — soit plus que son propre poids en œufs.","Les abeilles doivent visiter environ 2 millions de fleurs pour produire 500 grammes de miel."],
    en:["Bees communicate through a figure-eight dance that indicates the direction and distance of a nectar source to other workers.","A queen bee can lay up to 2,000 eggs per day — more than her own weight in eggs.","Bees must visit about 2 million flowers to produce 500 grams of honey."],
    es:["Las abejas comunican la ubicación de las flores mediante una danza en forma de ocho que indica la dirección y la distancia respecto a la colmena.","La danza del abdomen (waggle dance) fue descifrada por Karl von Frisch, que recibió el Nobel en 1973 por este descubrimiento.","La precisión de la danza es extraordinaria: indica la dirección respecto al sol con un margen de error de solo unos pocos grados."]
  },
  'a15': {
    fr:["Alex, le perroquet gris le plus célèbre, a été le premier animal à poser une question existentielle — il a demandé de quelle couleur il était.","Les perroquets gris peuvent résoudre des puzzles logiques au niveau d'un enfant de 4-6 ans.","Ils vivent en moyenne 50 ans en captivité — certains individus ont dépassé les 80 ans."],
    en:["Alex, the most famous grey parrot, was the first animal to ask an existential question — he asked what color he was.","Grey parrots can solve logical puzzles at the level of a 4-6 year old child.","They live on average 50 years in captivity — some individuals have exceeded 80 years."],
    es:["Alex, el loro gris más célebre, fue el primer animal en formular una pregunta existencial: al verse en un espejo preguntó de qué color era.","Fue entrenado durante 30 años por la científica Irene Pepperberg — demostró comprensión de conceptos como color, forma, tamaño y cantidad.","Sus últimas palabras a Pepperberg fueron «You be good, I love you» — murió en 2007, dejando un legado que transformó la comprensión de la cognición aviar."]
  },
  'a16': {
    fr:["Chaque requin-baleine possède un motif unique de points et de lignes sur sa peau — comme une empreinte digitale.","Malgré sa taille imposante, sa gorge ne mesure que la taille d'un poing humain — il ne pourrait pas avaler un humain.","Les requin-baleines peuvent vivre plus de 100 ans — certains scientifiques estiment même jusqu'à 150 ans."],
    en:["Each whale shark has a unique pattern of dots and lines on its skin — like a fingerprint.","Despite its imposing size, its throat is only the size of a human fist — it couldn't swallow a person.","Whale sharks can live over 100 years — some scientists estimate up to 150 years."],
    es:["Cada tiburón ballena tiene un patrón único de puntos y líneas en su piel, como una huella dactilar, que los investigadores usan para identificarlos.","Se cree que pueden vivir más de 100 años, aunque es difícil de confirmar porque crecen muy lentamente y migran grandes distancias.","A pesar de su tamaño colosal (hasta 18 metros), son dóciles y permiten a los buceadores nadar junto a ellos."]
  },
  'a17': {
    fr:["Les crocodiles ont survécu à l'extinction des dinosaures il y a 66 millions d'années — leur design est si efficace qu'il n'a presque pas changé.","Ils avalent des pierres volontairement pour servir de lest et les aider à plonger plus profondément.","La mâchoire d'un crocodile marin exerce la morsure la plus puissante du règne animal : 16 000 newtons, soit 10 fois celle d'un lion."],
    en:["Crocodiles survived the dinosaur extinction 66 million years ago — their design is so efficient it has barely changed.","They deliberately swallow stones as ballast to help them dive deeper.","A saltwater crocodile's jaw delivers the most powerful bite in the animal kingdom: 16,000 newtons, 10 times that of a lion."],
    es:["Los cocodrilos han sobrevivido a la extinción de los dinosaurios hace 66 millones de años — su diseño corporal ha cambiado poco desde entonces.","Son los reptiles vivos más grandes del mundo: el cocodrilo de agua salada puede medir 7 metros y pesar más de una tonelada.","La mordedura del cocodrilo es la más potente del reino animal: hasta 3 700 psi — pero los músculos de apertura son tan débiles que se pueden sujetar con una goma elástica."]
  },
  'a18': {
    fr:["Le plus gros homard jamais capturé pesait 20,1 kg et a été pêché au large de la Nouvelle-Écosse en 1977.","Les homards possèdent des récepteurs gustatifs sur leurs pattes — ils « goûtent » le sol marin en marchant dessus.","Leur sang est incolore mais devient bleu quand il est exposé à l'oxygène, comme celui des pieuvres."],
    en:["The largest lobster ever caught weighed 20.1 kg and was caught off Nova Scotia in 1977.","Lobsters have taste receptors on their legs — they 'taste' the seafloor by walking on it.","Their blood is colorless but turns blue when exposed to oxygen, like octopus blood."],
    es:["El bogavante más grande jamás capturado pesaba 20,1 kg y fue pescado frente a la costa de Nueva Escocia (Canadá) en 1977.","Los bogavantes pueden vivir más de 100 años: siguen creciendo durante toda su vida y sus células no muestran signos de envejecimiento (senescencia).","Producen telomerasa indefinidamente — la enzima que protege los telómeros cromosómicos — lo que teóricamente les permitiría vivir eternamente si no fueran cazados."]
  },
  'a19': {
    fr:["Ce sommeil unihémisphérique leur permet aussi de continuer à nager pendant qu'ils dorment — ils ne s'arrêtent littéralement jamais.","Les nouveau-nés dauphins ne dorment pas du tout pendant le premier mois de leur vie — et leur mère non plus.","Les dauphins alternent les hémisphères toutes les deux heures environ, gardant toujours un œil ouvert du côté éveillé."],
    en:["This unihemispheric sleep also allows them to keep swimming while sleeping — they literally never stop.","Newborn dolphins don't sleep at all during the first month of life — and neither does their mother.","Dolphins alternate hemispheres roughly every two hours, always keeping one eye open on the awake side."],
    es:["El sueño unihemisférico les permite también seguir nadando mientras duermen — una necesidad vital para los cetáceos que deben subir a respirar.","Los delfines alternan qué hemisferio duerme cada pocas horas, manteniendo siempre un ojo abierto para vigilar depredadores.","Las aves migratorias también duermen unihemiféricamente durante vuelos largos — una adaptación convergente fascinante."]
  },
  'a20': {
    fr:["Les premiers requins n'avaient pas de mâchoires articulées — ils se nourrissaient en filtrant l'eau ou en aspirant leurs proies.","Le requin du Groenland est le vertébré qui vit le plus longtemps : certains individus auraient plus de 500 ans.","Les requins perdent et repoussent environ 30 000 dents au cours de leur vie — ils en ont toujours de nouvelles en réserve."],
    en:["The first sharks had no articulated jaws — they fed by filtering water or sucking in prey.","The Greenland shark is the longest-living vertebrate: some individuals may be over 500 years old.","Sharks lose and regrow about 30,000 teeth in their lifetime — they always have new ones in reserve."],
    es:["Los primeros tiburones no tenían mandíbulas articuladas — se alimentaban filtrando nutrientes del agua como las lampreas actuales.","Los tiburones modernos evolucionaron mandíbulas móviles hace unos 400 millones de años — una innovación que los convirtió en depredadores supremos.","Los dientes de tiburón se reemplazan continuamente: un tiburón puede producir más de 30 000 dientes a lo largo de su vida."]
  },
  // === BODY ===
  'b1': {
    fr:["Si tu tapais l'intégralité de ton code génétique à raison de 60 mots par minute, il te faudrait environ 50 ans sans t'arrêter.","Chaque cellule de ton corps subit environ 10 000 dommages à son ADN par jour — heureusement, des enzymes réparatrices corrigent la quasi-totalité.","Seulement 2 % de ton ADN code des protéines — le reste, longtemps appelé « ADN poubelle », joue en fait des rôles régulateurs complexes."],
    en:["If you typed your entire genetic code at 60 words per minute, it would take about 50 years non-stop.","Each cell in your body suffers about 10,000 DNA damage events per day — thankfully, repair enzymes fix nearly all of them.","Only 2% of your DNA codes for proteins — the rest, long called 'junk DNA', actually plays complex regulatory roles."],
    es:["Si teclearas tu código genético a 60 palabras por minuto, 8 horas al día, tardarías unos 50 años en terminar.","El genoma humano tiene 3 200 millones de pares de bases — pero solo el 1-2 % codifica proteínas funcionales.","El resto, antes llamado ADN basura, cumple funciones reguladoras cada vez mejor comprendidas por la genómica moderna."]
  },
  'b2': {
    fr:["Le cerveau est composé de 75 % d'eau — une déshydratation de seulement 2 % affecte déjà l'attention et la mémoire.","Il ne ressent pas la douleur lui-même — c'est pourquoi les chirurgiens peuvent opérer le cerveau sur un patient éveillé.","Le cerveau d'un nouveau-né double de taille dans la première année de vie et atteint 80 % de sa taille adulte à 3 ans."],
    en:["The brain is 75% water — just 2% dehydration already affects attention and memory.","It doesn't feel pain itself — that's why surgeons can operate on the brain while the patient is awake.","A newborn's brain doubles in size in the first year and reaches 80% of its adult size by age 3."],
    es:["El cerebro está compuesto en un 75 % de agua — una deshidratación de solo el 2 % afecta a la concentración, la memoria y el tiempo de reacción.","El cerebro consume 20 % de la energía corporal a pesar de representar solo el 2 % de la masa — es el órgano más hambriento del cuerpo.","El cerebro no almacena energía: depende de un suministro continuo de glucosa y oxígeno vía la sangre."]
  },
  'b3': {
    fr:["L'os le plus solide du corps est le fémur — il peut supporter une pression de 1 700 kg avant de se fracturer.","Les os sont aussi légers que le bois grâce à leur structure en nid d'abeilles — s'ils étaient massifs, le squelette pèserait 5 fois plus.","Les astronautes perdent environ 1 % de masse osseuse par mois dans l'espace à cause de l'absence de gravité."],
    en:["The strongest bone in the body is the femur — it can withstand 1,700 kg of pressure before fracturing.","Bones are as light as wood thanks to their honeycomb structure — if solid, the skeleton would weigh 5 times more.","Astronauts lose about 1% of bone mass per month in space due to the absence of gravity."],
    es:["El fémur es el hueso más sólido del cuerpo — puede soportar una presión de hasta 1 700 kg antes de fracturarse.","Es también el hueso más largo: mide aproximadamente un cuarto de la estatura total de una persona.","Los huesos son materiales compuestos: la hidroxiapatita aporta dureza y el colágeno flexibilidad — como el hormigón armado."]
  },
  'b4': {
    fr:["L'acide chlorhydrique de ton estomac est assez puissant pour dissoudre du métal — son pH est compris entre 1 et 3.","Ton estomac rougit quand tu rougis — la même réaction nerveuse qui dilate les vaisseaux du visage affecte aussi la muqueuse gastrique.","Le gargouillement de l'estomac s'appelle un borborygme et se produit aussi quand l'estomac est plein, pas seulement quand il est vide."],
    en:["The hydrochloric acid in your stomach is strong enough to dissolve metal — its pH is between 1 and 3.","Your stomach blushes when you blush — the same nervous reaction that dilates facial vessels also affects the gastric lining.","Stomach rumbling is called borborygmus and happens when the stomach is full too, not just when empty."],
    es:["El ácido clorhídrico del estómago es lo suficientemente potente como para disolver metal — su pH oscila entre 1,5 y 3,5.","Una capa de moco protege las paredes del estómago de su propia acidez — se renueva cada dos semanas.","Las células parietales del estómago producen unos 2 litros de ácido al día — cuando el equilibrio se rompe, aparecen las úlceras."]
  },
  'b5': {
    fr:["En une vie moyenne, le cœur pompe environ 200 millions de litres de sang — assez pour remplir 80 piscines olympiques.","Le cœur possède son propre système électrique indépendant — il peut continuer à battre même séparé du corps s'il reçoit de l'oxygène.","Le son « lub-dub » du battement cardiaque est produit par la fermeture successive des valves du cœur."],
    en:["In an average lifetime, the heart pumps about 200 million liters of blood — enough to fill 80 Olympic pools.","The heart has its own independent electrical system — it can keep beating even separated from the body if it receives oxygen.","The 'lub-dub' sound of a heartbeat is produced by the successive closing of the heart's valves."],
    es:["En una vida media, el corazón bombea unos 200 millones de litros de sangre — suficiente para llenar 80 piscinas olímpicas.","Late unas 100 000 veces al día sin descanso, impulsado por su propio sistema eléctrico autónomo (el nodo sinusal).","El corazón puede seguir latiendo fuera del cuerpo mientras reciba oxígeno — un fenómeno visible durante los trasplantes."]
  },
  'b6': {
    fr:["La cornée est le tissu du corps qui se régénère le plus vite — une légère égratignure peut guérir en 24 à 48 heures.","C'est grâce à cette absence de vaisseaux sanguins que les greffes de cornée ont un taux de succès exceptionnellement élevé.","Les cornées de requin sont si similaires aux cornées humaines qu'elles ont été utilisées dans des recherches sur les transplantations."],
    en:["The cornea is the fastest-healing tissue in the body — a minor scratch can heal in 24 to 48 hours.","Thanks to this lack of blood vessels, corneal transplants have an exceptionally high success rate.","Shark corneas are so similar to human corneas they've been used in transplant research."],
    es:["La córnea es el tejido del cuerpo que se regenera más rápido — un rasguño leve se cura en 24-48 horas.","No tiene vasos sanguíneos (lo que le da transparencia) y obtiene oxígeno directamente del aire a través de la película lagrimal.","Los trasplantes de córnea tienen la tasa de éxito más alta de todos los trasplantes de tejidos — superior al 90 %."]
  },
  'b7': {
    fr:["Les Grecs anciens connaissaient déjà cette capacité — le mythe de Prométhée décrit un foie qui repousse chaque nuit après avoir été dévoré par un aigle.","Le foie effectue plus de 500 fonctions différentes, dont la filtration de 1,4 litre de sang par minute.","Un donneur vivant de foie retrouve 90 % de son volume hépatique en seulement 8 semaines."],
    en:["The ancient Greeks already knew this ability — the myth of Prometheus describes a liver regrowing each night after being eaten by an eagle.","The liver performs over 500 different functions, including filtering 1.4 liters of blood per minute.","A living liver donor regains 90% of their liver volume in just 8 weeks."],
    es:["Los griegos antiguos ya conocían la regeneración hepática — el mito de Prometeo describe cómo un águila le devoraba el hígado cada día y se regeneraba cada noche.","El hígado puede regenerar hasta el 75 % de su masa en pocas semanas — la base de los trasplantes de donante vivo.","Realiza más de 500 funciones: filtrar toxinas, producir bilis, sintetizar proteínas, almacenar vitaminas y metabolizar fármacos."]
  },
  'b8': {
    fr:["Les astronautes grandissent de 3 à 5 cm dans l'espace car sans gravité, les disques intervertébraux se décompressent entièrement.","Ce phénomène explique aussi pourquoi les personnes de plus de 40 ans rapetissent progressivement — environ 1 cm par décennie.","Le matin, tes disques intervertébraux sont gonflés d'eau comme des éponges — le soir, la gravité les a comprimés de 15 à 25 %."],
    en:["Astronauts grow 3 to 5 cm in space because without gravity, the intervertebral discs fully decompress.","This also explains why people over 40 gradually shrink — about 1 cm per decade.","In the morning, your intervertebral discs are swollen with water like sponges — by evening, gravity has compressed them 15 to 25%."],
    es:["Los astronautas crecen de 3 a 5 cm en el espacio porque sin gravedad, los discos intervertebrales se expanden.","Este efecto es temporal: al volver a la Tierra, la gravedad comprime los discos y la estatura vuelve a la normalidad en semanas.","La pérdida de masa ósea (1-2 % al mes) y muscular en el espacio es un problema grave para las misiones de larga duración."]
  },
  'b9': {
    fr:["L'os hyoïde, dans la gorge, est le seul os du corps humain qui n'est relié à aucun autre os — il flotte, tenu uniquement par des muscles et des ligaments.","Les bébés n'ont pas de rotule à la naissance — le cartilage ne s'ossifie en vrai os qu'entre 3 et 5 ans.","Le plus petit os du corps est l'étrier, dans l'oreille interne — il mesure 3 mm et est essentiel à l'audition."],
    en:["The hyoid bone in the throat is the only bone not connected to any other bone — it floats, held only by muscles and ligaments.","Babies don't have kneecaps at birth — the cartilage doesn't ossify into real bone until ages 3 to 5.","The smallest bone in the body is the stapes in the inner ear — it measures 3 mm and is essential for hearing."],
    es:["El hueso hioides, en la garganta, es el único hueso del cuerpo que no está articulado con ningún otro hueso.","Está suspendido por músculos y ligamentos y es esencial para tragar, hablar y respirar — sirve de ancla para la lengua.","El hioides es clave en la evolución del habla: su posición baja en los humanos (frente a otros primates) permite una mayor variedad de sonidos."]
  },
  'b10': {
    fr:["Le cervelet est responsable de cette prédiction — il compare les signaux envoyés par tes doigts avec les sensations attendues et annule le chatouillement.","Les personnes atteintes de schizophrénie peuvent parfois se chatouiller elles-mêmes — leur cerveau a plus de difficulté à prédire ses propres actions.","Les zones les plus chatouilleuses — pieds, aisselles, cou — sont aussi les plus vulnérables aux attaques, ce qui suggère un lien avec un réflexe de défense ancestral."],
    en:["The cerebellum is responsible for this prediction — it compares signals sent by your fingers with expected sensations and cancels the tickle.","People with schizophrenia can sometimes tickle themselves — their brains have more difficulty predicting their own actions.","The most ticklish areas — feet, armpits, neck — are also the most vulnerable to attacks, suggesting a link to an ancestral defense reflex."],
    es:["El cerebelo compara los señales enviadas y recibidas — si coinciden, suprime la respuesta sensorial. Por eso no puedes hacerte cosquillas a ti mismo.","Este mecanismo predictivo es esencial para el control motor: el cerebelo anticipa las consecuencias de cada movimiento.","Algunas personas con lesiones cerebelares sí pueden hacerse cosquillas — lo que confirma el papel del cerebelo en este filtro sensorial."]
  },
  'b11': {
    fr:["Tu effectues environ 20 000 respirations par jour, inhalant environ 11 000 litres d'air en 24 heures.","Les poumons contiennent environ 600 millions d'alvéoles — de minuscules sacs où s'effectuent les échanges gazeux.","Le poumon droit est légèrement plus grand que le gauche, qui laisse de la place au cœur."],
    en:["You take about 20,000 breaths per day, inhaling about 11,000 liters of air in 24 hours.","Lungs contain about 600 million alveoli — tiny sacs where gas exchange takes place.","The right lung is slightly larger than the left, which makes room for the heart."],
    es:["Realizas unas 20 000 respiraciones al día, inhalando unos 11 000 litros de aire.","Los alvéolos pulmonares suman una superficie de intercambio de 70 m² — medio campo de tenis empaquetado en dos pulmones.","El diafragma, el músculo principal de la respiración, es el único músculo esquelético que funciona automáticamente las 24 horas del día."]
  },
  'b12': {
    fr:["Les ongles poussent plus vite en été qu'en hiver — la chaleur et la lumière stimulent la circulation sanguine dans les doigts.","Il faut environ 6 mois pour qu'un ongle de main se renouvelle entièrement, et 12 à 18 mois pour un ongle de pied.","Les ongles sont constitués de kératine, la même protéine que les cheveux, les cornes de rhinocéros et les plumes d'oiseaux."],
    en:["Nails grow faster in summer than winter — heat and light stimulate blood circulation in fingers.","It takes about 6 months for a fingernail to fully regrow, and 12 to 18 months for a toenail.","Nails are made of keratin, the same protein as hair, rhino horns, and bird feathers."],
    es:["Las uñas crecen más rápido en verano que en invierno — el calor y la luz estimulan la circulación sanguínea en las extremidades.","Las uñas de las manos crecen unos 3,5 mm al mes, el doble que las de los pies — y la uña del dedo medio crece más rápido.","Las uñas están hechas de queratina, la misma proteína que el pelo, los cuernos de rinoceronte y las plumas de ave."]
  },
  'b13': {
    fr:["L'odorat est le sens le plus étroitement lié à la mémoire — une odeur peut déclencher un souvenir vieux de plusieurs décennies en un instant.","Les humains peuvent détecter la géosmine (odeur de pluie) à une concentration de 5 parties par trillion — nous y sommes plus sensibles que les requins au sang.","Chaque personne a une odeur unique, déterminée par son ADN — les chiens policiers exploitent cette signature pour retrouver des individus."],
    en:["Smell is the sense most closely linked to memory — a scent can trigger a decades-old memory in an instant.","Humans can detect geosmin (rain smell) at 5 parts per trillion — we're more sensitive to it than sharks are to blood.","Each person has a unique scent determined by their DNA — police dogs exploit this signature to track individuals."],
    es:["El olfato está directamente conectado al sistema límbico (emociones y memoria), sin pasar por el tálamo — un atajo neuronal único entre los sentidos.","Un olor puede desencadenar un recuerdo vívido e involuntario décadas después — un fenómeno conocido como efecto Proust.","Los humanos pueden distinguir más de un billón de olores diferentes — una capacidad muy superior a lo que se creía antes de un estudio de 2014."]
  },
  'b14': {
    fr:["Le corps humain contient aussi assez de carbone pour fabriquer 900 crayons, et assez de phosphore pour 2 200 allumettes.","Le fer est si vital que le corps le recycle intensivement — quand un globule rouge meurt après 120 jours, son fer est immédiatement réutilisé.","L'anémie touche environ 30 % de la population mondiale — c'est la carence nutritionnelle la plus répandue sur Terre."],
    en:["The human body also contains enough carbon for 900 pencils, and enough phosphorus for 2,200 matches.","Iron is so vital the body intensively recycles it — when a red blood cell dies after 120 days, its iron is immediately reused.","Anemia affects about 30% of the world population — it's the most common nutritional deficiency on Earth."],
    es:["El cuerpo humano contiene suficiente carbono para fabricar 900 lápices, suficiente fósforo para 2 200 cerillas y suficiente hierro para un clavo.","El valor de los elementos químicos del cuerpo (oxígeno, carbono, hidrógeno, nitrógeno, calcio, fósforo) es de apenas unos pocos euros al precio de mercado.","Sin embargo, el valor de las moléculas organizadas (ADN, proteínas, células) es incalculable — la organización lo es todo en biología."]
  },
  'b15': {
    fr:["Les ostéoclastes détruisent l'os ancien tandis que les ostéoblastes en construisent du neuf — ce remodelage permet aux os de se renforcer là où ils sont le plus sollicités.","La densité osseuse atteint son pic vers 30 ans — après quoi elle diminue lentement, d'où l'importance de l'exercice physique tôt dans la vie.","L'os spongieux à l'intérieur des os est organisé exactement comme les arches de la Tour Eiffel — Gustave Eiffel s'est d'ailleurs inspiré de l'anatomie osseuse."],
    en:["Osteoclasts destroy old bone while osteoblasts build new bone — this remodeling allows bones to strengthen where they're most stressed.","Bone density peaks around age 30 — after which it slowly decreases, hence the importance of exercise early in life.","The spongy bone inside bones is organized exactly like the arches of the Eiffel Tower — Gustave Eiffel was actually inspired by bone anatomy."],
    es:["Los osteoclastos destruyen el hueso viejo y los osteoblastos construyen hueso nuevo — un ciclo que renueva el esqueleto entero cada 7-10 años.","Este remodelado permite al hueso adaptarse a las cargas mecánicas: los huesos que soportan más peso se vuelven más densos (ley de Wolff).","El ejercicio estimula a los osteoblastos, mientras que la inactividad los inhibe — por eso los astronautas y las personas sedentarias pierden masa ósea."]
  },
  'b16': {
    fr:["Même les vrais jumeaux ont des empreintes digitales différentes — la génétique ne détermine que le type général de motif.","Il existe trois types principaux de motifs : boucles (65 % des gens), tourbillons (30 %) et arcs (5 %).","Les koalas sont les seuls autres animaux avec des empreintes digitales quasi identiques aux nôtres — au point de parfois tromper les experts."],
    en:["Even identical twins have different fingerprints — genetics only determines the general pattern type.","There are three main pattern types: loops (65% of people), whorls (30%), and arches (5%).","Koalas are the only other animals with fingerprints nearly identical to ours — sometimes fooling experts."],
    es:["Incluso los gemelos idénticos tienen huellas dactilares diferentes — la genética define el patrón general pero los detalles dependen de factores aleatorios en el útero.","Las huellas se forman entre las semanas 10 y 17 de gestación por la interacción entre la presión del líquido amniótico y el crecimiento de la piel.","La probabilidad de que dos personas tengan huellas idénticas es de 1 entre 64 000 millones — la base de la identificación forense desde 1892."]
  },
  'b17': {
    fr:["La majorité de ces cellules sont des globules rouges — ton corps en produit environ 2,4 millions par seconde.","Les cellules de la peau se renouvellent complètement toutes les 2 à 3 semaines — tu « changes de peau » environ 900 fois au cours de ta vie.","Paradoxalement, plus de la moitié des cellules de ton corps ne sont pas humaines — ce sont des bactéries, des virus et des champignons symbiotiques."],
    en:["Most of these cells are red blood cells — your body produces about 2.4 million per second.","Skin cells completely renew every 2 to 3 weeks — you 'change skin' about 900 times in your lifetime.","Paradoxically, more than half the cells in your body aren't human — they're symbiotic bacteria, viruses, and fungi."],
    es:["La mayoría de estas células son glóbulos rojos — tu cuerpo produce unos 200 000 millones de glóbulos rojos nuevos cada día.","Cada glóbulo rojo vive unos 120 días y recorre 300 km a través del sistema circulatorio antes de ser reciclado por el bazo.","Los glóbulos rojos no tienen núcleo (en los mamíferos): lo pierden durante la maduración para dejar más espacio a la hemoglobina."]
  },
  'b18': {
    fr:["L'émail dentaire est composé à 96 % de minéraux — principalement d'hydroxyapatite — ce qui en fait le tissu le plus minéralisé du corps.","Contrairement aux os, l'émail ne se régénère pas — une fois endommagé, il est perdu définitivement.","La salive protège tes dents en neutralisant les acides et en reminéralisant l'émail — tu en produis environ 1 litre par jour."],
    en:["Tooth enamel is 96% minerals — mainly hydroxyapatite — making it the most mineralized tissue in the body.","Unlike bones, enamel doesn't regenerate — once damaged, it's permanently lost.","Saliva protects your teeth by neutralizing acids and remineralizing enamel — you produce about 1 liter per day."],
    es:["El esmalte dental está compuesto en un 96 % de minerales — principalmente hidroxiapatita — y es el tejido más duro del cuerpo humano.","A diferencia de los huesos, el esmalte no se regenera: una vez dañado por caries o erosión, la pérdida es permanente.","El esmalte puede soportar fuerzas de mordida de hasta 70 kg por cm² — pero es frágil ante los ácidos de los alimentos y las bacterias."]
  },
  'b19': {
    fr:["Le nombre total de connexions synaptiques dans le cerveau est estimé à 100 000 milliards — plus que le nombre d'étoiles dans la Voie Lactée.","Chaque seconde, environ 1 million de nouvelles connexions synaptiques se forment dans le cerveau d'un bébé.","Les synapses inutilisées sont éliminées par un processus appelé « élagage synaptique » — le cerveau se spécialise en abandonnant les circuits non utilisés."],
    en:["The total number of synaptic connections in the brain is estimated at 100 trillion — more than the number of stars in the Milky Way.","Every second, about 1 million new synaptic connections form in a baby's brain.","Unused synapses are eliminated through 'synaptic pruning' — the brain specializes by abandoning unused circuits."],
    es:["El número total de conexiones sinápticas en el cerebro se estima en 100 billones — una complejidad que supera la de cualquier sistema artificial.","Cada sinapsis puede modularse (potenciación o depresión) en función de la experiencia — la base física del aprendizaje y la memoria.","El cerebro puede almacenar el equivalente de 2,5 petabytes de datos — unos 3 millones de horas de vídeo."]
  },
  'b20': {
    fr:["Le fémur est l'os le plus long et le plus solide du squelette — il représente environ un quart de la taille totale d'une personne.","Les os contiennent des cellules vivantes, des vaisseaux sanguins et des nerfs — ce sont des organes à part entière, pas de simples structures rigides.","La moelle osseuse produit environ 200 milliards de nouveaux globules rouges chaque jour."],
    en:["The femur is the longest and strongest bone in the skeleton — it accounts for about a quarter of a person's total height.","Bones contain living cells, blood vessels, and nerves — they're full organs, not just rigid structures.","Bone marrow produces about 200 billion new red blood cells every day."],
    es:["El fémur es el hueso más largo y sólido del esqueleto — representa aproximadamente un cuarto de la estatura total de una persona.","Puede soportar fuerzas de compresión de hasta 1 700 kg — más resistente que el hormigón armado por unidad de peso.","La médula ósea del fémur produce glóbulos rojos, blancos y plaquetas — es una fábrica de células sanguíneas."]
  },
  // === SPACE ===
  'sp1': {
    fr:["Vénus tourne aussi dans le sens inverse de la plupart des planètes — le Soleil s'y lève à l'ouest et se couche à l'est.","La pression atmosphérique à la surface de Vénus est 92 fois celle de la Terre — l'équivalent d'être à 900 mètres sous l'eau.","Avec ses pluies d'acide sulfurique et ses 465 °C en surface, Vénus est souvent surnommée la « jumelle infernale » de la Terre."],
    en:["Venus also rotates in the opposite direction of most planets — the Sun rises in the west and sets in the east.","Atmospheric pressure on Venus's surface is 92 times Earth's — equivalent to being 900 meters underwater.","With its sulfuric acid rain and 465°C surface, Venus is often called Earth's 'evil twin'."],
    es:["Venus tarda 243 días terrestres en completar una rotación sobre su eje, pero solo 225 días en orbitar el Sol — su día es más largo que su año.","Además, Venus gira en sentido retrógrado (de este a oeste), por lo que el Sol sale por el oeste y se pone por el este.","Las nubes de ácido sulfúrico de Venus reflejan tanta luz solar que es el planeta más brillante visto desde la Tierra, conocido como «lucero del alba» o «estrella vespertina»."]
  },
  'sp2': {
    fr:["Saturne possède au moins 146 lunes connues — plus que n'importe quelle autre planète du système solaire.","Ses anneaux sont principalement composés de morceaux de glace et de roche, allant de grains de sable à des blocs de la taille d'une maison.","Les anneaux de Saturne sont relativement jeunes — peut-être seulement 100 millions d'années — et pourraient disparaître dans 300 millions d'années."],
    en:["Saturn has at least 146 known moons — more than any other planet in the solar system.","Its rings are mainly composed of ice and rock chunks, ranging from sand grains to house-sized blocks.","Saturn's rings are relatively young — perhaps only 100 million years old — and could disappear in 300 million years."],
    es:["La densidad media de Saturno es de 0,687 g/cm³, inferior a la del agua (1 g/cm³), lo que teóricamente le permitiría flotar.","Sus famosos anillos están compuestos principalmente de hielo y roca, y se extienden hasta 282 000 km del planeta, pero tienen un grosor de apenas 10 metros.","Saturno posee al menos 146 lunas confirmadas — la más grande, Titán, tiene una atmósfera densa y lagos de metano líquido en su superficie."]
  },
  'sp3': {
    fr:["Le Soleil fusionne environ 620 millions de tonnes d'hydrogène en hélium chaque seconde au cœur de son noyau.","La surface du Soleil est couverte de cellules de convection appelées granules — chacune de la taille de la France — qui bouillonnent en permanence.","Le Soleil émet un « vent solaire » de particules chargées à 1,5 million de km/h qui crée les aurores boréales en frappant notre magnétosphère."],
    en:["The Sun fuses about 620 million tons of hydrogen into helium every second in its core.","The Sun's surface is covered with convection cells called granules — each the size of France — constantly churning.","The Sun emits a 'solar wind' of charged particles at 1.5 million km/h that creates auroras when hitting our magnetosphere."],
    es:["En el núcleo del Sol, los fotones son absorbidos y reemitidos tantas veces que tardan entre 10 000 y 170 000 años en alcanzar la superficie.","Este proceso se llama «camino aleatorio» (random walk): cada fotón recorre una distancia microscópica antes de ser absorbido por otro átomo.","Una vez en la superficie, la luz viaja en línea recta y tarda solo 8 minutos y 20 segundos en llegar a la Tierra, recorriendo 150 millones de kilómetros."]
  },
  'sp4': {
    fr:["Voyager 1 transporte un disque d'or contenant des sons et images de la Terre, destiné à toute civilisation extraterrestre qui la trouverait.","Le signal radio de Voyager 1 met plus de 22 heures pour atteindre la Terre — et il est 10 milliards de fois plus faible qu'un signal de téléphone portable.","Voyager 1 a quitté l'héliosphère en 2012, devenant le premier objet humain à atteindre l'espace interstellaire."],
    en:["Voyager 1 carries a golden record with sounds and images of Earth, intended for any extraterrestrial civilization that might find it.","Voyager 1's radio signal takes over 22 hours to reach Earth — and is 10 billion times weaker than a cell phone signal.","Voyager 1 left the heliosphere in 2012, becoming the first human-made object to reach interstellar space."],
    es:["La Voyager 1, lanzada el 5 de septiembre de 1977, es el objeto fabricado por el ser humano más lejano de la Tierra, a más de 24 000 millones de km del Sol.","Lleva a bordo un disco dorado con sonidos, música e imágenes de la Tierra, concebido como mensaje para posibles civilizaciones extraterrestres.","A pesar de la distancia, sigue comunicándose con la Tierra: sus señales de radio, viajando a la velocidad de la luz, tardan más de 22 horas en llegar."]
  },
  'sp5': {
    fr:["Olympus Mons est un volcan bouclier — sa pente est si douce qu'en se tenant à sa base, on ne verrait pas le sommet à l'horizon.","Mars n'a pas de tectonique des plaques, ce qui a permis au magma de s'empiler au même endroit pendant des millions d'années.","La caldeira au sommet d'Olympus Mons mesure 85 km de large — assez grande pour contenir la ville de Paris."],
    en:["Olympus Mons is a shield volcano — its slope is so gentle that standing at its base, you couldn't see the summit on the horizon.","Mars has no plate tectonics, allowing magma to pile up in the same spot for millions of years.","The caldera at the top of Olympus Mons is 85 km wide — large enough to contain the city of Paris."],
    es:["El Olympus Mons es un volcán escudo de 21,9 km de altura y 600 km de diámetro — su base cubriría la totalidad de Francia.","Su enorme tamaño se explica por la ausencia de tectónica de placas en Marte: el punto caliente volcánico permaneció fijo durante millones de años, acumulando lava.","A pesar de su altura, la pendiente del Olympus Mons es tan suave (5°) que un observador en su base no podría ver la cima — quedaría oculta por la curvatura del horizonte."]
  },
  'sp6': {
    fr:["Mars possède aussi des tempêtes de poussière qui peuvent couvrir la planète entière pendant des mois, bloquant la lumière du Soleil.","Les calottes polaires de Mars contiennent assez de glace d'eau pour couvrir toute la planète d'une couche de 11 mètres si elle fondait.","La température sur Mars peut chuter à -140 °C aux pôles en hiver — mais atteindre 20 °C à l'équateur en été."],
    en:["Mars also has dust storms that can cover the entire planet for months, blocking sunlight.","Mars's polar ice caps contain enough water ice to cover the whole planet in an 11-meter layer if melted.","Temperatures on Mars can drop to -140°C at the poles in winter — but reach 20°C at the equator in summer."],
    es:["La nieve de CO₂ en Marte fue detectada por la sonda Mars Reconnaissance Orbiter en 2012 mediante su espectrómetro infrarrojo.","Las partículas de hielo seco se subliman (pasan de sólido a gas) antes de tocar el suelo, creando un fenómeno de «nieve fantasma» única en el sistema solar.","Los polos marcianos están cubiertos por casquetes permanentes de hielo de agua y CO₂ cuyo avance y retroceso estacional es visible desde la Tierra con un telescopio potente."]
  },
  'sp7': {
    fr:["Il y a 4,5 milliards d'années, la Lune était 15 fois plus proche de la Terre — les marées étaient des murs d'eau de plusieurs kilomètres.","L'éloignement de la Lune ralentit aussi la rotation de la Terre — les journées s'allongent de 2,3 millisecondes par siècle.","La face cachée de la Lune n'est pas toujours sombre — elle reçoit autant de lumière que la face visible, mais on ne la voit jamais depuis la Terre."],
    en:["4.5 billion years ago, the Moon was 15 times closer to Earth — tides were walls of water several kilometers high.","The Moon's retreat also slows Earth's rotation — days are lengthening by 2.3 milliseconds per century.","The far side of the Moon isn't always dark — it receives as much light as the near side, but we never see it from Earth."],
    es:["La Luna se aleja de la Tierra a un ritmo de 3,8 cm por año debido a las fuerzas de marea que transfieren energía rotacional de la Tierra a la órbita lunar.","Hace 4 500 millones de años, la Luna estaba mucho más cerca y los días terrestres duraban solo 5 horas — las mareas eran gigantescas.","Dentro de unos 600 millones de años, la Luna estará tan lejos que no cubrirá completamente el disco solar, poniendo fin a los eclipses totales de Sol."]
  },
  'sp8': {
    fr:["La molécule responsable est le formiate d'éthyle — elle donne aussi leur arôme aux framboises et se trouve dans le rhum.","Au centre de la Voie Lactée, il y aurait assez d'alcool éthylique gazeux pour remplir 400 trillions de verres de bière.","Les astronautes décrivent souvent l'odeur de l'espace (sur leurs combinaisons) comme celle du steak grillé ou de la poudre à canon."],
    en:["The responsible molecule is ethyl formate — it also gives raspberries their aroma and is found in rum.","At the center of the Milky Way, there's enough gaseous ethyl alcohol to fill 400 trillion pints of beer.","Astronauts often describe the smell of space (on their suits) as grilled steak or gunpowder."],
    es:["En 2009, astrónomos del Instituto Max Planck detectaron etil formiato y ácido cianhídrico en la nube Sagitario B2, cerca del centro de la Vía Láctea.","El etil formiato es la molécula responsable del aroma de las frambuesas y del sabor del ron — de ahí la curiosa descripción del «olor del espacio».","En realidad, el espacio interplanetario tiene otro olor: los astronautas describen un olor metálico a carne quemada en sus trajes tras las caminatas espaciales, causado por átomos de oxígeno atómico."]
  },
  'sp9': {
    fr:["Les étoiles à neutrons tournent si vite que certaines font 700 rotations par seconde — les pulsars les plus rapides connus.","Une étoile à neutrons a un champ magnétique un trillion de fois plus puissant que celui de la Terre.","Si tu laissais tomber un objet d'un mètre au-dessus d'une étoile à neutrons, il toucherait la surface en une microseconde — à une vitesse de 7 millions de km/h."],
    en:["Neutron stars spin so fast some make 700 rotations per second — the fastest known pulsars.","A neutron star has a magnetic field a trillion times stronger than Earth's.","If you dropped an object from 1 meter above a neutron star, it would hit the surface in a microsecond — at 7 million km/h."],
    es:["Las estrellas de neutrones se forman cuando una estrella masiva colapsa al final de su vida, comprimiendo su núcleo hasta una densidad inimaginable.","Una cucharadita de su materia pesaría alrededor de mil millones de toneladas — equivalente al peso del monte Fuji concentrado en un volumen diminuto.","Algunas estrellas de neutrones giran a velocidades vertiginosas: los púlsares más rápidos completan más de 700 rotaciones por segundo."]
  },
  'sp10': {
    fr:["Si le Soleil était remplacé par un trou noir de même masse, les planètes continueraient à orbiter exactement de la même manière.","Le temps ralentit à l'approche d'un trou noir — pour un observateur lointain, un objet tombant dedans semblerait se figer indéfiniment au bord.","Le plus grand trou noir connu, TON 618, a une masse de 66 milliards de soleils et un diamètre 11 fois celui de notre système solaire."],
    en:["If the Sun were replaced by a black hole of the same mass, the planets would continue orbiting exactly the same way.","Time slows near a black hole — to a distant observer, an object falling in would appear to freeze forever at the edge.","The largest known black hole, TON 618, has a mass of 66 billion suns and a diameter 11 times our solar system."],
    es:["Los agujeros negros son regiones del espacio-tiempo donde la gravedad es tan intensa que nada, ni siquiera la luz, puede escapar una vez cruzado el horizonte de sucesos.","En 2019, el proyecto Event Horizon Telescope capturó la primera imagen directa de un agujero negro, situado en el centro de la galaxia M87, a 55 millones de años luz.","Según la relatividad general, el tiempo se ralentiza cerca de un agujero negro: un observador externo vería a un objeto caer cada vez más lento, sin cruzar nunca el horizonte."]
  },
  'sp11': {
    fr:["L'océan d'Europe contient environ deux fois plus d'eau que tous les océans de la Terre réunis.","La glace d'Europe se fissure et se renouvelle en permanence, ce qui suggère une activité géologique intense sous la surface.","La NASA prévoit une mission dédiée, Europa Clipper, pour survoler cette lune et analyser les geysers d'eau qui jaillissent à travers la glace."],
    en:["Europa's ocean contains about twice as much water as all of Earth's oceans combined.","Europa's ice constantly cracks and renews, suggesting intense geological activity beneath the surface.","NASA plans a dedicated mission, Europa Clipper, to fly by this moon and analyze water geysers erupting through the ice."],
    es:["La Estación Espacial Internacional orbita la Tierra a unos 408 km de altitud y viaja a 27 600 km/h, completando una vuelta cada 90 minutos.","Sus tripulantes experimentan 16 amaneceres y 16 atardeceres cada día — la ISS es visible a simple vista como un punto luminoso que cruza el cielo nocturno.","La ISS es el objeto más caro jamás construido por la humanidad: su coste total supera los 150 000 millones de dólares, financiados por 15 países."]
  },
  'sp12': {
    fr:["Jupiter à elle seule représente 0,1 % de la masse restante — toutes les autres planètes, lunes et astéroïdes se partagent les 0,04 % restants.","Le Soleil perd environ 4 millions de tonnes de masse chaque seconde en convertissant de l'hydrogène en énergie.","Si le Soleil avait la taille d'une porte d'entrée, la Terre serait de la taille d'une pièce de monnaie."],
    en:["Jupiter alone accounts for 0.1% of the remaining mass — all other planets, moons, and asteroids share the remaining 0.04%.","The Sun loses about 4 million tons of mass every second by converting hydrogen into energy.","If the Sun were the size of a front door, Earth would be the size of a coin."],
    es:["Un año-luz equivale a unos 9,46 billones de kilómetros — la distancia que la luz recorre en un año viajando a 300 000 km/s.","La estrella más cercana al Sol, Próxima Centauri, está a 4,24 años-luz. Con la tecnología actual, un viaje hasta allí tomaría más de 70 000 años.","El universo observable tiene un radio de unos 46 000 millones de años-luz, pero su tamaño real podría ser infinito — solo podemos ver la luz que ha tenido tiempo de llegar hasta nosotros."]
  },
  'sp13': {
    fr:["La nébuleuse du Boomerang se refroidit par l'expansion rapide de ses gaz — un effet similaire à celui d'une bombe aérosol qui devient froide en se vidant.","Elle se trouve à 5 000 années-lumière de la Terre dans la constellation du Centaure.","Même le rayonnement fossile du Big Bang, à -270 °C, est plus chaud que cette nébuleuse."],
    en:["The Boomerang Nebula cools through the rapid expansion of its gases — similar to how an aerosol can gets cold when emptying.","It's located 5,000 light-years from Earth in the Centaurus constellation.","Even the cosmic microwave background from the Big Bang, at -270°C, is warmer than this nebula."],
    es:["La nébulosa del Boomerang, situada a 5 000 años-luz de la Tierra, tiene una temperatura de −272 °C, apenas un grado por encima del cero absoluto.","Esta temperatura extrema se debe a la rápida expansión del gas que emite la estrella central, un fenómeno similar al enfriamiento que se produce al abrir una lata de aerosol.","El cero absoluto (−273,15 °C o 0 kelvin) es inalcanzable según las leyes de la termodinámica, pero los científicos han logrado enfriar átomos hasta una milmillonésima de grado por encima."]
  },
  'sp14': {
    fr:["La collision ne détruira probablement aucune étoile — les distances entre elles sont si grandes que les galaxies passeront l'une à travers l'autre.","Le Soleil sera encore en vie lors de cette fusion, mais la Terre sera déjà inhabitable depuis des milliards d'années à cause de l'expansion solaire.","Andromède s'approche de nous à 110 km par seconde — c'est l'une des rares galaxies à se rapprocher au lieu de s'éloigner."],
    en:["The collision probably won't destroy any stars — distances between them are so great the galaxies will pass through each other.","The Sun will still be alive during this merger, but Earth will have been uninhabitable for billions of years due to solar expansion.","Andromeda approaches us at 110 km per second — it's one of the rare galaxies moving toward us instead of away."],
    es:["Las estrellas de neutrones tienen un diámetro de apenas 20 km pero una masa equivalente a 1,4 veces la del Sol.","Su campo magnético es billones de veces más intenso que el de la Tierra — suficiente para reorganizar los átomos y crear una superficie de hierro cristalino.","Los magnetares, un tipo especial de estrella de neutrones, emiten destellos de rayos gamma tan potentes que uno situado a medio camino de la Vía Láctea podría dañar la capa de ozono terrestre."]
  },
  'sp15': {
    fr:["La photo a nécessité 8 télescopes répartis sur 4 continents, formant un télescope virtuel de la taille de la Terre.","Le trou noir photographié, M87*, est situé à 55 millions d'années-lumière et a une masse de 6,5 milliards de soleils.","Les données étaient si volumineuses qu'elles ont dû être transportées par avion sur des disques durs — internet n'était pas assez rapide."],
    en:["The photo required 8 telescopes across 4 continents, forming a virtual telescope the size of Earth.","The photographed black hole, M87*, is 55 million light-years away with a mass of 6.5 billion suns.","The data was so massive it had to be flown on hard drives by plane — the internet wasn't fast enough."],
    es:["La Voyager 1 entró en el espacio interestelar en agosto de 2012, convirtiéndose en el primer objeto humano en abandonar la heliosfera.","Su fuente de energía, un generador termoeléctrico de radioisótopos de plutonio-238, pierde potencia gradualmente — los científicos estiman que dejará de funcionar hacia 2025-2030.","La placa dorada a bordo incluye saludos en 55 idiomas, sonidos de la naturaleza, música de Bach, Mozart y Chuck Berry, y 116 imágenes codificadas de la Tierra."]
  },
  'sp16': {
    fr:["Pluton possède aussi des montagnes de glace d'eau de 3 500 mètres de haut, comparables aux Alpes terrestres.","Sa plus grande lune, Charon, est si grosse par rapport à Pluton que les deux corps tournent autour d'un point situé dans l'espace entre eux.","Pluton met 248 années terrestres pour faire un tour complet autour du Soleil — elle n'a pas encore achevé une orbite depuis sa découverte en 1930."],
    en:["Pluto also has water ice mountains 3,500 meters high, comparable to the terrestrial Alps.","Its largest moon, Charon, is so large relative to Pluto that both bodies orbit a point in the space between them.","Pluto takes 248 Earth years to orbit the Sun — it hasn't completed one orbit since its discovery in 1930."],
    es:["El Olympus Mons entró en erupción por última vez hace unos 25 millones de años, pero los científicos no descartan que pueda estar aún activo en su interior.","Su caldera, de 80 km de ancho, contiene seis cráteres superpuestos formados por erupciones sucesivas a lo largo de millones de años.","La baja gravedad de Marte (38 % de la terrestre) es la razón principal por la que las montañas marcianas pueden alcanzar alturas imposibles en la Tierra."]
  },
  'sp17': {
    fr:["La Lune est le seul autre corps céleste où des êtres humains ont marché — 12 personnes au total, toutes entre 1969 et 1972.","La poussière lunaire est extrêmement abrasive — elle a usé les combinaisons des astronautes et a même endommagé leurs poumons.","Il n'y a pas de vent sur la Lune, donc les empreintes de pas laissées par les astronautes d'Apollo pourraient durer des millions d'années."],
    en:["The Moon is the only other celestial body where humans have walked — 12 people total, all between 1969 and 1972.","Lunar dust is extremely abrasive — it wore down astronauts' suits and even damaged their lungs.","There's no wind on the Moon, so the footprints left by Apollo astronauts could last millions of years."],
    es:["La Luna tarda exactamente el mismo tiempo en rotar sobre su eje que en orbitar la Tierra (27,3 días), un fenómeno llamado rotación síncrona.","Esta sincronización no es una coincidencia: las fuerzas de marea terrestres frenaron gradualmente la rotación lunar hasta bloquearla en su posición actual.","El lado oculto de la Luna, fotografiado por primera vez por la sonda soviética Luna 3 en 1959, tiene una corteza más gruesa y muchos menos mares (llanuras de lava) que el lado visible."]
  },
  'sp18': {
    fr:["La Grande Tache Rouge a rétréci de 50 % depuis les premières observations au XIXe siècle — les scientifiques ne savent pas si elle finira par disparaître.","Les vents à l'intérieur de la tempête atteignent 680 km/h — bien plus rapides que n'importe quel ouragan terrestre.","Jupiter possède au moins 95 lunes connues, dont 4 « galiléennes » découvertes par Galilée en 1610."],
    en:["The Great Red Spot has shrunk 50% since first observations in the 19th century — scientists don't know if it will eventually disappear.","Winds inside the storm reach 680 km/h — far faster than any hurricane on Earth.","Jupiter has at least 95 known moons, including 4 'Galilean' moons discovered by Galileo in 1610."],
    es:["La Gran Mancha Roja de Júpiter es un anticiclón persistente observado desde al menos 1665 — ha durado más que cualquier fenómeno meteorológico terrestre.","Su tamaño ha disminuido durante el último siglo: pasó de poder contener 3 Tierras a apenas 1,3 en la actualidad, aunque su viento sigue soplando a más de 640 km/h.","Júpiter no tiene superficie sólida: bajo las nubes hay capas de hidrógeno gaseoso, líquido y finalmente hidrógeno metálico a presiones de millones de atmósferas."]
  },
  'sp19': {
    fr:["Si tu pouvais conduire à travers les anneaux à 100 km/h, il te faudrait environ 280 000 ans pour traverser leur diamètre complet.","Les anneaux sont divisés en plusieurs bandes séparées par des lacunes, la plus célèbre étant la division de Cassini, large de 4 800 km.","La sonde Cassini a plongé entre Saturne et ses anneaux avant de se désintégrer dans l'atmosphère de la planète en 2017 — un finale spectaculaire."],
    en:["If you could drive through the rings at 100 km/h, it would take about 280,000 years to cross their full diameter.","The rings are divided into several bands separated by gaps, the most famous being the Cassini Division, 4,800 km wide.","The Cassini probe dove between Saturn and its rings before disintegrating in the planet's atmosphere in 2017 — a spectacular finale."],
    es:["Se estima que el universo observable contiene unas 2 billones (2 × 10¹²) de galaxias, cada una con miles de millones de estrellas.","El número total de estrellas ronda los 10²⁴ (un cuatrillón), mientras que los granos de arena de la Tierra se estiman en unos 7,5 × 10¹⁸.","A pesar de estas cifras vertiginosas, el universo está compuesto en un 99,9999 % de vacío — la materia es una excepción extraordinariamente rara."]
  },
  'sp20': {
    fr:["En 2022, la NASA a transformé les données de pression d'un trou noir en ondes sonores audibles — un bourdonnement grave 57 octaves sous le do médian.","Dans l'atmosphère dense de Vénus, le son se propagerait différemment — ta voix y serait plus grave et plus lente.","Le premier son enregistré sur une autre planète a été capturé par le rover Perseverance sur Mars en 2021 — un léger bourdonnement de vent."],
    en:["In 2022, NASA converted pressure data from a black hole into audible sound — a deep hum 57 octaves below middle C.","In Venus's dense atmosphere, sound would travel differently — your voice would be deeper and slower.","The first sound recorded on another planet was captured by the Perseverance rover on Mars in 2021 — a faint wind hum."],
    es:["El sonido necesita un medio material (aire, agua, metal) para propagarse — en el vacío del espacio, no hay moléculas que puedan transmitir las ondas.","Sin embargo, en 2022 la NASA publicó una «sonificación» de datos del telescopio Chandra: ondas de presión en el gas caliente del cúmulo de Perseo, traducidas a frecuencias audibles.","Las nebulosas y los cúmulos de gas sí transmiten vibraciones, pero a frecuencias tan bajas (un Si bemol, 57 octavas por debajo del do central) que ningún oído humano podría detectarlas."]
  },
  // === POSITIVE ===
  'p1': {
    fr:["La tortue verte peut parcourir plus de 2 000 km pour migrer entre ses zones d'alimentation et de ponte.","Les efforts de protection des plages de nidification ont été déterminants — dans certaines régions, le nombre de nids a quadruplé en 20 ans.","Elle peut vivre jusqu'à 80 ans et peser plus de 200 kg — c'est l'une des plus grandes espèces de tortues marines."],
    en:["The green sea turtle can travel over 2,000 km migrating between feeding and nesting areas.","Protection of nesting beaches was decisive — in some regions, nest numbers quadrupled in 20 years.","It can live up to 80 years and weigh over 200 kg — one of the largest sea turtle species."],
    es:["La tortuga verde puede recorrer más de 2 000 km para migrar entre sus zonas de alimentación y sus playas de anidación.","Los programas de conservación han duplicado el número de nidos en muchas playas protegidas — una recuperación lenta pero real.","Las tortugas marinas son indicadores de la salud de los océanos: su recuperación beneficia a todo el ecosistema marino."]
  },
  'p2': {
    fr:["L'énergie solaire a été la source d'électricité qui a connu la plus forte croissance en 2024, avec une augmentation de 29 % par rapport à l'année précédente.","Le Danemark a produit 84 % de son électricité à partir d'éoliennes en janvier 2024 — un record mondial.","Le coût des batteries lithium-ion a chuté de 97 % depuis 1991, rendant le stockage d'énergie renouvelable enfin compétitif."],
    en:["Solar energy was the fastest-growing electricity source in 2024, with a 29% increase over the previous year.","Denmark produced 84% of its electricity from wind turbines in January 2024 — a world record.","The cost of lithium-ion batteries has dropped 97% since 1991, making renewable energy storage finally competitive."],
    es:["La energía solar fue la fuente de electricidad con mayor crecimiento en la última década, superando a todas las demás fuentes combinadas.","El coste del kilovatio-hora solar cayó un 89 % entre 2010 y 2023 — más barato que el carbón, el gas y la nuclear en la mayoría de los mercados.","En 2023, la capacidad solar mundial superó los 1 200 GW — equivalente a más de 1 000 reactores nucleares."]
  },
  'p3': {
    fr:["Les pots catalytiques, obligatoires sur les voitures depuis les années 1990, ont éliminé plus de 90 % des émissions toxiques des gaz d'échappement.","La qualité de l'air à Londres est aujourd'hui meilleure qu'à n'importe quel moment depuis le Moyen Âge.","Les zones à faibles émissions dans les grandes villes européennes ont réduit les particules fines de 15 à 30 % en quelques années seulement."],
    en:["Catalytic converters, mandatory on cars since the 1990s, eliminated over 90% of toxic exhaust emissions.","London's air quality is now better than at any point since the Middle Ages.","Low emission zones in major European cities reduced fine particles by 15-30% in just a few years."],
    es:["Los catalizadores, obligatorios en los coches desde los años 1990, han reducido las emisiones de CO, NOx e hidrocarburos en más del 90 %.","La calidad del aire en las grandes ciudades occidentales ha mejorado drásticamente: el plomo en el aire bajó un 99 % desde la prohibición de la gasolina con plomo.","La contaminación atmosférica sigue siendo un problema global: 7 millones de muertes prematuras al año según la OMS — pero la tendencia es a la mejora."]
  },
  'p4': {
    fr:["Le « trou » de la couche d'ozone au-dessus de l'Antarctique diminue régulièrement et devrait se refermer complètement d'ici 2066.","Le Protocole de Montréal de 1987 est considéré comme le traité environnemental le plus réussi de l'histoire.","Sans cette action, les radiations UV auraient rendu les cultures agricoles impossibles dans de nombreuses régions d'ici 2060."],
    en:["The ozone 'hole' over Antarctica is steadily shrinking and should fully close by 2066.","The 1987 Montreal Protocol is considered the most successful environmental treaty in history.","Without this action, UV radiation would have made farming impossible in many regions by 2060."],
    es:["El agujero de la capa de ozono sobre la Antártida disminuye regularmente desde la prohibición de los CFC por el Protocolo de Montreal (1987).","Los científicos estiman que la capa de ozono se recuperará completamente hacia 2066 sobre la Antártida y antes en otras regiones.","Es la demostración más clara de que la cooperación internacional puede resolver problemas ambientales globales."]
  },
  'p5': {
    fr:["Les filtres à particules sur les moteurs diesel ont été le principal facteur de cette baisse spectaculaire.","Paris a réduit le trafic automobile de 45 % dans son centre-ville entre 2010 et 2024 grâce aux zones piétonnes et pistes cyclables.","Les capteurs de qualité de l'air connectés permettent désormais aux citoyens de suivre en temps réel la pollution dans leur quartier."],
    en:["Particulate filters on diesel engines were the main factor behind this spectacular decline.","Paris reduced car traffic by 45% in its city center between 2010 and 2024 through pedestrian zones and bike lanes.","Connected air quality sensors now allow citizens to monitor pollution in their neighborhood in real time."],
    es:["Los filtros de partículas en los motores diésel han sido el principal factor de reducción de las emisiones de partículas finas en Europa.","Las zonas de bajas emisiones (ZBE) en ciudades como Madrid, Barcelona, París y Londres han acelerado la renovación del parque automovilístico.","La transición al vehículo eléctrico promete eliminar las emisiones directas del transporte urbano — el sector responsable del 25 % de las emisiones de CO₂."]
  },
  'p6': {
    fr:["La Chine et l'Inde sont les deux pays qui ont le plus contribué à ce verdissement, principalement grâce aux programmes de reforestation.","Le satellite Landsat surveille la surface terrestre depuis 1972, fournissant 50 ans de données sur l'évolution de la végétation mondiale.","Les mangroves, plantées massivement en Asie du Sud-Est, ont augmenté de 8 000 km² en dix ans — elles protègent les côtes et absorbent 4 fois plus de CO₂ que les forêts classiques."],
    en:["China and India contributed most to this greening, mainly through reforestation programs.","The Landsat satellite has monitored Earth's surface since 1972, providing 50 years of data on global vegetation changes.","Mangroves, massively planted in Southeast Asia, increased by 8,000 km² in ten years — they protect coasts and absorb 4 times more CO₂ than regular forests."],
    es:["China e India son los dos países que más han contribuido al reverdecimiento del planeta en las últimas dos décadas, según datos de la NASA.","China ha plantado más de 66 000 millones de árboles desde 1978 mediante el programa de la Gran Muralla Verde.","La India plantó 220 millones de árboles en un solo día en 2019 — un récord mundial de reforestación coordinada."]
  },
  'p7': {
    fr:["La centrale de Ratcliffe-on-Soar, la dernière du pays, a fermé ses portes le 30 septembre 2024 après 57 ans de service.","En 1990, le charbon représentait 80 % de l'électricité britannique — en 2024, il était à 0 %.","Le Royaume-Uni vise désormais un réseau électrique 100 % décarboné d'ici 2030."],
    en:["The Ratcliffe-on-Soar plant, the country's last, closed on September 30, 2024 after 57 years of service.","In 1990, coal represented 80% of British electricity — in 2024, it was 0%.","The UK now aims for a 100% decarbonized electricity grid by 2030."],
    es:["La central de Ratcliffe-on-Soar, la última central de carbón del Reino Unido, cerró el 30 de septiembre de 2024 tras 57 años de funcionamiento.","El Reino Unido pasó de generar el 40 % de su electricidad con carbón en 2012 al 0 % en 2024 — una transición energética espectacular.","El carbón fue el combustible de la Revolución Industrial británica — su abandono cierra un ciclo de 250 años."]
  },
  'p8': {
    fr:["La maladie de Huntington touche environ 1 personne sur 10 000 et est causée par une mutation génétique héréditaire unique.","La thérapie génique utilisée cible directement le gène défectueux HTT en empêchant la production de la protéine toxique.","C'est l'une des premières maladies neurodégénératives pour laquelle un traitement causal (et non symptomatique) est en développement avancé."],
    en:["Huntington's disease affects about 1 in 10,000 people and is caused by a single inherited genetic mutation.","The gene therapy used directly targets the defective HTT gene by preventing production of the toxic protein.","It's one of the first neurodegenerative diseases for which a causal (not symptomatic) treatment is in advanced development."],
    es:["La enfermedad de Huntington afecta a 1 de cada 10 000 personas y está causada por una mutación en el gen HTT del cromosoma 4.","Las terapias génicas experimentales (silenciamiento del gen mutado) ofrecen esperanza de tratamiento por primera vez en la historia de esta enfermedad.","Los ensayos clínicos de fase III están en curso — si tienen éxito, podrían transformar una sentencia en una condición manejable."]
  },
  'p9': {
    fr:["L'aire marine protégée couvre plus de 500 000 km² — soit presque la taille de la France métropolitaine.","La Polynésie française abrite la moitié des récifs coralliens de la France et plus de 1 000 espèces de poissons.","Ces zones protégées permettent aux populations de poissons de se reconstituer, bénéficiant aussi les pêcheurs des zones adjacentes."],
    en:["The marine protected area covers over 500,000 km² — almost the size of metropolitan France.","French Polynesia hosts half of France's coral reefs and over 1,000 fish species.","These protected zones allow fish populations to recover, also benefiting fishers in adjacent areas."],
    es:["El área marina protegida cubre más de 500 000 km² — casi la superficie de Francia — protegiendo ecosistemas marinos únicos.","Las AMP bien gestionadas aumentan la biomasa de peces un 446 % de media — beneficiando también a las pesquerías vecinas.","La meta del 30 % de océanos protegidos para 2030 (acuerdo COP15) requiere triplicar la superficie protegida actual."]
  },
  'p10': {
    fr:["La vaccination contre la rougeole a sauvé à elle seule plus de 56 millions de vies entre 2000 et 2021.","Les solutions de réhydratation orale, simples et peu coûteuses, ont été qualifiées de « plus grande avancée médicale du XXe siècle » par The Lancet.","Aujourd'hui, un enfant né dans un pays en développement a 14 fois plus de chances d'atteindre son 5e anniversaire qu'en 1950."],
    en:["Measles vaccination alone saved over 56 million lives between 2000 and 2021.","Oral rehydration solutions, simple and inexpensive, were called 'the greatest medical advance of the 20th century' by The Lancet.","Today, a child born in a developing country is 14 times more likely to reach their 5th birthday than in 1950."],
    es:["La vacunación contra el sarampión ha salvado más de 56 millones de vidas entre 2000 y 2021 — una de las intervenciones de salud pública más exitosas.","Antes de la vacuna (1963), el sarampión mataba a 2,6 millones de personas al año — hoy la cifra es inferior a 130 000.","Cada dólar invertido en vacunación contra el sarampión genera 44 dólares en beneficios económicos — la inversión sanitaria más rentable."]
  },
  'p11': {
    fr:["Les moustiquaires imprégnées d'insecticide coûtent moins de 2 € pièce et protègent une famille entière pendant 3 ans.","Le vaccin RTS,S contre le paludisme, approuvé par l'OMS en 2021, est le premier vaccin antiparasitaire au monde.","L'Afrique a réduit ses décès liés au paludisme de 50 % en 15 ans, sauvant des millions d'enfants de moins de 5 ans."],
    en:["Insecticide-treated bed nets cost less than €2 each and protect an entire family for 3 years.","The RTS,S malaria vaccine, approved by WHO in 2021, is the world's first antiparasitic vaccine.","Africa reduced malaria deaths by 50% in 15 years, saving millions of children under 5."],
    es:["Las mosquiteras impregnadas de insecticida cuestan menos de 2 € y protegen durante 3-5 años — una de las intervenciones sanitarias más eficientes del mundo.","Desde 2000, la mortalidad por malaria ha caído un 30 % gracias a las mosquiteras, los test rápidos y los tratamientos combinados.","La primera vacuna contra la malaria (RTS,S) fue aprobada en 2021 y una segunda (R21) en 2023 — un hito tras décadas de investigación."]
  },
  'p12': {
    fr:["En 2023, le monde a installé plus de panneaux solaires en un an que dans toute l'histoire cumulée jusqu'en 2016.","L'Inde a construit la plus grande ferme solaire du monde à Bhadla, couvrant 57 km² — la taille de Manhattan.","Une heure d'ensoleillement sur Terre produit théoriquement assez d'énergie pour alimenter la planète pendant un an."],
    en:["In 2023, the world installed more solar panels in one year than in all of history combined through 2016.","India built the world's largest solar farm in Bhadla, covering 57 km² — the size of Manhattan.","One hour of sunlight on Earth theoretically produces enough energy to power the planet for a year."],
    es:["En 2023, el mundo instaló más paneles solares en un año que en toda la historia anterior combinada — un crecimiento exponencial.","China lidera la instalación solar: añadió más de 200 GW en 2023, más que el resto del mundo junto.","El coste del panel solar cayó un 99 % desde 1976 — pasando de 106 $/vatio a menos de 0,20 $/vatio."]
  },
  'p13': {
    fr:["Dans les années 1960, il ne restait que 1 400 baleines à bosse dans l'Atlantique Nord — aujourd'hui on en compte plus de 80 000 dans le monde.","Leur chant complexe peut voyager sur des milliers de kilomètres sous l'eau et évolue d'année en année, comme une culture musicale.","Le tourisme d'observation des baleines génère aujourd'hui plus de revenus que l'ancienne industrie baleinière."],
    en:["In the 1960s, only 1,400 humpback whales remained in the North Atlantic — today there are over 80,000 worldwide.","Their complex songs can travel thousands of kilometers underwater and evolve year to year, like a musical culture.","Whale watching tourism now generates more revenue than the former whaling industry."],
    es:["En los años 1960, solo quedaban unas 1 400 ballenas jorobadas en el Atlántico — hoy son más de 25 000 gracias a la moratoria de caza de 1986.","La recuperación de las ballenas beneficia al ecosistema marino entero: sus heces fertilizan el fitoplancton, que absorbe CO₂ y produce oxígeno.","El turismo de observación de ballenas genera más de 2 000 millones de dólares al año — más que la caza de ballenas en su apogeo."]
  },
  'p14': {
    fr:["La Chine à elle seule a sorti plus de 800 millions de personnes de l'extrême pauvreté depuis 1980.","Le seuil d'extrême pauvreté est fixé par la Banque mondiale à 2,15 $ par jour — en dessous, la survie quotidienne est menacée.","L'accès au microcrédit dans les pays en développement a permis à des millions de femmes de lancer leur propre activité économique."],
    en:["China alone lifted over 800 million people out of extreme poverty since 1980.","The extreme poverty line is set by the World Bank at $2.15 per day — below which daily survival is threatened.","Access to microcredit in developing countries has enabled millions of women to start their own businesses."],
    es:["China sacó a más de 800 millones de personas de la pobreza extrema entre 1978 y 2020 — la mayor reducción de pobreza de la historia.","Las reformas económicas de Deng Xiaoping (desde 1978) transformaron China de una economía agraria a la segunda potencia mundial.","A nivel global, el porcentaje de personas en pobreza extrema pasó del 36 % en 1990 al 9 % en 2023."]
  },
  'p15': {
    fr:["La campagne d'éradication a duré 11 ans et a mobilisé des milliers de travailleurs sanitaires dans les régions les plus reculées du monde.","La variole tuait environ 300 millions de personnes par siècle — son éradication a probablement sauvé plus de vies que toute autre intervention médicale.","La poliomyélite pourrait être la prochaine maladie éradiquée — les cas ont diminué de 99,9 % depuis 1988."],
    en:["The eradication campaign lasted 11 years and mobilized thousands of health workers in the world's most remote regions.","Smallpox killed about 300 million people per century — its eradication probably saved more lives than any other medical intervention.","Polio could be the next disease eradicated — cases have decreased 99.9% since 1988."],
    es:["La campaña de erradicación de la viruela duró 11 años (1967-1977) y movilizó a miles de trabajadores sanitarios en todo el mundo.","El último caso natural de viruela fue registrado en Somalia en 1977 — la OMS declaró la erradicación en 1980.","Es la única enfermedad humana erradicada de la naturaleza — un logro que demuestra el poder de la vacunación a escala global."]
  },
  'p16': {
    fr:["L'Islande a été le premier pays européen à reboiser massivement — après avoir perdu 95 % de ses forêts depuis la colonisation viking.","En Éthiopie, 350 millions d'arbres ont été plantés en une seule journée le 29 juillet 2019 — un record mondial.","Les forêts urbaines réduisent la température locale de 2 à 8 °C en été et filtrent les polluants atmosphériques."],
    en:["Iceland was the first European country to massively reforest — after losing 95% of its forests since Viking colonization.","In Ethiopia, 350 million trees were planted in a single day on July 29, 2019 — a world record.","Urban forests reduce local temperatures by 2-8°C in summer and filter atmospheric pollutants."],
    es:["Islandia fue el primer país europeo en reforestar masivamente — tras perder el 95 % de sus bosques durante la colonización vikinga.","El Servicio Forestal islandés planta más de 3 millones de árboles al año, principalmente abedules y coníferas adaptadas al clima subártico.","La reforestación reduce la erosión del suelo, secuestra carbono y restaura la biodiversidad — beneficios que superan con creces la inversión."]
  },
  'p17': {
    fr:["Le dessalement de l'eau de mer fournit aujourd'hui de l'eau potable à plus de 300 millions de personnes dans le monde.","En Afrique subsaharienne, le nombre de points d'eau potable a doublé en 20 ans grâce à des forages et des pompes solaires.","Chaque dollar investi dans l'eau potable et l'assainissement génère un retour économique de 4 à 12 dollars."],
    en:["Seawater desalination now provides drinking water to over 300 million people worldwide.","In sub-Saharan Africa, the number of clean water points doubled in 20 years through boreholes and solar pumps.","Every dollar invested in clean water and sanitation generates an economic return of 4 to 12 dollars."],
    es:["La desalación de agua de mar abastece hoy a más de 300 millones de personas en el mundo, principalmente en Oriente Medio, norte de África y Australia.","El coste de la desalación ha caído un 60 % en 20 años gracias a las mejoras en las membranas de ósmosis inversa.","Israel obtiene el 80 % de su agua potable por desalación — un modelo para los países con estrés hídrico."]
  },
  'p18': {
    fr:["La Norvège est le leader mondial : 82 % des voitures neuves vendues en 2023 étaient électriques.","Les batteries de voitures électriques peuvent être recyclées et réutilisées comme stockage d'énergie domestique après leur vie automobile.","Un véhicule électrique émet 2 à 3 fois moins de CO₂ sur l'ensemble de sa vie qu'un véhicule thermique, même en comptant la fabrication de la batterie."],
    en:["Norway is the world leader: 82% of new cars sold in 2023 were electric.","Electric car batteries can be recycled and reused as home energy storage after their automotive life.","An EV emits 2-3 times less CO₂ over its lifetime than a combustion vehicle, even counting battery manufacturing."],
    es:["Noruega es líder mundial: el 82 % de los coches nuevos vendidos en 2023 eran eléctricos, gracias a incentivos fiscales y una red de recarga densa.","A nivel global, los vehículos eléctricos representaron el 18 % de las ventas de coches nuevos en 2023 — un crecimiento del 35 % respecto a 2022.","Las baterías de litio-ion han bajado un 90 % de precio desde 2010, acelerando la transición hacia la movilidad eléctrica."]
  },
  'p19': {
    fr:["Le panda géant est passé de « en danger » à « vulnérable » en 2016 grâce à 30 ans de conservation ciblée en Chine.","Le lynx ibérique, autrefois le félin le plus menacé au monde avec 94 individus en 2002, en compte aujourd'hui plus de 2 000.","Les programmes de reproduction en captivité ont sauvé le condor de Californie — il ne restait que 27 individus en 1987, contre plus de 500 aujourd'hui."],
    en:["The giant panda went from 'endangered' to 'vulnerable' in 2016 thanks to 30 years of targeted conservation in China.","The Iberian lynx, once the most endangered cat with 94 individuals in 2002, now numbers over 2,000.","Captive breeding programs saved the California condor — only 27 remained in 1987, compared to over 500 today."],
    es:["El panda gigante pasó de «en peligro» a «vulnerable» en 2016 gracias a 30 años de esfuerzos de conservación del gobierno chino.","La creación de 67 reservas naturales protegió el 66 % del hábitat del panda — más de 10 000 km² de bosque de bambú.","La población de pandas salvajes pasó de 1 114 en los años 1970 a más de 1 800 en 2023 — una recuperación lenta pero constante."]
  },
  'p20': {
    fr:["Le Programme alimentaire mondial (PAM) distribue chaque année des repas à plus de 150 millions de personnes dans 120 pays.","Les techniques d'agriculture de précision permettent de produire jusqu'à 30 % de nourriture en plus avec moins d'eau et d'engrais.","Le gaspillage alimentaire représente un tiers de la production mondiale — réduire ce gaspillage de moitié suffirait à nourrir 2 milliards de personnes supplémentaires."],
    en:["The World Food Programme (WFP) distributes meals to over 150 million people in 120 countries each year.","Precision farming techniques can produce up to 30% more food with less water and fertilizer.","Food waste accounts for a third of global production — halving this waste would be enough to feed 2 billion more people."],
    es:["El Programa Mundial de Alimentos (PMA) distribuye cada año comida a más de 150 millones de personas en 120 países.","El PMA recibió el Nobel de la Paz en 2020 por su lucha contra el hambre y su contribución a la paz en las zonas de conflicto.","Cada euro invertido en prevención del hambre genera 3,5 euros en beneficios económicos — la ayuda alimentaria es una inversión, no un gasto."]
  },
  // === ARTS ===
  'ar1':{fr:["Dalí vivait avec un ocelot apprivoisé nommé Babou qu'il emmenait partout, même au restaurant.","Son chef-d'œuvre La Persistance de la mémoire a été peint en moins de deux heures, inspiré par du camembert fondant au soleil.","Dalí a conçu le logo de la sucette Chupa Chups, toujours utilisé aujourd'hui."],en:["Dalí lived with a pet ocelot named Babou that he took everywhere, even to restaurants.","His masterpiece The Persistence of Memory was painted in under two hours, inspired by melting Camembert.","Dalí designed the Chupa Chups lollipop logo, still used today."],
    es:["La Mona Lisa mide apenas 77 × 53 cm — mucho más pequeña de lo que la mayoría imagina — y está protegida por un cristal antibalas en el Louvre.","Leonardo da Vinci trabajó en ella durante al menos cuatro años (1503-1507) y probablemente nunca la consideró terminada — se la llevó consigo a Francia.","La técnica del sfumato, que da al cuadro su característica suavidad, consiste en superponer decenas de capas translúcidas de pintura, cada una de apenas unas micras de espesor."]},
  'ar2':{fr:["La Joconde mesure seulement 77×53 cm — bien plus petite que ce que la plupart des visiteurs imaginent.","Plus de 6 millions de personnes tentent de la voir chaque année au Louvre, pour une moyenne de 15 secondes.","On ignore toujours si le modèle est Lisa Gherardini ou un autoportrait féminisé de Léonard."],en:["The Mona Lisa measures only 77×53 cm — much smaller than most visitors imagine.","Over 6 million people try to see it each year at the Louvre, for an average of 15 seconds.","It's still debated whether the model is Lisa Gherardini or a feminized self-portrait of Leonardo."],
    es:["La Capilla Sixtina fue pintada por Miguel Ángel entre 1508 y 1512, trabajando de pie sobre un andamio inclinado a 20 metros de altura.","Contrariamente al mito popular, Miguel Ángel no pintó tumbado boca arriba — trabajaba de pie con los brazos levantados, una postura que le causó graves problemas cervicales.","El techo contiene más de 300 figuras humanas y nueve escenas del Génesis — la más famosa, La Creación de Adán, se ha convertido en una de las imágenes más reproducidas del mundo."]},
  'ar3':{fr:["Hugo avait fait retirer tous ses meubles pour s'obliger à écrire debout sans distraction.","Les Misérables a été traduit dans plus de langues que n'importe quel autre roman français.","Le manuscrit a été vendu pour 4,1 millions d'euros en 2017 — un record pour un manuscrit français."],en:["Hugo had all furniture removed to force himself to write standing without distraction.","Les Misérables has been translated into more languages than any other French novel.","The manuscript sold for €4.1 million in 2017 — a record for a French manuscript."],
    es:["La Noche Estrellada fue pintada por Van Gogh en junio de 1889 desde su habitación en el asilo de Saint-Rémy-de-Provence, en plena crisis mental.","Los remolinos del cielo podrían representar la turbulencia atmosférica: matemáticos han demostrado que las espirales de Van Gogh siguen patrones de flujo turbulento con una precisión sorprendente.","Van Gogh vendió un solo cuadro en vida (El viñedo rojo) por 400 francos. Hoy, sus obras se cotizan en cientos de millones de dólares."]},
  'ar4':{fr:["Le film a été tourné dans la propre maison du réalisateur Oren Peli avec une caméra à 200 dollars.","Steven Spielberg aurait été si effrayé qu'il a renvoyé le DVD au studio dans un sac poubelle.","Le succès du film a lancé toute une vague de films d'horreur en found footage."],en:["The film was shot in director Oren Peli's own house with a $200 camera.","Spielberg was reportedly so scared he returned the DVD in a garbage bag.","The film's success launched an entire wave of found footage horror movies."],
    es:["El Guernica de Picasso (1937) denuncia el bombardeo de la ciudad vasca de Guernica durante la Guerra Civil Española por la aviación nazi e italiana.","Mide 3,49 × 7,77 metros y está pintado únicamente en blanco, negro y gris — los colores del duelo y de las fotografías de prensa de la época.","Picasso se negó a que el cuadro regresara a España mientras durara la dictadura franquista — el Guernica estuvo en el MoMA de Nueva York hasta 1981, seis años después de la muerte de Franco."]},
  'ar5':{fr:["Mozart est mort à 35 ans mais a laissé plus de 600 compositions.","Son Requiem est resté inachevé — la légende dit qu'un mystérieux étranger l'avait commandé anonymement.","Mozart pouvait mémoriser un morceau entier après une seule écoute et le reproduire note pour note."],en:["Mozart died at 35 but left over 600 compositions.","His Requiem remained unfinished — legend says a mysterious stranger anonymously commissioned it.","Mozart could memorize an entire piece after one hearing and reproduce it note for note."],
    es:["La arquitectura gótica se caracteriza por el arco ojival, la bóveda de crucería y los arbotantes, que permitieron construir catedrales de alturas sin precedentes.","Estas innovaciones estructurales trasladaron el peso de los muros a pilares externos, liberando las paredes para instalar enormes vidrieras que inundaban de luz el interior.","Notre-Dame de París, comenzada en 1163, tardó casi dos siglos en completarse — su aguja, añadida en el siglo XIX por Viollet-le-Duc, se derrumbó durante el incendio de 2019."]},
  'ar6':{fr:["Les couleurs étaient si vives que certains historiens comparent les temples grecs à des parcs d'attractions modernes.","La peinture a disparu à cause de l'érosion naturelle sur des millénaires.","Les artistes de la Renaissance ont pris ces statues blanches comme modèle, créant une esthétique qui a dominé l'art occidental."],en:["Colors were so vivid some historians compare Greek temples to modern theme parks.","The paint disappeared through natural erosion over millennia.","Renaissance artists took these white statues as models, creating an aesthetic that dominated Western art."],
    es:["La proporción áurea (φ ≈ 1,618) aparece en numerosas obras de arte, desde el Partenón hasta los cuadros de Salvador Dalí.","También se encuentra en la naturaleza: las espirales de los girasoles, las conchas de nautilus y las galaxias espirales siguen patrones relacionados con la secuencia de Fibonacci.","Algunos historiadores del arte cuestionan que los artistas antiguos usaran conscientemente la proporción áurea — en muchos casos podría ser una coincidencia o una proyección moderna."]},
  'ar7':{fr:["Jackson voulait aussi jouer Spider-Man — il avait tenté de racheter les droits du personnage.","Il a joué l'Épouvantail dans The Wiz, son seul vrai rôle au cinéma.","Si Jackson avait réussi, l'univers cinématographique Marvel n'existerait probablement pas."],en:["Jackson also wanted to play Spider-Man — he tried to buy the character's rights.","He played the Scarecrow in The Wiz, his only real movie role.","If Jackson had succeeded, the MCU as we know it probably wouldn't exist."],
    es:["El impresionismo nació en 1874 cuando Monet, Renoir, Degas y otros expusieron fuera del Salón oficial, desafiando las convenciones académicas de la época.","El nombre del movimiento proviene de una crítica despectiva al cuadro de Monet Impresión, sol naciente — el término «impresionista» era inicialmente un insulto.","Los impresionistas pintaban al aire libre (en plein air) para captar los efectos fugaces de la luz natural, una práctica facilitada por la invención de los tubos de pintura portátiles."]},
  'ar8':{fr:["La Tour a été construite en seulement 2 ans, 2 mois et 5 jours par 300 ouvriers.","Elle a été la structure la plus haute du monde pendant 41 ans, jusqu'au Chrysler Building en 1930.","La Tour grandit d'environ 15 cm en été à cause de la dilatation thermique de l'acier."],en:["The Tower was built in just 2 years, 2 months and 5 days by 300 workers.","It was the world's tallest structure for 41 years, until the Chrysler Building in 1930.","The Tower grows about 15 cm in summer due to thermal expansion of steel."],
    es:["El origami tradicional japonés se practica con una sola hoja de papel cuadrada, sin cortes ni pegamento, siguiendo reglas geométricas precisas.","Las matemáticas del plegado de papel han encontrado aplicaciones en ingeniería: los paneles solares del telescopio James Webb se pliegan como origami para caber en el cohete.","La grulla de papel (tsuru) es el símbolo más conocido del origami: según la tradición japonesa, plegar mil grullas (senbazuru) concede un deseo."]},
  'ar9':{fr:["La statuette pèse 3,85 kg et est plaquée de 24 carats d'or sur un alliage de bronze et d'étain.","L'Oscar le plus cher jamais vendu est celui de Citizen Kane, adjugé à 861 000 dollars en 2011.","Pendant la Seconde Guerre mondiale, les Oscars étaient en plâtre peint à cause de la pénurie de métal."],en:["The statuette weighs 3.85 kg and is plated with 24-karat gold over bronze and tin alloy.","The most expensive Oscar ever sold was for Citizen Kane, auctioned for $861,000 in 2011.","During WWII, Oscars were made of painted plaster due to metal shortages."],
    es:["La fotografía fue inventada simultáneamente por Niépce y Daguerre en Francia y Fox Talbot en Inglaterra entre 1826 y 1839.","La primera fotografía conocida, Vista desde la ventana en Le Gras de Niépce, requirió una exposición de aproximadamente 8 horas.","La fotografía revolucionó el arte: liberó a la pintura de su función documental, abriendo el camino al impresionismo, el expresionismo y la abstracción."]},
  'ar10':{fr:["Picasso et le poète Apollinaire étaient suspectés car Apollinaire possédait des statuettes volées au Louvre.","Le vrai voleur, Vincenzo Peruggia, a caché le tableau dans sa chambre à Paris pendant deux ans.","Peruggia pensait que la Joconde avait été volée par Napoléon — en réalité, Léonard l'avait apportée en France lui-même."],en:["Picasso and poet Apollinaire were suspected because Apollinaire had stolen statuettes from the Louvre.","The real thief, Vincenzo Peruggia, hid the painting in his Paris room for two years.","Peruggia believed Napoleon stole it — actually, Leonardo brought it to France himself."],
    es:["La Novena Sinfonía de Beethoven (1824) fue la primera gran sinfonía en incluir un coro y solistas vocales, rompiendo con todas las convenciones del género.","Beethoven estaba completamente sordo cuando la compuso y no pudo oír la ovación del público en su estreno — un músico tuvo que girarlo para que viera los aplausos.","El Himno a la Alegría, su movimiento final, fue adoptado como himno de la Unión Europea en 1985 — probablemente la melodía clásica más universalmente reconocida."]},
  'ar11':{fr:["Avant le vol, la Joconde était une peinture parmi d'autres au Louvre, sans protection spéciale.","L'espace vide sur le mur attirait plus de visiteurs que le tableau lui-même avant le vol.","Le vol a fait la une des journaux du monde entier pendant des semaines."],en:["Before the theft, the Mona Lisa was just another painting at the Louvre with no special protection.","The empty wall space attracted more visitors than the painting itself did before.","The theft made worldwide headlines for weeks."],
    es:["El teatro griego nació en el siglo V a.C. en Atenas como parte de las festividades en honor a Dionisio, dios del vino y la fertilidad.","Las tragedias de Esquilo, Sófocles y Eurípides exploraban temas universales como el destino, la justicia y el conflicto entre lo individual y lo colectivo.","Los anfiteatros griegos, como el de Epidauro, tenían una acústica tan perfecta que un murmullo en el escenario podía oírse en la última fila, a 60 metros de distancia."]},
  'ar12':{fr:["Minecraft a été vendu à Microsoft pour 2,5 milliards de dollars en 2014.","Le jeu est utilisé dans des écoles comme outil pédagogique pour les mathématiques et l'histoire.","La carte de Minecraft est théoriquement 8 fois plus grande que la surface de la Terre."],en:["Minecraft was sold to Microsoft for $2.5 billion in 2014.","The game is used in schools worldwide as an educational tool for math and history.","A Minecraft map is theoretically 8 times larger than Earth's surface."],
    es:["El Renacimiento italiano (siglos XIV-XVII) fue un periodo de explosión artística, científica y cultural que transformó Europa desde sus raíces medievales.","Florencia, bajo el mecenazgo de los Médicis, fue su epicentro: Brunelleschi, Botticelli, Leonardo, Miguel Ángel y Rafael trabajaron allí en la misma época.","La perspectiva lineal, sistematizada por Brunelleschi hacia 1420, permitió representar la profundidad tridimensional en una superficie plana — un avance que revolucionó la pintura occidental."]},
  'ar13':{fr:["Pour sentir les vibrations, Beethoven mordait une baguette fixée à son piano.","La Neuvième Symphonie dure plus de 70 minutes — elle a influencé la durée standard du CD (74 min).","L'hymne européen, l'Ode à la Joie, est le quatrième mouvement de cette symphonie."],en:["To feel vibrations, Beethoven bit a rod attached to his piano.","The Ninth Symphony lasts over 70 minutes — it influenced the standard CD length (74 min).","The European anthem, Ode to Joy, is the fourth movement of this symphony."],
    es:["La caligrafía árabe es considerada una de las formas artísticas más refinadas del islam, ya que la representación figurativa está tradicionalmente restringida.","Existen más de 100 estilos caligráficos, desde el anguloso kufi hasta el fluido nastaliq, cada uno con reglas proporcionales estrictas.","La caligrafía decora mezquitas, manuscritos y objetos cotidianos, convirtiendo la palabra escrita en un arte visual que trasciende la simple comunicación."]},
  'ar14':{fr:["L'acheteur est le prince héritier d'Arabie saoudite, Mohammed ben Salmane, révélé en 2019.","De nombreux experts doutent que le tableau soit entièrement de la main de Léonard.","Le tableau a été retrouvé en 2005 dans une vente de succession, vendu pour seulement 10 000 dollars."],en:["The buyer is Saudi Crown Prince Mohammed bin Salman, revealed in 2019.","Many experts doubt the painting is entirely by Leonardo's hand.","The painting was found in 2005 at an estate sale, sold for only $10,000."],
    es:["El surrealismo, fundado por André Breton en 1924, buscaba liberar la creatividad del pensamiento racional mediante el automatismo psíquico y la exploración del inconsciente.","Salvador Dalí, René Magritte y Max Ernst crearon obras que desafían la lógica: relojes blandos, pipas que no son pipas y paisajes oníricos imposibles.","Las técnicas surrealistas — como el cadáver exquisito, el frottage y la escritura automática — influyeron profundamente en la publicidad, el cine y el diseño gráfico del siglo XX."]},
  'ar15':{fr:["Le tableau vaut aujourd'hui environ 120 millions de dollars.","Munch a peint quatre versions du Cri entre 1893 et 1910.","Le ciel rouge s'inspire peut-être de l'éruption du Krakatoa en 1883, dont les cendres ont coloré les couchers de soleil."],en:["The painting is now worth about $120 million.","Munch painted four versions of The Scream between 1893 and 1910.","The red sky may be inspired by the 1883 Krakatoa eruption, whose ash colored sunsets worldwide."],
    es:["El ballet clásico se codificó en la corte de Luis XIV de Francia en el siglo XVII — el propio Rey Sol fue bailarín y creó la primera academia de danza en 1661.","Los cinco posiciones básicas de los pies en ballet fueron establecidas por Pierre Beauchamp, maître de ballet de Luis XIV, y siguen siendo la base de la técnica actual.","El ballet sobre puntas, donde las bailarinas se sostienen sobre las puntas de los pies, no apareció hasta principios del siglo XIX con Marie Taglioni en La Sílfide (1832)."]},
  'ar16':{fr:["Beethoven gardait des « cahiers de conversation » — ses visiteurs écrivaient leurs questions et il répondait à voix haute.","Sa surdité a commencé vers 28 ans et est devenue totale vers 44 ans.","Son testament d'Heiligenstadt révèle sa détresse face à la surdité et son désir de continuer à composer."],en:["Beethoven kept 'conversation notebooks' — visitors wrote questions and he answered aloud.","His deafness began around 28 and became total around 44.","His Heiligenstadt Testament reveals his distress over deafness and desire to keep composing."],
    es:["El jazz nació a finales del siglo XIX en Nueva Orleans, donde las tradiciones musicales africanas se fusionaron con el blues, el ragtime y la música de las bandas de desfile.","La improvisación es la esencia del jazz: los músicos crean melodías espontáneas sobre progresiones armónicas compartidas, convirtiendo cada interpretación en un acto único e irrepetible.","Louis Armstrong, Duke Ellington y Miles Davis transformaron el jazz en un arte universal que influyó decisivamente en el rock, el funk, el hip-hop y la música electrónica."]},
  'ar17':{fr:["Le Louvre a été un palais royal pendant 200 ans avant de devenir un musée en 1793.","Il faudrait 100 jours pour voir chaque œuvre en y consacrant 30 secondes — le musée compte plus de 380 000 objets.","La pyramide de verre de I.M. Pei (1989) a été très controversée mais est devenue un symbole de Paris."],en:["The Louvre was a royal palace for 200 years before becoming a museum in 1793.","It would take 100 days to see every work spending 30 seconds each — over 380,000 objects.","I.M. Pei's glass pyramid (1989) was very controversial but became a Paris symbol."],
    es:["El cine fue inventado por los hermanos Lumière, que proyectaron la primera película pública el 28 de diciembre de 1895 en el Grand Café de París.","La llegada de un tren a la estación, una de sus primeras películas, supuestamente provocó el pánico entre los espectadores que creyeron que el tren iba a salir de la pantalla.","Georges Méliès, un mago de profesión, fue el primer cineasta en usar efectos especiales: su Viaje a la Luna (1902) es considerada la primera película de ciencia ficción."]},
  'ar18':{fr:["Frida Kahlo a subi 32 opérations suite à un grave accident de bus à 18 ans.","Elle et Diego Rivera se sont mariés, divorcés, puis remariés.","Son tableau Diego y yo s'est vendu pour 34,9 millions de dollars en 2021."],en:["Frida Kahlo underwent 32 surgeries after a severe bus accident at 18.","She and Diego Rivera married, divorced, then remarried.","Her painting Diego y yo sold for $34.9 million in 2021."],
    es:["La escultura griega clásica alcanzó un nivel de realismo anatómico que no se igualaría hasta el Renacimiento, más de 1 500 años después.","La mayoría de las esculturas griegas que conocemos son copias romanas en mármol — los originales eran a menudo de bronce y fueron fundidos para reutilizar el metal.","Las estatuas griegas no eran blancas: estaban pintadas con colores vivos — rojo, azul, oro — que se perdieron con el tiempo, creando el mito del mármol puro y austero."]},
  'ar19':{fr:["Klein a mélangé du pigment outremer avec une résine synthétique pour préserver l'éclat pur de la couleur.","Il a réalisé des toiles monochromes, des sculptures d'éponges et des empreintes de corps nus peints en bleu.","Klein est mort d'une crise cardiaque à 34 ans, en 1962."],en:["Klein mixed ultramarine pigment with synthetic resin to preserve the pure brilliance.","He created monochrome canvases, sponge sculptures, and imprints of nude bodies painted blue.","Klein died of a heart attack at 34 in 1962."],
    es:["El art déco floreció entre las décadas de 1920 y 1930, combinando geometría, lujo y modernidad en arquitectura, moda, joyería y diseño industrial.","El Empire State Building, el Chrysler Building y el teatro Paramount de Times Square son iconos del art déco arquitectónico que definieron el perfil de Nueva York.","El movimiento fusionó influencias del cubismo, el constructivismo ruso, el arte egipcio y las artes decorativas japonesas — un eclecticismo deliberado que celebraba la era de las máquinas."]},
  'ar20':{fr:["Michel-Ange peignait debout, la tête renversée — pas couché sur le dos comme on le croit souvent.","Il a dessiné plus de 300 figures sur les 500 m² du plafond.","Il considérait la sculpture comme son art véritable — il a accepté la commande sous la pression du pape Jules II."],en:["Michelangelo painted standing with head tilted back — not lying down as often believed.","He drew over 300 figures across the 500 m² ceiling.","He considered sculpture his true art — he accepted the commission under pressure from Pope Julius II."],
    es:["El arte rupestre de las cuevas de Lascaux (Francia), datado en unos 17 000 años, representa bisontes, caballos y ciervos con una maestría técnica que sigue asombrando.","Las pinturas utilizaban pigmentos naturales — óxidos de hierro para el rojo, manganeso para el negro — mezclados con grasa animal y aplicados con pinceles, sopletes y las propias manos.","Lascaux fue cerrada al público en 1963 porque la respiración de los visitantes deterioraba las pinturas — hoy se puede visitar una réplica exacta, Lascaux IV."]},
  // === CELEBRITIES ===
  'cel1':{fr:["Walken a également appris à danser dès l'enfance et a intégré des pas de danse dans plusieurs de ses films.","Il refuse d'utiliser un ordinateur ou un téléphone portable — il préfère communiquer par courrier.","Son rôle dans Pulp Fiction a été improvisé en grande partie, notamment le monologue de la montre."],en:["Walken also learned to dance as a child and incorporated dance moves into several films.","He refuses to use a computer or cell phone — he prefers communicating by mail.","His role in Pulp Fiction was largely improvised, especially the watch monologue."],
    es:["Cleopatra hablaba al menos nueve idiomas y fue la primera soberana ptolemaica en aprender egipcio — una política estratégica para ganarse al pueblo.","Su relación con Julio César y Marco Antonio fue tanto romántica como diplomática: Cleopatra buscaba aliados para preservar la independencia de Egipto frente a Roma.","Su suicidio en el 30 a.C. — según la leyenda, mediante la mordedura de un áspid — marcó el fin de la era faraónica y el comienzo del Egipto romano."]},
  'cel2':{fr:["Buscemi a travaillé des quarts de 12 heures avec son ancienne caserne pendant une semaine après le 11 septembre.","Il a refusé toute interview sur ce sujet pendant des années — l'histoire n'a été révélée que par ses anciens collègues.","Avant les pompiers, il avait aussi été chauffeur de camion de glaces."],en:["Buscemi worked 12-hour shifts with his old firehouse for a week after 9/11.","He refused all interviews on the subject for years — the story was only revealed by former colleagues.","Before firefighting, he had also been an ice cream truck driver."],
    es:["Albert Einstein publicó cuatro artículos revolucionarios en 1905, su annus mirabilis: sobre el efecto fotoeléctrico, el movimiento browniano, la relatividad especial y la equivalencia masa-energía (E=mc²).","Einstein era un estudiante mediocre en las materias que no le interesaban pero excepcional en física y matemáticas — el mito de que era mal estudiante es una simplificación.","Tras huir de la Alemania nazi en 1933, Einstein se estableció en Princeton y escribió la famosa carta a Roosevelt que impulsó el Proyecto Manhattan — una decisión que lamentó profundamente."]},
  'cel3':{fr:["Hanks a tapé sa lettre de remerciement pour chaque Oscar sur une machine à écrire différente de sa collection.","Il est également un passionné d'espace et a produit le film Apollo 13 après des années de recherche.","Hanks et sa femme Rita Wilson ont été parmi les premières célébrités à annoncer publiquement leur diagnostic de COVID-19 en 2020."],en:["Hanks typed his thank-you letter for each Oscar on a different typewriter from his collection.","He's also a space enthusiast and produced Apollo 13 after years of research.","Hanks and wife Rita Wilson were among the first celebrities to publicly announce COVID-19 in 2020."],
    es:["Leonardo da Vinci era vegetariano, zurdo, disléxico probable y escribía en espejo — hay que leer sus cuadernos reflejados para descifrarlos.","Diseñó máquinas voladoras, tanques, escafandras, robots y puentes portátiles siglos antes de que la tecnología permitiera construirlos.","Nunca publicó sus descubrimientos científicos: sus 7 200 páginas de notas permanecieron inéditas durante siglos, lo que retrasó avances que podrían haber cambiado la historia."]},
  'cel4':{fr:["Parton a écrit Jolene et I Will Always Love You le même jour — deux de ses plus grands succès.","Elle finance un programme qui envoie un livre gratuit par mois à chaque enfant inscrit, de la naissance à 5 ans.","Parton a refusé la Médaille présidentielle de la Liberté deux fois, estimant ne pas la mériter."],en:["Parton wrote Jolene and I Will Always Love You on the same day — two of her biggest hits.","She funds a program sending one free book per month to every enrolled child from birth to age 5.","Parton declined the Presidential Medal of Freedom twice, feeling she didn't deserve it."],
    es:["Marie Curie fue la primera persona en recibir dos Premios Nobel en disciplinas diferentes: Física (1903) y Química (1911).","Sus cuadernos de laboratorio siguen siendo tan radiactivos que deben consultarse con ropa protectora y se guardan en cajas forradas de plomo en la Bibliothèque Nationale de París.","Curie murió en 1934 de anemia aplásica causada por su exposición prolongada a la radiación — en su época, los peligros de la radiactividad eran desconocidos."]},
  'cel5':{fr:["Robbie a aussi produit le film Barbie, qui a généré plus d'un milliard de dollars au box-office mondial.","Elle est originaire d'une petite ville du Queensland en Australie et a déménagé seule à Melbourne à 17 ans.","Pour son rôle dans Moi, Tonya, elle a appris le patinage artistique pendant 5 mois."],en:["Robbie also produced the Barbie film, which grossed over $1 billion worldwide.","She's from a small Queensland town in Australia and moved alone to Melbourne at 17.","For her role in I, Tonya, she learned figure skating for 5 months."],
    es:["Nikola Tesla patentó más de 300 inventos, incluyendo la corriente alterna, el motor de inducción y los fundamentos de la radio y el control remoto.","Tesla fue eclipsado en vida por Edison, su rival, que dominaba el negocio y la prensa — Tesla murió solo y arruinado en una habitación de hotel de Nueva York en 1943.","Tesla imaginó el wifi, los drones y la energía inalámbrica más de un siglo antes de que existieran — sus visiones futuristas lo han convertido en icono de la cultura geek."]},
  'cel6':{fr:["Reeves a aussi donné une partie importante de son salaire de Matrix à l'équipe technique du film.","Il prend régulièrement le métro et le bus à Los Angeles au lieu de voitures de luxe.","Reeves a créé sa propre marque de motos, Arch Motorcycle, avec un design personnalisé haut de gamme."],en:["Reeves also gave a significant portion of his Matrix salary to the film's technical crew.","He regularly takes the subway and bus in LA instead of luxury cars.","Reeves created his own motorcycle brand, Arch Motorcycle, with high-end custom designs."],
    es:["Frida Kahlo sufrió poliomielitis a los 6 años y un terrible accidente de autobús a los 18 que le causó fracturas múltiples y dolor crónico de por vida.","Su obra pictórica es profundamente autobiográfica: 55 de sus 143 cuadros son autorretratos que exploran el dolor, la identidad, el cuerpo y la mexicanidad.","Kahlo fue redescubierta en los años 1980 como icono feminista y LGBTQ+ — hoy es la artista latinoamericana más cotizada del mundo."]},
  'cel7':{fr:["Murray a accepté le rôle dans Lost in Translation après un simple message sur son répondeur.","Il apparaît parfois dans des bars ou des fêtes d'inconnus — puis dit « personne ne vous croira ».","Murray est un joueur de golf passionné et a écrit un livre humoristique sur le sujet."],en:["Murray accepted his Lost in Translation role after a simple voicemail message.","He sometimes shows up at strangers' bars or parties — then says 'no one will ever believe you'.","Murray is an avid golfer and wrote a humorous book about the sport."],
    es:["William Shakespeare escribió 37 obras de teatro, 154 sonetos e inventó más de 1 700 palabras inglesas, incluyendo «eyeball», «lonely» y «assassination».","Se sabe muy poco de su vida personal — existe un periodo de siete años (1585-1592) conocido como «los años perdidos» del que no hay ningún documento.","Algunos académicos dudan de que Shakespeare escribiera realmente sus obras, proponiendo candidatos como el conde de Oxford o Francis Bacon — un debate que sigue abierto."]},
  'cel8':{fr:["Obama a aussi une playlist officielle d'été qu'il publie chaque année et qui influence les classements musicaux.","Il collectionne les premières éditions de comics Spider-Man et Conan le Barbare depuis l'université.","Obama est gaucher — comme 7 des 46 présidents américains, une proportion supérieure à la moyenne de la population."],en:["Obama also has an official summer playlist published each year that influences music charts.","He's collected first-edition Spider-Man and Conan the Barbarian comics since college.","Obama is left-handed — like 7 of 46 US presidents, a proportion higher than the general population."],
    es:["Napoleón Bonaparte no era bajo: medía 1,69 m, por encima de la media francesa de la época (1,64 m).","Fue un genio militar y administrativo: el Código Napoleónico, la meritocracia, el sistema métrico y el banco de Francia son legados que perduran hasta hoy.","Exiliado a Santa Helena, Napoleón murió en 1821 — análisis modernos sugieren que murió de cáncer de estómago, aunque la hipótesis del envenenamiento por arsénico no se ha descartado del todo."]},
  'cel9':{fr:["Cage a aussi acheté un château hanté en Louisiane et un crâne de T-Rex de 276 000 dollars (qu'il a dû restituer).","Son vrai nom est Nicolas Kim Coppola — il est le neveu du réalisateur Francis Ford Coppola.","Il a changé de nom pour éviter les accusations de favoritisme dans l'industrie."],en:["Cage also bought a haunted castle in Louisiana and a $276,000 T-Rex skull (which he had to return).","His real name is Nicolas Kim Coppola — he's director Francis Ford Coppola's nephew.","He changed his name to avoid accusations of favoritism in the industry."],
    es:["Mahatma Gandhi lideró el movimiento de independencia de la India mediante la resistencia no violenta (ahimsa) y la desobediencia civil.","Su Marcha de la Sal en 1930 — 388 km a pie para protestar contra el monopolio británico de la sal — movilizó a millones de indios y debilitó la legitimidad del dominio colonial.","Gandhi fue asesinado en 1948 por un extremista hindú que consideraba que sus políticas de conciliación con los musulmanes eran una traición — su muerte conmocionó al mundo entero."]},
  'cel10':{fr:["Elvis a reçu sa ceinture noire 8e dan en 1960, après 12 ans de pratique intensive.","Il possédait plus de 30 armes à feu et a un jour tiré sur sa télévision parce qu'il n'aimait pas le programme.","Le jour de sa mort en 1977, les ventes de ses disques ont augmenté de 400 %."],en:["Elvis received his 8th-degree black belt in 1960, after 12 years of intensive practice.","He owned over 30 firearms and once shot his TV because he didn't like the program.","The day he died in 1977, his record sales increased by 400%."],
    es:["Martin Luther King Jr. pronunció su célebre discurso «I Have a Dream» ante 250 000 personas en Washington D.C. en agosto de 1963.","Inspirado por Gandhi, King abogó por la resistencia no violenta contra la segregación racial — su liderazgo fue clave para la aprobación del Civil Rights Act de 1964.","King recibió el Nobel de la Paz en 1964 con solo 35 años y fue asesinado en Memphis en 1968 — su legado sigue siendo el pilar del movimiento por los derechos civiles."]},
  'cel11':{fr:["Depp ne regarde jamais ses propres films — il trouve l'expérience trop gênante.","Il joue de la guitare dans un groupe de rock appelé Hollywood Vampires, avec Alice Cooper et Joe Perry.","Pour le premier Pirates des Caraïbes, Disney voulait le licencier car ils ne comprenaient pas son interprétation de Jack Sparrow."],en:["Depp never watches his own movies — he finds the experience too uncomfortable.","He plays guitar in a rock band called Hollywood Vampires, with Alice Cooper and Joe Perry.","For the first Pirates of the Caribbean, Disney wanted to fire him because they didn't understand his Jack Sparrow."],
    es:["Coco Chanel revolucionó la moda femenina al liberar a la mujer del corsé, popularizar los pantalones, el vestido negro y el perfume Chanel N°5.","Chanel creó un estilo que combinaba elegancia y comodidad — tomó prestados elementos del guardarropa masculino y los transformó en símbolos de independencia femenina.","Su pasado durante la ocupación nazi — mantuvo relaciones con oficiales alemanes — es una faceta controvertida que la marca Chanel prefiere minimizar."]},
  'cel12':{fr:["Winfrey est devenue la première femme noire milliardaire aux États-Unis en 2003.","Son club de lecture a le pouvoir de transformer instantanément un livre inconnu en bestseller mondial.","Elle a été renvoyée de son premier poste de présentatrice TV car on la jugeait trop émotive."],en:["Winfrey became the first Black female billionaire in the US in 2003.","Her book club can instantly turn an unknown book into a worldwide bestseller.","She was fired from her first TV anchor job because she was deemed too emotional."],
    es:["Stephen Hawking fue diagnosticado con esclerosis lateral amiotrófica (ELA) a los 21 años y le dieron dos años de vida — sobrevivió 55 años más.","Su libro Breve historia del tiempo (1988) vendió más de 10 millones de ejemplares y acercó la física teórica al gran público como ningún otro antes.","Hawking demostró que los agujeros negros emiten radiación (radiación de Hawking), un descubrimiento que unió la mecánica cuántica y la relatividad general por primera vez."]},
  'cel13':{fr:["Jolie est aussi envoyée spéciale du Haut-Commissariat des Nations Unies pour les réfugiés depuis 2012.","Elle a visité plus de 30 zones de conflit dans le monde dans le cadre de ses missions humanitaires.","Elle a subi une double mastectomie préventive en 2013 après avoir découvert un gène BRCA1 — sa décision publique a sensibilisé des millions de femmes."],en:["Jolie has been a UNHCR Special Envoy since 2012.","She's visited over 30 conflict zones worldwide for humanitarian missions.","She had a preventive double mastectomy in 2013 after discovering a BRCA1 gene — her public decision raised awareness for millions."],
    es:["Nelson Mandela pasó 27 años en prisión por luchar contra el apartheid en Sudáfrica — 18 de ellos en la isla de Robben Island.","Tras su liberación en 1990, Mandela negoció el fin pacífico del apartheid y fue elegido primer presidente negro de Sudáfrica en 1994.","Su capacidad de perdón y reconciliación — simbolizada por la Comisión de Verdad y Reconciliación — evitó una guerra civil y le valió el Nobel de la Paz en 1993."]},
  'cel14':{fr:["Chan a été hospitalisé pour presque toutes les parties de son corps — y compris le crâne, le nez, les deux pommettes et la quasi-totalité de ses doigts.","Il exécute toutes ses cascades lui-même et insiste pour que son équipe en fasse autant.","Il a été formé dès l'âge de 7 ans à l'Opéra de Pékin, où l'entraînement incluait acrobatie, chant et arts martiaux."],en:["Chan has been hospitalized for almost every body part — including skull, nose, both cheekbones, and nearly all fingers.","He performs all stunts himself and insists his team does the same.","He trained from age 7 at the Peking Opera, where training included acrobatics, singing, and martial arts."],
    es:["Steve Jobs cofundó Apple en un garaje en 1976, fue expulsado de su propia empresa en 1985 y regresó en 1997 para transformarla en la marca más valiosa del mundo.","El iPhone (2007) no fue el primer smartphone, pero Jobs lo convirtió en un objeto de deseo que redefinió la industria tecnológica y la cultura digital.","Jobs era conocido por su perfeccionismo obsesivo: rechazaba prototipos por defectos invisibles y dedicaba meses al diseño de detalles que la mayoría de usuarios nunca notarían."]},
  'cel15':{fr:["Ford a secouru une randonneuse déshydratée dans le Wyoming avec son hélicoptère personnel.","Il a survécu à un crash d'avion en 2015 peu après le décollage — il s'est posé d'urgence sur un terrain de golf.","Avant d'être acteur, il était charpentier — il a construit des meubles pour des studios hollywoodiens."],en:["Ford rescued a dehydrated hiker in Wyoming with his personal helicopter.","He survived a 2015 plane crash shortly after takeoff — landing on a golf course.","Before acting, he was a carpenter — he built furniture for Hollywood studios."],
    es:["Simone de Beauvoir publicó El segundo sexo en 1949, un ensayo fundacional del feminismo moderno que analiza la condición de la mujer como construcción social.","Su relación con Jean-Paul Sartre fue un pacto de libertad radical: pareja intelectual y sentimental durante 51 años, nunca vivieron juntos ni se casaron.","Beauvoir rechazó la Legión de Honor francesa pero aceptó el premio Goncourt — su influencia en el feminismo, la filosofía existencialista y la literatura del siglo XX es inmensa."]},
  'cel16':{fr:["Jackson est l'acteur le plus rentable du box-office mondial avec des films totalisant plus de 27 milliards de dollars.","Il porte un bonnet violet caractéristique avec la mention « Bad Mother F***er », un clin d'œil à Pulp Fiction.","Il bégayait sévèrement enfant — jouer la comédie et les arts martiaux l'ont aidé à surmonter ce trouble."],en:["Jackson is the highest-grossing box office actor with films totaling over $27 billion.","He wears a characteristic purple 'Bad Mother F***er' beanie, a nod to Pulp Fiction.","He stuttered severely as a child — acting and martial arts helped him overcome it."],
    es:["Elon Musk cofundó PayPal, fundó SpaceX, dirige Tesla y adquirió Twitter (renombrado X) — una diversificación empresarial sin precedentes en la era moderna.","SpaceX logró en 2020 lo que ninguna empresa privada había conseguido: enviar astronautas a la Estación Espacial Internacional, rompiendo el monopolio de las agencias espaciales gubernamentales.","Musk es una figura polarizante: admirado por su visión tecnológica pero criticado por su gestión de redes sociales y sus declaraciones polémicas."]},
  'cel17':{fr:["Cranston a aussi doublé des personnages dans plusieurs dessins animés avant d'être connu pour Breaking Bad.","Il a failli devenir officier de police — il avait passé le concours avant de choisir le métier d'acteur.","Pour jouer Walter White, il a rasé sa tête et a gardé le look pendant toute la durée du tournage."],en:["Cranston also voiced characters in several cartoons before being known for Breaking Bad.","He almost became a police officer — he'd passed the exam before choosing acting.","To play Walter White, he shaved his head and kept the look throughout filming."],
    es:["Malala Yousafzai recibió un disparo en la cabeza por parte de un talibán en 2012, a los 15 años, por defender el derecho de las niñas a la educación en Pakistán.","Sobrevivió milagrosamente y se convirtió en la persona más joven en recibir el Premio Nobel de la Paz en 2014, a los 17 años.","Hoy, la Fundación Malala trabaja en 10 países para garantizar el acceso a la educación de las niñas — Malala se graduó de Oxford en 2020."]},
  'cel18':{fr:["Gosling a aussi appris le piano en 3 mois pour son rôle dans La La Land.","Il a commencé sa carrière au Mickey Mouse Club aux côtés de Justin Timberlake et Christina Aguilera.","Il a vécu un an en Nouvelle-Zélande pour apprendre à parler avec un accent local pour un film."],en:["Gosling also learned piano in 3 months for his La La Land role.","He started his career on the Mickey Mouse Club alongside Justin Timberlake and Christina Aguilera.","He lived in New Zealand for a year to learn a local accent for a film."],
    es:["Charles Darwin publicó El origen de las especies en 1859, presentando la teoría de la evolución por selección natural que transformó nuestra comprensión de la vida.","Darwin dudó durante 20 años antes de publicar, temeroso de las implicaciones religiosas — fue la competencia de Alfred Russel Wallace, que había llegado a conclusiones similares, lo que lo decidió.","La evolución es una de las teorías más sólidas de la ciencia moderna, respaldada por la genética, la paleontología, la biología molecular y la observación directa de la selección natural."]},
  'cel19':{fr:["McConaughey joue des bongos torse nu dans son jardin — un hobby qui l'a rendu viral avant l'ère des réseaux sociaux.","Il a vécu dans un camping-car pendant plusieurs années, même après être devenu célèbre.","Son discours de remerciement aux Oscars en 2014 est considéré comme l'un des plus mémorables de l'histoire de la cérémonie."],en:["McConaughey plays bongos shirtless in his yard — a hobby that went viral before social media.","He lived in a camper van for several years, even after becoming famous.","His 2014 Oscar acceptance speech is considered one of the most memorable in ceremony history."],
    es:["Ada Lovelace es considerada la primera programadora de la historia: en 1843 escribió un algoritmo para la máquina analítica de Charles Babbage, un siglo antes de los primeros ordenadores.","Lovelace fue hija del poeta Lord Byron, pero nunca lo conoció — su madre la orientó hacia las matemáticas precisamente para alejarla de la poesía y la imaginación paterna.","Lovelace previó que las máquinas podrían crear música y arte, no solo calcular — una visión profética que anticipó la inteligencia artificial."]},
  'cel20':{fr:["Reeves a aussi financé anonymement des hôpitaux pour enfants pendant des années sans jamais en parler publiquement.","Il a perdu sa petite amie et leur fille dans des circonstances tragiques — ces épreuves ont profondément marqué sa philosophie de vie.","Malgré sa fortune estimée à 380 millions de dollars, il mène une vie notoirement simple."],en:["Reeves also anonymously funded children's hospitals for years without ever speaking publicly about it.","He lost his girlfriend and their daughter in tragic circumstances — these trials deeply shaped his life philosophy.","Despite an estimated $380 million fortune, he leads a notoriously simple life."],
    es:["Usain Bolt es el ser humano más rápido de la historia: su récord de 9,58 segundos en 100 metros (Berlín, 2009) sigue imbatido.","En su momento de máxima velocidad, Bolt alcanzó los 44,72 km/h — y lo hizo siendo significativamente más alto (1,95 m) que la mayoría de velocistas.","Bolt ganó 8 medallas olímpicas de oro consecutivas en 3 Juegos (2008-2016) y se retiró invicto en finales olímpicas — una dominación sin precedentes en el atletismo."]},
  // === CINEMA ===
  'cin1':{fr:["Ben Burtt a aussi créé le son de R2-D2 en mélangeant sa propre voix avec des sifflets électroniques.","Le son du blaster de Star Wars est le bruit d'un câble de haubanage frappé avec un marteau.","Chewbacca est un mélange de morse, ours, blaireau et chameau enregistrés au zoo."],en:["Ben Burtt also created R2-D2's sound by mixing his own voice with electronic whistles.","The Star Wars blaster sound is the noise of a guy wire struck with a hammer.","Chewbacca is a mix of walrus, bear, badger, and camel recorded at the zoo."],
    es:["Los hermanos Lumière proyectaron la primera película pública el 28 de diciembre de 1895 en el Grand Café de París ante 33 espectadores que pagaron 1 franco cada uno.","La llegada de un tren a la estación supuestamente causó pánico entre los espectadores — aunque esta anécdota es probablemente exagerada, refleja el impacto del nuevo medio.","Los Lumière creían que el cine no tenía futuro comercial: «El cine es una invención sin porvenir», declaró Auguste Lumière — una de las peores predicciones de la historia."]},
  'cin2':{fr:["Hitchcock a répété la scène 70 fois sur 7 jours de tournage pour obtenir la terreur parfaite.","Janet Leigh a déclaré que le film l'avait traumatisée — elle n'a plus jamais pris de douche, seulement des bains.","La scène dure 45 secondes mais contient 78 plans différents — un montage révolutionnaire pour l'époque."],en:["Hitchcock repeated the scene 70 times over 7 days to achieve perfect terror.","Janet Leigh said the film traumatized her — she never took a shower again, only baths.","The scene lasts 45 seconds but contains 78 different shots — revolutionary editing for the time."],
    es:["Ciudadano Kane (1941) de Orson Welles es considerada la mejor película de todos los tiempos en innumerables listas — Welles la dirigió, protagonizó y coescribió con solo 25 años.","La película introdujo técnicas revolucionarias: planos secuencia, profundidad de campo extrema, iluminación expresionista y una estructura narrativa no lineal.","William Randolph Hearst, el magnate de la prensa en quien está basado Charles Foster Kane, intentó destruir la película comprando todas las copias — fracasó, pero perjudicó su distribución."]},
  'cin3':{fr:["Le chat ronronnait si fort qu'il couvrait les dialogues — certaines répliques ont dû être réenregistrées en studio.","Brando ne mémorisait jamais ses textes — il les lisait sur des cartons placés hors champ.","Le Parrain a failli ne jamais être réalisé — Paramount voulait un réalisateur plus expérimenté que Coppola."],en:["The cat purred so loudly it drowned out dialogue — some lines had to be re-recorded in studio.","Brando never memorized his lines — he read them from cue cards placed off-camera.","The Godfather almost wasn't made — Paramount wanted a more experienced director than Coppola."],
    es:["Bollywood produce más de 1 500 películas al año, superando ampliamente a Hollywood, y su audiencia supera los 3 000 millones de espectadores en todo el mundo.","Las películas de Bollywood suelen durar 3 horas e incluyen números musicales, romance, acción y drama familiar — un formato que refleja la cultura india del entretenimiento total.","El nombre «Bollywood» combina Bombay (actual Mumbai) y Hollywood — pero la industria india tiene tradiciones cinematográficas que preceden a las de Hollywood en varias décadas."]},
  'cin4':{fr:["Les sons du T-Rex incluent un bébé éléphant, un alligator et un tigre mélangés ensemble.","Spielberg a embauché un paléontologue comme consultant pour s'assurer de la crédibilité des dinosaures.","Le film a relancé un intérêt mondial pour la paléontologie — les inscriptions en fac de sciences ont bondi de 30 %."],en:["T-Rex sounds include a baby elephant, alligator, and tiger mixed together.","Spielberg hired a paleontologist as consultant to ensure dinosaur credibility.","The film reignited worldwide interest in paleontology — science enrollments jumped 30%."],
    es:["Alfred Hitchcock, el «maestro del suspense», dirigió más de 50 películas y desarrolló técnicas narrativas que siguen siendo estudiadas en todas las escuelas de cine.","Su cameo en cada una de sus películas se convirtió en un juego para los espectadores — una tradición de autorreferencia que anticipó la cultura del «easter egg».","Psycho (1960) rompió todas las reglas: mató a su protagonista en el primer tercio, mostró un inodoro en pantalla por primera vez y utilizó la música de Bernard Herrmann para crear terror puro."]},
  'cin5':{fr:["Cameron est gaucher comme le personnage de Jack — il a inversé l'image pour que le dessin paraisse naturel.","Le budget de Titanic était de 200 millions de dollars — à l'époque le film le plus cher jamais réalisé.","Kate Winslet a failli mourir de noyade pendant le tournage des scènes dans l'eau glacée."],en:["Cameron is left-handed like Jack — he flipped the image so the drawing looked natural.","Titanic's budget was $200 million — at the time the most expensive film ever made.","Kate Winslet nearly drowned during filming of the freezing water scenes."],
    es:["Star Wars: Una nueva esperanza (1977) fue rechazada por todos los estudios excepto Fox, y George Lucas cedió su salario de director a cambio de los derechos de merchandising — una decisión que lo convirtió en multimillonario.","Industrial Light & Magic, fundada por Lucas para los efectos especiales, revolucionó la industria y ganó más de 30 premios Oscar.","La saga Star Wars ha generado más de 70 000 millones de dólares en total, convirtiéndose en la franquicia de entretenimiento más valiosa de la historia."]},
  'cin6':{fr:["Lee parlait couramment 6 langues et avait travaillé pour les services secrets britanniques pendant la guerre.","Il corrigeait souvent Peter Jackson sur les détails de combat car il avait une vraie expérience militaire.","Lee détient le record du plus grand nombre de rôles dans des films — plus de 280 au total."],en:["Lee spoke 6 languages fluently and worked for British intelligence during the war.","He often corrected Peter Jackson on combat details due to real military experience.","Lee holds the record for most film roles — over 280 in total."],
    es:["Studio Ghibli, fundado por Miyazaki e Isao Takahata en 1985, ha producido algunas de las películas de animación más aclamadas de la historia.","El viaje de Chihiro (2001) es la única película de animación que ha ganado simultáneamente el Oscar y el Oso de Oro de Berlín.","Miyazaki rechaza la animación digital y dibuja cada fotograma a mano — una filosofía artesanal que convierte cada película en una hazaña de paciencia y dedicación."]},
  'cin7':{fr:["Stallone a refusé des offres allant jusqu'à 350 000 dollars pour son scénario car les studios ne voulaient pas qu'il joue le rôle principal.","Le combat final de Rocky a été tourné en une seule journée pour économiser sur le budget.","Il a racheté son chien Butkus pour 15 000 dollars après le succès du film — il l'avait vendu 40 dollars."],en:["Stallone refused offers up to $350,000 for his script because studios didn't want him as the lead.","Rocky's final fight was filmed in one day to save budget.","He bought back his dog Butkus for $15,000 after the film's success — he'd sold him for $40."],
    es:["Titanic (1997) de James Cameron fue la primera película en superar los 1 000 millones de dólares en taquilla y mantuvo el récord 12 años hasta Avatar (2009).","Cameron construyó una réplica del Titanic a tamaño casi real en un estudio de México — el presupuesto se disparó a 200 millones, el más alto de la época.","La escena de Jack y Rose en la proa del barco se convirtió en una de las imágenes más icónicas y parodiadas de la historia del cine."]},
  'cin8':{fr:["Ledger a tenu un journal intime pendant cette préparation, rempli de coupures et d'images troublantes.","Sa performance lui a valu un Oscar posthume — le Joker est devenu l'un des méchants les plus iconiques du cinéma.","Nolan n'a jamais dit à l'équipe exactement ce que Ledger allait faire — les réactions des acteurs sont souvent authentiques."],en:["Ledger kept a diary during preparation, filled with disturbing clippings and images.","His performance earned him a posthumous Oscar — the Joker became one of cinema's most iconic villains.","Nolan never told the crew exactly what Ledger would do — actors' reactions are often genuine."],
    es:["El cine mudo no era realmente silencioso: las proyecciones se acompañaban de orquestas, pianistas o efectos sonoros en vivo.","Charlie Chaplin, Buster Keaton y Harold Lloyd fueron las primeras estrellas globales del cine — su comedia física trascendía las barreras lingüísticas.","La transición al cine sonoro (1927) acabó con la carrera de muchos actores del cine mudo cuyas voces no correspondían a su imagen — un drama retratado en Cantando bajo la lluvia."]},
  'cin9':{fr:["Spielberg a changé l'idée en voiture car il craignait que des enfants s'enferment dans des réfrigérateurs pour imiter le film.","La DeLorean a été choisie car sa carrosserie en acier inoxydable lui donnait un look futuriste crédible.","La vitesse de 88 mph (142 km/h) a été choisie car elle était facile à lire sur le compteur."],en:["Spielberg changed the idea to a car fearing children might lock themselves in fridges to copy the film.","The DeLorean was chosen because its stainless steel body gave a credible futuristic look.","88 mph was chosen because it was easy to read on the speedometer."],
    es:["La trilogía de El Señor de los Anillos de Peter Jackson se filmó íntegramente en Nueva Zelanda durante 438 días consecutivos — las tres películas se rodaron simultáneamente.","El retorno del Rey (2003) ganó los 11 premios Oscar a los que estaba nominado — un récord compartido solo con Ben-Hur y Titanic.","Las películas transformaron la economía neozelandesa: el turismo «hobbit» genera cientos de millones de dólares anuales y el país se promociona oficialmente como «la Tierra Media»."]},
  'cin10':{fr:["Le film a pris quatre ans à réaliser — un record pour l'époque, car chaque image devait être calculée par ordinateur.","Le personnage de Woody devait être un méchant ventriloque à l'origine — Disney a insisté pour un héros sympathique.","Pixar a failli fermer avant Toy Story — le film a sauvé le studio de la faillite."],en:["The film took four years to make — a record at the time, as every frame had to be computer-calculated.","Woody was originally meant to be a villainous ventriloquist — Disney insisted on a likable hero.","Pixar nearly closed before Toy Story — the film saved the studio from bankruptcy."],
    es:["Akira Kurosawa es considerado uno de los directores más influyentes de la historia — sus películas de samuráis inspiraron directamente Star Wars, Los Siete Magníficos y El Rey León.","Los siete samuráis (1954) estableció la estructura narrativa del «equipo de héroes reunidos para una misión» que sigue siendo la base de innumerables películas de acción.","George Lucas reconoció abiertamente que La fortaleza escondida (1958) de Kurosawa fue la inspiración directa de Star Wars — los droides C-3PO y R2-D2 están basados en dos campesinos de la película."]},
  'cin11':{fr:["Le champ de maïs a été vendu après le tournage et Nolan a récupéré une partie de l'investissement.","Le physicien Kip Thorne a été consultant scientifique — son travail sur le trou noir a mené à une publication scientifique réelle.","La scène de la vague géante sur la planète de Miller a été tournée en Islande avec des murs d'eau réels."],en:["The cornfield was sold after filming and Nolan recouped part of the investment.","Physicist Kip Thorne was science consultant — his black hole work led to an actual scientific paper.","The giant wave scene on Miller's planet was filmed in Iceland with real water walls."],
    es:["El MCU (Marvel Cinematic Universe) ha generado más de 30 000 millones de dólares en taquilla con más de 30 películas interconectadas desde Iron Man (2008).","Kevin Feige diseñó un modelo de narración transmedia sin precedentes: cada película funciona individualmente pero contribuye a una trama global que abarca años.","Avengers: Endgame (2019) se convirtió brevemente en la película más taquillera de la historia con 2 800 millones de dólares — superando el récord de Avatar."]},
  'cin12':{fr:["John Hurt a déclaré que la scène était l'une des expériences les plus traumatisantes de sa carrière.","Ridley Scott avait caché des poches de sang et d'entrailles de poulet sous la chemise de Hurt pour un effet de surprise maximal.","Le design du xénomorphe a été créé par l'artiste suisse H.R. Giger, inspiré de ses cauchemars."],en:["John Hurt said the scene was one of the most traumatizing experiences of his career.","Ridley Scott hid blood bags and chicken entrails under Hurt's shirt for maximum shock.","The xenomorph design was created by Swiss artist H.R. Giger, inspired by his nightmares."],
    es:["La Nouvelle Vague francesa (años 1960) revolucionó el cine mundial: Godard, Truffaut, Rohmer y Varda rechazaron las convenciones del cine comercial para crear un lenguaje más libre y personal.","Jean-Luc Godard rompió todas las reglas narrativas: jump cuts, miradas a cámara, diálogos improvisados y mezcla de ficción y documental.","La Nouvelle Vague demostró que se podía hacer cine con poco dinero y mucha creatividad — influyó directamente en Scorsese, Coppola, Tarantino y todo el cine independiente moderno."]},
  'cin13':{fr:["Spielberg a transformé ce problème technique en atout — en montrant moins le requin, il a créé plus de suspense.","Le film a inventé le concept de blockbuster estival — avant Jaws, les studios évitaient les sorties d'été.","La musique iconique de John Williams ne contient que deux notes (mi et fa) — l'une des bandes-son les plus reconnaissables au monde."],en:["Spielberg turned this technical problem into an asset — showing less of the shark created more suspense.","The film invented the summer blockbuster concept — before Jaws, studios avoided summer releases.","John Williams' iconic score uses just two notes (E and F) — one of the world's most recognizable soundtracks."],
    es:["Los efectos especiales digitales nacieron con Tron (1982), pero fue Jurassic Park (1993) de Spielberg el que demostró que los CGI podían crear criaturas fotorrealistas.","Los dinosaurios de Jurassic Park combinaban animatrónicos de Stan Winston y CGI de ILM — la mezcla era tan convincente que cambió el cine para siempre.","Hoy, más del 90 % de los planos de una película de superhéroes contienen CGI — una dependencia que genera debates sobre la pérdida de artesanía en el cine."]},
  'cin14':{fr:["Un deuxième faux film apparaît dans Maman j'ai raté l'avion 2 : Angels with Even Filthier Souls.","Macaulay Culkin avait 10 ans pendant le tournage et est devenu l'enfant le plus célèbre du monde.","Le film a rapporté 476 millions de dollars — il est resté le film familial le plus rentable pendant des décennies."],en:["A second fake film appears in Home Alone 2: Angels with Even Filthier Souls.","Macaulay Culkin was 10 during filming and became the world's most famous child.","The film grossed $476 million — it remained the highest-grossing family film for decades."],
    es:["Parasite (2019) de Bong Joon-ho fue la primera película en lengua no inglesa en ganar el Oscar a la Mejor Película, rompiendo una barrera de 92 años.","La película ganó cuatro premios Oscar (Película, Director, Guion Original, Película Internacional) — un logro sin precedentes para el cine asiático.","Bong Joon-ho declaró en su discurso: «Una vez que superas la barrera de los subtítulos, descubres muchas más películas increíbles» — una frase que se hizo viral."]},
  'cin15':{fr:["Le designer Simon Whiteley a photographié des recettes de sushis de sa femme japonaise, puis les a numérisées et inversées.","Les Wachowski ont exigé que tous les acteurs lisent le livre Simulacres et Simulation de Baudrillard avant le tournage.","L'effet bullet time, inventé pour Matrix, a nécessité 120 appareils photo disposés en cercle et déclenchés en séquence."],en:["Designer Simon Whiteley photographed his Japanese wife's sushi recipes, then digitized and reversed them.","The Wachowskis required all actors to read Baudrillard's Simulacra and Simulation before filming.","The bullet time effect, invented for Matrix, required 120 cameras arranged in a circle fired in sequence."],
    es:["Walt Disney creó el primer largometraje de animación de la historia occidental: Blancanieves y los siete enanitos (1937), que costó 1,5 millones de dólares de la época.","Los críticos de Hollywood lo llamaron «la locura de Disney» durante la producción — pero Blancanieves recaudó 8 millones y estableció Disney como imperio del entretenimiento.","Disney Studios ha producido más de 60 largometrajes de animación y genera más de 80 000 millones de dólares anuales entre cine, parques, merchandising y streaming."]},
  'cin16':{fr:["Todd a été piqué 23 fois pendant le tournage de la scène mais a touché un bonus de 1 000 dollars par piqûre.","Le personnage de Candyman est inspiré d'une légende urbaine sur un fantôme vengeur invoqué par un miroir.","Le film a relancé l'intérêt pour le genre du slasher surnaturel dans les années 1990."],en:["Todd was stung 23 times during the scene but received a $1,000 bonus per sting.","Candyman is inspired by an urban legend about a vengeful ghost summoned through a mirror.","The film revived interest in the supernatural slasher genre in the 1990s."],
    es:["El cine de terror japonés (J-Horror) influyó profundamente en Hollywood con películas como Ringu (1998) y Ju-On (2002), que fueron adaptadas como The Ring y The Grudge.","El J-Horror se distingue por su horror psicológico y atmosférico: fantasmas femeninos de pelo largo, tecnología maldita y amenazas invisibles que no se pueden combatir.","La cultura del miedo japonesa tiene raíces en los yūrei (fantasmas) y los yōkai (espíritus) del folclore, transmitidos durante siglos a través del teatro kabuki y los cuentos kaidan."]},
  'cin17':{fr:["Le designer sonore a également écrasé des noix avec ses mains pour imiter le bruit des os de l'extraterrestre.","Le geste iconique du doigt lumineux d'E.T. n'était pas prévu — Spielberg l'a ajouté spontanément pendant le tournage.","E.T. a fait pleurer les spectateurs du monde entier et est resté le film le plus rentable de l'histoire pendant 11 ans."],en:["The sound designer also crushed walnuts with his hands to mimic E.T.'s bone sounds.","E.T.'s iconic glowing finger gesture wasn't planned — Spielberg added it spontaneously during filming.","E.T. made audiences worldwide cry and remained the highest-grossing film for 11 years."],
    es:["2001: Una odisea del espacio (1968) de Stanley Kubrick es considerada la película de ciencia ficción más influyente jamás filmada — y una de las más enigmáticas.","Kubrick colaboró con Arthur C. Clarke: la película y la novela se desarrollaron simultáneamente, cada una influyendo en la otra.","La secuencia del «Star Gate» y el final con el monolito siguen generando interpretaciones 55 años después — Kubrick se negó siempre a explicar su significado."]},
  'cin18':{fr:["Le réalisateur Peter Weir a choisi cette date en hommage à son propre sentiment de vivre dans un monde surveillé.","Jim Carrey a improvisé plusieurs scènes clés — la scène du miroir est entièrement improvisée.","Le concept du film a inspiré le terme psychologique « syndrome de Truman » — la croyance qu'on vit dans un show télévisé."],en:["Director Peter Weir chose this date as a tribute to his own feeling of living in a watched world.","Jim Carrey improvised several key scenes — the mirror scene is entirely improvised.","The film inspired the psychological term 'Truman syndrome' — the belief one lives in a TV show."],
    es:["Pixar revolucionó la animación con Toy Story (1995), la primera película íntegramente creada por ordenador — un logro técnico que nadie creía posible.","Steve Jobs compró Pixar a Lucasfilm en 1986 por 10 millones de dólares — la vendió a Disney 20 años después por 7 400 millones.","El modelo narrativo de Pixar — historias emocionales universales para todas las edades — ha generado 15 películas que han recaudado más de 14 000 millones de dólares."]},
  'cin19':{fr:["Les animateurs ont filmé des acteurs en costumes comme référence pour chaque mouvement des personnages.","Walt Disney a hypothéqué sa maison pour financer le film — les critiques l'appelaient « la folie de Disney ».","Le film a rapporté 8 millions de dollars en 1937, sauvant Disney de la faillite et finançant la construction des studios."],en:["Animators filmed actors in costumes as reference for every character movement.","Walt Disney mortgaged his house to fund the film — critics called it 'Disney's Folly'.","The film grossed $8 million in 1937, saving Disney from bankruptcy and funding studio construction."],
    es:["El cine neorrealista italiano (1940-50) filmaba en escenarios reales con actores no profesionales, retratando la pobreza y las dificultades de la posguerra.","Ladrón de bicicletas (1948) de Vittorio De Sica es su obra maestra: un padre desempleado busca desesperadamente su bicicleta robada por las calles de Roma.","El neorrealismo influyó en la Nouvelle Vague francesa, el Cinema Novo brasileño y prácticamente todo el cine independiente posterior — demostró que la realidad podía ser más dramática que la ficción."]},
  'cin20':{fr:["Le budget du film était de 200 millions de dollars en 1997, contre 7,5 millions pour construire le vrai Titanic en 1912.","James Cameron a plongé 33 fois jusqu'à l'épave réelle du Titanic à 3 800 mètres de profondeur.","Le tournage a duré 160 jours — Cameron dormait souvent seulement 3 heures par nuit."],en:["The film's budget was $200 million in 1997, versus $7.5 million to build the real Titanic in 1912.","James Cameron dove 33 times to the actual Titanic wreck at 3,800 meters depth.","Filming lasted 160 days — Cameron often slept only 3 hours a night."],
    es:["Avatar (2009) de James Cameron fue la primera película en superar los 2 000 millones de dólares en taquilla y revolucionó el cine 3D y la captura de movimiento.","Cameron desarrolló una tecnología de captura de movimiento que permitía ver las escenas CGI en tiempo real durante el rodaje — una innovación que cambió la producción cinematográfica.","El mundo de Pandora fue inspirado por ecosistemas bioluminiscentes reales — la película generó un fenómeno llamado «depresión post-Avatar» entre espectadores que querían vivir en ese mundo."]},
  // === DINOSAURS ===
  'dino1':{fr:["Sa morsure était 10 fois plus puissante que celle d'un alligator actuel.","Le T-Rex pouvait broyer des os et les digérer entièrement — des fossiles de ses excréments contiennent des fragments d'os.","Malgré sa taille terrifiante, le T-Rex ne pouvait probablement pas courir à plus de 20 km/h à cause de sa masse."],en:["Its bite was 10 times more powerful than a modern alligator's.","T-Rex could crush bones and fully digest them — fossils of its droppings contain bone fragments.","Despite its terrifying size, T-Rex probably couldn't run faster than 20 km/h due to its mass."],
    es:["Los dinosaurios dominaron la Tierra durante más de 165 millones de años — los humanos llevamos apenas 300 000 años, una fracción insignificante en comparación.","Se extinguieron hace 66 millones de años tras el impacto de un asteroide de 10 km de diámetro en Chicxulub (actual México), que provocó un invierno global y extinguió al 75 % de las especies.","Sin embargo, los dinosaurios no desaparecieron del todo: las aves son dinosaurios terópodos que sobrevivieron a la extinción — técnicamente, vivimos rodeados de dinosaurios."]},
  'dino2':{fr:["Si l'histoire de la Terre était compressée en 24 heures, les dinosaures auraient régné de 22h40 à 23h40.","L'humanité n'apparaîtrait qu'à 23h59 et 59 secondes dans cette échelle.","Les dinosaures ont traversé trois périodes géologiques : le Trias, le Jurassique et le Crétacé."],en:["If Earth's history were compressed into 24 hours, dinosaurs would have reigned from 10:40 PM to 11:40 PM.","Humanity would only appear at 11:59 PM and 59 seconds on this scale.","Dinosaurs spanned three geological periods: Triassic, Jurassic, and Cretaceous."],
    es:["El Tyrannosaurus rex medía hasta 12 metros de largo, pesaba unas 8 toneladas y poseía la mordedura más potente de todos los animales terrestres conocidos: más de 5 800 kg de fuerza.","Sus brazos diminutos siguen siendo un misterio evolutivo: algunas hipótesis sugieren que servían para sujetar presas durante el apareamiento o para levantarse del suelo.","El T. rex no podía correr a la velocidad que muestra Jurassic Park: estudios biomecánicos sugieren una velocidad máxima de unos 20 km/h — rápido para su tamaño, pero no un velocista."]},
  'dino3':{fr:["Le vrai Vélociraptor ne mesurait que 50 cm de haut — les raptors de Jurassic Park sont basés sur le Deinonychus.","Ses plumes ne lui servaient probablement pas à voler mais à réguler sa température et impressionner ses partenaires.","Il chassait en meutes coordonnées, utilisant ses griffes en faucille pour immobiliser ses proies."],en:["The real Velociraptor was only 50 cm tall — Jurassic Park raptors are based on Deinonychus.","Its feathers probably weren't for flying but for temperature regulation and impressing mates.","It hunted in coordinated packs, using sickle-shaped claws to pin down prey."],
    es:["El Velociraptor real era mucho más pequeño que el de Jurassic Park: apenas medía 2 metros de largo y 50 cm de alto — del tamaño de un pavo grande.","Tenía plumas y probablemente se parecía más a un ave depredadora que a un reptil escamoso — la imagen cinematográfica es científicamente incorrecta.","Los «raptores» de Jurassic Park están basados en el Deinonychus, un pariente mayor y más impresionante — Spielberg usó el nombre Velociraptor porque le parecía más dramático."]},
  'dino4':{fr:["L'impact a libéré l'énergie de 10 milliards de bombes d'Hiroshima et a créé un cratère de 180 km de diamètre.","L'hiver d'impact qui a suivi a duré des années — la poussière a bloqué le soleil et fait chuter les températures de 15 °C.","75 % des espèces vivantes ont disparu, y compris tous les dinosaures non-aviens."],en:["The impact released the energy of 10 billion Hiroshima bombs, creating a 180 km crater.","The impact winter that followed lasted years — dust blocked sunlight and dropped temperatures 15°C.","75% of living species went extinct, including all non-avian dinosaurs."],
    es:["Los saurópodos (Brachiosaurus, Argentinosaurus, Diplodocus) fueron los animales más grandes que han caminado sobre la Tierra: hasta 40 metros de largo y 70 toneladas.","Para mantener su enorme cuerpo, comían hasta 400 kg de vegetación al día — su largo cuello les permitía alcanzar copas de árboles inaccesibles para otros herbívoros.","No masticaban: tragaban piedras (gastrolitos) que trituraban la vegetación en su estómago, como hacen hoy las aves — un método digestivo heredado de sus ancestros dinosaurios."]},
  'dino5':{fr:["Le Brachiosaure avait les narines au sommet du crâne — les scientifiques pensaient qu'il vivait dans l'eau, ce qui est faux.","Son cou pouvait atteindre 9 mètres de long, mais il ne pouvait probablement pas le lever au-dessus de son corps.","Son cœur devait peser environ 400 kg pour pomper le sang jusqu'à sa tête."],en:["Brachiosaurus had nostrils atop its skull — scientists thought it lived in water, which is false.","Its neck could reach 9 meters but it probably couldn't raise it above body level.","Its heart likely weighed about 400 kg to pump blood to its head."],
    es:["El Triceratops, con sus tres cuernos y su escudo óseo, era uno de los herbívoros más formidables del Cretácico — vivió junto al T. rex y era probablemente su presa principal.","Su escudo craneal no era solo defensivo: pudo servir para la termorregulación (como las orejas de un elefante) y para el reconocimiento entre individuos de la misma especie.","Fósiles muestran marcas de mordeduras de T. rex en escudos de Triceratops — evidencia directa de combates entre los dos iconos del Cretácico."]},
  'dino6':{fr:["Le passage dinosaure-oiseau s'est fait progressivement sur des millions d'années — pas en un événement soudain.","Le plus petit dinosaure connu est le Bee Hummingbird... qui est en fait un colibri vivant aujourd'hui.","Les autruches, les aigles et même les poules sont techniquement des dinosaures théropodes modernes."],en:["The dinosaur-to-bird transition happened gradually over millions of years — not in a sudden event.","The smallest known dinosaur is the Bee Hummingbird... which is actually a living hummingbird today.","Ostriches, eagles, and even chickens are technically modern theropod dinosaurs."],
    es:["El Stegosaurus tenía un cerebro del tamaño de una nuez (70 gramos) para un cuerpo de 5 toneladas — una de las ratios cerebro/cuerpo más bajas de todos los dinosaurios.","Sus placas dorsales no eran armadura sino probablemente reguladores térmicos: vascularizadas, podían absorber o irradiar calor según la orientación al sol.","Vivió hace 155 millones de años, 80 millones de años antes que el T. rex — el Stegosaurus está más lejos en el tiempo del T. rex que el T. rex de nosotros."]},
  'dino7':{fr:["Malgré son petit cerveau, le Stégosaure a survécu pendant 10 millions d'années — un succès évolutif indiscutable.","Ses plaques dorsales servaient probablement à réguler sa température et à intimider les prédateurs.","Les pointes de sa queue, appelées thagomizer, pouvaient infliger des blessures mortelles aux prédateurs."],en:["Despite its tiny brain, Stegosaurus survived for 10 million years — an undeniable evolutionary success.","Its back plates likely served to regulate temperature and intimidate predators.","The spikes on its tail, called a thagomizer, could inflict fatal wounds on predators."],
    es:["El Spinosaurus fue el mayor dinosaurio depredador conocido: hasta 15 metros de largo, superando al T. rex — y era semiacuático, el único dinosaurio carnívoro adaptado a la vida en el agua.","Su vela dorsal de hasta 1,8 metros de alto servía probablemente para la termorregulación, la exhibición sexual o la intimidación de rivales.","Fósiles recientes revelaron una cola aplanada como la de un tritón, confirmando que el Spinosaurus nadaba y cazaba peces y tiburones en los ríos del Cretácico norteafricano."]},
  'dino8':{fr:["Le Spinosaure mesurait environ 15 mètres de long — plus grand que le T-Rex de 2 à 3 mètres.","Sa voile dorsale pouvait mesurer 2 mètres de haut et servait probablement de régulateur thermique.","Il pêchait comme un ours grizzly, debout dans l'eau, attrapant des poissons géants avec ses griffes."],en:["Spinosaurus was about 15 meters long — 2-3 meters longer than T-Rex.","Its dorsal sail could reach 2 meters high and likely served as a heat regulator.","It fished like a grizzly bear, standing in water, catching giant fish with its claws."],
    es:["Los pterosaurios no eran dinosaurios sino reptiles voladores emparentados: el Quetzalcoatlus, con 10-12 metros de envergadura, fue el animal volador más grande de la historia.","A pesar de su tamaño, el Quetzalcoatlus pesaba solo unos 250 kg gracias a sus huesos huecos — como los de las aves modernas, sus descendientes evolutivos.","Los pterosaurios dominaron los cielos durante 160 millones de años antes de extinguirse junto con los dinosaurios — las aves, más pequeñas y adaptables, ocuparon su nicho ecológico."]},
  'dino9':{fr:["Les bras du T-Rex avaient des muscles puissants attachés à des os épais — leur fonction exacte reste débattue.","Certains scientifiques pensent qu'ils servaient à s'accrocher pendant l'accouplement.","Proportionnellement, les bras d'un T-Rex sont plus courts que ceux d'un humain comparé à la taille du corps."],en:["T-Rex arms had powerful muscles attached to thick bones — their exact function remains debated.","Some scientists think they were used for gripping during mating.","Proportionally, T-Rex arms are shorter than human arms compared to body size."],
    es:["Los primeros fósiles de dinosaurio fueron identificados científicamente en 1824 por William Buckland (Megalosaurus) — antes, se creía que eran huesos de gigantes o dragones.","Richard Owen acuñó el término «dinosaurio» (lagarto terrible) en 1842 para agrupar a estos reptiles extintos de tamaño descomunal.","La «manía de los dinosaurios» del siglo XIX generó una feroz rivalidad entre los paleontólogos Othniel Marsh y Edward Cope (la «Guerra de los Huesos»), que descubrieron más de 130 especies nuevas."]},
  'dino10':{fr:["La crête creuse fonctionnait comme un résonateur acoustique — chaque espèce produisait un son unique.","Les paléontologues ont reconstitué numériquement le son de cette crête — un grave bourdonnement semblable à un cor de brume.","Le Parasaurolophus était un herbivore qui vivait en troupeaux de centaines d'individus."],en:["The hollow crest worked as an acoustic resonator — each species produced a unique sound.","Paleontologists digitally reconstructed the crest's sound — a deep hum similar to a foghorn.","Parasaurolophus was a herbivore living in herds of hundreds."],
    es:["El Ankylosaurus era un tanque viviente: cubierto de placas óseas y equipado con una maza caudal capaz de romper los huesos de un T. rex.","Pesaba hasta 6 toneladas y medía 8 metros de largo — su armadura lo protegía de los depredadores más grandes de su época.","La maza caudal estaba formada por vértebras fusionadas y huesos dérmicos que podían generar un impacto equivalente al de un coche a 50 km/h."]},
  'dino11':{fr:["Le Megalosaurus a été le premier dinosaure nommé, mais un os de dinosaure avait été trouvé en 1677 et identifié comme un os de géant humain.","Le mot dinosaure n'existait pas avant 1842 — les premiers fossiles étaient attribués à des dragons ou des géants.","Mary Anning, une chasseuse de fossiles autodidacte, a découvert certains des premiers reptiles marins mais n'a jamais été reconnue de son vivant."],en:["Megalosaurus was the first dinosaur named, but a dinosaur bone found in 1677 was identified as a human giant's bone.","The word dinosaur didn't exist before 1842 — early fossils were attributed to dragons or giants.","Mary Anning, a self-taught fossil hunter, discovered some of the first marine reptiles but was never recognized in her lifetime."],
    es:["Los dinosaurios con plumas no son una excepción sino la norma: la mayoría de los terópodos (el grupo que incluye al T. rex) tenían algún tipo de plumaje.","El Sinosauropteryx (1996) fue el primer dinosaurio con plumas confirmadas — su descubrimiento en China revolucionó nuestra comprensión de la evolución de las aves.","Las plumas no evolucionaron para volar sino para el aislamiento térmico y la exhibición sexual — el vuelo fue una adaptación secundaria."]},
  'dino12':{fr:["Le Quetzalcoatlus pesait environ 250 kg — le poids maximal pour un animal volant.","Il se lançait en poussant sur ses pattes avant comme une chauve-souris géante.","Son envergure dépassait celle d'un avion de chasse F-16 — c'est le plus grand animal volant de tous les temps."],en:["Quetzalcoatlus weighed about 250 kg — the maximum weight for a flying animal.","It launched by pushing off with its front legs like a giant bat.","Its wingspan exceeded an F-16 fighter jet — the largest flying animal ever."],
    es:["El asteroide de Chicxulub liberó una energía equivalente a 10 000 millones de bombas de Hiroshima al impactar en la actual península de Yucatán hace 66 millones de años.","El impacto generó tsunamis de 1 500 metros, incendios forestales globales, lluvia ácida y un invierno nuclear que redujo la temperatura media del planeta 15 °C durante años.","Sin esta extinción masiva, los mamíferos habrían seguido siendo pequeños y nocturnos — la desaparición de los dinosaurios abrió el camino a la evolución de los primates y, eventualmente, los humanos."]},
  'dino13':{fr:["On a retrouvé des gastrolithes polis dans les estomacs fossilisés de plusieurs espèces de sauropodes.","Ce système est similaire au gésier des oiseaux modernes — une preuve supplémentaire du lien évolutif.","Les gastrolithes pouvaient mesurer jusqu'à 10 cm de diamètre et étaient souvent en quartz."],en:["Polished gastroliths have been found in fossilized stomachs of several sauropod species.","This system is similar to the gizzard of modern birds — further proof of the evolutionary link.","Gastroliths could measure up to 10 cm in diameter and were often quartz."],
    es:["El Diplodocus, con sus 27 metros de largo, usaba su cola como un látigo supersónico: los cálculos indican que la punta podía romper la barrera del sonido, produciendo un estallido audible.","Su cuello de 6 metros no se elevaba verticalmente (como en las ilustraciones clásicas) sino que se mantenía horizontal, barriendo grandes extensiones de vegetación baja.","Un Diplodocus adulto ponía huevos del tamaño de un balón de fútbol — la diferencia de tamaño entre la cría (1 metro) y el adulto (27 metros) es una de las mayores del reino animal."]},
  'dino14':{fr:["Owen a proposé le nom en 1842, combinant les mots grecs deinos (terrible) et sauros (lézard).","Avant lui, les fossiles étaient classés comme simples reptiles géants sans catégorie propre.","Owen a fondé le Muséum d'histoire naturelle de Londres, en partie pour exposer les dinosaures."],en:["Owen proposed the name in 1842, combining Greek words deinos (terrible) and sauros (lizard).","Before him, fossils were classified as simple giant reptiles without their own category.","Owen founded London's Natural History Museum, partly to exhibit dinosaurs."],
    es:["El Archaeopteryx (hace 150 millones de años) es considerado el eslabón entre dinosaurios y aves: tenía plumas y alas como un ave, pero dientes, garras y cola ósea como un reptil.","Solo se han encontrado 12 fósiles de Archaeopteryx, todos en las calizas de Solnhofen (Baviera, Alemania) — una preservación excepcional debida a las condiciones anóxicas de la laguna donde vivían.","El debate sobre si el Archaeopteryx volaba realmente o solo planeaba sigue abierto — sus plumas asimétricas sugieren capacidad de vuelo, pero su estructura ósea era más primitiva que la de las aves modernas."]},
  'dino15':{fr:["La massue caudale de l'Ankylosaurus pesait environ 30 kg — un coup pouvait briser la jambe d'un T-Rex.","Son corps était recouvert de plaques osseuses appelées ostéodermes, formant une armure naturelle impénétrable.","Même ses paupières étaient blindées — il était pratiquement invulnérable aux attaques par le dessus."],en:["The Ankylosaurus tail club weighed about 30 kg — one blow could break a T-Rex leg.","Its body was covered in bony plates called osteoderms, forming impenetrable natural armor.","Even its eyelids were armored — it was practically invulnerable to attacks from above."],
    es:["Los mosasaurios no eran dinosaurios sino reptiles marinos gigantes del Cretácico: el Mosasaurus alcanzaba los 17 metros y era el depredador supremo de los mares.","Estaban más emparentados con los lagartos y las serpientes que con los dinosaurios — su cuerpo hidrodinámico y sus mandíbulas articuladas recuerdan a las serpientes actuales.","Los plesiosaurios (cuello largo) y los ictiosaurios (forma de delfín) tampoco eran dinosaurios — la distinción es importante para entender la diversidad de reptiles del Mesozoico."]},
  'dino16':{fr:["Le Microraptor avait des plumes sur les quatre membres, lui permettant de planer d'arbre en arbre.","Ses plumes avaient un reflet iridescent noir-bleu, comme celles d'un corbeau moderne.","Il vivait en Chine il y a 120 millions d'années et se nourrissait de petits poissons et de lézards."],en:["Microraptor had feathers on all four limbs, allowing it to glide from tree to tree.","Its feathers had an iridescent blue-black sheen, like a modern crow.","It lived in China 120 million years ago and fed on small fish and lizards."],
    es:["La paleontología moderna usa escáneres CT, análisis isotópicos, biomecánica computacional y ADN antiguo para reconstruir la biología de los dinosaurios con una precisión antes impensable.","Se puede estimar la velocidad de un dinosaurio a partir de sus huellas, su temperatura corporal a partir de la química de sus huesos, e incluso su color a partir de los melanosomas de sus plumas fosilizadas.","El Sinosauropteryx fue el primer dinosaurio cuyo color fue determinado científicamente: tenía un patrón de rayas naranjas y blancas con una máscara oscura alrededor de los ojos."]},
  'dino17':{fr:["Un Tricératops adulte pesait entre 6 et 12 tonnes — autant qu'un éléphant d'Afrique.","Leurs combats laissaient des traces visibles — des fossiles montrent des cornes brisées et des collerettes perforées.","Le Tricératops est l'un des derniers dinosaures à avoir vécu avant l'extinction massive il y a 66 millions d'années."],en:["An adult Triceratops weighed 6 to 12 tons — as much as an African elephant.","Their fights left visible marks — fossils show broken horns and punctured frills.","Triceratops was one of the last dinosaurs alive before the mass extinction 66 million years ago."],
    es:["Los huevos de dinosaurio más grandes conocidos son los del Macroelongatoolithus, con hasta 60 cm de largo — pero eran relativamente pequeños en comparación con el tamaño del adulto.","Los saurópodos gigantes ponían huevos del tamaño de un balón porque la cáscara no podía ser más gruesa sin impedir el intercambio gaseoso — una limitación física que frenaba el tamaño del huevo.","Nidos fosilizados de Maiasaura (buena madre lagarto) revelan que algunos dinosaurios cuidaban a sus crías, les llevaban comida y protegían el nido — un comportamiento más parecido al de las aves que al de los reptiles."]},
  'dino18':{fr:["Le Patagotitan mesurait environ 37 mètres de long — la longueur de trois autobus bout à bout.","Son fémur seul mesure 2,4 mètres — plus grand qu'un humain adulte.","Il a été découvert par un berger argentin qui a repéré un os dépassant du sol en 2008."],en:["Patagotitan was about 37 meters long — the length of three buses end to end.","Its femur alone measures 2.4 meters — taller than an adult human.","It was discovered by an Argentine shepherd who spotted a bone sticking out of the ground in 2008."],
    es:["El Giganotosaurus, descubierto en Argentina en 1993, rivalizaba con el T. rex en tamaño: hasta 13 metros de largo y 8 toneladas.","Vivió 30 millones de años antes que el T. rex y en otro continente (Sudamérica vs Norteamérica) — nunca se encontraron, contrariamente a lo que sugiere Jurassic World.","Los carcarodontosaurios (familia del Giganotosaurus) tenían dientes como cuchillos de carne, diseñados para cortar y desgarrar en lugar de triturar huesos como el T. rex."]},
  'dino19':{fr:["Certains œufs de dinosaures avaient des coquilles colorées — des pigments bleus et rouges ont été retrouvés.","Les nids de dinosaures pouvaient contenir jusqu'à 30 œufs disposés en cercle, couvés par un parent.","Le plus petit œuf de dinosaure connu mesure seulement 2 cm — la taille d'un œuf de pigeon."],en:["Some dinosaur eggs had colored shells — blue and red pigments have been found.","Dinosaur nests could contain up to 30 eggs arranged in a circle, incubated by a parent.","The smallest known dinosaur egg measures only 2 cm — the size of a pigeon egg."],
    es:["Los dinosaurios vivieron en los tres periodos del Mesozoico: Triásico (252-201 Ma), Jurásico (201-145 Ma) y Cretácico (145-66 Ma) — cada uno con faunas muy diferentes.","Los primeros dinosaurios del Triásico eran pequeños y bípedos (como el Eoraptor, de 1 metro) — la diversificación masiva llegó tras la extinción del Triásico-Jurásico.","Más especies de dinosaurios vivieron en el Cretácico que en cualquier otro periodo — paradójicamente, fue justo antes de su extinción cuando alcanzaron su máxima diversidad."]},
  'dino20':{fr:["L'Antarctique était autrefois couvert de forêts tempérées — les dinosaures y vivaient sous un climat doux.","Le Cryolophosaurus, découvert en Antarctique en 1991, avait une crête osseuse en forme d'Elvis — d'où son surnom « Elvisaurus ».","Ces fossiles prouvent que l'Antarctique faisait partie du supercontinent Gondwana, relié à l'Amérique du Sud et à l'Afrique."],en:["Antarctica was once covered in temperate forests — dinosaurs lived there in a mild climate.","Cryolophosaurus, discovered in Antarctica in 1991, had an Elvis-shaped crest — hence its nickname 'Elvisaurus'.","These fossils prove Antarctica was part of the supercontinent Gondwana, connected to South America and Africa."],
    es:["El Parasaurolophus tenía una cresta hueca de hasta 1 metro de largo que funcionaba como una trompeta natural, produciendo sonidos graves que podían oírse a kilómetros.","Simulaciones por ordenador han recreado el sonido que producía: un tono grave y resonante, como un trombón — probablemente usado para comunicarse con su manada y atraer parejas.","Los hadrosaurios (dinosaurios pico de pato) eran los herbívoros más comunes del Cretácico tardío: vivían en manadas y tenían baterías dentales de más de 1 000 dientes para triturar vegetación dura."]},
  // === FICTION ===
  'fic1':{fr:["La casquette de chasseur vient d'une illustration de Sidney Paget en 1891 qui est devenue iconique.","Conan Doyle a tué Holmes dans Le Problème final en 1893, mais la pression des lecteurs l'a forcé à le ressusciter.","Le 221B Baker Street n'existait pas à l'époque — l'adresse a été créée plus tard et reçoit toujours du courrier pour Holmes."],en:["The deerstalker cap comes from a Sidney Paget illustration in 1891 that became iconic.","Conan Doyle killed Holmes in The Final Problem in 1893, but reader pressure forced him to resurrect the character.","221B Baker Street didn't exist at the time — the address was created later and still receives mail for Holmes."],
    es:["Sherlock Holmes fue creado por Arthur Conan Doyle en 1887 y se convirtió en el personaje de ficción más adaptado de la historia, con más de 250 películas y series.","Conan Doyle detestaba a su personaje y lo mató en Las cataratas de Reichenbach (1893) — la protesta pública fue tan intensa que se vio obligado a resucitarlo 10 años después.","Los métodos deductivos de Holmes inspiraron avances reales en la criminología: la policía adoptó técnicas de observación y análisis forense influidas por la ficción."]},
  'fic2':{fr:["L'ourse Winnipeg était la mascotte d'un régiment canadien pendant la Première Guerre mondiale avant d'être donnée au zoo de Londres.","Le nom Winnie vient de Winnipeg, la ville natale du soldat qui l'a amenée.","Le fils de l'auteur A.A. Milne, Christopher Robin, visitait réellement l'ourse au zoo — il a inspiré le personnage."],en:["Winnipeg the bear was a Canadian regiment mascot during WWI before being given to London Zoo.","The name Winnie comes from Winnipeg, hometown of the soldier who brought her.","Author A.A. Milne's son Christopher Robin actually visited the bear at the zoo — he inspired the character."],
    es:["Harry Potter fue rechazado por 12 editoriales antes de que Bloomsbury lo publicara en 1997, con una tirada inicial de solo 500 ejemplares.","La saga ha vendido más de 500 millones de ejemplares, ha sido traducida a 80 idiomas y ha generado un universo de películas, parques temáticos y productos valorado en más de 25 000 millones de dólares.","J.K. Rowling escribió gran parte del primer libro en cafeterías de Edimburgo mientras vivía de prestaciones sociales como madre soltera — una historia de superación tan famosa como la propia saga."]},
  'fic3':{fr:["L'acteur vocal de Superman avait besoin de jours de congé — la Kryptonite permettait à un remplaçant de gémir faiblement.","La Kryptonite était verte dans les comics, mais sur la radio, chaque type avait un effet différent décrit vocalement.","Ce dispositif scénaristique est devenu le talon d'Achille le plus célèbre de la culture pop."],en:["Superman's voice actor needed days off — Kryptonite let a substitute weakly groan.","Kryptonite was green in comics, but on radio, each type had a different vocally described effect.","This plot device became the most famous Achilles' heel in pop culture."],
    es:["El Señor de los Anillos fue escrito por J.R.R. Tolkien entre 1937 y 1949 como secuela de El Hobbit, pero se convirtió en una obra maestra de la literatura fantástica.","Tolkien, filólogo de Oxford, creó idiomas completos (élfico sindarin y quenya) antes de escribir la historia — las lenguas inspiraron el mundo, no al revés.","La trilogía cinematográfica de Peter Jackson (2001-2003) ganó 17 premios Oscar y transformó Nueva Zelanda en destino turístico, generando más de 3 000 millones en taquilla."]},
  'fic4':{fr:["Rowling a écrit le premier Harry Potter dans des cafés d'Édimbourg car son appartement n'avait pas de chauffage.","Elle a été refusée par 12 éditeurs avant que Bloomsbury n'accepte le manuscrit.","La série s'est vendue à plus de 500 millions d'exemplaires — le livre le plus vendu du XXIe siècle."],en:["Rowling wrote the first Harry Potter in Edinburgh cafés because her apartment had no heating.","She was rejected by 12 publishers before Bloomsbury accepted the manuscript.","The series sold over 500 million copies — the best-selling book of the 21st century."],
    es:["Don Quijote de la Mancha (1605-1615) de Cervantes es considerada la primera novela moderna y el libro más traducido del mundo después de la Biblia.","Cervantes escribió la segunda parte en parte como respuesta a una continuación apócrifa escrita por un autor desconocido bajo el seudónimo de Avellaneda.","Don Quijote parodia las novelas de caballerías pero trasciende la sátira: su exploración de la locura, el idealismo y la realidad ha inspirado a filósofos de Unamuno a Foucault."]},
  'fic5':{fr:["Le Grinch est devenu vert uniquement dans le dessin animé de 1966 réalisé par Chuck Jones.","Dr. Seuss a écrit Le Chat chapeauté en utilisant seulement 236 mots différents — un défi éditorial.","Ses livres ont été traduits dans plus de 20 langues et se sont vendus à plus de 600 millions d'exemplaires."],en:["The Grinch only became green in the 1966 cartoon by Chuck Jones.","Dr. Seuss wrote The Cat in the Hat using only 236 different words — an editorial challenge.","His books have been translated into over 20 languages and sold over 600 million copies."],
    es:["Star Wars fue rechazado por todos los estudios de Hollywood excepto Fox, y George Lucas tuvo que financiar parte de la producción con su propio dinero.","Lucas se inspiró en los monomitos de Joseph Campbell (El héroe de las mil caras), los samuráis de Kurosawa y la Flash Gordon de los años 1930.","La saga ha generado más de 70 000 millones de dólares en total (películas, merchandising, parques) — es la franquicia de entretenimiento más lucrativa de la historia."]},
  'fic6':{fr:["Le premier dessin animé de Mickey Mouse avec son synchronisé est Steamboat Willie, sorti en 1928.","Walt Disney a lui-même doublé Mickey Mouse pendant les 20 premières années.","Mickey Mouse rapporte à Disney environ 3 milliards de dollars par an en licences."],en:["The first Mickey Mouse cartoon with synchronized sound is Steamboat Willie, released in 1928.","Walt Disney himself voiced Mickey Mouse for the first 20 years.","Mickey Mouse earns Disney about $3 billion per year in licensing."],
    es:["Frankenstein de Mary Shelley (1818) es considerada la primera novela de ciencia ficción — escrita cuando la autora tenía apenas 18 años.","Shelley la concibió durante un verano lluvioso en Suiza, como parte de un reto de historias de terror con Lord Byron y Percy Shelley.","La novela plantea cuestiones éticas sobre la creación artificial de vida que siguen siendo centrales en los debates sobre inteligencia artificial y biotecnología."]},
  'fic7':{fr:["Dans la version originale, Pinocchio est aussi cruel — il écrase le Criquet parlant avec un marteau.","L'histoire a été publiée en feuilleton entre 1881 et 1883 dans un journal pour enfants italien.","Disney a adouci l'histoire pour en faire un conte moral sur l'honnêteté et la bravoure."],en:["In the original, Pinocchio is also cruel — he crushes the Talking Cricket with a hammer.","The story was serialized between 1881 and 1883 in an Italian children's newspaper.","Disney softened the story into a moral tale about honesty and bravery."],
    es:["Batman fue creado en 1939 por Bob Kane y Bill Finger, aunque Finger — quien diseñó el traje, el nombre y la personalidad — no recibió crédito oficial hasta 2015.","A diferencia de la mayoría de superhéroes, Batman no tiene superpoderes: su fuerza reside en su inteligencia, su entrenamiento y su fortuna — un héroe humano.","The Dark Knight Returns de Frank Miller (1986) reinventó el personaje como un antihéroe oscuro y complejo, transformando el cómic de superhéroes en literatura adulta."]},
  'fic8':{fr:["Fleming a trouvé le nom dans un guide ornithologique — l'auteur James Bond était un expert en oiseaux des Caraïbes.","L'auteur ornithologique a un jour rencontré Fleming et lui a dit qu'il avait « donné son nom à un voyou ».","Fleming a écrit chaque roman Bond en environ 2 mois, toujours dans sa villa GoldenEye en Jamaïque."],en:["Fleming found the name in a bird guide — James Bond was an expert on Caribbean birds.","The real James Bond once met Fleming and said he'd 'given his name to a thug'.","Fleming wrote each Bond novel in about 2 months, always at his GoldenEye villa in Jamaica."],
    es:["Alicia en el País de las Maravillas (1865) fue escrita por Lewis Carroll, pseudónimo del matemático Charles Dodgson, para la hija de un colega de Oxford.","El libro está lleno de juegos lógicos, paradojas matemáticas y sátiras políticas disfrazadas de absurdo infantil — opera en múltiples niveles de lectura.","Las adaptaciones de Disney (1951 y 2010) popularizaron una versión suavizada — el original de Carroll es mucho más extraño, oscuro y filosóficamente provocador."]},
  'fic9':{fr:["Les créateurs ont évité le mot zombie car dans leur univers, les films de zombies n'ont jamais existé.","Les personnages les appellent « rôdeurs », « mordeurs » ou « infectés » selon les groupes.","La série a été adaptée en jeu vidéo par Telltale Games, considéré comme l'un des meilleurs jeux narratifs."],en:["The creators avoided the word zombie because in their universe, zombie movies never existed.","Characters call them 'walkers', 'biters', or 'infected' depending on the group.","The series was adapted into a Telltale Games video game, considered one of the best narrative games."],
    es:["Drácula de Bram Stoker (1897) se inspiró en el folclore vampírico de Europa del Este y posiblemente en Vlad Tepes, el príncipe rumano del siglo XV.","Stoker investigó durante años la historia y la geografía de Transilvania, aunque nunca visitó Rumanía — el castillo de Drácula es una creación literaria.","Drácula ha generado más de 1 000 adaptaciones cinematográficas, convirtiéndolo en el personaje de ficción más filmado después de Sherlock Holmes."]},
  'fic10':{fr:["L'hôpital Great Ormond Street reçoit encore aujourd'hui des royalties à chaque mise en scène ou adaptation de Peter Pan.","Barrie a été inspiré par les fils de son ami Llewelyn Davies — il est devenu leur tuteur après la mort de leurs parents.","Peter Pan est un personnage ambigu — dans le livre original, il oublie ses amis et peut être cruel."],en:["Great Ormond Street Hospital still receives royalties for every Peter Pan staging or adaptation.","Barrie was inspired by his friend Llewelyn Davies's sons — he became their guardian after their parents' death.","Peter Pan is ambiguous — in the original, he forgets his friends and can be cruel."],
    es:["1984 de George Orwell (1949) introdujo conceptos como Gran Hermano, neolengua, doblepensar y policía del pensamiento en el vocabulario común.","Orwell escribió la novela mientras agonizaba de tuberculosis en una isla escocesa — murió siete meses después de su publicación.","Las ventas de 1984 se disparan cada vez que un escándalo de vigilancia gubernamental sacude la opinión pública — fue bestseller en 2013 tras las revelaciones de Snowden y en 2017 tras la llegada de Trump."]},
  'fic11':{fr:["Bob Kane, le créateur de Batman, a aussi été inspiré par le Zorro et le film Le Fantôme de l'Opéra de 1925.","Batman n'a pas de superpouvoirs — sa seule arme est sa fortune, son intelligence et son entraînement physique.","Le Joker est apparu dès le premier numéro de Batman en 1940 et devait mourir dans ce même épisode."],en:["Bob Kane, Batman's creator, was also inspired by Zorro and the 1925 Phantom of the Opera film.","Batman has no superpowers — his only weapons are wealth, intelligence, and physical training.","The Joker appeared in the very first Batman issue in 1940 and was meant to die in that same episode."],
    es:["Los mangas japoneses representan un mercado de más de 6 000 millones de dólares anuales y se leen de derecha a izquierda en su formato original.","Osamu Tezuka, creador de Astro Boy (1952), es considerado el padre del manga moderno — introdujo los ojos grandes y las narrativas complejas que definen el estilo.","One Piece de Eiichiro Oda ha vendido más de 500 millones de copias, convirtiéndolo en la serie de manga más vendida de la historia."]},
  'fic12':{fr:["Le personnage de Shrek est basé en partie sur le catcheur français Maurice Tillet, surnommé « l'Ange français ».","Le film a remporté le tout premier Oscar du meilleur film d'animation en 2002.","Mike Myers a réenregistré toutes les voix de Shrek avec un accent écossais après avoir déjà tout enregistré avec un accent canadien."],en:["Shrek is partly based on French wrestler Maurice Tillet, nicknamed 'The French Angel'.","The film won the very first Academy Award for Best Animated Feature in 2002.","Mike Myers re-recorded all Shrek voices with a Scottish accent after already recording everything with a Canadian accent."],
    es:["El Principito de Antoine de Saint-Exupéry (1943) es el libro más traducido del mundo después de la Biblia y el Corán, con versiones en más de 300 idiomas.","Saint-Exupéry, piloto de guerra, desapareció durante una misión de reconocimiento en 1944 — los restos de su avión fueron encontrados en el Mediterráneo en 2004.","La frase «lo esencial es invisible a los ojos» se ha convertido en una de las citas literarias más universales, citada en contextos que van de la filosofía al marketing."]},
  'fic13':{fr:["Burroughs a créé Tarzan en 1912 en s'inspirant du mythe de Romulus et Rémus et du Livre de la Jungle.","Le cri de Tarzan au cinéma a été créé en superposant plusieurs voix et sons d'animaux — sa recette exacte est un secret de studio.","Tarzan est l'un des personnages les plus adaptés au cinéma avec plus de 50 films."],en:["Burroughs created Tarzan in 1912, inspired by the Romulus and Remus myth and The Jungle Book.","Tarzan's movie yell was created by layering multiple voices and animal sounds — its exact recipe is a studio secret.","Tarzan is one of the most adapted characters in cinema with over 50 films."],
    es:["James Bond fue creado por Ian Fleming en 1953, inspirándose en espías reales que conoció durante su trabajo en la inteligencia naval británica.","El agente 007 ha sido interpretado por 7 actores diferentes en 25 películas oficiales que han recaudado más de 7 000 millones de dólares en taquilla.","Fleming eligió el nombre James Bond del autor de un libro de ornitología del Caribe — quería un nombre lo más anodino y poco memorable posible."]},
  'fic14':{fr:["Christie a écrit 33 romans avec Poirot mais rêvait de se concentrer sur Miss Marple.","Le dernier roman de Poirot, Rideau, a été écrit dans les années 1940 mais publié en 1975, un an avant la mort de Christie.","Poirot est l'un des rares personnages fictifs à avoir eu un obituaire dans le New York Times."],en:["Christie wrote 33 Poirot novels but dreamed of focusing on Miss Marple.","Poirot's last novel, Curtain, was written in the 1940s but published in 1975, a year before Christie's death.","Poirot is one of the few fictional characters to receive a New York Times obituary."],
    es:["El Quijote inventó la novela polifónica: múltiples voces, puntos de vista y niveles de realidad se entrelazan en una estructura que anticipó la literatura posmoderna.","Sancho Panza no es simplemente un contrapunto cómico: su evolución a lo largo de la novela es tan profunda como la de Don Quijote — ambos se influyen mutuamente.","La frase «tilting at windmills» (luchar contra molinos de viento) se usa en decenas de idiomas para describir batallas contra enemigos imaginarios — un legado lingüístico universal."]},
  'fic15':{fr:["Martin utilise WordStar 4.0, un logiciel de 1987 qui ne fonctionne que sous DOS.","Il a commencé à écrire Game of Thrones en 1991 — le premier tome a été publié 5 ans plus tard.","La série télévisée a dépassé les livres en 2016 — les fans attendent le sixième tome depuis 2011."],en:["Martin uses WordStar 4.0, a 1987 program that only runs on DOS.","He started writing Game of Thrones in 1991 — the first book was published 5 years later.","The TV series surpassed the books in 2016 — fans have been waiting for book six since 2011."],
    es:["Los superhéroes modernos nacieron en 1938 con la aparición de Superman en Action Comics #1, creado por Jerry Siegel y Joe Shuster, dos adolescentes de Cleveland.","Siegel y Shuster vendieron los derechos de Superman por 130 dólares — el personaje ha generado desde entonces miles de millones en productos y entretenimiento.","Superman fue concebido como inmigrante (de Krypton) que se integra en su país de adopción — una metáfora de la experiencia de los inmigrantes judíos en Estados Unidos."]},
  'fic16':{fr:["Travers a pleuré à la première du film en 1964 — pas de joie, mais de déception.","Elle a exigé contractuellement que les scénaristes n'utilisent jamais la couleur rouge dans le film.","L'histoire de son conflit avec Disney a été adaptée dans le film Dans l'ombre de Mary en 2013."],en:["Travers cried at the 1964 premiere — not from joy, but disappointment.","She contractually demanded screenwriters never use the color red in the film.","Her conflict with Disney was adapted in the 2013 film Saving Mr. Banks."],
    es:["Game of Thrones (Juego de Tronos) de George R.R. Martin se inspira en la Guerra de las Rosas inglesas (Lancaster vs York) y en las intrigas de los Borgia.","La serie de HBO (2011-2019) se convirtió en el fenómeno televisivo más grande de su era, con audiencias de más de 19 millones por episodio en su última temporada.","Martin lleva más de 13 años escribiendo el sexto libro (Vientos de Invierno) — la espera se ha convertido en un meme cultural y una fuente de frustración para millones de lectores."]},
  'fic17':{fr:["Le rêve montrait un vampire et une jeune fille dans une prairie — cette scène est devenue le chapitre 13 du livre.","Meyer n'avait aucune expérience d'écriture avant Twilight — elle était mère au foyer.","La saga s'est vendue à plus de 160 millions d'exemplaires et a généré 3,3 milliards au cinéma."],en:["The dream showed a vampire and a girl in a meadow — this scene became chapter 13 of the book.","Meyer had no writing experience before Twilight — she was a stay-at-home mom.","The saga sold over 160 million copies and grossed $3.3 billion in films."],
    es:["Cien años de soledad de Gabriel García Márquez (1967) es la obra cumbre del realismo mágico latinoamericano y una de las novelas más influyentes del siglo XX.","García Márquez vendió su coche y empeñó los electrodomésticos de su esposa para poder escribir la novela durante 18 meses sin interrupciones.","La novela narra siete generaciones de la familia Buendía en el pueblo ficticio de Macondo — una metáfora de la historia de América Latina."]},
  'fic18':{fr:["Stoker a passé 7 ans à rechercher le folklore des vampires dans la bibliothèque de Whitby, en Angleterre.","Le nom Dracula vient de Dracul, signifiant « dragon » en roumain — c'était le surnom du père de Vlad l'Empaleur.","Le roman a failli s'appeler The Un-Dead avant que Stoker ne change le titre au dernier moment."],en:["Stoker spent 7 years researching vampire folklore at the Whitby library in England.","The name Dracula comes from Dracul, meaning 'dragon' in Romanian — it was Vlad the Impaler's father's nickname.","The novel was almost called The Un-Dead before Stoker changed the title at the last moment."],
    es:["Los cuentos de los hermanos Grimm (1812) no eran originalmente para niños: contenían violencia, crueldad y temas adultos que fueron suavizados en ediciones posteriores.","En la versión original de Cenicienta, las hermanastras se cortan los dedos de los pies para que les quepa el zapato — y palomas les arrancan los ojos al final como castigo.","Walt Disney transformó estos cuentos oscuros en películas familiares, creando las versiones edulcoradas que la mayoría del mundo conoce hoy."]},
  'fic19':{fr:["Vlad III l'Empaleur était connu pour empaler ses ennemis sur des pieux — d'où le lien avec le vampire.","Stoker n'a jamais confirmé le lien entre Dracula et Vlad — les historiens l'ont fait après sa mort.","Le château de Bran en Roumanie est présenté comme le « château de Dracula » mais Vlad n'y a probablement jamais vécu."],en:["Vlad III the Impaler was known for impaling enemies on stakes — hence the vampire connection.","Stoker never confirmed the link between Dracula and Vlad — historians made it after his death.","Bran Castle in Romania is marketed as 'Dracula's castle' but Vlad probably never lived there."],
    es:["Pikachu, la mascota de Pokémon, no fue el protagonista original: los creadores querían a Clefairy, pero Pikachu fue elegido por ser más atractivo visualmente.","Pokémon ha generado más de 100 000 millones de dólares desde su creación en 1996, convirtiéndolo en la franquicia de medios más lucrativa de todos los tiempos.","El nombre Pokémon es una contracción de Pocket Monsters (monstruos de bolsillo) — el juego original fue creado por Satoshi Tajiri, un niño coleccionista de insectos."]},
  'fic20':{fr:["La phrase griffonnée était « In a hole in the ground there lived a hobbit » — il ne savait pas encore ce qu'un hobbit était.","Tolkien a créé plusieurs langues complètes pour son univers, dont l'elfique quenya et le sindarin.","Le Seigneur des Anneaux a été écrit comme suite au Hobbit mais est devenu une œuvre bien plus sombre et complexe."],en:["The scribbled phrase was 'In a hole in the ground there lived a hobbit' — he didn't yet know what a hobbit was.","Tolkien created several complete languages for his universe, including Quenya and Sindarin Elvish.","Lord of the Rings was written as a Hobbit sequel but became a much darker and more complex work."],
    es:["El Hobbit fue publicado en 1937 como cuento para niños y tuvo tanto éxito que el editor pidió una secuela — Tolkien tardó 12 años en escribir El Señor de los Anillos.","Tolkien se inspiró en las mitologías nórdica, celta y finlandesa (el Kalevala) para crear la Tierra Media — quería dar a Inglaterra una mitología propia.","Los hobbits están inspirados en los ingleses rurales del siglo XIX: amantes de la buena comida, del jardín y de la tranquilidad — un reflejo del propio Tolkien."]},
  // === FOOD ===
  'f1':{fr:["Du miel vieux de 3 000 ans a été trouvé dans les tombes des pharaons égyptiens — encore comestible.","Le miel est le seul aliment qui contient tout ce dont un être humain a besoin pour survivre : eau, vitamines, minéraux et enzymes.","Une abeille ne produit qu'un douzième de cuillère à café de miel dans toute sa vie."],en:["3,000-year-old honey was found in Egyptian pharaohs' tombs — still edible.","Honey is the only food containing everything humans need to survive: water, vitamins, minerals, and enzymes.","A single bee produces only one-twelfth of a teaspoon of honey in its entire life."],
    es:["Las primeras patatas fritas documentadas aparecen en textos españoles del siglo XVII, no en Bélgica ni en Francia como suele creerse.","La disputa entre belgas y franceses por la paternidad de las «frites» nunca ha sido zanjada definitivamente — ambos países las consideran patrimonio cultural propio.","La patata llegó a Europa desde Perú en el siglo XVI y fue inicialmente rechazada por los europeos, que la consideraban venenosa o alimento para animales."]},
  'f2':{fr:["Les Aztèques utilisaient les fèves de cacao comme monnaie — 10 fèves valaient un lapin.","Le chocolat au lait a été inventé en Suisse par Daniel Peter en 1875 en ajoutant du lait condensé.","La Suisse consomme le plus de chocolat par habitant — environ 10 kg par personne par an."],en:["Aztecs used cacao beans as currency — 10 beans were worth one rabbit.","Milk chocolate was invented in Switzerland by Daniel Peter in 1875 by adding condensed milk.","Switzerland consumes the most chocolate per capita — about 10 kg per person per year."],
    es:["La miel no caduca porque su bajo contenido en agua, alta acidez y producción natural de peróxido de hidrógeno impiden el crecimiento bacteriano.","Arqueólogos han encontrado vasijas de miel en tumbas egipcias de 3 000 años de antigüedad que seguían siendo perfectamente comestibles.","Las abejas deben visitar unos 2 millones de flores y recorrer más de 88 000 km para producir un solo kilo de miel."]},
  'f3':{fr:["Les premières carottes étaient blanches ou violettes — la variété orange est apparue aux Pays-Bas au XVIIe siècle.","La couleur orange a été sélectionnée en hommage à la maison royale d'Orange-Nassau.","Les carottes violettes contiennent des anthocyanines — des antioxydants puissants absents de la variété orange."],en:["The first carrots were white or purple — the orange variety appeared in the Netherlands in the 17th century.","The orange color was selected in tribute to the Royal House of Orange-Nassau.","Purple carrots contain anthocyanins — powerful antioxidants absent from the orange variety."],
    es:["La salsa Worcestershire fue creada accidentalmente por los farmacéuticos John Lea y William Perrins en Worcester, Inglaterra, hacia 1837.","La mezcla encargada por un gobernador colonial resultó tan desagradable que la abandonaron en una bodega — al probarla dos años después, la fermentación la había transformado en una salsa exquisita.","Su receta sigue siendo secreta, pero se sabe que contiene vinagre, melaza, anchoas, tamarindo, ajo, cebolla y especias — la fermentación es la clave de su sabor complejo."]},
  'f4':{fr:["La Finlande consomme le plus de café par habitant — environ 12 kg par personne par an.","Le café a été découvert en Éthiopie par un berger qui a remarqué que ses chèvres devenaient agitées après avoir mangé les cerises de caféier.","La caféine est un pesticide naturel produit par les plantes pour repousser les insectes."],en:["Finland consumes the most coffee per capita — about 12 kg per person per year.","Coffee was discovered in Ethiopia by a shepherd who noticed his goats became agitated after eating coffee cherries.","Caffeine is a natural pesticide produced by plants to repel insects."],
    es:["Los pistachos son técnicamente frutas, no frutos secos, y pertenecen a la misma familia botánica (Anacardiaceae) que los mangos y los anacardos.","Irán es el mayor productor mundial de pistachos, seguido de Estados Unidos (California) — juntos representan más del 70 % de la producción global.","Los pistachos se abren solos cuando maduran en el árbol: la cáscara se hiende con un «clic» audible — los cultivadores iraníes los llaman «la nuez sonriente»."]},
  'f5':{fr:["Les fraises sont les seuls fruits dont les graines sont à l'extérieur — environ 200 graines par fraise.","La banane est une baie botaniquement car son fruit se développe à partir d'un seul ovaire.","Le kiwi et la pastèque sont aussi des baies botaniques — contrairement aux framboises qui sont des fruits agrégés."],en:["Strawberries are the only fruit with seeds on the outside — about 200 per strawberry.","The banana is botanically a berry because its fruit develops from a single ovary.","Kiwis and watermelons are also botanical berries — unlike raspberries which are aggregate fruits."],
    es:["El chocolate era una bebida amarga, fría y especiada consumida por los mayas y aztecas durante ceremonias religiosas y como moneda de cambio.","Los granos de cacao eran tan valiosos que los aztecas los usaban como dinero: un pavo costaba 100 granos y un esclavo, 1 000.","El chocolate con leche fue inventado en 1875 por el suizo Daniel Peter, que tuvo la idea de añadir leche condensada de su vecino Henri Nestlé — naciendo así una industria multimillonaria."]},
  'f6':{fr:["La capsaïcine est si puissante que le Carolina Reaper, le piment le plus fort du monde, atteint 2,2 millions d'unités Scoville.","Les oiseaux ne sentent pas la capsaïcine — c'est pourquoi ils sont les principaux disséminateurs de graines de piments.","Les humains développent une tolérance à la capsaïcine — plus on en mange, plus on peut en supporter."],en:["Capsaicin is so powerful the Carolina Reaper, the world's hottest pepper, reaches 2.2 million Scoville units.","Birds don't feel capsaicin — that's why they're the main dispersers of chili seeds.","Humans develop tolerance to capsaicin — the more you eat, the more you can handle."],
    es:["Las zanahorias eran originalmente blancas, amarillas o moradas — la variedad naranja fue seleccionada por horticultores holandeses en el siglo XVII.","La leyenda dice que fue un homenaje a la Casa de Orange, pero los historiadores creen que fue simplemente porque la variedad naranja era más dulce y menos amarga.","Las zanahorias moradas originales están regresando a los mercados como producto gourmet — contienen antocianinas, los mismos antioxidantes presentes en los arándanos."]},
  'f7':{fr:["Le Nutella a été créé en 1964, mais sa recette est basée sur une pâte appelée « Supercrema » inventée en 1951.","Un pot de Nutella est vendu toutes les 2,5 secondes dans le monde.","Si toute la production annuelle de Nutella était étalée sur des tartines, elles couvriraient 1 000 terrains de football."],en:["Nutella was created in 1964 but its recipe is based on a paste called 'Supercrema' invented in 1951.","A jar of Nutella is sold every 2.5 seconds worldwide.","If all yearly Nutella production were spread on toast, it would cover 1,000 football fields."],
    es:["El café es la segunda mercancía más comercializada del mundo después del petróleo, y más de 2 000 millones de tazas se consumen cada día en el planeta.","La leyenda atribuye su descubrimiento a un pastor etíope llamado Kaldi que notó que sus cabras se ponían hiperactivas tras comer las bayas de un arbusto.","Finlandia es el mayor consumidor de café per cápita del mundo, con unos 12 kg por persona al año — los finlandeses incluso tienen una pausa café legalmente protegida en el trabajo."]},
  'f8':{fr:["L'assiette en plomb des Européens se dissolvait au contact de l'acidité de la tomate, provoquant un empoisonnement.","La tomate est originaire d'Amérique du Sud et n'est arrivée en Europe qu'au XVIe siècle.","Techniquement, la tomate est un fruit — mais la Cour suprême américaine l'a classée comme légume en 1893."],en:["Europeans' lead plates dissolved on contact with tomato acid, causing poisoning.","Tomatoes originated in South America and didn't reach Europe until the 16th century.","Technically, the tomato is a fruit — but the US Supreme Court classified it as a vegetable in 1893."],
    es:["Las fresas no son bayas en el sentido botánico — son «falsos frutos»: la parte roja es en realidad el receptáculo floral, y los verdaderos frutos son los puntitos de la superficie.","En cambio, los plátanos, los aguacates, las sandías y los kiwis son botánicamente bayas, porque se desarrollan a partir de un solo ovario con semillas incrustadas.","Esta clasificación sorprendente se debe a que la botánica define «baya» de forma muy precisa: un fruto carnoso derivado de un solo ovario que contiene semillas en su interior."]},
  'f9':{fr:["Les fortune cookies sont totalement inconnus en Chine — les Chinois sont souvent surpris de les voir dans les restaurants américains.","Un boulanger japonais de San Francisco, Makoto Hagiwara, les a popularisés au début du XXe siècle.","Trois milliards de fortune cookies sont produits chaque année — presque uniquement pour le marché américain."],en:["Fortune cookies are completely unknown in China — Chinese people are often surprised to see them in American restaurants.","A Japanese baker in San Francisco, Makoto Hagiwara, popularized them in the early 20th century.","3 billion fortune cookies are produced each year — almost exclusively for the American market."],
    es:["La capsaicina, molécula responsable del picante, no produce quemaduras reales: engaña a los receptores TRPV1 de la lengua haciéndoles enviar una falsa señal de calor al cerebro.","Los mamíferos evitan el picante, pero las aves no poseen receptores TRPV1 — las plantas de chile evolucionaron para que los pájaros dispersen sus semillas sin ser comidas por mamíferos.","La escala Scoville mide el picante: un pimiento jalapeño alcanza 8 000 unidades, mientras que el Carolina Reaper supera los 2 200 000 — más de 200 veces más picante."]},
  'f10':{fr:["Le chocolat blanc est composé de beurre de cacao, de sucre et de lait — sans pâte de cacao.","Il a été inventé par Nestlé en Suisse dans les années 1930 pour utiliser les surplus de beurre de cacao.","Techniquement, certains pays ne l'autorisent pas à porter le nom « chocolat » sur l'emballage."],en:["White chocolate is made of cocoa butter, sugar, and milk — no cocoa paste.","It was invented by Nestlé in Switzerland in the 1930s to use surplus cocoa butter.","Technically, some countries don't allow it to be labeled 'chocolate' on packaging."],
    es:["El Nutella fue inventado en 1946 por Pietro Ferrero en Alba, Italia, como solución a la escasez de cacao en la posguerra: añadió avellanas del Piamonte para estirar el chocolate.","Hoy se producen unas 365 000 toneladas de Nutella al año, y la empresa Ferrero consume el 25 % de la producción mundial de avellanas.","Si se apilaran todos los tarros de Nutella vendidos en un año, la torre resultante mediría 200 veces la altura del monte Everest."]},
  'f11':{fr:["Le miel ne se périme pas grâce à sa faible teneur en eau et son pH acide qui empêchent les bactéries de proliférer.","Les abeilles ajoutent une enzyme (glucose oxydase) qui produit du peroxyde d'hydrogène — un antiseptique naturel.","Les Égyptiens utilisaient le miel pour embaumer les morts et soigner les blessures — ses propriétés antibactériennes sont confirmées par la science moderne."],en:["Honey doesn't spoil thanks to its low water content and acidic pH that prevent bacteria from growing.","Bees add an enzyme (glucose oxidase) that produces hydrogen peroxide — a natural antiseptic.","Egyptians used honey for embalming the dead and treating wounds — its antibacterial properties are confirmed by modern science."],
    es:["Los europeos creyeron durante siglos que los tomates eran venenosos, principalmente porque su acidez disolvía el plomo de los platos de estaño, envenenando a los aristócratas.","El tomate, originario de Mesoamérica, llegó a Europa en el siglo XVI como planta ornamental antes de convertirse en ingrediente culinario en Italia hacia el siglo XVIII.","Italia consume hoy más de 6 millones de toneladas de tomates al año — la salsa de tomate es probablemente la contribución culinaria más influyente del Nuevo Mundo al Viejo."]},
  'f12':{fr:["La famille des Rosacées comprend plus de 3 000 espèces et est l'une des plus importantes pour l'alimentation humaine.","Les amandes sont aussi des Rosacées — le fruit est en réalité le noyau d'un fruit ressemblant à une pêche.","Les roses elles-mêmes sont comestibles — l'eau de rose est utilisée dans la cuisine du Moyen-Orient depuis des millénaires."],en:["The Rosaceae family includes over 3,000 species and is one of the most important for human food.","Almonds are also Rosaceae — the nut is actually the pit of a peach-like fruit.","Roses themselves are edible — rosewater has been used in Middle Eastern cuisine for millennia."],
    es:["Las galletas de la fortuna no tienen nada de chinas: fueron inventadas en Japón y popularizadas en Estados Unidos por inmigrantes japoneses a principios del siglo XX.","Durante la Segunda Guerra Mundial, los japoneses-estadounidenses fueron internados en campos y sus negocios de galletas fueron retomados por empresarios chinos — lo que creó la asociación con la cocina china.","Hoy se fabrican más de 3 000 millones de galletas de la fortuna al año, casi exclusivamente para el mercado estadounidense — en China son prácticamente desconocidas."]},
  'f13':{fr:["La pollinisation manuelle est nécessaire car l'abeille native du Mexique, seule capable de polliniser naturellement la vanille, n'existe pas ailleurs.","La vanille est la deuxième épice la plus chère au monde après le safran.","Madagascar produit environ 80 % de la vanille mondiale — son prix peut dépasser celui de l'argent au kilo."],en:["Manual pollination is needed because the native Mexican bee, the only one capable of naturally pollinating vanilla, doesn't exist elsewhere.","Vanilla is the second most expensive spice after saffron.","Madagascar produces about 80% of the world's vanilla — its price can exceed silver per kilo."],
    es:["El chocolate blanco no es técnicamente chocolate porque no contiene sólidos de cacao — solo manteca de cacao, azúcar y leche.","La manteca de cacao es la grasa natural del grano de cacao, responsable de la textura fundente del chocolate — pero sin los sólidos, no hay sabor a chocolate.","El primer chocolate blanco comercial fue el Milkybar de Nestlé, lanzado en 1936 en el Reino Unido — inicialmente fue rechazado por los puristas del chocolate."]},
  'f14':{fr:["Ferrero achète environ un quart de la production mondiale de noisettes, principalement en Turquie.","L'usine principale d'Alba, en Italie, produit environ 365 000 tonnes de Nutella par an.","Le Nutella a été inspiré par la tradition piémontaise du « gianduja » — un mélange chocolat-noisette du XIXe siècle."],en:["Ferrero buys about a quarter of the world's hazelnut production, mainly from Turkey.","The main factory in Alba, Italy produces about 365,000 tons of Nutella per year.","Nutella was inspired by the Piedmontese tradition of 'gianduja' — a 19th-century chocolate-hazelnut blend."],
    es:["El sushi no era originalmente un plato japonés refinado: nació en el sudeste asiático como método de conservación del pescado en arroz fermentado.","El arroz se descartaba inicialmente y solo se comía el pescado preservado — el nigiri-zushi (pescado sobre arroz) tal como lo conocemos fue inventado en Edo (Tokio) en el siglo XIX.","En Japón, convertirse en maestro sushiya requiere un aprendizaje de al menos 10 años: tres años solo para aprender a cocinar el arroz perfectamente."]},
  'f15':{fr:["Les meules de parmesan sont affinées pendant au moins 12 mois — les meilleures pendant 36 mois ou plus.","Une meule standard pèse environ 38 kg et nécessite 550 litres de lait pour être produite.","Les banques italiennes stockent environ 430 000 meules — une garantie estimée à 4,5 milliards d'euros."],en:["Parmesan wheels are aged for at least 12 months — the best for 36 months or more.","A standard wheel weighs about 38 kg and requires 550 liters of milk to produce.","Italian banks store about 430,000 wheels — collateral worth an estimated €4.5 billion."],
    es:["La vainilla es la segunda especia más cara del mundo después del azafrán — una vaina de vainilla natural puede costar más de 500 dólares el kilo.","Proviene de una orquídea (Vanilla planifolia) originaria de México, polinizada naturalmente por una abeja endémica — fuera de México, cada flor debe polinizarse a mano.","El 99 % del «sabor vainilla» usado en la industria alimentaria es sintético (vanillina), derivado de la madera, el petróleo o incluso de secreciones de castor (castóreo)."]},
  'f16':{fr:["Le comté est le fromage le plus volé en France, suivi du camembert.","Le vol de fromage est parfois appelé le « fromage run » par les agents de sécurité des supermarchés.","Le marché noir du fromage est estimé à plusieurs millions d'euros en Europe."],en:["Comté is the most stolen cheese in France, followed by Camembert.","Cheese theft is sometimes called the 'cheese run' by supermarket security.","The cheese black market is estimated at several million euros in Europe."],
    es:["El wasabi auténtico es una de las plantas más difíciles de cultivar: crece solo en lechos de ríos de montaña a temperaturas estables entre 8 y 20 °C.","El 95 % del wasabi servido fuera de Japón es en realidad rábano picante teñido de verde con colorante — el wasabi real cuesta más de 200 euros el kilo.","El wasabi genuino se ralla justo antes de servir porque pierde su sabor en 15 minutos — un lujo que incluso muchos restaurantes japoneses no pueden permitirse."]},
  'f17':{fr:["Le vrai wasabi est si cher car la plante met 2 ans à pousser et ne pousse que dans des conditions très spécifiques.","Le wasabi perd sa saveur en 15 minutes après avoir été râpé — c'est pourquoi il est râpé à la commande dans les restaurants haut de gamme.","Le raifort coloré est 10 fois moins cher que le vrai wasabi, mais la différence de goût est notable pour les connaisseurs."],en:["Real wasabi is expensive because the plant takes 2 years to grow in very specific conditions.","Wasabi loses its flavor 15 minutes after grating — that's why it's grated to order in high-end restaurants.","Colored horseradish is 10 times cheaper but the taste difference is notable for connoisseurs."],
    es:["El champán solo puede llamarse así si procede de la región de Champagne, en el noreste de Francia — todo lo demás es «vino espumoso» o «cava».","El monje Dom Pérignon no inventó el champán: la efervescencia era un defecto no deseado. Su contribución fue perfeccionar el ensamblaje de uvas y el uso de tapones de corcho.","Una botella de champán contiene unas 49 millones de burbujas y la presión interior es de 6 atmósferas — el triple de la presión de un neumático de coche."]},
  'f18':{fr:["Le durian est interdit dans les hôtels, avions et métros de Singapour, Malaisie et Thaïlande.","Malgré son odeur, le durian est appelé « roi des fruits » en Asie du Sud-Est pour son goût crémeux unique.","Certaines personnes décrivent son goût comme un mélange de crème anglaise, d'amandes et de vanille."],en:["Durian is banned in hotels, planes, and subways in Singapore, Malaysia, and Thailand.","Despite its smell, durian is called the 'king of fruits' in Southeast Asia for its unique creamy taste.","Some describe its flavor as a mix of custard, almonds, and vanilla."],
    es:["El pan es uno de los alimentos más antiguos: se han encontrado restos de pan de 14 000 años en un yacimiento jordano, anterior a la agricultura.","La fermentación del pan con levadura fue probablemente descubierta por accidente en el antiguo Egipto, donde la masa olvidada empezó a crecer sola gracias a levaduras ambientales.","Francia consume más de 10 000 millones de baguettes al año, y la baguette fue inscrita en el Patrimonio Cultural Inmaterial de la UNESCO en 2022."]},
  'f19':{fr:["La muscade était si précieuse au XVIIe siècle que les Hollandais ont échangé l'île de Manhattan contre l'île de Run, productrice de muscade.","Le safran reste l'épice la plus chère au monde — 1 kg nécessite 150 000 fleurs de crocus récoltées à la main.","Les Routes de la Soie tiraient leur nom du commerce des épices autant que de la soie elle-même."],en:["Nutmeg was so valuable in the 17th century that the Dutch traded Manhattan Island for the nutmeg-producing island of Run.","Saffron remains the world's most expensive spice — 1 kg requires 150,000 hand-picked crocus flowers.","The Silk Roads were named for the spice trade as much as silk itself."],
    es:["El azafrán es la especia más cara del mundo: se necesitan 150 000 flores de azafrán (Crocus sativus) para obtener un kilo, recolectadas a mano una por una.","Cada flor produce solo tres estigmas rojos, que deben recogerse al amanecer antes de que el sol las abra completamente — es una cosecha extremadamente laboriosa.","Irán produce el 90 % del azafrán mundial, pero la mejor calidad es disputada por los productores de La Mancha (España) y Cachemira (India)."]},
  'f20':{fr:["La légende dit que la pizza Margherita représente le drapeau italien : tomate (rouge), mozzarella (blanc) et basilic (vert).","Naples a inscrit l'art du pizzaiolo napolitain au patrimoine immatériel de l'UNESCO en 2017.","La pizza hawaïenne (avec ananas) a en fait été inventée au Canada par un immigré grec en 1962."],en:["Legend says pizza Margherita represents the Italian flag: tomato (red), mozzarella (white), and basil (green).","Naples inscribed Neapolitan pizza-making as UNESCO Intangible Cultural Heritage in 2017.","Hawaiian pizza (with pineapple) was actually invented in Canada by a Greek immigrant in 1962."],
    es:["El umami, el quinto sabor básico junto con dulce, salado, ácido y amargo, fue descubierto en 1908 por el químico japonés Kikunae Ikeda al estudiar el dashi (caldo de alga kombu).","Ikeda aisló el glutamato monosódico como la molécula responsable y lo comercializó como el condimento Ajinomoto — hoy uno de los aditivos más usados del mundo.","El umami está presente en alimentos ricos en glutamato: parmesano, tomates maduros, salsa de soja, anchoas, setas shiitake y jamón ibérico."]},
  // === FUN ===
  'u1':{fr:["La dose de radiation d'une banane est appelée BED (Banana Equivalent Dose) — elle sert de référence humoristique en physique nucléaire.","Les bananes sont courbées car elles poussent vers le soleil en s'éloignant de la gravité — un phénomène appelé géotropisme négatif.","Le potassium-40 radioactif des bananes est aussi présent dans les haricots, les pommes de terre et le corps humain."],en:["A banana's radiation dose is called BED (Banana Equivalent Dose) — used as a humorous nuclear physics reference.","Bananas are curved because they grow toward the sun against gravity — called negative geotropism.","Radioactive potassium-40 in bananas is also in beans, potatoes, and the human body."],
    es:["La dosis de radiación de una banana se llama BED (Banana Equivalent Dose) — es de unos 0,1 microsieverts, completamente inofensiva.","Necesitarías comer 10 millones de bananas de una vez para recibir una dosis peligrosa de radiación.","El potasio-40 de las bananas es el mismo isótopo que se encuentra en tu propio cuerpo — eres más radiactivo que una banana."]},
  'u2':{fr:["La blatte survit car elle respire par des spiracles sur son corps — elle n'a pas besoin de sa tête pour respirer.","Elle meurt finalement de soif car elle ne peut plus boire sans sa tête.","Les blattes existent depuis plus de 300 millions d'années — elles ont survécu à toutes les extinctions de masse."],en:["The cockroach survives because it breathes through spiracles on its body — it doesn't need its head to breathe.","It eventually dies of thirst because it can no longer drink without its head.","Cockroaches have existed for over 300 million years — they survived all mass extinctions."],
    es:["La cucaracha sobrevive sin cabeza porque respira por espiráculos en su cuerpo — no necesita la boca para respirar.","Muere finalmente de deshidratación tras unas semanas porque no puede beber agua sin cabeza.","Las cucarachas existen desde hace 300 millones de años — sobrevivieron a los dinosaurios y probablemente nos sobrevivirán a nosotros."]},
  'u3':{fr:["Tous les noms d'éléments utilisent les lettres a à i et k à z — le J est la seule lettre manquante.","L'élément 101 s'appelle Mendélévium, en l'honneur du créateur du tableau, Dimitri Mendeleïev.","Il y a 118 éléments dans le tableau périodique actuel — les 4 derniers ont été ajoutés en 2016."],en:["All element names use letters a-i and k-z — J is the only missing letter.","Element 101 is called Mendelevium, honoring the table's creator, Dmitri Mendeleev.","There are 118 elements in the current periodic table — the last 4 were added in 2016."],
    es:["Todos los nombres de elementos químicos usan las letras de la A a la I y de la K a la Z — la J es la única que nunca aparece.","Esto se debe a que los nombres derivan del latín, griego, alemán e inglés — lenguas donde la J es rara o inexistente en la nomenclatura científica.","Incluso el Jodio se escribe Iodine en inglés y Iod en alemán — la J sigue resistiéndose a entrar en la tabla periódica."]},
  'u4':{fr:["L'oxygène liquide est aussi magnétique — il est attiré par les aimants, contrairement à l'eau.","Il bout à -183 °C et est utilisé comme comburant dans les fusées spatiales.","L'air que tu respires contient 21 % d'oxygène — si ce taux montait à 25 %, les forêts s'enflammeraient spontanément."],en:["Liquid oxygen is also magnetic — attracted to magnets, unlike water.","It boils at -183°C and is used as an oxidizer in space rockets.","The air you breathe contains 21% oxygen — if it rose to 25%, forests would spontaneously combust."],
    es:["El oxígeno líquido es también magnético — es atraído por los imanes, al contrario de lo que la mayoría de la gente espera de un gas licuado.","Este paramagnetismo se debe a los dos electrones desapareados de la molécula de O₂ — una propiedad que la mecánica cuántica explica perfectamente.","El oxígeno líquido es de color azul pálido — el mismo fenómeno que da color al cielo y al hielo."]},
  'u5':{fr:["Le champignon force la fourmi à grimper en hauteur et à se fixer sous une feuille — la position idéale pour libérer ses spores.","Ce parasite a inspiré le jeu vidéo The Last of Us, où un champignon similaire infecte les humains.","Chaque espèce d'Ophiocordyceps ne cible qu'une seule espèce de fourmi — c'est une spécialisation extrême."],en:["The fungus forces the ant to climb high and attach under a leaf — the ideal position to release spores.","This parasite inspired the video game The Last of Us, where a similar fungus infects humans.","Each Ophiocordyceps species targets only one ant species — extreme specialization."],
    es:["El hongo obliga a la hormiga a trepar a una altura específica y fijarse bajo una hoja antes de morir — un control del comportamiento escalofriante.","El hongo Ophiocordyceps manipula los músculos mandibulares de la hormiga para que muerda la nervadura de la hoja con una fuerza mortal.","Una vez fijada, el hongo brota de la cabeza de la hormiga para liberar esporas sobre las hormigas que pasan por debajo — un ciclo de vida digno de ciencia ficción."]},
  'u6':{fr:["Ton estomac se protège en produisant une nouvelle couche de mucus toutes les deux semaines.","Si tu avales une pièce de monnaie, l'acide gastrique ne la dissoudra pas — les métaux modernes résistent.","L'acide gastrique est assez puissant pour dissoudre du zinc en quelques heures."],en:["Your stomach protects itself by producing a new mucus layer every two weeks.","If you swallow a coin, stomach acid won't dissolve it — modern metals resist.","Stomach acid is powerful enough to dissolve zinc in a few hours."],
    es:["Tu estómago se protege produciendo una nueva capa de moco cada dos semanas — sin ella, se digeriría a sí mismo.","El ácido clorhídrico gástrico tiene un pH de 1,5-3,5 — lo bastante fuerte como para disolver metales.","Las úlceras gástricas ocurren cuando la bacteria Helicobacter pylori debilita la capa de moco — un descubrimiento que valió el Nobel en 2005."]},
  'u7':{fr:["L'univers observable contient environ 2 000 milliards de galaxies, chacune avec des milliards d'étoiles.","Le nombre estimé de grains de sable sur Terre est d'environ 7,5 × 10¹⁸ — les étoiles sont au moins 10 fois plus nombreuses.","Malgré ces nombres vertigineux, l'univers est composé à 99,9999 % de vide."],en:["The observable universe contains about 2 trillion galaxies, each with billions of stars.","The estimated number of sand grains on Earth is about 7.5 × 10¹⁸ — stars outnumber them at least 10 to 1.","Despite these staggering numbers, the universe is 99.9999% empty space."],
    es:["El universo observable contiene unos 2 billones de galaxias, cada una con cientos de miles de millones de estrellas.","Pese a esta inmensidad, el 95 % del universo está compuesto de materia y energía oscuras que nunca hemos observado directamente.","Si el universo fuera del tamaño de la Tierra, la parte que podemos ver sería más pequeña que un grano de arena."]},
  'u8':{fr:["Son venin contient de la tétrodotoxine — la même toxine que le poisson-globe.","Elle mesure seulement 12 cm mais est considérée comme l'animal marin le plus dangereux d'Australie.","Il n'existe aucun antivenin efficace — le seul traitement est la respiration artificielle jusqu'à élimination du venin."],en:["Its venom contains tetrodotoxin — the same toxin as the pufferfish.","It measures only 12 cm but is considered Australia's most dangerous marine animal.","No effective antivenom exists — the only treatment is artificial respiration until the venom clears."],
    es:["Su veneno contiene tetrodotoxina — la misma toxina que el pez globo — en cantidad suficiente para matar a 26 humanos adultos.","La picadura es indolora inicialmente, lo que hace que muchas víctimas no busquen ayuda a tiempo.","No existe antídoto: el único tratamiento es el soporte vital hasta que el cuerpo metaboliza la toxina — un proceso que puede durar 24 horas."]},
  'u9':{fr:["Ta bouche contient plus de 700 espèces de bactéries — c'est l'un des écosystèmes les plus diversifiés du corps.","Un baiser de 10 secondes transfère environ 80 millions de bactéries entre deux personnes.","La salive contient des composés antibactériens qui empêchent la plupart de ces bactéries de causer des maladies."],en:["Your mouth contains over 700 bacterial species — one of the body's most diverse ecosystems.","A 10-second kiss transfers about 80 million bacteria between two people.","Saliva contains antibacterial compounds that prevent most of these bacteria from causing disease."],
    es:["Tu boca contiene más de 700 especies de bacterias — es uno de los ecosistemas más diversos del cuerpo humano.","La mayoría son inofensivas o beneficiosas: ayudan a la digestión, protegen contra patógenos y mantienen el pH bucal.","Un beso de 10 segundos transfiere unos 80 millones de bacterias entre dos personas — una intimidad biológica real."]},
  'u10':{fr:["L'énergie thermique dépend de la masse totale — un iceberg a des milliards de fois plus de molécules qu'une allumette.","Même à -10 °C, chaque molécule d'eau d'un iceberg possède de l'énergie thermique — il y en a juste des trillions.","Ce principe est utilisé en géo-ingénierie : certains proposent de remorquer des icebergs pour fournir de l'eau douce aux régions arides."],en:["Thermal energy depends on total mass — an iceberg has billions more molecules than a match.","Even at -10°C, every water molecule in an iceberg has thermal energy — there are just trillions of them.","This principle is used in geoengineering: some propose towing icebergs to supply fresh water to arid regions."],
    es:["La energía térmica depende de la masa total — un iceberg tiene miles de millones de veces más energía térmica que una taza de café caliente.","La temperatura mide la energía cinética media de las moléculas — pero la energía total depende del número de moléculas.","Por eso el océano, aunque esté a 4 °C, contiene más energía térmica que toda la lava del Etna — la masa lo es todo en termodinámica."]},
  'u11':{fr:["Le terme « tittle » vient du latin titulus signifiant inscription.","En typographie, le point du i est si important qu'oublier de le placer peut changer le sens d'un mot dans certaines langues.","La lettre J n'existait pas avant le XVIe siècle — elle s'est séparée du I dans les langues européennes."],en:["The term 'tittle' comes from Latin titulus meaning inscription.","In typography, the dot on the i is so important that forgetting it can change a word's meaning in some languages.","The letter J didn't exist before the 16th century — it separated from I in European languages."],
    es:["El término «tittle» proviene del latín titulus, que significa inscripción o marca.","En tipografía, el punto sobre la i es tan importante que olvidarlo puede cambiar el significado de una palabra en ciertos idiomas.","La letra J no existía antes del siglo XVI — se separó de la I en las lenguas europeas, y ambas conservaron su tittle."]},
  'u12':{fr:["Le test a été réalisé à l'université de Kyoto — les chimpanzés mémorisent la position de 9 chiffres en moins de 200 millisecondes.","Cette capacité s'appelle la mémoire eidétique — elle est beaucoup plus développée chez les jeunes chimpanzés que chez les humains.","Les chercheurs pensent que les humains ont échangé cette capacité pour développer le langage."],en:["The test was done at Kyoto University — chimps memorize 9 digit positions in under 200 milliseconds.","This ability is called eidetic memory — much more developed in young chimps than humans.","Researchers believe humans traded this ability for language development."],
    es:["El primatólogo Tetsuro Matsuzawa demostró en 2007 que los chimpancés jóvenes memorizan secuencias numéricas con una rapidez que supera a cualquier humano adulto.","Esta capacidad se denomina memoria eidética de trabajo y podría ser un vestigio evolutivo que los humanos perdieron al desarrollar el lenguaje.","El chimpancé estrella del estudio, Ayumu, logra recordar la posición de nueve dígitos mostrados durante apenas 210 milisegundos."]},
  'u13':{fr:["L'enzyme PETase a été améliorée en laboratoire pour être 6 fois plus rapide que la version naturelle.","Le plastique PET met normalement 500 ans à se décomposer — cette enzyme le fait en quelques heures.","Des start-ups travaillent déjà à industrialiser le processus pour recycler les bouteilles en plastique à grande échelle."],en:["The PETase enzyme was improved in the lab to be 6 times faster than the natural version.","PET plastic normally takes 500 years to decompose — this enzyme does it in hours.","Startups are already working to industrialize the process for large-scale plastic bottle recycling."],
    es:["La enzima PETasa fue descubierta por casualidad en 2016 en una bacteria japonesa que vivía cerca de una planta de reciclaje de plástico.","En 2022, investigadores de la Universidad de Texas crearon una variante optimizada capaz de degradar el PET en tan solo unas horas a temperatura ambiente.","Este avance podría revolucionar el reciclaje: en lugar de fundir el plástico, la enzima lo descompone en sus componentes químicos originales, reutilizables al 100 %."]},
  'u14':{fr:["Les chats reconnaissent aussi la voix de leur propriétaire mais ne réagissent que quand ça les arrange.","Ils communiquent davantage par miaulements avec les humains qu'entre eux — entre chats, ils utilisent surtout le langage corporel.","Les chats ronronnent à une fréquence de 25-50 Hz, qui est connue pour favoriser la guérison des os et des tissus."],en:["Cats also recognize their owner's voice but only respond when it suits them.","They communicate more through meowing with humans than with each other — between cats, they mainly use body language.","Cats purr at 25-50 Hz, a frequency known to promote bone and tissue healing."],
    es:["Un estudio publicado en Scientific Reports en 2019 demostró que los gatos domésticos distinguen su nombre de otras palabras, incluso pronunciadas por desconocidos.","A diferencia de los perros, los gatos no han sido seleccionados genéticamente para obedecer — su domesticación fue un proceso mucho más reciente y menos dirigido.","Los investigadores observaron que los gatos reaccionan con movimientos sutiles de orejas y cabeza, pero rara vez se acercan — una indiferencia perfectamente calculada."]},
  'u15':{fr:["Les flamants roses naissent gris-blanc — leur couleur rose vient des pigments caroténoïdes des crevettes et algues qu'ils mangent.","Sans ces pigments dans leur alimentation, ils redeviennent blancs en quelques mois.","En captivité, les zoos ajoutent des compléments alimentaires pour maintenir leur couleur rose."],en:["Flamingos are born grey-white — their pink color comes from carotenoid pigments in the shrimp and algae they eat.","Without these pigments in their diet, they turn white again within months.","In captivity, zoos add dietary supplements to maintain their pink color."],
    es:["Los flamencos nacen con plumaje gris o blanco — su color rosado aparece gradualmente gracias a los pigmentos carotenoides de su dieta de crustáceos y algas.","En cautiverio, los flamencos pueden perder su color si no reciben una alimentación adecuada, por lo que los zoológicos añaden suplementos de carotenoides a su comida.","El término «flamboyance» para un grupo de flamencos proviene del francés antiguo flambe (llama), aludiendo al espectáculo visual de una bandada en vuelo."]},
  'u16':{fr:["Le pistolet shrimp produit aussi un flash de lumière quand sa bulle éclate — un phénomène appelé sonoluminescence.","Le bruit est si puissant qu'il interfère avec les sonars des sous-marins militaires.","Certaines espèces vivent en colonies avec une reine, comme les fourmis — le seul crustacé eusocial connu."],en:["The pistol shrimp also produces a light flash when its bubble bursts — a phenomenon called sonoluminescence.","The noise is so powerful it interferes with military submarine sonar.","Some species live in colonies with a queen, like ants — the only known eusocial crustacean."],
    es:["El camarón pistola cierra su pinza a tal velocidad que genera una burbuja de cavitación cuyo colapso produce un destello de luz y temperaturas cercanas a 4 700 °C.","El chasquido resultante alcanza los 218 decibelios bajo el agua — más fuerte que un disparo de arma de fuego y suficiente para aturdir o matar a pequeñas presas.","Colonias de camarones pistola producen tanto ruido que interfieren con los sónares de los submarinos militares, creando un muro de sonido subacuático."]},
  'u17':{fr:["La crevette mante a les yeux les plus complexes du règne animal — elle voit 16 types de couleurs (l'humain en voit 3).","Ses coups sont si rapides que l'eau autour de son poing atteint momentanément la température du soleil.","Certains aquariums utilisent du verre blindé pour la contenir car elle peut briser le verre ordinaire."],en:["The mantis shrimp has the most complex eyes in the animal kingdom — seeing 16 color types (humans see 3).","Its strikes are so fast the water around its fist momentarily reaches the sun's temperature.","Some aquariums use bulletproof glass to contain it because it can break regular glass."],
    es:["La mantis marina (Stomatopoda) posee los golpes más rápidos del reino animal: su pinza se despliega en menos de 3 milisegundos, alcanzando una aceleración comparable a la de una bala calibre .22.","El impacto es tan violento que genera burbujas de cavitación que colapsan a temperaturas de hasta 4 000 °C, causando un segundo golpe de daño a la presa.","Sus ojos son los más complejos conocidos: detectan 16 tipos de receptores de color (los humanos tienen 3) y perciben luz polarizada y ultravioleta."]},
  'u18':{fr:["Les harengs émettent ces sons principalement la nuit, formant des réseaux de communication acoustique sous-marine.","Les scientifiques ont nommé ces sons FRT (Fast Repetitive Tick) — un acronyme qui les fait sourire.","Cette découverte a valu à ses auteurs le prix Ig Nobel de biologie en 2004."],en:["Herring emit these sounds mainly at night, forming underwater acoustic communication networks.","Scientists named these sounds FRT (Fast Repetitive Tick) — an acronym that makes them smile.","This discovery earned its authors the Ig Nobel Prize in biology in 2004."],
    es:["Los arenques expulsan burbujas de aire por el ano para comunicarse en la oscuridad del fondo marino — un mecanismo llamado Fast Repetitive Tick (FRT).","Los investigadores Ben Wilson y Bob Batty descubrieron este fenómeno en 2003 y recibieron el Premio Ig Nobel de Biología por su hallazgo.","Estas burbujas no son producto de la digestión: los arenques tragan aire en la superficie y lo liberan voluntariamente, probablemente para mantener cohesión en el cardumen durante la noche."]},
  'u19':{fr:["Chaque nombril a un écosystème microbien unique — comme une empreinte digitale bactérienne.","Le projet Belly Button Biodiversity a identifié plus de 2 300 espèces de bactéries en étudiant 60 nombrils.","Certaines bactéries trouvées dans des nombrils n'avaient jamais été observées nulle part ailleurs sur Terre."],en:["Each belly button has a unique microbial ecosystem — like a bacterial fingerprint.","The Belly Button Biodiversity project identified over 2,300 bacterial species studying 60 navels.","Some bacteria found in belly buttons had never been observed anywhere else on Earth."],
    es:["El proyecto Belly Button Biodiversity de la Universidad de Carolina del Norte identificó más de 2 300 especies de bacterias en los ombligos de apenas 60 voluntarios.","Cada persona alberga una combinación única de microorganismos — una especie de huella digital bacteriana imposible de duplicar.","Entre los hallazgos más sorprendentes: bacterias típicas del suelo japonés en alguien que nunca había visitado Japón, y arqueas normalmente asociadas a fuentes termales."]},
  'u20':{fr:["Le homard peut aussi régénérer ses pattes et ses pinces s'il les perd au combat.","La mue est le moment le plus dangereux de sa vie — il est vulnérable pendant que sa nouvelle carapace durcit.","Un homard américain géant capturé en 2009 pesait 9 kg et avait un âge estimé de 140 ans."],en:["Lobsters can also regenerate legs and claws if lost in combat.","Molting is the most dangerous moment of their life — they're vulnerable while the new shell hardens.","A giant American lobster caught in 2009 weighed 9 kg with an estimated age of 140 years."],
    es:["Los bogavantes escapan de los depredadores mediante un reflejo llamado «caridoid escape reaction»: flexionan su cola musculosa y se propulsan hacia atrás a más de 5 m/s.","Esta técnica es tan eficaz que algunos bogavantes pueden recorrer varios metros en una sola sacudida, desapareciendo de la vista del depredador en milisegundos.","A pesar de su fama culinaria, los bogavantes pueden vivir más de 100 años y no muestran signos de envejecimiento biológico — un fenómeno llamado senescencia despreciable."]},
  // === GAMING ===
  'gam1':{fr:["Avant Mario, le personnage s'appelait Jumpman dans le jeu original Donkey Kong en 1981.","Mario a été plombier car les premiers jeux se déroulaient dans des sous-sols avec des tuyaux.","Mario est le personnage de jeu vidéo le plus reconnu au monde — devant Pac-Man et Sonic."],en:["Before Mario, the character was called Jumpman in the original 1981 Donkey Kong.","Mario became a plumber because early games took place in basements with pipes.","Mario is the most recognized video game character — ahead of Pac-Man and Sonic."],
    es:["Pong (1972) de Atari no fue el primer videojuego, pero fue el primero en tener éxito comercial — sus máquinas recreativas se averiaban porque las cajas se llenaban de monedas.","El primer videojuego reconocido es Tennis for Two (1958), creado por el físico William Higinbotham en un osciloscopio del laboratorio nacional de Brookhaven.","Pong era tan simple que su manual de instrucciones decía: «Evita perder la pelota para conseguir una puntuación alta» — una época en que la simplicidad era virtud."]},
  'gam2':{fr:["Le nom original de Pac-Man était Puck-Man, mais il a été changé pour éviter le vandalisme sur les bornes d'arcade.","Le fantôme Blinky (rouge) est le seul qui poursuit directement le joueur — les autres ont des comportements programmés différents.","Le score parfait de Pac-Man est de 3 333 360 points — seule une poignée de joueurs l'a atteint."],en:["Pac-Man's original name was Puck-Man, changed to prevent vandalism on arcade machines.","Ghost Blinky (red) is the only one that directly chases the player — others have different programmed behaviors.","The perfect Pac-Man score is 3,333,360 — only a handful of players have achieved it."],
    es:["Super Mario Bros. (1985) salvó la industria del videojuego tras la crisis de 1983, que había reducido el mercado estadounidense de 3 200 a 100 millones de dólares.","Shigeru Miyamoto creó a Mario como un carpintero (luego fontanero) porque los bigotes eran más fáciles de animar que una boca con los píxeles disponibles en la NES.","Mario es el personaje de videojuego más reconocido del mundo — ha aparecido en más de 200 juegos y ha vendido más de 800 millones de copias en total."]},
  'gam3':{fr:["Serebrov a joué sur un Game Boy pendant sa mission de 196 jours à bord de la station Mir en 1993.","Le jeu a été créé sur un ordinateur Elektronika 60 sans graphismes — les blocs étaient des crochets.","Tetris a été utilisé dans des études scientifiques pour prouver qu'il réduit le stress et les symptômes de stress post-traumatique."],en:["Serebrov played on a Game Boy during his 196-day mission aboard the Mir station in 1993.","The game was created on an Elektronika 60 computer without graphics — blocks were brackets.","Tetris has been used in scientific studies proving it reduces stress and PTSD symptoms."],
    es:["Minecraft, creado por Markus «Notch» Persson en 2009, es el videojuego más vendido de la historia con más de 300 millones de copias.","El juego no tiene objetivos fijos: los jugadores construyen, exploran y sobreviven en un mundo infinito generado proceduralmente — una libertad creativa sin precedentes.","Microsoft compró Minecraft en 2014 por 2 500 millones de dólares — hoy se usa en escuelas de todo el mundo como herramienta educativa para enseñar programación, arquitectura y colaboración."]},
  'gam4':{fr:["Zelda Fitzgerald était connue pour son esprit libre et sa beauté — des qualités que Miyamoto admirait.","Link, le héros jouable, est souvent confondu avec Zelda par le grand public.","Le premier Zelda contenait un second jeu caché accessible en entrant ZELDA comme nom de sauvegarde."],en:["Zelda Fitzgerald was known for her free spirit and beauty — qualities Miyamoto admired.","Link, the playable hero, is often confused with Zelda by the general public.","The first Zelda contained a hidden second game accessible by entering ZELDA as the save name."],
    es:["La Game Boy de Nintendo (1989) vendió más de 118 millones de unidades a pesar de tener una pantalla monocroma y un procesador inferior a sus competidores.","Tetris, incluido con la Game Boy, fue creado en 1984 por el programador soviético Alexei Pajitnov en un ordenador del gobierno — los derechos fueron objeto de una guerra legal internacional.","La Game Boy era tan robusta que un ejemplar sobrevivió a un bombardeo durante la Guerra del Golfo y sigue funcionando — se exhibe en la Nintendo World Store de Nueva York."]},
  'gam5':{fr:["La couleur bleue a été choisie pour se démarquer de Mario (rouge) et pour évoquer la vitesse et la liberté.","Les anneaux dorés de Sonic étaient inspirés du concept du jeu de pinball.","Sonic a été la mascotte officielle de Sega et a brièvement détrôné Mario en popularité dans les années 90."],en:["Blue was chosen to stand out from Mario (red) and evoke speed and freedom.","Sonic's gold rings were inspired by the pinball concept.","Sonic was Sega's official mascot and briefly dethroned Mario in popularity in the 90s."],
    es:["World of Warcraft (2004) de Blizzard alcanzó 12 millones de suscriptores mensuales en su apogeo, convirtiéndolo en el MMORPG más exitoso de la historia.","La economía virtual de WoW es tan compleja que economistas la han estudiado como modelo de mercado: la inflación, la especulación y el comercio siguen patrones del mundo real.","En 2005, una plaga virtual (Corrupted Blood) se propagó accidentalmente por el juego, matando a miles de personajes — epidemiólogos usaron el incidente para estudiar la propagación de pandemias."]},
  'gam6':{fr:["Sakaguchi pensait quitter l'industrie du jeu vidéo si le jeu échouait — d'où le nom Final Fantasy.","Le jeu s'est finalement vendu à 2 millions d'exemplaires et a lancé une franchise de 180 millions d'unités vendues.","La série a introduit le système de combat au tour par tour qui a défini le genre JRPG pendant des décennies."],en:["Sakaguchi planned to leave the gaming industry if the game failed — hence Final Fantasy.","The game eventually sold 2 million copies and launched a franchise selling 180 million units.","The series introduced the turn-based combat system that defined the JRPG genre for decades."],
    es:["The Legend of Zelda (1986) fue revolucionario por ofrecer un mundo abierto no lineal donde el jugador podía explorar libremente — un concepto adelantado a su época.","Shigeru Miyamoto se inspiró en sus exploraciones de niño por las colinas y cuevas de Kioto para crear Hyrule — un mundo diseñado para evocar la sensación de descubrimiento.","Breath of the Wild (2017) redefinió el género de mundo abierto con una física emergente donde casi todo es interactivo — fue elegido Juego del Año por unanimidad."]},
  'gam7':{fr:["Persson a codé la première version en Java en mai 2009 — elle ne contenait que des blocs de terre et de pierre.","Le jeu a atteint un million de joueurs avant même sa sortie officielle en 2011.","Minecraft a engendré toute une sous-culture de YouTube — des créateurs comme PewDiePie ont bâti leur audience dessus."],en:["Persson coded the first version in Java in May 2009 — it only contained dirt and stone blocks.","The game reached one million players before its official 2011 release.","Minecraft spawned an entire YouTube subculture — creators like PewDiePie built their audiences on it."],
    es:["Pokémon Rojo y Azul (1996) vendieron más de 31 millones de copias y lanzaron una franquicia que supera los 100 000 millones de dólares — la más lucrativa del entretenimiento.","Satoshi Tajiri creó Pokémon inspirándose en su infancia coleccionando insectos en los campos de Tokio — la mecánica de captura y colección nació de esa pasión.","Pokémon GO (2016) generó un fenómeno social global: millones de personas salieron a la calle a capturar Pokémon virtuales, causando accidentes de tráfico y trespassing en masa."]},
  'gam8':{fr:["Les bruits de Grognards incluent aussi des réenregistrements de voix d'enfants accélérées et décalées en pitch.","Le compositeur Martin O'Donnell a enregistré la bande-son de Halo dans une église pour obtenir la réverbe caractéristique.","Le thème musical de Halo est devenu l'un des morceaux de jeu vidéo les plus reconnaissables au monde."],en:["Grunt sounds also include re-recorded children's voices sped up and pitch-shifted.","Composer Martin O'Donnell recorded Halo's soundtrack in a church for the characteristic reverb.","Halo's theme became one of the most recognizable video game music pieces worldwide."],
    es:["Grand Theft Auto V (2013) es el producto de entretenimiento más rentable de la historia: ha generado más de 8 000 millones de dólares, superando a cualquier película, libro o álbum.","Su mundo abierto de Los Santos (basado en Los Ángeles) es tan detallado que incluye un mercado de valores funcional que responde a las acciones de los jugadores en línea.","La serie GTA ha sido objeto de intensas polémicas por su violencia y su sátira de la sociedad estadounidense — sus críticos la acusan de glorificar el crimen, sus defensores la defienden como sátira social."]},
  'gam9':{fr:["Ce bug est devenu une feature — les joueurs ont adoré la difficulté croissante liée à la vitesse.","Space Invaders a provoqué une pénurie de pièces de 100 yens au Japon en 1978.","Le jeu a rapporté plus de 13 milliards de dollars en revenus d'arcade — plus que Star Wars au cinéma à l'époque."],en:["This bug became a feature — players loved the increasing difficulty from speed.","Space Invaders caused a shortage of 100-yen coins in Japan in 1978.","The game earned over $13 billion in arcade revenue — more than Star Wars at the box office at the time."],
    es:["Los esports mueven más de 1 800 millones de dólares al año y la final del Mundial de League of Legends atrae más espectadores que el Super Bowl.","Los jugadores profesionales entrenan 8-14 horas diarias, tienen nutricionistas, psicólogos deportivos y contratos millonarios — su vida es comparable a la de un atleta olímpico.","Corea del Sur es la superpotencia de los esports: los jugadores profesionales son celebridades nacionales y las partidas se retransmiten en canales de televisión dedicados."]},
  'gam10':{fr:["L'incident du « Sang corrompu » en 2005 a simulé une pandémie virtuelle qui a décimé des villes entières dans le jeu.","Des épidémiologistes ont étudié la propagation du virus dans WoW pour modéliser des scénarios réels de pandémie.","Le jeu comptait plus de 12 millions d'abonnés actifs en 2010 — l'équivalent de la population de la Belgique."],en:["The 2005 'Corrupted Blood' incident simulated a virtual pandemic that decimated entire in-game cities.","Epidemiologists studied virus spread in WoW to model real pandemic scenarios.","The game had over 12 million active subscribers in 2010 — equivalent to Belgium's population."],
    es:["Pac-Man (1980) fue diseñado por Toru Iwatani para atraer a un público femenino en las salas recreativas, dominadas por juegos de guerra y deportes.","La forma de Pac-Man se inspiró en una pizza a la que le faltaba un trozo — los fantasmas tienen nombres y personalidades: Blinky persigue, Pinky embosca, Inky es impredecible y Clyde va a su aire.","Pac-Man generó más de 2 500 millones de dólares en monedas en los años 80 — fue el primer personaje de videojuego en tener merchandising oficial."]},
  'gam11':{fr:["L'équipe a ajouté le mode multi en seulement 6 semaines, juste avant la date limite de livraison.","Le jeu n'était pas prévu pour avoir un mode multijoueur — le chef de projet ne l'avait pas autorisé.","GoldenEye a défini les standards du FPS console et prouvé que le genre pouvait fonctionner sans clavier-souris."],en:["The team added multiplayer in just 6 weeks, right before the delivery deadline.","The game wasn't supposed to have multiplayer — the project lead hadn't authorized it.","GoldenEye defined console FPS standards and proved the genre could work without keyboard-mouse."],
    es:["Dark Souls (2011) popularizó el género «soulslike»: juegos de acción-RPG conocidos por su dificultad extrema y su diseño de mundo interconectado.","Hidetaka Miyazaki, su director, se inspiró en libros de fantasía en inglés que no entendía del todo — rellenaba los vacíos con su imaginación, creando una narrativa intencionalmente fragmentaria.","La frase «You Died» se ha convertido en un meme cultural que simboliza la perseverancia ante el fracaso — toda una filosofía de diseño que ha influido en cientos de juegos posteriores."]},
  'gam12':{fr:["Wright s'est inspiré d'une fourmi-ferme électronique et de son expérience après avoir perdu sa maison dans un incendie.","Les Sims est le jeu PC le plus vendu de tous les temps avec plus de 200 millions d'exemplaires.","Le simlish, la langue fictive des Sims, a été créé pour éviter les coûts de traduction dans 20 langues."],en:["Wright was inspired by an electronic ant farm and his experience after losing his home in a fire.","The Sims is the best-selling PC game of all time with over 200 million copies.","Simlish, the Sims' fictional language, was created to avoid translation costs in 20 languages."],
    es:["Tetris es el juego más universal de la historia: se ha vendido en más de 500 millones de copias en todas las plataformas, desde el Game Boy hasta los smartphones.","Su creador Alexei Pajitnov no ganó nada durante años porque los derechos pertenecían al gobierno soviético — solo empezó a cobrar regalías tras la caída de la URSS.","Estudios científicos han demostrado que jugar a Tetris reduce los síntomas de estrés postraumático y las ansias de adicción — el fenómeno se conoce como «efecto Tetris»."]},
  'gam13':{fr:["Les policiers poursuivaient les joueurs de façon ultra-agressive à cause du bug — les développeurs ont trouvé ça hilarant.","GTA est l'une des franchises les plus lucratives de l'histoire du divertissement — plus de 8 milliards de dollars de revenus.","GTA V s'est vendu à plus de 200 millions d'exemplaires — le produit culturel le plus rentable jamais créé."],en:["Police chased players ultra-aggressively due to the bug — developers found it hilarious.","GTA is one of the most profitable entertainment franchises ever — over $8 billion in revenue.","GTA V sold over 200 million copies — the most profitable cultural product ever created."],
    es:["La PlayStation de Sony (1994) nació de una colaboración fallida con Nintendo: Sony iba a fabricar un periférico de CD para la SNES, pero Nintendo rompió el acuerdo — y Sony decidió crear su propia consola.","La primera PlayStation vendió más de 102 millones de unidades y derrocó a Nintendo como líder del mercado, inaugurando la era del CD y los gráficos 3D.","La rivalidad Sony-Nintendo-Microsoft ha impulsado la innovación tecnológica más rápida en la historia del entretenimiento electrónico."]},
  'gam14':{fr:["Les cartes de Nintendo étaient faites à la main avec de l'écorce de mûrier — elles étaient utilisées pour les jeux de hasard.","La société a aussi vendu des taxis, du riz instantané et géré des « love hotels » avant de se tourner vers les jeux vidéo.","Le nom Nintendo signifie approximativement « laissez la chance au ciel » en japonais."],en:["Nintendo cards were handmade from mulberry bark — used for gambling games.","The company also sold taxis, instant rice, and ran 'love hotels' before turning to video games.","The name Nintendo roughly means 'leave luck to heaven' in Japanese."],
    es:["Fortnite Battle Royale (2017) pasó de ser un modo de juego secundario a un fenómeno cultural global con más de 400 millones de cuentas registradas.","Epic Games generó más de 5 000 millones de dólares solo en 2018 con un juego gratuito — monetizado exclusivamente mediante cosméticos (skins, bailes, emotes).","Fortnite organizó conciertos virtuales con Travis Scott, Ariana Grande y Eminem que atrajeron a decenas de millones de espectadores simultáneos — difuminando la frontera entre videojuego y plataforma de entretenimiento."]},
  'gam15':{fr:["Pikachu est devenu la mascotte de Pokémon grâce à sa popularité auprès des enfants pendant l'anime — Clefairy était le premier choix.","Il existe plus de 1 000 espèces de Pokémon en 2024, chacune avec une base dans un animal, une plante ou un mythe réel.","Le jeu Pokémon Go a été téléchargé plus d'un milliard de fois et a généré plus de 6 milliards de dollars."],en:["Pikachu became the Pokémon mascot due to its anime popularity among children — Clefairy was the first choice.","There are over 1,000 Pokémon species in 2024, each based on a real animal, plant, or myth.","Pokémon Go was downloaded over 1 billion times and generated over $6 billion."],
    es:["Space Invaders (1978) fue tan popular en Japón que causó una escasez nacional de monedas de 100 yenes — el gobierno tuvo que acuñar más para satisfacer la demanda.","El juego introdujo conceptos ahora universales: puntuaciones guardadas, enemigos con patrones de ataque y dificultad creciente a medida que avanza la partida.","Space Invaders generó más de 13 000 millones de dólares en su vida útil y es considerado el juego que lanzó la edad dorada de las recreativas."]},
  'gam16':{fr:["Sapkowski a reçu environ 35 000 złotys (environ 9 000 euros) pour les droits — le jeu a ensuite rapporté des milliards.","Il a plus tard intenté un procès à CD Projekt Red et obtenu un accord financier complémentaire.","The Witcher 3 est considéré comme l'un des meilleurs RPG de tous les temps avec plus de 300 Game of the Year awards."],en:["Sapkowski received about 35,000 złotys (about €9,000) for the rights — the game later earned billions.","He later sued CD Projekt Red and obtained an additional financial settlement.","The Witcher 3 is considered one of the best RPGs ever with over 300 Game of the Year awards."],
    es:["Animal Crossing: New Horizons (2020) vendió 44 millones de copias, impulsado por el confinamiento de la pandemia de COVID-19.","El juego simula la vida en una isla tropical sin objetivos ni violencia — se juega en tiempo real y cambia con las estaciones y la hora del día.","Animal Crossing se convirtió en un espacio social: los jugadores celebraron bodas, graduaciones y hasta mítines políticos virtuales durante los confinamientos."]},
  'gam17':{fr:["Le changement de nom visait à donner au personnage un son plus britannique et aristocratique.","Lara Croft est devenue une icône de la culture pop des années 90 — elle a eu sa propre série de films avec Angelina Jolie.","Le premier Tomb Raider s'est vendu à plus de 7 millions d'exemplaires — un record pour l'époque."],en:["The name change aimed to give the character a more British and aristocratic sound.","Lara Croft became a 90s pop culture icon — she had her own film series with Angelina Jolie.","The first Tomb Raider sold over 7 million copies — a record at the time."],
    es:["Doom (1993) popularizó el shooter en primera persona y creó la cultura del modding: id Software liberó el motor del juego para que los jugadores crearan sus propios niveles.","El juego fue tan adictivo en las oficinas que empresas como Intel lo prohibieron en sus ordenadores por la caída de productividad.","Doom ha sido portado a prácticamente todo dispositivo con pantalla: calculadoras, relojes inteligentes, pruebas de embarazo e incluso tractores John Deere."]},
  'gam18':{fr:["Le partenariat a échoué à cause de désaccords sur les royalties — Sony a alors créé sa propre console.","La PlayStation a vendu plus de 100 millions d'unités — transformant Sony en géant du jeu vidéo.","Sans cette rupture, Nintendo et Sony auraient pu dominer ensemble le marché des consoles."],en:["The partnership failed due to royalty disagreements — Sony then created its own console.","PlayStation sold over 100 million units — transforming Sony into a gaming giant.","Without this breakup, Nintendo and Sony could have dominated the console market together."],
    es:["The Sims (2000) de Will Wright es el juego de simulación de vida más vendido de la historia, con más de 200 millones de copias en toda la saga.","Wright se inspiró en la pérdida de su casa en un incendio: mientras la reconstruía, empezó a pensar en un juego sobre la arquitectura y las relaciones humanas cotidianas.","Los Sims tienen su propio idioma inventado, el simlish, compuesto de balbuceos sin significado — artistas como Katy Perry y The Black Eyed Peas han grabado canciones en simlish."]},
  'gam19':{fr:["Shigeru Miyamoto a créé Donkey Kong en 1981 quand il a eu besoin d'un méchant pour son nouveau jeu.","Le jeu original mettait en scène Mario (alors Jumpman) qui devait sauver Pauline d'un gorille.","Donkey Kong a rapporté plus de 280 millions de dollars en arcade — lançant la carrière de Miyamoto et de Nintendo en Amérique."],en:["Shigeru Miyamoto created Donkey Kong in 1981 when he needed a villain for his new game.","The original game featured Mario (then Jumpman) rescuing Pauline from a gorilla.","Donkey Kong earned over $280 million in arcades — launching Miyamoto's career and Nintendo in America."],
    es:["Final Fantasy VII (1997) es el RPG japonés más influyente de la historia: sus cinemáticas, su historia emocional y su banda sonora elevaron el género a la categoría de arte.","La muerte de Aerith es uno de los momentos más impactantes de la historia del videojuego — miles de jugadores intentaron durante años encontrar una forma de evitarla.","El remake en varias partes (desde 2020) reimagina el juego original con gráficos modernos y mecánicas expandidas, generando un debate apasionado sobre la fidelidad a la obra original."]},
  'gam20':{fr:["Pajitnov n'a reçu aucune royaltie pendant 10 ans — tous les revenus allaient au gouvernement soviétique.","Tetris a provoqué une guerre juridique internationale pour les droits — impliquant l'URSS, Nintendo et plusieurs entreprises.","Le jeu se vend encore aujourd'hui — Tetris 99 et Tetris Effect ont relancé la franchise avec succès."],en:["Pajitnov received no royalties for 10 years — all revenue went to the Soviet government.","Tetris sparked an international legal war over rights — involving the USSR, Nintendo, and several companies.","The game still sells today — Tetris 99 and Tetris Effect successfully revived the franchise."],
    es:["Roblox (2006) cuenta con más de 70 millones de usuarios activos diarios, la mayoría menores de 16 años — es tanto una plataforma de juegos como un motor de creación.","Los creadores de juegos en Roblox pueden ganar dinero real: los más exitosos ganan millones de dólares al año mediante la moneda virtual Robux.","La plataforma ha sido criticada por problemas de seguridad infantil y prácticas de monetización agresivas dirigidas a niños — un debate recurrente sobre la responsabilidad de las plataformas digitales."]},
  // === HISTORY ===
  'h1':{fr:["L'ammoniac de l'urine était un agent blanchissant efficace — les Romains collectaient l'urine publiquement dans des amphores.","L'empereur Vespasien a même créé un impôt sur l'urine — d'où l'expression « l'argent n'a pas d'odeur ».","Les teinturiers romains utilisaient aussi l'urine pour fixer les couleurs sur les tissus."],en:["Ammonia in urine was an effective bleaching agent — Romans publicly collected urine in amphorae.","Emperor Vespasian even created a urine tax — hence the saying 'money has no smell'.","Roman dyers also used urine to fix colors on fabrics."],
    es:["La orina humana contiene amoníaco de forma natural, un potente desengrasante y blanqueador utilizado en la antigüedad.","Los romanos instalaban urinarios públicos (llamados fullonicae) donde los artesanos recogían la orina para lavar las togas — un negocio tan lucrativo que el emperador Vespasiano le impuso un impuesto.","De esta anécdota nació la célebre frase «Pecunia non olet» (el dinero no huele), atribuida a Vespasiano cuando su hijo Tito criticó el impuesto."]},
  'h2':{fr:["Les pyramides de Gizeh ont été construites vers 2560 av. J.-C. — Cléopâtre est née en 69 av. J.-C., soit 2 500 ans plus tard.","Cléopâtre parlait 9 langues et était la première de sa dynastie à parler égyptien.","Elle a vécu plus proche de l'invention du smartphone que de la construction des pyramides."],en:["The Giza pyramids were built around 2560 BC — Cleopatra was born in 69 BC, 2,500 years later.","Cleopatra spoke 9 languages and was the first of her dynasty to speak Egyptian.","She lived closer to the invention of the smartphone than to the building of the pyramids."],
    es:["Las pirámides de Guiza fueron construidas alrededor del 2560 a.C., mientras que Cleopatra VII nació en el 69 a.C. — más de 2 400 años de diferencia.","Cleopatra vivió más cerca del lanzamiento del iPhone (2007) que de la construcción de las pirámides — una perspectiva que desafía nuestra percepción lineal de la historia.","Cleopatra fue la última gobernante de la dinastía ptolemaica, una familia de origen macedonio que gobernó Egipto durante casi 300 años tras la conquista de Alejandro Magno."]},
  'h3':{fr:["Le feu grégeois pouvait être projeté par des siphons montés sur les navires byzantins — un ancêtre du lance-flammes.","Sa composition exacte reste un mystère — les hypothèses incluent du naphte, de la résine et de la chaux vive.","Cette arme a permis à Constantinople de résister à des sièges pendant des siècles."],en:["Greek fire could be projected through siphons mounted on Byzantine ships — an ancestor of the flamethrower.","Its exact composition remains a mystery — hypotheses include naphtha, resin, and quickite.","This weapon helped Constantinople withstand sieges for centuries."],
    es:["El fuego griego era un arma incendiaria que ardía incluso sobre el agua y resistía al viento, utilizada por el Imperio Bizantino desde el siglo VII.","Su composición exacta sigue siendo un misterio: los historiadores sospechan una mezcla de nafta, azufre, cal viva y posiblemente salitre.","Esta arma fue decisiva en varias batallas navales contra los árabes y contribuyó a mantener Constantinopla durante siglos — un auténtico secreto de Estado que murió con el Imperio."]},
  'h4':{fr:["La calcite islandaise polarise la lumière — en la tournant, les Vikings pouvaient localiser le Soleil même par ciel couvert.","Des fragments de calcite ont été retrouvés dans des épaves de navires vikings, confirmant cette théorie.","Les Vikings naviguaient aussi grâce aux étoiles, aux courants et au comportement des oiseaux marins."],en:["Icelandic calcite polarizes light — by rotating it, Vikings could locate the Sun even under cloudy skies.","Calcite fragments have been found in Viking shipwrecks, confirming this theory.","Vikings also navigated using stars, currents, and seabird behavior."],
    es:["Los vikingos utilizaban cristales de calcita islandesa, llamados «piedras solares», para detectar la posición del sol en días nublados o con niebla.","El cristal birrefringente descompone la luz en dos haces polarizados: al girar la piedra, la diferencia de intensidad revela la dirección del sol oculto.","En 2013, investigadores franceses demostraron experimentalmente que esta técnica funciona con una precisión de ±1°, suficiente para navegar entre Noruega y Groenlandia."]},
  'h5':{fr:["Oxford a commencé comme une école monastique bien avant de devenir une université formelle.","L'Empire aztèque n'a été fondé qu'en 1428, plus de 300 ans après les premiers cours à Oxford.","Oxford compte 39 collèges indépendants — le plus ancien, University College, a été fondé en 1249."],en:["Oxford began as a monastic school long before becoming a formal university.","The Aztec Empire wasn't founded until 1428, over 300 years after Oxford's first lectures.","Oxford has 39 independent colleges — the oldest, University College, was founded in 1249."],
    es:["La Universidad de Oxford comenzó a impartir clases hacia 1096, cuando profesores ingleses fueron expulsados de la Universidad de París.","La capital azteca Tenochtitlán fue fundada en 1325, más de dos siglos después — cuando Oxford ya era una institución consolidada con varios colleges.","Esta comparación ilustra lo engañoso de las líneas temporales eurocéntricas: civilizaciones sofisticadas florecían simultáneamente en distintas partes del mundo, a menudo sin contacto entre sí."]},
  'h6':{fr:["Ces batailles navales s'appelaient naumachies — le Colisée pouvait être rempli d'eau en quelques heures grâce à un système d'aqueducs.","Le Colisée pouvait accueillir entre 50 000 et 80 000 spectateurs — plus que la plupart des stades modernes.","Un système de voiles appelé velarium protégeait les spectateurs du soleil — ancêtre des toits rétractables."],en:["These naval battles were called naumachiae — the Colosseum could be filled with water in hours via aqueducts.","The Colosseum held 50,000-80,000 spectators — more than most modern stadiums.","A sail system called the velarium protected spectators from sun — ancestor of retractable roofs."],
    es:["Desde la órbita terrestre baja (~400 km), la Gran Muralla China es demasiado estrecha (5-8 metros) para ser vista a simple vista por los astronautas.","El mito probablemente se originó en 1932, antes de la era espacial, en un libro de Robert Ripley (Believe It or Not!) que especulaba sobre su visibilidad.","En 2003, el astronauta chino Yang Liwei confirmó que no pudo ver la Muralla desde el espacio — una declaración que causó gran decepción nacional."]},
  'h7':{fr:["Ce régime à base de céréales leur donnait une couche de graisse protectrice contre les blessures superficielles.","Les gladiateurs étaient des investissements coûteux — leurs propriétaires les nourrissaient bien et les soignaient avec des médecins dédiés.","Certains gladiateurs étaient des célébrités — leurs noms étaient gravés sur les murs de Pompéi par des fans."],en:["This grain-based diet gave them a protective fat layer against superficial wounds.","Gladiators were expensive investments — owners fed them well and provided dedicated doctors.","Some gladiators were celebrities — their names were carved on Pompeii walls by fans."],
    es:["Las naumaquias eran espectáculos navales en los que el Coliseo u otros anfiteatros se inundaban parcialmente para recrear batallas marítimas.","Julio César organizó la primera naumaquia conocida en el 46 a.C. en un lago artificial excavado junto al Tíber, con 2 000 combatientes y 4 000 remeros.","El sistema de inundación del Coliseo, que utilizaba canales subterráneos y el acueducto Aqua Claudia, es considerado una de las mayores proezas de ingeniería hidráulica de la Antigüedad."]},
  'h8':{fr:["La bibliothèque a subi des destructions partielles lors du siège de César en 48 av. J.-C., puis d'autres au fil des siècles.","À son apogée, elle contenait entre 400 000 et 700 000 rouleaux de papyrus.","Les navires entrant dans le port devaient remettre tous leurs livres pour copie — les originaux étaient souvent gardés."],en:["The library suffered partial destruction during Caesar's siege in 48 BC, then others over centuries.","At its peak, it held 400,000-700,000 papyrus scrolls.","Ships entering the port had to surrender all books for copying — originals were often kept."],
    es:["Napoleón medía 1,69 m, ligeramente por encima de la media francesa de la época (1,64 m).","La confusión se debe a la diferencia entre las unidades francesas y británicas: su estatura de «5 pieds 2 pouces» en medida francesa equivale a unos 5 pies 7 pulgadas en medida británica, pero los británicos usaron su propia escala.","La propaganda británica caricaturizó a Napoleón como un hombrecillo furioso — una imagen que perduró en la cultura popular gracias a dibujantes como James Gillray."]},
  'h9':{fr:["La confusion vient des unités de mesure : le pouce français (2,7 cm) était plus grand que le pouce anglais (2,54 cm).","En réalité, Napoléon mesurait environ 1,69 m — au-dessus de la moyenne française de l'époque (1,64 m).","La propagande anglaise l'a volontairement représenté petit pour le ridiculiser."],en:["The confusion comes from measurement units: the French inch (2.7 cm) was larger than the English inch (2.54 cm).","Napoleon actually stood about 1.69 m — above the French average of the time (1.64 m).","English propaganda deliberately depicted him as short to ridicule him."],
    es:["Los papiros egipcios del 1550 a.C. (Papiro de Ebers) ya describen métodos anticonceptivos a base de miel, acacia fermentada y fibras vegetales.","El ácido láctico producido por la acacia fermentada actúa efectivamente como espermicida — un hallazgo confirmado por estudios modernos de laboratorio.","Los egipcios también utilizaban tapones de lino empapados en sustancias ácidas como barreras físicas, anticipando en miles de años el concepto del diafragma moderno."]},
  'h10':{fr:["Le sultan de Zanzibar a capitulé après que la marine britannique a bombardé le palais royal.","L'armée de Zanzibar comptait environ 2 800 soldats mal équipés face à la Royal Navy.","Un seul navire britannique, le HMS St George, a détruit le palais en quelques minutes."],en:["The Sultan of Zanzibar surrendered after the British Navy bombarded the royal palace.","Zanzibar's army had about 2,800 poorly equipped soldiers against the Royal Navy.","A single British ship, HMS St George, destroyed the palace in minutes."],
    es:["La Biblioteca de Alejandría fue fundada por Ptolomeo I alrededor del 295 a.C. y llegó a albergar entre 400 000 y 700 000 rollos de papiro.","Contrariamente al mito popular, no fue destruida en un solo incendio: sufrió daños durante el asedio de Julio César (48 a.C.), un terremoto en 365 d.C. y recortes presupuestarios progresivos.","Su institución hermana, el Serapeo, sobrevivió hasta el 391 d.C., cuando fue destruido durante los disturbios religiosos ordenados por el obispo Teófilo de Alejandría."]},
  'h11':{fr:["Les ouvriers étaient logés dans des villages à proximité du chantier — leurs tombes ont été retrouvées avec des honneurs.","Ils recevaient des rations de pain et de bière — environ 4 litres de bière par jour par ouvrier.","La construction a mobilisé environ 20 000 ouvriers pendant 20 ans."],en:["Workers were housed in villages near the construction site — their graves were found with honors.","They received bread and beer rations — about 4 liters of beer per worker per day.","Construction mobilized about 20,000 workers over 20 years."],
    es:["La Peste Negra (1347-1353) mató entre 75 y 200 millones de personas en Eurasia, eliminando entre el 30 % y el 60 % de la población europea.","La pandemia fue causada por la bacteria Yersinia pestis, transmitida por pulgas que viajaban en ratas negras a lo largo de las rutas comerciales.","Paradójicamente, la despoblación masiva mejoró las condiciones de los supervivientes: los salarios subieron, la servidumbre retrocedió y se aceleró la innovación tecnológica para compensar la falta de mano de obra."]},
  'h12':{fr:["Les pyramides soudanaises sont plus petites et plus pointues que les pyramides égyptiennes.","Elles ont été construites par le royaume de Koush entre 700 av. J.-C. et 300 apr. J.-C.","Beaucoup ont été endommagées au XIXe siècle par un chasseur de trésors italien, Giuseppe Ferlini."],en:["Sudanese pyramids are smaller and more pointed than Egyptian ones.","They were built by the Kingdom of Kush between 700 BC and 300 AD.","Many were damaged in the 19th century by Italian treasure hunter Giuseppe Ferlini."],
    es:["Los samuráis constituían la clase guerrera del Japón feudal desde el siglo XII hasta la abolición del sistema de castas en 1876 durante la era Meiji.","Además de guerreros, muchos samuráis eran poetas, calígrafos y filósofos: el bushido (camino del guerrero) exigía tanto dominio marcial como refinamiento cultural.","El último gran enfrentamiento samurái fue la Rebelión de Satsuma en 1877, cuando guerreros tradicionalistas se alzaron contra la modernización del ejército imperial — un episodio que inspiró numerosas obras de ficción."]},
  'h13':{fr:["Le traité de Kadesh (1259 av. J.-C.) est le plus ancien traité de paix dont le texte nous est parvenu.","Une copie est exposée au siège des Nations Unies à New York comme symbole de diplomatie.","Le traité incluait une clause d'extradition mutuelle — l'une des premières de l'histoire."],en:["The Treaty of Kadesh (1259 BC) is the oldest peace treaty whose text has survived.","A copy is displayed at the UN headquarters in New York as a symbol of diplomacy.","The treaty included a mutual extradition clause — one of the first in history."],
    es:["La Piedra Rosetta fue descubierta en 1799 por soldados franceses durante la campaña de Napoleón en Egipto, cerca de la ciudad de Rashid (Rosetta).","Contiene el mismo decreto en tres escrituras: jeroglíficos egipcios, escritura demótica y griego antiguo, lo que permitió descifrar los jeroglíficos por comparación.","Jean-François Champollion logró descifrar los jeroglíficos en 1822, abriendo la puerta a toda la egiptología moderna — la piedra se conserva hoy en el Museo Británico."]},
  'h14':{fr:["Depuis l'espace, on voit mieux les serres d'Almería en Espagne, qui couvrent 260 km² de plastique blanc.","La muraille mesure environ 21 000 km si l'on inclut toutes les branches et fortifications annexes.","Elle a été construite sur plus de 2 000 ans par différentes dynasties chinoises."],en:["From space, the greenhouses of Almería in Spain are more visible, covering 260 km² of white plastic.","The wall measures about 21,000 km including all branches and auxiliary fortifications.","It was built over 2,000 years by different Chinese dynasties."],
    es:["Pompeya fue sepultada bajo metros de ceniza y piedra pómez tras la erupción del Vesubio el 24 de agosto del 79 d.C., preservando la ciudad en un estado extraordinario.","Las excavaciones, iniciadas en 1748, revelaron calles, frescos, grafitis, tabernas e incluso moldes de los cuerpos de las víctimas congelados en sus últimos instantes.","Pompeya nos ofrece una ventana única a la vida cotidiana romana: desde la publicidad electoral pintada en las paredes hasta los menús de las termas y los burdeles."]},
  'h15':{fr:["César a exigé que sa rançon soit doublée car il jugeait le montant initial insultant pour sa dignité.","Une fois libéré, il a levé une flotte, capturé les pirates et les a fait crucifier comme il l'avait promis.","Pendant sa captivité, il leur lisait ses poèmes et les insultait quand ils ne les appréciaient pas."],en:["Caesar demanded his ransom be doubled because he found the initial amount insulting to his dignity.","Once freed, he raised a fleet, captured the pirates, and had them crucified as he'd promised.","During captivity, he read them his poems and insulted them when they didn't appreciate them."],
    es:["Gengis Kan unificó las tribus mongolas en 1206 y construyó el mayor imperio terrestre contiguo de la historia, que se extendía de Corea a Europa Central.","A pesar de su reputación de conquistador brutal, Gengis Kan instauró la libertad religiosa, un sistema postal eficiente (el Yam) y un código legal escrito (el Yasaq).","Estudios genéticos sugieren que aproximadamente el 0,5 % de la población mundial masculina desciende directamente de Gengis Kan — unos 16 millones de hombres."]},
  'h16':{fr:["Les casques à cornes apparaissent dans l'opéra Der Ring des Nibelungen de Wagner en 1876 — une invention théâtrale.","Les vrais casques vikings étaient en fer simple, parfois avec un protège-nez — conçus pour le combat pratique.","Les Vikings étaient aussi des commerçants et des explorateurs — ils ont atteint l'Amérique 500 ans avant Colomb."],en:["Horned helmets appear in Wagner's 1876 opera Der Ring des Nibelungen — a theatrical invention.","Real Viking helmets were plain iron, sometimes with a nose guard — designed for practical combat.","Vikings were also traders and explorers — they reached America 500 years before Columbus."],
    es:["La Revolución Francesa comenzó en 1789 con la toma de la Bastilla y transformó radicalmente la estructura política y social de Francia y de Europa entera.","La guillotina, adoptada como método de ejecución «humanitario» en 1792, se convirtió en símbolo del Terror — periodo en el que más de 16 000 personas fueron ejecutadas.","Los ideales revolucionarios de libertad, igualdad y fraternidad inspiraron movimientos democráticos en todo el mundo y sentaron las bases del concepto moderno de derechos humanos."]},
  'h17':{fr:["Cette pratique s'appelait tameshigiri — les bourreaux étaient aussi des experts en lames.","Les katanas étaient forgés en pliant l'acier des milliers de fois, créant des lames d'une qualité exceptionnelle.","Un katana de qualité prenait plusieurs mois à forger et valait l'équivalent d'une maison."],en:["This practice was called tameshigiri — executioners were also blade experts.","Katanas were forged by folding steel thousands of times, creating blades of exceptional quality.","A quality katana took months to forge and was worth the equivalent of a house."],
    es:["La Ruta de la Seda era una red de rutas comerciales que conectaba China con el Mediterráneo desde el siglo II a.C. hasta el siglo XV.","Además de seda, se intercambiaban especias, metales preciosos, cerámicas, papel y pólvora — pero también ideas, religiones y enfermedades.","La Ruta de la Seda facilitó la difusión del budismo hacia China, del islam hacia Asia Central y de la peste negra hacia Europa — un ejemplo temprano de globalización."]},
  'h18':{fr:["Le message complet devait être 'login' mais le système a planté après les deux premières lettres.","ARPANET connectait initialement 4 universités : UCLA, Stanford, UCSB et l'université de l'Utah.","Le premier email a été envoyé en 1971 par Ray Tomlinson — il a choisi le symbole @ pour séparer le nom de l'hôte."],en:["The full message was supposed to be 'login' but the system crashed after the first two letters.","ARPANET initially connected 4 universities: UCLA, Stanford, UCSB, and the University of Utah.","The first email was sent in 1971 by Ray Tomlinson — he chose the @ symbol to separate name from host."],
    es:["Los mayas desarrollaron un sistema matemático vigesimal (base 20) y fueron una de las primeras civilizaciones en concebir el concepto del cero como número.","Su calendario, el Cuenta Larga, era tan preciso que calculaba el año solar con un error de solo 17,31 segundos — más exacto que el calendario gregoriano.","Contrariamente al mito popular, la civilización maya no desapareció: más de 6 millones de descendientes mayas viven hoy en Guatemala, México y Belice, conservando sus lenguas y tradiciones."]},
  'h19':{fr:["Les routes romaines étaient construites en couches — gravier, sable, pierres taillées — une technique qui a inspiré les routes modernes.","La Via Appia, construite en 312 av. J.-C., est toujours utilisable aujourd'hui, plus de 2 300 ans après.","Le réseau permettait aux légions de se déplacer à 25 km par jour en formation — une vitesse remarquable pour l'époque."],en:["Roman roads were built in layers — gravel, sand, cut stones — a technique that inspired modern roads.","The Appian Way, built in 312 BC, is still usable today, over 2,300 years later.","The network allowed legions to travel 25 km per day in formation — remarkable speed for the era."],
    es:["El Muro de Berlín dividió la ciudad durante 28 años (1961-1989), separando familias y simbolizando la división ideológica de la Guerra Fría.","Al menos 140 personas murieron intentando cruzar el Muro, que estaba protegido por torres de vigilancia, alambradas, minas y una franja de muerte de 100 metros.","Su caída el 9 de noviembre de 1989 fue en gran parte accidental: un portavoz del gobierno de la RDA anunció prematuramente la apertura de fronteras, provocando una avalancha masiva de ciudadanos."]},
  'h20':{fr:["Les pigeons transportaient des messages miniaturisés dans des capsules attachées à leurs pattes.","Plus de 250 000 pigeons ont servi pendant les deux guerres mondiales combinées.","Le pigeon Cher Ami a sauvé 194 soldats américains en 1918 en délivrant un message malgré une blessure grave."],en:["Pigeons carried miniaturized messages in capsules attached to their legs.","Over 250,000 pigeons served during both World Wars combined.","Pigeon Cher Ami saved 194 American soldiers in 1918 by delivering a message despite severe injury."],
    es:["Leonardo da Vinci fue un genio polifacético del Renacimiento: pintor, escultor, ingeniero, anatomista, músico, arquitecto e inventor.","Sus cuadernos contienen diseños de máquinas voladoras, tanques de guerra, escafandras y robots — conceptos adelantados varios siglos a su época.","La Mona Lisa, su obra más célebre, se encuentra detrás de un cristal blindado en el Louvre y recibe más de 10 millones de visitantes al año — es probablemente el cuadro más famoso del mundo."]},
  // === INVENTIONS ===
  'inv1':{fr:["L'ingénieur Percy Spencer travaillait sur les radars militaires quand sa barre de chocolat a fondu dans sa poche.","Le premier micro-ondes commercial, le Radarange, pesait 340 kg et coûtait 5 000 dollars en 1947.","Le premier aliment testé au micro-ondes a été du popcorn — le deuxième, un œuf qui a explosé."],en:["Engineer Percy Spencer was working on military radars when his chocolate bar melted in his pocket.","The first commercial microwave, the Radarange, weighed 340 kg and cost $5,000 in 1947.","The first food tested in the microwave was popcorn — the second, an egg that exploded."],
    es:["La rueda no fue inventada para el transporte sino para la alfarería: los primeros tornos de alfarero aparecieron en Mesopotamia hacia el 3500 a.C.","Las primeras ruedas para vehículos aparecieron unos 300 años después, en la estepa póntica (actual Ucrania), como discos macizos de madera sin radios.","Curiosamente, las civilizaciones precolombinas conocían la rueda pero solo la usaban en juguetes — la ausencia de animales de tiro la hacía poco práctica para el transporte."]},
  'inv2':{fr:["Art Fry, un collègue de Silver chez 3M, a eu l'idée d'utiliser cette colle pour marquer les pages de son livre de cantiques.","3M vend aujourd'hui plus de 50 milliards de Post-it par an dans plus de 100 pays.","Le jaune canari du Post-it n'était pas un choix de design — c'était la seule couleur de papier disponible dans le laboratoire voisin."],en:["Art Fry, Silver's colleague at 3M, had the idea to use this glue to bookmark his hymnal.","3M now sells over 50 billion Post-its per year in over 100 countries.","The canary yellow wasn't a design choice — it was the only paper color available in the nearby lab."],
    es:["La imprenta de tipos móviles fue inventada en China por Bi Sheng hacia 1040 d.C., cuatro siglos antes que Gutenberg.","Sin embargo, los miles de caracteres chinos hacían poco prácticos los tipos móviles, por lo que la xilografía siguió dominando en Asia oriental.","Gutenberg combinó los tipos móviles metálicos con una prensa de tornillo adaptada de las prensas de vino, creando un sistema revolucionario para los alfabetos europeos de pocas letras."]},
  'inv3':{fr:["Fleming a remarqué qu'une moisissure Penicillium avait tué les bactéries dans une boîte de Petri oubliée.","Il a fallu 10 ans pour que Florey et Chain transforment la découverte en médicament utilisable.","La pénicilline a sauvé des millions de vies pendant la Seconde Guerre mondiale et a lancé l'ère des antibiotiques."],en:["Fleming noticed that Penicillium mold had killed bacteria in a forgotten Petri dish.","It took 10 years for Florey and Chain to turn the discovery into a usable drug.","Penicillin saved millions of lives during WWII and launched the antibiotic era."],
    es:["La brújula magnética fue inventada en China durante la dinastía Han (siglo II a.C.) para la adivinación geomántica (feng shui), no para la navegación.","Su uso marítimo no se documenta hasta el siglo XI en China y el XII en Europa — transformando la navegación oceánica y posibilitando la era de los descubrimientos.","El polo magnético terrestre no coincide con el polo geográfico y se desplaza constantemente — actualmente migra hacia Siberia a unos 55 km por año."]},
  'inv4':{fr:["George de Mestral a observé les crochets microscopiques des bardanes au microscope — puis les a reproduits en nylon.","Le Velcro a été utilisé par la NASA pour fixer des objets en apesanteur dans les navettes spatiales.","Le nom Velcro vient de « velours » et « crochet » — un mot-valise français."],en:["George de Mestral observed the microscopic hooks of burdock under a microscope — then reproduced them in nylon.","Velcro was used by NASA to secure objects in zero gravity on space shuttles.","The name Velcro comes from 'velours' (velvet) and 'crochet' (hook) — a French portmanteau."],
    es:["La bombilla incandescente no fue inventada por Edison: al menos 22 inventores trabajaron en lámparas eléctricas antes que él, incluidos Humphry Davy y Joseph Swan.","La contribución de Edison fue crear una bombilla práctica y duradera (más de 1 200 horas) y, sobre todo, diseñar todo el sistema eléctrico para alimentarla: centrales, cables e interruptores.","La primera central eléctrica comercial del mundo, la Pearl Street Station de Edison en Manhattan, se inauguró en 1882 y suministraba electricidad a 85 clientes."]},
  'inv5':{fr:["Les étudiants de Yale lançaient les plats en criant « Frisbie ! » pour prévenir les passants dans les années 1940.","Wham-O a déposé le nom « Frisbee » en 1957 et en a vendu plus de 200 millions d'unités.","Le sport Ultimate Frisbee est aujourd'hui pratiqué dans plus de 80 pays et a failli devenir olympique."],en:["Yale students threw the pans shouting 'Frisbie!' to warn passersby in the 1940s.","Wham-O trademarked 'Frisbee' in 1957 and sold over 200 million units.","Ultimate Frisbee is now played in over 80 countries and nearly became an Olympic sport."],
    es:["El teléfono fue patentado por Alexander Graham Bell el 14 de febrero de 1876, apenas dos horas antes que su rival Elisha Gray presentara un documento similar.","Antonio Meucci, un inventor italiano, había desarrollado un prototipo funcional años antes pero no pudo pagar la tasa de renovación de su patente provisional.","En 2002, el Congreso de EE.UU. reconoció oficialmente la contribución de Meucci a la invención del teléfono, sin invalidar la patente de Bell."]},
  'inv6':{fr:["L'astronome John O'Sullivan a découvert un moyen de débruiter les signaux radio des trous noirs — cette technique est devenue le Wi-Fi.","Le Wi-Fi ne signifie rien — c'est un jeu de mots sur Hi-Fi (haute fidélité) inventé par une agence de marketing.","Le premier réseau Wi-Fi commercial a été installé dans un hôtel de Amsterdam en 1999."],en:["Astronomer John O'Sullivan found a way to denoise radio signals from black holes — this technique became Wi-Fi.","Wi-Fi doesn't stand for anything — it's a play on Hi-Fi coined by a marketing agency.","The first commercial Wi-Fi network was installed in an Amsterdam hotel in 1999."],
    es:["La penicilina fue descubierta por accidente en 1928 cuando Alexander Fleming observó que un moho (Penicillium notatum) mataba bacterias en una placa de Petri contaminada.","Fleming no logró purificar la sustancia: fueron Howard Florey y Ernst Boris Chain quienes la transformaron en medicamento utilizable en 1940.","La penicilina salvó millones de vidas durante la Segunda Guerra Mundial y abrió la era de los antibióticos — pero Fleming advirtió desde su discurso del Nobel sobre el riesgo de resistencia bacteriana."]},
  'inv7':{fr:["Le briquet de Döbereiner utilisait de l'hydrogène et du platine pour créer une flamme par catalyse.","Les allumettes à friction ont été inventées en 1826 par le pharmacien anglais John Walker.","Les premières allumettes étaient dangereuses — elles contenaient du phosphore blanc, un poison mortel."],en:["Döbereiner's lighter used hydrogen and platinum to create a flame through catalysis.","Friction matches were invented in 1826 by English pharmacist John Walker.","Early matches were dangerous — they contained white phosphorus, a deadly poison."],
    es:["La pólvora fue inventada en China durante el siglo IX por alquimistas taoístas que buscaban el elixir de la inmortalidad — un irónico giro del destino.","Los chinos la usaron primero para fuegos artificiales y señales antes de aplicarla a armas: las primeras «lanzas de fuego» aparecieron en el siglo X.","La pólvora llegó a Europa en el siglo XIII a través de la Ruta de la Seda y transformó radicalmente la guerra, volviendo obsoletas las armaduras y los castillos medievales."]},
  'inv8':{fr:["ENIAC pouvait effectuer 5 000 additions par seconde — impressionnant pour l'époque, mais un smartphone est des milliards de fois plus rapide.","Il consommait 150 kW d'électricité — assez pour alimenter un quartier résidentiel.","Les « ordinateurs » avant ENIAC étaient des personnes, principalement des femmes, qui calculaient à la main."],en:["ENIAC could perform 5,000 additions per second — impressive then, but a smartphone is billions of times faster.","It consumed 150 kW of electricity — enough to power a residential neighborhood.","'Computers' before ENIAC were people, mainly women, who calculated by hand."],
    es:["El motor de vapor, perfeccionado por James Watt en 1769, fue el catalizador de la Revolución Industrial y transformó la manufactura, el transporte y la minería.","Watt no inventó el motor de vapor: mejoró el diseño de Thomas Newcomen añadiendo un condensador separado que triplicó la eficiencia energética.","La unidad de potencia «vatio» (watt) lleva su nombre, y el concepto de «caballo de vapor» fue creado por él mismo para comercializar sus máquinas comparándolas con caballos de tiro."]},
  'inv9':{fr:["Les sœurs Tatin tenaient un hôtel à Lamotte-Beuvron — leur tarte renversée est devenue un classique de la pâtisserie française.","La recette a été popularisée par le restaurant Maxim's à Paris qui l'a ajoutée à son menu.","Aujourd'hui, la tarte Tatin se décline avec des poires, des tomates ou même des endives."],en:["The Tatin sisters ran a hotel in Lamotte-Beuvron — their upside-down tart became a French pastry classic.","The recipe was popularized by Maxim's restaurant in Paris which added it to its menu.","Today, tarte Tatin comes in pear, tomato, or even endive variations."],
    es:["El microondas fue inventado por accidente en 1945 cuando Percy Spencer, ingeniero de Raytheon, notó que una barra de chocolate se había derretido en su bolsillo junto a un magnetrón.","El primer horno microondas comercial, el Radarange (1947), pesaba 340 kg, medía 1,80 m de alto y costaba el equivalente actual de unos 60 000 dólares.","Las microondas no calientan desde fuera hacia dentro: excitan las moléculas de agua del alimento, generando calor por fricción molecular — por eso los alimentos secos no se calientan bien."]},
  'inv10':{fr:["Röntgen a immédiatement radiographié la main de sa femme — elle a vu ses propres os et s'est écriée « J'ai vu ma mort ! ».","Il a reçu le tout premier prix Nobel de physique en 1901 pour cette découverte.","Röntgen a refusé de breveter les rayons X, voulant que l'humanité entière puisse en bénéficier."],en:["Röntgen immediately X-rayed his wife's hand — she saw her own bones and exclaimed 'I have seen my death!'.","He received the very first Nobel Prize in Physics in 1901 for this discovery.","Röntgen refused to patent X-rays, wanting all of humanity to benefit."],
    es:["Internet nació como ARPANET en 1969, una red militar estadounidense que conectaba cuatro universidades para compartir recursos informáticos.","El primer mensaje enviado por ARPANET fue «LO» — debía ser «LOGIN» pero el sistema se bloqueó después de las dos primeras letras.","Internet y la World Wide Web no son lo mismo: Internet es la infraestructura de red, mientras que la Web (inventada por Tim Berners-Lee en 1989) es un servicio que funciona sobre ella."]},
  'inv11':{fr:["Les inventeurs Alfred Fielding et Marc Chavannes ont créé le papier bulle en 1957 en scellant deux rideaux de douche ensemble.","Avant de devenir un emballage, il a aussi été testé comme isolant pour serres.","Le papier bulle a sa propre journée mondiale — le dernier lundi de janvier — où les gens sont encouragés à le faire éclater."],en:["Inventors Alfred Fielding and Marc Chavannes created bubble wrap in 1957 by sealing two shower curtains together.","Before becoming packaging, it was also tested as greenhouse insulation.","Bubble wrap has its own world day — the last Monday of January — when people are encouraged to pop it."],
    es:["El GPS (Sistema de Posicionamiento Global) fue desarrollado por el ejército estadounidense en los años 1970 y liberado para uso civil en 1983 tras el derribo de un avión coreano que se había desviado de su ruta.","El sistema funciona con una constelación de al menos 24 satélites que orbitan a 20 200 km de altitud: un receptor necesita señales de al menos 4 satélites para calcular su posición.","Los relojes atómicos a bordo de los satélites GPS deben corregir los efectos de la relatividad general de Einstein — sin esta corrección, la posición se desviaría unos 10 km por día."]},
  'inv12':{fr:["Laennec a d'abord roulé un cahier en tube pour écouter le cœur de sa patiente — le premier prototype de stéthoscope.","Le stéthoscope biauriculaire (à deux écouteurs) n'a été inventé qu'en 1852, 36 ans plus tard.","Le mot stéthoscope vient du grec stethos (poitrine) et skopein (examiner)."],en:["Laennec first rolled a notebook into a tube to listen to his patient's heart — the first stethoscope prototype.","The binaural stethoscope (two earpieces) wasn't invented until 1852, 36 years later.","The word stethoscope comes from Greek stethos (chest) and skopein (to examine)."],
    es:["El velcro fue inventado en 1941 por el ingeniero suizo George de Mestral tras observar cómo los frutos del cardo (bardana) se enganchaban a su ropa y al pelo de su perro.","Tardó ocho años en perfeccionar el sistema y patentarlo en 1955 — inicialmente fue ridiculizado por la industria textil que lo consideraba poco elegante.","La NASA adoptó el velcro para las misiones espaciales porque funciona en gravedad cero: permite fijar objetos, herramientas y hasta comida dentro de las naves."]},
  'inv13':{fr:["Avant la machine à laver, une femme passait en moyenne un jour entier par semaine à faire la lessive à la main.","La première machine à laver électrique a été inventée en 1908 par Alva J. Fisher.","Les économistes considèrent la machine à laver comme l'invention qui a le plus contribué à la libération des femmes."],en:["Before the washing machine, a woman spent an average of one full day per week doing laundry by hand.","The first electric washing machine was invented in 1908 by Alva J. Fisher.","Economists consider the washing machine the invention that most contributed to women's liberation."],
    es:["La aspirina, sintetizada por Felix Hoffmann en 1897, tiene su origen en la corteza de sauce, utilizada como analgésico desde la antigua Sumeria hace 4 000 años.","El ácido acetilsalicílico es uno de los medicamentos más consumidos del mundo: se estima que se toman 100 000 millones de comprimidos al año.","Además de aliviar el dolor, la aspirina tiene propiedades anticoagulantes que reducen el riesgo de infarto — un efecto secundario descubierto décadas después de su comercialización."]},
  'inv14':{fr:["L'acide salicylique, base de l'aspirine, est extrait de l'écorce de saule — un remède connu depuis l'Antiquité.","Bayer a breveté l'aspirine en 1899, mais a perdu le brevet après la Première Guerre mondiale comme compensation de guerre.","L'aspirine est aussi utilisée comme anticoagulant — des millions de personnes en prennent quotidiennement pour prévenir les crises cardiaques."],en:["Salicylic acid, aspirin's base, is extracted from willow bark — a remedy known since antiquity.","Bayer patented aspirin in 1899 but lost the patent after WWI as war compensation.","Aspirin is also used as an anticoagulant — millions take it daily to prevent heart attacks."],
    es:["El avión fue inventado por los hermanos Wright, que realizaron el primer vuelo motorizado controlado el 17 de diciembre de 1903 en Kitty Hawk, Carolina del Norte.","El primer vuelo duró apenas 12 segundos y cubrió 36 metros — menos que la envergadura de un Boeing 747 moderno.","Los Wright resolvieron el problema clave del vuelo — el control direccional — inspirándose en cómo las aves tuercen las puntas de sus alas, un mecanismo que llamaron «torsión alar»."]},
  'inv15':{fr:["Bell a déposé son brevet seulement 2 heures avant son rival Elisha Gray — une des courses au brevet les plus serrées de l'histoire.","La première phrase prononcée au téléphone était « Mr. Watson, venez ici, je veux vous voir ».","Antonio Meucci, un inventeur italien, avait déposé un caveat (pré-brevet) en 1871, 5 ans avant Bell."],en:["Bell filed his patent just 2 hours before rival Elisha Gray — one of history's tightest patent races.","The first phone sentence was 'Mr. Watson, come here, I want to see you'.","Antonio Meucci, an Italian inventor, had filed a caveat (pre-patent) in 1871, 5 years before Bell."],
    es:["La dinamita fue inventada por Alfred Nobel en 1867 al descubrir que la nitroglicerina, altamente inestable, podía estabilizarse absorbiéndola en tierra de diatomeas.","Nobel amasó una fortuna con la dinamita pero se horrorizó al leer su propio obituario prematuro, que lo llamaba «el mercader de la muerte» — esto lo llevó a crear los Premios Nobel.","Los Premios Nobel se otorgan desde 1901 en Física, Química, Medicina, Literatura y Paz — el de Economía fue añadido en 1969 por el Banco de Suecia."]},
  'inv16':{fr:["Internet est un réseau de réseaux né dans les années 1960 — le Web est une application qui fonctionne sur ce réseau.","Berners-Lee a inventé le WWW au CERN en 1989 pour faciliter le partage de documents entre scientifiques.","Le premier site web est toujours en ligne : info.cern.ch — il explique ce qu'est le World Wide Web."],en:["The internet is a network of networks born in the 1960s — the Web is an application running on it.","Berners-Lee invented the WWW at CERN in 1989 to facilitate document sharing between scientists.","The first website is still online: info.cern.ch — it explains what the World Wide Web is."],
    es:["El papel fue inventado en China por Cai Lun en el año 105 d.C., utilizando corteza de morera, cáñamo, trapos viejos y redes de pesca triturados.","Durante siglos, los chinos mantuvieron el secreto de su fabricación — los árabes lo aprendieron en 751 tras capturar a artesanos chinos en la batalla de Talas.","Antes del papel, se escribía sobre papiro (Egipto), pergamino (piel animal), tablillas de arcilla (Mesopotamia) y bambú (China) — todos mucho más caros y pesados."]},
  'inv17':{fr:["Stephanie Kwolek a découvert le Kevlar par hasard en étudiant des polymères pour des pneus plus légers.","Le Kevlar est utilisé dans les gilets pare-balles, les casques militaires et les câbles de ponts suspendus.","Il résiste aussi à des températures de 450 °C — il est utilisé dans les combinaisons de pompiers."],en:["Stephanie Kwolek discovered Kevlar by accident while studying polymers for lighter tires.","Kevlar is used in bulletproof vests, military helmets, and suspension bridge cables.","It also withstands temperatures of 450°C — used in firefighter suits."],
    es:["La vacuna fue inventada por Edward Jenner en 1796 al demostrar que la inoculación con viruela bovina protegía contra la mortal viruela humana.","El término «vacuna» viene de vacca (vaca en latín), en referencia al virus bovino utilizado por Jenner.","La viruela es la única enfermedad humana erradicada de la naturaleza: la OMS declaró su erradicación en 1980, tras una campaña mundial de vacunación que comenzó en 1967."]},
  'inv18':{fr:["Le GPS utilise 31 satellites en orbite à 20 200 km d'altitude, chacun faisant le tour de la Terre en 12 heures.","La précision civile du GPS est d'environ 3-5 mètres — la précision militaire peut descendre à quelques centimètres.","Sans correction relativiste (théorie d'Einstein), le GPS dériverait de 10 km par jour."],en:["GPS uses 31 satellites orbiting at 20,200 km altitude, each circling Earth in 12 hours.","Civilian GPS accuracy is about 3-5 meters — military accuracy can reach centimeters.","Without relativistic correction (Einstein's theory), GPS would drift 10 km per day."],
    es:["Los Post-it nacieron de un adhesivo «fallido»: en 1968, Spencer Silver en 3M creó un pegamento que se despegaba fácilmente sin dejar residuos.","Durante años nadie supo qué hacer con ese adhesivo inútil, hasta que en 1974 su colega Art Fry lo usó para marcar las páginas de su himnario sin dañarlas.","Los Post-it se comercializaron en 1980 y se convirtieron en un fenómeno mundial: hoy se fabrican en más de 60 colores y formas, y se venden en más de 100 países."]},
  'inv19':{fr:["Le système GPS coûte environ 2 milliards de dollars par an à maintenir — financé par les contribuables américains.","L'Europe a développé son propre système, Galileo, pour ne pas dépendre du GPS américain.","La Russie a GLONASS, la Chine a BeiDou — il existe 4 systèmes de navigation par satellite dans le monde."],en:["GPS costs about $2 billion per year to maintain — funded by American taxpayers.","Europe developed its own system, Galileo, to avoid depending on American GPS.","Russia has GLONASS, China has BeiDou — there are 4 satellite navigation systems worldwide."],
    es:["El transistor fue inventado en 1947 en los Laboratorios Bell por John Bardeen, Walter Brattain y William Shockley, quienes recibieron el Nobel de Física en 1956.","Reemplazó a los tubos de vacío: más pequeño, más rápido, más fiable y con mucho menos consumo energético, hizo posible la electrónica moderna.","Un procesador actual contiene miles de millones de transistores, cada uno más pequeño que un virus — la miniaturización sigue la Ley de Moore, que predice la duplicación cada dos años."]},
  'inv20':{fr:["Les premiers porteurs de lunettes étaient moqués — on pensait que corriger la vue était contre la volonté divine.","Benjamin Franklin a inventé les verres bifocaux en 1784 — deux verres en un pour voir de près et de loin.","Aujourd'hui, environ 4 milliards de personnes dans le monde portent des lunettes ou des lentilles de contact."],en:["Early glasses wearers were mocked — correcting vision was thought to go against divine will.","Benjamin Franklin invented bifocals in 1784 — two lenses in one for near and far vision.","Today, about 4 billion people worldwide wear glasses or contact lenses."],
    es:["El refrigerador doméstico se popularizó en los años 1920, sustituyendo las neveras de hielo que dependían de entregas regulares de bloques congelados.","Los primeros refrigeradores usaban gases tóxicos como el amoníaco y el cloruro de metilo — el freón, inventado en 1930, fue la solución segura hasta que se descubrió que destruía la capa de ozono.","La refrigeración transformó la dieta humana: por primera vez en la historia, la comida podía conservarse durante semanas, reduciendo el desperdicio y las enfermedades alimentarias."]},
  // === LANGUAGE ===
  'l1':{fr:["Karel Čapek a introduit le mot dans sa pièce R.U.R. (Rossum's Universal Robots) en 1920.","C'est en fait son frère Josef qui a suggéré le mot « robot » — Karel voulait l'appeler « labori ».","Ironiquement, les robots de la pièce étaient organiques, pas mécaniques — plus proches des androïdes."],en:["Karel Čapek introduced the word in his play R.U.R. (Rossum's Universal Robots) in 1920.","It was actually his brother Josef who suggested 'robot' — Karel wanted 'labori'.","Ironically, the play's robots were organic, not mechanical — closer to androids."],
    es:["El mandarín es la lengua más hablada del mundo como lengua materna, con más de 920 millones de hablantes nativos.","El chino mandarín es tonal: una misma sílaba puede tener cuatro significados diferentes según la entonación — por ejemplo, mā (madre), má (cáñamo), mǎ (caballo), mà (insultar).","El sistema de escritura chino no es un alfabeto sino un sistema logográfico: cada carácter representa una palabra o morfema, y existen más de 50 000 caracteres, aunque 3 000 bastan para la lectura cotidiana."]},
  'l2':{fr:["Ce mot est « komorebi » (木漏れ日) — un concept si poétique qu'il n'a pas d'équivalent dans les langues occidentales.","Le japonais possède aussi « tsundoku » — l'habitude d'acheter des livres sans jamais les lire.","Et « wabi-sabi » — la beauté de l'imperfection et de l'éphémère."],en:["The word is 'komorebi' (木漏れ日) — a concept so poetic it has no Western language equivalent.","Japanese also has 'tsundoku' — the habit of buying books without ever reading them.","And 'wabi-sabi' — the beauty of imperfection and transience."],
    es:["El esperanto fue creado en 1887 por el oculista polaco Ludwik Zamenhof como lengua universal para fomentar la paz y la comprensión entre pueblos.","Su gramática tiene solo 16 reglas sin excepciones y su vocabulario se basa en raíces latinas, germánicas y eslavas — se estima que se puede aprender 5 veces más rápido que cualquier idioma natural.","Hoy cuenta con entre 100 000 y 2 millones de hablantes y tiene su propia literatura, música, congresos anuales e incluso hablantes nativos (niños criados en esperanto)."]},
  'l3':{fr:["Le sel était si précieux que les soldats recevaient parfois leur solde directement en sel.","L'expression « ne pas valoir son sel » signifiait qu'un soldat n'était pas digne de sa paie.","La Via Salaria, l'une des plus anciennes routes romaines, servait au transport du sel."],en:["Salt was so valuable soldiers sometimes received their pay directly in salt.","The expression 'not worth his salt' meant a soldier wasn't worthy of his pay.","The Via Salaria, one of the oldest Roman roads, was used for salt transport."],
    es:["La palabra «salario» proviene del latín salarium, la ración de sal que recibían los legionarios romanos como parte de su paga.","La sal era tan valiosa en la Antigüedad que se usaba como moneda de cambio — de ahí también la expresión «no valer su sal» (no merecer su sueldo).","Las rutas de la sal (viae salariae) eran arterias comerciales vitales en el Imperio Romano y dieron nombre a ciudades como Salzburgo (castillo de la sal) en Austria."]},
  'l4':{fr:["Les berserkers se battaient dans un état de transe frénétique, possiblement induit par des champignons hallucinogènes.","Ils portaient des peaux d'ours (berserk = « chemise d'ours ») et se croyaient invincibles au combat.","Leur réputation était telle que les armées ennemies fuyaient souvent à leur simple vue."],en:["Berserkers fought in a frenzied trance state, possibly induced by hallucinogenic mushrooms.","They wore bear skins (berserk = 'bear shirt') and believed themselves invincible in combat.","Their reputation was such that enemy armies often fled at the mere sight of them."],
    es:["La palabra «berserk» proviene de los guerreros vikingos llamados berserkers, que entraban en un estado de trance furioso durante la batalla.","Algunos historiadores creen que este frenesí se inducía mediante el consumo de hongos alucinógenos (Amanita muscaria) o simplemente mediante rituales de exaltación colectiva.","Los berserkers luchaban sin armadura, mordiendo sus escudos y aullando — su ferocidad aterrorizaba tanto a enemigos como a aliados."]},
  'l5':{fr:["La conquête normande de 1066 a introduit le français comme langue de la cour et de l'administration en Angleterre.","C'est pourquoi les mots anglais liés au pouvoir viennent du français (government, justice, parliament).","L'anglais est la seule langue germanique avec une majorité de vocabulaire d'origine latine et française."],en:["The Norman conquest of 1066 introduced French as the language of court and administration in England.","That's why English power-related words come from French (government, justice, parliament).","English is the only Germanic language with a majority of Latin and French-origin vocabulary."],
    es:["Tras la conquista normanda de 1066, el francés se convirtió en la lengua de la corte, la ley y la aristocracia inglesa durante más de 300 años.","Esto explica por qué los animales vivos tienen nombres anglosajones (cow, sheep, pig) pero sus carnes tienen nombres franceses (beef, mutton, pork) — los campesinos criaban, los nobles comían.","Unas 10 000 palabras francesas entraron en el inglés durante este periodo, incluyendo justice, parliament, fashion, restaurant y la propia palabra «language»."]},
  'l6':{fr:["L'abréviation est apparue dans le Boston Morning Post en 1839, pendant une mode de raccourcis humoristiques.","Parmi les autres abréviations de l'époque : KY pour « know yuse » (no use) et KG pour « know go » (no go).","OK a survécu grâce à la campagne présidentielle de Martin Van Buren en 1840, surnommé « Old Kinderhook »."],en:["The abbreviation appeared in the Boston Morning Post in 1839, during a trend of humorous shortcuts.","Other abbreviations of the era: KY for 'know yuse' (no use) and KG for 'know go' (no go).","OK survived thanks to Martin Van Buren's 1840 presidential campaign, nicknamed 'Old Kinderhook'."],
    es:["La abreviatura OK apareció por primera vez el 23 de marzo de 1839 en el Boston Morning Post como broma ortográfica de «Oll Korrect» (All Correct mal escrito a propósito).","La moda de las abreviaturas humorísticas era viral en la prensa estadounidense de los años 1830 — pero solo OK sobrevivió para convertirse en la palabra más universalmente comprendida del mundo.","La campaña presidencial de Martin Van Buren en 1840, apodado «Old Kinderhook», popularizó OK al usarlo como eslogan — el doble sentido aseguró su difusión masiva."]},
  'l7':{fr:["Chaque lettre du mot « oiseaux » se prononce différemment de sa prononciation habituelle dans d'autres mots.","Le français est l'une des langues où la différence entre l'orthographe et la prononciation est la plus grande.","Le mot « anticonstitutionnellement » est souvent cité comme le plus long mot du dictionnaire français."],en:["Each letter of 'oiseaux' is pronounced differently from its usual pronunciation in other words.","French is one of the languages with the biggest gap between spelling and pronunciation.","'Anticonstitutionnellement' is often cited as the longest word in the French dictionary."],
    es:["El albanés es una de las lenguas más aisladas de Europa: constituye por sí solo una rama entera de la familia indoeuropea, sin parientes cercanos conocidos.","Su alfabeto actual, basado en el latino, fue estandarizado recién en 1908 en el Congreso de Manastir — antes se escribía con caracteres griegos, árabes o cirílicos según la región.","El albanés conserva palabras de un sustrato preindoeuropeo que podrían ser vestigios de la antigua lengua iliria, hablada en los Balcanes antes de la llegada de los romanos."]},
  'l8':{fr:["Le premier emoji a été créé en 1999 par Shigetaka Kurita pour l'opérateur mobile japonais NTT DoCoMo.","Il existait 176 emojis originaux — aujourd'hui il y en a plus de 3 600.","L'emoji « visage avec des larmes de joie » 😂 a été le mot de l'année du dictionnaire Oxford en 2015."],en:["The first emoji was created in 1999 by Shigetaka Kurita for Japanese mobile carrier NTT DoCoMo.","There were 176 original emojis — today there are over 3,600.","The 'face with tears of joy' emoji 😂 was Oxford Dictionary's word of the year in 2015."],
    es:["La palabra «emoji» proviene del japonés e (絵, imagen) y moji (文字, carácter) — no tiene relación etimológica con la palabra inglesa «emotion», aunque la coincidencia es notable.","Los primeros emojis fueron creados en 1999 por Shigetaka Kurita para el operador japonés NTT DoCoMo: eran 176 iconos de 12×12 píxeles diseñados para mejorar la comunicación por SMS.","En 2015, el emoji «cara llorando de risa» (😂) fue elegido «palabra del año» por el Oxford Dictionary — el primer pictograma en recibir ese honor en la historia."]},
  'l9':{fr:["En gaélique, « uisce beatha » signifie eau de vie — « uisce » est devenu « whisky » en anglais.","Le mot « vodka » signifie aussi « petite eau » en russe — le même concept linguistique.","« Aquavit », la boisson scandinave, vient du latin « aqua vitae » — encore la même idée."],en:["In Gaelic, 'uisce beatha' means water of life — 'uisce' became 'whisky' in English.","The word 'vodka' also means 'little water' in Russian — the same linguistic concept.","'Aquavit', the Scandinavian drink, comes from Latin 'aqua vitae' — the same idea again."],
    es:["La palabra «whisky» proviene del gaélico irlandés uisce beatha, que significa literalmente «agua de vida» — el mismo concepto que aquavit en escandinavo y eau-de-vie en francés.","La destilación del whisky fue probablemente introducida en Escocia e Irlanda por monjes que habían aprendido la técnica en el Mediterráneo para producir perfumes y medicinas.","La diferencia entre «whisky» (escocés) y «whiskey» (irlandés y americano) no es solo ortográfica: refleja tradiciones de destilación, ingredientes y procesos de envejecimiento diferentes."]},
  'l10':{fr:["Le mot « set » a plus de 430 sens différents dans l'Oxford English Dictionary.","La définition complète du mot « set » occupe plus de 60 000 mots dans le dictionnaire — un article entier.","Le mot « run » est le deuxième avec plus de 300 définitions."],en:["The word 'set' has over 430 different meanings in the Oxford English Dictionary.","The complete definition of 'set' takes over 60,000 words in the dictionary — an entire article.","The word 'run' is second with over 300 definitions."],
    es:["El inglés ha tomado más del 30 % de su vocabulario del francés, principalmente tras la conquista normanda de 1066, cuando el francés se convirtió en lengua de prestigio en Inglaterra.","Palabras como beef (bœuf), parliament (parlement), justice y fashion son todas de origen francés — la coexistencia de sinónimos anglosajones y franceses enriqueció enormemente el vocabulario inglés.","Esta dualidad persiste hoy: los registros formales del inglés usan preferentemente palabras de origen francés/latino, mientras que el habla cotidiana conserva las raíces germánicas."]},
  'l11':{fr:["Les quatre systèmes sont : hiragana, katakana, kanji (caractères chinois) et romaji (alphabet latin).","Un Japonais lettré connaît environ 2 000 kanji — il en existe plus de 50 000 au total.","Le katakana est principalement utilisé pour les mots étrangers — « コンピュータ » (konpyuuta) signifie ordinateur."],en:["The four systems are: hiragana, katakana, kanji (Chinese characters), and romaji (Latin alphabet).","A literate Japanese person knows about 2,000 kanji — over 50,000 exist in total.","Katakana is mainly used for foreign words — 'コンピュータ' (konpyuuta) means computer."],
    es:["El finés no tiene género gramatical: el pronombre hän se usa tanto para «él» como para «ella», sin distinción.","El finés no pertenece a la familia indoeuropea sino a la familia urálica, emparentado con el estonio y el húngaro — aunque las similitudes con este último son muy lejanas.","El finés es una lengua aglutinante con 15 casos gramaticales: una sola palabra puede expresar lo que en español requiere una frase entera — por ejemplo, talossanikin significa «también en mi casa»."]},
  'l12':{fr:["Les chiffres arabes (1, 2, 3...) ont en fait été inventés en Inde — les Arabes les ont transmis à l'Europe.","L'arabe est une langue officielle dans 26 pays et est parlée par environ 420 millions de personnes.","La calligraphie arabe est considérée comme un art à part entière — elle est inscrite au patrimoine de l'UNESCO."],en:["Arabic numerals (1, 2, 3...) were actually invented in India — Arabs transmitted them to Europe.","Arabic is an official language in 26 countries, spoken by about 420 million people.","Arabic calligraphy is considered a standalone art form — inscribed as UNESCO heritage."],
    es:["El latín, considerado una lengua muerta, sigue siendo la lengua oficial del Vaticano y se usa en documentos papales, inscripciones y ceremonias.","La influencia del latín en las lenguas romances (español, francés, italiano, portugués, rumano) es tan profunda que un hablante de cualquiera de ellas puede reconocer cientos de palabras latinas.","Wikipedia tiene una versión completa en latín (Vicipaedia) con más de 130 000 artículos, y el Vaticano tiene un cajero automático con instrucciones en latín."]},
  'l13':{fr:["La sauce ketchup originale ne contenait pas de tomates — c'était une sauce de poisson fermenté avec des épices.","Les Américains ont ajouté des tomates au XIXe siècle, transformant complètement la recette.","Heinz vend environ 650 millions de bouteilles de ketchup par an dans le monde."],en:["The original ketchup sauce contained no tomatoes — it was fermented fish sauce with spices.","Americans added tomatoes in the 19th century, completely transforming the recipe.","Heinz sells about 650 million ketchup bottles per year worldwide."],
    es:["El euskera (vasco) es la única lengua preindoeuropea que sobrevive en Europa occidental, sin relación conocida con ninguna otra familia lingüística del mundo.","Su origen es un misterio: se habla en el País Vasco desde antes de la llegada de los celtas, los romanos y los indoeuropeos — posiblemente desde el Neolítico.","El euskera utiliza un sistema ergativo-absolutivo (raro en Europa) y forma palabras por aglutinación: etxe (casa), etxea (la casa), etxean (en la casa), etxearen (de la casa)."]},
  'l14':{fr:["Le mandarin a 4 tons — le même son prononcé avec un ton différent peut signifier mère, chanvre, cheval ou insulte.","Le chinois n'a pas d'alphabet — chaque caractère représente un concept ou un son, pas une lettre.","Environ 1,1 milliard de personnes parlent le mandarin — 15 % de la population mondiale."],en:["Mandarin has 4 tones — the same sound with a different tone can mean mother, hemp, horse, or insult.","Chinese has no alphabet — each character represents a concept or sound, not a letter.","About 1.1 billion people speak Mandarin — 15% of the world's population."],
    es:["El árabe se escribe de derecha a izquierda y su alfabeto de 28 letras cambia de forma según su posición en la palabra (inicio, medio, final o aislada).","El árabe es la quinta lengua más hablada del mundo con más de 420 millones de hablantes, y es lengua oficial en 26 países.","La contribución del árabe al vocabulario español es inmensa: más de 4 000 palabras castellanas tienen origen árabe, incluyendo almohada, alfombra, azúcar, alcalde y hasta la exclamación ¡ojalá! (inshallah)."]},
  'l15':{fr:["Le Silbo Gomero des Canaries permet de communiquer à plus de 5 km de distance en sifflant.","Il a été inscrit au patrimoine immatériel de l'UNESCO en 2009.","Il est enseigné obligatoirement dans les écoles de La Gomera depuis 1999."],en:["The Silbo Gomero of the Canary Islands allows communication over 5 km by whistling.","It was inscribed as UNESCO Intangible Cultural Heritage in 2009.","It has been mandatory in schools on La Gomera since 1999."],
    es:["El idioma con más hablantes nativos es el mandarín (920 millones), pero el inglés es la lengua más hablada en total (1 500 millones incluyendo no nativos).","El inglés es lengua oficial o cooficial en 67 países y es la lingua franca de la ciencia, la aviación, la diplomacia y la tecnología.","Sin embargo, se estima que unas 3 000 de las 7 000 lenguas del mundo desaparecerán antes de 2100 — una cada dos semanas — llevándose consigo conocimientos culturales irremplazables."]},
  'l16':{fr:["Le directeur de théâtre Richard Daly aurait parié qu'il pouvait introduire un mot sans sens dans la langue en 48 heures.","Il a fait écrire « quiz » sur tous les murs de Dublin pendant la nuit — le lendemain, tout le monde parlait du mystérieux mot.","Bien que cette histoire soit contestée, le mot est apparu en anglais vers cette époque."],en:["Theater director Richard Daly reportedly bet he could introduce a meaningless word into the language in 48 hours.","He had 'quiz' written on every Dublin wall overnight — the next day, everyone was talking about the mysterious word.","Though this story is disputed, the word appeared in English around this time."],
    es:["La onomatopeya varía enormemente entre idiomas: un gallo dice «quiquiriquí» en español, «cocoricó» en francés, «cock-a-doodle-doo» en inglés y «kokekokkō» en japonés.","Estas diferencias no son caprichosas: cada lengua filtra los sonidos según su propio sistema fonológico, adaptando los ruidos naturales a patrones de sílabas y sonidos familiares.","Los lingüistas estudian las onomatopeyas como ejemplo de motivación fonética parcial — un raro caso donde el sonido de la palabra guarda cierta relación con su significado."]},
  'l17':{fr:["Le pirahã ne possède que 3 voyelles et 8 consonnes — l'un des systèmes phonétiques les plus simples au monde.","Ils n'ont pas de mots pour les nombres au-delà de « un, deux, beaucoup ».","Le linguiste Daniel Everett a passé 30 ans à étudier cette langue, ce qui a remis en cause des théories fondamentales de Noam Chomsky."],en:["Pirahã has only 3 vowels and 8 consonants — one of the world's simplest phonetic systems.","They have no words for numbers beyond 'one, two, many'.","Linguist Daniel Everett spent 30 years studying this language, challenging fundamental theories by Noam Chomsky."],
    es:["El Braille fue inventado en 1824 por Louis Braille, un joven francés de 15 años que había quedado ciego tras un accidente en el taller de su padre.","El sistema se basa en celdas de 6 puntos en relieve que permiten 63 combinaciones, representando letras, números, signos de puntuación y notación musical.","Braille se inspiró en un sistema militar de escritura nocturna creado por Charles Barbier para que los soldados pudieran comunicarse sin luz — lo simplificó y adaptó para uso civil."]},
  'l18':{fr:["Le français est langue officielle dans 29 pays répartis sur les 5 continents.","Environ 321 millions de personnes parlent français dans le monde — ce nombre devrait atteindre 700 millions en 2050.","Le français a été la langue de la diplomatie internationale pendant plus de 300 ans, du XVIIe au XXe siècle."],en:["French is an official language in 29 countries across all 5 continents.","About 321 million people speak French worldwide — this number could reach 700 million by 2050.","French was the language of international diplomacy for over 300 years, from the 17th to 20th century."],
    es:["La lengua de signos no es universal: cada país o región tiene su propia lengua de signos con gramática, vocabulario y sintaxis propios.","La lengua de signos americana (ASL) tiene más similitudes con la lengua de signos francesa (LSF) que con la lengua de signos británica (BSL), debido a su origen histórico común.","Las lenguas de signos son lenguas naturales completas, no simples traducciones del idioma oral — tienen su propia poesía, humor, juegos de palabras y dialectos regionales."]},
  'l19':{fr:["Le roi Sejong a créé le hangul pour que les gens du peuple puissent lire et écrire — les élites utilisaient les caractères chinois.","Le hangul a 14 consonnes et 10 voyelles, organisées en blocs syllabiques.","Il est considéré comme l'un des systèmes d'écriture les plus logiques et les plus faciles à apprendre au monde."],en:["King Sejong created hangul so common people could read and write — elites used Chinese characters.","Hangul has 14 consonants and 10 vowels, organized in syllabic blocks.","It's considered one of the most logical and easiest writing systems to learn in the world."],
    es:["Los palíndromos (palabras o frases que se leen igual al derecho y al revés) existen en casi todos los idiomas: «reconocer» en español, «kayak» en inglés, «saippuakivikauppias» en finés.","El palíndromo finés saippuakivikauppias (vendedor de piedra pómez) es uno de los más largos del mundo en una sola palabra, con 19 letras.","En latín, el cuadrado mágico SATOR-ROTAS es un palíndromo bidimensional del siglo I que se lee igual en cuatro direcciones — su significado sigue siendo debatido."]},
  'l20':{fr:["La Langue des Signes Française (LSF) a influencé l'American Sign Language (ASL) — elles partagent environ 60 % de vocabulaire.","Un sourd français et un sourd américain peuvent communiquer partiellement grâce à ce lien historique.","La LSF a été interdite dans les écoles françaises de 1880 à 1991 — une période sombre de l'histoire de la communauté sourde."],en:["French Sign Language (LSF) influenced American Sign Language (ASL) — they share about 60% vocabulary.","A deaf French person and deaf American can partially communicate thanks to this historical link.","LSF was banned in French schools from 1880 to 1991 — a dark period in deaf community history."],
    es:["El sánscrito es una de las lenguas más antiguas del mundo documentado, con textos (los Vedas) que datan del 1500 a.C. aproximadamente.","Es la lengua litúrgica del hinduismo y una de las 22 lenguas oficiales de la India, aunque apenas tiene hablantes nativos en la actualidad.","La gramática del sánscrito, codificada por Pāṇini en el siglo IV a.C., es tan precisa y sistemática que los lingüistas computacionales la consideran un precursor de los lenguajes de programación."]},
  // === LAWS ===
  'law1':{fr:["Cette loi concerne les nuisances sonores nocturnes dans les immeubles collectifs suisses.","En Suisse, il est aussi interdit de tondre la pelouse le dimanche et les jours fériés.","Chaque canton suisse peut avoir ses propres règles de bruit — certains sont plus stricts que d'autres."],en:["This law concerns nighttime noise disturbances in Swiss apartment buildings.","In Switzerland, mowing the lawn on Sundays and holidays is also forbidden.","Each Swiss canton can have its own noise rules — some are stricter than others."],
    es:["La Ley de Murphy («Todo lo que puede salir mal, saldrá mal») no es una ley científica sino un adagio del ingeniero Edward Murphy, formulado en 1949 durante pruebas de desaceleración en la base Edwards.","Murphy culpó a un técnico que había instalado todos los sensores al revés — su frustración se convirtió en un principio universal de ingeniería: diseña asumiendo que los errores ocurrirán.","La ley tiene una aplicación seria: la ingeniería de seguridad y la aviación diseñan sistemas redundantes precisamente porque asumen que cualquier fallo posible acabará ocurriendo."]},
  'law2':{fr:["L'interdiction a été introduite après que des chewing-gums ont bloqué les portes du métro automatique de Singapour.","Les contrevenants risquent une amende pouvant aller jusqu'à 100 000 dollars singapouriens.","Depuis 2004, les chewing-gums thérapeutiques (nicotine) sont autorisés sur ordonnance en pharmacie."],en:["The ban was introduced after chewing gum jammed the doors of Singapore's automated subway.","Offenders face fines up to 100,000 Singapore dollars.","Since 2004, therapeutic gum (nicotine) has been allowed by prescription at pharmacies."],
    es:["La Ley de Moore (1965) predice que el número de transistores en un microchip se duplica aproximadamente cada dos años, doblando la potencia informática.","Gordon Moore, cofundador de Intel, formuló esta observación como tendencia empírica, no como ley física — y ha resultado asombrosamente precisa durante más de 50 años.","Los físicos predicen el fin de la Ley de Moore porque los transistores se acercan al tamaño atómico — las alternativas incluyen computación cuántica, fotónica y chips 3D."]},
  'law3':{fr:["Cette loi daterait de l'époque de Napoléon lui-même qui ne voulait pas être ridiculisé par un animal portant son nom.","En pratique, aucune poursuite n'a jamais été engagée pour cette infraction.","La France possède de nombreuses lois anciennes jamais abrogées — comme l'interdiction aux femmes de porter un pantalon à Paris (abrogée en 2013)."],en:["This law reportedly dates from Napoleon himself who didn't want to be ridiculed by an animal bearing his name.","In practice, no prosecution has ever been brought for this offense.","France has many old unrepealied laws — like the ban on women wearing pants in Paris (repealed 2013)."],
    es:["La Ley de Pareto (regla 80/20) establece que el 80 % de los efectos proviene del 20 % de las causas — formulada por Vilfredo Pareto al estudiar la distribución de la riqueza en Italia.","Esta proporción aparece en contextos sorprendentes: el 20 % de los clientes genera el 80 % de los ingresos, el 20 % de los bugs causa el 80 % de los fallos, el 20 % del guardarropa se usa el 80 % del tiempo.","La ley no es exacta (puede ser 70/30 o 90/10) pero el principio es robusto: concentrar esfuerzos en los pocos factores que generan la mayor parte del impacto es una estrategia universalmente eficaz."]},
  'law4':{fr:["Le roi de Thaïlande est protégé par une loi de lèse-majesté parmi les plus strictes au monde.","Les billets de banque thaïlandais ne doivent jamais être froissés, déchirés ou utilisés de manière irrespectueuse.","Un touriste a été arrêté en 2006 pour avoir marché sur un billet de 20 bahts tombé au sol."],en:["The Thai king is protected by one of the world's strictest lèse-majesté laws.","Thai banknotes must never be crumpled, torn, or used disrespectfully.","A tourist was arrested in 2006 for stepping on a 20-baht bill that fell on the ground."],
    es:["La Ley de Godwin (1990) establece que cuanto más se prolonga una discusión en Internet, más se acerca a 1 la probabilidad de que alguien haga una comparación con Hitler o el nazismo.","Mike Godwin formuló esta ley como un experimento memético: quería demostrar que los memes culturales se propagan como virus, y su propia ley se convirtió en el mejor ejemplo.","Godwin ha precisado que su ley no invalida todas las comparaciones con el nazismo — las comparaciones legítimas existen, pero las hiperbólicas trivializan la historia."]},
  'law5':{fr:["En Italie, la loi considère que les tongs ne permettent pas un contrôle suffisant des pédales.","La même loi interdit de conduire pieds nus — seules les chaussures fermées sont autorisées.","L'amende peut atteindre 158 euros et s'accompagner d'un retrait de points sur le permis."],en:["In Italy, the law considers flip-flops don't allow sufficient pedal control.","The same law prohibits driving barefoot — only closed shoes are authorized.","The fine can reach €158 and may include license point deduction."],
    es:["La Ley de Parkinson (1955) establece que «el trabajo se expande hasta llenar el tiempo disponible para completarlo» — formulada por Cyril Northcote Parkinson sobre la burocracia británica.","Parkinson observó que el número de funcionarios del Almirantazgo británico creció un 78 % entre 1914 y 1928, mientras la flota se reducía un 67 % — la burocracia crecía independientemente de la carga real.","La ley se aplica a la productividad personal: fijar plazos más cortos obliga a ser más eficiente — las tareas que «deberían» llevar una semana a menudo se completan en un día si el plazo lo exige."]},
  'law6':{fr:["La loi Metabo impose des contrôles de tour de taille pour les employés de plus de 40 ans lors des check-ups annuels.","Les entreprises dont les employés dépassent les limites peuvent être sanctionnées financièrement.","Le Japon a l'un des taux d'obésité les plus bas au monde — environ 4 % contre 42 % aux États-Unis."],en:["The Metabo law mandates waist measurements for employees over 40 during annual check-ups.","Companies whose employees exceed limits can face financial penalties.","Japan has one of the world's lowest obesity rates — about 4% vs 42% in the US."],
    es:["La Ley de Hofstadter establece que «las cosas siempre tardan más de lo que esperas, incluso cuando tienes en cuenta la Ley de Hofstadter» — una paradoja autoreferencial deliberada.","Douglas Hofstadter la formuló en Gödel, Escher, Bach (1979) en el contexto de la inteligencia artificial y la complejidad de los proyectos — su recursividad captura un sesgo humano profundo.","Esta ley explica por qué los proyectos de software, las obras públicas y las reformas siempre se retrasan: subestimamos la complejidad incluso cuando sabemos que la subestimamos."]},
  'law7':{fr:["Les pigeons voyageurs étaient essentiels pour les communications militaires pendant les deux guerres mondiales.","Certains pigeons ont reçu la médaille Dickin, l'équivalent animal de la Victoria Cross.","Aujourd'hui, les courses de pigeons voyageurs sont un sport avec des prix pouvant atteindre des millions de dollars."],en:["Carrier pigeons were essential for military communications during both World Wars.","Some pigeons received the Dickin Medal, the animal equivalent of the Victoria Cross.","Today, pigeon racing is a sport with prizes reaching millions of dollars."],
    es:["La Ley de Metcalfe establece que el valor de una red es proporcional al cuadrado del número de usuarios — 10 usuarios generan 100 conexiones potenciales, 100 usuarios generan 10 000.","Esta ley explica el crecimiento explosivo de redes sociales y plataformas: cada nuevo usuario aumenta el valor para todos los demás, creando un efecto de bola de nieve.","Facebook, WhatsApp y TikTok son ejemplos perfectos: su valor no reside en la tecnología sino en la masa crítica de usuarios — una vez alcanzada, es casi imposible que un competidor la desplace."]},
  'law8':{fr:["L'Autobahn n'a pas de limite de vitesse sur certaines sections — tomber en panne y est considéré comme évitable et dangereux.","L'amende peut atteindre 70 euros, mais le vrai risque est la responsabilité en cas d'accident causé par l'arrêt.","Les Allemands sont légalement tenus de vérifier leur jauge d'essence avant de prendre l'autoroute."],en:["The Autobahn has no speed limit on some sections — running out of gas is considered avoidable and dangerous.","The fine can reach €70, but the real risk is liability if the stop causes an accident.","Germans are legally required to check their fuel gauge before entering the highway."],
    es:["La primera ley de la termodinámica establece que la energía no se crea ni se destruye, solo se transforma — un principio fundamental de la física.","Esta ley implica que es imposible crear una máquina de movimiento perpetuo del primer tipo: no se puede obtener energía de la nada.","La segunda ley (la entropía siempre aumenta) es aún más implacable: toda transformación energética genera desperdicio — el universo tiende inevitablemente hacia el desorden."]},
  'law9':{fr:["En réalité, des gens sont morts au Parlement — mais aucune cérémonie d'État n'a été organisée pour autant.","La loi est probablement un mythe urbain, mais elle est régulièrement citée dans les compilations de lois absurdes.","Le Parlement de Westminster date de 1295 — il a accumulé de nombreuses traditions et règles obscures."],en:["In reality, people have died in Parliament — but no state ceremony was organized.","The law is probably an urban myth, but is regularly cited in absurd law compilations.","Westminster Parliament dates from 1295 — it has accumulated many obscure traditions and rules."],
    es:["La Ley de Cunningham establece que la mejor manera de obtener la respuesta correcta en Internet no es hacer una pregunta sino publicar una respuesta incorrecta.","Ward Cunningham (creador del primer wiki) formuló esta observación sobre la naturaleza humana: las personas son más propensas a corregir errores que a responder preguntas.","Este principio se aplica en redes sociales, foros y Wikipedia — la necesidad de corregir al otro es un impulso más fuerte que la generosidad de compartir conocimiento."]},
  'law10':{fr:["La loi sur la monnaie légale limite le paiement en pièces de 1 dollar à 25 pièces maximum par transaction.","Cette loi existe pour protéger les commerçants contre les paiements intentionnellement pénibles.","D'autres pays ont des lois similaires — en France, on ne peut pas payer plus de 50 pièces par transaction."],en:["Legal tender law limits payment in 1-dollar coins to a maximum of 25 per transaction.","This law exists to protect merchants from intentionally annoying payments.","Other countries have similar laws — in France, you can't pay more than 50 coins per transaction."],
    es:["La Ley de Benford establece que en conjuntos de datos numéricos naturales, el dígito 1 aparece como primer dígito el 30 % de las veces, no el 11 % que esperaríamos si la distribución fuera uniforme.","Esta distribución logarítmica aparece en datos tan diversos como poblaciones de ciudades, cotizaciones bursátiles, caudales de ríos y declaraciones de impuestos.","Las autoridades fiscales y los auditores usan la Ley de Benford para detectar fraudes: los datos fabricados tienden a tener una distribución de dígitos demasiado uniforme, delatando la manipulación."]},
  'law11':{fr:["Les talons aiguilles concentrent tout le poids sur quelques millimètres carrés, exerçant une pression supérieure à celle d'un éléphant.","La loi a été introduite après que des touristes ont causé des dommages aux marbres de l'Acropole.","Les sites archéologiques grecs accueillent plus de 30 millions de visiteurs par an."],en:["Stiletto heels concentrate all weight on a few square millimeters, exerting more pressure than an elephant.","The law was introduced after tourists damaged the Acropolis marbles.","Greek archaeological sites receive over 30 million visitors per year."],
    es:["Las tres leyes de Newton (1687) revolucionaron la física: inercia, F=ma y acción-reacción — con ellas se puede explicar desde la caída de una manzana hasta la órbita de los planetas.","Newton formuló estas leyes en los Principia Mathematica, considerado el libro científico más importante jamás publicado.","Las leyes de Newton funcionan perfectamente a escalas humanas, pero fallan a velocidades cercanas a la luz (donde rige la relatividad de Einstein) y a escalas subatómicas (donde rige la mecánica cuántica)."]},
  'law12':{fr:["Cette loi écossaise daterait du Moyen Âge, quand les toilettes publiques n'existaient pas.","L'Écosse possède un système juridique distinct de l'Angleterre, avec ses propres traditions et lois.","Parmi les autres lois écossaises insolites : il serait illégal d'être ivre et en charge d'une vache."],en:["This Scottish law reportedly dates from the Middle Ages, when public toilets didn't exist.","Scotland has a legal system distinct from England, with its own traditions and laws.","Among other unusual Scottish laws: it's reportedly illegal to be drunk in charge of a cow."],
    es:["La Ley de Brandolini (principio de asimetría del bullshit) establece que desmentir una falsedad requiere un orden de magnitud más esfuerzo que producirla.","En la era de la desinformación, esta ley explica por qué los bulos se propagan más rápido que las correcciones: una mentira se tuitea en segundos, desmentirla requiere investigación, datos y argumentos.","Los verificadores de hechos (fact-checkers) luchan contra esta asimetría a diario — pero sus correcciones alcanzan a una fracción de la audiencia que vio la información falsa original."]},
  'law13':{fr:["Les pigeons endommageaient les bâtiments historiques de la place avec leurs fientes acides.","L'amende pour avoir nourri les pigeons peut atteindre 500 euros.","La population de pigeons à Venise a chuté de 50 % depuis l'introduction de cette loi."],en:["Pigeons damaged the square's historic buildings with their acidic droppings.","The fine for feeding pigeons can reach €500.","Venice's pigeon population dropped 50% since the law was introduced."],
    es:["La Ley de la gravedad de Newton (1687) establece que todos los cuerpos se atraen con una fuerza proporcional al producto de sus masas e inversamente proporcional al cuadrado de la distancia.","Newton supuestamente concibió la idea al ver caer una manzana — la anécdota es probablemente exagerada pero ilustra su genio: conectó un fenómeno cotidiano con el movimiento de los planetas.","Einstein corrigió a Newton con la relatividad general (1915): la gravedad no es una fuerza sino una curvatura del espacio-tiempo causada por la masa — un concepto radicalmente diferente."]},
  'law14':{fr:["La Suède protège l'harmonie visuelle des quartiers résidentiels par des réglementations strictes sur les couleurs.","Le « rouge de Falun », une peinture traditionnelle à base d'oxyde de fer, est la couleur la plus courante des maisons suédoises.","Changer la couleur d'une façade nécessite un permis de construire dans la plupart des communes."],en:["Sweden protects visual harmony in residential areas through strict color regulations.","'Falun red', a traditional iron oxide paint, is the most common color for Swedish houses.","Changing a facade color requires a building permit in most municipalities."],
    es:["La Ley de Sturgeon establece que «el 90 % de todo es basura» — una generalización provocadora formulada por el escritor de ciencia ficción Theodore Sturgeon en los años 1950.","Sturgeon respondía a los críticos que despreciaban la ciencia ficción señalando que el 90 % de cualquier campo (literatura, cine, academia) es igualmente mediocre — la calidad siempre es la excepción.","La ley se aplica especialmente bien a Internet, donde la abundancia de contenido diluye la calidad: encontrar el 10 % valioso es el verdadero desafío de la era digital."]},
  'law15':{fr:["La loi portugaise sur l'urine en mer date d'une initiative de protection environnementale des années 2000.","L'application de cette loi est évidemment impossible — elle est surtout symbolique.","Le Portugal a aussi décriminalisé toutes les drogues en 2001 — une approche pionnière en Europe."],en:["The Portuguese sea urination law dates from an environmental protection initiative in the 2000s.","Enforcement is obviously impossible — the law is mostly symbolic.","Portugal also decriminalized all drugs in 2001 — a pioneering approach in Europe."],
    es:["La Ley de Goodhart establece que «cuando una medida se convierte en objetivo, deja de ser una buena medida» — formulada por el economista Charles Goodhart en 1975.","Los hospitales que optimizan las listas de espera rechazan pacientes complejos; las escuelas que optimizan los exámenes enseñan para el test — la métrica se cumple pero el objetivo real se pierde.","En tecnología, esta ley explica los problemas de las métricas de redes sociales: optimizar para «engagement» produce contenido adictivo y polarizante, no necesariamente valioso."]},
  'law16':{fr:["En 2002, un dirigeant de Nokia a reçu une amende de 116 000 euros pour un excès de vitesse à Helsinki.","Ce système d'amendes proportionnelles s'appelle le « jour-amende » et existe aussi en Suisse et en Allemagne.","L'amende la plus élevée jamais infligée en Finlande est de 170 000 euros pour un excès de 27 km/h."],en:["In 2002, a Nokia executive received a €116,000 fine for speeding in Helsinki.","This proportional fine system is called 'day-fine' and also exists in Switzerland and Germany.","The highest fine ever imposed in Finland was €170,000 for exceeding the limit by 27 km/h."],
    es:["La Ley de Hanlon aconseja «no atribuir a la malicia lo que puede explicarse por la incompetencia» — un principio de caridad interpretativa muy útil en la vida cotidiana.","En las organizaciones, la mayoría de los problemas no son conspiraciones sino errores de comunicación, falta de información o malas decisiones tomadas con buenas intenciones.","Aplicar esta ley reduce la paranoia y el conflicto: asumir incompetencia antes que malicia facilita la resolución de problemas y preserva las relaciones."]},
  'law17':{fr:["L'Alabama possède de nombreuses lois héritées de l'ère puritaine qui n'ont jamais été formellement abrogées.","Dans le même État, il est techniquement illégal de jouer aux dominos le dimanche.","Ces lois ne sont plus appliquées mais restent dans les textes faute de volonté politique de les retirer."],en:["Alabama has many laws inherited from the Puritan era that were never formally repealed.","In the same state, it's technically illegal to play dominoes on Sundays.","These laws are no longer enforced but remain on the books for lack of political will to remove them."],
    es:["La Ley de Brooks establece que «añadir personas a un proyecto de software retrasado lo retrasa aún más» — formulada por Fred Brooks en The Mythical Man-Month (1975).","Los nuevos miembros necesitan formación, la comunicación se vuelve más compleja (n personas generan n(n-1)/2 canales) y el trabajo de coordinación supera el beneficio de los recursos adicionales.","Esta ley sigue siendo ignorada por los gestores de proyectos medio siglo después — es uno de los principios más citados y menos aplicados de la ingeniería del software."]},
  'law18':{fr:["Le Bhoutan mesure le bonheur national brut plutôt que le PIB — le seul pays au monde à le faire officiellement.","L'interdiction du tabac est cohérente avec la philosophie bouddhiste du pays qui valorise la santé et le bien-être.","Le Bhoutan est aussi le seul pays au monde dont le bilan carbone est négatif — il absorbe plus de CO₂ qu'il n'en émet."],en:["Bhutan measures Gross National Happiness rather than GDP — the only country to officially do so.","The tobacco ban aligns with the country's Buddhist philosophy valuing health and wellbeing.","Bhutan is also the only country in the world with a negative carbon balance — absorbing more CO₂ than it emits."],
    es:["La Ley de Amara establece que «tendemos a sobreestimar el efecto de una tecnología a corto plazo y a subestimarlo a largo plazo».","Internet, los smartphones y la IA siguieron exactamente este patrón: burbujas de expectativas excesivas seguidas de desilusión, antes de transformar silenciosamente la sociedad.","La ley explica los ciclos de hype tecnológico (Gartner Hype Cycle): entusiasmo, desilusión, adopción real — la tecnología que realmente importa no es la que genera más titulares al principio."]},
  'law19':{fr:["En Turquie, le respect des aînés est un pilier de la culture — cette loi en est une expression juridique.","D'autres pays ont des lois similaires : en Corée du Sud, les seniors ont des wagons réservés dans le métro.","Au Japon, le « Respect for the Aged Day » est un jour férié national célébré le troisième lundi de septembre."],en:["In Turkey, respect for elders is a cultural pillar — this law is a legal expression of it.","Other countries have similar laws: in South Korea, seniors have reserved subway cars.","In Japan, 'Respect for the Aged Day' is a national holiday celebrated the third Monday of September."],
    es:["La Ley de Amdahl establece que la mejora máxima de un sistema está limitada por la fracción que no puede ser paralelizada — si el 25 % de una tarea es secuencial, duplicar los procesadores solo mejora un 33 %.","Esta ley es fundamental en informática: añadir más CPUs tiene rendimientos decrecientes porque siempre existe un cuello de botella secuencial.","El principio se aplica más allá de la informática: en cualquier proceso, identificar y optimizar el cuello de botella es más eficaz que mejorar las partes que ya funcionan bien."]},
  'law20':{fr:["Cette loi protège les droits de propriété aérienne dans un pays où les drones deviennent de plus en plus courants.","La Nouvelle-Zélande a aussi été le premier pays à donner le droit de vote aux femmes en 1893.","Le pays a aussi reconnu la personnalité juridique d'un fleuve (le Whanganui) en 2017 — une première mondiale."],en:["This law protects aerial property rights in a country where drones are increasingly common.","New Zealand was also the first country to give women the right to vote in 1893.","The country also granted legal personhood to a river (the Whanganui) in 2017 — a world first."],
    es:["La Ley de Zipf establece que en cualquier idioma, la frecuencia de una palabra es inversamente proporcional a su rango: la segunda más frecuente aparece la mitad de veces que la primera, la tercera un tercio, etc.","En español, «de» es la palabra más frecuente (7 % de todas las palabras), seguida de «la», «que», «el» y «en» — las 100 palabras más comunes cubren más del 50 % de cualquier texto.","La ley de Zipf aparece en fenómenos dispares: tamaño de ciudades, distribución de ingresos, visitas a páginas web — una universalidad que los matemáticos aún no explican completamente."]},
  // === MUSIC ===
  'mus1':{fr:["La Red Special est fabriquée à partir du bois d'une cheminée victorienne du XVIIIe siècle et d'un manche de couteau.","May est aussi astrophysicien — il a obtenu son doctorat en 2007 après 30 ans d'interruption pour Queen.","Il utilise une pièce de six pence britannique comme médiator, ce qui donne ce son si caractéristique."],en:["The Red Special is made from an 18th-century Victorian fireplace wood and a knife handle.","May is also an astrophysicist — he completed his PhD in 2007 after a 30-year break for Queen.","He uses a British sixpence coin as a pick, giving that characteristic sound."],
    es:["La flauta de Hohle Fels, tallada en hueso de buitre hace 43 000 años, es el instrumento musical más antiguo conocido — demuestra que la música precede a la civilización.","La flauta tiene cinco agujeros y produce una escala pentatónica — los mismos intervalos usados hoy en el blues, el rock y la música tradicional de todo el mundo.","La existencia de instrumentos tan antiguos sugiere que la música no es un lujo cultural sino una necesidad biológica profunda, ligada a la cohesión social y la supervivencia del grupo."]},
  'mus2':{fr:["Paul McCartney a rêvé la mélodie de Yesterday — il s'est réveillé et l'a jouée immédiatement au piano.","Les paroles provisoires étaient « Scrambled eggs, oh my baby how I love your legs » avant de devenir Yesterday.","Yesterday est la chanson la plus reprise de tous les temps — plus de 2 200 versions enregistrées."],en:["Paul McCartney dreamed the melody of Yesterday — he woke up and immediately played it on piano.","The working lyrics were 'Scrambled eggs, oh my baby how I love your legs' before becoming Yesterday.","Yesterday is the most covered song ever — over 2,200 recorded versions."],
    es:["Beethoven compuso su Novena Sinfonía (1824) estando completamente sordo — nunca pudo escuchar la obra más aclamada de su vida.","En el estreno, el público aplaudió de pie durante varios minutos, pero Beethoven, de espaldas, no lo supo hasta que una cantante lo giró para que viera la ovación.","El Himno a la Alegría del cuarto movimiento fue adoptado como himno de la Unión Europea en 1985 — un símbolo de unidad que trasciende naciones y culturas."]},
  'mus3':{fr:["La petite amie de Cobain utilisait le déodorant Teen Spirit — elle avait écrit « Kurt smells like teen spirit » sur un mur.","Cobain ne savait pas que c'était une marque — il pensait que la phrase avait un sens révolutionnaire.","Le clip a coûté seulement 50 000 dollars à produire mais est devenu l'un des clips les plus iconiques de l'histoire."],en:["Cobain's girlfriend used Teen Spirit deodorant — she wrote 'Kurt smells like teen spirit' on a wall.","Cobain didn't know it was a brand — he thought the phrase had revolutionary meaning.","The video cost only $50,000 to produce but became one of the most iconic music videos ever."],
    es:["El blues nació en el Delta del Misisipi a finales del siglo XIX, como expresión musical del sufrimiento de los afroamericanos tras la esclavitud.","La estructura del blues (12 compases, acordes I-IV-V, blue notes) es la base del rock and roll, el jazz, el R&B, el funk y el hip-hop — prácticamente toda la música popular moderna.","Robert Johnson, leyenda del blues, supuestamente vendió su alma al diablo en un cruce de caminos a cambio de su talento — murió a los 27 años, inaugurando el «Club de los 27»."]},
  'mus4':{fr:["Le « lean » de 45 degrés dans le clip de Smooth Criminal semblait défier la gravité.","Les chaussures brevetées utilisent un clou rétractable dans le sol qui s'accroche au talon de la chaussure.","Le brevet (US Patent 5,255,452) a été déposé en 1993 et est devenu un objet de collection."],en:["The 45-degree lean in the Smooth Criminal video seemed to defy gravity.","The patented shoes use a retractable nail in the floor that hooks into the shoe heel.","The patent (US Patent 5,255,452) was filed in 1993 and became a collector's item."],
    es:["Los Beatles son el grupo más exitoso de la historia con más de 600 millones de discos vendidos — transformaron la música, la moda, la cultura y la política de los años 60.","Lennon y McCartney escribieron más de 180 canciones juntos, aunque muchas fueron compuestas individualmente — el crédito conjunto fue un pacto acordado al inicio del grupo.","La separación de los Beatles en 1970 fue un trauma cultural global: fans lloraron en la calle y las teorías sobre las causas de la ruptura siguen siendo debatidas hoy."]},
  'mus5':{fr:["Eminem a écrit la chanson sur des feuilles volantes entre les prises de tournage du film 8 Mile.","Lose Yourself est la première chanson de rap à remporter l'Oscar de la meilleure chanson originale en 2003.","Eminem n'était pas présent à la cérémonie des Oscars — il dormait chez lui, convaincu qu'il ne gagnerait pas."],en:["Eminem wrote the song on loose paper between takes on the 8 Mile film set.","Lose Yourself was the first rap song to win the Oscar for Best Original Song in 2003.","Eminem wasn't at the Oscars ceremony — he was sleeping at home, convinced he wouldn't win."],
    es:["El hip-hop nació en el Bronx de Nueva York en los años 1970, cuando DJ Kool Herc empezó a aislar los breakbeats de los discos de funk para que los B-boys bailaran.","Los cuatro elementos del hip-hop son: DJing, MCing (rap), breakdance y graffiti — una cultura completa nacida de las comunidades afroamericanas y latinas marginalizadas.","Hoy el hip-hop es el género musical más escuchado del mundo en streaming, y su influencia se extiende a la moda, el lenguaje, el cine y la política."]},
  'mus6':{fr:["Les casques intégraient des LED, un micro, un système de ventilation et pesaient environ 4 kg chacun.","Thomas Bangalter et Guy-Manuel de Homem-Christo n'ont jamais révélé leurs visages en public en tant que Daft Punk.","Le duo s'est séparé en 2021 après 28 ans de carrière — leur vidéo d'adieu Epilogue a fait le tour du monde."],en:["The helmets integrated LEDs, a mic, ventilation, and weighed about 4 kg each.","Thomas Bangalter and Guy-Manuel de Homem-Christo never revealed their faces publicly as Daft Punk.","The duo split in 2021 after 28 years — their farewell video Epilogue went worldwide."],
    es:["Mozart compuso más de 600 obras antes de morir a los 35 años — un promedio de una obra nueva cada tres semanas durante toda su vida adulta.","A los 5 años ya componía, a los 8 escribió su primera sinfonía y a los 12 su primera ópera — su genio precoz no tiene equivalente en la historia de la música.","La causa de su muerte sigue siendo un misterio: más de 100 diagnósticos diferentes han sido propuestos, desde envenenamiento hasta fiebre reumática y triquinosis."]},
  'mus7':{fr:["Prince a enregistré son premier album For You entièrement seul dans un studio — voix, instruments et production.","Il avait une voûte secrète à Paisley Park contenant des milliers de chansons inédites.","Prince a changé son nom en un symbole imprononçable en 1993 pour protester contre son contrat avec Warner Bros."],en:["Prince recorded his first album For You entirely alone in a studio — vocals, instruments, and production.","He had a secret vault at Paisley Park containing thousands of unreleased songs.","Prince changed his name to an unpronounceable symbol in 1993 to protest his Warner Bros contract."],
    es:["El reggae nació en Jamaica a finales de los años 1960 como evolución del ska y el rocksteady, impregnado de la espiritualidad rastafari.","Bob Marley convirtió el reggae en un movimiento global: sus canciones de libertad, justicia y amor lo transformaron en el artista más influyente del Tercer Mundo.","La canción One Love de Marley fue declarada «canción del milenio» por la BBC — su mensaje de unidad sigue resonando décadas después de su muerte en 1981."]},
  'mus8':{fr:["Richards a enregistré le riff sur un magnétophone posé sur sa table de nuit — puis s'est rendormi.","Le lendemain matin, il a trouvé 40 minutes d'enregistrement dont 2 minutes de riff et 38 minutes de ronflements.","Satisfaction est considérée comme l'un des meilleurs riffs de guitare de tous les temps."],en:["Richards recorded the riff on a tape recorder on his nightstand — then fell back asleep.","The next morning he found 40 minutes of recording: 2 minutes of riff and 38 minutes of snoring.","Satisfaction is considered one of the greatest guitar riffs of all time."],
    es:["La música electrónica nació en los años 1950 con compositores como Stockhausen y Pierre Schaeffer, que manipulaban sonidos grabados y sintetizadores experimentales.","El sintetizador Moog (1964) democratizó la electrónica: Wendy Carlos popularizó el instrumento con su álbum Switched-On Bach (1968).","El techno nació en Detroit en los años 1980, la house en Chicago y el drum and bass en Londres — tres ciudades postindustriales que canalizaron su energía en la pista de baile."]},
  'mus9':{fr:["La blessure a été causée par un coup de poing de son ami George Underwood lors d'une dispute à 15 ans.","L'œil gauche de Bowie est resté avec une pupille dilatée de façon permanente, lui donnant l'apparence de deux yeux de couleur différente.","Bowie et Underwood sont restés amis toute leur vie — Underwood est devenu artiste peintre."],en:["The injury was caused by a punch from his friend George Underwood during a fight at age 15.","Bowie's left eye kept a permanently dilated pupil, giving the appearance of two different-colored eyes.","Bowie and Underwood remained friends for life — Underwood became a painter."],
    es:["El K-pop se ha convertido en un fenómeno global liderado por BTS, BLACKPINK y Stray Kids — la industria genera más de 10 000 millones de dólares anuales.","Los idols del K-pop pasan por años de entrenamiento intensivo (canto, baile, idiomas, actuación) antes de debutar — un sistema que ha sido comparado con academias militares del entretenimiento.","BTS fue el primer grupo de K-pop en llenar estadios en todo el mundo y en hablar ante la Asamblea General de la ONU — un soft power cultural sin precedentes para Corea del Sur."]},
  'mus10':{fr:["Sheeran jouait jusqu'à 3 concerts par nuit dans des petites salles londoniennes pour se faire connaître.","Il a été repéré par Jamie Foxx qui l'a hébergé chez lui et lui a donné accès à son studio.","Son album ÷ (Divide) est l'album le plus streamé de l'année 2017 avec plus de 3 milliards d'écoutes."],en:["Sheeran played up to 3 gigs per night in small London venues to get noticed.","He was spotted by Jamie Foxx who hosted him and gave him access to his studio.","His album ÷ (Divide) was the most-streamed album of 2017 with over 3 billion plays."],
    es:["El vinilo de 33 RPM fue introducido por Columbia Records en 1948, permitiendo grabar hasta 25 minutos por cara — una revolución que hizo posible el concepto de álbum.","El formato LP (Long Play) permitió a los artistas crear obras cohesivas de 40-50 minutos en lugar de singles sueltos — nació el álbum como forma artística.","A pesar de la era digital, las ventas de vinilos han crecido cada año desde 2006: en 2023 se vendieron más de 40 millones de discos de vinilo en EE.UU."]},
  'mus11':{fr:["L'album est resté dans le Billboard 200 pendant 937 semaines — plus de 18 ans consécutifs.","Il s'est vendu à plus de 45 millions d'exemplaires, ce qui en fait l'un des albums les plus vendus de l'histoire.","La pochette du prisme a été conçue par Storm Thorgerson — l'un des designers d'album les plus célèbres."],en:["The album stayed in the Billboard 200 for 937 weeks — over 18 consecutive years.","It sold over 45 million copies, making it one of the best-selling albums ever.","The prism cover was designed by Storm Thorgerson — one of the most famous album designers."],
    es:["El flamenco combina cante (voz), toque (guitarra) y baile en una expresión artística nacida en Andalucía entre las comunidades gitanas, moriscas y judías.","El compás (ritmo) del flamenco puede ser extremadamente complejo: la bulería tiene un ciclo de 12 tiempos con acentos irregulares que desafían la notación occidental.","El duende, esa emoción intensa que trasciende la técnica, es el santo grial del flamenco — Lorca lo describió como un poder que se siente pero no se puede explicar."]},
  'mus12':{fr:["Ce système de numérotation crée une connexion intime entre l'artiste et les chansons.","L'album 21 contient Rolling in the Deep et Someone Like You — deux des chansons les plus populaires du XXIe siècle.","Adele a battu des records de ventes avec l'album 25 : 3,38 millions d'exemplaires vendus en une semaine aux États-Unis."],en:["This numbering system creates an intimate connection between artist and songs.","Album 21 contains Rolling in the Deep and Someone Like You — two of the 21st century's most popular songs.","Adele broke sales records with 25: 3.38 million copies sold in one week in the US."],
    es:["Spotify, lanzado en 2008, transformó la industria musical: pasó de vender álbumes a vender acceso, pagando a los artistas fracciones de céntimo por reproducción.","Con más de 600 millones de usuarios, Spotify ha democratizado el acceso a la música pero ha reducido drásticamente los ingresos de los artistas independientes.","Los algoritmos de recomendación de Spotify (Discover Weekly, Release Radar) han creado un nuevo intermediario entre artistas y oyentes — la curación humana ha cedido terreno a la IA."]},
  'mus13':{fr:["Lady Gaga a souffert de dépression sévère avant le succès de Just Dance qui a changé sa vie.","Elle a étudié la musique à la Tisch School of the Arts de NYU mais a abandonné pour poursuivre sa carrière.","Son nom de scène vient de la chanson Radio Ga Ga de Queen — un autocorrecteur a transformé « Radio » en « Lady »."],en:["Lady Gaga suffered severe depression before the success of Just Dance changed her life.","She studied music at NYU's Tisch School of the Arts but dropped out to pursue her career.","Her stage name comes from Queen's Radio Ga Ga — autocorrect changed 'Radio' to 'Lady'."],
    es:["Freddie Mercury tenía un rango vocal de cuatro octavas y una técnica que los científicos han comparado con la de los cantantes de ópera — algo inusual en el rock.","Bohemian Rhapsody (1975) fue rechazada por la discográfica por ser demasiado larga y experimental — se convirtió en una de las canciones más icónicas de la historia.","El concierto de Queen en Live Aid (1985) ante 72 000 personas en Wembley es considerado la mejor actuación en directo de la historia del rock."]},
  'mus14':{fr:["Houston a vendu plus de 20 millions d'exemplaires du single — sa version est devenue plus célèbre que l'originale.","Parton gagne environ 10 millions de dollars par an en royalties grâce à la version de Houston.","Parton a dit en plaisantant que grâce à Whitney, elle s'est payé beaucoup de perruques et de maquillage."],en:["Houston sold over 20 million copies of the single — her version became more famous than the original.","Parton earns about $10 million per year in royalties from Houston's version.","Parton jokingly said that thanks to Whitney, she bought a lot of wigs and makeup."],
    es:["La guitarra eléctrica fue desarrollada en los años 1930 para que los guitarristas de jazz pudieran ser escuchados sobre las secciones de viento.","La Fender Telecaster (1950) y la Gibson Les Paul (1952) establecieron los dos arquetipos de guitarra eléctrica que dominan el rock desde hace más de 70 años.","Jimi Hendrix reinventó la guitarra eléctrica con feedback, distorsión y wah-wah — su interpretación del himno estadounidense en Woodstock (1969) es uno de los momentos más icónicos del siglo XX."]},
  'mus15':{fr:["Jay-Z entre en studio, écoute le beat, et rappe ses vers directement — sans aucune note écrite.","Il estime que cette méthode rend ses paroles plus naturelles et conversationnelles.","Jay-Z est devenu le premier rappeur milliardaire en 2019 — sa fortune vient autant de la musique que des affaires."],en:["Jay-Z enters the studio, listens to the beat, and raps his verses directly — with no written notes.","He believes this method makes his lyrics more natural and conversational.","Jay-Z became the first billionaire rapper in 2019 — his fortune comes from business as much as music."],
    es:["El piano fue inventado por Bartolomeo Cristofori en Florencia hacia 1700 — su nombre original era «gravicembalo col piano e forte» (clave con suave y fuerte).","El piano es el instrumento más versátil: puede tocar melodía, armonía y ritmo simultáneamente, lo que lo convierte en el instrumento por excelencia para la composición.","Un piano de cola de concierto Steinway cuesta más de 150 000 euros y contiene más de 12 000 piezas — cada instrumento se fabrica artesanalmente durante más de un año."]},
  'mus16':{fr:["Le groupe TLC a trouvé la chanson trop mielleuse — Britney, 16 ans, l'a transformée en tube pop mondial.","Max Martin, le producteur suédois, a écrit le titre — il est derrière plus de 25 numéros un dans le monde.","La chanson a lancé la carrière de Britney et l'ère de la pop teen des années 2000."],en:["TLC found the song too saccharine — 16-year-old Britney turned it into a worldwide pop hit.","Swedish producer Max Martin wrote the track — he's behind over 25 number ones worldwide.","The song launched Britney's career and the teen pop era of the 2000s."],
    es:["Michael Jackson vendió más de 400 millones de discos, con Thriller (1982) como el álbum más vendido de la historia: más de 70 millones de copias.","El moonwalk, presentado durante la interpretación de Billie Jean en 1983, se convirtió en el paso de baile más imitado del mundo.","Jackson transformó el videoclip en forma artística con Thriller (1983), un cortometraje de 14 minutos dirigido por John Landis que revolucionó MTV y la industria musical."]},
  'mus17':{fr:["L'album s'est vendu à plus de 30 millions d'exemplaires dans le monde.","Le groupe vivait dans la misère totale à Hollywood avant le succès de l'album — ils dormaient dans les rues.","La pochette originale comportait une image controversée qui a été remplacée par une croix celtique."],en:["The album sold over 30 million copies worldwide.","The band lived in total poverty in Hollywood before the album's success — sleeping on streets.","The original cover had a controversial image that was replaced with a Celtic cross."],
    es:["El jazz nació en Nueva Orleans a principios del siglo XX, fusionando tradiciones musicales africanas, blues, ragtime y música de desfile.","La improvisación es su esencia: los músicos crean melodías espontáneas sobre progresiones armónicas compartidas, convirtiendo cada actuación en irrepetible.","Miles Davis reinventó el jazz al menos cinco veces en su carrera: bebop, cool jazz, hard bop, jazz modal (Kind of Blue) y fusión (Bitches Brew)."]},
  'mus18':{fr:["Elvis recevait des crédits de co-auteur sur certaines chansons en échange de leur enregistrement — une pratique courante à l'époque.","Ses auteurs les plus célèbres étaient Jerry Leiber et Mike Stoller, qui ont écrit Hound Dog et Jailhouse Rock.","Malgré cela, Elvis reste l'artiste solo ayant vendu le plus de disques de l'histoire — environ 500 millions."],en:["Elvis received co-writing credits on some songs in exchange for recording them — a common practice then.","His most famous songwriters were Jerry Leiber and Mike Stoller, who wrote Hound Dog and Jailhouse Rock.","Despite this, Elvis remains the best-selling solo artist ever — about 500 million records."],
    es:["La ópera nació en Florencia a finales del siglo XVI como intento de recrear el drama musical de la Grecia antigua.","Las voces de ópera se clasifican en seis rangos: soprano, mezzosoprano, contralto (mujeres) y tenor, barítono, bajo (hombres) — cada rol exige una técnica vocal específica.","Luciano Pavarotti popularizó la ópera en los años 1990 con Los Tres Tenores y el uso de sus arias en la publicidad — la ópera dejó de ser un arte exclusivamente elitista."]},
  'mus19':{fr:["Mercury pouvait couvrir du fa grave au fa aigu — une gamme exceptionnelle que peu de chanteurs atteignent.","Des scientifiques ont analysé sa voix en 2016 et découvert qu'il utilisait ses fausses cordes vocales, normalement inactives.","Bohemian Rhapsody, sa composition la plus ambitieuse, a été enregistrée sur 180 pistes séparées."],en:["Mercury could span from low F to high F — an exceptional range few singers achieve.","Scientists analyzed his voice in 2016 and found he used his ventricular folds, normally inactive.","Bohemian Rhapsody, his most ambitious composition, was recorded on 180 separate tracks."],
    es:["La música country nació en los Apalaches del sur de EE.UU. como fusión de folk irlandés y escocés, blues afroamericano y gospel.","Nashville, Tennessee, se convirtió en la capital del country gracias al programa de radio Grand Ole Opry (desde 1925) — la emisión de radio más longeva de la historia de EE.UU.","Johnny Cash, el «hombre de negro», fue un rebelde que trascendió el country: tocó en prisiones, luchó contra la adicción y colaboró con artistas de rock y punk."]},
  'mus20':{fr:["Avant 1939, le La de référence variait entre 415 et 460 Hz selon les pays et les orchestres.","La standardisation à 440 Hz a été adoptée lors d'une conférence internationale à Londres.","Certains musiciens préfèrent le La 432 Hz, affirmant qu'il est plus harmonieux — mais c'est surtout une préférence subjective."],en:["Before 1939, the reference A varied between 415 and 460 Hz depending on country and orchestra.","The 440 Hz standard was adopted at an international conference in London.","Some musicians prefer A 432 Hz, claiming it's more harmonious — but it's mainly subjective preference."],
    es:["La samba es el género musical emblemático de Brasil, nacido en las comunidades afrobrasileñas de Río de Janeiro a principios del siglo XX.","El Carnaval de Río, con sus escuelas de samba (cada una con hasta 4 000 participantes), es el mayor espectáculo musical del mundo.","La bossa nova, fusión de samba y jazz creada por João Gilberto y Tom Jobim en los años 1950, se convirtió en uno de los géneros brasileños más influyentes a nivel internacional."]},
  // === MYTHOLOGY ===
  'myth1':{fr:["Zeus souffrait d'un mal de tête si violent qu'il a demandé à Héphaïstos de lui fendre le crâne avec une hache.","Athéna est la déesse de la sagesse, de la guerre stratégique et de l'artisanat — elle protégeait Athènes.","Elle n'a jamais eu de mère — elle est née uniquement de Zeus, ce qui en fait une divinité unique dans le panthéon grec."],en:["Zeus had such a violent headache he asked Hephaestus to split his skull with an axe.","Athena is the goddess of wisdom, strategic warfare, and craft — she protected Athens.","She never had a mother — born solely from Zeus, making her unique in the Greek pantheon."],
    es:["Zeus, rey de los dioses del Olimpo, era un mujeriego compulsivo que se transformaba en cisne, toro, lluvia de oro y hasta hormiga para seducir a mortales y diosas.","Sus numerosas aventuras amorosas engendraron héroes (Heracles, Perseo, Helena) y provocaron la ira de su esposa Hera, cuya venganza caía siempre sobre las amantes, no sobre Zeus.","El rayo de Zeus no era solo un arma sino un símbolo de justicia divina — los griegos consideraban que los lugares alcanzados por un rayo eran sagrados."]},
  'myth2':{fr:["Le moucheron était en fait Loki déguisé, qui voulait saboter la fabrication du marteau.","Malgré ce défaut, Mjölnir reste l'arme la plus puissante d'Asgard — seul Thor peut le soulever.","Le marteau revient toujours dans la main de Thor après avoir été lancé — comme un boomerang divin."],en:["The gnat was actually Loki in disguise, trying to sabotage the hammer's creation.","Despite this flaw, Mjölnir remains Asgard's most powerful weapon — only Thor can lift it.","The hammer always returns to Thor's hand after being thrown — like a divine boomerang."],
    es:["El Valhalla nórdico era el paraíso de los guerreros caídos en combate, donde festejaban y luchaban eternamente hasta el Ragnarök, la batalla del fin del mundo.","Las valkirias, guerreras divinas, elegían a los más valientes entre los muertos en batalla para llevarlos al Valhalla — un destino más honorable que el frío y gris Hel.","El Ragnarök no es solo destrucción: tras la batalla final donde mueren la mayoría de los dioses, el mundo renace purificado — un ciclo de muerte y renovación."]},
  'myth3':{fr:["Si le cœur était plus lourd que la plume de Maât, le défunt était dévoré par Ammit, un monstre mi-crocodile mi-lion mi-hippopotame.","Anubis guidait aussi les âmes dans le monde souterrain — il était le « psychopompe » égyptien.","Il était représenté avec une tête de chacal car ces animaux rôdaient souvent près des tombes."],en:["If the heart was heavier than Maat's feather, the deceased was devoured by Ammit, a crocodile-lion-hippo monster.","Anubis also guided souls in the underworld — the Egyptian 'psychopomp'.","He was depicted with a jackal head because these animals often lurked near tombs."],
    es:["El Minotauro, mitad hombre mitad toro, habitaba el laberinto de Creta diseñado por Dédalo — cada año devoraba siete jóvenes y siete doncellas atenienses.","Teseo mató al Minotauro con ayuda del hilo de Ariadna, que le permitió encontrar la salida del laberinto — luego abandonó a Ariadna en la isla de Naxos.","El mito puede reflejar un hecho histórico: la dominación cretense sobre Atenas, que exigía tributos humanos, y la posterior liberación ateniense."]},
  'myth4':{fr:["Les autres dieux ont dû la faire sortir en plaçant un miroir devant la grotte — curieuse, elle est sortie voir son propre reflet.","Ce mythe explique les éclipses solaires et le cycle des saisons au Japon.","Amaterasu est l'ancêtre divine de la famille impériale japonaise selon la tradition shinto."],en:["Other gods lured her out by placing a mirror before the cave — curious, she came out to see her reflection.","This myth explains solar eclipses and seasonal cycles in Japan.","Amaterasu is the divine ancestor of the Japanese imperial family in Shinto tradition."],
    es:["Quetzalcóatl, la serpiente emplumada, era uno de los dioses principales del panteón azteca y mesoamericano — asociado al viento, la sabiduría y la estrella de la mañana.","La leyenda de su regreso por el este fue supuestamente aprovechada por Hernán Cortés para presentarse como el dios que volvía — aunque esta versión es discutida por los historiadores modernos.","Quetzalcóatl aparece en las culturas olmeca, teotihuacana, tolteca y azteca con diferentes nombres pero funciones similares — un dios panmesoamericano que perduró más de 2 000 años."]},
  'myth5':{fr:["Le Minotaure est né de l'union de Pasiphaé, l'épouse du roi Minos, avec un taureau blanc envoyé par Poséidon.","Thésée a tué le Minotaure grâce au fil d'Ariane qui lui a permis de retrouver la sortie du labyrinthe.","Le labyrinthe de Dédale a inspiré le concept même du mot « labyrinthe » dans toutes les langues européennes."],en:["The Minotaur was born from the union of Pasiphae, King Minos's wife, with a white bull sent by Poseidon.","Theseus killed the Minotaur using Ariadne's thread to find the labyrinth's exit.","Daedalus's labyrinth inspired the very concept of the word 'labyrinth' in all European languages."],
    es:["Odiseo (Ulises) tardó 10 años en regresar a Ítaca tras la Guerra de Troya, enfrentando cíclopes, sirenas, la hechicera Circe y la ira de Poseidón.","La Odisea de Homero (siglo VIII a.C.) es el primer relato de aventuras de la literatura occidental y el modelo de toda narrativa de viaje y retorno.","La astucia de Odiseo — su «inteligencia práctica» (metis) — lo distingue de los héroes musculosos: es el prototipo del héroe que triunfa con su ingenio."]},
  'myth6':{fr:["Le cheval né de Loki s'appelle Sleipnir — il a huit pattes et est devenu la monture d'Odin.","Loki est aussi le père du loup Fenrir, du serpent Jörmungandr et de la déesse des morts Hel.","Malgré ses méfaits, Loki est toléré par les dieux car son intelligence leur est souvent utile."],en:["The horse born from Loki is called Sleipnir — it has eight legs and became Odin's mount.","Loki is also father of wolf Fenrir, serpent Jörmungandr, and death goddess Hel.","Despite his misdeeds, Loki is tolerated by the gods because his intelligence is often useful."],
    es:["Anubis, el dios egipcio con cabeza de chacal, presidía el embalsamamiento y guiaba a los muertos al inframundo para el juicio de Osiris.","En el pesaje del corazón, Anubis colocaba el corazón del difunto en un platillo de la balanza y la pluma de Maat (verdad) en el otro — si el corazón era más pesado, el monstruo Ammit lo devoraba.","Los antiguos egipcios momificaban a los muertos para preservar el cuerpo como receptáculo del ka (fuerza vital) — el proceso duraba 70 días e incluía la extracción del cerebro por la nariz."]},
  'myth7':{fr:["Prométhée a aussi créé les humains à partir d'argile selon certaines versions du mythe.","Son supplice a duré des millénaires jusqu'à ce qu'Héraclès le libère en tuant l'aigle.","Le « feu » qu'il a volé est interprété comme un symbole de la connaissance et de la civilisation."],en:["Prometheus also created humans from clay according to some versions of the myth.","His torment lasted millennia until Heracles freed him by killing the eagle.","The 'fire' he stole is interpreted as a symbol of knowledge and civilization."],
    es:["El Rey Arturo, Excalibur, la Tabla Redonda y la búsqueda del Santo Grial son los mitos fundacionales de la literatura caballeresca europea.","No existe evidencia histórica de un rey Arturo real, aunque podría estar basado en un líder britano del siglo V o VI que luchó contra las invasiones sajonas.","Las historias artúricas evolucionaron durante siglos: Chrétien de Troyes añadió a Lancelot y el Grial, Mallory compiló Le Morte d'Arthur (1485) y T.H. White las reinventó en el siglo XX."]},
  'myth8':{fr:["La tortue cosmique s'appelle Akupara — elle porte le monde sur son dos dans la mythologie hindoue.","Quand les éléphants tremblent, cela provoque des tremblements de terre selon cette cosmologie.","Ce mythe a inspiré Terry Pratchett pour son Disque-monde, porté par quatre éléphants sur une tortue géante."],en:["The cosmic turtle is called Akupara — it carries the world on its back in Hindu mythology.","When the elephants tremble, it causes earthquakes according to this cosmology.","This myth inspired Terry Pratchett's Discworld, carried by four elephants on a giant turtle."],
    es:["Prometeo robó el fuego a los dioses para dárselo a los humanos — Zeus lo castigó encadenándolo a una roca donde un águila le devoraba el hígado cada día, que se regeneraba cada noche.","El mito de Prometeo es una metáfora del conocimiento y la tecnología: un regalo que empodera pero que conlleva consecuencias imprevistas.","Mary Shelley tituló su novela Frankenstein; o el moderno Prometeo — una comparación entre el titán que desafió a los dioses y el científico que desafía la naturaleza."]},
  'myth9':{fr:["Persée a utilisé un bouclier poli comme miroir pour ne pas croiser le regard de Méduse.","Méduse était autrefois une belle femme transformée en monstre par Athéna après avoir été violée dans son temple par Poséidon.","Du sang de Méduse est né le cheval ailé Pégase — l'une des créatures les plus célèbres de la mythologie."],en:["Perseus used a polished shield as a mirror to avoid meeting Medusa's gaze.","Medusa was once a beautiful woman turned into a monster by Athena after being assaulted in her temple by Poseidon.","From Medusa's blood, the winged horse Pegasus was born — one of mythology's most famous creatures."],
    es:["Los dragones aparecen en las mitologías de todo el mundo: serpientes voladoras en China, dragones que escupen fuego en Europa, serpientes emplumadas en Mesoamérica.","En Oriente, los dragones son criaturas benéficas asociadas al agua, la lluvia y la prosperidad — en Occidente son bestias malvadas que acumulan tesoros y devoran doncellas.","Algunos paleontólogos sugieren que los mitos de dragones se inspiraron en fósiles de dinosaurios y grandes reptiles que las civilizaciones antiguas encontraban sin poder explicar."]},
  'myth10':{fr:["Le Dagda est le chef des Tuatha Dé Danann, les dieux irlandais — il possédait aussi une harpe magique qui contrôlait les saisons.","Le chaudron pouvait aussi ressusciter les guerriers morts — mais ils revenaient muets et sans âme.","La mythologie celtique a été transmise oralement pendant des siècles avant d'être transcrite par des moines chrétiens."],en:["The Dagda is chief of the Tuatha Dé Danann, Irish gods — he also owned a magic harp controlling seasons.","The cauldron could also resurrect dead warriors — but they returned mute and soulless.","Celtic mythology was transmitted orally for centuries before being transcribed by Christian monks."],
    es:["Atenea, diosa de la sabiduría y la guerra estratégica, nació adulta y armada de la cabeza de Zeus tras un terrible dolor de cabeza.","A diferencia de Ares (dios de la guerra brutal), Atenea representaba la guerra inteligente: estrategia, planificación y victoria mediante el ingenio.","La ciudad de Atenas lleva su nombre tras un concurso con Poseidón: ella ofreció el olivo (alimento, aceite, madera) mientras él ofreció una fuente de agua salada — los atenienses eligieron el olivo."]},
  'myth11':{fr:["Achille a été plongé dans le Styx par sa mère Thétis — mais elle le tenait par le talon, laissant ce point vulnérable.","Charon, le passeur, exigeait une pièce de monnaie pour traverser le Styx — d'où l'habitude de placer une pièce dans la bouche des morts.","Il existe cinq fleuves des Enfers : Styx (haine), Achéron (douleur), Léthé (oubli), Phlégéton (feu) et Cocyte (lamentation)."],en:["Achilles was dipped in the Styx by his mother Thetis — but she held him by the heel, leaving that weak point.","Charon the ferryman demanded a coin to cross the Styx — hence the custom of placing a coin in the dead's mouth.","There are five rivers of the Underworld: Styx (hate), Acheron (pain), Lethe (forgetfulness), Phlegethon (fire), and Cocytus (lamentation)."],
    es:["Thor, el dios nórdico del trueno, no era el rubio musculoso de Marvel: las fuentes vikingas lo describen pelirrojo, con barba espesa y un apetito insaciable.","Su martillo Mjölnir fue forjado por los enanos Sindri y Brokkr — el mango era demasiado corto debido a una apuesta de Loki con los enanos, que resultó en su distracción.","Thor era el dios más popular entre los vikingos comunes: protector de los humanos contra los gigantes, patrón de los campesinos y los marineros."]},
  'myth12':{fr:["La chaîne magique Gleipnir était faite de six ingrédients impossibles : le bruit d'un pas de chat, la barbe d'une femme, les racines d'une montagne, les tendons d'un ours, le souffle d'un poisson et la salive d'un oiseau.","Fenrir dévorera Odin lors du Ragnarök — la fin du monde dans la mythologie nordique.","Le fils de Fenrir, Sköll, poursuit le Soleil dans le ciel — quand il l'attrapera, le Ragnarök commencera."],en:["The magic chain Gleipnir was made of six impossible ingredients: a cat's footstep, a woman's beard, a mountain's roots, a bear's sinews, a fish's breath, and a bird's spit.","Fenrir will devour Odin during Ragnarök — the end of the world in Norse mythology.","Fenrir's son Sköll chases the Sun across the sky — when he catches it, Ragnarök will begin."],
    es:["Isis, diosa egipcia de la magia y la maternidad, reconstruyó el cuerpo desmembrado de su esposo Osiris (cortado en 14 pedazos por su hermano Seth) y lo resucitó brevemente para concebir a Horus.","El culto a Isis se extendió por todo el Mediterráneo romano y perduró hasta el siglo VI — algunos historiadores ven paralelos entre Isis con Horus y la Virgen María con Jesús.","Isis representaba el poder femenino en su forma más completa: esposa devota, madre protectora y maga suprema — un arquetipo que trasciende la mitología egipcia."]},
  'myth13':{fr:["Orphée est descendu aux Enfers pour ramener sa femme Eurydice — Hadès a accepté à condition qu'il ne se retourne pas.","Il s'est retourné juste avant la sortie — perdant Eurydice pour toujours.","Après sa mort, sa lyre a été placée dans les étoiles par Zeus, formant la constellation de la Lyre."],en:["Orpheus descended to the Underworld to bring back his wife Eurydice — Hades agreed on condition he not look back.","He looked back just before the exit — losing Eurydice forever.","After his death, his lyre was placed among the stars by Zeus, forming the Lyra constellation."],
    es:["La caja de Pandora no era originalmente una caja sino un pithos (gran vasija de almacenamiento) — la confusión viene de una traducción errónea de Erasmo en el siglo XVI.","Según Hesíodo, Zeus envió a Pandora como castigo por el robo del fuego de Prometeo — al abrir la vasija, liberó todos los males del mundo, pero dejó la esperanza dentro.","El mito plantea una pregunta filosófica: ¿la esperanza fue retenida como consuelo para la humanidad o como el peor de los males, que prolonga el sufrimiento?"]},
  'myth14':{fr:["Quetzalcóatl est représenté comme un serpent couvert de plumes de quetzal — un oiseau aux plumes vertes iridescentes.","Les Aztèques croyaient que Cortés était Quetzalcóatl revenu — ce malentendu a facilité la conquête espagnole.","Le quetzal est aujourd'hui l'oiseau national du Guatemala et sa monnaie porte son nom."],en:["Quetzalcóatl is depicted as a serpent covered in quetzal feathers — a bird with iridescent green plumage.","Aztecs believed Cortés was Quetzalcóatl returned — this misunderstanding aided the Spanish conquest.","The quetzal is now Guatemala's national bird and its currency bears its name."],
    es:["Ganesh, el dios hindú con cabeza de elefante, es el patrón de los inicios, la sabiduría y la eliminación de obstáculos — toda oración hindú comienza invocándolo.","Según la leyenda, Shiva le cortó la cabeza a Ganesh sin saber que era su hijo, y la reemplazó con la del primer animal que encontró: un elefante.","Ganesh es una de las deidades más veneradas del mundo: su festividad (Ganesh Chaturthi) reúne a millones de devotos en India y en la diáspora hindú."]},
  'myth15':{fr:["Les Valkyries emmenaient les élus au Valhalla, le palais d'Odin, où ils festoyaient en attendant le Ragnarök.","Le mot Valkyrie signifie « celle qui choisit les morts » en vieux norrois.","Wagner a rendu les Valkyries célèbres avec La Chevauchée des Walkyries, l'un des morceaux classiques les plus reconnaissables."],en:["Valkyries took the chosen to Valhalla, Odin's palace, where they feasted awaiting Ragnarök.","The word Valkyrie means 'chooser of the slain' in Old Norse.","Wagner made Valkyries famous with Ride of the Valkyries, one of the most recognizable classical pieces."],
    es:["Las sirenas de la mitología griega no eran mujeres con cola de pez sino mujeres-pájaro cuyo canto irresistible atraía a los marineros hacia las rocas.","La representación como mujeres-pez surgió en la Edad Media, probablemente por confusión con los tritones y las melusinas del folclore europeo.","Odiseo es el único mortal que escuchó el canto de las sirenas y sobrevivió: se hizo atar al mástil de su barco mientras sus marineros se tapaban los oídos con cera."]},
  'myth16':{fr:["Le mythe de Sisyphe est devenu un symbole philosophique de l'absurdité de la condition humaine.","Albert Camus a écrit Le Mythe de Sisyphe en 1942, concluant qu'il faut imaginer Sisyphe heureux.","Sisyphe avait trompé la mort deux fois avant d'être finalement condamné à ce châtiment éternel."],en:["The myth of Sisyphus became a philosophical symbol of the absurdity of the human condition.","Albert Camus wrote The Myth of Sisyphus in 1942, concluding we must imagine Sisyphus happy.","Sisyphus had cheated death twice before being finally condemned to this eternal punishment."],
    es:["Amaterasu, diosa del sol en la mitología japonesa, se encerró en una cueva tras una disputa con su hermano Susanoo, sumiendo el mundo en la oscuridad.","Los demás dioses la atrajeron fuera con una danza y un espejo de bronce — ese espejo es uno de los tres tesoros sagrados del emperador de Japón.","La familia imperial japonesa afirma descender directamente de Amaterasu — una genealogía divina que otorga al emperador un estatus sagrado único entre las monarquías modernas."]},
  'myth17':{fr:["Après avoir séparé le Yin et le Yang, Pan Gu a tenu le ciel et la terre éloignés pendant 18 000 ans.","À sa mort, ses yeux sont devenus le Soleil et la Lune, son sang les rivières et les mers.","Ce mythe est l'un des plus anciens récits de création chinois, datant d'environ 200 apr. J.-C."],en:["After separating Yin and Yang, Pan Gu held sky and earth apart for 18,000 years.","At his death, his eyes became the Sun and Moon, his blood the rivers and seas.","This myth is one of the oldest Chinese creation stories, dating from about 200 AD."],
    es:["El Arca de Noé tiene paralelos en mitologías de todo el mundo: el Utnapishtim sumerio, el Manu hindú, el Deucalión griego y el Nüwa chino sobrevivieron a diluvios similares.","Los geólogos creen que estas leyendas podrían basarse en inundaciones reales, como el desbordamiento del Mar Negro hace 7 600 años, que sumergió vastas regiones habitadas.","Las dimensiones del Arca descritas en el Génesis (137 × 23 × 14 metros) coinciden sorprendentemente con las proporciones óptimas para la estabilidad de un barco según la ingeniería naval moderna."]},
  'myth18':{fr:["Dédale avait prévenu Icare de ne pas voler trop près du soleil ni trop près de la mer.","Le mythe d'Icare est devenu un symbole universel de l'hubris — l'orgueil démesuré qui mène à la chute.","La mer où Icare est tombé s'appelle la mer Icarienne, près de l'île d'Ikaria en Grèce."],en:["Daedalus warned Icarus not to fly too close to the sun or too near the sea.","The myth of Icarus became a universal symbol of hubris — excessive pride leading to downfall.","The sea where Icarus fell is called the Icarian Sea, near the island of Ikaria in Greece."],
    es:["Heracles (Hércules) realizó los Doce Trabajos como penitencia por haber matado a su familia en un acceso de locura provocado por Hera.","Los trabajos incluyen hazañas imposibles: matar al león de Nemea (cuya piel era invulnerable), limpiar los establos de Augías y robar las manzanas de oro de las Hespérides.","Heracles es el héroe semidivino por excelencia: hijo de Zeus y una mortal, sus aventuras simbolizan la lucha humana por superar lo imposible y alcanzar la inmortalidad."]},
  'myth19':{fr:["Orphée a réussi à endormir Cerbère grâce à sa lyre pour entrer aux Enfers et tenter de ramener Eurydice.","Cerbère laissait entrer les morts mais ne les laissait jamais sortir — sauf dans de très rares cas mythologiques.","Le mot « cerbère » est devenu un nom commun en français signifiant un gardien sévère et intraitable."],en:["Orpheus managed to lull Cerberus to sleep with his lyre to enter the Underworld and try to bring back Eurydice.","Cerberus let the dead in but never let them out — except in very rare mythological cases.","The word 'cerberus' became a common French noun meaning a strict and unyielding guardian."],
    es:["Loki, el dios embaucador nórdico, no era un dios sino un jötun (gigante) adoptado por los Æsir — su naturaleza ambigua lo convierte en el personaje más complejo del panteón nórdico.","Loki engendró criaturas monstruosas: el lobo Fenrir, la serpiente Jörmungandr y Hel, gobernante del inframundo — también dio a luz al caballo de ocho patas Sleipnir tras transformarse en yegua.","En el Ragnarök, Loki lidera el ejército de los muertos contra los dioses — su traición final sella el destino del mundo nórdico."]},
  'myth20':{fr:["Le poisson de Māui est devenu l'île du Nord, tandis que son canot est devenu l'île du Sud.","Māui a aussi ralenti le Soleil en le frappant avec la mâchoire de sa grand-mère pour que les jours durent plus longtemps.","La mythologie maorie est vivante — elle est enseignée dans les écoles néo-zélandaises et influence la culture contemporaine."],en:["Māui's fish became the North Island, while his canoe became the South Island.","Māui also slowed the Sun by striking it with his grandmother's jawbone so days would last longer.","Maori mythology is living — taught in New Zealand schools and influencing contemporary culture."],
    es:["El Popol Vuh, libro sagrado de los mayas quichés, narra la creación del mundo y de la humanidad: los dioses fracasaron con el barro y la madera antes de crear al hombre de maíz.","Los Héroes Gemelos Hunahpú e Ixbalanqué descendieron a Xibalbá (el inframundo maya) y vencieron a los señores de la muerte mediante astucia y juego de pelota.","El Popol Vuh fue transcrito en caracteres latinos por un maya quiché en el siglo XVI — sin esa transcripción, gran parte de la mitología maya se habría perdido."]},
  // === OCEANS ===
  'ocean1':{fr:["Les océans couvrent 71 % de la surface de la Terre mais seuls 5 % ont été explorés en détail.","La technologie actuelle ne permet pas encore d'atteindre certaines profondeurs de manière routinière.","On découvre en moyenne 2 000 nouvelles espèces marines par an."],en:["Oceans cover 71% of Earth's surface but only 5% have been explored in detail.","Current technology still can't routinely reach certain depths.","About 2,000 new marine species are discovered per year on average."],
    es:["Los océanos cubren el 71 % de la superficie terrestre pero más del 80 % permanece inexplorado — conocemos mejor la superficie de Marte que el fondo de nuestros mares.","La fosa de las Marianas, el punto más profundo del océano (10 994 m), podría sumergir el Everest con más de 2 km de margen.","Solo tres personas han alcanzado el fondo de la fosa de las Marianas: Jacques Piccard y Don Walsh en 1960, y James Cameron en 2012."]},
  'ocean2':{fr:["Seules trois personnes sont descendues au fond de la fosse des Mariannes — moins que celles ayant marché sur la Lune.","Jacques Piccard et Don Walsh ont été les premiers en 1960 à bord du bathyscaphe Trieste.","James Cameron y est descendu seul en 2012 dans le Deepsea Challenger — il a filmé 3 heures de fond."],en:["Only three people have reached the bottom of the Mariana Trench — fewer than those who walked on the Moon.","Jacques Piccard and Don Walsh were the first in 1960 aboard the bathyscaphe Trieste.","James Cameron descended alone in 2012 in the Deepsea Challenger — filming 3 hours of the bottom."],
    es:["El Gran Arrecife de Coral australiano es la estructura biológica más grande del planeta: 2 300 km de longitud, visible desde el espacio.","Alberga más de 1 500 especies de peces, 400 tipos de coral, 4 000 especies de moluscos y 240 especies de aves — un ecosistema de biodiversidad incomparable.","El blanqueamiento masivo causado por el calentamiento oceánico ha afectado a más del 60 % de los corales en episodios cada vez más frecuentes — su supervivencia a largo plazo está amenazada."]},
  'ocean3':{fr:["Les méduses n'ont ni cerveau, ni cœur, ni os — elles sont composées à 95 % d'eau.","Certaines méduses sont bioluminescentes — leur protéine fluorescente (GFP) a révolutionné la biologie moléculaire.","La méduse-boîte australienne est l'animal le plus venimeux au monde — son venin peut tuer un humain en 2 minutes."],en:["Jellyfish have no brain, heart, or bones — they're 95% water.","Some jellyfish are bioluminescent — their fluorescent protein (GFP) revolutionized molecular biology.","The Australian box jellyfish is the world's most venomous animal — its venom can kill a human in 2 minutes."],
    es:["Las corrientes oceánicas funcionan como una cinta transportadora global (circulación termohalina) que distribuye calor, nutrientes y oxígeno por todo el planeta.","La Corriente del Golfo transporta más agua que todos los ríos del mundo juntos y mantiene la Europa occidental hasta 10 °C más cálida de lo que le correspondería por su latitud.","El debilitamiento de la circulación termohalina por el deshielo del Ártico podría alterar drásticamente el clima europeo — un escenario que los climatólogos vigilan con preocupación."]},
  'ocean4':{fr:["Ses yeux mesurent 27 cm de diamètre — les plus grands du règne animal, de la taille d'un ballon de basket.","Le calmar colossal vit dans les profondeurs de l'océan Antarctique et n'a été filmé vivant qu'en 2013.","Ses tentacules sont équipés de ventouses avec des crochets rotatifs capables de déchirer la chair."],en:["Its eyes measure 27 cm in diameter — the largest in the animal kingdom, basketball-sized.","The colossal squid lives in Antarctic ocean depths and was only filmed alive in 2013.","Its tentacles have suckers with rotating hooks capable of tearing flesh."],
    es:["Las ballenas azules son los animales más grandes que han existido jamás: hasta 30 metros de largo y 180 toneladas — su corazón es del tamaño de un coche pequeño.","Solo su lengua pesa tanto como un elefante, y un bebé de ballena azul nace midiendo 7 metros y gana 90 kg por día durante el primer año.","La caza industrial redujo su población de 300 000 a menos de 5 000 en el siglo XX — la prohibición de 1966 ha permitido una lenta recuperación hasta unos 15 000 ejemplares."]},
  'ocean5':{fr:["Sa langue pèse autant qu'un éléphant et son cœur est de la taille d'une voiture.","Elle peut consommer jusqu'à 4 tonnes de krill par jour pendant la saison d'alimentation.","Les baleines bleues communiquent par des sons à basse fréquence audibles à plus de 1 600 km."],en:["Its tongue weighs as much as an elephant and its heart is the size of a car.","It can consume up to 4 tons of krill per day during feeding season.","Blue whales communicate through low-frequency sounds audible over 1,600 km."],
    es:["El océano produce más del 50 % del oxígeno que respiramos, principalmente a través del fitoplancton — organismos microscópicos que también absorben enormes cantidades de CO₂.","Los océanos han absorbido el 30 % del CO₂ emitido por la humanidad, lo que provoca su acidificación — el pH del agua ha bajado un 30 % desde la era preindustrial.","La acidificación dificulta la formación de conchas y esqueletos calcáreos, amenazando a corales, moluscos y plancton — organismos que forman la base de la cadena alimentaria marina."]},
  'ocean6':{fr:["Le Titanic reste l'épave la plus célèbre, reposant à 3 800 mètres de profondeur depuis 1912.","Les bactéries mangent lentement le Titanic — il pourrait avoir complètement disparu d'ici 2030.","Certaines épaves contiennent des trésors estimés à des milliards — comme le San José colombien, coulé en 1708."],en:["The Titanic remains the most famous wreck, resting at 3,800 meters since 1912.","Bacteria are slowly eating the Titanic — it could completely vanish by 2030.","Some wrecks contain treasures worth billions — like Colombia's San José, sunk in 1708."],
    es:["Los pulpos tienen tres corazones, sangre azul (basada en cobre, no en hierro), nueve cerebros (un central y uno en cada tentáculo) y pueden cambiar de color en milisegundos.","Son los invertebrados más inteligentes: abren tarros, resuelven laberintos, reconocen a personas individuales y se han fugado de acuarios abriendo tapas y recorriendo pasillos.","Los pulpos tienen una vida trágicamente corta (1-5 años): la hembra muere tras cuidar sus huevos durante semanas sin comer, y el macho muere poco después del apareamiento."]},
  'ocean7':{fr:["Les récifs coralliens ne couvrent que 0,1 % du fond marin mais abritent 25 % de toutes les espèces marines.","Le corail blanchit quand il est stressé par la chaleur — il expulse les algues symbiotiques qui lui donnent sa couleur.","Si la température des océans augmente de 2 °C, 99 % des récifs coralliens pourraient disparaître."],en:["Coral reefs cover only 0.1% of the ocean floor but shelter 25% of all marine species.","Coral bleaches when heat-stressed — it expels the symbiotic algae that give it color.","If ocean temperatures rise 2°C, 99% of coral reefs could disappear."],
    es:["Los tiburones existen desde hace más de 400 millones de años — han sobrevivido a cinco extinciones masivas, incluyendo la que eliminó a los dinosaurios.","A pesar de su reputación, los tiburones matan menos de 10 personas al año, mientras que los humanos matamos más de 100 millones de tiburones anuales, principalmente por sus aletas.","El olfato del tiburón es extraordinario: puede detectar una gota de sangre diluida en 100 litros de agua y seguir rastros olfativos a kilómetros de distancia."]},
  'ocean8':{fr:["Le phytoplancton produit de l'oxygène par photosynthèse — exactement comme les plantes terrestres.","Si le phytoplancton disparaissait, la Terre perdrait la moitié de son oxygène en quelques décennies.","Le phytoplancton est aussi la base de toute la chaîne alimentaire marine — sans lui, les océans mourraient."],en:["Phytoplankton produces oxygen through photosynthesis — exactly like land plants.","If phytoplankton disappeared, Earth would lose half its oxygen within decades.","Phytoplankton is also the base of the entire marine food chain — without it, oceans would die."],
    es:["La isla de plástico del Pacífico (Great Pacific Garbage Patch) se extiende sobre 1,6 millones de km², tres veces la superficie de Francia.","No es una isla sólida sino una zona de alta concentración de microplásticos suspendidos en el agua — invisible desde la superficie pero devastadora para la vida marina.","Cada año, entre 8 y 12 millones de toneladas de plástico llegan al océano — al ritmo actual, habrá más plástico que peces en el mar para 2050."]},
  'ocean9':{fr:["À cette pression, un corps humain non protégé serait écrasé instantanément.","Des organismes vivent pourtant à cette profondeur — des amphipodes et des bactéries extrémophiles.","Le sous-marin de Victor Vescovo, le Limiting Factor, est le seul véhicule capable de plongées répétées à cette profondeur."],en:["At this pressure, an unprotected human body would be instantly crushed.","Organisms still live at this depth — amphipods and extremophile bacteria.","Victor Vescovo's submersible, the Limiting Factor, is the only vehicle capable of repeated dives to this depth."],
    es:["Las medusas llevan más de 600 millones de años en los océanos — son más antiguas que los dinosaurios, los tiburones e incluso que los árboles.","La medusa inmortal (Turritopsis dohrnii) puede revertir su ciclo de vida y volver al estado de pólipo juvenil cuando envejece o se estresa — teóricamente, puede vivir para siempre.","Las proliferaciones masivas de medusas están aumentando por el calentamiento oceánico, la sobrepesca de sus depredadores y la contaminación — en algunas zonas, amenazan la pesca y las centrales eléctricas."]},
  'ocean10':{fr:["Sans le Gulf Stream, le Royaume-Uni aurait un climat similaire au Labrador canadien.","Le Gulf Stream transporte 30 fois plus d'eau que tous les fleuves de la Terre combinés.","Le changement climatique pourrait affaiblir le Gulf Stream, provoquant un refroidissement paradoxal de l'Europe."],en:["Without the Gulf Stream, the UK would have a climate similar to Canadian Labrador.","The Gulf Stream carries 30 times more water than all of Earth's rivers combined.","Climate change could weaken the Gulf Stream, causing a paradoxical cooling of Europe."],
    es:["Las fuentes hidrotermales del fondo oceánico albergan ecosistemas que no dependen del sol sino de la quimiosíntesis — bacterias que convierten compuestos químicos volcánicos en energía.","Descubiertas en 1977, estas comunidades incluyen gusanos tubícolas de 2 metros, camarones ciegos y cangrejos que prosperan a 400 °C de temperatura y presiones aplastantes.","Las fuentes hidrotermales son candidatas como cuna de la vida: sus condiciones químicas podrían haber generado las primeras moléculas orgánicas hace 3 800 millones de años."]},
  'ocean11':{fr:["La bioluminescence est utilisée pour attirer des proies, communiquer et se camoufler dans les profondeurs.","Le poisson-lanterne possède des organes lumineux appelés photophores qui produisent une lumière bleue-verte.","Si on rassemblait tous les organismes bioluminescents des abysses, ils éclaireraient plus que toutes les villes du monde."],en:["Bioluminescence is used to attract prey, communicate, and camouflage in the depths.","The lanternfish has luminous organs called photophores producing blue-green light.","If all bioluminescent deep-sea organisms were gathered, they'd shine brighter than all the world's cities."],
    es:["Las mareas son causadas principalmente por la atracción gravitatoria de la Luna y, en menor medida, del Sol — la diferencia entre marea alta y baja puede superar los 16 metros en la Bahía de Fundy (Canadá).","Las mareas no son simples subidas y bajadas: generan corrientes poderosas que moldean las costas, alimentan los ecosistemas intermareales y mueven millones de toneladas de sedimentos.","La energía mareomotriz es una fuente renovable prometedora: la central de La Rance en Francia genera electricidad desde 1966 aprovechando las mareas del Canal de la Mancha."]},
  'ocean12':{fr:["Les océans contiennent environ 50 millions de milliards de tonnes de sel dissous.","La mer Morte contient 33 % de sel — 10 fois plus que l'océan — ce qui permet de flotter sans effort.","L'eau de mer contient aussi de l'or dissous — environ 20 millions de tonnes au total, mais en concentration trop faible pour être extraites."],en:["Oceans contain about 50 million billion tons of dissolved salt.","The Dead Sea contains 33% salt — 10 times more than the ocean — allowing effortless floating.","Seawater also contains dissolved gold — about 20 million tons total, but too dilute to extract."],
    es:["Los arrecifes de coral ocupan menos del 0,1 % del fondo oceánico pero albergan el 25 % de todas las especies marinas — son la selva tropical del mar.","Los corales no son plantas sino animales (pólipos) que viven en simbiosis con algas microscópicas (zooxantelas) — el coral proporciona refugio y las algas producen alimento mediante fotosíntesis.","Cuando el agua se calienta, los corales expulsan sus algas simbióticas y pierden su color (blanqueamiento) — si el estrés persiste, el coral muere."]},
  'ocean13':{fr:["La Grande Barrière mesure 2 300 km de long et couvre une surface plus grande que l'Italie.","Elle est composée de 2 900 récifs individuels et de 900 îles.","Le réchauffement climatique a provoqué 5 épisodes majeurs de blanchissement depuis 1998."],en:["The Great Barrier Reef is 2,300 km long and covers an area larger than Italy.","It consists of 2,900 individual reefs and 900 islands.","Climate change has caused 5 major bleaching events since 1998."],
    es:["Los tsunamis pueden viajar a más de 800 km/h en mar abierto (la velocidad de un avión) pero solo miden centímetros de altura — al acercarse a la costa, se ralentizan y se elevan.","El tsunami de 2004 en el océano Índico mató a más de 230 000 personas en 14 países — fue causado por un terremoto de magnitud 9,1 frente a Sumatra.","Los sistemas de alerta de tsunamis del Pacífico utilizan boyas de presión en el fondo del mar que detectan cambios de nivel oceánico y emiten alertas en minutos."]},
  'ocean14':{fr:["Un hippocampe mâle peut donner naissance à plus de 1 000 bébés en une seule portée.","Les hippocampes sont monogames — les couples se retrouvent chaque matin pour une « danse de salutation ».","Ils n'ont ni dents ni estomac — ils aspirent leur nourriture comme un aspirateur et la digèrent directement dans l'intestin."],en:["A male seahorse can give birth to over 1,000 babies in a single brood.","Seahorses are monogamous — pairs meet each morning for a 'greeting dance'.","They have no teeth or stomach — they suck in food like a vacuum and digest it directly in the intestine."],
    es:["Las ballenas jorobadas cantan las canciones más complejas del reino animal: secuencias de sonidos que duran hasta 20 minutos y se repiten durante horas.","Todas las ballenas jorobadas de una misma zona cantan la misma canción, que evoluciona gradualmente durante la temporada — una «cultura musical» que se transmite entre individuos.","Los cantos se propagan entre poblaciones a miles de kilómetros: una canción nueva puede viajar de Australia a la Polinesia Francesa en pocos años."]},
  'ocean15':{fr:["Son venin peut provoquer une douleur si intense que les victimes supplient parfois qu'on leur ampute le membre affecté.","Il n'existe aucun antivenin — le seul traitement est l'immersion du membre dans l'eau très chaude pour décomposer les toxines.","Le poisson-pierre peut survivre hors de l'eau pendant 24 heures, ce qui le rend dangereux même sur les plages."],en:["Its venom can cause pain so intense victims sometimes beg for amputation of the affected limb.","No antivenom exists — the only treatment is immersing the limb in very hot water to break down toxins.","The stonefish can survive out of water for 24 hours, making it dangerous even on beaches."],
    es:["El calamar gigante (Architeuthis dux) puede alcanzar los 13 metros de longitud y posee los ojos más grandes del reino animal: hasta 27 cm de diámetro.","Durante siglos fue considerado una leyenda (el Kraken nórdico), hasta que se filmó por primera vez un ejemplar vivo en su hábitat natural en 2004.","El calamar gigante lucha contra los cachalotes en las profundidades: las marcas de ventosas en la piel de los cachalotes atestiguan combates épicos en la oscuridad abisal."]},
  'ocean16':{fr:["Ce tapis roulant, appelé circulation thermohaline, met environ 1 000 ans pour faire un cycle complet.","Il est alimenté par les différences de température et de salinité entre les eaux polaires et tropicales.","Ce système régule le climat mondial — son ralentissement pourrait provoquer des changements climatiques dramatiques."],en:["This conveyor belt, called thermohaline circulation, takes about 1,000 years for a complete cycle.","It's driven by temperature and salinity differences between polar and tropical waters.","This system regulates global climate — its slowdown could cause dramatic climate changes."],
    es:["El Mar de los Sargazos, en el Atlántico Norte, es el único mar sin costas: delimitado por corrientes oceánicas, alberga masas flotantes de algas sargazo.","Las anguilas europeas y americanas recorren miles de kilómetros para reproducirse exclusivamente en el Mar de los Sargazos — luego mueren, y sus larvas hacen el viaje de vuelta solas.","El misterio de la reproducción de las anguilas desconcertó a los científicos durante siglos: Freud y Aristóteles intentaron encontrar sus órganos reproductores sin éxito."]},
  'ocean17':{fr:["Le cœlacanthe a été redécouvert en 1938 au large de l'Afrique du Sud par une conservatrice de musée, Marjorie Courtenay-Latimer.","Il vit à des profondeurs de 150 à 700 mètres et peut atteindre 2 mètres de long.","Ses nageoires lobées bougent de manière alternée, comme les pattes d'un animal terrestre — un lien avec l'évolution des tétrapodes."],en:["The coelacanth was rediscovered in 1938 off South Africa by museum curator Marjorie Courtenay-Latimer.","It lives at depths of 150 to 700 meters and can reach 2 meters long.","Its lobed fins move alternately, like a land animal's legs — a link to tetrapod evolution."],
    es:["Los manglares son bosques costeros tropicales que actúan como guarderías de peces, barreras contra tormentas y sumideros de carbono extraordinarios.","Un manglar puede almacenar hasta 10 veces más carbono que un bosque terrestre de la misma superficie — su destrucción libera enormes cantidades de CO₂.","Se ha perdido más del 35 % de los manglares del mundo en los últimos 50 años debido a la acuicultura, el desarrollo costero y la contaminación."]},
  'ocean18':{fr:["Les vagues les plus hautes jamais enregistrées atteignaient 29 mètres — la taille d'un immeuble de 10 étages.","Les tsunamis se déplacent à plus de 800 km/h en pleine mer — aussi vite qu'un avion de ligne.","En pleine mer, un tsunami ne mesure que quelques centimètres de haut — il ne devient destructeur qu'en approchant des côtes."],en:["The highest waves ever recorded reached 29 meters — the height of a 10-story building.","Tsunamis travel over 800 km/h in the open ocean — as fast as a commercial airplane.","In open sea, a tsunami is only a few centimeters high — it only becomes destructive approaching shores."],
    es:["El pez payaso y la anémona de mar tienen una de las relaciones simbióticas más conocidas del océano: el pez limpia los parásitos de la anémona y ella lo protege con sus tentáculos urticantes.","Los peces payaso son inmunes al veneno de su anémona gracias a una capa de moco especial — cada especie de pez payaso se asocia con especies específicas de anémona.","Todos los peces payaso nacen machos y el individuo dominante del grupo se transforma en hembra — Nemo habría tenido una historia muy diferente si Pixar hubiera seguido la biología real."]},
  'ocean19':{fr:["Les tortues utilisent le champ magnétique terrestre comme un GPS naturel pour retrouver leur plage de naissance.","Une tortue caouanne a parcouru 14 500 km entre le Japon et le Mexique — le plus long trajet enregistré.","Seul 1 bébé tortue sur 1 000 atteint l'âge adulte — les prédateurs, la pollution et le braconnage sont les principales menaces."],en:["Turtles use Earth's magnetic field as natural GPS to find their birth beach.","A loggerhead turtle traveled 14,500 km between Japan and Mexico — the longest recorded journey.","Only 1 in 1,000 baby turtles reaches adulthood — predators, pollution, and poaching are the main threats."],
    es:["La bioluminiscencia marina es producida por miles de especies: medusas, peces abisales, calamares, dinoflagelados y bacterias que generan luz mediante reacciones químicas.","En las profundidades donde no llega la luz solar (más del 90 % del volumen oceánico), la bioluminiscencia es la forma de comunicación dominante: atraer presas, confundir depredadores y encontrar pareja.","Las bahías bioluminiscentes (como Mosquito Bay en Puerto Rico) brillan con un resplandor azul-verde cuando se agita el agua — un espectáculo creado por millones de dinoflagelados."]},
  'ocean20':{fr:["Le point Nemo est si isolé que les astronautes de l'ISS sont souvent les humains les plus proches quand ils passent au-dessus.","C'est aussi le « cimetière des vaisseaux spatiaux » — plus de 260 engins désorbités y ont été dirigés.","La station Mir, le cargo Progress et des restes de la station Skylab reposent dans cette zone."],en:["Point Nemo is so isolated that ISS astronauts are often the closest humans when passing overhead.","It's also the 'spacecraft cemetery' — over 260 deorbited craft have been directed there.","The Mir station, Progress cargo ships, and Skylab remains rest in this area."],
    es:["Las tortugas marinas existen desde hace 100 millones de años y navegan miles de kilómetros usando el campo magnético terrestre como GPS biológico.","Las hembras vuelven a la playa exacta donde nacieron para poner sus huevos, décadas después — un sistema de orientación que la ciencia aún no comprende del todo.","La temperatura del nido determina el sexo de las crías: más calor produce más hembras — el calentamiento global podría crear poblaciones con un desequilibrio sexual fatal."]},
  // === PSYCHOLOGY ===
  'psy1':{fr:["Inversement, les experts sous-estiment souvent leurs compétences — ils supposent que ce qui est facile pour eux l'est aussi pour les autres.","L'effet porte le nom de David Dunning et Justin Kruger qui l'ont démontré en 1999 à Cornell University.","Le meilleur remède est la métacognition — apprendre à évaluer objectivement ses propres compétences."],en:["Conversely, experts often underestimate their skills — assuming what's easy for them is easy for others.","The effect is named after David Dunning and Justin Kruger who demonstrated it in 1999 at Cornell.","The best remedy is metacognition — learning to objectively evaluate your own skills."],
    es:["El efecto Dunning-Kruger describe cómo las personas con menos competencia en un tema tienden a sobreestimar sus habilidades, mientras que los expertos tienden a subestimarlas.","Este sesgo no es simple arrogancia: la incompetencia impide reconocer la propia incompetencia — se necesita cierto nivel de conocimiento para evaluar lo que no se sabe.","El efecto tiene implicaciones profundas en la política, la medicina y las redes sociales, donde las opiniones más seguras suelen ser las menos informadas."]},
  'psy2':{fr:["Ce nombre magique de 7 (±2) a été identifié par George Miller en 1956 dans une étude devenue célèbre.","En France, les numéros courants ont 10 chiffres et se lisent souvent par groupes de 2 ; ailleurs, le découpage varie, mais l'idée reste de créer des blocs faciles à retenir.","Les experts contournent cette limite en regroupant les informations en « chunks » — des blocs significatifs."],en:["This magic number 7 (±2) was identified by George Miller in 1956 in a landmark study.","In France, common phone numbers have 10 digits and are often read in 2-digit groups; formats vary by country, but chunking makes them easier to remember.","Experts bypass this limit by grouping information into 'chunks' — meaningful blocks."],
    es:["El efecto placebo demuestra que el simple hecho de creer que un tratamiento funciona puede producir mejoras reales y medibles en la salud.","Estudios muestran que placebos más caros funcionan mejor que los baratos, las inyecciones placebo superan a las pastillas placebo, y los placebos de color funcionan diferente según la cultura.","Aún más sorprendente: el efecto placebo funciona incluso cuando el paciente sabe que está tomando un placebo — el ritual del tratamiento en sí tiene poder terapéutico."]},
  'psy3':{fr:["Les participants croyaient administrer des chocs électriques à un acteur — les cris étaient préenregistrés.","L'expérience montre que la soumission à l'autorité peut faire commettre des actes cruels à des gens ordinaires.","Milgram a mené cette recherche pour comprendre comment des citoyens ordinaires avaient participé à la Shoah."],en:["Participants believed they were shocking an actor — the screams were pre-recorded.","The experiment shows authority submission can make ordinary people commit cruel acts.","Milgram conducted this research to understand how ordinary citizens participated in the Holocaust."],
    es:["El sesgo de confirmación nos lleva a buscar, interpretar y recordar selectivamente la información que confirma nuestras creencias preexistentes.","Este sesgo es tan poderoso que personas con opiniones opuestas pueden leer el mismo estudio y sentir que ambas posiciones han sido confirmadas.","Las redes sociales amplifican el sesgo de confirmación creando burbujas de filtro: los algoritmos muestran contenido que refuerza nuestras creencias, aislándonos de perspectivas diferentes."]},
  'psy4':{fr:["Ce biais affecte tout le monde — même les scientifiques qui en sont conscients ont du mal à l'éviter.","Les réseaux sociaux amplifient ce biais en créant des « bulles de filtre » qui ne montrent que du contenu aligné avec nos opinions.","Se forcer à chercher des arguments contre sa propre position est l'un des meilleurs exercices pour contrer ce biais."],en:["This bias affects everyone — even scientists aware of it struggle to avoid it.","Social media amplifies this bias by creating 'filter bubbles' showing only opinion-aligned content.","Forcing yourself to seek arguments against your own position is one of the best exercises to counter it."],
    es:["La disonancia cognitiva, teorizada por Leon Festinger en 1957, es la incomodidad que sentimos cuando nuestras creencias contradicen nuestras acciones.","Para reducir esta tensión, tendemos a cambiar nuestras creencias en lugar de nuestras acciones — por ejemplo, un fumador que minimiza los riesgos del tabaco en lugar de dejar de fumar.","Festinger descubrió este fenómeno infiltrándose en una secta que predijo el fin del mundo: cuando la profecía falló, los miembros reforzaron su fe en lugar de abandonarla."]},
  'psy5':{fr:["Cet effet a été découvert par Robert Zajonc en 1968 — il l'a appelé l'effet de simple exposition.","C'est pourquoi les publicitaires répètent les mêmes messages — la familiarité crée une préférence inconsciente.","L'effet fonctionne même pour des stimuli présentés de manière subliminale — en dessous du seuil de conscience."],en:["This effect was discovered by Robert Zajonc in 1968 — he called it the mere exposure effect.","That's why advertisers repeat the same messages — familiarity creates unconscious preference.","The effect works even for stimuli presented subliminally — below the threshold of consciousness."],
    es:["El experimento de Milgram (1961) demostró que personas comunes podían administrar lo que creían eran descargas eléctricas letales simplemente porque una autoridad se lo ordenaba.","El 65 % de los participantes aplicaron la descarga máxima (450 voltios) a un actor que gritaba de dolor — un resultado que conmocionó al mundo y planteó preguntas sobre la obediencia ciega.","Milgram diseñó el experimento para entender cómo ciudadanos normales participaron en el Holocausto — demostró que la obediencia a la autoridad es un comportamiento humano universal, no una anomalía."]},
  'psy6':{fr:["Bertram Forer a démontré cet effet en 1948 en donnant le même profil de personnalité à tous ses étudiants — 85 % l'ont trouvé précis.","Les voyants, médiums et tests de personnalité en ligne exploitent souvent cet effet.","Les descriptions Barnum fonctionnent car elles sont suffisamment vagues pour que chacun y projette sa propre réalité."],en:["Bertram Forer demonstrated this in 1948 by giving all students the same personality profile — 85% found it accurate.","Psychics, mediums, and online personality tests often exploit this effect.","Barnum statements work because they're vague enough for everyone to project their own reality onto them."],
    es:["La pirámide de Maslow (1943) organiza las necesidades humanas en cinco niveles: fisiológicas, seguridad, pertenencia, estima y autorrealización.","La idea es que no se pueden satisfacer las necesidades superiores sin cubrir las inferiores — pero la vida real muestra excepciones: artistas que crean en la pobreza o activistas que arriesgan su seguridad por ideales.","Maslow reconoció las limitaciones de su modelo hacia el final de su vida y propuso un sexto nivel: la autotrascendencia, donde el individuo se dedica a algo más grande que sí mismo."]},
  'psy7':{fr:["Cette théorie s'appelle l'hypothèse du feedback facial — elle suggère que nos expressions influencent nos émotions.","Des études récentes ont nuancé ces résultats — l'effet existe mais est plus faible qu'on ne le pensait.","Le rire provoqué, même forcé, libère quand même des endorphines — c'est le principe du yoga du rire."],en:["This theory is called the facial feedback hypothesis — suggesting our expressions influence our emotions.","Recent studies have nuanced these results — the effect exists but is weaker than thought.","Forced laughter still releases endorphins — that's the principle behind laughter yoga."],
    es:["El efecto espectador describe cómo la probabilidad de que alguien ayude en una emergencia disminuye cuando hay más personas presentes.","El caso de Kitty Genovese (1964), supuestamente ignorada por 38 vecinos mientras era asesinada, popularizó el concepto — aunque investigaciones posteriores revelaron que la historia fue exagerada por la prensa.","La difusión de responsabilidad explica el fenómeno: cada persona asume que otro actuará, lo que resulta en que nadie lo hace — un sesgo social con consecuencias a veces fatales."]},
  'psy8':{fr:["L'expérience a dû être arrêtée après 6 jours au lieu des 14 prévus à cause de la brutalité des « gardiens ».","Les résultats sont controversés — certains critiques accusent Zimbardo d'avoir influencé le comportement des participants.","L'expérience a profondément changé notre compréhension de la dynamique du pouvoir et de l'obéissance."],en:["The experiment was stopped after 6 days instead of 14 due to the 'guards'' brutality.","Results are controversial — critics accuse Zimbardo of influencing participant behavior.","The experiment profoundly changed our understanding of power dynamics and obedience."],
    es:["La memoria humana no funciona como una grabación fiel: cada vez que recordamos algo, reconstruimos el recuerdo, lo que puede introducir distorsiones y falsos recuerdos.","Elizabeth Loftus demostró que es posible implantar recuerdos falsos con simples sugerencias — sus investigaciones transformaron el sistema judicial al cuestionar la fiabilidad de los testimonios.","Los flashbulb memories (recuerdos vívidos de eventos impactantes) parecen perfectos pero son igual de susceptibles a la distorsión — creemos recordar exactamente, pero los detalles cambian con el tiempo."]},
  'psy9':{fr:["Barry Schwartz a montré que plus de choix mène à plus d'anxiété et moins de satisfaction.","Les supermarchés exploitent ce paradoxe — réduire les options d'un produit augmente souvent les ventes.","La solution est la « satisfaction suffisante » — choisir la première option acceptable plutôt que chercher la meilleure."],en:["Barry Schwartz showed that more choice leads to more anxiety and less satisfaction.","Supermarkets exploit this paradox — reducing product options often increases sales.","The solution is 'satisficing' — choosing the first acceptable option rather than seeking the best."],
    es:["El condicionamiento clásico fue descubierto por Pavlov a principios del siglo XX al observar que sus perros salivaban al oír una campana que habían asociado con la comida.","Este mecanismo explica muchas respuestas emocionales automáticas: el miedo a un sonido, la nostalgia de una canción o las náuseas provocadas por un olor asociado a una mala experiencia.","La publicidad explota masivamente el condicionamiento clásico: asociar un producto con emociones positivas (música, paisajes, personas atractivas) para crear una respuesta de deseo automática."]},
  'psy10':{fr:["L'effet de halo explique pourquoi les personnes attirantes reçoivent des peines de prison plus légères en moyenne.","Les marques de luxe exploitent cet effet — un seul produit de qualité améliore la perception de toute la gamme.","L'inverse existe aussi : l'effet de corne fait qu'un seul trait négatif influence négativement notre jugement global."],en:["The halo effect explains why attractive people receive lighter prison sentences on average.","Luxury brands exploit this — one quality product improves perception of the entire range.","The reverse exists too: the horn effect makes one negative trait negatively influence our overall judgment."],
    es:["La inteligencia emocional (IE), popularizada por Daniel Goleman en 1995, incluye la autoconciencia, la autorregulación, la empatía, la motivación y las habilidades sociales.","Estudios sugieren que la IE puede predecir el éxito profesional y personal mejor que el cociente intelectual (CI), especialmente en roles de liderazgo y trabajo en equipo.","La IE no es innata sino que puede desarrollarse: la meditación, la terapia y la práctica consciente de la empatía mejoran significativamente la regulación emocional."]},
  'psy11':{fr:["Le sommeil consolide les souvenirs en les transférant de la mémoire à court terme (hippocampe) vers la mémoire à long terme (cortex).","Les rêves joueraient un rôle dans ce processus — ils « rejouent » les informations de la journée.","La privation de sommeil réduit la capacité de mémorisation de 40 % — dormir est littéralement apprendre."],en:["Sleep consolidates memories by transferring them from short-term (hippocampus) to long-term memory (cortex).","Dreams may play a role — they 'replay' the day's information.","Sleep deprivation reduces memorization capacity by 40% — sleeping is literally learning."],
    es:["El síndrome del impostor afecta a un 70 % de las personas en algún momento de su vida: la sensación de no merecer su éxito y el miedo a ser «desenmascarado» como fraude.","Fue descrito por primera vez en 1978 por las psicólogas Pauline Clance e Iman Ames al estudiar a mujeres exitosas que atribuían sus logros a la suerte.","Paradójicamente, el síndrome del impostor es más común entre personas altamente competentes — los menos capaces rara vez lo experimentan (véase el efecto Dunning-Kruger)."]},
  'psy12':{fr:["Le FOMO touche particulièrement les 18-35 ans et est fortement lié à l'utilisation des réseaux sociaux.","Des études montrent que 56 % des utilisateurs de réseaux sociaux ressentent du FOMO régulièrement.","La pratique du JOMO (Joy of Missing Out) — le plaisir de ne pas participer — est une réponse consciente au FOMO."],en:["FOMO particularly affects 18-35 year olds and is strongly linked to social media use.","Studies show 56% of social media users regularly experience FOMO.","JOMO (Joy of Missing Out) — the pleasure of not participating — is a conscious response to FOMO."],
    es:["La teoría del apego de John Bowlby establece que la calidad del vínculo entre un bebé y su cuidador principal moldea las relaciones afectivas durante toda la vida adulta.","Mary Ainsworth identificó tres estilos de apego: seguro (66 %), ansioso-ambivalente (20 %) e inseguro-evitativo (14 %) — un cuarto estilo, desorganizado, fue añadido posteriormente.","El apego seguro en la infancia se asocia con mayor autoestima, relaciones más estables y mejor regulación emocional en la edad adulta — pero los estilos inseguros pueden modificarse con terapia."]},
  'psy13':{fr:["Bluma Zeigarnik a découvert cet effet en observant des serveurs qui se souvenaient mieux des commandes non livrées.","C'est pourquoi les cliffhangers dans les séries TV sont si efficaces — notre cerveau veut absolument la suite.","Les to-do lists exploitent cet effet — écrire une tâche réduit l'anxiété même si on ne la fait pas immédiatement."],en:["Bluma Zeigarnik discovered this by observing waiters who remembered undelivered orders better.","That's why TV cliffhangers are so effective — our brain desperately wants the continuation.","To-do lists exploit this — writing a task reduces anxiety even if you don't do it immediately."],
    es:["La psicología positiva, fundada por Martin Seligman en 1998, estudia lo que hace florecer a las personas en lugar de centrarse solo en la patología.","El modelo PERMA de Seligman identifica cinco pilares del bienestar: emociones Positivas, Engagement (compromiso), Relaciones, Meaning (sentido) y Achievement (logro).","La gratitud, la meditación mindfulness y los actos de bondad son intervenciones de psicología positiva con eficacia demostrada para aumentar el bienestar subjetivo."]},
  'psy14':{fr:["L'étude de John Bargh en 2008 a montré que tenir une tasse chaude influence positivement notre jugement sur les autres.","Inversement, tenir un objet froid rend notre jugement plus distant et critique.","Ce phénomène s'appelle la cognition incarnée — notre corps influence nos pensées sans qu'on en soit conscient."],en:["John Bargh's 2008 study showed holding a warm cup positively influences our judgment of others.","Conversely, holding a cold object makes our judgment more distant and critical.","This phenomenon is called embodied cognition — our body influences thoughts without our awareness."],
    es:["La procrastinación no es pereza sino un problema de regulación emocional: evitamos tareas que generan emociones negativas (ansiedad, aburrimiento, frustración).","El cerebro prefiere la gratificación inmediata (scrollear el móvil) a la recompensa diferida (terminar un proyecto) — un sesgo evolutivo que era útil para la supervivencia pero contraproducente hoy.","Las técnicas más eficaces contra la procrastinación incluyen la regla de los 2 minutos, la técnica Pomodoro y la autocompasión — castigarse por procrastinar solo empeora el ciclo."]},
  'psy15':{fr:["Environ 4 % de la population est synesthète — la plupart l'ignorent car c'est leur perception normale depuis la naissance.","La forme la plus courante est la graphème-couleur : chaque lettre ou chiffre a une couleur spécifique.","Kandinsky et Nabokov étaient synesthètes — cette condition a profondément influencé leur art et leur écriture."],en:["About 4% of the population is synesthetic — most don't know as it's been their normal perception since birth.","The most common form is grapheme-color: each letter or number has a specific color.","Kandinsky and Nabokov were synesthetes — the condition deeply influenced their art and writing."],
    es:["Los sueños lúcidos son aquellos en los que el soñador es consciente de estar soñando y puede influir en el desarrollo del sueño.","Estudios con resonancia magnética han confirmado que los sueños lúcidos son un estado real de conciencia, diferente tanto del sueño normal como de la vigilia.","Técnicas como la verificación de realidad, el diario de sueños y la meditación MILD pueden aumentar la frecuencia de sueños lúcidos — un campo en expansión en la neurociencia."]},
  'psy16':{fr:["Les chercheurs de Harvard ont montré que les gens surévaluent un meuble IKEA de 63 % par rapport à un meuble identique monté par un professionnel.","Cet effet explique aussi pourquoi les kits de cuisine Betty Crocker ont été un succès — en ajoutant un œuf, les cuisiniers sentaient qu'ils « faisaient » le gâteau.","L'effet Ikea s'applique aussi aux idées — on valorise davantage nos propres solutions que celles des autres."],en:["Harvard researchers showed people overvalue IKEA furniture by 63% compared to identical professionally assembled furniture.","This also explains why Betty Crocker cake mixes succeeded — adding an egg made cooks feel they 'made' the cake.","The IKEA effect also applies to ideas — we value our own solutions more than others'."],
    es:["El efecto halo hace que una impresión positiva en un aspecto (atractivo físico, por ejemplo) influya en la evaluación de otros aspectos no relacionados (inteligencia, honestidad).","Estudios muestran que las personas atractivas reciben sentencias judiciales más leves, mejores notas y más ofertas de empleo — un sesgo inconsciente con consecuencias reales.","El efecto inverso también existe: el efecto «cuernos» (horn effect) hace que un rasgo negativo contamine la percepción global de una persona."]},
  'psy17':{fr:["Ce phénomène augmente avec l'âge et la fatigue — il est plus fréquent pour les noms propres que pour les noms communs.","Le mot est souvent « bloqué » par un mot similaire mais incorrect qui occupe sa place dans la mémoire.","Le multilinguisme augmente la fréquence de ce phénomène — plus on connaît de mots, plus les interférences sont possibles."],en:["This phenomenon increases with age and fatigue — more common for proper nouns than common ones.","The word is often 'blocked' by a similar but incorrect word occupying its place in memory.","Multilingualism increases this phenomenon — the more words you know, the more interference is possible."],
    es:["La terapia cognitivo-conductual (TCC) es la psicoterapia con más evidencia científica: parte del principio de que los pensamientos distorsionados generan emociones negativas y conductas disfuncionales.","La TCC enseña a identificar y cuestionar pensamientos automáticos negativos para reemplazarlos por interpretaciones más realistas y adaptativas.","Es eficaz para la depresión, la ansiedad, el TOC, las fobias, el TEPT y muchos otros trastornos — y sus beneficios se mantienen a largo plazo, a diferencia de algunos tratamientos farmacológicos."]},
  'psy18':{fr:["Thomas Gilovich a nommé ce phénomène en 2000 — les gens pensent être observés bien plus qu'ils ne le sont réellement.","Dans une expérience, des étudiants portant un T-shirt embarrassant pensaient que 50 % des gens l'avaient remarqué — en réalité, seulement 23 %.","Comprendre cet effet libère : les gens sont bien trop occupés par leurs propres insécurités pour scruter les vôtres."],en:["Thomas Gilovich named this in 2000 — people think they're observed far more than they actually are.","In an experiment, students wearing an embarrassing T-shirt thought 50% noticed — actually only 23%.","Understanding this is freeing: people are too busy with their own insecurities to scrutinize yours."],
    es:["La neuroplasticidad es la capacidad del cerebro para reorganizar sus conexiones neuronales a lo largo de toda la vida — no solo en la infancia como se creía antes.","Aprender un idioma, tocar un instrumento o meditar regularmente puede cambiar físicamente la estructura del cerebro, aumentando la densidad de materia gris en las áreas involucradas.","La neuroplasticidad ofrece esperanza para la rehabilitación tras lesiones cerebrales: zonas sanas pueden aprender a asumir funciones de zonas dañadas, aunque el proceso es lento y exigente."]},
  'psy19':{fr:["La dopamine est libérée non seulement en écoutant la musique mais aussi en anticipant le moment fort d'un morceau.","Les frissons musicaux (appelés « chills ») activent les mêmes circuits de récompense que la nourriture et les substances addictives.","La musique peut réduire le cortisol (hormone du stress) de 25 % et augmenter les immunoglobulines de 15 %."],en:["Dopamine is released not just when listening but also anticipating a song's peak moment.","Musical chills activate the same reward circuits as food and addictive substances.","Music can reduce cortisol (stress hormone) by 25% and increase immunoglobulins by 15%."],
    es:["El efecto ancla hace que la primera información que recibimos sobre un tema influya desproporcionadamente en nuestros juicios posteriores.","En una negociación, quien hace la primera oferta establece el ancla: todas las contraofertas se moverán en torno a ese punto de referencia inicial.","Los precios «antes/después» en las rebajas explotan el efecto ancla: el precio original (aunque sea ficticio) hace que el descuento parezca mayor de lo que realmente es."]},
  'psy20':{fr:["Dans les négociations, la première offre sert d'ancre — même si elle est absurde, elle influence le résultat final.","Les prix « avant/après » en magasin exploitent cet effet — le prix barré sert d'ancre pour faire paraître le nouveau prix attractif.","Kahneman et Tversky ont démontré en 1974 que même un nombre aléatoire peut servir d'ancre et biaiser nos estimations."],en:["In negotiations, the first offer serves as anchor — even if absurd, it influences the final outcome.","'Before/after' prices in stores exploit this — the crossed-out price anchors to make the new price look attractive.","Kahneman and Tversky showed in 1974 that even a random number can serve as anchor and bias our estimates."],
    es:["Sigmund Freud, padre del psicoanálisis, propuso que el inconsciente, los sueños y las experiencias infantiles moldean la personalidad adulta.","Muchas de sus teorías específicas (complejo de Edipo, envidia del pene, interpretación de los sueños) han sido cuestionadas o refutadas por la psicología moderna.","Sin embargo, la idea central de Freud — que tenemos procesos mentales inconscientes que influyen en nuestro comportamiento — está ampliamente respaldada por la neurociencia contemporánea."]},
  // === QUOTES ===
  'quote1':{fr:["Cette citation est souvent attribuée à Einstein, mais aucune preuve ne confirme qu'il l'ait jamais dite.","Elle est apparue pour la première fois dans un roman de 1983 — bien après la mort d'Einstein en 1955.","La véritable folie, selon les psychologues, s'appelle la persévérance dysfonctionnelle."],en:["This quote is often attributed to Einstein, but no evidence confirms he ever said it.","It first appeared in a 1983 novel — well after Einstein's death in 1955.","True madness, according to psychologists, is called dysfunctional perseverance."],
    es:["«Solo sé que no sé nada» es la frase más famosa de Sócrates, aunque probablemente nunca la dijo exactamente así — es una interpretación de Platón en la Apología.","La paradoja socrática plantea que la verdadera sabiduría comienza con el reconocimiento de la propia ignorancia — un principio fundacional de la filosofía occidental.","Sócrates no dejó escritos: todo lo que sabemos de él proviene de sus discípulos, principalmente Platón y Jenofonte, que pudieron idealizar o distorsionar su pensamiento."]},
  'quote2':{fr:["Einstein a publié sa théorie de la relativité restreinte en 1905, alors qu'il travaillait comme simple employé de bureau.","Il a reçu le prix Nobel de physique en 1921, non pas pour la relativité, mais pour l'effet photoélectrique.","Son cerveau a été conservé après sa mort en 1955 — les scientifiques l'ont étudié et ont trouvé des régions inhabituellement développées."],en:["Einstein published his special relativity theory in 1905 while working as a simple office clerk.","He received the 1921 Nobel Prize in Physics, not for relativity, but for the photoelectric effect.","His brain was preserved after his 1955 death — scientists studied it and found unusually developed regions."],
    es:["«Pienso, luego existo» (Cogito, ergo sum) de Descartes (1637) es el punto de partida de la filosofía moderna: la única certeza que resiste la duda total.","Descartes llegó a esta conclusión tras dudar de todo: los sentidos, las matemáticas, la realidad misma — pero no podía dudar de que estaba dudando, lo que probaba su existencia.","Esta frase marcó el giro subjetivo de la filosofía: del mundo exterior al mundo interior, de la metafísica a la epistemología — un cambio que sigue definiendo el pensamiento occidental."]},
  'quote3':{fr:["Churchill a prononcé le célèbre discours « We shall fight on the beaches » en juin 1940 pour galvaniser la résistance britannique.","Il a reçu le prix Nobel de littérature en 1953 — pas de la paix, mais bien de littérature, pour ses mémoires de guerre.","Sa consommation quotidienne incluait du champagne au déjeuner et du whisky le soir — un régime qu'il a maintenu jusqu'à 90 ans."],en:["Churchill delivered the famous 'We shall fight on the beaches' speech in June 1940 to galvanize British resistance.","He received the 1953 Nobel Prize in Literature — not Peace, but Literature, for his war memoirs.","His daily consumption included champagne at lunch and whisky at night — a regime he maintained until age 90."],
    es:["«El fin justifica los medios» se atribuye a Maquiavelo, pero nunca escribió esa frase exacta — es una simplificación de El Príncipe (1513).","Maquiavelo argumentaba que un gobernante debe ser pragmático y estar dispuesto a actuar sin escrúpulos morales para mantener el Estado — un realismo político revolucionario para su época.","El Príncipe fue escrito como manual para Lorenzo de Médicis, pero su legado va mucho más allá: fundó la ciencia política moderna al separar la moral de la política."]},
  'quote4':{fr:["Descartes a écrit le Discours de la méthode en 1637, posant les bases du rationalisme moderne.","Il est aussi l'inventeur du système de coordonnées cartésiennes — la base de la géométrie analytique.","Descartes est mort en 1650 à Stockholm d'une pneumonie, contractée en donnant des cours de philosophie à la reine de Suède à 5h du matin."],en:["Descartes wrote Discourse on the Method in 1637, laying the foundations of modern rationalism.","He also invented the Cartesian coordinate system — the basis of analytical geometry.","Descartes died in 1650 in Stockholm of pneumonia, caught giving philosophy lessons to Sweden's queen at 5 AM."],
    es:["«Ser o no ser, esa es la cuestión» es el monólogo más famoso de la literatura universal, pronunciado por Hamlet en la obra de Shakespeare (1600).","Hamlet reflexiona sobre el suicidio y el sentido de la existencia: ¿es mejor sufrir los males de la vida o acabar con ellos mediante la muerte?","El monólogo ha sido interpretado de mil maneras: como reflexión filosófica, como cobardía disfrazada de profundidad, como crisis existencial moderna — su ambigüedad es su grandeza."]},
  'quote5':{fr:["Mandela a passé 27 ans en prison — 18 ans sur l'île de Robben Island — avant de devenir président de l'Afrique du Sud.","Pendant son emprisonnement, il a secrètement écrit son autobiographie, Un long chemin vers la liberté.","Il a partagé le prix Nobel de la paix 1993 avec Frederik de Klerk, le président qui a aboli l'apartheid."],en:["Mandela spent 27 years in prison — 18 on Robben Island — before becoming South Africa's president.","During imprisonment, he secretly wrote his autobiography, Long Walk to Freedom.","He shared the 1993 Nobel Peace Prize with Frederik de Klerk, the president who abolished apartheid."],
    es:["«Dios ha muerto» de Nietzsche (La gaya ciencia, 1882) no es una declaración atea sino un diagnóstico cultural: la sociedad occidental ha dejado de creer en los valores cristianos.","Para Nietzsche, la muerte de Dios no era motivo de celebración sino de angustia: sin fundamento trascendente, ¿cómo distinguir el bien del mal? ¿Cómo dar sentido a la vida?","La respuesta de Nietzsche fue el Übermensch (superhombre): un ser capaz de crear sus propios valores y vivir sin muletas metafísicas — una idea frecuentemente malinterpretada."]},
  'quote6':{fr:["Curie est la seule personne à avoir remporté le prix Nobel dans deux disciplines scientifiques différentes : physique et chimie.","Elle a découvert deux éléments : le polonium (nommé d'après sa Pologne natale) et le radium.","Elle est morte en 1934 d'une anémie aplasique causée par son exposition prolongée aux radiations."],en:["Curie is the only person to win Nobel Prizes in two different scientific disciplines: physics and chemistry.","She discovered two elements: polonium (named after her native Poland) and radium.","She died in 1934 of aplastic anemia caused by prolonged radiation exposure."],
    es:["«Eureka!» (¡Lo encontré!) fue supuestamente gritado por Arquímedes al descubrir en su bañera el principio del desplazamiento de líquidos en el siglo III a.C.","El rey Hierón le había pedido verificar si su corona era de oro puro sin dañarla — Arquímedes comprendió que podía medir el volumen sumergiendo la corona en agua.","La anécdota de Arquímedes corriendo desnudo por las calles de Siracusa es probablemente legendaria, pero el principio científico es real y sigue siendo fundamental en la física."]},
  'quote7':{fr:["La vraie citation de Gandhi est « Si nous pouvions nous changer nous-mêmes, les tendances dans le monde changeraient aussi ».","Gandhi a mené la résistance non-violente contre l'Empire britannique, aboutissant à l'indépendance de l'Inde en 1947.","Il a été assassiné en 1948, seulement un an après avoir réalisé le rêve de sa vie."],en:["Gandhi's real quote is 'If we could change ourselves, the tendencies in the world would also change'.","Gandhi led non-violent resistance against the British Empire, leading to India's independence in 1947.","He was assassinated in 1948, only one year after achieving his life's dream."],
    es:["«El Estado soy yo» (L'État, c'est moi), atribuido a Luis XIV de Francia, encarna el absolutismo monárquico — aunque los historiadores dudan de que realmente lo dijera.","Luis XIV centralizó el poder de forma sin precedentes, construyó Versalles como símbolo de su autoridad y reinó 72 años — el reinado más largo de la historia europea.","Paradójicamente, su bisnieto Luis XVI perdió la cabeza en la guillotina durante la Revolución Francesa — del poder absoluto a la ejecución pública en tres generaciones."]},
  'quote8':{fr:["Wilde a été emprisonné pendant 2 ans pour « gross indecency » — son homosexualité — ce qui a détruit sa carrière.","Pendant son séjour en prison, il a écrit De Profundis, l'une de ses œuvres les plus poignantes.","Wilde est mort à 46 ans à Paris, dans la pauvreté — ses derniers mots auraient été une remarque sur le papier peint de sa chambre."],en:["Wilde was imprisoned for 2 years for 'gross indecency' — his homosexuality — which destroyed his career.","During prison, he wrote De Profundis, one of his most poignant works.","Wilde died at 46 in Paris in poverty — his last words reportedly concerned his room's wallpaper."],
    es:["«Dadme un punto de apoyo y moveré el mundo» es atribuido a Arquímedes para ilustrar el principio de la palanca — una de las máquinas simples fundamentales de la física.","La palanca multiplica la fuerza aplicada: con una palanca suficientemente larga, una persona podría teóricamente levantar cualquier peso — el principio es real, la aplicación cósmica es metafórica.","Arquímedes fue uno de los mayores científicos de la Antigüedad: inventó la polea compuesta, el tornillo sin fin y máquinas de guerra que defendieron Siracusa contra los romanos."]},
  'quote9':{fr:["De nombreuses citations célèbres sont mal attribuées — internet amplifie ce phénomène en propageant les erreurs.","Lincoln, Marilyn Monroe et Mark Twain sont les personnages historiques les plus victimes de fausses attributions.","La règle d'or : si une citation semble trop parfaite pour être vraie, elle est probablement mal attribuée."],en:["Many famous quotes are misattributed — the internet amplifies this by spreading errors.","Lincoln, Marilyn Monroe, and Mark Twain are the historical figures most victimized by false attributions.","Golden rule: if a quote seems too perfect to be true, it's probably misattributed."],
    es:["«La imaginación es más importante que el conocimiento» de Einstein refleja su método de trabajo: los experimentos mentales (Gedankenexperiment) fueron su herramienta principal.","Einstein imaginó perseguir un rayo de luz a los 16 años — esa fantasía adolescente lo llevó a la relatividad especial una década después.","La frase subraya que el conocimiento es limitado por lo que ya sabemos, mientras que la imaginación puede explorar lo desconocido — una filosofía de la ciencia profundamente creativa."]},
  'quote10':{fr:["Le Deuxième Sexe a été mis à l'Index des livres interdits par le Vatican à sa publication.","Beauvoir et Jean-Paul Sartre ont formé l'un des couples intellectuels les plus célèbres du XXe siècle.","Elle a refusé la Légion d'honneur en 1982 par fidélité à ses convictions anticonformistes."],en:["The Second Sex was placed on the Vatican's Index of Forbidden Books upon publication.","Beauvoir and Jean-Paul Sartre formed one of the 20th century's most famous intellectual couples.","She refused the Legion of Honor in 1982, staying true to her nonconformist convictions."],
    es:["«Veni, vidi, vici» (Vine, vi, vencí) fue el mensaje que Julio César envió al Senado romano tras su rápida victoria en la batalla de Zela (47 a.C.).","La brevedad del mensaje era deliberada: César quería mostrar que la victoria había sido tan fácil que no merecía más de tres palabras.","César era un maestro de la comunicación política: sus Comentarios sobre la Guerra de las Galias son tanto obras literarias como propaganda personal brillantemente construida."]},
  'quote11':{fr:["Archimède a découvert le principe de la poussée (poussée d'Archimède) en remarquant que l'eau montait quand il entrait dans son bain.","Le roi Hiéron II lui avait demandé de vérifier si sa couronne était en or pur sans la détruire.","Archimède est aussi l'inventeur de la vis d'Archimède, encore utilisée aujourd'hui pour pomper l'eau."],en:["Archimedes discovered the buoyancy principle by noticing water rose when he got into his bath.","King Hiero II had asked him to verify if his crown was pure gold without destroying it.","Archimedes also invented the Archimedes screw, still used today for pumping water."],
    es:["«Que coman pasteles» (Qu'ils mangent de la brioche), atribuido a María Antonieta, nunca fue dicho por ella — la anécdota aparece en Rousseau antes de que María Antonieta llegara a Francia.","La frase simboliza la desconexión de la aristocracia con el sufrimiento del pueblo — un tópico que alimentó la propaganda revolucionaria.","María Antonieta fue ejecutada en 1793 a los 37 años — su imagen de reina frívola y derrochadora ha sido parcialmente rehabilitada por los historiadores modernos."]},
  'quote12':{fr:["Twain a aussi dit « Les rumeurs de ma mort sont grandement exagérées » — en réponse à un journal qui avait publié son obituaire par erreur.","Il a prédit qu'il mourrait au passage de la comète de Halley — et c'est exactement ce qui s'est passé en 1910.","Twain est considéré comme le père de la littérature américaine — Hemingway a dit que tout venait de lui."],en:["Twain also said 'Reports of my death are greatly exaggerated' — responding to a newspaper that mistakenly published his obituary.","He predicted he'd die when Halley's Comet passed — and that's exactly what happened in 1910.","Twain is considered the father of American literature — Hemingway said everything came from him."],
    es:["«El conocimiento es poder» (Scientia potentia est) se atribuye a Francis Bacon (1597), quien argumentaba que el saber empírico permitía dominar la naturaleza.","Bacon fue el padre del método científico moderno: observación, hipótesis, experimentación y verificación — un proceso que revolucionó la manera de conocer el mundo.","La frase adquiere un significado nuevo en la era digital: los datos son el nuevo poder, y quien controla la información controla la sociedad."]},
  'quote13':{fr:["Le discours de Stanford en 2005 contenait trois histoires personnelles sur la connexion des points, l'amour et la mort.","Il avait été adopté et ses parents biologiques avaient exigé qu'il soit élevé par des diplômés universitaires — ce qui n'a pas été le cas.","Apple a été fondé dans un garage en 1976 avec Steve Wozniak et un budget de 1 300 dollars."],en:["The 2005 Stanford speech contained three personal stories about connecting dots, love, and death.","He was adopted and his biological parents demanded he be raised by college graduates — which didn't happen.","Apple was founded in a garage in 1976 with Steve Wozniak and a $1,300 budget."],
    es:["«Un pequeño paso para el hombre, un gran salto para la humanidad» fue dicho por Neil Armstrong al pisar la Luna el 20 de julio de 1969.","Armstrong afirmó haber dicho «un pequeño paso para un hombre» (a man), pero la grabación es ambigua — la partícula «a» se perdió en la transmisión o nunca fue pronunciada.","La frase fue preparada de antemano por Armstrong, quien la mantuvo en secreto incluso de la NASA — un momento de elocuencia personal en el mayor evento tecnológico de la historia."]},
  'quote14':{fr:["Voltaire a écrit plus de 20 000 lettres et 2 000 livres — l'un des auteurs les plus prolifiques de l'histoire.","Il a été emprisonné deux fois à la Bastille et exilé en Angleterre — ses idées étaient jugées dangereuses par le pouvoir.","Malgré sa consommation excessive de café, il a vécu jusqu'à 83 ans — une longévité remarquable pour le XVIIIe siècle."],en:["Voltaire wrote over 20,000 letters and 2,000 books — one of history's most prolific authors.","He was imprisoned twice in the Bastille and exiled to England — his ideas deemed dangerous by authorities.","Despite excessive coffee consumption, he lived to 83 — remarkable longevity for the 18th century."],
    es:["«La única cosa que debemos temer es el miedo mismo» fue dicho por Franklin D. Roosevelt en su discurso inaugural de 1933, en plena Gran Depresión.","Roosevelt buscaba restaurar la confianza de una nación paralizada por el pánico bancario: el miedo colectivo era tan destructivo como la crisis económica misma.","El New Deal de Roosevelt transformó el papel del gobierno federal en la economía — sus programas de empleo público y regulación bancaria establecieron el Estado de bienestar moderno en EE.UU."]},
  'quote15':{fr:["Chanel a introduit le tailleur en tweed, le sac matelassé 2.55 et le parfum N°5 — des icônes de la mode.","Le N°5 est le parfum le plus vendu au monde depuis plus de 100 ans.","Chanel a grandi dans un orphelinat — c'est là qu'elle a appris à coudre et développé son goût pour la simplicité."],en:["Chanel introduced the tweed suit, the 2.55 quilted bag, and N°5 perfume — fashion icons.","N°5 has been the world's best-selling perfume for over 100 years.","Chanel grew up in an orphanage — where she learned to sew and developed her taste for simplicity."],
    es:["«I have a dream» (Tengo un sueño) fue pronunciado por Martin Luther King Jr. el 28 de agosto de 1963 ante 250 000 personas en Washington D.C.","La parte más memorable del discurso fue improvisada: Mahalia Jackson gritó «¡Cuéntales lo del sueño, Martin!» y King abandonó su texto preparado.","El discurso aceleró la aprobación del Civil Rights Act (1964) y del Voting Rights Act (1965) — dos leyes que transformaron la sociedad estadounidense."]},
  'quote16':{fr:["Bruce Lee a créé son propre art martial, le Jeet Kune Do, en rejetant les formes rigides au profit de la fluidité.","Il est mort à 32 ans dans des circonstances mystérieuses — probablement d'un œdème cérébral.","Il pouvait effectuer des pompes sur deux doigts et frapper si vite que les caméras ne pouvaient pas le suivre."],en:["Bruce Lee created his own martial art, Jeet Kune Do, rejecting rigid forms in favor of fluidity.","He died at 32 under mysterious circumstances — probably from cerebral edema.","He could do two-finger pushups and strike so fast cameras couldn't follow him."],
    es:["«Lo esencial es invisible a los ojos» del Principito de Saint-Exupéry (1943) es una de las citas literarias más universales, usada en contextos que van de la filosofía al marketing.","La frase la pronuncia el zorro al Principito al enseñarle el significado de la amistad: «Solo se ve bien con el corazón».","Saint-Exupéry era piloto de guerra y desapareció durante una misión en 1944 — su obra literaria refleja una búsqueda constante de sentido en un mundo violento."]},
  'quote17':{fr:["Kahlo a commencé à peindre à 18 ans pendant sa convalescence — un miroir au-dessus de son lit lui a donné l'idée des autoportraits.","Ses œuvres mêlent surréalisme, symbolisme mexicain et expression brute de la douleur physique et émotionnelle.","Elle a été la première artiste mexicaine exposée au Louvre — un honneur exceptionnel."],en:["Kahlo started painting at 18 during convalescence — a mirror above her bed gave her the idea for self-portraits.","Her works blend surrealism, Mexican symbolism, and raw expression of physical and emotional pain.","She was the first Mexican artist exhibited at the Louvre — an exceptional honor."],
    es:["«Sapere aude» (Atrévete a saber) fue adoptado por Kant en 1784 como lema de la Ilustración — una llamada a pensar por uno mismo sin recurrir a la autoridad de otros.","La frase original es de Horacio (siglo I a.C.), pero Kant la convirtió en el grito de batalla de la razón autónoma contra la superstición, el dogma y la tradición ciega.","La Ilustración transformó Occidente: separación de poderes, derechos humanos, libertad de prensa, educación pública y método científico son hijos directos de este movimiento."]},
  'quote18':{fr:["Léonard écrivait en miroir probablement pour protéger ses idées — mais aussi parce qu'il était gaucher et que c'était plus naturel.","Ses carnets contiennent des inventions en avance sur leur temps : hélicoptère, char d'assaut, scaphandre.","La Joconde et La Cène sont ses œuvres les plus célèbres, mais il n'a achevé qu'environ 15 tableaux dans toute sa vie."],en:["Leonardo wrote in mirror probably to protect his ideas — but also because he was left-handed and it was more natural.","His notebooks contain inventions ahead of their time: helicopter, tank, diving suit.","The Mona Lisa and The Last Supper are his most famous works, but he only completed about 15 paintings in his life."],
    es:["«El infierno son los otros» (L'enfer, c'est les autres) de Jean-Paul Sartre (Huis clos, 1944) no significa que las personas sean malas, sino que la mirada del otro nos define y nos limita.","En la obra, tres personajes muertos descubren que su castigo eterno no es fuego ni tormentos sino la presencia perpetua de los otros, sin posibilidad de estar solos.","Sartre fue el padre del existencialismo francés: la existencia precede a la esencia, somos libres de elegir y responsables de nuestras elecciones — una filosofía de libertad radical."]},
  'quote19':{fr:["Ali a changé son nom de Cassius Clay après sa conversion à l'islam en 1964.","Il a refusé d'aller au Vietnam en 1967, disant « Aucun Viêt-cong ne m'a jamais traité de nègre » — perdant son titre et sa licence de boxe.","Ali a été diagnostiqué avec la maladie de Parkinson en 1984, probablement liée aux coups reçus pendant sa carrière."],en:["Ali changed his name from Cassius Clay after converting to Islam in 1964.","He refused to go to Vietnam in 1967, saying 'No Viet Cong ever called me n****r' — losing his title and boxing license.","Ali was diagnosed with Parkinson's disease in 1984, likely linked to blows received during his career."],
    es:["«La pluma es más poderosa que la espada» de Edward Bulwer-Lytton (1839) argumenta que la escritura, la comunicación y las ideas tienen más impacto que la fuerza militar.","La historia confirma esta idea: las obras de Voltaire, Marx, Paine y Luther transformaron sociedades enteras sin ejércitos — las revoluciones nacen primero en los textos.","En la era digital, la frase adquiere nueva fuerza: un tweet, un vídeo viral o un artículo pueden movilizar a millones de personas en horas."]},
  'quote20':{fr:["L'expression apparaît pour la première fois en 1789, dans un livre de Jean-Jacques Rousseau publié à titre posthume.","Marie-Antoinette avait en réalité un vrai souci des pauvres — elle a adopté plusieurs enfants défavorisés.","Elle a été exécutée en 1793 à 37 ans — sa dernière phrase fut « Pardonnez-moi, monsieur » après avoir marché sur le pied du bourreau."],en:["The phrase first appears in 1789, in a posthumously published book by Jean-Jacques Rousseau.","Marie-Antoinette actually cared about the poor — she adopted several underprivileged children.","She was executed in 1793 at 37 — her last words were 'Pardon me, sir' after stepping on the executioner's foot."],
    es:["«Conócete a ti mismo» (Gnōthi seauton) estaba inscrito en el templo de Apolo en Delfos — un mandato que Sócrates adoptó como principio filosófico fundamental.","El autoconocimiento es la base de la ética socrática: solo quien se conoce puede actuar con virtud, porque la ignorancia de uno mismo es la raíz de todos los males.","La psicología moderna confirma esta intuición: la metacognición (pensar sobre el propio pensamiento) es una de las habilidades más importantes para el bienestar y la toma de decisiones."]},
  // === RECORDS ===
  'rec1':{fr:["Daniel Scali a battu ce record en 2021 en Australie malgré une condition médicale qui lui cause des douleurs chroniques.","Le record féminin est de 4 heures et 20 minutes, détenu par Dana Glowacka du Canada.","Le gainage active plus de 20 muscles simultanément — c'est l'un des exercices les plus complets."],en:["Daniel Scali broke this record in 2021 in Australia despite a medical condition causing chronic pain.","The women's record is 4 hours 20 minutes, held by Dana Glowacka of Canada.","Planking activates over 20 muscles simultaneously — one of the most complete exercises."],
    es:["La persona que ha vivido más años de forma verificada fue Jeanne Calment (Francia), que murió en 1997 a los 122 años y 164 días.","Calment nació en 1875, conoció a Van Gogh, vivió dos guerras mundiales y la invención de la televisión, el avión, el ordenador e Internet.","Los supercentenarios (110+ años) son extremadamente raros: en cualquier momento dado, solo hay unas 300-400 personas en todo el mundo que han alcanzado esa edad."]},
  'rec2':{fr:["Wadlow pesait 222 kg et chaussait du 75 — ses chaussures étaient fabriquées sur mesure gratuitement en échange de publicité.","Sa croissance était causée par une hyperplasie de l'hypophyse qui produisait trop d'hormone de croissance.","Il était si grand qu'il avait besoin d'appareils orthopédiques aux jambes — c'est une infection due à ces appareils qui l'a tué."],en:["Wadlow weighed 222 kg and wore size 37AA shoes — custom-made for free in exchange for publicity.","His growth was caused by pituitary hyperplasia producing too much growth hormone.","He was so tall he needed leg braces — an infection from these braces killed him."],
    es:["El hombre más alto de la historia documentada fue Robert Wadlow (EE.UU.), que alcanzó 2,72 metros antes de morir a los 22 años en 1940.","Su crecimiento continuo se debía a una hiperplasia de la glándula pituitaria que producía niveles anormales de hormona del crecimiento.","Wadlow necesitaba muletas para caminar y usaba zapatos de talla 76 — pese a su fama, era conocido por su carácter amable y gentil."]},
  'rec3':{fr:["Max Park a établi le record de 3,13 secondes en 2023 — il est autiste et le Rubik's Cube l'a aidé à développer sa motricité fine.","Il existe 43 252 003 274 489 856 000 combinaisons possibles sur un Rubik's Cube standard.","Le « nombre de Dieu » est 20 — c'est le nombre minimum de mouvements pour résoudre n'importe quelle configuration."],en:["Max Park set the 3.13-second record in 2023 — he's autistic and the Rubik's Cube helped develop his fine motor skills.","There are 43,252,003,274,489,856,000 possible combinations on a standard Rubik's Cube.","'God's number' is 20 — the minimum moves needed to solve any configuration."],
    es:["Usain Bolt posee el récord de los 100 metros lisos (9,58 s) y los 200 metros (19,19 s), ambos establecidos en el Mundial de Berlín 2009.","A su velocidad máxima, Bolt alcanzó 44,72 km/h — pero curiosamente, su salida era más lenta que la de sus rivales; su ventaja estaba en la fase de velocidad máxima.","Los biomecánicos calculan que el límite teórico humano para los 100 metros está entre 9,27 y 9,40 segundos — pero nadie se ha acercado al récord de Bolt en más de 15 años."]},
  'rec4':{fr:["Le Monopoly est le jeu de société le plus vendu au monde avec plus de 275 millions d'exemplaires.","Le jeu a été inventé pour dénoncer les dangers du monopole foncier — un message que la plupart des joueurs ignorent.","La case la plus visitée est la Prison — et la moins visitée est Mediterranean Avenue."],en:["Monopoly is the world's best-selling board game with over 275 million copies.","The game was invented to denounce the dangers of land monopoly — a message most players ignore.","The most visited space is Jail — and the least visited is Mediterranean Avenue."],
    es:["El edificio más alto del mundo es el Burj Khalifa en Dubái, con 828 metros y 163 pisos — su punta es visible a más de 95 km de distancia.","La construcción empleó a más de 12 000 trabajadores y usó 330 000 m³ de hormigón — la diferencia de temperatura entre la base y la cima puede superar los 10 °C.","El Jeddah Tower en Arabia Saudita (en construcción) está diseñado para superar los 1 000 metros — la carrera por el rascacielos más alto continúa."]},
  'rec5':{fr:["Les clics du cachalot servent aussi d'écholocation pour repérer les calmars géants dans les profondeurs.","À 230 décibels, un clic de cachalot pourrait théoriquement rompre les tympans d'un plongeur.","Le cachalot possède le plus gros cerveau de tous les animaux — environ 7,8 kg."],en:["Sperm whale clicks also serve as echolocation to locate giant squid in the depths.","At 230 decibels, a sperm whale click could theoretically rupture a diver's eardrums.","The sperm whale has the largest brain of any animal — about 7.8 kg."],
    es:["El avión más rápido jamás construido fue el North American X-15, que alcanzó 7 274 km/h (Mach 6,7) en 1967 — un récord para aviones tripulados que sigue vigente.","El avión comercial más rápido fue el Concorde (2 180 km/h), retirado en 2003 — cruzaba el Atlántico en 3 horas y media, la mitad que un avión convencional.","Boom Supersonic desarrolla el Overture, un avión supersónico que promete vuelos transatlánticos en 3,5 horas para la década de 2030 — el sucesor espiritual del Concorde."]},
  'rec6':{fr:["Le puzzle a été assemblé par 1 600 personnes à Ravensburg, en Allemagne, en 2008.","Le plus grand puzzle commercial disponible compte 60 000 pièces et mesure 8,52 m de long.","Le plus ancien puzzle connu date de 1766 — une carte géographique découpée pour enseigner la géographie aux enfants."],en:["The puzzle was assembled by 1,600 people in Ravensburg, Germany, in 2008.","The largest commercially available puzzle has 60,000 pieces and measures 8.52 m long.","The oldest known puzzle dates from 1766 — a cut-up map used to teach children geography."],
    es:["La temperatura más alta registrada en la Tierra fue 56,7 °C en el Valle de la Muerte (California) el 10 de julio de 1913 — aunque algunos meteorólogos cuestionan esta medición.","La más baja fue -89,2 °C en la estación Vostok (Antártida) el 21 de julio de 1983 — tan frío que el acero se vuelve frágil como vidrio.","El lugar habitado más frío del mundo es Oymyakón, en Siberia, donde se han registrado -67,7 °C — los habitantes dejan los motores de sus coches encendidos toda la noche."]},
  'rec7':{fr:["Ce record a été mesuré à Furnace Creek Ranch dans la Vallée de la Mort en Californie le 10 juillet 1913.","La température la plus basse jamais enregistrée est -89,2 °C à la station Vostok en Antarctique en 1983.","L'écart entre le record de chaleur et le record de froid est de 145,9 °C."],en:["This record was measured at Furnace Creek Ranch in Death Valley, California on July 10, 1913.","The lowest temperature ever recorded is -89.2°C at Vostok Station, Antarctica in 1983.","The gap between the heat and cold records is 145.9°C."],
    es:["El animal más rápido del mundo es el halcón peregrino, que alcanza más de 380 km/h en picado — el vertebrado más veloz del planeta.","En tierra, el guepardo alcanza 112 km/h en sprints cortos, pero un antílope americano (berrendo) puede mantener 90 km/h durante kilómetros — la velocidad sostenida más alta.","El animal más rápido del mar es el pez vela (Istiophorus), que alcanza 110 km/h — una velocidad comparable a la de un coche en autopista."]},
  'rec8':{fr:["Joey Chestnut a dominé le concours de Nathan's à Coney Island pendant plus de 15 ans.","Ce concours existe depuis 1916 et attire des millions de téléspectateurs chaque 4 juillet.","Les compétiteurs s'entraînent en étirant leur estomac avec de grandes quantités d'eau et de nourriture."],en:["Joey Chestnut dominated Nathan's contest at Coney Island for over 15 years.","This contest has existed since 1916 and attracts millions of viewers every July 4th.","Competitors train by stretching their stomachs with large amounts of water and food."],
    es:["El objeto artificial más lejano de la Tierra es la sonda Voyager 1, lanzada en 1977, que se encuentra a más de 24 000 millones de km del Sol.","A pesar de su distancia, Voyager 1 sigue transmitiendo datos a la Tierra — la señal tarda más de 22 horas en llegar, viajando a la velocidad de la luz.","La sonda lleva un disco de oro con sonidos e imágenes de la Tierra: música de Bach, saludos en 55 idiomas y fotografías de la humanidad — un mensaje para posibles civilizaciones extraterrestres."]},
  'rec9':{fr:["L'arbre s'appelle Mathusalem et pousse dans les White Mountains en Californie — son emplacement exact est gardé secret.","Un autre pin Bristlecone, Prométhée, avait plus de 4 900 ans quand il a été abattu par un chercheur en 1964.","Ces arbres survivent grâce à leur bois très dense et résineux qui résiste aux maladies et aux parasites."],en:["The tree is called Methuselah and grows in the White Mountains of California — its exact location is kept secret.","Another Bristlecone pine, Prometheus, was over 4,900 years old when cut down by a researcher in 1964.","These trees survive thanks to very dense, resinous wood that resists disease and parasites."],
    es:["El récord de apnea estática (sin respirar bajo el agua, inmóvil) supera los 24 minutos — una hazaña que desafía la comprensión de la fisiología humana.","Los apneístas entrenan para reducir su consumo de oxígeno y tolerar altos niveles de CO₂ — el reflejo de inmersión mamífero (bradicardia, vasoconstricción) es la clave fisiológica.","La apnea profunda supera los 130 metros de profundidad: a esa presión, los pulmones se comprimen al tamaño de un puño y la sangre se concentra en los órganos vitales."]},
  'rec10':{fr:["Baumgartner est monté dans une capsule attachée à un ballon stratosphérique rempli d'hélium.","Il a atteint la vitesse maximale de 1 357,6 km/h — devenant le premier humain à briser le mur du son en chute libre.","L'ensemble du saut a duré 9 minutes et 3 secondes, dont 4 minutes et 19 secondes en chute libre."],en:["Baumgartner ascended in a capsule attached to a helium-filled stratospheric balloon.","He reached a top speed of 1,357.6 km/h — becoming the first human to break the sound barrier in freefall.","The entire jump lasted 9 minutes 3 seconds, with 4 minutes 19 seconds in freefall."],
    es:["El libro más vendido de la historia es la Biblia, con más de 5 000 millones de copias distribuidas — seguida del Corán y Don Quijote.","El Principito de Saint-Exupéry es el libro más traducido después de textos religiosos, con versiones en más de 300 idiomas y dialectos.","Harry Potter y la piedra filosofal (1997) ha vendido más de 120 millones de copias en un solo volumen — el libro de ficción más vendido de las últimas décadas."]},
  'rec11':{fr:["Le vol Singapore Airlines SQ22 relie Singapour à New York sur un Airbus A350-900ULR.","Les passagers en classe affaires disposent de lits plats et de repas spécialement conçus pour les vols ultra-longs.","La distance parcourue est d'environ 16 700 km — presque la moitié du tour de la Terre."],en:["Singapore Airlines flight SQ22 connects Singapore to New York on an Airbus A350-900ULR.","Business class passengers have flat beds and meals specially designed for ultra-long flights.","The distance covered is about 16,700 km — nearly half way around Earth."],
    es:["El vuelo espacial más largo fue el de Valeri Polyakov, que pasó 437 días consecutivos en la estación Mir (1994-1995) — más de 14 meses en gravedad cero.","Los efectos del vuelo espacial prolongado incluyen pérdida ósea, atrofia muscular, redistribución de fluidos y cambios en la visión — desafíos que la NASA debe resolver antes de viajar a Marte.","El récord acumulado pertenece a Gennady Padalka, con 879 días en el espacio repartidos en cinco misiones — el equivalente a casi dos años y medio."]},
  'rec12':{fr:["Charlotte Lee a commencé sa collection en 1996 et la stocke dans une pièce dédiée de sa maison.","Chaque canard est catalogué et numéroté — elle connaît l'histoire de chacun.","Le canard en caoutchouc a été inventé dans les années 1940 et est devenu un symbole de l'enfance."],en:["Charlotte Lee started her collection in 1996 and stores it in a dedicated room.","Each duck is catalogued and numbered — she knows the story of each one.","The rubber duck was invented in the 1940s and became a symbol of childhood."],
    es:["El récord de velocidad terrestre es de 1 228 km/h (Mach 1,016), establecido por Andy Green en el ThrustSSC en 1997 — el primer vehículo terrestre en romper la barrera del sonido.","El proyecto Bloodhound intentó superar los 1 600 km/h pero fue abandonado por falta de financiación — la búsqueda de velocidad extrema sigue siendo costosísima.","Los salt flats de Bonneville (Utah) y Black Rock Desert (Nevada) son las pistas naturales más utilizadas para récords de velocidad terrestre."]},
  'rec13':{fr:["Le mot le plus long attesté dans un dictionnaire est « intergouvernementalisations » avec 27 lettres.","En allemand, les mots composés n'ont pas de limite — le plus long officiel fait 80 lettres.","Le mot le plus long en anglais est « pneumonoultramicroscopicsilicovolcanoconiosis » avec 45 lettres — une maladie pulmonaire."],en:["The longest attested word in a dictionary is 'intergouvernementalisations' with 27 letters.","In German, compound words have no limit — the longest official one has 80 letters.","The longest English word is 'pneumonoultramicroscopicsilicovolcanoconiosis' with 45 letters — a lung disease."],
    es:["La obra de arte más cara jamás vendida fue el Salvator Mundi, atribuido a Leonardo da Vinci, por 450 millones de dólares en 2017.","La autenticidad del Salvator Mundi es debatida por algunos expertos, lo que no impidió que alcanzara un precio récord — el mercado del arte desafía la lógica económica.","La obra de arte de un artista vivo más cara fue una escultura de Jeff Koons vendida por 91 millones de dólares en 2019."]},
  'rec14':{fr:["Šobat a atteint ce record en 2021 en Croatie après des années d'entraînement de respiration.","Le corps humain peut survivre sans oxygène pendant environ 3 minutes en conditions normales.","Les plongeurs en apnée utilisent des techniques de relaxation pour ralentir leur rythme cardiaque à 20 battements par minute."],en:["Šobat achieved this record in 2021 in Croatia after years of breathing training.","The human body can survive without oxygen for about 3 minutes under normal conditions.","Freedivers use relaxation techniques to slow their heart rate to 20 beats per minute."],
    es:["El animal más longevo conocido es el tiburón de Groenlandia: un ejemplar fue datado en 512 años, lo que lo convierte en el vertebrado más antiguo del planeta.","La almeja Arctica islandica «Ming» fue datada en 507 años antes de ser accidentalmente matada por los científicos que la estudiaban — un final irónico para el animal más viejo conocido.","Las esponjas de cristal antárticas podrían vivir más de 10 000 años, aunque su edad exacta es difícil de determinar — los límites de la longevidad animal siguen siendo desconocidos."]},
  'rec15':{fr:["La Paedophryne amauensis a été découverte en 2009 dans la litière forestière de Papouasie-Nouvelle-Guinée.","Elle est aussi le plus petit vertébré connu au monde — plus petite qu'une pièce de monnaie.","Sa petite taille est une adaptation à la vie dans la litière humide de la forêt tropicale."],en:["Paedophryne amauensis was discovered in 2009 in the forest litter of Papua New Guinea.","It's also the smallest known vertebrate — smaller than a coin.","Its tiny size is an adaptation to life in the moist tropical forest litter."],
    es:["El terremoto más potente registrado fue el de Valdivia, Chile, en 1960: magnitud 9,5 en la escala de Richter — generó un tsunami que cruzó el Pacífico hasta Japón.","El terremoto desplazó la costa chilena varios metros hacia el Pacífico y liberó una energía equivalente a 178 000 millones de toneladas de TNT.","Chile es uno de los países más sísmicos del mundo, situado en el Cinturón de Fuego del Pacífico — sus estrictas normas de construcción antisísmica salvan miles de vidas."]},
  'rec16':{fr:["Le record a été établi en 2009 en Allemagne lors d'un événement officiel du Guinness World Records.","Les participants devaient être entièrement peints en bleu avec un bonnet blanc — aucun visage visible.","La Belgique a tenté de battre ce record en 2011 mais n'a atteint que 2 500 participants."],en:["The record was set in 2009 in Germany at an official Guinness World Records event.","Participants had to be entirely painted blue with a white cap — no face visible.","Belgium tried to break this record in 2011 but only reached 2,500 participants."],
    es:["El récord de flexiones en 24 horas es de más de 46 000, logrado por Charles Servizio en 1993 — una media de 32 flexiones por minuto durante un día entero.","Los récords de resistencia física desafían la comprensión médica: maratones de baile de 126 horas, natación continua de más de 50 horas y ayunos verificados de más de 380 días.","El Guinness World Records existe desde 1955: fue creado para resolver debates en pubs irlandeses — el propio libro se ha convertido en uno de los más vendidos de la historia."]},
  'rec17':{fr:["L'événement a eu lieu aux Pays-Bas en 2009 et a nécessité des mois de préparation par une équipe internationale.","Un seul domino mal placé peut ruiner des semaines de travail — les équipes utilisent des « barrières de sécurité » tous les 100 dominos.","Le premier domino rallye télévisé a eu lieu en 1979 avec 1 million de dominos."],en:["The event took place in the Netherlands in 2009 and required months of preparation by an international team.","One misplaced domino can ruin weeks of work — teams use 'safety barriers' every 100 dominoes.","The first televised domino rally was in 1979 with 1 million dominoes."],
    es:["El mayor diamante en bruto jamás encontrado fue el Cullinan (1905, Sudáfrica): 3 106 quilates (621 gramos), del que se tallaron las joyas más grandes de la Corona Británica.","La Estrella de África (Cullinan I, 530 quilates) está engastada en el cetro real británico y es el mayor diamante tallado en talla de pera del mundo.","Los diamantes no son raros: lo que mantiene su precio alto es el control de la oferta por la industria — los diamantes sintéticos, químicamente idénticos, cuestan una fracción del precio."]},
  'rec18':{fr:["L'éclair a duré 17,1 secondes — un record pour la durée d'un éclair unique.","Les éclairs se forment quand les charges électriques dans les nuages deviennent suffisamment intenses pour ioniser l'air.","La foudre frappe la Terre environ 100 fois par seconde — soit 8,6 millions de fois par jour."],en:["The lightning lasted 17.1 seconds — a record for a single flash duration.","Lightning forms when electrical charges in clouds become intense enough to ionize air.","Lightning strikes Earth about 100 times per second — 8.6 million times per day."],
    es:["El río Amazonas tiene el mayor caudal del mundo: 209 000 m³/s en su desembocadura — más que los siguientes siete ríos más caudalosos juntos.","La cuenca amazónica cubre 6,9 millones de km², casi tan grande como Australia, y su selva produce el 20 % del oxígeno del planeta.","El Amazonas no tiene ni un solo puente en toda su longitud de 6 400 km — la selva circundante es tan densa que no existe infraestructura terrestre que lo cruce."]},
  'rec19':{fr:["Le bonhomme de neige s'appelait Olympia et a été construit par les habitants de Bethel, Maine en 2008.","Il a nécessité 6 000 tonnes de neige et ses bras étaient de vrais sapins de 9 mètres.","Ses yeux étaient des pneus de voiture, son nez un tronc d'arbre et son écharpe mesurait 40 mètres."],en:["The snowman was named Olympia and built by residents of Bethel, Maine in 2008.","It required 6,000 tons of snow and its arms were real 9-meter spruce trees.","Its eyes were car tires, its nose a tree trunk, and its scarf measured 40 meters."],
    es:["La canción más reproducida en Spotify es Blinding Lights de The Weeknd, con más de 4 000 millones de reproducciones.","Una reproducción en Spotify genera entre 0,003 y 0,005 dólares para el artista — para ganar un salario mínimo mensual, un músico necesitaría más de 250 000 reproducciones al mes.","El algoritmo de Spotify ha creado un nuevo tipo de canción: intros cortas (menos de 5 segundos), estribillos inmediatos y duración reducida (2-3 minutos) para maximizar las reproducciones."]},
  'rec20':{fr:["Le Guinness World Records a été créé en 1955 par la brasserie Guinness pour trancher les débats de pub.","Il se vend environ 3 millions d'exemplaires par an — l'un des livres les plus vendus au monde.","Le livre lui-même détient un record : c'est le livre sous copyright le plus vendu de tous les temps."],en:["Guinness World Records was created in 1955 by Guinness Brewery to settle pub debates.","About 3 million copies sell per year — one of the world's best-selling books.","The book itself holds a record: it's the best-selling copyrighted book of all time."],
    es:["La Gran Muralla China se extiende más de 21 000 km incluyendo todas sus ramificaciones — no es visible a simple vista desde el espacio, contrariamente al mito popular.","Su construcción se prolongó durante más de 2 000 años (desde el siglo VII a.C. hasta el XVII d.C.) y costó la vida a millones de trabajadores.","La muralla no fue eficaz como barrera militar: fue atravesada varias veces por invasores, incluyendo los mongoles de Gengis Khan y los manchúes que fundaron la dinastía Qing."]},
  // === SPORTS ===
  'sp01':{fr:["Bolt mesurait 1,95 m — sa grande taille est à la fois un avantage (foulée longue) et un handicap (départ lent).","Il a pris sa retraite invaincu sur 100 m aux JO — triple champion olympique en 2008, 2012 et 2016.","Bolt mangeait des nuggets de poulet avant chaque course aux JO de Pékin 2008 — environ 100 nuggets par jour."],en:["Bolt stands 1.95 m — his height is both an advantage (long stride) and handicap (slow start).","He retired undefeated in Olympic 100m — triple champion in 2008, 2012, and 2016.","Bolt ate chicken nuggets before every race at the 2008 Beijing Olympics — about 100 nuggets per day."],
    es:["Los Juegos Olímpicos antiguos se celebraron en Olimpia (Grecia) cada cuatro años durante más de 1 100 años, del 776 a.C. al 393 d.C.","Los atletas competían desnudos y las mujeres casadas tenían prohibido asistir — las competidoras femeninas tenían sus propios juegos, los Heraia, en honor a Hera.","Los Juegos modernos fueron restaurados por Pierre de Coubertin en 1896 en Atenas, con 241 atletas de 14 países — hoy participan más de 10 000 atletas de 200 naciones."]},
  'sp02':{fr:["Le départ a été déplacé au château de Windsor pour que la famille royale puisse voir la course depuis la terrasse.","Les 385 yards supplémentaires ont été ajoutés pour que l'arrivée soit devant la loge royale.","Le premier coureur de marathon antique, Pheidippides, serait mort d'épuisement après avoir annoncé la victoire."],en:["The start was moved to Windsor Castle so the royal family could watch from the terrace.","The extra 385 yards were added so the finish would be in front of the royal box.","The ancient marathon runner Pheidippides reportedly died of exhaustion after announcing victory."],
    es:["El fútbol es el deporte más popular del mundo, con más de 4 000 millones de aficionados y 270 millones de jugadores activos.","Las reglas modernas fueron codificadas en 1863 en Londres por la Football Association — antes, cada escuela inglesa jugaba con sus propias reglas.","La FIFA tiene 211 países miembros, más que las Naciones Unidas (193) — el fútbol es literalmente el idioma más universal del planeta."]},
  'sp03':{fr:["Phelps a remporté 23 médailles d'or, 3 d'argent et 2 de bronze — 28 médailles olympiques au total.","Son envergure de bras (2,01 m) est plus grande que sa taille (1,93 m) — un avantage anatomique rare.","Il s'entraînait 6 heures par jour, 6 jours par semaine, consommant 12 000 calories quotidiennes."],en:["Phelps won 23 gold, 3 silver, and 2 bronze — 28 Olympic medals total.","His arm span (2.01 m) exceeds his height (1.93 m) — a rare anatomical advantage.","He trained 6 hours a day, 6 days a week, consuming 12,000 calories daily."],
    es:["El maratón moderno conmemora la legendaria carrera de Filípides desde Maratón hasta Atenas (42,195 km) en 490 a.C. para anunciar la victoria sobre los persas.","Sin embargo, los historiadores dudan de esta leyenda: Heródoto describe un corredor que recorrió 240 km hasta Esparta para pedir refuerzos, no los 42 km hasta Atenas.","La distancia oficial de 42,195 km se fijó en los Juegos de Londres de 1908 para que la carrera terminara frente al palco real — antes, cada maratón tenía una longitud diferente."]},
  'sp04':{fr:["Shepard a frappé deux balles avec un fer 6 improvisé — la première est allée dans un cratère, la seconde « des miles et des miles ».","La balle a probablement parcouru environ 400 mètres grâce à la faible gravité lunaire.","Le club et les balles sont toujours sur la Lune — ils font partie du patrimoine humain extraterrestre."],en:["Shepard hit two balls with an improvised 6-iron — the first went into a crater, the second 'miles and miles'.","The ball probably traveled about 400 meters thanks to the Moon's low gravity.","The club and balls are still on the Moon — part of humanity's extraterrestrial heritage."],
    es:["El cricket es el segundo deporte más seguido del mundo con 2 500 millones de aficionados, principalmente en India, Pakistán, Australia e Inglaterra.","Un partido de Test Cricket puede durar hasta cinco días, con pausas para el té — es probablemente el deporte más largo del mundo.","India es la superpotencia económica del cricket: la Indian Premier League (IPL) genera más ingresos que muchas ligas de fútbol europeas."]},
  'sp05':{fr:["Le tir à la corde a été remplacé par des sports jugés plus modernes et spectaculaires.","Le Royaume-Uni a remporté le plus de médailles dans cette discipline avec 2 or, 2 argent et 1 bronze.","Des mouvements militent pour le retour du tir à la corde aux JO — il est encore pratiqué comme sport officiel dans de nombreux pays."],en:["Tug of war was replaced by sports deemed more modern and spectacular.","The UK won the most medals in this event with 2 gold, 2 silver, and 1 bronze.","Movements advocate for tug of war's Olympic return — it's still an official sport in many countries."],
    es:["El baloncesto fue inventado en 1891 por James Naismith, un profesor canadiense de educación física que necesitaba un deporte de interior para el invierno.","Los primeros aros eran cestas de melocotones colgadas a 3,05 metros de altura — alguien tenía que subir una escalera para recuperar la pelota tras cada canasta.","La NBA se fundó en 1946 y se ha convertido en una de las ligas deportivas más valiosas del mundo, con franquicias valoradas en miles de millones de dólares."]},
  'sp06':{fr:["Les anciennes balles blanches étaient difficiles à voir sur les écrans TV noir et blanc et couleur.","Le jaune fluorescent a été adopté car il offre le meilleur contraste sur les surfaces vertes et bleues.","Wimbledon a été le dernier grand tournoi à adopter les balles jaunes, en 1986."],en:["Old white balls were hard to see on both black-and-white and color TV screens.","Fluorescent yellow was adopted as it offers the best contrast on green and blue surfaces.","Wimbledon was the last major tournament to adopt yellow balls, in 1986."],
    es:["El surf fue inventado por los polinesios hace al menos 3 000 años y era una actividad sagrada en la antigua Hawái, reservada a la nobleza.","El duque hawaiano Kahanamoku introdujo el surf en Australia y California a principios del siglo XX, convirtiéndolo en un fenómeno mundial.","El surf debutó como deporte olímpico en Tokio 2020 y las olas de los Juegos de París 2024 se disputaron en Tahití, a 15 000 km de la capital francesa."]},
  'sp07':{fr:["James Naismith a inventé le basket-ball en 1891 pour occuper ses élèves pendant l'hiver.","Les paniers ouverts n'ont été introduits qu'en 1906 — pendant 15 ans, quelqu'un grimpait chercher la balle.","Le premier match officiel s'est terminé 1-0 — le seul panier a été marqué d'une distance de 7,6 mètres."],en:["James Naismith invented basketball in 1891 to keep his students busy during winter.","Open baskets weren't introduced until 1906 — for 15 years, someone climbed to get the ball.","The first official game ended 1-0 — the only basket was scored from 7.6 meters."],
    es:["El rugby debe su nombre a la escuela de Rugby (Inglaterra), donde en 1823 el estudiante William Webb Ellis supuestamente cogió el balón con las manos durante un partido de fútbol.","Esta historia es probablemente apócrifa, pero el trofeo de la Copa del Mundo de Rugby lleva el nombre de Webb Ellis en su honor.","La haka, danza guerrera maorí interpretada por los All Blacks de Nueva Zelanda antes de cada partido, se ha convertido en uno de los momentos más icónicos del deporte mundial."]},
  'sp08':{fr:["Les dernières médailles en or massif ont été décernées aux JO de Stockholm en 1912.","Les médailles de bronze ne contiennent que 5 % d'étain — elles sont principalement en cuivre.","Les médailles des JO de Tokyo 2020 ont été fabriquées à partir de métaux recyclés provenant de téléphones portables."],en:["The last solid gold medals were awarded at the 1912 Stockholm Olympics.","Bronze medals contain only 5% tin — they're mainly copper.","The Tokyo 2020 Olympic medals were made from recycled metals from mobile phones."],
    es:["El tenis moderno nació en 1873 cuando el mayor Walter Wingfield patentó un juego llamado «Sphairistikè» que se jugaba en césped — el nombre no cuajó, pero el deporte sí.","Wimbledon, el torneo más antiguo del mundo (desde 1877), sigue exigiendo que los jugadores vistan de blanco y se juega exclusivamente sobre hierba natural.","El servicio más rápido jamás registrado fue de 263,4 km/h por Sam Groth en 2012 — la pelota tarda apenas 0,4 segundos en cruzar la pista."]},
  'sp09':{fr:["Le volant de badminton peut passer de 493 km/h à 0 en quelques mètres grâce à la résistance de l'air de ses plumes.","C'est le projectile de sport le plus rapide — plus rapide qu'une balle de golf ou un service de tennis.","Les volants professionnels sont faits avec 16 plumes d'oie — toujours de la même aile pour un vol stable."],en:["The shuttlecock can go from 493 km/h to 0 in meters thanks to feather air resistance.","It's the fastest sports projectile — faster than a golf ball or tennis serve.","Professional shuttlecocks are made with 16 goose feathers — always from the same wing for stable flight."],
    es:["El ajedrez se originó en la India hacia el siglo VI como chaturanga, un juego que simulaba una batalla entre cuatro divisiones del ejército indio.","La pieza de la reina era originalmente un «consejero» débil que solo se movía un cuadrado en diagonal — su transformación en la pieza más poderosa del tablero ocurrió en la Europa del siglo XV.","El número de partidas de ajedrez posibles supera el número de átomos en el universo observable — se estima en 10^120, conocido como el número de Shannon."]},
  'spo10':{fr:["Louis était un porteur d'eau — il n'avait jamais participé à une course officielle avant les JO.","Il est devenu un héros national grec et a reçu des cadeaux extravagants dont des repas gratuits à vie.","Le marathon des JO de 1896 faisait 40 km — la distance de 42,195 km n'a été standardisée qu'en 1921."],en:["Louis was a water carrier — he had never competed in an official race before the Olympics.","He became a Greek national hero and received extravagant gifts including free meals for life.","The 1896 Olympic marathon was 40 km — the 42.195 km distance wasn't standardized until 1921."],
    es:["Louis era aguador — nunca había participado en una carrera oficial antes de ganar el primer maratón olímpico en Atenas en 1896.","Corrió los 40 km (la distancia oficial era diferente de los 42,195 km actuales) en 2 horas y 58 minutos.","Fue recibido como un héroe nacional griego y el rey Jorge I lo acompañó a pie en la última vuelta al estadio Panatenaico."]},
  'sp011':{fr:["La princesse Alexandra voulait que la course parte sous les fenêtres de la nursery de ses enfants au château de Windsor.","Cette distance est devenue le standard officiel en 1921 lors du congrès de l'IAAF.","Le record du monde actuel du marathon est détenu par Kelvin Kiptum avec un temps de 2h00m35s."],en:["Princess Alexandra wanted the race to start beneath the nursery windows at Windsor Castle.","This distance became the official standard in 1921 at the IAAF congress.","The current marathon world record is held by Kelvin Kiptum at 2:00:35."],
    es:["El béisbol es conocido como el «pasatiempo nacional» de Estados Unidos y tiene raíces que se remontan a juegos de bate y pelota del siglo XVIII.","Un lanzador profesional puede enviar la pelota a más de 160 km/h — el bateador tiene menos de 0,4 segundos para decidir si golpea o no.","Japón, Corea del Sur, Cuba y la República Dominicana tienen ligas de béisbol tan competitivas que rivalizan con la MLB estadounidense en nivel técnico."]},
  'sp012':{fr:["La Chine domine le tennis de table mondial avec plus de 100 millions de joueurs.","La balle de ping-pong ne pèse que 2,7 grammes mais peut atteindre 112 km/h lors d'un smash.","Le tennis de table a joué un rôle diplomatique — la « diplomatie du ping-pong » en 1971 a ouvert les relations entre les USA et la Chine."],en:["China dominates world table tennis with over 100 million players.","A ping-pong ball weighs only 2.7 grams but can reach 112 km/h during a smash.","Table tennis played a diplomatic role — 'ping-pong diplomacy' in 1971 opened US-China relations."],
    es:["La natación competitiva ha sido parte de los Juegos Olímpicos desde 1896, pero los primeros estilos eran variaciones del braza — el crol no se generalizó hasta los años 1900.","Michael Phelps es el atleta olímpico más laureado de la historia con 28 medallas (23 de oro), un récord que probablemente no se superará en décadas.","Los trajes de baño de poliuretano fueron prohibidos en 2010 tras provocar una avalancha de récords mundiales — se consideró que convertían la competición en una carrera tecnológica."]},
  'sp013':{fr:["L'Inde est le pays le plus passionné de cricket — un match de la Coupe du monde peut rassembler un milliard de téléspectateurs.","Le cricket se joue dans plus de 100 pays mais est surtout populaire dans les anciennes colonies britanniques.","Sachin Tendulkar est considéré comme le plus grand joueur de cricket — il a marqué 100 centuries internationaux."],en:["India is the most passionate cricket country — a World Cup match can gather a billion viewers.","Cricket is played in over 100 countries but is mostly popular in former British colonies.","Sachin Tendulkar is considered the greatest cricketer — he scored 100 international centuries."],
    es:["El yoga, aunque hoy se practica principalmente como ejercicio físico, es una disciplina espiritual india de más de 5 000 años de antigüedad.","Existen decenas de estilos: hatha (posturas y respiración), vinyasa (flujo continuo), bikram (a 40 °C), kundalini (energía y meditación) y ashtanga (secuencias fijas).","Estudios científicos han demostrado que la práctica regular de yoga reduce el estrés, la ansiedad, la presión arterial y el dolor crónico, y mejora la flexibilidad y el equilibrio."]},
  'sp014':{fr:["Le Tour couvre environ 3 500 km en 21 étapes sur 23 jours à travers la France.","Le maillot jaune a été introduit en 1919 — jaune car c'était la couleur du journal L'Auto qui organisait la course.","Le Tour de France 1904 a été si truffé de tricheries que les 4 premiers du classement ont été disqualifiés."],en:["The Tour covers about 3,500 km in 21 stages over 23 days across France.","The yellow jersey was introduced in 1919 — yellow because it was the color of L'Auto newspaper organizing the race.","The 1904 Tour de France was so rife with cheating that the top 4 finishers were disqualified."],
    es:["El golf moderno nació en Escocia en el siglo XV — el rey Jacobo II lo prohibió en 1457 porque distraía a los soldados del entrenamiento con arco.","Una pelota de golf tiene entre 300 y 500 hoyuelos que reducen la resistencia aerodinámica y permiten que vuele hasta 2,5 veces más lejos que una esfera lisa.","El Augusta National Golf Club, sede del Masters, no admitió mujeres hasta 2012 y no tuvo un miembro afroamericano hasta 1990 — un reflejo de la historia segregacionista del deporte."]},
  'sp015':{fr:["Sans fossettes, une balle de golf ne volerait qu'à moitié de la distance — les alvéoles créent une couche de turbulence qui réduit la traînée.","La balle de golf a été standardisée à un diamètre minimum de 42,67 mm et un poids maximum de 45,93 g.","Le plus long drive enregistré est de 515 mètres, réalisé par un golfeur professionnel avec un vent favorable."],en:["Without dimples, a golf ball would fly only half the distance — dimples create turbulence reducing drag.","The golf ball is standardized at a minimum 42.67 mm diameter and maximum 45.93 g weight.","The longest recorded drive is 515 meters, hit by a pro golfer with favorable wind."],
    es:["Las artes marciales asiáticas tienen miles de años de historia: el kung-fu shaolín se practica desde el siglo VI, el judo fue codificado en 1882 y el taekwondo en 1955.","Bruce Lee revolucionó las artes marciales al crear el Jeet Kune Do, una filosofía que rechazaba los estilos rígidos en favor de la adaptabilidad — «sé como el agua».","Las artes marciales mixtas (MMA) combinan técnicas de boxeo, lucha libre, jiu-jitsu brasileño, muay thai y otras disciplinas — el UFC se ha convertido en una de las organizaciones deportivas más lucrativas del mundo."]},
  'sp016':{fr:["De Coubertin était inspiré par les Jeux Olympiques antiques qui se tenaient à Olympie tous les 4 ans depuis 776 av. J.-C.","Les premiers Jeux modernes comptaient 241 athlètes de 14 pays — contre plus de 10 000 athlètes aujourd'hui.","La devise olympique « Citius, Altius, Fortius » (Plus vite, plus haut, plus fort) a été complétée par « Communiter » (ensemble) en 2021."],en:["De Coubertin was inspired by ancient Olympic Games held at Olympia every 4 years since 776 BC.","The first modern Games had 241 athletes from 14 countries — vs over 10,000 today.","The Olympic motto 'Citius, Altius, Fortius' was extended with 'Communiter' (together) in 2021."],
    es:["El ciclismo profesional incluye las tres grandes vueltas: el Tour de Francia (desde 1903), el Giro de Italia (1909) y la Vuelta a España (1935).","El Tour de Francia recorre más de 3 500 km en 23 etapas durante 3 semanas — los ciclistas queman entre 5 000 y 8 000 calorías diarias durante la carrera.","La historia del ciclismo está manchada por el dopaje: la era de Lance Armstrong reveló un sistema organizado que afectaba a la mayoría de los equipos profesionales."]},
  'sp017':{fr:["Pendant les 5 jours, les joueurs prennent des pauses pour le thé et le déjeuner — le cricket est le sport le plus civilisé du monde.","Un match nul est possible même après 5 jours de jeu — si aucune équipe ne termine ses manches.","Le score le plus élevé jamais atteint dans un Test match est 952/6 par le Sri Lanka contre l'Inde en 1997."],en:["During 5 days, players take tea and lunch breaks — cricket is the world's most civilized sport.","A draw is possible even after 5 days — if neither team finishes their innings.","The highest score in a Test match is 952/6 by Sri Lanka against India in 1997."],
    es:["El Ironman es la prueba de triatlón más exigente: 3,8 km de natación, 180 km de ciclismo y un maratón completo (42,195 km), todo en un solo día.","El récord actual del Ironman de Hawái está por debajo de las 7 horas y 30 minutos — una hazaña de resistencia humana que parecía imposible hace apenas 20 años.","El primer Ironman se celebró en Hawái en 1978 con solo 15 participantes — hoy participan miles de atletas en decenas de Ironman por todo el mundo."]},
  'sp018':{fr:["Serena a remporté son premier Grand Chelem à 17 ans et son dernier à 35 ans — une longévité exceptionnelle.","Avec sa sœur Venus, elles ont dominé le double féminin avec 14 titres du Grand Chelem ensemble.","Serena a remporté l'Open d'Australie 2017 alors qu'elle était enceinte de 8 semaines."],en:["Serena won her first Grand Slam at 17 and her last at 35 — exceptional longevity.","With sister Venus, they dominated women's doubles with 14 Grand Slam titles together.","Serena won the 2017 Australian Open while 8 weeks pregnant."],
    es:["Serena Williams es considerada la mejor tenista de todos los tiempos, con 23 títulos de Grand Slam en la era abierta — un récord en categoría individual.","Williams dominó el tenis femenino durante más de dos décadas, transformando el deporte con su potencia atlética y su servicio devastador.","Más allá del deporte, Williams se ha convertido en un icono cultural y empresarial, rompiendo barreras raciales y de género en un deporte históricamente elitista."]},
  'sp019':{fr:["La FIFA compte 211 pays membres — plus que les Nations Unies qui n'en comptent que 193.","La Coupe du Monde 2022 au Qatar a été regardée par 5 milliards de personnes — plus des deux tiers de la population mondiale.","Le football génère plus de 500 milliards de dollars par an — c'est la plus grande industrie sportive au monde."],en:["FIFA has 211 member countries — more than the United Nations with only 193.","The 2022 Qatar World Cup was watched by 5 billion people — over two-thirds of the world's population.","Football generates over $500 billion per year — the world's largest sports industry."],
    es:["El fútbol es el único deporte practicado en todos los países reconocidos por la ONU — la FIFA tiene más países miembros (211) que las Naciones Unidas (193).","La Copa del Mundo de la FIFA es el evento deportivo más visto del planeta: la final de 2022 en Qatar fue seguida por más de 1 500 millones de espectadores.","El fútbol femenino crece exponencialmente: el Mundial femenino de 2023 en Australia atrajo más de 1 900 millones de espectadores acumulados."]},
  'sp020':{fr:["Sam Groth a établi ce record en 2012 lors d'un tournoi Challenger en Corée du Sud.","La balle atteint la raquette adverse en environ 0,4 seconde — le temps de réaction humain moyen est de 0,25 seconde.","Les raquettes modernes en graphite et kevlar permettent des services bien plus rapides que les anciennes en bois."],en:["Sam Groth set this record in 2012 at a Challenger tournament in South Korea.","The ball reaches the opponent's racket in about 0.4 seconds — average human reaction time is 0.25 seconds.","Modern graphite and kevlar rackets allow much faster serves than old wooden ones."],
    es:["El servicio más rápido jamás registrado en tenis fue de 263,4 km/h, logrado por Sam Groth en un challenger en 2012.","A esa velocidad, la pelota cruza los 23,77 metros de la pista en apenas 0,32 segundos — más rápido de lo que un ojo humano puede seguir.","Los avances en materiales de raqueta (grafito, fibra de carbono) han aumentado drásticamente la potencia de los servicios en las últimas décadas."]},
  // === TALES ===
  'tale1':{fr:["Dans la version de Perrault, le loup mange le Chaperon rouge et la grand-mère — pas de chasseur pour les sauver.","Les frères Grimm ont ajouté le chasseur en 1812 pour rendre l'histoire plus acceptable pour les enfants.","Le conte a été interprété comme une métaphore de la puberté et des dangers de la séduction."],en:["In Perrault's version, the wolf eats Red Riding Hood and grandma — no hunter to save them.","The Brothers Grimm added the hunter in 1812 to make the story more acceptable for children.","The tale has been interpreted as a metaphor for puberty and the dangers of seduction."],
    es:["Cenicienta es uno de los cuentos más universales del mundo: más de 500 versiones existen en culturas de todos los continentes, la más antigua es la china Ye Xian (siglo IX).","En la versión de los hermanos Grimm, las hermanastras se cortan los dedos de los pies para que les quepa el zapato — las palomas delatan la sangre y les arrancan los ojos al final.","El zapato de cristal podría ser un error de traducción de Perrault: «verre» (cristal) en lugar de «vair» (piel de ardilla) — un debate que nunca ha sido zanjado definitivamente."]},
  'tale2':{fr:["Les échantillons de poils attribués au Yéti se sont révélés provenir d'ours bruns de l'Himalaya.","Le mythe persiste car l'Himalaya reste l'une des régions les moins explorées de la planète.","Le « Yéti » tibétain signifie littéralement « ours des rochers » — il pourrait s'agir d'un ours rare encore non identifié."],en:["Hair samples attributed to the Yeti turned out to come from Himalayan brown bears.","The myth persists because the Himalayas remain one of the least explored regions on the planet.","The Tibetan 'Yeti' literally means 'rock bear' — it could be a rare unidentified bear."],
    es:["Caperucita Roja es un cuento de advertencia cuyas versiones más antiguas, anteriores a Perrault (1697), terminaban con el lobo devorando a la niña sin rescate posible.","La versión de los Grimm (1812) añadió al cazador que abre el vientre del lobo para salvar a Caperucita y a la abuela — una resolución moral ausente en el original francés.","Los psicoanalistas interpretan el cuento como una alegoría sexual: el lobo representa el depredador masculino y la caperuza roja la transición de la infancia a la pubertad."]},
  'tale3':{fr:["Gilles de Rais était l'un des hommes les plus riches de France au XVe siècle et a été condamné pour le meurtre de dizaines d'enfants.","Le conte a été publié par Perrault en 1697 dans les Contes de ma mère l'Oye.","Barbe-Bleue est aussi interprété comme un avertissement sur la curiosité féminine et les dangers du mariage."],en:["Gilles de Rais was one of France's richest men in the 15th century and was convicted of murdering dozens of children.","The tale was published by Perrault in 1697 in Tales of Mother Goose.","Bluebeard is also interpreted as a warning about female curiosity and marriage dangers."],
    es:["Las fábulas de Esopo (siglo VI a.C.) son las más antiguas y difundidas de Occidente: la tortuga y la liebre, la cigarra y la hormiga, el lobo con piel de cordero.","Esopo era supuestamente un esclavo frigio que obtuvo su libertad gracias a su ingenio — pero su existencia histórica es incierta y muchas fábulas atribuidas a él son posteriores.","La fábula como género moralizante existe en todas las culturas: el Panchatantra indio (200 a.C.) influyó en las fábulas árabes, que a su vez influyeron en las europeas de La Fontaine."]},
  'tale4':{fr:["Le calmar géant peut atteindre 13 mètres de long — assez impressionnant pour inspirer des légendes de monstres marins.","Les marins scandinaves décrivaient le Kraken comme une île flottante capable d'engloutir des navires entiers.","Jules Verne s'est inspiré du Kraken pour la scène du calmar géant dans 20 000 Lieues sous les mers."],en:["The giant squid can reach 13 meters long — impressive enough to inspire sea monster legends.","Scandinavian sailors described the Kraken as a floating island capable of swallowing entire ships.","Jules Verne was inspired by the Kraken for the giant squid scene in 20,000 Leagues Under the Sea."],
    es:["Hansel y Gretel refleja el horror real de las hambrunas medievales europeas, donde el abandono de niños era una práctica documentada durante las crisis alimentarias.","La casa de dulces es una trampa que representa la seducción del exceso: la bruja ofrece abundancia para atraer, engordar y devorar — una metáfora del peligro de la gula y la codicia.","Los Grimm suavizaron el cuento en ediciones sucesivas: en la versión original, era la madre biológica (no la madrastra) quien abandonaba a los niños — demasiado perturbador incluso para el siglo XIX."]},
  'tale5':{fr:["La version chinoise, Ye Xian, date du IXe siècle — 800 ans avant la version de Perrault.","La pantoufle de verre est peut-être une erreur — « vair » (fourrure d'écureuil) aurait été confondu avec « verre ».","Disney a sorti son adaptation en 1950 — le film a sauvé le studio de la faillite."],en:["The Chinese version, Ye Xian, dates from the 9th century — 800 years before Perrault's.","The glass slipper may be an error — 'vair' (squirrel fur) may have been confused with 'verre' (glass).","Disney released its adaptation in 1950 — the film saved the studio from bankruptcy."],
    es:["Las Mil y Una Noches es una compilación de cuentos persas, árabes e indios cuya versión más antigua conocida data del siglo VIII — fue ampliada durante siglos por diferentes narradores.","La estructura de cajas chinas (cuentos dentro de cuentos dentro de cuentos) prefigura la metaficción postmoderna por más de un milenio.","Aladino y Ali Baba, los cuentos más famosos, no figuraban en los manuscritos originales: fueron añadidos por el traductor francés Antoine Galland en 1704 a partir de un cuentista sirio."]},
  'tale6':{fr:["Le moine Saint Columba aurait fait fuir un monstre dans le Loch Ness en faisant le signe de croix.","La photo la plus célèbre du monstre (1934) s'est avérée être un canular — un sous-marin jouet.","Malgré les nombreuses recherches sonar, aucune preuve scientifique n'a jamais été trouvée."],en:["Saint Columba reportedly drove away a Loch Ness monster by making the sign of the cross.","The most famous monster photo (1934) turned out to be a hoax — a toy submarine.","Despite numerous sonar searches, no scientific evidence has ever been found."],
    es:["La Bella y la Bestia fue escrita por primera vez por Gabrielle-Suzanne de Villeneuve en 1740, luego abreviada por Jeanne-Marie Leprince de Beaumont en 1756.","El cuento es una alegoría sobre el matrimonio arreglado: la Bella aprende a amar a un esposo impuesto al descubrir sus cualidades interiores — un mensaje consolador para las jóvenes de la época.","La versión de Disney (1991) fue la primera película de animación nominada al Oscar a la Mejor Película — un logro que elevó el cine de animación a la categoría de arte para todas las edades."]},
  'tale7':{fr:["Dans la version de Giambattista Basile (1634), la Belle est réveillée non par un baiser mais par son propre bébé qui lui suce le doigt.","La version de Basile est beaucoup plus sombre — la Belle endormie est violée par un roi pendant son sommeil.","Disney a adouci l'histoire en 1959 avec le baiser du prince — un changement qui a défini la version populaire moderne."],en:["In Giambattista Basile's version (1634), the Beauty is awakened not by a kiss but by her baby sucking her finger.","Basile's version is much darker — the sleeping Beauty is assaulted by a king during her sleep.","Disney softened the story in 1959 with the prince's kiss — a change that defined the modern popular version."],
    es:["El Gato con Botas de Perrault (1697) es un cuento sobre la astucia y la movilidad social: un gato astuto transforma a su amo pobre en marqués mediante engaños y manipulación.","El cuento celebra la inteligencia práctica sobre la nobleza de nacimiento — un tema subversivo en la Francia absolutista de Luis XIV.","Variantes del gato astuto existen en culturas de todo el mundo: desde el zorro japonés (kitsune) hasta el Anansi africano — el embaucador que usa su ingenio para vencer a los poderosos."]},
  'tale8':{fr:["Les Grimm ont aussi censuré leurs propres contes entre la première édition (1812) et les suivantes pour les rendre plus acceptables.","Blanche-Neige originale voit la méchante reine condamnée à danser avec des chaussures de fer chauffées au rouge.","Les contes des Grimm ont été traduits dans plus de 160 langues — après la Bible, c'est l'un des livres les plus traduits."],en:["The Grimms also censored their own tales between the first edition (1812) and later ones to make them more acceptable.","Original Snow White has the evil queen condemned to dance in red-hot iron shoes.","Grimm tales have been translated into over 160 languages — after the Bible, one of the most translated books."],
    es:["Blancanieves de los Grimm (1812) tiene raíces que podrían remontarse a la historia real de Margarethe von Waldeck, una condesa alemana del siglo XVI envenenada por motivos políticos.","El espejo mágico simboliza la obsesión narcisista por la belleza y la juventud — un tema que resuena hoy tanto como en el siglo XIX.","Los siete enanitos no tenían nombres individuales hasta la película de Disney (1937): Grumpy, Sleepy, Bashful, Happy, Sneezy, Dopey y Doc son creaciones de Hollywood."]},
  'tale9':{fr:["Le Golem était activé en inscrivant le mot « emet » (vérité) sur son front et désactivé en effaçant la première lettre pour former « met » (mort).","Le rabbin Loew aurait créé le Golem pour protéger les Juifs de Prague contre les pogroms.","Le Golem est considéré comme un précurseur des robots et de l'intelligence artificielle dans la littérature."],en:["The Golem was activated by inscribing 'emet' (truth) on its forehead and deactivated by erasing the first letter to form 'met' (death).","Rabbi Loew reportedly created the Golem to protect Prague's Jews from pogroms.","The Golem is considered a precursor to robots and AI in literature."],
    es:["Pinocho, escrito por Carlo Collodi en 1883, era originalmente una historia moralizante y bastante oscura: Pinocho es ahorcado en el capítulo 15 — los lectores exigieron una continuación.","La nariz que crece al mentir no es solo un recurso cómico sino una metáfora de la transparencia: en el mundo del cuento, la mentira es imposible de ocultar.","La versión de Disney (1940) suavizó enormemente la historia: el Pinocho original es desobediente, cruel y violento — un niño que necesita disciplina, no magia."]},
  'tale10':{fr:["Dans la version originale d'Andersen (1837), la sirène se transforme en écume de mer après que le prince en épouse une autre.","Disney a changé la fin en 1989 — Ariel épouse le prince et vit heureuse.","Andersen a écrit ce conte comme une métaphore de son propre amour non partagé pour un homme."],en:["In Andersen's original (1837), the mermaid turns to sea foam after the prince marries another.","Disney changed the ending in 1989 — Ariel marries the prince and lives happily.","Andersen wrote this tale as a metaphor for his own unrequited love for a man."],
    es:["La sirenita de Hans Christian Andersen (1837) no tiene un final feliz: la sirenita no consigue el amor del príncipe y se transforma en espuma de mar en lugar de obtener un alma inmortal.","Andersen escribió el cuento como alegoría de su amor no correspondido por Edvard Collin — el dolor del sacrificio y la transformación refleja su propia experiencia sentimental.","La versión de Disney (1989) cambió el final trágico por un matrimonio feliz — una decisión que transformó una fábula sobre el sufrimiento en una historia de empoderamiento femenino (parcial)."]},
  'tale11':{fr:["Les dragons européens étaient généralement maléfiques, tandis que les dragons asiatiques étaient bienveillants et sages.","Les os de dinosaures découverts dans l'Antiquité ont probablement inspiré certains mythes de dragons.","Le dragon gallois (Y Ddraig Goch) figure sur le drapeau du Pays de Galles depuis le Ve siècle."],en:["European dragons were generally evil, while Asian dragons were benevolent and wise.","Dinosaur bones discovered in antiquity probably inspired some dragon myths.","The Welsh dragon (Y Ddraig Goch) has appeared on the Welsh flag since the 5th century."],
    es:["El patito feo de Andersen (1843) es la historia autobiográfica del propio autor: un niño danés pobre, feo y ridiculizado que se convirtió en el escritor de cuentos más famoso del mundo.","La metáfora de la transformación — de patito rechazado a cisne admirado — es tan poderosa que «patito feo» se ha convertido en expresión universal para describir una transformación positiva.","Andersen sufrió toda su vida de inseguridades y nunca encontró el amor correspondido — sus cuentos más bellos nacieron del dolor y la soledad."]},
  'tale12':{fr:["Robin des Bois volait aux riches pour donner aux pauvres — un archétype de la justice sociale.","Son existence réelle n'a jamais été prouvée — il pourrait être un composite de plusieurs hors-la-loi médiévaux.","La forêt de Sherwood existe toujours dans le Nottinghamshire — elle accueille un festival annuel de Robin des Bois."],en:["Robin Hood stole from the rich to give to the poor — a social justice archetype.","His real existence was never proven — he could be a composite of several medieval outlaws.","Sherwood Forest still exists in Nottinghamshire — hosting an annual Robin Hood festival."],
    es:["Los cuentos de hadas no eran para niños: eran relatos orales para adultos transmitidos durante siglos junto al fuego, llenos de violencia, sexo y crueldad.","Charles Perrault (1697) y los hermanos Grimm (1812) los recopilaron y suavizaron para un público burgués — Disney completó la sanitización en el siglo XX.","Autores como Angela Carter, Neil Gaiman y la serie Once Upon a Time han recuperado la oscuridad original de los cuentos, demostrando que su poder reside en los temas adultos que abordan."]},
  'tale13':{fr:["La première « observation » a été faite par Madelyne Tolentino, qui décrivait une créature bipède avec des épines dorsales.","Des analyses ont montré que les animaux attaqués étaient victimes de chiens sauvages ou de coyotes.","Le Chupacabra a probablement été influencé par le film Species (1995), sorti peu avant les premières observations."],en:["The first 'sighting' was by Madelyne Tolentino, describing a bipedal creature with dorsal spines.","Analyses showed attacked animals were victims of wild dogs or coyotes.","The Chupacabra was probably influenced by the film Species (1995), released shortly before first sightings."],
    es:["Robin Hood, el forajido que robaba a los ricos para dar a los pobres, aparece por primera vez en baladas inglesas del siglo XIII — pero su existencia histórica nunca ha sido probada.","Las primeras versiones lo presentan como un yeoman (campesino libre), no como un noble desposeído — la aristocratización del personaje es posterior.","Robin Hood encarna un arquetipo universal: el rebelde justo que desafía la autoridad corrupta — una figura que reaparece en cada generación, de Zorro a V de Vendetta."]},
  'tale14':{fr:["Collodi a ressuscité Pinocchio dans des chapitres suivants sous la pression des lecteurs — comme Conan Doyle avec Sherlock Holmes.","La Fée bleue joue le rôle de figure maternelle dans le roman complet.","Le livre a été traduit dans plus de 260 langues — le troisième livre le plus traduit au monde après la Bible et le Coran."],en:["Collodi resurrected Pinocchio in later chapters under reader pressure — like Conan Doyle with Sherlock Holmes.","The Blue Fairy plays the maternal figure role in the complete novel.","The book has been translated into over 260 languages — the third most translated book after the Bible and Quran."],
    es:["Rapunzel fue recopilado por los Grimm en 1812, pero versiones similares existen en la tradición persa (Rudaba) y la napolitana (Petrosinella, 1634) desde siglos antes.","La torre sin puerta es un símbolo del encierro femenino y el control parental excesivo — el cabello como escalera representa la conexión prohibida con el mundo exterior.","En la versión original de los Grimm, Rapunzel queda embarazada del príncipe durante sus visitas secretas — un detalle eliminado en ediciones posteriores por considerarse inapropiado."]},
  'tale15':{fr:["La Dame Blanche apparaît souvent sur les routes la nuit et disparaît quand on s'approche.","En France, les dames blanches sont souvent associées à des ponts, des carrefours et des châteaux en ruine.","Les psychologues expliquent ces apparitions par la paréidolie — la tendance du cerveau à voir des formes familières dans le brouillard ou l'obscurité."],en:["The White Lady often appears on roads at night and vanishes when approached.","In France, white ladies are often associated with bridges, crossroads, and ruined castles.","Psychologists explain these sightings through pareidolia — the brain's tendency to see familiar shapes in fog or darkness."],
    es:["La leyenda de la Llorona, presente en toda Latinoamérica, narra la historia de una mujer que ahoga a sus hijos y vaga eternamente llorando y buscándolos.","Sus orígenes podrían remontarse a la diosa azteca Cihuacóatl o a la Malinche — la leyenda fusiona elementos prehispánicos y coloniales.","La Llorona funciona como cuento de advertencia: los niños no deben acercarse al agua de noche, y las mujeres que desobedecen las normas sociales sufren castigos eternos."]},
  'tale16':{fr:["La Grande Famine de 1315-1317 a tué des millions de personnes en Europe — l'abandon d'enfants était une réalité tragique.","La maison en pain d'épices symbolise la tentation de la nourriture en période de famine.","Le conte est aussi interprété comme un récit d'émancipation — les enfants surmontent leurs peurs et triomphent."],en:["The Great Famine of 1315-1317 killed millions in Europe — child abandonment was a tragic reality.","The gingerbread house symbolizes the temptation of food during famine.","The tale is also interpreted as an emancipation story — children overcome fears and triumph."],
    es:["Pedro y el lobo de Prokófiev (1936) fue compuesto como obra pedagógica para enseñar a los niños los instrumentos de la orquesta: cada personaje es representado por un instrumento diferente.","Pedro es la cuerda, el pájaro la flauta, el pato el oboe, el gato el clarinete, el abuelo el fagot, el lobo las trompas y los cazadores los timbales y el bombo.","La obra se ha convertido en una de las piezas de música clásica más interpretadas del mundo y ha sido narrada por celebridades de David Bowie a Sofía Vergara."]},
  'tale17':{fr:["Le Satyricon de Pétrone (Ier siècle) contient l'un des premiers récits de lycanthropie de la littérature.","Au Moyen Âge, des « procès de loups-garous » étaient menés — des personnes accusées étaient torturées et exécutées.","La lycanthropie clinique est un trouble psychiatrique réel où la personne croit se transformer en animal."],en:["Petronius's Satyricon (1st century) contains one of the first lycanthropy accounts in literature.","In the Middle Ages, 'werewolf trials' were conducted — accused persons were tortured and executed.","Clinical lycanthropy is a real psychiatric disorder where a person believes they transform into an animal."],
    es:["El Rey Midas, según la mitología griega, pidió a Dioniso el poder de convertir en oro todo lo que tocara — un deseo que pronto se convirtió en maldición.","No podía comer, beber ni abrazar a su hija sin convertirlos en metal inerte — una parábola sobre la codicia y las consecuencias imprevistas de los deseos materiales.","La expresión «tener el toque de Midas» se usa hoy para describir a alguien que todo lo que toca se convierte en éxito — un uso irónico que olvida el aspecto trágico del mito original."]},
  'tale18':{fr:["Excalibur n'est pas l'épée dans la pierre — c'est l'épée donnée par la Dame du Lac, selon la plupart des versions.","La quête du Graal, ajoutée par Chrétien de Troyes au XIIe siècle, est devenue l'une des histoires les plus racontées du monde occidental.","L'île d'Avalon, lieu de repos d'Arthur, a été associée à Glastonbury en Angleterre — un site de pèlerinage depuis des siècles."],en:["Excalibur isn't the sword in the stone — it's the sword given by the Lady of the Lake in most versions.","The Grail quest, added by Chrétien de Troyes in the 12th century, became one of the Western world's most told stories.","The island of Avalon, Arthur's resting place, has been linked to Glastonbury, England — a pilgrimage site for centuries."],
    es:["Barba Azul de Perrault (1697) narra la historia de un noble que asesina a sus esposas y guarda sus cuerpos en una habitación prohibida.","El cuento es una advertencia sobre la curiosidad femenina (la esposa desobedece la prohibición) pero también una denuncia de la violencia doméstica y el poder masculino sin límites.","Barba Azul tiene paralelos históricos: Gilles de Rais (siglo XV), compañero de Juana de Arco y asesino en serie, y Enrique VIII, que ejecutó a dos de sus seis esposas."]},
  'tale19':{fr:["Kintarō est un héros folklorique japonais associé à la force, au courage et à la bonté.","Il est souvent représenté avec un ours qu'il a vaincu enfant — un symbole de puissance physique.","Les poupées de Kintarō sont offertes aux garçons japonais lors du Kodomo no Hi (jour des enfants) le 5 mai."],en:["Kintarō is a Japanese folk hero associated with strength, courage, and kindness.","He's often depicted with a bear he defeated as a child — a symbol of physical power.","Kintarō dolls are given to Japanese boys during Kodomo no Hi (Children's Day) on May 5th."],
    es:["La tortuga y la liebre de Esopo enseña que la constancia vence al talento cuando el talento se confía demasiado — una de las lecciones más citadas de la literatura universal.","La fábula tiene raíces filosóficas profundas: la paradoja de Zenón sobre Aquiles y la tortuga plantea la imposibilidad teórica de que el rápido alcance al lento, un problema matemático serio.","En el mundo moderno, la fábula se aplica a las carreras profesionales, las startups y el aprendizaje: la persistencia supera al talento natural cuando este carece de disciplina."]},
  'tale20':{fr:["Le triangle ne connaît pas plus d'accidents ou de disparitions que n'importe quelle autre zone maritime de taille similaire.","Les « disparitions mystérieuses » s'expliquent par les tempêtes tropicales, le Gulf Stream et les erreurs de navigation.","Le triangle des Bermudes a été démystifié par la science mais reste l'un des mythes modernes les plus tenaces."],en:["The triangle doesn't experience more accidents or disappearances than any similarly-sized maritime zone.","'Mysterious disappearances' are explained by tropical storms, the Gulf Stream, and navigation errors.","The Bermuda Triangle has been debunked by science but remains one of the most persistent modern myths."],
    es:["Los cuentos de Nasrudín (también Nasreddin o Joha) son fábulas humorísticas de la tradición islámica protagonizadas por un sabio-loco que enseña mediante paradojas y absurdos.","Nasrudín existe en las tradiciones turca, persa, árabe y centroasiática desde el siglo XIII — sus historias se transmiten oralmente y varían según la región.","Sus cuentos funcionan en múltiples niveles: son chistes superficiales para los niños, lecciones morales para los adultos y koans filosóficos para los buscadores espirituales."]},
  // === WORLD ===
  'w1':{fr:["Les cochons d'Inde sont des animaux grégaires qui peuvent mourir de solitude — la loi protège leur bien-être.","La Suisse a aussi interdit les aquariums à poissons rouges isolés pour la même raison.","Le pays a l'une des lois de protection animale les plus strictes au monde."],en:["Guinea pigs are gregarious animals that can die of loneliness — the law protects their wellbeing.","Switzerland also banned solo goldfish bowls for the same reason.","The country has one of the world's strictest animal protection laws."],
    es:["Rusia es tan extensa que abarca 11 husos horarios — cuando amanece en Kaliningrado, ya es de noche en Kamchatka.","Con 17,1 millones de km², su superficie terrestre es ligeramente inferior a la de Plutón (17,6 millones de km²), un dato que sorprende incluso a los geógrafos.","Siberia alberga el lago Baikal, que contiene el 20 % del agua dulce no congelada del planeta y alcanza una profundidad de 1 642 metros."]},
  'w2':{fr:["Le Canada possède environ 31 752 lacs de plus de 3 km² — un nombre inégalé dans le monde.","Le Grand Lac des Esclaves dans les Territoires du Nord-Ouest est si profond (614 m) que la Tour Eiffel y tiendrait debout avec de la marge.","60 % de tous les lacs de la planète se trouvent au Canada — principalement formés par le retrait des glaciers."],en:["Canada has about 31,752 lakes larger than 3 km² — unmatched worldwide.","Great Slave Lake in the Northwest Territories is so deep (614 m) the Eiffel Tower would fit with room to spare.","60% of all the planet's lakes are in Canada — mainly formed by glacial retreat."],
    es:["Islandia es uno de los pocos territorios del mundo sin mosquitos, a pesar de tener abundante agua y veranos relativamente templados.","La razón es climática: las oscilaciones térmicas rápidas y frecuentes de Islandia interrumpen el ciclo reproductivo del mosquito, que necesita aguas estancadas estables.","Islandia tampoco tiene ejército ni reptiles nativos — y su policía rara vez porta armas, dado que el país tiene una de las tasas de criminalidad más bajas del mundo."]},
  'w3':{fr:["Le mariage posthume nécessite l'autorisation du président de la République et la preuve que le couple avait l'intention de se marier.","Le cas le plus célèbre est celui d'une femme qui a épousé son compagnon décédé dans un accident en 2009.","Le conjoint survivant hérite des droits normaux du mariage, y compris le nom et la pension."],en:["Posthumous marriage requires the president's authorization and proof the couple intended to marry.","The most famous case was a woman who married her partner killed in an accident in 2009.","The surviving spouse inherits normal marriage rights, including the name and pension."],
    es:["Suiza obliga por ley a tener al menos dos cobayas si se posee una — un animal gregario no puede vivir solo sin sufrir estrés psicológico.","Esta ley de 2008 forma parte de una de las legislaciones de protección animal más estrictas del mundo, que también prohíbe los anzuelos vivos para la pesca.","Existe incluso un servicio de «alquiler de cobayas» en Suiza para propietarios cuya compañera ha muerto, evitando un ciclo infinito de compras."]},
  'w4':{fr:["La Lune a un diamètre de 3 474 km, tandis que l'Australie s'étend sur 4 000 km d'est en ouest.","L'Australie est aussi le seul pays qui est un continent entier.","Si l'Australie était en Europe, elle s'étendrait de Londres à Moscou."],en:["The Moon has a diameter of 3,474 km, while Australia spans 4,000 km east to west.","Australia is also the only country that is an entire continent.","If Australia were in Europe, it would stretch from London to Moscow."],
    es:["Canadá posee más lagos que todos los demás países del mundo juntos: unos 879 800, que cubren el 9 % de su superficie.","El Gran Lago de los Esclavos, en los Territorios del Noroeste, es tan profundo (614 m) que podría sumergir la Torre Eiffel con espacio de sobra.","Canadá tiene la costa más larga del mundo (243 000 km) y una densidad de población tan baja que la mayoría de sus habitantes viven a menos de 150 km de la frontera estadounidense."]},
  'w5':{fr:["Quand il est midi à Moscou, il est déjà 21h à Petropavlovsk-Kamchatsky, à l'extrême est.","La Russie couvre 17,1 millions de km² — plus de 30 fois la superficie de la France.","Le Transsibérien traverse tout le pays en 6 jours sur 9 289 km — le plus long trajet ferroviaire au monde."],en:["When it's noon in Moscow, it's already 9 PM in Petropavlovsk-Kamchatsky in the far east.","Russia covers 17.1 million km² — over 30 times the area of France.","The Trans-Siberian crosses the entire country in 6 days over 9,289 km — the world's longest railway journey."],
    es:["Noruega tiene más de 1 000 fiordos, valles glaciares inundados por el mar que pueden alcanzar profundidades de más de 1 300 metros.","El fiordo de Sogn, el más largo de Noruega (204 km), es también el más profundo de Europa — sus acantilados verticales se elevan hasta 1 700 m sobre el agua.","Los fiordos se formaron durante las glaciaciones del Pleistoceno, cuando glaciares de kilómetros de espesor erosionaron valles en forma de U que el mar inundó al retirarse el hielo."]},
  'w6':{fr:["Le drapeau népalais est composé de deux triangles superposés représentant l'Himalaya et les deux religions principales du pays.","Le soleil et la lune sur le drapeau symbolisent l'espoir que le Népal durera aussi longtemps que ces astres.","Le Népal est le seul pays au monde dont le drapeau n'est pas un quadrilatère."],en:["The Nepalese flag consists of two overlapping triangles representing the Himalayas and the country's two main religions.","The sun and moon on the flag symbolize hope that Nepal will last as long as these celestial bodies.","Nepal is the only country whose flag is not a quadrilateral."],
    es:["Australia es el único país que es también un continente, con una superficie de 7,7 millones de km² — casi tan grande como Europa.","El interior australiano, conocido como Outback, es tan árido y despoblado que la densidad de población del país es de apenas 3 habitantes por km².","Australia alberga 21 de las 25 serpientes más venenosas del mundo, así como arañas, medusas y pulpos letales — pero los ataques mortales son sorprendentemente raros."]},
  'w7':{fr:["Don Featherstone a inventé le flamant rose en plastique en 1957 — il est devenu un symbole du kitsch américain.","On estime qu'il y a environ 10 millions de flamants roses en plastique et seulement 3 millions de vrais.","Le flamant rose en plastique a été désigné oiseau officiel de la ville de Madison, Wisconsin en 2009."],en:["Don Featherstone invented the plastic flamingo in 1957 — it became a symbol of American kitsch.","An estimated 10 million plastic flamingos exist versus only 3 million real ones.","The plastic flamingo was designated the official bird of Madison, Wisconsin in 2009."],
    es:["El río Amazonas transporta más agua que los siguientes siete ríos más caudalosos del mundo juntos — su caudal medio es de 209 000 m³ por segundo.","Su cuenca hidrográfica cubre 6,9 millones de km², casi el tamaño de Australia, y alberga el 10 % de todas las especies conocidas del planeta.","La desembocadura del Amazonas es tan amplia que la isla de Marajó, situada en ella, es más grande que Suiza."]},
  'w8':{fr:["La surface de la Russie (17,1 millions km²) dépasse celle de Pluton (16,7 millions km²).","La Russie est si grande que sa partie orientale est plus proche de l'Alaska que de Moscou.","Il y a 9 heures de décalage horaire entre les deux extrémités de la Russie."],en:["Russia's surface (17.1 million km²) exceeds Pluto's (16.7 million km²).","Russia is so large its eastern part is closer to Alaska than to Moscow.","There's a 9-hour time difference between Russia's two extremities."],
    es:["El Vaticano, con 0,44 km² y unos 800 habitantes, es el estado independiente más pequeño del mundo — cabe entero dentro del Coliseo romano.","A pesar de su tamaño, tiene su propia oficina de correos, estación de radio, periódico, ferrocarril (300 m de vías) y fuerza de seguridad (la Guardia Suiza).","El Vaticano genera ingresos a través de los museos (6 millones de visitantes al año), sellos postales, publicaciones y donaciones de los 1 400 millones de católicos del mundo."]},
  'w9':{fr:["Les scientifiques pensent que le vent islandais est trop fort pour les moustiques et les températures trop instables.","L'Antarctique n'a pas non plus de moustiques — ce sont les deux seuls endroits sans moustiques.","L'Islande a aussi très peu d'arbres — les Vikings les ont presque tous coupés en arrivant."],en:["Scientists think Icelandic wind is too strong for mosquitoes and temperatures too unstable.","Antarctica also has no mosquitoes — they're the only two places without them.","Iceland also has very few trees — Vikings cut nearly all of them when they arrived."],
    es:["La Antártida es el continente más frío, más seco, más ventoso y más elevado de la Tierra — su altitud media supera los 2 300 metros.","Contiene el 70 % del agua dulce del planeta en forma de hielo: si se derritiera por completo, el nivel del mar subiría unos 60 metros.","A pesar de las temperaturas extremas (récord de −89,2 °C), la Antártida alberga vida: pingüinos, focas, krill y más de 1 000 especies de hongos y líquenes."]},
  'w10':{fr:["Les lapins descendent d'animaux de laboratoire libérés par les soldats japonais à la fin de la Seconde Guerre mondiale.","L'île avait été utilisée comme site de production d'armes chimiques — un passé sombre gardé secret pendant des décennies.","Aujourd'hui, plus de 1 000 lapins vivent librement sur l'île et attirent des touristes du monde entier."],en:["The rabbits descend from lab animals released by Japanese soldiers at the end of WWII.","The island was used as a chemical weapons production site — a dark past kept secret for decades.","Today, over 1,000 rabbits live freely on the island, attracting tourists from around the world."],
    es:["El Mar Muerto, situado entre Israel, Palestina y Jordania, es el punto más bajo de la superficie terrestre, a 430 metros bajo el nivel del mar.","Su salinidad (34 %) es casi 10 veces la del océano, lo que permite flotar sin esfuerzo — pero también impide toda forma de vida macroscópica.","El Mar Muerto se encoge unos 1,2 metros por año debido a la desviación de sus afluentes para riego — podría desaparecer por completo antes de 2050 si no se toman medidas."]},
  'w11':{fr:["Doublement enclavé signifie entouré par un pays qui est lui-même enclavé — sans accès à la mer.","Le Liechtenstein est entouré par la Suisse et l'Autriche, tous deux sans façade maritime.","L'Ouzbékistan est entouré par le Kazakhstan, le Kirghizistan, le Tadjikistan, l'Afghanistan et le Turkménistan — tous enclavés."],en:["Doubly landlocked means surrounded by countries that are themselves landlocked — no sea access.","Liechtenstein is surrounded by Switzerland and Austria, both without coastline.","Uzbekistan is surrounded by Kazakhstan, Kyrgyzstan, Tajikistan, Afghanistan, and Turkmenistan — all landlocked."],
    es:["Japón está compuesto por 6 852 islas, pero el 97 % de su población vive en las cuatro principales: Honshū, Hokkaidō, Kyūshū y Shikoku.","Japón experimenta unos 1 500 terremotos perceptibles al año y está situado en el «Cinturón de Fuego del Pacífico», donde convergen cuatro placas tectónicas.","La cultura japonesa del preparacionismo ante desastres es ejemplar: los edificios modernos son antisísmicos y los simulacros de evacuación se practican desde la infancia."]},
  'w12':{fr:["Les territoires d'outre-mer couvrent tous les océans : Pacifique, Atlantique, Indien et Antarctique.","Grâce à ses territoires, la France possède la deuxième plus grande zone économique exclusive maritime au monde.","Si on additionne tous les territoires français, le soleil ne se couche jamais sur la France."],en:["Overseas territories cover all oceans: Pacific, Atlantic, Indian, and Antarctic.","Thanks to its territories, France has the world's second-largest exclusive maritime economic zone.","If you add all French territories, the sun never sets on France."],
    es:["El desierto del Sahara es el desierto cálido más grande del mundo, con 9,2 millones de km² — casi tan grande como Estados Unidos.","Hace apenas 6 000 años, el Sahara era verde y fértil, con ríos, lagos y una fauna abundante — un periodo conocido como el «Sahara verde» o «periodo húmedo africano».","Solo el 25 % del Sahara está cubierto de dunas de arena (erg): el resto es roca (hamada), grava (reg) y mesetas — la imagen del desierto de arena infinita es una simplificación."]},
  'w13':{fr:["La Mongolie a une superficie de 1,6 million de km² pour seulement 3,3 millions d'habitants.","La tradition nomade mongole explique cette faible densité — une grande partie de la population vit encore sous des yourtes.","Oulan-Bator est la capitale la plus froide du monde avec une température moyenne annuelle de -1,3 °C."],en:["Mongolia covers 1.6 million km² with only 3.3 million inhabitants.","Mongolian nomadic tradition explains this low density — much of the population still lives in yurts.","Ulaanbaatar is the world's coldest capital with an average annual temperature of -1.3°C."],
    es:["El monte Everest, con 8 849 metros, es la montaña más alta del mundo medida desde el nivel del mar — pero no la más alta desde su base.","Ese honor corresponde al Mauna Kea en Hawái: mide 10 203 metros desde su base submarina, aunque solo 4 207 m sobresalen del agua.","Más de 6 000 personas han alcanzado la cima del Everest desde la primera ascensión de Hillary y Tenzing en 1953 — pero más de 300 han muerto en el intento."]},
  'w14':{fr:["En Suède, il existe un village appelé « Y » — les noms courts sont courants en Scandinavie.","Le nom de lieu le plus long du monde est au Pays de Galles : Llanfairpwllgwyngyllgogerychwyrndrobwllllantysiliogogogoch (58 lettres).","La ville thaïlandaise de Bangkok a un nom officiel de 168 lettres en thaï."],en:["In Sweden, there's a village called 'Y' — short names are common in Scandinavia.","The world's longest place name is in Wales: Llanfairpwllgwyngyllgogerychwyrndrobwllllantysiliogogogoch (58 letters).","Bangkok's official name in Thai has 168 letters."],
    es:["Venecia está construida sobre 118 pequeñas islas conectadas por más de 400 puentes, en una laguna del mar Adriático.","La ciudad se hunde gradualmente (1-2 mm/año) mientras el nivel del mar sube — el sistema de barreras MOSE, inaugurado en 2020, protege la laguna de las inundaciones.","Venecia fue durante siglos una potencia marítima y comercial que rivalizaba con el Imperio Bizantino y controlaba las rutas comerciales entre Europa y Oriente."]},
  'w15':{fr:["Le lac Baïkal est aussi le lac le plus ancien du monde — environ 25 millions d'années.","Il contient environ 23 000 km³ d'eau douce — plus que les cinq Grands Lacs nord-américains réunis.","Plus de 2 500 espèces animales y vivent, dont 80 % n'existent nulle part ailleurs sur Terre."],en:["Lake Baikal is also the world's oldest lake — about 25 million years.","It contains about 23,000 km³ of fresh water — more than all five North American Great Lakes combined.","Over 2,500 animal species live there, 80% of which exist nowhere else on Earth."],
    es:["La Gran Barrera de Coral australiana es la mayor estructura biológica del planeta: se extiende más de 2 300 km y es visible desde el espacio.","Está compuesta por más de 2 900 arrecifes individuales y alberga 1 500 especies de peces, 400 tipos de coral y 4 000 especies de moluscos.","El blanqueamiento masivo causado por el calentamiento del agua amenaza gravemente su supervivencia — episodios en 2016, 2017, 2020 y 2024 han afectado a más del 60 % de los corales."]},
  'w16':{fr:["Le mont Chimborazo mesure 6 263 m d'altitude, soit 2 585 m de moins que l'Everest.","Mais le renflement équatorial de la Terre fait que son sommet est 2 163 m plus éloigné du centre de la Terre que celui de l'Everest.","Si on mesure depuis le centre de la Terre, le Chimborazo est le point le plus haut de la planète."],en:["Mount Chimborazo is 6,263 m altitude, 2,585 m less than Everest.","But Earth's equatorial bulge makes its summit 2,163 m farther from Earth's center than Everest's.","Measured from Earth's center, Chimborazo is the planet's highest point."],
    es:["Finlandia es el país con más saunas per cápita del mundo: unas 3,3 millones para 5,5 millones de habitantes — más saunas que coches.","El sauna finlandés no es un lujo sino una parte integral de la cultura: históricamente, las mujeres daban a luz en saunas y los difuntos eran preparados allí para el entierro.","En 2020, la tradición del sauna finlandés fue inscrita en la lista del Patrimonio Cultural Inmaterial de la UNESCO."]},
  'w17':{fr:["Quito est à 2 850 m d'altitude — la deuxième capitale la plus haute du monde après La Paz (3 640 m).","L'air est 30 % moins dense à cette altitude — les sportifs doivent s'acclimater avant de performer.","L'Équateur tire son nom de la ligne de l'équateur qui traverse le pays — un monument marque l'emplacement exact."],en:["Quito is at 2,850 m altitude — the second-highest capital after La Paz (3,640 m).","Air is 30% less dense at this altitude — athletes must acclimatize before performing.","Ecuador takes its name from the equator line crossing the country — a monument marks the exact location."],
    es:["Bolivia tiene dos capitales: Sucre (capital constitucional y sede del poder judicial) y La Paz (sede del gobierno y del poder legislativo).","La Paz, a 3 640 m de altitud, es la capital administrativa más alta del mundo — y su aeropuerto internacional de El Alto, a 4 061 m, es uno de los más elevados del planeta.","El Salar de Uyuni boliviano, el mayor desierto de sal del mundo (10 582 km²), contiene la mayor reserva mundial de litio, mineral esencial para las baterías de vehículos eléctricos."]},
  'w18':{fr:["La Gambie mesure seulement 48 km de large à son point le plus large — elle suit le cours du fleuve Gambie.","Les deux pays partagent une frontière de 740 km malgré la petite taille de la Gambie.","La Gambie a brièvement formé une confédération avec le Sénégal appelée Sénégambie entre 1982 et 1989."],en:["The Gambia is only 48 km wide at its widest point — it follows the Gambia River.","The two countries share a 740 km border despite The Gambia's small size.","The Gambia briefly formed a confederation with Senegal called Senegambia between 1982 and 1989."],
    es:["Etiopía utiliza un calendario propio de 13 meses (12 de 30 días más uno de 5 o 6 días) que lleva entre 7 y 8 años de retraso respecto al gregoriano.","Etiopía es también la cuna del café: según la leyenda, un pastor llamado Kaldi observó que sus cabras se ponían hiperactivas tras comer bayas de un arbusto.","Addis Abeba, su capital, significa «nueva flor» en amárico y alberga la sede de la Unión Africana — es considerada la capital diplomática de África."]},
  'w19':{fr:["L'Antarctique reçoit moins de 166 mm de précipitations par an — moins que le Sahara.","Il contient 70 % de l'eau douce de la planète sous forme de glace.","Si toute la glace antarctique fondait, le niveau des mers s'élèverait d'environ 58 mètres."],en:["Antarctica receives less than 166 mm of precipitation per year — less than the Sahara.","It contains 70% of the planet's fresh water in the form of ice.","If all Antarctic ice melted, sea levels would rise about 58 meters."],
    es:["Bután mide su prosperidad no por el PIB sino por el Índice de Felicidad Nacional Bruta, un concepto introducido por el rey Jigme Singye Wangchuck en 1972.","Bután es el único país del mundo con un balance de carbono negativo: sus bosques absorben más CO₂ del que emite todo el país.","El turismo está regulado mediante una tarifa diaria mínima de 200 dólares por visitante, lo que limita el turismo de masas y financia servicios públicos gratuitos como la sanidad y la educación."]},
  'w20':{fr:["La mer Morte est si salée (33,7 %) que pratiquement aucun organisme ne peut y vivre — d'où son nom.","Son niveau baisse d'environ 1 mètre par an à cause de l'évaporation et du détournement du Jourdain.","La boue de la mer Morte est utilisée depuis l'Antiquité pour ses propriétés thérapeutiques — Cléopâtre l'utilisait déjà."],en:["The Dead Sea is so salty (33.7%) that virtually no organisms can live in it — hence the name.","Its level drops about 1 meter per year due to evaporation and Jordan River diversion.","Dead Sea mud has been used since antiquity for therapeutic properties — Cleopatra already used it."],
    es:["Mongolia es el país con menor densidad de población del mundo: apenas 2 habitantes por km² en un territorio de 1,5 millones de km².","La tradición nómada sigue viva: un tercio de la población vive en ger (yurtas) y se desplaza estacionalmente con sus rebaños de caballos, yaks y ovejas.","La capital Ulán Bator es la más fría del mundo, con temperaturas invernales que alcanzan los −40 °C, y concentra casi la mitad de la población del país."]}
};
// === EPHEMERIS DEEP DIVES (e001-e366) ===
Object.assign(DEEP_DIVES, {
'e001': {
  fr:["L'effet Mpemba a été redécouvert en 1963 par Erasto Mpemba, un lycéen tanzanien qui observa que son mélange de glace chaud gelait plus vite que celui de ses camarades.","Plusieurs théories tentent d'expliquer ce phénomène : évaporation, convection, liaisons hydrogène — mais aucune n'a fait consensus en physique.","En 2020, une étude a proposé que les liaisons hydrogène de l'eau chaude stockent moins d'énergie, accélérant le refroidissement — un résultat encore débattu."],
  en:["The Mpemba effect was rediscovered in 1963 by Erasto Mpemba, a Tanzanian high schooler who noticed his hot ice cream mix froze faster than his classmates' cold one.","Several theories attempt to explain this phenomenon: evaporation, convection, hydrogen bonds — but none has reached consensus in physics.","In 2020, a study proposed that hydrogen bonds in hot water store less energy, speeding up cooling — a result still debated."],
    es:["El efecto Mpemba describe cómo el agua caliente puede congelarse más rápido que la fría en ciertas condiciones — un fenómeno que Aristóteles ya mencionó hace 2 300 años.","Las explicaciones propuestas incluyen la evaporación (el agua caliente pierde masa), la convección (corrientes internas más activas) y la menor concentración de gases disueltos.","A pesar de siglos de observación, el efecto Mpemba sigue sin explicación definitiva: un estudio de 2020 en Nature sugiere que depende de las condiciones iniciales precisas del agua."]
},
'e002': {
  fr:["La matière noire ne réfléchit, n'absorbe ni n'émet de lumière — on ne la détecte que par ses effets gravitationnels sur la matière visible.","Fritz Zwicky a proposé l'existence de la matière noire dès 1933 en observant que les galaxies de l'amas de Coma se déplaçaient trop vite pour être retenues par la masse visible seule.","Le détecteur souterrain XENON1T, situé sous les Apennins italiens, cherche la matière noire à 1 400 mètres sous terre pour éviter les interférences cosmiques."],
  en:["Dark matter does not reflect, absorb, or emit light — it is only detected through its gravitational effects on visible matter.","Fritz Zwicky proposed the existence of dark matter as early as 1933, observing that galaxies in the Coma Cluster moved too fast to be held together by visible mass alone.","The underground XENON1T detector, located beneath the Apennine mountains in Italy, searches for dark matter 1,400 metres below ground to avoid cosmic interference."],
    es:["La materia oscura constituye el 27 % del universo pero nunca ha sido observada directamente — solo se detecta por su efecto gravitatorio sobre la materia visible.","Si pudiéramos convertir materia oscura en energía según E=mc², un solo gramo liberaría una cantidad de energía suficiente para abastecer una ciudad durante años.","Detectores como el LUX-ZEPLIN (en una mina de Dakota del Sur) y el XENON1T (bajo los Apeninos italianos) buscan partículas de materia oscura sin éxito hasta la fecha."]
},
'e003': {
  fr:["Les baleines exploitent ce phénomène : leur chant peut être entendu à plus de 1 600 km de distance grâce à la propagation efficace du son sous l'eau.","Il existe un canal acoustique naturel dans l'océan, appelé canal SOFAR, où le son peut voyager sur des milliers de kilomètres sans se dissiper.","Le son ne peut pas du tout se propager dans le vide spatial — les explosions dans les films de science-fiction seraient en réalité totalement silencieuses."],
  en:["Whales exploit this phenomenon: their songs can be heard over 1,600 km away thanks to efficient underwater sound propagation.","There is a natural acoustic channel in the ocean, called the SOFAR channel, where sound can travel thousands of kilometres without dissipating.","Sound cannot propagate at all in the vacuum of space — explosions in sci-fi films would actually be completely silent."],
    es:["El sonido viaja a 1 480 m/s en el agua, frente a 343 m/s en el aire, porque las moléculas de agua están mucho más juntas y transmiten las vibraciones más eficientemente.","Las ballenas aprovechan esta propiedad: sus cantos pueden recorrer miles de kilómetros bajo el agua, un sistema de comunicación a larga distancia sin equivalente terrestre.","En los sólidos, el sonido viaja aún más rápido: en el acero alcanza los 5 960 m/s — casi 18 veces más rápido que en el aire."]
},
'e004': {
  fr:["Les glaciers et icebergs les plus purs apparaissent d'un bleu intense car toutes les bulles d'air ont été compressées hors de la glace.","La neige paraît blanche parce que ses cristaux diffusent toutes les longueurs d'onde de la lumière — contrairement à la glace compacte qui filtre le rouge.","Certains glaciers en Antarctique présentent des stries vert émeraude, causées par des oxydes de fer piégés dans la glace marine."],
  en:["The purest glaciers and icebergs appear deep blue because all air bubbles have been compressed out of the ice.","Snow appears white because its crystals scatter all wavelengths of light — unlike compact ice, which filters out red.","Some Antarctic glaciers display emerald green streaks, caused by iron oxides trapped in marine ice."],
    es:["El hielo absorbe selectivamente las longitudes de onda rojas y amarillas del espectro visible, dejando pasar el azul — por eso los glaciares y los icebergs tienen tonos azulados.","Este efecto solo es visible en grandes masas de hielo puro: los cubitos de hielo domésticos parecen blancos porque las burbujas de aire atrapadas dispersan la luz en todas direcciones.","El azul de los glaciares es el mismo fenómeno que explica el color del cielo: la dispersión de Rayleigh favorece las longitudes de onda cortas (azules) sobre las largas (rojas)."]
},
'e005': {
  fr:["Le fer de votre hémoglobine et l'or de vos bijoux ont été créés au même endroit : dans l'explosion de supernovae massives.","L'hydrogène de l'eau que vous buvez est le seul élément de votre corps qui ne vient pas d'une étoile — il date du Big Bang lui-même.","Le calcium de vos os a été forgé dans des supernovae il y a plus de 5 milliards d'années, bien avant la formation du Soleil."],
  en:["The iron in your haemoglobin and the gold in your jewellery were created in the same place: inside massive supernovae.","The hydrogen in the water you drink is the only element in your body that didn't come from a star — it dates back to the Big Bang itself.","The calcium in your bones was forged in supernovae over 5 billion years ago, long before the Sun formed."],
    es:["Casi todos los elementos de tu cuerpo más pesados que el hidrógeno y el helio fueron forjados en el núcleo de estrellas por fusión nuclear o en explosiones de supernovas.","El calcio de tus huesos, el hierro de tu sangre y el oxígeno que respiras fueron sintetizados en estrellas que explotaron hace miles de millones de años — somos literalmente polvo de estrellas.","Carl Sagan popularizó esta idea con la frase «somos materia estelar que se contempla a sí misma» — una verdad científica que conecta la astrofísica con la filosofía."]
},
'e006': {
  fr:["Un seul orage peut libérer autant d'énergie qu'une bombe atomique de 20 kilotonnes — répartie sur des milliers d'éclairs.","La Terre est frappée par environ 100 éclairs par seconde, soit plus de 8 millions par jour.","Le Venezuela possède un endroit unique, le lac Maracaibo, où des éclairs frappent 300 nuits par an — le record mondial."],
  en:["A single thunderstorm can release as much energy as a 20-kiloton atomic bomb — spread across thousands of strikes.","Earth is struck by about 100 lightning bolts per second, or more than 8 million per day.","Venezuela has a unique spot, Lake Maracaibo, where lightning strikes 300 nights a year — a world record."],
    es:["Un rayo alcanza unos 30 000 K (cinco veces la temperatura de la superficie solar), pero dura tan poco tiempo (microsegundos) que la energía total liberada es relativamente modesta.","El aire sobrecalentado por el rayo se expande a velocidad supersónica, creando la onda de choque que percibimos como trueno — el sonido tarda en llegar porque viaja a 343 m/s.","La Tierra recibe unos 100 rayos por segundo (8,6 millones al día) — los rayos fijan nitrógeno atmosférico en el suelo, un fertilizante natural que beneficia a los ecosistemas."]
},
'e007': {
  fr:["L'hélium superfluide, à des températures proches du zéro absolu, peut grimper le long des parois d'un récipient et s'en échapper tout seul.","L'hélium est si léger qu'il s'échappe constamment de l'atmosphère terrestre — la quasi-totalité de l'hélium utilisé provient de gisements souterrains de gaz naturel.","L'hélium-3, un isotope rare, est abondant sur la Lune et pourrait théoriquement servir de carburant pour la fusion nucléaire."],
  en:["Superfluid helium, at temperatures near absolute zero, can climb the walls of a container and escape on its own.","Helium is so light it constantly escapes Earth's atmosphere — nearly all helium used comes from underground natural gas deposits.","Helium-3, a rare isotope, is abundant on the Moon and could theoretically serve as fuel for nuclear fusion."],
    es:["El helio permanece líquido incluso a 0 kelvin (−273,15 °C) a presión atmosférica normal — es el único elemento con esta propiedad, debida a su masa atómica extremadamente baja y a efectos cuánticos.","A temperaturas cercanas al cero absoluto, el helio se convierte en superfluido: fluye sin fricción, trepa por las paredes de los recipientes y atraviesa poros microscópicos.","El helio terrestre proviene de la desintegración radiactiva del uranio y el torio en la corteza — una vez liberado a la atmósfera, escapa al espacio, lo que lo convierte en un recurso no renovable."]
},
'e008': {
  fr:["Le cerveau consomme environ 20 % de l'énergie du corps alors qu'il ne représente que 2 % de sa masse.","Même au repos, le cerveau brûle environ 5,6 mg de glucose par minute — les neurones ne s'arrêtent jamais de fonctionner.","Les signaux nerveux voyagent dans le cerveau à des vitesses allant de 1 à 120 m/s selon le type de fibre nerveuse."],
  en:["The brain consumes about 20% of the body's energy despite making up only 2% of its mass.","Even at rest, the brain burns about 5.6 mg of glucose per minute — neurons never stop firing.","Nerve signals travel through the brain at speeds ranging from 1 to 120 m/s depending on the type of nerve fibre."],
    es:["El cerebro humano consume unos 23 vatios de energía, el 20 % del total corporal, a pesar de representar solo el 2 % de la masa del cuerpo.","Esta energía proviene casi exclusivamente de la glucosa: el cerebro necesita unos 120 gramos al día, y una caída de glucemia afecta rápidamente a la concentración y el estado de ánimo.","Un superordenador que igualara la capacidad de procesamiento del cerebro necesitaría del orden de un megavatio — unas 40 000 veces más energía que nuestro cerebro biológico."]
},
'e009': {
  fr:["Si le Soleil s'éteignait soudainement, nous continuerions à le voir briller pendant plus de 8 minutes — et à ressentir sa gravité pendant le même temps.","La lumière du Soleil qui nous éclaire a été créée dans le noyau solaire il y a entre 10 000 et 170 000 ans — elle met tout ce temps à atteindre la surface.","La lumière de l'étoile la plus proche après le Soleil, Proxima du Centaure, met 4,24 ans pour nous parvenir."],
  en:["If the Sun suddenly went out, we would continue to see it shining for over 8 minutes — and feel its gravity for the same duration.","The sunlight illuminating us was created in the solar core between 10,000 and 170,000 years ago — it takes that long to reach the surface.","Light from the nearest star after the Sun, Proxima Centauri, takes 4.24 years to reach us."],
    es:["La luz viaja a 299 792 km/s en el vacío, pero tarda 8 minutos y 20 segundos en recorrer los 150 millones de km que separan el Sol de la Tierra.","Esto significa que siempre vemos el Sol como era hace 8 minutos: si se apagara, no lo sabríamos hasta pasado ese tiempo — un concepto que ilustra la velocidad finita de la información.","La luz tarda 1,3 segundos en llegar a la Luna, 4,2 años en llegar a la estrella más cercana (Próxima Centauri) y más de 2 millones de años en llegar a la galaxia de Andrómeda."]
},
'e010': {
  fr:["Si l'on mettait bout à bout l'ADN de toutes les cellules d'un corps humain, le fil atteindrait Pluton et reviendrait — plusieurs fois.","L'ADN humain partage environ 60 % de ses gènes avec celui de la banane et 98,7 % avec celui du chimpanzé.","Chaque jour, chacune de vos cellules subit entre 10 000 et 100 000 lésions d'ADN, la plupart réparées automatiquement par des enzymes."],
  en:["If you lined up the DNA from every cell in a human body, the strand would reach Pluto and back — several times.","Human DNA shares about 60% of its genes with a banana and 98.7% with a chimpanzee.","Every day, each of your cells suffers between 10,000 and 100,000 DNA lesions, most automatically repaired by enzymes."],
    es:["El ADN de una sola célula humana mide unos 2 metros desenrollado, pero cabe en un núcleo celular de apenas 6 micrómetros gracias a un empaquetamiento extraordinariamente eficiente.","Si uniéramos el ADN de todas las células de un cuerpo humano (37 billones de células), obtendríamos un hilo de unos 74 000 millones de km — suficiente para ir al Sol y volver 250 veces.","El ADN humano tiene 3 200 millones de pares de bases, pero solo el 1-2 % codifica proteínas: el resto, antes llamado «ADN basura», cumple funciones reguladoras cada vez más comprendidas."]
},
'e011': {
  fr:["Le séisme de 2011 au Japon a raccourci la durée du jour terrestre de 1,8 microseconde en redistribuant la masse de la planète.","Les séismes peuvent aussi modifier l'axe de rotation de la Terre — celui de 2004 à Sumatra l'a déplacé d'environ 7 cm.","La Terre n'a pas toujours tourné à la même vitesse : il y a 400 millions d'années, un jour ne durait que 22 heures."],
  en:["The 2011 Japan earthquake shortened Earth's day by 1.8 microseconds by redistributing the planet's mass.","Earthquakes can also shift Earth's rotation axis — the 2004 Sumatra quake moved it by about 7 cm.","Earth hasn't always spun at the same speed: 400 million years ago, a day lasted only 22 hours."],
    es:["Los grandes terremotos redistribuyen la masa terrestre, acercándola al eje de rotación — como un patinador que recoge los brazos, la Tierra gira más rápido.","El terremoto de Japón de 2011 (magnitud 9,1) acortó el día en 1,8 microsegundos y desplazó el eje terrestre unos 17 cm — efectos minúsculos pero medibles con relojes atómicos.","A largo plazo, las mareas lunares frenan la rotación terrestre: los días se alargan unos 2,3 milisegundos por siglo — hace 620 millones de años, un día duraba solo 21 horas."]
},
'e012': {
  fr:["Les neutrinos sont si difficiles à détecter qu'il faudrait un mur de plomb d'un année-lumière d'épaisseur pour en arrêter la moitié.","On distingue trois types de neutrinos — électronique, muonique et tauique — et ils peuvent se transformer d'un type à l'autre en vol.","Le détecteur Super-Kamiokande au Japon contient 50 000 tonnes d'eau ultra-pure et 11 000 capteurs pour piéger les rares interactions de neutrinos."],
  en:["Neutrinos are so hard to detect that you would need a lead wall one light-year thick to stop half of them.","There are three types of neutrinos — electron, muon, and tau — and they can morph from one type to another in flight.","The Super-Kamiokande detector in Japan holds 50,000 tonnes of ultra-pure water and 11,000 sensors to catch rare neutrino interactions."],
    es:["Los neutrinos son partículas subatómicas casi sin masa que interactúan tan débilmente con la materia que pueden atravesar la Tierra entera sin chocar con nada.","Cada segundo, unos 100 000 millones de neutrinos solares cruzan cada cm² de tu cuerpo — pero la probabilidad de que uno interactúe con un átomo tuyo es prácticamente nula.","Detectarlos requiere instalaciones gigantescas como Super-Kamiokande (Japón): 50 000 toneladas de agua ultra-pura rodeadas de 11 000 fotomultiplicadores esperando un destello ocasional."]
},
'e013': {
  fr:["Le mot « ozone » vient du grec ozein, qui signifie « sentir » — une référence directe à son odeur caractéristique.","La couche d'ozone stratosphérique, à 15-35 km d'altitude, absorbe environ 97 % des rayons ultraviolets nocifs du Soleil.","Le trou de la couche d'ozone au-dessus de l'Antarctique se referme lentement grâce au Protocole de Montréal de 1987, qui a interdit les CFC."],
  en:["The word 'ozone' comes from Greek ozein, meaning 'to smell' — a direct reference to its distinctive odour.","The stratospheric ozone layer, at 15–35 km altitude, absorbs about 97% of the Sun's harmful ultraviolet rays.","The ozone hole over Antarctica is slowly closing thanks to the 1987 Montreal Protocol, which banned CFCs."],
    es:["El ozono (O₃) tiene un olor penetrante y fresco que se percibe tras las tormentas: los rayos descomponen las moléculas de O₂ y los átomos libres se recombinan como O₃.","El olfato humano puede detectar ozono a concentraciones de 10 partes por mil millones (ppb) — una sensibilidad extraordinaria que demuestra la eficacia evolutiva de nuestro sistema olfativo.","La capa de ozono estratosférica filtra el 97-99 % de la radiación ultravioleta solar — su adelgazamiento por los CFC provocó el agujero de ozono, que el Protocolo de Montreal (1987) está corrigiendo."]
},
'e014': {
  fr:["Le verre est en réalité un solide amorphe : ses molécules sont désordonnées comme dans un liquide, mais figées en place.","Le verre le plus ancien jamais découvert est une perle égyptienne datant d'environ 3 500 av. J.-C.","Le verre auto-réparant existe déjà : des chercheurs japonais ont créé en 2017 un polymère vitreux qui se ressoudle en se pressant à température ambiante."],
  en:["Glass is actually an amorphous solid: its molecules are disordered like a liquid's, but frozen in place.","The oldest glass ever found is an Egyptian bead dating from around 3,500 BC.","Self-healing glass already exists: Japanese researchers created a glass polymer in 2017 that rebonds when pressed together at room temperature."],
    es:["El vidrio es un sólido amorfo, no un líquido que fluye lentamente — este mito persiste a pesar de haber sido refutado repetidamente por la física de materiales.","Las ventanas gruesas en la base de las catedrales se deben a los métodos de fabricación medievales (vidrio soplado en corona), que producían paneles de espesor irregular.","Un vidrio de ventana tardaría un tiempo superior a la edad del universo en mostrar una deformación gravitatoria medible — la viscosidad del vidrio a temperatura ambiente es esencialmente infinita."]
},
'e015': {
  fr:["La pression de radiation solaire est si faible qu'une voile solaire de 800 m² ne produit qu'environ 0,006 newton de poussée — mais en continu, sans carburant.","Le projet Breakthrough Starshot vise à utiliser des lasers pour propulser des nano-vaisseaux à 20 % de la vitesse de la lumière grâce à la pression photonique.","Albert Einstein a reçu le prix Nobel de physique en 1921 pour l'effet photoélectrique — qui démontre que la lumière se comporte comme des particules (photons)."],
  en:["Solar radiation pressure is so faint that an 800 m² solar sail produces only about 0.006 newtons of thrust — but continuously, with no fuel.","The Breakthrough Starshot project aims to use lasers to propel nano-spacecraft to 20% of light speed using photonic pressure.","Albert Einstein received the 1921 Nobel Prize in Physics for the photoelectric effect — which shows light behaves as particles (photons)."],
    es:["Un fotón no tiene masa en reposo pero transporta momento (cantidad de movimiento), lo que le permite ejercer presión sobre las superficies que ilumina — es la presión de radiación.","Las velas solares aprovechan esta presión: una nave espacial con una superficie reflectante grande puede ser acelerada por la luz solar sin necesidad de combustible.","La misión IKAROS (2010) de la JAXA demostró por primera vez la propulsión por vela solar: una membrana de 14 metros de lado acelerada exclusivamente por fotones del Sol."]
},
'e016': {
  fr:["La « dose équivalente en banane » est une unité informelle utilisée en radioprotection pour illustrer les doses de radiation quotidiennes.","Il faudrait manger environ 10 millions de bananes d'un coup pour recevoir une dose mortelle de radiation.","Le potassium-40 est présent partout dans la nature : le corps humain en contient naturellement environ 140 grammes, ce qui le rend lui aussi légèrement radioactif."],
  en:["The 'banana equivalent dose' is an informal unit used in radiation protection to illustrate everyday radiation doses.","You would need to eat about 10 million bananas at once to receive a lethal dose of radiation.","Potassium-40 is found everywhere in nature: the human body naturally contains about 140 grams, making it slightly radioactive too."],
    es:["El potasio-40 de las bananas emite radiación beta, pero la dosis es tan ínfima (0,1 microsievert por banana) que necesitarías comer 10 millones de bananas de una vez para que fuera peligroso.","La «dosis equivalente en bananas» (BED) se usa informalmente para comunicar niveles de radiación: una radiografía dental equivale a unas 50 bananas, un vuelo transatlántico a unas 400.","El cuerpo humano contiene unos 140 gramos de potasio, incluyendo potasio-40: eres más radiactivo que una banana — pero tu cuerpo mantiene el potasio en equilibrio constante."]
},
'e017': {
  fr:["On estime qu'il existe environ 200 milliards de billions (2×10²³) d'étoiles dans l'univers observable — un nombre proprement inconcevable.","La plupart de ces étoiles possèdent au moins une planète : il y aurait donc plus de planètes que d'étoiles dans l'univers.","Malgré ce nombre vertigineux, l'espace entre les étoiles est si vaste que l'univers est composé à 99,9999 % de vide."],
  en:["There are an estimated 200 billion trillion (2×10²³) stars in the observable universe — a truly inconceivable number.","Most of these stars have at least one planet, meaning there are likely more planets than stars in the universe.","Despite this staggering number, space between stars is so vast that the universe is 99.9999% empty."],
    es:["Se estima que el universo observable contiene unas 200 000 trillones (2×10²³) de estrellas, mientras que todas las playas de la Tierra contienen unos 7,5×10¹⁸ granos de arena.","Cada estrella puede tener planetas: los datos de Kepler sugieren que hay más planetas que estrellas en la Vía Láctea — al menos 100 000 millones de planetas solo en nuestra galaxia.","A pesar de esta inmensidad, no hemos detectado señales de vida extraterrestre — la paradoja de Fermi sigue sin respuesta satisfactoria."]
},
'e018': {
  fr:["Les 95 % restants de l'univers se répartissent entre environ 27 % de matière noire et 68 % d'énergie noire.","L'énergie noire est responsable de l'accélération de l'expansion de l'univers — un phénomène découvert en 1998 qui a valu le Nobel en 2011.","Si la matière noire et l'énergie noire n'existaient pas, les galaxies se seraient dispersées bien avant que la vie n'apparaisse."],
  en:["The remaining 95% of the universe is split between about 27% dark matter and 68% dark energy.","Dark energy is responsible for accelerating the expansion of the universe — a phenomenon discovered in 1998 that earned the Nobel Prize in 2011.","If dark matter and dark energy didn't exist, galaxies would have dispersed long before life appeared."],
    es:["La materia ordinaria (bariónica) — todo lo que vemos, tocamos y medimos — representa solo el 5 % del contenido del universo; el 27 % es materia oscura y el 68 % energía oscura.","La energía oscura es aún más misteriosa que la materia oscura: es la fuerza responsable de la aceleración de la expansión del universo, descubierta en 1998 por dos equipos que ganaron el Nobel en 2011.","Vivimos en un universo del que desconocemos el 95 % de su contenido — un recordatorio de humildad para una especie que a menudo cree comprenderlo todo."]
},
'e019': {
  fr:["La réaction de Maillard n'est techniquement pas la même chose que la caramélisation — elle implique des acides aminés en plus des sucres, créant des saveurs plus complexes.","Les 300+ composés aromatiques du caramel incluent le diacétyle (goût beurré) et le maltol (goût de barbe à papa).","La température précise de caramélisation varie selon le sucre : le fructose caramélise à 110 °C, le saccharose à 160 °C, le glucose à 150 °C."],
  en:["The Maillard reaction is technically not the same as caramelisation — it involves amino acids alongside sugars, creating more complex flavours.","The 300+ aromatic compounds in caramel include diacetyl (buttery taste) and maltol (candyfloss flavour).","The exact caramelisation temperature varies by sugar: fructose caramelises at 110°C, sucrose at 160°C, glucose at 150°C."],
    es:["La caramelización del azúcar es un proceso de pirólisis (descomposición por calor) que genera más de 300 compuestos volátiles responsables del aroma complejo del caramelo.","No es estrictamente una reacción de Maillard (que requiere aminoácidos), aunque ambas contribuyen al dorado y al sabor de los alimentos cocinados — la distinción química importa en la cocina molecular.","La temperatura de caramelización varía según el tipo de azúcar: la fructosa se carameliza a 110 °C, la sacarosa a 160 °C y la glucosa a 150 °C — por eso diferentes azúcares producen diferentes sabores."]
},
'e020': {
  fr:["Le cœur systémique de la pieuvre cesse de battre quand elle nage — c'est pourquoi elle préfère ramper plutôt que nager.","Les pieuvres ont le sang bleu : il contient de l'hémocyanine (à base de cuivre) au lieu de l'hémoglobine (à base de fer).","Chaque bras d'une pieuvre possède son propre mini-cerveau — les deux tiers de ses neurones se trouvent dans ses tentacules."],
  en:["The octopus's systemic heart stops beating when it swims — which is why it prefers crawling to swimming.","Octopuses have blue blood: it contains haemocyanin (copper-based) instead of haemoglobin (iron-based).","Each octopus arm has its own mini-brain — two-thirds of its neurons are located in its tentacles."],
    es:["Los pulpos tienen tres corazones porque su sangre (basada en hemocianina de cobre, no hemoglobina de hierro) transporta el oxígeno menos eficientemente, necesitando más bombeo.","Dos corazones branquiales bombean sangre a las branquias para oxigenarla, y un corazón sistémico la envía al resto del cuerpo — este último se detiene cuando el pulpo nada, por lo que prefiere caminar.","Además de tres corazones, los pulpos tienen nueve cerebros (un central y un ganglio por tentáculo), sangre azul y la capacidad de cambiar de color en milisegundos."]
},
'e021': {
  fr:["Les éléphants peuvent communiquer par des vibrations infrasonores que leurs pattes captent à travers le sol, à des kilomètres de distance.","Un éléphant peut se reconnaître dans un miroir — un signe d'intelligence qui n'est partagé que par quelques espèces.","Les éléphants d'Afrique ont une période de gestation de 22 mois — la plus longue de tous les mammifères terrestres."],
  en:["Elephants can communicate through infrasonic vibrations that their feet pick up through the ground, from kilometres away.","An elephant can recognise itself in a mirror — a sign of intelligence shared by only a few species.","African elephants have a gestation period of 22 months — the longest of any land mammal."],
    es:["Los elefantes muestran comportamientos de duelo únicos en el reino animal: tocan los huesos de sus muertos con la trompa, los acarician y permanecen junto a ellos durante horas.","Investigadores han documentado que los elefantes reconocen los cráneos de su especie entre los de otros animales, dedicando especial atención a los de su propia familia.","Este comportamiento sugiere una conciencia de la muerte que solo se ha observado en unos pocos animales: elefantes, primates, delfines, cuervos y posiblemente ballenas."]
},
'e022': {
  fr:["Les geckos peuvent aussi adhérer à des surfaces lisses grâce aux forces de Van der Waals exercées par des millions de poils nanométriques sous leurs pattes.","Un seul doigt de gecko peut supporter le poids de l'animal entier — la force d'adhésion totale de ses quatre pattes pourrait supporter un humain.","Des chercheurs du MIT ont créé un adhésif « gecko tape » inspiré de ces nano-poils, capable de coller et décoller à l'infini sans laisser de résidu."],
  en:["Geckos can also cling to smooth surfaces through Van der Waals forces exerted by millions of nanoscale hairs under their toes.","A single gecko toe can support the animal's entire weight — the total adhesion force from all four feet could support a human.","MIT researchers created a 'gecko tape' adhesive inspired by these nano-hairs, able to stick and unstick endlessly without residue."],
    es:["Los geckos basiliscos corren sobre el agua golpeando la superficie con sus patas a una velocidad de hasta 20 golpes por segundo, creando bolsas de aire que los sostienen brevemente.","Este fenómeno combina tres fuerzas: el impacto del pie (slap), el empuje de desplazamiento del agua y la tensión superficial — un equilibrio que solo funciona a cierta velocidad.","A escala humana, necesitaríamos correr a unos 100 km/h con piernas mucho más potentes para replicar el efecto — aunque algunos robots bípedos ya imitan esta capacidad."]
},
'e023': {
  fr:["Les pieuvres changent de couleur pendant leur sommeil en traversant différentes phases, comme les humains alternent entre sommeil léger et profond.","Une pieuvre endormie a été filmée changeant de couleur en séquence rapide, passant du blanc au brun foncé en quelques secondes.","Les pieuvres dorment environ 10 heures par jour mais par cycles très courts de 30 à 40 secondes chacun."],
  en:["Octopuses change colour during sleep as they cycle through phases, much like humans alternate between light and deep sleep.","A sleeping octopus was filmed changing colour in rapid sequence, shifting from white to dark brown in seconds.","Octopuses sleep about 10 hours a day but in very short cycles of 30 to 40 seconds each."],
    es:["Los pulpos cambian de color y textura de piel durante el sueño en patrones que sugieren sueños activos — pasando de camuflaje a colores vivos en segundos.","Un estudio de 2021 en iScience identificó dos fases de sueño en los pulpos, análogas al sueño REM y no-REM de los mamíferos — una evolución convergente fascinante.","Si los pulpos sueñan, su último ancestro común con los humanos vivió hace 600 millones de años — lo que sugiere que el sueño es una necesidad biológica profunda y universal."]
},
'e024': {
  fr:["Le requin-baleine peut filtrer plus de 6 000 litres d'eau par heure à travers ses branchies pour en extraire le plancton.","Malgré sa bouche pouvant atteindre 1,5 mètre de large, le requin-baleine ne peut pas avaler un objet plus gros qu'un pamplemousse.","Chaque requin-baleine possède un motif de points unique — les chercheurs les identifient individuellement, comme des empreintes digitales."],
  en:["The whale shark can filter over 6,000 litres of water per hour through its gills to extract plankton.","Despite a mouth up to 1.5 metres wide, the whale shark cannot swallow anything larger than a grapefruit.","Each whale shark has a unique spot pattern — researchers identify individuals, much like fingerprints."],
    es:["El tiburón ballena puede medir hasta 18 metros y pesar 20 toneladas, pero se alimenta filtrando plancton y pequeños peces a través de sus enormes branquias.","Cada tiburón ballena tiene un patrón único de manchas blancas, como una huella digital, que los investigadores usan para identificar individuos en programas de conservación.","A pesar de su tamaño, son animales dóciles que permiten a los buceadores nadar junto a ellos — pero su población ha disminuido un 50 % en los últimos 75 años."]
},
'e025': {
  fr:["Les fourmis-tisserandes forment des chaînes vivantes en s'accrochant les unes aux autres pour rapprocher des feuilles éloignées.","La soie produite par les larves de tisserandes est cinq fois plus résistante que l'acier à diamètre égal.","Les colonies de fourmis-tisserandes peuvent compter plus de 500 000 individus répartis sur des dizaines d'arbres interconnectés."],
  en:["Weaver ants form living chains by gripping each other to pull distant leaves together.","Silk produced by weaver ant larvae is five times stronger than steel at the same diameter.","Weaver ant colonies can number over 500,000 individuals spread across dozens of interconnected trees."],
    es:["Las hormigas tejedoras (Oecophylla) sujetan a sus larvas como pistolas de pegamento, exprimiendo la seda que estas producen para coser hojas y construir nidos aéreos.","Una colonia puede contener hasta 500 000 individuos distribuidos en varios árboles, con nidos de hojas vivas conectados por puentes de hormigas entrelazadas.","Este comportamiento cooperativo extremo es un ejemplo de superorganismo: la colonia funciona como un solo individuo, con las hormigas como células de un cuerpo colectivo."]
},
'e026': {
  fr:["Pendant des décennies, les scientifiques pensaient que les bactéries de la morsure du varan de Komodo provoquaient des infections mortelles — le venin n'a été découvert qu'en 2009.","Le varan de Komodo peut détecter une proie à 10 km de distance grâce à sa langue bifide qui analyse les molécules odorantes.","Les femelles varan de Komodo peuvent se reproduire par parthénogenèse — elles pondent des œufs fertiles sans fécondation par un mâle."],
  en:["For decades, scientists believed bacteria from Komodo dragon bites caused deadly infections — the venom was only discovered in 2009.","A Komodo dragon can detect prey from 10 km away using its forked tongue to analyse scent molecules.","Female Komodo dragons can reproduce by parthenogenesis — laying fertile eggs without male fertilisation."],
    es:["El dragón de Komodo posee glándulas venenosas en la mandíbula inferior que secretan toxinas anticoagulantes, vasodilatadoras y inductoras de shock.","Durante décadas se creyó que sus presas morían por infecciones bacterianas de la mordedura, pero un estudio de 2009 demostró que el veneno es el verdadero agente letal.","Los dragones de Komodo son los lagartos más grandes del mundo (hasta 3 metros y 70 kg) y viven exclusivamente en unas pocas islas de Indonesia — una especie vulnerable."]
},
'e027': {
  fr:["Les corbeaux sont capables de fabriquer et d'utiliser des outils — un signe d'intelligence autrefois attribué aux seuls primates.","Des chercheurs ont montré que les corbeaux peuvent planifier pour le lendemain, échangeant des jetons contre de la nourriture le jour suivant.","Les corbeaux organisent des « funérailles » : ils se rassemblent bruyamment autour du corps d'un congénère, probablement pour évaluer les dangers."],
  en:["Crows can make and use tools — a sign of intelligence once attributed only to primates.","Researchers showed that crows can plan for the next day, trading tokens for food the following morning.","Crows hold 'funerals': they gather noisily around a dead comrade, likely to assess potential dangers."],
    es:["Los cuervos pueden recordar rostros humanos individuales durante al menos 5 años y transmitir esta información a otros cuervos que nunca han visto a esa persona.","En un experimento de la Universidad de Washington, cuervos atacaban a investigadores que llevaban una máscara específica — incluso cuervos que no habían sido capturados se unían al acoso.","Los córvidos (cuervos, cornejas, urracas) son las aves más inteligentes: fabrican herramientas, planifican el futuro, reconocen su reflejo y comprenden la causalidad."]
},
'e028': {
  fr:["Tous les poissons-clowns naissent mâles — seul le plus grand d'un groupe devient femelle pour diriger la hiérarchie.","Les poissons-clowns sont immunisés contre les piqûres d'anémones grâce à un mucus spécial qui les protège des nématocystes.","Il existe environ 30 espèces de poissons-clowns dans le monde, chacune associée à une ou deux espèces d'anémones spécifiques."],
  en:["All clownfish are born male — only the largest in a group becomes female to lead the hierarchy.","Clownfish are immune to anemone stings thanks to a special mucus that protects them from nematocysts.","There are about 30 species of clownfish worldwide, each associated with one or two specific anemone species."],
    es:["Todos los peces payaso nacen machos, y la jerarquía del grupo determina quién se convierte en hembra: solo el individuo dominante cambia de sexo.","Este hermafroditismo secuencial protándrico es una adaptación a la vida en anémonas aisladas: al morir la hembra, el grupo necesita una nueva rápidamente.","La película Buscando a Nemo se tomó libertades con la biología: en la realidad, tras la muerte de la madre, el padre Marlin se habría transformado en hembra."]
},
'e029': {
  fr:["Le tatou à neuf bandes donne naissance à des quadruplés identiques à chaque portée — quatre bébés issus du même œuf.","La carapace du tatou est faite de plaques osseuses recouvertes de kératine — le même matériau que les ongles humains.","Le tatou peut retenir sa respiration pendant six minutes, ce qui lui permet de traverser des rivières en marchant sur le fond."],
  en:["The nine-banded armadillo gives birth to identical quadruplets every time — four babies from the same egg.","An armadillo's shell is made of bony plates covered in keratin — the same material as human fingernails.","The armadillo can hold its breath for six minutes, allowing it to cross rivers by walking along the bottom."],
    es:["El armadillo de nueve bandas es el único animal silvestre conocido que puede transmitir la lepra (enfermedad de Hansen) a los humanos mediante contacto directo.","Los armadillos son susceptibles al Mycobacterium leprae porque su temperatura corporal baja (32-35 °C) es ideal para el crecimiento de esta bacteria.","A pesar del riesgo, la lepra es poco contagiosa y fácilmente tratable con antibióticos modernos — los casos humanos asociados a armadillos son raros y se concentran en el sureste de EE.UU."]
},
'e030': {
  fr:["Les chants de baleines à bosse sont les compositions les plus longues du règne animal — certaines durent plus de 24 heures en boucle.","Un « hit » de baleine peut se propager d'un océan à l'autre : des chercheurs ont suivi un refrain né dans l'Indien jusqu'au Pacifique en quelques années.","Seuls les mâles chantent — on pense que c'est un outil de séduction, mais le rôle exact reste mystérieux car les femelles semblent parfois s'en éloigner."],
  en:["Humpback whale songs are the longest compositions in the animal kingdom — some loop for over 24 hours.","A whale 'hit' can spread from one ocean to another: researchers tracked a chorus born in the Indian Ocean reaching the Pacific within a few years.","Only males sing — it's thought to be a courtship tool, but the exact role remains mysterious since females sometimes swim away from singers."],
    es:["Las ballenas jorobadas componen canciones complejas que evolucionan gradualmente durante la temporada de cría — y todas las ballenas de una misma cuenca oceánica cantan la misma versión.","Las canciones nuevas pueden propagarse de una población a otra: una melodía nacida en Australia ha sido rastreada hasta la Polinesia Francesa, viajando miles de kilómetros en pocos años.","Solo los machos cantan, lo que sugiere una función reproductiva — pero el mecanismo exacto (atraer hembras, competir con otros machos, o ambos) sigue siendo debatido."]
},
'e031': {
  fr:["La grenouille des bois d'Alaska peut geler à −18 °C et survivre : son cœur s'arrête, sa respiration cesse, et elle « ressuscite » au printemps.","Le glucose agit comme un antigel naturel en empêchant la formation de cristaux de glace destructeurs à l'intérieur des cellules.","Certaines espèces de grenouilles survivent aussi grâce à l'urée, qui en combinaison avec le glucose offre une double protection cryogénique."],
  en:["The Alaskan wood frog can freeze at −18°C and survive: its heart stops, breathing ceases, and it 'resurrects' in spring.","Glucose acts as a natural antifreeze by preventing destructive ice crystals from forming inside cells.","Some frog species also survive using urea, which combined with glucose provides a dual cryogenic protection."],
    es:["La rana de bosque (Lithobates sylvaticus) sobrevive a la congelación parcial acumulando glucosa y urea como anticongelante en sus células, protegiendo sus membranas del daño por cristales de hielo.","Hasta el 65 % de su agua corporal se congela: el corazón se detiene, la respiración cesa y el cerebro se apaga — pero al descongelarse en primavera, revive en pocas horas.","Este mecanismo inspira la investigación en criopreservación de órganos humanos para trasplantes — un desafío que la medicina aún no ha resuelto para tejidos complejos."]
},
'e032': {
  fr:["Le monarque utilise un compas solaire couplé à une horloge biologique dans ses antennes pour maintenir son cap vers le sud.","Aucun papillon ne fait le voyage aller-retour complet : il faut 3 à 4 générations pour accomplir la migration annuelle.","Les sites d'hivernage au Mexique, dans les forêts d'oyamels, voient des millions de papillons se regrouper sur quelques hectares seulement."],
  en:["The monarch uses a sun compass coupled with a biological clock in its antennae to maintain its southward heading.","No single butterfly completes the round trip: it takes 3 to 4 generations to accomplish the annual migration.","The overwintering sites in Mexico's oyamel forests see millions of butterflies gathering on just a few hectares."],
    es:["La mariposa monarca migra hasta 4 500 km entre Canadá y los bosques de oyamel de Michoacán (México), un viaje que tarda cuatro generaciones en completarse en sentido inverso.","La generación que migra al sur vive 8 meses (frente a las 4-6 semanas habituales) y navega usando una brújula solar calibrada por un reloj circadiano en sus antenas.","Los santuarios de la mariposa monarca en México reciben millones de ejemplares cada invierno — un espectáculo natural amenazado por la deforestación y el cambio climático."]
},
'e033': {
  fr:["Les yeux du calmar colossal sont adaptés aux abysses : ils captent la bioluminescence des prédateurs à plus de 120 mètres dans l'obscurité totale.","Le calmar colossal possède aussi des crochets rotatifs sur ses tentacules — une arme unique dans le règne animal.","Malgré sa taille (jusqu'à 14 mètres), le calmar colossal n'a été filmé vivant dans son habitat naturel qu'en 2013."],
  en:["The colossal squid's eyes are adapted to the abyss: they detect bioluminescence from predators over 120 metres away in total darkness.","The colossal squid also has swivelling hooks on its tentacles — a unique weapon in the animal kingdom.","Despite its size (up to 14 metres), the colossal squid was only filmed alive in its natural habitat in 2013."],
    es:["El calamar colossal (Mesonychoteuthis hamiltoni) tiene los ojos más grandes del reino animal: hasta 30 cm de diámetro, del tamaño de un balón de fútbol.","Estos ojos gigantes están adaptados a la oscuridad abisal: detectan la bioluminiscencia de los cachalotes que se acercan para cazarlos, dándoles tiempo para huir.","Solo se han examinado unos pocos ejemplares completos — la mayoría encontrados en los estómagos de cachalotes — y su biología sigue siendo en gran parte desconocida."]
},
'e034': {
  fr:["Les ratons laveurs possèdent cinq fois plus de terminaisons nerveuses dans leurs pattes avant que la plupart des mammifères.","Ils plongent souvent leurs mains dans l'eau non pas pour laver la nourriture, mais parce que l'eau amplifie leur sens du toucher.","Le raton laveur est capable d'ouvrir des serrures, des loquets et des poubelles complexes — leur QI de résolution de problèmes rivalise avec certains primates."],
  en:["Raccoons have five times more nerve endings in their front paws than most mammals.","They often dip their hands in water not to wash food, but because water amplifies their sense of touch.","Raccoons can open locks, latches, and complex bins — their problem-solving IQ rivals that of some primates."],
    es:["Los mapaches tienen una densidad de terminaciones nerviosas en las patas delanteras comparable a la de las puntas de los dedos humanos — una sensibilidad táctil extraordinaria.","Mojan frecuentemente su comida no para lavarla sino para activar sus receptores táctiles: el agua mejora la sensibilidad de sus patas, permitiéndoles examinar los alimentos con mayor precisión.","Su nombre en inglés (raccoon) proviene del algonquino arahkun, que significa «el que rasca con las manos» — una descripción perfecta de su método de exploración."]
},
'e035': {
  fr:["Les deux pointes de la langue bifide permettent au serpent de percevoir un gradient odorant et donc de localiser la direction d'une proie.","Les molécules captées par la langue sont analysées par l'organe de Jacobson, situé dans le palais, qui complète l'odorat classique.","Certains serpents, comme les pythons, possèdent en plus des fossettes thermosensibles qui détectent la chaleur corporelle de leurs proies dans le noir."],
  en:["The two tips of the forked tongue let the snake sense a scent gradient, pinpointing the direction of prey.","Molecules captured by the tongue are analysed by the Jacobson's organ in the palate, which supplements standard smell.","Some snakes, like pythons, also have heat-sensing pits that detect prey body heat in total darkness."],
    es:["La lengua bífida de las serpientes funciona como un sensor estéreo de olores: cada punta recoge moléculas de direcciones ligeramente diferentes, permitiendo localizar la fuente del olor.","Al retraer la lengua, la insertan en el órgano vomeronasal (órgano de Jacobson) del paladar, que analiza las moléculas químicas captadas — un sistema olfativo de alta precisión.","Este sistema es tan eficiente que una serpiente ciega puede seguir el rastro de una presa a decenas de metros de distancia, discriminando entre diferentes tipos de presas."]
},
'e036': {
  fr:["Les manchots Adélie construisent des nids en pierre qu'ils élaborent pendant des semaines — les galets les plus ronds et lisses sont les plus prisés.","Le vol de galets est fréquent dans les colonies de manchots Adélie : certains individus dérobent des pierres dans les nids voisins.","Les manchots Adélie peuvent nager jusqu'à 300 km pour trouver de la nourriture et reviennent toujours au même nid retrouver leur partenaire."],
  en:["Adélie penguins build stone nests that they assemble over weeks — the roundest, smoothest pebbles are the most prized.","Pebble theft is common in Adélie penguin colonies: some individuals steal stones from neighbouring nests.","Adélie penguins can swim up to 300 km to find food and always return to the same nest to rejoin their partner."],
    es:["Los pingüinos de Adelia buscan el guijarro más liso y redondeado posible para ofrecer a su pareja como parte del cortejo — un guijarro de calidad puede ser robado por otros pingüinos.","Los guijarros tienen también función práctica: se usan para construir el nido elevado que protege los huevos del agua de deshielo — un nido bajo significa huevos ahogados.","Los pingüinos de Adelia son monógamos estacionales: reconocen a su pareja por su vocalización específica entre los miles de individuos de una colonia."]
},
'e037': {
  fr:["Les dauphins se passent le poisson-coffre de l'un à l'autre en cercle, comme une forme de partage social.","Les toxines libérées par le poisson-coffre (tétrodotoxine) sont mortelles à forte dose, mais en micro-quantité elles produisent un effet narcotique.","Les dauphins sont l'une des rares espèces à utiliser des substances récréatives — un comportement longtemps cru exclusif aux humains."],
  en:["Dolphins pass the puffer fish around to each other in a circle, as a form of social sharing.","Toxins released by puffer fish (tetrodotoxin) are lethal in high doses, but in micro-quantities they produce a narcotic effect.","Dolphins are one of the few species to use recreational substances — a behaviour long thought exclusive to humans."],
    es:["Los delfines han sido filmados pasándose un pez globo (que libera tetrodotoxina en pequeñas dosis) y entrando aparentemente en un estado alterado de conciencia.","El comportamiento fue documentado por la BBC en 2014: los delfines mordisqueaban suavemente el pez sin matarlo y luego flotaban inmóviles cerca de la superficie durante minutos.","Este uso de sustancias psicoactivas en la naturaleza no es exclusivo de los delfines: los renos comen setas alucinógenas y los monos vervet roban bebidas alcohólicas a los turistas."]
},
'e038': {
  fr:["Les tardigrades peuvent survivre à la déshydratation complète en entrant en cryptobiose — leur métabolisme tombe à 0,01 % de la normale.","En 2007, des tardigrades ont été envoyés dans l'espace à bord du satellite FOTON-M3 et ont survécu 10 jours d'exposition directe au vide spatial.","Il existe plus de 1 300 espèces de tardigrades connues, vivant partout : des fosses océaniques aux sommets de l'Himalaya."],
  en:["Tardigrades can survive complete dehydration by entering cryptobiosis — their metabolism drops to 0.01% of normal.","In 2007, tardigrades were sent into space aboard the FOTON-M3 satellite and survived 10 days of direct exposure to the vacuum of space.","Over 1,300 tardigrade species are known, living everywhere from ocean trenches to Himalayan peaks."],
    es:["Los tardígrados soportan condiciones que matarían a cualquier otro animal: vacío espacial, radiación 1 000 veces letal, temperaturas de −272 °C a +150 °C y presiones de 6 000 atmósferas.","Sobreviven mediante criptobiosis: se deshidratan hasta el 1 % de su agua corporal, reemplazándola con trehalosa (un azúcar protector) y formando una estructura llamada tun.","En 2019, la sonda israelí Beresheet se estrelló en la Luna con tardígrados a bordo — es posible que sobrevivieran al impacto, convirtiéndolos en los primeros colonizadores involuntarios de la Luna."]
},
'e039': {
  fr:["Certaines étoiles de mer, comme la Linckia, peuvent régénérer un corps entier à partir d'un seul bras — à condition qu'il contienne une partie du disque central.","La régénération d'un bras complet peut prendre jusqu'à un an, pendant lequel l'étoile de mer continue de vivre normalement.","Les étoiles de mer n'ont pas de cerveau ni de sang — elles utilisent un système vasculaire aqueux pour se déplacer et respirer."],
  en:["Some starfish, like Linckia, can regenerate an entire body from a single arm — as long as it contains part of the central disc.","Regrowing a full arm can take up to a year, during which the starfish continues to live normally.","Starfish have no brain or blood — they use a water vascular system to move and breathe."],
    es:["Las estrellas de mar pueden regenerar un brazo perdido en semanas o meses — y en algunas especies, un solo brazo separado puede regenerar un cuerpo completo nuevo.","La regeneración se basa en células madre pluripotentes que pueden diferenciarse en cualquier tipo de tejido: músculo, sistema nervioso, tubo digestivo y sistema reproductivo.","Los científicos estudian los mecanismos de regeneración de las estrellas de mar para aplicarlos a la medicina regenerativa humana — un campo que podría revolucionar el tratamiento de lesiones."]
},
'e040': {
  fr:["Les chromatophores sont des cellules contenant des pigments que les muscles étirent ou contractent pour changer la couleur instantanément.","Sous les chromatophores, les iridophores réfléchissent la lumière comme des miroirs microscopiques, créant des reflets métalliques et iridescents.","Les pieuvres sont daltonniennes — elles ne voient qu'en noir et blanc mais adaptent leurs couleurs parfaitement grâce à des photorécepteurs dans leur peau."],
  en:["Chromatophores are cells containing pigments that muscles stretch or contract to change colour instantly.","Beneath chromatophores, iridophores reflect light like microscopic mirrors, creating metallic and iridescent sheens.","Octopuses are colour-blind — they see only in black and white but match colours perfectly through photoreceptors in their skin."],
    es:["Los cromatóforos del pulpo son células especializadas que contienen pigmentos elásticos controlados por músculos — al expandirlos o contraerlos, el pulpo cambia de color casi instantáneamente.","Debajo de los cromatóforos hay iridóforos (reflectores) y leucóforos (blancos), creando un sistema de tres capas que permite imitar prácticamente cualquier color o textura del entorno.","Sorprendentemente, los pulpos son daltónicos (tienen un solo tipo de fotorreceptor) — cómo logran un camuflaje cromático perfecto sin percibir los colores sigue siendo un misterio."]
},
'e041': {
  fr:["Les chauves-souris vampires pratiquent le partage de sang par régurgitation entre congénères affamés, un rare exemple d'altruisme réciproque chez les mammifères.","Elles détectent les vaisseaux sanguins proches de la peau grâce à des capteurs infrarouges sur leur nez — un sens unique chez les mammifères.","La salive de la chauve-souris vampire contient un anticoagulant si efficace qu'il a inspiré un médicament contre les AVC appelé desmoteplase."],
  en:["Vampire bats share blood by regurgitating to hungry colony-mates — a rare example of reciprocal altruism in mammals.","They detect blood vessels near the skin using infrared sensors on their nose — a sense unique among mammals.","Vampire bat saliva contains an anticoagulant so effective it inspired a stroke medication called desmoteplase."],
    es:["Los murciélagos vampiros comunes se alimentan exclusivamente de sangre (hematofagia), consumiendo unos 20 ml por noche — necesitan comer cada 48 horas o mueren.","Si un murciélago no encuentra comida, otros miembros de la colonia le regurgitan sangre — un comportamiento altruista basado en la reciprocidad: los que comparten hoy recibirán mañana.","Sus dientes incisivos son tan afilados que la víctima rara vez despierta durante la mordedura, y su saliva contiene draculina, un anticoagulante potente estudiado para tratamientos médicos."]
},
'e042': {
  fr:["Un donneur vivant peut céder jusqu'à 60 % de son foie : les deux parties repoussent à leur taille complète en quelques semaines.","Le foie remplit plus de 500 fonctions différentes, dont la détoxification, la production de bile et le stockage de vitamines.","Le foie est le seul organe qui reçoit un double apport sanguin : l'artère hépatique (sang oxygéné) et la veine porte (sang riche en nutriments de l'intestin)."],
  en:["A living donor can give up to 60% of their liver: both portions regrow to full size within weeks.","The liver performs over 500 different functions, including detoxification, bile production, and vitamin storage.","The liver is the only organ with a dual blood supply: the hepatic artery (oxygenated blood) and the portal vein (nutrient-rich blood from the gut)."],
    es:["El hígado puede regenerar hasta el 75 % de su masa en unas pocas semanas — una capacidad que permite los trasplantes de hígado de donante vivo.","Realiza más de 500 funciones: filtra toxinas, produce bilis, almacena glucógeno, sintetiza proteínas, metaboliza fármacos y regula el colesterol.","El mito de Prometeo, cuyo hígado era devorado cada día por un águila y se regeneraba cada noche, refleja un conocimiento antiguo sorprendente de esta capacidad regenerativa."]
},
'e043': {
  fr:["Les oreilles s'allongent d'environ 0,22 mm par an en raison de la dégradation du cartilage et de l'effet de la gravité.","Le nez ne grandit pas réellement — c'est la peau et le cartilage qui s'affaissent avec l'âge, donnant l'illusion de croissance.","Les globes oculaires, en revanche, atteignent leur taille définitive vers 13 ans et ne changent pratiquement plus."],
  en:["Ears elongate by about 0.22 mm per year due to cartilage breakdown and gravity.","The nose doesn't actually grow — the skin and cartilage sag with age, giving the illusion of growth.","Eyeballs, on the other hand, reach their final size around age 13 and barely change afterwards."],
    es:["Las orejas y la nariz no «crecen» realmente con la edad: están compuestas de cartílago, que se debilita y cede ante la gravedad, dando la impresión de crecimiento.","El lóbulo de la oreja se alarga unos 0,22 mm por año, y la nariz puede caer hasta 1 cm a lo largo de una vida — cambios sutiles pero acumulativos.","Los ojos, en cambio, alcanzan su tamaño adulto hacia los 13 años y permanecen prácticamente iguales el resto de la vida — uno de los pocos órganos que no cambia de dimensiones."]
},
'e044': {
  fr:["L'acide chlorhydrique de l'estomac est assez puissant pour dissoudre du métal — il atteint un pH de 1 à 2.","L'estomac est protégé de sa propre acidité par une couche de mucus d'environ 1 mm d'épaisseur, constamment renouvelée.","Sans cette régénération rapide, l'estomac se digérerait lui-même en une dizaine de jours."],
  en:["The stomach's hydrochloric acid is strong enough to dissolve metal — reaching a pH of 1 to 2.","The stomach is protected from its own acid by a mucus layer about 1 mm thick, constantly renewed.","Without this rapid regeneration, the stomach would digest itself in about ten days."],
    es:["El ácido clorhídrico del estómago tiene un pH de 1,5-3,5, lo suficientemente fuerte como para disolver metales — una capa de moco protege las paredes del estómago de su propia acidez.","Esta capa de moco se renueva cada dos semanas porque el ácido la degrada constantemente — un equilibrio dinámico entre destrucción y regeneración.","Las células parietales del estómago producen unos 2 litros de ácido clorhídrico al día — cuando este equilibrio se rompe, se producen úlceras gástricas."]
},
'e045': {
  fr:["Les capillaires les plus fins ont un diamètre de 5 à 10 microns — juste assez pour laisser passer un globule rouge à la fois.","Le sang parcourt l'ensemble du réseau circulatoire en environ 60 secondes : un globule rouge fait le tour complet du corps en une minute.","Si l'on ajoutait le réseau lymphatique, le total dépasserait 160 000 km de vaisseaux dans un seul corps humain."],
  en:["The thinnest capillaries are 5 to 10 microns in diameter — just wide enough for red blood cells to pass through one at a time.","Blood travels through the entire circulatory network in about 60 seconds: a red blood cell completes a full loop in one minute.","Adding the lymphatic network, the total exceeds 160,000 km of vessels in a single human body."],
    es:["El sistema capilar humano es una red de vasos microscópicos (5-10 micrómetros de diámetro) que conecta las arterias con las venas y permite el intercambio de gases y nutrientes.","Los 100 000 km de capilares garantizan que cada célula del cuerpo esté a menos de 0,1 mm de un capilar — una distancia óptima para la difusión de oxígeno.","Los capilares son tan finos que los glóbulos rojos (7 micrómetros) deben deformarse para pasar por ellos, lo que maximiza el contacto con las paredes y facilita el intercambio gaseoso."]
},
'e046': {
  fr:["La cornée est aussi le tissu qui guérit le plus vite du corps : une égratignure superficielle se referme en 24 à 72 heures.","Les greffes de cornée sont les transplantations les plus courantes au monde — et les plus réussies, avec un taux de succès supérieur à 90 %.","La cornée est l'une des rares structures du corps qui ne provoque pas de rejet immunitaire fort, car elle n'a pas de vaisseaux sanguins."],
  en:["The cornea is also the fastest-healing tissue in the body: a superficial scratch closes within 24 to 72 hours.","Corneal transplants are the most common transplant worldwide — and the most successful, with over 90% success rates.","The cornea is one of the few body structures that doesn't trigger strong immune rejection, because it has no blood vessels."],
    es:["La córnea obtiene oxígeno directamente del aire a través de la película lagrimal, y nutrientes del humor acuoso — esta ausencia de vasos sanguíneos es lo que le da su transparencia.","Esta propiedad la convierte en un sitio inmunológicamente privilegiado: los trasplantes de córnea tienen la tasa de éxito más alta de todos los trasplantes de tejidos, superior al 90 %.","La córnea enfoca el 75 % de la luz que entra al ojo — el cristalino solo ajusta el enfoque fino. La cirugía LASIK modifica la forma de la córnea para corregir la miopía."]
},
'e047': {
  fr:["Pendant le sommeil profond, le cerveau consomme presque autant d'énergie qu'en état d'éveil — il consolide les souvenirs et élimine les déchets métaboliques.","Le cerveau utilise exclusivement du glucose comme carburant — il ne peut pas brûler de graisse directement, contrairement aux muscles.","Si le cerveau était un ordinateur, il consommerait environ 10 millions de fois moins d'énergie qu'un supercalculateur de puissance équivalente."],
  en:["During deep sleep, the brain uses almost as much energy as when awake — consolidating memories and clearing metabolic waste.","The brain uses glucose exclusively as fuel — it cannot burn fat directly, unlike muscles.","If the brain were a computer, it would consume about 10 million times less energy than an equivalent supercomputer."],
    es:["El cerebro consume 20 % de la energía corporal pero representa solo el 2 % de la masa — gramo por gramo, es el órgano más hambriento del cuerpo.","La mayor parte de esta energía se destina a mantener los gradientes iónicos de las neuronas (las bombas de sodio-potasio) — el procesamiento de información es energéticamente costosísimo.","El cerebro no puede almacenar energía: depende de un suministro constante de glucosa y oxígeno. Una interrupción de 5-10 minutos causa daño neuronal irreversible."]
},
'e048': {
  fr:["La poussière domestique est composée à 70-80 % de cellules de peau mortes mêlées à des acariens, du pollen et des fibres textiles.","En une vie, un être humain perd environ 45 kg de peau morte — soit le poids d'un adolescent.","Les cellules de la peau se renouvellent complètement en 27 jours environ, ce qui signifie que vous changez littéralement de peau tous les mois."],
  en:["Household dust is 70–80% dead skin cells mixed with dust mites, pollen, and textile fibres.","Over a lifetime, a human sheds about 45 kg of dead skin — roughly the weight of a teenager.","Skin cells fully renew in about 27 days, meaning you literally get new skin every month."],
    es:["Las células de la piel se renuevan cada 2-4 semanas: las nuevas se forman en la capa basal y migran hacia la superficie, donde mueren y se desprenden como escamas microscópicas.","El polvo doméstico está compuesto en un 50-70 % por piel humana muerta — un adulto produce unos 1,5 gramos de piel muerta al día.","Los ácaros del polvo se alimentan de estas escamas de piel: una cama típica puede contener entre 100 000 y 10 millones de ácaros, que a su vez producen alérgenos."]
},
'e049': {
  fr:["Même les vrais jumeaux n'ont pas les mêmes empreintes digitales — le processus de formation est influencé par des facteurs aléatoires in utero.","Les koalas sont les seuls animaux en dehors des primates à avoir des empreintes digitales — et elles sont si similaires aux nôtres qu'elles pourraient tromper un expert.","Les empreintes digitales ne changent jamais au cours de la vie, sauf en cas de brûlure profonde ou de maladie de peau très rare."],
  en:["Even identical twins don't share fingerprints — the formation process is influenced by random factors in utero.","Koalas are the only non-primate animals with fingerprints — and they're so similar to ours they could fool an expert.","Fingerprints never change during a person's lifetime, except in cases of deep burns or extremely rare skin diseases."],
    es:["Las huellas digitales se forman entre las semanas 10 y 17 de gestación por la interacción entre la presión del líquido amniótico y el crecimiento de la piel fetal.","Ni siquiera los gemelos idénticos tienen las mismas huellas dactilares: el proceso es influido por la posición del feto, la presión y factores aleatorios — cada patrón es único.","Francis Galton demostró en 1892 que la probabilidad de que dos personas compartan huellas idénticas es de 1 entre 64 000 millones — lo que convirtió las huellas en herramienta forense universal."]
},
'e050': {
  fr:["On estime que le microbiome intestinal pèse entre 1 et 2 kg — soit plus que le cerveau humain.","Plus de 1 000 espèces de bactéries différentes cohabitent dans l'intestin, et leur composition est unique à chaque individu.","Le microbiome communique avec le cerveau via le nerf vague — il influence l'humeur, le stress et même certaines décisions alimentaires."],
  en:["The gut microbiome is estimated to weigh 1 to 2 kg — more than the human brain.","Over 1,000 different bacterial species coexist in the gut, and their composition is unique to each individual.","The microbiome communicates with the brain via the vagus nerve — influencing mood, stress, and even food choices."],
    es:["El microbioma intestinal contiene entre 30 y 50 billones de bacterias, comparable al número de células humanas del cuerpo — somos tanto bacterias como humanos.","Estas bacterias pesan entre 1 y 2 kg y realizan funciones esenciales: sintetizan vitaminas (K, B12), digieren fibra, entrenan el sistema inmunitario y producen neurotransmisores.","El eje intestino-cerebro conecta el microbioma con el estado de ánimo: cambios en la flora intestinal se asocian con depresión, ansiedad y trastornos del espectro autista."]
},
'e051': {
  fr:["Les yeux exécutent environ 250 000 saccades par jour — des mouvements si rapides que le cerveau les « efface » pour éviter le flou visuel.","Le phénomène de suppression saccadique signifie que vous êtes techniquement aveugle pendant environ 40 minutes par jour sans le savoir.","Les muscles oculomoteurs se fatiguent moins que tout autre muscle du corps : ils sont constitués de fibres spéciales qui résistent à l'épuisement."],
  en:["The eyes perform about 250,000 saccades per day — movements so fast the brain 'erases' them to avoid visual blur.","Saccadic suppression means you're technically blind for about 40 minutes per day without knowing it.","Eye muscles fatigue less than any other muscle: they're made of special fibres that resist exhaustion."],
    es:["Los músculos oculomotores realizan movimientos sacádicos de hasta 700°/segundo, reposicionando el ojo varias veces por segundo para mantener una imagen nítida en la fóvea.","Cada ojo tiene seis músculos extraoculares que trabajan en coordinación — el cerebro los controla con una precisión de milímetros para que ambos ojos converjan en el mismo punto.","Los movimientos sacádicos son tan rápidos que el cerebro suprime la visión durante el movimiento (supresión sacádica) — por eso no ves el barrido al mover los ojos rápidamente."]
},
'e052': {
  fr:["Les fontanelles d'un bébé — les zones molles sur le crâne — sont des espaces entre des os non encore fusionnés qui permettent au cerveau de croître rapidement.","Les derniers os à fusionner sont ceux du bassin et de la clavicule, qui ne se soudent complètement que vers 25 ans.","L'os hyoïde, situé dans la gorge, est le seul os du corps qui n'est articulé à aucun autre — il flotte librement, retenu par des muscles."],
  en:["A baby's fontanelles — the soft spots on the skull — are gaps between bones not yet fused, allowing the brain to grow rapidly.","The last bones to fuse are those of the pelvis and collarbone, fully joining only around age 25.","The hyoid bone in the throat is the only bone not connected to any other — it floats freely, held by muscles."],
    es:["Un recién nacido tiene unos 300 huesos, pero muchos se fusionan durante el crecimiento: las fontanelas del cráneo se cierran, las vértebras del sacro se unen y las epífisis se sueldan.","Los huesos más pequeños del cuerpo están en el oído medio: el martillo, el yunque y el estribo (3 mm) amplifican las vibraciones sonoras del tímpano hacia el oído interno.","El hueso más largo y fuerte es el fémur, que puede soportar fuerzas de compresión de hasta 1 700 kg — más resistente que el hormigón armado por unidad de peso."]
},
'e053': {
  fr:["Les plaies dans la bouche guérissent 2 à 3 fois plus vite que les plaies cutanées, en partie grâce à l'histatine et au milieu humide.","La salive contient aussi du facteur de croissance épidermique (EGF), qui stimule la régénération des cellules — c'est pourquoi les animaux lèchent leurs blessures.","Un adulte produit entre 0,5 et 1,5 litre de salive par jour — soit environ 35 000 litres au cours d'une vie."],
  en:["Mouth wounds heal 2 to 3 times faster than skin wounds, partly thanks to histatin and the moist environment.","Saliva also contains epidermal growth factor (EGF), which stimulates cell regeneration — that's why animals lick their wounds.","An adult produces 0.5 to 1.5 litres of saliva per day — about 35,000 litres over a lifetime."],
    es:["La histatina de la saliva acelera la cicatrización al promover la migración celular y la formación de nuevos vasos sanguíneos en la zona dañada.","Esto explica el instinto de lamerse las heridas, observado también en perros, gatos y primates — la saliva contiene además lisozima y lactoferrina, con propiedades antibacterianas.","Sin embargo, la boca humana contiene más de 700 especies de bacterias: lamerse una herida profunda puede introducir infecciones — el efecto beneficioso se limita a heridas superficiales."]
},
'e054': {
  fr:["La cochlée, l'organe en forme de spirale dans l'oreille interne, ne fait que 9 mm de diamètre mais contient environ 15 000 cellules ciliées.","Si ces cellules ciliées sont endommagées (par le bruit excessif ou l'âge), elles ne se régénèrent pas — c'est la cause principale de surdité permanente.","L'oreille interne contient aussi le système vestibulaire, responsable de l'équilibre : il détecte la gravité et les accélérations."],
  en:["The cochlea, the spiral-shaped organ in the inner ear, is only 9 mm across but contains about 15,000 hair cells.","If these hair cells are damaged (by excessive noise or ageing), they don't regenerate — this is the main cause of permanent hearing loss.","The inner ear also houses the vestibular system, responsible for balance: it detects gravity and acceleration."],
    es:["El oído interno contiene la cóclea (audición) y el aparato vestibular (equilibrio), ambos con células ciliadas microscópicas que detectan vibraciones y movimientos de fluidos.","La cóclea puede distinguir frecuencias entre 20 Hz y 20 000 Hz con una precisión de 0,3 % — un rango y una resolución que superan a la mayoría de los micrófonos artificiales.","Las células ciliadas del oído no se regeneran en los mamíferos: el daño por ruido excesivo es permanente — por eso la pérdida auditiva por ruido es irreversible."]
},
'e055': {
  fr:["Les larmes émotionnelles contiennent de la leucine-enképhaline, un analgésique naturel — pleurer peut littéralement atténuer la douleur.","Il existe trois types de larmes : basales (lubrification), réflexes (protection contre les irritants) et émotionnelles (seuls les humains les produisent).","Sous microscope, chaque type de larme présente un motif cristallin différent une fois séché — un projet artistique entier leur a été consacré."],
  en:["Emotional tears contain leucine-enkephalin, a natural painkiller — crying can literally reduce pain.","There are three types of tears: basal (lubrication), reflex (protection from irritants), and emotional (only humans produce them).","Under a microscope, each type of tear shows a different crystalline pattern when dried — an entire art project has been devoted to them."],
    es:["Las lágrimas emocionales contienen leucina-encefalina (un analgésico natural), prolactina y ACTH — hormonas del estrés que el cuerpo elimina literalmente al llorar.","Las lágrimas reflejas (causadas por irritantes como la cebolla) tienen una composición diferente: más agua y lisozima, menos proteínas emocionales.","Llorar es un comportamiento exclusivamente humano entre los primates: otros animales producen lágrimas para lubricar los ojos, pero solo nosotros lloramos por razones emocionales."]
},
'e056': {
  fr:["Le cœur bat environ 100 000 fois par jour et pompe environ 7 500 litres de sang — assez pour remplir un camion-citerne.","Le cœur commence à battre dès la quatrième semaine de grossesse, bien avant que le système nerveux ne soit formé.","Le bruit du battement cardiaque (« lub-dub ») est produit par la fermeture séquentielle des valves cardiaques, pas par le muscle lui-même."],
  en:["The heart beats about 100,000 times per day and pumps roughly 7,500 litres of blood — enough to fill a fuel tanker.","The heart starts beating in the fourth week of pregnancy, well before the nervous system is formed.","The heartbeat sound ('lub-dub') is produced by the sequential closing of heart valves, not by the muscle itself."],
    es:["El corazón genera una presión sistólica de unos 120 mmHg, suficiente para proyectar un chorro de sangre a unos 9 metros de altura si una arteria fuera seccionada.","Late unas 100 000 veces al día (3 000 millones de veces en una vida media de 80 años) sin descanso, bombeando 7 500 litros de sangre diarios a través de 100 000 km de vasos.","El corazón tiene su propio sistema eléctrico (nodo sinusal) que genera los impulsos: puede seguir latiendo fuera del cuerpo mientras tenga oxígeno — un fenómeno visible en trasplantes."]
},
'e057': {
  fr:["Environ 55 % des personnes ont fait au moins un rêve lucide dans leur vie, mais seulement 23 % en font régulièrement.","Des chercheurs ont réussi à communiquer en temps réel avec des rêveurs lucides — les sujets répondaient à des questions par des mouvements oculaires convenus.","La technique la plus étudiée pour induire des rêves lucides est la MILD (Mnemonic Induction of Lucid Dreams), mise au point par Stephen LaBerge."],
  en:["About 55% of people have had at least one lucid dream, but only 23% have them regularly.","Researchers managed to communicate in real time with lucid dreamers — subjects answered questions using pre-arranged eye movements.","The most studied technique for inducing lucid dreams is MILD (Mnemonic Induction of Lucid Dreams), developed by Stephen LaBerge."],
    es:["Los sueños lúcidos activan el córtex prefrontal dorsolateral, una zona asociada a la toma de decisiones y la autoconsciencia — normalmente inactiva durante el sueño REM convencional.","En un sueño lúcido, el soñador es consciente de estar soñando y puede modificar el entorno onírico: volar, cambiar escenarios o interactuar con personajes de forma deliberada.","Técnicas como la verificación de realidad (preguntarse regularmente si se está soñando) y el MILD de Stephen LaBerge aumentan la frecuencia de sueños lúcidos con práctica regular."]
},
'e058': {
  fr:["Le fémur est l'os le plus long et le plus fort du corps humain — il ne se fracture en général que sous un choc violent.","L'os est un tissu vivant qui se remodèle constamment : l'ensemble du squelette est renouvelé tous les 7 à 10 ans.","Les os sont composés à 70 % de minéraux (surtout l'hydroxyapatite) et à 30 % de collagène — c'est le collagène qui leur donne leur flexibilité."],
  en:["The femur is the longest and strongest bone in the body — it typically fractures only under violent impact.","Bone is living tissue that constantly remodels: the entire skeleton is renewed every 7 to 10 years.","Bones are 70% mineral (mainly hydroxyapatite) and 30% collagen — it's the collagen that gives them flexibility."],
    es:["El fémur humano puede soportar fuerzas de compresión de hasta 1 700 kg y fuerzas de tracción de 800 kg — lo que lo hace más resistente que muchos materiales de construcción.","Los huesos son materiales compuestos: la hidroxiapatita mineral proporciona dureza y el colágeno orgánico proporciona flexibilidad — como el hormigón armado con sus barras de acero.","Los astronautas pierden entre el 1 y el 2 % de masa ósea por mes en el espacio por falta de gravedad — un problema crucial para misiones de larga duración como un viaje a Marte."]
},
'e059': {
  fr:["Les alvéoles pulmonaires sont au nombre d'environ 480 millions dans les deux poumons — chacune ne fait que 0,2 mm de diamètre.","Les poumons droit et gauche ne sont pas symétriques : le poumon droit a trois lobes, le gauche seulement deux, pour laisser de la place au cœur.","Si l'on comptait toutes les ramifications bronchiques, il y aurait environ 23 niveaux de division — du tronc bronchique jusqu'aux alvéoles."],
  en:["There are about 480 million alveoli across both lungs — each only 0.2 mm in diameter.","The right and left lungs are not symmetrical: the right has three lobes, the left only two, to make room for the heart.","Counting all bronchial branches, there are about 23 levels of division — from the main bronchus down to the alveoli."],
    es:["Los alvéolos pulmonares suman una superficie de intercambio gaseoso de unos 70 m², equivalente a medio campo de tenis — empaquetados en un órgano de apenas 6 litros.","Cada pulmón contiene unos 300-500 millones de alvéolos, cada uno rodeado de capilares donde el oxígeno pasa a la sangre y el CO₂ es expulsado en cada respiración.","Un adulto respira unas 20 000 veces al día, moviendo entre 7 000 y 10 000 litros de aire — todo para que el oxígeno cruce una membrana alvéolo-capilar de apenas 0,5 micrómetros de espesor."]
},
'e060': {
  fr:["La peau se renouvelle complètement environ toutes les 4 semaines — ce qui signifie que vous avez littéralement une nouvelle peau chaque mois.","Le derme contient les empreintes digitales, les glandes sudoripares et environ 3 millions de glandes sébacées.","La peau du talon est la plus épaisse du corps (jusqu'à 4 mm), tandis que celle des paupières est la plus fine (environ 0,5 mm)."],
  en:["Skin fully renews roughly every 4 weeks — meaning you literally have new skin each month.","The dermis contains fingerprints, sweat glands, and about 3 million sebaceous glands.","Heel skin is the thickest on the body (up to 4 mm), while eyelid skin is the thinnest (about 0.5 mm)."],
    es:["La piel es el órgano más grande del cuerpo: 1,5-2 m² de superficie y 4-5 kg de peso, con tres capas (epidermis, dermis e hipodermis) que protegen contra infecciones, radiación UV y deshidratación.","Contiene más de 4 millones de receptores sensoriales: termorreguladores (calor/frío), nociceptores (dolor), mecanorreceptores (presión/vibración) y propioceptores (posición).","La piel se renueva completamente cada 27-30 días: las células basales migran hacia la superficie donde mueren y se descaman — una persona produce unos 18 kg de piel muerta a lo largo de su vida."]
},
'e061': {fr:["Le cerveau humain possède environ 86 milliards de neurones — chacun formant en moyenne 7 000 connexions synaptiques.","Les synapses peuvent se renforcer ou s'affaiblir selon l'usage — c'est la plasticité synaptique, base de l'apprentissage et de la mémoire.","La vitesse de transmission d'un signal entre deux synapses est d'environ 0,5 milliseconde — mille fois plus lent qu'un circuit électronique, mais massivement parallèle."],en:["The human brain has about 86 billion neurons — each forming an average of 7,000 synaptic connections.","Synapses can strengthen or weaken with use — this is synaptic plasticity, the basis of learning and memory.","Signal transmission between two synapses takes about 0.5 milliseconds — a thousand times slower than an electronic circuit, but massively parallel."],
    es:["Con hasta 10 000 conexiones sinápticas por neurona y 86 000 millones de neuronas, el cerebro humano contiene unos 860 billones de sinapsis — una complejidad que supera la de cualquier computadora.","Cada sinapsis puede modularse en fuerza (potenciación o depresión a largo plazo), lo que permite el aprendizaje y la memoria — la red se reconfigura constantemente con la experiencia.","Se estima que el cerebro puede almacenar el equivalente de 2,5 petabytes de datos — el equivalente de 3 millones de horas de vídeo, o 300 años de televisión continua."]},
'e062': {fr:["Moins de 2 % de l'ADN humain code des protéines — le reste, longtemps appelé « ADN poubelle », joue en fait des rôles régulateurs essentiels.","L'ADN humain et celui d'une banane partagent environ 60 % de séquences communes — un héritage de notre ancêtre commun unicellulaire.","Si l'on tapait l'ADN d'une cellule à raison d'un caractère par seconde, il faudrait environ 95 ans pour tout écrire."],en:["Less than 2% of human DNA codes for proteins — the rest, long called 'junk DNA', actually plays essential regulatory roles.","Human DNA and banana DNA share about 60% of their sequences — a legacy of our common single-celled ancestor.","If you typed a cell's DNA at one character per second, it would take about 95 years to finish."],
    es:["Si se uniera el ADN de todas las células de un cuerpo humano, el filamento mediría unos 74 000 millones de km — equivalente a 500 veces la distancia del Sol a la Tierra.","Todo este ADN cabe en un volumen microscópico gracias a las histonas: proteínas-bobina alrededor de las cuales el ADN se enrolla como hilo en un carrete, compactándose 10 000 veces.","El ADN humano es idéntico en un 99,9 % entre todas las personas: el 0,1 % restante (unos 3 millones de pares de bases) explica toda la diversidad genética de nuestra especie."]},
'e063': {fr:["Cléopâtre est née en 69 av. J.-C., soit environ 2 500 ans après la construction de la pyramide de Khéops (vers 2560 av. J.-C.).","Elle parlait au moins neuf langues et fut la première souveraine ptolémaïque à apprendre l'égyptien.","Cléopâtre n'était pas égyptienne de sang — elle appartenait à la dynastie macédonienne des Ptolémées, fondée par un général d'Alexandre le Grand."],en:["Cleopatra was born in 69 BC, about 2,500 years after the Great Pyramid of Giza was built (around 2560 BC).","She spoke at least nine languages and was the first Ptolemaic ruler to learn Egyptian.","Cleopatra was not ethnically Egyptian — she belonged to the Macedonian Ptolemaic dynasty, founded by one of Alexander the Great's generals."],
    es:["Cleopatra VII nació en 69 a.C. — 2 500 años después de la construcción de las pirámides de Guiza (2560 a.C.) pero solo 2 000 años antes de nosotros.","Esta diferencia temporal es difícil de concebir: la civilización egipcia es tan antigua que ya era antigua para los propios egipcios de la época de Cleopatra.","Cuando Cleopatra visitó las pirámides, estas ya tenían la misma edad que tiene para nosotros el nacimiento de Cristo — un vértigo temporal que desafía la intuición."]},
'e064': {fr:["L'astronaute chinois Yang Liwei a confirmé en 2003 qu'il ne pouvait pas voir la Grande Muraille depuis l'orbite terrestre.","En revanche, les autoroutes, aéroports et grandes villes sont facilement visibles depuis l'espace à l'œil nu.","La Muraille mesure en moyenne 6 mètres de large — trop étroite pour être distinguée à plus de 300 km d'altitude."],en:["Chinese astronaut Yang Liwei confirmed in 2003 that he could not see the Great Wall from Earth's orbit.","Motorways, airports, and large cities, however, are easily visible from space with the naked eye.","The Wall averages about 6 metres wide — too narrow to be distinguished from over 300 km altitude."],
    es:["La Gran Muralla China, con sus 21 000 km de ramificaciones, no es visible a simple vista desde la órbita baja terrestre — su anchura de 5-8 metros es insuficiente para ser distinguida.","El astronauta chino Yang Liwei confirmó en 2003 que no pudo verla desde el espacio — el mito fue popularizado por un libro de texto de 1932 y nunca se corrigió.","Desde la órbita baja sí se ven autopistas, aeropuertos y ciudades, que son mucho más anchos y contrastados con el entorno que la muralla."]},
'e065': {fr:["L'Empire byzantin a duré plus de 1 000 ans après la chute de Rome en 476 — sa capitale Constantinople était la plus grande ville d'Europe.","Les Byzantins se considéraient eux-mêmes comme Romains et appelaient leur État « l'Empire romain ».","Constantinople est tombée aux mains des Ottomans en 1453, marquant la fin du dernier vestige direct de l'Empire romain."],en:["The Byzantine Empire lasted over 1,000 years after Rome's fall in 476 — its capital Constantinople was Europe's largest city.","The Byzantines considered themselves Romans and called their state 'the Roman Empire'.","Constantinople fell to the Ottomans in 1453, marking the end of the last direct remnant of the Roman Empire."],
    es:["El Imperio Bizantino (395-1453 d.C.) fue la continuación directa del Imperio Romano de Oriente, con Constantinopla como capital — sus habitantes se llamaban a sí mismos «romanos».","El término «bizantino» es una invención de los historiadores del siglo XVI: los propios bizantinos nunca usaron esa palabra para describirse.","Constantinopla cayó ante los turcos otomanos en 1453, poniendo fin a un imperio que había durado más de un milenio — la fecha se usa convencionalmente como fin de la Edad Media."]},
'e066': {fr:["On estime qu'entre 1600 et 1660, plus de 10 000 nobles français sont morts en duel — plus que dans certaines guerres.","Le cardinal de Richelieu, principal artisan de l'édit de 1626, fit exécuter des duellistes célèbres pour l'exemple.","Le dernier duel officiel en France a eu lieu en 1967, entre deux députés — avec une simple égratignure comme résultat."],en:["Between 1600 and 1660, an estimated 10,000+ French nobles died in duels — more than in some wars.","Cardinal Richelieu, the driving force behind the 1626 edict, had famous duellists executed as examples.","The last official duel in France took place in 1967 between two politicians — resulting in just a scratch."],
    es:["Se estima que entre 1588 y 1608 murieron más de 10 000 nobles franceses en duelos — más que en algunas guerras del periodo, lo que motivó la prohibición de 1626.","El edicto de Richelieu (1626) imponía la pena de muerte por duelo, pero la práctica persistió: los aristócratas consideraban el honor más importante que la ley.","Los duelos fueron legales en algunos estados alemanes hasta 1871 y en Uruguay hasta 1992 — una de las últimas legislaciones en abolir la práctica."]},
'e067': {fr:["Jules César a accidentellement brûlé une partie de la bibliothèque en 48 av. J.-C. lors du siège d'Alexandrie — mais pas la totalité.","À son apogée, la bibliothèque contenait entre 400 000 et 700 000 rouleaux de papyrus — la plus grande collection du monde antique.","Le concept de bibliothèque universelle d'Alexandrie a inspiré des projets modernes comme Internet Archive et le Projet Gutenberg."],en:["Julius Caesar accidentally burned part of the library in 48 BC during the siege of Alexandria — but not all of it.","At its peak, the library held between 400,000 and 700,000 papyrus scrolls — the largest collection in the ancient world.","Alexandria's concept of a universal library inspired modern projects like the Internet Archive and Project Gutenberg."],
    es:["La Biblioteca de Alejandría no fue destruida en un solo incendio espectacular: sufrió múltiples daños a lo largo de siglos — incendios, saqueos, negligencia y falta de financiación.","En su apogeo (siglo III a.C.) contenía entre 400 000 y 700 000 rollos de papiro — el mayor repositorio de conocimiento del mundo antiguo.","La pérdida de la Biblioteca es simbólica del frágil destino del conocimiento humano: obras de filósofos, científicos y poetas de la Antigüedad se perdieron para siempre."]},
'e068': {fr:["L'Althing islandais se réunissait en plein air à Thingvellir, dans une faille tectonique spectaculaire entre les plaques nord-américaine et eurasienne.","L'Islande n'a pas eu de forces armées depuis le Moyen Âge — elle reste le seul pays de l'OTAN sans armée permanente.","Le christianisme a été adopté par l'Althing en l'an 1000, après un vote pacifique plutôt qu'une conversion forcée."],en:["The Icelandic Althing met outdoors at Thingvellir, in a spectacular tectonic rift between the North American and Eurasian plates.","Iceland has had no armed forces since the Middle Ages — it remains the only NATO member without a standing army.","Christianity was adopted by the Althing in the year 1000, following a peaceful vote rather than forced conversion."],
    es:["El Althing islandés fue fundado en 930 d.C. en Thingvellir, un campo de lava donde los jefes vikingos se reunían al aire libre para dictar leyes y resolver disputas.","Es el parlamento más antiguo del mundo aún en funcionamiento, aunque fue suspendido bajo la administración danesa (1800-1843) antes de ser restaurado.","Thingvellir es también un sitio geológico único: está sobre la dorsal mesoatlántica, donde las placas tectónicas americana y euroasiática se separan visiblemente."]},
'e069': {fr:["La confusion vient de la différence entre le pouce français et le pouce anglais — 5 pieds 2 pouces français correspondent à environ 1,68 m.","Les caricatures britanniques de l'époque exagéraient sa petite taille pour ridiculiser l'ennemi — un outil de propagande efficace.","Napoléon était entouré de sa Garde impériale, des soldats sélectionnés pour leur grande taille, ce qui le faisait paraître plus petit par contraste."],en:["The confusion stems from the difference between French and English inches — 5 feet 2 French inches equals about 1.68 m.","British cartoons of the era exaggerated his short stature to ridicule the enemy — an effective propaganda tool.","Napoleon was surrounded by his Imperial Guard, soldiers selected for their tall stature, making him appear shorter by contrast."],
    es:["Napoleón medía 1,68-1,70 m, por encima de la media francesa de la época (1,64 m) — el mito de su baja estatura proviene de la confusión entre pies franceses y pies ingleses.","El caricaturista británico James Gillray lo representó como un enano agresivo para la propaganda anti-francesa — una imagen que se fijó en el imaginario popular.","Su verdadera estatura se confirma por sus ropas conservadas en museos y por la medición post-mortem realizada por su médico personal."]},
'e070': {fr:["Ce traité, le Traité de Windsor, a été invoqué par le Portugal pendant la Seconde Guerre mondiale pour accorder aux Alliés l'accès aux Açores.","Le Portugal et l'Angleterre ont combattu côte à côte dans de nombreux conflits, dont les guerres napoléoniennes et la Première Guerre mondiale.","L'alliance a même survécu à la rivalité coloniale entre les deux pays en Afrique au XIXe siècle."],en:["This treaty, the Treaty of Windsor, was invoked by Portugal during WWII to grant the Allies access to the Azores.","Portugal and England fought side by side in many conflicts, including the Napoleonic Wars and World War I.","The alliance even survived colonial rivalry between the two countries in 19th-century Africa."],
    es:["El Tratado de Windsor (1386) entre Inglaterra y Portugal es la alianza militar más antigua del mundo aún en vigor — más de 630 años de vigencia continuada.","La alianza fue invocada durante las guerras napoleónicas, la Primera y la Segunda Guerra Mundial, y sigue siendo una referencia diplomática activa.","Portugal e Inglaterra han mantenido esta alianza a pesar de cambios de régimen, revoluciones y guerras civiles en ambos países — un caso único de continuidad diplomática."]},
'e071': {fr:["La guerre de Trente Ans a commencé comme un conflit religieux entre protestants et catholiques, mais s'est transformée en lutte de pouvoir entre grandes puissances.","Le traité de Westphalie (1648) qui l'a conclue est considéré comme le fondement du système moderne d'États-nations souverains.","La population du Saint-Empire romain germanique est passée d'environ 21 millions à 13 millions pendant le conflit."],en:["The Thirty Years' War started as a religious conflict between Protestants and Catholics, but became a power struggle between great powers.","The Treaty of Westphalia (1648) that ended it is considered the foundation of the modern system of sovereign nation-states.","The Holy Roman Empire's population dropped from about 21 million to 13 million during the conflict."],
    es:["La Guerra de los Treinta Años (1618-1648) devastó Europa Central: algunas regiones alemanas perdieron entre el 25 y el 40 % de su población — una catástrofe demográfica comparable a la Peste Negra.","Lo que comenzó como un conflicto religioso entre católicos y protestantes se transformó en una lucha geopolítica entre las grandes potencias europeas: España, Francia, Suecia y el Sacro Imperio.","La Paz de Westfalia (1648) que puso fin a la guerra estableció el principio de soberanía nacional y el sistema de estados-nación que sigue siendo la base del orden internacional."]},
'e072': {fr:["Leif Erikson a atteint l'Amérique du Nord vers l'an 1000, établissant un campement à Terre-Neuve (actuel Canada).","Les sagas islandaises mentionnent un lieu appelé « Vinland » — probablement la côte est du Canada ou de la Nouvelle-Angleterre.","Les Vikings ne portaient pas de casques à cornes — cette image provient d'opéras du XIXe siècle, pas de sources historiques."],en:["Leif Erikson reached North America around the year 1000, establishing a camp in Newfoundland (present-day Canada).","Icelandic sagas mention a place called 'Vinland' — probably the east coast of Canada or New England.","Vikings did not wear horned helmets — that image comes from 19th-century operas, not historical sources."],
    es:["Los vikingos llegaron a América del Norte hacia el año 1000 d.C. bajo el liderazgo de Leif Eriksson, fundando un asentamiento en L'Anse aux Meadows (Terranova, Canadá).","El sitio fue excavado en 1960 por los arqueólogos Helge y Anne Stine Ingstad, confirmando las sagas nórdicas que describían «Vinlandia» — una tierra de viñas y pastos.","Los vikingos abandonaron América tras unos pocos años debido a conflictos con los pueblos indígenas — cinco siglos antes de que Colón cruzara el Atlántico."]},
'e073': {fr:["Avant Gutenberg, un moine copiste mettait environ un an pour reproduire un seul exemplaire de la Bible.","La Bible de Gutenberg, imprimée vers 1455, comptait 180 exemplaires — il en reste 49 aujourd'hui, parmi les livres les plus précieux du monde.","L'imprimerie a été un facteur clé de la Réforme protestante : Luther a pu diffuser ses 95 thèses massivement en quelques semaines."],en:["Before Gutenberg, a monk copyist took about a year to reproduce a single Bible.","The Gutenberg Bible, printed around 1455, had a run of 180 copies — 49 survive today, among the world's most valuable books.","The printing press was a key factor in the Protestant Reformation: Luther could spread his 95 Theses widely within weeks."],
    es:["Antes de Gutenberg, un libro manuscrito costaba el equivalente de varios años de salario de un artesano — después de la imprenta, los precios cayeron un 80 % en pocas décadas.","La Biblia de Gutenberg (1455) fue el primer libro impreso con tipos móviles metálicos en Europa — se imprimieron unas 180 copias, de las cuales sobreviven 49.","La imprenta democratizó el conocimiento: en 1500, apenas 50 años después, ya se habían impreso más de 20 millones de volúmenes en Europa — una revolución comparable a Internet."]},
'e074': {fr:["Les Égyptiens momifiaient aussi des crocodiles, des ibis, des faucons et même des scarabées — souvent comme offrandes aux dieux.","Le processus de momification humaine prenait environ 70 jours et impliquait le retrait de tous les organes sauf le cœur.","Les bandelettes d'une seule momie, mises bout à bout, pouvaient mesurer plus de 1,5 km de long."],en:["Egyptians also mummified crocodiles, ibises, falcons, and even beetles — often as offerings to the gods.","Human mummification took about 70 days and involved removing all organs except the heart.","The wrappings from a single mummy, laid end to end, could stretch over 1.5 km."],
    es:["Los antiguos egipcios momificaron millones de animales como ofrendas a los dioses: gatos para Bastet, ibis para Thoth, cocodrilos para Sobek y toros para Apis.","Arqueólogos han descubierto catacumbas con más de 4 millones de momias de ibis y 8 millones de momias de perros — una industria funeraria animal a escala industrial.","Estudios con escáneres CT revelan que muchas momias animales están vacías o contienen solo fragmentos: una estafa milenaria por parte de los vendedores de ofrendas."]},
'e075': {fr:["Hiroo Onoda a vécu 29 ans dans la jungle des Philippines, convaincu que la guerre continuait — il n'a rendu les armes que sur ordre de son ancien commandant.","Plusieurs autres soldats japonais ont aussi tenu des décennies : Teruo Nakamura s'est rendu en 1974, quelques mois après Onoda.","Onoda a écrit ses mémoires et ouvert une école de survie au Japon après son retour — il est décédé en 2014 à 91 ans."],en:["Hiroo Onoda lived 29 years in the Philippine jungle, convinced the war was still on — he only surrendered on orders from his former commander.","Several other Japanese soldiers also held out for decades: Teruo Nakamura surrendered in 1974, months after Onoda.","Onoda wrote his memoirs and opened a survival school in Japan after returning — he died in 2014 at age 91."],
    es:["El teniente Hiroo Onoda continuó luchando en la isla filipina de Lubang hasta 1974, convencido de que la rendición de Japón era propaganda enemiga.","Solo aceptó rendirse cuando su antiguo oficial superior viajó a Filipinas y le dio personalmente la orden de deponer las armas — 29 años después del fin de la guerra.","Onoda no fue el último: el soldado Teruo Nakamura fue encontrado en Indonesia en 1974, unos meses después — ambos habían sobrevivido décadas en la selva con recursos mínimos."]},
'e076': {fr:["Au sommet de la bulle, un seul bulbe de tulipe « Semper Augustus » valait plus qu'une maison de canal à Amsterdam.","La crise a éclaté quand les acheteurs ont réalisé qu'ils payaient des fortunes pour des contrats à terme, pas pour de vraies fleurs.","Contrairement à la légende, les effets économiques réels de la tulipomanie furent relativement limités — la bulle était surtout spéculative et localisée."],en:["At the bubble's peak, a single 'Semper Augustus' tulip bulb was worth more than a canal house in Amsterdam.","The crash came when buyers realised they were paying fortunes for futures contracts, not actual flowers.","Contrary to legend, the real economic effects of tulip mania were relatively limited — the bubble was mostly speculative and localised."],
    es:["En el pico de la tulipomanía de 1637, un solo bulbo de tulipán Semper Augustus podía costar el equivalente de una casa de lujo en los canales de Ámsterdam.","La burbuja estalló en febrero de 1637 cuando los compradores dejaron de presentarse en las subastas — los precios cayeron un 99 % en semanas, arruinando a especuladores.","Los historiadores debaten si fue una verdadera burbuja o un fenómeno exagerado por fuentes posteriores — pero sigue siendo el ejemplo paradigmático de especulación irracional."]},
'e077': {fr:["Le marathon commémore la légende de Philippidès, qui aurait couru d'Athènes à Marathon (ou l'inverse) pour annoncer la victoire sur les Perses.","La distance officielle de 42,195 km n'a été fixée qu'en 1921 — aux JO de 1908, on l'avait ajustée pour que l'arrivée soit devant la loge royale.","Spyridon Louis est devenu un héros national grec et a reçu des offres de mariage, de nourriture gratuite à vie et même une boutique."],en:["The marathon commemorates the legend of Pheidippides, who supposedly ran from Athens to Marathon (or vice versa) to announce victory over the Persians.","The official distance of 42.195 km was only fixed in 1921 — at the 1908 Olympics, it was adjusted so the finish was in front of the royal box.","Spyridon Louis became a Greek national hero and received offers of marriage, free food for life, and even a shop."],
    es:["Spyridon Louis, un aguador de profesión, ganó el primer maratón olímpico de 1896 en 2 horas 58 minutos — convirtiéndose en héroe nacional griego.","La carrera partió de Maratón hasta Atenas (40 km, no los 42,195 km actuales) para conmemorar la legendaria carrera de Filípides en 490 a.C.","Louis fue recibido por una multitud enfervorecida y el rey Jorge I lo acompañó a pie en la última vuelta al estadio Panatenaico — un momento fundacional del olimpismo moderno."]},
'e078': {fr:["L'assassinat de François-Ferdinand à Sarajevo le 28 juin 1914 a été commis par Gavrilo Princip, un nationaliste serbe de 19 ans.","Le système d'alliances a transformé un conflit régional en guerre mondiale en seulement six semaines.","La Première Guerre mondiale a mobilisé plus de 70 millions de soldats et causé environ 20 millions de morts."],en:["The assassination of Franz Ferdinand in Sarajevo on 28 June 1914 was carried out by Gavrilo Princip, a 19-year-old Serbian nationalist.","The alliance system turned a regional conflict into a world war in just six weeks.","World War I mobilised over 70 million soldiers and caused about 20 million deaths."],
    es:["El asesinato del archiduque Francisco Fernando en Sarajevo (28 de junio de 1914) fue la chispa, pero las tensiones que llevaron a la guerra se acumularon durante décadas.","El sistema de alianzas (Triple Alianza vs Triple Entente), el militarismo, el imperialismo y el nacionalismo crearon un polvorín que cualquier incidente podía detonar.","Un detalle irónico: el asesino Gavrilo Princip falló su primer intento y fue el azar (un giro equivocado del coche del archiduque) lo que le dio una segunda oportunidad."]},
'e079': {fr:["La Déclaration des droits de l'Homme de 1789 s'inspire aussi des Lumières françaises, notamment de Voltaire, Montesquieu et Rousseau.","Le marquis de La Fayette, héros de la Révolution américaine, a personnellement contribué à la rédaction de la Déclaration française.","La devise « Liberté, Égalité, Fraternité » n'a été officiellement adoptée comme devise nationale qu'en 1848, lors de la Deuxième République."],en:["The 1789 Declaration of the Rights of Man also draws from the French Enlightenment, particularly Voltaire, Montesquieu, and Rousseau.","The Marquis de Lafayette, hero of the American Revolution, personally helped draft the French Declaration.","The motto 'Liberty, Equality, Fraternity' was only officially adopted as the national motto in 1848, during the Second Republic."],
    es:["La Revolución Americana (1776) precedió a la Francesa (1789) e influyó directamente en ella: Lafayette, héroe de la independencia americana, fue un líder de la Revolución Francesa.","La Declaración de Independencia de Jefferson y la Constitución americana inspiraron la Declaración de los Derechos del Hombre y del Ciudadano francesa.","Sin embargo, las revoluciones tomaron caminos muy diferentes: la americana preservó la estabilidad institucional, mientras la francesa derivó en el Terror, Napoleón y décadas de inestabilidad."]},
'e080': {fr:["La Magna Carta garantissait aux barons le droit à un procès équitable et limitait le pouvoir du roi — des principes qui ont inspiré les démocraties modernes.","Le roi Jean sans Terre a signé la charte sous la contrainte et a tenté de l'annuler quelques semaines plus tard.","Seules quatre copies originales de la Magna Carta de 1215 ont survécu — deux sont à la British Library, une à Salisbury et une à Lincoln."],en:["Magna Carta guaranteed barons the right to a fair trial and limited the king's power — principles that inspired modern democracies.","King John signed the charter under duress and tried to annul it just weeks later.","Only four original copies of the 1215 Magna Carta survive — two at the British Library, one at Salisbury, and one at Lincoln."],
    es:["La Carta Magna (1215) fue un acuerdo entre el rey Juan de Inglaterra y sus barones rebeldes, no un documento democrático — protegía los privilegios feudales, no los derechos individuales.","Solo 3 de sus 63 cláusulas originales siguen vigentes en el derecho inglés, incluyendo el habeas corpus y el derecho a un juicio justo — principios fundamentales del Estado de derecho.","La Carta Magna fue anulada por el papa a las pocas semanas de su firma, pero fue reemitida varias veces y se convirtió en símbolo de la limitación del poder real."]},
'e081': {fr:["Le cunéiforme s'écrivait en pressant un roseau taillé en biseau dans de l'argile molle — d'où la forme en coins caractéristique.","Ce système d'écriture a été utilisé pendant plus de 3 000 ans pour écrire en sumérien, akkadien, babylonien et d'autres langues.","Le déchiffrement du cunéiforme au XIXe siècle a révélé l'Épopée de Gilgamesh, le plus ancien texte littéraire connu de l'humanité."],en:["Cuneiform was written by pressing a sharpened reed into soft clay — hence the characteristic wedge shapes.","This writing system was used for over 3,000 years to write Sumerian, Akkadian, Babylonian, and other languages.","The decipherment of cuneiform in the 19th century revealed the Epic of Gilgamesh, the oldest known literary text in human history."],
    es:["La escritura cuneiforme sumeria usaba una cuña de caña presionada sobre arcilla húmeda, produciendo marcas triangulares — un sistema que evolucionó desde pictogramas hasta signos abstractos.","Fue usada durante más de 3 000 años por múltiples civilizaciones (sumerios, acadios, babilonios, asirios, hititas) para escribir en diferentes lenguas.","Su desciframiento en el siglo XIX por Henry Rawlinson (basándose en la inscripción trilingüe de Behistún) abrió una ventana a las primeras civilizaciones de la historia humana."]},
'e082': {fr:["La Peste noire est arrivée en Europe par des navires marchands génois venant de Crimée, où le siège de Caffa avait catapulté des cadavres infectés.","La bactérie Yersinia pestis, responsable de la peste, était transmise par les puces des rats noirs qui proliféraient dans les villes médiévales.","Paradoxalement, la Peste noire a amélioré les conditions des survivants : la pénurie de main-d'œuvre a fait monter les salaires et accéléré la fin du servage."],en:["The Black Death reached Europe via Genoese trading ships from Crimea, where the siege of Caffa had catapulted infected corpses.","The bacterium Yersinia pestis, which causes plague, was transmitted by fleas on black rats that thrived in medieval cities.","Paradoxically, the Black Death improved conditions for survivors: labour shortages raised wages and accelerated serfdom's end."],
    es:["La Peste Negra (1347-1353) mató entre 75 y 200 millones de personas en Eurasia — entre un tercio y la mitad de la población europea desapareció en menos de una década.","La bacteria Yersinia pestis se transmitía por pulgas de ratas que infestaban los barcos comerciales — la Ruta de la Seda y las rutas marítimas propagaron la pandemia a una velocidad sin precedentes.","Paradójicamente, la despoblación causó una mejora de las condiciones laborales: la escasez de mano de obra aumentó los salarios y debilitó el feudalismo, acelerando transformaciones sociales."]},
'e083': {fr:["La civilisation égyptienne a vu naître et mourir environ 170 pharaons au cours de 30 dynasties successives.","Les Égyptiens avaient déjà inventé le dentifrice, le calendrier solaire de 365 jours et les serrures à verrou.","Le Sphinx de Gizeh, sculpté vers 2500 av. J.-C., est la plus grande sculpture monolithique du monde — il mesure 73 mètres de long."],en:["Egyptian civilisation saw about 170 pharaohs rise and fall across 30 successive dynasties.","The Egyptians had already invented toothpaste, the 365-day solar calendar, and pin tumbler locks.","The Sphinx of Giza, carved around 2500 BC, is the world's largest monolithic sculpture — 73 metres long."],
    es:["La civilización del antiguo Egipto duró más de 3 000 años (3100 a.C. - 30 a.C.), con 30 dinastías de faraones — una longevidad que ninguna otra civilización ha igualado.","Los egipcios inventaron el papiro, la tinta, el calendario de 365 días, técnicas quirúrgicas avanzadas y monumentos que siguen en pie tras 4 500 años.","Cuando Roma conquistó Egipto en el 30 a.C. (muerte de Cleopatra), la civilización egipcia ya era más antigua que lo que Roma sería para nosotros — una escala temporal difícil de comprender."]},
'e084': {fr:["Pluton a un cœur : la sonde New Horizons a révélé en 2015 une vaste plaine en forme de cœur, nommée Tombaugh Regio.","Pluton possède cinq lunes, dont Charon, si grande qu'on parle souvent d'un « système binaire » plutôt que d'une planète et son satellite.","Une année sur Pluton dure 248 années terrestres — depuis sa découverte en 1930, elle n'a pas encore complété une seule orbite autour du Soleil."],en:["Pluto has a heart: the New Horizons probe revealed in 2015 a vast heart-shaped plain named Tombaugh Regio.","Pluto has five moons, including Charon, so large that the pair is often called a 'binary system' rather than a planet and satellite.","A year on Pluto lasts 248 Earth years — since its discovery in 1930, it hasn't yet completed a single orbit around the Sun."],
    es:["Plutón tiene un diámetro de 2 377 km, menor que la Luna (3 474 km) — su masa es solo el 0,2 % de la terrestre y el 18 % de la lunar.","Fue descubierto en 1930 por Clyde Tombaugh y considerado el noveno planeta durante 76 años, hasta que la IAU lo reclasificó como planeta enano en 2006.","La sonda New Horizons reveló en 2015 un mundo sorprendentemente complejo: montañas de hielo de agua, glaciares de nitrógeno y una tenue atmósfera azulada."]},
'e085': {fr:["Saturne a une densité moyenne de 0,687 g/cm³ — environ 30 % moins dense que l'eau (1 g/cm³).","Les anneaux de Saturne sont composés de milliards de morceaux de glace et de roche, allant de la taille d'un grain de sable à celle d'une maison.","Saturne possède au moins 146 lunes confirmées — dont Titan, la seule lune du système solaire avec une atmosphère dense."],en:["Saturn has an average density of 0.687 g/cm³ — about 30% less dense than water (1 g/cm³).","Saturn's rings are composed of billions of pieces of ice and rock, ranging from sand-grain size to house-sized.","Saturn has at least 146 confirmed moons — including Titan, the only moon in the solar system with a thick atmosphere."],
    es:["La densidad de Saturno es de 0,687 g/cm³, inferior a la del agua (1 g/cm³) — si existiera un océano lo suficientemente grande, Saturno flotaría en él.","Saturno es mayoritariamente hidrógeno y helio gaseosos, con un pequeño núcleo rocoso — su baja densidad media se debe a la predominancia de gases ligeros.","Sus anillos, aunque espectaculares (280 000 km de diámetro), tienen un espesor de apenas 10-100 metros — proporcionalmente más finos que una hoja de papel."]},
'e086': {fr:["Le régolithe lunaire est le résultat de milliards d'années d'impacts de micrométéorites qui ont pulvérisé la roche de surface.","Les astronautes d'Apollo ont rapporté que la poussière lunaire sentait la poudre à canon, probablement à cause de l'oxydation au contact de l'air.","La poussière lunaire est si abrasive qu'elle a rayé les visières de casques et usé les joints des combinaisons spatiales."],en:["Lunar regolith is the result of billions of years of micrometeorite impacts that pulverised the surface rock.","Apollo astronauts reported that moon dust smelled like gunpowder, likely due to oxidation when exposed to air.","Lunar dust is so abrasive it scratched helmet visors and wore out spacesuit seals."],
    es:["El regolito lunar es una capa de polvo y fragmentos de roca de 2-15 metros de espesor, producida por miles de millones de años de impactos de micrometeoritos.","Este polvo es extremadamente abrasivo porque no ha sido erosionado por agua ni viento: sus partículas tienen bordes afilados que dañaron los trajes y equipos de los astronautas del Apollo.","El regolito se carga electrostáticamente por la radiación solar y puede levitar sobre la superficie lunar — un fenómeno que complica la exploración y el mantenimiento de equipos."]},
'e087': {fr:["En 2022, le télescope Event Horizon a publié la première image directe de Sagittarius A*, confirmant les prédictions de la relativité générale.","Si le Soleil était remplacé par un trou noir de même masse, les orbites des planètes ne changeraient pas — seule la lumière disparaîtrait.","L'horizon des événements de Sagittarius A* a un diamètre d'environ 25 millions de km — plus petit que l'orbite de Mercure."],en:["In 2022, the Event Horizon Telescope published the first direct image of Sagittarius A*, confirming general relativity predictions.","If the Sun were replaced by a black hole of equal mass, planetary orbits wouldn't change — only the light would vanish.","Sagittarius A*'s event horizon has a diameter of about 25 million km — smaller than Mercury's orbit."],
    es:["Sagittarius A* fue fotografiado por primera vez en 2022 por el Event Horizon Telescope — una red de radiotelescopios del tamaño de la Tierra que funciona como un telescopio virtual gigante.","A pesar de su masa (4 millones de soles), Sgr A* es relativamente tranquilo comparado con los agujeros negros supermasivos de otras galaxias, que emiten jets de energía devastadores.","Nada que cruce el horizonte de eventos de Sgr A* puede escapar — ni siquiera la luz. El radio de su horizonte de eventos es de unos 12 millones de km, similar a la órbita de Mercurio."]},
'e088': {fr:["Voyager 1 se trouve à plus de 24 milliards de km de la Terre — les signaux radio mettent plus de 22 heures à nous parvenir.","La sonde emporte un disque d'or contenant des sons, de la musique et des images destinés à d'éventuelles civilisations extraterrestres.","Voyager 1 est alimentée par des générateurs thermoélectriques au plutonium-238, qui devraient fonctionner jusqu'à environ 2025-2030."],en:["Voyager 1 is over 24 billion km from Earth — radio signals take more than 22 hours to reach us.","The probe carries a golden record containing sounds, music, and images intended for potential extraterrestrial civilisations.","Voyager 1 is powered by plutonium-238 thermoelectric generators, expected to function until around 2025–2030."],
    es:["Voyager 1 viaja a 61 000 km/h y se encuentra a más de 24 000 millones de km del Sol — su señal de radio tarda más de 22 horas en llegar a la Tierra.","Lleva un disco de oro con saludos en 55 idiomas, música (Bach, Mozart, Chuck Berry), sonidos de la Tierra y 115 imágenes que representan a la humanidad.","Con su generador de plutonio agotándose, Voyager 1 dejará de funcionar hacia 2025-2030 — pero el disco de oro seguirá viajando por el espacio interestelar durante millones de años."]},
'e089': {fr:["Olympus Mons a un diamètre de 600 km — il couvrirait la France entière. Sa caldeira seule mesure 80 km de large.","Le volcan est si large et sa pente si douce (environ 5°) qu'un observateur au pied ne verrait pas le sommet — il dépasserait l'horizon.","Mars possède aussi Valles Marineris, un canyon de 4 000 km de long — dix fois plus long que le Grand Canyon."],en:["Olympus Mons is 600 km in diameter — it would cover all of France. Its caldera alone is 80 km wide.","The volcano is so wide and its slope so gentle (about 5°) that an observer at the base couldn't see the summit — it would extend beyond the horizon.","Mars also has Valles Marineris, a 4,000 km canyon — ten times longer than the Grand Canyon."],
    es:["El Olympus Mons marciano mide 22 km de alto (2,5 veces el Everest) y 600 km de diámetro — su base es tan grande que desde el borde no se ve la cumbre por la curvatura del planeta.","Es un volcán escudo formado por la acumulación de flujos de lava durante miles de millones de años — en Marte no hay tectónica de placas, así que el magma se acumula siempre en el mismo punto.","La última erupción del Olympus Mons podría haber ocurrido hace apenas 25 millones de años — lo que significa que Marte podría ser aún volcánicamente activo."]},
'e090': {fr:["La NASA a toutefois converti en son des ondes électromagnétiques captées par ses sondes — ces « sons de l'espace » sont fascinants mais artificiels.","Le son le plus grave de l'univers a été détecté autour d'un trou noir dans l'amas de Persée — un Si bémol 57 octaves sous le do moyen.","Dans l'espace, les astronautes communiquent par radio car les ondes électromagnétiques, contrairement au son, n'ont pas besoin de matière."],en:["NASA has, however, converted electromagnetic waves captured by probes into sound — these 'sounds of space' are fascinating but artificial.","The lowest sound in the universe was detected around a black hole in the Perseus cluster — a B-flat 57 octaves below middle C.","In space, astronauts communicate by radio since electromagnetic waves, unlike sound, don't need a medium."],
    es:["El sonido necesita un medio material para propagarse (aire, agua, sólido) — en el vacío del espacio, las moléculas están tan separadas que no pueden transmitir vibraciones acústicas.","Sin embargo, en 2022 la NASA publicó una «sonificación» del agujero negro de Perseo: ondas de presión en el gas caliente del cúmulo galáctico traducidas a frecuencias audibles.","Las películas de ciencia ficción ignoran este hecho por razones dramáticas — en realidad, las explosiones en el espacio serían completamente silenciosas."]},
'e091': {fr:["La Grande Tache rouge rétrécit : elle faisait 40 000 km de large au XIXe siècle, mais ne mesure plus qu'environ 16 000 km aujourd'hui.","Les vents à l'intérieur de la tempête atteignent 680 km/h — plus du double des ouragans les plus puissants sur Terre.","Jupiter possède au moins 95 lunes connues, dont les quatre galiléennes (Io, Europe, Ganymède, Callisto), découvertes par Galilée en 1610."],en:["The Great Red Spot is shrinking: it was 40,000 km wide in the 19th century but now measures only about 16,000 km.","Winds inside the storm reach 680 km/h — more than double Earth's most powerful hurricanes.","Jupiter has at least 95 known moons, including the four Galilean moons (Io, Europa, Ganymede, Callisto), discovered by Galileo in 1610."],
    es:["La Gran Mancha Roja de Júpiter es un anticiclón con vientos de hasta 640 km/h y un diámetro que ha variado entre 1 y 3 veces el de la Tierra.","Observada desde al menos 1665, podría ser la tormenta más longeva del sistema solar — aunque datos recientes muestran que se está reduciendo progresivamente.","La Mancha Roja se eleva unos 8 km por encima de las nubes circundantes y su color podría deberse a compuestos de azufre y fósforo expuestos a la radiación ultravioleta solar."]},
'e092': {fr:["Les étoiles à neutrons sont si denses qu'une cuillère à café de leur matière pèserait environ 6 milliards de tonnes.","Elles naissent de l'effondrement d'étoiles massives lors d'une supernova — tout le contenu de l'étoile est compressé dans une sphère de 20 km.","Certains pulsars émettent des faisceaux de rayons X si précis qu'ils pourraient servir de système GPS cosmique pour la navigation spatiale."],en:["Neutron stars are so dense that a teaspoon of their material would weigh about 6 billion tonnes.","They are born from the collapse of massive stars during a supernova — the entire star compressed into a 20 km sphere.","Some pulsars emit X-ray beams so precise they could serve as a cosmic GPS for space navigation."],
    es:["Los púlsares son estrellas de neutrones que giran a velocidades vertiginosas emitiendo haces de radiación como faros cósmicos — el más rápido conocido gira 716 veces por segundo.","Una estrella de neutrones tiene la masa de 1-2 soles comprimida en una esfera de solo 20 km de diámetro — una cucharadita de su materia pesaría mil millones de toneladas.","La regularidad de los púlsares es tan precisa que cuando Jocelyn Bell Burnell descubrió el primero en 1967, lo apodaron «LGM-1» (Little Green Men) porque parecía una señal artificial."]},
'e093': {fr:["Le Soleil convertit environ 600 millions de tonnes d'hydrogène en hélium chaque seconde par fusion nucléaire.","Malgré cette perte colossale, le Soleil a assez de carburant pour briller encore environ 5 milliards d'années.","La température au cœur du Soleil atteint 15 millions de degrés Celsius — assez pour maintenir la fusion thermonucléaire."],en:["The Sun converts about 600 million tonnes of hydrogen into helium every second through nuclear fusion.","Despite this colossal loss, the Sun has enough fuel to shine for another 5 billion years or so.","The temperature at the Sun's core reaches 15 million degrees Celsius — enough to sustain thermonuclear fusion."],
    es:["El Sol convierte 600 millones de toneladas de hidrógeno en helio cada segundo mediante fusión nuclear — pero su masa es tan colosal que apenas pierde el 0,03 % en mil millones de años.","La energía producida en el núcleo tarda entre 10 000 y 170 000 años en llegar a la superficie como luz visible — el fotón rebota millones de veces entre los átomos del interior solar.","Al Sol le quedan unos 5 000 millones de años de vida antes de convertirse en una gigante roja que engullirá Mercurio, Venus y posiblemente la Tierra."]},
'e094': {fr:["Il y a 4,5 milliards d'années, la Lune était environ 15 fois plus proche de la Terre — les marées étaient donc colossales.","Quand la Lune sera suffisamment éloignée, les éclipses solaires totales ne seront plus possibles — elle sera trop petite pour couvrir le Soleil.","L'éloignement de la Lune ralentit aussi la rotation terrestre : les jours s'allongent d'environ 2,3 millisecondes par siècle."],en:["4.5 billion years ago, the Moon was about 15 times closer to Earth — tides were therefore colossal.","When the Moon is distant enough, total solar eclipses will no longer be possible — it will be too small to cover the Sun.","The Moon's retreat also slows Earth's rotation: days lengthen by about 2.3 milliseconds per century."],
    es:["La Luna se aleja de la Tierra 3,8 cm por año debido a la transferencia de energía rotacional terrestre a energía orbital lunar a través de las mareas.","Hace 4 500 millones de años, la Luna estaba mucho más cerca y un día terrestre duraba solo 5 horas — las mareas eran colosales y la Luna dominaba el cielo.","Dentro de miles de millones de años, la Luna estará tan lejos que los eclipses solares totales serán imposibles — vivimos en una era cósmica privilegiada para observarlos."]},
'e095': {fr:["Le nuage de Sagittaire B2 contient suffisamment d'éthanol pour remplir 400 billions de billions de pintes de bière.","On y a aussi détecté du formate d'éthyle, la molécule responsable de l'arôme des framboises — l'espace sent la framboise et le rhum.","Ces molécules organiques complexes dans l'espace soutiennent l'hypothèse que les briques de la vie ont pu se former dans les nuages interstellaires."],en:["The Sagittarius B2 cloud contains enough ethanol to fill 400 trillion trillion pints of beer.","Ethyl formate, the molecule responsible for raspberry flavour, has also been detected there — space smells of raspberries and rum.","These complex organic molecules in space support the hypothesis that life's building blocks may have formed in interstellar clouds."],
    es:["La nube molecular Sagittarius B2, cerca del centro de la Vía Láctea, contiene mil millones de miles de millones de litros de alcohol etílico — suficiente para llenar 400 billones de jarras de cerveza.","También contiene formiato de etilo, la molécula que da a las frambuesas su aroma, y acetato de etilo — la química orgánica es sorprendentemente abundante en el espacio interestelar.","Estas moléculas se forman en la superficie de granos de polvo cósmico por reacciones de bajo rendimiento que se acumulan durante millones de años."]},
'e096': {fr:["La surface de Vénus atteint environ 465 °C — assez chaud pour faire fondre le plomb — à cause d'un effet de serre massif.","L'atmosphère de Vénus est composée à 96 % de CO₂ et sa pression atmosphérique est 90 fois celle de la Terre.","Vénus tourne sur elle-même à l'envers (rotation rétrograde) et si lentement qu'un jour vénusien dure plus longtemps qu'une année vénusienne."],en:["Venus's surface reaches about 465°C — hot enough to melt lead — due to a massive greenhouse effect.","Venus's atmosphere is 96% CO₂ and its atmospheric pressure is 90 times that of Earth.","Venus rotates backwards (retrograde rotation) and so slowly that a Venusian day is longer than a Venusian year."],
    es:["Venus es el planeta más caliente (462 °C de media) a pesar de estar más lejos del Sol que Mercurio, porque su densa atmósfera de CO₂ atrapa el calor mediante un efecto invernadero extremo.","La presión atmosférica en la superficie de Venus es 92 veces la terrestre — equivalente a estar a 900 metros de profundidad bajo el mar.","Venus gira sobre sí mismo en sentido contrario al de los demás planetas (rotación retrógrada) y tan lentamente que un día venusiano (243 días terrestres) es más largo que su año (225 días)."]},
'e097': {fr:["La queue de poussière suit la trajectoire de la comète, tandis que la queue ionisée pointe toujours à l'opposé du Soleil, poussée par le vent solaire.","Les comètes sont souvent appelées « boules de neige sale » — elles sont composées de glace, de poussière et de roches.","La comète de Halley revient tous les 75-79 ans — elle est documentée depuis au moins 240 av. J.-C. et reviendra en 2061."],en:["The dust tail follows the comet's path, while the ion tail always points away from the Sun, pushed by solar wind.","Comets are often called 'dirty snowballs' — they're made of ice, dust, and rock.","Halley's Comet returns every 75–79 years — documented since at least 240 BC, it will return in 2061."],
    es:["La cola de polvo de un cometa es curvada y blanca (refleja la luz solar), mientras que la cola iónica es recta y azulada (gas ionizado empujado por el viento solar).","Ambas colas apuntan siempre en dirección opuesta al Sol, independientemente de la dirección del movimiento del cometa — son empujadas por la presión de radiación y el viento solar.","El cometa Halley pasa cada 75-76 años: Mark Twain nació en 1835 durante un paso y murió en 1910 durante el siguiente — tal como él mismo había predicho."]},
'e098': {fr:["Malgré le mot « collision », les étoiles individuelles ne se heurteront probablement pas — l'espace entre elles est trop vaste.","La galaxie résultante a déjà un surnom : Milkomeda (ou Milkdromeda), un mélange de Milky Way et Andromeda.","Andromède se rapproche de nous à environ 110 km/s — elle est déjà visible à l'œil nu dans le ciel nocturne."],en:["Despite the word 'collision', individual stars probably won't hit each other — the space between them is too vast.","The resulting galaxy already has a nickname: Milkomeda (or Milkdromeda), a blend of Milky Way and Andromeda.","Andromeda is approaching us at about 110 km/s — it is already visible to the naked eye in the night sky."],
    es:["La Vía Láctea y Andrómeda se acercan a 110 km/s y colisionarán dentro de unos 4 500 millones de años, formando una nueva galaxia elíptica gigante llamada «Milkomeda».","A pesar de la colisión galáctica, la probabilidad de que dos estrellas choquen es prácticamente nula: las distancias entre estrellas son tan enormes que las galaxias se atraviesan como fantasmas.","El Sol seguirá existiendo durante la fusión, pero habrá sido eyectado a una órbita diferente — la Tierra, si aún existe, verá un cielo nocturno radicalmente diferente."]},
'e099': {fr:["En microgravité, la colonne vertébrale se décompresse car les disques intervertébraux ne sont plus comprimés — d'où le gain de taille.","L'effet est temporaire : les astronautes retrouvent leur taille normale quelques jours après leur retour sur Terre.","Scott Kelly et son frère jumeau Mark, resté sur Terre, ont été étudiés par la NASA pour comprendre les effets du séjour spatial — c'est l'étude « Twins Study »."],en:["In microgravity, the spine decompresses because intervertebral discs are no longer compressed — hence the height gain.","The effect is temporary: astronauts return to normal height within days of landing.","Scott Kelly and his twin Mark, who stayed on Earth, were studied by NASA to understand spaceflight effects — the famous 'Twins Study'."],
    es:["Scott Kelly creció 2 cm durante su año en la ISS porque la falta de gravedad permite que las vértebras se separen ligeramente — volvió a su estatura normal tras unas semanas en Tierra.","La NASA comparó a Scott con su gemelo idéntico Mark (que permaneció en Tierra) en el «Twin Study»: Scott mostró cambios en la expresión genética, la flora intestinal y los telómeros.","Estos datos son cruciales para planificar misiones a Marte (6-9 meses de viaje): la microgravedad afecta la visión, la densidad ósea, la masa muscular y el sistema cardiovascular."]},
'e100': {fr:["L'univers observable est limité par la vitesse de la lumière et l'âge de l'univers (13,8 milliards d'années) — pas par sa taille réelle.","L'expansion de l'univers fait que des objets visibles aujourd'hui sont en réalité à 46 milliards d'années-lumière de nous — bien plus que les 13,8 milliards attendus.","Certains modèles cosmologiques estiment que l'univers total pourrait être 250 fois plus grand que l'univers observable — voire infini."],en:["The observable universe is limited by the speed of light and the age of the universe (13.8 billion years) — not by its actual size.","The expansion of the universe means objects visible today are actually 46 billion light-years away — far more than the expected 13.8 billion.","Some cosmological models estimate the total universe could be 250 times larger than the observable one — or even infinite."],
    es:["El universo observable tiene un diámetro de 93 000 millones de años-luz porque la expansión del espacio ha alejado los objetos más distantes mucho más allá de los 13 800 millones de años-luz que la edad del universo sugeriría.","Más allá del universo observable podría haber una extensión infinita (o finita pero sin bordes) de espacio que nunca podremos ver porque su luz no ha tenido tiempo de llegar a nosotros.","La radiación cósmica de fondo (CMB), emitida 380 000 años después del Big Bang, es la imagen más antigua del universo que podemos observar — más allá, el universo era opaco."]},
'e101': {fr:["Titan est la seule lune du système solaire où un engin spatial s'est posé en surface — la sonde Huygens en 2005.","La température de surface de Titan est d'environ −179 °C, ce qui permet au méthane d'exister sous forme liquide comme l'eau sur Terre.","Des scientifiques ont proposé que la vie pourrait théoriquement exister dans les lacs de méthane de Titan, basée sur une chimie totalement différente de la nôtre."],en:["Titan is the only moon in the solar system where a spacecraft has landed on the surface — the Huygens probe in 2005.","Titan's surface temperature is about −179°C, allowing methane to exist in liquid form like water on Earth.","Scientists have proposed that life could theoretically exist in Titan's methane lakes, based on chemistry entirely different from ours."],
    es:["Titán es la única luna del sistema solar con una atmósfera densa (1,5 veces la presión terrestre) y la única con líquidos estables en su superficie — pero son lagos de metano y etano, no de agua.","Su atmósfera de nitrógeno y metano produce una neblina naranja que oculta la superficie — la sonda Huygens la atravesó en 2005 y aterrizó en un paisaje que recuerda a una playa terrestre.","Titán tiene un ciclo hidrológico similar al terrestre pero con metano: lluvia de metano, ríos de metano y mares de metano — un mundo alienígena con procesos extrañamente familiares."]},
'e102': {fr:["L'ISS est le plus grand objet construit par l'Homme en orbite — elle mesure 109 mètres de long, soit la taille d'un terrain de football.","Les astronautes à bord voient 16 levers et 16 couchers de soleil chaque jour — un cycle complet toutes les 90 minutes.","L'ISS est un projet collaboratif entre 5 agences spatiales et 15 pays — le plus grand programme de coopération scientifique internationale de l'histoire."],en:["The ISS is the largest human-built object in orbit — 109 metres long, roughly the size of a football pitch.","Astronauts aboard see 16 sunrises and 16 sunsets every day — a full cycle every 90 minutes.","The ISS is a collaborative project between 5 space agencies and 15 countries — the largest international scientific cooperation programme in history."],
    es:["La ISS orbita a 408 km de altitud a una velocidad de 28 000 km/h, completando una vuelta a la Tierra cada 90 minutos — sus astronautas ven 16 amaneceres y 16 atardeceres al día.","Del tamaño de un campo de fútbol y pesando 420 toneladas, es el objeto artificial más grande en órbita — ha estado habitada continuamente desde noviembre de 2000.","La ISS es visible a simple vista como una estrella brillante que se desplaza rápidamente por el cielo: es el tercer objeto más brillante del cielo nocturno, después de la Luna y Venus."]},
'e103': {fr:["L'image du trou noir de M87 a nécessité 8 télescopes répartis sur 5 continents, fonctionnant comme un télescope virtuel de la taille de la Terre.","Les données collectées étaient si volumineuses qu'il a fallu les transporter physiquement par avion sur des disques durs — Internet aurait été trop lent.","Katie Bouman, une chercheuse de 29 ans, a développé l'algorithme clé qui a permis de reconstruire l'image à partir des données brutes."],en:["The M87 black hole image required 8 telescopes across 5 continents, functioning as a virtual Earth-sized telescope.","The collected data was so massive it had to be physically flown on hard drives — the Internet would have been too slow.","Katie Bouman, a 29-year-old researcher, developed the key algorithm that reconstructed the image from raw data."],
    es:["La imagen del agujero negro de M87 (55 millones de años-luz) fue creada combinando datos de 8 radiotelescopios en 4 continentes, formando un telescopio virtual del tamaño de la Tierra.","Los datos fueron tan voluminosos (5 petabytes) que fue más rápido enviar los discos duros por avión que transferirlos por Internet — el procesamiento tomó dos años.","La imagen muestra el anillo de emisión alrededor de la «sombra» del agujero negro: un objeto con 6 500 millones de masas solares cuyo horizonte de eventos es del tamaño del sistema solar."]},
'e104': {fr:["Les aurores sur Jupiter sont alimentées par les particules chargées émises par les volcans de sa lune Io, pas par le vent solaire comme sur Terre.","Les aurores de Saturne forment des anneaux lumineux presque parfaits autour de ses pôles, photographiés par le télescope Hubble.","Sur Terre, les aurores se produisent à environ 100-300 km d'altitude — sur Jupiter, elles atteignent des milliers de kilomètres de hauteur."],en:["Jupiter's auroras are powered by charged particles from the volcanoes on its moon Io, not by solar wind as on Earth.","Saturn's auroras form nearly perfect luminous rings around its poles, photographed by the Hubble telescope.","On Earth, auroras occur at about 100–300 km altitude — on Jupiter, they reach thousands of kilometres high."],
    es:["Las auroras de Júpiter son permanentes y miles de veces más potentes que las terrestres — alimentadas por la interacción entre el intenso campo magnético de Júpiter y la actividad volcánica de su luna Io.","Io inyecta una tonelada de dióxido de azufre por segundo en la magnetosfera joviana, creando un toroide de plasma que alimenta auroras visibles incluso en ultravioleta y rayos X.","Las auroras de Saturno también son espectaculares, formando anillos ovales de luz alrededor de los polos — cada planeta gigante tiene su propio espectáculo auroral."]},
'e105': {fr:["Le premier aliment cuit au micro-ondes par Spencer fut du pop-corn — puis un œuf, qui a explosé au visage d'un collègue.","Le magnétron, la technologie au cœur du micro-ondes, avait été développé pour les radars militaires pendant la Seconde Guerre mondiale.","Les micro-ondes chauffent la nourriture en faisant vibrer les molécules d'eau à 2,45 milliards de fois par seconde."],en:["The first food Spencer cooked in a microwave was popcorn — then an egg, which exploded in a colleague's face.","The magnetron, the technology at the heart of the microwave, was developed for military radar during World War II.","Microwaves heat food by vibrating water molecules 2.45 billion times per second."],
    es:["Percy Spencer descubrió el efecto del microondas en 1945 al notar que una barra de chocolate se derretía en su bolsillo mientras trabajaba con un magnetrón de radar.","El primer alimento cocinado intencionalmente con microondas fueron palomitas de maíz — el segundo fue un huevo, que explotó en la cara de un colega.","Los hornos microondas calientan los alimentos excitando las moléculas de agua a 2,45 GHz: los alimentos sin agua (aceite, plástico seco) apenas se calientan."]},
'e106': {fr:["De Mestral a observé les minuscules crochets des bardanes au microscope et mis huit ans à perfectionner le système de boucles-crochets.","Le velcro a d'abord été boudé par l'industrie textile — c'est la NASA qui l'a popularisé en l'utilisant dans les combinaisons spatiales.","Le nom « Velcro » est un mot-valise de « velours » et « crochet » — une invention sémantique aussi astucieuse que technique."],en:["De Mestral observed the tiny hooks of burdock burrs under a microscope and spent eight years perfecting the loop-hook system.","Velcro was initially shunned by the textile industry — NASA popularised it by using it in spacesuits.","The name 'Velcro' is a portmanteau of 'velours' (velvet) and 'crochet' (hook) — a semantic invention as clever as the technical one."],
    es:["George de Mestral observó cómo los frutos del cardo se enganchaban al pelo de su perro durante un paseo por los Alpes suizos en 1941 — al microscopio, descubrió pequeños ganchos en cada fruto.","Tardó ocho años en desarrollar un sistema de ganchos y bucles reproducible industrialmente — las primeras pruebas con algodón fracasaron hasta que probó con nailon.","La NASA adoptó el velcro para las misiones espaciales: en microgravedad, es la solución ideal para fijar objetos sin tornillos ni pegamento."]},
'e107': {fr:["Spencer Silver a inventé la colle « faible » du Post-it en 1968, mais personne chez 3M ne trouvait d'application utile.","Art Fry, un collègue de 3M, a eu l'idée en 1974 en cherchant un marque-page qui ne tomberait pas de son livre de cantiques.","3M a vendu 1,1 milliard de dollars de Post-it la première année de commercialisation nationale en 1980 — le produit est devenu emblématique."],en:["Spencer Silver invented the Post-it's 'weak' adhesive in 1968, but no one at 3M could find a useful application.","Art Fry, a 3M colleague, had the idea in 1974 while looking for a bookmark that wouldn't fall out of his hymn book.","3M sold $1.1 billion worth of Post-its in the first year of national rollout in 1980 — the product became iconic."],
    es:["Spencer Silver inventó el adhesivo del Post-it en 1968 en 3M: un pegamento que se despegaba fácilmente sin dejar residuos — pero nadie le vio utilidad durante años.","Art Fry, su colega, tuvo la idea en 1974 al buscar un marcapáginas que no se cayera de su himnario — y el producto se lanzó comercialmente en 1980.","Hoy se fabrican más de 50 000 millones de Post-it al año en más de 60 colores — un ejemplo clásico de innovación nacida de un «fracaso» que encontró la aplicación correcta."]},
'e108': {fr:["Le premier email envoyé par Tomlinson était un message test dont il ne se souvient plus du contenu — probablement « QWERTYUIOP » ou similaire.","Le signe @ a été choisi car il n'apparaissait dans aucun nom de personne, évitant toute confusion dans les adresses.","En 2024, plus de 300 milliards d'emails sont envoyés chaque jour dans le monde — dont environ la moitié sont des spams."],en:["The first email Tomlinson sent was a test message whose content he couldn't remember — probably 'QWERTYUIOP' or similar.","The @ sign was chosen because it didn't appear in anyone's name, avoiding confusion in addresses.","In 2024, over 300 billion emails are sent worldwide each day — about half of which are spam."],
    es:["Ray Tomlinson eligió el símbolo @ para separar el nombre del usuario del nombre del servidor porque era un carácter poco usado en los textos y no generaba confusión.","El primer email que Tomlinson se envió a sí mismo contenía algo como «QWERTYUIOP» — ni él recordaba el contenido exacto, considerándolo un mensaje de prueba intrascendente.","En 1978, Gary Thuerk envió el primer spam de la historia: un anuncio de ordenadores DEC a 393 direcciones de ARPANET — provocó quejas inmediatas y estableció el primer precedente de correo no deseado."]},
'e109': {fr:["Le vol KAL 007 s'est égaré au-dessus de l'espace aérien soviétique en 1983, abattu avec 269 personnes à bord — l'incident a accéléré l'ouverture du GPS civil.","Le système GPS utilise 31 satellites en orbite à environ 20 200 km d'altitude, émettant des signaux horaires ultra-précis.","La précision du GPS civil est passée d'environ 100 mètres à moins de 30 cm grâce aux améliorations successives et à la désactivation du brouillage intentionnel en 2000."],en:["KAL Flight 007 strayed into Soviet airspace in 1983 and was shot down with 269 people aboard — the incident accelerated civilian GPS access.","GPS uses 31 satellites orbiting at about 20,200 km altitude, broadcasting ultra-precise time signals.","Civilian GPS accuracy improved from about 100 metres to under 30 cm through successive upgrades and the removal of intentional degradation in 2000."],
    es:["El GPS fue desarrollado por el Departamento de Defensa de EE.UU. en los años 1970, pero su señal civil fue deliberadamente degradada (Selective Availability) hasta el año 2000.","El derribo del vuelo KAL 007 en 1983, un avión coreano que se desvió al espacio aéreo soviético, convenció al presidente Reagan de abrir el GPS al uso civil.","La precisión del GPS depende de los relojes atómicos de los satélites: deben corregir tanto la relatividad especial (los relojes van más rápido por la velocidad) como la general (más lentos por la menor gravedad)."]},
'e110': {fr:["Gray et Bell ont déposé leurs brevets le même jour, le 14 février 1876 — Bell aurait eu seulement quelques heures d'avance.","La controverse dure encore : certains historiens pensent que Bell a eu accès aux plans de Gray avant de finaliser son propre brevet.","Les premières paroles prononcées au téléphone par Bell furent : « Mr. Watson, come here — I want to see you. »"],en:["Gray and Bell filed their patents on the same day, 14 February 1876 — Bell reportedly had only a few hours' lead.","The controversy endures: some historians believe Bell accessed Gray's designs before finalising his own patent.","The first words spoken over the telephone by Bell were: 'Mr. Watson, come here — I want to see you.'"],
    es:["Alexander Graham Bell y Elisha Gray presentaron patentes de teléfono el mismo día (14 de febrero de 1876) — Bell llegó unas horas antes, lo que le otorgó la prioridad.","Antonio Meucci había desarrollado un prototipo funcional años antes pero no pudo pagar los 10 dólares para renovar su patente provisional — un caso clásico de genio sin recursos.","En 2002, el Congreso de EE.UU. reconoció la contribución de Meucci a la invención del teléfono, sin invalidar la patente de Bell."]},
'e111': {fr:["L'ENIAC utilisait 17 468 tubes à vide, consommait 150 kW et tombait en panne en moyenne toutes les cinq heures.","Sa programmation se faisait en reconfigurant physiquement des câbles et des interrupteurs — il fallait parfois plusieurs jours pour un seul programme.","Six femmes mathématiciennes ont programmé l'ENIAC — elles ont longtemps été ignorées par l'histoire avant d'être redécouvertes dans les années 1990."],en:["ENIAC used 17,468 vacuum tubes, consumed 150 kW, and broke down on average every five hours.","Programming it meant physically reconfiguring cables and switches — sometimes taking days for a single program.","Six women mathematicians programmed ENIAC — they were long overlooked by history before being rediscovered in the 1990s."],
    es:["El ENIAC (1945) utilizaba 18 000 tubos de vacío que generaban tanto calor que la sala necesitaba un sistema de refrigeración industrial — y un tubo se fundía cada dos días de media.","Programar el ENIAC requería reconectar físicamente miles de cables y conmutadores — un proceso que podía llevar semanas para un solo cálculo nuevo.","Su potencia de cálculo era de unas 5 000 operaciones por segundo — una calculadora de bolsillo moderna es millones de veces más rápida."]},
'e112': {fr:["Jenner a inoculé du pus de variole bovine (cowpox) à un garçon de 8 ans, puis l'a exposé à la variole humaine — l'enfant n'a pas été infecté.","Le mot « vaccination » vient du latin vacca (vache), en référence directe à la variole bovine utilisée par Jenner.","La variole est la seule maladie humaine jamais éradiquée par la vaccination — le dernier cas naturel a été enregistré en 1977 en Somalie."],en:["Jenner inoculated an 8-year-old boy with cowpox pus, then exposed him to smallpox — the child was not infected.","The word 'vaccination' comes from Latin vacca (cow), a direct reference to the cowpox Jenner used.","Smallpox is the only human disease ever eradicated by vaccination — the last natural case was recorded in 1977 in Somalia."],
    es:["Edward Jenner observó que las lecheras que habían contraído la viruela vacuna (una enfermedad leve) no se contagiaban de la mortal viruela humana.","En 1796, inoculó a un niño de 8 años con viruela vacuna y luego lo expuso a la viruela humana — el niño no enfermó, demostrando el principio de la vacunación.","La viruela fue erradicada en 1980 tras una campaña de la OMS — la única enfermedad humana eliminada de la naturaleza, gracias a la vacunación masiva."]},
'e113': {fr:["Les premières lunettes étaient des « pierres de lecture » — des demi-sphères de verre posées sur les textes pour grossir les lettres.","Benjamin Franklin a inventé les lunettes bifocales vers 1784, las de changer constamment entre ses lunettes de lecture et de distance.","Environ 75 % de la population mondiale a besoin d'une correction visuelle — les lunettes sont l'un des dispositifs médicaux les plus utilisés au monde."],en:["The first spectacles were 'reading stones' — glass half-spheres placed on text to magnify letters.","Benjamin Franklin invented bifocal lenses around 1784, tired of constantly switching between reading and distance glasses.","About 75% of the world's population needs vision correction — spectacles are one of the most widely used medical devices in the world."],
    es:["Las primeras gafas (finales del siglo XIII en Italia) eran remachadas o sujetadas a mano — las patillas laterales no se inventaron hasta 1727 por Edward Scarlett en Londres.","Antes de las gafas, las personas présbitas usaban piedras de lectura: esferas de cristal de roca pulido que se colocaban sobre el texto para ampliarlo.","Se estima que 2 500 millones de personas en el mundo necesitan gafas pero no tienen acceso a ellas — un problema de salud pública que limita la educación y la productividad."]},
'e114': {fr:["Le papier chinois original était fabriqué à partir d'écorce de mûrier, de chanvre et de vieux chiffons, mélangés et pressés en feuilles.","Le secret de fabrication du papier a mis 600 ans pour atteindre le monde arabe (VIIIe siècle) et encore 400 ans pour l'Europe (XIIe siècle).","Avant le papier, les Européens écrivaient sur du parchemin en peau animale — 250 peaux de mouton pour une seule Bible."],en:["The original Chinese paper was made from mulberry bark, hemp, and old rags, mixed and pressed into sheets.","The secret of papermaking took 600 years to reach the Arab world (8th century) and another 400 to reach Europe (12th century).","Before paper, Europeans wrote on animal-skin parchment — 250 sheepskins for a single Bible."],
    es:["Cai Lun perfeccionó la fabricación de papel en China en el 105 d.C. usando corteza de morera, cáñamo y trapos — un proceso que se mantuvo secreto durante siglos.","Los árabes aprendieron la técnica tras capturar a artesanos chinos en la batalla de Talas (751) — el papel llegó a Europa a través de España e Italia en el siglo XII.","Antes del papel, los europeos escribían en pergamino (piel de animal), mucho más caro: una Biblia completa necesitaba la piel de 300 ovejas."]},
'e115': {fr:["Les plus anciens tours de potier datent d'environ 3 500 av. J.-C. en Mésopotamie — la roue de transport est apparue 500 ans plus tard.","La roue à rayons, plus légère et rapide, n'a été inventée que vers 2000 av. J.-C. — elle a révolutionné les chars de guerre.","Étonnamment, les civilisations précolombiennes d'Amérique n'ont jamais utilisé la roue pour le transport, bien qu'ils la connaissaient — on en a retrouvé sur des jouets."],en:["The oldest potter's wheels date to about 3,500 BC in Mesopotamia — the transport wheel appeared 500 years later.","The spoked wheel, lighter and faster, was only invented around 2,000 BC — it revolutionised war chariots.","Surprisingly, pre-Columbian civilisations in the Americas never used the wheel for transport, although they knew of it — it has been found on toys."],
    es:["Los tornos de alfarero (3500 a.C. en Mesopotamia) son los primeros usos conocidos de la rueda — las ruedas para transporte aparecieron unos 300 años después.","Las civilizaciones precolombinas conocían la rueda (aparece en juguetes) pero no la usaban para el transporte, probablemente porque carecían de animales de tiro adecuados.","La rueda de radios, más ligera y resistente que el disco macizo, apareció hacia 2000 a.C. y revolucionó la guerra (carros de combate) y el comercio."]},
'e116': {fr:["Avant les antibiotiques, des infections mineures comme une coupure pouvaient être mortelles — la pneumonie tuait environ 30 % des patients.","La pénicilline a sauvé des milliers de soldats alliés pendant la Seconde Guerre mondiale, réduisant drastiquement les morts par infection.","Fleming avait prévenu dès 1945 que l'usage excessif d'antibiotiques mènerait à la résistance bactérienne — un problème majeur aujourd'hui."],en:["Before antibiotics, minor infections from a cut could be fatal — pneumonia killed about 30% of patients.","Penicillin saved thousands of Allied soldiers during WWII, drastically reducing deaths from infection.","Fleming warned as early as 1945 that antibiotic overuse would lead to bacterial resistance — a major problem today."],
    es:["Alexander Fleming descubrió la penicilina por accidente en 1928, pero no logró purificarla — fueron Howard Florey y Ernst Chain quienes la convirtieron en medicamento en 1940.","La penicilina salvó millones de vidas durante la Segunda Guerra Mundial: los soldados aliados tuvieron acceso a antibióticos mientras los del Eje no, una ventaja médica decisiva.","Fleming advirtió en su discurso del Nobel (1945) sobre el riesgo de resistencia bacteriana por uso inadecuado — una predicción que hoy se cumple con las superbacterias."]},
'e117': {fr:["Le QR code peut stocker jusqu'à 7 089 chiffres ou 4 296 caractères alphanumériques — bien plus qu'un code-barres traditionnel.","Le QR code est resté un outil industriel discret pendant 17 ans avant d'exploser auprès du grand public avec les smartphones vers 2011.","Masahiro Hara s'est inspiré des pierres du jeu de go pour concevoir le motif en noir et blanc du QR code."],en:["A QR code can store up to 7,089 digits or 4,296 alphanumeric characters — far more than a traditional barcode.","The QR code remained a discreet industrial tool for 17 years before exploding into public use with smartphones around 2011.","Masahiro Hara was inspired by the black and white stones of the Go board game to design the QR code pattern."],
    es:["El código QR fue creado por Denso Wave (filial de Toyota) para rastrear componentes en las cadenas de montaje — su capacidad de almacenar 7 089 caracteres numéricos superó con creces al código de barras.","A diferencia del código de barras unidimensional, el QR codifica información en dos dimensiones y puede leerse incluso si está parcialmente dañado (hasta un 30 % de corrección de errores).","La pandemia de COVID-19 popularizó masivamente los códigos QR para menús de restaurantes, pasaportes sanitarios y pagos sin contacto — una tecnología de 1994 que encontró su momento en 2020."]},
'e118': {fr:["Le premier saut de Garnerin s'est fait sans trou au sommet du parachute — il a oscillé violemment et a vomi en atterrissant, mais a survécu.","Garnerin a perfectionné son design en ajoutant un trou au sommet de la toile pour stabiliser la descente — un principe encore utilisé aujourd'hui.","Le mot « parachute » vient de l'italien para (protéger) et du français chute — littéralement « qui protège de la chute »."],en:["Garnerin's first jump was without a hole at the top of the parachute — he oscillated wildly and vomited on landing, but survived.","Garnerin improved his design by adding a hole at the canopy's apex to stabilise descent — a principle still used today.","The word 'parachute' comes from Italian para (to protect) and French chute (fall) — literally 'that which protects from falling'."],
    es:["André-Jacques Garnerin realizó el primer salto en paracaídas desde un globo a 680 metros de altitud el 22 de octubre de 1797 en París, ante una multitud asombrada.","Su paracaídas, inspirado en un parasol invertido, oscilaba violentamente — su esposa Jeanne-Geneviève fue la primera mujer en saltar en paracaídas en 1799.","El paracaídas moderno con abertura central (que estabiliza las oscilaciones) fue inventado casi un siglo después — el diseño de Garnerin era funcional pero peligrosamente inestable."]},
'e119': {fr:["Les briques de Jéricho, datant d'environ 7 500 av. J.-C., sont les plus anciennes briques cuites retrouvées par les archéologues.","La Grande Muraille de Chine contient environ 3,8 milliards de briques — c'est la plus grande structure en briques jamais construite.","La brique reste le matériau de construction le plus utilisé au monde — environ 1 500 milliards sont produites chaque année."],en:["The bricks of Jericho, dating to about 7,500 BC, are the oldest fired bricks found by archaeologists.","The Great Wall of China contains about 3.8 billion bricks — it is the largest brick structure ever built.","Brick remains the world's most-used building material — about 1.5 trillion are produced each year."],
    es:["Los ladrillos de arcilla cocida más antiguos datan de unos 4500 a.C. en Mesopotamia — antes se usaban ladrillos de adobe (arcilla secada al sol), que son aún más antiguos.","Los romanos perfeccionaron la fabricación con hornos de alta temperatura que producían ladrillos de calidad uniforme — algunos acueductos y edificios romanos de ladrillo siguen en pie 2 000 años después.","Hoy se fabrican más de 1,5 billones de ladrillos al año en el mundo — China e India producen más del 60 % del total global."]},
'e120': {fr:["Monier a eu l'idée d'insérer un treillis métallique dans le ciment après avoir observé que le béton seul se fissurait trop facilement.","Le béton armé a rendu possible les gratte-ciels : sans lui, les bâtiments de plus de quelques étages seraient structurellement impossibles.","Le Panthéon de Rome, construit en 125 ap. J.-C. en béton non armé, possède toujours le plus grand dôme en béton non renforcé du monde — 43 mètres de diamètre."],en:["Monier had the idea of embedding metal mesh in cement after observing that plain concrete cracked too easily.","Reinforced concrete made skyscrapers possible: without it, buildings over a few storeys would be structurally impossible.","The Pantheon in Rome, built in 125 AD from unreinforced concrete, still has the world's largest unreinforced concrete dome — 43 metres across."],
    es:["Joseph Monier era jardinero, no ingeniero: inventó el hormigón armado al insertar una malla de hierro en las macetas de cemento para que no se rompieran.","La combinación es genial: el hormigón resiste la compresión y el hierro la tracción — juntos, forman un material que resiste ambas fuerzas, ideal para la construcción.","El hormigón armado es el material de construcción más utilizado del mundo: se producen más de 4 300 millones de toneladas de cemento al año, generando el 8 % de las emisiones globales de CO₂."]},
'e121': {
  fr:["Humphry Davy avait créé une lampe à arc dès 1809 et Joseph Swan avait breveté une ampoule viable en 1878 — un an avant Edison.","Edison a testé plus de 3 000 matériaux pour le filament avant de trouver le bambou carbonisé, qui durait plus de 1 200 heures.","Edison et Swan ont fini par fusionner leurs brevets en créant la société Ediswan pour éviter un procès — preuve que l'invention n'avait pas un père unique."],
  en:["Humphry Davy had created an arc lamp in 1809 and Joseph Swan had patented a viable bulb in 1878 — one year before Edison.","Edison tested over 3,000 materials for the filament before finding carbonised bamboo, which lasted over 1,200 hours.","Edison and Swan ended up merging their patents into the Ediswan company to avoid a lawsuit — proof the invention had no single father."],
    es:["Al menos 22 inventores trabajaron en la bombilla antes de Edison, incluyendo Humphry Davy (1802), Warren de la Rue (1840) y Joseph Swan (1860).","La contribución de Edison fue crear un sistema completo: bombilla duradera (más de 1 200 horas), generador eléctrico, cables de distribución e interruptores — no solo la bombilla aislada.","La primera central eléctrica comercial del mundo, la Pearl Street Station de Edison en Manhattan, se inauguró en 1882 y suministraba electricidad a 85 clientes."]
},
'e122': {
  fr:["Léotard était un trapéziste français qui a inventé le trapèze volant au Cirque d'Hiver de Paris en 1859.","Le maillot de corps moulant qu'il portait lors de ses numéros a pris son nom — c'est devenu le justaucorps de danse moderne.","Avant le filet de sécurité, les trapézistes tombaient sur des matelas empilés — les blessures graves étaient fréquentes."],
  en:["Léotard was a French trapeze artist who invented the flying trapeze at the Cirque d'Hiver in Paris in 1859.","The tight-fitting bodysuit he wore during performances took his name — it became the modern dance leotard.","Before safety nets, trapeze artists fell onto stacked mattresses — serious injuries were common."],
    es:["Jules Léotard inventó el trapecio volante en 1859 e inspiró la prenda ajustada que lleva su nombre — pero no inventó el filet de sécurité, que fue patentado por otro artista en 1871.","Léotard actuaba sobre colchones apilados y murió a los 28 años de viruela, no de una caída — era considerado el mayor acróbata de su tiempo.","La canción «The Daring Young Man on the Flying Trapeze» (1867) fue escrita en su honor y se convirtió en un éxito popular duradero."]
},
'e123': {
  fr:["Bíró a fui la Hongrie nazie en 1938 pour s'installer en Argentine, où il a perfectionné son invention — en Argentine, le stylo à bille s'appelle encore « birome ».","Le brevet de Bíró a été acheté par Marcel Bich en 1950, qui en a fait le stylo BIC Cristal — le plus vendu de l'histoire avec plus de 100 milliards d'unités.","Un stylo à bille BIC Cristal contient assez d'encre pour tracer une ligne de 3 km."],
  en:["Bíró fled Nazi Hungary in 1938 and settled in Argentina, where he perfected his invention — in Argentina, the ballpoint pen is still called a 'birome'.","Bíró's patent was purchased by Marcel Bich in 1950, who turned it into the BIC Cristal pen — the best-selling in history with over 100 billion units.","A BIC Cristal ballpoint pen contains enough ink to draw a line 3 km long."],
    es:["László Bíró, periodista húngaro, se frustró con las plumas estilográficas que manchaban y tardaban en secar — observó que la tinta de imprenta secaba rápidamente y diseñó una bola que la dispensara.","Patentó su invento en 1938 y lo comercializó desde Argentina, donde había emigrado huyendo del nazismo — en Argentina, los bolígrafos se llaman «biromes» en su honor.","El bolígrafo Bic Cristal, lanzado en 1950 por Marcel Bich, democratizó la escritura al ofrecer un bolígrafo desechable a un precio accesible — se han vendido más de 100 000 millones de unidades."]
},
'e124': {
  fr:["Cochrane a construit son premier prototype dans sa remise en utilisant un moteur à vapeur, de la pression d'eau et des compartiments en fil de fer.","Elle a présenté son invention à l'Exposition universelle de Chicago en 1893, où elle a remporté un prix pour sa conception robuste.","Cochrane a dû convaincre les hôtels et restaurants avant les ménages — les particuliers n'ont adopté le lave-vaisselle qu'à partir des années 1950."],
  en:["Cochrane built her first prototype in her shed using a steam engine, water pressure, and wire compartments.","She exhibited her invention at the 1893 Chicago World's Fair, where it won an award for its robust design.","Cochrane had to convince hotels and restaurants before households — domestic adoption only began in the 1950s."],
    es:["Josephine Cochrane, una mujer adinerada de Illinois, inventó el primer lavavajillas mecánico práctico en 1886 porque sus sirvientes rompían su porcelana fina al lavarla a mano.","Su máquina usaba presión de agua caliente dirigida a compartimentos individuales para cada pieza — un diseño tan eficaz que fue adoptado por hoteles y restaurantes antes que por hogares.","Los lavavajillas domésticos no se popularizaron hasta los años 1950-60, cuando la clase media pudo permitírselos — hoy, un lavavajillas eficiente usa menos agua que lavar a mano."]
},
'e125': {
  fr:["Le premier message transmis sur ARPANET le 29 octobre 1969 était censé être « LOGIN » — le système a planté après les deux premières lettres « LO ».","Tim Berners-Lee a inventé le World Wide Web en 1989 au CERN — ARPANET fournissait l'infrastructure réseau, le Web y a ajouté les pages et les liens.","En 2025, plus de 5,5 milliards de personnes utilisent Internet — soit environ 68 % de la population mondiale."],
  en:["The first message sent on ARPANET on 29 October 1969 was supposed to be 'LOGIN' — the system crashed after the first two letters 'LO'.","Tim Berners-Lee invented the World Wide Web in 1989 at CERN — ARPANET provided the network infrastructure, the Web added pages and links.","By 2025, over 5.5 billion people use the Internet — about 68% of the world's population."],
    es:["ARPANET envió su primer mensaje el 29 de octubre de 1969 entre la UCLA y el Stanford Research Institute — el mensaje era «LOGIN» pero el sistema se colgó tras «LO».","El protocolo TCP/IP, inventado por Vint Cerf y Bob Kahn en 1974, permitió que redes diferentes se comunicaran entre sí — la base técnica de Internet tal como lo conocemos.","Tim Berners-Lee inventó la World Wide Web en 1989 en el CERN — pero Internet (la infraestructura de red) y la Web (el sistema de páginas) no son lo mismo, aunque se usen como sinónimos."]
},
'e126': {
  fr:["Les Mayas mélangeaient le cacao avec du piment, de la vanille et parfois du sang dans des rituels sacrés.","Le mot « chocolat » vient du nahuatl « xocoatl » — une boisson amère et froide que les Aztèques considéraient comme sacrée.","Les fèves de cacao servaient aussi de monnaie chez les Aztèques : un lapin coûtait environ 10 fèves, un esclave environ 100."],
  en:["The Maya mixed cacao with chilli, vanilla, and sometimes blood in sacred rituals.","The word 'chocolate' comes from the Nahuatl 'xocoatl' — a bitter, cold drink the Aztecs considered sacred.","Cacao beans also served as currency among the Aztecs: a rabbit cost about 10 beans, a slave about 100."],
    es:["Los mayas preparaban el chocolate como bebida fría, amarga y especiada con chili, vainilla y achiote — la versión dulce y caliente es una invención europea del siglo XVII.","Los granos de cacao eran tan valiosos que los aztecas los usaban como moneda: un conejo costaba 10 granos, un esclavo 100 y una calabaza 4.","El chocolate con leche fue inventado en 1875 por Daniel Peter en Suiza, usando leche condensada de su vecino Henri Nestlé — naciendo una industria de 130 000 millones de dólares anuales."]
},
'e127': {
  fr:["Les trois couleurs de la margherita sont : basilic (vert), mozzarella (blanc) et tomate (rouge) — les couleurs du drapeau italien.","Le pizzaiolo Raffaele Esposito de la Pizzeria Brandi est crédité de cette création — bien que certains historiens doutent de l'anecdote.","Naples a été inscrite au patrimoine immatériel de l'UNESCO en 2017 pour l'art de la pizza napolitaine (« pizzaiuolo »)."],
  en:["The margherita's three colours are: basil (green), mozzarella (white), and tomato (red) — the Italian flag's colours.","Pizzaiolo Raffaele Esposito of Pizzeria Brandi is credited with the creation — though some historians question the anecdote.","Naples was inscribed on the UNESCO Intangible Heritage list in 2017 for the art of Neapolitan pizza ('pizzaiuolo')."],
    es:["La pizza margherita fue creada por Raffaele Esposito en 1889 con los colores de la bandera italiana: tomate (rojo), mozzarella (blanco) y albahaca (verde).","Sin embargo, los napolitanos ya comían pizzas similares desde al menos el siglo XVIII — la visita de la reina Margherita simplemente oficializó un plato popular.","La Associazione Verace Pizza Napoletana certifica las pizzerías auténticas: masa fermentada 24h, mozzarella di bufala, tomate San Marzano y horno a 485 °C durante 60-90 segundos."]
},
'e128': {
  fr:["La légende raconte que le berger Kaldi a remarqué que ses chèvres dansaient après avoir mangé des baies rouges d'un arbuste inconnu — au IXe siècle.","Le café a d'abord été cultivé au Yémen avant de se répandre dans tout le monde arabe, puis en Europe au XVIIe siècle.","La Finlande est le plus grand consommateur de café par habitant au monde, avec environ 12 kg par personne et par an."],
  en:["Legend says shepherd Kaldi noticed his goats dancing after eating red berries from an unknown bush — in the 9th century.","Coffee was first cultivated in Yemen before spreading throughout the Arab world, then to Europe in the 17th century.","Finland is the world's largest coffee consumer per capita, at about 12 kg per person per year."],
    es:["La leyenda atribuye el descubrimiento del café a un pastor etíope llamado Kaldi que observó que sus cabras se ponían hiperactivas al comer bayas de un arbusto.","Los sufíes yemeníes fueron los primeros en preparar una bebida con granos de café tostados (siglo XV) para mantenerse despiertos durante las oraciones nocturnas.","Hoy se consumen más de 2 000 millones de tazas de café al día en el mundo — Finlandia lidera el consumo per cápita con 12 kg por persona al año."]
},
'e129': {
  fr:["Les « graines » visibles sur la fraise sont en fait des akènes — de minuscules fruits secs contenant chacun une graine.","La fraise est la seule fruit dont les graines se trouvent à l'extérieur — toutes les autres espèces les cachent à l'intérieur.","Il existe plus de 600 variétés de fraises dans le monde, allant du rouge vif au blanc (fraise blanche japonaise, très prisée)."],
  en:["The visible 'seeds' on a strawberry are actually achenes — tiny dry fruits each containing a seed.","The strawberry is the only fruit with seeds on the outside — all other species hide them inside.","Over 600 strawberry varieties exist worldwide, ranging from bright red to white (Japanese white strawberries are highly prized)."],
    es:["Las fresas son «falsos frutos»: la parte roja es en realidad el receptáculo floral hinchado, y los verdaderos frutos son los puntos amarillos (aquenios) de la superficie.","Botánicamente, los plátanos, las sandías y los aguacates son bayas verdaderas (fruto carnoso de un solo ovario), mientras que las fresas, frambuesas y moras no lo son.","Esta clasificación sorprendente se debe a que la botánica define «baya» de forma estricta: un fruto derivado de un solo ovario con semillas incrustadas en la pulpa."]
},
'e130': {
  fr:["Le vrai wasabi provient de la racine d'Eutrema japonicum, une plante très difficile à cultiver qui nécessite de l'eau courante et de l'ombre.","Le wasabi frais perd sa saveur en 15 minutes — c'est pourquoi même au Japon, les restaurants haut de gamme le râpent devant vous.","Un kilo de wasabi frais peut coûter plus de 250 €, ce qui en fait l'une des plantes les plus chères au monde."],
  en:["Real wasabi comes from the root of Eutrema japonicum, a very difficult plant to grow that requires running water and shade.","Fresh wasabi loses its flavour within 15 minutes — which is why even in Japan, high-end restaurants grate it in front of you.","A kilo of fresh wasabi can cost over €250, making it one of the most expensive plants in the world."],
    es:["El wasabi genuino proviene de la raíz de Wasabia japonica, una planta que crece solo en lechos de ríos de montaña a temperaturas estables — y cuesta más de 200 €/kg.","El 95 % del wasabi servido fuera de Japón es rábano picante (horseradish) teñido de verde con colorante y aromatizado con mostaza — un sustituto mucho más barato.","El wasabi real debe rallarse en el momento y consumirse en 15 minutos porque los isotiocianatos (moléculas picantes) se evaporan rápidamente."]
},
'e131': {
  fr:["Le miel ne se périme pas grâce à sa faible teneur en eau (~17 %), son pH acide (~3,9) et la production naturelle de peroxyde d'hydrogène par les enzymes d'abeille.","Les abeilles doivent visiter environ 2 millions de fleurs et parcourir 88 000 km pour produire un seul kilo de miel.","Le miel de Manuka de Nouvelle-Zélande possède des propriétés antibactériennes si puissantes qu'il est utilisé médicalement pour traiter les plaies."],
  en:["Honey doesn't spoil thanks to its low water content (~17%), acidic pH (~3.9), and natural hydrogen peroxide produced by bee enzymes.","Bees must visit about 2 million flowers and fly 88,000 km to produce a single kilo of honey.","Manuka honey from New Zealand has such powerful antibacterial properties that it's used medically to treat wounds."],
    es:["La miel no caduca porque su bajo contenido en agua (~17 %), alta acidez (pH 3,5-4) y producción natural de peróxido de hidrógeno inhiben el crecimiento bacteriano.","Arqueólogos han encontrado miel de 3 000 años en tumbas egipcias que seguía siendo comestible — los egipcios usaban la miel también como ungüento para heridas.","Las abejas deben visitar unos 2 millones de flores y volar más de 88 000 km para producir un solo kilo de miel — el trabajo de toda una vida de 12 abejas obreras."]
},
'e132': {
  fr:["Un plant d'ananas met 2 à 3 ans pour produire un seul fruit — ce qui expliquait son prix exorbitant en Europe au XVIIIe siècle.","L'ananas contient de la bromélaïne, une enzyme qui dissout les protéines — c'est pourquoi il « pique » la langue en le mangeant.","Au XVIIIe siècle, louer un ananas pour décorer une table de banquet était un signe de richesse extrême en Angleterre."],
  en:["A pineapple plant takes 2 to 3 years to produce a single fruit — which explained its exorbitant price in 18th-century Europe.","Pineapple contains bromelain, an enzyme that breaks down proteins — that's why it 'stings' the tongue when eaten.","In 18th-century England, renting a pineapple to decorate a banquet table was a sign of extreme wealth."],
    es:["La planta de piña (Ananas comosus) es una bromelia herbácea que crece a ras de suelo y produce un solo fruto por ciclo de cultivo, que tarda 18-24 meses en madurar.","Cada «piña» es en realidad una infrutescencia: la fusión de 100-200 flores individuales que se sueldan para formar un solo fruto compuesto.","La enzima bromelina de la piña descompone las proteínas — por eso la piña ablanda la carne y produce una sensación de hormigueo en la boca al comerla cruda."]
},
'e133': {
  fr:["Le fromage est facile à revendre car il est cher, compact et n'a pas de numéro de série — un produit idéal pour le marché noir.","Le Parmigiano-Reggiano est si précieux en Italie que certaines banques acceptent des meules de parmesan en garantie de prêts.","Il existe plus de 1 800 variétés de fromages en France — le général de Gaulle aurait dit : « Comment voulez-vous gouverner un pays qui a 246 variétés de fromage ? »"],
  en:["Cheese is easy to resell because it's expensive, compact, and has no serial number — an ideal black market product.","Parmigiano-Reggiano is so valuable in Italy that some banks accept wheels of Parmesan as loan collateral.","France has over 1,800 cheese varieties — General de Gaulle reportedly said: 'How can you govern a country that has 246 varieties of cheese?'"],
    es:["Según estudios del Centre for Retail Research, el queso es el alimento más robado en las tiendas de todo el mundo, con un 4 % de la producción sustraída anualmente.","El queso de alta calidad es caro, fácil de revender y difícil de rastrear — lo que lo convierte en objetivo preferente de ladrones organizados.","En Italia, los bancos aceptan ruedas de Parmigiano-Reggiano como garantía de préstamos: el Credito Emiliano tiene bóvedas refrigeradas con más de 300 000 ruedas valoradas en cientos de millones."]
},
'e134': {
  fr:["Le poivre noir était surnommé « l'or noir » — les marchands vénitiens et génois ont bâti des fortunes sur son commerce.","Alaric le Wisigoth exigea 3 000 livres de poivre dans la rançon de Rome en 410 ap. J.-C. — preuve de sa valeur stratégique.","La quête d'un accès direct aux épices a motivé les grandes explorations maritimes du XVe siècle, y compris le voyage de Vasco de Gama vers l'Inde."],
  en:["Black pepper was nicknamed 'black gold' — Venetian and Genoese merchants built fortunes on its trade.","Alaric the Visigoth demanded 3,000 pounds of pepper in Rome's ransom in 410 AD — proof of its strategic value.","The quest for direct access to spices drove the great maritime explorations of the 15th century, including Vasco da Gama's voyage to India."],
    es:["El pimienta negra era tan valiosa en la Europa medieval que se usaba como moneda: los alquileres y los impuestos podían pagarse en granos de pimienta.","La búsqueda de especias fue uno de los principales motores de la era de los descubrimientos: Colón buscaba una ruta a la India para acceder al comercio de especias.","Venecia amasó su fortuna como intermediaria en el comercio de especias entre Oriente y Europa — cuando los portugueses encontraron la ruta marítima directa, Venecia perdió su monopolio."]
},
'e135': {
  fr:["Les piments Tabasco sont fermentés pendant trois ans dans des fûts de chêne ayant contenu du bourbon — comme un bon whisky.","Edmund McIlhenny a fondé la marque en 1868 et la famille McIlhenny dirige toujours l'entreprise aujourd'hui, à la sixième génération.","Avery Island n'est pas vraiment une île : c'est un dôme de sel géant qui s'élève au milieu des marais de Louisiane."],
  en:["Tabasco peppers are fermented for three years in oak barrels that previously held bourbon — like a fine whisky.","Edmund McIlhenny founded the brand in 1868 and the McIlhenny family still runs the company today, in its sixth generation.","Avery Island isn't really an island: it's a giant salt dome rising from the Louisiana marshlands."],
    es:["La salsa Tabasco se produce desde 1868 en Avery Island, una cúpula de sal en la costa de Luisiana — los chiles se fermentan con sal durante tres años antes de mezclarlos con vinagre.","Avery Island no es realmente una isla sino una elevación de 50 metros sobre los pantanos circundantes, formada por un depósito subterráneo de sal de 50 000 años.","La familia McIlhenny produce Tabasco con la misma receta desde hace más de 150 años — se vende en más de 195 países y se incluye en las raciones del ejército estadounidense."]
},
'e136': {
  fr:["L'hémocyanine est moins efficace que l'hémoglobine pour transporter l'oxygène, mais elle fonctionne mieux dans des environnements froids et pauvres en oxygène.","Les crevettes, les crabes et les homards ont tous le sang bleu — tout comme les pieuvres et certains escargots.","Lorsqu'un crustacé est cuit, l'hémocyanine se dénature et son sang devient incolore — la couleur rouge vient du pigment astaxanthine de la carapace."],
  en:["Haemocyanin is less efficient than haemoglobin at carrying oxygen, but performs better in cold, oxygen-poor environments.","Shrimp, crabs, and lobsters all have blue blood — as do octopuses and some snails.","When a crustacean is cooked, haemocyanin denatures and its blood turns colourless — the red colour comes from the shell pigment astaxanthin."],
    es:["Las gambas, langostas y cangrejos tienen sangre azul porque usan hemocianina (basada en cobre) en lugar de hemoglobina (basada en hierro) para transportar oxígeno.","La hemocianina es menos eficiente que la hemoglobina pero funciona mejor a bajas temperaturas y presiones — una adaptación ideal para los crustáceos de aguas frías y profundas.","La sangre azul del cangrejo herradura (Limulus) se usa en la industria farmacéutica para detectar endotoxinas bacterianas — un litro puede costar hasta 15 000 dólares."]
},
'e137': {
  fr:["L'affaire « Nix v. Hedden » de 1893 à la Cour suprême américaine a classé la tomate comme légume pour des raisons de tarifs douaniers, pas de botanique.","La tomate était considérée comme toxique en Europe jusqu'au XVIIIe siècle car elle appartient à la famille des solanacées, comme la belladone.","La plus grosse tomate jamais cultivée pesait 4,896 kg — elle a été récoltée dans le Minnesota en 2020."],
  en:["The 1893 'Nix v. Hedden' Supreme Court case classified the tomato as a vegetable for tariff purposes, not botanical ones.","Tomatoes were considered toxic in Europe until the 18th century because they belong to the nightshade family, like belladonna.","The heaviest tomato ever grown weighed 4.896 kg — it was harvested in Minnesota in 2020."],
    es:["El tomate es botánicamente un fruto (una baya), pero fue clasificado legalmente como verdura por la Corte Suprema de EE.UU. en 1893 (caso Nix v. Hedden) por razones arancelarias.","Originario de Mesoamérica, el tomate llegó a Europa en el siglo XVI pero fue rechazado durante dos siglos como ornamental o venenoso — los italianos fueron los primeros europeos en cocinarlo.","Hoy, Italia consume más de 6 millones de toneladas de tomates al año — la salsa de tomate es probablemente la contribución culinaria más universal del Nuevo Mundo al Viejo."]
},
'e138': {
  fr:["L'odeur du durian est si intense qu'elle est détectable à travers un emballage hermétique — les molécules responsables incluent des composés soufrés.","Malgré son odeur, la chair du durian est onctueuse et sucrée, avec des notes de crème pâtissière, d'amande et de vanille.","Le durian est extrêmement nutritif : il contient plus de potassium que la banane et est riche en vitamines B et C."],
  en:["Durian's smell is so intense it can be detected through airtight packaging — the responsible molecules include sulphur compounds.","Despite its odour, durian flesh is creamy and sweet, with notes of custard, almond, and vanilla.","Durian is extremely nutritious: it contains more potassium than banana and is rich in B and C vitamins."],
    es:["El durian (Durio zibethinus) produce un olor tan potente que está prohibido en hoteles, metros y aviones en varios países del sudeste asiático.","Su olor se describe como una mezcla de calcetines sucios, ajo, queso podrido y fruta tropical — pero su sabor cremoso y dulce es adorado por millones de personas en Asia.","El durian es rico en nutrientes, antioxidantes y fibra — pero no debe consumirse con alcohol porque contiene compuestos que inhiben la enzima aldehído deshidrogenasa, causando náuseas severas."]
},
'e139': {
  fr:["Le riz est cultivé depuis au moins 10 000 ans — les plus anciens restes de riz domestiqué ont été trouvés dans la vallée du Yangtze en Chine.","Il existe plus de 40 000 variétés de riz dans le monde, des riz gluants asiatiques aux riz longs parfumés comme le basmati.","La culture du riz inondé produit du méthane — les rizières contribuent à environ 1,5 % des émissions mondiales de gaz à effet de serre."],
  en:["Rice has been cultivated for at least 10,000 years — the oldest remains of domesticated rice were found in China's Yangtze Valley.","Over 40,000 rice varieties exist worldwide, from Asian sticky rices to long-grain aromatics like basmati.","Flooded rice cultivation produces methane — paddy fields contribute about 1.5% of global greenhouse gas emissions."],
    es:["El arroz (Oryza sativa) fue domesticado en China hace unos 9 000 años y hoy alimenta a más de 3 500 millones de personas — la mitad de la humanidad.","Los arrozales inundados producen hasta el 12 % de las emisiones globales de metano: las bacterias anaerobias del agua estancada generan este potente gas de efecto invernadero.","Existen más de 40 000 variedades de arroz cultivadas, desde el basmati indio hasta el arroz glutinoso japonés — una diversidad genética crucial para la seguridad alimentaria mundial."]
},
'e140': {
  fr:["L'esturgeon américain a été tellement surexploité qu'il est passé du statut de nourriture gratuite à celui de mets de luxe en moins d'un siècle.","Certaines espèces d'esturgeons peuvent vivre plus de 100 ans et mesurer plus de 7 mètres de long.","Le béluga de la mer Caspienne produit le caviar le plus cher du monde — un kilo peut dépasser les 25 000 €."],
  en:["American sturgeon was so overfished it went from free bar snack to luxury delicacy in less than a century.","Some sturgeon species can live over 100 years and grow more than 7 metres long.","The Caspian beluga produces the world's most expensive caviar — a kilo can exceed €25,000."],
    es:["En el siglo XIX, el esturión era tan abundante en los ríos de EE.UU. que el caviar se ofrecía gratis en los bares como acompañamiento de la cerveza — como los cacahuetes hoy.","La sobreexplotación llevó al esturión al borde de la extinción: hoy, el caviar de esturión salvaje del Caspio (beluga, osetra, sevruga) puede costar más de 10 000 €/kg.","La acuicultura de esturión se ha desarrollado en China, Italia y EE.UU. para satisfacer la demanda sin extinguir las poblaciones salvajes — China produce hoy más del 60 % del caviar mundial."]
},
'e141': {
  fr:["Le client difficile en question, Cornelius Vanderbilt, se plaignait que ses pommes de terre frites étaient trop épaisses — Crum les a coupées le plus fin possible par défi.","L'histoire de Crum est probablement embellie, mais les « Saratoga chips » sont bien devenues populaires dans la région avant de se répandre nationalement.","Les chips sont aujourd'hui un marché mondial de plus de 35 milliards de dollars par an — les saveurs les plus populaires varient considérablement selon les pays."],
  en:["The fussy customer, Cornelius Vanderbilt, complained that his fried potatoes were too thick — Crum sliced them as thin as possible out of spite.","Crum's story is likely embellished, but 'Saratoga chips' did become popular in the region before spreading nationally.","Crisps are now a global market worth over $35 billion per year — the most popular flavours vary considerably by country."],
    es:["George Crum, un cocinero mestizo del resort Moon's Lake House, creó las chips en 1853 cuando un cliente (posiblemente Cornelius Vanderbilt) se quejó de que sus patatas estaban demasiado gruesas.","Crum cortó las patatas tan finas como pudo, las frió y las saló abundantemente como acto de despecho — el cliente las adoró y las «Saratoga Chips» se convirtieron en un éxito.","Hoy se consumen 11 000 millones de dólares en chips de patata al año solo en EE.UU. — una industria gigante nacida de un acto de frustración culinaria."]
},
'e142': {
  fr:["Le plasma créé par les raisins au micro-ondes atteint des milliers de degrés Celsius — il a été étudié par des physiciens de l'Université de Waterloo en 2019.","Le phénomène est dû à la concentration du champ électromagnétique dans le pont aqueux entre les deux moitiés du raisin coupé.","Cette découverte a des applications potentielles en nanotechnologie et en physique des plasmas à basse énergie."],
  en:["The plasma created by grapes in a microwave reaches thousands of degrees Celsius — it was studied by physicists at the University of Waterloo in 2019.","The phenomenon is caused by the concentration of the electromagnetic field in the aqueous bridge between the two halves of a cut grape.","This discovery has potential applications in nanotechnology and low-energy plasma physics."],
    es:["Cuando se colocan dos mitades de uva pelada en un microondas, la piel que las conecta concentra el campo electromagnético y genera un arco de plasma visible — un fenómeno de física fascinante.","Un estudio de 2019 en PNAS demostró que el efecto se debe a la resonancia de las microondas en las esferas acuosas de las uvas, no a la piel conductora como se creía antes.","No se recomienda reproducir este experimento en casa: el plasma puede dañar el horno microondas y causar incendios — es un fenómeno para laboratorios, no para cocinas."]
},
'e143': {
  fr:["La vanille est le fruit d'une orchidée — Vanilla planifolia — la seule orchidée au monde à produire un fruit comestible.","Au Mexique, la pollinisation naturelle est assurée par une abeille locale, la mélipone — absente partout ailleurs, d'où la pollinisation manuelle.","Edmond Albius, un esclave de 12 ans à La Réunion, a découvert en 1841 la technique de pollinisation manuelle encore utilisée aujourd'hui dans le monde entier."],
  en:["Vanilla is the fruit of an orchid — Vanilla planifolia — the only orchid in the world that produces an edible fruit.","In Mexico, natural pollination is done by a local bee, the melipona — absent elsewhere, hence the need for hand pollination.","Edmond Albius, a 12-year-old enslaved boy in Réunion, discovered in 1841 the hand pollination technique still used worldwide today."],
    es:["La vainilla natural proviene de la orquídea Vanilla planifolia, originaria de México — fuera de su hábitat, cada flor debe polinizarse a mano porque la abeja endémica (Melipona) no existe.","Madagascar produce el 80 % de la vainilla mundial: los agricultores polinizan cada flor individualmente con un palillo de bambú durante las pocas horas en que está abierta.","El 99 % de la vanillina utilizada en la industria alimentaria es sintética, producida a partir de lignina (madera), guayacol (petroquímica) o incluso eugenol (clavo de olor)."]
},
'e144': {
  fr:["Les Péruviens faisaient éclater le maïs en plaçant les grains sur des pierres chaudes ou dans du sable brûlant.","Le pop-corn a été popularisé aux États-Unis lors de la Grande Dépression car il était bon marché — 5 à 10 cents le sachet.","Chaque grain de pop-corn contient une goutte d'eau qui, en chauffant, se transforme en vapeur et fait exploser l'enveloppe à environ 180 °C."],
  en:["Peruvians popped corn by placing kernels on hot stones or in burning sand.","Popcorn became popular in the US during the Great Depression because it was cheap — 5 to 10 cents a bag.","Each popcorn kernel contains a drop of water that, when heated, turns to steam and bursts the hull at about 180°C."],
    es:["Restos de palomitas de maíz de 6 700 años fueron encontrados en cuevas del norte de Perú — haciendo de las palomitas uno de los snacks más antiguos de la humanidad.","El maíz palomero (Zea mays everta) es especial: su cáscara gruesa atrapa el vapor de agua interior hasta que explota a 180 °C, invirtiendo el grano.","Las palomitas se popularizaron en EE.UU. durante la Gran Depresión porque eran baratas, y durante la Segunda Guerra Mundial cuando el azúcar fue racionado y los dulces escaseaban."]
},
'e145': {
  fr:["Certains historiens contestent cette origine et suggèrent que la mayonnaise existait déjà en Espagne sous le nom d'« aïoli sans ail ».","La base de la mayonnaise est une émulsion d'huile dans du jaune d'œuf — la lécithine du jaune sert d'émulsifiant naturel.","La mayonnaise est le condiment le plus vendu aux États-Unis, devançant le ketchup depuis les années 2010."],
  en:["Some historians dispute this origin and suggest mayonnaise already existed in Spain as 'garlic-free aïoli'.","Mayonnaise is an emulsion of oil in egg yolk — the lecithin in the yolk serves as a natural emulsifier.","Mayonnaise is the best-selling condiment in the United States, overtaking ketchup since the 2010s."],
    es:["La mayonesa se atribuye al chef del duque de Richelieu tras la conquista de Mahón (Menorca) en 1756 — de ahí su nombre, derivado de «mahonnaise».","Otros historiadores la atribuyen a Bayonne (bayonnaise) o al verbo francés manier (manipular/mezclar) — su origen exacto sigue siendo disputado.","La emulsión de la mayonesa es un milagro de la física: la lecitina del huevo actúa como emulsionante, estabilizando millones de gotitas de aceite suspendidas en vinagre o limón."]
},
'e146': {
  fr:["Le soja est l'une des plus anciennes cultures au monde — il est cultivé en Chine depuis au moins 5 000 ans.","Le soja contient les huit acides aminés essentiels, ce qui en fait l'une des rares protéines végétales complètes.","Le Brésil est devenu le premier producteur mondial de soja, dépassant les États-Unis — la culture est aussi controversée pour la déforestation qu'elle entraîne."],
  en:["Soybeans are one of the world's oldest crops — cultivated in China for at least 5,000 years.","Soybeans contain all eight essential amino acids, making them one of the few complete plant proteins.","Brazil has become the world's top soybean producer, surpassing the US — the crop is also controversial for the deforestation it drives."],
    es:["La Gioconda solo mide 77 × 53 cm — muchos visitantes del Louvre se sorprenden al descubrir que el cuadro más famoso del mundo es más pequeño que un cartel de película.","El sfumato de Leonardo (transiciones imperceptibles entre colores) es tan sutil que la técnica no se pudo analizar hasta el siglo XXI con escáneres de fluorescencia de rayos X.","La Mona Lisa recibe 10 millones de visitantes al año — más que cualquier otra obra de arte, protegida por cristal antibalas tras el robo de 1911 y el ataque con ácido de 1956."]
},
'e147': {
  fr:["La Joconde est protégée par une vitre blindée depuis 1956, après qu'un visiteur lui a jeté de l'acide et un autre un caillou.","Le tableau a été volé au Louvre en 1911 par Vincenzo Peruggia, un vitrier italien — il fut retrouvé deux ans plus tard à Florence.","Le sourire de la Joconde utilise la technique du sfumato — des couches de glacis ultra-fines qui créent des contours fondus et insaisissables."],
  en:["The Mona Lisa has been behind bulletproof glass since 1956, after a visitor threw acid at it and another a stone.","The painting was stolen from the Louvre in 1911 by Vincenzo Peruggia, an Italian glazier — it was recovered two years later in Florence.","The Mona Lisa's smile uses the sfumato technique — ultra-thin glaze layers that create blurred, elusive contours."],
    es:["Van Gogh produjo más de 2 100 obras en apenas 10 años de carrera artística (1880-1890), incluyendo 860 óleos — un ritmo frenético que refleja su urgencia creativa.","La vigne rouge fue vendida en 1890 por 400 francos a la coleccionista belga Anna Boch — hoy, sus cuadros se venden por decenas de millones de dólares.","Van Gogh sufría probablemente de trastorno bipolar y epilepsia del lóbulo temporal — su visión artística podría haber sido influida por las auras visuales de sus crisis epilépticas."]
},
'e148': {
  fr:["Van Gogh a produit environ 2 100 œuvres en seulement dix ans de carrière artistique — dont 860 peintures à l'huile.","Sa peinture « Portrait du Dr Gachet » s'est vendue pour 82,5 millions de dollars en 1990 — un record mondial à l'époque.","Van Gogh écrivait des lettres prolifiques à son frère Théo — plus de 800 ont survécu et sont considérées comme une œuvre littéraire à part entière."],
  en:["Van Gogh produced about 2,100 works in just ten years of artistic career — including 860 oil paintings.","His 'Portrait of Dr Gachet' sold for $82.5 million in 1990 — a world record at the time.","Van Gogh wrote prolific letters to his brother Theo — over 800 survive and are considered a literary work in their own right."],
    es:["Miguel Ángel pintó la Capilla Sixtina de pie sobre andamios que él mismo diseñó, no tumbado como suele representarse — el trabajo le causó dolor crónico de cuello y espalda.","Tardó cuatro años (1508-1512) y pintó todo al fresco: cada día, una capa de yeso fresco sobre la que pintar antes de que secara — cualquier error obligaba a raspar y empezar de nuevo.","Los frescos fueron restaurados entre 1984 y 1999, revelando colores brillantes ocultos bajo siglos de hollín y barnices — la restauración fue controvertida por algunos expertos."]
},
'e149': {
  fr:["Michelange a mis quatre ans (1508-1512) à peindre le plafond de la chapelle Sixtine — une surface de plus de 500 m².","Il se plaignait dans un poème que la peinture lui coulait sur le visage et qu'il avait mal au dos — mais il travaillait debout, la tête renversée.","Le plafond contient plus de 300 figures humaines, dont la célèbre scène de la Création d'Adam avec les doigts qui se touchent presque."],
  en:["Michelangelo took four years (1508–1512) to paint the Sistine Chapel ceiling — a surface of over 500 m².","He complained in a poem that paint dripped on his face and his back ached — but he worked standing up with his head tilted back.","The ceiling contains over 300 human figures, including the famous Creation of Adam scene with the nearly touching fingers."],
    es:["El David de Miguel Ángel fue esculpido a partir de un bloque de mármol defectuoso que otros escultores habían rechazado — un bloque demasiado estrecho y con una grieta lateral.","Miguel Ángel comenzó la escultura en 1501 y la terminó en 1504, a los 29 años — fue su primera gran comisión y lo catapultó a la fama.","La inclinación de la cabeza de David, su mirada desafiante y la vena palpitante de su mano derecha transmiten una tensión dramática que revolucionó la escultura renacentista."]
},
'e150': {
  fr:["Le bloc de marbre utilisé par Michel-Ange avait été abandonné par deux autres sculpteurs avant lui — il était considéré comme défectueux.","Michel-Ange n'avait que 26 ans quand il a achevé le David en 1504 — le chef-d'œuvre a pris deux ans à réaliser.","Le David devait initialement être placé sur le toit de la cathédrale de Florence — mais sa beauté l'a fait installer sur la place publique."],
  en:["The marble block used by Michelangelo had been abandoned by two other sculptors — it was considered flawed.","Michelangelo was only 26 when he completed David in 1504 — the masterpiece took two years to create.","David was originally meant to sit on the roof of Florence Cathedral — but its beauty led to its placement in the public square."],
    es:["El nombre «impresionismo» fue dado despectivamente por el crítico Louis Leroy tras ver Impresión, sol naciente de Monet en 1874 — los artistas adoptaron el insulto como bandera.","Los impresionistas rompieron con la tradición académica al pintar al aire libre (plein air), capturando la luz natural y los efectos atmosféricos con pinceladas visibles y colores puros.","Monet, Renoir, Degas, Pissarro y Berthe Morisot fueron rechazados sistemáticamente por el Salón oficial — sus exposiciones independientes cambiaron la historia del arte para siempre."]
},
'e151': {
  fr:["Le critique Louis Leroy a utilisé le titre du tableau de Monet pour se moquer du style — les artistes ont adopté le terme avec fierté.","Les impressionnistes peignaient souvent en plein air (« en plein air ») pour capturer la lumière naturelle changeante — une révolution technique.","Monet a peint plus de 250 tableaux de nymphéas dans les 30 dernières années de sa vie, presque exclusivement dans son jardin de Giverny."],
  en:["Critic Louis Leroy used Monet's painting title to mock the style — the artists adopted the term with pride.","Impressionists often painted outdoors ('en plein air') to capture changing natural light — a technical revolution.","Monet painted over 250 water lily paintings in the last 30 years of his life, almost exclusively in his Giverny garden."],
    es:["Dalí se dormía en un sillón sosteniendo una llave sobre un plato metálico: al caer dormido, la llave caía, el ruido lo despertaba y pintaba las imágenes de ese estado hipnagógico.","Esta técnica, llamada «sueño con una llave», le permitía acceder a imágenes del subconsciente — los relojes blandos de La persistencia de la memoria nacieron de esta práctica.","Dalí era un genio del marketing personal: su bigote, sus declaraciones provocadoras y sus apariciones excéntricas lo convirtieron en el artista más famoso de su tiempo."]
},
'e152': {
  fr:["Cette méthode s'appelle la technique de la cuillère — quand le crayon tombe et frappe le sol, le bruit réveille l'artiste.","Dalí appelait ces micro-siestes des « rêves d'une seconde » — il affirmait qu'elles nourrissaient directement ses peintures surréalistes.","Thomas Edison utilisait la même technique avec des billes métalliques — preuve que les esprits créatifs cherchent l'inspiration à la frontière du sommeil."],
  en:["This method is called the spoon technique — when the pencil drops and hits the floor, the noise wakes the artist.","Dalí called these micro-naps 'one-second dreams' — he claimed they directly fed his surrealist paintings.","Thomas Edison used the same technique with metal balls — proof that creative minds seek inspiration at sleep's threshold."],
    es:["La Torre Eiffel fue construida en 2 años, 2 meses y 5 días por 300 obreros que ensamblaron 18 038 piezas metálicas con 2,5 millones de remaches.","Fue ferozmente criticada por artistas e intelectuales como Maupassant, que almorzaba en su restaurante porque era «el único lugar de París desde donde no se ve la Torre Eiffel».","La torre se repinta cada 7 años con 60 toneladas de pintura en tres tonos de marrón (más claro arriba) — el color original era rojo veneciano."]
},
'e153': {
  fr:["À 330 mètres, la Tour Eiffel a été la plus haute structure du monde pendant 41 ans, jusqu'à la construction du Chrysler Building en 1930.","Gustave Eiffel avait un appartement privé au sommet de la tour, où il recevait des visiteurs comme Thomas Edison.","La tour change de taille selon la température : la dilatation thermique du fer peut la faire grandir de 15 cm en été."],
  en:["At 330 metres, the Eiffel Tower was the world's tallest structure for 41 years, until the Chrysler Building was erected in 1930.","Gustave Eiffel had a private apartment at the top where he received visitors like Thomas Edison.","The tower changes size with temperature: thermal expansion of the iron can make it grow 15 cm in summer."],
    es:["Picasso atravesó múltiples períodos artísticos — azul, rosa, cubismo, neoclasicismo, surrealismo — reinventándose constantemente durante 80 años de carrera.","Cofundó el cubismo con Georges Braque, descomponiendo los objetos en formas geométricas y mostrando múltiples perspectivas simultáneamente — una revolución visual radical.","El Guernica (1937), pintado en respuesta al bombardeo de la ciudad vasca, es considerado uno de los alegatos más poderosos contra la guerra jamás creados."]
},
'e154': {
  fr:["Picasso a traversé de nombreuses périodes stylistiques : bleue, rose, cubiste, classique, surréaliste — se réinventant constamment.","Son tableau « Les Demoiselles d'Avignon » (1907) est considéré comme l'acte fondateur du cubisme et de l'art moderne.","Picasso a vécu jusqu'à 91 ans et a travaillé presque chaque jour — il disait : « L'inspiration existe, mais elle doit te trouver en train de travailler. »"],
  en:["Picasso went through many stylistic periods: Blue, Rose, Cubist, Classical, Surrealist — constantly reinventing himself.","His painting 'Les Demoiselles d'Avignon' (1907) is considered the founding act of Cubism and modern art.","Picasso lived to 91 and worked almost every day — he said: 'Inspiration exists, but it has to find you working.'"],
    es:["La tapisserie de Bayeux mide 70 metros de largo por 50 cm de alto y narra en 58 escenas bordadas la conquista normanda de Inglaterra en 1066.","No es técnicamente un tapiz (tejido en telar) sino un bordado sobre lino — probablemente realizado en Canterbury, no en Bayeux, por encargo del obispo Odón.","Es un documento histórico invaluable: muestra armas, barcos, comida, fortificaciones y el cometa Halley — la representación más antigua de este cometa."]
},
'e155': {
  fr:["Malgré son nom, la tapisserie de Bayeux est en réalité une broderie — les images sont cousues au fil de laine sur une toile de lin.","Elle contient 626 personnages humains, 190 chevaux, 35 chiens et 37 bâtiments — avec des détails remarquables sur les armes et navires normands.","La tapisserie a failli être découpée par des soldats napoléoniens pour couvrir un chariot de ravitaillement — elle a été sauvée de justesse."],
  en:["Despite its name, the Bayeux Tapestry is actually an embroidery — the images are stitched in wool thread on a linen canvas.","It contains 626 human figures, 190 horses, 35 dogs, and 37 buildings — with remarkable details on Norman weapons and ships.","The tapestry was nearly cut up by Napoleonic soldiers to cover a supply wagon — it was saved just in time."],
    es:["El ballet nació en las cortes italianas del Renacimiento como entretenimiento aristocrático y se codificó en Francia bajo Luis XIV, quien fundó la Académie Royale de Danse en 1661.","Luis XIV era un bailarín consumado que interpretó el papel del Sol en el Ballet de la Nuit (1653) — de ahí su sobrenombre de «Rey Sol».","Las puntas (técnica de bailar sobre la punta de los pies) no se desarrollaron hasta principios del siglo XIX — antes, las bailarinas usaban tacones bajos."]
},
'e156': {
  fr:["Les cinq positions fondamentales des pieds en ballet ont été codifiées par Pierre Beauchamp, maître de danse de Louis XIV.","Louis XIV lui-même était un danseur passionné — il a joué le rôle du Soleil dans le Ballet de la Nuit en 1653, d'où son surnom de Roi-Soleil.","Les pointes n'ont été introduites qu'au début du XIXe siècle — les danseuses utilisent des chaussons renforcés qui durent en moyenne 12 heures de spectacle."],
  en:["The five fundamental foot positions in ballet were codified by Pierre Beauchamp, dance master to Louis XIV.","Louis XIV himself was a passionate dancer — he played the role of the Sun in the Ballet de la Nuit in 1653, earning his nickname the Sun King.","Pointe shoes were only introduced in the early 19th century — dancers use reinforced slippers that last an average of 12 hours of performance."],
    es:["La caligrafía islámica es considerada la forma más elevada de arte visual en la tradición musulmana, porque la representación figurativa de Dios y el Profeta está prohibida.","Los calígrafos maestros (hattat) pasaban décadas perfeccionando su arte y podían alcanzar el estatus social de nobles — sus obras adornaban mezquitas, palacios y manuscritos del Corán.","Los estilos caligráficos principales incluyen el nasj (claro, para textos), el thuluth (monumental, para inscripciones) y el diwani (ornamental, para documentos oficiales)."]
},
'e157': {
  fr:["La calligraphie arabe est considérée comme l'art le plus noble de l'islam car elle transcrit la parole divine du Coran.","Il existe six styles calligraphiques classiques (« les six plumes ») codifiés par le grand calligraphe Ibn Muqla au Xe siècle.","Les mosquées sont décorées de calligraphie plutôt que d'images figuratives, conformément à l'interdiction de la représentation humaine dans l'art sacré."],
  en:["Arabic calligraphy is considered Islam's noblest art form because it transcribes the divine word of the Quran.","Six classical calligraphic styles ('the six pens') were codified by the great calligrapher Ibn Muqla in the 10th century.","Mosques are decorated with calligraphy rather than figurative images, in keeping with the prohibition of human depiction in sacred art."],
    es:["El origami japonés ha inspirado aplicaciones en ingeniería: paneles solares plegables para satélites, stents cardíacos y airbags de automóvil usan principios de plegado de papel.","El teorema de Huzita-Hatori establece que el origami puede resolver ecuaciones cúbicas que la regla y el compás no pueden — es matemáticamente más potente que la geometría euclidiana.","La grulla de papel (orizuru) es el símbolo más conocido del origami: la leyenda dice que quien pliega 1 000 grullas verá cumplido un deseo — Sadako Sasaki, víctima de Hiroshima, lo popularizó."]
},
'e158': {
  fr:["Robert Lang, physicien et origamiste, utilise des algorithmes mathématiques pour concevoir des plis d'origami d'une complexité inégalée.","Un stent artériel inspiré de l'origami peut être inséré replié dans une artère, puis se déployer à sa taille fonctionnelle une fois en place.","Le satellite JAXA utilise un panneau solaire plié selon le motif Miura-ori, qui se déploie en un seul mouvement dans l'espace."],
  en:["Robert Lang, a physicist and origamist, uses mathematical algorithms to design origami folds of unmatched complexity.","An origami-inspired arterial stent can be inserted folded into an artery, then expand to functional size once in place.","The JAXA satellite uses a solar panel folded in the Miura-ori pattern, which unfolds in a single motion in space."],
    es:["La obra Girl with Balloon de Banksy se autodestruyó parcialmente con una trituradora oculta en el marco justo después de venderse por 1,4 millones de dólares en Sotheby's en 2018.","La obra parcialmente triturada, rebautizada Love is in the Bin, se vendió tres años después por 25,4 millones — la autodestrucción multiplicó su valor por 18.","Banksy permanece anónimo a pesar de ser uno de los artistas más famosos del mundo — su identidad es objeto de especulación constante y nunca ha sido confirmada oficialmente."]
},
'e159': {
  fr:["L'œuvre, « Girl with Balloon », s'est vendue pour 1,04 million de livres — puis a été rebaptisée « Love Is in the Bin » après sa destruction partielle.","L'identité de Banksy reste inconnue malgré des décennies de spéculation — il communique via son site web et ses réseaux sociaux.","Ironiquement, la version partiellement détruite s'est revendue en 2021 pour 18,6 millions de livres — 18 fois plus que l'original intact."],
  en:["The work, 'Girl with Balloon', sold for £1.04 million — then was renamed 'Love Is in the Bin' after its partial destruction.","Banksy's identity remains unknown despite decades of speculation — he communicates via his website and social media.","Ironically, the partially destroyed version resold in 2021 for £18.6 million — 18 times more than the intact original."],
    es:["El azul ultramarino medieval se obtenía exclusivamente del lapislázuli afgano: costaba más que el oro y se reservaba para representar el manto de la Virgen María.","Los pintores medievales usaban una paleta limitada por el coste de los pigmentos: el azul era un lujo, el rojo bermellón (cinabrio) era tóxico y el verde de París (arseniato de cobre) era venenoso.","El primer pigmento azul sintético fue el azul de Prusia, descubierto accidentalmente en 1704 por un fabricante de pinturas — democratizó el color azul en la pintura occidental."]
},
'e160': {
  fr:["Le bleu outremer, fabriqué à partir de lapis-lazuli broyé, coûtait plus cher que l'or — il était réservé aux éléments les plus sacrés des peintures.","La Vierge Marie est presque toujours représentée en bleu dans l'art européen médiéval — un signe de son statut divin lié au coût du pigment.","En 1826, le chimiste français Jean-Baptiste Guimet a synthétisé le bleu outremer artificiel, rendant cette couleur enfin accessible à tous les peintres."],
  en:["Ultramarine blue, made from crushed lapis lazuli, cost more than gold — it was reserved for the most sacred elements in paintings.","The Virgin Mary is almost always depicted in blue in medieval European art — a sign of divine status linked to the pigment's cost.","In 1826, French chemist Jean-Baptiste Guimet synthesised artificial ultramarine blue, finally making the colour accessible to all painters."],
    es:["El Coliseo tenía un sistema de toldos retráctiles (velarium) operado por 1 000 marineros que protegía a los espectadores del sol — una ingeniería que los estadios modernos aún replican.","Bajo la arena había un laberinto de túneles (hypogeum) con ascensores mecánicos que hacían aparecer animales y gladiadores por trampillas — un sistema de efectos especiales de la Antigüedad.","Los espectáculos del Coliseo incluían batallas navales (naumaquias): la arena se inundaba mediante acueductos para simular combates entre barcos reales."]
},
'e161': {
  fr:["Le Colisée possédait un velum, une immense toile rétractable actionnée par 1 000 marins, qui protégeait les spectateurs du soleil.","Les spectacles au Colisée incluaient des naumachies — des batailles navales reconstituées en inondant l'arène d'eau.","Le Colisée a été construit en seulement 8 ans (72-80 ap. J.-C.) par des dizaines de milliers d'esclaves et d'artisans."],
  en:["The Colosseum had a velarium, a massive retractable awning operated by 1,000 sailors, shielding spectators from the sun.","Colosseum shows included naumachiae — naval battles recreated by flooding the arena with water.","The Colosseum was built in just 8 years (72–80 AD) by tens of thousands of enslaved people and craftsmen."],
    es:["Las pinturas rupestres de la cueva de Leang Tedongnge en Sulawesi (Indonesia) tienen al menos 45 500 años — las más antiguas representaciones figurativas conocidas.","Representan un cerdo verrugoso de Sulawesi pintado con ocre rojo y miden 136 × 54 cm — una composición elaborada que demuestra capacidades artísticas avanzadas.","Estas pinturas demuestran que el arte figurativo no fue una invención exclusivamente europea: los Homo sapiens que colonizaron el sudeste asiático ya eran artistas plenamente desarrollados."]
},
'e162': {
  fr:["La peinture de Leang Bulu Sipong 4 représente une scène de chasse avec des figures mi-humaines mi-animales — les premiers thérianthropes connus de l'art.","Ces peintures remettent en question l'idée que l'art figuratif est né en Europe — l'Asie du Sud-Est pourrait être un berceau artistique plus ancien.","Les pigments utilisés sont à base d'ocre rouge et de charbon — des matériaux qui résistent remarquablement au temps dans les conditions de grotte."],
  en:["The Leang Bulu Sipong 4 painting depicts a hunting scene with half-human, half-animal figures — the earliest known therianthropes in art.","These paintings challenge the idea that figurative art originated in Europe — Southeast Asia may be an older artistic cradle.","The pigments used are red ochre and charcoal — materials that resist time remarkably well in cave conditions."],
    es:["El Ópera de Sydney tardó 14 años en construirse (1959-1973) y costó 102 millones de dólares — 14 veces el presupuesto original de 7 millones.","El arquitecto danés Jørn Utzon ganó el concurso con un diseño revolucionario de conchas de hormigón, pero abandonó el proyecto en 1966 por desacuerdos con el gobierno — nunca vio el edificio terminado en persona.","En 2003, Utzon recibió el Premio Pritzker (el «Nobel de la arquitectura») y fue invitado a participar en la renovación — murió en 2008, reconciliado con su obra maestra."]
},
'e163': {
  fr:["L'architecte danois Jørn Utzon a remporté le concours avec un dessin si schématique que le jury a failli le rejeter — un juré l'a repêché in extremis.","Les « voiles » du toit ont posé des problèmes d'ingénierie si complexes qu'Utzon a dû les reconcevoir comme des sections d'une même sphère.","Utzon a démissionné en cours de chantier suite à des conflits avec le gouvernement — il n'a jamais vu le bâtiment terminé en personne."],
  en:["Danish architect Jørn Utzon won the competition with such a schematic sketch that the jury nearly rejected it — a juror rescued it at the last moment.","The roof 'sails' posed such complex engineering problems that Utzon had to redesign them as sections of a single sphere.","Utzon resigned mid-construction due to conflicts with the government — he never saw the finished building in person."],
    es:["La mosaico romano más famoso es el de Alejandro (Pompeya, siglo II a.C.), que representa la batalla de Issos con 1,5 millones de teselas de piedra y vidrio coloreado.","El arte del mosaico alcanzó su cumbre en Bizancio: los mosaicos de Rávena (siglo VI) usan teselas de oro y vidrio que reflejan la luz, creando un efecto sobrenatural.","Los mosaicos bizantinos no son solo decoración: son teología visual, con programas iconográficos que enseñaban la doctrina cristiana a una población mayoritariamente analfabeta."]
},
'e164': {
  fr:["Les tesselles byzantines étaient souvent en verre doré : une feuille d'or prise en sandwich entre deux couches de verre, créant un éclat lumineux permanent.","La basilique Sainte-Sophie à Istanbul contient environ 30 millions de tesselles dans ses mosaïques, couvrant plus de 1 600 m².","Les mosaïques romaines de Pompéi, préservées sous les cendres du Vésuve, sont parmi les mieux conservées du monde antique."],
  en:["Byzantine tesserae were often gold glass: a gold leaf sandwiched between two glass layers, creating a permanent luminous glow.","The Hagia Sophia in Istanbul contains about 30 million tesserae in its mosaics, covering over 1,600 m².","Roman mosaics from Pompeii, preserved under Vesuvius ash, are among the best-preserved in the ancient world."],
    es:["La invención de la fotografía en los años 1830-40 liberó a la pintura de la obligación de representar la realidad, abriendo el camino al impresionismo, el expresionismo y la abstracción.","Delacroix declaró: «A partir de hoy, la pintura ha muerto» — pero en realidad, la fotografía empujó a los pintores a explorar lo que la cámara no podía capturar: la emoción, el color y la subjetividad.","La relación entre fotografía y pintura sigue evolucionando: el hiperrealismo (pintura que imita la fotografía) y la fotografía artística (fotografía que imita la pintura) difuminan la frontera."]
},
'e165': {
  fr:["Paul Delaroche aurait déclaré en 1840 devant un daguerréotype : « À partir d'aujourd'hui, la peinture est morte » — une prophétie largement exagérée.","L'impressionnisme est né en partie comme réponse à la photographie : si la machine capture la réalité, le peintre capture la sensation.","Paradoxalement, de nombreux peintres ont utilisé la photographie comme outil — Degas, Toulouse-Lautrec et Munch s'en servaient pour composer leurs œuvres."],
  en:["Paul Delaroche reportedly declared in 1840 before a daguerreotype: 'From today, painting is dead' — a prophecy widely overstated.","Impressionism was born partly as a response to photography: if the machine captures reality, the painter captures sensation.","Paradoxically, many painters used photography as a tool — Degas, Toulouse-Lautrec, and Munch all used it to compose their works."],
    es:["La escultura en madera más grande del mundo tallada de un solo tronco se encuentra en China: un Buda reclinado de 14,5 metros de largo esculpido en un tronco de canfor de 1 000 años.","La madera ha sido el material escultórico más accesible de la historia: desde los tótems de los pueblos del Pacífico Norte hasta los retablos barrocos españoles.","La escultura en madera presenta un desafío único: el artista debe trabajar con la veta, los nudos y las grietas naturales — las limitaciones del material definen la obra."]
},
'e166': {
  fr:["La sculpture a été créée à partir d'un seul tronc de cyprès de plus de 12 mètres de long — le travail de sculpture a duré trois ans.","Elle représente une scène maritime avec 36 navires, des centaines de poissons et des créatures mythologiques chinoises.","Le séquoia d'origine avait été préservé par des conditions marécageuses qui empêchaient la décomposition pendant des millénaires."],
  en:["The sculpture was carved from a single cypress trunk over 12 metres long — the carving work took three years.","It depicts a maritime scene with 36 ships, hundreds of fish, and Chinese mythological creatures.","The original sequoia had been preserved by marshy conditions that prevented decomposition for millennia."],
    es:["Beethoven compuso la Novena Sinfonía (1824) estando completamente sordo — dirigió el estreno pero no pudo oír la ovación del público hasta que una cantante lo giró hacia la audiencia.","El Himno a la Alegría del cuarto movimiento fue adoptado como himno de la Unión Europea en 1985 — un símbolo de unidad que trasciende naciones y culturas.","Beethoven es el puente entre el clasicismo y el romanticismo: amplió la sinfonía, liberó la expresión emocional y elevó la música instrumental a la categoría de arte supremo."]
},
'e167': {
  fr:["Beethoven a commencé à perdre l'audition vers 26 ans — à 45 ans, il était complètement sourd mais continuait de composer.","Pour sentir les vibrations de sa musique, Beethoven sciait les pieds de son piano et posait l'oreille contre le sol pendant qu'il jouait.","La 9e Symphonie, avec son « Ode à la joie », est devenue l'hymne officiel de l'Union européenne."],
  en:["Beethoven began losing his hearing around age 26 — by 45 he was completely deaf but continued composing.","To feel the vibrations of his music, Beethoven sawed the legs off his piano and pressed his ear to the floor while playing.","The 9th Symphony, with its 'Ode to Joy', became the official anthem of the European Union."],
    es:["Beethoven compuso varias de sus obras maestras — incluida la Novena Sinfonía — después de quedarse completamente sordo, «escuchando» la música solo en su imaginación.","Usaba un dispositivo de conducción ósea: una varilla de madera sujeta entre los dientes y apoyada en el piano para sentir las vibraciones — un ingenio nacido de la desesperación.","La Novena Sinfonía fue la primera gran sinfonía en incluir voces humanas (el Himno a la Alegría) — una innovación que rompió las convenciones del género e influyó en toda la música posterior."]
},
'e168': {
  fr:["Le finnois est une langue agglutinante : on peut ajouter des suffixes en chaîne pour former des mots extrêmement longs mais grammaticalement corrects.","Le finnois n'appartient pas à la famille des langues indo-européennes — il fait partie des langues ouraliennes, avec le hongrois et l'estonien.","En finnois, il n'y a pas de genre grammatical (pas de « il » ou « elle ») — le pronom « hän » est neutre."],
  en:["Finnish is an agglutinative language: suffixes can be chained to form extremely long but grammatically correct words.","Finnish doesn't belong to the Indo-European language family — it's part of the Uralic languages, alongside Hungarian and Estonian.","In Finnish, there is no grammatical gender (no 'he' or 'she') — the pronoun 'hän' is gender-neutral."],
    es:["El finés es una lengua aglutinante con 15 casos gramaticales: una sola palabra puede expresar lo que en español requiere toda una frase.","El finés no pertenece a la familia indoeuropea sino a la familia urálica, sin relación con sus vecinos suecos, noruegos o rusos.","Las palabras finesas más largas del lenguaje cotidiano superan las 30 letras — en contextos técnicos o administrativos pueden superar las 50."]
},
'e169': {
  fr:["L'esperanto a été créé par Ludwik Zamenhof, un ophtalmologiste polonais qui rêvait d'une langue universelle pour favoriser la paix entre les peuples.","La grammaire de l'esperanto ne comporte que 16 règles sans exception — ce qui en fait l'une des langues les plus faciles à apprendre.","Google Translate, Duolingo et Wikipedia proposent tous une version en esperanto — la Wikipédia esperanto compte plus de 340 000 articles."],
  en:["Esperanto was created by Ludwik Zamenhof, a Polish ophthalmologist who dreamed of a universal language to promote peace.","Esperanto grammar has only 16 rules with no exceptions — making it one of the easiest languages to learn.","Google Translate, Duolingo, and Wikipedia all offer Esperanto versions — Esperanto Wikipedia has over 340,000 articles."],
    es:["El esperanto tiene solo 16 reglas gramaticales sin excepciones — se estima que se puede aprender 5 veces más rápido que cualquier idioma natural.","Su vocabulario combina raíces latinas, germánicas y eslavas diseñadas para ser reconocibles por el mayor número de europeos posible.","A pesar de más de 130 años de existencia, el esperanto nunca alcanzó la masa crítica necesaria para convertirse en lengua franca — pero mantiene una comunidad activa de 100 000 a 2 millones de hablantes."]
},
'e170': {
  fr:["L'ubykh s'est éteint en 1992 avec la mort de son dernier locuteur natif, Tevfik Esenç, en Turquie.","Malgré ses 84 consonnes, l'ubykh ne possédait que 2 voyelles — un rapport consonnes/voyelles unique au monde.","Le linguiste Georges Dumézil a consacré une grande partie de sa carrière à documenter l'ubykh avant sa disparition."],
  en:["Ubykh went extinct in 1992 with the death of its last native speaker, Tevfik Esenç, in Turkey.","Despite its 84 consonants, Ubykh had only 2 vowels — a consonant-to-vowel ratio unique in the world.","Linguist Georges Dumézil devoted much of his career to documenting Ubykh before its disappearance."],
    es:["El ubykh, extinto desde 1992 con la muerte de su último hablante Tevfik Esenç en Turquía, tenía 84 consonantes y solo 2 vocales.","Las lenguas del Cáucaso son famosas por su complejidad consonántica: el ubykh y sus parientes (abjaso, circasiano) desafían la tipología lingüística estándar.","La documentación de lenguas en peligro es una carrera contra el reloj: unas 3 000 de las 7 000 lenguas del mundo podrían desaparecer antes de 2100."]
},
'e171': {
  fr:["Une légende populaire attribue le mot « quiz » à un pari fait à Dublin en 1791 par un directeur de théâtre qui aurait affiché le mot partout pour le rendre viral.","Le sens actuel de « quiz » comme test de connaissances n'est apparu qu'au milieu du XIXe siècle — avant, il signifiait « personne excentrique ».","Le format de quiz télévisé est né dans les années 1930 aux États-Unis avec des émissions radio comme « Ask Me Another »."],
  en:["A popular legend attributes the word 'quiz' to a 1791 Dublin bet by a theatre manager who allegedly posted the word everywhere to make it viral.","The current meaning of 'quiz' as a knowledge test only appeared in the mid-19th century — before that, it meant 'eccentric person'.","The TV quiz format was born in 1930s America with radio shows like 'Ask Me Another'."],
    es:["Una leyenda popular cuenta que un director de teatro dublinés apostó en 1791 que podía introducir una palabra sin sentido en el idioma en 24 horas — y la palabra era «quiz».","Otra teoría la conecta con el latín «quis» (quién/qué) — pero ninguna etimología es definitiva, lo que hace de «quiz» una de las palabras inglesas más misteriosas.","El formato de quiz (preguntas y respuestas) se popularizó en la radio estadounidense de los años 1930 y se convirtió en un pilar de la televisión con programas como Jeopardy! y Who Wants to Be a Millionaire?."]
},
'e172': {
  fr:["L'Académie française, fondée en 1634, a pour mission de réglementer et enrichir la langue française — elle publie son Dictionnaire depuis 1694.","Le français a emprunté des milliers de mots à l'anglais au XXe siècle (« parking », « week-end ») malgré les efforts de l'Académie pour les remplacer.","Le français est langue officielle dans 29 pays et parlé par plus de 320 millions de personnes dans le monde."],
  en:["The Académie française, founded in 1634, is tasked with regulating and enriching the French language — it has published its Dictionary since 1694.","French borrowed thousands of words from English in the 20th century ('parking', 'weekend') despite the Académie's efforts to replace them.","French is an official language in 29 countries and spoken by over 320 million people worldwide."],
    es:["El enriquecimiento del vocabulario francés refleja la evolución de la sociedad: miles de palabras nuevas entran en los diccionarios cada década, mientras otras caen en desuso.","La Academia Francesa, fundada en 1635, intenta regular la lengua con su lema «Limpia, fija y da esplendor» — pero el uso popular siempre supera a la norma académica.","Los anglicismos son una fuente constante de debate en Francia: el gobierno promueve equivalentes franceses (courriel vs email) con un éxito variable."]
},
'e173': {
  fr:["Le Scriptio continua (écriture continue sans espaces) était la norme dans les manuscrits grecs et latins — les lecteurs devaient deviner où finissait chaque mot.","Les premiers signes de ponctuation ont été introduits par le bibliothécaire Aristophane de Byzance au IIIe siècle av. J.-C. sous forme de points à différentes hauteurs.","Le point d'interrogation tel qu'on le connaît n'est apparu qu'au XIIIe siècle — il dérive probablement de l'abréviation latine « quaestio » (qo)."],
  en:["Scriptio continua (continuous writing without spaces) was standard in Greek and Latin manuscripts — readers had to guess where each word ended.","The first punctuation marks were introduced by librarian Aristophanes of Byzantium in the 3rd century BC as dots at different heights.","The question mark as we know it only appeared in the 13th century — it likely derives from the Latin abbreviation 'quaestio' (qo)."],
    es:["Los manuscritos antiguos se escribían en scriptio continua: todas las letras pegadas sin espacios, sin puntuación y sin mayúsculas — el lector debía descifrar el texto leyéndolo en voz alta.","Los espacios entre palabras fueron introducidos por los monjes irlandeses en el siglo VII para facilitar la lectura del latín, que no era su lengua materna.","La puntuación moderna se estandarizó con la imprenta: Aldo Manuzio (Venecia, siglo XV) inventó el punto y coma, la coma y el formato de itálica que usamos hoy."]
},
'e174': {
  fr:["Louis Braille est devenu aveugle à l'âge de 3 ans après un accident avec un outil tranchant dans l'atelier de son père.","Le système braille est basé sur une cellule de 6 points permettant 63 combinaisons — suffisant pour représenter toutes les lettres, chiffres et signes de ponctuation.","Braille s'est inspiré de la « sonographie » de Charles Barbier, un code militaire nocturne à 12 points — il l'a simplifié à 6 points pour le rendre lisible du bout du doigt."],
  en:["Louis Braille became blind at age 3 after an accident with a sharp tool in his father's workshop.","The Braille system is based on a 6-dot cell allowing 63 combinations — enough to represent all letters, numbers, and punctuation marks.","Braille was inspired by Charles Barbier's 'sonography', a 12-dot military night code — he simplified it to 6 dots to make it fingertip-readable."],
    es:["Louis Braille perdió la vista a los 3 años por un accidente con un punzón en el taller de su padre — usó la misma herramienta para inventar su sistema de escritura a los 15 años.","Se inspiró en un sistema militar de escritura nocturna (código Barbier) que simplificó de 12 a 6 puntos por celda, haciéndolo legible con un solo toque de dedo.","El Braille permite leer a velocidades de 100-200 palabras por minuto — comparable a la lectura visual en tinta para muchas personas."]
},
'e175': {
  fr:["Le mot a été inventé par Horace Walpole en 1754 dans une lettre où il décrivait des découvertes faites par hasard alors qu'il cherchait autre chose.","La pénicilline, le velcro, le four à micro-ondes et le Post-it sont tous des exemples célèbres de serendipité scientifique.","Le concept de serendipité est devenu si populaire en sciences qu'il existe des prix et des conférences dédiés aux découvertes accidentelles."],
  en:["The word was coined by Horace Walpole in 1754 in a letter describing discoveries made by chance while looking for something else.","Penicillin, Velcro, the microwave oven, and the Post-it Note are all famous examples of scientific serendipity.","The concept of serendipity has become so popular in science that there are prizes and conferences dedicated to accidental discoveries."],
    es:["La serendipia (descubrimiento afortunado e inesperado) fue acuñada por Horace Walpole en 1754, inspirándose en el cuento persa Los tres príncipes de Serendip (antiguo Sri Lanka).","Los príncipes del cuento hacían descubrimientos constantemente gracias a su agudeza observacional y su sagacidad — no por pura suerte, sino por una mente preparada.","La penicilina, el velcro, los rayos X, el microondas y los Post-it son ejemplos de serendipia científica — «la suerte favorece a la mente preparada», como dijo Pasteur."]
},
'e176': {
  fr:["Les kanji sont des caractères chinois adoptés par le japonais — un Japonais lettré en connaît environ 2 000 à 3 000.","Le katakana est utilisé principalement pour les mots étrangers empruntés — « コンピュータ » (konpyūta) signifie « computer ».","L'hiragana et le katakana comptent chacun 46 caractères de base et représentent les mêmes sons — mais avec des usages différents."],
  en:["Kanji are Chinese characters adopted by Japanese — a literate Japanese person knows about 2,000 to 3,000.","Katakana is mainly used for foreign loanwords — 'コンピュータ' (konpyūta) means 'computer'.","Hiragana and katakana each have 46 basic characters representing the same sounds — but with different uses."],
    es:["El japonés usa cuatro sistemas de escritura simultáneamente: hiragana (46 caracteres fonéticos nativos), katakana (46 caracteres para extranjerismos), kanji (caracteres chinos) y romaji (alfabeto latino).","Un adulto japonés educado conoce unos 2 136 kanji (los jōyō kanji oficiales), pero los diccionarios contienen más de 50 000 — cada kanji puede tener múltiples lecturas según el contexto.","Esta complejidad no ha impedido que Japón tenga una de las tasas de alfabetización más altas del mundo (99 %) — el sistema educativo dedica años al aprendizaje de los kanji."]
},
'e177': {
  fr:["Les mots anglais d'origine française couvrent des domaines comme le droit (judge, jury), la cuisine (beef, pork) et l'administration (government, parliament).","Pendant trois siècles après 1066, le français était la langue de la cour et de l'aristocratie en Angleterre — l'anglais était parlé par le peuple.","C'est pourquoi l'animal vivant garde son nom anglo-saxon (cow, pig, sheep) tandis que la viande prend un nom français (beef, pork, mutton)."],
  en:["English words from French cover domains like law (judge, jury), cuisine (beef, pork), and administration (government, parliament).","For three centuries after 1066, French was the language of the court and aristocracy in England — English was spoken by common people.","That's why the living animal keeps its Anglo-Saxon name (cow, pig, sheep) while the meat takes a French name (beef, pork, mutton)."],
    es:["Unas 10 000 palabras francesas entraron en el inglés tras la conquista normanda de 1066: justice, parliament, beef, fashion, restaurant y la propia palabra language.","La coexistencia de sinónimos anglosajones (cotidianos) y franceses (formales) enriqueció enormemente el inglés: begin/commence, ask/demand, help/assist, hide/conceal.","El inglés moderno tiene el vocabulario más extenso del mundo (más de 170 000 palabras en uso), en parte gracias a esta doble herencia germánica y romance."]
},
'e178': {
  fr:["Le mandarin possède quatre tons principaux — prononcer la même syllabe avec un ton différent change complètement le sens du mot.","Le mandarin n'utilise pas d'alphabet : plus de 50 000 caractères existent, mais 3 000 suffisent pour lire un journal.","Le mandarin est devenu langue officielle de la Chine en 1956 sous le nom de putonghua (« langue commune »), remplaçant des centaines de dialectes locaux."],
  en:["Mandarin has four main tones — pronouncing the same syllable with a different tone completely changes the word's meaning.","Mandarin doesn't use an alphabet: over 50,000 characters exist, but 3,000 are enough to read a newspaper.","Mandarin became China's official language in 1956 as putonghua ('common speech'), replacing hundreds of local dialects."],
    es:["El mandarín tiene 4 tonos (más un tono neutro): la sílaba mā puede significar madre, cáñamo, caballo o insultar según la entonación — una fuente inagotable de malentendidos para los extranjeros.","A pesar de los miles de caracteres, el mandarín hablado funciona con solo unas 400 sílabas distintas (sin contar los tonos) — una ambigüedad que el contexto resuelve.","El pinyin (romanización del chino) fue adoptado en 1958 para facilitar la alfabetización — hoy se usa universalmente para escribir chino en teclados y teléfonos."]
},
'e179': {
  fr:["La pièce R.U.R. (Rossum's Universal Robots) de 1920 décrit des robots biologiques, pas mécaniques — plus proches des androïdes de science-fiction moderne.","Le frère de Karel Čapek, Josef, est celui qui a suggéré le mot « robot » — Karel voulait initialement utiliser « laboř » (travailleur).","Isaac Asimov a ensuite popularisé le concept de robot mécanique et inventé les célèbres « Trois Lois de la Robotique » en 1942."],
  en:["The 1920 play R.U.R. (Rossum's Universal Robots) describes biological robots, not mechanical ones — closer to modern sci-fi androids.","Karel Čapek's brother Josef suggested the word 'robot' — Karel originally wanted to use 'laboř' (worker).","Isaac Asimov later popularised the concept of mechanical robots and invented the famous 'Three Laws of Robotics' in 1942."],
    es:["Karel Čapek acuñó «robot» en su obra R.U.R. (1920), pero la idea fue de su hermano Josef — la palabra viene del checo robota (trabajo forzado, servidumbre).","En la obra, los robots no son máquinas sino seres biológicos fabricados que se rebelan contra sus creadores — un tema que anticipa décadas de ciencia ficción sobre IA.","Isaac Asimov formuló las Tres Leyes de la Robótica en 1942, estableciendo un marco ético para robots que sigue siendo referencia en el debate actual sobre inteligencia artificial."]
},
'e180': {
  fr:["Le linguiste Franz Boas avait identifié quatre mots inuits pour la neige en 1911 — le mythe des « centaines de mots » est une exagération journalistique.","En réalité, la langue yupik peut former des dizaines de termes précis pour la neige en combinant des racines et suffixes — mais c'est le fonctionnement normal d'une langue agglutinante.","Le linguiste Geoffrey Pullum a démystifié cette légende dans un essai devenu célèbre : « The Great Eskimo Vocabulary Hoax » (1989)."],
  en:["Linguist Franz Boas identified four Inuit words for snow in 1911 — the 'hundreds of words' myth is a journalistic exaggeration.","In reality, the Yupik language can form dozens of precise snow terms by combining roots and suffixes — but that's the normal functioning of an agglutinative language.","Linguist Geoffrey Pullum debunked this legend in a now-famous essay: 'The Great Eskimo Vocabulary Hoax' (1989)."],
    es:["Los inuit no tienen cientos de palabras para la nieve, pero su lengua polisintética (aglutinante) puede crear expresiones extremadamente específicas combinando raíces y sufijos.","El lingüista Franz Boas mencionó en 1911 que los inuit tenían cuatro raíces para la nieve — la cifra fue inflada por sucesivos autores hasta convertirse en mito.","El debate ilustra un fenómeno real: cada cultura desarrolla vocabulario detallado para lo que le importa — los esquiadores tienen decenas de términos para la nieve, los enólogos para el vino."]
},
'e181': {
  fr:["La philologie moderne est née en Allemagne au XVIIIe siècle avec Friedrich August Wolf, qui en fit une discipline universitaire à part entière.","Le mot « logophile » (amateur de mots) est un cousin de philologie — les deux partagent la racine grecque philos (amour).","Les philologues ont joué un rôle crucial dans le déchiffrement des langues anciennes, du cunéiforme sumérien aux hiéroglyphes égyptiens."],
  en:["Modern philology was born in 18th-century Germany with Friedrich August Wolf, who made it a full university discipline.","The word 'logophile' (word lover) is a cousin of philology — both share the Greek root philos (love).","Philologists played a crucial role in deciphering ancient languages, from Sumerian cuneiform to Egyptian hieroglyphs."],
    es:["La filología (amor por las palabras) fue fundada como disciplina académica en la Alejandría helenística del siglo III a.C. para preservar y estudiar los textos homéricos.","Los filólogos alejandrinos crearon los primeros signos de puntuación, catálogos bibliográficos y ediciones críticas — las herramientas intelectuales que usamos hasta hoy.","La filología moderna incluye la lingüística histórica, la crítica textual y la hermenéutica — disciplinas que investigan cómo las lenguas y los textos evolucionan en el tiempo."]
},
'e182': {
  fr:["La langue des signes française (LSF) a influencé la langue des signes américaine (ASL) — elles partagent environ 60 % de signes communs.","Chaque langue des signes a sa propre grammaire, syntaxe et argot — ce n'est pas une traduction gestuelle de la langue parlée locale.","Les sourds qui utilisent la langue des signes activent les mêmes zones cérébrales du langage (aire de Broca) que les personnes entendantes."],
  en:["French Sign Language (LSF) influenced American Sign Language (ASL) — they share about 60% of their signs.","Each sign language has its own grammar, syntax, and slang — it's not a gestural translation of the local spoken language.","Deaf people using sign language activate the same brain language areas (Broca's area) as hearing people."],
    es:["Cada país o región tiene su propia lengua de signos con gramática, vocabulario y sintaxis propios — la lengua de signos americana (ASL) tiene más similitudes con la francesa (LSF) que con la británica (BSL).","Las lenguas de signos son lenguas naturales completas, no mímica ni traducción del idioma oral — tienen su propia poesía, humor, juegos de palabras y dialectos regionales.","Los niños sordos adquieren la lengua de signos con la misma facilidad y los mismos hitos que los niños oyentes adquieren la lengua oral — prueba de que el lenguaje es independiente del canal."]
},
'e183': {
  fr:["La quarantaine de 40 jours à Venise remonte à 1377 — c'est l'une des premières mesures de santé publique systématiques de l'histoire.","Avant la quarantaine, Venise pratiquait le « trentino » (30 jours d'isolement) — le passage à 40 jours s'est fait pour des raisons à la fois médicales et religieuses.","Le port de Raguse (aujourd'hui Dubrovnik) a été le premier à instaurer une quarantaine officielle en 1377, avant même Venise."],
  en:["Venice's 40-day quarantine dates back to 1377 — one of the first systematic public health measures in history.","Before the quarantine, Venice practised the 'trentino' (30 days of isolation) — the switch to 40 days was for both medical and religious reasons.","The port of Ragusa (now Dubrovnik) was the first to establish an official quarantine in 1377, even before Venice."],
    es:["La cuarentena de 40 días fue establecida por Venecia en 1377 para los barcos que llegaban de zonas afectadas por la peste — los barcos debían fondear en la isla de Lazzaretto Nuovo.","El número 40 tiene connotaciones bíblicas (40 días de diluvio, 40 días de Jesús en el desierto) que pudieron influir en la elección, además de consideraciones médicas empíricas.","El concepto de cuarentena se globalizó con la COVID-19: miles de millones de personas experimentaron el aislamiento sanitario por primera vez en la historia moderna."]
},
'e184': {
  fr:["Le mandarin distingue quatre tons, le cantonais en a six, et certaines langues hmong en ont jusqu'à huit.","Environ 70 % des langues du monde sont des langues à tons — c'est le mode « non tonal » qui est l'exception, pas l'inverse.","Les locuteurs natifs de langues à tons ont plus de chances de développer l'oreille absolue en musique que les autres."],
  en:["Mandarin has four tones, Cantonese has six, and some Hmong languages have up to eight.","About 70% of the world's languages are tonal — the 'non-tonal' mode is the exception, not the rule.","Native speakers of tonal languages are more likely to develop perfect pitch in music than others."],
    es:["Las lenguas tonales representan más del 60 % de las lenguas del mundo: chino mandarín, cantonés, vietnamita, tailandés, yoruba, zulú y muchas otras usan tonos para distinguir significados.","El cantonés tiene 6-9 tonos, el vietnamita 6, el tailandés 5 y el mandarín 4 — los hablantes nativos de lenguas tonales tienen mayor probabilidad de tener oído absoluto en música.","Los hablantes de lenguas no tonales pueden aprender a percibir los tonos con práctica — el cerebro es suficientemente plástico para adaptarse, aunque requiere más esfuerzo en la edad adulta."]
},
'e185': {
  fr:["Une langue disparaît en moyenne toutes les deux semaines — avec elle s'éteint un patrimoine culturel et des connaissances uniques sur le monde.","La Papouasie-Nouvelle-Guinée est le pays le plus linguistiquement diversifié au monde avec plus de 840 langues vivantes.","Des projets comme Endangered Languages de Google et l'Atlas des langues en danger de l'UNESCO travaillent à documenter ces langues avant qu'elles ne disparaissent."],
  en:["A language dies on average every two weeks — with it goes a cultural heritage and unique knowledge about the world.","Papua New Guinea is the world's most linguistically diverse country with over 840 living languages.","Projects like Google's Endangered Languages and UNESCO's Atlas of Languages in Danger work to document these languages before they vanish."],
    es:["Cada dos semanas desaparece una lengua en el mundo — con ella se pierde un sistema único de conocimientos, una visión del mundo y una parte irreemplazable del patrimonio cultural humano.","El 50 % de las lenguas del mundo son habladas por menos de 10 000 personas — las más vulnerables son las lenguas indígenas de América, África, Asia-Pacífico y Australia.","Programas de revitalización como el hawaiano y el maorí demuestran que la inmersión lingüística puede salvar lenguas al borde de la extinción — pero requiere voluntad política y recursos."]
},
'e186': {
  fr:["Le verlan est apparu dans les banlieues françaises dans les années 1970-80 comme un langage codé entre jeunes.","Certains mots de verlan sont entrés dans le dictionnaire officiel, comme « meuf » (femme), « keum » (mec) et « beur » (arabe).","Le verlan peut se « reverlaniser » : « beur » est devenu « rebeu », et « meuf » a donné « feumeu » dans certains cercles."],
  en:["Verlan emerged in French suburbs in the 1970s–80s as a coded language among young people.","Some Verlan words have entered the official dictionary, like 'meuf' (woman), 'keum' (guy), and 'beur' (Arab).","Verlan can be 're-verlanised': 'beur' became 'rebeu', and 'meuf' spawned 'feumeu' in some circles."],
    es:["El verlan invierte las sílabas: femme → meuf, flic → keuf, bizarre → zarbi, Arabe → beur — un código lingüístico nacido en los barrios populares de París en los años 1970-80.","El verlan no es un fenómeno nuevo: el argot francés del siglo XIX ya invertía sílabas (bonbon → bobonne) — pero su difusión masiva es reciente, gracias al rap y al cine.","Algunas palabras del verlan han entrado en el francés estándar: meuf, beur, keuf son comprendidas por todos los francoparlantes, aunque su uso marca un registro informal."]
},
'e187': {
  fr:["La Chanson de Roland est le plus ancien poème épique français conservé — elle raconte la défaite de l'arrière-garde de Charlemagne à Roncevaux en 778.","Le mot « bonjour » est une contraction de « bon » et « jour » — une formule de souhait (« je te souhaite un bon jour ») devenue salutation.","Avant « bonjour », les Français utilisaient « Dieu vous garde » ou « Dieu vous donne le bonjour » — la version laïque a fini par l'emporter."],
  en:["The Song of Roland is the oldest surviving French epic poem — it recounts the defeat of Charlemagne's rearguard at Roncevaux in 778.","'Bonjour' is a contraction of 'bon' (good) and 'jour' (day) — a well-wishing formula ('I wish you a good day') that became a greeting.","Before 'bonjour', the French used 'Dieu vous garde' (God keep you) — the secular version eventually prevailed."],
    es:["La Chanson de Roland (hacia 1080), el poema épico más antiguo de la literatura francesa, contiene una de las primeras apariciones documentadas de «bonjour» en francés.","La fórmula de saludo ha evolucionado: del «Diex vos saut» (Dios os salve) medieval al «bonjour» moderno, reflejo de la secularización progresiva de la sociedad francesa.","El «bonjour» francés es más que un saludo: no decirlo al entrar en un comercio o al dirigirse a un desconocido se considera una grave falta de educación en Francia."]
},
'e188': {
  fr:["L'alphabet phénicien, ancêtre de presque tous les alphabets modernes, ne contenait que des consonnes — les voyelles ont été ajoutées par les Grecs.","L'alphabet latin original ne comptait que 21 lettres — les lettres J, U et W ont été ajoutées au Moyen Âge.","L'alphabet cyrillique, utilisé en Russie, dérive aussi du grec — il a été créé au IXe siècle par les disciples de Cyrille et Méthode."],
  en:["The Phoenician alphabet, ancestor of nearly all modern alphabets, contained only consonants — vowels were added by the Greeks.","The original Latin alphabet had only 21 letters — J, U, and W were added in the Middle Ages.","The Cyrillic alphabet, used in Russia, also derives from Greek — it was created in the 9th century by disciples of Cyril and Methodius."],
    es:["El alfabeto latino evolucionó desde el fenicio (siglo XI a.C.) pasando por el griego y el etrusco hasta llegar al latín — cada cultura adaptó los signos a los sonidos de su lengua.","El alfabeto fenicio original tenía solo 22 consonantes (sin vocales): los griegos añadieron las vocales, y los etruscos y romanos adaptaron las formas a su fonología.","Hoy, más de 4 000 millones de personas usan el alfabeto latino — es el sistema de escritura más extendido del mundo, usado por lenguas tan diversas como el turco, el swahili y el vietnamita."]
},
'e189': {
  fr:["Quand il est midi à Kaliningrad (ouest), il est déjà 22h au Kamtchatka (est) — les Russes vivent littéralement dans des journées décalées.","Avant la réforme de 2010, la Russie comptait même 9 fuseaux officiels — Medvedev les avait réduits avant que Poutine ne rétablisse les 11 en 2014.","La Russie est si vaste qu'elle couvre plus de 17 millions de km² — plus grande que Pluton en surface."],
  en:["When it's noon in Kaliningrad (west), it's already 10 PM in Kamchatka (east) — Russians literally live in staggered days.","Before a 2010 reform, Russia had even more convoluted time zone rules — Medvedev reduced them before Putin restored 11 in 2014.","Russia is so vast it covers over 17 million km² — larger than Pluto in surface area."],
    es:["Rusia abarca 11 husos horarios: cuando son las 9 de la mañana en Kaliningrado (enclave báltico), son las 8 de la noche en Kamchatka (Pacífico).","Con 17,1 millones de km², Rusia es más grande que Plutón en superficie — un dato que sorprende incluso a los geógrafos.","A pesar de su inmensidad, el 77 % de la población rusa vive en la parte europea, que representa solo el 25 % del territorio — Siberia es mayoritariamente vacía."]
},
'e190': {
  fr:["Le Vatican a sa propre pharmacie, bureau de poste, gare ferroviaire et héliport — tout cela sur 0,44 km².","La Garde suisse pontificale, fondée en 1506, est la plus ancienne armée encore en service au monde — ses uniformes colorés datent de la Renaissance.","Le Vatican possède l'un des taux de criminalité les plus élevés au monde par habitant — principalement des vols à la tire par des touristes."],
  en:["The Vatican has its own pharmacy, post office, railway station, and heliport — all within 0.44 km².","The Pontifical Swiss Guard, founded in 1506, is the oldest army still in service — its colourful uniforms date from the Renaissance.","The Vatican has one of the highest crime rates per capita in the world — mainly pickpocketing by tourists."],
    es:["El Vaticano tiene su propia oficina de correos (más eficiente que la italiana), estación de radio, periódico, ferrocarril (300 m de vías) y fuerza de seguridad (Guardia Suiza).","La Guardia Suiza, fundada en 1506, es el ejército más pequeño del mundo: 135 soldados suizos católicos solteros de entre 19 y 30 años, con su famoso uniforme renacentista.","Los museos del Vaticano reciben 6 millones de visitantes al año — la Capilla Sixtina y las Estancias de Rafael generan una parte significativa de los ingresos del micro-Estado."]
},
'e191': {
  fr:["L'Inde abrite 22 langues officielles et plus de 1 600 dialectes — c'est l'un des pays les plus linguistiquement diversifiés au monde.","La population indienne est très jeune : l'âge médian est d'environ 28 ans, contre 38 aux États-Unis et 47 au Japon.","L'Inde devrait devenir la troisième économie mondiale d'ici 2030, dépassant le Japon et l'Allemagne."],
  en:["India is home to 22 official languages and over 1,600 dialects — one of the most linguistically diverse countries in the world.","India's population is very young: the median age is about 28, compared to 38 in the US and 47 in Japan.","India is expected to become the world's third-largest economy by 2030, overtaking Japan and Germany."],
    es:["India superó a China como país más poblado del mundo en abril de 2023, con más de 1 430 millones de habitantes — y sigue creciendo mientras China decrece.","La demografía india es joven (edad media 28 años, frente a 39 en China), lo que representa un «dividendo demográfico» potencial pero también un desafío de empleo y educación.","India tiene 22 lenguas oficiales reconocidas por la Constitución y más de 1 600 dialectos — una diversidad lingüística sin parangón en el mundo."]
},
'e192': {
  fr:["80 % du territoire des Maldives se trouve à moins d'un mètre au-dessus du niveau de la mer — une montée de 1 mètre submergerait la majeure partie du pays.","Le gouvernement maldivien a tenu une réunion du Cabinet sous l'eau en 2009 pour alerter le monde sur le changement climatique.","Les Maldives envisagent d'acheter des terres en Australie ou en Inde pour reloger leur population si le pays venait à disparaître sous les eaux."],
  en:["80% of the Maldives' territory is less than one metre above sea level — a 1-metre rise would submerge most of the country.","The Maldivian government held an underwater Cabinet meeting in 2009 to alert the world to climate change.","The Maldives has considered buying land in Australia or India to relocate its population if the country disappears beneath the waves."],
    es:["Las Maldivas, con una elevación máxima de 2,4 metros, son el país más vulnerable al cambio climático y a la subida del nivel del mar.","Si el nivel del mar sube 1 metro (escenario posible para 2100), el 80 % de las Maldivas quedaría sumergido — el gobierno ha estudiado la compra de tierras en India o Australia.","Las Maldivas dependen del turismo (28 % del PIB) y de la pesca — ambos sectores están amenazados por el calentamiento oceánico y el blanqueamiento de los corales."]
},
'e193': {
  fr:["La forêt amazonienne couvre 5,5 millions de km² répartis sur 9 pays — le Brésil en possède environ 60 %.","On estime qu'un arbre sur dix dans le monde se trouve en Amazonie — la forêt compte environ 390 milliards d'arbres individuels.","Le fleuve Amazone déverse environ 209 000 m³ d'eau par seconde dans l'océan Atlantique — plus que les sept fleuves suivants combinés."],
  en:["The Amazon rainforest covers 5.5 million km² across 9 countries — Brazil holds about 60%.","An estimated one in ten trees in the world is in the Amazon — the forest contains roughly 390 billion individual trees.","The Amazon River discharges about 209,000 m³ of water per second into the Atlantic — more than the next seven rivers combined."],
    es:["La selva amazónica cubre 5,5 millones de km² (el 40 % de Sudamérica) y produce el 20 % del oxígeno del planeta mediante fotosíntesis.","Alberga el 10 % de todas las especies conocidas: más de 80 000 plantas, 2 500 peces, 1 500 aves y 500 mamíferos — la mayor biodiversidad del planeta.","La deforestación destruye unos 10 000 km² al año (equivalente a un campo de fútbol cada minuto) — si continúa, la Amazonía podría convertirse en sabana en pocas décadas."]
},
'e194': {
  fr:["L'Antarctique est le continent le plus froid, le plus sec, le plus venteux et le plus élevé en moyenne (2 300 m d'altitude).","Il n'y a aucune population permanente en Antarctique — seuls des scientifiques y séjournent, entre 1 000 en hiver et 5 000 en été.","Le Traité sur l'Antarctique de 1959 interdit toute activité militaire et exploitation minière — le continent est dédié à la science et à la paix."],
  en:["Antarctica is the coldest, driest, windiest, and highest continent on average (2,300 m elevation).","There is no permanent population in Antarctica — only scientists stay there, between 1,000 in winter and 5,000 in summer.","The 1959 Antarctic Treaty bans all military activity and mining — the continent is dedicated to science and peace."],
    es:["La Antártida recibe menos de 200 mm de precipitaciones anuales (menos que el Sahara) y sus temperaturas pueden bajar a −89,2 °C — el récord terrestre de frío.","Contiene el 70 % del agua dulce del planeta en forma de hielo: si se derritiera, el nivel del mar subiría unos 60 metros, inundando todas las ciudades costeras.","El Tratado Antártico (1959) dedica el continente a la investigación científica y prohíbe la actividad militar y la explotación minera — una de las mayores conquistas diplomáticas del siglo XX."]
},
'e195': {
  fr:["Des peintures rupestres au Tassili n'Ajjer (Algérie) montrent des nageurs, des troupeaux de bétail et des girafes — preuve d'un Sahara verdoyant.","Le Sahara alterne entre phases humides et arides tous les 20 000 ans environ, en raison des variations de l'axe de rotation terrestre.","Le Sahara est le plus grand désert chaud du monde avec 9,2 millions de km² — mais il est plus petit que l'Antarctique, qui est un désert froid."],
  en:["Rock paintings at Tassili n'Ajjer (Algeria) show swimmers, cattle herds, and giraffes — evidence of a green Sahara.","The Sahara alternates between wet and dry phases roughly every 20,000 years, due to variations in Earth's axial tilt.","The Sahara is the world's largest hot desert at 9.2 million km² — but it's smaller than Antarctica, which is a cold desert."],
    es:["Hace 6 000 años, el Sahara era verde: cubierto de lagos, ríos y praderas donde pastaban hipopótamos, cocodrilos y grandes manadas de herbívoros.","El cambio fue causado por una variación cíclica de la órbita terrestre (ciclos de Milankovitch) que alteró el régimen de lluvias monzónicas — un proceso gradual de unos 1 000 años.","Pinturas rupestres en el Tassili n'Ajjer (Argelia) muestran pastores con rebaños, nadadores y animales acuáticos — testimonio artístico de un Sahara radicalmente diferente."]
},
'e196': {
  fr:["Quand il est 8h à Pékin, il fait encore nuit noire dans la région du Xinjiang à l'extrême ouest — mais les horloges affichent la même heure.","Les habitants du Xinjiang utilisent officieusement une « heure locale » décalée de deux heures par rapport à Pékin.","La Chine a adopté un fuseau unique en 1949 sous Mao Zedong pour unifier le pays — avant, elle en avait cinq."],
  en:["When it's 8 AM in Beijing, it's still pitch dark in Xinjiang in the far west — but the clocks show the same time.","Xinjiang residents unofficially use a 'local time' two hours behind Beijing.","China adopted a single time zone in 1949 under Mao Zedong to unify the country — before that, it had five."],
    es:["China adoptó un único huso horario (UTC+8, hora de Pekín) en 1949, a pesar de que su territorio abarca geográficamente 5 husos — una decisión de unidad nacional.","En la región de Xinjiang, en el extremo occidental, el sol no sale hasta las 10 de la mañana en invierno según la hora oficial — los uigures usan informalmente su propia hora local (UTC+6).","EE.UU. (sin Hawaii ni Alaska) tiene 4 husos horarios, Rusia 11 e India 1 (UTC+5:30) — la política horaria refleja decisiones de unidad, no la geografía."]
},
'e197': {
  fr:["Le Burj Khalifa est si haut qu'il est possible de prendre un ascenseur pendant le ramadan, rompre le jeûne en haut, redescendre et voir le soleil encore levé.","La construction a nécessité 22 millions d'heures-homme et 330 000 m³ de béton — plus de 12 000 ouvriers y travaillaient chaque jour.","Le Burj Khalifa possède le plus haut restaurant (At.Mosphere, 442 m), la plus haute piscine (76e étage) et le plus haut observatoire public du monde."],
  en:["The Burj Khalifa is so tall that during Ramadan, you can ride the elevator, break your fast at the top, descend, and see the sun still up.","Construction required 22 million man-hours and 330,000 m³ of concrete — over 12,000 workers were on site daily.","The Burj Khalifa has the world's highest restaurant (At.Mosphere, 442 m), highest pool (76th floor), and highest public observation deck."],
    es:["La diferencia de temperatura entre la base y la cima del Burj Khalifa puede superar los 10 °C — los residentes de los pisos superiores ven el sol ponerse varios minutos después que los de abajo.","Esto tiene implicaciones durante el Ramadán: los musulmanes de los pisos altos pueden comer unos minutos más tarde que los de los pisos bajos, porque el sol se pone más tarde para ellos.","El Burj Khalifa contiene más de 24 000 paneles de vidrio, 57 ascensores y una piscina en el piso 76 — su sistema de agua requiere bombear 946 000 litros al día."]
},
'e198': {
  fr:["Le Groënland appartient au Danemark mais jouit d'une large autonomie depuis 2009 — il a sa propre langue officielle, le groenlandais.","La calotte glaciaire du Groënland contient assez de glace pour élever le niveau des mers de 7,2 mètres si elle fondait entièrement.","Malgré son nom (« Terre verte »), le Groënland est recouvert à 80 % de glace — Erik le Rouge l'aurait nommé ainsi pour attirer des colons."],
  en:["Greenland belongs to Denmark but has enjoyed broad autonomy since 2009 — it has its own official language, Greenlandic.","Greenland's ice sheet contains enough ice to raise sea levels by 7.2 metres if it melted entirely.","Despite its name ('Green Land'), Greenland is 80% ice-covered — Erik the Red reportedly named it to attract settlers."],
    es:["Groenlandia fue bautizada «Tierra Verde» por Erik el Rojo hacia 985 d.C., probablemente como estrategia de marketing para atraer colonos vikingos a una isla mayoritariamente helada.","El casquete de hielo groenlandés tiene hasta 3 km de espesor y contiene suficiente agua para elevar el nivel del mar 7,4 metros si se derritiera completamente.","Groenlandia es un territorio autónomo de Dinamarca con solo 56 000 habitantes — la mayoría inuit, concentrados en la costa occidental libre de hielo."]
},
'e199': {
  fr:["Le lac Baïkal est aussi le plus ancien lac du monde (25 millions d'années) et le plus profond (1 642 mètres).","Plus de 2 500 espèces animales et végétales vivent dans le Baïkal — dont les deux tiers ne se trouvent nulle part ailleurs sur Terre.","Le nerpa, un phoque d'eau douce unique au monde, vit dans le lac Baïkal — personne ne sait exactement comment il y est arrivé."],
  en:["Lake Baikal is also the world's oldest lake (25 million years) and deepest (1,642 metres).","Over 2,500 animal and plant species live in Baikal — two-thirds of which are found nowhere else on Earth.","The nerpa, a freshwater seal unique in the world, lives in Lake Baikal — nobody knows exactly how it got there."],
    es:["El lago Baikal es el lago más profundo (1 642 m) y más antiguo (25-30 millones de años) del mundo — contiene el 20 % del agua dulce no congelada del planeta.","Alberga más de 2 500 especies animales, de las cuales el 80 % son endémicas (no existen en ningún otro lugar) — incluyendo la foca nerpa, la única foca de agua dulce del mundo.","El lago Baikal se congela cada invierno formando una capa de hielo de 1-2 metros — tan transparente que se puede ver el fondo a través de ella en las zonas poco profundas."]
},
'e200': {
  fr:["Les Maoris polynésiens ont navigué sur des pirogues doubles sur plus de 4 000 km à travers le Pacifique pour atteindre la Nouvelle-Zélande.","La Nouvelle-Zélande n'avait aucun mammifère terrestre avant l'arrivée des Maoris — seuls des oiseaux régnaient, dont le moa géant de 3,6 mètres.","La Nouvelle-Zélande a été le premier pays au monde à accorder le droit de vote aux femmes, en 1893."],
  en:["Polynesian Maori navigated double-hulled canoes over 4,000 km across the Pacific to reach New Zealand.","New Zealand had no land mammals before the Maori arrived — only birds reigned, including the 3.6-metre giant moa.","New Zealand was the first country in the world to grant women the right to vote, in 1893."],
    es:["Los maoríes, pueblo polinesio, llegaron a Nueva Zelanda entre los siglos XIII y XIV en canoas oceánicas de doble casco, navegando miles de kilómetros por el Pacífico.","Encontraron una fauna única que había evolucionado sin mamíferos terrestres: aves gigantes no voladoras como el moa (hasta 3,6 m de alto), que cazaron hasta la extinción.","La cultura maorí tiene un estatus protegido en Nueva Zelanda: el te reo maorí es lengua oficial, y el haka de los All Blacks ha convertido la danza guerrera maorí en un icono global."]
},
'e201': {
  fr:["L'Islande possède tout de même une garde côtière et une unité de maintien de la paix — elle a participé à des missions de l'ONU en Irak et en Afghanistan.","La dernière « guerre » de l'Islande fut la « guerre de la morue » contre le Royaume-Uni dans les années 1970 — une dispute sur les zones de pêche.","L'Islande est régulièrement classée parmi les pays les plus pacifiques du monde selon l'Indice mondial de la paix."],
  en:["Iceland does have a coast guard and a peacekeeping unit — it has participated in UN missions in Iraq and Afghanistan.","Iceland's last 'war' was the 'Cod Wars' against the UK in the 1970s — a dispute over fishing zones.","Iceland is regularly ranked among the most peaceful countries in the world on the Global Peace Index."],
    es:["Islandia disolvió su ejército en 1869 y no ha tenido fuerzas militares desde entonces — su defensa se basa en la OTAN y en su guardia costera.","A pesar de la ausencia de ejército, Islandia tiene una de las tasas de criminalidad más bajas del mundo: la policía rara vez porta armas y los homicidios se cuentan con los dedos de una mano.","Islandia fue la primera democracia moderna en elegir a una mujer como jefa de Estado: Vigdís Finnbogadóttir fue presidenta de 1980 a 1996."]
},
'e202': {
  fr:["La Micronésie, la Mélanésie et la Polynésie forment les trois grandes régions de l'Océanie — chacune avec ses cultures et langues distinctes.","De nombreuses îles du Pacifique sont des atolls coralliens ne dépassant pas 2 mètres d'altitude — menacés par la montée des eaux.","Les navigateurs polynésiens traversaient le Pacifique sans instruments, en lisant les étoiles, les courants et le vol des oiseaux."],
  en:["Micronesia, Melanesia, and Polynesia form the three main regions of Oceania — each with distinct cultures and languages.","Many Pacific islands are coral atolls barely 2 metres above sea level — threatened by rising seas.","Polynesian navigators crossed the Pacific without instruments, reading stars, currents, and bird flight."],
    es:["Oceanía comprende más de 25 000 islas repartidas en tres subregiones: Melanesia, Micronesia y Polinesia — una superficie marina inmensa pero una superficie terrestre mínima.","Los navegantes polinesios colonizaron el Pacífico usando solo las estrellas, las corrientes y el vuelo de los pájaros — una hazaña de navegación que precedió en siglos a los instrumentos europeos.","Muchas islas del Pacífico están amenazadas por la subida del nivel del mar: Tuvalu, Kiribati y las Islas Marshall podrían quedar inhabitables antes de finales de siglo."]
},
'e203': {
  fr:["La muraille a été construite entre 122 et 128 ap. J.-C. pour marquer la frontière nord de l'Empire romain et protéger la province de Bretagne.","Elle comprenait 80 fortins, 16 forts majeurs et un fossé défensif — un système défensif sophistiqué pour l'époque.","Contrairement à la croyance populaire, la muraille ne marquait pas la frontière entre l'Angleterre et l'Écosse — elle se situe entièrement en Angleterre."],
  en:["The wall was built between 122 and 128 AD to mark the northern boundary of the Roman Empire and protect the province of Britannia.","It included 80 milecastles, 16 major forts, and a defensive ditch — a sophisticated defensive system for its time.","Contrary to popular belief, the wall did not mark the England–Scotland border — it lies entirely within England."],
    es:["El muro de Adriano fue construido en 122 d.C. por orden del emperador Adriano para marcar el límite norte del Imperio Romano en Britania.","Tenía 118 km de largo, hasta 5 metros de alto y 3 de ancho, con un fuerte cada 1,5 km y torres de vigilancia intermedias — una infraestructura militar colosal.","El muro no era solo una barrera militar sino una frontera económica y cultural: controlaba el comercio, la inmigración y la recaudación de impuestos."]
},
'e204': {
  fr:["Les fjords norvégiens ont été creusés par des glaciers pendant les ères glaciaires — le Sognefjorden atteint 204 km de long et 1 308 m de profondeur.","Si l'on déployait toutes les côtes norvégiennes en ligne droite, elles feraient plus de deux fois le tour de la Terre.","La Norvège possède environ 50 000 îles le long de ses côtes — la plupart inhabitées."],
  en:["Norwegian fjords were carved by glaciers during the Ice Ages — Sognefjorden reaches 204 km long and 1,308 m deep.","If Norway's entire coastline were stretched in a straight line, it would wrap around the Earth more than twice.","Norway has about 50,000 islands along its coasts — most of them uninhabited."],
    es:["La costa noruega, con sus miles de fiordos, islas y calas, se extiende sobre más de 100 000 km — si se estirara en línea recta, rodearía la Tierra 2,5 veces.","Los fiordos se formaron durante las glaciaciones: glaciares de kilómetros de espesor erosionaron valles profundos en forma de U que el mar inundó al retirarse el hielo.","El fiordo de Sogn, el más largo de Noruega (204 km), alcanza 1 308 metros de profundidad — más que la mayoría de mares del mundo."]
},
'e205': {
  fr:["Le bassin du Congo couvre plus de 2 millions de km² — une surface presque quatre fois la France.","Cette forêt stocke environ 8 % du carbone forestier mondial, ce qui en fait un acteur clé dans la lutte contre le changement climatique.","Le fleuve Congo est le deuxième plus long d'Afrique et le plus profond du monde, atteignant plus de 220 mètres par endroits."],
  en:["The Congo Basin covers over 2 million km² — nearly four times the size of France.","This forest stores about 8% of global forest carbon, making it a key player in the fight against climate change.","The Congo River is Africa's second longest and the world's deepest, reaching over 220 metres in places."],
    es:["La cuenca del Congo cubre 2 millones de km² de selva tropical — la segunda más grande del mundo tras la Amazonía y el mayor sumidero de carbono de África.","A diferencia de la Amazonía, la selva del Congo absorbe más CO₂ del que emite — un servicio ecológico global que las comunidades locales no reciben compensación.","El río Congo es el más profundo del mundo (220 m) y el segundo más caudaloso (41 000 m³/s) — sus rápidos y cataratas impiden la navegación continua entre Kinshasa y Kisangani."]
},
'e206': {
  fr:["Le projet Deltawerken, achevé en 1997, est un réseau de 13 barrages et digues considéré comme l'une des sept merveilles du monde moderne.","Environ 26 % des Pays-Bas se trouvent sous le niveau de la mer — sans les digues, ces zones seraient régulièrement inondées.","Le lac IJssel, le plus grand lac des Pays-Bas, est entièrement artificiel — c'est un ancien bras de mer fermé par la digue de l'Afsluitdijk en 1932."],
  en:["The Deltawerken project, completed in 1997, is a network of 13 dams and dikes considered one of the Seven Modern Wonders of the World.","About 26% of the Netherlands lies below sea level — without dikes, these areas would flood regularly.","The IJsselmeer, the largest lake in the Netherlands, is entirely artificial — a former sea arm closed off by the Afsluitdijk dam in 1932."],
    es:["Los Países Bajos han ganado más de 7 000 km² al mar mediante pólderes (tierras drenadas protegidas por diques) — el 17 % de su superficie actual.","Sin los diques, bombas y exclusas, el 26 % de los Países Bajos estaría bajo el agua — incluyendo el aeropuerto de Schiphol, que se encuentra a 3,4 metros bajo el nivel del mar.","La ingeniería hidráulica holandesa es reconocida mundialmente: el Plan Delta, construido tras la catastrófica inundación de 1953, es una de las Siete Maravillas del Mundo Moderno."]
},
'e207': {
  fr:["Les tours de Shibam sont construites en briques de pisé séchées au soleil — elles sont constamment entretenues car la pluie les érode.","Shibam est inscrite au patrimoine mondial de l'UNESCO depuis 1982 — c'est l'un des plus anciens exemples de planification urbaine verticale.","La ville a été fondée au IIIe siècle, mais les tours actuelles datent du XVIe siècle après la destruction de la ville par une inondation."],
  en:["Shibam's towers are built from sun-dried mud bricks — they require constant maintenance as rain erodes them.","Shibam has been a UNESCO World Heritage Site since 1982 — it's one of the oldest examples of vertical urban planning.","The city was founded in the 3rd century, but the current towers date from the 16th century after the city was destroyed by a flood."],
    es:["Shibam, en el Valle de Hadramaut (Yemen), tiene torres de adobe de hasta 30 metros y 11 pisos, construidas en el siglo XVI — los rascacielos más antiguos del mundo.","Las torres están hechas de ladrillos de barro secados al sol, recubiertos de una capa de cal blanca — un aislamiento térmico natural que mantiene el interior fresco en el desierto.","Shibam fue declarada Patrimonio de la Humanidad por la UNESCO en 1982, pero la guerra civil yemení amenaza su conservación — un tesoro arquitectónico en peligro."]
},
'e208': {
  fr:["La salinité de la mer Morte est d'environ 34 %, soit dix fois plus que l'océan — il est impossible de couler, le corps flotte automatiquement.","Le niveau de la mer Morte baisse d'environ 1 mètre par an en raison de la surexploitation du Jourdain et de l'évaporation intensive.","Des dolines (gouffres) se forment le long des rives à mesure que l'eau se retire, dissolvant les dépôts de sel souterrains — des centaines apparaissent chaque année."],
  en:["The Dead Sea's salinity is about 34%, ten times the ocean's — it's impossible to sink, the body floats automatically.","The Dead Sea level drops about 1 metre per year due to over-exploitation of the Jordan River and intensive evaporation.","Sinkholes form along the shores as the water retreats, dissolving underground salt deposits — hundreds appear each year."],
    es:["El Mar Muerto pierde 1,2 metros de nivel por año debido a la desviación del río Jordán para riego — podría desaparecer completamente antes de 2050 sin intervención.","Su salinidad (34 %) es casi 10 veces la del océano, lo que permite flotar sin esfuerzo — pero también impide toda forma de vida macroscópica (de ahí su nombre).","Un proyecto jordano-israelí propuso conectar el Mar Muerto con el Mar Rojo mediante un canal, pero los impactos ambientales y las tensiones políticas han paralizado la iniciativa."]
},
'e209': {
  fr:["Le réseau de métro de Tokyo transporte plus de 8 millions de passagers par jour — des « pousseurs » professionnels aident à faire entrer les voyageurs aux heures de pointe.","Malgré sa densité, Tokyo est l'une des villes les plus sûres au monde — le taux de criminalité y est extrêmement faible.","Tokyo était autrefois un petit village de pêcheurs appelé Edo — il est devenu la capitale du Japon en 1868 lors de la restauration Meiji."],
  en:["Tokyo's metro system carries over 8 million passengers daily — professional 'pushers' help squeeze commuters in during rush hour.","Despite its density, Tokyo is one of the safest cities in the world — crime rates are extremely low.","Tokyo was once a small fishing village called Edo — it became Japan's capital in 1868 during the Meiji Restoration."],
    es:["Tokio es la mayor área metropolitana del mundo con más de 37 millones de habitantes — más poblada que muchos países, incluyendo Canadá o Perú.","Su sistema de transporte es una maravilla de la logística: los trenes llegan con una puntualidad media de 18 segundos de retraso — y la empresa se disculpa si un tren parte 20 segundos antes.","Tokio se encuentra en una de las zonas sísmicas más activas del mundo: los edificios están diseñados para resistir terremotos de magnitud 7+ y los simulacros son una rutina desde la infancia."]
},
'e210': {
  fr:["Le Protocole de Montréal de 1987 est considéré comme le traité environnemental le plus réussi de l'histoire — ratifié par 198 pays.","L'interdiction des CFC (chlorofluorocarbures) a non seulement sauvé la couche d'ozone mais a aussi ralenti le réchauffement climatique.","Le trou dans la couche d'ozone au-dessus de l'Antarctique a commencé à rétrécir de façon mesurable depuis 2000."],
  en:["The 1987 Montreal Protocol is considered the most successful environmental treaty in history — ratified by 198 countries.","The ban on CFCs (chlorofluorocarbons) not only saved the ozone layer but also slowed climate change.","The ozone hole over Antarctica has been measurably shrinking since 2000."],
    es:["El Protocolo de Montreal (1987), que prohibió los CFC, es considerado el acuerdo medioambiental más exitoso de la historia — la capa de ozono debería recuperarse completamente hacia 2066.","Sin el Protocolo, la radiación UV habría aumentado un 550 % para 2100, causando millones de casos adicionales de cáncer de piel y cataratas.","Este éxito demuestra que la cooperación internacional puede resolver problemas ambientales globales — un precedente esperanzador para la lucha contra el cambio climático."]
},
'e211': {
  fr:["Au début du XXe siècle, un seul cyclone au Bangladesh (1970) a tué plus de 500 000 personnes — aujourd'hui, des cyclones similaires font quelques centaines de victimes grâce aux alertes.","Les satellites météorologiques, les digues et les abris anticycloniques ont transformé la prévention des catastrophes naturelles.","Le Bangladesh a réduit la mortalité liée aux cyclones de 100 fois en 50 ans — un modèle de résilience pour les pays en développement."],
  en:["In the early 20th century, a single cyclone in Bangladesh (1970) killed over 500,000 — today, similar cyclones cause hundreds of deaths thanks to warnings.","Weather satellites, levees, and cyclone shelters have transformed natural disaster prevention.","Bangladesh has reduced cyclone-related mortality 100-fold in 50 years — a resilience model for developing nations."],
    es:["En 1900, las catástrofes naturales mataban a más de 1 millón de personas por década — hoy esa cifra ha caído a menos de 100 000 gracias a la predicción meteorológica y la ingeniería.","Los sistemas de alerta temprana para tsunamis, huracanes y terremotos salvan miles de vidas cada año — la tecnología satelital ha transformado la gestión de desastres.","Bangladesh, que perdió 500 000 personas en el ciclón Bhola (1970), sufrió menos de 200 muertos en el ciclón Amphan (2020) — gracias a refugios, alertas y evacuaciones organizadas."]
},
'e212': {
  fr:["En Afrique subsaharienne, l'espérance de vie est passée de 40 ans en 1960 à plus de 62 ans aujourd'hui — une progression spectaculaire.","Les progrès en vaccination, nutrition infantile et accès à l'eau potable sont les principaux moteurs de cette amélioration.","Le Japon détient l'une des espérances de vie les plus élevées au monde avec plus de 84 ans — la longévité d'Okinawa fascine les chercheurs."],
  en:["In sub-Saharan Africa, life expectancy rose from 40 in 1960 to over 62 today — a spectacular improvement.","Advances in vaccination, child nutrition, and clean water access are the main drivers of this improvement.","Japan has one of the highest life expectancies in the world at over 84 years — Okinawan longevity fascinates researchers."],
    es:["La esperanza de vida mundial ha pasado de 46 años en 1950 a más de 73 años en 2023 — un progreso sin precedentes en la historia de la humanidad.","Los principales factores son la reducción de la mortalidad infantil, los antibióticos, las vacunas, el agua potable, la mejora nutricional y los avances en cirugía.","La brecha entre países ricos y pobres se reduce: la esperanza de vida en África subsahariana pasó de 40 años en 1960 a 62 años en 2023."]
},
'e213': {
  fr:["En 1900, seulement 21 % de la population mondiale savait lire — un siècle plus tard, c'est la grande majorité.","L'UNESCO estime que chaque année supplémentaire de scolarisation augmente les revenus futurs d'un individu de 10 % en moyenne.","La Finlande possède l'un des systèmes éducatifs les plus performants au monde — les enseignants y sont recrutés parmi les meilleurs diplômés."],
  en:["In 1900, only 21% of the world's population could read — a century later, the vast majority can.","UNESCO estimates that each additional year of schooling increases an individual's future earnings by an average of 10%.","Finland has one of the world's best-performing education systems — teachers are recruited from top graduates."],
    es:["En 1820, solo el 12 % de la población mundial sabía leer y escribir — hoy, más del 86 % es alfabetizada, con un crecimiento espectacular en Asia y África.","La alfabetización femenina ha avanzado aún más rápido: pasó del 12 % en 1900 al 83 % en 2022, acercándose a la masculina (90 %).","La UNESCO estima que cada año adicional de escolarización aumenta los ingresos de una persona en un 10 % — la educación es la inversión más rentable para el desarrollo."]
},
'e214': {
  fr:["En 2000, environ 245 millions d'enfants travaillaient dans le monde — ce chiffre est tombé à environ 160 millions en 2020.","La Convention des droits de l'enfant de l'ONU (1989), ratifiée par presque tous les pays, a été un moteur essentiel de ce progrès.","L'Inde a interdit le travail des enfants de moins de 14 ans en 2016, touchant des millions de jeunes dans les secteurs informels."],
  en:["In 2000, about 245 million children worked worldwide — that number fell to about 160 million by 2020.","The UN Convention on the Rights of the Child (1989), ratified by nearly all countries, was a key driver of this progress.","India banned child labour under age 14 in 2016, affecting millions of young people in informal sectors."],
    es:["El número de niños trabajadores en el mundo descendió de 246 millones en 2000 a 160 millones en 2020 — una reducción del 35 % en dos décadas.","Las leyes nacionales, los programas de becas escolares y la presión internacional de organizaciones como la OIT han sido los principales motores de este progreso.","Sin embargo, la pandemia de COVID-19 revirtió parte del avance: se estima que 9 millones de niños adicionales fueron empujados al trabajo infantil entre 2020 y 2022."]
},
'e215': {
  fr:["L'énergie solaire hors réseau (kits solaires domestiques) a transformé l'accès à l'électricité en Afrique subsaharienne et en Asie du Sud.","La baisse du coût des LED a multiplié l'impact : une ampoule LED consomme 75 % d'énergie en moins qu'une ampoule à incandescence.","L'Inde a électrifié ses 600 000 derniers villages en 2018, un exploit logistique sans précédent."],
  en:["Off-grid solar energy (home solar kits) has transformed electricity access in sub-Saharan Africa and South Asia.","The falling cost of LEDs has multiplied the impact: an LED bulb uses 75% less energy than an incandescent bulb.","India electrified its last 600,000 villages in 2018, an unprecedented logistical feat."],
    es:["En el año 2000, 1 600 millones de personas vivían sin electricidad — en 2022, esa cifra bajó a 675 millones gracias a la expansión de las redes eléctricas y la energía solar descentralizada.","Los paneles solares domésticos han electrificado millones de hogares rurales en África y Asia donde extender la red eléctrica convencional era imposible o demasiado caro.","El acceso a la electricidad transforma vidas: permite estudiar de noche, conservar alimentos, acceder a información y desarrollar actividades económicas productivas."]
},
'e216': {
  fr:["La forêt de Fontainebleau, près de Paris, est l'une des plus anciennes forêts protégées au monde — certains de ses chênes ont plus de 500 ans.","Cette augmentation est due à la déprise agricole : les terres abandonnées se reboisent naturellement, surtout en montagne et dans le sud.","La France est le quatrième pays le plus boisé d'Europe, après la Suède, la Finlande et l'Espagne."],
  en:["The forest of Fontainebleau near Paris is one of the oldest protected forests in the world — some oaks are over 500 years old.","This increase is due to agricultural abandonment: deserted farmland naturally reforests, especially in mountains and the south.","France is the fourth most forested country in Europe, after Sweden, Finland, and Spain."],
    es:["Los bosques franceses han pasado de 9 millones de hectáreas en 1830 a más de 17 millones en 2023 — una duplicación en menos de dos siglos.","Esta reforestación se debe al abandono de tierras agrícolas marginales, a las políticas forestales nacionales y a la disminución del uso de leña como combustible principal.","Francia no es un caso aislado: Europa ha ganado un 9 % de superficie forestal desde 1990, aunque la deforestación tropical sigue siendo un problema grave en otras regiones."]
},
'e217': {
  fr:["En 1990, environ 12 millions d'enfants de moins de 5 ans mouraient chaque année — en 2023, ce chiffre est passé sous les 5 millions.","La réhydratation orale, une solution simple d'eau, sel et sucre, a sauvé à elle seule des dizaines de millions d'enfants depuis les années 1980.","Les vaccins contre la rougeole, la pneumonie et la diarrhée ont été les trois interventions les plus efficaces contre la mortalité infantile."],
  en:["In 1990, about 12 million children under 5 died each year — by 2023, that number fell below 5 million.","Oral rehydration therapy, a simple solution of water, salt, and sugar, has single-handedly saved tens of millions of children since the 1980s.","Vaccines against measles, pneumonia, and diarrhea have been the three most effective interventions against child mortality."],
    es:["La mortalidad infantil (menores de 5 años) pasó de 12,6 millones de muertes en 1990 a 4,9 millones en 2022 — millones de vidas salvadas cada año.","Las principales causas de esta mejora son las vacunas, la terapia de rehidratación oral, los mosquiteros tratados con insecticida y la mejora en la nutrición materna.","A pesar del progreso, 13 000 niños menores de 5 años siguen muriendo cada día, principalmente en África subsahariana y Asia del Sur — la mayoría por causas prevenibles."]
},
'e218': {
  fr:["La plus grande aire marine protégée du monde est la réserve marine de Ross en Antarctique — 1,55 million de km², créée en 2016.","Les aires marines protégées permettent aux populations de poissons de se reconstituer — les zones voisines en bénéficient aussi par « effet de débordement ».","L'objectif international est d'atteindre 30 % des océans protégés d'ici 2030 — un engagement pris lors de la COP15 Biodiversité."],
  en:["The world's largest marine protected area is the Ross Sea Reserve in Antarctica — 1.55 million km², created in 2016.","Marine protected areas allow fish populations to recover — neighbouring zones benefit too through a 'spillover effect'.","The international goal is to protect 30% of the oceans by 2030 — a commitment made at the COP15 Biodiversity summit."],
    es:["Las áreas marinas protegidas (AMP) cubren más del 8 % de los océanos en 2023, un progreso significativo hacia el objetivo del 30 % para 2030 fijado por la COP15.","Las AMP bien gestionadas aumentan la biomasa de peces un 446 % de media y benefician a las pesquerías vecinas gracias al efecto de desbordamiento de poblaciones.","La creación del Área Marina Protegida de Ross (Antártida) en 2016, de 1,55 millones de km², fue el mayor acuerdo de conservación marina de la historia."]
},
'e219': {
  fr:["En 2010, un panneau solaire coûtait environ 2 $/watt — en 2023, il coûte moins de 0,20 $/watt, une baisse de 90 % en 13 ans.","La Chine produit plus de 80 % des panneaux solaires mondiaux — sa domination a contribué à faire chuter les prix.","En une heure, le Soleil envoie sur Terre plus d'énergie que l'humanité entière n'en consomme en un an."],
  en:["In 2010, a solar panel cost about $2/watt — by 2023, it costs less than $0.20/watt, a 90% drop in 13 years.","China produces over 80% of the world's solar panels — its dominance has helped drive prices down.","In one hour, the Sun sends more energy to Earth than all of humanity uses in an entire year."],
    es:["El coste de la energía solar fotovoltaica ha caído un 89 % entre 2010 y 2023, convirtiéndola en la fuente de electricidad más barata de la historia en la mayoría de los mercados.","En 2023, la capacidad solar instalada superó los 1 200 GW — equivalente a más de 1 000 reactores nucleares, con un crecimiento anual del 30 %.","La revolución solar demuestra que la transición energética no es solo una necesidad ambiental sino una oportunidad económica: la electricidad limpia es ahora más barata que la fósil."]
},
'e220': {
  fr:["En 1987, il ne restait que 22 condors sauvages et 5 en captivité — tous les survivants ont été capturés pour un programme d'élevage d'urgence.","Les condors de Californie ont une envergure de 2,9 mètres — ce sont les plus grands oiseaux volants d'Amérique du Nord.","Le programme a coûté plus de 35 millions de dollars sur 30 ans — un investissement considérable mais un succès retentissant pour la conservation."],
  en:["In 1987, only 22 wild and 5 captive condors remained — all survivors were captured for an emergency breeding programme.","California condors have a wingspan of 2.9 metres — they are the largest flying birds in North America.","The programme cost over $35 million over 30 years — a significant investment but a resounding conservation success."],
    es:["El programa de recuperación del cóndor de California es una de las historias de conservación más exitosas: de 27 individuos en 1987 a más de 500 en 2023 gracias a la cría en cautividad.","Cada huevo fue incubado artificialmente, cada polluelo alimentado con marionetas con forma de cóndor adulto para evitar la impronta humana.","El cóndor de California tiene una envergadura de 3 metros y puede vivir hasta 60 años — su recuperación demuestra que incluso las especies al borde de la extinción pueden ser salvadas."]
},
'e221': {
  fr:["L'accès à l'eau potable a été reconnu comme un droit fondamental par l'ONU en 2010 — une résolution votée par 122 pays.","Les puits à pompe manuelle et les systèmes de filtration à faible coût ont permis de desservir des millions de foyers ruraux en Afrique et en Asie.","L'UNICEF estime que chaque dollar investi dans l'eau potable en rapporte quatre en économies de santé et productivité."],
  en:["Access to safe drinking water was recognised as a fundamental right by the UN in 2010 — a resolution backed by 122 countries.","Hand-pump wells and low-cost filtration systems have served millions of rural households in Africa and Asia.","UNICEF estimates that every dollar invested in clean water returns four in health savings and productivity."],
    es:["En 1990, solo el 76 % de la población mundial tenía acceso a agua potable mejorada — en 2022, esa cifra superó el 90 %, un progreso que ha salvado millones de vidas.","Las enfermedades transmitidas por el agua (diarrea, cólera, disentería) mataban a más de 3 millones de personas al año en 1990 — hoy esa cifra se ha reducido a menos de 1,5 millones.","La inversión en infraestructuras de agua potable tiene un retorno de 4 a 12 dólares por cada dólar invertido — es una de las intervenciones de salud pública más rentables."]
},
'e222': {
  fr:["En 1980, moins de 30 % de la population mondiale vivait dans un pays démocratique — en 2020, cette proportion dépasse 55 %.","La « troisième vague de démocratisation » (années 1970-90) a vu la chute de dictatures en Amérique latine, en Europe de l'Est et en Asie.","Le Portugal a été le premier pays de cette vague, avec la Révolution des Œillets en 1974 qui a renversé la dictature de Salazar."],
  en:["In 1980, less than 30% of the world's population lived in a democratic country — by 2020, that share exceeds 55%.","The 'third wave of democratisation' (1970s–90s) saw dictatorships fall in Latin America, Eastern Europe, and Asia.","Portugal was the first country in this wave, with the 1974 Carnation Revolution that overthrew Salazar's dictatorship."],
    es:["En 1980, solo el 30 % de la población mundial vivía en democracias liberales — en 2023, esa proporción supera el 55 %, a pesar de retrocesos recientes.","La tercera ola de democratización (1974-presente) transformó el sur de Europa, América Latina, Asia del Este y partes de África — un cambio político sin precedentes.","La democracia no es un estado final sino un proceso continuo: la vigilancia ciudadana, la prensa libre y las instituciones independientes son esenciales para mantenerla."]
},
'e223': {
  fr:["Les statines, découvertes dans les années 1970, ont à elles seules sauvé des millions de vies en réduisant le cholestérol.","L'angioplastie coronarienne par ballonnet, inventée en 1977, permet de déboucher une artère sans chirurgie à cœur ouvert.","Le taux de mortalité par AVC a aussi diminué de 70 % dans les pays développés grâce aux traitements d'urgence et à la prévention de l'hypertension."],
  en:["Statins, discovered in the 1970s, have single-handedly saved millions of lives by lowering cholesterol.","Balloon coronary angioplasty, invented in 1977, allows an artery to be unblocked without open-heart surgery.","Stroke mortality has also fallen by 70% in developed countries thanks to emergency treatments and hypertension prevention."],
    es:["La mortalidad por enfermedades cardiovasculares ha caído más del 50 % en los países desarrollados desde los años 1970 gracias a la prevención, los medicamentos y la cirugía.","Las estatinas, los antihipertensivos, la cirugía de bypass y la angioplastia coronaria han transformado el pronóstico de las enfermedades del corazón.","Los cambios de estilo de vida (reducción del tabaquismo, dieta y ejercicio) han contribuido tanto como los tratamientos médicos — la prevención sigue siendo la mejor medicina."]
},
'e224': {
  fr:["Les causes principales de mortalité maternelle — hémorragies, infections et éclampsie — sont aujourd'hui largement évitables avec des soins basiques.","Le nombre de sages-femmes formées dans le monde a augmenté de 60 % depuis 2000, surtout en Afrique subsaharienne et en Asie du Sud.","Le Sri Lanka a réussi à réduire sa mortalité maternelle de 90 % en 50 ans uniquement en investissant dans les soins de santé primaires."],
  en:["The main causes of maternal death — haemorrhage, infection, and eclampsia — are now largely preventable with basic care.","The number of trained midwives worldwide has increased by 60% since 2000, especially in sub-Saharan Africa and South Asia.","Sri Lanka cut its maternal mortality by 90% in 50 years solely by investing in primary healthcare."],
    es:["La mortalidad materna mundial cayó de 385 muertes por 100 000 nacimientos en 2000 a 223 en 2020 — gracias a la atención prenatal, los partos asistidos y el acceso a cesáreas de urgencia.","En los países más afectados (África subsahariana), una mujer tiene 1 probabilidad entre 37 de morir por causas relacionadas con el embarazo — frente a 1 entre 7 800 en Europa.","La formación de matronas y el acceso a centros de salud rurales son las intervenciones más eficaces para reducir la mortalidad materna en países en desarrollo."]
},
'e225': {
  fr:["L'éolien et le solaire combinés ont produit plus d'électricité que le nucléaire pour la première fois en 2021.","Le Danemark a atteint 80 % d'électricité renouvelable en 2023 — principalement grâce à l'éolien offshore en mer du Nord.","Le Costa Rica fonctionne avec plus de 98 % d'électricité renouvelable depuis plusieurs années — grâce à l'hydroélectricité et la géothermie."],
  en:["Wind and solar combined produced more electricity than nuclear for the first time in 2021.","Denmark reached 80% renewable electricity in 2023 — mainly thanks to offshore wind in the North Sea.","Costa Rica has run on over 98% renewable electricity for several years — thanks to hydropower and geothermal energy."],
    es:["En 2023, las energías renovables generaron más del 30 % de la electricidad mundial — la eólica y la solar representaron el 12 %, con un crecimiento récord del 50 % en capacidad instalada.","China lidera la transición renovable: instala más paneles solares al año que el resto del mundo combinado, y su capacidad eólica es la mayor del planeta.","El objetivo del Acuerdo de París (limitar el calentamiento a 1,5 °C) requiere alcanzar el 60-70 % de electricidad renovable para 2030 — ambicioso pero técnicamente posible."]
},
'e226': {
  fr:["Le nombre de morts au combat dans le monde a chuté de 90 % entre les années 1950 et les années 2010, selon l'Université d'Uppsala.","Les missions de maintien de la paix de l'ONU, malgré leurs limites, ont contribué à réduire la reprise des conflits de 50 %.","Le commerce international croissant entre nations est considéré comme l'un des facteurs réduisant les risques de conflits armés entre elles."],
  en:["The number of battle deaths worldwide fell by 90% between the 1950s and 2010s, according to Uppsala University.","UN peacekeeping missions, despite their limitations, have helped reduce conflict recurrence by 50%.","Growing international trade between nations is considered one of the factors reducing the risk of armed conflict between them."],
    es:["El número de muertes en conflictos armados ha disminuido significativamente desde los años 1950: la Segunda Guerra Mundial mató a 70 millones, los conflictos actuales matan menos de 200 000 al año.","Steven Pinker argumenta en Los ángeles que llevamos dentro que la violencia per cápita ha disminuido a lo largo de la historia — una tendencia contraintuitiva pero respaldada por datos.","Las operaciones de mantenimiento de paz de la ONU, la diplomacia multilateral y la interdependencia económica son factores que contribuyen a esta reducción."]
},
'e227': {
  fr:["La Chine a sorti plus de 800 millions de personnes de l'extrême pauvreté entre 1981 et 2015 — la plus grande réduction de pauvreté de l'histoire.","La « Révolution verte » des années 1960-70, avec ses variétés de blé et de riz à haut rendement, a sauvé un milliard de personnes de la famine.","Norman Borlaug, père de la Révolution verte, a reçu le Prix Nobel de la paix en 1970 pour avoir nourri le monde."],
  en:["China lifted over 800 million people out of extreme poverty between 1981 and 2015 — the largest poverty reduction in history.","The 'Green Revolution' of the 1960s–70s, with high-yield wheat and rice varieties, saved a billion people from famine.","Norman Borlaug, father of the Green Revolution, received the 1970 Nobel Peace Prize for feeding the world."],
    es:["El porcentaje de personas que sufren hambre extrema en el mundo pasó del 19 % en 1990 al 9,2 % en 2023 — una reducción que ha salvado a cientos de millones de personas.","China sacó a más de 800 millones de personas de la pobreza extrema entre 1978 y 2020 — la mayor reducción de pobreza de la historia, impulsada por la reforma económica.","A pesar del progreso, 735 millones de personas siguen pasando hambre — la guerra, el cambio climático y la desigualdad son los principales obstáculos para erradicar el hambre."]
},
'e228': {
  fr:["Les filles ont rattrapé les garçons en termes de scolarisation dans la plupart des régions du monde — un changement historique en une génération.","L'Éthiopie a triplé son taux de scolarisation primaire entre 2000 et 2015, passant de 35 % à plus de 95 %.","L'éducation des filles est considérée par les économistes comme l'investissement ayant le meilleur retour au monde — chaque année supplémentaire réduit la mortalité infantile de 5 à 10 %."],
  en:["Girls have caught up with boys in school enrolment in most regions of the world — a historic shift in one generation.","Ethiopia tripled its primary school enrolment between 2000 and 2015, from 35% to over 95%.","Girls' education is considered by economists as the best-return investment in the world — each extra year reduces child mortality by 5–10%."],
    es:["En 1950, la media mundial de escolarización era de 4 años — en 2023 supera los 8 años, con muchos países alcanzando los 12-13 años de educación media.","La expansión de la educación primaria universal es uno de los mayores logros del siglo XX: hoy, el 90 % de los niños del mundo completan la educación primaria.","La educación de las niñas tiene un efecto multiplicador: cada año adicional reduce la mortalidad infantil un 5-10 % y aumenta los ingresos futuros un 10-20 %."]
},
'e229': {
  fr:["En 1988, la polio paralysait 350 000 enfants par an dans 125 pays — en 2023, moins de 15 cas ont été signalés dans le monde.","Le vaccin oral de Sabin (OPV) a été l'outil clé : une goutte sur un sucre, facile à administrer même dans les zones reculées.","Le Pakistan et l'Afghanistan sont les deux derniers pays où la polio reste endémique — les campagnes de vaccination y font face à des défis sécuritaires."],
  en:["In 1988, polio paralysed 350,000 children a year in 125 countries — in 2023, fewer than 15 cases were reported worldwide.","Sabin's oral vaccine (OPV) was the key tool: a drop on a sugar cube, easy to administer even in remote areas.","Pakistan and Afghanistan are the last two countries where polio remains endemic — vaccination campaigns face security challenges there."],
    es:["En 1988, se registraron 350 000 casos de polio al año en 125 países — en 2023, solo hubo 12 casos en 2 países (Pakistán y Afganistán).","La polio es una de las enfermedades a punto de ser erradicadas gracias a la vacunación masiva liderada por la OMS, UNICEF, Rotary International y la Fundación Gates.","La erradicación total se enfrenta a obstáculos logísticos (zonas de conflicto) y culturales (desconfianza hacia las vacunas) — pero el objetivo está al alcance."]
},
'e230': {
  fr:["Les mangroves absorbent les vagues comme un amortisseur naturel — elles peuvent réduire la hauteur d'un tsunami de 70 % sur quelques centaines de mètres.","Un hectare de mangrove stocke jusqu'à 1 000 tonnes de carbone — quatre fois plus qu'un hectare de forêt tropicale terrestre.","L'Indonésie, le Brésil et le Sénégal font partie des pays leaders en restauration de mangroves, avec des millions d'arbres plantés ces dernières années."],
  en:["Mangroves absorb waves like a natural shock absorber — they can reduce tsunami height by 70% over a few hundred metres.","One hectare of mangrove stores up to 1,000 tonnes of carbon — four times more than a hectare of tropical forest on land.","Indonesia, Brazil, and Senegal are among the leaders in mangrove restoration, with millions of trees planted in recent years."],
    es:["Las mangroves protegen a más de 100 millones de personas de tormentas y tsunamis, y almacenan hasta 10 veces más carbono por hectárea que los bosques terrestres.","Los programas de restauración de manglares han replantado miles de hectáreas en Indonesia, Bangladesh, Kenia y México — con resultados positivos para la pesca y la protección costera.","Cada dólar invertido en restauración de manglares genera entre 3 y 10 dólares en beneficios económicos — una de las inversiones ambientales más rentables."]
},
'e231': {
  fr:["Le « médicament » au ketchup de 1834 était vendu en pilules par le Dr John Cook Bennett, qui vantait les bienfaits de la tomate.","Le ketchup actuel contient environ 4 g de sucre par cuillère à soupe — il est devenu un condiment, pas un remède.","Avant la tomate, le ketchup était fait à base de champignons, de noix ou de poisson — les premières recettes anglaises datent du XVIIe siècle."],
  en:["The 1834 ketchup 'medicine' was sold in pill form by Dr John Cook Bennett, who touted the benefits of tomatoes.","Modern ketchup contains about 4 g of sugar per tablespoon — it's become a condiment, not a remedy.","Before tomatoes, ketchup was made from mushrooms, walnuts, or fish — the earliest English recipes date from the 17th century."],
    es:["El ketchup fue patentado como medicamento en 1834 por el Dr. John Cook Bennett de Ohio, que lo recetaba en forma de pastillas para tratar la diarrea, la indigestión y la ictericia.","Las «pastillas de tomate» del Dr. Bennett fueron un éxito comercial efímero — cuando imitadores empezaron a vender pastillas fraudulentas, el producto cayó en descrédito.","El ketchup moderno (Heinz, 1876) añadió vinagre y azúcar al tomate — hoy se consumen más de 650 millones de botellas al año solo en EE.UU."]
},
'e232': {
  fr:["Environ 1 personne sur 1 000 peut réellement se lécher le coude — une particularité liée à l'hypermobilité articulaire.","L'articulation du coude humain ne peut se plier que dans un sens — contrairement aux oiseaux dont les ailes se replient dans plusieurs directions.","Le nerf cubital, qui passe près du coude, est responsable de la sensation électrique quand on se cogne le « petit juif » — il est le nerf le moins protégé du corps."],
  en:["About 1 in 1,000 people can actually lick their elbow — a trait linked to joint hypermobility.","The human elbow joint only bends one way — unlike bird wings, which fold in multiple directions.","The ulnar nerve near the elbow causes that electric feeling when you hit your 'funny bone' — it's the least protected nerve in the body."],
    es:["Es anatómicamente imposible lamerse el codo para la mayoría de las personas porque la articulación del codo no permite la rotación necesaria del antebrazo para acercar la lengua.","Sin embargo, una pequeña minoría de personas con hipermovilidad articular (hiperlaxitud) puede lograrlo — los contorsionistas de circo lo demuestran regularmente.","Este dato es un ejemplo perfecto de «información inútil irresistible»: al oírlo, casi todo el mundo intenta hacerlo — un impulso automático que la psicología llama «reactancia»."]
},
'e233': {
  fr:["Le cœur systémique des pieuvres pompe le sang vers le corps, tandis que les deux cœurs branchiaux l'envoient aux branchies pour l'oxygéner.","Chaque « mini-cerveau » dans les tentacules peut agir de façon semi-autonome — un bras coupé continue de réagir aux stimuli pendant des heures.","Les pieuvres ont environ 500 millions de neurones — autant qu'un chien — ce qui en fait les invertébrés les plus intelligents."],
  en:["The systemic heart pumps blood to the body, while the two branchial hearts send it to the gills for oxygenation.","Each 'mini-brain' in the tentacles can act semi-autonomously — a severed arm continues reacting to stimuli for hours.","Octopuses have about 500 million neurons — as many as a dog — making them the most intelligent invertebrates."],
    es:["Los pulpos son los invertebrados más inteligentes: abren tarros, resuelven laberintos, reconocen rostros humanos, usan herramientas y se han fugado de acuarios.","Su sangre azul (basada en hemocianina de cobre) transporta el oxígeno menos eficientemente que la hemoglobina, lo que explica la necesidad de tres corazones.","Cada uno de los 8 tentáculos tiene su propio ganglio nervioso (mini-cerebro) que puede actuar de forma semi-independiente — un sistema nervioso distribuido único en el reino animal."]
},
'e234': {
  fr:["Les fourmis coupeuses de feuilles cultivent des champignons dans des jardins souterrains — elles pratiquent l'agriculture depuis 60 millions d'années, bien avant les humains.","La biomasse totale des fourmis sur Terre est estimée à environ 80 millions de tonnes — comparable à celle de tous les humains.","Certaines fourmis peuvent survivre sous l'eau pendant 14 jours en entrant dans un état de quasi-dormance."],
  en:["Leafcutter ants cultivate fungi in underground gardens — they've been farming for 60 million years, long before humans.","The total biomass of ants on Earth is estimated at about 80 million tonnes — comparable to that of all humans.","Some ants can survive underwater for 14 days by entering a near-dormant state."],
    es:["Las hormigas cortadoras de hojas (Atta) cultivaban hongos como alimento hace 50 millones de años — la agricultura más antigua del planeta, 45 millones de años antes que la humana.","Una hormiga soldado puede cargar 50 veces su peso porque su exoesqueleto de quitina es proporcionalmente mucho más resistente que los huesos humanos.","La biomasa total de las hormigas del planeta supera los 80 millones de toneladas — comparable a la biomasa total de los humanos (unos 60 millones de toneladas de carbono seco)."]
},
'e235': {
  fr:["Les gènes partagés avec la banane concernent principalement les fonctions cellulaires de base : division, réparation d'ADN et métabolisme énergétique.","Nous partageons aussi 70 % de nos gènes avec le poisson-zèbre et 85 % avec la souris — la vie partage un socle génétique commun.","Le génome de la banane Cavendish est presque identique d'un plant à l'autre car elle est reproduite par clonage — ce qui la rend vulnérable aux maladies."],
  en:["The genes shared with bananas mostly involve basic cell functions: division, DNA repair, and energy metabolism.","We also share 70% of our genes with zebrafish and 85% with mice — life shares a common genetic foundation.","The Cavendish banana genome is nearly identical from plant to plant because it's reproduced by cloning — making it vulnerable to disease."],
    es:["Los humanos comparten el 60 % de su ADN con las bananas, el 85 % con los ratones, el 96 % con los chimpancés y el 99,9 % con otros humanos.","Esta similitud genética refleja un origen evolutivo común: todos los seres vivos descienden del mismo ancestro unicelular que vivió hace unos 3 800 millones de años.","La mayoría de los genes compartidos con las bananas son los que codifican las funciones celulares básicas: replicación del ADN, producción de proteínas y metabolismo energético."]
},
'e236': {
  fr:["La couleur rose des flamants vient de leur alimentation en crevettes et algues riches en caroténoïdes — sans ce régime, ils deviennent blancs.","Les flamants filtrent leur nourriture la tête en bas, à l'envers dans l'eau — leur bec est spécialement conçu pour cette posture.","Les flamants peuvent dormir debout sur une seule patte — des études montrent que cette posture nécessite en fait moins d'énergie musculaire que deux pattes."],
  en:["Flamingos' pink colour comes from their diet of shrimp and algae rich in carotenoids — without it, they turn white.","Flamingos filter-feed with their heads upside down in water — their beaks are specially designed for this posture.","Flamingos can sleep standing on one leg — studies show this posture actually requires less muscular energy than two legs."],
    es:["Los nombres colectivos de animales en inglés son a menudo poéticos: un «murder» de cuervos, un «parliament» de búhos, un «tower» de jirafas, un «crash» de rinocerontes.","Estos términos vienen en su mayoría del Book of Saint Albans (1486), un manual de caza escrito por una priora inglesa — muchos fueron inventados por diversión, no por uso real.","La «flamboyance» de flamencos es especialmente apropiada: su nombre ya viene de «flama» (llama) por su color rojizo intenso."]
},
'e237': {
  fr:["Les pieuvres ciblaient spécifiquement certains individus, suggérant que ce comportement n'est pas aléatoire mais social et peut-être émotionnel.","Cette découverte a été faite en 2022 par des chercheurs de l'Université de Sydney observant des pieuvres sombres (Octopus tetricus) en Australie.","Les projectiles utilisés incluaient des coquillages, du sable et des algues — projetés grâce à un jet d'eau dirigé par le siphon."],
  en:["Octopuses targeted specific individuals, suggesting the behaviour is not random but social and possibly emotional.","This discovery was made in 2022 by University of Sydney researchers observing gloomy octopuses (Octopus tetricus) in Australia.","Projectiles included shells, sand, and algae — launched via a water jet directed through the siphon."],
    es:["Investigadores australianos filmaron en 2022 a pulpos lanzando conchas, algas y lodo a otros pulpos que les molestaban — un comportamiento social agresivo raro en invertebrados.","Los lanzamientos eran dirigidos (no aleatorios) y más frecuentes hacia individuos específicos — evidencia de conflictos sociales intencionales.","Los pulpos viven generalmente en solitario, lo que hace estos comportamientos sociales aún más sorprendentes — su inteligencia social podría ser mayor de lo que se creía."]
},
'e238': {
  fr:["Le mythe du « coin-coin sans écho » a circulé pendant des décennies — il a été réfuté par Trevor Cox de l'Université de Salford en 2003.","L'écho du canard est simplement très faible et se confond avec le son original — c'est pourquoi il passe inaperçu.","Les canards colverts femelles sont plus bruyantes que les mâles — le « coin-coin » classique est principalement émis par la femelle."],
  en:["The 'quack with no echo' myth circulated for decades — it was debunked by Trevor Cox at the University of Salford in 2003.","The duck's echo is simply very faint and blends with the original sound — which is why it goes unnoticed.","Female mallard ducks are louder than males — the classic 'quack' is mainly produced by the female."],
    es:["El mito de que el graznido del pato no produce eco fue desmentido por investigadores de la Universidad de Salford en 2003 — el eco existe pero es difícil de distinguir del sonido original.","El graznido del pato tiene una forma de onda que se confunde con su propio eco, creando la ilusión de que no resuena — un efecto acústico fascinante pero no misterioso.","Este es un ejemplo perfecto de cómo un mito urbano puede persistir durante décadas simplemente porque nadie se molesta en verificarlo experimentalmente."]
},
'e239': {
  fr:["La soie d'araignée est cinq fois plus résistante que l'acier à poids égal et plus élastique que le nylon.","Si l'on pouvait fabriquer un câble en soie d'araignée du diamètre d'un crayon, il pourrait arrêter un Boeing 747 en vol.","Les chercheurs tentent de produire de la soie d'araignée synthétique pour des applications médicales, militaires et textiles — sans succès à grande échelle pour l'instant."],
  en:["Spider silk is five times stronger than steel by weight and more elastic than nylon.","If you could make a spider silk cable the diameter of a pencil, it could stop a Boeing 747 in flight.","Researchers are trying to produce synthetic spider silk for medical, military, and textile applications — without large-scale success so far."],
    es:["Las arañas producen colectivamente una cantidad de seda que, si se pesara, superaría el peso total de todos los seres humanos del planeta.","La seda de araña es, peso por peso, cinco veces más resistente que el acero y más elástica que el nailon — un material que la ingeniería intenta replicar desde hace décadas.","Las arañas reciclan su propia seda comiéndola cuando ya no la necesitan: las proteínas se reutilizan para producir nuevos hilos — un sistema de reciclaje perfecto."]
},
'e240': {
  fr:["Le « ploc » d'une bouteille de champagne est produit par la libération soudaine du CO₂ sous pression — environ 6 atmosphères dans la bouteille.","Le bouchon d'une bouteille de champagne peut être éjecté à plus de 50 km/h — assez pour causer des blessures oculaires graves.","La forme idéale du verre à champagne est la flûte allongée : elle préserve les bulles plus longtemps en réduisant la surface d'exposition à l'air."],
  en:["A champagne bottle's 'pop' is produced by the sudden release of CO₂ under pressure — about 6 atmospheres inside the bottle.","A champagne cork can be ejected at over 50 km/h — fast enough to cause serious eye injuries.","The ideal champagne glass shape is the elongated flute: it preserves bubbles longer by reducing the surface exposed to air."],
    es:["Investigadores de la Universidad de Cambridge analizaron el sonido del descorche y determinaron que la frecuencia ideal del «ploc» perfecto es de 8-12 kHz con un pico de 10 kHz.","El sonido depende de la presión del gas, la velocidad de extracción del corcho, el diámetro del cuello de la botella y la elasticidad del corcho.","El champán produce un sonido diferente al vino tranquilo porque la presión interna (6 atm) expulsa el corcho, mientras que en el vino tranquilo es la fuerza manual la que lo extrae."]
},
'e241': {
  fr:["Dans la mythologie celtique, la licorne représentait un adversaire digne du lion anglais — d'où la présence des deux animaux sur les armoiries royales britanniques.","La licorne figure sur les armoiries royales d'Écosse depuis au moins le XIIe siècle, enchaînée car les légendes disaient qu'elle était dangereuse si elle était libre.","Le mythe de la licorne remonte à l'Antiquité grecque — Ctésias de Cnide décrivait en 400 av. J.-C. un âne sauvage avec une corne unique."],
  en:["In Celtic mythology, the unicorn represented a worthy adversary to the English lion — hence both animals on the British royal coat of arms.","The unicorn has appeared on Scotland's royal arms since at least the 12th century, chained because legends said it was dangerous if free.","The unicorn myth dates back to ancient Greece — Ctesias of Cnidus described a wild donkey with a single horn around 400 BC."],
    es:["El unicornio es el animal heráldico oficial de Escocia desde al menos el siglo XII — en la mitología escocesa, era el enemigo natural del león, símbolo de Inglaterra.","Cuando Escocia e Inglaterra se unieron bajo la corona de Jacobo VI/I en 1603, el escudo real combinó el león inglés y el unicornio escocés — el unicornio está encadenado, simbolizando su domesticación.","La elección del unicornio tiene raíces celtas: en la tradición gaélica, el unicornio representaba la pureza, la inocencia y el poder indomable — cualidades que los escoceses apreciaban."]
},
'e242': {
  fr:["Chaque dauphin développe un sifflement unique dans les premiers mois de sa vie — un véritable « nom » qu'il garde toute sa vie.","Les dauphins utilisent le sifflement d'un autre pour l'appeler — l'équivalent de crier le prénom de quelqu'un dans une foule.","Des chercheurs ont montré que les dauphins se souviennent du sifflement d'un ancien compagnon même après 20 ans de séparation."],
  en:["Each dolphin develops a unique whistle in the first months of life — a true 'name' it keeps for life.","Dolphins use another's whistle to call them — the equivalent of shouting someone's name in a crowd.","Researchers showed that dolphins remember a former companion's whistle even after 20 years apart."],
    es:["Cada delfín desarrolla un silbido firma (signature whistle) único durante su primer año de vida, que funciona como un nombre propio — otros delfines lo usan para llamarlo.","Los delfines pueden recordar el silbido firma de un compañero durante al menos 20 años — una de las memorias sociales más largas del reino animal fuera de los humanos.","Esta capacidad de nombrar individuos es extremadamente rara: solo se ha documentado en delfines, loros y posiblemente elefantes — sugiere un nivel de conciencia social avanzado."]
},
'e243': {
  fr:["De nombreuses espèces ont été nommées d'après des célébrités : il existe aussi un coléoptère nommé d'après Beyoncé (Scaptia beyonceae) grâce à son abdomen doré.","La tradition de nommer des espèces d'après des personnalités permet d'attirer l'attention du public sur la biodiversité.","David Bowie a un genre d'araignée à son nom (Heteropoda davidbowie), décrit en 2008 en Malaisie."],
  en:["Many species are named after celebrities: there's also a beetle named after Beyoncé (Scaptia beyonceae) thanks to its golden abdomen.","The tradition of naming species after public figures helps draw attention to biodiversity.","David Bowie has a spider genus named after him (Heteropoda davidbowie), described in 2008 in Malaysia."],
    es:["La araña Lennoniella fue bautizada en honor a John Lennon por el aracnólogo brasileño Antonio Brescovit — se une a cientos de especies nombradas en honor a músicos y celebridades.","Otras especies con nombres de famosos incluyen Beyoncé (una mosca dorada), Obama (un lagarto y un parásito), y Gaga (un helecho) — nombrar especies es una tradición científica lúdica.","La taxonomía permite a los descubridores elegir el nombre: algunos lo usan para honrar mentores, otros para atraer atención mediática hacia especies desconocidas."]
},
'e244': {
  fr:["Les corvidés (corbeaux, corneilles, pies) sont considérés comme les oiseaux les plus intelligents — certains fabriquent des outils.","Des corneilles ont aussi été filmées faisant du luge sur des toits enneigés avec des couvercles de plastique — un jeu manifestement récréatif.","Le jeu chez les animaux est un indicateur d'intelligence sociale : il développe les compétences de résolution de problèmes et renforce les liens sociaux."],
  en:["Corvids (crows, ravens, magpies) are considered the smartest birds — some make tools.","Crows have also been filmed sledding down snowy rooftops on plastic lids — a clearly recreational game.","Play in animals is a marker of social intelligence: it develops problem-solving skills and strengthens social bonds."],
    es:["Las cornejas y los cuervos han sido filmados deslizándose repetidamente por tejados nevados usando objetos como trineos improvisados — un comportamiento que solo se explica por diversión.","El juego en los animales es un indicador de inteligencia: requiere creatividad, planificación y la capacidad de hacer algo sin beneficio inmediato de supervivencia.","Los córvidos también juegan a soltar objetos en el aire y atraparlos, a balancearse de ramas y a provocar a otros animales (incluidos perros y gatos) por pura diversión."]
},
'e245': {
  fr:["Le flehmen expose l'organe de Jacobson, situé dans le palais, aux phéromones et molécules odorantes — il analyse la chimie de l'air.","Les chevaux ne sont pas les seuls : les chats, les girafes, les éléphants et les rhinocéros pratiquent aussi le flehmen.","Chez le cheval, le flehmen sert souvent à détecter si une jument est en chaleur — c'est un outil de communication sexuelle."],
  en:["The flehmen response exposes the Jacobson's organ in the palate to pheromones and scent molecules — it analyses the air's chemistry.","Horses aren't the only ones: cats, giraffes, elephants, and rhinos also perform the flehmen response.","In horses, flehmen often serves to detect whether a mare is in heat — it's a tool for sexual communication."],
    es:["El flehmen es una respuesta a los olores que activa el órgano vomeronasal del paladar: el caballo retrousse les lèvres para analizar feromonas, no para sonreír.","Muchos mamíferos practican el flehmen: gatos, caballos, cabras, jirafas y felinos salvajes — cada especie tiene su propia expresión característica.","El órgano vomeronasal humano existe pero es vestigial: los científicos debaten si sigue siendo funcional o si es un remanente evolutivo sin utilidad."]
},
'e246': {
  fr:["Le nom « Lego » vient du danois « leg godt », qui signifie « joue bien » — Ole Kirk ne savait pas que le mot signifie aussi « j'assemble » en latin.","Il se fabrique environ 36 milliards de briques Lego par an — soit environ 1 140 par seconde.","Si l'on empilait toutes les briques Lego jamais fabriquées, la pile atteindrait la Lune plus de 10 fois."],
  en:["The name 'Lego' comes from Danish 'leg godt', meaning 'play well' — Ole Kirk didn't know the word also means 'I assemble' in Latin.","About 36 billion Lego bricks are made per year — roughly 1,140 every second.","If you stacked all Lego bricks ever made, the pile would reach the Moon over 10 times."],
    es:["LEGO fue fundada en 1932 por Ole Kirk Christiansen en Billund (Dinamarca) — el nombre viene del danés «leg godt» (juega bien).","Hoy, LEGO es el mayor fabricante de neumáticos del mundo (en miniatura): produce más de 300 millones de pequeños neumáticos de goma cada año para sus vehículos.","Hay más de 400 000 millones de ladrillos LEGO en el mundo — unas 62 piezas por cada habitante del planeta. Seis ladrillos de 2×4 pueden combinarse de 915 millones de maneras."]
},
'e247': {
  fr:["D'autres noms collectifs d'animaux élégants : un « parlement » de hiboux, un « flamboiement » de flamants, et un « meurtre » de corbeaux.","Le mot « kindle » pour un groupe de chatons vient du moyen anglais « kindelen » signifiant « mettre bas ».","Les chats domestiques sont des animaux semi-sociaux : contrairement à la croyance, ils peuvent former des groupes stables avec des hiérarchies complexes."],
  en:["Other elegant collective animal nouns: a 'parliament' of owls, a 'flamboyance' of flamingos, and a 'murder' of crows.","The word 'kindle' for a group of kittens comes from Middle English 'kindelen', meaning 'to give birth'.","Domestic cats are semi-social animals: contrary to belief, they can form stable groups with complex hierarchies."],
    es:["En inglés, un grupo de gatos es un «clowder» (del inglés antiguo «clodder», ovillo), un grupo de gatitos un «kindle» y un grupo de gatos salvajes un «destruction».","Los nombres colectivos de animales son una peculiaridad del inglés medieval: muchos fueron inventados como juegos de palabras por la nobleza en libros de caza y etiqueta.","El gato doméstico se domesticó hace unos 10 000 años en el Creciente Fértil — pero a diferencia del perro, el gato se «autodomesticó» acercándose a los graneros humanos para cazar ratones."]
},
'e248': {
  fr:["Chez les manchots Adélie, les galets sont une ressource limitée — leur rareté crée une véritable économie avec vol, échange et séduction.","Des chercheurs ont observé des femelles manchots Adélie offrant des faveurs sexuelles en échange de galets — un exemple rare de « prostitution animale ».","Les manchots empereurs, eux, ne font pas de nid — ils couvent leur œuf unique sur leurs pattes pendant 65 jours dans le froid antarctique."],
  en:["Among Adélie penguins, pebbles are a limited resource — their scarcity creates a real economy of theft, trade, and courtship.","Researchers observed female Adélie penguins offering sexual favours in exchange for pebbles — a rare example of 'animal prostitution'.","Emperor penguins don't build nests — they incubate their single egg on their feet for 65 days in Antarctic cold."],
    es:["Los pingüinos emperador y Adélie ofrecen guijarros como parte del cortejo: un guijarro perfecto (liso, redondeado, del tamaño adecuado) puede ser la diferencia entre el rechazo y la aceptación.","Los guijarros tienen también una función práctica: elevan el nido por encima del agua de deshielo para proteger los huevos — un mal nido significa huevos ahogados.","Los robos de guijarros entre pingüinos son frecuentes y generan peleas ruidosas en la colonia — la propiedad privada es un concepto que incluso los pingüinos defienden."]
},
'e249': {
  fr:["George Nissen et Larry Griswold ont construit le premier prototype dans un garage avec du fer, de la toile et des chambres à air de pneu.","Le mot « trampoline » vient de l'espagnol « trampolín » (plongeoir) — Nissen l'a entendu lors d'une démonstration au Mexique.","Le trampoline est devenu un sport olympique en 2000 aux Jeux de Sydney — la Chine et la Russie dominent la discipline."],
  en:["George Nissen and Larry Griswold built the first prototype in a garage using iron, canvas, and tyre inner tubes.","The word 'trampoline' comes from Spanish 'trampolín' (diving board) — Nissen heard it during a demonstration in Mexico.","Trampolining became an Olympic sport in 2000 at the Sydney Games — China and Russia dominate the discipline."],
    es:["George Nissen y Larry Griswold inventaron la cama elástica moderna en 1934 inspirándose en las redes de seguridad del trapecio — el nombre «trampoline» viene del español «trampolín».","Nissen viajó por el mundo haciendo demostraciones con un canguro saltando sobre su trampolín — una estrategia de marketing memorable que popularizó el invento.","El trampolín se convirtió en deporte olímpico en los Juegos de Sydney 2000 — los gimnastas alcanzan alturas de 8 metros y realizan múltiples saltos mortales con giros."]
},
'e250': {
  fr:["Les pieuvres alternent entre un sommeil calme (couleur pâle, immobile) et un sommeil actif (changements de couleurs rapides, mouvements) — similaire au sommeil REM humain.","Ce cycle sommeil calme/actif dure environ 30 à 40 minutes, avec des phases actives de seulement 1 à 2 minutes.","Si les pieuvres rêvent vraiment, cela signifie que le rêve a pu évoluer indépendamment chez les vertébrés et les invertébrés — une convergence évolutive fascinante."],
  en:["Octopuses alternate between quiet sleep (pale, still) and active sleep (rapid colour changes, twitching) — similar to human REM sleep.","This quiet/active cycle lasts about 30 to 40 minutes, with active phases of only 1 to 2 minutes.","If octopuses truly dream, it means dreaming may have evolved independently in vertebrates and invertebrates — a fascinating evolutionary convergence."],
    es:["Los pulpos en fase de sueño activo cambian de color en patrones rápidos e impredecibles, sugiriendo que «ven» imágenes durante el sueño — posiblemente recuerdos de caza o exploración.","El sueño activo del pulpo dura solo 40 segundos de media pero se repite cada 30-40 minutos — un ciclo mucho más corto que el REM de los mamíferos.","Si los pulpos sueñan, su conciencia es más compleja de lo que su vida solitaria y su corta existencia (1-5 años) sugieren — un misterio que desafía nuestra comprensión de la cognición animal."]
},
'e251': {
  fr:["La Finlande compte environ 3,3 millions de saunas pour 5,5 millions d'habitants — soit plus de saunas que de voitures.","Le sauna finlandais est inscrit au patrimoine immatériel de l'UNESCO depuis 2020 — il est considéré comme un lieu d'égalité où toutes les classes sociales se mélangent.","La température d'un sauna finlandais traditionnel se situe entre 80 et 100 °C — l'eau jetée sur les pierres crée la « löyly », la vapeur sacrée."],
  en:["Finland has about 3.3 million saunas for 5.5 million inhabitants — more saunas than cars.","The Finnish sauna has been UNESCO Intangible Heritage since 2020 — it's considered an equalising space where all social classes mix.","A traditional Finnish sauna temperature is between 80 and 100°C — water thrown on the stones creates the 'löyly', the sacred steam."],
    es:["En Finlandia, el sauna es un espacio social sagrado donde se han tomado decisiones políticas, se han cerrado negocios y se han resuelto conflictos familiares durante siglos.","Hay 3,3 millones de saunas para 5,5 millones de finlandeses — más saunas que coches, y prácticamente cada casa tiene el suyo.","La tradición del sauna finlandés fue inscrita en la lista del Patrimonio Cultural Inmaterial de la UNESCO en 2020 — un reconocimiento a una práctica de bienestar milenaria."]
},
'e252': {
  fr:["Hepburn a survécu à la famine aux Pays-Bas occupés pendant la Seconde Guerre mondiale — cette expérience a motivé son engagement humanitaire.","Elle a effectué plus de 50 missions de terrain pour l'UNICEF dans des pays en crise, de l'Éthiopie au Bangladesh.","Hepburn parlait couramment cinq langues : anglais, français, néerlandais, italien et espagnol."],
  en:["Hepburn survived the famine in Nazi-occupied Netherlands during WWII — this experience drove her humanitarian commitment.","She undertook over 50 UNICEF field missions in crisis-stricken countries, from Ethiopia to Bangladesh.","Hepburn was fluent in five languages: English, French, Dutch, Italian, and Spanish."],
    es:["Audrey Hepburn sufrió desnutrición severa durante la ocupación nazi de los Países Bajos — una experiencia que la motivó a dedicar los últimos años de su vida a UNICEF.","Como embajadora de buena voluntad de UNICEF (1988-1993), visitó países devastados por la guerra y la hambruna: Etiopía, Sudán, Somalia, Bangladesh y Guatemala.","Hepburn fue la primera actriz en combinar estrellato de Hollywood con activismo humanitario a gran escala — un modelo que siguieron Angelina Jolie y otros después."]
},
'e253': {
  fr:["Reeves a également offert des Harley-Davidson à chaque membre de l'équipe de cascadeurs de Matrix Reloaded.","Connu pour sa générosité discrète, il est régulièrement aperçu dans les transports en commun et les restaurants ordinaires de Los Angeles.","Reeves a traversé de nombreuses épreuves personnelles tragiques — son ami River Phoenix, sa compagne et leur enfant décédés — ce qui a renforcé sa philosophie de vie humble."],
  en:["Reeves also gave Harley-Davidsons to every member of the Matrix Reloaded stunt team.","Known for his quiet generosity, he's regularly spotted on public transport and ordinary restaurants in Los Angeles.","Reeves has endured many personal tragedies — his friend River Phoenix, his partner, and their child all passed — which reinforced his humble life philosophy."],
    es:["Keanu Reeves donó más de 70 millones de dólares de su salario de Matrix a los equipos técnicos de la película — maquilladores, especialistas en efectos y técnicos de vestuario.","También compró Harley-Davidson para cada uno de los 12 dobles de riesgo del equipo como regalo de agradecimiento al final del rodaje.","Reeves ha mantenido un perfil bajo y generoso a lo largo de su carrera, a pesar de tragedias personales (muerte de su pareja e hijo) — es considerado una de las personas más amables de Hollywood."]
},
'e254': {
  fr:["Le poste a finalement été accepté par Yitzhak Ben-Zvi, qui est devenu le deuxième président d'Israël.","Einstein a passé les 22 dernières années de sa vie à Princeton, aux États-Unis, où il poursuivait sa recherche sur la théorie du champ unifié.","À sa mort en 1955, le pathologiste Thomas Harvey a prélevé le cerveau d'Einstein sans autorisation — il l'a conservé dans un bocal pendant 40 ans."],
  en:["The position was ultimately accepted by Yitzhak Ben-Zvi, who became Israel's second president.","Einstein spent the last 22 years of his life at Princeton, USA, pursuing research on unified field theory.","Upon his death in 1955, pathologist Thomas Harvey removed Einstein's brain without permission — he kept it in a jar for 40 years."],
    es:["Einstein rechazó la presidencia de Israel en 1952 porque se consideraba un científico, no un político — su carta de declinación es un modelo de humildad intelectual.","A pesar de su pacifismo declarado, Einstein firmó la carta a Roosevelt en 1939 que impulsó el Proyecto Manhattan — una decisión que lamentó el resto de su vida.","Tras la guerra, Einstein se convirtió en activista por el desarme nuclear y los derechos civiles — su fama le otorgaba una plataforma que usó hasta su muerte en 1955."]
},
'e255': {
  fr:["Les carnets de Tesla décrivent des inventions visionnaires : transmission d'énergie sans fil, radar et même des concepts proches du smartphone.","Tesla et Edison étaient des rivaux acharnés : la « Guerre des courants » opposait le courant alternatif de Tesla au courant continu d'Edison.","Tesla est mort seul et ruiné dans une chambre d'hôtel à New York en 1943 — son génie n'a été pleinement reconnu que des décennies plus tard."],
  en:["Tesla's notebooks describe visionary inventions: wireless energy transmission, radar, and even concepts close to the smartphone.","Tesla and Edison were fierce rivals: the 'War of Currents' pitted Tesla's alternating current against Edison's direct current.","Tesla died alone and broke in a New York hotel room in 1943 — his genius was only fully recognised decades later."],
    es:["Tesla dormía solo 2 horas por noche pero compensaba con siestas breves durante el día — un patrón de sueño polifásico que él consideraba esencial para su productividad.","Afirmaba visualizar sus inventos completos en la mente antes de construirlos, como modelos 3D mentales que podía girar, desmontar y probar sin necesidad de prototipos.","Tesla murió solo y arruinado en una habitación del hotel New Yorker en 1943 — sus papeles fueron confiscados por el FBI, alimentando teorías conspirativas que perduran."]
},
'e256': {
  fr:["Les carnets de recherche de Marie Curie sont encore radioactifs aujourd'hui — ils sont conservés dans des boîtes de plomb à la Bibliothèque nationale de France.","Pierre et Marie Curie ont découvert le polonium et le radium ensemble — Pierre est mort en 1906, renversé par un attelage de chevaux.","Marie Curie a été la première femme professeur à la Sorbonne et la première femme à recevoir un Prix Nobel."],
  en:["Marie Curie's research notebooks are still radioactive today — they're stored in lead-lined boxes at France's National Library.","Pierre and Marie Curie discovered polonium and radium together — Pierre died in 1906, run over by a horse-drawn carriage.","Marie Curie was the first female professor at the Sorbonne and the first woman to receive a Nobel Prize."],
    es:["Marie Curie ganó el Nobel de Física (1903, con Pierre Curie y Becquerel) por el estudio de la radiación, y el de Química (1911) por el descubrimiento del radio y el polonio.","Sus cuadernos de laboratorio son tan radiactivos que se conservan en cajas forradas de plomo en la Bibliothèque Nationale de Francia — consultarlos requiere ropa protectora y un formulario de consentimiento.","Curie fundó institutos de investigación en París y Varsovia que siguen activos — su legado incluye no solo sus descubrimientos sino la apertura de la ciencia a las mujeres."]
},
'e257': {
  fr:["Darwin a publié « La formation de la terre végétale par l'action des vers » en 1881, six mois avant sa mort — le livre s'est mieux vendu que « L'Origine des espèces » au départ.","Il a démontré que les vers de terre retournent entre 10 et 40 tonnes de terre par hectare et par an — un rôle écologique fondamental.","Darwin jouait du basson à ses vers de terre pour tester leur sensibilité aux vibrations — un exemple de son approche expérimentale unique."],
  en:["Darwin published 'The Formation of Vegetable Mould Through the Action of Worms' in 1881, six months before his death — it initially outsold 'On the Origin of Species'.","He demonstrated that earthworms turn over 10 to 40 tonnes of soil per hectare per year — a fundamental ecological role.","Darwin played bassoon to his earthworms to test their sensitivity to vibrations — an example of his unique experimental approach."],
    es:["Darwin dedicó 40 años al estudio de los gusanos de tierra: su último libro, La formación del mantillo vegetal por la acción de los gusanos (1881), demostró su papel crucial en la fertilidad del suelo.","Los gusanos procesan hasta 15 toneladas de tierra por hectárea cada año, aerando el suelo, mezclando nutrientes y acelerando la descomposición de materia orgánica.","Darwin consideraba este trabajo tan importante como El origen de las especies — una demostración de que los organismos más humildes pueden transformar ecosistemas enteros."]
},
'e258': {
  fr:["Les médecins lui avaient donné deux ans à vivre — il a vécu 55 ans de plus, devenant l'un des physiciens les plus célèbres de l'histoire.","Hawking a rendu la physique accessible au grand public avec « Une brève histoire du temps » (1988), vendu à plus de 25 millions d'exemplaires.","Il communiquait via un synthétiseur vocal contrôlé par un muscle de sa joue — sa « voix » robotique est devenue iconique."],
  en:["Doctors gave him two years to live — he lived 55 more, becoming one of the most famous physicists in history.","Hawking made physics accessible to the public with 'A Brief History of Time' (1988), selling over 25 million copies.","He communicated via a speech synthesiser controlled by a cheek muscle — his robotic 'voice' became iconic."],
    es:["Los médicos le dieron a Hawking 2 años de vida cuando le diagnosticaron ELA a los 21 años — vivió 55 años más, hasta los 76, desafiando todas las estadísticas médicas.","Comunicándose a través de un sintetizador de voz controlado por un músculo de la mejilla, publicó best-sellers, dio conferencias y se convirtió en el científico más famoso del mundo.","Su voz sintética se convirtió en un icono cultural: cuando le ofrecieron una voz más natural, Hawking la rechazó porque la original «ya era su voz»."]
},
'e259': {
  fr:["L'histoire de la chatière de Newton est peut-être apocryphe — mais elle est si charmante qu'elle est devenue inséparable de sa légende.","Newton aurait aussi fait un petit trou à côté du grand pour les chatons — ne réalisant pas qu'ils pouvaient passer par le grand trou.","Au-delà de l'anecdote, Newton possédait vraiment des chats et tenait ses expériences d'optique dans l'obscurité — les chats perturbaient ses prismes en ouvrant la porte."],
  en:["The story of Newton's cat flap may be apocryphal — but it's so charming it has become inseparable from his legend.","Newton supposedly also made a small hole next to the big one for kittens — not realising they could use the big hole.","Beyond the anecdote, Newton did own cats and kept his optics experiments in darkness — cats disrupted his prisms by opening the door."],
    es:["La anécdota de Newton y la chatière es probablemente apócrifa: la primera mención data de un texto de 1827, un siglo después de la muerte de Newton.","Lo que sí es cierto es que Newton mantenía gatos en su estudio del Trinity College de Cambridge — los registros mencionan gastos para su alimentación.","Newton era conocido por su excentricidad: olvidaba comer, recibía visitas en pijama y podía pasar días sin salir de su laboratorio durante sus periodos de trabajo intenso."]
},
'e260': {
  fr:["Les montres molles de « La Persistance de la mémoire » (1931) sont devenues le symbole du surréalisme — Dalí disait s'être inspiré du camembert fondant.","Dalí cultivait une moustache extravagante aux pointes relevées à la cire — il la considérait comme une œuvre d'art à part entière.","Il a conçu le logo de la sucette Chupa Chups en 1969 — un design toujours utilisé aujourd'hui, devenu l'un des logos les plus reconnaissables au monde."],
  en:["The melting watches of 'The Persistence of Memory' (1931) became the symbol of Surrealism — Dalí said he was inspired by melting Camembert cheese.","Dalí cultivated an extravagant wax-tipped upturned moustache — he considered it a work of art in itself.","He designed the Chupa Chups lollipop logo in 1969 — a design still used today, one of the world's most recognisable logos."],
    es:["Dalí cultivaba deliberadamente su imagen extravagante como herramienta de marketing: sus bigotes engomados, sus declaraciones provocadoras y sus apariciones eran performances calculadas.","La «locura» de Dalí era en gran parte una estrategia comercial: fue uno de los primeros artistas en comprender que la personalidad del artista era tan vendible como su obra.","André Breton, líder del surrealismo, expulsó a Dalí del movimiento en 1939 por sus simpatías franquistas y su comercialismo — Dalí respondió: «El surrealismo soy yo»."]
},
'e261': {
  fr:["Mozart a composé plus de 600 œuvres en seulement 35 ans de vie — symphonies, opéras, concertos et musique de chambre.","Son opéra « Bastien und Bastienne », composé à 12 ans, est encore joué aujourd'hui dans les opéras du monde entier.","Mozart avait un sens de l'humour scatologique bien documenté — plusieurs de ses lettres à sa cousine contiennent des blagues graveleuses."],
  en:["Mozart composed over 600 works in just 35 years of life — symphonies, operas, concertos, and chamber music.","His opera 'Bastien und Bastienne', composed at 12, is still performed in opera houses worldwide.","Mozart had a well-documented scatological sense of humour — several letters to his cousin contain crude jokes."],
    es:["Mozart compuso su primer minueto a los 5 años y su primera sinfonía completa (K. 16) a los 8, durante una gira europea con su padre y su hermana Nannerl.","Su padre Leopold fue su principal maestro y manager — un equilibrio entre educación, explotación y devoción que ha sido analizado por biógrafos durante siglos.","Mozart produjo más de 600 obras en 35 años de vida: sinfonías, conciertos, óperas, sonatas, misas y cuartetos — un promedio de una obra cada tres semanas."]
},
'e262': {
  fr:["La théorie des groupes de Galois est devenue l'un des piliers des mathématiques modernes — elle est fondamentale en algèbre et en cryptographie.","Galois a été tué lors d'un duel le 31 mai 1832, probablement pour une querelle amoureuse — ses manuscrits ont failli être perdus.","La nuit avant le duel, il a griffonné « je n'ai pas le temps » dans les marges de ses notes — conscient qu'il laissait des théorèmes inachevés."],
  en:["Galois' group theory became a pillar of modern mathematics — it's fundamental in algebra and cryptography.","Galois was killed in a duel on 31 May 1832, likely over a romantic dispute — his manuscripts nearly got lost.","The night before the duel, he scrawled 'I have not time' in the margins of his notes — aware he was leaving unfinished theorems."],
    es:["Évariste Galois escribió los fundamentos de la teoría de grupos en una carta la noche antes de morir en un duelo a los 20 años — una de las tragedias más conmovedoras de la historia de las matemáticas.","La carta contenía ideas que no serían plenamente comprendidas hasta décadas después — la «teoría de Galois» es hoy esencial en álgebra abstracta y en la física teórica.","Las circunstancias del duelo (mayo de 1832) son confusas: ¿un asunto de honor por una mujer? ¿Una provocación política? Los historiadores siguen debatiendo."]
},
'e263': {
  fr:["L'accident de bus à Mexico en 1925 lui a brisé la colonne vertébrale, le bassin, les côtes et le pied — elle a subi plus de 30 opérations au cours de sa vie.","Elle a commencé à peindre dans son lit de convalescence grâce à un miroir fixé au-dessus d'elle — c'est pourquoi tant de ses œuvres sont des autoportraits.","Kahlo et Diego Rivera ont eu une relation tumultueuse — ils se sont mariés, divorcé, puis remariés, leur passion nourrissant l'art de Frida."],
  en:["The 1925 bus accident in Mexico broke her spine, pelvis, ribs, and foot — she underwent over 30 surgeries in her lifetime.","She began painting in her recovery bed using a mirror mounted above her — which is why so many of her works are self-portraits.","Kahlo and Diego Rivera had a tumultuous relationship — they married, divorced, and remarried, their passion fuelling Frida's art."],
    es:["Frida Kahlo sufrió un accidente de autobús a los 18 años que le provocó fracturas en la columna, la pelvis, las costillas y el pie — fue durante su convalecencia cuando empezó a pintar.","55 de sus 143 cuadros son autorretratos que exploran el dolor físico, la identidad, la mexicanidad, la sexualidad y la relación tumultuosa con Diego Rivera.","Kahlo fue redescubierta en los años 1980 como icono feminista y LGBTQ+ — su Autorretrato con collar de espinas se vendió por 34,9 millones de dólares en 2021."]
},
'e264': {
  fr:["Avant Chanel, le noir était réservé au deuil — elle en a fait un symbole d'élégance universelle.","Coco Chanel a également inventé le parfum moderne avec le N°5 en 1921 — le premier parfum à utiliser des aldéhydes de synthèse.","Née Gabrielle Bonheur Chasnel dans un hospice de Saumur, elle a grandi dans un orphelinat — un parcours qui contraste avec l'empire de luxe qu'elle a bâti."],
  en:["Before Chanel, black was reserved for mourning — she turned it into a universal symbol of elegance.","Coco Chanel also invented modern perfume with N°5 in 1921 — the first fragrance to use synthetic aldehydes.","Born Gabrielle Bonheur Chasnel in a poorhouse in Saumur, she grew up in an orphanage — a background contrasting sharply with the luxury empire she built."],
    es:["Antes Chanel, el negro era el color del luto y de los sirvientes — la petite robe noire (1926) lo convirtió en símbolo de elegancia, modernidad e independencia femenina.","Chanel liberó a la mujer del corsé, popularizó los pantalones y creó el tweed como tela de moda — tomó prestados elementos del vestuario masculino y los transformó.","Chanel N°5, creado en 1921 con el perfumista Ernest Beaux, fue el primer perfume en usar aldehídos sintéticos — sigue siendo el perfume más vendido del mundo un siglo después."]
},
'e265': {
  fr:["Christie a écrit 66 romans policiers et 14 recueils de nouvelles — en plus de la plus longue pièce de théâtre jamais jouée (« La Souricière », depuis 1952).","En 1926, Christie a mystérieusement disparu pendant 11 jours — un épisode jamais totalement expliqué qui a fait la une des journaux.","Son personnage Hercule Poirot a reçu une nécrologie dans le New York Times à la publication de son dernier roman — le seul personnage de fiction à avoir eu cet honneur."],
  en:["Christie wrote 66 detective novels and 14 short story collections — plus the longest-running play ever ('The Mousetrap', since 1952).","In 1926, Christie mysteriously vanished for 11 days — an episode never fully explained that made headline news.","Her character Hercule Poirot received an obituary in the New York Times upon his final novel — the only fictional character so honoured."],
    es:["Agatha Christie ha vendido más de 2 000 millones de ejemplares en más de 100 idiomas — solo superada por Shakespeare y la Biblia en ventas totales.","Su propia desaparición en 1926 (11 días sin dar señales) sigue siendo un misterio: se la encontró en un hotel bajo un nombre falso, sin explicación convincente.","El ratonero (The Mousetrap), estrenado en 1952, se sigue representando en el West End de Londres — es la obra de teatro con el período de representaciones continuas más largo de la historia."]
},
'e266': {
  fr:["De Vinci écrivait en écriture miroir (de droite à gauche) dans ses carnets — probablement pour protéger ses idées, ou simplement parce qu'il était gaucher.","Ses carnets contiennent des croquis d'hélicoptères, de chars d'assaut et de scaphandres — des concepts réalisés des siècles plus tard.","De Vinci pratiquait la dissection de cadavres pour comprendre l'anatomie — ses dessins anatomiques sont d'une précision qui rivalise avec l'imagerie moderne."],
  en:["Da Vinci wrote in mirror script (right to left) in his notebooks — probably to protect his ideas, or simply because he was left-handed.","His notebooks contain sketches of helicopters, tanks, and diving suits — concepts realised centuries later.","Da Vinci practised cadaver dissection to understand anatomy — his anatomical drawings rival modern imaging in precision."],
    es:["Da Vinci era ambidextro y escribía en espejo (de derecha a izquierda) — sus cuadernos necesitan un espejo para ser leídos, posiblemente para mantener el secreto de sus investigaciones.","Diseñó máquinas voladoras, tanques, escafandras, robots y puentes portátiles siglos antes de que la tecnología permitiera construirlos — sus 7 200 páginas de notas son un tesoro de ingenio.","Nunca publicó sus descubrimientos científicos: sus manuscritos permanecieron dispersos e inéditos durante siglos, retrasando avances que podrían haber cambiado la historia."]
},
'e267': {
  fr:["Churchill a commencé à peindre en 1915 pendant une période de dépression après l'échec de Gallipoli — la peinture est devenue sa thérapie.","Il peignait principalement des paysages impressionnistes et des natures mortes — sous le pseudonyme « Charles Morin » pour les expositions.","Churchill a été élu membre honoraire de la Royal Academy of Arts en 1948 — un honneur très rare pour un non-professionnel."],
  en:["Churchill began painting in 1915 during a depression after the Gallipoli failure — painting became his therapy.","He mainly painted Impressionist landscapes and still lifes — under the pseudonym 'Charles Morin' for exhibitions.","Churchill was elected Honorary Member of the Royal Academy of Arts in 1948 — a very rare honour for a non-professional."],
    es:["Churchill pintó más de 500 óleos durante su vida, principalmente paisajes al aire libre — una actividad que le servía como terapia contra lo que él llamaba su «perro negro» (depresión).","Su ensayo Painting as a Pastime (1948) describe cómo la pintura le proporcionaba alivio mental durante los períodos más oscuros de su carrera política.","Algunas de sus obras se han vendido por más de un millón de dólares — aunque su talento artístico era real, su celebridad como estadista infla inevitablemente los precios."]
},
'e268': {
  fr:["Tesla avait de nombreuses obsessions et rituels : il devait calculer le volume de sa nourriture avant de manger et comptait ses pas en marchant.","Il était également obsédé par le chiffre 3 — il faisait le tour d'un bâtiment trois fois avant d'y entrer.","Malgré ces excentricités, Tesla a déposé plus de 300 brevets et ses inventions (courant alternatif, moteur à induction) alimentent littéralement le monde moderne."],
  en:["Tesla had many obsessions and rituals: he had to calculate the volume of his food before eating and counted his steps while walking.","He was also obsessed with the number 3 — he would walk around a building three times before entering.","Despite these eccentricities, Tesla filed over 300 patents and his inventions (AC current, induction motor) literally power the modern world."],
    es:["Tesla tenía una fobia extrema a las perlas: no podía estar en presencia de una mujer que llevara joyas de perlas y abandonaba reuniones si veía un collar de perlas.","También era germófobo, tenía obsesión por el número 3 (daba vueltas a una manzana 3 veces antes de entrar en un edificio) y se negaba a estrechar manos.","Estos comportamientos, combinados con su genio y su aislamiento social, han llevado a algunos psiquiatras postumos a diagnosticar un posible trastorno obsesivo-compulsivo."]
},
'e269': {
  fr:["Dickens faisait aussi de longues marches nocturnes de 15 à 30 km à travers Londres — l'insomnie alimentait ses observations sociales.","Il a donné des lectures publiques de ses œuvres qui attiraient des milliers de personnes — des spectacles si intenses qu'ils ont contribué à détériorer sa santé.","Dickens a inventé de nombreux mots et expressions entrés dans la langue anglaise, dont « butterfingers » et « boredom »."],
  en:["Dickens also took long night walks of 15 to 30 km through London — insomnia fuelled his social observations.","He gave public readings of his works that drew thousands — performances so intense they contributed to declining health.","Dickens coined many words and phrases that entered the English language, including 'butterfingers' and 'boredom'."],
    es:["Dickens tenía numerosas manías: dormía siempre orientado al norte (creía en el magnetismo terrestre), reordenaba los muebles de los hoteles y caminaba 20-30 km diarios por Londres.","Sus paseos nocturnos por los barrios más pobres de Londres alimentaban directamente su ficción: las descripciones de la miseria urbana en Oliver Twist y Bleak House son testimonios de primera mano.","Dickens era también un actor consumado: sus lecturas públicas eran espectáculos tan intensos que su médico le prohibió continuar — el estrés probablemente contribuyó a su muerte a los 58 años."]
},
'e270': {
  fr:["L'algorithme de Lovelace était destiné à calculer les nombres de Bernoulli sur la machine analytique de Charles Babbage — une machine qui n'a jamais été construite.","Lovelace a vu au-delà du simple calcul : elle a prédit que les machines pourraient un jour composer de la musique et manipuler des symboles.","Elle était la fille du poète Lord Byron — qu'elle n'a jamais connu car il a quitté l'Angleterre peu après sa naissance."],
  en:["Lovelace's algorithm was designed to calculate Bernoulli numbers on Charles Babbage's Analytical Engine — a machine never built.","Lovelace saw beyond mere calculation: she predicted machines could one day compose music and manipulate symbols.","She was the daughter of poet Lord Byron — whom she never knew, as he left England shortly after her birth."],
    es:["Ada Lovelace escribió en 1843 un algoritmo para la máquina analítica de Charles Babbage, un dispositivo mecánico que nunca se construyó — el primer programa informático de la historia.","Hija del poeta Lord Byron (a quien nunca conoció), fue orientada hacia las matemáticas por su madre para alejarla de la «peligrosa imaginación» paterna.","Lovelace previó que las máquinas podrían crear música y arte, no solo calcular — una visión que anticipó la inteligencia artificial por más de un siglo."]
},
'e271': {
  fr:["Tubman a effectué environ 13 missions de sauvetage entre 1850 et 1860, libérant environ 70 personnes esclavisées.","Pendant la guerre de Sécession, elle est devenue espionne et éclaireuse pour l'armée de l'Union — la première femme à mener un raid armé (raid de Combahee River, 1863).","Une prime de 40 000 dollars avait été mise sur sa tête — pourtant elle n'a jamais été capturée et a vécu jusqu'à 91 ans."],
  en:["Tubman made about 13 rescue missions between 1850 and 1860, freeing roughly 70 enslaved people.","During the Civil War, she became a spy and scout for the Union Army — the first woman to lead an armed raid (Combahee River Raid, 1863).","A $40,000 bounty was placed on her head — yet she was never caught and lived to 91."],
    es:["Harriet Tubman realizó 13 misiones de rescate a través del Underground Railroad entre 1850 y 1860, liberando a unas 70 personas esclavizadas — nunca perdió a un solo «pasajero».","Durante la Guerra Civil, Tubman sirvió como espía, enfermera y la primera mujer en liderar una operación militar en EE.UU.: el raid del río Combahee, que liberó a más de 700 esclavos.","En 2016, el Tesoro de EE.UU. anunció que Tubman reemplazaría a Andrew Jackson en el billete de 20 dólares — el proceso ha sufrido múltiples retrasos pero sigue en marcha."]
},
'e272': {
  fr:["Turing a conçu la « bombe » électromécanique à Bletchley Park, capable de tester des milliers de combinaisons Enigma par jour.","Après la guerre, Turing a posé les bases théoriques de l'intelligence artificielle — son « test de Turing » (1950) reste un concept clé en IA.","Malgré ses contributions immenses, Turing a été condamné pour homosexualité en 1952 et contraint à un traitement chimique — il a été gracié à titre posthume par la reine en 2013."],
  en:["Turing designed the electromechanical 'bombe' at Bletchley Park, capable of testing thousands of Enigma combinations per day.","After the war, Turing laid the theoretical foundations of artificial intelligence — his 'Turing test' (1950) remains a key AI concept.","Despite his immense contributions, Turing was convicted for homosexuality in 1952 and forced to undergo chemical treatment — he was posthumously pardoned by the Queen in 2013."],
    es:["Alan Turing diseñó la «máquina de Turing» en 1936, un modelo teórico que define los límites de lo que puede ser calculado — la base conceptual de toda la informática moderna.","Su trabajo en Bletchley Park descifrando el código Enigma acortó la guerra en al menos 2 años y salvó millones de vidas — un logro mantenido en secreto durante décadas.","Turing fue perseguido por su homosexualidad, condenado y sometido a castración química en 1952 — se suicidó en 1954. El gobierno británico le otorgó un perdón póstumo en 2013."]
},
'e273': {
  fr:["Les robots de R.U.R. se rebellent contre leurs créateurs humains — un thème repris dans d'innombrables œuvres de science-fiction depuis.","La pièce R.U.R. a été un succès international dès sa première en 1921 à Prague — traduite en 30 langues en quelques années.","Čapek lui-même craignait les dangers de l'automatisation et de la déshumanisation — des thèmes étonnamment actuels un siècle plus tard."],
  en:["The robots in R.U.R. rebel against their human creators — a theme revisited in countless sci-fi works since.","R.U.R. was an international hit from its 1921 Prague premiere — translated into 30 languages within a few years.","Čapek himself feared the dangers of automation and dehumanisation — themes startlingly relevant a century later."],
    es:["Karel Čapek introdujo el concepto de robot en R.U.R. (1920), pero su hermano Josef sugirió la palabra — los «robots» de la obra son seres biológicos, no mecánicos.","La obra termina con los robots rebelándose y exterminando a la humanidad — un tema que anticipa décadas de ciencia ficción sobre la revuelta de las máquinas.","Asimov formuló las Tres Leyes de la Robótica en 1942 como respuesta directa al tropo del «robot asesino» de Čapek — un marco ético que sigue siendo referencia."]
},
'e274': {
  fr:["Tolkien était professeur de vieil anglais à Oxford — son expertise linguistique a directement nourri la création de ses langues fictives.","Le quenya est inspiré du finnois et le sindarin du gallois — Tolkien les a dotés de grammaires complètes, de phonologies et même d'évolutions historiques.","Tolkien a dit que ses langues étaient venues en premier : « L'histoire a grandi pour fournir un monde aux langues, plutôt que l'inverse. »"],
  en:["Tolkien was a professor of Old English at Oxford — his linguistic expertise directly fed his fictional language creation.","Quenya is inspired by Finnish and Sindarin by Welsh — Tolkien gave them complete grammars, phonologies, and even historical evolution.","Tolkien said the languages came first: 'The story grew to provide a world for the languages, rather than the other way around.'"],
    es:["Tolkien creó las lenguas élficas (quenya y sindarin) antes de escribir las historias — el mundo de la Tierra Media nació para dar un hogar a sus lenguas inventadas.","El quenya está basado en el finés y el sindarin en el galés — ambas tienen gramáticas completas, fonologías coherentes y vocabularios extensos.","Tolkien era filólogo de Oxford, especialista en anglosajón: su conocimiento de las lenguas germánicas antiguas y las mitologías nórdicas alimenta cada página de El Señor de los Anillos."]
},
'e275': {
  fr:["La réplique la plus proche dans les textes originaux est « Elementary » tout court, sans le « my dear Watson » — dans « The Crooked Man » (1893).","La phrase complète vient des adaptations théâtrales et cinématographiques du début du XXe siècle — elle est devenue inséparable du personnage.","Conan Doyle a tenté de tuer Holmes dans « Le Dernier Problème » (1893), mais la pression des lecteurs l'a forcé à le ressusciter."],
  en:["The closest line in the original texts is just 'Elementary', without 'my dear Watson' — in 'The Crooked Man' (1893).","The full phrase came from early 20th-century stage and film adaptations — it became inseparable from the character.","Conan Doyle tried to kill Holmes in 'The Final Problem' (1893), but reader pressure forced him to bring him back."],
    es:["Holmes dice «Elementary» y «my dear Watson» en varias ocasiones en los textos de Conan Doyle, pero nunca combina ambas en una sola frase.","La expresión combinada fue popularizada por las adaptaciones teatrales del actor William Gillette y los primeros films — se convirtió en la cita apócrifa más famosa de la ficción.","Conan Doyle detestaba a Holmes y lo mató en Las cataratas de Reichenbach (1893) — la protesta pública fue tan intensa que tuvo que resucitarlo en 1903."]
},
'e276': {
  fr:["Bloomsbury a offert un contrat à J.K. Rowling après que la fille du directeur de 8 ans a lu le premier chapitre et supplié de connaître la suite.","Le premier tirage de « Harry Potter à l'école des sorciers » n'était que de 500 exemplaires — aujourd'hui un exemplaire peut valoir plus de 50 000 €.","La série Harry Potter s'est vendue à plus de 600 millions d'exemplaires dans 84 langues — c'est la série de livres la plus vendue de l'histoire."],
  en:["Bloomsbury offered Rowling a contract after the publisher's 8-year-old daughter read the first chapter and begged for more.","The first print run of 'Philosopher's Stone' was just 500 copies — today a first edition can be worth over €50,000.","The Harry Potter series has sold over 600 million copies in 84 languages — the best-selling book series in history."],
    es:["J.K. Rowling escribió gran parte del primer Harry Potter en cafeterías de Edimburgo mientras vivía de prestaciones sociales como madre soltera — The Elephant House es hoy un lugar de peregrinación.","La saga ha vendido más de 500 millones de ejemplares, ha sido traducida a 80 idiomas y ha generado un universo valorado en más de 25 000 millones de dólares.","El primer editor, Barry Cunningham de Bloomsbury, aconsejó a Rowling «buscarse un trabajo de día porque los libros infantiles no dan dinero» — uno de los peores consejos empresariales de la historia."]
},
'e277': {
  fr:["Don Quichotte a été publié en deux parties (1605 et 1615) — entre les deux, un auteur rival a publié une suite non autorisée que Cervantes a dénoncée.","Le roman a introduit des techniques narratives révolutionnaires : récit enchâssé, métafiction et personnages qui commentent leur propre histoire.","L'expression « se battre contre des moulins à vent » vient directement de Don Quichotte — elle est utilisée dans des dizaines de langues."],
  en:["Don Quixote was published in two parts (1605 and 1615) — between them, a rival author published an unauthorised sequel that Cervantes denounced.","The novel introduced revolutionary narrative techniques: stories within stories, metafiction, and characters commenting on their own tale.","The expression 'tilting at windmills' comes directly from Don Quixote — it's used in dozens of languages."],
    es:["Don Quijote (1605-1615) es la primera novela moderna: usa la ironía, la autorreferencia, los múltiples narradores y la mezcla de géneros que definen la novela contemporánea.","Cervantes escribió la segunda parte en parte como respuesta a una continuación apócrifa de Avellaneda (1614) — la rivalidad literaria más productiva de la historia.","Don Quijote es el libro más traducido del mundo después de la Biblia, y su influencia se extiende de Flaubert a Borges, de Kafka a Rushdie."]
},
'e278': {
  fr:["Le communicateur de Kirk a directement inspiré Martin Cooper, l'inventeur du téléphone portable chez Motorola en 1973.","Le tricordeur médical de Bones McCoy a inspiré des appareils de diagnostic portables réels, dont certains sont aujourd'hui en développement clinique.","Le traducteur universel de Star Trek préfigurait les outils de traduction en temps réel comme Google Translate et les oreillettes traductrices."],
  en:["Kirk's communicator directly inspired Martin Cooper, the inventor of the mobile phone at Motorola in 1973.","Dr McCoy's medical tricorder inspired real portable diagnostic devices, some now in clinical development.","Star Trek's universal translator prefigured real-time translation tools like Google Translate and translator earbuds."],
    es:["Star Trek predijo los teléfonos móviles (comunicadores), las tabletas (PADD), la traducción automática (traductor universal), las puertas automáticas y la telemedicina.","El creador Gene Roddenberry quiso mostrar un futuro utópico donde la humanidad había superado el racismo, la guerra y la pobreza — una visión optimista radical para la televisión de los años 1960.","Star Trek presentó el primer beso interracial de la televisión estadounidense (Kirk y Uhura, 1968) — la NBC quiso eliminarlo pero Shatner y Nichols sabotearon deliberadamente las tomas alternativas."]
},
'e279': {
  fr:["Le concours avait lieu chez Lord Byron au bord du lac Léman — Percy Shelley, John Polidori et Byron lui-même y participaient.","Polidori a écrit « Le Vampire » lors du même concours — considéré comme le premier récit de vampire en littérature anglaise.","Shelley s'est inspirée des expériences de galvanisme (stimulation électrique de cadavres) populaires à l'époque pour imaginer la créature de Frankenstein."],
  en:["The competition took place at Lord Byron's house by Lake Geneva — Percy Shelley, John Polidori, and Byron himself all participated.","Polidori wrote 'The Vampyre' during the same contest — considered the first vampire tale in English literature.","Shelley drew inspiration from galvanism experiments (electrical stimulation of corpses) popular at the time to imagine Frankenstein's creature."],
    es:["Mary Shelley concibió Frankenstein durante un verano lluvioso en Suiza (1816), como parte de un reto de historias de terror con Lord Byron, Percy Shelley y John Polidori.","La novela plantea cuestiones éticas sobre la creación artificial de vida que siguen siendo centrales en los debates sobre inteligencia artificial, clonación y edición genética.","El monstruo de Frankenstein no tiene nombre en la novela — «Frankenstein» es el creador, no la criatura. Esta confusión refleja irónicamente el tema de la obra: la responsabilidad del creador."]
},
'e280': {
  fr:["Orwell a probablement choisi 1984 en inversant les deux derniers chiffres de 1948, l'année de rédaction.","Les concepts de « novlangue », « double pensée » et « Big Brother » inventés par Orwell sont entrés dans le vocabulaire courant.","Les ventes de « 1984 » explosent à chaque fois qu'un scandale de surveillance est révélé — elles ont triplé après les révélations de Snowden en 2013."],
  en:["Orwell likely chose 1984 by reversing the last two digits of 1948, the year he wrote the book.","Concepts like 'Newspeak', 'doublethink', and 'Big Brother' invented by Orwell have entered everyday vocabulary.","Sales of '1984' spike whenever a surveillance scandal breaks — they tripled after the Snowden revelations in 2013."],
    es:["Orwell eligió 1984 como título invirtiendo las dos últimas cifras de 1948, año en que terminó el manuscrito — estaba agonizando de tuberculosis en la isla escocesa de Jura.","Los conceptos de neolengua (manipulación del lenguaje), doblepensar (aceptar dos verdades contradictorias) y Gran Hermano (vigilancia total) se han integrado en el vocabulario común.","Las ventas de 1984 se disparan en cada crisis de vigilancia gubernamental: fueron bestseller en 2013 (Snowden), 2017 (Trump) y durante la pandemia de COVID-19."]
},
'e281': {
  fr:["Dans « De la Terre à la Lune » (1865), Verne a prédit un lancement depuis la Floride avec trois passagers — Apollo 11 est parti du même État avec trois astronautes.","« Vingt mille lieues sous les mers » (1870) a décrit un sous-marin électrique autonome — le premier vrai sous-marin opérationnel date de 1900.","Verne est le deuxième auteur le plus traduit de l'histoire après Agatha Christie — ses 62 romans sont disponibles dans plus de 150 langues."],
  en:["In 'From the Earth to the Moon' (1865), Verne predicted a launch from Florida with three passengers — Apollo 11 left from the same state with three astronauts.","'Twenty Thousand Leagues Under the Sea' (1870) described an autonomous electric submarine — the first real operational submarine dates from 1900.","Verne is the second most translated author in history after Agatha Christie — his 62 novels are available in over 150 languages."],
    es:["Jules Verne describió en sus novelas el submarino eléctrico (Nautilus, 1870), el vuelo a la Luna (1865), los helicópteros (1886) y las videoconferencias (1889).","Veinte mil leguas de viaje submarino anticipó el submarino nuclear por casi un siglo — el primer submarino nuclear de EE.UU., lanzado en 1954, fue bautizado USS Nautilus en su honor.","Verne no era científico sino un escritor meticuloso que investigaba obsesivamente: consultaba expertos, leía revistas científicas y actualizaba sus manuscritos con los últimos descubrimientos."]
},
'e282': {
  fr:["Tolkien a mis 12 ans à écrire Le Seigneur des Anneaux (1937-1949) — il réécrivait obsessionnellement chaque passage pour maintenir la cohérence de son monde.","Le manuscrit original faisait plus de 1 200 pages — l'éditeur Allen & Unwin l'a divisé en trois volumes : La Communauté, Les Deux Tours et Le Retour du Roi.","Tolkien a d'abord été refusé par Collins, qui trouvait le manuscrit trop long et n'y voyait pas d'intérêt commercial — une erreur éditoriale historique."],
  en:["Tolkien took 12 years to write The Lord of the Rings (1937–1949) — obsessively rewriting every passage to maintain his world's consistency.","The original manuscript was over 1,200 pages — publisher Allen & Unwin split it into three volumes: Fellowship, Two Towers, and Return of the King.","Tolkien was first rejected by Collins, who found the manuscript too long and saw no commercial interest — a historic editorial mistake."],
    es:["Tolkien envió el manuscrito de El Señor de los Anillos a su editor en 1949, pero este lo rechazó por su longitud excesiva — finalmente se publicó en tres volúmenes entre 1954 y 1955.","La trilogía cinematográfica de Peter Jackson (2001-2003) ganó 17 premios Oscar y transformó Nueva Zelanda en destino turístico — generando más de 3 000 millones en taquilla.","Tolkien detestaba las alegorías: insistía en que El Señor de los Anillos no era una metáfora de la Segunda Guerra Mundial, a pesar de las similitudes evidentes."]
},
'e283': {
  fr:["Vlad III, surnommé « l'Empaleur », régnait en Valachie (actuelle Roumanie) au XVe siècle — sa cruauté légendaire a nourri le mythe du vampire.","Stoker n'a jamais visité la Transylvanie — il a construit son décor à partir de guides de voyage et de recherches en bibliothèque à Londres.","Le roman a d'abord été un échec commercial modeste — c'est le cinéma, avec Nosferatu (1922) puis Dracula (1931), qui a rendu le personnage iconique."],
  en:["Vlad III, nicknamed 'the Impaler', ruled in Wallachia (modern Romania) in the 15th century — his legendary cruelty fed the vampire myth.","Stoker never visited Transylvania — he built his setting from travel guides and library research in London.","The novel was initially a modest commercial failure — cinema, with Nosferatu (1922) then Dracula (1931), made the character iconic."],
    es:["Bram Stoker investigó durante años el folclore vampírico de Europa del Este para escribir Drácula (1897) — pero nunca visitó Transilvania.","Vlad Tepes (Vlad el Empalador), príncipe de Valaquia del siglo XV, sirvió de inspiración parcial — aunque el personaje de ficción tiene poco en común con el histórico.","Drácula ha generado más de 1 000 adaptaciones cinematográficas — es el personaje de ficción más filmado después de Sherlock Holmes."]
},
'e284': {
  fr:["Saint-Exupéry a écrit et illustré Le Petit Prince à New York en 1942, pendant son exil — le livre a été publié d'abord en anglais avant le français.","Le livre se vend à environ 2 millions d'exemplaires par an — il est le livre le plus traduit au monde après les textes religieux.","Saint-Exupéry a disparu en vol au-dessus de la Méditerranée en 1944 — les restes de son avion n'ont été retrouvés qu'en 2004."],
  en:["Saint-Exupéry wrote and illustrated The Little Prince in New York in 1942, during his exile — the book was first published in English before French.","The book sells about 2 million copies per year — it's the most translated book in the world after religious texts.","Saint-Exupéry vanished during a flight over the Mediterranean in 1944 — the remains of his plane were only found in 2004."],
    es:["El Principito ha sido traducido a más de 300 idiomas y dialectos, incluyendo lenguas en peligro como el toba y el maya lacandón — un récord de traducción para un libro no religioso.","Saint-Exupéry desapareció durante una misión de reconocimiento sobre el Mediterráneo el 31 de julio de 1944 — los restos de su avión fueron encontrados cerca de Marsella en 2004.","La frase «lo esencial es invisible a los ojos» se ha convertido en una de las citas más universales de la literatura — citada en contextos que van de la filosofía al marketing."]
},
'e285': {
  fr:["Martin s'est inspiré de la Guerre des Deux-Roses en Angleterre (XVe siècle) pour créer les conflits entre Stark et Lannister.","Le premier livre, « A Game of Thrones », est sorti en 1996 — Martin travaille toujours sur les deux derniers volumes de la saga, attendus par des millions de fans.","Martin a déclaré que les personnages de Tolkien étaient trop « noirs ou blancs » — il voulait des personnages moralement ambigus comme dans la vraie histoire."],
  en:["Martin drew inspiration from England's Wars of the Roses (15th century) to create the Stark vs Lannister conflicts.","The first book, 'A Game of Thrones', came out in 1996 — Martin is still working on the final two volumes, awaited by millions of fans.","Martin said Tolkien's characters were too 'black or white' — he wanted morally ambiguous characters like in real history."],
    es:["George R.R. Martin se inspiró en la Guerra de las Rosas inglesa (Lancaster vs York → Lannister vs Stark) y en las intrigas de los Borgia para crear Juego de Tronos.","Martin rompe con las convenciones de la fantasía épica matando a los protagonistas, evitando el maniqueísmo y mostrando las consecuencias políticas reales de la guerra.","Lleva más de 13 años escribiendo Vientos de Invierno (el sexto libro) — la espera se ha convertido en un meme cultural y una fuente de ansiedad para millones de lectores."]
},
'e286': {
  fr:["Herbert a mis six ans à écrire Dune, menant des recherches approfondies sur l'écologie des déserts, la politique et la religion.","Le roman a remporté les deux prix les plus prestigieux de la SF — le Hugo et le Nebula — lors de sa sortie en 1965.","L'épice « mélange » de Dune, ressource qui contrôle l'univers, est une métaphore directe du pétrole et de la géopolitique du Moyen-Orient."],
  en:["Herbert spent six years writing Dune, conducting extensive research on desert ecology, politics, and religion.","The novel won both the most prestigious SF awards — the Hugo and the Nebula — upon its 1965 release.","The 'spice melange' in Dune, a resource controlling the universe, is a direct metaphor for oil and Middle Eastern geopolitics."],
    es:["Frank Herbert envió el manuscrito de Dune a 23 editores antes de que Chilton (una editorial de manuales de automóviles) aceptara publicarlo en 1965.","Dune es la novela de ciencia ficción más vendida de la historia — su exploración de la ecología, la religión, la política y el destino sigue siendo extraordinariamente relevante.","Herbert se inspiró en el programa de estabilización de dunas del Departamento de Agricultura de EE.UU. en Oregón — la ecología de Arrakis nació de un reportaje periodístico."]
},
'e287': {
  fr:["La version chinoise, « Ye Xian » (IXe siècle), met en scène une jeune fille avec un poisson magique au lieu d'une marraine fée.","Charles Perrault a publié la version française la plus célèbre en 1697, avec la citrouille, les souris et la pantoufle de verre.","Les frères Grimm ont publié une version plus sombre en 1812 où les demi-sœurs se coupent les orteils pour entrer dans la pantoufle."],
  en:["The Chinese version, 'Ye Xian' (9th century), features a girl with a magic fish instead of a fairy godmother.","Charles Perrault published the most famous French version in 1697, with the pumpkin, mice, and glass slipper.","The Brothers Grimm published a darker version in 1812 where the stepsisters cut off their toes to fit into the slipper."],
    es:["La versión más antigua documentada de Cenicienta es la china Ye Xian (siglo IX) — más de 500 variantes existen en culturas de todos los continentes.","En la versión de los hermanos Grimm, las hermanastras se mutilan los pies para que les quepa el zapato — una brutalidad eliminada en las versiones modernas.","El zapato de «cristal» (verre) podría ser un error de traducción de Perrault: «vair» (piel de ardilla gris) se pronuncia igual — un debate que dura desde el siglo XIX."]
},
'e288': {
  fr:["Asimov pouvait écrire dans 9 des 10 catégories de la classification décimale de Dewey — seule la catégorie « Philosophie » lui manquait.","Il tapait à une vitesse de 90 mots par minute et écrivait régulièrement 8 heures par jour, 7 jours par semaine.","Ses « Trois lois de la robotique » sont devenues un cadre de réflexion éthique pour les chercheurs en intelligence artificielle réels."],
  en:["Asimov could write in 9 of the 10 Dewey Decimal categories — only 'Philosophy' was missing.","He typed at 90 words per minute and regularly wrote 8 hours a day, 7 days a week.","His 'Three Laws of Robotics' have become an ethical framework for real artificial intelligence researchers."],
    es:["Isaac Asimov publicó más de 500 libros en casi todas las categorías de la clasificación Dewey — el autor más prolífico del siglo XX.","Su ciclo de la Fundación, inspirado en la caída del Imperio Romano, describe una «psicohistoria» capaz de predecir el comportamiento de masas — un concepto que anticipa el big data.","Asimov acuñó los términos «robótica» y «positrónico» y sus Tres Leyes de la Robótica siguen siendo el marco ético más citado en las discusiones sobre inteligencia artificial."]
},
'e289': {
  fr:["Carroll (de son vrai nom Charles Dodgson) était mathématicien et logicien — le chat du Cheshire incarne des paradoxes logiques.","La scène du thé fou est une satire des quaternions mathématiques — un sujet de débat intense à Oxford dans les années 1860.","Alice a été écrit pour Alice Liddell, la fille de 10 ans d'un collègue de Dodgson — la vraie Alice a gardé le manuscrit original toute sa vie."],
  en:["Carroll (real name Charles Dodgson) was a mathematician and logician — the Cheshire Cat embodies logical paradoxes.","The Mad Tea Party scene is a satire of mathematical quaternions — a heated topic at 1860s Oxford.","Alice was written for Alice Liddell, the 10-year-old daughter of Dodgson's colleague — the real Alice kept the original manuscript her whole life."],
    es:["Lewis Carroll (Charles Dodgson) era matemático en Oxford: Alicia está llena de juegos lógicos, paradojas y sátiras del sistema educativo victoriano disfrazadas de absurdo infantil.","La escena del Sombrerero Loco refleja el envenenamiento por mercurio que sufrían los fabricantes de sombreros — «loco como un sombrerero» era una expresión común en la Inglaterra victoriana.","Las adaptaciones de Disney suavizaron el original: el Carroll de 1865 es mucho más extraño, oscuro y filosóficamente inquietante que cualquier versión cinematográfica."]
},
'e290': {
  fr:["Fleming a travaillé dans les services de renseignement de la Royal Navy pendant la guerre — il a planifié des opérations réelles de sabotage et de désinformation.","Le commandant « Biffy » Dunderdale du MI6 et l'agent double Dusko Popov sont parmi les espions qui auraient inspiré le personnage de Bond.","Le nom « James Bond » vient d'un ornithologue américain dont Fleming possédait le livre — il trouvait que ce nom « banal » convenait parfaitement à un espion."],
  en:["Fleming worked in Royal Navy intelligence during the war — he planned real sabotage and disinformation operations.","Commander 'Biffy' Dunderdale of MI6 and double agent Dusko Popov are among the spies who reportedly inspired Bond.","The name 'James Bond' came from an American ornithologist whose book Fleming owned — he found the 'dull' name perfectly suited for a spy."],
    es:["Ian Fleming eligió el nombre «James Bond» del autor de un libro de ornitología del Caribe que tenía en su mesa — quería un nombre lo más anodino y genérico posible para su espía.","Fleming trabajó en la inteligencia naval británica durante la Segunda Guerra Mundial y utilizó sus experiencias para crear los escenarios y personajes de la saga 007.","Bond ha sido interpretado por 7 actores en 25 películas oficiales que han recaudado más de 7 000 millones de dólares — una de las franquicias más duraderas del cine."]
},
'e291': {
  fr:["Dans la version originale de Cendrillon des Grimm, les demi-sœurs se mutilent les pieds et des colombes leur crèvent les yeux lors du mariage.","Blanche-Neige originale voit la belle-mère condamnée à danser dans des chaussures de fer chauffées à blanc jusqu'à en mourir.","Les Grimm ont progressivement adouci les contes pour les rendre adaptés aux enfants à partir de la 2e édition (1819) — la 1re édition (1812) était destinée aux folkloristes."],
  en:["In the Grimms' original Cinderella, the stepsisters mutilate their feet and doves peck out their eyes at the wedding.","The original Snow White sees the stepmother condemned to dance in red-hot iron shoes until she dies.","The Grimms gradually softened the tales for children from the 2nd edition (1819) — the 1st (1812) was intended for folklorists."],
    es:["Los cuentos originales de los Grimm contenían violencia gráfica, canibalismo, mutilación y castigos crueles — fueron suavizados en cada nueva edición entre 1812 y 1857.","En la Cenicienta original, las palomas arrancan los ojos a las hermanastras; en Blancanieves, la madrastra es obligada a bailar con zapatos de hierro al rojo vivo hasta morir.","Walt Disney transformó estos cuentos oscuros en películas familiares, creando las versiones edulcoradas que la mayoría del mundo conoce — pero el mercado del «cuento oscuro original» florece."]
},
'e292': {
  fr:["Auguste Maquet est le collaborateur le plus connu de Dumas — il a co-écrit « Les Trois Mousquetaires » et « Le Comte de Monte-Cristo ».","Dumas a publié environ 100 000 pages au cours de sa vie — un volume de production quasi industriel, même avec des collaborateurs.","Malgré la controverse sur ses co-auteurs, le style flamboyant, les dialogues vifs et la structure narrative restent reconnaissables comme du Dumas pur."],
  en:["Auguste Maquet is Dumas' best-known collaborator — he co-wrote 'The Three Musketeers' and 'The Count of Monte Cristo'.","Dumas published about 100,000 pages in his lifetime — a near-industrial output, even with collaborators.","Despite the controversy over co-authors, the flamboyant style, sharp dialogue, and narrative structure remain unmistakably pure Dumas."],
    es:["Alejandro Dumas empleaba un equipo de colaboradores (nègres littéraires), el más notable siendo Auguste Maquet, quien proporcionó las tramas de Los tres mosqueteros y El conde de Montecristo.","Esta práctica era común y legal en el siglo XIX — Dumas aportaba su estilo, sus diálogos brillantes y su capacidad de transformar tramas en aventuras irresistibles.","Dumas era nieto de una esclava haitiana y sufrió racismo durante toda su vida — Los tres mosqueteros puede leerse como una fantasía de meritocracia donde el talento supera al nacimiento."]
},
'e293': {
  fr:["Le monstre de Frankenstein n'a pas de nom dans le roman — « Frankenstein » est le nom de son créateur, Victor Frankenstein.","Le sous-titre du roman est « Le Prométhée moderne » — une référence au titan grec qui a donné le feu (la connaissance) aux humains et en a payé le prix.","Shelley a exploré des questions que l'IA pose aujourd'hui : la responsabilité du créateur envers sa création et les limites éthiques de la science."],
  en:["Frankenstein's monster has no name in the novel — 'Frankenstein' is the name of its creator, Victor Frankenstein.","The novel's subtitle is 'The Modern Prometheus' — a reference to the Greek Titan who gave fire (knowledge) to humans and paid the price.","Shelley explored questions AI poses today: the creator's responsibility toward their creation and the ethical limits of science."],
    es:["Frankenstein plantea la pregunta central de la biotecnología: ¿tiene el creador responsabilidad moral sobre su creación? Victor Frankenstein abandona al monstruo, desencadenando la tragedia.","La novela fue escrita durante el «año sin verano» de 1816 (causado por la erupción del volcán Tambora) — el clima apocalíptico influyó en la atmósfera gótica de la obra.","Shelley tenía 18 años al comenzar Frankenstein — una de las obras fundacionales de la literatura occidental fue escrita por una adolescente."]
},
'e294': {
  fr:["Le nombre de Shannon estime les positions légales aux échecs à environ 10^44 — le nombre d'atomes dans l'univers observable est d'environ 10^80.","Le nombre total de parties d'échecs possibles est encore plus vertigineux : estimé à 10^120, appelé le « nombre de Shannon game-tree ».","Malgré cette complexité, le moteur Stockfish et AlphaZero jouent à un niveau qui dépasse tout joueur humain — mais n'ont exploré qu'une fraction infime des possibilités."],
  en:["The Shannon number estimates legal chess positions at about 10^44 — the number of atoms in the observable universe is about 10^80.","The total number of possible chess games is even more staggering: estimated at 10^120, called the 'Shannon game-tree number'.","Despite this complexity, engines Stockfish and AlphaZero play beyond any human level — yet have explored only a tiny fraction of possibilities."],
    es:["El número de partidas de ajedrez posibles (10^120, número de Shannon) supera el número de átomos en el universo observable (10^80) — una complejidad que ningún ordenador puede explorar exhaustivamente.","Deep Blue de IBM venció al campeón mundial Garry Kasparov en 1997, pero los programas modernos como Stockfish y AlphaZero son millones de veces más potentes.","AlphaZero (Google DeepMind) aprendió a jugar al ajedrez en solo 4 horas partiendo de cero — y derrotó al programa más fuerte del mundo con un estilo creativo que asombró a los grandes maestros."]
},
'e295': {
  fr:["Pajitnov n'a perçu aucun revenu de Tetris pendant des années — les droits appartenaient à l'État soviétique jusqu'à la chute de l'URSS.","Tetris est basé sur les pentominos, un puzzle mathématique utilisant des formes composées de cinq carrés — Pajitnov l'a simplifié à quatre (d'où « tetr- »).","Tetris est le jeu vidéo le plus vendu de tous les temps avec plus de 520 millions d'exemplaires sur toutes plateformes."],
  en:["Pajitnov received no income from Tetris for years — the rights belonged to the Soviet state until the fall of the USSR.","Tetris is based on pentominoes, a mathematical puzzle using shapes made of five squares — Pajitnov simplified it to four (hence 'tetr-').","Tetris is the best-selling video game of all time with over 520 million copies across all platforms."],
    es:["Alexei Pajitnov creó Tetris en un ordenador Elektronika 60 en la Academia de Ciencias de Moscú — el gobierno soviético se quedó con los derechos durante años.","La batalla por los derechos de Tetris involucró a la URSS, Nintendo, Atari, Maxwell Communications y el KGB — una historia digna de una novela de espías de la Guerra Fría.","Estudios científicos demuestran que jugar a Tetris reduce los flashbacks de estrés postraumático y las ansias de adicción — el «efecto Tetris» es un fenómeno psicológico documentado."]
},
'e296': {
  fr:["Le nombre de positions légales au go est estimé à 2,08 × 10^170 — incomparablement plus que les échecs (10^44).","AlphaGo de Google DeepMind a battu le champion mondial Lee Sedol en 2016 — un événement considéré comme un tournant majeur de l'intelligence artificielle.","Le go est joué depuis plus de 4 000 ans en Chine — c'est l'un des plus anciens jeux de stratégie encore pratiqué aujourd'hui."],
  en:["The number of legal go positions is estimated at 2.08 × 10^170 — incomparably more than chess (10^44).","Google DeepMind's AlphaGo defeated world champion Lee Sedol in 2016 — an event considered a major AI turning point.","Go has been played for over 4,000 years in China — it's one of the oldest strategy games still played today."],
    es:["El número de posiciones legales en el go es de 2,08 × 10^170 — incomparablemente mayor que en el ajedrez, lo que lo convierte en el juego de tablero más complejo conocido.","AlphaGo de Google DeepMind venció al campeón mundial Lee Sedol en 2016 con un movimiento (jugada 37, partida 2) que ningún humano habría concebido — un hito de la inteligencia artificial.","El go tiene más de 4 000 años de historia y es uno de los cuatro artes clásicos del caballero chino (junto con la caligrafía, la pintura y la música)."]
},
'e297': {
  fr:["Le nom original de Pac-Man était « Puck-Man » (de « paku-paku », onomatopée japonaise pour manger) — changé pour l'export car trop facile à vandaliser en anglais.","Pac-Man a généré plus de 2,5 milliards de dollars en pièces de monnaie dans les salles d'arcade dans les années 1980.","Le niveau 256 de Pac-Man original contient un bug célèbre : la moitié droite de l'écran se transforme en charabia de caractères — appelé le « kill screen »."],
  en:["Pac-Man's original name was 'Puck-Man' (from 'paku-paku', Japanese onomatopoeia for eating) — changed for export because it was too easy to vandalise in English.","Pac-Man generated over $2.5 billion in coins in arcade halls during the 1980s.","Level 256 of the original Pac-Man contains a famous bug: the right half of the screen turns into character gibberish — called the 'kill screen'."],
    es:["Toru Iwatani diseñó Pac-Man para atraer a las mujeres a las salas de arcade, dominadas por juegos de guerra — la forma redonda y los colores suaves eran deliberadamente no agresivos.","Los cuatro fantasmas tienen personalidades programadas: Blinky persigue directamente, Pinky embosca por delante, Inky es impredecible y Clyde huye cuando está cerca.","Pac-Man generó más de 2 500 millones de dólares en monedas en los años 80 y fue el primer personaje de videojuego en tener merchandising, una canción pop y una serie de televisión."]
},
'e298': {
  fr:["Computer Space a été créé par Nolan Bushnell et Ted Dabney — les mêmes qui fonderont Atari un an plus tard.","La borne avait un design futuriste en fibre de verre moulé — elle apparaît brièvement dans le film « Soylent Green » (1973).","Computer Space a été un semi-échec commercial car les joueurs trouvaient les commandes trop complexes — Pong a été créé comme version simplifiée."],
  en:["Computer Space was created by Nolan Bushnell and Ted Dabney — the same duo who would found Atari a year later.","The cabinet had a futuristic moulded fibreglass design — it briefly appears in the film 'Soylent Green' (1973).","Computer Space was a commercial semi-failure as players found the controls too complex — Pong was created as a simplified version."],
    es:["Computer Space (1971) fue creado por Nolan Bushnell y Ted Dabney antes de fundar Atari — su carcasa futurista era tan llamativa que apareció en la película Soylent Green (1973).","El juego fue un fracaso comercial porque era demasiado complejo para los bares — Bushnell aprendió la lección y creó Pong (1972), mucho más simple e intuitivo.","La simplicidad de Pong demostró un principio que sigue vigente: los mejores juegos tienen reglas que se entienden en segundos pero requieren años para dominar."]
},
'e299': {
  fr:["Le stick analogique de la N64 a révolutionné le contrôle 3D — Super Mario 64 a été le premier jeu à en exploiter pleinement le potentiel.","La forme à trois branches de la manette N64 était controversée car il était physiquement impossible d'atteindre les trois poignées simultanément.","Le Rumble Pak de la N64 (1997) a été le premier accessoire de vibration pour console — un retour haptique devenu standard sur toutes les manettes modernes."],
  en:["The N64's analogue stick revolutionised 3D control — Super Mario 64 was the first game to fully exploit its potential.","The N64 controller's three-pronged shape was controversial because it was physically impossible to reach all three grips simultaneously.","The N64 Rumble Pak (1997) was the first console vibration accessory — haptic feedback that became standard on all modern controllers."],
    es:["La Nintendo 64 (1996) introdujo el stick analógico como estándar en las consolas — antes, el control se limitaba a la cruceta digital (D-pad) de 8 direcciones.","Super Mario 64 fue el primer juego en demostrar las posibilidades del control analógico en 3D: la precisión del movimiento era revolucionaria para la época.","El botón Z trasero (trigger) de la N64 fue precursor de los gatillos analógicos de PlayStation 2, Xbox y todas las consolas modernas."]
},
'e300': {
  fr:["Spacewar! a été créé par Steve Russell, Martin Graetz et Wayne Wiitanen sur un ordinateur PDP-1 qui coûtait 120 000 dollars.","Le jeu mettait en scène deux vaisseaux spatiaux en combat autour d'une étoile dont la gravité influençait les trajectoires — une physique impressionnante pour 1962.","Spacewar! a directement inspiré la première borne d'arcade commerciale : « Computer Space » de Bushnell en 1971."],
  en:["Spacewar! was created by Steve Russell, Martin Graetz, and Wayne Wiitanen on a PDP-1 computer that cost $120,000.","The game featured two spaceships fighting around a star whose gravity influenced trajectories — impressive physics for 1962.","Spacewar! directly inspired the first commercial arcade cabinet: Bushnell's 'Computer Space' in 1971."],
    es:["Spacewar! fue programado por Steve Russell y otros estudiantes del MIT en un PDP-1 que costaba 120 000 dólares — el juego se distribuyó gratis a otras universidades con PDP-1.","El juego inspiró directamente a Nolan Bushnell, que creó Computer Space (1971) y luego Pong (1972) — Spacewar! es el abuelo de toda la industria del videojuego.","Spacewar! incluía gravedad realista de una estrella central, inercia y munición limitada — un diseño sorprendentemente sofisticado para 1962."]
},
'e301': {
  fr:["Robinett a caché son nom dans une salle secrète du jeu car Atari refusait de créditer les développeurs — un acte de rébellion créative.","L'Easter egg d'Adventure est une simple pièce affichant « Created by Warren Robinett » — mais sa découverte a lancé une tradition dans toute l'industrie.","Les Easter eggs sont devenus une culture à part entière : des films, logiciels et sites web en cachent régulièrement."],
  en:["Robinett hid his name in a secret room because Atari refused to credit developers — an act of creative rebellion.","Adventure's Easter egg is a simple room displaying 'Created by Warren Robinett' — but its discovery launched an industry-wide tradition.","Easter eggs have become a culture of their own: films, software, and websites regularly hide them."],
    es:["Warren Robinett escondió un mensaje secreto («Created by Warren Robinett») en Adventure (1979) porque Atari no acreditaba a sus programadores.","Cuando un jugador descubrió el secreto, Atari decidió mantenerlo y animar a los programadores a incluir más — naciendo la tradición de los Easter eggs en los videojuegos.","El término «Easter egg» digital se ha extendido más allá de los videojuegos: Google, Apple, Tesla y muchos programas contienen secretos ocultos para los usuarios curiosos."]
},
'e302': {
  fr:["Mario a été renommé d'après Mario Segale, le propriétaire de l'entrepôt que louait Nintendo of America — qui aurait fait irruption pour réclamer le loyer en retard.","Shigeru Miyamoto a créé Mario avec des contraintes graphiques : la casquette cachait les cheveux, la moustache évitait de dessiner une bouche détaillée.","Mario est apparu dans plus de 200 jeux et est le personnage de jeu vidéo le plus reconnaissable au monde."],
  en:["Mario was renamed after Mario Segale, the landlord of Nintendo of America's warehouse — who reportedly barged in demanding late rent.","Shigeru Miyamoto designed Mario around graphical constraints: the cap hid hair, the moustache avoided drawing a detailed mouth.","Mario has appeared in over 200 games and is the most recognisable video game character in the world."],
    es:["Jumpman (futuro Mario) fue diseñado por Shigeru Miyamoto con gorra porque dibujar pelo era difícil, bigote porque una boca era imposible con los píxeles disponibles, y overol porque facilitaba la animación de los brazos.","El nombre «Mario» fue adoptado del propietario del almacén de Nintendo of America, Mario Segale, que se presentó exigiendo el alquiler atrasado durante una reunión.","Mario ha aparecido en más de 200 juegos y ha vendido más de 800 millones de copias — es el personaje de videojuego más reconocido y lucrativo de la historia."]
},
'e303': {
  fr:["Les speedrunners exploitent des glitchs comme le « flagpole glitch » et le « wrong warp » pour sauter des niveaux entiers.","Le record du monde est régulièrement battu par des fractions de seconde — la compétition se joue au centième de seconde près.","Le speedrun « tool-assisted » (TAS), réalisé image par image par un programme, peut finir le jeu en moins de 5 minutes avec une précision surhumaine."],
  en:["Speedrunners exploit glitches like the 'flagpole glitch' and 'wrong warp' to skip entire levels.","The world record is regularly broken by fractions of a second — the competition plays out to the hundredth of a second.","Tool-assisted speedruns (TAS), performed frame by frame by a program, can finish the game in under 5 minutes with superhuman precision."],
    es:["Los speedrunners explotan glitches, bugs y atajos no previstos por los desarrolladores para completar juegos en fracciones del tiempo normal — Super Mario Bros se completa en menos de 5 minutos.","La comunidad de speedrunning tiene reglas estrictas: las categorías «any%» permiten atajos, «100%» exigen completar todo el contenido y «glitchless» prohíben los bugs.","Games Done Quick, el mayor evento de speedrunning, recauda millones de dólares para obras benéficas — un ejemplo de cómo la cultura gamer puede generar un impacto social positivo."]
},
'e304': {
  fr:["La franchise Pokémon a généré plus de 100 milliards de dollars de revenus depuis 1996 — en jeux, cartes, jouets, films et produits dérivés.","Pikachu, la mascotte, n'était pas le premier choix de Game Freak — c'est l'anime qui l'a rendu populaire et en a fait le visage de la franchise.","Pokémon Rouge et Bleu (1996) ont été développés par seulement 4 programmeurs chez Game Freak — un budget minuscule pour un phénomène mondial."],
  en:["The Pokémon franchise has generated over $100 billion in revenue since 1996 — from games, cards, toys, films, and merchandise.","Pikachu, the mascot, wasn't Game Freak's first choice — the anime made it popular and turned it into the franchise's face.","Pokémon Red and Blue (1996) were developed by just 4 programmers at Game Freak — a tiny budget for a global phenomenon."],
    es:["Pokémon es la franquicia de entretenimiento más lucrativa del mundo con más de 100 000 millones de dólares generados — por delante de Hello Kitty, Star Wars y Marvel.","Satoshi Tajiri creó Pokémon inspirándose en su infancia coleccionando insectos en los campos de Machida (Tokio) — la mecánica de captura y colección nació de esa pasión.","Pokémon GO (2016) generó un fenómeno social: millones de personas salieron a la calle a capturar Pokémon virtuales, y la app generó más de 6 000 millones de dólares en ingresos."]
},
'e305': {
  fr:["Les dés romains en os (tali) étaient souvent pipés — des dés truqués ont été retrouvés dans les ruines de Pompéi.","Les dés cubiques à six faces standardisés (avec les faces opposées totalisant 7) sont apparus en Chine vers 600 av. J.-C.","Le dé à 20 faces (d20) utilisé dans les jeux de rôle existe depuis l'Antiquité — des icosaèdres en verre ont été retrouvés en Égypte ptolémaïque."],
  en:["Roman bone dice (tali) were often loaded — rigged dice have been found in the ruins of Pompeii.","Standardised six-sided cubic dice (with opposite faces totalling 7) appeared in China around 600 BC.","The 20-sided die (d20) used in role-playing games has existed since antiquity — glass icosahedra were found in Ptolemaic Egypt."],
    es:["Los dados más antiguos conocidos datan de hace 5 000 años: tallados en hueso de oveja (astrágalos), se usaban en Mesopotamia y Egipto para la adivinación y el juego.","Los dados cúbicos con puntos (pips) aparecieron hacia el 2000 a.C. — la evolución de los dados refleja el desarrollo del concepto humano de azar y probabilidad.","Los casinos modernos usan dados de precisión (±0,0005 cm) fabricados con celulosa transparente para evitar cualquier desequilibrio — la aleatoriedad es un negocio serio."]
},
'e306': {
  fr:["L'industrie du jeu vidéo a généré environ 200 milliards de dollars en 2023 — contre 100 milliards pour le cinéma et 30 milliards pour la musique.","Le jeu mobile représente à lui seul plus de 50 % du marché — grâce à l'essor des smartphones dans les pays en développement.","L'esport est devenu un phénomène mondial : les finales de League of Legends attirent plus de spectateurs que le Super Bowl."],
  en:["The video game industry generated about $200 billion in 2023 — versus $100 billion for cinema and $30 billion for music.","Mobile gaming alone represents over 50% of the market — thanks to smartphone growth in developing countries.","Esports has become a global phenomenon: League of Legends finals draw more viewers than the Super Bowl."],
    es:["La industria del videojuego genera más de 180 000 millones de dólares anuales — más que el cine (100 000 M$) y la música (26 000 M$) combinados.","Los juegos móviles representan más del 50 % de los ingresos — Candy Crush, Genshin Impact y PUBG Mobile dominan un mercado de 3 000 millones de jugadores.","La edad media del jugador es de 35 años y el 48 % son mujeres — la imagen del gamer adolescente masculino es un estereotipo obsoleto."]
},
'e307': {
  fr:["Will Wright, le créateur des Sims, s'est inspiré de l'architecture et de la psychologie comportementale pour concevoir le jeu.","Les Sims est l'une des rares franchises de jeu où les joueuses représentent plus de 60 % du public — un cas unique dans l'industrie à l'époque.","Le « Simlish », la langue fictive des Sims, a été créé pour éviter les coûts de localisation — des artistes comme Katy Perry ont enregistré des chansons en Simlish."],
  en:["Will Wright, the creator of The Sims, drew on architecture and behavioural psychology to design the game.","The Sims is one of the rare game franchises where female players represent over 60% of the audience — unique in the industry at the time.","'Simlish', The Sims' fictional language, was created to avoid localisation costs — artists like Katy Perry recorded songs in Simlish."],
    es:["Will Wright presentó The Sims como simulador de arquitectura: Electronic Arts rechazó el concepto tres veces antes de aceptar publicarlo en 2000.","El juego vendió más de 200 millones de copias en toda la franquicia — demostró que la simulación de la vida cotidiana podía ser tan atractiva como la acción o la guerra.","The Sims popularizó el simlish, un idioma inventado que artistas reales (Katy Perry, The Black Eyed Peas, Lily Allen) han grabado en versiones exclusivas para el juego."]
},
'e308': {
  fr:["Minecraft a été créé par Markus « Notch » Persson en 2009 comme un projet solo — il l'a vendu à Microsoft en 2014 pour 2,5 milliards de dollars.","Le monde de Minecraft fait 8 fois la surface de la Terre — théoriquement, on peut marcher pendant des années sans atteindre les limites.","Minecraft est utilisé dans des écoles du monde entier pour enseigner la géologie, l'architecture, la programmation et même la chimie."],
  en:["Minecraft was created by Markus 'Notch' Persson in 2009 as a solo project — he sold it to Microsoft in 2014 for $2.5 billion.","Minecraft's world is 8 times the surface area of Earth — theoretically, you could walk for years without reaching the limits.","Minecraft is used in schools worldwide to teach geology, architecture, programming, and even chemistry."],
    es:["Minecraft fue creado por Markus «Notch» Persson en un fin de semana de 2009, inspirándose en Dwarf Fortress, Infiniminer y los bloques LEGO de su infancia.","Microsoft compró Mojang (y Minecraft) en 2014 por 2 500 millones de dólares — hoy el juego se utiliza en más de 10 000 escuelas como herramienta educativa.","La generación procedimental de mundos de Minecraft crea universos de 60 millones de bloques de lado — 8 veces la superficie de la Tierra."]
},
'e309': {
  fr:["Les règles exactes du Senet restent débattues par les historiens — les reconstitutions modernes sont basées sur des textes fragmentaires et des représentations picturales.","Le Senet avait probablement une dimension spirituelle : il symbolisait le voyage de l'âme vers l'au-delà dans la mythologie égyptienne.","Le jeu royal d'Ur, un autre jeu ancien (2600 av. J.-C.), a été reconstitué grâce à une tablette cunéiforme contenant ses règles complètes."],
  en:["Senet's exact rules are still debated by historians — modern reconstructions are based on fragmentary texts and pictorial depictions.","Senet likely had a spiritual dimension: it symbolised the soul's journey to the afterlife in Egyptian mythology.","The Royal Game of Ur, another ancient game (2600 BC), was reconstructed thanks to a cuneiform tablet containing its full rules."],
    es:["Senet, el juego de mesa más antiguo documentado (3100 a.C.), se encontró en tumbas egipcias con las reglas inscritas en los tableros — se jugaba como rito funerario.","Los egipcios creían que ganar al Senet garantizaba un paso seguro al más allá — los difuntos eran enterrados con tableros para jugar contra los dioses.","Las reglas exactas del Senet se perdieron y fueron reconstruidas por el historiador Timothy Kendall en los años 1970 a partir de textos fragmentarios y representaciones artísticas."]
},
'e310': {
  fr:["Gygax et Arneson ont développé D&D à partir de « Chainmail », un jeu de simulation de batailles médiévales avec des éléments fantastiques.","D&D a introduit des concepts devenus universels dans le jeu vidéo : points d'expérience, classes de personnages, niveaux et quêtes.","La « panique satanique » des années 1980 a accusé D&D de promouvoir l'occultisme — une controverse infondée qui a paradoxalement augmenté sa notoriété."],
  en:["Gygax and Arneson developed D&D from 'Chainmail', a medieval battle simulation game with fantasy elements.","D&D introduced concepts now universal in video gaming: experience points, character classes, levels, and quests.","The 'Satanic Panic' of the 1980s accused D&D of promoting occultism — a baseless controversy that paradoxically boosted its fame."],
    es:["Gary Gygax y Dave Arneson crearon D&D combinando wargames miniaturistas con la narrativa de ficción fantástica — cada jugador controlaba un personaje individual, no un ejército.","D&D popularizó conceptos ahora universales: puntos de vida, niveles de experiencia, clases de personaje y dados poliédricos — la base de prácticamente todos los RPG modernos.","La «Scare Pánique Satánica» de los años 1980 acusó a D&D de promover el satanismo y el suicidio — investigaciones posteriores demostraron que estas acusaciones eran infundadas."]
},
'e311': {
  fr:["Le design de difficulté croissante des jeux d'arcade était calculé pour que le joueur moyen survive environ 3 minutes par pièce.","Cette économie de la « mort rentable » a généré des milliards — l'industrie arcade américaine pesait 8 milliards de dollars en 1982, plus que Hollywood.","La transition vers les consoles domestiques dans les années 1990 a détruit le modèle économique de l'arcade — remplacé par l'achat unique de jeux."],
  en:["Arcade difficulty curves were calculated so the average player survived about 3 minutes per coin.","This 'profitable death' economy generated billions — the US arcade industry was worth $8 billion in 1982, more than Hollywood.","The shift to home consoles in the 1990s destroyed the arcade business model — replaced by one-time game purchases."],
    es:["Las máquinas arcade de los años 1980 estaban diseñadas para que el jugador muriera rápidamente y metiera más monedas — la dificultad era un modelo de negocio, no una filosofía de diseño.","La curva de dificultad escalaba exponencialmente: cada nivel era más rápido y más impredecible, garantizando que incluso los mejores jugadores fueran derrotados en minutos.","Cuando los videojuegos pasaron al hogar (consolas, PC), la dificultad disminuyó porque el modelo de negocio cambió: venta única, no monedas continuas."]
},
'e312': {
  fr:["Games Done Quick, le plus grand marathon caritatif de speedrun, a collecté plus de 50 millions de dollars pour des associations depuis 2010.","Le speedrun de « The Legend of Zelda: Ocarina of Time » est passé de plus de 5 heures à moins de 7 minutes grâce à la découverte de glitchs.","Certains speedrunners s'entraînent plus de 8 heures par jour pour gagner une fraction de seconde — un niveau de dévouement comparable aux athlètes olympiques."],
  en:["Games Done Quick, the largest speedrun charity marathon, has raised over $50 million for charities since 2010.","The 'Legend of Zelda: Ocarina of Time' speedrun dropped from over 5 hours to under 7 minutes through glitch discoveries.","Some speedrunners train over 8 hours a day to shave off a fraction of a second — dedication comparable to Olympic athletes."],
    es:["El speedrunning se convirtió en una comunidad organizada con la creación de Speed Demos Archive en 1998 y el lanzamiento de Twin Galaxies para registros oficiales.","Games Done Quick ha recaudado más de 50 millones de dólares para organizaciones benéficas como Médecins Sans Frontières y la Prevent Cancer Foundation.","Los speedruns de juegos como Dark Souls, que normalmente requieren 40-60 horas, se completan en menos de 25 minutos — una demostración de destreza y conocimiento enciclopédico."]
},
'e313': {
  fr:["La Game Boy utilisait un écran LCD sans rétroéclairage — un choix délibéré de Gunpei Yokoi pour maximiser l'autonomie aux dépens de la qualité graphique.","Plus de 118 millions de Game Boy et Game Boy Color ont été vendues — un succès phénoménal qui a lancé le marché du jeu portable.","Tetris, le jeu inclus avec la Game Boy, est largement crédité comme la raison principale de son succès — le duo console/jeu était irrésistible."],
  en:["The Game Boy used a non-backlit LCD screen — a deliberate choice by Gunpei Yokoi to maximise battery life over graphics quality.","Over 118 million Game Boy and Game Boy Color units were sold — a phenomenal success that launched the portable gaming market.","Tetris, bundled with the Game Boy, is widely credited as the main reason for its success — the console/game duo was irresistible."],
    es:["La Game Boy utilizaba un procesador Sharp LR35902 a solo 4,19 MHz con una pantalla monocroma de 160×144 píxeles — pero su autonomía de 30 horas la hizo imbatible frente a competidores más potentes.","La estrategia de Nintendo fue priorizar la duración de la batería y la robustez sobre los gráficos — una filosofía de diseño que se repetiría con la DS y la Switch.","Un soldado estadounidense sobrevivió a un bombardeo durante la Guerra del Golfo con su Game Boy quemada pero funcional — se exhibe en la Nintendo World Store de Nueva York."]
},
'e314': {
  fr:["Le terme « newbie » est apparu dans l'argot militaire américain dans les années 1960 pour désigner les nouvelles recrues au Vietnam.","« Noob » s'est répandu dans les forums en ligne et les jeux multijoueurs dans les années 1990 avec l'essor d'Internet.","Il existe une distinction dans la culture gaming : « newbie » désigne un débutant qui apprend, tandis que « noob » implique quelqu'un qui ne fait pas d'effort pour progresser."],
  en:["The term 'newbie' appeared in US military slang in the 1960s for new recruits in Vietnam.","'Noob' spread through online forums and multiplayer games in the 1990s with the rise of the Internet.","There's a gaming culture distinction: 'newbie' refers to a beginner who's learning, while 'noob' implies someone who makes no effort to improve."],
    es:["«Noob» (novato) viene del argot militar «newbie», usado desde la Segunda Guerra Mundial para referirse a los soldados recién llegados al frente.","En los juegos online, el término evolucionó de descriptivo (nuevo jugador) a peyorativo (jugador incompetente) — la cultura gamer tiene su propio ecosistema lingüístico.","Otros términos gamers que han pasado al lenguaje cotidiano: «lag» (retraso), «respawn» (reinicio), «GG» (good game, buen juego) y «AFK» (away from keyboard, ausente)."]
},
'e315': {
  fr:["Les frères Lumière ont filmé cette scène à Lyon le 19 mars 1895 — les spectateurs de la première projection auraient paniqué en voyant un train arriver vers eux.","La légende de la panique est probablement exagérée, mais les premières projections ont bel et bien choqué un public qui n'avait jamais vu d'images en mouvement.","Les Lumière pensaient que le cinéma était « une invention sans avenir » — ils ont cessé de produire des films dès 1905 pour se concentrer sur la photographie couleur."],
  en:["The Lumière brothers filmed this scene in Lyon on 19 March 1895 — first-screening viewers supposedly panicked seeing a train coming toward them.","The panic legend is probably exaggerated, but early screenings did genuinely shock audiences who had never seen moving images.","The Lumières thought cinema was 'an invention with no future' — they stopped making films by 1905 to focus on colour photography."],
    es:["La sortie de l'usine Lumière duró 46 segundos y mostraba a los obreros saliendo de la fábrica Lumière en Lyon — una escena cotidiana que inauguró una revolución cultural.","Los Lumière organizaron la primera proyección pública de pago el 28 de diciembre de 1895 en el Grand Café de París — 33 espectadores pagaron 1 franco cada uno.","Auguste Lumière declaró que el cine era «una invención sin porvenir» — una de las peores predicciones tecnológicas de la historia."]
},
'e316': {
  fr:["Chaplin composait ses musiques en fredonnant les mélodies à un arrangeur — il ne savait pas lire les partitions.","Il a reçu un Oscar honorifique en 1972 avec la plus longue standing ovation de l'histoire des Oscars — 12 minutes d'applaudissements.","Chaplin a été banni des États-Unis en 1952 pendant le maccarthysme en raison de ses opinions politiques jugées trop à gauche."],
  en:["Chaplin composed his music by humming melodies to an arranger — he couldn't read musical notation.","He received an Honorary Oscar in 1972 with the longest standing ovation in Oscar history — 12 minutes of applause.","Chaplin was banned from the US in 1952 during McCarthyism due to his political views deemed too left-wing."],
    es:["Chaplin era un multiinstrumentista autodidacta que componía la música de todas sus películas, tocando violín, violonchelo y órgano — su partitura para Luces de la ciudad es considerada una obra maestra.","Nacido en la pobreza extrema en Londres, Chaplin se convirtió en la primera estrella mundial del cine — su vagabundo (The Tramp) es uno de los personajes más universalmente reconocidos.","Chaplin fue expulsado de EE.UU. en 1952 durante el macartismo por supuestas simpatías comunistas — no regresó hasta 1972 para recibir un Oscar honorífico."]
},
'e317': {
  fr:["Linklater a tourné quelques jours chaque année avec les mêmes acteurs, dont Ellar Coltrane (Mason) qui avait 6 ans au début et 18 à la fin.","Le film a été nommé pour 6 Oscars — Patricia Arquette a remporté celui de la meilleure actrice dans un second rôle.","Le concept de tourner sur 12 ans était un risque énorme : si un acteur quittait le projet ou si le financement s'arrêtait, le film aurait été perdu."],
  en:["Linklater filmed a few days each year with the same cast, including Ellar Coltrane (Mason) who was 6 at the start and 18 at the end.","The film was nominated for 6 Oscars — Patricia Arquette won Best Supporting Actress.","Filming over 12 years was a huge risk: if an actor left or funding stopped, the film would have been lost."],
    es:["Richard Linklater filmó Boyhood durante 12 años con los mismos actores, capturando el envejecimiento real del protagonista Mason (Ellar Coltrane) de los 6 a los 18 años.","No hubo guion completo al inicio: Linklater escribía cada año en función de la evolución real de los actores y de los eventos contemporáneos — un proceso orgánico único.","La película fue nominada a 6 premios Oscar y ganó el de Mejor Actriz de Reparto (Patricia Arquette) — un logro extraordinario para un proyecto de producción tan poco convencional."]
},
'e318': {
  fr:["John Williams a composé la musique de Star Wars en s'inspirant des compositeurs romantiques du XIXe siècle, notamment Wagner et son usage du leitmotiv.","Chaque personnage ou thème a son propre leitmotiv : la Marche impériale pour Dark Vador, le thème de la Force pour Luke.","Williams a remporté l'Oscar de la meilleure musique originale pour Star Wars en 1978 — le premier de ses 5 Oscars, sur 54 nominations au total."],
  en:["John Williams composed Star Wars music drawing on 19th-century Romantic composers, notably Wagner and his use of leitmotifs.","Each character or theme has its own leitmotif: the Imperial March for Darth Vader, the Force Theme for Luke.","Williams won the Best Original Score Oscar for Star Wars in 1978 — the first of his 5 Oscars, from 54 total nominations."],
    es:["John Williams compuso la partitura de Star Wars en apenas dos semanas, dirigiendo la London Symphony Orchestra — la banda sonora se convirtió en el álbum instrumental más vendido de la historia.","Williams ha compuesto las bandas sonoras de más de 100 películas, incluyendo Jaws, Indiana Jones, E.T., Jurassic Park, Harry Potter y Schindler's List — ha ganado 5 premios Oscar.","El leitmotiv (tema musical asociado a un personaje) es la técnica central de Williams: el tema de Darth Vader, la marcha imperial, es instantáneamente reconocible en todo el mundo."]
},
'e319': {
  fr:["La scène des 127 prises était celle de Shelley Duvall montant l'escalier avec une batte de baseball — Duvall a décrit le tournage comme le plus difficile de sa vie.","Kubrick faisait parfois 70 à 80 prises même pour des plans simples — sa perfectionnisme terrorisait et épuisait régulièrement ses acteurs.","Malgré un accueil critique mitigé à sa sortie (1980), The Shining est aujourd'hui considéré comme l'un des meilleurs films d'horreur de l'histoire."],
  en:["The 127-take scene was Shelley Duvall climbing the stairs with a baseball bat — Duvall described the shoot as the hardest of her life.","Kubrick sometimes did 70 to 80 takes even for simple shots — his perfectionism regularly terrified and exhausted his actors.","Despite mixed reviews at release (1980), The Shining is now considered one of the greatest horror films in history."],
    es:["Kubrick exigía decenas de tomas de cada escena: en El resplandor, Shelley Duvall filmó la escena del bate de béisbol 127 veces, un récord que la dejó al borde del colapso.","Su perfeccionismo era legendario: controlaba cada detalle, desde la iluminación hasta el vestuario, pasando por la temperatura del set y la elección de la música.","2001: Una odisea del espacio (1968) fue tan adelantada a su tiempo que Kubrick consultó a la NASA para diseñar los interiores de la nave — los efectos especiales siguen siendo impresionantes hoy."]
},
'e320': {
  fr:["Les premiers Oscars ne récompensaient que 12 catégories — aujourd'hui il y en a plus de 20.","Les gagnants étaient annoncés trois mois avant la cérémonie — le système des enveloppes scellées n'a été introduit qu'en 1941.","La statuette Oscar pèse 3,85 kg et mesure 34 cm — elle est plaquée or 24 carats sur un socle en métal."],
  en:["The first Oscars only awarded 12 categories — today there are over 20.","Winners were announced three months before the ceremony — the sealed envelope system wasn't introduced until 1941.","The Oscar statuette weighs 3.85 kg and stands 34 cm tall — it's plated in 24-karat gold on a metal base."],
    es:["La primera ceremonia de los Oscar (16 de mayo de 1929) tuvo 270 invitados, los ganadores se conocían de antemano y la cena costó 5 dólares por persona.","La estatuilla fue diseñada por Cedric Gibbons y mide 34 cm: un caballero de pie sobre un rollo de película con una espada — su nombre oficial es «Academy Award of Merit».","El récord de Oscars por una película es de 11, compartido por Ben-Hur (1959), Titanic (1997) y El retorno del Rey (2003)."]
},
'e321': {
  fr:["Avatar a rapporté plus de 2,9 milliards de dollars au box-office mondial — un record battu temporairement par Avengers: Endgame avant qu'une re-sortie en Chine ne redonne la première place à Avatar.","Cameron a développé une technologie de capture de mouvement et de caméras 3D spécialement pour le film — un travail de R&D qui a duré plus de 10 ans.","La langue Na'vi parlée dans le film a été créée par le linguiste Paul Frommer — elle possède un vocabulaire de plus de 2 600 mots."],
  en:["Avatar grossed over $2.9 billion worldwide — a record temporarily beaten by Avengers: Endgame before a Chinese re-release restored Avatar to first place.","Cameron developed motion-capture technology and 3D cameras specifically for the film — R&D work spanning over 10 years.","The Na'vi language spoken in the film was created by linguist Paul Frommer — it has a vocabulary of over 2,600 words."],
    es:["Avatar fue la primera película en superar los 2 000 millones de dólares en taquilla — Cameron desarrolló nueva tecnología de captura de movimiento y proyección 3D estereoscópica.","El mundo de Pandora fue inspirado por ecosistemas bioluminiscentes reales — la película generó un fenómeno llamado «depresión post-Avatar» entre espectadores que querían vivir en ese mundo.","Cameron esperó 12 años entre Titanic y Avatar para que la tecnología estuviera a la altura de su visión — y otros 13 años para Avatar 2."]
},
'e322': {
  fr:["Kubrick a utilisé un objectif Zeiss conçu pour la NASA pour filmer des scènes à la lumière de bougies dans « Barry Lyndon » — sa quête de réalisme était obsessionnelle.","Les effets de « 2001 » ont été réalisés sans ordinateur : maquettes, projections frontales et centrifugeuses réelles ont créé l'illusion de l'apesanteur.","Le film a remporté l'Oscar des meilleurs effets visuels en 1969 — la seule récompense de l'Académie pour Kubrick dans toute sa carrière."],
  en:["Kubrick used a Zeiss lens designed for NASA to film candlelit scenes in 'Barry Lyndon' — his pursuit of realism was obsessive.","The effects in '2001' were achieved without computers: models, front projection, and real centrifuges created the illusion of weightlessness.","The film won the Best Visual Effects Oscar in 1969 — the only Academy Award Kubrick ever received in his career."],
    es:["Kubrick consultó a expertos de la NASA y empresas aeroespaciales para diseñar los interiores de la estación espacial de 2001 — el resultado fue tan realista que algunos creyeron que era un documental.","La secuencia del Star Gate fue creada con la técnica slit-scan inventada por Douglas Trumbull — un efecto fotoquímico que no usaba ordenadores.","Kubrick destruyó deliberadamente todos los decorados y accesorios después del rodaje para que no pudieran reutilizarse — un perfeccionismo que llegaba más allá de la pantalla."]
},
'e323': {
  fr:["Le budget de Metropolis était de 5 millions de Reichsmarks — un montant astronomique qui a mis le studio UFA au bord de la faillite.","Le film a utilisé plus de 37 000 figurants et des décors gigantesques représentant une ville dystopique du futur.","Le robot « Maria » de Metropolis est l'une des premières représentations d'androïde au cinéma — son design a influencé C-3PO dans Star Wars."],
  en:["Metropolis' budget was 5 million Reichsmarks — an astronomical sum that drove studio UFA to the brink of bankruptcy.","The film used over 37,000 extras and gigantic sets depicting a dystopian city of the future.","Metropolis' robot 'Maria' is one of the first android depictions in cinema — her design influenced C-3PO in Star Wars."],
    es:["Metropolis (1927) de Fritz Lang costó 5 millones de marcos (equivalente a 200 millones de dólares actuales) y casi arruinó a la UFA, el mayor estudio de cine alemán.","La película empleó más de 36 000 extras y su diseño visual influyó directamente en Blade Runner, Star Wars, Batman y prácticamente todo el cine de ciencia ficción posterior.","El robot María es uno de los primeros androides femeninos del cine — su diseño inspiró tanto a C-3PO de Star Wars como a la estética del art déco cinematográfico."]
},
'e324': {
  fr:["Le budget final de Titanic était de 200 millions de dollars — le studio Fox était si inquiet qu'il a partagé le financement avec Paramount.","Cameron a finalement touché des revenus grâce aux bénéfices du film : Titanic a rapporté plus de 2,2 milliards de dollars au box-office.","Un réplique du navire à 90 % de sa taille réelle a été construite dans un bassin au Mexique — la plus grande construction de décor de l'histoire du cinéma à l'époque."],
  en:["Titanic's final budget was $200 million — Fox was so worried it shared financing with Paramount.","Cameron eventually earned income through the film's profits: Titanic grossed over $2.2 billion at the box office.","A 90%-scale replica of the ship was built in a tank in Mexico — the largest set construction in cinema history at the time."],
    es:["Titanic costó 200 millones de dólares en 1997, un récord absoluto que muchos consideraron una locura — la película recaudó 2 200 millones y ganó 11 premios Oscar.","Cameron construyó una réplica del Titanic a escala 90 % en un estudio de Baja California (México) — el barco medía 231 metros y fue uno de los decorados más grandes de la historia.","La escena de Jack y Rose en la proa, con la música de Celine Dion, se convirtió en la imagen más icónica y parodiada del cine de los años 1990."]
},
'e325': {
  fr:["Heath Ledger s'est enfermé dans une chambre d'hôtel pendant 6 semaines pour préparer son Joker — tenant un journal intime du personnage rempli de pensées sombres.","Joaquin Phoenix a perdu 23 kg pour incarner le Joker en 2019 — un régime extrême qui a affecté son humeur et son sommeil.","Jack Nicholson, premier Joker au cinéma en 1989, avait prévenu Ledger des dangers psychologiques du rôle — son conseil : « ne fais jamais ça »."],
  en:["Heath Ledger locked himself in a hotel room for 6 weeks to prepare his Joker — keeping a character diary filled with dark thoughts.","Joaquin Phoenix lost 23 kg to play the Joker in 2019 — an extreme diet that affected his mood and sleep.","Jack Nicholson, the first cinema Joker in 1989, reportedly warned Ledger about the role's psychological dangers — his advice: 'never do that'."],
    es:["Heath Ledger se encerró un mes en una habitación de hotel, llevando un diario del Joker, para preparar su papel en El caballero oscuro — murió de una sobredosis accidental antes del estreno.","Joaquin Phoenix perdió 24 kg para su Joker (2019) y permaneció en el personaje durante todo el rodaje — la transformación física y psicológica preocupó al equipo de producción.","Jared Leto envió ratas vivas, condones usados y balas a sus compañeros de reparto durante el rodaje de Escuadrón Suicida — un «method acting» que muchos consideraron excesivo."]
},
'e326': {
  fr:["Hitchcock a utilisé un melon de Casaba pour simuler le son du couteau poignardant la chair — un effet sonore devenu célèbre en design audio.","Janet Leigh (Marion Crane) a déclaré que la scène l'avait traumatisée au point de ne plus jamais prendre de douche — seulement des bains.","La scène a été montée par George Tomasini en un montage rapide révolutionnaire qui suggère la violence sans jamais montrer le couteau pénétrant le corps."],
  en:["Hitchcock used a Casaba melon to simulate the sound of the knife stabbing flesh — a sound effect that became famous in audio design.","Janet Leigh (Marion Crane) said the scene traumatised her so much she never took a shower again — only baths.","The scene was edited by George Tomasini in a revolutionary rapid montage that suggests violence without ever showing the knife penetrating the body."],
    es:["La escena de la ducha de Psicosis (1960) dura 45 segundos, usa 77 ángulos de cámara diferentes y se rodó durante 7 días — Hitchcock planificó cada corte con storyboards detallados.","Janet Leigh no se duchó durante años después del rodaje — el efecto psicológico de la escena fue tan poderoso que afectó incluso a la actriz que la interpretó.","La sangre era jarabe de chocolate: Hitchcock filmó en blanco y negro deliberadamente para poder usar este sustituto y para atenuar la violencia visual."]
},
'e327': {
  fr:["Blade Runner n'a rapporté que 33 millions de dollars pour un budget de 28 millions — un échec relatif face à E.T. sorti la même année.","Le film a eu sept versions différentes au fil des décennies — le « Final Cut » de 2007 est considéré comme la version définitive par Ridley Scott.","Les questions philosophiques du film sur la conscience artificielle et l'identité sont devenues plus pertinentes avec l'essor de l'intelligence artificielle."],
  en:["Blade Runner grossed only $33 million against a $28 million budget — a relative flop against E.T., released the same year.","The film has had seven different versions over the decades — the 2007 'Final Cut' is considered the definitive version by Ridley Scott.","The film's philosophical questions about artificial consciousness and identity have become more relevant with the rise of AI."],
    es:["Blade Runner (1982) fracasó en taquilla y recibió críticas mixtas — hoy es considerada una de las películas de ciencia ficción más influyentes jamás filmadas.","Ridley Scott se inspiró en la novela de Philip K. Dick ¿Sueñan los androides con ovejas eléctricas? pero transformó su trama filosófica en una experiencia visual y atmosférica única.","Existen al menos 7 versiones diferentes de Blade Runner — la «Final Cut» de 2007 es la que Scott considera definitiva."]
},
'e328': {
  fr:["Bigelow était en compétition directe avec son ex-mari James Cameron (Avatar) cette année-là — elle l'a battu dans les deux catégories principales.","Démineurs a été réalisé avec un budget modeste de 15 millions de dollars — il en a rapporté 49 millions, un ratio remarquable.","Malgré cette victoire historique, en 2024, seules trois femmes au total ont été nommées pour l'Oscar du meilleur réalisateur dans l'histoire de la cérémonie."],
  en:["Bigelow was in direct competition with her ex-husband James Cameron (Avatar) that year — she beat him in both major categories.","The Hurt Locker was made on a modest $15 million budget — it earned $49 million, a remarkable ratio.","Despite this historic win, by 2024 only three women in total had ever been nominated for the Best Director Oscar."],
    es:["Kathryn Bigelow ganó el Oscar a la Mejor Dirección en 2010 por En tierra hostil — fue la primera mujer en lograrlo en 82 años de historia de la Academia.","Bigelow fue la exesposa de James Cameron, que competía el mismo año con Avatar — ella ganó en casi todas las categorías importantes.","A pesar de su logro, hasta 2024 solo tres mujeres han sido nominadas al Oscar de Dirección — la brecha de género en el cine sigue siendo significativa."]
},
'e329': {
  fr:["Gance a utilisé un système de triple écran appelé « Polyvision » — un précurseur du CinemaScope et de l'IMAX, inventé 30 ans avant eux.","Le film a nécessité des milliers de figurants et des scènes de bataille d'une ampleur inédite — Gance montait parfois des caméras sur des chevaux au galop.","La restauration complète du film a pris des décennies — la version de 2024 restaurée par la Cinémathèque française dure 7 heures."],
  en:["Gance used a triple-screen system called 'Polyvision' — a forerunner of CinemaScope and IMAX, invented 30 years before them.","The film required thousands of extras and battle scenes of unprecedented scale — Gance sometimes mounted cameras on galloping horses.","Full restoration of the film took decades — the 2024 version restored by the Cinémathèque française runs 7 hours."],
    es:["La versión restaurada de Napoléon de Abel Gance dura más de 5 horas y fue proyectada en tres pantallas simultáneas (Polyvision) — un precursor del Cinerama y el IMAX.","Gance filmó batallas con cámaras atadas a caballos, péndulos y trineos — innovaciones técnicas que anticiparon la steadicam y las cámaras en drones por décadas.","La restauración de Kevin Brownlow tardó más de 50 años en completarse — es una de las mayores hazañas de preservación cinematográfica de la historia."]
},
'e330': {
  fr:["Pour « Abyss » (1989), Cameron a passé sa certification de plongée profonde et a supervisé personnellement les tournages sous-marins à 10 000 pieds.","En 2012, Cameron a effectué une plongée en solitaire jusqu'au fond de la fosse des Mariannes — le point le plus profond de l'océan à 10 908 m.","Pour Titanic, il a effectué 33 plongées sur l'épave réelle à 3 800 m de profondeur — filmant les images utilisées dans le film."],
  en:["For 'The Abyss' (1989), Cameron got deep-diving certified and personally supervised underwater filming at 10,000 feet.","In 2012, Cameron made a solo dive to the bottom of the Mariana Trench — the ocean's deepest point at 10,908 m.","For Titanic, he made 33 dives to the real wreck at 3,800 m depth — filming footage used in the movie."],
    es:["James Cameron obtuvo su licencia de piloto de sumergibles, aprendió a soldar y realizó más de 70 inmersiones al Titanic real para preparar sus películas.","Para The Abyss (1989), Cameron construyó el mayor set de rodaje subacuático del mundo: una central nuclear abandonada inundada con 30 millones de litros de agua.","Cameron es uno de los tres realizadores que han alcanzado el fondo de la fosa de las Marianas (10 908 m) en 2012 — además de hacer películas, es un explorador legítimo."]
},
'e331': {
  fr:["Le film a aussi été le premier avec un acteur afro-américain à recevoir un Oscar : Hattie McDaniel a remporté le prix de la meilleure actrice dans un second rôle.","McDaniel n'a pas pu s'asseoir avec le reste du casting lors de la cérémonie — elle était reléguée à une table séparée en raison de la ségrégation.","Le film reste controversé pour sa représentation romantique du Sud esclavagiste — HBO Max a ajouté un avertissement contextuel lors de sa diffusion."],
  en:["The film also featured the first African American to receive an Oscar: Hattie McDaniel won Best Supporting Actress.","McDaniel couldn't sit with the rest of the cast at the ceremony — she was relegated to a separate table due to segregation.","The film remains controversial for its romanticised portrayal of the slaveholding South — HBO Max added a contextual disclaimer to its streaming."],
    es:["Lo que el viento se llevó (1939) ganó 8 premios Oscar competitivos más 2 honoríficos — un récord que se mantuvo durante 20 años.","Hattie McDaniel fue la primera persona afroamericana en ganar un Oscar (Mejor Actriz de Reparto) — pero tuvo que sentarse en una mesa segregada durante la ceremonia.","La película ha sido objeto de debate por su romanticización de la esclavitud y la Confederación — HBO Max la retiró temporalmente en 2020 antes de reponerla con un contexto histórico añadido."]
},
'e332': {
  fr:["Dans « Steamboat Bill Jr. » (1928), la façade entière d'une maison tombe sur Keaton — il survit grâce à la fenêtre ouverte qui passe exactement autour de lui, avec 5 cm de marge.","Keaton s'est fracturé le cou pendant le tournage de « Sherlock Jr. » (1924) sans le savoir — il ne l'a découvert que des années plus tard via une radiographie.","Contrairement à Chaplin qui misait sur l'émotion, Keaton privilégiait la mécanique physique et le timing parfait — il était surnommé « l'homme qui ne rit jamais »."],
  en:["In 'Steamboat Bill Jr.' (1928), an entire house facade falls on Keaton — he survives thanks to an open window passing exactly around him, with just 5 cm clearance.","Keaton broke his neck during filming of 'Sherlock Jr.' (1924) without knowing — he only discovered it years later via X-ray.","Unlike Chaplin who relied on emotion, Keaton favoured physical mechanics and perfect timing — he was nicknamed 'the man who never laughed'."],
    es:["Buster Keaton realizó personalmente todas sus acrobacias sin dobles ni trucajes: se colgó de trenes en movimiento, se lanzó por cascadas y se dejó golpear por la fachada de una casa real.","En Sherlock Jr. (1924), Keaton se rompió el cuello durante una escena sin darse cuenta — el dolor fue tan gradual que solo lo descubrió años después en una radiografía.","Keaton rechazaba el sonoro por principio artístico: su comedia visual pura no necesitaba palabras — hoy es considerado superior a Chaplin por muchos cineastas."]
},
'e333': {
  fr:["Ben Burtt, le créateur sonore de Star Wars, a aussi créé la voix de R2-D2 en mélangeant ses propres vocalises avec des sons de synthétiseur.","Le son du blaster de Han Solo a été créé en frappant un câble de hauban avec un marteau — un son métallique distinctif.","Le rugissement de Chewbacca est un mélange de sons d'ours, de morse, de lion et de blaireau — assemblés par Burtt pour créer une voix unique."],
  en:["Ben Burtt, Star Wars' sound designer, also created R2-D2's voice by mixing his own vocalisations with synthesiser sounds.","Han Solo's blaster sound was created by hitting a guy wire with a hammer — a distinctive metallic sound.","Chewbacca's roar is a blend of bear, walrus, lion, and badger sounds — assembled by Burtt to create a unique voice."],
    es:["Ben Burtt creó el sonido del sable láser combinando el zumbido de un proyector de cine con la interferencia electromagnética de un televisor captada por un micrófono.","Los sonidos de R2-D2 son una mezcla de sintetizador y las propias vocalizaciones de Burtt — cada «bip» y «silbido» fue diseñado para expresar una emoción específica.","El rugido del TIE Fighter es una combinación de un elefante y un coche en una carretera mojada — el diseño sonoro de Star Wars es tan icónico como su diseño visual."]
},
'e334': {
  fr:["Hitchcock a réalisé 53 longs métrages entre 1925 et 1976 — il apparaît en caméo dans 39 d'entre eux.","Ses apparitions sont devenues si célèbres qu'il les plaçait au début du film pour ne pas distraire le public pendant les scènes de suspense.","Dans « Lifeboat » (1944), qui se passe entièrement sur un canot de sauvetage, Hitchcock apparaît dans une publicité de journal pour un régime amaigrissant."],
  en:["Hitchcock directed 53 features between 1925 and 1976 — he appears in cameos in 39 of them.","His appearances became so famous he placed them early in films to avoid distracting the audience during suspense scenes.","In 'Lifeboat' (1944), set entirely on a lifeboat, Hitchcock appears in a newspaper ad for a weight-loss programme."],
    es:["Hitchcock aparece en 39 de sus 52 películas — en Los pájaros camina con dos terriers, en Náufragos aparece en un anuncio de periódico y en La soga cruza la calle con un violonchelo.","Sus cameos se volvieron tan esperados que empezó a colocarlos al principio de la película para que el público dejara de buscarlos y se concentrara en la trama.","Hitchcock nunca ganó un Oscar a la Mejor Dirección a pesar de 5 nominaciones — uno de los olvidos más flagrantes de la Academia, corregido con un Oscar honorífico en 1968."]
},
'e335': {
  fr:["Scheider a improvisé la réplique en réaction à sa première vue du requin mécanique (surnommé « Bruce ») — Spielberg l'a gardée car elle capturait une terreur authentique.","Le requin mécanique tombait constamment en panne, forçant Spielberg à montrer le moins possible le requin — une contrainte qui a rendu le film plus terrifiant.","Les Dents de la mer (1975) est considéré comme le premier « blockbuster d'été » de l'histoire — il a inventé le concept de sortie massive simultanée dans des centaines de salles."],
  en:["Scheider improvised the line upon his first sight of the mechanical shark (nicknamed 'Bruce') — Spielberg kept it because it captured genuine terror.","The mechanical shark constantly broke down, forcing Spielberg to show the shark as little as possible — a constraint that made the film more terrifying.","Jaws (1975) is considered the first 'summer blockbuster' in history — it invented the concept of wide simultaneous release in hundreds of theatres."],
    es:["La frase exacta en Tiburón es «You're gonna need a bigger boat» (vas a necesitar un barco más grande) — fue improvisada por Roy Scheider, no escrita en el guion.","Steven Spielberg tenía solo 27 años cuando dirigió Tiburón — el tiburón mecánico (apodado «Bruce») funcionaba tan mal que Spielberg tuvo que mostrar el peligro sin mostrarlo, creando un suspense más efectivo.","Tiburón inventó el concepto de «blockbuster veraniego»: fue la primera película en superar los 100 millones en taquilla y cambió la estrategia de distribución de Hollywood para siempre."]
},
'e336': {
  fr:["Cette réduction est liée aux plateformes de streaming : les artistes sont payés par écoute, donc une chanson plus courte peut être rejouée plus souvent.","Le streaming a aussi favorisé les « intros courtes » : le refrain doit arriver dans les 15 premières secondes pour éviter que l'auditeur ne passe au titre suivant.","Les tubes des années 1970 comme « Bohemian Rhapsody » (5 min 55) ou « Stairway to Heaven » (8 min 02) seraient difficilement des hits dans le paysage musical actuel."],
  en:["This reduction is linked to streaming platforms: artists are paid per stream, so a shorter song can be replayed more often.","Streaming has also favoured 'short intros': the chorus must arrive within the first 15 seconds to prevent the listener from skipping.","1970s hits like 'Bohemian Rhapsody' (5:55) or 'Stairway to Heaven' (8:02) would struggle to become hits in today's musical landscape."],
    es:["En los años 1990, la canción pop media duraba 4 minutos; en 2023, la media bajó a 3 minutos 30 segundos — un efecto directo del modelo de streaming, que paga por reproducción.","Spotify no cuenta una reproducción hasta los 30 segundos: los artistas optimizan sus canciones con intros cortas y estribillos inmediatos para enganchar antes de ese umbral.","Drake y otros artistas han maximizado los álbumes de 20+ canciones cortas para generar más reproducciones totales — la economía del streaming moldea la creatividad."]
},
'e337': {
  fr:["Le groupe a inséré une clause dans ses contrats de tournée interdisant la ségrégation dans les salles — une prise de position forte dans l'Amérique des années 1960.","Leur concert au Gator Bowl de Jacksonville en 1964 a été le premier concert intégré de l'histoire de la ville — les spectateurs noirs et blancs étaient mélangés.","Les Beatles ont aussi refusé de jouer devant un public exclusivement blanc en Afrique du Sud — ils n'ont jamais joué dans le pays pendant l'apartheid."],
  en:["The band inserted a clause in their tour contracts forbidding segregation in venues — a strong stance in 1960s America.","Their 1964 Gator Bowl concert in Jacksonville was the city's first integrated concert — Black and white audiences mixed together.","The Beatles also refused to play to all-white audiences in South Africa — they never performed in the country during apartheid."],
    es:["Los Beatles se negaron a tocar en el Gator Bowl de Jacksonville (1964) cuando descubrieron que la audiencia estaría segregada — amenazaron con cancelar y el organizador cedió.","John Lennon y Yoko Ono organizaron los «bed-ins» de 1969 en Ámsterdam y Montreal como protesta pacífica contra la guerra de Vietnam — Give Peace a Chance se grabó en la habitación del hotel.","Los Beatles se separaron en 1970 tras una mezcla de tensiones creativas, financieras y personales — su legado sigue siendo la referencia suprema de la música popular."]
},
'e338': {
  fr:["La flûte a été trouvée dans la grotte de Hohle Fels, dans le Jura souabe en Allemagne — elle fait 22 cm et possède 5 trous.","D'autres flûtes en ivoire de mammouth ont été retrouvées dans la même région — prouvant que la musique faisait partie de la culture des premiers Homo sapiens en Europe.","La musique est considérée comme un avantage évolutif : elle renforçait la cohésion sociale et la communication dans les groupes humains préhistoriques."],
  en:["The flute was found in Hohle Fels cave in the Swabian Jura, Germany — it's 22 cm long with 5 holes.","Other mammoth ivory flutes were found in the same region — proving music was part of early Homo sapiens culture in Europe.","Music is considered an evolutionary advantage: it strengthened social cohesion and communication in prehistoric human groups."],
    es:["La flauta de Hohle Fels (43 000 años) fue tallada en un hueso de buitre por Homo sapiens en lo que hoy es Alemania — demuestra que la música es tan antigua como el arte figurativo.","Produce una escala pentatónica con 5 agujeros — los mismos intervalos que se encuentran en el blues, el rock, la música china y las canciones infantiles de todo el mundo.","La universalidad de la escala pentatónica sugiere que ciertas relaciones tonales son innatas al oído humano — no convenciones culturales sino constantes biológicas."]
},
'e339': {
  fr:["Le Si♭ -4 à 7,5 Hz est bien en dessous du seuil d'audition humaine (environ 20 Hz) — cette note est ressentie plus que entendue.","Storms détient aussi le record de la tessiture vocale la plus large : 10 octaves, du grave extrême au registre aigu.","Les baleines bleues émettent des sons à environ 14 Hz — Storms peut donc chanter plus grave qu'une baleine bleue."],
  en:["B♭ -4 at 7.5 Hz is well below the human hearing threshold (about 20 Hz) — this note is felt more than heard.","Storms also holds the record for the widest vocal range: 10 octaves, from extreme low to high register.","Blue whales produce sounds at about 14 Hz — so Storms can sing lower than a blue whale."],
    es:["Tim Storms, cantante estadounidense, posee el récord de la nota más grave producida por un ser humano: un G-7 (0,189 Hz), inaudible para el oído humano.","Su rango vocal abarca más de 10 octavas — la mayoría de cantantes profesionales cubren entre 2 y 3 octavas, y los mejores (Mariah Carey, Freddie Mercury) alcanzan 4-5.","Las frecuencias inferiores a 20 Hz (infrasonidos) no se «oyen» pero se sienten como vibraciones corporales — algunos órganos de iglesia producen infrasonidos que generan sensaciones de reverencia."]
},
'e340': {
  fr:["Jean-Baptiste Lully, compositeur de Louis XIV, dirigeait en frappant le sol avec un long bâton — il s'est un jour transpercé le pied, provoquant une gangrène fatale.","La baguette moderne a été popularisée par Louis Spohr dans les années 1820 — elle permettait des gestes plus précis et visibles pour les grands orchestres.","Certains chefs contemporains dirigent encore sans baguette — Pierre Boulez et Valery Gergiev étaient célèbres pour diriger à mains nues."],
  en:["Jean-Baptiste Lully, Louis XIV's composer, conducted by striking the floor with a long staff — he once pierced his foot, causing fatal gangrene.","The modern baton was popularised by Louis Spohr in the 1820s — it allowed more precise and visible gestures for large orchestras.","Some contemporary conductors still lead without a baton — Pierre Boulez and Valery Gergiev were famous for conducting bare-handed."],
    es:["Antes de la batuta, los directores de orquesta usaban un rollo de papel, un bastón o golpeaban el suelo con un palo — Jean-Baptiste Lully murió de gangrena tras clavarse su bastón en el pie.","La batuta moderna fue introducida por Louis Spohr hacia 1820 y popularizada por Mendelssohn y Wagner — su ligereza permitió gestos más expresivos y precisos.","Algunos directores contemporáneos prescinden de la batuta (como Valery Gergiev) — el debate sobre su necesidad refleja las diferentes filosofías de dirección orquestal."]
},
'e341': {
  fr:["Le premier modèle, le « Frying Pan » de Rickenbacker, était un instrument à cordes hawaïen en aluminium posé sur les genoux.","La guitare électrique n'a explosé dans le rock qu'à la fin des années 1950 avec Chuck Berry, Buddy Holly et les premiers amplificateurs puissants.","Leo Fender, qui a popularisé la Telecaster (1950) et la Stratocaster (1954), ne savait pas jouer de la guitare lui-même."],
  en:["The first model, Rickenbacker's 'Frying Pan', was an aluminium Hawaiian lap steel instrument.","The electric guitar only exploded in rock in the late 1950s with Chuck Berry, Buddy Holly, and the first powerful amplifiers.","Leo Fender, who popularised the Telecaster (1950) and Stratocaster (1954), couldn't actually play guitar himself."],
    es:["La primera guitarra eléctrica comercial, la «Frying Pan» de Rickenbacker (1931), fue diseñada para amplificar la guitarra hawaiana (lap steel) usada en el jazz y el country.","La pastilla electromagnética convierte las vibraciones de las cuerdas metálicas en señales eléctricas — el principio es tan simple que guitarristas experimentan con imanes de todo tipo.","La guitarra eléctrica transformó la música popular: sin ella, no existirían el rock and roll, el blues eléctrico, el heavy metal, el punk ni la mayor parte de la música moderna."]
},
'e342': {
  fr:["Beethoven comptait exactement 60 grains de café pour son café du matin — un rituel obsessionnel qu'il ne déléguait jamais.","Il a composé certaines de ses œuvres les plus célèbres — la 9e symphonie, les derniers quatuors — alors qu'il était complètement sourd.","Pour « entendre » ses compositions, il sciait les pieds de son piano et posait l'oreille sur le plancher pour sentir les vibrations."],
  en:["Beethoven counted exactly 60 coffee beans for his morning coffee — an obsessive ritual he never delegated.","He composed some of his most famous works — the 9th Symphony, the late quartets — while completely deaf.","To 'hear' his compositions, he sawed the legs off his piano and pressed his ear to the floor to feel the vibrations."],
    es:["Beethoven vertía agua fría sobre su cabeza como técnica de estimulación antes de componer — sus vecinos se quejaban de las filtraciones de agua en sus pisos.","También usaba un dispositivo de conducción ósea (una varilla de madera sujeta entre los dientes y apoyada en el piano) para «sentir» las vibraciones musicales cuando su sordera avanzó.","Los cuadernos de conversación de Beethoven, donde sus visitantes escribían sus preguntas, se han conservado — son una fuente invaluable sobre su vida cotidiana y su proceso creativo."]
},
'e343': {
  fr:["La symphonie « Gothique » nécessite plus de 800 musiciens et choristes pour être jouée — elle n'a été créée intégralement qu'en 1961, 34 ans après son achèvement.","L'exécution complète dure environ 1h50 — un marathon pour les interprètes comme pour le public.","Havergal Brian a composé 32 symphonies au total, dont la plupart après ses 80 ans — un cas exceptionnel de productivité tardive."],
  en:["The 'Gothic' Symphony requires over 800 musicians and choristers to perform — it wasn't premiered in full until 1961, 34 years after completion.","A complete performance lasts about 1h50 — a marathon for performers and audience alike.","Havergal Brian composed 32 symphonies in total, most of them after age 80 — an exceptional case of late-life productivity."],
    es:["La Sinfonía Gótica de Havergal Brian (1919-1927) requiere 4 solistas, 2 coros, un coro infantil y una orquesta de 200 músicos — su primera interpretación completa tuvo lugar en 1961.","Con una duración de más de 2 horas, es técnicamente la sinfonía más larga del repertorio — aunque la Sinfonía n.° 3 de Kaikhosru Sorabji la supera si se incluyen las repeticiones opcionales.","Brian compuso 32 sinfonías en total, la mayoría después de los 70 años — un ejemplo de productividad artística tardía que desafía los estereotipos sobre la creatividad y la edad."]
},
'e344': {
  fr:["Le brevet US 5,255,452 décrit un système de clous rétractables dans la semelle qui s'accrochent à une fente dans le sol de la scène.","Cette illusion a été utilisée pour la première fois dans le clip « Smooth Criminal » en 1988 — devenant l'une des images les plus iconiques de la pop.","Jackson détenait aussi des brevets pour des effets de scène sonores et visuels — il était inventeur autant qu'artiste."],
  en:["US patent 5,255,452 describes a system of retractable pegs in the shoe sole that lock into a slot in the stage floor.","This illusion was first used in the 'Smooth Criminal' video in 1988 — becoming one of pop's most iconic images.","Jackson also held patents for sound and visual stage effects — he was an inventor as much as an artist."],
    es:["Michael Jackson patentó en 1993 un mecanismo de calzado con una ranura en el talón que se enganchaba a un clavo en el suelo, permitiendo la inclinación de 45° del «Smooth Criminal lean».","Sin este dispositivo, la inclinación sería físicamente imposible: el centro de gravedad se desplaza más allá de la base de apoyo — la física básica lo prohíbe.","Jackson era un perfeccionista obsesivo del movimiento: ensayaba sus coreografías durante meses y exigía sincronización perfecta de cada bailarín al milisegundo."]
},
'e345': {
  fr:["Les droits étaient détenus par Warner/Chappell Music qui facturait jusqu'à 25 000 dollars par utilisation dans un film.","En 2015, un tribunal a jugé que le copyright était invalide — la chanson a été déclarée dans le domaine public en 2016.","La mélodie originale a été composée en 1893 par les sœurs Patty et Mildred Hill sous le titre « Good Morning to All » — un chant pour les enfants de maternelle."],
  en:["The rights were held by Warner/Chappell Music, which charged up to $25,000 per use in a film.","In 2015, a court ruled the copyright invalid — the song was declared in the public domain in 2016.","The original melody was composed in 1893 by sisters Patty and Mildred Hill as 'Good Morning to All' — a kindergarten song."],
    es:["Happy Birthday to You fue compuesta en 1893 por las hermanas Patty y Mildred Hill como Good Morning to All — la letra de cumpleaños fue añadida posteriormente por un autor desconocido.","Warner/Chappell cobró derechos de autor por la canción hasta 2015, generando unos 2 millones de dólares al año — un juicio federal dictaminó que los derechos eran inválidos.","Happy Birthday es cantada en prácticamente todos los países del mundo y ha sido traducida a cientos de idiomas — es probablemente la canción más cantada de la historia."]
},
'e346': {
  fr:["Les cordes constituent la plus grande section avec environ 60 musiciens — violons (premiers et seconds), altos, violoncelles et contrebasses.","Le chef d'orchestre ne produit aucun son mais est essentiel : il unifie le tempo, l'interprétation et les dynamiques de l'ensemble.","Un orchestre symphonique complet coûte entre 30 et 50 millions de dollars par an en salaires — les orchestres dépendent fortement du mécénat et des subventions."],
  en:["Strings are the largest section with about 60 players — violins (first and second), violas, cellos, and double basses.","The conductor produces no sound but is essential: they unify tempo, interpretation, and dynamics across the ensemble.","A full symphony orchestra costs $30–50 million per year in salaries — orchestras rely heavily on patronage and grants."],
    es:["Un orchestre symphonique estándar cuenta con 4 familias de instrumentos: cuerdas (violines, violas, violonchelos, contrabajos), vientos madera, vientos metal y percusión.","La disposición de los músicos en el escenario no es aleatoria: los violines a la izquierda, los vientos al centro y la percusión al fondo optimizan el balance sonoro y la comunicación visual con el director.","Los instrumentos más caros de una orquesta son los violines: un Stradivarius puede costar más de 15 millones de dólares — muchos solistas tocan con instrumentos prestados por fundaciones."]
},
'e347': {
  fr:["Le colonel Tom Parker, manager d'Elvis, était un immigré illégal néerlandais — il n'avait pas de passeport américain et craignait de ne pas pouvoir revenir s'il quittait le pays.","Elvis a effectué son service militaire en Allemagne de 1958 à 1960 — sa seule période à l'étranger, mais il n'y a pas donné de concerts.","Malgré cela, Elvis reste l'un des artistes les plus vendus de l'histoire avec plus d'un milliard de disques écoulés dans le monde."],
  en:["Colonel Tom Parker, Elvis's manager, was an illegal Dutch immigrant — he had no US passport and feared being unable to return if he left the country.","Elvis served in the military in Germany from 1958 to 1960 — his only time abroad, but he gave no concerts there.","Despite this, Elvis remains one of the best-selling artists in history with over one billion records sold worldwide."],
    es:["Elvis nunca dio conciertos fuera de América del Norte por decisión de su manager, el coronel Tom Parker, que era un inmigrante ilegal holandés y temía que le denegaran la reentrada a EE.UU.","Parker (nacido Andreas Cornelis van Kuijk) nunca obtuvo la ciudadanía estadounidense — su secreto condicionó la carrera internacional de la mayor estrella del rock.","Elvis vendió más de 500 millones de discos, tuvo 18 números uno en EE.UU. y protagonizó 31 películas — a pesar de nunca actuar fuera de Norteamérica."]
},
'e348': {
  fr:["La chanson a été inspirée par le synthétiseur des années 1980 et le son new wave — The Weeknd voulait créer un morceau intemporel.","« Blinding Lights » est restée 90 semaines dans le Billboard Hot 100 — un record de longévité dans le classement.","Le succès de la chanson a relancé l'intérêt pour le synthwave et la pop rétro des années 1980 dans la musique contemporaine."],
  en:["The song was inspired by 1980s synthesisers and the new wave sound — The Weeknd wanted to create a timeless track.","'Blinding Lights' spent 90 weeks on the Billboard Hot 100 — a record for chart longevity.","The song's success revived interest in synthwave and 1980s retro pop in contemporary music."],
    es:["Blinding Lights de The Weeknd supera los 4 000 millones de reproducciones en Spotify — su éxito se debe a una combinación de nostalgia synthwave de los 80 y producción pop moderna.","La canción permaneció 90 semanas en el Billboard Hot 100 — el récord de permanencia más largo en la historia de la lista, superando a Radioactive de Imagine Dragons.","El éxito en streaming no se traduce necesariamente en ingresos: con 0,003-0,005 $ por reproducción, 4 000 millones de streams generan unos 12-20 millones $ — una fracción de lo que generaría en ventas físicas."]
},
'e349': {
  fr:["Le nom complet de l'instrument était « gravicembalo col piano e forte » — littéralement « clavecin avec doux et fort », raccourci en « pianoforte » puis « piano ».","Le premier piano de Cristofori utilisait des marteaux frappant les cordes au lieu de les pincer comme le clavecin — une innovation révolutionnaire.","Un piano de concert moderne contient environ 230 cordes sous une tension totale de 20 tonnes — plus qu'un pont suspendu par unité de surface."],
  en:["The instrument's full name was 'gravicembalo col piano e forte' — literally 'harpsichord with soft and loud', shortened to 'pianoforte' then 'piano'.","Cristofori's first piano used hammers striking strings instead of plucking them like the harpsichord — a revolutionary innovation.","A modern concert grand contains about 230 strings under a total tension of 20 tonnes — more than a suspension bridge per unit area."],
    es:["Cristofori buscaba crear un instrumento de teclado capaz de tocar suave (piano) y fuerte (forte) — de ahí el nombre original pianoforte, abreviado a piano.","El clavecín, instrumento dominante antes del piano, no podía variar la dinámica: cada nota sonaba con la misma intensidad independientemente de la fuerza de la pulsación.","Un piano de cola moderno tiene 88 teclas, 230 cuerdas y más de 12 000 piezas — cada instrumento Steinway se construye artesanalmente durante 1-2 años."]
},
'e350': {
  fr:["L'offre venait de promoteurs qui proposaient 250 concerts dans le monde — chaque membre aurait touché environ 250 millions de dollars.","ABBA s'est finalement « retrouvé » virtuellement en 2022 avec le concert « ABBA Voyage » à Londres — des avatars numériques jouent devant un public réel.","ABBA a vendu plus de 400 millions de disques — ce qui en fait l'un des groupes les plus vendus de tous les temps."],
  en:["The offer came from promoters proposing 250 shows worldwide — each member would have received about $250 million.","ABBA finally 'reunited' virtually in 2022 with the 'ABBA Voyage' concert in London — digital avatars perform before a live audience.","ABBA has sold over 400 million records — making them one of the best-selling groups of all time."],
    es:["ABBA rechazó una oferta de 1 000 millones de dólares para una gira de 100 conciertos de reunión — la cantidad más alta jamás ofrecida a un grupo musical.","En lugar de girar, ABBA creó ABBA Voyage (2022): un espectáculo en Londres con avatares digitales (ABBAtars) que interpretan sus canciones con movimientos capturados de los miembros reales.","ABBA vendió más de 400 millones de discos y su musical Mamma Mia! se ha representado más de 65 millones de veces en todo el mundo — un legado cultural global."]
},
'e351': {
  fr:["Les 88 touches d'un piano standard couvrent plus de 7 octaves — une plage plus large que tout autre instrument acoustique courant.","Les fréquences les plus hautes du piano (au-dessus de 4 000 Hz) sont difficiles à percevoir pour les personnes de plus de 50 ans en raison de la presbyacousie.","Le la 440 Hz (la3) est la note de référence internationale pour l'accordage — mais historiquement, cette fréquence a varié entre 400 et 480 Hz selon les époques."],
  en:["A standard piano's 88 keys span over 7 octaves — a wider range than any other common acoustic instrument.","The piano's highest frequencies (above 4,000 Hz) are hard to perceive for people over 50 due to presbycusis.","A 440 Hz (A4) is the international tuning reference note — but historically this frequency varied between 400 and 480 Hz across eras."],
    es:["El piano de concierto cubre 7,5 octavas (de A0 a C8), pero el oído humano puede percibir frecuencias equivalentes a unas 10 octavas (20 Hz a 20 000 Hz).","Las notas más agudas del piano (por encima de C6) suenan cada vez más «metálicas» porque los armónicos son inarmónicos — los afinadores deben compensar estirando la afinación.","Beethoven solicitó repetidamente pianos con más teclas para ampliar su rango expresivo — los fabricantes añadieron teclas gradualmente, pasando de 61 (5 octavas) en 1700 a 88 en los años 1880."]
},
'e352': {
  fr:["Les castrats étaient des garçons castrés avant la puberté pour préserver leur voix aiguë — une pratique cruelle mais répandue en Italie du XVIe au XIXe siècle.","Farinelli, le castrat le plus célèbre, avait une tessiture de plus de 3 octaves et pouvait tenir une note pendant plus d'une minute sans respirer.","Le dernier castrat connu, Alessandro Moreschi, a enregistré des disques en 1902 — les seuls enregistrements existants d'une voix de castrat."],
  en:["Castrati were boys castrated before puberty to preserve their high voice — a cruel but widespread practice in Italy from the 16th to 19th century.","Farinelli, the most famous castrato, had a range of over 3 octaves and could hold a note for over a minute without breathing.","The last known castrato, Alessandro Moreschi, recorded in 1902 — the only existing recordings of a castrato voice."],
    es:["Los castrati eran niños castrados antes de la pubertad para preservar su voz aguda: la laringe no crecía pero los pulmones y la caja torácica sí, produciendo una potencia vocal extraordinaria.","Farinelli, el castrato más famoso del siglo XVIII, tenía un rango de 3,5 octavas y podía sostener una nota durante más de un minuto sin respirar.","La práctica fue prohibida por la Iglesia Católica en 1903 — el último castrato de la Capilla Sixtina, Alessandro Moreschi, es el único cuya voz fue grabada (1902-1904)."]
},
'e353': {
  fr:["Thomas Bangalter et Guy-Manuel de Homem-Christo ont déclaré qu'un « accident » les avait transformés en robots le 9 septembre 1999 — une mythologie soigneusement entretenue.","Les casques ont évolué au fil des albums : simples au début, puis chromés et lumineux pour « Random Access Memories » (2013).","Daft Punk s'est séparé en 2021 avec une vidéo intitulée « Epilogue » — l'un des robots se fait exploser dans le désert, mettant fin au duo."],
  en:["Thomas Bangalter and Guy-Manuel de Homem-Christo claimed an 'accident' turned them into robots on 9 September 1999 — a carefully maintained mythology.","The helmets evolved across albums: simple at first, then chromed and illuminated for 'Random Access Memories' (2013).","Daft Punk split in 2021 with a video titled 'Epilogue' — one robot self-destructs in the desert, ending the duo."],
    es:["Daft Punk adoptó los cascos de robot en 1999 tras un accidente de estudio que, según su versión, los transformó en androides — una historia probablemente ficticia pero brillante en marketing.","Los cascos les permitieron mantener su vida privada (Thomas Bangalter y Guy-Manuel de Homem-Christo son parisinos) mientras creaban una identidad visual icónica.","Random Access Memories (2013) ganó 5 premios Grammy y Get Lucky se convirtió en una de las canciones más escuchadas de la década — su disolución en 2021 fue un evento cultural."]
},
'e354': {
  fr:["« Rocket 88 » a été enregistré au studio Sun Records de Sam Phillips à Memphis — le même studio qui découvrira Elvis Presley trois ans plus tard.","L'amplificateur de guitare utilisé pour l'enregistrement était endommagé — la distorsion accidentelle a créé un son nouveau qui est devenu la signature du rock.","Le débat sur la « première chanson rock » continue : d'autres candidats incluent « Good Rockin' Tonight » (1947) et « Rock Around the Clock » (1954)."],
  en:["'Rocket 88' was recorded at Sam Phillips' Sun Records studio in Memphis — the same studio that would discover Elvis Presley three years later.","The guitar amplifier used for the recording was damaged — the accidental distortion created a new sound that became rock's signature.","Debate over the 'first rock song' continues: other candidates include 'Good Rockin' Tonight' (1947) and 'Rock Around the Clock' (1954)."],
    es:["Rocket 88 de Jackie Brenston (1951, producida por Ike Turner) es generalmente considerada la primera canción de rock and roll — aunque el debate sobre el «primer rock» no tiene respuesta definitiva.","La distorsión de la guitarra, causada por un amplificador dañado durante el transporte, fue conservada deliberadamente — un accidente que definió el sonido del rock.","Chuck Berry, Little Richard, Fats Domino y Elvis Presley popularizaron el género entre 1955 y 1957 — el rock and roll fusionó el blues negro y el country blanco, desafiando la segregación racial."]
},
'e355': {
  fr:["Götterdämmerung (Le Crépuscule des dieux) est le quatrième et dernier opéra du cycle « L'Anneau du Nibelung » de Wagner — le cycle entier dure environ 15 heures.","Wagner a fait construire un théâtre spécial à Bayreuth (Allemagne) uniquement pour jouer ses opéras — le Festspielhaus, inauguré en 1876.","L'orchestre de Götterdämmerung compte plus de 100 musiciens — Wagner exigeait des instruments spéciaux comme les tubas Wagner, qu'il a fait fabriquer sur mesure."],
  en:["Götterdämmerung (Twilight of the Gods) is the fourth and final opera in Wagner's 'Ring of the Nibelung' cycle — the full cycle runs about 15 hours.","Wagner had a special theatre built in Bayreuth, Germany, solely to perform his operas — the Festspielhaus, opened in 1876.","Götterdämmerung's orchestra exceeds 100 players — Wagner demanded special instruments like Wagner tubas, custom-made to his specifications."],
    es:["Götterdämmerung (El ocaso de los dioses) de Wagner dura unas 4 horas y 45 minutos — es la última ópera del ciclo del Anillo del Nibelungo, que en total dura más de 15 horas.","Wagner construyó el Festspielhaus de Bayreuth (1876) específicamente para representar sus óperas — un teatro con foso de orquesta oculto y acústica revolucionaria.","El leitmotiv wagneriano (tema musical asociado a un personaje o idea) influyó directamente en la música de cine — John Williams reconoce abiertamente la deuda de Star Wars con Wagner."]
},
'e356': {
  fr:["McCartney a dit que la mélodie lui est venue dans un rêve — il a d'abord pensé qu'il l'avait involontairement copiée d'un autre artiste.","Le titre de travail était « Scrambled Eggs » (œufs brouillés) — McCartney chantait « Scrambled eggs, oh my baby how I love your legs » en attendant les vraies paroles.","La chanson n'a d'abord pas convaincu les autres Beatles — elle a finalement été enregistrée en solo par McCartney avec un quatuor à cordes."],
  en:["McCartney said the melody came to him in a dream — he first thought he had unconsciously copied it from another artist.","The working title was 'Scrambled Eggs' — McCartney sang 'Scrambled eggs, oh my baby how I love your legs' while waiting for real lyrics.","The song didn't initially convince the other Beatles — it was ultimately recorded solo by McCartney with a string quartet."],
    es:["Yesterday de los Beatles ha sido versionada más de 2 200 veces por artistas de todos los géneros — desde Frank Sinatra hasta Boyz II Men, pasando por orquestas clásicas y grupos de jazz.","McCartney compuso la melodía en un sueño y la canturreó durante semanas con la letra provisional «Scrambled eggs, oh my baby how I love your legs» antes de escribir la versión final.","La canción usa una estructura armónica inusual para el pop (progresión descendente cromática) que le da su cualidad melancólica única — un puente entre la canción popular y la música culta."]
},
'e357': {
  fr:["Le Tour a été créé en 1903 par le journal L'Auto pour booster ses ventes — le premier Tour ne comptait que 60 coureurs et 6 étapes.","Le maillot jaune est apparu en 1919 — sa couleur correspond à celle du papier du journal L'Auto qui sponsorisait la course.","Les coureurs brûlent environ 6 000 à 8 000 calories par jour pendant le Tour — ils doivent manger en pédalant pour compenser cette dépense énergétique."],
  en:["The Tour was created in 1903 by newspaper L'Auto to boost sales — the first Tour had only 60 riders and 6 stages.","The yellow jersey appeared in 1919 — its colour matches the paper of L'Auto newspaper, which sponsored the race.","Riders burn about 6,000 to 8,000 calories per day during the Tour — they must eat while pedalling to offset this energy expenditure."],
    es:["El Tour de Francia cubre más de 3 500 km en 23 etapas durante 3 semanas — los ciclistas queman entre 5 000 y 8 000 calorías diarias y pierden hasta 5 kg durante la carrera.","Henri Desgrange creó el Tour en 1903 para promocionar el periódico L'Auto — el primer Tour tenía solo 6 etapas y 60 participantes, de los cuales solo 21 terminaron.","El maillot jaune (maillot amarillo) fue introducido en 1919 para que el líder fuera fácilmente identificable por los espectadores — su color viene del papel amarillo del periódico L'Auto."]
},
'e358': {
  fr:["Owens a remporté le 100 m, le 200 m, le saut en longueur et le relais 4×100 m — une performance inégalée pendant 48 ans, jusqu'à Carl Lewis en 1984.","Contrairement à la légende, Hitler n'a pas explicitement snobé Owens — il avait cessé de féliciter tous les athlètes après le premier jour sur ordre du CIO.","De retour aux États-Unis, Owens n'a pas reçu de félicitations du président Roosevelt — il a déclaré : « Hitler ne m'a pas snobé, c'est notre président qui l'a fait. »"],
  en:["Owens won the 100 m, 200 m, long jump, and 4×100 m relay — a feat unmatched for 48 years, until Carl Lewis in 1984.","Contrary to legend, Hitler didn't explicitly snub Owens — he had stopped congratulating all athletes after day one on IOC orders.","Back in the US, Owens received no congratulations from President Roosevelt — he said: 'Hitler didn't snub me, it was our president who did.'"],
    es:["Jesse Owens ganó 4 medallas de oro en los Juegos de Berlín 1936, humillando la ideología de supremacía racial nazi ante los ojos del mundo.","Owens estableció récords mundiales en los 100 m, 200 m, salto de longitud y relevos 4×100 m — su marca de salto de longitud (8,06 m) perduró 25 años.","A pesar de su hazaña, Owens fue ignorado por el presidente Roosevelt (que no lo invitó a la Casa Blanca) y tuvo que competir contra caballos para ganarse la vida al volver a EE.UU."]
},
'e359': {
  fr:["Le crawl moderne a été popularisé par le nageur australien Richard Cavill au début du XXe siècle — il s'est inspiré des techniques de nage des peuples du Pacifique Sud.","Lors du 50 m nage libre, les nageurs olympiques passent près de 60 % de la course sous l'eau — les coulées sous-marines sont plus rapides que la nage en surface.","La combinaison en polyuréthane, qui améliorait la flottabilité et réduisait la friction, a été interdite en 2010 après une avalanche de records jugés artificiels."],
  en:["Modern front crawl was popularised by Australian swimmer Richard Cavill in the early 20th century — he drew from South Pacific islanders' swimming techniques.","In the 50 m freestyle, Olympic swimmers spend nearly 60% of the race underwater — underwater phases are faster than surface swimming.","The polyurethane bodysuit, which improved buoyancy and reduced drag, was banned in 2010 after a wave of records deemed artificial."],
    es:["El récord mundial de 100 m en natación estilo crawl está por debajo de los 47 segundos — un nadador olímpico avanza a unos 7,6 km/h, más rápido que la mayoría de personas corriendo.","La técnica del crawl combina la rotación del cuerpo, el tirón subacuático, el batido de piernas y la respiración bilateral — cada detalle puede significar centésimas de segundo.","Los trajes de poliuretano fueron prohibidos en 2010 tras una avalancha de récords: 43 récords mundiales cayeron en el Mundial de Roma 2009 con trajes que reducían la resistencia un 10 %."]
},
'e360': {
  fr:["Le run de Vienne en 2019 n'est pas reconnu comme record officiel car Kipchoge bénéficiait de lièvres en rotation et d'une voiture laser de rythme.","Le record officiel du marathon est de 2h00m35s, détenu par Kelvin Kiptum (Chicago 2023) — tragiquement décédé dans un accident de voiture en février 2024.","Les scientifiques estiment que la limite physiologique humaine du marathon se situe autour de 1h55 — un temps qui pourrait être atteint d'ici 2050."],
  en:["The 2019 Vienna run isn't recognised as an official record because Kipchoge had rotating pacers and a laser-pacing car.","The official marathon record is 2h00m35s, held by Kelvin Kiptum (Chicago 2023) — tragically killed in a car accident in February 2024.","Scientists estimate the human physiological marathon limit is around 1h55 — a time that could be reached by 2050."],
    es:["Eliud Kipchoge corrió los 42,195 km en 1:59:40 en Viena en 2019 (proyecto INEOS 1:59 Challenge), pero la marca no fue homologada por la IAAF debido a las condiciones controladas.","Su récord oficial es de 2:01:09, establecido en el maratón de Berlín 2022 — el circuito plano y el clima fresco de Berlín lo convierten en la pista de maratón más rápida del mundo.","Kipchoge es considerado el mayor maratonista de la historia: 2 oros olímpicos, 15 de 19 maratones ganados y un dominio inigualado que ha durado más de una década."]
},
'e361': {
  fr:["Kano a créé le judo à partir du jujitsu traditionnel en éliminant les techniques les plus dangereuses — il voulait un art martial éducatif et sûr.","Le principe fondamental du judo est « seiryoku zen'yō » (utilisation optimale de l'énergie) — vaincre un adversaire plus fort grâce à la technique, pas la force brute.","Le judo est entré aux Jeux olympiques en 1964 à Tokyo — un choix symbolique puisque le Japon est le pays d'origine de cet art martial."],
  en:["Kano created judo from traditional jujitsu by removing the most dangerous techniques — he wanted a safe, educational martial art.","Judo's fundamental principle is 'seiryoku zen'yō' (optimal use of energy) — defeating a stronger opponent through technique, not brute force.","Judo entered the Olympics in 1964 in Tokyo — a symbolic choice since Japan is the sport's country of origin."],
    es:["Jigoro Kano fundó el judo en 1882 como una síntesis de técnicas de jiu-jitsu orientada hacia la educación moral y física — «el camino de la suavidad» (ju = suavidad, do = camino).","Kano eliminó las técnicas mortales del jiu-jitsu y añadió un sistema de competición con reglas claras — transformando un arte marcial de combate en un deporte educativo.","El judo fue el primer arte marcial incluido en los Juegos Olímpicos (Tokio 1964) y es hoy practicado por más de 50 millones de personas en más de 200 países."]
},
'e362': {
  fr:["Les épreuves olympiques de surf aux JO de Paris 2024 se sont tenues à Tahiti (Teahupo'o) — à 15 000 km de Paris, pour bénéficier des meilleures vagues.","Le surf a été inventé par les Polynésiens il y a plus de 3 000 ans — les premiers explorateurs européens ont décrit des Hawaïens surfant au XVIIIe siècle.","Duke Kahanamoku, nageur olympique hawaïen, est considéré comme le père du surf moderne — il a popularisé le sport dans le monde entier au début du XXe siècle."],
  en:["Olympic surfing events at the Paris 2024 Games were held in Tahiti (Teahupo'o) — 15,000 km from Paris, to get the best waves.","Surfing was invented by Polynesians over 3,000 years ago — early European explorers described Hawaiians surfing in the 18th century.","Duke Kahanamoku, Hawaiian Olympic swimmer, is considered the father of modern surfing — he popularised the sport worldwide in the early 20th century."],
    es:["El surf debutó en los Juegos Olímpicos de Tokio 2020 en la playa de Tsurigasaki — las olas naturales hacen de cada competición un evento impredecible, a diferencia de los deportes en pista.","Para París 2024, la competición se trasladó a Teahupoo (Tahití), a 15 700 km de París — la ola más peligrosa y espectacular del circuito mundial.","Duke Kahanamoku, el «padre del surf moderno», introdujo el deporte en Australia y California a principios del siglo XX — antes era una práctica sagrada de la realeza hawaiana."]
},
'e363': {
  fr:["Les alvéoles réduisent la traînée aérodynamique en créant une fine couche de turbulence qui maintient l'air collé à la balle plus longtemps.","Une balle de golf avec alvéoles vole environ deux fois plus loin qu'une balle lisse — la différence peut atteindre 130 mètres.","Une balle standard possède entre 300 et 500 alvéoles — leur nombre, taille et profondeur sont optimisés par des ingénieurs en aérodynamique."],
  en:["Dimples reduce aerodynamic drag by creating a thin layer of turbulence that keeps air hugging the ball longer.","A dimpled golf ball flies roughly twice as far as a smooth one — the difference can reach 130 metres.","A standard ball has between 300 and 500 dimples — their number, size, and depth are optimised by aerodynamic engineers."],
    es:["Las 300-500 alvéoles de una pelota de golf reducen la resistencia aerodinámica (drag) y aumentan la sustentación (lift), permitiéndola volar 2,5 veces más lejos que una bola lisa.","Las alvéoles crean una capa límite turbulenta que se adhiere mejor a la superficie — reduciendo la zona de baja presión detrás de la pelota que la frenaría.","Los fabricantes invierten millones en optimizar el número, la profundidad y la disposición de las alvéoles — cada modelo es el resultado de simulaciones aerodinámicas computacionales."]
},
'e364': {
  fr:["Phelps a participé à 5 Jeux olympiques de 2000 à 2016 — remportant au total 28 médailles dont 23 en or, 3 en argent et 2 en bronze.","Son envergure de bras (2,01 m) dépasse sa taille (1,93 m) de 8 cm — un avantage anatomique rare qui contribue à son efficacité dans l'eau.","Phelps a pris sa retraite en 2016, puis est devenu un ambassadeur de la santé mentale — il a parlé ouvertement de sa dépression et de ses pensées suicidaires."],
  en:["Phelps competed in 5 Olympics from 2000 to 2016 — winning 28 medals total: 23 gold, 3 silver, and 2 bronze.","His arm span (2.01 m) exceeds his height (1.93 m) by 8 cm — a rare anatomical advantage contributing to his water efficiency.","Phelps retired in 2016, then became a mental health ambassador — he spoke openly about his depression and suicidal thoughts."],
    es:["Michael Phelps tiene 23 medallas de oro olímpicas individuales y 3 más en relevo — más oros que la mayoría de los países del mundo en toda su historia olímpica.","Su envergadura (2,01 m para 1,93 m de talla), sus pies talla 47 y su producción reducida de ácido láctico le otorgan ventajas biomecánicas que pocos humanos comparten.","Phelps ha hablado abiertamente de su lucha contra la depresión y las ideas suicidas — su testimonio ha ayudado a desestigmatizar los problemas de salud mental en el deporte de élite."]
},
'e365': {
  fr:["Un match de cricket test peut durer jusqu'à 5 jours — c'est le format le plus long de tous les sports professionnels.","L'Indian Premier League (IPL) est la ligue sportive la plus riche d'Asie — les droits TV ont été vendus pour 6,2 milliards de dollars en 2023.","Le cricket a été inventé en Angleterre au XVIe siècle et exporté dans les colonies britanniques — c'est pourquoi l'Inde, le Pakistan et l'Australie dominent le sport."],
  en:["A test cricket match can last up to 5 days — the longest format in all professional sports.","The Indian Premier League (IPL) is Asia's richest sports league — TV rights sold for $6.2 billion in 2023.","Cricket was invented in England in the 16th century and exported to British colonies — which is why India, Pakistan, and Australia dominate the sport."],
    es:["El cricket es seguido por más de 2 500 millones de fans, principalmente en India, Pakistán, Australia, Inglaterra y el Caribe — la Indian Premier League genera más de 11 000 millones de dólares.","Un partido de Test Cricket puede durar 5 días con pausas para el té — la versión T20 (20 overs) se juega en 3 horas y ha modernizado el deporte para las nuevas generaciones.","India es la superpotencia del cricket: la BCCI (Board of Control for Cricket in India) controla más del 70 % de los ingresos mundiales del cricket."]
},
'e366': {
  fr:["Une année bissextile survient tous les 4 ans pour compenser le fait que la Terre met 365,2422 jours à orbiter autour du Soleil — sans ce jour supplémentaire, les saisons dériveraient.","Les années divisibles par 100 ne sont pas bissextiles, sauf si elles sont aussi divisibles par 400 — c'est pourquoi 1900 n'était pas bissextile mais 2000 l'était.","Les personnes nées un 29 février sont appelées « leaplings » en anglais — la probabilité de naître ce jour est d'environ 1 sur 1 461."],
  en:["A leap year occurs every 4 years to compensate for Earth taking 365.2422 days to orbit the Sun — without this extra day, seasons would drift.","Years divisible by 100 are not leap years, unless also divisible by 400 — which is why 1900 was not a leap year but 2000 was.","People born on 29 February are called 'leaplings' — the probability of being born that day is about 1 in 1,461."],
    es:["El 29 de febrero solo ocurre cada 4 años (excepto los años divisibles por 100 pero no por 400) — el calendario gregoriano corrige el desfase entre el año solar (365,2422 días) y el calendario.","Las personas nacidas el 29 de febrero se llaman «leaplings» en inglés: solo celebran su «verdadero» cumpleaños una vez cada 4 años — aunque legalmente cumplen años el 1 de marzo o el 28 de febrero.","La probabilidad de nacer un 29 de febrero es de 1/1461 — hay unos 5 millones de leaplings en el mundo, y tienen sus propias comunidades y celebraciones especiales."]
}
});

// === BATCH 3 DEEP DIVES (IDs 21-30 per category) ===
Object.assign(DEEP_DIVES, {

's21': {
  fr:["Ce phénomène s'appelle l'hydrotropisme acoustique — les racines captent les vibrations de l'eau à plusieurs mètres de distance.","L'étude pionnière de Monica Gagliano (2017) a montré que les racines de pois choisissaient un tuyau avec de l'eau courante plutôt qu'un sol humide silencieux.","Les plantes émettent aussi des clics ultrasoniques quand elles manquent d'eau — des sons inaudibles pour nous mais détectables par des capteurs sensibles."],
  en:["This phenomenon is called acoustic hydrotropism — roots can detect water vibrations from several meters away.","Monica Gagliano's pioneering 2017 study showed pea roots chose a pipe with running water over silently moist soil.","Plants also emit ultrasonic clicks when water-stressed — sounds inaudible to us but detectable by sensitive equipment."],
    es:["Este fenómeno se llama hidrotropismo acústico — las raíces captan vibraciones del agua a través del suelo para orientar su crecimiento.","Un estudio de 2017 de la Universidad de Western Australia demostró que las raíces de los guisantes crecen hacia fuentes de sonido de agua.","Esta capacidad desafía la idea de que las plantas son organismos pasivos: perciben su entorno y responden activamente a él."]
},
's22': {
  fr:["Ce record a été obtenu en 2021 par des physiciens allemands à l'université de Brême, en lâchant un nuage d'atomes de rubidium en chute libre.","À cette température, la matière forme un condensat de Bose-Einstein — un état où des milliers d'atomes se comportent comme une seule particule quantique.","Le zéro absolu (0 Kelvin, soit −273,15 °C) est théoriquement inatteignable — mais 38 picoKelvins n'en sont qu'à 0,000000000038 degré."],
  en:["This record was achieved in 2021 by German physicists at the University of Bremen, dropping a rubidium atom cloud in free fall.","At this temperature, matter forms a Bose-Einstein condensate — a state where thousands of atoms behave as a single quantum particle.","Absolute zero (0 Kelvin, or −273.15°C) is theoretically unreachable — but 38 picoKelvins is only 0.000000000038 degrees away."],
    es:["Este récord fue logrado en 2021 por físicos alemanes de la Universidad de Brunswick, alcanzando la temperatura más baja jamás registrada en laboratorio.","A esta temperatura, los átomos casi dejan de moverse y aparecen efectos cuánticos macroscópicos como la condensación de Bose-Einstein.","El cero absoluto teórico (0 K = −273,15 °C) es inalcanzable según la tercera ley de la termodinámica — pero nos acercamos cada vez más."]
},
's23': {
  fr:["Un éclair typique dure moins d'une seconde et libère environ 1 à 5 milliards de joules — mais en quelques microsecondes seulement.","Des chercheurs tentent de capturer cette énergie avec des tours paratonnerres spéciales, mais le rendement reste inférieur à 0,1 %.","La température d'un éclair atteint 30 000 °C — cinq fois plus chaud que la surface du Soleil, ce qui crée l'onde de choc qu'on entend comme le tonnerre."],
  en:["A typical lightning bolt lasts less than a second and releases about 1 to 5 billion joules — but in just a few microseconds.","Researchers are trying to capture this energy with special lightning rod towers, but efficiency remains below 0.1%.","Lightning reaches 30,000°C — five times hotter than the Sun's surface, creating the shockwave we hear as thunder."],
    es:["Un rayo típico dura menos de un segundo y libera entre 1 000 y 5 000 millones de julios de energía — equivalente a unos 150 litros de gasolina.","La mayor parte de esta energía se disipa en forma de calor, luz y sonido — capturarla para uso práctico es técnicamente inviable con la tecnología actual.","Los rayos fijan nitrógeno atmosférico en el suelo (unas 250 000 toneladas al año), un fertilizante natural que beneficia a los ecosistemas."]
},
's24': {
  fr:["Contrairement aux cristaux classiques qui ont une structure répétitive dans l'espace, les cristaux de temps ont une structure répétitive dans le temps.","Google et des physiciens de Stanford ont créé un cristal de temps dans un processeur quantique en 2021, confirmant leur existence pratique.","Ces cristaux pourraient révolutionner le stockage quantique d'information car ils maintiennent leur état sans apport d'énergie extérieure."],
  en:["Unlike regular crystals with repeating patterns in space, time crystals have repeating patterns in time.","Google and Stanford physicists created a time crystal in a quantum processor in 2021, confirming their practical existence.","These crystals could revolutionize quantum information storage because they maintain their state without external energy input."],
    es:["A diferencia de los cristales clásicos que tienen una estructura repetitiva, los cuasicristales tienen simetría de rotación pero no periodicidad traslacional.","Dan Shechtman descubrió los cuasicristales en 1982 y recibió el Nobel de Química en 2011 — al principio fue ridiculizado por la comunidad científica.","Los cuasicristales se han encontrado en meteoritos, lo que sugiere que pueden formarse de manera natural en condiciones extremas."]
},
's25': {
  fr:["Cet effet, prédit par Einstein en 1915, a été mesuré avec des horloges atomiques embarquées dans des avions dès 1971 (expérience Hafele-Keating).","Les satellites GPS doivent corriger ce décalage de 38 microsecondes par jour — sans correction, les positions dériveraient de 10 km par jour.","Au sommet de l'Everest, tu vieillis d'environ 15 microsecondes de plus par an qu'au niveau de la mer — infime mais mesurable."],
  en:["This effect, predicted by Einstein in 1915, was measured with atomic clocks on airplanes in 1971 (Hafele-Keating experiment).","GPS satellites must correct for this 38-microsecond daily drift — without correction, positions would shift by 10 km per day.","On top of Everest, you age about 15 microseconds more per year than at sea level — tiny but measurable."],
    es:["Este efecto, predicho por Einstein en 1915, fue medido con relojes atómicos en aviones y satélites — confirmando que la gravedad ralentiza el tiempo.","Los relojes del GPS deben corregir este efecto: sin la corrección relativista, la posición se desviaría unos 10 km por día.","A nivel del mar, el tiempo pasa más lento que en la cima de una montaña — una diferencia real aunque infinitesimal en la vida cotidiana."]
},
's26': {
  fr:["La NASA a mené des expériences de combustion sur l'ISS (projet FLEX) pour étudier ces flammes sphériques depuis 2009.","Ces flammes brûlent plus lentement et à plus basse température, ce qui a conduit à la découverte de « flammes froides » invisibles à l'œil nu.","Comprendre la combustion en microgravité est essentiel pour la sécurité des futures missions habitées vers Mars."],
  en:["NASA has conducted combustion experiments on the ISS (FLEX project) to study these spherical flames since 2009.","These flames burn slower and at lower temperatures, leading to the discovery of 'cool flames' invisible to the naked eye.","Understanding combustion in microgravity is essential for safety on future crewed missions to Mars."],
    es:["La NASA realizó experimentos de combustión en la ISS (proyecto FLEX) para estudiar cómo arden las llamas en microgravedad.","En el espacio, las llamas son esféricas y azules porque la convección no existe sin gravedad — los gases calientes no suben.","Estos experimentos ayudan a diseñar sistemas de extinción de incendios para futuras estaciones espaciales y misiones a Marte."]
},
's27': {
  fr:["Le mythe du « verre liquide » vient des vitraux médiévaux plus épais en bas — mais c'est dû au procédé de soufflage en couronne qui produisait des plaques irrégulières.","Le verre de transition se forme quand un liquide refroidit trop vite pour cristalliser — ses molécules se figent dans un désordre gelé.","L'obsidienne, le verre volcanique naturel, prouve que ce phénomène existe dans la nature depuis des millions d'années."],
  en:["The 'liquid glass' myth comes from medieval windows being thicker at the bottom — but that's due to the crown glass blowing process which produced uneven panes.","Transition glass forms when liquid cools too fast to crystallize — its molecules freeze in a locked disorder.","Obsidian, natural volcanic glass, proves this phenomenon has existed in nature for millions of years."],
    es:["El mito del vidrio líquido viene de los vitrales medievales más gruesos en la base — pero esto se debe al método de fabricación, no al flujo.","El vidrio soplado en corona producía paneles de espesor irregular que los vidrieros colocaban con la parte más gruesa abajo por estabilidad.","La viscosidad del vidrio a temperatura ambiente es tan alta que tardaría más que la edad del universo en deformarse visiblemente."]
},
's28': {
  fr:["Ce parcours chaotique s'appelle la « marche aléatoire » — le photon est absorbé et réémis des milliards de fois avant d'atteindre la surface.","Une fois en surface, ce même photon ne met plus que 8 minutes et 20 secondes pour parcourir les 150 millions de km jusqu'à la Terre.","Le noyau du Soleil est si dense (150 tonnes par mètre cube) qu'un photon y parcourt en moyenne moins d'un centimètre entre chaque collision."],
  en:["This chaotic journey is called a 'random walk' — the photon is absorbed and re-emitted billions of times before reaching the surface.","Once at the surface, that same photon takes only 8 minutes and 20 seconds to travel 150 million km to Earth.","The Sun's core is so dense (150 tonnes per cubic meter) that a photon travels less than one centimeter on average between collisions."],
    es:["Este recorrido caótico se llama caminata aleatoria: el fotón es absorbido y reemitido millones de veces antes de llegar a la superficie solar.","Un fotón producido en el núcleo del Sol tarda entre 10 000 y 170 000 años en alcanzar la superficie — pero solo 8 minutos más en llegar a la Tierra.","Esta diferencia ilustra la densidad extrema del interior solar: la materia es tan densa que la luz avanza a paso de caracol."]
},
's29': {
  fr:["La plus destructrice tornade de feu documentée s'est formée lors du séisme de Tokyo en 1923, tuant 38 000 personnes en 15 minutes.","Les « fire whirls » se forment quand des vents convergents rencontrent un incendie intense — ils peuvent aspirer des débris à plus de 160 km/h.","L'incendie de Carr en Californie (2018) a généré une tornade de feu EF-3 avec des vents de 230 km/h — un phénomène extrêmement rare."],
  en:["The most destructive documented fire tornado formed during the 1923 Tokyo earthquake, killing 38,000 people in 15 minutes.","Fire whirls form when converging winds meet an intense blaze — they can suck in debris at over 160 km/h.","The 2018 Carr Fire in California generated an EF-3 fire tornado with 230 km/h winds — an extremely rare phenomenon."],
    es:["La tornado de fuego más destructiva documentada se formó durante el terremoto de Tokio de 1923, matando a 38 000 personas en un solo parque.","Los tornados de fuego se producen cuando el calor intenso de un incendio crea corrientes ascendentes que se combinan con vientos rotatorios.","Los incendios forestales de California y Australia han generado pirocúmulonimbos — nubes de tormenta alimentadas por el propio incendio que producen rayos y más fuego."]
},
's30': {
  fr:["L'éruption a produit un son de 310 décibels à la source — au-delà du seuil de douleur (120 dB), il aurait été fatal à proximité.","L'onde de choc a été enregistrée sur des baromètres du monde entier pendant 5 jours — elle a fait le tour de la Terre 3,5 fois.","L'éruption a projeté 25 km³ de roche dans l'atmosphère, abaissant la température mondiale de 1,2 °C pendant un an."],
  en:["The eruption produced a sound of 310 decibels at the source — beyond the pain threshold (120 dB), it would have been fatal nearby.","The shockwave was recorded on barometers worldwide for 5 days — it circled the Earth 3.5 times.","The eruption ejected 25 km³ of rock into the atmosphere, lowering global temperature by 1.2°C for a year."],
    es:["La erupción del Krakatoa en 1883 produjo un sonido de 310 decibelios en la fuente — más allá del umbral de dolor humano, audible a 5 000 km.","La onda expansiva dio tres vueltas a la Tierra y fue registrada por barómetros en todo el planeta durante 5 días.","La erupción expulsó 25 km³ de roca y ceniza, oscureció los cielos durante meses y redujo la temperatura global 1,2 °C durante un año."]
},


'p21': {
  fr:["Le lynx ibérique était classé « en danger critique » en 2002 — il est passé à « en danger » en 2015, puis « vulnérable » en 2024.","Le programme de reproduction en captivité a commencé avec seulement 4 femelles fertiles — un défi génétique considérable surmonté par les biologistes.","Plus de 400 lynx ont été réintroduits dans la nature entre 2014 et 2023, dans des zones protégées d'Espagne et du Portugal."],
  en:["The Iberian lynx was classified 'critically endangered' in 2002 — it moved to 'endangered' in 2015, then 'vulnerable' in 2024.","The captive breeding program started with only 4 fertile females — a major genetic challenge overcome by biologists.","Over 400 lynx were reintroduced into the wild between 2014 and 2023, in protected areas of Spain and Portugal."],
    es:["El lince ibérico pasó de «en peligro crítico» en 2002 a «vulnerable» en 2015 gracias a programas de cría en cautividad y reintroducción.","De menos de 100 ejemplares en 2002, la población superó los 1 600 en 2023 — una de las recuperaciones más espectaculares de un felino salvaje.","La conservación del lince ibérico benefició también al ecosistema mediterráneo: su presencia regula las poblaciones de conejos y mejora la biodiversidad."]
},
'p22': {
  fr:["L'Éthiopie a été l'un des plus grands succès : le taux de scolarisation primaire est passé de 30 % en 2000 à plus de 85 % en 2020.","L'éducation des filles a particulièrement progressé — dans certains pays d'Afrique de l'Ouest, le ratio filles/garçons à l'école a doublé en 20 ans.","Des programmes comme « School Feeding » de l'ONU ont montré que fournir un repas à l'école augmente la fréquentation de 10 à 30 %."],
  en:["Ethiopia was one of the biggest successes: primary enrollment rose from 30% in 2000 to over 85% in 2020.","Girls' education improved dramatically — in some West African countries, the girls-to-boys ratio in school doubled in 20 years.","Programs like the UN's 'School Feeding' showed that providing a school meal increases attendance by 10 to 30%."],
    es:["Etiopía fue uno de los mayores éxitos: la tasa de escolarización primaria pasó del 21 % en 1994 al 85 % en 2020.","La educación de las niñas ha sido el mayor motor de cambio: cada año adicional de escolarización reduce la mortalidad infantil un 5-10 %.","Los programas de becas condicionadas (transferencias monetarias a familias que escolarizan a sus hijos) han demostrado una eficacia probada."]
},
'p23': {
  fr:["Le Costa Rica tire la majorité de son électricité de l'hydroélectricité (70 %), complétée par la géothermie (15 %) et l'éolien (12 %).","Le pays a fonctionné pendant 300 jours consécutifs à 100 % d'énergie renouvelable en 2017 — un record mondial.","Le Costa Rica vise la neutralité carbone totale d'ici 2050, incluant les transports et l'agriculture — un objectif parmi les plus ambitieux au monde."],
  en:["Costa Rica draws most of its electricity from hydropower (70%), supplemented by geothermal (15%) and wind (12%).","The country ran for 300 consecutive days on 100% renewable energy in 2017 — a world record.","Costa Rica aims for total carbon neutrality by 2050, including transport and agriculture — one of the world's most ambitious targets."],
    es:["Costa Rica obtiene la mayoría de su electricidad de la hidroeléctrica (70 %), la geotérmica (15 %) y la eólica/solar (15 %).","El país funcionó con 100 % de electricidad renovable durante 300 días en 2017 — un récord para un país de su tamaño.","Costa Rica demuestra que un país tropical de renta media puede descarbonizar su red eléctrica sin sacrificar el crecimiento económico."]
},
'p24': {
  fr:["Dans les années 1920, les catastrophes naturelles tuaient en moyenne 500 000 personnes par an — aujourd'hui c'est environ 10 000 à 15 000.","Le Bangladesh, frappé par un cyclone qui tua 300 000 personnes en 1970, n'a perdu que 12 personnes lors d'un cyclone similaire en 2023 grâce aux abris et alertes.","Les systèmes d'alerte tsunami, inexistants avant 2004, couvrent désormais l'océan Indien, le Pacifique et la Méditerranée."],
  en:["In the 1920s, natural disasters killed an average of 500,000 people per year — today it's about 10,000 to 15,000.","Bangladesh, hit by a cyclone that killed 300,000 in 1970, lost only 12 people in a similar cyclone in 2023 thanks to shelters and alerts.","Tsunami warning systems, nonexistent before 2004, now cover the Indian Ocean, Pacific, and Mediterranean."],
    es:["En los años 1920, las catástrofes naturales mataban en promedio a 500 000 personas por década — hoy esa cifra es inferior a 100 000.","La meteorología satelital, las alertas tempranas y las infraestructuras antisísmicas salvan miles de vidas cada año.","Bangladesh pasó de 500 000 muertos en el ciclón Bhola (1970) a menos de 200 en el ciclón Amphan (2020) — gracias a refugios y evacuaciones."]
},
'p25': {
  fr:["L'état de l'Uttar Pradesh a mobilisé 800 000 volontaires pour planter ces arbres en une seule journée le long du Gange et de ses affluents.","Le taux de survie des arbres plantés lors de ces campagnes massives est estimé entre 60 et 80 %, ce qui reste significatif à cette échelle.","L'Éthiopie a rivalisé en plantant 350 millions d'arbres en 12 heures la même année — la course au reboisement est devenue mondiale."],
  en:["The state of Uttar Pradesh mobilized 800,000 volunteers to plant these trees in a single day along the Ganges and its tributaries.","The survival rate of trees planted during these massive campaigns is estimated at 60 to 80%, which remains significant at this scale.","Ethiopia competed by planting 350 million trees in 12 hours the same year — the reforestation race has gone global."],
    es:["El estado de Uttar Pradesh (India) movilizó a 800 000 voluntarios para plantar 220 millones de árboles en un solo día en 2019.","La reforestación masiva combate la erosión, captura carbono, restaura la biodiversidad y mejora los medios de vida rurales.","Otros países han seguido el ejemplo: Etiopía plantó 350 millones de árboles en 12 horas en 2019 — otro récord mundial."]
},
'p26': {
  fr:["En 1820, seulement 12 % de la population mondiale savait lire — il a fallu deux siècles pour atteindre le niveau actuel.","L'UNESCO estime que chaque année supplémentaire de scolarisation augmente les revenus d'un individu de 10 % en moyenne.","La Corée du Sud est passée de 22 % d'alphabétisation en 1945 à 99 % en une seule génération — l'une des progressions les plus rapides de l'histoire."],
  en:["In 1820, only 12% of the world's population could read — it took two centuries to reach the current level.","UNESCO estimates that each additional year of schooling increases an individual's earnings by 10% on average.","South Korea went from 22% literacy in 1945 to 99% in a single generation — one of the fastest progressions in history."],
    es:["En 1820, solo el 12 % de la población mundial sabía leer — hizo falta dos siglos de esfuerzo educativo para alcanzar el 86 % actual.","La imprenta (1450), la escolarización obligatoria (siglo XIX) y las campañas de alfabetización del siglo XX fueron los hitos clave.","La UNESCO estima que cada año adicional de escolarización aumenta los ingresos de una persona un 10 % — la educación es la mejor inversión."]
},
'p27': {
  fr:["L'Inde abrite environ 75 % des tigres sauvages du monde et a doublé sa population depuis 2006 grâce à des réserves protégées.","Le Népal est en passe de devenir le premier pays à doubler sa population de tigres depuis le sommet mondial de Saint-Pétersbourg en 2010.","La technologie des pièges photographiques et l'IA permettent désormais d'identifier chaque tigre individuellement par ses rayures uniques."],
  en:["India is home to about 75% of the world's wild tigers and has doubled its population since 2006 through protected reserves.","Nepal is on track to become the first country to double its tiger population since the 2010 St. Petersburg global summit.","Camera trap technology and AI now allow researchers to identify each tiger individually by its unique stripe pattern."],
    es:["India alberga el 75 % de los tigres salvajes del mundo y ha duplicado su población de tigres de 1 411 en 2006 a más de 3 000 en 2023.","Project Tiger, lanzado en 1973, creó 53 reservas de tigres que protegen más de 75 000 km² de hábitat.","La recuperación del tigre beneficia a todo el ecosistema: como superdepredador, regula las poblaciones de herbívoros y mantiene el equilibrio forestal."]
},
'p28': {
  fr:["Le Protocole de Montréal (1987) est considéré comme le traité environnemental le plus réussi de l'histoire — 197 pays l'ont ratifié.","Sans ce protocole, les scientifiques estiment que la couche d'ozone aurait été détruite à 67 % d'ici 2065, rendant la vie en surface dangereuse.","La couche d'ozone devrait retrouver son niveau de 1980 vers 2066 au-dessus de l'Antarctique — la preuve que l'action collective fonctionne."],
  en:["The Montreal Protocol (1987) is considered the most successful environmental treaty in history — 197 countries ratified it.","Without this protocol, scientists estimate the ozone layer would have been 67% depleted by 2065, making surface life dangerous.","The ozone layer is expected to return to its 1980 level around 2066 over Antarctica — proof that collective action works."],
    es:["El Protocolo de Montreal (1987) es considerado el tratado medioambiental más exitoso de la historia — ratificado por los 198 países miembros de la ONU.","Sin él, la radiación UV habría aumentado un 550 % para 2100, causando millones de casos de cáncer de piel y cataratas.","Su éxito demuestra que la cooperación internacional puede resolver problemas ambientales — un precedente esperanzador para el cambio climático."]
},
'p29': {
  fr:["À l'aéroport de Kigali, les douaniers confisquent tous les sacs plastiques des voyageurs — une mesure stricte mais efficace.","Le Rwanda organise chaque dernier samedi du mois l'« Umuganda », une journée de travaux communautaires où les citoyens nettoient ensemble leur quartier.","Cette politique a inspiré plus de 90 pays à adopter des restrictions similaires sur les plastiques à usage unique depuis 2008."],
  en:["At Kigali airport, customs officers confiscate all plastic bags from travelers — a strict but effective measure.","Rwanda organizes 'Umuganda' every last Saturday of the month, a community work day where citizens clean their neighborhood together.","This policy has inspired over 90 countries to adopt similar restrictions on single-use plastics since 2008."],
    es:["En el aeropuerto de Kigali (Ruanda), los aduaneros confiscan todas las bolsas de plástico de los viajeros — el país prohibió el plástico de un solo uso en 2008.","Ruanda es hoy uno de los países más limpios de África: jornadas comunitarias de limpieza (umuganda) se celebran el último sábado de cada mes.","Más de 90 países han adoptado alguna forma de regulación del plástico de un solo uso desde entonces — Ruanda fue pionero."]
},
'p30': {
  fr:["Le Cambodge a réduit sa mortalité maternelle de 82 % entre 2000 et 2020 — l'une des plus fortes baisses au monde.","L'accès aux sages-femmes qualifiées est le facteur le plus déterminant : les pays qui en ont formé massivement ont vu les décès chuter de 50 %.","L'OMS estime que 295 000 femmes meurent encore chaque année de causes liées à la grossesse — mais ce chiffre était de 451 000 en 2000."],
  en:["Cambodia reduced its maternal mortality by 82% between 2000 and 2020 — one of the steepest drops in the world.","Access to skilled midwives is the most decisive factor: countries that trained them massively saw deaths drop by 50%.","WHO estimates 295,000 women still die each year from pregnancy-related causes — but this figure was 451,000 in 2000."],
    es:["Camboya redujo su mortalidad materna un 82 % entre 2000 y 2020 — una de las mejoras más rápidas del mundo.","La formación de matronas comunitarias y la ampliación de centros de salud rurales fueron los factores clave de este progreso.","El acceso a cesáreas de emergencia en zonas rurales pasó del 1 % al 12 % en dos décadas — salvando miles de vidas."]
},

'u21': {
  fr:["La forme cubique est créée par les derniers 8 % de l'intestin du wombat, dont les parois ont des élasticités différentes qui moulent la matière en cubes.","Les wombats produisent entre 80 et 100 de ces cubes par nuit et les empilent sur des rochers et des souches pour marquer leur territoire.","Des ingénieurs de Georgia Tech ont étudié ce processus en 2018, espérant s'en inspirer pour fabriquer des objets cubiques sans moule."],
  en:["The cubic shape is created by the last 8% of the wombat's intestine, whose walls have varying elasticities that mold matter into cubes.","Wombats produce 80 to 100 of these cubes per night and stack them on rocks and stumps to mark territory.","Georgia Tech engineers studied this process in 2018, hoping to use it as inspiration for manufacturing cubic objects without molds."],
    es:["La forma cúbica se crea en el último 8 % del intestino del wombat, cuyas paredes tienen elasticidad variable que moldea las heces en cubos.","Los wombats marcan su territorio con heces apiladas — la forma cúbica evita que rueden y se mantengan visibles.","Un estudio de 2018 ganó el premio Ig Nobel de Física por explicar este fenómeno — la ciencia no tiene temas indignos."]
},
'u22': {
  fr:["Un cumulus typique mesure environ 1 km³ et contient 500 000 litres d'eau sous forme de gouttelettes microscopiques en suspension.","Ces gouttelettes sont si petites (10 à 20 microns) que les courants ascendants les maintiennent en l'air — elles tombent à seulement 1 cm/s.","Un cumulonimbus d'orage peut peser jusqu'à un million de tonnes et contenir assez d'eau pour remplir 400 piscines olympiques."],
  en:["A typical cumulus cloud measures about 1 km³ and contains 500,000 liters of water as suspended microscopic droplets.","These droplets are so tiny (10 to 20 microns) that updrafts keep them airborne — they fall at only 1 cm/s.","A cumulonimbus storm cloud can weigh up to one million tonnes and hold enough water to fill 400 Olympic pools."],
    es:["Un cúmulo típico mide unos 1 km³ y contiene 500 000 litros de agua en forma de minúsculas gotitas suspendidas.","A pesar de todo ese agua, un cúmulo pesa «solo» unas 500 toneladas — lo mismo que 100 elefantes flotando en el aire.","Las nubes flotan porque las gotitas son tan pequeñas (10-20 micrómetros) que las corrientes de aire ascendentes las mantienen en suspensión."]
},
'u23': {
  fr:["Le chimiste Wuzong Zhou de l'université de St Andrews a découvert ces nanodiamants en 2011 en analysant la base d'une flamme de bougie.","Ces diamants se forment dans la zone bleu foncé de la flamme, où la température atteint 1 400 °C et le carbone se restructure brièvement.","Environ 1,5 million de nanodiamants sont créés chaque seconde dans une flamme de bougie — puis brûlent immédiatement en CO₂."],
  en:["Chemist Wuzong Zhou at the University of St Andrews discovered these nanodiamonds in 2011 by analyzing the base of a candle flame.","These diamonds form in the dark blue zone of the flame, where temperature reaches 1,400°C and carbon briefly restructures.","About 1.5 million nanodiamonds are created every second in a candle flame — then immediately burn into CO₂."],
    es:["El químico Wuzong Zhou de la Universidad de St Andrews descubrió nanodiamantes en las llamas de velas usando microscopía electrónica de transmisión.","Cada segundo, una vela produce unos 1,5 millones de nanodiamantes que se transforman inmediatamente en CO₂ al ser quemados.","Este descubrimiento de 2011 demostró que los diamantes se forman en condiciones mucho más variadas de lo que se creía."]
},
'u24': {
  fr:["Ce phénomène s'appelle le « rope coiling » — il se produit avec tout fluide visqueux tombant d'une certaine hauteur, pas uniquement le miel.","La fréquence de rotation des spirales augmente quand le miel est plus froid (donc plus visqueux) — on peut compter jusqu'à 30 boucles par seconde.","Les physiciens utilisent ce phénomène pour modéliser des problèmes géologiques comme l'enroulement des coulées de lave sur les fonds océaniques."],
  en:["This phenomenon is called 'rope coiling' — it occurs with any viscous fluid falling from a certain height, not just honey.","The rotation frequency of the spirals increases when honey is colder (thus more viscous) — up to 30 loops per second can be counted.","Physicists use this phenomenon to model geological problems like lava flow coiling on ocean floors."],
    es:["Este fenómeno se llama rope coiling — se produce con todo fluido viscoso que cae en un chorro fino sobre una superficie.","La frecuencia de enrollamiento depende de la altura de caída, la viscosidad y el caudal — los físicos lo modelan con ecuaciones de fluidos.","La miel, el jarabe de chocolate y la masa de churros hacen exactamente lo mismo — es una propiedad universal de los fluidos viscosos."]
},
'u25': {
  fr:["Avec 50 personnes, la probabilité monte à 97 % — et à 70 personnes, elle atteint 99,9 %, quasiment une certitude.","Ce résultat est contre-intuitif car notre cerveau compare inconsciemment à 365 jours, alors qu'il faut compter les paires possibles (253 paires pour 23 personnes).","Ce paradoxe a des applications en cryptographie : il explique pourquoi les « attaques par anniversaire » peuvent casser certains algorithmes de hachage."],
  en:["With 50 people, the probability rises to 97% — and at 70 people, it reaches 99.9%, near certainty.","This result is counterintuitive because our brain unconsciously compares to 365 days, when we should count possible pairs (253 pairs for 23 people).","This paradox has cryptography applications: it explains why 'birthday attacks' can break certain hashing algorithms."],
    es:["Con 50 personas, la probabilidad sube al 97 % — y con 70 personas alcanza el 99,9 %. Es contraintuitivo pero matemáticamente riguroso.","La clave es que no se busca una fecha concreta sino cualquier coincidencia entre todos los pares posibles — y con 23 personas hay 253 pares.","Este problema ilustra lo mal que los humanos intuimos las probabilidades — nuestro cerebro no está diseñado para el cálculo combinatorio."]
},
'u26': {
  fr:["Les disques intervertébraux, normalement comprimés par la gravité, se remplissent de liquide en microgravité et s'épaississent.","Ce gain de taille cause souvent des douleurs dorsales aux astronautes — c'est l'une des plaintes médicales les plus fréquentes sur l'ISS.","Scott Kelly, après un an dans l'espace, avait grandi de 5 cm — il est revenu à sa taille normale en 48 heures sur Terre."],
  en:["Intervertebral discs, normally compressed by gravity, fill with fluid in microgravity and thicken.","This height gain often causes back pain in astronauts — it's one of the most common medical complaints on the ISS.","Scott Kelly, after one year in space, had grown 5 cm taller — he returned to normal height within 48 hours on Earth."],
    es:["Los discos intervertebrales, normalmente comprimidos por la gravedad, se llenan de líquido en el espacio, separando las vértebras y aumentando la estatura.","Los astronautas pueden crecer hasta 5 cm durante una misión larga — pero vuelven a su estatura normal al regresar a la Tierra.","Este efecto también ocurre durante la noche: eres 1-2 cm más alto al despertarte que al acostarte, por la descompresión nocturna de los discos."]
},
'u27': {
  fr:["Ce palindrome numérique fonctionne grâce à la structure de la multiplication : chaque chiffre du résultat est la somme des retenues partielles.","Le même schéma marche à plus petite échelle : 11² = 121, 111² = 12 321, 1 111² = 1 234 321 — un motif qui s'étend jusqu'à 9 chiffres.","À partir de 1 111 111 111 (dix 1), le palindrome se brise à cause des retenues à deux chiffres qui perturbent le schéma."],
  en:["This numerical palindrome works because of multiplication structure: each digit in the result is the sum of partial carries.","The same pattern works at smaller scales: 11² = 121, 111² = 12,321, 1,111² = 1,234,321 — a pattern extending up to 9 digits.","Starting from 1,111,111,111 (ten 1s), the palindrome breaks because two-digit carries disrupt the pattern."],
    es:["Este palíndromo numérico funciona gracias a la estructura de la multiplicación: cada dígito del resultado es la suma de los dígitos del multiplicando.","111 111 111 × 111 111 111 = 12 345 678 987 654 321 — un patrón simétrico perfecto que fascina a los matemáticos recreativos.","Los números repunit (formados solo por unos) tienen propiedades matemáticas sorprendentes, incluida esta simetría multiplicativa."]
},
'u28': {
  fr:["Les scientifiques estiment que 1 000 tonnes de diamants se forment chaque année dans l'atmosphère de Saturne, tombant comme une pluie scintillante.","À grande profondeur, la pression et la chaleur sont si intenses que les diamants fondent en « mer de diamant liquide » — un état exotique du carbone.","Neptune et Uranus ont aussi des pluies de diamants — des expériences laser en 2017 ont reproduit les conditions et créé de vrais nanodiamants en laboratoire."],
  en:["Scientists estimate 1,000 tonnes of diamonds form each year in Saturn's atmosphere, falling like sparkling rain.","At great depth, pressure and heat are so intense that diamonds melt into a 'liquid diamond sea' — an exotic state of carbon.","Neptune and Uranus also have diamond rain — laser experiments in 2017 reproduced the conditions and created real nanodiamonds in the lab."],
    es:["Los científicos estiman que 1 000 toneladas de diamantes se forman cada año en las atmósferas de Neptuno y Urano por la compresión de metano.","Las presiones extremas (200 000 atmósferas) y las temperaturas (5 000 °C) en el interior de estos planetas transforman el carbono del metano en diamante.","Estos diamantes «llueven» hacia el núcleo del planeta — un concepto tan extraordinario que parecería ciencia ficción si no estuviera respaldado por la física."]
},
'u29': {
  fr:["Le sulfure d'hydrogène, responsable de l'odeur, est produit par les bactéries intestinales qui décomposent les aliments riches en soufre comme les œufs et le brocoli.","Une personne moyenne produit entre 0,5 et 1,5 litre de gaz intestinal par jour, réparti en 14 à 23 émissions.","Les pets sont inflammables : le méthane et l'hydrogène qu'ils contiennent peuvent effectivement s'enflammer — une pratique stupide mais documentée."],
  en:["Hydrogen sulfide, responsible for the smell, is produced by gut bacteria breaking down sulfur-rich foods like eggs and broccoli.","An average person produces 0.5 to 1.5 liters of intestinal gas per day, spread across 14 to 23 emissions.","Farts are flammable: the methane and hydrogen they contain can indeed ignite — a foolish but documented practice."],
    es:["El sulfuro de hidrógeno, responsable del olor, es producido por las bacterias intestinales al descomponer los aminoácidos azufrados de los alimentos.","Solo el 1 % de la flatulencia es sulfuro de hidrógeno — el 99 % restante es nitrógeno, hidrógeno, CO₂ y metano, todos inodoros.","Un adulto produce entre 0,5 y 2 litros de gas intestinal al día, repartidos en 10-20 flatulencias — un proceso digestivo perfectamente normal y saludable."]
},
'u30': {
  fr:["Ce phénomène s'appelle la protandrie — tous les poissons-clowns naissent mâles et seul le plus dominant devient femelle.","Dans un groupe, une hiérarchie stricte existe : la femelle domine, suivie du mâle reproducteur, puis des mâles subordonnés non reproducteurs.","Dans « Le Monde de Nemo », biologiquement parlant, le père Marin aurait dû devenir femelle après la mort de Corail — ce qui aurait changé l'histoire."],
  en:["This phenomenon is called protandry — all clownfish are born male and only the most dominant one becomes female.","Within a group, a strict hierarchy exists: the female dominates, followed by the breeding male, then non-breeding subordinate males.","In 'Finding Nemo,' biologically speaking, father Marlin should have become female after Coral's death — which would have changed the story."],
    es:["Este fenómeno se llama protandria: todos los peces payaso nacen machos y solo el individuo dominante se transforma en hembra.","Si la hembra del grupo muere, el macho dominante cambia de sexo en pocas semanas para sustituirla — un hermafroditismo secuencial.","En Buscando a Nemo, el padre Marlin debería haberse convertido en hembra tras la muerte de su pareja — pero Pixar prefirió la licencia dramática."]
},


'h21': {
  fr:["Les conquêtes mongoles ont causé la mort d'environ 40 millions de personnes — soit 10 % de la population mondiale de l'époque.","Les terres agricoles abandonnées ont été recolonisées par les forêts, absorbant environ 700 millions de tonnes de carbone de l'atmosphère.","Paradoxalement, Gengis Khan pourrait être la seule personne de l'histoire à avoir réduit le CO₂ atmosphérique de façon mesurable — par la destruction."],
  en:["The Mongol conquests caused the death of about 40 million people — roughly 10% of the world's population at the time.","Abandoned farmland was recolonized by forests, absorbing about 700 million tonnes of carbon from the atmosphere.","Paradoxically, Genghis Khan may be the only person in history to have measurably reduced atmospheric CO₂ — through destruction."],
    es:["La escritura cuneiforme, inventada en Sumeria hacia el 3400 a.C., es uno de los sistemas de escritura más antiguos conocidos.","Se grababa con un estilete en tablillas de arcilla húmeda — el nombre «cuneiforme» proviene del latín cuneus (cuña) por la forma de las marcas.","Miles de tablillas cuneiformes han sobrevivido hasta hoy gracias a la durabilidad de la arcilla cocida, preservando registros comerciales, leyes, poemas y recetas de cerveza."]
},
'h22': {
  fr:["Le programme s'appelait « dénaturalisation » — le gouvernement ajoutait du méthanol, du kérosène et même du chloroforme à l'alcool industriel.","Les bootleggers engageaient des chimistes pour tenter de retirer les poisons — une course chimique entre le gouvernement et les contrebandiers.","Le médecin Charles Norris, médecin légiste de New York, a dénoncé publiquement cette politique en 1927, la qualifiant d'empoisonnement de masse légalisé."],
  en:["The program was called 'denaturing' — the government added methanol, kerosene, and even chloroform to industrial alcohol.","Bootleggers hired chemists to try removing the poisons — a chemical arms race between government and smugglers.","Dr. Charles Norris, New York's chief medical examiner, publicly denounced this policy in 1927, calling it legalized mass poisoning."],
    es:["Los gladiadores romanos rara vez luchaban a muerte: eran inversiones costosas, entrenados durante años y alimentados con dietas especiales ricas en cebada.","Los combates seguían reglas estrictas supervisadas por un árbitro, y los gladiadores famosos gozaban de una popularidad comparable a la de las estrellas del deporte actual.","Un gladiador caído podía pedir clemencia (missio) y sobrevivir si había luchado con valor — la señal del pulgar hacia abajo que conocemos del cine es probablemente un invento moderno."]
},
'h23': {
  fr:["Un quipu pouvait contenir des centaines de cordelettes attachées à un cordon principal — les nœuds, couleurs et espacements codaient les informations.","Les « quipucamayocs », fonctionnaires spécialisés, étaient les seuls à savoir les lire — c'était un métier respecté dans l'empire inca.","Des chercheurs de Harvard ont montré en 2017 que certains quipus contenaient des récits narratifs, pas uniquement des données comptables."],
  en:["A quipu could contain hundreds of strings attached to a main cord — knots, colors, and spacing encoded information.","'Quipucamayocs,' specialized officials, were the only ones who could read them — a respected profession in the Inca empire.","Harvard researchers showed in 2017 that some quipus contained narrative stories, not just accounting data."],
    es:["Cleopatra hablaba al menos nueve idiomas y fue la primera gobernante ptolemaica en aprender egipcio — sus antecesores solo hablaban griego.","Lejos de la imagen de seductora frívola, Cleopatra era una hábil estratega política que negoció alianzas con Julio César y Marco Antonio para preservar la independencia de Egipto.","Su muerte en el 30 a.C. marcó el fin del Egipto faraónico y el comienzo de la dominación romana sobre todo el Mediterráneo oriental."]
},
'h24': {
  fr:["Defferre avait traité Ribière d'« abruti » à l'Assemblée nationale — Ribière l'a alors défié en duel, une pratique encore légale à l'époque.","Le duel a duré deux reprises : Defferre a blessé Ribière au bras, mettant fin au combat — les deux hommes se sont ensuite serré la main.","Le duel n'a jamais été explicitement interdit par la loi française — il a simplement disparu des mœurs après cet épisode."],
  en:["Defferre had called Ribière an 'idiot' in the National Assembly — Ribière then challenged him to a duel, still legal at the time.","The duel lasted two rounds: Defferre wounded Ribière in the arm, ending the fight — the two men then shook hands.","Dueling was never explicitly banned by French law — it simply faded from customs after this episode."],
    es:["Los vikingos llegaron a América del Norte alrededor del año 1000 d.C., casi 500 años antes que Cristóbal Colón.","El asentamiento de L'Anse aux Meadows, en Terranova (Canadá), es la única colonia vikinga confirmada arqueológicamente en el continente americano.","Los vikingos llamaron a estas tierras Vinland (tierra del vino) por las uvas silvestres que encontraron — pero abandonaron la colonia tras pocos años debido a conflictos con los pueblos indígenas."]
},
'h25': {
  fr:["L'Empire ottoman a été fondé par Osman Ier vers 1299 et n'a pris fin qu'en 1922 avec l'abolition du sultanat par Mustafa Kemal Atatürk.","À son apogée sous Soliman le Magnifique (XVIe siècle), l'empire s'étendait de la Hongrie à l'Arabie et de l'Algérie à l'Irak.","Le harem impérial du palais de Topkapi pouvait héberger jusqu'à 300 femmes — c'était aussi un centre politique où se décidaient des alliances."],
  en:["The Ottoman Empire was founded by Osman I around 1299 and only ended in 1922 when Mustafa Kemal Atatürk abolished the sultanate.","At its peak under Suleiman the Magnificent (16th century), the empire stretched from Hungary to Arabia and from Algeria to Iraq.","The imperial harem at Topkapi Palace could house up to 300 women — it was also a political center where alliances were decided."],
    es:["La Gran Pirámide de Guiza, construida hacia el 2560 a.C., fue la estructura más alta del mundo durante más de 3 800 años, hasta la construcción de la catedral de Lincoln en 1311.","Sus 2,3 millones de bloques de piedra caliza, de unas 2,5 toneladas cada uno, fueron transportados y colocados con una precisión milimétrica que aún desconcierta a los ingenieros modernos.","Contrariamente al mito, las pirámides no fueron construidas por esclavos sino por trabajadores asalariados que vivían en aldeas cercanas y recibían raciones de pan y cerveza."]
},
'h26': {
  fr:["Les frères Richard et Maurice McDonald ont inventé le « Speedee Service System » en 1948 — un système de préparation rapide inspiré des chaînes de montage Ford.","Ray Kroc, un vendeur de machines à milkshake, a été si impressionné qu'il a racheté les droits de franchise et ouvert 100 restaurants en 4 ans.","Le Big Mac, inventé par le franchisé Jim Delligatti en 1967, n'a été approuvé par Kroc qu'après des mois de résistance — il est devenu le produit le plus vendu."],
  en:["Brothers Richard and Maurice McDonald invented the 'Speedee Service System' in 1948 — a fast preparation system inspired by Ford assembly lines.","Ray Kroc, a milkshake machine salesman, was so impressed he bought the franchise rights and opened 100 restaurants in 4 years.","The Big Mac, invented by franchisee Jim Delligatti in 1967, was only approved by Kroc after months of resistance — it became the best-selling product."],
    es:["El Imperio Romano, en su apogeo bajo Trajano (117 d.C.), se extendía desde Escocia hasta Mesopotamia y albergaba entre 60 y 70 millones de habitantes.","Los romanos construyeron más de 80 000 km de carreteras pavimentadas, muchas de las cuales sirvieron de base para las redes viarias europeas modernas.","La caída del Imperio Romano de Occidente en 476 d.C. no fue un evento repentino sino un proceso gradual de fragmentación política, presión migratoria y crisis económica."]
},
'h27': {
  fr:["Le canton d'Appenzell Rhodes-Intérieures n'a accordé le vote aux femmes qu'en 1991 — sur ordre du Tribunal fédéral, pas par choix.","Le référendum de 1971 a été voté par les hommes uniquement — 65,7 % ont dit oui, après deux rejets en 1959 (67 % de non).","Le Liechtenstein, voisin de la Suisse, a été encore plus tardif : les femmes n'ont obtenu le vote qu'en 1984."],
  en:["The canton of Appenzell Innerrhoden didn't grant women the vote until 1991 — by Federal Court order, not by choice.","The 1971 referendum was voted on by men only — 65.7% said yes, after two rejections in 1959 (67% said no).","Liechtenstein, Switzerland's neighbor, was even later: women didn't get the vote until 1984."],
    es:["La imprenta de tipos móviles, inventada por Gutenberg hacia 1440, transformó radicalmente la difusión del conocimiento en Europa.","Antes de la imprenta, copiar un libro a mano requería meses de trabajo; la imprenta reducía ese tiempo a días, democratizando el acceso a la información.","La Biblia de Gutenberg (1455) fue el primer libro impreso en masa en Occidente — se conservan 49 ejemplares, cada uno valorado en varios millones de euros."]
},
'h28': {
  fr:["Sa bataille la plus célèbre, Gaugamèles (331 av. J.-C.), l'a opposé à une armée perse cinq fois plus nombreuse — il a gagné grâce à une charge de cavalerie au centre.","Alexandre fondait des villes partout où il allait — au moins 20 portent son nom, dont Alexandrie en Égypte, qui est devenue le centre intellectuel du monde antique.","Sa mort mystérieuse à Babylone fait toujours débat : fièvre typhoïde, malaria, empoisonnement ou consommation excessive d'alcool — aucune théorie n'est confirmée."],
  en:["His most famous battle, Gaugamela (331 BC), pitted him against a Persian army five times larger — he won with a cavalry charge through the center.","Alexander founded cities wherever he went — at least 20 bear his name, including Alexandria in Egypt, which became the ancient world's intellectual center.","His mysterious death in Babylon is still debated: typhoid fever, malaria, poisoning, or excessive alcohol — no theory is confirmed."],
    es:["El antiguo Egipto veneró a los gatos durante milenios: la diosa Bastet, representada con cabeza felina, simbolizaba la protección del hogar y la fertilidad.","Matar a un gato, incluso accidentalmente, podía castigarse con la pena de muerte — y los gatos eran momificados con el mismo cuidado que los humanos.","Cuando moría un gato doméstico, los miembros de la familia se afeitaban las cejas en señal de duelo — una práctica documentada por el historiador griego Heródoto."]
},
'h29': {
  fr:["Le zéro maya était représenté par un glyphe en forme de coquillage — il servait de marqueur de position dans leur système vigésimal (base 20).","Les Babyloniens avaient un espace vide comme marqueur de position, mais les Mayas et les Indiens sont les seuls à avoir conceptualisé le zéro comme un nombre à part entière.","Le calendrier maya, d'une précision remarquable, n'aurait pas pu exister sans le zéro — il leur permettait de calculer des dates sur des millions d'années."],
  en:["The Mayan zero was represented by a shell-shaped glyph — it served as a placeholder in their vigesimal (base-20) system.","Babylonians had an empty space as a placeholder, but the Maya and Indians were the only ones to conceptualize zero as a number in its own right.","The Maya calendar, remarkably precise, couldn't have existed without zero — it allowed them to calculate dates spanning millions of years."],
    es:["La Guerra de los Cien Años (1337-1453) entre Francia e Inglaterra duró en realidad 116 años e incluyó largos periodos de tregua.","Juana de Arco, una campesina analfabeta de 17 años, lideró las tropas francesas en una serie de victorias decisivas antes de ser capturada, juzgada por herejía y quemada viva en 1431.","La guerra aceleró la transición del feudalismo al Estado-nación moderno y popularizó el uso de la artillería con pólvora, que volvió obsoletas las fortificaciones medievales."]
},
'h30': {
  fr:["La peste est arrivée en Europe en 1347 par des navires génois à Messine, en Sicile — les marins étaient déjà mourants à leur arrivée.","Après la peste, les survivants ont vu leurs salaires augmenter de 40 à 100 % en raison de la pénurie de main-d'œuvre — un effet économique paradoxal.","Des chercheurs ont découvert que les descendants des survivants portent des variantes génétiques qui renforcent leur immunité — un héritage génétique encore mesurable aujourd'hui."],
  en:["The plague arrived in Europe in 1347 on Genoese ships at Messina, Sicily — the sailors were already dying upon arrival.","After the plague, survivors saw wages rise 40 to 100% due to labor shortages — a paradoxical economic effect.","Researchers found that survivors' descendants carry gene variants that boost immunity — a genetic legacy still measurable today."],
    es:["Las Cruzadas fueron una serie de expediciones militares y religiosas entre 1096 y 1291, destinadas a recuperar Tierra Santa del control musulmán.","Más allá de la guerra, las Cruzadas provocaron un intenso intercambio cultural: los europeos descubrieron el azúcar, las especias, los números arábigos y nuevas técnicas médicas y arquitectónicas.","El impacto económico fue considerable: las Cruzadas impulsaron el comercio mediterráneo y enriquecieron ciudades como Venecia, Génova y Pisa, sentando las bases del capitalismo comercial europeo."]
},

'sp21': {
  fr:["L'ISS orbite à environ 408 km d'altitude — assez haut pour éviter l'atmosphère, assez bas pour que des fusées puissent l'atteindre.","À cette vitesse, les astronautes vieillissent très légèrement moins vite que sur Terre — environ 0,01 seconde de moins par an à cause de la dilatation du temps.","L'ISS est le troisième objet le plus brillant dans le ciel nocturne après la Lune et Vénus — visible à l'œil nu dans de bonnes conditions."],
  en:["The ISS orbits at about 408 km altitude — high enough to avoid the atmosphere, low enough for rockets to reach it.","At this speed, astronauts age very slightly slower than on Earth — about 0.01 seconds less per year due to time dilation.","The ISS is the third brightest object in the night sky after the Moon and Venus — visible to the naked eye in good conditions."],
    es:["Plutón fue descubierto en 1930 por Clyde Tombaugh y clasificado como planeta durante 76 años hasta su reclasificación como planeta enano por la UAI en 2006.","La decisión fue polémica: Plutón no cumple el tercer criterio de planeta (haber limpiado su órbita de otros objetos), ya que comparte el cinturón de Kuiper con miles de cuerpos similares.","La sonda New Horizons reveló en 2015 que Plutón tiene montañas de hielo de agua de 3 500 m, glaciares de nitrógeno y una fina atmósfera de metano — mucho más complejo de lo esperado."]
},
'sp22': {
  fr:["L'estimation de 200 milliards de milliards d'étoiles est basée sur environ 2 000 milliards de galaxies, chacune contenant en moyenne 100 milliards d'étoiles.","Chacune de ces étoiles pourrait avoir en moyenne 1 à 2 planètes — soit potentiellement plus de planètes que d'étoiles dans l'univers.","Ces chiffres ne concernent que l'univers observable (93 milliards d'années-lumière de diamètre) — l'univers réel pourrait être infiniment plus grand."],
  en:["The estimate of 200 billion billion stars is based on about 2 trillion galaxies, each containing roughly 100 billion stars on average.","Each of these stars could have 1 to 2 planets on average — meaning potentially more planets than stars in the universe.","These numbers only cover the observable universe (93 billion light-years across) — the actual universe could be infinitely larger."],
    es:["Los anillos de Saturno están compuestos en un 99 % de hielo de agua, con partículas que van desde granos de arena hasta bloques del tamaño de una casa.","Aunque parecen sólidos, los anillos tienen un grosor de apenas 10 metros de media — una estructura increíblemente delgada en proporción a su extensión de 282 000 km.","Estudios recientes sugieren que los anillos podrían tener solo 100 millones de años — relativamente jóvenes en la escala cósmica — y que podrían desaparecer dentro de otros 100 millones."]
},
'sp23': {
  fr:["Olympus Mons mesure 21,9 km de haut — soit 2,5 fois l'Everest — et sa base fait 600 km de diamètre, la taille de la France.","Sa pente est si douce (environ 5°) qu'un observateur au sommet ne verrait pas la base — elle disparaîtrait au-delà de l'horizon martien.","Mars a des volcans si grands car elle n'a pas de tectonique des plaques — le magma s'accumule au même point pendant des centaines de millions d'années."],
  en:["Olympus Mons stands 21.9 km tall — 2.5 times Everest — and its base is 600 km wide, the size of France.","Its slope is so gentle (about 5°) that an observer at the summit couldn't see the base — it would vanish beyond the Martian horizon.","Mars has such large volcanoes because it lacks tectonic plates — magma accumulates at the same point for hundreds of millions of years."],
    es:["La Vía Láctea contiene entre 100 000 y 400 000 millones de estrellas y tiene un diámetro de unos 100 000 años-luz.","Nuestro sistema solar se encuentra en el brazo de Orión, a unos 26 000 años-luz del centro galáctico, y tarda 230 millones de años en completar una órbita.","En el centro de la Vía Láctea se encuentra Sagitario A*, un agujero negro supermasivo con una masa de 4 millones de soles, cuya primera imagen fue capturada en 2022."]
},
'sp24': {
  fr:["Titan est la seule lune du système solaire avec une atmosphère dense — 1,5 fois la pression de la Terre, composée principalement d'azote.","Les lacs de méthane de Titan atteignent 150 mètres de profondeur — la sonde Huygens en 2005 a été le premier engin à se poser sur un corps du système solaire externe.","La NASA prépare la mission Dragonfly pour 2034 : un drone volant qui explorera la surface de Titan à la recherche de chimie prébiotique."],
  en:["Titan is the only moon in the solar system with a thick atmosphere — 1.5 times Earth's pressure, mainly composed of nitrogen.","Titan's methane lakes reach 150 meters deep — the Huygens probe in 2005 was the first craft to land on an outer solar system body.","NASA is preparing the Dragonfly mission for 2034: a flying drone to explore Titan's surface searching for prebiotic chemistry."],
    es:["Los cometas son cuerpos de hielo, polvo y roca que orbitan el Sol en trayectorias elípticas muy alargadas, procedentes del cinturón de Kuiper o la nube de Oort.","Al acercarse al Sol, el hielo se sublima y forma la característica cola, que siempre apunta en dirección opuesta al Sol debido a la presión de la radiación solar.","El cometa Halley, visible cada 75-76 años, ha sido observado desde al menos el 240 a.C. y su próximo paso será en 2061."]
},
'sp25': {
  fr:["La poussière lunaire (régolithe) est extrêmement fine et collante — elle s'accroche à tout et a même endommagé les combinaisons des astronautes.","Aucune érosion naturelle ne se produit sur la Lune : pas de vent, pas de pluie, pas de tectonique — seuls les impacts de micrométéorites effacent lentement les traces.","Les sites d'alunissage d'Apollo sont désormais considérés comme des sites patrimoniaux — un accord international interdit d'y atterrir à moins de 2 km."],
  en:["Lunar dust (regolith) is extremely fine and sticky — it clings to everything and even damaged astronaut suits.","No natural erosion occurs on the Moon: no wind, no rain, no tectonics — only micrometeorite impacts slowly erase traces.","Apollo landing sites are now considered heritage sites — an international agreement prohibits landing within 2 km of them."],
    es:["Marte tiene dos lunas diminutas, Fobos y Deimos, nombradas así por los hijos del dios Ares (Marte) en la mitología griega: el Miedo y el Terror.","Fobos se acerca a Marte 1,8 cm por año y será destruido por las fuerzas de marea en unos 50 millones de años, formando posiblemente un anillo temporal.","Ambas lunas son probablemente asteroides capturados por la gravedad marciana, dada su forma irregular y su composición similar a los asteroides del cinturón principal."]
},
'sp26': {
  fr:["Neptune a été découverte en 1846 par calcul mathématique avant d'être observée — les perturbations d'Uranus trahissaient sa présence.","Les vents sur Neptune atteignent 2 100 km/h — les plus rapides du système solaire, malgré sa distance au Soleil.","Neptune n'a complété son premier tour du Soleil depuis sa découverte qu'en 2011 — cet événement a été célébré par les astronomes du monde entier."],
  en:["Neptune was discovered in 1846 by mathematical calculation before being observed — perturbations in Uranus's orbit betrayed its presence.","Winds on Neptune reach 2,100 km/h — the fastest in the solar system, despite its distance from the Sun.","Neptune only completed its first orbit since discovery in 2011 — this event was celebrated by astronomers worldwide."],
    es:["La galaxia de Andrómeda (M31) es la galaxia espiral más cercana a la Vía Láctea, a unos 2,5 millones de años-luz de distancia.","Andrómeda y la Vía Láctea se acercan a 110 km/s y colisionarán dentro de unos 4 500 millones de años, fusionándose en una galaxia elíptica gigante.","A pesar de la colisión galáctica, es muy improbable que estrellas individuales choquen entre sí: las distancias interestelares son tan enormes que las galaxias se atravesarán como fantasmas."]
},
'sp27': {
  fr:["La lumière du Soleil que tu vois a 8 minutes et 20 secondes — tu ne vois jamais le Soleil en temps réel, mais toujours son passé.","La sonde Voyager 1, l'objet humain le plus lointain, met plus de 22 heures à recevoir un signal depuis la Terre.","Si on pouvait voyager à la vitesse de la lumière, traverser notre seule galaxie prendrait tout de même 100 000 ans."],
  en:["The sunlight you see is 8 minutes and 20 seconds old — you never see the Sun in real time, only its past.","Voyager 1, the farthest human-made object, takes over 22 hours to receive a signal from Earth.","Even traveling at the speed of light, crossing just our galaxy would still take 100,000 years."],
    es:["La materia oscura constituye aproximadamente el 27 % del universo, pero no emite ni absorbe luz — su existencia se deduce de sus efectos gravitacionales sobre la materia visible.","Las galaxias rotan demasiado rápido para la masa visible que contienen: sin materia oscura, se desintegrarían — esta fue la primera evidencia de su existencia.","A pesar de décadas de investigación, aún no se ha detectado directamente una partícula de materia oscura — es uno de los mayores misterios de la física moderna."]
},
'sp28': {
  fr:["Le miroir principal du James Webb fait 6,5 mètres de diamètre — composé de 18 segments hexagonaux recouverts d'or, métal choisi pour sa réflectivité en infrarouge.","Le télescope orbite au point de Lagrange L2, à 1,5 million de km de la Terre — quatre fois la distance Terre-Lune.","Son pare-soleil, de la taille d'un court de tennis, maintient les instruments à −233 °C — indispensable pour détecter la lumière infrarouge des premières galaxies."],
  en:["Webb's primary mirror is 6.5 meters across — made of 18 hexagonal segments coated in gold, chosen for its infrared reflectivity.","The telescope orbits at Lagrange point L2, 1.5 million km from Earth — four times the Earth-Moon distance.","Its sunshield, the size of a tennis court, keeps instruments at −233°C — essential for detecting infrared light from the first galaxies."],
    es:["El telescopio espacial James Webb, lanzado en diciembre de 2021, es el observatorio más potente jamás puesto en órbita, con un espejo de 6,5 metros de diámetro.","Orbita en el punto de Lagrange L2, a 1,5 millones de km de la Tierra, donde su parasol de 5 capas lo protege del calor del Sol.","Sus primeras imágenes revelaron galaxias formadas apenas 300 millones de años después del Big Bang — las más antiguas jamás observadas."]
},
'sp29': {
  fr:["Un jour sur Vénus (243 jours terrestres) dure plus longtemps qu'une année sur Vénus (225 jours terrestres) — une bizarrerie unique dans le système solaire.","La cause de cette rotation rétrograde est débattue : une collision cataclysmique ancienne ou un renversement progressif dû aux effets de marée atmosphérique.","Vénus est surnommée la jumelle de la Terre par sa taille, mais sa surface à 470 °C et ses pluies d'acide sulfurique la rendent totalement inhospitalière."],
  en:["A day on Venus (243 Earth days) is longer than a year on Venus (225 Earth days) — a quirk unique in the solar system.","The cause of this retrograde rotation is debated: an ancient cataclysmic collision or gradual reversal due to atmospheric tidal effects.","Venus is called Earth's twin for its size, but its 470°C surface and sulfuric acid rain make it utterly inhospitable."],
    es:["El Big Bang no fue una explosión en el espacio, sino una expansión del propio espacio-tiempo a partir de un estado de densidad y temperatura infinitas hace 13 800 millones de años.","La radiación cósmica de fondo, descubierta accidentalmente en 1965 por Penzias y Wilson, es el «eco» del Big Bang y es visible en todas las direcciones del cielo.","El universo sigue expandiéndose y esa expansión se está acelerando, impulsada por una fuerza misteriosa llamada energía oscura, que constituye el 68 % del contenido total del universo."]
},
'sp30': {
  fr:["Sagittarius B2 est un nuage moléculaire géant situé à 26 000 années-lumière de la Terre, près du centre de notre galaxie.","Outre l'éthanol, les astronomes y ont détecté du formiate d'éthyle (arôme de framboise) et de l'alcool isopropylique — une véritable distillerie cosmique.","Ce nuage mesure 150 années-lumière de diamètre et contient l'équivalent de 3 millions de masses solaires en gaz et poussière."],
  en:["Sagittarius B2 is a giant molecular cloud located 26,000 light-years from Earth, near the center of our galaxy.","Beyond ethanol, astronomers have detected ethyl formate (raspberry flavor) and isopropyl alcohol — a true cosmic distillery.","This cloud spans 150 light-years across and contains the equivalent of 3 million solar masses in gas and dust."],
    es:["Las exoplanetas son planetas que orbitan estrellas distintas al Sol. Desde el primer descubrimiento confirmado en 1995, se han catalogado más de 5 600.","El método más común de detección es el de tránsito: cuando un planeta pasa delante de su estrella, la luz de esta disminuye ligeramente, revelando el tamaño y la órbita del planeta.","Algunos exoplanetas se encuentran en la «zona habitable» de su estrella, donde las temperaturas permiten la existencia de agua líquida — un requisito clave para la vida tal como la conocemos."]
},


'a21': {
  fr:["Les éléphants détectent ces vibrations grâce à des corpuscules de Pacini dans leurs pieds — les mêmes récepteurs sensoriels que dans nos doigts.","Ils peuvent percevoir un troupeau en mouvement ou un orage à plus de 30 km de distance en « écoutant » le sol avec leurs pattes.","Pour mieux capter les vibrations, les éléphants se figent et appuient leurs pieds à plat — un comportement observé avant les tremblements de terre et les tsunamis."],
  en:["Elephants detect these vibrations through Pacinian corpuscles in their feet — the same sensory receptors found in our fingers.","They can sense a moving herd or a storm over 30 km away by 'listening' to the ground through their feet.","To better capture vibrations, elephants freeze and press their feet flat — behavior observed before earthquakes and tsunamis."],
    es:["Los elefantes detectan vibraciones sísmicas a través de corpúsculos de Pacini en las almohadillas de sus patas.","Pueden sentir las pisadas de otros elefantes a más de 30 km de distancia — una forma de comunicación a larga distancia complementaria a los infrasonidos.","Cuando detectan vibraciones de alarma, se inmovilizan y presionan las patas contra el suelo para amplificar la señal."]
},
'a22': {
  fr:["Les ailes du colibri tournent en forme de 8, générant de la portance à la montée ET à la descente — contrairement à tous les autres oiseaux.","Le cœur d'un colibri bat jusqu'à 1 200 fois par minute en vol — et il entre en torpeur la nuit pour ralentir son métabolisme et survivre.","Le colibri-abeille de Cuba, pesant 1,8 gramme, est le plus petit oiseau du monde — il est plus léger qu'une pièce de 1 centime."],
  en:["Hummingbird wings rotate in a figure-8, generating lift on both upstroke AND downstroke — unlike all other birds.","A hummingbird's heart beats up to 1,200 times per minute in flight — and it enters torpor at night to slow its metabolism and survive.","Cuba's bee hummingbird, weighing 1.8 grams, is the world's smallest bird — lighter than a penny."],
    es:["Las alas del colibrí giran en forma de 8, generando sustentación tanto en la subida como en la bajada — un vuelo único entre las aves.","El corazón del colibrí late hasta 1 200 veces por minuto y consume 10 veces más oxígeno por gramo que un corredor olímpico.","De noche entran en torpor: reducen su metabolismo un 95 % y su temperatura corporal baja a la del ambiente — un mini-estado de hibernación diaria."]
},
'a23': {
  fr:["Jaak Panksepp a découvert en 2003 que les rats émettent des ultrasons à 50 kHz quand on les chatouille — un son associé au plaisir.","Les rats préfèrent la compagnie de chercheurs qui les chatouillent — ils courent vers la main de l'expérimentateur et font des bonds de joie.","Cette découverte a contribué à prouver que les émotions positives ne sont pas réservées aux humains — d'autres mammifères les ressentent aussi."],
  en:["Jaak Panksepp discovered in 2003 that rats emit ultrasonic calls at 50 kHz when tickled — a sound associated with pleasure.","Rats prefer the company of researchers who tickle them — they run toward the experimenter's hand and make joyful leaps.","This discovery helped prove that positive emotions aren't exclusive to humans — other mammals experience them too."],
    es:["Jaak Panksepp descubrió en 2003 que las ratas emiten ultrasonidos a 50 kHz cuando juegan — un sonido interpretado como risa animal.","Las ratas jóvenes buscan activamente las cosquillas y prefieren la compañía de las ratas que más les hacen «reír».","Este descubrimiento sugiere que la risa no es exclusivamente humana sino un comportamiento social profundo con raíces evolutivas antiguas."]
},
'a24': {
  fr:["L'axolotl peut régénérer non seulement ses membres, mais aussi son cœur, ses yeux, sa moelle épinière et même des parties de son cerveau.","Il accomplit cela grâce à la dédifférenciation cellulaire : ses cellules adultes redeviennent des cellules souches pour reconstruire le tissu perdu.","Originaire uniquement du lac Xochimilco à Mexico, l'axolotl est quasiment éteint dans la nature — il ne survit que grâce à l'élevage en captivité."],
  en:["The axolotl can regenerate not only limbs but also its heart, eyes, spinal cord, and even parts of its brain.","It achieves this through cell dedifferentiation: adult cells revert to stem cells to rebuild lost tissue.","Native only to Lake Xochimilco in Mexico City, the axolotl is nearly extinct in the wild — surviving only through captive breeding."],
    es:["El ajolote puede regenerar no solo sus extremidades, sino también su corazón, sus ojos, su médula espinal y partes de su cerebro.","La regeneración se basa en células madre pluripotentes que se activan en el sitio de la herida y reconstruyen el tejido perdido.","Los científicos estudian los mecanismos del ajolote para la medicina regenerativa humana — un campo que podría revolucionar el tratamiento de lesiones."]
},
'a25': {
  fr:["L'organe voméronasal (ou organe de Jacobson) est situé sur le palais du chat, juste derrière les incisives supérieures.","La grimace de flehmen permet au chat d'aspirer les molécules odorantes vers cet organe — il analyse les phéromones d'autres chats, la nourriture et les dangers.","Les serpents utilisent le même organe mais différemment : ils captent les particules avec leur langue fourchue et les déposent sur le voméronasal."],
  en:["The vomeronasal (or Jacobson's) organ is located on the cat's palate, just behind the upper incisors.","The flehmen grimace lets the cat draw scent molecules toward this organ — analyzing pheromones from other cats, food, and dangers.","Snakes use the same organ differently: they capture particles with their forked tongue and deposit them on the vomeronasal."],
    es:["El órgano vomeronasal (u órgano de Jacobson) está situado en el paladar del gato, justo detrás de los incisivos superiores.","Cuando un gato hace la «mueca de Flehmen» (labio superior levantado), está dirigiendo moléculas odorantes hacia este órgano.","El órgano vomeronasal detecta feromonas: información sobre el estado reproductivo, el territorio y la identidad de otros gatos."]
},
'a26': {
  fr:["Le jet d'eau peut atteindre 3 mètres de hauteur avec une force 10 fois supérieure au poids de l'insecte visé — un tir d'une précision remarquable.","Le poisson archer compense la réfraction de la lumière entre l'eau et l'air — un calcul optique que même certains humains auraient du mal à faire.","Les jeunes poissons archers apprennent en observant les adultes tirer — c'est l'un des rares exemples d'apprentissage social chez les poissons."],
  en:["The water jet can reach 3 meters high with 10 times the force of the targeted insect's weight — a remarkably precise shot.","The archerfish compensates for light refraction between water and air — an optical calculation even some humans would struggle with.","Young archerfish learn by watching adults shoot — one of the rare examples of social learning in fish."],
    es:["El chorro de agua del pez arquero puede alcanzar 3 metros de altura con una fuerza 10 veces superior a la de su propia musculatura.","Compensa la refracción de la luz en la superficie del agua — un cálculo óptico instantáneo que pocos animales dominan.","Los peces arquero jóvenes aprenden la técnica observando a los adultos — un ejemplo de aprendizaje social en los peces."]
},
'a27': {
  fr:["Cette sécrétion n'est pas de la sueur — elle est produite par des glandes sous-cutanées spéciales et contient deux pigments : l'acide hipposudorique (rouge) et l'acide norhipposudorique (orange).","L'acide hipposudorique absorbe les UV et inhibe la croissance bactérienne — une protection double, solaire et antibiotique, unique dans le règne animal.","Les hippopotames passent jusqu'à 16 heures par jour dans l'eau — cette sécrétion les protège durant les heures qu'ils passent à terre pour brouter la nuit."],
  en:["This secretion isn't sweat — it's produced by special subcutaneous glands and contains two pigments: hipposudoric acid (red) and norhipposudoric acid (orange).","Hipposudoric acid absorbs UV rays and inhibits bacterial growth — a dual sun and antibiotic protection unique in the animal kingdom.","Hippos spend up to 16 hours a day in water — this secretion protects them during hours spent on land grazing at night."],
    es:["Esta secreción no es sudor — es producida por glándulas subcutáneas que secretan un líquido alcalino, rojizo, con propiedades antibacterianas y de protección solar.","El pigmento se llama hiposudórico y actúa como un filtro UV natural que protege la piel del hipopótamo de las quemaduras solares.","El «sudor de sangre» del hipopótamo inspiró a los cosmetólogos: se estudian sus propiedades para desarrollar protectores solares biodegradables."]
},
'a28': {
  fr:["Ces corbeaux façonnent des crochets à partir de brindilles pour extraire des larves des troncs d'arbres — un comportement jamais observé chez d'autres oiseaux.","Ils fabriquent aussi des outils en feuilles de pandanus, découpées en forme d'escalier, qu'ils emportent d'arbre en arbre.","Des expériences ont montré qu'ils peuvent résoudre des puzzles à 8 étapes pour obtenir de la nourriture — un niveau de planification comparable aux grands singes."],
  en:["These crows shape hooks from twigs to extract larvae from tree trunks — behavior never observed in other birds.","They also make tools from pandanus leaves, cut into staircase shapes, which they carry from tree to tree.","Experiments showed they can solve 8-step puzzles to obtain food — a level of planning comparable to great apes."],
    es:["Estos cuervos fabrican ganchos a partir de ramitas para extraer larvas de los agujeros — un proceso que requiere planificación y selección de materiales.","Los cuervos de Nueva Caledonia son una de las pocas especies no primates que fabrican herramientas compuestas (combinando varios elementos).","Transmiten sus técnicas de fabricación a las crías mediante aprendizaje social — una tradición cultural que varía entre poblaciones."]
},
'a29': {
  fr:["Le poulpe mimétique (Thaumoctopus mimicus) peut imiter des rascasses, des raies, des serpents de mer et même des méduses en changeant forme, couleur et mouvement.","Découvert en 1998 au large de l'Indonésie, c'est le seul animal connu capable de choisir quelle espèce imiter en fonction du prédateur qu'il affronte.","Il choisit ses imitations stratégiquement : face à une demoiselle agressive, il imite le serpent de mer — son prédateur naturel."],
  en:["The mimic octopus (Thaumoctopus mimicus) can impersonate lionfish, stingrays, sea snakes, and even jellyfish by changing shape, color, and movement.","Discovered in 1998 off Indonesia, it's the only known animal able to choose which species to mimic based on the predator it faces.","It chooses imitations strategically: when facing an aggressive damselfish, it mimics the sea snake — its natural predator."],
    es:["El pulpo mimético (Thaumoctopus mimicus) puede imitar a rascasas, rayas, peces león, serpientes de mar y medusas cambiando de forma y color.","Elige qué animal imitar según el depredador que lo amenaza: imita una serpiente venenosa ante los peces damisela, y una raya ante los peces león.","Descubierto en 1998 en Indonesia, es el único animal conocido capaz de imitar múltiples especies de forma selectiva."]
},
'a30': {
  fr:["Pour atteindre cette profondeur, les manchots empereurs ralentissent leur rythme cardiaque de 200 à 20 battements par minute.","Ils stockent l'oxygène dans leurs muscles grâce à une concentration élevée de myoglobine — une adaptation similaire à celle des baleines.","Pendant l'hiver antarctique, les mâles jeûnent pendant 115 jours en couvant l'œuf, perdant jusqu'à 45 % de leur masse corporelle."],
  en:["To reach this depth, emperor penguins slow their heart rate from 200 to 20 beats per minute.","They store oxygen in their muscles through high myoglobin concentration — an adaptation similar to whales.","During the Antarctic winter, males fast for 115 days while incubating the egg, losing up to 45% of their body mass."],
    es:["Para alcanzar los 500 m de profundidad, los pingüinos emperador reducen su ritmo cardíaco de 80 a 15 latidos por minuto y colapsan sus pulmones.","Sus músculos almacenan mioglobina (una proteína que retiene oxígeno), permitiéndoles bucear hasta 22 minutos sin respirar.","Caminan hasta 120 km para llegar a sus zonas de cría — a veces se deslizan sobre el vientre para ahorrar energía."]
},

'b21': {
  fr:["Si l'apport en oxygène au cerveau est interrompu pendant seulement 5 minutes, des lésions cérébrales irréversibles commencent à se produire.","Le cerveau consomme environ 400 calories par jour rien que pour fonctionner — penser intensément ne brûle cependant que 20 à 50 calories de plus.","Pendant le sommeil profond, le cerveau ne réduit sa consommation que de 5 % — il reste extrêmement actif pour consolider la mémoire et nettoyer les déchets métaboliques."],
  en:["If oxygen supply to the brain is interrupted for just 5 minutes, irreversible brain damage begins to occur.","The brain uses about 400 calories per day just to function — though intensive thinking only burns an extra 20 to 50 calories.","During deep sleep, the brain only reduces its consumption by 5% — it stays extremely active consolidating memory and clearing metabolic waste."],
    es:["Si el suministro de oxígeno al cerebro se interrumpe durante solo 5 minutos, comienzan a producirse daños neuronales irreversibles.","Las neuronas son las células más sensibles a la falta de oxígeno — mucho más que las células musculares o hepáticas.","La hipotermia terapéutica (enfriar el cuerpo) puede ampliar esta ventana a 10-15 minutos, reduciendo el metabolismo cerebral."]
},
'b22': {
  fr:["Le corps humain d'un adulte moyen contient environ 16 kg de carbone — le même élément que le diamant et le graphite des mines de crayon.","Au-delà du carbone, tu contiens aussi assez de fer pour fabriquer un clou de 7 cm et assez de phosphore pour 2 200 allumettes.","Si on vendait tous les éléments chimiques d'un corps humain aux prix du marché, la valeur totale serait d'environ 160 dollars — relativement modeste."],
  en:["An average adult human body contains about 16 kg of carbon — the same element as diamond and pencil lead graphite.","Beyond carbon, you also contain enough iron for a 7 cm nail and enough phosphorus for 2,200 matches.","If you sold all the chemical elements of a human body at market prices, the total value would be about $160 — relatively modest."],
    es:["El cuerpo humano de un adulto medio contiene unos 16 kg de carbono — el mismo elemento que forma los diamantes y el grafito.","Este carbono fue forjado en el núcleo de estrellas hace miles de millones de años y reciclado a través de la biosfera terrestre.","Cuando morimos, nuestro carbono vuelve al ciclo: se integra en el suelo, las plantas, el aire y eventualmente en otros seres vivos."]
},
'b23': {
  fr:["Les larmes basales (lubrification) contiennent des lysozymes antibactériens, les larmes réflexes (oignon) sont riches en anticorps, et les larmes émotionnelles libèrent de la leucine-enképhaline, un antidouleur naturel.","La photographe Rose-Lynn Fisher a observé au microscope que les larmes forment des cristaux uniques selon leur origine — comme des paysages miniatures différents.","Les femmes pleurent en moyenne 5,3 fois par mois et les hommes 1,3 fois — cette différence est en partie hormonale (prolactine) et en partie culturelle."],
  en:["Basal tears (lubrication) contain antibacterial lysozymes, reflex tears (onion) are rich in antibodies, and emotional tears release leucine enkephalin, a natural painkiller.","Photographer Rose-Lynn Fisher observed under a microscope that tears form unique crystals depending on their origin — like different miniature landscapes.","Women cry an average of 5.3 times per month and men 1.3 times — this difference is partly hormonal (prolactin) and partly cultural."],
    es:["Las lágrimas basales contienen lisozima antibacteriana, las reflejas son mayoritariamente agua, y las emocionales contienen hormonas del estrés.","Llorar reduce los niveles de cortisol y adrenalina — literalmente nos desestramos a través de las lágrimas.","Los humanos son los únicos animales que lloran por razones emocionales — otros animales producen lágrimas solo para lubricar los ojos."]
},
'b24': {
  fr:["Des études récentes ont révisé ce ratio : il serait plus proche de 1:1, soit autant de bactéries que de cellules humaines — environ 38 000 milliards de chaque.","Le microbiome intestinal pèse environ 1,5 kg — à peu près le poids du cerveau — et contient plus de 1 000 espèces de bactéries différentes.","Chaque personne a un microbiome aussi unique que ses empreintes digitales — il est influencé par la naissance, l'alimentation, l'environnement et les antibiotiques."],
  en:["Recent studies revised this ratio to closer to 1:1, with roughly equal numbers of bacteria and human cells — about 38 trillion of each.","The gut microbiome weighs about 1.5 kg — roughly the weight of the brain — and contains over 1,000 different bacterial species.","Each person's microbiome is as unique as their fingerprints — shaped by birth, diet, environment, and antibiotics."],
    es:["Estudios recientes han revisado la proporción bacterias/células humanas: sería más cercana a 1:1, no 10:1 como se creía antes.","Aun así, el microbioma intestinal pesa entre 1 y 2 kg y contiene más de 1 000 especies de bacterias.","El eje intestino-cerebro conecta la flora intestinal con el estado de ánimo: los probióticos pueden influir en la ansiedad y la depresión."]
},
'b25': {
  fr:["Le record de force de morsure humaine mesurée est de 442 kg — mais une morsure normale utilise rarement plus de 30 kg pour éviter d'endommager les dents.","Le masséter travaille en coordination avec trois autres muscles masticateurs — ensemble, ils effectuent environ 2 000 mouvements de mastication par repas.","Les bruxistes (qui grincent des dents la nuit) peuvent exercer une force de morsure 6 fois supérieure à la normale, causant usure et fractures dentaires."],
  en:["The record measured human bite force is 442 kg — but a normal bite rarely uses more than 30 kg to avoid damaging teeth.","The masseter works with three other chewing muscles — together, they perform about 2,000 chewing motions per meal.","Bruxists (who grind teeth at night) can exert 6 times normal bite force, causing tooth wear and fractures."],
    es:["El récord de fuerza de mordida humana medida es de 442 kg — pero una mordida normal genera entre 70 y 100 kg.","Los músculos maseteros (de la mandíbula) son los más potentes del cuerpo en relación con su tamaño.","La mandíbula humana es proporcionalmente más débil que la de otros primates porque nuestra dieta cocinada requiere menos fuerza masticatoria."]
},
'b26': {
  fr:["La rétine contient environ 130 millions de cellules photoréceptrices — 120 millions de bâtonnets (vision nocturne) et 6 à 7 millions de cônes (couleurs).","Le nerf optique transmet l'information au cerveau via environ 1,2 million de fibres nerveuses — c'est l'un des « câbles » les plus denses du corps.","Les yeux effectuent environ 100 000 saccades (micro-mouvements) par jour — sans ces mouvements, l'image se figerait et disparaîtrait en quelques secondes."],
  en:["The retina contains about 130 million photoreceptor cells — 120 million rods (night vision) and 6 to 7 million cones (color).","The optic nerve transmits information to the brain via about 1.2 million nerve fibers — one of the body's densest 'cables'.","Eyes perform about 100,000 saccades (micro-movements) per day — without these movements, the image would freeze and disappear within seconds."],
    es:["La retina contiene unos 130 millones de fotorreceptores: 120 millones de bastones (visión nocturna) y 6-7 millones de conos (color y detalle).","Los conos se concentran en la fóvea, una zona central de 1,5 mm que proporciona la visión nítida — el resto de la retina ve de forma más borrosa.","El punto ciego (donde el nervio óptico sale del ojo) no tiene fotorreceptores — el cerebro rellena la imagen automáticamente sin que lo notemos."]
},
'b27': {
  fr:["Cette lumière est émise par des réactions chimiques impliquant des radicaux libres et des fluorophores dans les cellules de la peau.","L'émission lumineuse varie au cours de la journée — elle est maximale en fin d'après-midi autour du visage, particulièrement les joues et le front.","Des chercheurs japonais ont capté cette lueur en 2009 avec des caméras CCD ultra-sensibles, capables de détecter un seul photon."],
  en:["This light is emitted by chemical reactions involving free radicals and fluorophores in skin cells.","The light emission varies throughout the day — it peaks in late afternoon around the face, particularly the cheeks and forehead.","Japanese researchers captured this glow in 2009 with ultra-sensitive CCD cameras capable of detecting a single photon."],
    es:["El cuerpo humano emite una luz ultradébil (biofotones) producida por reacciones químicas de radicales libres en las células.","Esta bioluminiscencia es 1 000 veces más débil de lo que el ojo puede percibir — solo se detecta con cámaras CCD ultrasensibles.","La emisión varía con el ritmo circadiano: es máxima por la tarde alrededor de los labios y las mejillas."]
},
'b28': {
  fr:["Les neurones les plus rapides sont les fibres myélinisées de type Aα, qui transmettent la douleur aiguë et les réflexes moteurs.","Les neurones les plus lents (fibres C) ne transmettent qu'à 2 km/h — c'est la raison pour laquelle la douleur sourde arrive après la douleur vive.","Le cerveau humain contient environ 86 milliards de neurones, chacun connecté à 7 000 autres en moyenne — soit 600 000 milliards de connexions synaptiques."],
  en:["The fastest neurons are myelinated Aα fibers, which transmit acute pain and motor reflexes.","The slowest neurons (C fibers) transmit at only 2 km/h — which is why dull pain arrives after sharp pain.","The human brain contains about 86 billion neurons, each connected to 7,000 others on average — meaning 600 trillion synaptic connections."],
    es:["Las neuronas más rápidas son las fibras mielinizadas de tipo Aα, que transmiten señales a 120 m/s — 432 km/h.","La mielina actúa como aislante eléctrico: las señales saltan entre los nodos de Ranvier (conducción saltatoria), acelerando la transmisión.","La esclerosis múltiple es causada por la destrucción de la mielina — lo que explica los síntomas neurológicos progresivos de la enfermedad."]
},
'b29': {
  fr:["Le cœur pompe environ 7 500 litres de sang par jour à travers un réseau de 100 000 km de vaisseaux sanguins — assez pour faire 2,5 fois le tour de la Terre.","Un globule rouge vit environ 120 jours et effectue environ 300 000 tours du circuit sanguin avant d'être détruit par la rate.","Le corps produit environ 2 millions de nouveaux globules rouges par seconde dans la moelle osseuse pour remplacer ceux qui meurent."],
  en:["The heart pumps about 7,500 liters of blood per day through a 100,000 km network of blood vessels — enough to circle Earth 2.5 times.","A red blood cell lives about 120 days and makes roughly 300,000 trips around the circulatory system before being destroyed by the spleen.","The body produces about 2 million new red blood cells per second in the bone marrow to replace dying ones."],
    es:["El corazón bombea unos 7 500 litros de sangre al día a través de 100 000 km de vasos — una red que daría dos veces y media la vuelta a la Tierra.","Las arterias son elásticas (soportan la presión), las venas tienen válvulas (evitan el reflujo) y los capilares son microscópicos (permiten el intercambio).","El sistema circulatorio se autorrepara: los vasos dañados activan la cascada de coagulación en segundos para sellar la brecha."]
},
'b30': {
  fr:["La surface de la langue présente des papilles de taille, forme et distribution uniques — une « empreinte linguale » qu'aucune autre personne ne partage.","Des chercheurs développent des systèmes de reconnaissance biométrique par la langue, utilisant des caméras et des algorithmes d'IA.","La langue est le seul muscle du corps attaché à une seule extrémité — ce qui lui confère une mobilité exceptionnelle avec plus de 8 muscles entrelacés."],
  en:["The tongue's surface has papillae of unique size, shape, and distribution — a 'lingual print' shared by no other person.","Researchers are developing biometric recognition systems using the tongue, with cameras and AI algorithms.","The tongue is the only muscle in the body attached at just one end — giving it exceptional mobility with over 8 interlaced muscles."],
    es:["La superficie de la lengua tiene papilas de tamaño, forma y distribución únicos para cada persona — una biometría potencial como las huellas dactilares.","La lengua tiene unos 10 000 papilas gustativas, cada una con 50-100 células receptoras que detectan dulce, salado, ácido, amargo y umami.","El mapa lingual clásico (dulce en la punta, amargo atrás) es un mito: todas las zonas de la lengua detectan todos los sabores."]
},


'ar21': {
  fr:["La Vigne rouge a été vendue 400 francs belges (environ 1 600 € actualisés) à la collectionneuse Anna Boch en 1890, quelques mois avant la mort de Van Gogh.","Son frère Théo, marchand d'art, a tout fait pour vendre ses œuvres — mais les critiques de l'époque trouvaient sa technique trop brutale et ses couleurs excessives.","En 2024, ses toiles se vendent jusqu'à 117 millions de dollars — un écart de valeur vertigineux qui illustre la cruauté du marché de l'art."],
  en:["The Red Vineyard was sold for 400 Belgian francs (about €1,600 adjusted) to collector Anna Boch in 1890, months before Van Gogh's death.","His brother Theo, an art dealer, tried everything to sell his works — but critics at the time found his technique too brutal and colors excessive.","In 2024, his paintings sell for up to $117 million — a dizzying value gap illustrating the cruelty of the art market."],
    es:["La ópera nació en Florencia a finales del siglo XVI, cuando un grupo de intelectuales (la Camerata Fiorentina) intentó recrear el drama musical de la Grecia antigua.","La primera ópera conservada completa es Euridice de Jacopo Peri (1600), aunque la forma alcanzó su madurez con Monteverdi y su Orfeo (1607).","Desde sus orígenes elitistas en las cortes italianas, la ópera se democratizó en el siglo XIX gracias a compositores como Verdi y Puccini, que escribieron para un público popular."]
},
'ar22': {
  fr:["Le Penseur faisait partie d'un ensemble monumental appelé « La Porte de l'Enfer », inspiré de la Divine Comédie de Dante Alighieri.","La sculpture originale ne mesure que 70 cm — les versions monumentales que l'on voit dans les musées sont des agrandissements réalisés après la mort de Rodin.","Rodin n'a jamais nommé la sculpture « Le Penseur » — c'est un critique d'art qui l'a baptisée ainsi, et le nom est resté."],
  en:["The Thinker was part of a monumental ensemble called 'The Gates of Hell,' inspired by Dante Alighieri's Divine Comedy.","The original sculpture is only 70 cm tall — the monumental versions seen in museums are enlargements made after Rodin's death.","Rodin never named the sculpture 'The Thinker' — an art critic gave it that name, and it stuck."],
    es:["El arte pop surgió en los años 1950-60 como reacción al expresionismo abstracto, incorporando imágenes de la cultura popular, la publicidad y los medios de comunicación.","Andy Warhol elevó objetos cotidianos como latas de sopa Campbell y botellas de Coca-Cola a la categoría de arte, cuestionando las fronteras entre arte elevado y cultura de masas.","Roy Lichtenstein se inspiró directamente en los cómics, reproduciendo viñetas con la técnica de puntos Ben-Day a gran escala — una ironía sobre la reproducción mecánica del arte."]
},
'ar23': {
  fr:["Le lapis-lazuli provenait exclusivement des mines de Badakhshan en Afghanistan — un voyage de 6 000 km pour atteindre les ateliers européens.","Les peintres de la Renaissance signaient des contrats spécifiant la quantité exacte de bleu outremer à utiliser — les commanditaires le fournissaient séparément.","En 1826, le chimiste français Jean-Baptiste Guimet a créé un outremer synthétique, effondrant le prix du pigment de 99 %."],
  en:["Lapis lazuli came exclusively from the Badakhshan mines in Afghanistan — a 6,000 km journey to reach European workshops.","Renaissance painters signed contracts specifying the exact amount of ultramarine to use — patrons supplied it separately.","In 1826, French chemist Jean-Baptiste Guimet created synthetic ultramarine, crashing the pigment's price by 99%."],
    es:["El flamenco es un arte que combina cante, baile y guitarra, originado en Andalucía entre las comunidades gitanas, moriscas y judías del sur de España.","Fue declarado Patrimonio Cultural Inmaterial de la Humanidad por la UNESCO en 2010, reconociendo su profundidad emocional y su complejidad rítmica.","El duende, concepto clave del flamenco, describe un estado de emoción intensa y autenticidad que trasciende la técnica — Federico García Lorca lo definió como un poder misterioso que todos sienten y ningún filósofo explica."]
},
'ar24': {
  fr:["L'œuvre s'est autodétruite juste après avoir été adjugée pour 1,04 million de livres — un mécanisme de broyage caché dans le cadre s'est activé à distance.","La toile ne s'est déchiquetée qu'à moitié — rebaptisée « Love is in the Bin », elle a été revendue en 2021 pour 18,6 millions de livres.","Banksy avait installé le broyeur dans le cadre des années auparavant — la batterie était restée chargée tout ce temps, prête pour le moment parfait."],
  en:["The work self-destructed right after being sold for £1.04 million — a shredding mechanism hidden in the frame was activated remotely.","The canvas only half-shredded — renamed 'Love is in the Bin,' it was resold in 2021 for £18.6 million.","Banksy had installed the shredder in the frame years earlier — the battery stayed charged all that time, ready for the perfect moment."],
    es:["La cerámica es una de las artes más antiguas de la humanidad: las primeras piezas conocidas, halladas en China, tienen más de 20 000 años.","La porcelana china, inventada durante la dinastía Tang (siglo VII), fue tan valiosa en Europa que se la conocía como «oro blanco» — los europeos tardaron siglos en descifrar su fórmula.","La técnica del kintsugi japonés repara las cerámicas rotas con oro, celebrando las fracturas como parte de la historia del objeto en lugar de ocultarlas."]
},
'ar25': {
  fr:["Monet a fait aménager un jardin japonais avec un pont et un étang de nénuphars à Giverny en 1893 — il l'a peint obsessionnellement jusqu'à sa mort en 1926.","Ses derniers Nymphéas, peints alors qu'il souffrait de cataracte, virent vers le rouge et le brun — sa perception des couleurs avait changé.","Après une opération de la cataracte en 1923, Monet a vu des ultraviolets — il a repeint certaines toiles en bleuté, correspondant à sa nouvelle vision."],
  en:["Monet had a Japanese garden built with a bridge and lily pond at Giverny in 1893 — he painted it obsessively until his death in 1926.","His last Water Lilies, painted while suffering from cataracts, shifted toward red and brown — his color perception had changed.","After cataract surgery in 1923, Monet could see ultraviolet light — he repainted some canvases in bluish tones matching his new vision."],
    es:["La arquitectura islámica se distingue por el uso de arabescos, mocárabes, arcos de herradura y jardines interiores que evocan el paraíso coránico.","La Alhambra de Granada es una obra maestra de esta tradición: sus patios, fuentes y decoraciones geométricas crean un juego de luz, agua y espacio de una belleza hipnótica.","La prohibición parcial de las imágenes figurativas en el islam impulsó un desarrollo extraordinario de la ornamentación geométrica y la caligrafía como formas de expresión artística."]
},
'ar26': {
  fr:["Picasso a réalisé le Guernica en seulement 35 jours — il a documenté le processus en 45 photographies prises par sa compagne Dora Maar.","Le tableau est resté au MoMA de New York pendant 42 ans — Picasso avait exigé qu'il ne retourne en Espagne qu'après la fin de la dictature franquiste.","Quand un officier nazi a vu une reproduction du Guernica et a demandé « C'est vous qui avez fait ça ? », Picasso aurait répondu : « Non, c'est vous. »"],
  en:["Picasso completed Guernica in just 35 days — documenting the process in 45 photographs taken by his partner Dora Maar.","The painting stayed at New York's MoMA for 42 years — Picasso demanded it not return to Spain until Franco's dictatorship ended.","When a Nazi officer saw a Guernica reproduction and asked 'Did you do this?', Picasso reportedly answered: 'No, you did.'"],
    es:["El muralismo mexicano (1920-1970) fue un movimiento artístico con fines sociales y políticos liderado por Diego Rivera, David Alfaro Siqueiros y José Clemente Orozco.","Sus obras monumentales, pintadas en edificios públicos, narraban la historia de México, la lucha de las clases populares y la identidad mestiza del país.","El muralismo influyó directamente en el arte callejero y el grafiti contemporáneo, estableciendo el precedente de llevar el arte fuera de los museos y a las calles."]
},
'ar27': {
  fr:["La projection publique du 28 décembre 1895 au Grand Café à Paris est considérée comme la naissance du cinéma — les spectateurs auraient pris peur devant L'Arrivée d'un train.","Les frères Lumière ne croyaient pas à l'avenir du cinéma — Auguste a déclaré que c'était « une invention sans avenir commercial ».","Le cinématographe Lumière pesait seulement 5 kg et servait à la fois de caméra, de projecteur et de tireuse — une invention trois-en-un révolutionnaire."],
  en:["The public screening on December 28, 1895, at the Grand Café in Paris is considered cinema's birth — viewers reportedly panicked at The Arrival of a Train.","The Lumière brothers didn't believe in cinema's future — Auguste declared it 'an invention with no commercial future'.","The Lumière cinematograph weighed only 5 kg and served as camera, projector, and printer simultaneously — a revolutionary three-in-one invention."],
    es:["La música clásica india (raga) es uno de los sistemas musicales más complejos del mundo, con más de 300 ragas codificados, cada uno asociado a una emoción y un momento del día.","A diferencia de la música occidental, el raga no tiene partitura fija: el músico improvisa dentro de un marco melódico y rítmico (tala) durante actuaciones que pueden durar horas.","Ravi Shankar popularizó el sitar en Occidente en los años 60, influyendo en músicos como George Harrison de los Beatles y generando un interés duradero por la música india."]
},
'ar28': {
  fr:["Michel-Ange a peint le plafond seul, allongé sur un échafaudage pendant 4 ans (1508-1512) — il a développé des douleurs au cou qui l'ont handicapé à vie.","Il a écrit un poème décrivant sa souffrance, se comparant à un arc tendu : « Mon ventre se presse sous mon menton... Je ne suis pas un peintre. »","Malgré son mépris pour la peinture, le plafond de la Sixtine contient 343 figures sur 1 100 m² — un exploit technique qui a redéfini l'art occidental."],
  en:["Michelangelo painted the ceiling alone, lying on scaffolding for 4 years (1508-1512) — developing neck pain that handicapped him for life.","He wrote a poem describing his suffering, comparing himself to a bent bow: 'My belly pushes under my chin... I am not a painter.'","Despite his contempt for painting, the Sistine ceiling contains 343 figures across 1,100 m² — a technical feat that redefined Western art."],
    es:["El grabado en madera (xilografía), inventado en China hacia el siglo II, fue la primera técnica de impresión de imágenes y textos en la historia.","Albrecht Dürero elevó la xilografía a la categoría de arte mayor en el Renacimiento europeo con obras como El Apocalipsis (1498), de un detalle y expresividad sin precedentes.","La técnica inspiró siglos después el manga japonés: las estampas ukiyo-e de Hokusai y Hiroshige influyeron directamente en el estilo visual del cómic japonés moderno."]
},
'ar29': {
  fr:["Van Gogh s'est volontairement interné à l'asile Saint-Paul-de-Mausole après s'être coupé l'oreille — il y a réalisé 150 tableaux en un an.","Des astronomes ont montré que le ciel dans La Nuit étoilée correspond au ciel réel du 19 juin 1889 — avec Vénus visible près de l'horizon.","Les tourbillons du tableau correspondent mathématiquement aux équations de turbulence de Kolmogorov — Van Gogh avait intuitivement capturé un phénomène physique complexe."],
  en:["Van Gogh voluntarily committed himself to the Saint-Paul-de-Mausole asylum after cutting his ear — he produced 150 paintings in one year there.","Astronomers showed that the sky in The Starry Night matches the real sky of June 19, 1889 — with Venus visible near the horizon.","The painting's swirls mathematically match Kolmogorov's turbulence equations — Van Gogh intuitively captured a complex physical phenomenon."],
    es:["El land art surgió en los años 1960 como rechazo a la comercialización del arte, creando obras efímeras directamente en el paisaje natural.","Spiral Jetty de Robert Smithson (1970), una espiral de roca y sal de 460 metros en el Gran Lago Salado de Utah, es su obra más emblemática.","El land art cuestiona la propiedad del arte, su permanencia y su relación con la naturaleza — muchas obras son accesibles solo en persona y cambian con el tiempo y las estaciones."]
},
'ar30': {
  fr:["En 2013, un juge new-yorkais a condamné un promoteur à payer 6,8 millions de dollars pour avoir détruit des graffitis protégés du bâtiment 5Pointz.","La ville de Łódź en Pologne a transformé ses façades en galerie d'art urbain géante — attirant des touristes du monde entier.","Banksy reste anonyme depuis plus de 25 ans malgré sa célébrité mondiale — seule une poignée de personnes connaîtrait sa véritable identité."],
  en:["In 2013, a New York judge ordered a developer to pay $6.8 million for destroying protected graffiti at the 5Pointz building.","The city of Łódź in Poland transformed its facades into a giant urban art gallery — attracting tourists from around the world.","Banksy has remained anonymous for over 25 years despite worldwide fame — only a handful of people allegedly know his true identity."],
    es:["El arte digital abarca desde la pintura digital y el modelado 3D hasta el arte generativo creado por inteligencia artificial y los NFT.","El primer «arte por computadora» reconocido fue creado en los años 1960 por artistas como Vera Molnár y Harold Cohen, pioneros en el uso de algoritmos como herramientas creativas.","La irrupción de la IA generativa ha reavivado el debate sobre la autoría artística: ¿puede una máquina ser creativa, o simplemente recombina patrones de obras humanas existentes?"]
},

'inv21': {
  fr:["Whittle a déposé son brevet en 1930 mais l'armée britannique l'a ignoré — von Ohain, financé par Heinkel, a fait voler le premier avion à réaction (He 178) en 1939.","Les deux inventeurs se sont rencontrés en 1978 et sont devenus amis — Whittle a déclaré que von Ohain aurait mérité plus de reconnaissance.","Le principe du moteur à réaction repose sur la troisième loi de Newton : éjecter du gaz vers l'arrière propulse l'avion vers l'avant."],
  en:["Whittle filed his patent in 1930 but the British military ignored it — von Ohain, funded by Heinkel, flew the first jet aircraft (He 178) in 1939.","The two inventors met in 1978 and became friends — Whittle said von Ohain deserved more recognition.","The jet engine principle relies on Newton's third law: ejecting gas backward propels the aircraft forward."],
    es:["La máquina de vapor atmosférica de Thomas Newcomen (1712) fue la primera máquina capaz de convertir calor en trabajo mecánico de forma práctica.","Se usó principalmente para bombear agua de las minas de carbón — un problema que ni los molinos de viento ni los caballos podían resolver a la escala necesaria.","La eficiencia de la máquina de Newcomen era inferior al 1 %, pero su impacto fue revolucionario: demostró que las máquinas podían reemplazar la fuerza animal y humana."]
},
'inv22': {
  fr:["Woodland a tracé les lignes dans le sable de Miami Beach en 1949 — il a étendu les points et tirets du Morse en barres fines et épaisses.","Le premier produit scanné par un code-barres était un paquet de chewing-gums Wrigley's, le 26 juin 1974, dans un supermarché de l'Ohio.","Aujourd'hui, plus de 6 milliards de codes-barres sont scannés chaque jour dans le monde — le système a été breveté pour seulement 15 000 dollars en 1952."],
  en:["Woodland drew the lines in the sand at Miami Beach in 1949 — extending Morse dots and dashes into thin and thick bars.","The first product scanned by barcode was a pack of Wrigley's gum on June 26, 1974, at a supermarket in Ohio.","Today, over 6 billion barcodes are scanned daily worldwide — the system was patented for just $15,000 in 1952."],
    es:["El telescopio fue patentado por Hans Lippershey en 1608, pero Galileo fue quien lo apuntó al cielo en 1609, descubriendo las lunas de Júpiter y los cráteres de la Luna.","Estos descubrimientos apoyaron la teoría heliocéntrica de Copérnico y desafiaron la visión geocéntrica de la Iglesia — lo que le valió a Galileo un juicio por herejía.","Los telescopios modernos como el James Webb observan en infrarrojo y pueden detectar galaxias formadas poco después del Big Bang, a más de 13 000 millones de años-luz."]
},
'inv23': {
  fr:["Avant Otis, les ascenseurs existaient mais personne ne voulait les utiliser — les câbles cassaient régulièrement, causant des chutes mortelles.","Son système de sécurité utilisait un ressort à cliquet qui bloquait l'ascenseur sur les rails si le câble se rompait — simple mais révolutionnaire.","Sans l'ascenseur sécurisé, les gratte-ciel n'auraient jamais existé — Otis a littéralement permis la construction verticale des villes modernes."],
  en:["Before Otis, elevators existed but nobody wanted to use them — cables broke regularly, causing fatal falls.","His safety system used a ratchet spring that locked the elevator to rails if the cable snapped — simple but revolutionary.","Without the safe elevator, skyscrapers would never have existed — Otis literally enabled the vertical construction of modern cities."],
    es:["La batería eléctrica fue inventada por Alessandro Volta en 1800, apilando discos alternos de zinc y cobre separados por cartón empapado en salmuera.","La «pila voltaica» fue la primera fuente estable de corriente eléctrica continua, abriendo el camino a la electroquímica y el electromagnetismo.","Las baterías de litio-ion, inventadas en los años 1980, almacenan hasta 10 veces más energía que las de plomo-ácido y son la base de los teléfonos móviles, los portátiles y los coches eléctricos."]
},
'inv24': {
  fr:["Greatbatch construisait un oscillateur pour enregistrer les battements cardiaques — la mauvaise résistance a produit un signal pulsé de 1,8 milliampère, imitant le rythme du cœur.","Le premier pacemaker implanté sur un humain a été posé en 1958 en Suède — le patient, Arne Larsson, a survécu 43 ans avec 26 pacemakers successifs.","Aujourd'hui, plus de 3 millions de personnes dans le monde portent un pacemaker — et les modèles actuels durent 10 à 15 ans avec une pile au lithium."],
  en:["Greatbatch was building an oscillator to record heartbeats — the wrong resistor produced a 1.8-milliamp pulsed signal mimicking heart rhythm.","The first pacemaker implanted in a human was placed in 1958 in Sweden — patient Arne Larsson survived 43 years with 26 successive pacemakers.","Today, over 3 million people worldwide wear a pacemaker — current models last 10 to 15 years on a lithium battery."],
    es:["El caucho vulcanizado fue descubierto por Charles Goodyear en 1839 al dejar caer accidentalmente una mezcla de caucho y azufre sobre una estufa caliente.","Antes de la vulcanización, el caucho natural se derretía con el calor y se agrietaba con el frío — el proceso de Goodyear lo hizo elástico, resistente y duradero.","Goodyear murió endeudado en 1860 sin haber ganado casi nada de su invento — la empresa Goodyear Tire, fundada 38 años después, adoptó su nombre como homenaje póstumo."]
},
'inv25': {
  fr:["La tolérance de fabrication des briques Lego est de 2 micromètres — soit 0,002 mm, plus précis qu'une montre suisse.","L'usine Lego de Billund au Danemark produit 36 000 briques par minute — soit plus de 19 milliards de pièces par an.","Il existe environ 400 milliards de briques Lego dans le monde — statistiquement, chaque habitant de la planète en possède 62."],
  en:["Lego bricks have a manufacturing tolerance of 2 micrometers — 0.002 mm, more precise than a Swiss watch.","The Lego factory in Billund, Denmark produces 36,000 bricks per minute — over 19 billion pieces per year.","There are roughly 400 billion Lego bricks in the world — statistically, every person on Earth owns 62."],
    es:["El código Morse fue desarrollado por Samuel Morse y Alfred Vail en 1838 como sistema de comunicación para el telégrafo eléctrico.","La señal de socorro SOS (· · · — — — · · ·) fue elegida en 1906 no por significar «Save Our Souls» sino por ser la secuencia más fácil de transmitir y reconocer.","El telégrafo fue la primera tecnología capaz de transmitir información más rápido que un mensajero físico — redujo la comunicación transatlántica de semanas a minutos."]
},
'inv26': {
  fr:["Le message a été envoyé par l'ingénieur Neil Papworth depuis un ordinateur au téléphone de Richard Jarvis chez Vodafone, le 3 décembre 1992.","Les utilisateurs ne pouvaient pas encore répondre par SMS — la fonction de réponse n'est arrivée qu'en 1993 avec les téléphones Nokia.","Le record mondial de SMS envoyés en une minute est de 160 caractères en 18,19 secondes — un exploit réalisé sur un clavier physique, pas tactile."],
  en:["The message was sent by engineer Neil Papworth from a computer to Richard Jarvis's phone at Vodafone on December 3, 1992.","Users couldn't reply by SMS yet — the reply function only arrived in 1993 with Nokia phones.","The world record for texting speed is 160 characters in 18.19 seconds — achieved on a physical keyboard, not touchscreen."],
    es:["La anestesia quirúrgica fue demostrada públicamente por primera vez en 1846 por William Morton, que administró éter dietílico a un paciente en el Hospital General de Massachusetts.","Antes de la anestesia, las operaciones se realizaban con el paciente consciente, sujeto por asistentes — la velocidad del cirujano era la principal virtud médica.","El evento se conoce como «Ether Day» y la sala donde tuvo lugar, el Ether Dome, se conserva como monumento histórico — una de las mayores revoluciones de la historia de la medicina."]
},
'inv27': {
  fr:["L'inventeur original, Whitcomb Judson, a créé un « fermoir de chaussures à chaîne » qui fonctionnait mal et coinçait constamment.","C'est l'ingénieur suédois Gideon Sundback qui a perfectionné le design en 1913, créant le modèle moderne avec des dents imbriquées.","Le nom « zipper » a été inventé par B.F. Goodrich en 1923 pour ses bottes en caoutchouc — le bruit « zip » de la fermeture a donné le nom."],
  en:["Original inventor Whitcomb Judson created a 'chain shoe fastener' that worked poorly and constantly jammed.","Swedish engineer Gideon Sundback perfected the design in 1913, creating the modern interlocking-teeth model.","The name 'zipper' was coined by B.F. Goodrich in 1923 for their rubber boots — the 'zip' sound of closing gave it the name."],
    es:["La máquina de escribir comercial fue patentada por Christopher Latham Sholes en 1868 y fabricada por Remington a partir de 1873.","El teclado QWERTY fue diseñado para separar las letras más frecuentes y evitar que los martillos mecánicos se trabaran — una solución a un problema que ya no existe pero que seguimos usando.","Mark Twain fue uno de los primeros autores en entregar un manuscrito mecanografiado a una editorial: Las aventuras de Tom Sawyer (1876)."]
},
'inv28': {
  fr:["Plunkett travaillait sur des réfrigérants chez DuPont quand il a trouvé un résidu blanc de polytétrafluoroéthylène (PTFE) — le matériau le plus glissant connu.","Le Teflon a d'abord été utilisé dans le projet Manhattan pour protéger les joints des gaz corrosifs d'uranium — sa première utilisation était militaire et secrète.","Le coefficient de friction du Teflon est si bas (0,04) que même un gecko ne peut pas s'y accrocher — c'est l'une des rares surfaces que ses pattes ne peuvent pas gripper."],
  en:["Plunkett was working on refrigerants at DuPont when he found a white residue of polytetrafluoroethylene (PTFE) — the slipperiest known material.","Teflon was first used in the Manhattan Project to protect seals from corrosive uranium gases — its first use was military and classified.","Teflon's friction coefficient is so low (0.04) that even a gecko can't cling to it — one of the few surfaces its feet can't grip."],
    es:["El hormigón armado fue patentado por Joseph Monier en 1867 al insertar una malla de hierro dentro del hormigón, combinando la resistencia a compresión de uno con la resistencia a tracción del otro.","Los romanos ya usaban una forma de hormigón (opus caementicium) que incluía ceniza volcánica — el Panteón de Roma, con su cúpula de hormigón no armado, se mantiene en pie tras 2 000 años.","El hormigón es el material más utilizado del mundo después del agua: se producen unos 4 300 millones de toneladas al año, y su fabricación genera el 8 % de las emisiones globales de CO₂."]
},
'inv29': {
  fr:["Nobel a inventé la dynamite en 1867 en mélangeant de la nitroglycérine avec de la terre de diatomée — rendant l'explosif stable et transportable.","Un journal français a publié par erreur la nécrologie de Nobel en 1888 (c'était son frère qui était mort), le qualifiant de « marchand de la mort ».","Choqué par cet héritage, Nobel a légué 94 % de sa fortune (31 millions de couronnes) pour créer les cinq prix Nobel — paix, littérature, physique, chimie et médecine."],
  en:["Nobel invented dynamite in 1867 by mixing nitroglycerin with diatomaceous earth — making the explosive stable and transportable.","A French newspaper mistakenly published Nobel's obituary in 1888 (his brother had died), calling him 'the merchant of death'.","Shocked by this legacy, Nobel bequeathed 94% of his fortune (31 million kronor) to create the five Nobel Prizes — peace, literature, physics, chemistry, and medicine."],
    es:["El Kevlar fue descubierto en 1965 por Stephanie Kwolek, una química de DuPont que investigaba fibras ligeras para neumáticos.","Es cinco veces más resistente que el acero por unidad de peso y se utiliza en chalecos antibalas, cascos militares, cuerdas de alta resistencia y velas de competición.","Kwolek casi descartó la solución turbia que produjo en el laboratorio, pero insistió en hilarla — ese momento de perseverancia cambió el curso de la ciencia de los materiales."]
},
'inv30': {
  fr:["L'ingénieur Steve Sasson de Kodak a construit le prototype avec un capteur CCD de 100×100 pixels — l'image mettait 23 secondes à s'enregistrer sur une cassette.","Kodak a enterré l'invention par peur de cannibaliser son marché de pellicules photo — une décision qui a conduit à la faillite de l'entreprise en 2012.","Le premier appareil photo numérique commercial, le Dycam Model 1 (1990), coûtait 600 dollars et offrait une résolution de 0,09 mégapixel en noir et blanc."],
  en:["Kodak engineer Steve Sasson built the prototype with a 100×100 pixel CCD sensor — the image took 23 seconds to record onto a cassette.","Kodak buried the invention fearing it would cannibalize their photo film market — a decision that led to the company's bankruptcy in 2012.","The first commercial digital camera, the Dycam Model 1 (1990), cost $600 and offered 0.09-megapixel resolution in black and white."],
    es:["El marcapasos cardíaco implantable fue desarrollado por Wilson Greatbatch en 1958 — también por accidente: instaló una resistencia equivocada en un circuito y el dispositivo comenzó a emitir pulsos rítmicos.","El primer marcapasos fue implantado en Arne Larsson en 1958 en Suecia — Larsson sobrevivió a su cirujano y vivió hasta los 86 años con 26 marcapasos diferentes.","Los marcapasos modernos pesan menos de 30 gramos, duran hasta 15 años y algunos modelos pueden monitorizarse remotamente por bluetooth desde el teléfono del paciente."]
},


'l21': {
  fr:["Pantalone était un vieillard avare vénitien, reconnaissable à ses longues culottes collantes — le vêtement a pris le nom du personnage au 17ᵉ siècle.","Avant le « pantalon », les hommes portaient des hauts-de-chausses (culottes courtes) — le pantalon long était considéré comme vulgaire et réservé aux classes populaires.","Le mot « jean » vient de Gênes (Genoa en anglais, « jean » en français ancien), d'où était exporté le tissu de coton sergé qui deviendrait le denim."],
  en:["Pantalone was a greedy old Venetian, recognizable by his tight long stockings — the garment took the character's name in the 17th century.","Before 'pantalons,' men wore breeches (short trousers) — long trousers were considered vulgar and reserved for the lower classes.","The word 'jeans' comes from Genoa (called 'jean' in old French), which exported the twill cotton fabric that would become denim."],
    es:["El coreano utiliza el hangul, un alfabeto diseñado en 1443 por el rey Sejong el Grande específicamente para que el pueblo llano pudiera leer y escribir.","Antes del hangul, los coreanos usaban caracteres chinos (hanja), accesibles solo para la élite letrada — el hangul democratizó la alfabetización.","El hangul es considerado uno de los sistemas de escritura más lógicos y eficientes del mundo: sus 24 letras básicas representan las posiciones de la lengua y los labios al pronunciarlas."]
},
'l22': {
  fr:["Le mot se décompose en « kalsari » (sous-vêtements) et « kännit » (ivresse) — un concept que la Finlande assume pleinement comme élément culturel.","En 2017, la Finlande a créé des emojis nationaux officiels, dont un représentant le kalsarikännit — un personnage en caleçon avec une bière.","Les Finlandais ont de nombreux mots uniques : « sisu » (courage face à l'adversité) et « poronkusema » (distance qu'un renne peut parcourir sans uriner)."],
  en:["The word breaks down into 'kalsari' (underwear) and 'kännit' (drunkenness) — a concept Finland fully embraces as a cultural element.","In 2017, Finland created official national emojis, including one representing kalsarikännit — a character in underwear with a beer.","Finns have many unique words: 'sisu' (courage in adversity) and 'poronkusema' (distance a reindeer can walk without urinating)."],
    es:["El swahili es una lengua bantú con fuerte influencia árabe que sirve como lingua franca en gran parte de África oriental, hablada por más de 100 millones de personas.","Es lengua oficial en Tanzania, Kenia, Uganda y la República Democrática del Congo, y fue la primera lengua africana añadida a Google Translate.","El swahili «hakuna matata» (no hay problema), popularizado por El Rey León de Disney, es una expresión real usada cotidianamente en África oriental."]
},
'l23': {
  fr:["Les Hashshashins étaient une secte ismaélienne du 11ᵉ siècle dirigée par Hassan ibn al-Sabbah depuis la forteresse d'Alamut en Perse.","L'association avec le haschisch est probablement une légende propagée par les Croisés — les historiens modernes la contestent.","Le mot a voyagé de l'arabe à l'italien « assassino », puis au français « assassin » — chaque langue a gardé la connotation de meurtre prémédité."],
  en:["The Hashshashin were an 11th-century Ismaili sect led by Hassan ibn al-Sabbah from the fortress of Alamut in Persia.","The association with hashish is likely a legend spread by Crusaders — modern historians dispute it.","The word traveled from Arabic to Italian 'assassino,' then French 'assassin' — each language kept the connotation of premeditated murder."],
    es:["La palabra «algoritmo» proviene del nombre del matemático persa Al-Juarismi (siglo IX), cuya obra Kitab al-jabr dio también origen a la palabra «álgebra».","Al-Juarismi introdujo los numerales indo-arábigos en el mundo islámico y europeo, reemplazando gradualmente el sistema romano y revolucionando las matemáticas.","Hoy, los algoritmos son la base de la informática moderna: desde los motores de búsqueda hasta la inteligencia artificial, todo se reduce a secuencias de instrucciones lógicas."]
},
'l24': {
  fr:["En islandais, la politesse s'exprime par le conditionnel et le subjonctif — « Gætirðu » (pourrais-tu) remplace un mot dédié à la politesse.","Le japonais fonctionne de manière similaire mais inverse : il possède des niveaux de politesse si complexes qu'utiliser le mauvais peut offenser gravement.","Le thaï n'a pas non plus de mot exact pour « s'il vous plaît » — la particule « khrap/kha » en fin de phrase remplit cette fonction de politesse."],
  en:["In Icelandic, politeness is expressed through conditional and subjunctive moods — 'Gætirðu' (could you) replaces a dedicated polite word.","Japanese works similarly but inversely: it has politeness levels so complex that using the wrong one can cause serious offense.","Thai also lacks an exact word for 'please' — the particle 'khrap/kha' at the end of sentences fills this politeness function."],
    es:["El portugués es la sexta lengua más hablada del mundo con 260 millones de hablantes, distribuidos entre Brasil, Portugal, Mozambique, Angola y otros seis países.","Brasil concentra el 80 % de los lusófonos del mundo — el portugués brasileño y el europeo difieren en pronunciación, vocabulario y gramática, comparables a las diferencias entre el español de España y el de Latinoamérica.","El portugués y el español son mutuamente inteligibles en un 89 % del vocabulario, lo que permite una comprensión básica entre hablantes sin formación previa."]
},
'l25': {
  fr:["Les Grecs anciens pensaient la même chose — le mot grec « mys » signifie à la fois « muscle » et « souris ».","Cette double signification existe aussi en arabe (« adala »), en allemand et en russe — preuve que l'observation était universelle.","Le mot « lacerte » (lézard en latin) a aussi servi à désigner un muscle — le biceps bougeant sous la peau évoquait un petit reptile."],
  en:["Ancient Greeks thought the same — the Greek word 'mys' means both 'muscle' and 'mouse'.","This dual meaning also exists in Arabic ('adala'), German, and Russian — proof that the observation was universal.","The word 'lacerta' (lizard in Latin) was also used to name a muscle — the biceps moving under the skin evoked a small reptile."],
    es:["Los jeroglíficos egipcios fueron descifrados en 1822 por Jean-François Champollion gracias a la Piedra Rosetta, que contenía el mismo texto en jeroglíficos, demótico y griego.","El sistema jeroglífico combinaba logogramas (signos que representan palabras) y fonogramas (signos que representan sonidos), lo que lo hacía excepcionalmente complejo.","Los antiguos egipcios tenían tres sistemas de escritura diferentes: jeroglífico (ceremonial), hierático (administrativo) y demótico (cotidiano) — una complejidad que contribuyó al olvido de los jeroglíficos."]
},
'l26': {
  fr:["Ce chiffre est débattu par les linguistes : Franz Boas en mentionnait 4 en 1911, puis le mythe a gonflé — mais les langues inuites sont polysynthétiques, combinant des racines en mots-phrases complexes.","En réalité, les langues inuites ont des dizaines de racines pour la neige : « qanik » (neige qui tombe), « aput » (neige au sol), « pukak » (neige cristalline) et bien d'autres.","L'anglais aussi possède de nombreux mots pour la neige : slush, sleet, flurry, blizzard, powder, pack — mais personne n'en fait un mythe."],
  en:["This number is debated by linguists: Franz Boas mentioned 4 in 1911, then the myth grew — but Inuit languages are polysynthetic, combining roots into complex word-sentences.","In reality, Inuit languages have dozens of snow roots: 'qanik' (falling snow), 'aput' (snow on ground), 'pukak' (crystalline snow) and many more.","English also has many snow words: slush, sleet, flurry, blizzard, powder, pack — but nobody makes a myth of it."],
    es:["La palabra «robot» fue acuñada por el escritor checo Karel Čapek en su obra R.U.R. (Robots Universales Rossum) de 1920, derivada del checo robota (trabajo forzado).","En la obra, los robots son seres biológicos fabricados, no máquinas — la asociación con máquinas mecánicas vino después, con el auge de la ciencia ficción y la automatización industrial.","Isaac Asimov popularizó el término «robótica» y formuló las Tres Leyes de la Robótica en 1942, que siguen siendo referencia ética en el debate sobre la inteligencia artificial."]
},
'l27': {
  fr:["Les mercenaires croates servaient dans l'armée de Louis XIII pendant la guerre de Trente Ans — leur foulard noué a séduit la cour de France.","Louis XIV, grand amateur de mode, a adopté la « cravate » et en a fait un accessoire obligatoire à Versailles — lançant la tendance dans toute l'Europe.","Le nœud de cravate le plus complexe répertorié est le « Eldredge knot », qui nécessite 15 étapes — mais le nœud Windsor reste le plus élégant selon les puristes."],
  en:["Croatian mercenaries served in Louis XIII's army during the Thirty Years' War — their knotted scarves charmed the French court.","Louis XIV, a great fashion enthusiast, adopted the 'cravate' and made it mandatory at Versailles — launching the trend across Europe.","The most complex cataloged tie knot is the 'Eldredge knot,' requiring 15 steps — but the Windsor knot remains most elegant according to purists."],
    es:["El hawaiano tiene solo 13 letras (8 consonantes y 5 vocales), lo que lo convierte en uno de los alfabetos más cortos del mundo.","A pesar de su fonología simple, el hawaiano es una lengua rica en metáforas y conceptos sin equivalente directo en otros idiomas, como aloha (amor, compasión, hola, adiós) y ohana (familia extendida).","El hawaiano estuvo al borde de la extinción en los años 1980, con menos de 2 000 hablantes nativos — los programas de inmersión lingüística han recuperado la lengua, que hoy se enseña en escuelas y universidades."]
},
'l28': {
  fr:["Le texte original provient du « De Finibus Bonorum et Malorum » de Cicéron (45 av. J.-C.), un traité sur l'éthique et le bonheur.","Un imprimeur anonyme du 16ᵉ siècle a mélangé les mots et ajouté des passages absurdes — créant le « lorem ipsum » encore utilisé 500 ans plus tard.","Le premier mot « lorem » n'existe pas en latin — c'est la coupure du mot « dolorem » (douleur), preuve que le texte a été volontairement altéré."],
  en:["The original text comes from Cicero's 'De Finibus Bonorum et Malorum' (45 BC), a treatise on ethics and happiness.","An anonymous 16th-century printer scrambled the words and added nonsensical passages — creating the 'lorem ipsum' still used 500 years later.","The first word 'lorem' doesn't exist in Latin — it's a truncation of 'dolorem' (pain), proof the text was deliberately altered."],
    es:["El náhuatl, lengua de los aztecas, ha dejado numerosas palabras en el español y el inglés: chocolate (xocolātl), tomate (tomatl), aguacate (āhuacatl) y chicle (tzictli).","Aguacate proviene de āhuacatl, que en náhuatl significa «testículo» — una referencia a la forma del fruto que los colonizadores españoles adoptaron sin conocer su significado original.","El náhuatl sigue siendo hablado por más de 1,7 millones de personas en México, lo que lo convierte en la lengua indígena más hablada del país."]
},
'l29': {
  fr:["L'euskara est parlé par environ 750 000 personnes au Pays basque (Espagne et France) — il a survécu aux invasions romaines, wisigothiques, arabes et franques.","Des théories le relient au géorgien, au berbère ou même aux langues préceltiques — mais aucune parenté n'a jamais été prouvée scientifiquement.","Le basque utilise un système ergatif unique en Europe : le sujet d'un verbe transitif est marqué différemment du sujet d'un verbe intransitif."],
  en:["Euskara is spoken by about 750,000 people in the Basque Country (Spain and France) — it survived Roman, Visigothic, Arab, and Frankish invasions.","Theories link it to Georgian, Berber, or even pre-Celtic languages — but no relationship has ever been scientifically proven.","Basque uses an ergative system unique in Europe: the subject of a transitive verb is marked differently from an intransitive verb's subject."],
    es:["La tipografía Times New Roman fue creada en 1931 para el periódico The Times de Londres por Stanley Morison y Victor Lardent, con el objetivo de maximizar la legibilidad en columnas estrechas.","Se convirtió en la fuente predeterminada de Microsoft Word durante décadas, lo que la hizo ubicua en documentos académicos, legales y administrativos de todo el mundo.","En 2023, muchas universidades y empresas la han sustituido por fuentes como Calibri o Arial — pero su legado como la fuente más leída de la historia es indiscutible."]
},
'l30': {
  fr:["Le mot « chandelier » en anglais (lustre) vient de « chandelle » via l'ancien français « chandelabre » — mais en français moderne, un « chandelier » est un bougeoir.","L'anglais a emprunté environ 30 % de son vocabulaire au français — suite à la conquête normande de 1066, le français était la langue de la cour d'Angleterre pendant 300 ans.","D'autres mots français utilisés tels quels en anglais : « entrepreneur », « restaurant », « fiancé », « cliché », « déjà vu » et « faux pas »."],
  en:["The English word 'chandelier' comes from 'chandelle' via Old French 'chandelabre' — but in modern French, a 'chandelier' means a candlestick holder.","English borrowed about 30% of its vocabulary from French — after the Norman Conquest of 1066, French was the language of England's court for 300 years.","Other French words used as-is in English: 'entrepreneur,' 'restaurant,' 'fiancé,' 'cliché,' 'déjà vu,' and 'faux pas.'"],
    es:["La Real Academia Española (RAE), fundada en 1713, vela por la unidad del español con su lema «Limpia, fija y da esplendor».","El español es la segunda lengua materna más hablada del mundo (490 millones de nativos), por detrás del mandarín y por delante del inglés.","Cada país hispanohablante tiene su propia academia de la lengua, y las 23 academias trabajan juntas en la Asociación de Academias de la Lengua Española para mantener la coherencia del idioma."]
},

'f21': {
  fr:["Chaque fleur de crocus sativus ne produit que 3 stigmates — il faut donc 50 000 fleurs pour un seul kilo de safran, récolté à l'aube avant que les fleurs ne s'ouvrent.","L'Iran produit environ 90 % du safran mondial — mais le safran le plus cher vient de La Mancha en Espagne, avec l'appellation d'origine protégée.","Le safran vaut entre 30 000 et 40 000 € le kilo — ce qui en fait l'une des substances les plus chères au monde, devant l'or au gramme."],
  en:["Each crocus sativus flower produces only 3 stigmas — so 50,000 flowers are needed for one kilo of saffron, harvested at dawn before flowers open.","Iran produces about 90% of the world's saffron — but the most expensive comes from La Mancha, Spain, with protected designation of origin.","Saffron is worth €30,000 to €40,000 per kilo — making it one of the most expensive substances in the world, exceeding gold per gram."],
    es:["La pizza margherita fue creada en 1889 en Nápoles por el pizzero Raffaele Esposito en honor a la reina Margherita de Italia, usando los colores de la bandera: tomate (rojo), mozzarella (blanco) y albahaca (verde).","Sin embargo, los napolitanos ya comían pizzas similares desde al menos un siglo antes — la visita real simplemente oficializó un plato popular.","La Associazione Verace Pizza Napoletana certifica las pizzerías que siguen las reglas tradicionales: masa fermentada 24h, mozzarella di bufala, tomate San Marzano y horno de leña a 485 °C durante 60-90 segundos."]
},
'f22': {
  fr:["La coque de la noix de cajou contient de l'urushiol, la même substance irritante que le sumac vénéneux — c'est pourquoi on ne les vend jamais en coque.","La pomme de cajou est un faux-fruit juteux et sucré, consommé frais au Brésil et en Inde — mais elle se conserve si mal qu'elle est quasiment inconnue ailleurs.","Le Mozambique, le Vietnam et l'Inde sont les trois plus grands producteurs — un ouvrier décortique en moyenne 30 kg de noix par jour, souvent à mains nues."],
  en:["The cashew shell contains urushiol, the same irritant found in poison ivy — which is why they're never sold in-shell.","The cashew apple is a juicy, sweet false fruit eaten fresh in Brazil and India — but it spoils so quickly it's virtually unknown elsewhere.","Mozambique, Vietnam, and India are the three largest producers — a worker shells an average of 30 kg per day, often bare-handed."],
    es:["El curry no es una especia sino una mezcla variable que puede incluir cúrcuma, comino, cilantro, jengibre, pimienta, canela, cardamomo y decenas de otras especias.","La palabra «curry» fue popularizada por los británicos en la India colonial — en la cocina india real, cada plato tiene su propia mezcla específica de especias (masala).","El curry japonés, traído por los británicos en el siglo XIX, se ha convertido en uno de los platos más populares de Japón — servido con arroz, es tan cotidiano como el ramen."]
},
'f23': {
  fr:["Le Dr John Cook Bennett a publié des recettes de « pilules de tomate concentrée » en 1834, affirmant qu'elles guérissaient la diarrhée, la jaunisse et l'indigestion.","La tomate était considérée comme toxique en Europe jusqu'au 18ᵉ siècle — les assiettes en étain réagissaient avec l'acidité, causant des empoisonnements au plomb.","Aujourd'hui, les Américains consomment environ 300 millions de litres de ketchup par an — Heinz en détient plus de 60 % du marché mondial."],
  en:["Dr. John Cook Bennett published recipes for 'concentrated tomato pills' in 1834, claiming they cured diarrhea, jaundice, and indigestion.","Tomatoes were considered poisonous in Europe until the 18th century — pewter plates reacted with the acidity, causing lead poisoning.","Today, Americans consume about 300 million liters of ketchup per year — Heinz holds over 60% of the global market."],
    es:["El aguacate fue domesticado en Mesoamérica hace más de 5 000 años — su nombre proviene del náhuatl āhuacatl, que significa «testículo», por su forma.","Los grandes mamíferos prehistóricos (megafauna) dispersaban las semillas de aguacate al ingerirlos enteros — su extinción debería haber condenado al aguacate, pero la intervención humana lo salvó.","México produce un tercio del aguacate mundial, principalmente en el estado de Michoacán, donde los carteles del narcotráfico han llegado a controlar parte de la lucrativa industria."]
},
'f24': {
  fr:["La légende raconte qu'un boulanger viennois, alerté par le bruit des Ottomans creusant un tunnel, sauva la ville — et créa le « Kipferl » en forme de croissant ottoman pour célébrer.","Marie-Antoinette, princesse autrichienne devenue reine de France, aurait popularisé le Kipferl à la cour — les boulangers français l'ont ensuite feuilleté au beurre.","Le croissant « à la française » au beurre feuilleté que l'on connaît n'est apparu qu'en 1920, grâce à la boulangerie industrielle parisienne."],
  en:["Legend says a Viennese baker, alerted by the noise of Ottomans digging a tunnel, saved the city — and created the crescent-shaped 'Kipferl' to celebrate.","Marie-Antoinette, an Austrian princess who became Queen of France, supposedly popularized the Kipferl at court — French bakers then layered it with butter.","The buttery puff-pastry 'French croissant' we know only appeared in 1920, thanks to Parisian industrial bakeries."],
    es:["El queso existe desde hace al menos 7 500 años: restos de queso se han encontrado en vasijas neolíticas en Polonia y Croacia.","Su invención fue probablemente accidental: la leche transportada en estómagos de animales (que contienen cuajo) se coaguló naturalmente durante un viaje.","Francia produce más de 1 600 variedades de queso — el general De Gaulle dijo célebremente: «¿Cómo se puede gobernar un país que tiene 246 variedades de queso?» (la cifra era conservadora)."]
},
'f25': {
  fr:["Les bulles étaient un problème : la pression faisait exploser les bouteilles en cave, parfois en chaîne — les moines portaient des masques de fer pour se protéger.","Dom Pérignon a en réalité essayé d'éliminer les bulles — ses contributions majeures étaient l'assemblage de cépages et le bouchon de liège.","La phrase « Je bois des étoiles ! » attribuée à Dom Pérignon est une invention publicitaire de la maison Moët & Chandon au 19ᵉ siècle."],
  en:["Bubbles were a problem: pressure made bottles explode in cellars, sometimes in chain reactions — monks wore iron masks for protection.","Dom Pérignon actually tried to eliminate bubbles — his major contributions were blending grape varieties and using cork stoppers.","The quote 'I am drinking stars!' attributed to Dom Pérignon is a marketing invention by Moët & Chandon in the 19th century."],
    es:["El té es la bebida más consumida del mundo después del agua, con más de 3 000 millones de tazas diarias.","Todo el té (verde, negro, blanco, oolong) proviene de la misma planta, Camellia sinensis — la diferencia está en el grado de oxidación de las hojas tras la cosecha.","La ceremonia del té japonesa (chanoyu) es mucho más que preparar una bebida: es una práctica filosófica y artística que encarna los principios zen de armonía, respeto, pureza y tranquilidad."]
},
'f26': {
  fr:["Les carottes originales, cultivées en Perse et en Afghanistan, étaient violettes ou jaunes — la version orange est apparue aux Pays-Bas au 17ᵉ siècle.","La légende veut que les Néerlandais aient créé la carotte orange en hommage à Guillaume d'Orange — mais les historiens la contestent.","Les carottes violettes contiennent des anthocyanines, les mêmes antioxydants que les myrtilles — elles reviennent à la mode dans les marchés bio."],
  en:["Original carrots, cultivated in Persia and Afghanistan, were purple or yellow — the orange version appeared in the Netherlands in the 17th century.","Legend says the Dutch created the orange carrot in tribute to William of Orange — but historians dispute this.","Purple carrots contain anthocyanins, the same antioxidants as blueberries — they're making a comeback in organic markets."],
    es:["El maíz fue domesticado en México hace unos 9 000 años a partir de una planta silvestre llamada teosinte, que apenas se parece al maíz moderno.","La transformación del teosinte en maíz es considerada una de las mayores proezas de selección genética de la historia humana — los agricultores mesoamericanos multiplicaron por 10 el tamaño de la mazorca.","Hoy el maíz es el cereal más producido del mundo (1 200 millones de toneladas/año), superando al trigo y al arroz — se utiliza en alimentos, biocarburantes, plásticos y más de 4 000 productos industriales."]
},
'f27': {
  fr:["La théobromine signifie « nourriture des dieux » (du grec theos + broma) — elle stimule le cœur et dilate les bronches chez l'humain.","Un chien de 10 kg peut mourir en mangeant seulement 60 g de chocolat noir — les chats sont encore plus sensibles, mais en mangent rarement.","Les humains métabolisent la théobromine en 6 à 10 heures — les chiens mettent 17 heures, ce qui explique l'accumulation toxique."],
  en:["Theobromine means 'food of the gods' (from Greek theos + broma) — it stimulates the heart and dilates bronchial tubes in humans.","A 10 kg dog can die from eating just 60 g of dark chocolate — cats are even more sensitive, but rarely eat it.","Humans metabolize theobromine in 6 to 10 hours — dogs take 17 hours, which explains the toxic buildup."],
    es:["El aceite de oliva es la base de la dieta mediterránea, declarada Patrimonio Inmaterial de la Humanidad por la UNESCO en 2013.","Algunos olivos del Mediterráneo tienen más de 2 000 años de antigüedad y siguen produciendo aceitunas — son los árboles frutales más longevos del mundo.","España es el mayor productor mundial de aceite de oliva, con más del 40 % de la producción global — solo la provincia de Jaén produce más aceite que toda Grecia."]
},
'f28': {
  fr:["Parmentier a convaincu Louis XVI de planter des champs de pommes de terre gardés par des soldats le jour — mais volontairement non gardés la nuit, pour attiser la curiosité.","Le stratagème a fonctionné : les Parisiens ont volé les pommes de terre la nuit, croyant qu'elles avaient de la valeur puisqu'elles étaient gardées.","Parmentier a aussi organisé un dîner entièrement à base de pommes de terre pour Benjamin Franklin et d'autres notables — popularisant le tubercule dans les cercles influents."],
  en:["Parmentier convinced Louis XVI to plant potato fields guarded by soldiers during the day — but deliberately unguarded at night, to arouse curiosity.","The ploy worked: Parisians stole potatoes at night, believing they must be valuable since they were guarded.","Parmentier also organized an all-potato dinner for Benjamin Franklin and other notables — popularizing the tuber in influential circles."],
    es:["Los insectos comestibles son consumidos por más de 2 000 millones de personas en el mundo, con más de 2 100 especies catalogadas como alimento.","Los grillos producen la misma cantidad de proteínas que el ganado bovino usando 12 veces menos alimento y emitiendo 100 veces menos gases de efecto invernadero.","La Unión Europea autorizó en 2023 la comercialización de cuatro especies de insectos como alimento, incluyendo el grillo doméstico y la larva del gusano de la harina."]
},
'f29': {
  fr:["Le sel provient de la mine de Khewra au Pakistan, la deuxième plus grande mine de sel au monde — formée il y a 600 millions d'années par l'évaporation d'une mer ancienne.","Malgré les 84 minéraux vantés par le marketing, leur concentration est si faible (moins de 2 %) qu'il faudrait en consommer des kilos pour en tirer un bénéfice.","Le nom « Himalaya » est purement commercial — la mine de Khewra est à 300 km de la chaîne himalayenne, dans la province du Punjab."],
  en:["The salt comes from the Khewra mine in Pakistan, the world's second-largest salt mine — formed 600 million years ago by an ancient sea's evaporation.","Despite marketing claims of 84 minerals, their concentration is so low (under 2%) that you'd need to eat kilos to get any benefit.","The name 'Himalayan' is purely commercial — the Khewra mine is 300 km from the Himalayan range, in Punjab province."],
    es:["El chile más picante del mundo en 2024 es el Pepper X, creado por Ed Currie con 2 693 000 unidades Scoville — superando al Carolina Reaper.","Para comparar: un jalapeño alcanza 8 000 Scoville, una salsa tabasco 5 000, y el spray de pimienta policial oscila entre 2 y 5 millones de Scoville.","Los amantes del picante extremo experimentan una descarga de endorfinas similar a la de una montaña rusa — el cerebro interpreta el dolor como peligro y responde liberando analgésicos naturales."]
},
'f30': {
  fr:["Chaque grain de maïs contient environ 14 % d'eau piégée dans un amidon dense — à 180 °C, la vapeur atteint 9 fois la pression atmosphérique avant d'exploser.","Les plus anciens grains de popcorn, trouvés au Pérou, datent de 4700 av. J.-C. — les Amérindiens en mangeaient bien avant l'invention du cinéma.","Le popcorn éclate en deux formes : « papillon » (irrégulier, léger) ou « champignon » (rond, compact) — les cinémas préfèrent le papillon car il retient mieux le beurre."],
  en:["Each corn kernel contains about 14% water trapped in dense starch — at 180°C, steam reaches 9 times atmospheric pressure before exploding.","The oldest popcorn kernels, found in Peru, date to 4700 BC — Native Americans ate it long before cinema was invented.","Popcorn pops into two shapes: 'butterfly' (irregular, light) or 'mushroom' (round, compact) — cinemas prefer butterfly because it holds butter better."],
    es:["La fermentación es una de las técnicas culinarias más antiguas: el pan, el queso, el vino, la cerveza, el yogur, el kimchi y la salsa de soja son todos productos fermentados.","Los alimentos fermentados contienen probióticos que benefician la flora intestinal — estudios recientes vinculan un microbioma sano con mejor inmunidad, salud mental y digestión.","La cerveza más antigua conocida tiene unos 13 000 años: los Natufios del Levante elaboraban una bebida fermentada de trigo y cebada antes de inventar la agricultura propiamente dicha."]
},


'sp021': {
  fr:["Pelé a marqué 1 283 buts en 1 366 matchs, dont 77 buts en 92 sélections avec le Brésil — un ratio d'efficacité extraordinaire.","Il reste le seul joueur à avoir remporté trois Coupes du monde (1958, 1962, 1970) — un exploit qu'aucun footballeur n'a égalé depuis.","Son vrai nom est Edson Arantes do Nascimento — le surnom « Pelé » n'a aucune signification connue et il le détestait enfant."],
  en:["Pelé scored 1,283 goals in 1,366 matches, including 77 goals in 92 caps for Brazil — an extraordinary efficiency ratio.","He remains the only player to win three World Cups (1958, 1962, 1970) — a feat no footballer has matched since.","His real name is Edson Arantes do Nascimento — the nickname 'Pelé' has no known meaning and he hated it as a child."],
    es:["El boxeo es uno de los deportes más antiguos del mundo: representaciones de combates de puños aparecen en relieves sumerios del 3000 a.C.","Muhammad Ali, considerado el mejor boxeador de la historia, no solo dominó el ring sino que se convirtió en símbolo de la lucha por los derechos civiles al negarse a ir a Vietnam.","El combate Alí-Foreman «Rumble in the Jungle» (Kinshasa, 1974) es considerado el evento deportivo más importante del siglo XX y fue visto por mil millones de personas."]
},
'sp022': {
  fr:["Le match de 1920 entre Dick, Kerr's Ladies et St Helens Ladies a attiré 53 000 spectateurs à Goodison Park — avec 14 000 personnes refoulées à l'entrée.","La FA anglaise a interdit le football féminin en 1921, déclarant qu'il était « inadapté aux femmes » — l'interdiction n'a été levée qu'en 1971.","Pendant ces 50 ans d'interdiction, les femmes ont continué à jouer sur des terrains non affiliés — un acte de résistance qui a maintenu le sport en vie."],
  en:["The 1920 match between Dick, Kerr's Ladies and St Helens Ladies drew 53,000 spectators at Goodison Park — with 14,000 turned away.","The English FA banned women's football in 1921, declaring it 'unsuitable for females' — the ban wasn't lifted until 1971.","During those 50 years of prohibition, women kept playing on unaffiliated grounds — an act of resistance that kept the sport alive."],
    es:["El hockey sobre hielo es el deporte nacional de Canadá, donde se practica desde los años 1870 en lagos y ríos congelados.","El puck (disco) puede alcanzar velocidades superiores a 170 km/h — los porteros llevan más de 20 kg de protecciones y aun así sufren impactos frecuentes.","La Stanley Cup, el trofeo más antiguo del deporte profesional norteamericano (desde 1893), tiene la tradición de que cada jugador del equipo campeón puede llevarse la copa a casa durante un día."]
},
'sp023': {
  fr:["Le premier terrain synthétique a été installé à l'Astrodome de Houston en 1966 — l'herbe naturelle mourrait sous le toit, d'où le nom « AstroTurf ».","Les terrains modernes utilisent du caoutchouc recyclé de pneus comme remplissage — environ 40 000 pneus broyés par terrain.","La température de surface d'un terrain synthétique peut atteindre 70 °C en plein soleil — 35 °C de plus qu'un terrain en herbe naturelle."],
  en:["The first synthetic field was installed at Houston's Astrodome in 1966 — natural grass died under the roof, hence the name 'AstroTurf'.","Modern fields use recycled tire rubber as infill — about 40,000 shredded tires per field.","A synthetic field's surface temperature can reach 70°C in direct sunlight — 35°C more than natural grass."],
    es:["La escalada deportiva debutó en los Juegos Olímpicos de Tokio 2020 con tres disciplinas: velocidad, bloque y dificultad.","La escalada de velocidad es la más espectacular: los atletas suben un muro de 15 metros en menos de 5 segundos — más rápido que un sprint de Usain Bolt.","El bouldering (bloque) se practica sin cuerda a baja altura sobre colchonetas — exige más resolución de problemas que resistencia, convirtiendo la escalada en un deporte tanto mental como físico."]
},
'sp024': {
  fr:["Mueller-Korenek a pédalé dans l'aspiration d'un dragster modifié sur le lac salé de Bonneville — l'aspiration réduisait la résistance de l'air de 95 %.","Son vélo spécial, construit sur mesure, avait un rapport de transmission de 28 mètres par tour de pédale — impossible à utiliser sans aide au démarrage.","Le record précédent, 268 km/h par Fred Rompelberg en 1995, a tenu 23 ans — la différence de 12 km/h représente un bond technologique énorme."],
  en:["Mueller-Korenek pedaled in the draft of a modified dragster on the Bonneville Salt Flats — drafting reduced air resistance by 95%.","Her custom-built bike had a gear ratio of 28 meters per pedal revolution — impossible to use without a running start.","The previous record, 268 km/h by Fred Rompelberg in 1995, stood for 23 years — the 12 km/h difference represents a huge technological leap."],
    es:["El ping-pong (tenis de mesa) es el deporte con más practicantes del mundo: más de 300 millones de jugadores activos, la mayoría en China.","La pelota puede alcanzar 170 km/h en el servicio y 9 000 revoluciones por minuto de efecto — los jugadores profesionales reaccionan en milisegundos.","China ha dominado el tenis de mesa olímpico como ningún otro país en ningún otro deporte: ha ganado el 85 % de todas las medallas de oro en juego desde 1988."]
},
'sp025': {
  fr:["Le chankonabe est un ragoût à base de poulet (jamais de viande à quatre pattes, car un sumotori ne doit pas « marcher à quatre pattes ») avec des légumes et du tofu.","Les sumotori sautent le petit-déjeuner et s'entraînent à jeun pendant 5 heures — le premier repas à midi est suivi d'une sieste pour favoriser la prise de poids.","Un yokozuna (grand champion) pèse en moyenne 150 kg — mais certains atteignent 280 kg, comme le Samoan Konishiki dans les années 1990."],
  en:["Chankonabe is a stew made with chicken (never four-legged meat, since a sumo wrestler must never 'walk on all fours') with vegetables and tofu.","Sumo wrestlers skip breakfast and train on an empty stomach for 5 hours — the first meal at noon is followed by a nap to promote weight gain.","A yokozuna (grand champion) averages 150 kg — but some reach 280 kg, like Samoan Konishiki in the 1990s."],
    es:["El skateboarding nació en California en los años 1950 cuando surfistas buscaron replicar la sensación de las olas en el asfalto colocando ruedas bajo tablas de madera.","Tony Hawk realizó el primer «900» (dos giros y medio en el aire) en 1999, un momento que definió toda una generación y llevó el skate a la cultura mainstream.","El skateboarding debutó como deporte olímpico en Tokio 2020 — la ganadora de la categoría femenina de calle tenía solo 13 años, la medallista olímpica más joven de la historia de Japón."]
},
'sp026': {
  fr:["Le « jeu de paume » se jouait initialement avec la paume de la main — le gant, puis la raquette, n'est apparu qu'au 16ᵉ siècle.","Le mot « tennis » viendrait du français « tenez ! » que criait le serveur avant de lancer la balle — les Anglais ont adopté et déformé le mot.","Le système de score bizarre (15-30-40) pourrait venir des quarts d'horloge au 13ᵉ siècle — le 45 a été raccourci en 40 pour des raisons pratiques."],
  en:["'Jeu de paume' was originally played with the palm of the hand — gloves, then rackets, only appeared in the 16th century.","The word 'tennis' may come from the French 'tenez!' (take this!) shouted by the server before launching the ball — the English adopted and altered the word.","The odd scoring system (15-30-40) may come from 13th-century clock quarters — 45 was shortened to 40 for practical reasons."],
    es:["El rugby a siete (rugby sevens) se juega con 7 jugadores por equipo en partidos de 14 minutos — es la versión olímpica del rugby, incluida desde Río 2016.","Nueva Zelanda y Fiyi son las potencias dominantes: Fiyi ganó el oro en las dos primeras ediciones olímpicas, un hito para una nación de menos de un millón de habitantes.","El rugby sevens es especialmente popular en Hong Kong, donde el torneo anual (Hong Kong Sevens) atrae a 40 000 espectadores y es uno de los mayores eventos deportivos de Asia."]
},
'sp027': {
  fr:["Le match contre les New York Knicks s'est joué à Hershey, Pennsylvanie — il n'existe aucune vidéo complète, seulement un enregistrement audio partiel.","Chamberlain a mis 36 lancers francs sur 63 tentatives ce soir-là — ironie du sort pour un joueur habituellement médiocre aux lancers francs (51 % en carrière).","Le plus proche d'égaler ce record est Kobe Bryant avec 81 points en 2006 — soit encore 19 points de moins que Chamberlain."],
  en:["The game against the New York Knicks was played in Hershey, Pennsylvania — no complete video exists, only a partial audio recording.","Chamberlain made 36 free throws on 63 attempts that night — ironic for a player usually poor at free throws (51% career average).","The closest anyone has come is Kobe Bryant with 81 points in 2006 — still 19 points short of Chamberlain."],
    es:["La gimnasia artística combina fuerza, flexibilidad, coordinación y gracia en aparatos como barra fija, paralelas, suelo y salto.","Simone Biles es la gimnasta más laureada de la historia con 37 medallas mundiales — ha inventado movimientos tan difíciles que llevan su nombre y que nadie más puede ejecutar.","En Tokio 2020, Biles se retiró de varias finales por «twisties» (pérdida de orientación en el aire), abriendo un debate global sobre salud mental en el deporte de élite."]
},
'sp028': {
  fr:["La Royal Navy britannique n'a rendu les cours de natation obligatoires qu'en 1879 — pendant des siècles, la noyade était considérée comme un risque acceptable.","La superstition maritime voulait qu'apprendre à nager « provoque » la mer et attire le mauvais sort — mieux valait couler rapidement que souffrir.","Jusqu'au 19ᵉ siècle, les gilets de sauvetage étaient faits de liège cousu dans du tissu — ils étaient lourds, encombrants et souvent inutilisables."],
  en:["The British Royal Navy didn't make swimming lessons mandatory until 1879 — for centuries, drowning was considered an acceptable risk.","Maritime superstition held that learning to swim would 'provoke' the sea and attract bad luck — better to sink quickly than suffer.","Until the 19th century, life jackets were made of cork sewn into fabric — they were heavy, bulky, and often unusable."],
    es:["El sumo es el deporte nacional de Japón, con rituales sintoístas de más de 1 500 años: los luchadores lanzan sal para purificar el ring (dohyō) antes de cada combate.","Los sumotoris profesionales (rikishi) siguen un régimen estricto: viven en establos (heya), se levantan a las 5 h, entrenan en ayunas y comen chanko-nabe (un estofado calórico) para ganar peso.","Solo 72 luchadores han alcanzado el rango supremo de yokozuna en toda la historia del sumo — un título que implica no solo victoria sino también dignidad y gracia."]
},
'sp029': {
  fr:["Les femmes étaient interdites de spectacle sous peine de mort — seule exception : la prêtresse de Déméter avait un siège d'honneur.","Les Jeux olympiques anciens ont duré 1 169 ans (de 776 av. J.-C. à 393 apr. J.-C.) — abolis par l'empereur romain Théodose Ier car jugés païens.","L'épreuve la plus brutale était le pancrace, un mélange de boxe et de lutte sans règles — seuls les morsures et l'arrachage d'yeux étaient interdits."],
  en:["Women were forbidden from spectating under penalty of death — the only exception: the priestess of Demeter had a seat of honor.","The ancient Olympics lasted 1,169 years (776 BC to 393 AD) — abolished by Roman Emperor Theodosius I as pagan.","The most brutal event was the pankration, a mix of boxing and wrestling with no rules — only biting and eye-gouging were forbidden."],
    es:["El parkour fue creado en los años 1990 por David Belle en los suburbios de París, inspirado en los métodos de entrenamiento militar de su padre, Raymond Belle.","La disciplina consiste en desplazarse de un punto a otro de la manera más fluida y eficiente posible, superando obstáculos urbanos con saltos, escaladas y equilibrios.","El parkour fue reconocido como disciplina deportiva por varias federaciones nacionales de gimnasia, aunque sus practicantes debaten si debería competirse o mantenerse como arte libre."]
},
'sp030': {
  fr:["Garnerin a sauté depuis un ballon à hydrogène au-dessus du parc Monceau à Paris — sa nacelle oscillait si violemment que les spectateurs pensaient qu'il allait mourir.","Son parachute, en forme de parapluie de 7 mètres de diamètre, n'avait pas de trou d'aération — c'est la physicienne Sophie Blanchard qui a suggéré d'en ajouter un.","Jeanne-Geneviève Labrosse, épouse de Garnerin, est devenue la première femme parachutiste en 1799 — seulement deux ans après l'invention."],
  en:["Garnerin jumped from a hydrogen balloon above Parc Monceau in Paris — his basket swung so violently that spectators thought he would die.","His parachute, shaped like a 7-meter umbrella, had no vent hole — physicist Sophie Blanchard suggested adding one.","Jeanne-Geneviève Labrosse, Garnerin's wife, became the first female parachutist in 1799 — just two years after the invention."],
    es:["Los e-sports (deportes electrónicos) mueven más de 1 500 millones de dólares al año y atraen a más de 500 millones de espectadores en todo el mundo.","Los jugadores profesionales entrenan 8-12 horas diarias, tienen psicólogos deportivos, nutricionistas y coaches — su vida se asemeja a la de cualquier atleta de élite.","League of Legends, Dota 2, CS2 y Valorant ofrecen premios de torneos que superan los 40 millones de dólares — más que muchos torneos de golf o tenis profesional."]
},

'cel21': {
  fr:["Johnson a grandi dans la pauvreté — sa famille a été expulsée de leur appartement à Hawaï quand il avait 14 ans.","C'est le football américain qui l'a sauvé : il a obtenu une bourse à l'université de Miami, où il a joué en tant que defensive lineman.","Après une carrière avortée en NFL, il est devenu catcheur à la WWE avec seulement 7 dollars en poche — aujourd'hui sa fortune dépasse les 800 millions."],
  en:["Johnson grew up in poverty — his family was evicted from their apartment in Hawaii when he was 14.","Football saved him: he earned a scholarship to the University of Miami, where he played as a defensive lineman.","After a failed NFL career, he became a WWE wrestler with only $7 in his pocket — today his fortune exceeds $800 million."],
    es:["Pablo Picasso produjo más de 50 000 obras a lo largo de su carrera de 80 años — pinturas, esculturas, cerámicas, grabados y dibujos.","Picasso cofundó el cubismo con Georges Braque, descomponiendo los objetos en formas geométricas y mostrando múltiples perspectivas simultáneamente — una revolución visual.","El Guernica (1937), su denuncia del bombardeo de la ciudad vasca, es considerado uno de los alegatos más poderosos contra la guerra jamás pintados."]
},
'cel22': {
  fr:["Portman a étudié la psychologie à Harvard tout en tournant Star Wars — elle a déclaré préférer être « éduquée qu'être une star de cinéma ».","Ses travaux de recherche portaient sur le développement du lobe frontal chez les enfants et la mémoire — publiés dans des revues à comité de lecture.","Elle parle couramment six langues : hébreu, anglais, français, japonais, espagnol et allemand — et a étudié l'arabe à l'université."],
  en:["Portman studied psychology at Harvard while filming Star Wars — she stated she'd rather be 'educated than be a movie star'.","Her research focused on frontal lobe development in children and memory — published in peer-reviewed journals.","She speaks six languages fluently: Hebrew, English, French, Japanese, Spanish, and German — and studied Arabic at university."],
    es:["Mozart compuso su primera obra a los 5 años y su primera sinfonía a los 8 — fue el niño prodigio más célebre de la historia de la música.","Produjo más de 600 obras en solo 35 años de vida, incluyendo 41 sinfonías, 27 conciertos para piano y óperas como Las bodas de Fígaro y La flauta mágica.","Mozart murió a los 35 años en la pobreza y fue enterrado en una fosa común en Viena — la causa exacta de su muerte sigue siendo debatida por los historiadores médicos."]
},
'cel23': {
  fr:["Sa thèse portait sur l'application de l'auto-adaptation aux systèmes de contrôle — un sujet très éloigné de Mr. Bean.","Atkinson souffre de bégaiement depuis l'enfance — jouer des personnages muets ou à l'élocution exagérée est en partie une réponse créative à ce handicap.","Il est aussi un passionné de voitures rapides — il a crashé sa McLaren F1 deux fois, causant la réclamation d'assurance auto la plus élevée du Royaume-Uni (910 000 £)."],
  en:["His thesis was on applying self-adaptation to control systems — a subject far removed from Mr. Bean.","Atkinson has suffered from stuttering since childhood — playing silent or exaggerated characters is partly a creative response to this disability.","He's also a sports car enthusiast — he crashed his McLaren F1 twice, causing the UK's highest ever car insurance claim (£910,000)."],
    es:["Greta Thunberg comenzó su huelga escolar por el clima en agosto de 2018, sentándose sola frente al Parlamento sueco con un cartel — tenía 15 años.","Su movimiento Fridays for Future se extendió a 150 países e inspiró a millones de jóvenes a manifestarse por la acción climática.","Thunberg ha sido elogiada como la voz de una generación y criticada como símbolo de activismo vacío — en ambos casos, ha obligado al mundo a hablar de la crisis climática."]
},
'cel24': {
  fr:["Gaga a été admise à la Tisch School of the Arts de NYU à 17 ans — elle a abandonné après un an pour poursuivre sa carrière musicale.","Avant d'être célèbre, elle jouait dans des bars du Lower East Side de New York pour 0 dollar — payée uniquement en pourboires.","Son nom de scène vient de la chanson « Radio Ga Ga » de Queen — un SMS auto-correcteur a transformé « Radio » en « Lady » et le nom est resté."],
  en:["Gaga was admitted to NYU's Tisch School of the Arts at 17 — she dropped out after one year to pursue her music career.","Before fame, she played in Lower East Side bars in New York for $0 — paid only in tips.","Her stage name comes from Queen's 'Radio Ga Ga' — an autocorrect text changed 'Radio' to 'Lady' and the name stuck."],
    es:["Juana de Arco, una campesina analfabeta de 17 años, afirmó oír voces divinas que la instaban a liberar Francia de la ocupación inglesa durante la Guerra de los Cien Años.","Lideró tropas francesas en varias victorias decisivas, incluyendo la liberación de Orleans en 1429, que cambió el curso de la guerra.","Capturada por los borgoñones, vendida a los ingleses y condenada por herejía, fue quemada viva en Rouen en 1431 — fue canonizada como santa en 1920."]
},
'cel25': {
  fr:["Blastar était un jeu de tir spatial codé en BASIC sur un Commodore VIC-20 — il a été publié dans un magazine informatique sud-africain.","Musk a ensuite cofondé Zip2 à 24 ans, vendu pour 307 millions de dollars — puis X.com, devenu PayPal, vendu pour 1,5 milliard à eBay.","Le code source original de Blastar a été retrouvé et mis en ligne — des développeurs l'ont même adapté en version jouable dans un navigateur."],
  en:["Blastar was a space shooter coded in BASIC on a Commodore VIC-20 — it was published in a South African computer magazine.","Musk then co-founded Zip2 at 24, sold for $307 million — then X.com, which became PayPal, sold for $1.5 billion to eBay.","The original Blastar source code was recovered and put online — developers even adapted it into a playable browser version."],
    es:["Wangari Maathai fue la primera mujer africana en recibir el Premio Nobel de la Paz (2004) por su lucha por el medio ambiente y los derechos de las mujeres en Kenia.","Fundó el Movimiento del Cinturón Verde en 1977, que ha plantado más de 50 millones de árboles en África y empoderado a miles de mujeres rurales.","Maathai fue encarcelada, golpeada y amenazada de muerte por su activismo — pero nunca cedió, convirtiéndose en símbolo de la resistencia pacífica africana."]
},
'cel26': {
  fr:["Lamarr et le compositeur George Antheil ont breveté le « saut de fréquence » en 1942 pour guider les torpilles sans interception radio ennemie.","La Navy a ignoré leur brevet pendant 20 ans — la technologie n'a été utilisée qu'à partir de la crise des missiles de Cuba en 1962.","Le principe du saut de fréquence est devenu la base du CDMA, du Wi-Fi et du Bluetooth — Lamarr n'a reçu de reconnaissance qu'en 1997, trois ans avant sa mort."],
  en:["Lamarr and composer George Antheil patented 'frequency hopping' in 1942 to guide torpedoes without enemy radio interception.","The Navy ignored their patent for 20 years — the technology wasn't used until the Cuban Missile Crisis in 1962.","The frequency-hopping principle became the basis of CDMA, Wi-Fi, and Bluetooth — Lamarr only received recognition in 1997, three years before her death."],
    es:["Copernico fue el primero en proponer un modelo heliocéntrico completo del sistema solar en 1543, desafiando 1 400 años de geocentrismo ptolemaico.","Su obra De revolutionibus orbium coelestium fue publicada poco antes de su muerte — según la leyenda, recibió el primer ejemplar impreso en su lecho de muerte.","La revolución copernicana tardó más de un siglo en aceptarse plenamente: Galileo fue condenado por la Iglesia en 1633 por defender el heliocentrismo."]
},
'cel27': {
  fr:["Schwarzenegger a investi ses gains de culturisme dans l'immobilier dès son arrivée aux États-Unis en 1968 — achetant des immeubles à appartements à Santa Monica.","Il était millionnaire à 25 ans grâce à ses investissements immobiliers — bien avant Conan le Barbare (1982) ou Terminator (1984).","Son approche : acheter des propriétés en mauvais état, les rénover et les revendre — un modèle qu'il a appris seul en lisant des livres d'investissement."],
  en:["Schwarzenegger invested his bodybuilding earnings in real estate upon arriving in the US in 1968 — buying apartment buildings in Santa Monica.","He was a millionaire by 25 through real estate investments — well before Conan the Barbarian (1982) or Terminator (1984).","His approach: buy run-down properties, renovate, and resell — a model he taught himself by reading investment books."],
    es:["Pelé, considerado por muchos el mejor futbolista de la historia, marcó 1 283 goles en su carrera — un récord que ningún otro jugador ha igualado oficialmente.","Ganó tres Copas del Mundo con Brasil (1958, 1962, 1970) — el único jugador en lograr esa hazaña — y fue declarado «tesoro nacional» por el gobierno brasileño.","Pelé popularizó el fútbol en Estados Unidos jugando en el New York Cosmos en los años 1970, preparando el terreno para la creación de la MLS."]
},
'cel28': {
  fr:["Cook a déclaré que les e-mails des clients sont sa priorité matinale — il en reçoit des centaines par jour et y répond personnellement.","Il est arrivé chez Apple en 1998, recruté par Steve Jobs — Cook a rationalisé la chaîne d'approvisionnement, réduisant les stocks de mois à jours.","Sous sa direction, la valeur boursière d'Apple est passée de 348 milliards à plus de 3 000 milliards de dollars — le premier groupe à atteindre ce seuil."],
  en:["Cook has stated that customer emails are his morning priority — he receives hundreds daily and replies personally.","He joined Apple in 1998, recruited by Steve Jobs — Cook streamlined the supply chain, reducing inventory from months to days.","Under his leadership, Apple's market cap grew from $348 billion to over $3 trillion — the first company to reach that threshold."],
    es:["Rosa Parks se negó a ceder su asiento a un pasajero blanco en un autobús de Montgomery, Alabama, el 1 de diciembre de 1955.","Su arresto desencadenó un boicot de autobuses de 381 días liderado por Martin Luther King Jr. — un acto de desobediencia civil que transformó el movimiento por los derechos civiles.","Parks no fue la primera en negarse: Claudette Colvin lo hizo nueve meses antes, pero los líderes del movimiento eligieron a Parks por su imagen respetable — la historia es más compleja de lo que parece."]
},
'cel29': {
  fr:["Rowling vivait des allocations sociales en tant que mère célibataire à Édimbourg — elle écrivait Harry Potter dans des cafés pendant que sa fille dormait.","L'éditeur Barry Cunningham de Bloomsbury lui a dit : « Vous ne gagnerez jamais d'argent avec les livres pour enfants, trouvez un emploi. »","La franchise Harry Potter a généré plus de 25 milliards de dollars (livres, films, parcs, produits dérivés) — faisant de Rowling la première auteure milliardaire."],
  en:["Rowling was living on welfare as a single mother in Edinburgh — she wrote Harry Potter in cafés while her daughter slept.","Editor Barry Cunningham at Bloomsbury told her: 'You'll never make money with children's books, get a job.'","The Harry Potter franchise has generated over $25 billion (books, films, parks, merchandise) — making Rowling the first billionaire author."],
    es:["Alan Turing es considerado el padre de la informática teórica: su concepto de «máquina de Turing» (1936) definió los fundamentos de la computación moderna.","Durante la Segunda Guerra Mundial, Turing lideró el equipo que descifró el código Enigma de los nazis en Bletchley Park, acortando la guerra en al menos dos años según los historiadores.","Turing fue perseguido por su homosexualidad, condenado por «indecencia grave» en 1952 y sometido a castración química — se suicidó en 1954 a los 41 años. El gobierno británico le otorgó un perdón póstumo en 2013."]
},
'cel30': {
  fr:["Shakira a grandi à Barranquilla en Colombie avec un père libanais — elle a appris l'arabe en famille et le chante dans plusieurs de ses titres.","Elle a appris le portugais pour le marché brésilien, le français pendant sa période parisienne, et l'italien par amour de la culture méditerranéenne.","Son nom complet est Shakira Isabel Mebarak Ripoll — « Shakira » signifie « reconnaissante » en arabe (شاكرة)."],
  en:["Shakira grew up in Barranquilla, Colombia with a Lebanese father — she learned Arabic at home and sings it in several of her tracks.","She learned Portuguese for the Brazilian market, French during her Paris period, and Italian out of love for Mediterranean culture.","Her full name is Shakira Isabel Mebarak Ripoll — 'Shakira' means 'grateful' in Arabic (شاكرة)."],
    es:["Beyoncé ha ganado más premios Grammy que cualquier otro artista en la historia, con más de 30 gramófonos dorados.","Su álbum visual Lemonade (2016) exploró la infidelidad, la raza y el empoderamiento femenino negro, trascendiendo la música para convertirse en un fenómeno cultural.","Beyoncé controla todos los aspectos de su carrera — dirección artística, coreografía, producción, negocios — redefiniendo lo que significa ser artista en la era digital."]
},


'fic21': {
  fr:["Tolkien était professeur de philologie à Oxford — il a créé le quenya et le sindarin avec des grammaires complètes, des systèmes d'écriture et des étymologies.","Le quenya est inspiré du finnois et du latin, tandis que le sindarin s'appuie sur le gallois — deux langues que Tolkien admirait profondément.","Il a écrit dans une lettre : « L'invention des langues est la fondation. Les histoires ont été créées pour fournir un monde où ces langues puissent exister. »"],
  en:["Tolkien was a philology professor at Oxford — he created Quenya and Sindarin with complete grammars, writing systems, and etymologies.","Quenya was inspired by Finnish and Latin, while Sindarin drew from Welsh — two languages Tolkien deeply admired.","He wrote in a letter: 'The invention of languages is the foundation. The stories were created to provide a world in which these languages could exist.'"],
    es:["Las Mil y Una Noches es una recopilación de cuentos árabes, persas e indios que incluye historias universalmente conocidas como Aladino, Simbad y Ali Baba.","La estructura de cajas chinas (cuentos dentro de cuentos) fue revolucionaria: Sheherezade narra historias durante 1001 noches para evitar su ejecución por el sultán.","Aladino y Alí Babá no figuraban en los manuscritos originales: fueron añadidos por el traductor francés Antoine Galland en el siglo XVIII, basándose en un cuentista sirio."]
},
'fic22': {
  fr:["Mary Shelley a écrit Frankenstein à seulement 18 ans, lors d'un concours d'histoires d'horreur avec Lord Byron et Percy Shelley en 1816.","Dans le roman, la créature est éloquente et philosophique — elle cite Milton et Goethe, très loin du monstre muet des films hollywoodiens.","Le roman est souvent considéré comme le premier livre de science-fiction — il pose des questions sur la responsabilité scientifique encore pertinentes aujourd'hui."],
  en:["Mary Shelley wrote Frankenstein at just 18, during a horror story contest with Lord Byron and Percy Shelley in 1816.","In the novel, the creature is eloquent and philosophical — it quotes Milton and Goethe, far from the mute Hollywood monster.","The novel is often considered the first science fiction book — it raises questions about scientific responsibility still relevant today."],
    es:["El manga Naruto de Masashi Kishimoto ha vendido más de 250 millones de copias y ha influido en toda una generación de artistas y creadores en el mundo entero.","La historia de un ninja marginado que sueña con ser líder de su aldea resuena con temas universales de perseverancia, amistad y superación personal.","Naruto introdujo la cultura ninja japonesa a millones de lectores occidentales, generando un interés real por la historia y la mitología japonesas."]
},
'fic23': {
  fr:["King a jeté les trois premières pages de Carrie, convaincu qu'un homme ne pouvait pas écrire de manière crédible sur une adolescente.","Tabitha a repêché les pages froissées dans la corbeille et les a lues — elle lui a dit : « Tu tiens quelque chose. Continue. »","Carrie s'est vendu à un million d'exemplaires en paperback la première année — les droits du film ont rapporté 400 000 dollars, lançant la carrière de King."],
  en:["King threw away the first three pages of Carrie, convinced a man couldn't credibly write about a teenage girl.","Tabitha fished the crumpled pages from the trash and read them — she told him: 'You've got something here. Keep going.'","Carrie sold one million paperback copies in its first year — film rights brought $400,000, launching King's career."],
    es:["Astérix, creado por Goscinny y Uderzo en 1959, es el cómic francés más exitoso de la historia, con más de 390 millones de álbumes vendidos en todo el mundo.","Cada álbum parodia un país o cultura diferente a través del prisma galo, con juegos de palabras que son una pesadilla para los traductores.","El parque Astérix, cerca de París, compite directamente con Disneyland — una rara victoria cultural europea frente a la hegemonía del entretenimiento estadounidense."]
},
'fic24': {
  fr:["Saint-Exupéry a écrit et illustré Le Petit Prince à New York en 1943, pendant son exil de la France occupée — il n'a jamais vu le succès du livre, étant mort en 1944.","Le livre se vend à plus de 2 millions d'exemplaires par an dans le monde — totalisant plus de 200 millions de copies vendues depuis sa publication.","Il a été traduit dans des langues rares comme le toba (Argentine), le judéo-espagnol et même le braille emoji — c'est un outil pédagogique universel."],
  en:["Saint-Exupéry wrote and illustrated The Little Prince in New York in 1943, during his exile from occupied France — he never saw the book's success, dying in 1944.","The book sells over 2 million copies yearly worldwide — totaling over 200 million copies sold since publication.","It has been translated into rare languages like Toba (Argentina), Judeo-Spanish, and even Braille emoji — it's a universal teaching tool."],
    es:["La Divina Comedia de Dante Alighieri (1320) es considerada una de las mayores obras de la literatura universal y fundó la lengua italiana literaria.","El poema describe un viaje por el Infierno, el Purgatorio y el Paraíso, con descripciones tan vívidas que influyeron en las representaciones artísticas del más allá durante siglos.","Dante escribió en toscano vulgar en lugar de latín — una decisión revolucionaria que democratizó la literatura y sentó las bases del italiano moderno."]
},
'fic25': {
  fr:["Conan Doyle a fait tomber Holmes avec son ennemi Moriarty aux chutes de Reichenbach en Suisse en 1893 — 20 000 lecteurs ont annulé leur abonnement au Strand Magazine.","Des Londoniens portaient des brassards noirs en signe de deuil — la reine Victoria elle-même aurait exprimé son mécontentement.","Conan Doyle a ressuscité Holmes en 1903 dans La Maison vide, expliquant qu'il avait simulé sa mort grâce au « baritsu », un art martial fictif."],
  en:["Conan Doyle had Holmes fall with his nemesis Moriarty at Reichenbach Falls in Switzerland in 1893 — 20,000 readers canceled their Strand Magazine subscriptions.","Londoners wore black armbands in mourning — Queen Victoria herself reportedly expressed displeasure.","Conan Doyle resurrected Holmes in 1903 in 'The Empty House,' explaining he faked his death using 'baritsu,' a fictional martial art."],
    es:["Spider-Man fue creado por Stan Lee y Steve Ditko en 1962 como un superhéroe adolescente con problemas cotidianos — una novedad radical en el género.","Peter Parker era tímido, tenía problemas de dinero y era acosado en el instituto — un héroe con el que los lectores jóvenes podían identificarse por primera vez.","Spider-Man es el superhéroe más popular del mundo en merchandising y ha protagonizado más de 10 películas que han recaudado conjuntamente más de 8 000 millones de dólares."]
},
'fic26': {
  fr:["L'Odyssée raconte le retour d'Ulysse à Ithaque après la guerre de Troie — un voyage de 10 ans rempli de monstres, de dieux et de tentations.","Le texte a été transmis oralement pendant des siècles avant d'être écrit — les « aèdes » (bardes grecs) le récitaient de mémoire en performances de plusieurs heures.","Le mot « odyssée » est devenu synonyme de voyage épique dans toutes les langues européennes — un testament de l'influence durable du poème d'Homère."],
  en:["The Odyssey tells of Odysseus's return to Ithaca after the Trojan War — a 10-year journey filled with monsters, gods, and temptations.","The text was transmitted orally for centuries before being written — 'aoidoi' (Greek bards) recited it from memory in hours-long performances.","The word 'odyssey' has become synonymous with epic journey in all European languages — a testament to Homer's lasting influence."],
    es:["Hamlet de Shakespeare (1600) es la obra de teatro más representada y estudiada de la historia, con el monólogo «ser o no ser» como texto dramático más famoso del mundo.","La obra explora la duda, la venganza, la locura y la mortalidad con una profundidad psicológica que anticipó el psicoanálisis de Freud por tres siglos.","Hamlet ha sido interpretado por los mayores actores de cada generación — desde Richard Burbage en 1601 hasta Benedict Cumberbatch en 2015."]
},
'fic27': {
  fr:["Anthony Pratt et sa femme Elva ont inventé le jeu pendant les longues nuits de black-out — les voisins se réunissaient pour jouer à des jeux de meurtre fictif.","Le jeu a été vendu à Waddingtons en 1947 — mais les pénuries d'après-guerre ont retardé sa production jusqu'en 1949.","Le Colonel Moutarde (Colonel Mustard) et les autres personnages ont des noms différents selon les pays — en Amérique, Mme Leblanc est Mrs. White."],
  en:["Anthony Pratt and his wife Elva invented the game during long blackout nights — neighbors gathered to play fictional murder games.","The game was sold to Waddingtons in 1947 — but post-war shortages delayed production until 1949.","Colonel Mustard and other characters have different names in different countries — in France, Mrs. White becomes Madame Leblanc."],
    es:["El Pequeño Príncipe ha sido adaptado a más de 300 idiomas y dialectos, incluyendo lenguas en peligro de extinción como el toba y el maya lacandón.","Saint-Exupéry ilustró personalmente el libro con acuarelas — sus dibujos aparentemente simples son parte integral de la obra y tan famosos como el texto.","La rosa del Principito es generalmente interpretada como un símbolo de Consuelo Suncín, la esposa salvadoreña de Saint-Exupéry — una relación apasionada y tormentosa."]
},
'fic28': {
  fr:["Dans la version de 1812, la sorcière découvre la liaison quand Raiponce demande pourquoi ses vêtements deviennent trop serrés — une allusion claire à sa grossesse.","Les frères Grimm ont édulcoré leurs contes au fil des éditions — la version de 1857 remplace la grossesse par une visite accidentelle mentionnée innocemment.","Blanche-Neige était encore plus sombre à l'origine : c'est la mère biologique (pas la belle-mère) qui ordonne son meurtre par jalousie."],
  en:["In the 1812 version, the witch discovers the affair when Rapunzel asks why her clothes are getting tight — a clear allusion to pregnancy.","The Brothers Grimm softened their tales across editions — the 1857 version replaces pregnancy with an innocently mentioned accidental visit.","Snow White was even darker originally: it's the biological mother (not stepmother) who orders her murder out of jealousy."],
    es:["Miyazaki Hayao, fundador del Studio Ghibli, es considerado el Walt Disney japonés — sus películas han ganado un Oscar y son tesoros culturales.","El viaje de Chihiro (2001) ganó el Oscar a Mejor Película de Animación y el Oso de Oro en Berlín — la única película animada en conseguir ambos premios.","Miyazaki se ha retirado y vuelto al trabajo al menos cuatro veces — su perfeccionismo y su pasión por la animación tradicional (dibujada a mano) lo distinguen en una era digital."]
},
'fic29': {
  fr:["Le titre complet est « De optimo reipublicae statu deque nova insula Utopia » — More décrit une île fictive avec une société idéale sans propriété privée.","More a été décapité par Henri VIII en 1535 pour avoir refusé de reconnaître le roi comme chef de l'Église d'Angleterre — il a été canonisé en 1935.","Le mot « dystopie », son opposé, n'est apparu qu'en 1868 — inventé par John Stuart Mill dans un discours au Parlement britannique."],
  en:["The full title is 'De optimo reipublicae statu deque nova insula Utopia' — More describes a fictional island with an ideal society without private property.","More was beheaded by Henry VIII in 1535 for refusing to recognize the king as head of the Church of England — he was canonized in 1935.","The word 'dystopia,' its opposite, only appeared in 1868 — coined by John Stuart Mill in a speech to the British Parliament."],
    es:["Los Miserables de Victor Hugo (1862) es una de las novelas más largas y ambiciosas de la literatura universal, con más de 1 500 páginas.","Hugo interrumpió la escritura durante 12 años (1848-1860) por su exilio político — retomó la novela en la isla de Guernesey con una visión aún más social y humanista.","El musical basado en la novela (1985) es el espectáculo más longevo de la historia del West End de Londres, con más de 13 000 representaciones."]
},
'fic30': {
  fr:["Don Quichotte est le livre le plus vendu de tous les temps après la Bible — plus de 500 millions d'exemplaires, traduit dans plus de 140 langues.","Cervantès a écrit la deuxième partie en 1615 parce qu'un imposteur avait publié une fausse suite — un des premiers cas de « fan fiction non autorisée ».","Le personnage de Sancho Panza est considéré comme le premier « sidekick » de la littérature — un archétype repris dans d'innombrables œuvres depuis."],
  en:["Don Quixote is the best-selling book of all time after the Bible — over 500 million copies, translated into more than 140 languages.","Cervantes wrote the second part in 1615 because an impostor published a fake sequel — one of the first cases of unauthorized fan fiction.","The character of Sancho Panza is considered literature's first 'sidekick' — an archetype replicated in countless works since."],
    es:["Mafalda, creada por el argentino Quino en 1964, es la tira cómica más influyente de América Latina — una niña de 6 años que cuestiona la política, la sociedad y la condición humana.","Quino dejó de dibujar Mafalda en 1973 para evitar que se volviera repetitiva — una decisión que preservó la frescura y la relevancia del personaje durante décadas.","La UNICEF adoptó a Mafalda como defensora de los derechos de los niños, y sus tiras se han traducido a más de 30 idiomas."]
},

'gam21': {
  fr:["Le créateur Hidetaka Miyazaki s'est inspiré de ses lectures de fantasy en anglais étant enfant — il ne comprenait pas tout et comblait les blancs par l'imagination.","Dark Souls a inventé le concept de « narration par l'environnement » — l'histoire n'est jamais racontée directement mais découverte par les objets et les décors.","Le jeu a engendré un genre entier appelé « souls-like » — des dizaines de jeux s'en inspirent, de Hollow Knight à Elden Ring (qui a dépassé 25 millions de ventes)."],
  en:["Creator Hidetaka Miyazaki was inspired by reading fantasy books in English as a child — he didn't understand everything and filled gaps with imagination.","Dark Souls pioneered 'environmental storytelling' — the story is never told directly but discovered through items and environments.","The game spawned an entire genre called 'souls-like' — dozens of games draw from it, from Hollow Knight to Elden Ring (which exceeded 25 million sales)."],
    es:["El primer speedrun documentado es de Doom en 1994 — hoy, el speedrunning es una subcultura global con eventos caritativos como Games Done Quick que recaudan millones.","Los speedrunners explotan bugs, glitches y atajos no previstos por los desarrolladores para terminar juegos en fracciones del tiempo normal.","Super Mario 64 se puede completar en menos de 7 minutos con las técnicas más avanzadas — un juego diseñado para docenas de horas de juego."]
},
'gam22': {
  fr:["Warren Robinett a caché un écran secret affichant « Created by Warren Robinett » — Atari ne l'a découvert qu'après avoir vendu des milliers de copies.","Atari a ensuite décidé de garder ces secrets cachés dans les jeux futurs — ils les ont baptisés « easter eggs » (œufs de Pâques), lançant une tradition durable.","Le film Ready Player One de Spielberg rend hommage à cet easter egg — le personnage principal doit le trouver dans une quête virtuelle."],
  en:["Warren Robinett hid a secret screen displaying 'Created by Warren Robinett' — Atari only discovered it after selling thousands of copies.","Atari then decided to keep these hidden secrets in future games — they named them 'easter eggs,' starting a lasting tradition.","Spielberg's Ready Player One pays tribute to this easter egg — the protagonist must find it in a virtual quest."],
    es:["Wii Sports (2006) de Nintendo vendió más de 82 millones de copias y convirtió a la Wii en un fenómeno social que atrajo a jugadores no tradicionales — abuelos, familias y no gamers.","El control por movimiento fue tan intuitivo que causó accidentes: televisores rotos y mandos estrellados se volvieron virales en los primeros meses.","La Wii demostró que la innovación en la interfaz puede ser más disruptiva que la potencia gráfica — una lección que Nintendo sigue aplicando con la Switch."]
},
'gam23': {
  fr:["La console appartenait au soldat Stephan Scoggins — après le bombardement de sa caserne, la Game Boy fonctionnait encore avec Tetris inséré.","Nintendo a exposé cette Game Boy calcinée dans son Nintendo World Store à New York pendant des années — elle est devenue un symbole de durabilité.","La Game Boy originale s'est vendue à 118 millions d'exemplaires — son écran monochrome vert et sa longue autonomie l'ont rendue quasiment indestructible."],
  en:["The console belonged to soldier Stephan Scoggins — after his barracks were bombed, the Game Boy still worked with Tetris inserted.","Nintendo displayed this charred Game Boy at its Nintendo World Store in New York for years — it became a symbol of durability.","The original Game Boy sold 118 million units — its green monochrome screen and long battery life made it virtually indestructible."],
    es:["Half-Life (1998) revolucionó el FPS narrativo: en lugar de cinemáticas separadas, la historia se cuenta durante el gameplay, sin interrumpir nunca el control del jugador.","Su secuela Half-Life 2 (2004) introdujo el motor Source y la física realista en los shooters, elevando el estándar técnico de toda la industria.","Half-Life 3 es el juego más esperado y nunca anunciado de la historia — la ausencia de secuela se ha convertido en el meme más duradero del mundo del gaming."]
},
'gam24': {
  fr:["Le tournoi, organisé par Stewart Brand (futur fondateur du Whole Earth Catalog), s'appelait les « Intergalactic Spacewar Olympics ».","Cinq étudiants ont participé en équipes de deux — la compétition se jouait sur un PDP-10, un ordinateur de la taille d'une armoire.","Le premier tournoi d'e-sport avec un prix en argent réel a eu lieu en 1980 — le Space Invaders Championship d'Atari a attiré 10 000 participants."],
  en:["The tournament, organized by Stewart Brand (future founder of the Whole Earth Catalog), was called the 'Intergalactic Spacewar Olympics'.","Five students participated in teams of two — the competition was played on a PDP-10, a computer the size of a wardrobe.","The first esports tournament with real prize money was in 1980 — Atari's Space Invaders Championship attracted 10,000 participants."],
    es:["Among Us (2018) pasó desapercibido durante dos años hasta que streamers de Twitch lo popularizaron en 2020 — llegó a 500 millones de jugadores activos mensuales.","El juego de deducción social (inspirado en Mafia y Los Hombres Lobo) demostró que un concepto simple con la plataforma adecuada puede convertirse en fenómeno global.","La palabra «sus» (sospechoso), popularizada por Among Us, entró en el vocabulario cotidiano de toda una generación — un ejemplo de cómo los videojuegos moldean el lenguaje."]
},
'gam25': {
  fr:["Le premier Animal Crossing (2001) sur Nintendo 64 au Japon utilisait l'horloge interne de la console — les joueurs découvraient des événements différents selon l'heure réelle.","Les joueurs qui avancent l'horloge (« time traveling ») sont mal vus par la communauté — le créateur Katsuya Eguchi a confirmé que ce n'était pas l'esprit du jeu.","Animal Crossing: New Horizons, sorti pendant le confinement de 2020, s'est vendu à 44 millions d'exemplaires — devenant un phénomène social mondial."],
  en:["The first Animal Crossing (2001) on Nintendo 64 in Japan used the console's internal clock — players discovered different events based on real time.","Players who advance the clock ('time traveling') are frowned upon by the community — creator Katsuya Eguchi confirmed it wasn't the game's spirit.","Animal Crossing: New Horizons, released during the 2020 lockdown, sold 44 million copies — becoming a global social phenomenon."],
    es:["Elden Ring (2022) de FromSoftware y George R.R. Martin vendió más de 20 millones de copias en su primer año, combinando la dificultad de Dark Souls con un mundo abierto épico.","Martin escribió la mitología y el trasfondo del mundo (The Lands Between), mientras Miyazaki diseñó el gameplay y la narrativa fragmentaria característica de sus obras.","Elden Ring ganó el Game Award al Juego del Año 2022 y revitalizó el debate sobre la accesibilidad en los videojuegos: ¿un juego debería adaptarse a todos o preservar su visión artística?"]
},
'gam26': {
  fr:["Le programmeur Kazuhisa Hashimoto a créé ce code pour faciliter ses tests de Gradius, un shoot'em up très difficile — il a oublié de le retirer avant la sortie.","Le code a ensuite été intégré dans plus de 100 jeux Konami — et adopté par des centaines de sites web comme Google, qui l'utilisent comme easter egg.","Hashimoto est décédé en 2020 — Konami lui a rendu hommage en tweetant le code : ↑↑↓↓←→←→BA."],
  en:["Programmer Kazuhisa Hashimoto created this code to ease his testing of Gradius, a very difficult shoot'em up — he forgot to remove it before release.","The code was then embedded in over 100 Konami games — and adopted by hundreds of websites including Google, which use it as an easter egg.","Hashimoto passed away in 2020 — Konami paid tribute by tweeting the code: ↑↑↓↓←→←→BA."],
    es:["La Nintendo Switch (2017) es una consola híbrida que se puede usar como portátil o conectar a la televisión — ha vendido más de 140 millones de unidades.","The Legend of Zelda: Tears of the Kingdom (2023) vendió más de 10 millones de copias en tres días, batiendo récords de la propia Nintendo.","La filosofía de Nintendo — «la jugabilidad antes que los gráficos» — le ha permitido competir contra Sony y Microsoft con hardware significativamente menos potente."]
},
'gam27': {
  fr:["Billy Mitchell a été le premier à réaliser un score parfait en 1999, en jouant pendant 6 heures sans une seule erreur.","Le niveau 256 est un « kill screen » — un bug qui rend la moitié droite de l'écran illisible, mettant fin au jeu.","Le nom original de Pac-Man était « Puck-Man » au Japon — Namco l'a changé aux États-Unis pour éviter un vandalisme prévisible sur les bornes d'arcade."],
  en:["Billy Mitchell was the first to achieve a perfect score in 1999, playing for 6 hours without a single mistake.","Level 256 is a 'kill screen' — a bug that makes the right half of the screen unreadable, ending the game.","Pac-Man's original name was 'Puck-Man' in Japan — Namco changed it in the US to avoid predictable vandalism on arcade cabinets."],
    es:["El ajedrez en línea experimentó un boom sin precedentes tras el éxito de la serie Gambito de Dama (2020): Chess.com duplicó sus usuarios en semanas.","Las plataformas de ajedrez en línea como Chess.com y Lichess cuentan con más de 100 millones de usuarios combinados.","El ajedrez se considera cada vez más un esport: los torneos en línea atraen a cientos de miles de espectadores y los streamers de ajedrez son celebridades en Twitch."]
},
'gam28': {
  fr:["Le jeu contient plus de 500 000 lignes de dialogue — plus que n'importe quel film jamais produit, nécessitant environ 2 200 jours d'enregistrement.","Les testicules des chevaux changent de taille selon la température dans le jeu — un niveau de détail qui a amusé les joueurs et impressionné les critiques.","RDR2 a généré 725 millions de dollars en trois jours — dépassant le record d'Avengers: Endgame au cinéma sur la même période."],
  en:["The game contains over 500,000 lines of dialogue — more than any movie ever produced, requiring about 2,200 days of recording.","Horse testicles change size based on in-game temperature — a level of detail that amused players and impressed critics.","RDR2 generated $725 million in three days — surpassing Avengers: Endgame's cinema record over the same period."],
    es:["Undertale (2015) fue creado casi íntegramente por una sola persona, Toby Fox, y se convirtió en un fenómeno indie con millones de copias vendidas.","El juego subvierte las convenciones del RPG: el jugador puede completar toda la aventura sin matar a ningún enemigo, eligiendo la compasión sobre la violencia.","La banda sonora, compuesta por Fox, es una de las más aclamadas del medio — Megalovania se ha convertido en un himno de la cultura gamer."]
},
'gam29': {
  fr:["Notch (Markus Persson) a inversé la hauteur et la largeur du modèle du cochon — obtenant une forme verticale allongée qu'il a trouvée hilarante.","Il a ensuite ajouté un comportement explosif pour le rendre menaçant — le sifflement distinctif du Creeper est devenu le son le plus reconnaissable de Minecraft.","Le Creeper est devenu la mascotte officieuse de Minecraft — son visage vert pixélisé est l'un des symboles les plus reconnus du jeu vidéo mondial."],
  en:["Notch (Markus Persson) swapped the height and width of the pig model — creating an elongated vertical shape he found hilarious.","He then added explosive behavior to make it threatening — the Creeper's distinctive hiss became Minecraft's most recognizable sound.","The Creeper became Minecraft's unofficial mascot — its pixelated green face is one of the most recognized symbols in global gaming."],
    es:["La realidad virtual en videojuegos despegó con el Oculus Rift (2016) y el PlayStation VR, pero el Meta Quest 2 (2020) democratizó el acceso con un precio asequible.","Half-Life: Alyx (2020) demostró que la VR puede ofrecer experiencias narrativas comparables a los mejores juegos tradicionales — fue aclamado como un hito del medio.","Los desafíos de la VR persisten: náuseas por movimiento, aislamiento social y fatiga visual limitan las sesiones de juego — la tecnología sigue madurando."]
},
'gam30': {
  fr:["Roblox n'est pas un jeu mais une plateforme — les utilisateurs créent eux-mêmes les jeux, et les meilleurs développeurs gagnent des millions de dollars par an.","La monnaie virtuelle Robux a créé une véritable économie — en 2023, Roblox a versé plus de 740 millions de dollars à ses créateurs de contenu.","Plus de la moitié des enfants américains de moins de 16 ans jouent à Roblox — ce qui en fait la plus grande plateforme de divertissement jeunesse au monde."],
  en:["Roblox isn't a game but a platform — users create the games themselves, and top developers earn millions of dollars per year.","The virtual currency Robux created a real economy — in 2023, Roblox paid over $740 million to its content creators.","Over half of American children under 16 play Roblox — making it the world's largest youth entertainment platform."],
    es:["La industria del videojuego genera más ingresos que el cine y la música combinados: más de 180 000 millones de dólares anuales en 2024.","Los juegos móviles representan más del 50 % de los ingresos totales — Candy Crush, Genshin Impact y PUBG Mobile dominan un mercado de 3 000 millones de jugadores.","La IA generativa está transformando el desarrollo de juegos: desde la creación de contenido procedural hasta los NPC con conversaciones naturales — el futuro del medio está en plena mutación."]
},


'cin21': {
  fr:["Kubrick a utilisé un objectif Zeiss Planar 50mm f/0.7, conçu à l'origine pour la NASA pour photographier la face cachée de la Lune.","Seulement dix de ces objectifs ont été fabriqués — Kubrick en a acquis trois et les a adaptés à sa caméra Mitchell BNC.","Les scènes à la bougie donnent au film une qualité picturale unique — chaque plan ressemble à un tableau de la Renaissance flamande."],
  en:["Kubrick used a Zeiss Planar 50mm f/0.7 lens, originally designed for NASA to photograph the far side of the Moon.","Only ten of these lenses were ever made — Kubrick acquired three and adapted them to his Mitchell BNC camera.","The candlelit scenes give the film a unique painterly quality — every shot resembles a Flemish Renaissance painting."],
    es:["El cine coreano experimentó una explosión internacional en los años 2000-2020 con directores como Bong Joon-ho, Park Chan-wook y Lee Chang-dong.","Old Boy (2003) de Park Chan-wook ganó el Gran Premio en Cannes y demostró que el cine coreano podía combinar violencia estilizada con profundidad emocional y filosófica.","El éxito de Parasite y la serie El Juego del Calamar consolidaron la «ola coreana» (hallyu) como fuerza cultural global, junto con el K-pop y los K-dramas."]
},
'cin22': {
  fr:["Le scénariste Herman Mankiewicz a écrit le scénario en s'inspirant de la vie du magnat de la presse William Randolph Hearst — qui a tout fait pour bloquer le film.","Hearst a interdit toute mention de Citizen Kane dans ses journaux et a fait pression sur les cinémas pour qu'ils ne le projettent pas — le film a été un échec commercial initial.","Citizen Kane est régulièrement élu meilleur film de tous les temps par les critiques — malgré un accueil mitigé à sa sortie en 1941."],
  en:["Screenwriter Herman Mankiewicz based the script on press magnate William Randolph Hearst's life — who did everything to block the film.","Hearst banned all mention of Citizen Kane in his newspapers and pressured theaters not to screen it — the film was initially a commercial failure.","Citizen Kane is regularly voted the greatest film ever by critics — despite a mixed reception at its 1941 release."],
    es:["El Padrino (1972) de Francis Ford Coppola es considerada una de las mejores películas jamás filmadas — Paramount quería despedir a Coppola durante el rodaje.","Marlon Brando se metió algodón en las mejillas para darle a Don Corleone su característica mandíbula — una decisión que definió al personaje más icónico de la historia del cine de gángsters.","La trilogía generó más de 900 millones de dólares y estableció el modelo del drama criminal épico que sigue imitándose medio siglo después."]
},
'cin23': {
  fr:["Fincher a déclaré que la présence du gobelet dans chaque scène symbolisait l'omniprésence du consumérisme — même dans un film qui le dénonce.","Le budget initial du film était de 63 millions — mais Starbucks a accepté gracieusement que son gobelet apparaisse, à condition qu'on ne détruise pas un de leurs magasins.","Fight Club a été un échec commercial au cinéma (37 millions pour 63 de budget) — mais est devenu culte en DVD, l'un des plus vendus de tous les temps."],
  en:["Fincher stated that the cup in every scene symbolized consumerism's omnipresence — even in a film denouncing it.","The film's initial budget was $63 million — but Starbucks graciously agreed to their cup appearing, on condition no store was destroyed.","Fight Club was a box office flop ($37M against a $63M budget) — but became a cult classic on DVD, one of the best-selling ever."],
    es:["Los Oscar se entregan desde 1929, cuando la primera ceremonia duró apenas 15 minutos y los ganadores eran conocidos de antemano.","La estatuilla de oro mide 34 cm, pesa 3,9 kg y está hecha de bronce recubierto de oro de 24 quilates — su valor material es de unos 1 000 dólares.","Solo tres películas han ganado los «Big Five» (Película, Director, Actor, Actriz, Guion): Sucedió una noche (1934), Alguien voló sobre el nido del cuco (1975) y El silencio de los corderos (1991)."]
},
'cin24': {
  fr:["La scène se situe à Amon Hen — l'acteur Lurtz (Lawrence Makoare) a lancé un vrai couteau de combat car l'accessoire en caoutchouc avait été égaré.","Viggo a dévié la lame avec son épée dans un réflexe — Peter Jackson a gardé la prise car la réaction de surprise était authentique.","Viggo s'est aussi cassé deux orteils en frappant un casque d'orc dans une autre scène — son cri de douleur est celui qu'on entend dans le film."],
  en:["The scene takes place at Amon Hen — actor Lurtz (Lawrence Makoare) threw a real combat knife because the rubber prop had been misplaced.","Viggo deflected the blade with his sword in a reflex — Peter Jackson kept the take because the surprised reaction was genuine.","Viggo also broke two toes kicking an orc helmet in another scene — his cry of pain is the one heard in the film."],
    es:["La animación japonesa (anime) es una industria de más de 25 000 millones de dólares que abarca todos los géneros y edades, no solo infantil.","Akira (1988) fue la película que introdujo el anime al público occidental con su animación revolucionaria, su violencia y su complejidad narrativa.","Netflix, Crunchyroll y otros servicios de streaming han globalizado el anime: series como Demon Slayer, Jujutsu Kaisen y Attack on Titan rivalizan con las producciones occidentales en audiencia."]
},
'cin25': {
  fr:["Quelqu'un a entré la commande Unix « rm -rf * » sur le serveur principal — le film entier a commencé à disparaître fichier par fichier.","Galyn Susman, directrice technique en congé maternité, avait une copie complète sur son ordinateur personnel à la maison — elle a sauvé le film.","Pixar a ensuite réécrit presque tout le scénario en 9 mois — les premiers résultats étaient si mauvais que Disney menaçait de le sortir directement en vidéo."],
  en:["Someone entered the Unix command 'rm -rf *' on the main server — the entire film started disappearing file by file.","Galyn Susman, technical director on maternity leave, had a complete copy on her home computer — she saved the film.","Pixar then rewrote nearly the entire script in 9 months — early results were so poor that Disney threatened a direct-to-video release."],
    es:["Quentin Tarantino empezó como dependiente de un videoclub — su enciclopédico conocimiento del cine alimenta sus guiones, plagados de referencias y homenajes.","Pulp Fiction (1994) revitalizó la carrera de John Travolta, popularizó la narrativa no lineal y redefinió el diálogo cinematográfico como arte en sí mismo.","Tarantino ha declarado que se retirará tras su décima película — la novena, Érase una vez en Hollywood (2019), fue un homenaje nostálgico al Los Ángeles de 1969."]
},
'cin26': {
  fr:["Le designer sonore Gary Rydstrom a enregistré des sons d'animaux pendant des mois — combinant un bébé éléphant, un alligator, un tigre et même un chiot.","Le son de respiration du T-Rex est en fait de l'air soufflé dans un tuba — ralenti et traité numériquement.","Le tremblement de l'eau dans le verre lors de l'arrivée du T-Rex a été créé en frappant une corde de guitare sous le tableau de bord de la voiture."],
  en:["Sound designer Gary Rydstrom recorded animal sounds for months — combining a baby elephant, alligator, tiger, and even a puppy.","The T-Rex breathing sound is actually air blown through a tuba — slowed down and digitally processed.","The water ripple in the glass during the T-Rex arrival was created by plucking a guitar string under the car's dashboard."],
    es:["Los documentales han evolucionado de formato educativo a género artístico y comercial: películas como Fahrenheit 9/11 y Free Solo han recaudado más de 100 millones.","El documental participativo, donde el cineasta se involucra en la historia (Michael Moore, Werner Herzog), ha difuminado las fronteras entre objetividad y subjetividad.","Las plataformas de streaming han revitalizado el documental: series como Making a Murderer, Tiger King y The Last Dance han alcanzado audiencias masivas."]
},
'cin27': {
  fr:["Hitchcock a déclaré : « Je suis effrayé par les œufs — cette chose ronde blanche sans trous. N'avez-vous jamais vu quelque chose de plus révoltant ? »","Il n'a jamais mangé un œuf de sa vie et refusait même d'en regarder un — les psychologues y voient un lien avec son obsession pour le contrôle.","Hitchcock avait d'autres phobies : il craignait la police à cause d'un traumatisme d'enfance — son père l'avait envoyé au commissariat avec un mot demandant de l'enfermer 10 minutes."],
  en:["Hitchcock declared: 'I'm frightened of eggs — that round white thing with no holes. Have you ever seen anything more revolting?'","He never ate an egg in his life and refused even to look at one — psychologists see a link with his obsession for control.","Hitchcock had other phobias: he feared police due to a childhood trauma — his father sent him to the station with a note asking to lock him up for 10 minutes."],
    es:["El cine de Wes Anderson se distingue por su simetría visual, paletas de colores pastel, planos cenitales y un humor seco e idiosincrásico.","El Gran Hotel Budapest (2014) es su película más exitosa — su estética de «casa de muñecas» ha influido en la fotografía, la moda y el diseño gráfico contemporáneos.","Anderson es uno de los pocos directores cuyo estilo visual es inmediatamente reconocible — una marca artística tan potente que «wesandersoniano» se ha convertido en adjetivo."]
},
'cin28': {
  fr:["Chris Farley a enregistré environ 80 à 90 % du dialogue de Shrek avant de mourir d'une overdose en décembre 1997.","La version de Farley était plus émotionnelle et vulnérable — Mike Myers a redéfini le personnage avec un accent écossais qui n'existait pas dans la version originale.","Des extraits de l'enregistrement de Farley ont fuité en ligne en 2015 — les fans ont pu entendre sa version douce et touchante du personnage."],
  en:["Chris Farley recorded about 80-90% of Shrek's dialogue before dying of an overdose in December 1997.","Farley's version was more emotional and vulnerable — Mike Myers redefined the character with a Scottish accent absent from the original version.","Clips of Farley's recording leaked online in 2015 — fans could hear his gentle, touching version of the character."],
    es:["El cine africano, liderado por Ousmane Sembène (Senegal) y Djibril Diop Mambéty, ha luchado durante décadas contra la falta de financiación y distribución.","Nollywood (Nigeria) ha resuelto el problema con un modelo de bajo coste y alta producción: más de 2 500 películas al año, distribuidas en DVD y streaming.","El Festival de Cine de Cannes ha otorgado la Palma de Oro a películas africanas y árabes, reconociendo voces que durante mucho tiempo fueron ignoradas por la industria occidental."]
},
'cin29': {
  fr:["Bong Joon-ho a déclaré dans son discours de remerciement : « Une fois que vous surmontez la barrière des sous-titres, vous découvrirez tant de films incroyables. »","Le film a rapporté 263 millions de dollars au box-office mondial pour un budget de 11 millions — l'un des meilleurs ratios coût/recettes de l'histoire.","Parasite a remporté quatre Oscars la même nuit : meilleur film, réalisateur, scénario original et film international — un exploit sans précédent."],
  en:["Bong Joon-ho said in his acceptance speech: 'Once you overcome the one-inch barrier of subtitles, you'll discover so many more amazing films.'","The film grossed $263 million worldwide on an $11 million budget — one of the best cost-to-revenue ratios in history.","Parasite won four Oscars in one night: Best Picture, Director, Original Screenplay, and International Film — an unprecedented feat."],
    es:["Christopher Nolan es conocido por películas que desafían la percepción del tiempo: Memento (hacia atrás), Inception (sueños dentro de sueños), Tenet (inversión temporal) e Interstellar (dilatación temporal).","Nolan prefiere los efectos prácticos a los digitales: para Interstellar hizo crecer campos de maíz reales, y para Tenet grabó la explosión de un avión real.","Oppenheimer (2023) le valió su primer Oscar a Mejor Director y recaudó más de 950 millones — demostrando que el cine de autor puede ser también un éxito masivo."]
},
'cin30': {
  fr:["Le bâtiment était un vrai ancien candy factory à Chicago reconverti pour la scène — les explosifs ont été placés par des experts pyrotechniques pendant plusieurs jours.","L'hésitation de Ledger face à la détonation retardée n'était PAS improvisée — le timing avait été planifié, mais l'acteur a joué la confusion de manière si naturelle que la légende persiste.","C'est l'un des derniers rôles de Heath Ledger — il est décédé en janvier 2008, six mois avant la sortie du film, et a reçu un Oscar posthume."],
  en:["The building was a real former candy factory in Chicago converted for the scene — explosives were placed by pyrotechnic experts over several days.","Ledger's hesitation during the delayed detonation was NOT improvised — the timing was planned, but the actor played confusion so naturally the legend persists.","It was one of Heath Ledger's final roles — he died in January 2008, six months before the film's release, and received a posthumous Oscar."],
    es:["El streaming ha transformado la distribución cinematográfica: Netflix, Disney+, Amazon Prime y Apple TV+ producen más contenido original que todos los estudios de Hollywood juntos.","En 2023, el streaming superó por primera vez a la taquilla como principal fuente de ingresos de la industria cinematográfica.","El debate «cine vs streaming» divide a los cineastas: Spielberg y Nolan defienden la experiencia de la sala oscura, mientras que otros celebran la democratización del acceso al cine."]
},

'mus21': {
  fr:["Mozart a écrit au moins six compositions scatologiques — dont « Leck mir den Arsch fein recht schön sauber » pour six voix.","Ses lettres à sa cousine Maria Anna Thekla sont truffées de blagues sur les excréments — les historiens y voient un humour typique de la culture bavaroise du 18ᵉ siècle.","Malgré ces excentricités, Mozart a composé plus de 600 œuvres en seulement 35 ans de vie — soit en moyenne une nouvelle composition tous les 18 jours."],
  en:["Mozart wrote at least six scatological compositions — including 'Leck mir den Arsch fein recht schön sauber' for six voices.","His letters to cousin Maria Anna Thekla are full of excrement jokes — historians see this as typical 18th-century Bavarian humor.","Despite these eccentricities, Mozart composed over 600 works in just 35 years — averaging one new composition every 18 days."],
    es:["David Bowie se reinventó constantemente durante cinco décadas: Ziggy Stardust, Aladdin Sane, el Thin White Duke — cada álbum era un nuevo personaje y un nuevo género.","Su álbum Blackstar, publicado dos días antes de su muerte en 2016, fue un adiós artístico deliberado: sus letras y su estética reflejaban la aceptación de la mortalidad.","Bowie influenció no solo la música sino la moda, el arte, el cine y las actitudes hacia la identidad de género — fue uno de los primeros artistas en desafiar abiertamente las normas binarias."]
},
'mus22': {
  fr:["Les ventes de vinyles ont atteint 43 millions d'unités aux États-Unis en 2023 — contre 37 millions de CD, une inversion historique.","Le vinyle séduit par son rituel : sortir le disque, le poser, baisser le bras — un geste physique qui manque au streaming.","Les usines de pressage sont débordées — les délais de production peuvent atteindre 6 à 12 mois, car la plupart avaient fermé dans les années 2000."],
  en:["Vinyl sales reached 43 million units in the US in 2023 — versus 37 million CDs, a historic reversal.","Vinyl appeals through its ritual: pulling out the record, placing it, lowering the arm — a physical gesture missing from streaming.","Pressing plants are overwhelmed — production times can reach 6 to 12 months, as most had closed in the 2000s."],
    es:["El tango nació en los barrios portuarios de Buenos Aires y Montevideo a finales del siglo XIX, fusionando ritmos africanos, milonga criolla y habanera cubana.","Inicialmente considerado música de los bajos fondos, el tango fue rechazado por la alta sociedad hasta que triunfó en París — solo entonces Buenos Aires lo adoptó como símbolo nacional.","Carlos Gardel, el «zorzal criollo», popularizó el tango a nivel mundial en los años 1920-30 — su muerte en un accidente aéreo en 1935 lo convirtió en leyenda eterna."]
},
'mus23': {
  fr:["La chanson a été écrite en 1893 par les sœurs Patty et Mildred Hill sous le titre « Good Morning to All » — les paroles ont été modifiées plus tard.","Warner/Chappell réclamait des droits de licence pour tout usage commercial — films, publicités et même restaurants devaient payer pour la chanter.","Un procès en 2015 a prouvé que Warner ne possédait pas les droits des paroles — un juge a déclaré la chanson dans le domaine public, remboursant 14 millions de dollars."],
  en:["The song was written in 1893 by sisters Patty and Mildred Hill as 'Good Morning to All' — the lyrics were changed later.","Warner/Chappell demanded license fees for any commercial use — movies, ads, and even restaurants had to pay to sing it.","A 2015 lawsuit proved Warner didn't own the lyrics' rights — a judge declared the song public domain, refunding $14 million."],
    es:["El punk nació en 1976 con los Ramones en Nueva York y los Sex Pistols en Londres — una reacción visceral contra el rock progresivo pretencioso y la conformidad social.","Los Sex Pistols duraron apenas 2 años y medio y grabaron un solo álbum (Never Mind the Bollocks), pero cambiaron la cultura musical, la moda y la actitud de toda una generación.","El punk demostró que cualquiera podía hacer música sin formación técnica: el DIY (hazlo tú mismo) se convirtió en filosofía vital y estética."]
},
'mus24': {
  fr:["La respiration circulaire consiste à souffler l'air stocké dans les joues tout en inspirant par le nez — une technique que les joueurs mettent des mois à maîtriser.","Le didgeridoo est l'un des plus anciens instruments à vent du monde — les Aborigènes d'Australie en jouent depuis au moins 1 500 ans.","Des études médicales ont montré que jouer du didgeridoo réduit les ronflements et l'apnée du sommeil de 65 % — en renforçant les muscles des voies aériennes."],
  en:["Circular breathing involves blowing air stored in the cheeks while inhaling through the nose — a technique that takes players months to master.","The didgeridoo is one of the world's oldest wind instruments — Australian Aboriginals have played it for at least 1,500 years.","Medical studies showed that playing didgeridoo reduces snoring and sleep apnea by 65% — by strengthening airway muscles."],
    es:["Taylor Swift es la artista que más rápido ha generado 1 000 millones de dólares con una sola gira (The Eras Tour, 2023-2024) — la gira más lucrativa de la historia.","Swift regrabó sus primeros álbumes (versiones «Taylor's Version») para recuperar la propiedad de su música — un precedente que empoderó a artistas de toda la industria.","Su influencia trasciende la música: el «efecto Taylor Swift» impacta en las economías locales de las ciudades donde actúa y en la participación electoral de los jóvenes."]
},
'mus25': {
  fr:["Finneas O'Connell a produit l'album entier dans sa chambre de 10 m² avec un micro à 100 dollars et le logiciel Logic Pro.","L'album « When We All Fall Asleep, Where Do We Go? » a débuté numéro 1 dans 17 pays — Billie avait 17 ans à sa sortie.","Billie a remporté cinq Grammy Awards pour cet album en 2020, dont les quatre catégories principales — une première pour une artiste de moins de 20 ans."],
  en:["Finneas O'Connell produced the entire album in his 10 m² bedroom with a $100 microphone and Logic Pro software.","The album 'When We All Fall Asleep, Where Do We Go?' debuted number 1 in 17 countries — Billie was 17 at release.","Billie won five Grammy Awards for this album in 2020, including all four main categories — a first for an artist under 20."],
    es:["Bach compuso más de 1 100 obras, incluyendo cantatas, fugas, conciertos y partitas — una producción monumental que abarca todos los géneros de su época.","Olvidado durante casi un siglo tras su muerte en 1750, Bach fue redescubierto por Mendelssohn en 1829 — hoy es considerado uno de los compositores más importantes de la historia.","La música de Bach tiene una estructura matemática tan perfecta que ha sido enviada al espacio en la sonda Voyager como representación de la inteligencia humana."]
},
'mus26': {
  fr:["Le Grammy de 1990 a été remis à Jethro Tull au lieu de Metallica — un choix si controversé que même Jethro Tull a reconnu que Metallica aurait dû gagner.","Metallica a finalement gagné le Grammy l'année suivante, en 1991, pour « One » — la chanson est devenue un hymne du metal.","Le groupe a vendu plus de 125 millions d'albums dans le monde — « Master of Puppets » est considéré comme l'un des albums les plus influents du métal."],
  en:["The 1990 Grammy was given to Jethro Tull instead of Metallica — a choice so controversial that even Jethro Tull admitted Metallica should have won.","Metallica finally won the Grammy the following year, 1991, for 'One' — the song became a metal anthem.","The band has sold over 125 million albums worldwide — 'Master of Puppets' is considered one of metal's most influential albums."],
    es:["El reggaetón nació en Puerto Rico en los años 1990 como fusión de reggae jamaicano, hip-hop latino y dembow — un ritmo que se hizo global en los 2000.","Daddy Yankee popularizó el género con Gasolina (2004), pero fue Despacito de Luis Fonsi y Daddy Yankee (2017) la que lo convirtió en fenómeno mundial con más de 8 000 millones de vistas.","El reggaetón ha transformado la industria musical global: el español es ahora la segunda lengua del pop mundial, con Bad Bunny como el artista más escuchado del planeta en Spotify."]
},
'mus27': {
  fr:["L'inventeur russe Léon Theremine l'a créé en travaillant sur des capteurs de proximité pour le gouvernement soviétique — le son était un effet secondaire.","Le theremin est utilisé dans des classiques du cinéma (Spellbound d'Hitchcock, The Day the Earth Stood Still) — il incarne le son « extraterrestre » par excellence.","Clara Rockmore, la plus grande théreministe de l'histoire, jouait avec une précision si extraordinaire qu'elle pouvait interpréter des concertos classiques."],
  en:["Russian inventor Leon Theremin created it while working on proximity sensors for the Soviet government — the sound was a side effect.","The theremin is used in cinema classics (Hitchcock's Spellbound, The Day the Earth Stood Still) — it embodies the quintessential 'alien' sound.","Clara Rockmore, history's greatest thereminist, played with such extraordinary precision she could perform classical concertos."],
    es:["Woodstock (1969) reunió a más de 400 000 personas durante tres días en una granja de Nueva York — se convirtió en el símbolo de la contracultura de los años 60.","Jimi Hendrix, Janis Joplin, The Who, Santana y Sly & the Family Stone actuaron ante un público que transformó un festival caótico en un momento de paz y comunidad.","Woodstock fue un desastre logístico: las carreteras colapsaron, la comida y el agua escasearon, y la lluvia convirtió los campos en barrizales — pero la música y el espíritu colectivo lo redimieron todo."]
},
'mus28': {
  fr:["Marley a été enterré dans un mausolée à Nine Mile, en Jamaïque, son village natal — le site est devenu un lieu de pèlerinage musical mondial.","Sa guitare Gibson Les Paul, un ballon de foot (sa passion), une bague offerte par le prince éthiopien Asfa Wossen et une branche de ganja l'accompagnent.","Marley est mort à 36 ans d'un mélanome sous l'ongle du pied — il avait refusé l'amputation pour des raisons religieuses rastafari."],
  en:["Marley was buried in a mausoleum in Nine Mile, Jamaica, his hometown — the site has become a global musical pilgrimage destination.","His Gibson Les Paul guitar, a soccer ball (his passion), a ring given by Ethiopian prince Asfa Wossen, and a branch of ganja accompany him.","Marley died at 36 from melanoma under his toenail — he refused amputation for Rastafari religious reasons."],
    es:["Adele vendió más de 120 millones de discos con una fórmula aparentemente simple: una voz extraordinaria, letras emocionales sobre el desamor y arreglos minimalistas.","Su álbum 21 (2011) es uno de los más vendidos del siglo XXI con más de 31 millones de copias — dominó las listas durante meses en decenas de países.","Adele es una de las pocas artistas que pueden vender millones de álbumes físicos en la era del streaming — una anomalía que demuestra el poder de la conexión emocional."]
},
'mus29': {
  fr:["Scott de Martinville a enregistré le son avec son phonautographe en traçant les ondes sur du papier noirci à la fumée — mais il n'avait aucun moyen de le réécouter.","Ce n'est qu'en 2008 que des chercheurs ont réussi à « relire » l'enregistrement par numérisation — on y entend une voix humaine chantant « Au clair de la lune ».","Edison n'a breveté son phonographe qu'en 1877, soit 17 ans plus tard — mais c'est lui qui a inventé la lecture du son, pas seulement son enregistrement."],
  en:["Scott de Martinville recorded sound with his phonautograph by tracing waves on smoke-blackened paper — but had no way to play it back.","Only in 2008 did researchers manage to 'read' the recording through digitization — a human voice singing 'Au clair de la lune' can be heard.","Edison didn't patent his phonograph until 1877, 17 years later — but he invented sound playback, not just recording."],
    es:["La cumbia nació en Colombia como fusión de ritmos africanos, indígenas y europeos, y se ha expandido por toda Latinoamérica con variantes locales en cada país.","La cumbia argentina, la cumbia villera, la cumbia sonidera mexicana y la chicha peruana son adaptaciones regionales que reflejan las realidades sociales de cada contexto.","La cumbia digital, fusionada con electrónica, ha encontrado un público global en el siglo XXI — festivales de todo el mundo programan artistas de cumbia junto a DJs de techno y house."]
},
'mus30': {
  fr:["Le fameux « BWAAAA » d'Inception est en fait la chanson « Non, je ne regrette rien » d'Édith Piaf, ralentie et distordue numériquement.","Zimmer compose sur un clavier MIDI connecté à des centaines de samples — il peut simuler un orchestre entier depuis son studio à Santa Monica.","Il a remporté un Oscar pour la musique du Roi Lion en 1995 — mais a confié qu'il ne sait pas lire une partition classique et travaille uniquement à l'oreille."],
  en:["The famous Inception 'BWAAAA' is actually Édith Piaf's song 'Non, je ne regrette rien,' slowed down and digitally distorted.","Zimmer composes on a MIDI keyboard connected to hundreds of samples — he can simulate an entire orchestra from his Santa Monica studio.","He won an Oscar for The Lion King score in 1995 — but confessed he can't read classical notation and works entirely by ear."],
    es:["La inteligencia artificial puede ahora componer música en cualquier estilo: herramientas como Suno, Udio y MusicLM generan canciones completas a partir de una descripción textual.","El debate sobre la IA en la música es intenso: ¿es creación o plagio algorítmico? ¿Puede una máquina expresar emociones que no siente?","Algunos artistas usan la IA como herramienta creativa (Brian Eno, Holly Herndon) mientras que otros la rechazan — la industria musical enfrenta su mayor transformación desde la invención del fonógrafo."]
},


'w21': {
  fr:["La Russie s'étend sur 11 fuseaux horaires — quand il est midi à Kaliningrad (frontière finlandaise), il est 22h à Vladivostok (près de la Corée du Nord).","La frontière entre la Russie et la Corée du Nord ne fait que 17 km de long — l'un des tronçons frontaliers les plus courts et les plus surveillés au monde.","D'autres pays sont aussi reliés de manière surprenante : la France et le Brésil partagent une frontière terrestre grâce à la Guyane française."],
  en:["Russia spans 11 time zones — when it's noon in Kaliningrad (Finnish border), it's 10 PM in Vladivostok (near North Korea).","The Russia-North Korea border is only 17 km long — one of the shortest and most heavily guarded border segments in the world.","Other countries are also surprisingly connected: France and Brazil share a land border thanks to French Guiana."],
    es:["Los Países Bajos deben su nombre al hecho de que un tercio del país se encuentra por debajo del nivel del mar, protegido por un sofisticado sistema de diques y pólderes.","El Plan Delta, construido tras la catastrófica inundación de 1953 que mató a 1 836 personas, es una de las mayores obras de ingeniería hidráulica de la historia.","Sin los diques y sistemas de bombeo, ciudades como Ámsterdam, Róterdam y La Haya estarían bajo agua — los holandeses llevan más de 800 años luchando contra el mar."]
},
'w22': {
  fr:["En 2023, le Japon a officiellement « découvert » 7 000 îles supplémentaires après une analyse satellite plus précise — doublant presque le chiffre officiel.","L'île d'Aogashima est un volcan habité par 170 personnes — accessible uniquement par hélicoptère ou bateau quand la météo le permet.","Hashima (Gunkanjima), île abandonnée au large de Nagasaki, était la zone la plus densément peuplée de l'histoire — 83 500 habitants/km² en 1959."],
  en:["In 2023, Japan officially 'discovered' 7,000 additional islands after more precise satellite analysis — nearly doubling the official count.","Aogashima island is a volcano inhabited by 170 people — accessible only by helicopter or boat when weather permits.","Hashima (Gunkanjima), an abandoned island off Nagasaki, was the most densely populated area in history — 83,500 people/km² in 1959."],
    es:["Indonesia es el mayor archipiélago del mundo: más de 17 000 islas repartidas en 5 100 km de longitud, con más de 270 millones de habitantes.","Alberga la mayor biodiversidad marina del planeta y bosques tropicales que son el último refugio del orangután, el rinoceronte de Java y el dragón de Komodo.","Indonesia tiene más volcanes activos que cualquier otro país (130) y se encuentra en el Cinturón de Fuego del Pacífico, una de las zonas sísmicas más activas del mundo."]
},
'w23': {
  fr:["Le Begich Towers, un ancien bâtiment militaire de 14 étages, abrite presque toute la communauté — appartements, mairie, bureau de poste et épicerie.","Les résidents accèdent à Whittier par un tunnel d'une seule voie de 4 km, le Anton Anderson Memorial Tunnel — partagé avec le train, il est ouvert seulement à certaines heures.","En hiver, les températures descendent à −20 °C avec des vents de 100 km/h — vivre dans un seul bâtiment n'est pas un choix mais une nécessité."],
  en:["Begich Towers, a former 14-story military building, houses nearly the entire community — apartments, city hall, post office, and grocery store.","Residents access Whittier through a single-lane 4 km tunnel, the Anton Anderson Memorial Tunnel — shared with the train, open only at certain hours.","In winter, temperatures drop to −20°C with 100 km/h winds — living in one building isn't a choice but a necessity."],
    es:["Groenlandia, la isla más grande del mundo (2,16 millones de km²), está cubierta en un 80 % por un casquete de hielo de hasta 3 km de espesor.","A pesar de su tamaño, su población es de apenas 56 000 personas — la mayor parte concentrada en la costa occidental, libre de hielo.","El nombre «Groenlandia» (Tierra Verde) fue acuñado por Erik el Rojo hacia el 985 d.C., probablemente como estrategia de marketing para atraer colonos vikingos."]
},
'w24': {
  fr:["Les pyramides nubiennes de Méroé, construites entre 700 av. J.-C. et 300 apr. J.-C., sont plus petites et plus pointues que celles d'Égypte.","Un explorateur italien, Giuseppe Ferlini, a détruit les sommets de plus de 40 pyramides en 1834 pour chercher des trésors — un acte de vandalisme irréparable.","Le site de Méroé est classé au patrimoine mondial de l'UNESCO depuis 2011 — mais reçoit moins de 15 000 visiteurs par an, contre 14 millions pour les pyramides de Gizeh."],
  en:["The Nubian pyramids of Meroe, built between 700 BC and 300 AD, are smaller and more pointed than Egypt's.","Italian explorer Giuseppe Ferlini destroyed the tops of over 40 pyramids in 1834 searching for treasure — an irreparable act of vandalism.","The Meroe site has been a UNESCO World Heritage site since 2011 — but receives fewer than 15,000 visitors yearly, versus 14 million for Giza."],
    es:["Madagascar se separó de África hace unos 160 millones de años y de la India hace 88 millones, lo que explica su biodiversidad única.","El 90 % de sus especies animales y vegetales no se encuentran en ningún otro lugar del planeta — incluidos los lémures, los camaleones y los baobabs.","La deforestación ha destruido el 90 % de los bosques originales de Madagascar, amenazando un ecosistema irreemplazable — es una de las prioridades de conservación más urgentes del mundo."]
},
'w25': {
  fr:["Le Vatican a environ 800 résidents et 600 citoyens — mais seulement environ 30 sont des femmes, et aucune n'a la citoyenneté de naissance.","La garde suisse pontificale, créée en 1506, est la plus petite et la plus ancienne armée du monde — ses 135 soldats doivent être suisses, catholiques et célibataires.","Le Vatican possède un observatoire astronomique à Castel Gandolfo — l'Église catholique a été un acteur majeur de l'astronomie depuis Copernic."],
  en:["The Vatican has about 800 residents and 600 citizens — but only about 30 are women, and none hold citizenship by birth.","The Pontifical Swiss Guard, created in 1506, is the world's smallest and oldest army — its 135 soldiers must be Swiss, Catholic, and single.","The Vatican has an astronomical observatory at Castel Gandolfo — the Catholic Church has been a major player in astronomy since Copernicus."],
    es:["Chile es el país más largo y estrecho del mundo: 4 300 km de norte a sur pero solo 177 km de ancho de media.","Su geografía extrema incluye el desierto más árido del mundo (Atacama), glaciares patagónicos, la cordillera de los Andes y la Isla de Pascua a 3 700 km de la costa.","El desierto de Atacama es tan seco y estéril que la NASA lo utiliza como análogo de Marte para probar rovers y equipos de exploración."]
},
'w26': {
  fr:["Le lac Baïkal est aussi le lac le plus ancien du monde — environ 25 millions d'années — et abrite 2 500 espèces uniques, dont le phoque d'eau douce nerpa.","En hiver, la glace du Baïkal est si transparente qu'on peut voir à travers jusqu'à 40 mètres de profondeur — un phénomène appelé « glace bleue ».","Si le lac était vidé, il faudrait la totalité des rivières du monde coulant ensemble pendant un an pour le remplir de nouveau."],
  en:["Lake Baikal is also the world's oldest lake — about 25 million years old — and home to 2,500 unique species, including the freshwater nerpa seal.","In winter, Baikal's ice is so transparent you can see through it to 40 meters deep — a phenomenon called 'blue ice'.","If the lake were emptied, it would take all the world's rivers flowing together for one year to refill it."],
    es:["Nueva Zelanda fue el último gran territorio habitable en ser colonizado por humanos: los polinesios (maoríes) llegaron entre los siglos XIII y XIV.","Su aislamiento de 85 millones de años dio lugar a especies únicas como el kiwi, el tuátara (un reptil de la era de los dinosaurios) y el kakapo (el único loro no volador del mundo).","Nueva Zelanda fue el primer país del mundo en conceder el voto a las mujeres en 1893, 27 años antes que Estados Unidos."]
},
'w27': {
  fr:["Le calendrier éthiopien est basé sur le calendrier copte, avec 12 mois de 30 jours et un 13ᵉ mois (Pagumē) de 5 ou 6 jours.","L'Éthiopie a célébré le nouveau millénaire le 12 septembre 2007 (calendrier grégorien) — avec 7 ans de retard dû à un calcul différent de la naissance du Christ.","L'heure éthiopienne est aussi différente : le jour commence à 6h du matin (heure 0) — quand il est « 2 heures » en Éthiopie, il est 8h du matin ailleurs."],
  en:["The Ethiopian calendar is based on the Coptic calendar, with 12 months of 30 days and a 13th month (Pagumē) of 5 or 6 days.","Ethiopia celebrated the new millennium on September 12, 2007 (Gregorian calendar) — 7 years late due to a different calculation of Christ's birth.","Ethiopian time is also different: the day starts at 6 AM (hour 0) — when it's '2 o'clock' in Ethiopia, it's 8 AM elsewhere."],
    es:["Nigeria es el país más poblado de África con más de 220 millones de habitantes y se prevé que supere a Estados Unidos antes de 2050.","Con más de 500 lenguas habladas, Nigeria es uno de los países lingüísticamente más diversos del mundo — el inglés es la lengua oficial pero el pidgin es la lingua franca popular.","Nollywood, la industria cinematográfica nigeriana, produce más películas al año que Hollywood y es la segunda del mundo por volumen, tras Bollywood."]
},
'w28': {
  fr:["Hell signifie « chance » ou « bonheur » en vieux norrois — le nom n'a rien de diabolique, mais les touristes adorent se photographier devant le panneau de la gare.","La gare de Hell est un vrai arrêt ferroviaire actif — les habitants ont un sens de l'humour assumé avec des panneaux comme « Hell Goods Expedition ».","D'autres lieux aux noms amusants : « Fucking » en Autriche (renommé « Fugging » en 2021 après le vol constant des panneaux), et « Batman » en Turquie."],
  en:["Hell means 'luck' or 'happiness' in Old Norse — the name has nothing diabolical, but tourists love posing for photos at the train station sign.","Hell station is a real active railway stop — residents have embraced the humor with signs like 'Hell Goods Expedition'.","Other amusingly named places: 'Fucking' in Austria (renamed 'Fugging' in 2021 after constant sign theft), and 'Batman' in Turkey."],
    es:["Islandia obtiene prácticamente el 100 % de su electricidad de fuentes renovables: geotermia (65 %) e hidroeléctrica (35 %).","La isla se encuentra sobre la dorsal mesoatlántica, donde las placas tectónicas norteamericana y euroasiática se separan, generando una intensa actividad geotérmica y volcánica.","Los islandeses calientan sus casas, piscinas e incluso aceras con agua geotérmica bombeada directamente del subsuelo — un sistema limpio y casi gratuito."]
},
'w29': {
  fr:["Le point le plus élevé des Pays-Bas « européens » est le Vaalserberg à 322 m — mais le point le plus élevé du Royaume est le mont Scenery (887 m) sur l'île de Saba aux Caraïbes.","Un tiers du pays se trouve sous le niveau de la mer — protégé par un système de digues de 3 500 km, le plus sophistiqué au monde.","Le projet Delta Works, construit après l'inondation catastrophique de 1953 qui tua 1 836 personnes, est considéré comme l'une des sept merveilles du monde moderne."],
  en:["The highest point in 'European' Netherlands is the Vaalserberg at 322 m — but the Kingdom's highest point is Mount Scenery (887 m) on the Caribbean island of Saba.","One-third of the country lies below sea level — protected by a 3,500 km dike system, the most sophisticated in the world.","The Delta Works project, built after the catastrophic 1953 flood that killed 1,836 people, is considered one of the seven modern wonders of the world."],
    es:["Singapur es una ciudad-Estado de apenas 733 km² con 5,9 millones de habitantes, una de las densidades de población más altas del mundo.","A pesar de su tamaño, Singapur es la cuarta plaza financiera mundial y tiene uno de los PIB per cápita más altos del planeta.","La isla ha aumentado su superficie un 25 % desde la independencia en 1965 mediante la construcción de terrenos ganados al mar con arena importada de países vecinos."]
},
'w30': {
  fr:["Le Bonheur National Brut (BNB) mesure neuf domaines : bien-être psychologique, santé, éducation, culture, gouvernance, écologie, vitalité communautaire, usage du temps et niveau de vie.","Le Bhoutan est le seul pays au monde à avoir un bilan carbone négatif — ses forêts absorbent plus de CO₂ que le pays n'en produit.","La télévision n'a été autorisée au Bhoutan qu'en 1999 — le roi craignait que les médias occidentaux ne perturbent la culture traditionnelle."],
  en:["Gross National Happiness (GNH) measures nine domains: psychological well-being, health, education, culture, governance, ecology, community vitality, time use, and living standards.","Bhutan is the world's only carbon-negative country — its forests absorb more CO₂ than the country produces.","Television wasn't allowed in Bhutan until 1999 — the king feared Western media would disrupt traditional culture."],
    es:["Egipto no es solo pirámides y desierto: el 95 % de su población vive a lo largo del valle y el delta del Nilo, una estrecha franja de tierra fértil.","El Nilo, con 6 650 km, disputa al Amazonas el título de río más largo del mundo — la medición depende de dónde se sitúe exactamente la fuente de cada río.","La presa de Asuán, terminada en 1970, controla las inundaciones del Nilo y genera electricidad, pero también atrapó el limo fértil que alimentaba la agricultura egipcia desde la Antigüedad."]
},

'myth21': {
  fr:["Orphée a endormi Cerbère en jouant de la lyre pour descendre aux Enfers chercher Eurydice — c'est la seule entrée « pacifique » connue dans le royaume d'Hadès.","Héraclès, lors de son douzième travail, a capturé Cerbère à mains nues — le ramenant vivant à la surface avant de le rendre à Hadès.","Le nom « Cerbère » pourrait venir du grec « Kerberos », signifiant « démon de la fosse » — mais certains linguistes le relient au sanskrit « Śarvara » (tacheté)."],
  en:["Orpheus put Cerberus to sleep by playing the lyre to descend to the Underworld for Eurydice — the only known 'peaceful' entry into Hades' realm.","Heracles, during his twelfth labor, captured Cerberus bare-handed — bringing him alive to the surface before returning him to Hades.","The name 'Cerberus' may come from Greek 'Kerberos,' meaning 'demon of the pit' — but some linguists link it to Sanskrit 'Śarvara' (spotted)."],
    es:["Medusa, una de las tres Gorgonas, tenía serpientes por cabellos y convertía en piedra a quien la mirara — fue decapitada por Perseo con ayuda de Atenea.","En versiones más antiguas, Medusa era un monstruo de nacimiento, pero Ovidio la convirtió en una bella sacerdotisa castigada por Atenea tras ser violada por Poseidón en su templo.","La cabeza de Medusa, incluso decapitada, conservaba su poder petrificante — Perseo la usó como arma y después la entregó a Atenea, que la montó en su escudo (la égida)."]
},
'myth22': {
  fr:["Nout est représentée comme une femme géante arquée au-dessus de la Terre (son frère Geb) — son corps étoilé forme la voûte céleste.","Chaque soir, le dieu Rê entre dans la bouche de Nout, traverse son corps pendant 12 heures et renaît à l'aube entre ses jambes.","Les sarcophages égyptiens étaient souvent peints avec Nout à l'intérieur du couvercle — protégeant le défunt comme elle protège le Soleil chaque nuit."],
  en:["Nut is depicted as a giant woman arched over the Earth (her brother Geb) — her star-covered body forms the celestial vault.","Each evening, the god Ra enters Nut's mouth, travels through her body for 12 hours, and is reborn at dawn between her legs.","Egyptian sarcophagi were often painted with Nut inside the lid — protecting the deceased as she protects the Sun each night."],
    es:["Los kami japoneses no son exactamente dioses sino espíritus o fuerzas divinas que habitan en la naturaleza: rocas, árboles, ríos, montañas y fenómenos naturales.","El sintoísmo reconoce yaoyorozu no kami (ocho millones de kami), una expresión que significa literalmente «una infinidad» de espíritus sagrados.","Los torii, las puertas rojas de los santuarios sintoístas, marcan la transición entre el mundo profano y el sagrado — el más famoso es el de Itsukushima, que parece flotar sobre el mar."]
},
'myth23': {
  fr:["Pendant le Ragnarök, le loup Fenrir avale Odin, le serpent Jörmungandr empoisonne Thor, et le feu de Surt consume les neuf mondes.","Deux humains, Líf et Lífþrasir, survivent en se cachant dans le bois d'Yggdrasil — ils repeupleront le monde nouveau.","Le Ragnarök n'est pas une punition mais un cycle cosmique — la mythologie nordique voyait le temps comme circulaire, pas linéaire."],
  en:["During Ragnarök, the wolf Fenrir swallows Odin, the serpent Jörmungandr poisons Thor, and Surt's fire consumes the nine worlds.","Two humans, Líf and Lífþrasir, survive by hiding in Yggdrasil's wood — they will repopulate the new world.","Ragnarök isn't punishment but a cosmic cycle — Norse mythology saw time as circular, not linear."],
    es:["Anansi, la araña embaucadora de la mitología ashanti (Ghana), es uno de los personajes más importantes del folclore africano y caribeño.","Anansi usa su astucia para vencer a enemigos más fuertes: engaña al leopardo, la serpiente pitón y al avispero, demostrando que la inteligencia supera a la fuerza bruta.","Los esclavos africanos llevaron las historias de Anansi al Caribe y América, donde evolucionaron en los cuentos de Brer Rabbit y otras tradiciones orales afroamericanas."]
},
'myth24': {
  fr:["Hermès est né dans une grotte en Arcadie à l'aube — à midi, il avait inventé la lyre à partir d'une carapace de tortue, et au soir, il volait les vaches d'Apollon.","Pour cacher le vol, il a fait marcher les vaches à reculons — laissant des traces qui semblaient aller dans la direction opposée.","Apollon, furieux, l'a traîné devant Zeus — mais Zeus a tellement ri de l'audace du bébé qu'il en a fait le dieu des voleurs et des messagers."],
  en:["Hermes was born in a cave in Arcadia at dawn — by noon he'd invented the lyre from a tortoise shell, and by evening he was stealing Apollo's cattle.","To hide the theft, he made the cattle walk backward — leaving tracks that seemed to go in the opposite direction.","Apollo, furious, dragged him before Zeus — but Zeus laughed so hard at the baby's audacity he made him god of thieves and messengers."],
    es:["El Mahabharata, la epopeya hindú más larga del mundo (100 000 estrofas), narra la guerra entre dos familias primas: los Pandavas y los Kauravas.","El Bhagavad Gita, insertado en el Mahabharata, es un diálogo filosófico entre el príncipe Arjuna y el dios Krishna sobre el deber, la acción y la naturaleza del ser.","El Mahabharata contiene toda la sabiduría de la India antigua: derecho, filosofía, mitología, astronomía y ética — se dice que «lo que no está en el Mahabharata no existe»."]
},
'myth25': {
  fr:["Selon la légende maorie, Maui a pêché l'île du Nord de la Nouvelle-Zélande (Te Ika-a-Māui, « le poisson de Maui ») avec un hameçon fait de la mâchoire de sa grand-mère.","L'île du Sud serait le canot (Te Waka a Māui) depuis lequel il a pêché — et l'île Stewart serait l'ancre du canot.","Maui est aussi celui qui a ralenti le Soleil en le battant avec une corde — pour donner aux humains des journées plus longues pour travailler."],
  en:["In Maori legend, Maui fished up the North Island of New Zealand (Te Ika-a-Māui, 'Maui's fish') with a hook made from his grandmother's jawbone.","The South Island is said to be the canoe (Te Waka a Māui) from which he fished — and Stewart Island is the canoe's anchor.","Maui also slowed the Sun by beating it with a rope — to give humans longer days to work."],
    es:["El hombre lobo (licántropo) aparece en mitologías de todo el mundo: el rey Licaón fue transformado en lobo por Zeus, y las sagas nórdicas mencionan guerreros úlfhednar que combatían vestidos de pieles de lobo.","En la Europa medieval, los juicios por licantropía eran reales: más de 30 000 casos documentados entre los siglos XV y XVIII — muchos acusados sufrían probablemente porfiria o hipertricosis.","La asociación del hombre lobo con la luna llena es una invención cinematográfica del siglo XX — las fuentes antiguas no mencionan esta conexión."]
},
'myth26': {
  fr:["Le Minotaure était enfermé dans le Labyrinthe de Cnossos, construit par l'architecte Dédale sur ordre du roi Minos de Crète.","Thésée a tué le Minotaure grâce au fil d'Ariane — elle lui a donné une bobine de fil pour retrouver son chemin dans le labyrinthe.","Le Minotaure était le fils de Pasiphaé (épouse de Minos) et d'un taureau envoyé par Poséidon — une punition divine contre Minos qui avait refusé de sacrifier l'animal."],
  en:["The Minotaur was imprisoned in the Labyrinth of Knossos, built by architect Daedalus on orders from King Minos of Crete.","Theseus killed the Minotaur thanks to Ariadne's thread — she gave him a ball of thread to find his way back through the labyrinth.","The Minotaur was the son of Pasiphaë (Minos's wife) and a bull sent by Poseidon — divine punishment against Minos for refusing to sacrifice the animal."],
    es:["Afrodita, diosa griega del amor y la belleza, nació de la espuma del mar (aphros) formada cuando los genitales de Urano, cortados por Crono, cayeron al agua.","Su cinturón mágico (cestus) hacía irresistible a quien lo portara — incluso Hera se lo pidió prestado para seducir a Zeus.","Afrodita estaba casada con Hefesto, el dios herrero y más feo del Olimpo, pero mantuvo numerosos amantes, incluido Ares, el dios de la guerra — una unión del amor y la violencia."]
},
'myth27': {
  fr:["Dédale avait construit les ailes en collant des plumes avec de la cire d'abeille — il avait prévenu Icare de ne voler ni trop haut (soleil) ni trop bas (embruns).","On oublie souvent que Dédale a réussi son vol — il a atterri en Sicile et a vécu le reste de sa vie en sécurité, accueilli par le roi Cocalos.","Le mythe d'Icare est souvent interprété comme un avertissement contre l'orgueil (hubris) — mais il parle aussi de la douleur d'un père qui a perdu son fils."],
  en:["Daedalus built the wings by gluing feathers with beeswax — he warned Icarus not to fly too high (sun) or too low (sea spray).","Often forgotten is that Daedalus succeeded in his flight — he landed in Sicily and lived safely for the rest of his life, welcomed by King Cocalos.","The Icarus myth is often interpreted as a warning against pride (hubris) — but it's also about a father's grief for his lost son."],
    es:["Coyote es el embaucador (trickster) de las mitologías de los pueblos nativos de América del Norte — creador, destructor y bufón en partes iguales.","En algunas tradiciones, Coyote roba el fuego para la humanidad (como Prometeo); en otras, crea accidentalmente la muerte al intentar hacer inmortales a los humanos.","El trickster no es bueno ni malo: representa el caos creativo necesario para que el mundo evolucione — una figura universal presente en casi todas las culturas."]
},
'myth28': {
  fr:["Kali est née de la colère de la déesse Durga lors d'un combat contre le démon Raktabija — chaque goutte de sang du démon créait un clone, alors Kali les a tous bus.","Sa langue tirée, son image la plus iconique, symbolise la honte qu'elle ressent après avoir marché sur Shiva par accident dans sa danse de destruction.","Malgré son apparence terrifiante, Kali est vénérée comme une mère protectrice — elle détruit l'ego et l'ignorance pour permettre la renaissance spirituelle."],
  en:["Kali was born from goddess Durga's fury during battle against demon Raktabija — each drop of the demon's blood created a clone, so Kali drank them all.","Her iconic stuck-out tongue symbolizes the shame she felt after accidentally stepping on Shiva during her dance of destruction.","Despite her terrifying appearance, Kali is worshipped as a protective mother — she destroys ego and ignorance to enable spiritual rebirth."],
    es:["Las Moiras griegas (Parcas romanas) eran tres hermanas que controlaban el destino de todos los mortales: Cloto hilaba el hilo de la vida, Láquesis medía su longitud y Átropos lo cortaba.","Ni siquiera Zeus podía alterar las decisiones de las Moiras — el destino era la fuerza suprema del universo griego, superior a los propios dioses.","La idea de tres diosas del destino es sorprendentemente universal: las Nornas nórdicas (Urd, Verdandi, Skuld) cumplen funciones casi idénticas en la mitología germánica."]
},
'myth29': {
  fr:["Le mot « Valkyrie » signifie « celle qui choisit les tués » (du vieux norrois « valr » = morts au combat, « kjósa » = choisir).","Les guerriers choisis par les Valkyries festoyaient au Valhalla chaque nuit — puis se battaient entre eux chaque jour, ressuscitant pour le banquet suivant.","Les Valkyries servaient aussi l'hydromel au Valhalla — un mélange de guerrières divines et de servantes, un double rôle typique de la mythologie nordique."],
  en:["The word 'Valkyrie' means 'chooser of the slain' (from Old Norse 'valr' = battlefield dead, 'kjósa' = to choose).","Warriors chosen by Valkyries feasted in Valhalla every night — then fought each other every day, resurrecting for the next banquet.","Valkyries also served mead in Valhalla — a blend of divine warriors and servants, a dual role typical of Norse mythology."],
    es:["El Golem de Praga, según la leyenda, fue creado en el siglo XVI por el rabino Löw a partir de arcilla del río Moldava para proteger a los judíos de la persecución.","El Golem cobraba vida al inscribir la palabra emet (verdad) en su frente — para desactivarlo, bastaba borrar una letra, dejando met (muerte).","La leyenda del Golem es considerada precursora de los relatos de inteligencia artificial: una creación que sirve a su creador hasta que escapa a su control."]
},
'myth30': {
  fr:["Le Phénix égyptien (Bennu) était un héron lié au dieu Rê et au cycle des crues du Nil — il renaissait tous les 500 ans.","Le Phénix chinois (Fenghuang) n'a rien à voir avec le feu — c'est un oiseau de bon augure qui apparaît en temps de paix et de prospérité.","Le Phénix grec, décrit par Hérodote, se consumait sur un bûcher d'encens et de myrrhe — le jeune Phénix emportait les cendres de son père au temple du Soleil à Héliopolis."],
  en:["The Egyptian Phoenix (Bennu) was a heron linked to the god Ra and the Nile flood cycle — it was reborn every 500 years.","The Chinese Phoenix (Fenghuang) has nothing to do with fire — it's an auspicious bird appearing in times of peace and prosperity.","The Greek Phoenix, described by Herodotus, consumed itself on a pyre of incense and myrrh — the young Phoenix carried its father's ashes to the Temple of the Sun in Heliopolis."],
    es:["Los mitos de creación del mundo varían enormemente: desde un huevo cósmico (China, Finlandia) hasta un océano primordial (Egipto, India) o un vacío primigenio (nórdico, griego).","El Enuma Elish babilónico narra cómo Marduk crea el mundo a partir del cuerpo de la diosa Tiamat — un combate cósmico que refleja la lucha del orden contra el caos.","Todas las culturas necesitan un relato de origen: los mitos de creación no son explicaciones científicas sino respuestas existenciales a las preguntas «¿de dónde venimos?» y «¿por qué existimos?»."]
},


'psy21': {
  fr:["Le biais de confirmation a été démontré par Peter Wason en 1960 avec son test « 2-4-6 » — les participants cherchaient à confirmer leur hypothèse plutôt qu'à la réfuter.","Ce biais est amplifié par les algorithmes des réseaux sociaux — ils montrent du contenu similaire à ce qu'on a déjà aimé, créant des « bulles de filtre ».","Les scientifiques luttent contre ce biais en utilisant la méthode de « falsification » de Karl Popper — chercher à prouver qu'on a tort plutôt qu'on a raison."],
  en:["Confirmation bias was demonstrated by Peter Wason in 1960 with his '2-4-6 task' — participants tried to confirm their hypothesis rather than disprove it.","This bias is amplified by social media algorithms — they show content similar to what you've already liked, creating 'filter bubbles'.","Scientists fight this bias using Karl Popper's 'falsification' method — trying to prove yourself wrong rather than right."],
    es:["El flow, descrito por Mihaly Csikszentmihalyi, es un estado de concentración total en el que la persona pierde la noción del tiempo y experimenta una satisfacción profunda.","El flow ocurre cuando el nivel de dificultad de una tarea coincide con el nivel de habilidad de la persona — demasiado fácil produce aburrimiento, demasiado difícil produce ansiedad.","Músicos, atletas, programadores y artistas describen experiencias de flow similares — un estado universal que Csikszentmihalyi vinculó directamente con la felicidad."]
},
'psy22': {
  fr:["Gilbert et Wilson ont montré que les gens surestiment l'impact émotionnel d'événements futurs — positifs comme négatifs — de 50 à 100 % en durée.","Les loteries gagnées et les accidents graves n'affectent le bonheur que pendant 3 à 6 mois — après quoi les gens reviennent à leur niveau de base.","Ce phénomène s'appelle l'adaptation hédonique — le cerveau a un « thermostat émotionnel » qui le ramène toujours vers un état moyen."],
  en:["Gilbert and Wilson showed that people overestimate the emotional impact of future events — both positive and negative — by 50 to 100% in duration.","Lottery wins and severe accidents only affect happiness for 3 to 6 months — after which people return to their baseline level.","This phenomenon is called hedonic adaptation — the brain has an 'emotional thermostat' that always returns it to an average state."],
    es:["El experimento de la prisión de Stanford (1971) de Philip Zimbardo dividió a estudiantes en «guardias» y «prisioneros» — en días, los guardias se volvieron sádicos y los prisioneros sumisos.","El experimento fue cancelado tras seis días (de los 14 previstos) cuando los abusos se volvieron extremos — demostró el poder de los roles sociales sobre el comportamiento individual.","Sin embargo, investigaciones recientes cuestionan la validez del estudio: Zimbardo instruyó activamente a los guardias para que fueran duros, lo que sesga los resultados."]
},
'psy23': {
  fr:["L'hypothèse a été testée par Fritz Strack en 1988 — les participants qui tenaient un stylo entre les dents (forçant un sourire) trouvaient les dessins plus drôles.","Des études récentes ont nuancé ces résultats — l'effet existe mais est plus faible que prévu, et dépend du contexte et de la conscience du participant.","Le botox offre une preuve indirecte : les personnes qui ne peuvent plus froncer les sourcils rapportent moins de sentiments de colère et de tristesse."],
  en:["The hypothesis was tested by Fritz Strack in 1988 — participants holding a pen between their teeth (forcing a smile) found cartoons funnier.","Recent studies have nuanced these results — the effect exists but is weaker than expected, depending on context and participant awareness.","Botox offers indirect evidence: people who can no longer frown report fewer feelings of anger and sadness."],
    es:["Los introvertidos no son tímidos ni antisociales: simplemente recobran energía en soledad, mientras que los extrovertidos la obtienen de la interacción social.","Carl Jung introdujo la distinción introversión/extroversión en 1921 — no como categorías rígidas sino como un espectro donde la mayoría de personas se sitúa en algún punto intermedio (ambivertidos).","Susan Cain, en su libro El poder de los introvertidos (2012), argumentó que la sociedad occidental sobrevalorar la extroversión ha marginado a un tercio de la población que piensa y crea mejor en silencio."]
},
'psy24': {
  fr:["Le psychologue Robert Boice a montré que les écrivains qui s'imposent des sessions courtes quotidiennes (15-30 min) produisent plus que ceux qui attendent l'inspiration.","Le perfectionnisme est le principal moteur du blocage — la peur que le premier jet soit « mauvais » empêche de commencer.","Ernest Hemingway combattait la page blanche en s'arrêtant toujours au milieu d'une phrase — le lendemain, il savait exactement où reprendre."],
  en:["Psychologist Robert Boice showed that writers who impose short daily sessions (15-30 min) produce more than those waiting for inspiration.","Perfectionism is the main driver of writer's block — the fear that the first draft will be 'bad' prevents starting.","Ernest Hemingway fought writer's block by always stopping mid-sentence — the next day, he knew exactly where to pick up."],
    es:["La aversión a la pérdida, descubierta por Kahneman y Tversky, muestra que perder 100 € duele psicológicamente el doble de lo que alegra ganar 100 €.","Este sesgo explica comportamientos irracionales: conservar inversiones perdedoras, evitar cambios positivos por miedo a perder lo actual, o comprar seguros excesivos.","Kahneman recibió el Nobel de Economía en 2002 por demostrar que los humanos no somos agentes racionales — nuestras decisiones están sistemáticamente sesgadas."]
},
'psy25': {
  fr:["Bluma Zeigarnik a découvert l'effet en observant des serveurs de café qui se souvenaient parfaitement des commandes en cours mais oubliaient les commandes payées.","Cet effet explique pourquoi les cliffhangers fonctionnent si bien — le cerveau ne peut pas « fermer » une histoire inachevée et y revient sans cesse.","Les listes de tâches exploitent cet effet : écrire une tâche inachevée réduit l'anxiété car le cerveau la considère comme « en cours de traitement »."],
  en:["Bluma Zeigarnik discovered the effect by observing café waiters who perfectly remembered ongoing orders but forgot paid ones.","This effect explains why cliffhangers work so well — the brain can't 'close' an unfinished story and keeps returning to it.","To-do lists exploit this effect: writing down an unfinished task reduces anxiety because the brain considers it 'being processed'."],
    es:["La meditación mindfulness, derivada de prácticas budistas, reduce el estrés, la ansiedad y la depresión según cientos de estudios revisados por pares.","La práctica modifica el cerebro de forma medible: aumenta el grosor del córtex prefrontal (planificación, autocontrol) y reduce la actividad de la amígdala (miedo, estrés).","Solo 8 semanas de meditación regular (programa MBSR) producen cambios significativos en el bienestar psicológico — un resultado comparable a los antidepresivos para la depresión leve a moderada."]
},
'psy26': {
  fr:["Une étude de Naomi Eisenberger (UCLA, 2003) a montré que le cortex cingulaire antérieur s'active autant lors d'un rejet social que lors d'une douleur physique.","Le paracétamol (Tylenol) réduit non seulement la douleur physique mais aussi la douleur sociale — une étude de 2010 l'a démontré sur trois semaines.","Évolutivement, cette connexion a du sens : chez les primates sociaux, l'exclusion du groupe signifiait la mort — le cerveau traite donc le rejet comme une menace vitale."],
  en:["A study by Naomi Eisenberger (UCLA, 2003) showed the anterior cingulate cortex activates equally during social rejection and physical pain.","Acetaminophen (Tylenol) reduces not only physical pain but also social pain — a 2010 study demonstrated this over three weeks.","Evolutionarily, this connection makes sense: for social primates, group exclusion meant death — so the brain treats rejection as a vital threat."],
    es:["El efecto Pygmalion (o profecía autocumplida) muestra que las expectativas de un profesor sobre sus alumnos influyen directamente en el rendimiento de estos.","Rosenthal y Jacobson (1968) dijeron a profesores que ciertos alumnos (elegidos al azar) eran «excepcionalmente brillantes» — al final del año, esos alumnos habían mejorado significativamente más que los demás.","Este efecto no se limita al aula: en el trabajo, en la pareja y en la crianza, las expectativas que proyectamos sobre los demás moldean su comportamiento real."]
},
'psy27': {
  fr:["L'expérience célèbre de Sheena Iyengar (2000) a montré que les clients achetaient 10 fois plus de confiture quand on leur proposait 6 variétés au lieu de 24.","Barry Schwartz appelle cela le « paradoxe du choix » — plus d'options génère plus de regret car on imagine toujours qu'un autre choix aurait été meilleur.","Les restaurants avec des menus courts vendent plus et satisfont davantage — limiter les options réduit l'anxiété décisionnelle et augmente la confiance dans le choix."],
  en:["Sheena Iyengar's famous experiment (2000) showed customers bought 10 times more jam when offered 6 varieties instead of 24.","Barry Schwartz calls this the 'paradox of choice' — more options generate more regret as we always imagine another choice would have been better.","Restaurants with shorter menus sell more and satisfy customers better — limiting options reduces decision anxiety and increases choice confidence."],
    es:["El trastorno de estrés postraumático (TEPT) fue reconocido oficialmente en 1980, aunque se describía desde la Antigüedad como «corazón de soldado» o «neurosis de guerra».","El TEPT no solo afecta a veteranos de guerra: accidentes, agresiones, catástrofes y traumas infantiles pueden desencadenarlo — afecta al 6-9 % de la población en algún momento de su vida.","La terapia EMDR (desensibilización y reprocesamiento por movimientos oculares) y la exposición prolongada son los tratamientos más eficaces, con tasas de remisión superiores al 80 %."]
},
'psy28': {
  fr:["John Bargh (1996) a montré que des participants exposés à des mots liés à la vieillesse marchaient plus lentement en sortant du laboratoire — sans en être conscients.","Le priming fonctionne aussi avec les odeurs — l'odeur de produit nettoyant pousse les gens à ranger leur espace de travail plus soigneusement.","Les supermarchés utilisent le priming constamment : musique lente pour ralentir les clients, odeurs de pain pour stimuler l'appétit et les achats impulsifs."],
  en:["John Bargh (1996) showed that participants exposed to old-age-related words walked more slowly leaving the lab — without being aware of it.","Priming also works with smells — the scent of cleaning products pushes people to tidy their workspace more carefully.","Supermarkets use priming constantly: slow music to slow customers down, bread smells to stimulate appetite and impulse buying."],
    es:["La creatividad no es un don reservado a los artistas sino una capacidad cognitiva universal que combina pensamiento divergente (generar ideas) y convergente (evaluarlas y seleccionarlas).","Los momentos «eureka» suelen ocurrir durante actividades relajantes (ducha, paseo, sueño) porque el cerebro en modo difuso conecta ideas distantes que el pensamiento focalizado no puede.","Estudios muestran que las restricciones pueden potenciar la creatividad: los límites obligan a pensar de forma no convencional — la libertad total puede paralizar más que inspirar."]
},
'psy29': {
  fr:["Le cerveau bilingue doit constamment inhiber une langue pour parler l'autre — cet exercice permanent renforce le cortex préfrontal et les fonctions exécutives.","Ellen Bialystok a montré que les bilingues développent les symptômes d'Alzheimer en moyenne 4 à 5 ans plus tard que les monolingues.","Les bébés bilingues distinguent les sons des deux langues dès 6 mois — leur cerveau maintient une flexibilité phonétique que les monolingues perdent à 10 mois."],
  en:["The bilingual brain must constantly inhibit one language to speak the other — this permanent exercise strengthens the prefrontal cortex and executive functions.","Ellen Bialystok showed that bilinguals develop Alzheimer's symptoms on average 4 to 5 years later than monolinguals.","Bilingual babies distinguish sounds from both languages by 6 months — their brain maintains phonetic flexibility that monolinguals lose at 10 months."],
    es:["La teoría de la autodeterminación (Deci y Ryan) identifica tres necesidades psicológicas básicas: autonomía, competencia y conexión social.","Cuando estas tres necesidades están satisfechas, las personas experimentan motivación intrínseca, bienestar y crecimiento personal — su frustración produce apatía, ansiedad y malestar.","Esta teoría explica por qué el dinero no motiva a largo plazo: la motivación extrínseca (recompensas, castigos) erosiona la motivación intrínseca cuando sustituye el sentido de autonomía."]
},
'psy30': {
  fr:["L'effet a été démontré par Bertram Forer en 1948 — il a donné le même profil de personnalité à tous ses étudiants, et chacun l'a jugé « très précis » (note moyenne : 4,26/5).","Les descriptions Barnum utilisent des phrases à double sens : « Vous avez besoin que les autres vous apprécient » s'applique à 95 % des gens.","Les médiums et voyants exploitent cet effet combiné au « cold reading » — des techniques de lecture du langage corporel qui donnent l'illusion de pouvoirs psychiques."],
  en:["The effect was demonstrated by Bertram Forer in 1948 — he gave the same personality profile to all his students, and each rated it 'very accurate' (average: 4.26/5).","Barnum descriptions use double-meaning phrases: 'You need others to appreciate you' applies to 95% of people.","Psychics exploit this effect combined with 'cold reading' — body language reading techniques that create the illusion of psychic powers."],
    es:["Los sesgos cognitivos son atajos mentales que el cerebro usa para tomar decisiones rápidas — útiles en la sabana africana, pero a menudo engañosos en el mundo moderno.","Kahneman distingue entre el Sistema 1 (rápido, intuitivo, automático) y el Sistema 2 (lento, analítico, esforzado) — la mayoría de nuestras decisiones las toma el Sistema 1 sin que nos demos cuenta.","Conocer nuestros sesgos no nos inmuniza contra ellos: el sesgo del punto ciego nos hace creer que somos menos sesgados que los demás — la autoconciencia es necesaria pero insuficiente."]
},

'ocean21': {
  fr:["Le Gulf Stream à lui seul transporte autant d'énergie thermique que 100 centrales nucléaires — réchauffant l'Europe de 5 à 10 °C par rapport à la même latitude en Amérique.","Si la circulation thermohaline s'arrêtait, les hivers européens ressembleraient à ceux de Terre-Neuve — des températures moyennes de −15 °C en janvier à Paris.","Le réchauffement climatique ralentit déjà la circulation atlantique de 15 % depuis 1950 — les scientifiques surveillent un possible point de basculement."],
  en:["The Gulf Stream alone transports as much thermal energy as 100 nuclear power plants — warming Europe by 5 to 10°C compared to the same latitude in America.","If thermohaline circulation stopped, European winters would resemble Newfoundland's — average January temperatures of −15°C in Paris.","Climate change has already slowed Atlantic circulation by 15% since 1950 — scientists are monitoring a possible tipping point."],
    es:["El Triángulo de las Bermudas, entre Miami, Bermudas y Puerto Rico, tiene fama de tragar barcos y aviones — pero estadísticamente, su tasa de accidentes no es superior a la de otras zonas de tráfico marítimo intenso.","Las explicaciones propuestas incluyen erupciones de metano del fondo marino (que reducirían la densidad del agua), corrientes impredecibles y tormentas tropicales súbitas.","El mito fue popularizado por el escritor Charles Berlitz en 1974 — investigaciones posteriores revelaron que muchos de los «desapariciones misteriosas» habían sido exageradas o inventadas."]
},
'ocean22': {
  fr:["Le programme Seabed 2030 vise à cartographier 100 % des fonds marins d'ici 2030 — en 2024, environ 25 % étaient cartographiés en haute résolution.","Les sonars multifaisceaux modernes peuvent scanner le fond à 12 000 m de profondeur — mais chaque navire ne couvre que 40 km² par jour.","On a découvert plus de 19 000 monts sous-marins (seamounts) — certains plus hauts que le Mont Blanc, totalement inconnus il y a 20 ans."],
  en:["The Seabed 2030 program aims to map 100% of the ocean floor by 2030 — by 2024, about 25% was mapped in high resolution.","Modern multibeam sonars can scan the bottom at 12,000 m depth — but each ship covers only 40 km² per day.","Over 19,000 seamounts have been discovered — some taller than Mont Blanc, completely unknown 20 years ago."],
    es:["Los delfines duermen con medio cerebro a la vez (sueño unihemisférico) para poder seguir respirando y vigilar a los depredadores — mantienen un ojo abierto.","Su ecolocalización es más precisa que cualquier sonar artificial: pueden detectar un objeto del tamaño de una pelota de golf a 100 metros de distancia.","Los delfines tienen nombres propios: cada individuo desarrolla un silbido firma único que los demás usan para llamarlo — una forma de comunicación individual rarísima en el reino animal."]
},
'ocean23': {
  fr:["La Grande Barrière de corail est si vaste (344 400 km²) qu'elle est visible depuis l'espace — c'est le plus grand organisme vivant de la planète.","Les coraux ne sont pas des plantes mais des animaux — ils vivent en symbiose avec des algues microscopiques (zooxanthelles) qui leur donnent leurs couleurs.","Le blanchissement corallien se produit quand l'eau se réchauffe de seulement 1 à 2 °C — les coraux expulsent leurs algues et meurent si le stress persiste."],
  en:["The Great Barrier Reef is so vast (344,400 km²) it's visible from space — it's the largest living organism on the planet.","Corals aren't plants but animals — they live in symbiosis with microscopic algae (zooxanthellae) that give them their colors.","Coral bleaching occurs when water warms by just 1 to 2°C — corals expel their algae and die if stress persists."],
    es:["La Corriente del Golfo transporta más de 30 millones de metros cúbicos de agua por segundo — más que todos los ríos del mundo combinados.","Sin la Corriente del Golfo, ciudades como Londres y París tendrían temperaturas comparables a las de Labrador en Canadá, a la misma latitud.","Los científicos vigilan signos de debilitamiento de esta corriente debido al deshielo de Groenlandia — un cambio que tendría consecuencias climáticas graves para Europa y América del Norte."]
},
'ocean24': {
  fr:["Ce lac sous-marin a une salinité 5 fois supérieure à l'océan environnant — il possède même ses propres « rivages » et des vagues à sa surface.","La concentration en méthane dissous y est extrêmement élevée — des organismes extrêmophiles comme des vers tubicoles et des moules chimiosynthétiques y prospèrent.","On appelle ces environnements des « piscines de la mort » — les rares poissons ou crabes qui y tombent entrent en choc toxique et meurent en quelques secondes."],
  en:["This underwater lake has salinity 5 times higher than the surrounding ocean — it even has its own 'shoreline' and waves on its surface.","Dissolved methane concentration is extremely high — extremophile organisms like tube worms and chemosynthetic mussels thrive there.","These environments are called 'death pools' — the rare fish or crabs that fall in enter toxic shock and die within seconds."],
    es:["Las profundidades abisales (más de 4 000 m) son un mundo de oscuridad total, presiones aplastantes y temperaturas cercanas a 0 °C — y sin embargo, están llenas de vida.","Los peces abisales tienen adaptaciones extraordinarias: mandíbulas extensibles, estómagos elásticos, órganos bioluminiscentes y metabolismos extremadamente lentos.","El pez rape abisal macho se fusiona físicamente con la hembra al encontrarla: pierde sus órganos y se convierte en un apéndice reproductor permanente — la estrategia reproductiva más extrema de la naturaleza."]
},
'ocean25': {
  fr:["La première vague scélérate scientifiquement mesurée est la vague Draupner, de 25,6 m, enregistrée en mer du Nord en 1995 par une plateforme pétrolière.","Ces vagues se forment par interférence constructive — plusieurs vagues se superposent au même moment, créant un mur d'eau qui peut atteindre deux fois la hauteur des vagues environnantes.","Des navires comme le MS München (1978) ont probablement été coulés par des vagues scélérates — le cargo a disparu avec ses 28 membres d'équipage sans laisser de trace."],
  en:["The first scientifically measured rogue wave was the Draupner wave, 25.6 m, recorded in the North Sea in 1995 by an oil platform.","These waves form through constructive interference — multiple waves stack at the same moment, creating a wall of water up to twice the height of surrounding waves.","Ships like the MS München (1978) were likely sunk by rogue waves — the cargo ship vanished with all 28 crew without a trace."],
    es:["El Océano Ártico se calienta cuatro veces más rápido que el resto del planeta — el hielo marino de verano podría desaparecer completamente antes de 2050.","La pérdida de hielo ártico afecta al albedo (reflectividad) terrestre: el agua oscura absorbe más calor que el hielo blanco, acelerando el calentamiento en un círculo vicioso.","La apertura de rutas marítimas árticas (Paso del Noroeste, Ruta del Mar del Norte) genera intereses geopolíticos entre Rusia, EE.UU., Canadá, China y la UE."]
},
'ocean26': {
  fr:["Le Point Nemo (48°52'S, 123°23'W) est à 2 688 km de la terre la plus proche — l'île Ducie, l'île Motu Nui et l'île Maher.","Les humains les plus proches du Point Nemo sont souvent les astronautes de l'ISS — qui passent à 400 km d'altitude, plus près que toute terre.","C'est aussi le « cimetière des vaisseaux spatiaux » — plus de 260 engins désorbitaux y ont été dirigés, dont la station Mir en 2001."],
  en:["Point Nemo (48°52'S, 123°23'W) is 2,688 km from the nearest land — Ducie Island, Motu Nui Island, and Maher Island.","The closest humans to Point Nemo are often ISS astronauts — who pass at 400 km altitude, closer than any land.","It's also the 'spacecraft cemetery' — over 260 deorbited craft have been directed there, including the Mir station in 2001."],
    es:["Las olas más grandes del mundo se forman en Nazaré, Portugal, donde un cañón submarino de 5 km de profundidad concentra la energía del oleaje atlántico.","El récord de la ola más grande jamás surfeada fue establecido en Nazaré: más de 26 metros (un edificio de 8 pisos), una hazaña que desafía los límites humanos.","Las olas gigantes (rogue waves o olas vagabundas) fueron consideradas mitos de marineros hasta que sensores satelitales confirmaron su existencia en los años 1990."]
},
'ocean27': {
  fr:["Les éponges existent depuis au moins 600 millions d'années — bien avant les dinosaures, les poissons ou même les premiers yeux dans le règne animal.","Elles filtrent jusqu'à 20 000 litres d'eau par jour pour une éponge de taille moyenne — extrayant les bactéries et les micro-organismes dont elles se nourrissent.","Certaines éponges produisent des composés chimiques anticancéreux — l'Eribuline, un médicament contre le cancer du sein, est dérivé de l'éponge Halichondria okadai."],
  en:["Sponges have existed for at least 600 million years — long before dinosaurs, fish, or even the first eyes in the animal kingdom.","An average-sized sponge filters up to 20,000 liters of water per day — extracting bacteria and microorganisms for food.","Some sponges produce anti-cancer chemical compounds — Eribulin, a breast cancer drug, is derived from the sponge Halichondria okadai."],
    es:["Las praderas de posidonia (Posidonia oceanica) del Mediterráneo producen más oxígeno que la selva amazónica por metro cuadrado y almacenan grandes cantidades de carbono.","Una pradera de posidonia en las Islas Baleares se considera el organismo vivo más grande (y posiblemente más antiguo) del mundo: tiene más de 100 000 años.","La posidonia está protegida en la UE como hábitat prioritario, pero sigue amenazada por el fondeo de embarcaciones, la contaminación y el desarrollo costero."]
},
'ocean28': {
  fr:["Le Gulf Stream transporte environ 30 millions de mètres cubes d'eau par seconde — soit 300 fois le débit de l'Amazone, le plus grand fleuve du monde.","Benjamin Franklin a été le premier à cartographier le Gulf Stream en 1770 — il avait remarqué que les navires postaux mettaient plus longtemps quand ils naviguaient à contre-courant.","Le Gulf Stream est si puissant qu'il influence les trajectoires des ouragans — les déviant vers le nord-est en leur fournissant de l'énergie thermique."],
  en:["The Gulf Stream carries about 30 million cubic meters of water per second — 300 times the flow of the Amazon, the world's largest river.","Benjamin Franklin was the first to chart the Gulf Stream in 1770 — he noticed mail ships took longer when sailing against it.","The Gulf Stream is so powerful it influences hurricane paths — deflecting them northeast while feeding them thermal energy."],
    es:["Los cachalotes pueden sumergirse a más de 2 000 metros de profundidad y contener la respiración durante 90 minutos — los mamíferos buceadores más extremos del planeta.","Su cerebro, el más grande del reino animal (8 kg), produce clics de ecolocalización que alcanzan los 230 decibelios — el sonido más fuerte producido por cualquier animal.","Los cachalotes tienen una cultura de clan: diferentes grupos usan dialectos de clics distintos y se transmiten técnicas de caza entre generaciones."]
},
'ocean29': {
  fr:["La bioluminescence est produite par une réaction chimique entre la luciférine et la luciférase — le même principe que les lucioles, mais adapté au milieu marin.","Les usages sont multiples : attirer des proies (baudroie), communiquer (calmars), se camoufler (contre-illumination) ou repousser les prédateurs.","Le phénomène des « mers laiteuses » — des zones océaniques lumineuses visibles depuis l'espace — est causé par des milliards de bactéries bioluminescentes."],
  en:["Bioluminescence is produced by a chemical reaction between luciferin and luciferase — the same principle as fireflies, adapted to the marine environment.","Uses are multiple: attracting prey (anglerfish), communicating (squid), camouflage (counter-illumination), or repelling predators.","The phenomenon of 'milky seas' — luminous ocean zones visible from space — is caused by billions of bioluminescent bacteria."],
    es:["El océano profundo contiene más del 90 % del espacio habitable de la Tierra, pero hemos explorado menos del 5 % de este vasto dominio.","Las llanuras abisales, vastas extensiones planas del fondo oceánico, son los hábitats más grandes y menos conocidos del planeta.","La minería de los fondos marinos (nódulos polimetálicos, sulfuros hidrotermales) genera un debate feroz entre la industria minera y los conservacionistas — los daños a estos ecosistemas serían irreversibles."]
},
'ocean30': {
  fr:["Les océans contiennent environ 50 millions de milliards de tonnes de sel dissous — principalement du chlorure de sodium (85 %) apporté par l'érosion des roches terrestres.","La mer Morte est 10 fois plus salée que l'océan — avec 340 g de sel par litre, on y flotte sans effort mais aucun poisson ne peut y survivre.","L'eau de mer est salée depuis des milliards d'années — le sel arrive par les rivières et les sources hydrothermales, mais ne repart jamais (pas d'évaporation du sel)."],
  en:["Oceans contain about 50 million billion tonnes of dissolved salt — mainly sodium chloride (85%) carried by erosion of land rocks.","The Dead Sea is 10 times saltier than the ocean — at 340 g per liter, you float effortlessly but no fish can survive.","Seawater has been salty for billions of years — salt arrives via rivers and hydrothermal vents but never leaves (salt doesn't evaporate)."],
    es:["Los océanos absorben el 90 % del exceso de calor causado por el cambio climático — sin ellos, la temperatura atmosférica sería mucho más alta.","El nivel del mar ha subido 20 cm desde 1900 y la velocidad de subida se acelera: se prevén entre 30 cm y 1 metro adicionales para 2100 según los escenarios.","Ciudades costeras como Miami, Yakarta, Shanghái y Bombay albergan a cientos de millones de personas amenazadas por la subida del nivel del mar — la adaptación costera es uno de los mayores desafíos del siglo XXI."]
},


'rec21': {
  fr:["Bryan Berg est architecte de formation — il utilise les principes de l'ingénierie structurelle pour concevoir des grilles de cartes capables de supporter leur propre poids.","Son château record de 2010 a utilisé 218 792 cartes — il a mis 44 jours à le construire et une fraction de seconde à le détruire pour la caméra.","Berg construit aussi des répliques de bâtiments célèbres en cartes — il a reproduit le Venetian de Las Vegas avec 4 051 jeux de cartes."],
  en:["Bryan Berg is a trained architect — he uses structural engineering principles to design card grids capable of supporting their own weight.","His 2010 record castle used 218,792 cards — it took 44 days to build and a fraction of a second to demolish for camera.","Berg also builds replicas of famous buildings from cards — he recreated the Venetian in Las Vegas with 4,051 decks of cards."],
    es:["El volcán más activo del mundo es el Kīlauea en Hawái, que ha estado en erupción casi continua desde 1983 — ha destruido más de 700 estructuras.","La erupción más mortífera de la historia fue la del Tambora (Indonesia) en 1815: mató a 71 000 personas y causó el «año sin verano» de 1816 en todo el hemisferio norte.","El supervolcán de Yellowstone, bajo el parque nacional, tiene una cámara magmática de 60 km de largo — una erupción masiva podría afectar al clima global durante décadas."]
},
'rec22': {
  fr:["Ce record a été battu en Italie en 2021 par un collectif de musiciens jouant en relais — chaque musicien jouait plusieurs heures avant d'être remplacé.","Il existe aussi un concert prévu pour durer 639 ANS — ORGAN²/ASLSP de John Cage, lancé en 2001 dans une église de Halberstadt en Allemagne, avec le prochain changement de note prévu en 2026.","Le concert continu le plus long par un SEUL artiste est de 56 heures — un record de résistance autant que de musique."],
  en:["This record was broken in Italy in 2021 by a collective of musicians playing in relay — each musician played several hours before being replaced.","There's also a concert planned to last 639 YEARS — John Cage's ORGAN²/ASLSP, started in 2001 in a Halberstadt church in Germany, with the next note change planned for 2026.","The longest continuous concert by a SINGLE artist is 56 hours — a record of endurance as much as music."],
    es:["El animal más pesado que ha existido es la ballena azul (180 toneladas) — ningún dinosaurio se acercó a ese peso.","El animal terrestre más pesado fue el Argentinosaurus, un saurópodo de unas 70 toneladas — aun así, menos de la mitad del peso de una ballena azul.","El insecto más pesado es el escarabajo Goliat, que puede pesar hasta 100 gramos — en la era del Carbonífero, los insectos alcanzaban tamaños mucho mayores gracias a niveles de oxígeno más altos."]
},
'rec23': {
  fr:["Furman a battu des records dans des catégories aussi variées que le pogo stick sous l'eau, la marche avec un bouteille de lait sur la tête et le jonglage en courant un marathon.","Il est inspiré par le gourou Sri Chinmoy, qui enseignait que repousser ses limites physiques développe aussi la force spirituelle.","Son premier record en 1979 était 27 000 sauts de jumping jacks — depuis, il a battu des records dans plus de 40 pays et sur les 7 continents."],
  en:["Furman has broken records in categories ranging from underwater pogo stick to walking with a milk bottle on his head and juggling while running a marathon.","He's inspired by guru Sri Chinmoy, who taught that pushing physical limits also develops spiritual strength.","His first record in 1979 was 27,000 jumping jacks — since then, he's broken records in over 40 countries across all 7 continents."],
    es:["El objeto más lejano visible a simple vista es la galaxia de Andrómeda, a 2,5 millones de años-luz — la luz que vemos salió de allí antes de que existieran los humanos.","El telescopio James Webb ha detectado galaxias a más de 13 000 millones de años-luz, formadas apenas 300 millones de años después del Big Bang.","La distancia más lejana que podremos observar jamás es de 46 000 millones de años-luz (borde del universo observable) — más allá, la luz no ha tenido tiempo de llegar a nosotros."]
},
'rec24': {
  fr:["Les participants étaient des gymnastes et des personnes de petite taille — chaque centimètre carré de la voiture était optimisé pour accueillir un maximum de corps.","Le record nécessite que toutes les portes et fenêtres soient fermées et que la voiture reste immobile — les participants y restent au moins 10 secondes.","Le record équivalent pour une Smart ForTwo est de 20 personnes — remarquable étant donné que la voiture ne fait que 2,7 mètres de long."],
  en:["Participants were gymnasts and small-statured people — every square centimeter of the car was optimized to fit maximum bodies.","The record requires all doors and windows closed and the car stationary — participants must stay for at least 10 seconds.","The equivalent record for a Smart ForTwo is 20 people — remarkable given the car is only 2.7 meters long."],
    es:["El partido de tenis más largo de la historia duró 11 horas y 5 minutos, repartidos en tres días: John Isner venció a Nicolas Mahut 70-68 en el quinto set en Wimbledon 2010.","Tras este maratón, Wimbledon introdujo el tie-break en el quinto set a 12-12 — una regla que no habría sido necesaria sin este partido histórico.","Ambos jugadores sufrieron lesiones tras el partido y Mahut perdió su siguiente encuentro en apenas una hora — el coste físico del récord fue devastador."]
},
'rec25': {
  fr:["Le record est détenu par Max Park (2023) — ses doigts effectuent en moyenne 10 à 12 mouvements par seconde, soit la vitesse d'un pianiste virtuose.","Les « speedcubers » mémorisent des centaines d'algorithmes (séquences de mouvements) — les meilleurs en connaissent plus de 400.","Le record de résolution les yeux bandés est de 12 secondes — le cuber mémorise la position en la regardant pendant quelques secondes, puis résout sans voir."],
  en:["The record is held by Max Park (2023) — his fingers average 10 to 12 moves per second, matching a virtuoso pianist's speed.","Speedcubers memorize hundreds of algorithms (move sequences) — the best know over 400.","The blindfolded solving record is 12 seconds — the cuber memorizes the position by looking for a few seconds, then solves without seeing."],
    es:["El mayor concierto de la historia reunió a 3,5 millones de personas para ver a Rod Stewart en Copacabana (Río de Janeiro) en la Nochevieja de 1994.","Jean-Michel Jarre ha dado varios de los conciertos más masivos de la historia, incluyendo 2,5 millones en la Défense (París) y 3,5 millones en Moscú.","La tecnología de streaming ha redefinido el concepto de «concierto más grande»: Travis Scott reunió a 12 millones de espectadores simultáneos en un concierto virtual dentro de Fortnite."]
},
'rec26': {
  fr:["En vol horizontal, le faucon pèlerin ne dépasse pas 100 km/h — c'est en piqué (le « stoop ») qu'il atteint sa vitesse record grâce à la gravité.","Ses narines possèdent des déflecteurs coniques qui empêchent l'air d'entrer trop vite dans ses poumons — une adaptation aérodynamique unique.","Le faucon pèlerin est présent sur tous les continents sauf l'Antarctique — après avoir frôlé l'extinction à cause du DDT, ses populations ont rebondi grâce à son interdiction."],
  en:["In level flight, the peregrine falcon doesn't exceed 100 km/h — it reaches record speed in its dive (the 'stoop') thanks to gravity.","Its nostrils have conical deflectors preventing air from entering its lungs too fast — a unique aerodynamic adaptation.","The peregrine falcon lives on every continent except Antarctica — after nearly going extinct from DDT, populations rebounded thanks to its ban."],
    es:["La velocidad máxima alcanzada por un ser humano fue 39 897 km/h, lograda por la tripulación del Apollo 10 durante la reentrada atmosférica en 1969.","En la superficie terrestre, el récord de velocidad humana sin vehículo es el de Usain Bolt: 44,72 km/h durante los 100 metros lisos.","Felix Baumgartner alcanzó 1 357 km/h (Mach 1,25) durante su salto estratosférico desde 39 km de altitud en 2012 — el primer humano en romper la barrera del sonido sin vehículo."]
},
'rec27': {
  fr:["Andras a parcouru cette distance en poussant sans relâche pendant 24 heures sur une route plate — l'équivalent de 12 marathons consécutifs.","La difficulté principale n'est pas la distance mais les pieds : les ampoules, les crampes et la douleur constante font abandonner la plupart des concurrents.","Le skateboard longue distance (« long distance pushing ») est un sport de niche avec sa propre communauté — des courses de 24 heures sont organisées chaque année."],
  en:["Andras covered this distance pushing nonstop for 24 hours on a flat road — the equivalent of 12 consecutive marathons.","The main difficulty isn't distance but feet: blisters, cramps, and constant pain force most competitors to quit.","Long distance pushing is a niche sport with its own community — 24-hour races are organized annually."],
    es:["El mayor organismo vivo del planeta es un hongo (Armillaria ostoyae) en Oregón que se extiende por 965 hectáreas bajo tierra — tiene más de 8 000 años.","El organismo individual más pesado es un álamo temblón clonal llamado Pando en Utah: un bosque de 47 000 árboles conectados por un único sistema de raíces, con un peso estimado de 6 000 toneladas.","Las secuoyas gigantes de California son los árboles más voluminosos: el General Sherman tiene un tronco de 1 487 m³ — el equivalente de un edificio de 5 plantas."]
},
'rec28': {
  fr:["Le Cullinan a été découvert en 1905 dans la mine Premier en Afrique du Sud — il pesait 621 grammes bruts, de la taille d'un poing.","Le joaillier Joseph Asscher a mis des mois à étudier le diamant avant de le fendre — selon la légende, il s'est évanoui après le premier coup réussi.","Les deux plus grandes pierres taillées du Cullinan — la Great Star of Africa (530 carats) et la Second Star (317 carats) — sont serties dans le sceptre et la couronne d'État britanniques."],
  en:["The Cullinan was discovered in 1905 at the Premier mine in South Africa — it weighed 621 grams rough, the size of a fist.","Jeweler Joseph Asscher spent months studying the diamond before cleaving it — legend says he fainted after the first successful blow.","The two largest cut stones from the Cullinan — the Great Star of Africa (530 carats) and Second Star (317 carats) — are set in the British Sovereign's Sceptre and Imperial State Crown."],
    es:["El humano que más idiomas ha dominado de forma verificable fue el cardenal Giuseppe Mezzofanti (1774-1849), que hablaba con fluidez entre 30 y 40 idiomas.","Los hiperpolíglotas modernos como Alexander Arguelles y Richard Simcott dominan más de 50 idiomas, aunque el nivel varía entre fluido y básico.","La mayoría de las personas pueden aprender un nuevo idioma a cualquier edad: el mito del «periodo crítico» absoluto ha sido matizado por la investigación moderna."]
},
'rec29': {
  fr:["Klaus Ohlmann a exploité les ondes de ressaut des Andes — des courants ascendants si puissants qu'ils peuvent propulser un planeur à plus de 10 000 mètres d'altitude.","Le vol a duré 14 heures et 40 minutes sans moteur — Ohlmann a suivi la cordillère des Andes de Zapala à San Rafael.","Le record d'altitude en planeur est de 23 202 mètres (2018) — dans la stratosphère, où le pilote doit porter une combinaison pressurisée comme les astronautes."],
  en:["Klaus Ohlmann exploited Andean wave lift — updrafts so powerful they can propel a glider above 10,000 meters altitude.","The flight lasted 14 hours and 40 minutes without an engine — Ohlmann followed the Andes from Zapala to San Rafael.","The glider altitude record is 23,202 meters (2018) — in the stratosphere, where the pilot must wear a pressure suit like astronauts."],
    es:["El puente más largo del mundo es el viaducto de Danyang-Kunshan (China), con 164,8 km — conecta Shanghái con Nankín y es una obra de ingeniería sin precedentes.","El puente colgante más largo es el puente de los Dardanelos «1915 Çanakkale» en Turquía (2 023 m de vano central), inaugurado en 2022.","Los puentes romanos, construidos hace 2 000 años con arcos de piedra, siguen en uso en muchas partes de Europa — una demostración de la durabilidad de la ingeniería antigua."]
},
'rec30': {
  fr:["Nazaré produit des vagues géantes grâce au Canyon de Nazaré — une faille sous-marine de 230 km qui concentre l'énergie des houles atlantiques.","Les surfeurs sont tractés par des jet-skis pour atteindre la vitesse nécessaire (50 km/h) — il est impossible de ramer dans des vagues de cette taille.","Steudtner portait un gilet gonflable et un système GPS — les équipes de sauvetage en jet-ski sont essentielles car une chute peut signifier être submergé pendant 30 secondes."],
  en:["Nazaré produces giant waves thanks to the Nazaré Canyon — a 230 km underwater fault that concentrates Atlantic swell energy.","Surfers are towed by jet skis to reach the necessary speed (50 km/h) — it's impossible to paddle into waves this size.","Steudtner wore an inflatable vest and GPS system — jet ski rescue teams are essential as a fall can mean being submerged for 30 seconds."],
    es:["La mayor explosión de origen humano antes de la bomba atómica fue la explosión de Halifax (Canadá) en 1917: un barco cargado de municiones devastó la ciudad, matando a 2 000 personas.","La mayor explosión nuclear fue la Tsar Bomba soviética (1961): 50 megatones de TNT — la onda expansiva dio tres vueltas a la Tierra y las ventanas se rompieron a 900 km.","La explosión más potente en la historia terrestre fue el impacto del asteroide Chicxulub hace 66 millones de años: equivalente a 10 000 millones de bombas de Hiroshima, que provocó la extinción de los dinosaurios."]
},

'quote21': {
  fr:["Confucius (551-479 av. J.-C.) n'a jamais écrit ses enseignements lui-même — ce sont ses disciples qui les ont compilés dans les « Analectes » après sa mort.","Sa philosophie repose sur cinq vertus : la bienveillance (ren), la justice (yi), la bienséance (li), la sagesse (zhi) et la fidélité (xin).","Le confucianisme a façonné la Chine, la Corée, le Japon et le Vietnam pendant plus de 2 000 ans — influençant l'éducation, la politique et la vie familiale."],
  en:["Confucius (551-479 BC) never wrote down his teachings himself — his disciples compiled them in the 'Analects' after his death.","His philosophy rests on five virtues: benevolence (ren), righteousness (yi), propriety (li), wisdom (zhi), and faithfulness (xin).","Confucianism shaped China, Korea, Japan, and Vietnam for over 2,000 years — influencing education, politics, and family life."],
    es:["«Carpe diem» (Aprovecha el día) de Horacio (Odas, 23 a.C.) no es una invitación al hedonismo sino al disfrute consciente del presente ante la certeza de la muerte.","La frase completa es «Carpe diem, quam minimum credula postero» — aprovecha el día, confiando lo menos posible en el mañana.","Robin Williams inmortalizó la expresión en El club de los poetas muertos (1989), conectando la poesía latina con la rebeldía adolescente y la urgencia de vivir."]
},
'quote22': {
  fr:["Tesla a décrit un appareil de poche sans fil capable de transmettre images, sons et textes à travers le monde — 80 ans avant l'iPhone.","Il a aussi prédit l'énergie sans fil, les drones et la communication interplanétaire — des idées considérées comme délirantes à l'époque.","Tesla est mort seul et ruiné dans une chambre d'hôtel new-yorkaise en 1943 — le FBI a confisqué ses papiers, alimentant des décennies de théories du complot."],
  en:["Tesla described a wireless pocket device capable of transmitting images, sound, and text worldwide — 80 years before the iPhone.","He also predicted wireless energy, drones, and interplanetary communication — ideas considered delusional at the time.","Tesla died alone and broke in a New York hotel room in 1943 — the FBI seized his papers, fueling decades of conspiracy theories."],
    es:["«El poder corrompe, y el poder absoluto corrompe absolutamente» fue escrito por Lord Acton en 1887 en una carta sobre la infalibilidad papal.","Acton era católico pero se opuso al dogma de la infalibilidad del papa — su frase trasciende el contexto religioso y se aplica a toda forma de poder sin control.","La separación de poderes (legislativo, ejecutivo, judicial) propuesta por Montesquieu es la respuesta institucional a esta observación: ningún poder debe ser absoluto."]
},
'quote23': {
  fr:["Angelou a surmonté un traumatisme d'enfance qui l'a rendue muette pendant cinq ans — elle est devenue l'une des voix les plus puissantes de la littérature américaine.","Elle a lu un poème lors de l'investiture de Bill Clinton en 1993 — seulement la deuxième poétesse à le faire, après Robert Frost pour JFK en 1961.","Avant d'écrire, elle a été danseuse, actrice, chanteuse, militante des droits civiques et professeure — une vie aussi riche que son œuvre littéraire."],
  en:["Angelou overcame a childhood trauma that left her mute for five years — she became one of the most powerful voices in American literature.","She read a poem at Bill Clinton's inauguration in 1993 — only the second poet to do so, after Robert Frost for JFK in 1961.","Before writing, she was a dancer, actress, singer, civil rights activist, and professor — a life as rich as her literary work."],
    es:["«La vida es lo que pasa mientras estás ocupado haciendo otros planes» apareció en la canción Beautiful Boy de John Lennon (1980), pero versiones anteriores existen desde los años 1950.","Lennon escribió la canción para su hijo Sean y fue asesinado pocas semanas después de su publicación — una coincidencia trágica que otorgó a la frase un significado profético.","La cita captura una verdad psicológica: nuestra obsesión por planificar el futuro nos impide vivir el presente — un tema central de la filosofía budista y la psicología positiva."]
},
'quote24': {
  fr:["Darwin a écrit dans L'Origine des espèces (1859) que la sélection naturelle favorise les organismes les mieux adaptés à leur environnement — pas les plus forts ou les plus gros.","L'expression « survival of the fittest » a été inventée par Herbert Spencer, pas Darwin — et « fit » signifie « adapté », pas « en forme physique ».","Le « darwinisme social », qui justifie les inégalités par la sélection naturelle, est une déformation de la pensée de Darwin — il s'y serait fermement opposé."],
  en:["Darwin wrote in On the Origin of Species (1859) that natural selection favors organisms best adapted to their environment — not the strongest or largest.","The phrase 'survival of the fittest' was coined by Herbert Spencer, not Darwin — and 'fit' means 'adapted,' not 'physically fit'.","Social Darwinism, which justifies inequality through natural selection, is a distortion of Darwin's thought — he would have firmly opposed it."],
    es:["«No es la especie más fuerte la que sobrevive, ni la más inteligente, sino la que mejor responde al cambio» se atribuye erróneamente a Darwin.","Darwin nunca escribió esta frase: fue formulada por Leon Megginson, un profesor de administración, en 1963 como interpretación libre de El origen de las especies.","Sin embargo, la idea captura la esencia de la selección natural: la adaptabilidad, no la fuerza bruta, es la clave de la supervivencia — un principio válido tanto en biología como en los negocios."]
},
'quote25': {
  fr:["La citation exacte est débattue — T.S. Eliot a écrit quelque chose de similaire en 1920, et des variantes circulent depuis le 19ᵉ siècle.","Ce que Picasso voulait dire : copier imite la surface, « voler » signifie s'approprier l'essence d'une idée et la transformer en quelque chose de nouveau.","Steve Jobs a cité cette phrase en 1996 pour justifier la philosophie de design d'Apple — s'inspirer d'idées existantes pour créer quelque chose de supérieur."],
  en:["The exact quote is debated — T.S. Eliot wrote something similar in 1920, and variations have circulated since the 19th century.","What Picasso meant: copying imitates the surface, 'stealing' means appropriating the essence of an idea and transforming it into something new.","Steve Jobs quoted this in 1996 to justify Apple's design philosophy — drawing from existing ideas to create something superior."],
    es:["«La locura es hacer lo mismo una y otra vez esperando resultados diferentes» se atribuye falsamente a Einstein — no hay ninguna evidencia de que la dijera.","La frase aparece por primera vez en un folleto de Narcóticos Anónimos de 1981 — su atribución a Einstein es un ejemplo clásico de cita apócrifa.","Las citas falsas son un fenómeno antiguo: atribuir una frase a una autoridad reconocida le otorga credibilidad instantánea — algo que las redes sociales han amplificado exponencialmente."]
},
'quote26': {
  fr:["Le Tao Te King, écrit au 6ᵉ siècle av. J.-C., ne compte que 5 000 caractères chinois — mais sa profondeur philosophique a inspiré des milliers de commentaires.","L'existence historique de Lao Tseu est débattue — certains historiens pensent que le Tao Te King est une compilation de plusieurs auteurs sous un nom collectif.","Le taoïsme a profondément influencé les arts martiaux, la médecine traditionnelle chinoise et la philosophie du « wu wei » (non-agir) — agir en accord avec le flux naturel."],
  en:["The Tao Te Ching, written in the 6th century BC, contains only 5,000 Chinese characters — but its philosophical depth has inspired thousands of commentaries.","The historical existence of Lao Tzu is debated — some historians believe the Tao Te Ching is a compilation by multiple authors under a collective name.","Taoism deeply influenced martial arts, traditional Chinese medicine, and the philosophy of 'wu wei' (non-action) — acting in accord with natural flow."],
    es:["«Hasta la victoria siempre» es la frase icónica del Che Guevara, convertida en eslogan revolucionario en toda América Latina y más allá.","Guevara fue médico, guerrillero, ministro y finalmente mártir: ejecutado en Bolivia en 1967, su imagen se convirtió en el póster más reproducido del siglo XX.","Su legado divide profundamente: héroe de la revolución para unos, símbolo de violencia política para otros — la realidad histórica es más compleja que el mito."]
},
'quote27': {
  fr:["Arendt a forgé ce concept en couvrant le procès d'Adolf Eichmann à Jérusalem en 1961 — elle a décrit un bureaucrate médiocre obéissant aux ordres sans réfléchir.","Sa thèse a provoqué un scandale : beaucoup l'accusaient de minimiser la responsabilité des nazis en les présentant comme des fonctionnaires ordinaires.","Le concept reste crucial aujourd'hui — il montre que les systèmes autoritaires n'ont pas besoin de monstres, mais de gens qui cessent de penser par eux-mêmes."],
  en:["Arendt coined this concept while covering Adolf Eichmann's trial in Jerusalem in 1961 — she described a mediocre bureaucrat obeying orders without thinking.","Her thesis caused a scandal: many accused her of minimizing Nazi responsibility by portraying them as ordinary officials.","The concept remains crucial today — it shows authoritarian systems don't need monsters, just people who stop thinking for themselves."],
    es:["«Elemental, mi querido Watson» nunca fue dicho por Sherlock Holmes en los libros de Arthur Conan Doyle — la frase fue inventada para las adaptaciones teatrales y cinematográficas.","Holmes dice «Elementary» en varias ocasiones y se dirige a «mi querido Watson», pero nunca combina ambas expresiones en una sola frase.","Es una de las citas falsas más famosas de la historia de la ficción — junto con «Play it again, Sam» (nunca dicho en Casablanca) y «Luke, yo soy tu padre» (ligeramente diferente en Star Wars)."]
},
'quote28': {
  fr:["La phrase est le plus souvent attribuée à Madame de Pompadour en 1757, consolant Louis XV après la défaite de Rossbach contre la Prusse.","Elle reflète l'insouciance aristocratique du 18ᵉ siècle — une aristocratie vivant dans le luxe tandis que le peuple souffrait de famine et de taxes écrasantes.","L'ironie est que le « déluge » est effectivement arrivé — la Révolution française de 1789 a balayé la monarchie seulement 32 ans après la phrase de Pompadour."],
  en:["The phrase is most often attributed to Madame de Pompadour in 1757, consoling Louis XV after the defeat at Rossbach against Prussia.","It reflects 18th-century aristocratic nonchalance — an aristocracy living in luxury while the people suffered from famine and crushing taxes.","The irony is that the 'flood' indeed came — the French Revolution of 1789 swept away the monarchy only 32 years after Pompadour's phrase."],
    es:["«Solo los muertos han visto el final de la guerra» se atribuye erróneamente a Platón — fue escrito por el filósofo George Santayana en 1922.","Santayana también escribió «Aquellos que no recuerdan el pasado están condenados a repetirlo» — una de las citas más citadas en contextos políticos e históricos.","El error de atribución persiste porque dar a Platón la autoría de una frase sobre la guerra le otorga una autoridad milenaria que Santayana, menos conocido, no posee."]
},
'quote29': {
  fr:["Cette citation est en réalité souvent confondue avec une phrase de Leonard Cohen : « There is a crack in everything, that's how the light gets in. »","Hemingway a bien écrit dans L'Adieu aux armes : « Le monde brise chacun d'entre nous, et ensuite, beaucoup sont forts aux endroits brisés. »","Son style « iceberg » consiste à n'écrire que la partie visible d'une histoire — le lecteur doit deviner ce qui se cache sous la surface."],
  en:["This quote is actually often confused with a Leonard Cohen lyric: 'There is a crack in everything, that's how the light gets in.'","Hemingway did write in A Farewell to Arms: 'The world breaks everyone and afterward many are strong at the broken places.'","His 'iceberg' style involves writing only the visible part of a story — the reader must guess what lies beneath the surface."],
    es:["«Sé el cambio que deseas ver en el mundo» se atribuye a Gandhi, pero nunca dijo esta frase exacta — es una paráfrasis simplificada de sus escritos.","Lo que Gandhi escribió es más matizado: que si cambiamos nosotros mismos, cambiamos el mundo, porque somos parte inseparable de él — una idea de transformación interior más profunda que un eslogan.","Las citas simplificadas de grandes pensadores son un fenómeno moderno: reducen ideas complejas a frases compartibles, perdiendo matices esenciales."]
},
'quote30': {
  fr:["Tutu a été archevêque du Cap et a mené le combat contre l'apartheid en Afrique du Sud aux côtés de Nelson Mandela — utilisant la non-violence comme arme.","Après la fin de l'apartheid, il a présidé la Commission Vérité et Réconciliation — un modèle de justice réparatrice unique au monde.","Sa philosophie « ubuntu » (« je suis parce que nous sommes ») résume l'interdépendance humaine — un concept qui a influencé des mouvements sociaux sur tous les continents."],
  en:["Tutu was Archbishop of Cape Town and led the fight against apartheid in South Africa alongside Nelson Mandela — using nonviolence as a weapon.","After apartheid ended, he chaired the Truth and Reconciliation Commission — a unique model of restorative justice.","His 'ubuntu' philosophy ('I am because we are') summarizes human interdependence — a concept that has influenced social movements on every continent."],
    es:["«Ars longa, vita brevis» (El arte es largo, la vida breve) de Hipócrates (siglo V a.C.) no hablaba del arte sino de la medicina: dominar el oficio requiere más tiempo del que dura una vida.","La frase completa incluye: «la oportunidad es fugaz, la experiencia engañosa, el juicio difícil» — un resumen de la condición humana en una sola oración.","La expresión se ha universalizado: se aplica a cualquier disciplina donde la maestría exige décadas de práctica — música, escritura, ciencia, artesanía."]
},


'law21': {
  fr:["Cette loi fait partie d'un ensemble de réglementations vestimentaires thaïlandaises — qui interdisent aussi de conduire torse nu ou pieds nus.","La Thaïlande a aussi une loi de lèse-majesté parmi les plus strictes au monde — critiquer la famille royale peut entraîner jusqu'à 15 ans de prison.","Malgré la loi sur les sous-vêtements, la Thaïlande est l'un des pays les plus tolérants d'Asie sur de nombreux sujets sociaux — les contradictions juridiques y sont fréquentes."],
  en:["This law is part of a set of Thai clothing regulations — which also prohibit driving shirtless or barefoot.","Thailand also has one of the world's strictest lèse-majesté laws — criticizing the royal family can carry up to 15 years in prison.","Despite the underwear law, Thailand is one of Asia's most tolerant countries on many social issues — legal contradictions are common."],
    es:["La navaja de Ockham (siglo XIV) establece que, entre dos explicaciones igualmente válidas, la más simple es probablemente la correcta.","Guillermo de Ockham no buscaba la simplicidad por estética sino por eficacia: las explicaciones innecesariamente complejas introducen más posibilidades de error.","La navaja de Ockham es un principio guía de la ciencia moderna: las teorías más elegantes (E=mc², la selección natural) suelen ser las más poderosas."]
},
'law22': {
  fr:["Cette réglementation remonte au Moyen Âge — le pain était si essentiel que les autorités garantissaient un accès permanent dans chaque quartier.","Aujourd'hui, ce sont les préfets qui fixent les tours de fermeture des boulangeries dans chaque commune — surtout en période estivale.","La France consomme environ 6 milliards de baguettes par an — mais ce chiffre a chuté de 70 % depuis 1900, quand chaque Français mangeait 900 g de pain par jour."],
  en:["This regulation dates back to the Middle Ages — bread was so essential that authorities guaranteed permanent access in every neighborhood.","Today, prefects set bakery closure schedules in each municipality — especially during summer.","France consumes about 6 billion baguettes per year — but this figure has dropped 70% since 1900, when each French person ate 900 g of bread daily."],
    es:["La Ley de los rendimientos decrecientes establece que añadir más de un factor productivo (trabajo, capital) eventualmente produce incrementos cada vez menores de resultado.","El primer fertilizante en un campo mejora mucho la cosecha, el segundo algo menos, el tercero apenas — más allá de cierto punto, añadir más empeora la situación.","Esta ley explica por qué más horas de trabajo no siempre significan más productividad: después de cierto umbral, la fatiga reduce la calidad y la creatividad."]
},
'law23': {
  fr:["L'amende théorique est de 100 euros — mais la loi prévoit des exceptions pour les hôpitaux, les funérailles et les enterrements.","Cette loi remonte à l'époque autrichienne de Milan — les Habsbourg voulaient que la ville projette une image de bonheur et de prospérité.","D'autres villes ont des lois absurdes similaires : à Paris, il est techniquement interdit de poser un avion sur les Champs-Élysées (ordonnance de 1916)."],
  en:["The theoretical fine is €100 — but the law makes exceptions for hospitals, funerals, and burials.","This law dates back to Milan's Austrian era — the Habsburgs wanted the city to project an image of happiness and prosperity.","Other cities have similarly absurd laws: in Paris, it's technically illegal to land a plane on the Champs-Élysées (1916 ordinance)."],
    es:["La Ley de Fitts establece que el tiempo para alcanzar un objetivo con el cursor depende de la distancia al objetivo y de su tamaño — a mayor distancia o menor tamaño, más tiempo.","Esta ley de 1954 es fundamental en diseño de interfaces: los botones importantes deben ser grandes y estar cerca del cursor — es la razón por la que los menús de macOS están en el borde de la pantalla.","Cada vez que un botón te parece fácil de pulsar o un menú se siente intuitivo, probablemente un diseñador ha aplicado la Ley de Fitts sin que lo sepas."]
},
'law24': {
  fr:["Cette loi illustre le problème des « lois zombies » — des textes jamais abrogés qui restent techniquement en vigueur malgré leur absurdité.","L'Oregon a de nombreuses lois étranges : il est aussi interdit de jongler sans licence et de marcher sur le trottoir sur les mains.","Aux États-Unis, chaque État a ses propres lois étranges — en Alabama, il est illégal de porter une fausse moustache à l'église si elle provoque des rires."],
  en:["This law illustrates the problem of 'zombie laws' — statutes never repealed that remain technically valid despite their absurdity.","Oregon has many strange laws: it's also illegal to juggle without a license and to walk on the sidewalk on your hands.","In the US, every state has its own strange laws — in Alabama, it's illegal to wear a fake mustache in church if it causes laughter."],
    es:["La Ley de Dunbar establece que un ser humano puede mantener relaciones sociales estables con un máximo de unas 150 personas.","Robin Dunbar correlacionó el tamaño del neocórtex de los primates con el tamaño de sus grupos sociales y extrapoló para los humanos — 150 aparece en tribus, compañías militares y pueblos tradicionales.","Las redes sociales permiten tener miles de «amigos» pero las investigaciones confirman que el círculo de relaciones significativas sigue siendo de unas 150, con 5 íntimos y 15 cercanos."]
},
'law25': {
  fr:["La section 32 du Salmon Act 1986 vise à combattre le braconnage — « circonstances suspectes » signifie posséder un saumon que l'on sait pêché illégalement.","Le Royaume-Uni est célèbre pour ses lois absurdes : il est techniquement interdit de porter une armure au Parlement (loi de 1313, jamais abrogée).","Le Salmon Act a été cité par Boris Johnson en 2015 comme exemple de surréglementation britannique — il ne l'a cependant pas abrogé."],
  en:["Section 32 of the Salmon Act 1986 aims to combat poaching — 'suspicious circumstances' means possessing salmon you know was illegally caught.","The UK is famous for absurd laws: it's technically illegal to wear armor in Parliament (1313 law, never repealed).","The Salmon Act was cited by Boris Johnson in 2015 as an example of British overregulation — he didn't repeal it though."],
    es:["La Ley de Campbell establece que cuanto más se usa un indicador cuantitativo para tomar decisiones sociales, más sujeto está a la corrupción y más distorsiona los procesos que pretende medir.","Los ránkings universitarios son un ejemplo perfecto: las universidades optimizan los criterios medidos (publicaciones, selectividad) en lugar de mejorar la educación real.","La solución no es eliminar las métricas sino usar múltiples indicadores, cambiarlos periódicamente y complementarlos con evaluaciones cualitativas."]
},
'law26': {
  fr:["Cette loi date de l'époque où les cirques ambulants traversaient la Floride avec leurs éléphants — les villes voulaient s'assurer que les rues restent accessibles.","La Floride est le champion des lois absurdes : il est aussi interdit de chanter en maillot de bain en public et de péter dans un lieu public après 18h le jeudi.","L'État a plus de 30 000 pages de lois sur les animaux — un héritage de l'industrie du spectacle et de la biodiversité exceptionnelle de la Floride."],
  en:["This law dates from when traveling circuses crossed Florida with their elephants — towns wanted to ensure streets remained accessible.","Florida is the champion of absurd laws: it's also illegal to sing in a swimsuit in public and to pass gas in public after 6 PM on Thursdays.","The state has over 30,000 pages of animal laws — a legacy of the entertainment industry and Florida's exceptional biodiversity."],
    es:["La paradoja de Fermi pregunta: si el universo es tan grande y antiguo, ¿dónde están todas las civilizaciones extraterrestres? — formulada por el físico Enrico Fermi en 1950.","Estadísticamente, deberían existir miles de civilizaciones avanzadas en nuestra galaxia — pero no hemos detectado ninguna señal, lo que constituye el «Gran Silencio».","Las explicaciones van desde la hipótesis del «Gran Filtro» (las civilizaciones se autodestruyen) hasta la del «Zoo» (nos observan sin intervenir) — ninguna es satisfactoria."]
},
'law27': {
  fr:["La liste contient environ 7 000 prénoms pour les filles et 7 000 pour les garçons — les parents souhaitant un prénom hors liste doivent obtenir l'approbation d'un comité gouvernemental.","Les prénoms refusés incluent « Monkey », « Anus » et « Pluto » — le comité vérifie que le prénom n'est pas ridicule, offensant ou source de confusion de genre.","L'Islande a un système similaire encore plus strict — le Comité des noms vérifie que chaque prénom peut être décliné selon les quatre cas grammaticaux islandais."],
  en:["The list contains about 7,000 names for girls and 7,000 for boys — parents wanting an unlisted name must get approval from a government committee.","Rejected names include 'Monkey,' 'Anus,' and 'Pluto' — the committee checks that names aren't ridiculous, offensive, or gender-confusing.","Iceland has an even stricter similar system — the Naming Committee verifies each name can be declined according to Iceland's four grammatical cases."],
    es:["La Ley de Say establece que «la oferta crea su propia demanda» — un principio de la economía clásica que Keynes cuestionó durante la Gran Depresión.","Say argumentaba que producir bienes genera los ingresos necesarios para comprarlos — pero Keynes demostró que el ahorro excesivo puede romper este ciclo, causando recesiones.","El debate Say vs Keynes sigue vivo: los liberales confían en el mercado (oferta), los keynesianos en el estímulo estatal (demanda) — la mayoría de las economías modernas combinan ambos enfoques."]
},
'law28': {
  fr:["L'illumination de la Tour Eiffel est une œuvre d'art créée par Pierre Bideau en 1985 — protégée par le droit d'auteur français jusqu'à 70 ans après sa mort.","Photographier la Tour de jour est libre de droit car la structure est dans le domaine public — mais les jeux de lumière ajoutent une couche de propriété intellectuelle.","En pratique, les poursuites sont extrêmement rares pour les particuliers — la SETE (exploitant de la Tour) vise surtout les utilisations commerciales non autorisées."],
  en:["The Eiffel Tower illumination is an artwork created by Pierre Bideau in 1985 — protected by French copyright for 70 years after his death.","Photographing the Tower by day is rights-free since the structure is public domain — but the light show adds an intellectual property layer.","In practice, lawsuits are extremely rare for individuals — SETE (Tower operator) mainly targets unauthorized commercial uses."],
    es:["La Ley de Gresham establece que «la moneda mala expulsa a la buena» — cuando dos monedas coexisten, la gente gasta la de menor valor y acumula la de mayor valor.","En la historia, esto se observó cuando los gobiernos adulteraban las monedas de oro y plata: los ciudadanos guardaban las monedas puras y circulaban las degradadas.","El principio se aplica más allá de la economía: en plataformas digitales, el contenido de baja calidad tiende a expulsar al de alta calidad cuando ambos compiten por la misma atención."]
},
'law29': {
  fr:["La loi Metabo (2008) fixe un tour de taille maximal de 85 cm pour les hommes et 90 cm pour les femmes de plus de 40 ans — les entreprises sont pénalisées si leurs employés dépassent ces limites.","Les entreprises doivent mesurer le tour de taille lors des bilans de santé annuels — les employés en surpoids reçoivent des conseils nutritionnels obligatoires.","Le Japon a l'un des taux d'obésité les plus bas au monde (3,6 %) — la loi Metabo est autant culturelle que médicale, reflétant la valeur de la discipline collective."],
  en:["The Metabo Law (2008) sets a maximum waistline of 85 cm for men and 90 cm for women over 40 — companies are penalized if employees exceed these limits.","Companies must measure waistlines during annual health checkups — overweight employees receive mandatory nutritional counseling.","Japan has one of the world's lowest obesity rates (3.6%) — the Metabo Law is as much cultural as medical, reflecting the value of collective discipline."],
    es:["La Ley de Peter (1969) establece que «en una jerarquía, todo empleado tiende a ascender hasta su nivel de incompetencia» — un principio que explica la mediocridad organizacional.","Un empleado excelente en su puesto es promovido hasta alcanzar un puesto donde no es competente — y allí se queda, porque ya no merece otra promoción.","La solución propuesta es la «inversión de Peter»: promover aleatoriamente produce mejores resultados estadísticos que promover por mérito pasado, porque el talento en un puesto no predice el talento en el siguiente."]
},
'law30': {
  fr:["Le dimanche en Suisse est protégé par des lois fédérales et cantonales très strictes — la tonte, le lavage de voiture et le recyclage du verre sont interdits.","Les machines à laver ne doivent pas fonctionner après 22h en appartement — les règlements de copropriété suisses précisent même les heures de bain autorisées.","La Suisse n'est pas seule : en Allemagne, le « Ruhezeit » (temps de repos) interdit aussi la tonte le dimanche et entre 13h et 15h les jours de semaine."],
  en:["Sundays in Switzerland are protected by strict federal and cantonal laws — mowing, car washing, and glass recycling are all banned.","Washing machines shouldn't run after 10 PM in apartments — Swiss condo rules even specify allowed bathing hours.","Switzerland isn't alone: in Germany, 'Ruhezeit' (rest time) also bans mowing on Sundays and between 1 PM and 3 PM on weekdays."],
    es:["La Ley de Lindy establece que la esperanza de vida futura de una idea, libro o tecnología es proporcional a su edad actual — lo que ha durado mucho probablemente durará mucho más.","Un libro que lleva 200 años imprimiéndose probablemente seguirá otros 200 — mientras que un bestseller reciente tiene menos probabilidades de sobrevivir una generación.","Nassim Taleb popularizó esta idea: la tecnología más antigua (ruedas, libros, lápices) suele ser más robusta que la más reciente — la novedad no implica superioridad."]
},

'tale21': {
  fr:["La légende la plus populaire situe l'origine au 17ᵉ siècle — le capitaine Hendrick van der Decken aurait défié Dieu de doubler le cap de Bonne-Espérance dans une tempête.","Des marins ont rapporté des observations du vaisseau fantôme jusqu'au 20ᵉ siècle — des mirages marins (Fata Morgana) expliquent probablement ces visions.","Richard Wagner s'est inspiré de cette légende pour son opéra « Der fliegende Holländer » (1843) — transformant le capitaine maudit en personnage romantique cherchant la rédemption par l'amour."],
  en:["The most popular legend places the origin in the 17th century — Captain Hendrick van der Decken supposedly defied God to round the Cape of Good Hope in a storm.","Sailors reported sightings of the ghost ship into the 20th century — marine mirages (Fata Morgana) likely explain these visions.","Richard Wagner drew from this legend for his opera 'Der fliegende Holländer' (1843) — transforming the cursed captain into a romantic figure seeking redemption through love."],
    es:["La Bella Durmiente tiene versiones que preceden a Perrault y los Grimm: la más antigua conocida, Sol, Luna y Talía de Basile (1634), es mucho más oscura.","En la versión de Basile, el rey no despierta a la princesa con un beso sino que la viola mientras duerme — ella se despierta nueve meses después al dar a luz gemelos.","La evolución del cuento refleja el cambio de las normas sociales: cada época suaviza los elementos más perturbadores para adaptarlos a su propia sensibilidad moral."]
},
'tale22': {
  fr:["Le Wendigo était une mise en garde morale : dans les hivers glacials canadiens, le cannibalisme était un danger réel — la légende servait à maintenir le tabou.","Les psychiatres ont identifié la « psychose du Wendigo » — une condition rare où une personne se croit en train de se transformer en monstre cannibale.","Le Wendigo est décrit différemment selon les tribus : géant de glace, esprit possesseur ou créature squelettique — mais toujours associé à une faim insatiable."],
  en:["The Wendigo was a moral warning: in freezing Canadian winters, cannibalism was a real danger — the legend maintained the taboo.","Psychiatrists identified 'Wendigo psychosis' — a rare condition where a person believes they're transforming into a cannibal monster.","The Wendigo is described differently across tribes: ice giant, possessing spirit, or skeletal creature — but always associated with insatiable hunger."],
    es:["Los cuentos africanos de Anansi la araña se extendieron por el Caribe y América a través de la trata de esclavos, transformándose en las historias de Brer Rabbit en el sur de EE.UU.","Anansi siempre vence a oponentes más fuertes mediante la astucia — para los esclavos, estas historias eran metáforas de supervivencia y resistencia contra el poder opresor.","Las tradiciones orales africanas transmitían no solo entretenimiento sino conocimiento, historia, valores y estrategias de supervivencia — los cuentos eran bibliotecas vivientes."]
},
'tale23': {
  fr:["Le Basilic était né d'un œuf de coq couvé par un serpent ou un crapaud — une naissance contre-nature qui expliquait sa nature maléfique.","Au Moyen Âge, on croyait que les belettes étaient immunes au regard du Basilic — elles étaient considérées comme son seul ennemi naturel.","J.K. Rowling a repris le Basilic dans Harry Potter et la Chambre des Secrets — le miroir, le reflet dans l'eau et les fantômes sauvaient les victimes de la mort directe."],
  en:["The Basilisk was born from a rooster's egg incubated by a snake or toad — an unnatural birth explaining its evil nature.","In the Middle Ages, weasels were believed immune to the Basilisk's gaze — they were considered its only natural enemy.","J.K. Rowling brought back the Basilisk in Harry Potter and the Chamber of Secrets — mirrors, water reflections, and ghosts saved victims from direct death."],
    es:["Jack y las habichuelas mágicas es un cuento inglés del siglo XVIII donde un niño escala un tallo gigante hasta un castillo en las nubes habitado por un ogro.","Jack roba el oro, la gallina de los huevos de oro y el arpa mágica del ogro — y lo mata cortando el tallo — un héroe moralmente ambiguo que triunfa mediante el robo y el asesinato.","El cuento ha sido interpretado como alegoría de la movilidad social, la conquista de lo imposible y la victoria del ingenio sobre la fuerza bruta."]
},
'tale24': {
  fr:["Dans le roman de J.M. Barrie (1904), Tinker Bell demande aux Garçons perdus d'abattre Wendy à coups de flèches — croyant que Peter le souhaitait.","Barrie a écrit que les fées sont si petites qu'elles n'ont de place que pour un seul sentiment à la fois — Tinker Bell est entièrement jalouse ou entièrement gentille, jamais les deux.","Le nom « Tinker Bell » signifie littéralement « clochette de rétameur » — elle était une fée artisane qui réparait les casseroles, pas la créature gracieuse de Disney."],
  en:["In J.M. Barrie's novel (1904), Tinker Bell asks the Lost Boys to shoot Wendy down with arrows — believing Peter wanted it.","Barrie wrote that fairies are so small they can only hold one feeling at a time — Tinker Bell is entirely jealous or entirely kind, never both.","The name 'Tinker Bell' literally means 'tinker's bell' — she was an artisan fairy who mended pots, not the graceful Disney creature."],
    es:["El flautista de Hamelín (1284) podría basarse en un hecho histórico real: la desaparición de 130 niños de la ciudad alemana de Hameln.","Las teorías incluyen una emigración masiva hacia Europa del Este (colonización germánica), una epidemia de peste, o un reclutamiento forzado de niños para las Cruzadas.","El cuento advierte sobre las consecuencias de no cumplir las promesas: la ciudad no pagó al flautista por librarla de las ratas, y él se llevó a los niños como venganza."]
},
'tale25': {
  fr:["Le Kappa a une cavité remplie d'eau sur le crâne (le « sara ») — si l'eau se renverse, il perd sa force et ne peut plus nuire.","C'est pourquoi s'incliner fonctionne : le Kappa, très poli, rend l'inclination — et renverse ainsi l'eau de sa tête, devenant inoffensif.","Au Japon, des panneaux d'avertissement « Attention aux Kappas » existent encore près de certaines rivières — une manière ludique de prévenir les enfants des dangers de la noyade."],
  en:["The Kappa has a water-filled cavity on its head (the 'sara') — if the water spills, it loses its strength and can no longer harm.","That's why bowing works: the Kappa, very polite, returns the bow — spilling its head water and becoming harmless.","In Japan, 'Beware of Kappa' warning signs still exist near some rivers — a playful way to warn children about drowning dangers."],
    es:["Los hermanos Grimm no inventaron sus cuentos: los recopilaron de tradiciones orales alemanas — aunque los modificaron significativamente para adaptarlos a su público.","Jacob y Wilhelm Grimm eran filólogos y lingüistas que buscaban preservar el folclore germánico — su diccionario de alemán, no los cuentos, era la obra que consideraban más importante.","Las siete ediciones de los Cuentos de los Grimm (1812-1857) muestran una progresiva suavización: madres convertidas en madrastras, violencia atenuada y moralejas reforzadas."]
},
'tale26': {
  fr:["Le mot « rougarou » est une déformation du français « loup-garou » — les Acadiens chassés du Canada ont apporté la légende en Louisiane au 18ᵉ siècle.","Selon la tradition cajun, on devient Rougarou en ne respectant pas le Carême pendant 7 ans consécutifs — la transformation dure 101 jours.","La légende servait à faire respecter les traditions catholiques — les parents menaçaient les enfants désobéissants d'être emportés par le Rougarou dans les bayous."],
  en:["The word 'rougarou' is a corruption of the French 'loup-garou' — Acadians expelled from Canada brought the legend to Louisiana in the 18th century.","According to Cajun tradition, you become a Rougarou by not observing Lent for 7 consecutive years — the transformation lasts 101 days.","The legend served to enforce Catholic traditions — parents threatened disobedient children with being carried off by the Rougarou in the bayous."],
    es:["Pulgarcita de Andersen (1835) narra la historia de una niña diminuta nacida de una flor que pasa por secuestros, matrimonios forzados y penurias antes de encontrar su lugar.","El cuento refleja la vulnerabilidad de los seres pequeños en un mundo dominado por los grandes — y la perseverancia necesaria para encontrar un hogar donde ser aceptado.","Andersen escribía para los marginados, los diferentes y los incomprendidos — sus cuentos más famosos hablan de identidad, pertenencia y la búsqueda de un lugar en el mundo."]
},
'tale27': {
  fr:["La légende raconte que la princesse Dahut ouvrait les portes de la digue chaque nuit pour son amant — jusqu'au soir où la mer a englouti la ville.","Le roi Gradlon, père de Dahut, a survécu en chevauchant les flots sur son cheval Morvarc'h — guidé par Saint Guénolé, il a fondé Quimper.","L'étymologie « Par-Ys » (égal à Ys) pour Paris est probablement une invention folklorique — mais elle illustre le prestige mythique de la cité bretonne."],
  en:["Legend says Princess Dahut opened the dike gates every night for her lover — until one evening the sea swallowed the city.","King Gradlon, Dahut's father, survived by riding the waves on his horse Morvarc'h — guided by Saint Guénolé, he founded Quimper.","The etymology 'Par-Ys' (equal to Ys) for Paris is likely a folk invention — but it illustrates the mythical prestige of the Breton city."],
    es:["Momotarō (el niño melocotón) es el cuento popular más famoso de Japón: un niño nacido de un melocotón gigante parte a derrotar a los oni (demonios) con la ayuda de un perro, un mono y un faisán.","El cuento enseña valores japoneses tradicionales: valentía, lealtad, generosidad y trabajo en equipo — Momotarō recompensa a sus compañeros animales que se unieron a él por su amabilidad.","Momotarō fue usado como propaganda durante la Segunda Guerra Mundial para representar a Japón luchando contra los «demonios» occidentales — un uso político que desnaturalizó un cuento infantil."]
},
'tale28': {
  fr:["La maison de Baba Yaga (l'isba) tourne sur elle-même et n'a ni portes ni fenêtres — le héros doit prononcer une formule magique pour qu'elle se retourne.","Baba Yaga se déplace dans un mortier géant qu'elle dirige avec un pilon — elle efface ses traces avec un balai en bouleau, ancêtre du balai de sorcière.","Elle n'est pas toujours méchante — dans certains contes, Baba Yaga aide le héros en lui donnant des objets magiques, mais seulement après des épreuves."],
  en:["Baba Yaga's house (the izba) spins on itself and has no doors or windows — the hero must speak a magic formula for it to turn around.","Baba Yaga travels in a giant mortar steered with a pestle — she sweeps away her tracks with a birch broom, ancestor of the witch's broomstick.","She isn't always evil — in some tales, Baba Yaga helps the hero by giving magical objects, but only after trials."],
    es:["Baba Yaga es la bruja del folclore eslavo que vive en una cabaña sobre patas de gallina en lo profundo del bosque ruso.","No es simplemente malvada: Baba Yaga puede ayudar o destruir a quien la visita, según su comportamiento — es una guardiana de umbrales entre el mundo de los vivos y el de los muertos.","La cabaña sobre patas de gallina podría basarse en las construcciones elevadas de los pueblos fineses y siberianos, diseñadas para proteger las provisiones de los animales y la humedad."]
},
'tale29': {
  fr:["Les descriptions du Bunyip varient énormément : certains le décrivent comme un chien géant, d'autres comme un phoque à queue de cheval ou un oiseau aquatique monstrueux.","Les paléontologues pensent que la légende pourrait être un « souvenir culturel » du Diprotodon — un marsupial géant de 3 tonnes disparu il y a 25 000 ans.","Les Aborigènes utilisaient le Bunyip pour éloigner les enfants des points d'eau dangereux — une fonction éducative similaire au Kappa japonais."],
  en:["Bunyip descriptions vary enormously: some describe it as a giant dog, others as a horse-tailed seal or a monstrous water bird.","Paleontologists think the legend could be a 'cultural memory' of the Diprotodon — a 3-tonne giant marsupial extinct for 25,000 years.","Aboriginals used the Bunyip to keep children away from dangerous waterways — an educational function similar to the Japanese Kappa."],
    es:["El Popol Vuh maya narra cómo los dioses crearon a los humanos de maíz tras fracasar con el barro y la madera — la humanidad es literalmente «gente de maíz».","Los Héroes Gemelos (Hunahpú e Ixbalanqué) descienden al inframundo (Xibalbá) y vencen a los señores de la muerte mediante juegos, trucos y sacrificio.","El Popol Vuh fue transcrito secretamente por un maya quiché en el siglo XVI para preservar la tradición oral de la destrucción colonial — sin él, gran parte de la cosmología maya se habría perdido."]
},
'tale30': {
  fr:["L'histoire d'Aladin n'apparaît pas dans les manuscrits originaux des Mille et Une Nuits — elle a été ajoutée par le traducteur français Antoine Galland en 1710.","Galland a entendu l'histoire d'un conteur syrien, Hanna Diyab, à Paris — Diyab mérite autant de crédit que Galland, mais est resté oublié pendant 300 ans.","La « Chine » du conte est probablement un lieu imaginaire et lointain pour le conteur — les descriptions correspondent davantage à une ville du Moyen-Orient qu'à la Chine réelle."],
  en:["Aladdin's story doesn't appear in the original Thousand and One Nights manuscripts — it was added by French translator Antoine Galland in 1710.","Galland heard the story from a Syrian storyteller, Hanna Diyab, in Paris — Diyab deserves as much credit as Galland but was forgotten for 300 years.","The 'China' in the tale is likely an imaginary, distant place for the storyteller — descriptions match a Middle Eastern city more than actual China."],
    es:["Los cuentos de Sheherezade en Las Mil y Una Noches son el ejemplo más famoso de narrativa como supervivencia: contar historias literalmente le salva la vida noche tras noche.","El poder de la narración es un tema universal: desde las fogatas prehistóricas hasta los podcasts modernos, contar historias es la forma más antigua y eficaz de transmitir conocimiento y emociones.","Las Mil y Una Noches influyeron en la literatura mundial: Borges, Proust, Rushdie y García Márquez reconocieron su deuda con la estructura y la magia narrativa de Sheherezade."]
},


'dino21': {
  fr:["Malgré ses griffes terrifiantes, le Therizinosaurus était probablement herbivore — les griffes servaient à tirer des branches vers sa bouche, comme un paresseux géant.","Il mesurait environ 10 mètres de long et pesait 5 tonnes — l'un des plus grands théropodes, mais avec un mode de vie paisible.","Ses griffes sont les plus longues de tous les animaux ayant jamais vécu — dépassant même celles des Megaraptor (35 cm)."],
  en:["Despite its terrifying claws, Therizinosaurus was likely herbivorous — the claws were used to pull branches toward its mouth, like a giant sloth.","It measured about 10 meters long and weighed 5 tonnes — one of the largest theropods but with a peaceful lifestyle.","Its claws are the longest of any animal that ever lived — exceeding even Megaraptor's (35 cm)."],
    es:["Los raptores (dromeosaurios) cazaban con una garra retráctil en forma de hoz en cada pie, usada para apuñalar y desgarrar a sus presas.","El Utahraptor, el mayor raptor conocido (7 metros de largo), tenía garras de hasta 24 cm — era un depredador formidable del Cretácico temprano.","Evidencias fósiles sugieren que algunos raptores cazaban en grupo: un fósil de Deinonychus fue encontrado junto a un Tenontosaurus, sugiriendo un ataque coordinado."]
},
'dino22': {
  fr:["Le Sinosauropteryx a été le premier dinosaure dont on a déterminé la couleur en 2010 — il était roux avec une queue rayée blanc et orange.","L'Anchiornis avait un plumage noir, blanc et rouge détaillé au niveau cellulaire — comme un pic-bois préhistorique.","Le Microraptor avait des plumes irisées comme celles d'un corbeau — la première preuve de coloration structurelle chez un dinosaure, pas seulement pigmentaire."],
  en:["Sinosauropteryx was the first dinosaur whose color was determined in 2010 — it was reddish with a white and orange striped tail.","Anchiornis had detailed black, white, and red plumage at the cellular level — like a prehistoric woodpecker.","Microraptor had iridescent feathers like a crow's — the first evidence of structural coloring in a dinosaur, not just pigment-based."],
    es:["Los dinosaurios no eran todos enormes: el Microraptor medía solo 77 cm y pesaba 1 kg — tenía cuatro alas con plumas y planeaba entre los árboles como una ardilla voladora.","El Compsognathus, del tamaño de un pollo, fue uno de los dinosaurios más pequeños — su velocidad y agilidad le permitían cazar insectos y pequeños lagartos.","La diversidad de tamaños era inmensa: desde el Microraptor de 1 kg hasta el Argentinosaurus de 70 toneladas, un rango de masa corporal incomparable en la historia de los vertebrados."]
},
'dino23': {
  fr:["Son dôme crânien de 25 cm d'os solide a longtemps été interprété comme une arme de combat — les mâles se seraient chargés tête contre tête comme des béliers.","Des études récentes suggèrent que le dôme était trop fragile pour encaisser des chocs frontaux — il servait peut-être plutôt à des coups latéraux sur les flancs des rivaux.","D'autres hypothèses proposent que le dôme servait à la reconnaissance d'espèce ou à la séduction — comme les cornes colorées des caméléons modernes."],
  en:["Its 25 cm solid bone dome was long interpreted as a combat weapon — males supposedly charged head-to-head like rams.","Recent studies suggest the dome was too fragile for frontal impacts — it may have been used for lateral flank strikes against rivals.","Other hypotheses propose the dome served for species recognition or mating display — like modern chameleons' colored horns."],
    es:["El desierto de Gobi (Mongolia) es uno de los yacimientos de dinosaurios más ricos del mundo: allí se descubrieron los primeros nidos, el Velociraptor y el Protoceratops.","El famoso fósil de los «dinosaurios luchando» muestra un Velociraptor y un Protoceratops atrapados en combate mortal, preservados por una tormenta de arena hace 80 millones de años.","Las expediciones de Roy Chapman Andrews al Gobi en los años 1920 inspiraron el personaje de Indiana Jones — Andrews era un aventurero y explorador que desafió desiertos, bandidos y tormentas."]
},
'dino24': {
  fr:["Le Giganotosaurus mesurait 13 mètres de long — environ 1 mètre de plus que le T-Rex — mais son cerveau ne pesait que 275 grammes.","Son crâne de 1,6 mètre de long était plus allongé que celui du T-Rex — avec des dents plus fines, adaptées à trancher plutôt qu'à broyer les os.","Il vivait en Argentine il y a 95 millions d'années et chassait probablement des sauropodes géants comme l'Argentinosaurus — en attaques coordonnées."],
  en:["Giganotosaurus measured 13 meters long — about 1 meter more than T-Rex — but its brain weighed only 275 grams.","Its 1.6-meter skull was more elongated than T-Rex's — with thinner teeth adapted for slicing rather than crushing bones.","It lived in Argentina 95 million years ago and likely hunted giant sauropods like Argentinosaurus — in coordinated attacks."],
    es:["Los dinosaurios polares existían: fósiles de dinosaurios se han encontrado en Alaska y en la Antártida, regiones que en el Mesozoico eran boscosas pero experimentaban meses de oscuridad.","Estos dinosaurios probablemente eran de sangre caliente (endotermos) o al menos tenían un metabolismo más alto que los reptiles actuales para sobrevivir a las bajas temperaturas y la oscuridad invernal.","El debate sobre la termorregulación de los dinosaurios ha evolucionado: la mayoría de los paleontólogos creen ahora que eran mesotermos (entre sangre fría y caliente), como los atunes actuales."]
},
'dino25': {
  fr:["Les ptérosaures formaient un ordre distinct appelé Pterosauria — ils sont les premiers vertébrés à avoir développé le vol actif, 75 millions d'années avant les oiseaux.","Le Quetzalcoatlus, le plus grand ptérosaure, avait une envergure de 10 à 12 mètres — comparable à un petit avion, c'est le plus grand animal volant de tous les temps.","Les ptérosaures marchaient à quatre pattes au sol, utilisant leurs ailes repliées comme des béquilles — des traces de pas fossiles le confirment."],
  en:["Pterosaurs formed a distinct order called Pterosauria — they were the first vertebrates to develop active flight, 75 million years before birds.","Quetzalcoatlus, the largest pterosaur, had a 10 to 12-meter wingspan — comparable to a small plane, the largest flying animal ever.","Pterosaurs walked on all fours on the ground, using their folded wings as crutches — fossil footprints confirm this."],
    es:["El ámbar báltico y birmano ha preservado plumas de dinosaurios con un detalle microscópico extraordinario — incluyendo la cola emplumada de un celurosaurio de 99 millones de años.","Desgraciadamente, extraer ADN de dinosaurios del ámbar es imposible: el ADN se degrada completamente en menos de 7 millones de años — Jurassic Park seguirá siendo ficción.","Sin embargo, las proteínas fósiles son más resistentes que el ADN: colágeno de T. rex de 68 millones de años ha sido identificado, revelando parentesco molecular con las aves actuales."]
},
'dino26': {
  fr:["Le mythe du « deuxième cerveau » vient d'une cavité découverte dans les vertèbres sacrées du Stegosaurus — 20 fois plus grande que son cerveau crânien.","Les paléontologues pensent aujourd'hui que cette cavité contenait un glycogen body — un amas de tissu nerveux stockant de l'énergie, présent aussi chez les oiseaux modernes.","Le cerveau du Stegosaurus pesait environ 75 grammes pour un animal de 5 tonnes — le ratio cerveau/corps le plus faible de tous les dinosaures."],
  en:["The 'second brain' myth comes from a cavity found in Stegosaurus sacral vertebrae — 20 times larger than its cranial brain.","Paleontologists now think this cavity contained a glycogen body — a nerve tissue mass storing energy, also present in modern birds.","The Stegosaurus brain weighed about 75 grams for a 5-tonne animal — the lowest brain-to-body ratio of all dinosaurs."],
    es:["El Pachycephalosaurus tenía un cráneo con una cúpula ósea de 25 cm de espesor — durante décadas se creyó que la usaba para golpearse cabeza contra cabeza como las cabras monteses.","Estudios recientes sugieren que la cúpula era demasiado frágil para impactos frontales: probablemente la usaba para golpear los flancos de rivales o como exhibición visual.","Muchos dinosaurios con crestas, cuernos y ornamentos craneales los usaban principalmente para el reconocimiento entre especies y la selección sexual, no para el combate."]
},
'dino27': {
  fr:["L'astéroïde de Chicxulub (10 km de diamètre) a frappé le Yucatán il y a 66 millions d'années — créant un cratère de 180 km et un tsunami de 1 500 mètres.","L'impact a projeté des milliards de tonnes de poussière dans l'atmosphère, bloquant le Soleil pendant des mois — la photosynthèse s'est arrêtée, entraînant l'effondrement des chaînes alimentaires.","Les survivants incluaient les petits mammifères, les oiseaux (descendants directs des dinosaures), les crocodiliens et les tortues — la petite taille et la capacité à hiberner ont été des avantages décisifs."],
  en:["The Chicxulub asteroid (10 km diameter) struck the Yucatán 66 million years ago — creating a 180 km crater and a 1,500-meter tsunami.","The impact hurled billions of tonnes of dust into the atmosphere, blocking the Sun for months — photosynthesis stopped, collapsing food chains.","Survivors included small mammals, birds (direct dinosaur descendants), crocodilians, and turtles — small size and hibernation ability were decisive advantages."],
    es:["Los terópodos evolucionaron desde los dinosaurios carnívoros bípedos del Triásico hasta las aves modernas — una transición documentada por cientos de fósiles intermedios.","La transición incluye la miniaturización progresiva, el desarrollo de plumas, la fusión de huesos, la reducción de la cola y la aparición del esternón quillado para el vuelo.","Las aves son dinosaurios: taxonómicamente, un gorrión está más emparentado con un T. rex que un T. rex con un Triceratops — una realidad que desafía la intuición pero es sólida científicamente."]
},
'dino28': {
  fr:["Le Dreadnoughtus a été découvert en 2005 en Patagonie par le paléontologue Kenneth Lacovara — il a fallu 4 ans pour extraire les 145 os du site.","Son nom signifie « qui ne craint rien » — un adulte de cette taille n'avait probablement aucun prédateur naturel.","Avec 70 % de son squelette retrouvé, c'est le titanosaure le plus complet jamais découvert — permettant des estimations de masse plus fiables que pour d'autres géants."],
  en:["Dreadnoughtus was discovered in 2005 in Patagonia by paleontologist Kenneth Lacovara — it took 4 years to extract the 145 bones from the site.","Its name means 'fears nothing' — an adult of this size likely had no natural predators.","With 70% of its skeleton recovered, it's the most complete titanosaur ever found — allowing more reliable mass estimates than for other giants."],
    es:["Los coprolitos (heces fosilizadas) de dinosaurios revelan su dieta: restos de plantas, huesos triturados, escamas de pez e incluso parásitos intestinales.","Un coprolito de T. rex encontrado en Saskatchewan contenía fragmentos de hueso de un ceratópsido joven — evidencia directa de que trituraba huesos, algo que su dentición ya sugería.","Los coprolitos también revelan los ecosistemas: el tipo de plantas digeridas indica el clima, la altitud y la estación del año en que vivió el dinosaurio."]
},
'dino29': {
  fr:["Les plésiosaures avaient un long cou et quatre nageoires — ils respiraient de l'air et devaient remonter à la surface, comme les baleines actuelles.","Les mosasaures étaient des lézards marins géants, plus proches des varans que des dinosaures — le plus grand, le Mosasaurus, atteignait 17 mètres.","Les ichtyosaures ressemblaient à des dauphins — un cas remarquable de convergence évolutive entre reptiles marins et mammifères marins, séparés par 200 millions d'années."],
  en:["Plesiosaurs had long necks and four flippers — they breathed air and had to surface, like modern whales.","Mosasaurs were giant marine lizards, closer to monitor lizards than dinosaurs — the largest, Mosasaurus, reached 17 meters.","Ichthyosaurs resembled dolphins — a remarkable case of convergent evolution between marine reptiles and marine mammals, separated by 200 million years."],
    es:["La paleontología de dinosaurios se ha diversificado enormemente: China ha aportado más especies nuevas que cualquier otro país en las últimas dos décadas.","La formación de Yixian (provincia de Liaoning) ha producido cientos de fósiles extraordinarios de dinosaurios emplumados, aves primitivas y mamíferos del Cretácico temprano.","La democratización de la paleontología ha permitido que países como Argentina, Marruecos, Mongolia y Brasil hagan descubrimientos que transforman nuestra comprensión de la evolución de los dinosaurios."]
},
'dino30': {
  fr:["Les bras du Carnotaurus sont si petits qu'ils ne pouvaient même pas atteindre sa bouche — ils n'avaient probablement aucune fonction pratique et étaient en voie de disparition.","En revanche, ses jambes étaient parmi les plus puissantes des théropodes — il était probablement l'un des prédateurs bipèdes les plus rapides, atteignant 50 km/h.","Le Carnotaurus est le seul grand théropode connu avec des cornes au-dessus des yeux — qui servaient peut-être au combat entre mâles ou à la parade nuptiale."],
  en:["Carnotaurus arms were so small they couldn't even reach its mouth — they likely had no practical function and were vestigial.","In contrast, its legs were among the most powerful of theropods — it was likely one of the fastest bipedal predators, reaching 50 km/h.","Carnotaurus is the only known large theropod with horns above the eyes — possibly used for male combat or courtship display."],
    es:["Los dinosaurios no se extinguieron: hay más de 10 000 especies de aves vivas, todas descendientes directas de los terópodos — técnicamente, los dinosaurios siguen entre nosotros.","Un pollo comparte más ADN con un T. rex que un T. rex con un Triceratops — la clasificación moderna coloca a las aves dentro del clado Dinosauria.","La próxima vez que veas un gorrión, un cuervo o un colibrí, recuerda que estás observando a un dinosaurio vivo: 66 millones de años de evolución, pero dinosaurio al fin y al cabo."]
}
});

Object.assign(DEEP_DIVES, {
  'rel1': {
    fr:["Le Vatican possède la plus petite armée du monde : la Garde suisse, composée de 135 soldats citoyens suisses, qui protège le pape depuis 1506.","Le Vatican a sa propre pharmacie, considérée comme la plus ancienne du monde encore en activité, et son propre observatoire astronomique fondé en 1891.","L'économie du Vatican repose principalement sur les dons des fidèles, les revenus des musées (6 millions de visiteurs par an) et la vente de timbres et souvenirs."],
    en:["The Vatican has the smallest army in the world: the Swiss Guard, made up of 135 Swiss citizens, protecting the pope since 1506.","The Vatican has its own pharmacy, considered the oldest still in operation in the world, and its own astronomical observatory founded in 1891.","The Vatican's economy relies mainly on donations from the faithful, museum revenues (6 million visitors per year), and the sale of stamps and souvenirs."],
    es:["El cristianismo es la religión más extendida del mundo con unos 2 400 millones de fieles, repartidos entre catolicismo, protestantismo y ortodoxia.","Nació como una secta judía en la Palestina romana del siglo I y se convirtió en religión oficial del Imperio Romano en el 380 d.C. bajo el emperador Teodosio.","La Biblia cristiana es el libro más traducido de la historia (más de 700 idiomas completos) y el más vendido con más de 5 000 millones de ejemplares distribuidos."]
  },
  'rel2': {
    fr:["Le swastika bouddhiste tourne dans le sens inverse des aiguilles d'une montre (卍), tandis que le symbole nazi tournait dans le sens horaire (卐) — une différence cruciale.","Ce symbole apparaît dans les ruines de Troie, sur des poteries grecques antiques, dans les catacombes chrétiennes et même chez les Amérindiens Navajos.","Après la Seconde Guerre mondiale, plusieurs pays asiatiques ont dû expliquer aux touristes occidentaux que le swastika sur leurs temples n'avait aucun lien avec le nazisme."],
    en:["The Buddhist swastika rotates counterclockwise (卍), while the Nazi symbol rotated clockwise (卐) — a crucial difference.","This symbol appears in the ruins of Troy, on ancient Greek pottery, in Christian catacombs, and even among the Navajo people of North America.","After World War II, several Asian countries had to explain to Western tourists that the swastika on their temples had no connection to Nazism."],
    es:["El islam, con unos 1 900 millones de fieles, es la segunda religión del mundo y la de más rápido crecimiento — se prevé que iguale al cristianismo hacia 2060.","Fundado por el profeta Mahoma en el siglo VII en Arabia, el islam se basa en cinco pilares: la profesión de fe, la oración (5 veces al día), la limosna, el ayuno del Ramadán y la peregrinación a La Meca.","El Corán, texto sagrado del islam, fue revelado en árabe y los musulmanes consideran que solo puede ser plenamente comprendido en esa lengua — las traducciones se consideran interpretaciones."]
  },
  'rel3': {
    fr:["Chaque soir, le Guru Granth Sahib est transporté en procession vers une chambre spéciale appelée Akal Takht, accompagné de chants et d'un éventail cérémoniel.","Le livre contient 1 430 pages, et chaque copie doit être identique — une seule erreur de transcription rend le livre impropre au culte.","Quand un Guru Granth Sahib est trop usé pour être utilisé, il est « crémé » lors d'une cérémonie funéraire similaire à celle d'un être humain."],
    en:["Each evening, the Guru Granth Sahib is carried in procession to a special chamber called the Akal Takht, accompanied by hymns and a ceremonial fan.","The book contains 1,430 pages, and every copy must be identical — a single transcription error renders the book unfit for worship.","When a Guru Granth Sahib becomes too worn for use, it is 'cremated' in a funeral ceremony similar to that of a human being."],
    es:["El hinduismo, con más de 1 200 millones de seguidores, es la religión organizada más antigua del mundo, con textos (los Vedas) que datan de al menos 1500 a.C.","No tiene un fundador único ni un dogma central: es un conjunto de tradiciones filosóficas, rituales y espirituales que comparten conceptos como karma, dharma, samsara y moksha.","El hinduismo reconoce miles de deidades que son manifestaciones de una realidad última (Brahman) — las tres principales son Brahma (creador), Vishnu (preservador) y Shiva (destructor/transformador)."]
  },
  'rel4': {
    fr:["Abraham est appelé Ibrahim dans le Coran, Avraham dans la Torah, et Abraham dans la Bible — trois noms pour une même figure fondatrice.","Jérusalem est sacrée pour les trois religions : le Mur des Lamentations (judaïsme), le Saint-Sépulcre (christianisme) et le Dôme du Rocher (islam) sont à quelques centaines de mètres les uns des autres.","Les trois religions partagent aussi des figures comme Moïse, Noé et Adam, mais les récits diffèrent parfois considérablement d'un texte à l'autre."],
    en:["Abraham is called Ibrahim in the Quran, Avraham in the Torah, and Abraham in the Bible — three names for the same founding figure.","Jerusalem is sacred to all three religions: the Western Wall (Judaism), the Church of the Holy Sepulchre (Christianity), and the Dome of the Rock (Islam) are just a few hundred meters apart.","All three religions also share figures like Moses, Noah, and Adam, though the narratives sometimes differ considerably between texts."],
    es:["El budismo fue fundado por Siddhartha Gautama (el Buda) en la India del siglo V a.C. tras alcanzar la iluminación bajo un árbol bodhi a los 35 años.","Las Cuatro Nobles Verdades son su base: la vida es sufrimiento (dukkha), el sufrimiento nace del deseo, el cese del deseo libera del sufrimiento, y el camino es el Noble Óctuple Sendero.","El budismo no requiere fe en un dios creador: es más una filosofía práctica que una religión teísta — su objetivo es liberar al individuo del ciclo de renacimientos (samsara)."]
  },
  'rel5': {
    fr:["Ce phénomène s'appelle le « syncrétisme religieux » — le Japon compte environ 80 000 sanctuaires shinto et 77 000 temples bouddhistes, souvent côte à côte.","Lors du recensement, la somme des fidèles déclarés dépasse largement la population totale du Japon, car beaucoup se comptent dans plusieurs religions à la fois.","Noël est aussi très populaire au Japon, non comme fête religieuse, mais comme événement romantique — les couples vont au restaurant et s'offrent des cadeaux."],
    en:["This phenomenon is called 'religious syncretism' — Japan has about 80,000 Shinto shrines and 77,000 Buddhist temples, often side by side.","In censuses, the total number of declared believers far exceeds Japan's total population, as many people count themselves in multiple religions simultaneously.","Christmas is also very popular in Japan, not as a religious holiday, but as a romantic event — couples go to restaurants and exchange gifts."],
    es:["El judaísmo, con unos 15 millones de practicantes, es la más antigua de las tres grandes religiones abrahámicas (judaísmo, cristianismo, islam).","La Torá (cinco libros de Moisés) es el texto sagrado central, complementado por el Talmud — una vasta colección de comentarios, debates y leyes rabínicas.","El judaísmo ha influido desproporcionadamente en la civilización occidental: el monoteísmo, los Diez Mandamientos, el concepto de justicia social y el día de descanso semanal son legados judíos."]
  },
  'rel6': {
    fr:["Le langar (cuisine communautaire) du Temple d'Or fonctionne 24h/24 grâce à environ 300 bénévoles par roulement qui épluchent, cuisinent et servent sans interruption.","Le système est si efficace que l'armée indienne l'a étudié comme modèle logistique pour nourrir des populations en situation de crise.","Aucune question n'est posée aux visiteurs : riches ou pauvres, croyants ou non, tout le monde s'assoit par terre côte à côte — symbole d'égalité absolue."],
    en:["The langar (community kitchen) at the Golden Temple operates 24/7 with about 300 rotating volunteers who peel, cook, and serve without interruption.","The system is so efficient that the Indian army has studied it as a logistics model for feeding populations in crisis situations.","No questions are asked of visitors: rich or poor, believers or not, everyone sits on the floor side by side — a symbol of absolute equality."],
    es:["El sintoísmo es la religión indígena de Japón, basada en la veneración de los kami (espíritus de la naturaleza, ancestros y fenómenos naturales).","No tiene fundador, escrituras sagradas centrales ni dogma moral fijo — es una práctica ritual centrada en la pureza, la armonía con la naturaleza y el respeto a los ancestros.","La mayoría de los japoneses practican simultáneamente el sintoísmo y el budismo: nacen sintoístas y mueren budistas, una coexistencia religiosa rara en el mundo."]
  },
  'rel7': {
    fr:["Le zoroastrisme a directement influencé le judaïsme pendant l'exil de Babylone (VIᵉ siècle av. J.-C.), et par extension le christianisme et l'islam.","Freddie Mercury, le chanteur de Queen, était zoroastrien — ses funérailles ont été célébrées selon les rites de cette religion antique.","Il ne reste aujourd'hui qu'environ 120 000 zoroastriens dans le monde, principalement en Inde (les Parsis) et en Iran."],
    en:["Zoroastrianism directly influenced Judaism during the Babylonian exile (6th century BCE), and by extension Christianity and Islam.","Freddie Mercury, the Queen singer, was Zoroastrian — his funeral was conducted according to the rites of this ancient religion.","Only about 120,000 Zoroastrians remain in the world today, mainly in India (the Parsis) and Iran."],
    es:["El sijismo, fundado por Guru Nanak en el Punjab (India) en el siglo XV, cuenta con unos 30 millones de seguidores y es la quinta religión más grande del mundo.","Los sijs creen en un único Dios sin forma, en la igualdad de todos los seres humanos y en el servicio comunitario — sus templos (gurdwaras) ofrecen comida gratis a cualquier persona.","Los cinco artículos de fe (las cinco K) incluyen el kesh (cabello sin cortar, cubierto por un turbante), el kara (brazalete de acero) y el kirpan (daga ceremonial)."]
  },
  'rel8': {
    fr:["Les moines jaïns digambara (« vêtus de ciel ») pratiquent la nudité totale comme forme de renoncement — ils ne possèdent littéralement rien, pas même des vêtements.","Le jaïnisme pousse le principe de non-violence si loin que certains fidèles balaient le sol devant eux en marchant pour éviter d'écraser un insecte.","Cette religion compte environ 4,5 millions de fidèles, presque tous en Inde, mais elle a une influence culturelle disproportionnée par rapport à sa taille."],
    en:["Digambara Jain monks ('sky-clad') practice total nudity as a form of renunciation — they literally own nothing, not even clothing.","Jainism takes the principle of non-violence so far that some devotees sweep the ground before them while walking to avoid crushing an insect.","This religion has about 4.5 million followers, almost all in India, but it has a cultural influence disproportionate to its size."],
    es:["El Ramadán es el mes sagrado del islam durante el cual los musulmanes ayunan desde el amanecer hasta el atardecer — unos 1 900 millones de personas participan cada año.","El ayuno (sawm) no es solo privación de comida y bebida: incluye abstinencia de tabaco, relaciones sexuales y comportamientos negativos como la mentira y la ira.","El iftar (comida para romper el ayuno al anochecer) es un momento comunitario y festivo — las familias y vecinos se reúnen, y los más ricos ofrecen comida a los necesitados."]
  },
  'rel9': {
    fr:["La Bible a été traduite en plus de 3 500 langues, ce qui en fait de loin le livre le plus traduit de l'histoire humaine.","Le livre le plus court de la Bible est la Deuxième Épître de Jean, avec seulement 13 versets — on peut le lire en moins d'une minute.","Les hôtels Gideon placent des Bibles dans les chambres depuis 1908 — ils en ont distribué plus de 2 milliards dans 200 pays."],
    en:["The Bible has been translated into over 3,500 languages, making it by far the most translated book in human history.","The shortest book of the Bible is the Second Epistle of John, with only 13 verses — it can be read in under a minute.","Gideon hotels have been placing Bibles in rooms since 1908 — they have distributed over 2 billion copies in 200 countries."],
    es:["La Reforma Protestante comenzó en 1517 cuando Martín Lutero clavó sus 95 tesis en la puerta de la iglesia de Wittenberg, cuestionando la venta de indulgencias por la Iglesia Católica.","Lutero argumentaba que la salvación se obtiene solo por la fe (sola fide) y la Escritura (sola scriptura), no por las obras ni la mediación de la Iglesia.","La Reforma fragmentó el cristianismo occidental en miles de denominaciones (luteranos, calvinistas, anglicanos, bautistas, metodistas) y provocó guerras religiosas que devastaron Europa durante un siglo."]
  },
  'rel10': {
    fr:["Le chiffre 108 apparaît aussi en astronomie : la distance Terre-Soleil est environ 108 fois le diamètre du Soleil, et la distance Terre-Lune environ 108 fois le diamètre de la Lune.","Dans le yoga, la salutation au soleil est traditionnellement répétée 108 fois lors de célébrations spéciales comme les changements de saison.","En arts martiaux japonais, certaines formes de karaté comportent exactement 108 mouvements, héritage direct de l'influence bouddhiste."],
    en:["The number 108 also appears in astronomy: the Earth-Sun distance is about 108 times the Sun's diameter, and the Earth-Moon distance about 108 times the Moon's diameter.","In yoga, the sun salutation is traditionally repeated 108 times during special celebrations like seasonal changes.","In Japanese martial arts, certain karate forms contain exactly 108 movements, a direct legacy of Buddhist influence."],
    es:["La meditación es una práctica común a muchas tradiciones espirituales: el budismo (vipassana, zen), el hinduismo (yoga, mantra), el islam (dhikr), el cristianismo (contemplación) y el judaísmo (hitbodedut).","Estudios neurocientíficos confirman que la meditación regular modifica la estructura del cerebro: aumenta la materia gris en áreas de atención y empatía, y reduce la actividad de la amígdala (estrés).","El mindfulness occidental, derivado de la meditación budista, se ha extendido a hospitales, escuelas y empresas — un fenómeno de secularización de prácticas religiosas milenarias."]
  },
  'rel11': {
    fr:["Les plus jeunes hafiz ont parfois seulement 5 ou 6 ans — ils mémorisent les 6 236 versets du Coran répartis sur 604 pages en arabe classique.","La mémorisation se fait généralement en 2 à 5 ans, avec un système de révision quotidienne pour ne jamais oublier un seul verset.","Dans certains pays, les hafiz portent un turban spécial ou un titre honorifique, et bénéficient d'un statut social particulier dans leur communauté."],
    en:["The youngest hafiz are sometimes only 5 or 6 years old — they memorize all 6,236 verses of the Quran spread across 604 pages in classical Arabic.","Memorization typically takes 2 to 5 years, with a daily revision system to never forget a single verse.","In some countries, hafiz wear a special turban or honorary title, and enjoy a special social status in their community."],
    es:["Los Diez Mandamientos, compartidos por el judaísmo y el cristianismo, establecen reglas éticas fundamentales: no matar, no robar, no mentir, honrar a los padres.","Según la Biblia, fueron entregados por Dios a Moisés en el monte Sinaí, grabados en tablas de piedra — un momento fundacional de la ley moral occidental.","Los Mandamientos influyeron en los códigos legales occidentales durante milenios — la separación entre ley religiosa y civil es un logro relativamente reciente de la Ilustración."]
  },
  'rel12': {
    fr:["Le mont Athos abrite 20 monastères habités par environ 2 000 moines qui vivent selon le calendrier julien, avec 13 jours de décalage par rapport au calendrier civil.","L'interdiction des femmes (l'avaton) s'étend même aux animaux femelles domestiques — seules les poules sont tolérées car elles fournissent les œufs pour la peinture des icônes.","Pour visiter le mont Athos, il faut obtenir un diamonitirion (permis spécial), limité à 10 visiteurs orthodoxes et 10 non-orthodoxes par jour."],
    en:["Mount Athos houses 20 monasteries inhabited by about 2,000 monks who live according to the Julian calendar, 13 days behind the civil calendar.","The ban on women (the avaton) extends even to female domestic animals — only hens are tolerated because they provide eggs for icon painting.","To visit Mount Athos, you must obtain a diamonitirion (special permit), limited to 10 Orthodox and 10 non-Orthodox visitors per day."],
    es:["La Meca, en Arabia Saudita, es la ciudad más sagrada del islam: hacia ella rezan los musulmanes cinco veces al día y a ella peregrinan al menos una vez en la vida (hajj).","La Kaaba, el cubo negro en el centro de la Gran Mezquita, es la estructura más sagrada del islam — según la tradición, fue construida por Abraham e Ismael.","El hajj anual reúne a más de 2 millones de peregrinos de todo el mundo: es la mayor reunión anual de seres humanos y un símbolo de la igualdad ante Dios."]
  },
  'rel13': {
    fr:["Le Bouddha historique, Siddhartha Gautama, était un prince indien né au Népal vers 563 av. J.-C. qui a renoncé à sa vie de luxe pour chercher l'illumination.","Le bouddhisme s'est divisé en trois branches principales : le Theravada (Asie du Sud-Est), le Mahayana (Chine, Japon, Corée) et le Vajrayana (Tibet, Mongolie).","Avec environ 500 millions de pratiquants, le bouddhisme est la quatrième religion mondiale, mais il est en forte croissance en Occident depuis les années 1960."],
    en:["The historical Buddha, Siddhartha Gautama, was an Indian prince born in Nepal around 563 BCE who renounced his life of luxury to seek enlightenment.","Buddhism has divided into three main branches: Theravada (Southeast Asia), Mahayana (China, Japan, Korea), and Vajrayana (Tibet, Mongolia).","With about 500 million practitioners, Buddhism is the world's fourth-largest religion, but it has been growing strongly in the West since the 1960s."],
    es:["El concepto de karma existe en el hinduismo, el budismo, el jainismo y el sijismo: cada acción tiene consecuencias que afectan a la presente y a las futuras vidas.","El karma no es un sistema de castigo divino sino una ley natural de causa y efecto: las acciones positivas generan frutos positivos, y viceversa.","En Occidente, el karma se ha simplificado como «lo que va, vuelve», perdiendo su complejidad filosófica original — en el budismo, por ejemplo, la intención detrás de la acción es más importante que la acción misma."]
  },
  'rel14': {
    fr:["Deux fois par an, les notes sont soigneusement retirées par les rabbins du Mur et enterrées au cimetière du mont des Oliviers, car elles contiennent le nom de Dieu.","Le Mur des Lamentations n'est pas le mur du Temple lui-même, mais un mur de soutènement de l'esplanade sur laquelle le Temple se dressait.","Depuis 2009, on peut envoyer des prières par e-mail ou fax au Mur — des bénévoles les impriment et les glissent entre les pierres."],
    en:["Twice a year, the notes are carefully removed by the Wall's rabbis and buried at the Mount of Olives cemetery, as they contain the name of God.","The Western Wall is not actually a wall of the Temple itself, but a retaining wall of the platform on which the Temple once stood.","Since 2009, you can send prayers by email or fax to the Wall — volunteers print them and tuck them between the stones."],
    es:["El Vaticano, sede de la Iglesia Católica, es el estado independiente más pequeño del mundo: 0,44 km² con unos 800 habitantes.","El papa es a la vez jefe de Estado del Vaticano y líder espiritual de los 1 400 millones de católicos del mundo — una doble función única en la política mundial.","La Capilla Sixtina, con los frescos de Miguel Ángel, es tanto una obra maestra del arte como un lugar sagrado: en ella se celebran los cónclaves para elegir al nuevo papa."]
  },
  'rel15': {
    fr:["L'expression « 33 millions de dieux » vient d'une traduction ambiguë du sanskrit « trayastrimsati koti » où « koti » peut signifier « type » ou « million ».","Les trois divinités principales de l'hindouisme forment la Trimurti : Brahma (le créateur), Vishnou (le préservateur) et Shiva (le destructeur/transformateur).","Chaque village indien a souvent sa propre divinité locale (gramadevata), ce qui explique en partie cette prolifération de formes divines."],
    en:["The expression '33 million gods' comes from an ambiguous translation of the Sanskrit 'trayastrimsati koti' where 'koti' can mean 'type' or 'million.'","Hinduism's three main deities form the Trimurti: Brahma (the creator), Vishnu (the preserver), and Shiva (the destroyer/transformer).","Each Indian village often has its own local deity (gramadevata), which partly explains this proliferation of divine forms."],
    es:["El taoísmo, fundado en China por Laozi (siglo VI a.C.), enseña a vivir en armonía con el Tao (el camino), la fuerza primordial que subyace a toda la realidad.","El yin y el yang representan la interdependencia de los opuestos: luz y oscuridad, masculino y femenino, acción y reposo — no son fuerzas contrarias sino complementarias.","El Tao Te King de Laozi es uno de los textos más traducidos del mundo: su filosofía de no-acción (wu wei) influyó en la medicina, las artes marciales, la estética y la política chinas."]
  },
  'rel16': {
    fr:["La cérémonie du sema a été créée par Rumi, le poète mystique persan du XIIIᵉ siècle, considéré comme l'un des plus grands poètes de tous les temps.","Le derviche tourne sur lui-même en ouvrant les bras : la main droite tournée vers le ciel reçoit la grâce divine, la main gauche tournée vers le sol la redistribue.","L'UNESCO a inscrit la cérémonie du sema au patrimoine culturel immatériel de l'humanité en 2008 pour la Turquie."],
    en:["The sema ceremony was created by Rumi, the 13th-century Persian mystic poet, considered one of the greatest poets of all time.","The dervish spins with open arms: the right hand turned skyward receives divine grace, the left hand turned earthward redistributes it.","UNESCO inscribed the sema ceremony on the Intangible Cultural Heritage of Humanity list in 2008 for Turkey."],
    es:["Las Cruzadas (1096-1291) fueron expediciones militares cristianas para recuperar Tierra Santa del control musulmán — provocaron siglos de conflicto entre Oriente y Occidente.","Más allá de lo religioso, las Cruzadas tuvieron motivaciones políticas y económicas: control de rutas comerciales, tierras y poder — el fervor religioso era a menudo un pretexto.","Los cruzados trajeron de vuelta a Europa conocimientos árabes en matemáticas, medicina, astronomía y filosofía — una transferencia cultural involuntaria que aceleró el Renacimiento."]
  },
  'rel17': {
    fr:["Le 13ᵉ mois éthiopien, Pagumē, ne dure que 5 jours (6 les années bissextiles) — d'où le slogan touristique du pays : « Thirteen months of sunshine ».","Le nouvel an éthiopien (Enkutatash) tombe le 11 septembre du calendrier grégorien, et l'Éthiopie a célébré son millénaire en… 2007.","Cette différence de calendrier a créé des confusions diplomatiques et logistiques, notamment pour les compagnies aériennes comme Ethiopian Airlines."],
    en:["The 13th Ethiopian month, Pagumē, lasts only 5 days (6 in leap years) — hence the country's tourism slogan: 'Thirteen months of sunshine.'","The Ethiopian New Year (Enkutatash) falls on September 11 of the Gregorian calendar, and Ethiopia celebrated its millennium in… 2007.","This calendar difference has created diplomatic and logistical confusion, especially for airlines like Ethiopian Airlines."],
    es:["El jainismo, una de las religiones más antiguas de la India, lleva el principio de no violencia (ahimsa) a su extremo: los monjes jainistas barren el suelo para no pisar insectos y usan mascarillas para no inhalar microorganismos.","El jainismo tiene unos 4,5 millones de seguidores, principalmente en India, pero su influencia filosófica es enorme: Gandhi fue profundamente influido por la ahimsa jainista.","Los templos jainistas son de una belleza extraordinaria: el complejo de Ranakpur (Rajastán) tiene 1 444 columnas de mármol, cada una tallada de forma única — una obra maestra de la arquitectura india."]
  },
  'rel18': {
    fr:["Dans l'hindouisme, le karma s'accumule sur plusieurs vies et détermine les conditions de la prochaine réincarnation — humain, animal ou même plante.","Le bouddhisme a redéfini le karma comme une intention : ce n'est pas l'acte lui-même qui compte, mais la motivation derrière l'acte.","En Occident, le mot « karma » est souvent réduit à l'idée de justice cosmique (« tu récoltes ce que tu sèmes »), ce qui est une simplification considérable."],
    en:["In Hinduism, karma accumulates over multiple lives and determines the conditions of the next reincarnation — human, animal, or even plant.","Buddhism redefined karma as intention: it's not the act itself that matters, but the motivation behind the act.","In the West, the word 'karma' is often reduced to the idea of cosmic justice ('you reap what you sow'), which is a considerable simplification."],
    es:["Las religiones africanas tradicionales, practicadas por más de 100 millones de personas, veneran a ancestros, espíritus de la naturaleza y un Dios creador supremo.","El vudú (vodou), lejos del estereotipo hollywoodense, es una religión compleja originaria de África occidental que llegó a Haití y Luisiana con los esclavos.","Las religiones afroamericanas (candomblé en Brasil, santería en Cuba, vudú en Haití) fusionaron las tradiciones africanas con el catolicismo colonial, creando sincretismos únicos."]
  },
  'rel19': {
    fr:["Les funérailles célestes se déroulent généralement à l'aube, sur des plateformes en hauteur, et sont conduites par un spécialiste appelé rogyapa (« briseur de corps »).","Cette pratique est aussi pragmatique : au Tibet, le sol gelé rend l'enterrement difficile et le bois est trop rare pour la crémation.","Le gouvernement chinois a tenté d'interdire cette pratique dans les années 1960, mais elle a été autorisée à nouveau en 1974 face à la résistance culturelle."],
    en:["Sky burials typically take place at dawn, on elevated platforms, and are conducted by a specialist called a rogyapa ('body breaker').","This practice is also pragmatic: in Tibet, frozen ground makes burial difficult and wood is too scarce for cremation.","The Chinese government tried to ban this practice in the 1960s, but it was allowed again in 1974 due to cultural resistance."],
    es:["El confucianismo no es estrictamente una religión sino una filosofía ética y social basada en las enseñanzas de Confucio (551-479 a.C.) sobre la armonía social, el respeto filial y la virtud.","Los cinco vínculos confucianos (gobernante-súbdito, padre-hijo, marido-mujer, hermano mayor-menor, amigo-amigo) definieron la estructura social china durante más de 2 000 años.","El confucianismo sigue influyendo profundamente en las sociedades de Asia oriental: la importancia de la educación, el respeto a los mayores y la armonía social son valores confucianos."]
  },
  'rel20': {
    fr:["Le Hajj suit un itinéraire précis de 5 jours autour de La Mecque, incluant 7 tours autour de la Kaaba, une course entre les collines de Safa et Marwa, et une veillée à Arafat.","La Kaaba est recouverte d'un tissu noir brodé d'or appelé kiswah, renouvelé chaque année — l'ancien est découpé et offert à des dignitaires ou institutions.","L'Arabie saoudite investit des milliards dans l'agrandissement des infrastructures : le projet prévoit d'accueillir 30 millions de pèlerins par an d'ici 2030."],
    en:["The Hajj follows a precise 5-day itinerary around Mecca, including 7 circles around the Kaaba, a run between the hills of Safa and Marwa, and a vigil at Arafat.","The Kaaba is covered with a gold-embroidered black cloth called the kiswah, renewed every year — the old one is cut up and given to dignitaries or institutions.","Saudi Arabia invests billions in expanding infrastructure: the project aims to accommodate 30 million pilgrims per year by 2030."],
    es:["Los manuscritos del Mar Muerto, descubiertos entre 1947 y 1956 en las cuevas de Qumrán (Israel), contienen los textos bíblicos más antiguos conocidos — algunos datan del siglo III a.C.","Los más de 900 manuscritos incluyen fragmentos de casi todos los libros del Antiguo Testamento y textos desconocidos de la secta de los esenios.","Su descubrimiento transformó la comprensión del judaísmo del Segundo Templo y los orígenes del cristianismo — revelaron la diversidad religiosa de la Palestina anterior a Jesús."]
  },
  'rel21': {
    fr:["Le wu wei ne signifie pas l'inaction totale, mais plutôt agir en harmonie avec le flux naturel des choses — comme l'eau qui contourne les obstacles sans effort.","Lao Tseu, le fondateur légendaire du taoïsme, aurait écrit le Tao Te King en une seule nuit avant de disparaître à dos de buffle vers l'ouest.","Le concept de wu wei a influencé les arts martiaux asiatiques : le judo (« voie de la souplesse ») et l'aïkido utilisent la force de l'adversaire plutôt que de s'y opposer."],
    en:["Wu wei doesn't mean total inaction, but rather acting in harmony with the natural flow of things — like water flowing around obstacles without effort.","Lao Tzu, the legendary founder of Taoism, is said to have written the Tao Te Ching in a single night before disappearing westward on a water buffalo.","The concept of wu wei has influenced Asian martial arts: judo ('the gentle way') and aikido use the opponent's force rather than opposing it."],
    es:["La Inquisición fue un sistema judicial eclesiástico creado en el siglo XII para combatir la herejía — su forma más conocida, la Inquisición española (1478-1834), persiguió a conversos, protestantes y supuestas brujas.","Contrariamente al estereotipo, la Inquisición española condenó a muerte a unas 3 000-5 000 personas en 356 años — una cifra terrible pero inferior a la de los tribunales civiles contemporáneos.","La «Leyenda Negra» protestante exageró los excesos de la Inquisición con fines propagandísticos — la realidad histórica es más matizada pero sigue siendo un capítulo oscuro de la historia religiosa."]
  },
  'rel22': {
    fr:["Le pape François vit dans une résidence modeste (la Maison Sainte-Marthe) plutôt que dans les appartements pontificaux luxueux, une première dans l'histoire moderne du Vatican.","Avant de devenir pape, Jorge Mario Bergoglio prenait le bus et cuisinait lui-même à Buenos Aires — il a conservé cette simplicité au Vatican.","Il est le premier pape à avoir ouvert un compte Instagram (@franciscus), qui a atteint un million d'abonnés en moins de 12 heures."],
    en:["Pope Francis lives in a modest residence (the Casa Santa Marta) rather than the luxurious papal apartments, a first in the Vatican's modern history.","Before becoming pope, Jorge Mario Bergoglio took the bus and cooked for himself in Buenos Aires — he maintained this simplicity at the Vatican.","He is the first pope to open an Instagram account (@franciscus), which reached one million followers in less than 12 hours."],
    es:["El zoroastrismo, fundado por Zaratustra en la antigua Persia (siglo VI a.C. o antes), fue la primera gran religión monoteísta del mundo.","Sus conceptos de cielo, infierno, juicio final, resurrección de los muertos y lucha cósmica entre el bien y el mal influyeron profundamente en el judaísmo, el cristianismo y el islam.","Hoy cuenta con solo 120 000-200 000 practicantes (parsis en India, zoroastrianos en Irán) — una de las religiones más antiguas del mundo al borde de la extinción."]
  },
  'rel23': {
    fr:["La destruction du mandala de sable est considérée comme aussi importante que sa création — les moines versent le sable dans une rivière pour disperser les bénédictions.","Certains mandalas complexes nécessitent le travail de 4 à 6 moines pendant 2 à 3 semaines, utilisant des tubes métalliques pour déposer le sable grain par grain.","Le mandala représente une carte de l'univers dans la cosmologie bouddhiste, avec le mont Méru au centre et les différents royaumes autour."],
    en:["The destruction of the sand mandala is considered as important as its creation — monks pour the sand into a river to disperse the blessings.","Some complex mandalas require the work of 4 to 6 monks over 2 to 3 weeks, using metal tubes to deposit sand grain by grain.","The mandala represents a map of the universe in Buddhist cosmology, with Mount Meru at the center and the different realms around it."],
    es:["Los monasterios budistas tibetanos son centros de estudio, meditación y preservación cultural donde los monjes pueden pasar décadas memorizando textos y practicando la meditación.","Los mandalas de arena tibetanos se crean durante semanas con granos de arena coloreada y luego se destruyen deliberadamente — una meditación sobre la impermanencia de todas las cosas.","El Dalái Lama, líder espiritual del budismo tibetano, vive en exilio en India desde 1959 tras la invasión china del Tíbet — su figura combina liderazgo religioso, político y moral."]
  },
  'rel24': {
    fr:["Le Rigveda contient 1 028 hymnes dédiés à différentes divinités, dont Agni (le feu) et Indra (le tonnerre), et a été transmis oralement pendant des siècles avant d'être écrit.","La précision de la transmission orale est stupéfiante : des techniques mnémotechniques complexes ont préservé chaque syllabe intacte pendant plus de 3 000 ans.","L'UNESCO a inscrit la tradition de récitation du Veda au patrimoine culturel immatériel de l'humanité en 2008."],
    en:["The Rigveda contains 1,028 hymns dedicated to various deities, including Agni (fire) and Indra (thunder), and was transmitted orally for centuries before being written down.","The precision of oral transmission is stunning: complex mnemonic techniques preserved every syllable intact for over 3,000 years.","UNESCO inscribed the tradition of Vedic chanting on the Intangible Cultural Heritage of Humanity list in 2008."],
    es:["La Navidad (25 de diciembre) no corresponde a la fecha real del nacimiento de Jesús — fue elegida en el siglo IV para coincidir con las fiestas romanas del Sol Invicto y las Saturnales.","Muchas tradiciones navideñas son de origen pagano: el árbol (germánico), el acebo (celta), los regalos (Saturnales romanas) y Papá Noel (mezcla de San Nicolás y tradiciones nórdicas).","La comercialización de la Navidad comenzó en el siglo XIX: el Santa Claus rojo fue popularizado por Coca-Cola en los años 1930, aunque su imagen ya existía antes."]
  },
  'rel25': {
    fr:["Les règles varient tellement d'une communauté à l'autre qu'un Amish de Pennsylvanie pourrait trouver un Amish de l'Indiana trop libéral ou trop strict.","Le Rumspringa est une période où les adolescents amish (vers 16 ans) sont autorisés à explorer le monde extérieur avant de choisir de rester ou non dans la communauté.","Environ 85 à 90 % des jeunes amish choisissent de rester dans la communauté après le Rumspringa — un taux de rétention remarquable."],
    en:["Rules vary so much between communities that an Amish person from Pennsylvania might find an Amish person from Indiana too liberal or too strict.","Rumspringa is a period when Amish teenagers (around age 16) are allowed to explore the outside world before choosing whether to remain in the community.","About 85 to 90% of Amish youth choose to stay in the community after Rumspringa — a remarkable retention rate."],
    es:["El bahá'ísmo, fundado en Irán en 1863 por Bahá'u'lláh, enseña la unidad de Dios, la unidad de las religiones y la unidad de la humanidad.","Con unos 8 millones de seguidores en más de 200 países, es una de las religiones más geográficamente extendidas del mundo.","Los bahá'ís son perseguidos en Irán desde la revolución de 1979: más de 200 han sido ejecutados y miles encarcelados — la mayor minoría religiosa perseguida del país."]
  },
  'rel26': {
    fr:["Les ascenseurs de Shabbat (« Shabbat elevators ») s'arrêtent automatiquement à chaque étage car appuyer sur un bouton est considéré comme un travail interdit le jour du repos.","Il existe 39 catégories de travail interdit le Shabbat (melakhot), incluant écrire, allumer un feu, coudre, et même arracher de l'herbe.","Des ingénieurs israéliens ont développé tout un écosystème technologique compatible avec le Shabbat : plaques chauffantes qui restent allumées, minuteries automatiques, et même des smartphones spéciaux."],
    en:["Shabbat elevators stop automatically at every floor because pressing a button is considered forbidden work on the day of rest.","There are 39 categories of forbidden work on Shabbat (melakhot), including writing, lighting a fire, sewing, and even pulling up grass.","Israeli engineers have developed an entire Shabbat-compatible technology ecosystem: hot plates that stay on, automatic timers, and even special smartphones."],
    es:["Los textos sagrados más antiguos del mundo son los Vedas hindúes, transmitidos oralmente durante milenios antes de ser escritos — los Rigveda datan de al menos 1500 a.C.","La Epopeya de Gilgamesh sumeria (2100 a.C.) contiene una versión del diluvio universal anterior a la bíblica — lo que sugiere que el relato de Noé tiene raíces mesopotámicas.","El Avesta zoroastriano, la Torá judía, el Tipitaka budista y el Corán islámico son otros textos sagrados que han moldeado civilizaciones enteras durante milenios."]
  },
  'rel27': {
    fr:["Le Kumbh Mela de 2019 à Prayagraj a accueilli environ 150 millions de personnes en 49 jours — visible depuis l'espace grâce à l'éclairage du campement.","Les pèlerins se baignent au confluent de trois rivières sacrées (le Gange, la Yamuna et la mythique Sarasvati) pour laver leurs péchés.","L'événement nécessite une ville temporaire entière : 250 000 tentes, 122 000 toilettes, 20 hôpitaux de campagne et 40 000 policiers pour la sécurité."],
    en:["The 2019 Kumbh Mela in Prayagraj drew about 150 million people over 49 days — visible from space thanks to the campsite lighting.","Pilgrims bathe at the confluence of three sacred rivers (the Ganges, the Yamuna, and the mythical Sarasvati) to wash away their sins.","The event requires an entire temporary city: 250,000 tents, 122,000 toilets, 20 field hospitals, and 40,000 police officers for security."],
    es:["La cábala es la tradición mística del judaísmo que busca comprender la naturaleza de Dios y el universo a través de interpretaciones esotéricas de la Torá.","El Árbol de la Vida cabalístico (10 sefirot conectadas por 22 senderos) representa la estructura de la realidad divina y ha influido en la filosofía, el ocultismo y el arte occidentales.","Madonna, el agua de cábala y las pulseras rojas han popularizado una versión simplificada de esta tradición milenaria — los rabinos ortodoxos generalmente desaprueban esta comercialización."]
  },
  'rel28': {
    fr:["Angkor Wat a été construit par le roi Suryavarman II au XIIᵉ siècle avec environ 5 millions de blocs de grès, sans mortier ni ciment — uniquement par emboîtement.","Le temple est orienté vers l'ouest (contrairement aux autres temples khmers), ce qui suggère qu'il aurait pu servir de temple funéraire pour le roi.","Angkor Wat n'a jamais été complètement abandonné : même après la chute de l'Empire khmer, des moines bouddhistes ont continué à y vivre."],
    en:["Angkor Wat was built by King Suryavarman II in the 12th century using about 5 million sandstone blocks, without mortar or cement — only interlocking.","The temple faces west (unlike other Khmer temples), suggesting it may have served as a funerary temple for the king.","Angkor Wat was never completely abandoned: even after the fall of the Khmer Empire, Buddhist monks continued to live there."],
    es:["Las peregrinaciones son comunes a casi todas las religiones: La Meca (islam), Jerusalén (judaísmo, cristianismo, islam), Varanasi (hinduismo), Bodh Gaya (budismo), Santiago de Compostela (catolicismo).","El Camino de Santiago ha experimentado un renacimiento espectacular: de 2 000 peregrinos en 1985 a más de 400 000 en 2023 — muchos lo recorren por razones espirituales, deportivas o de búsqueda personal.","Las peregrinaciones combinan lo sagrado con lo práctico: históricamente fueron motores económicos, rutas de intercambio cultural y catalizadores del desarrollo de infraestructuras."]
  },
  'rel29': {
    fr:["Le mouvement rastafari est né en Jamaïque dans les années 1930, fortement influencé par Marcus Garvey, militant panafricaniste qui prônait le retour en Afrique.","Les dreadlocks rasta ne sont pas qu'esthétiques : ils s'inspirent du vœu de Nazaréen dans la Bible, où Samson tirait sa force de ses cheveux non coupés.","Bob Marley, le plus célèbre rasta du monde, a été baptisé dans l'Église éthiopienne orthodoxe peu avant sa mort en 1981, combinant ses deux traditions spirituelles."],
    en:["The Rastafari movement was born in Jamaica in the 1930s, strongly influenced by Marcus Garvey, a Pan-Africanist activist who advocated a return to Africa.","Rasta dreadlocks aren't just aesthetic: they're inspired by the Nazirite vow in the Bible, where Samson drew his strength from his uncut hair.","Bob Marley, the world's most famous Rasta, was baptized in the Ethiopian Orthodox Church shortly before his death in 1981, combining his two spiritual traditions."],
    es:["El ateísmo y el agnosticismo están en crecimiento en muchas sociedades occidentales: en Europa, más del 25 % de la población se declara sin religión.","El «nuevo ateísmo» de Richard Dawkins, Sam Harris y Christopher Hitchens generó un debate público intenso sobre el papel de la religión en la sociedad moderna.","Sin embargo, la secularización no es universal: la religión crece en África, Asia y América Latina — la geografía de la fe está cambiando, no desapareciendo."]
  },
  'rel30': {
    fr:["Gaudí savait qu'il ne verrait jamais l'achèvement de la Sagrada Família — il disait que « son client (Dieu) n'est pas pressé ».","L'église combine des éléments gothiques et Art nouveau avec des formes inspirées de la nature : les colonnes intérieures imitent des arbres, créant une forêt de pierre.","La technologie moderne a considérablement accéléré la construction : l'impression 3D et la taille numérique de la pierre permettent en quelques mois ce qui prenait autrefois des années."],
    en:["Gaudí knew he would never see the Sagrada Família completed — he said that 'his client (God) is not in a hurry.'","The church combines Gothic and Art Nouveau elements with nature-inspired forms: the interior columns mimic trees, creating a forest of stone.","Modern technology has considerably accelerated construction: 3D printing and digital stone cutting achieve in months what once took years."],
    es:["El diálogo interreligioso ha avanzado significativamente en el siglo XXI: encuentros entre el papa Francisco, líderes musulmanes, judíos y budistas buscan la convivencia pacífica.","El Documento de Abu Dabi (2019), firmado por el papa Francisco y el gran imán Ahmed al-Tayeb, declaró que la diversidad religiosa es «querida por Dios» — un hito en las relaciones islamo-cristianas.","El desafío del siglo XXI no es eliminar las diferencias religiosas sino aprender a convivir con ellas: la tolerancia, el respeto mutuo y el conocimiento del otro son las claves de la paz interreligiosa."]
  },
});

DEEP_DIVES['s1'].es = ["Una sola tormenta puede liberar tanta energía como una bomba atómica de 20 kilotones — repartida en miles de rayos.","La Tierra es alcanzada por unos 100 rayos por segundo, es decir más de 8 millones al día.","Venezuela posee un lugar único, el lago Maracaibo, donde caen rayos 300 noches al año — el récord mundial."];
DEEP_DIVES['s2'].es = ["El calcio de tus huesos proviene de explosiones de supernovas ocurridas hace más de 5 mil millones de años.","El hierro de tu sangre y el oro de tus joyas se crearon en el mismo lugar: en el corazón de estrellas moribundas.","El hidrógeno del agua que bebes es el único elemento de tu cuerpo que no viene de una estrella — data del Big Bang."];
DEEP_DIVES['s3'].es = ["Esta capacidad se basa en una proteína llamada criptocromo, situada en la retina, que reacciona al campo magnético terrestre.","Las palomas mensajeras también poseen cristales de magnetita en su pico, actuando como una segunda brújula biológica.","Algunas tortugas marinas usan un sistema similar para cruzar océanos enteros y volver a su lugar de nacimiento."];
DEEP_DIVES['s4'].es = ["Un solo gramo de suelo forestal contiene unas 10 000 especies de bacterias diferentes, la mayoría jamás estudiadas.","Algunas bacterias del suelo producen geosmina, la molécula responsable del olor característico de la tierra tras la lluvia.","Los científicos estiman que hemos identificado menos del 1 % de las especies microbianas que viven en el suelo terrestre."];
DEEP_DIVES['s5'].es = ["Estos rapaces, principalmente los milanos negros, transportan ramas ardiendo en sus garras hasta zonas secas.","Este comportamiento ha sido documentado por aborígenes australianos durante miles de años antes de ser confirmado por la ciencia.","El fuego les permite descubrir a sus presas huyendo de las llamas — una estrategia de caza de una inteligencia fascinante."];
DEEP_DIVES['s6'].es = ["Las rayas verdes se forman cuando el agua de mar se congela en la parte inferior del iceberg, atrapando algas y minerales.","Cada iceberg verde es único: la distribución de sus rayas depende de las capas de hielo acumuladas a lo largo de los siglos.","Estos icebergs transportan hierro y nutrientes esenciales para el fitoplancton — contribuyen a la vida marina."];
DEEP_DIVES['s7'].es = ["El fitoplancton, organismos microscópicos de la superficie oceánica, produce más oxígeno que todos los bosques tropicales juntos.","Prochlorococcus, una cianobacteria marina, es el organismo fotosintético más pequeño y abundante de la Tierra.","Sin estos micro-organismos, la atmósfera terrestre no contendría suficiente oxígeno para sostener la vida animal."];
DEEP_DIVES['s8'].es = ["Las fulguritas se forman en menos de un segundo, cuando la arena se funde a más de 1 800 °C por el impacto de un rayo.","Algunas fulguritas encontradas miden más de 5 metros de largo — siguiendo la trayectoria subterránea del rayo.","El interior vitrificado de una fulgurita conserva burbujas de gas que revelan la composición de la atmósfera en el momento del impacto."];
DEEP_DIVES['s9'].es = ["El censo de 2015 reveló 3,04 billones de árboles en la Tierra — siete veces más de lo que las estimaciones anteriores sugerían.","La Vía Láctea contiene entre 100 y 400 mil millones de estrellas, es decir al menos 7 veces menos que el número de árboles terrestres.","A pesar de esta abundancia, perdemos unos 10 mil millones de árboles al año por la deforestación."];
DEEP_DIVES['s10'].es = ["Unos 800 millones de virus caen del cielo por cada metro cuadrado de superficie terrestre cada día.","Estos virus son transportados a la estratosfera por corrientes de aire ascendentes y partículas de polvo.","La mayoría de estos virus afectan únicamente a bacterias (son bacteriófagos) y participan activamente en la regulación de los ecosistemas."];
DEEP_DIVES['s11'].es = ["Esta red de hongos subterráneos, llamada micorriza, conecta hasta el 90 % de las especies de plantas terrestres.","A través de esta red, los árboles pueden compartir nutrientes: un árbol madre puede alimentar a sus descendientes a distancia.","Cuando un árbol es atacado por un insecto, puede enviar señales químicas a través de la red fúngica para alertar a sus vecinos."];
DEEP_DIVES['s12'].es = ["Este fenómeno, observado por primera vez por Aristóteles, fue redescubierto en 1963 por un estudiante tanzano llamado Erasto Mpemba.","La explicación exacta sigue siendo debatida: las hipótesis incluyen la evaporación, la convección y la distribución del calor.","En 2020, un equipo demostró que los enlaces de hidrógeno del agua caliente almacenan más energía, lo que podría acelerar la cristalización."];
DEEP_DIVES['s13'].es = ["La velocidad del sonido en el acero alcanza unos 5 960 m/s, frente a 343 m/s en el aire a 20 °C.","Esta diferencia se explica por la rigidez del acero: los átomos transmiten las vibraciones más rápidamente en un medio sólido.","Es por esto que se puede oír un tren llegando apoyando la oreja sobre el raíl mucho antes de oírlo en el aire."];
DEEP_DIVES['s14'].es = ["El ADN humano se enrolla alrededor de proteínas llamadas histonas, formando una estructura ultra-compacta llamada cromatina.","Si desplegáramos todo el ADN de todas las células de un ser humano, la longitud alcanzaría unas 1 000 veces la distancia Tierra-Sol.","Solo el 2 % de nuestro ADN codifica proteínas — el resto, antes llamado 'ADN basura', desempeña funciones reguladoras esenciales."];
DEEP_DIVES['s15'].es = ["Un neutrón libre se transforma en un protón emitiendo un electrón y un antineutrino — es la desintegración beta.","Dentro de un núcleo atómico, los neutrones pueden ser perfectamente estables durante miles de millones de años.","Esta diferencia entre estabilidad ligada y desintegración libre es una de las claves de la física nuclear."];
DEEP_DIVES['s16'].es = ["Los tardígrados soportan el vacío espacial, radiaciones 1 000 veces superiores a la dosis letal para un humano y presiones de 6 000 atmósferas.","En estado de criptobiosis, su metabolismo cae a menos del 0,01 % — pueden permanecer así durante décadas.","Un estudio de 2019 mostró que tardígrados enviados a la Luna tras un accidente de la sonda israelí Beresheet podrían haber sobrevivido al impacto."];
DEEP_DIVES['s17'].es = ["Los 23 vatios generados por el cerebro provienen de la combustión de glucosa y representan el 20 % de la energía total del cuerpo.","El cerebro consume esta energía incluso en reposo — la mayor parte se destina a mantener las señales eléctricas entre las neuronas.","Un cerebro humano contiene unos 86 mil millones de neuronas, cada una capaz de formar miles de conexiones sinápticas."];
DEEP_DIVES['s18'].es = ["La hemocianina, proteína a base de cobre, transporta el oxígeno en la sangre del pulpo, dándole su color azul.","Este sistema es menos eficiente que nuestra hemoglobina pero funciona mejor en entornos fríos y poco oxigenados como las profundidades marinas.","Cada uno de los tres corazones del pulpo tiene un papel específico: dos bombean sangre hacia las branquias y el tercero hacia el resto del cuerpo."];
DEEP_DIVES['s19'].es = ["En 2012, investigadores de Harvard lograron almacenar 700 terabytes de datos en un solo gramo de ADN.","La densidad de almacenamiento del ADN supera a cualquier tecnología actual en un factor de un millón.","El principal obstáculo sigue siendo el coste de la síntesis y lectura del ADN, pero disminuye exponencialmente cada año."];
DEEP_DIVES['s20'].es = ["El hielo XVI fue sintetizado en 2014 a partir de clatratos — estructuras de hielo que encierran moléculas de gas.","A diferencia del hielo ordinario, el hielo XVI es menos denso porque su estructura cristalina contiene cavidades vacías.","Este descubrimiento ayuda a los científicos a comprender el comportamiento del hielo en las lunas heladas de Júpiter y Saturno."];
DEEP_DIVES['a1'].es = ["Cada tentáculo del pulpo posee su propio ganglio nervioso, capaz de tomar decisiones de forma autónoma sin consultar al cerebro central.","La sangre azul del pulpo le permite sobrevivir en aguas profundas y frías donde nuestra hemoglobina sería ineficaz.","Ciertos pulpos, como el pulpo mimético, pueden imitar la apariencia y el comportamiento de más de 15 especies distintas para escapar de los depredadores."];
DEEP_DIVES['a2'].es = ["Cada delfín desarrolla un silbido único en los primeros meses de vida, que funciona como un nombre propio.","Los delfines pueden recordar el silbido de un antiguo compañero incluso después de 20 años de separación.","Cuando dos grupos de delfines se encuentran, intercambian sus silbidos identificadores como una forma de presentación social."];
DEEP_DIVES['a3'].es = ["En estado de criptobiosis, el tardígrado pierde casi toda su agua corporal y puede permanecer así durante décadas.","Tardígrados expuestos al vacío del espacio durante 10 días en la estación espacial sobrevivieron y se reprodujeron normalmente después.","Poseen una proteína única llamada Dsup que protege su ADN contra la radiación formando un escudo molecular."];
DEEP_DIVES['a4'].es = ["Los cuervos pueden reconocer un rostro humano específico entre una multitud, incluso años después del encuentro.","Investigadores de la Universidad de Washington demostraron que los cuervos transmiten información sobre humanos peligrosos a sus congéneres.","Los cuervos también son capaces de fabricar herramientas complejas, una capacidad cognitiva antes reservada a los primates."];
DEEP_DIVES['a5'].es = ["Esta hibernación se llama estivación: el caracol segrega una capa de moco endurecido que sella su concha para retener la humedad.","En estado de estivación, su metabolismo se reduce a casi cero — puede permanecer así varios años si las condiciones lo exigen.","Un experimento de museo demostró que un caracol considerado muerto y pegado en una vitrina durante cuatro años despertó al ser sumergido en agua."];
DEEP_DIVES['a6'].es = ["Este proceso, llamado transdiferenciación, permite a la medusa revertir sus células adultas a un estado embrionario.","En teoría, este ciclo puede repetirse indefinidamente, haciendo de Turritopsis dohrnii un organismo biológicamente inmortal.","Los investigadores estudian este mecanismo para comprender la regeneración celular y potencialmente aplicarlo a la medicina humana."];
DEEP_DIVES['a7'].es = ["La burbuja de cavitación producida por la pinza del camarón pistola genera un destello de luz visible — un fenómeno llamado sonoluminiscencia.","La onda de choque que sigue es tan potente que puede romper el cristal de un acuario pequeño.","Esta capacidad le sirve tanto para cazar como para excavar madrigueras en la roca coralina."];
DEEP_DIVES['a8'].es = ["Las hormigas cortadoras de hojas no comen las hojas: las mastican para crear un sustrato sobre el que cultivan un hongo específico.","Este hongo, de la familia Leucoagaricus, ha coevolucionado con las hormigas durante 50 millones de años hasta volverse dependiente de ellas.","Las hormigas usan además antibióticos naturales producidos por bacterias de su cuerpo para proteger su cultivo contra las enfermedades."];
DEEP_DIVES['a9'].es = ["Estudios con monitores de frecuencia cardíaca mostraron que las vacas experimentan estrés medible cuando se separan de su mejor amiga.","Las vacas también muestran emociones positivas: su producción de leche aumenta cuando se las trata con delicadeza y se las llama por su nombre.","Los investigadores concluyeron que las vacas tienen personalidades distintas — algunas son optimistas, otras pesimistas, al igual que los humanos."];
DEEP_DIVES['a10'].es = ["Este comportamiento, llamado 'rafting', evita que las nutrias deriven mar adentro mientras duermen en las corrientes del Pacífico.","Los grupos de nutrias descansando juntas forman lo que se llama una 'balsa' — a veces hasta 100 individuos tomados de las patas.","Las nutrias marinas también envuelven a sus crías en algas para mantenerlas inmóviles mientras bucean en busca de alimento."];
DEEP_DIVES['a11'].es = ["Los receptores gustativos de las patas permiten a las mariposas identificar instantáneamente si una planta es comestible con solo posarse.","Estos quimiorreceptores son hasta 200 veces más sensibles que nuestras papilas gustativas humanas.","Esta adaptación es crucial para la supervivencia: la mariposa debe encontrar la planta adecuada para poner sus huevos en solo unos minutos."];
DEEP_DIVES['a12'].es = ["La estructura ósea del elefante no permite el movimiento de rebote necesario para el salto — sus patas funcionan como pilares.","A pesar de esta limitación, los elefantes pueden correr hasta 40 km/h, aunque técnicamente nunca tienen las cuatro patas en el aire al mismo tiempo.","Los elefantes son también los únicos mamíferos terrestres que no pueden técnicamente trotar — pasan directamente de caminar a correr."];
DEEP_DIVES['a13'].es = ["El corazón de una ballena azul pesa unos 450 kg — el tamaño de un coche pequeño — y late solo 8 a 10 veces por minuto en inmersión.","Su aorta es tan ancha que un niño podría gatear a través de ella.","Pese a su tamaño, la ballena azul se alimenta casi exclusivamente de krill — unos 4 toneladas al día durante la temporada de alimentación."];
DEEP_DIVES['a14'].es = ["Las abejas memorizan los rasgos faciales humanos utilizando un proceso similar a nuestro reconocimiento facial — una hazaña para un cerebro de menos de un millón de neuronas.","Pueden recordar un rostro aprendido durante al menos 2 días, algo que antes se creía exclusivo de los mamíferos.","Esta capacidad es utilizada por los investigadores para estudiar los mecanismos del reconocimiento facial, incluso para la inteligencia artificial."];
DEEP_DIVES['a15'].es = ["Alex, un loro gris africano estudiado por la Dra. Irene Pepperberg durante 30 años, comprendía conceptos como 'más grande', 'más pequeño' y 'diferente'.","Alex fue el primer animal no humano en hacer una pregunta existencial: preguntó de qué color era — y aprendió que era gris.","Los loros grises pueden comprender el concepto de cero, una capacidad cognitiva que los niños humanos solo adquieren hacia los 3-4 años."];
DEEP_DIVES['a16'].es = ["A pesar de su enorme tamaño, el tiburón ballena es completamente inofensivo para los humanos — se alimenta filtrando plancton y pequeños peces.","Cada tiburón ballena tiene un patrón de manchas único, como una huella dactilar, lo que permite a los científicos identificar a cada individuo.","Las hembras de tiburón ballena pueden llevar hasta 300 embriones en diferentes estadios de desarrollo simultáneamente."];
DEEP_DIVES['a17'].es = ["La lengua del cocodrilo está unida a la mandíbula inferior por toda su longitud, lo que le impide moverla libremente.","Esta particularidad no es un inconveniente: el cocodrilo traga sus presas enteras, sin masticar, por lo que la lengua no le es útil para comer.","Los cocodrilos poseen sin embargo receptores sensoriales extremadamente finos en su hocico, más sensibles que las yemas de los dedos humanos."];
DEEP_DIVES['a18'].es = ["Las langostas producen una enzima llamada telomerasa que repara indefinidamente los extremos de sus cromosomas, evitando el envejecimiento celular.","Con cada muda, la langosta crece — pero el proceso se vuelve cada vez más agotador y la langosta puede morir de fatiga durante la muda.","La langosta más grande jamás capturada pesaba más de 20 kg y se estimaba que tenía más de 100 años."];
DEEP_DIVES['a19'].es = ["Este sueño unihemisférico permite a los delfines seguir nadando y subiendo a la superficie para respirar incluso mientras descansan.","Un ojo permanece abierto durante el sueño, vigilando a los depredadores y a los miembros del grupo.","Los delfines alternan los hemisferios cada dos horas aproximadamente, asegurando así que cada mitad del cerebro descanse lo suficiente."];
DEEP_DIVES['a20'].es = ["Los primeros tiburones aparecieron en el Devónico, unos 100 millones de años antes que los primeros árboles.","Atravesaron cinco extinciones masivas, incluida la que eliminó a los dinosaurios, adaptándose cada vez al nuevo entorno.","El tiburón martillo evolucionó su característica cabeza para tener un campo de visión de 360° y un electroreceptor más eficaz."];
DEEP_DIVES['b1'].es = ["Si desplegáramos todo el ADN de una sola célula humana, mediría unos 2 metros de largo.","Todo el ADN de tu cuerpo, puesto extremo con extremo, cubriría más de 1 000 veces la distancia entre la Tierra y el Sol.","Este ADN está empaquetado en un núcleo celular de solo 6 micrómetros de diámetro — una proeza de compactación molecular."];
DEEP_DIVES['b2'].es = ["El cerebro humano contiene unos 86 mil millones de neuronas, cada una conectada a miles de otras mediante sinapsis.","A pesar de representar solo el 2 % de la masa corporal, el cerebro consume el 20 % de la energía total.","Incluso en reposo, el cerebro genera actividad eléctrica suficiente para alimentar una pequeña bombilla LED."];
DEEP_DIVES['b3'].es = ["El fémur humano puede soportar una presión de 1 700 kg — superando al acero en resistencia por unidad de peso.","Los huesos se renuevan constantemente: unas células llamadas osteoclastos los destruyen mientras los osteoblastos los reconstruyen.","Un adulto renueva completamente su esqueleto aproximadamente cada 10 años gracias a este proceso de remodelación ósea."];
DEEP_DIVES['b4'].es = ["El revestimiento mucoso del estómago se regenera cada 2 semanas para proteger las paredes contra el ácido clorhídrico que produce.","El pH del ácido gástrico está entre 1 y 2, lo suficientemente agresivo como para disolver metales como el zinc.","Sin esta regeneración constante, el estómago literalmente se digeriría a sí mismo en pocos días."];
DEEP_DIVES['b5'].es = ["El corazón humano bombea unos 7 500 litros de sangre al día a través de 100 000 km de vasos sanguíneos.","En una vida de 80 años, el corazón habrá latido más de 3 mil millones de veces sin una sola pausa voluntaria.","El corazón tiene su propio sistema eléctrico autónomo — puede seguir latiendo incluso separado del cuerpo."];
DEEP_DIVES['b6'].es = ["La córnea es el único tejido del cuerpo humano que no tiene vasos sanguíneos — absorbe el oxígeno directamente del aire.","Esta ausencia de vasos sanguíneos es lo que la hace tan transparente y lo que permite que la luz entre limpiamente en el ojo.","La córnea es también el tejido que cicatriza más rápido en el cuerpo humano — un arañazo menor se repara en 24 a 48 horas."];
DEEP_DIVES['b7'].es = ["El hígado puede regenerarse a partir del 25 % de su masa original en solo unos meses — una capacidad única entre los órganos.","Este poder de regeneración inspiró probablemente el mito de Prometeo, cuyo hígado volvía a crecer cada noche.","El hígado realiza más de 500 funciones diferentes, incluyendo filtración de la sangre, producción de bilis y almacenamiento de vitaminas."];
DEEP_DIVES['b8'].es = ["Los discos intervertebrales se comprimen bajo el peso del cuerpo a lo largo del día, provocando una pérdida de altura de unos 1 cm.","Los astronautas pueden ganar hasta 5 cm en el espacio porque la ausencia de gravedad descomprime su columna vertebral.","Esta variación diaria se mide fácilmente: los pilotos de línea lo tienen en cuenta para sus certificados médicos."];
DEEP_DIVES['b9'].es = ["Los 300 huesos de un recién nacido se fusionan progresivamente durante el crecimiento, llegando a 206 en la edad adulta.","El cráneo de un bebé posee fontanelas — espacios blandos entre los huesos que permiten al cerebro crecer rápidamente durante los primeros años.","La fusión completa de todos los huesos no termina hasta aproximadamente los 25 años — la última zona es la clavícula."];
DEEP_DIVES['b10'].es = ["El cerebelo anticipa la sensación al generar una señal predictiva que anula la respuesta de cosquilleo producida por tus propios dedos.","Este mecanismo de predicción es crucial para distinguir las sensaciones generadas por uno mismo de las causadas por el mundo exterior.","Algunas personas con esquizofrenia pueden hacerse cosquillas a sí mismas — un fallo del sistema de predicción cerebral."];
DEEP_DIVES['b11'].es = ["Los pulmones contienen unos 600 millones de alvéolos, cada uno rodeado de capilares donde se produce el intercambio de oxígeno.","Desplegados, estos alvéolos cubrirían una superficie de unos 70 m² — el tamaño de un apartamento pequeño.","Respiramos unas 20 000 veces al día, moviendo unos 11 000 litros de aire a través de esta inmensa superficie de intercambio."];
DEEP_DIVES['b12'].es = ["Las uñas de las manos crecen en promedio 3,5 mm al mes, frente a 1,6 mm para los pies.","La uña del dedo medio crece ligeramente más rápido que las demás — probablemente porque es la más larga y la más estimulada.","Una uña de la mano tarda unos 6 meses en renovarse por completo, frente a 12 a 18 meses para una uña del pie."];
DEEP_DIVES['b13'].es = ["En 2014, investigadores de la Universidad Rockefeller demostraron que la nariz humana puede distinguir al menos un billón de olores.","Los receptores olfativos representan aproximadamente el 3 % de nuestro genoma — una inversión genética considerable.","El olfato es el único sentido que se conecta directamente al sistema límbico, el centro cerebral de las emociones y la memoria."];
DEEP_DIVES['b14'].es = ["La mayor parte del hierro del cuerpo (unos 3-4 g) se encuentra en la hemoglobina de los glóbulos rojos.","El cuerpo humano contiene también oro (unos 0,2 mg), arrastrado por la sangre en cantidades ínfimas.","Con el hierro del cuerpo se podría forjar un clavo de 7 cm — pero hace falta la hemoglobina de 70 000 glóbulos rojos para ello."];
DEEP_DIVES['b15'].es = ["El esqueleto humano se renueva por completo cada 10 años mediante un proceso llamado remodelación ósea.","Los osteoclastos destruyen el hueso viejo mientras los osteoblastos construyen nuevo — un equilibrio crucial para la salud ósea.","A partir de los 30 años, la destrucción supera gradualmente a la construcción — por eso la densidad ósea disminuye con la edad."];
DEEP_DIVES['b16'].es = ["Las huellas dactilares se forman entre las semanas 12 y 17 de gestación, bajo la influencia de presiones aleatorias en el útero.","Incluso los gemelos idénticos tienen huellas dactilares diferentes — las presiones uterinas son únicas para cada dedo.","Las huellas dactilares no cambian nunca durante toda la vida, salvo en caso de heridas profundas en la dermis."];
DEEP_DIVES['b17'].es = ["El cuerpo produce unos 25 millones de nuevas células cada segundo — más rápido de lo que puedes contarlas.","La mayoría de estas células reemplazan a las que mueren naturalmente por apoptosis — un suicidio celular programado.","Algunas células, como las neuronas y las células cardíacas, raramente se renuevan — conservas casi las mismas desde tu nacimiento."];
DEEP_DIVES['b18'].es = ["El esmalte dental es la sustancia más dura del cuerpo humano, con una dureza de 5 en la escala de Mohs.","A diferencia de los huesos, el esmalte dental no puede regenerarse — una vez dañado, se pierde permanentemente.","Los dientes de tiburón se renuevan continuamente a lo largo de su vida — un tiburón puede producir hasta 30 000 dientes en su existencia."];
DEEP_DIVES['b19'].es = ["Cada neurona puede formar hasta 10 000 conexiones sinápticas con otras neuronas, creando una red de una complejidad inimaginable.","El número total de sinapsis en el cerebro humano se estima en unos 100 billones — más que estrellas en la Vía Láctea.","La información viaja entre neuronas tanto por impulsos eléctricos como por señales químicas — los neurotransmisores."];
DEEP_DIVES['b20'].es = ["Un cubo de hueso de 2,5 cm de lado puede soportar una carga de 9 toneladas — más que un bloque de hormigón armado del mismo tamaño.","Esta resistencia proviene de la estructura interna del hueso, organizada en trabéculas que distribuyen las fuerzas como arcos de una catedral.","El fémur, el hueso más largo y fuerte del cuerpo, puede soportar una presión de 1 700 kg antes de fracturarse."];
DEEP_DIVES['p1'].es = ["Las poblaciones de tortugas verdes marinas aumentaron un 28 % desde 1970 gracias a la protección de las playas de anidación.","En Florida, algunas playas antes desiertas ahora acogen miles de nidos de tortugas cada año.","La tortuga verde puede vivir más de 80 años y recorrer miles de kilómetros entre sus zonas de alimentación y reproducción."];
DEEP_DIVES['p2'].es = ["En el primer semestre de 2025, la energía eólica y solar combinadas superaron por primera vez la producción eléctrica de carbón a nivel mundial.","China, a pesar de ser el mayor emisor de CO₂, instaló más paneles solares en 2024 que todo el resto del mundo junto.","El coste de la energía solar cayó un 89 % entre 2010 y 2024, haciéndola la fuente de electricidad más barata de la historia."];
DEEP_DIVES['p3'].es = ["La mejora de la calidad del aire ha evitado millones de muertes prematuras en las últimas tres décadas.","En Europa, las partículas finas disminuyeron un 30 % entre 2000 y 2020 gracias a normas de emisión más estrictas.","China redujo la contaminación atmosférica de Pekín un 40 % en solo 5 años gracias a medidas drásticas contra el carbón."];
DEEP_DIVES['p4'].es = ["El Protocolo de Montreal de 1987 prohibió los CFC y se convirtió en el primer tratado medioambiental ratificado por todos los países.","La capa de ozono debería recuperar su nivel de 1980 hacia 2066 sobre la Antártida, según las proyecciones actuales.","Sin esta acción, las tasas de cáncer de piel se habrían multiplicado por cinco en las zonas templadas."];
DEEP_DIVES['p5'].es = ["La calidad del aire en Francia mejoró considerablemente gracias a los filtros de partículas diésel y al auge del coche eléctrico.","Las zonas de baja emisión instaladas en las grandes ciudades francesas aceleraron esta transición.","A nivel europeo, la directiva sobre calidad del aire de 2008 salvó unas 60 000 vidas al año según la Agencia Europea de Medio Ambiente."];
DEEP_DIVES['p6'].es = ["La reforestación en China e India es responsable de la mayor parte de este incremento del 5 % de superficie verde.","El programa chino 'Gran Muralla Verde' plantó más de 66 mil millones de árboles desde 1978.","India plantó 220 millones de árboles en un solo día en 2019 — un récord mundial."];
DEEP_DIVES['p7'].es = ["La central de Ratcliffe-on-Soar, la última del Reino Unido alimentada con carbón, cerró sus puertas en septiembre de 2024.","El Reino Unido fue el primer país en usar carbón para producir electricidad en 1882 — y ahora el primero del G7 en abandonarlo.","En 10 años, la proporción de carbón en la producción eléctrica británica pasó del 40 % a cero."];
DEEP_DIVES['p8'].es = ["Este ensayo clínico utilizó oligonucleótidos antisentido para reducir la producción de la proteína huntingtina mutante en el cerebro.","La enfermedad de Huntington afecta a unas 30 000 personas en Europa — hasta ahora, ningún tratamiento podía frenar su progresión.","Los resultados preliminares mostraron una reducción significativa de la proteína tóxica en el líquido cefalorraquídeo de los pacientes tratados."];
DEEP_DIVES['p9'].es = ["Esta área marina protegida cubre más de un millón de km² de océano en la Polinesia francesa.","Protege ecosistemas coralinos únicos y especies en peligro como la tortuga carey y el tiburón martillo.","Francia posee el segundo espacio marítimo más grande del mundo — esta reserva refuerza su papel en la conservación oceánica."];
DEEP_DIVES['p10'].es = ["En 1990, unos 12 millones de niños menores de 5 años morían cada año. En 2023, esta cifra bajó a menos de 5 millones.","Las vacunas, los mosquiteros y el acceso al agua potable son los tres principales factores de esta espectacular reducción.","Los mayores progresos se observaron en el África subsahariana, donde la mortalidad infantil se redujo a la mitad en 20 años."];
DEEP_DIVES['p11'].es = ["La distribución masiva de mosquiteros impregnados de insecticida redujo la incidencia de la malaria un 40 % en los países más afectados.","Las terapias combinadas a base de artemisinina (ACT) se convirtieron en el tratamiento estándar, salvando millones de vidas.","La vacuna RTS,S, aprobada en 2021, es la primera vacuna contra un parásito en la historia de la medicina — un avance importante."];
DEEP_DIVES['p12'].es = ["En 2010, la energía solar costaba 0,36 $/kWh. En 2023, cuesta menos de 0,05 $/kWh — una caída del 86 %.","Este desplome de precios hace de la solar la fuente de electricidad nueva más barata en el 90 % de los países del mundo.","Un panel solar moderno produce en su vida entre 20 y 40 veces la energía necesaria para fabricarlo."];
DEEP_DIVES['p13'].es = ["En los años 1960, solo quedaban unos 5 000 ejemplares de ballena jorobada en el mundo por la caza comercial.","Gracias a la moratoria de la CBI de 1986, las poblaciones se recuperaron hasta más de 80 000 individuos.","Las ballenas jorobadas también desempeñan un papel ecológico crucial: sus excrementos fertilizan el fitoplancton, que absorbe CO₂."];
DEEP_DIVES['p14'].es = ["En 1990, 1 900 millones de personas vivían con menos de 1,90 $ al día. En 2024, esta cifra bajó a menos de 650 millones.","China por sí sola sacó a más de 800 millones de personas de la pobreza extrema entre 1990 y 2020.","Los Objetivos de Desarrollo Sostenible de la ONU fijaron la erradicación total de la pobreza extrema para 2030."];
DEEP_DIVES['p15'].es = ["La campaña de erradicación de la viruela movilizó a más de 150 000 trabajadores sanitarios en todo el mundo durante más de 10 años.","El último caso natural de viruela fue registrado en Somalia en 1977 — desde entonces, la enfermedad desapareció completamente.","Este éxito demostró que la cooperación internacional puede erradicar una enfermedad — un modelo para la lucha contra la polio."];
DEEP_DIVES['p16'].es = ["Francia ganó un 30 % de superficie forestal desde 1950 — una tendencia opuesta a la deforestación tropical.","En Europa, la superficie forestal aumentó en 17 millones de hectáreas entre 1990 y 2020.","Estos bosques capturan cada año unos 360 millones de toneladas de CO₂ — el equivalente del 10 % de las emisiones europeas."];
DEEP_DIVES['p17'].es = ["El acceso al agua potable segura pasó del 59 % al 73 % de la población mundial entre 2000 y 2023.","Los mayores avances se registraron en el sudeste asiático, donde la tasa de acceso casi se duplicó.","Sin embargo, 2 200 millones de personas aún carecen de acceso a agua gestionada de forma segura — un desafío importante."];
DEEP_DIVES['p18'].es = ["Las ventas de vehículos eléctricos superaron los 14 millones de unidades en 2023, representando el 18 % de los coches nuevos.","China representa más de la mitad de estas ventas, seguida de Europa y Estados Unidos.","El precio de las baterías cayó un 89 % desde 2010, haciendo los coches eléctricos cada vez más accesibles."];
DEEP_DIVES['p19'].es = ["El Índice Planeta Vivo del WWF muestra una recuperación de la fauna en las zonas protegidas en varios continentes.","Las poblaciones de tigres aumentaron un 40 % desde 2010 gracias a la lucha contra la caza furtiva.","Las áreas marinas protegidas también muestran resultados: las poblaciones de peces se recuperan un 670 % más rápido dentro de las reservas."];
DEEP_DIVES['p20'].es = ["La proporción de la población mundial afectada por la hambruna pasó del 15 % en 1990 al 8 % en 2023.","La revolución verde y las mejoras en los rendimientos agrícolas son las principales causas de esta reducción.","Sin embargo, el cambio climático amenaza estos avances — las sequías e inundaciones podrían revertir las tendencias."];
DEEP_DIVES['u1'].es = ["El potasio-40, un isótopo naturalmente presente en los plátanos, emite una muy débil radiación beta.","La dosis radiactiva de un plátano (0,1 microsievert) es tan ínfima que necesitarías comer 10 millones de golpe para sentir el menor efecto.","Este concepto es tan popular que se convirtió en una unidad informal de medida de la radiación: la 'dosis equivalente en plátano'."];
DEEP_DIVES['u2'].es = ["La cucaracha sobrevive a la decapitación porque su sistema nervioso está descentralizado — no depende enteramente del cerebro.","Puede seguir moviéndose, reaccionando al tacto e incluso esquivando los obstáculos durante varios días sin cabeza.","Muere finalmente de deshidratación porque ya no puede beber — su cuerpo pierde agua sin control."];
DEEP_DIVES['u3'].es = ["La tabla periódica contiene 118 elementos confirmados en 2024, cada uno designado por una o dos letras.","La letra J nunca fue necesaria porque los elementos se nombraron según el latín, el griego o los nombres de sus descubridores.","La IUPAC (Unión Internacional de Química Pura y Aplicada) valida cada nuevo nombre según reglas estrictas de nomenclatura."];
DEEP_DIVES['u4'].es = ["A -183 °C, el oxígeno se condensa en un líquido azul pálido con propiedades magnéticas sorprendentes.","Este color azulado proviene de la absorción de la luz roja por las moléculas de O₂ en estado líquido.","El oxígeno líquido es tan fuertemente paramagnético que puede ser atraído por un imán — un fenómeno espectacular para demostraciones científicas."];
DEEP_DIVES['u5'].es = ["El Ophiocordyceps modifica el comportamiento de la hormiga haciéndola trepar a una altura precisa antes de matarla.","La hormiga infectada muerde una hoja o rama en un ángulo preciso — un comportamiento nunca observado en hormigas sanas.","Desde la cabeza de la hormiga muerta, el hongo crece un tallo que libera esporas sobre las hormigas de abajo — perpetuando el ciclo."];
DEEP_DIVES['u6'].es = ["El estómago produce unos 2 litros de ácido clorhídrico al día — lo suficiente para corroer un clavo.","Una capa de moco de solo 1 mm de espesor protege las paredes gástricas contra este ácido.","Cuando esta protección falla, se produce una úlcera — en el 90 % de los casos causada por la bacteria Helicobacter pylori."];
DEEP_DIVES['u7'].es = ["Se estima que el universo observable contiene entre 200 y 2 000 mil millones de galaxias, cada una con miles de millones de estrellas.","En comparación, todas las playas y desiertos de la Tierra contienen unos 7,5 quintillones de granos de arena.","Cada grano de arena que sostienes entre los dedos representa unos 10 000 estrellas en el universo observable."];
DEEP_DIVES['u8'].es = ["El pulpo de anillos azules produce tetrodotoxina, la misma toxina que se encuentra en el pez globo.","Un solo pulpo lleva suficiente veneno para matar a 26 adultos, y no existe antídoto conocido.","A pesar de su letalidad, mide solo 12 a 20 cm y suele ser tímido — solo pica cuando se siente amenazado directamente."];
DEEP_DIVES['u9'].es = ["La boca humana contiene entre 500 y 700 especies diferentes de bacterias, formando un ecosistema complejo llamado microbioma oral.","Tu teléfono alberga en promedio 25 000 bacterias por cm² — 10 veces más que un asiento de inodoro.","El 80 % de las bacterias en tu boca son inofensivas o incluso beneficiosas — participan activamente en la digestión y la protección contra los patógenos."];
DEEP_DIVES['u10'].es = ["La energía térmica total de un iceberg, aunque a 0 °C, es inmensa porque depende de la masa — y un iceberg puede pesar millones de toneladas.","Una cerilla encendida está mucho más caliente (800 °C), pero su masa ínfima le da una energía total ridícula.","Este principio ilustra la diferencia fundamental entre temperatura (agitación molecular) y energía térmica (temperatura × masa)."];
// ── FUN u11-u20 ──

DEEP_DIVES['u11'].es = ["El término «tittle» proviene del latín titulus, que significa inscripción o marca.","En tipografía, el punto sobre la i es tan importante que olvidarlo puede cambiar el significado de una palabra en ciertos idiomas.","La letra J no existía antes del siglo XVI — se separó de la I en las lenguas europeas, y ambas conservaron su tittle."];

DEEP_DIVES['u12'].es = ["El primatólogo Tetsuro Matsuzawa demostró en 2007 que los chimpancés jóvenes memorizan secuencias numéricas con una rapidez que supera a cualquier humano adulto.","Esta capacidad se denomina memoria eidética de trabajo y podría ser un vestigio evolutivo que los humanos perdieron al desarrollar el lenguaje.","El chimpancé estrella del estudio, Ayumu, logra recordar la posición de nueve dígitos mostrados durante apenas 210 milisegundos."];

DEEP_DIVES['u13'].es = ["La enzima PETasa fue descubierta por casualidad en 2016 en una bacteria japonesa que vivía cerca de una planta de reciclaje de plástico.","En 2022, investigadores de la Universidad de Texas crearon una variante optimizada capaz de degradar el PET en tan solo unas horas a temperatura ambiente.","Este avance podría revolucionar el reciclaje: en lugar de fundir el plástico, la enzima lo descompone en sus componentes químicos originales, reutilizables al 100 %."];

DEEP_DIVES['u14'].es = ["Un estudio publicado en Scientific Reports en 2019 demostró que los gatos domésticos distinguen su nombre de otras palabras, incluso pronunciadas por desconocidos.","A diferencia de los perros, los gatos no han sido seleccionados genéticamente para obedecer — su domesticación fue un proceso mucho más reciente y menos dirigido.","Los investigadores observaron que los gatos reaccionan con movimientos sutiles de orejas y cabeza, pero rara vez se acercan — una indiferencia perfectamente calculada."];

DEEP_DIVES['u15'].es = ["Los flamencos nacen con plumaje gris o blanco — su color rosado aparece gradualmente gracias a los pigmentos carotenoides de su dieta de crustáceos y algas.","En cautiverio, los flamencos pueden perder su color si no reciben una alimentación adecuada, por lo que los zoológicos añaden suplementos de carotenoides a su comida.","El término «flamboyance» para un grupo de flamencos proviene del francés antiguo flambe (llama), aludiendo al espectáculo visual de una bandada en vuelo."];

DEEP_DIVES['u16'].es = ["El camarón pistola cierra su pinza a tal velocidad que genera una burbuja de cavitación cuyo colapso produce un destello de luz y temperaturas cercanas a 4 700 °C.","El chasquido resultante alcanza los 218 decibelios bajo el agua — más fuerte que un disparo de arma de fuego y suficiente para aturdir o matar a pequeñas presas.","Colonias de camarones pistola producen tanto ruido que interfieren con los sónares de los submarinos militares, creando un muro de sonido subacuático."];

DEEP_DIVES['u17'].es = ["La mantis marina (Stomatopoda) posee los golpes más rápidos del reino animal: su pinza se despliega en menos de 3 milisegundos, alcanzando una aceleración comparable a la de una bala calibre .22.","El impacto es tan violento que genera burbujas de cavitación que colapsan a temperaturas de hasta 4 000 °C, causando un segundo golpe de daño a la presa.","Sus ojos son los más complejos conocidos: detectan 16 tipos de receptores de color (los humanos tienen 3) y perciben luz polarizada y ultravioleta."];

DEEP_DIVES['u18'].es = ["Los arenques expulsan burbujas de aire por el ano para comunicarse en la oscuridad del fondo marino — un mecanismo llamado Fast Repetitive Tick (FRT).","Los investigadores Ben Wilson y Bob Batty descubrieron este fenómeno en 2003 y recibieron el Premio Ig Nobel de Biología por su hallazgo.","Estas burbujas no son producto de la digestión: los arenques tragan aire en la superficie y lo liberan voluntariamente, probablemente para mantener cohesión en el cardumen durante la noche."];

DEEP_DIVES['u19'].es = ["El proyecto Belly Button Biodiversity de la Universidad de Carolina del Norte identificó más de 2 300 especies de bacterias en los ombligos de apenas 60 voluntarios.","Cada persona alberga una combinación única de microorganismos — una especie de huella digital bacteriana imposible de duplicar.","Entre los hallazgos más sorprendentes: bacterias típicas del suelo japonés en alguien que nunca había visitado Japón, y arqueas normalmente asociadas a fuentes termales."];

DEEP_DIVES['u20'].es = ["Los bogavantes escapan de los depredadores mediante un reflejo llamado «caridoid escape reaction»: flexionan su cola musculosa y se propulsan hacia atrás a más de 5 m/s.","Esta técnica es tan eficaz que algunos bogavantes pueden recorrer varios metros en una sola sacudida, desapareciendo de la vista del depredador en milisegundos.","A pesar de su fama culinaria, los bogavantes pueden vivir más de 100 años y no muestran signos de envejecimiento biológico — un fenómeno llamado senescencia despreciable."];

// ── HISTORY h1-h30 ──

DEEP_DIVES['h1'].es = ["La orina humana contiene amoníaco de forma natural, un potente desengrasante y blanqueador utilizado en la antigüedad.","Los romanos instalaban urinarios públicos (llamados fullonicae) donde los artesanos recogían la orina para lavar las togas — un negocio tan lucrativo que el emperador Vespasiano le impuso un impuesto.","De esta anécdota nació la célebre frase «Pecunia non olet» (el dinero no huele), atribuida a Vespasiano cuando su hijo Tito criticó el impuesto."];

DEEP_DIVES['h2'].es = ["Las pirámides de Guiza fueron construidas alrededor del 2560 a.C., mientras que Cleopatra VII nació en el 69 a.C. — más de 2 400 años de diferencia.","Cleopatra vivió más cerca del lanzamiento del iPhone (2007) que de la construcción de las pirámides — una perspectiva que desafía nuestra percepción lineal de la historia.","Cleopatra fue la última gobernante de la dinastía ptolemaica, una familia de origen macedonio que gobernó Egipto durante casi 300 años tras la conquista de Alejandro Magno."];

DEEP_DIVES['h3'].es = ["El fuego griego era un arma incendiaria que ardía incluso sobre el agua y resistía al viento, utilizada por el Imperio Bizantino desde el siglo VII.","Su composición exacta sigue siendo un misterio: los historiadores sospechan una mezcla de nafta, azufre, cal viva y posiblemente salitre.","Esta arma fue decisiva en varias batallas navales contra los árabes y contribuyó a mantener Constantinopla durante siglos — un auténtico secreto de Estado que murió con el Imperio."];

DEEP_DIVES['h4'].es = ["Los vikingos utilizaban cristales de calcita islandesa, llamados «piedras solares», para detectar la posición del sol en días nublados o con niebla.","El cristal birrefringente descompone la luz en dos haces polarizados: al girar la piedra, la diferencia de intensidad revela la dirección del sol oculto.","En 2013, investigadores franceses demostraron experimentalmente que esta técnica funciona con una precisión de ±1°, suficiente para navegar entre Noruega y Groenlandia."];

DEEP_DIVES['h5'].es = ["La Universidad de Oxford comenzó a impartir clases hacia 1096, cuando profesores ingleses fueron expulsados de la Universidad de París.","La capital azteca Tenochtitlán fue fundada en 1325, más de dos siglos después — cuando Oxford ya era una institución consolidada con varios colleges.","Esta comparación ilustra lo engañoso de las líneas temporales eurocéntricas: civilizaciones sofisticadas florecían simultáneamente en distintas partes del mundo, a menudo sin contacto entre sí."];

DEEP_DIVES['h6'].es = ["Desde la órbita terrestre baja (~400 km), la Gran Muralla China es demasiado estrecha (5-8 metros) para ser vista a simple vista por los astronautas.","El mito probablemente se originó en 1932, antes de la era espacial, en un libro de Robert Ripley (Believe It or Not!) que especulaba sobre su visibilidad.","En 2003, el astronauta chino Yang Liwei confirmó que no pudo ver la Muralla desde el espacio — una declaración que causó gran decepción nacional."];

DEEP_DIVES['h7'].es = ["Las naumaquias eran espectáculos navales en los que el Coliseo u otros anfiteatros se inundaban parcialmente para recrear batallas marítimas.","Julio César organizó la primera naumaquia conocida en el 46 a.C. en un lago artificial excavado junto al Tíber, con 2 000 combatientes y 4 000 remeros.","El sistema de inundación del Coliseo, que utilizaba canales subterráneos y el acueducto Aqua Claudia, es considerado una de las mayores proezas de ingeniería hidráulica de la Antigüedad."];

DEEP_DIVES['h8'].es = ["Napoleón medía 1,69 m, ligeramente por encima de la media francesa de la época (1,64 m).","La confusión se debe a la diferencia entre las unidades francesas y británicas: su estatura de «5 pieds 2 pouces» en medida francesa equivale a unos 5 pies 7 pulgadas en medida británica, pero los británicos usaron su propia escala.","La propaganda británica caricaturizó a Napoleón como un hombrecillo furioso — una imagen que perduró en la cultura popular gracias a dibujantes como James Gillray."];

DEEP_DIVES['h9'].es = ["Los papiros egipcios del 1550 a.C. (Papiro de Ebers) ya describen métodos anticonceptivos a base de miel, acacia fermentada y fibras vegetales.","El ácido láctico producido por la acacia fermentada actúa efectivamente como espermicida — un hallazgo confirmado por estudios modernos de laboratorio.","Los egipcios también utilizaban tapones de lino empapados en sustancias ácidas como barreras físicas, anticipando en miles de años el concepto del diafragma moderno."];

DEEP_DIVES['h10'].es = ["La Biblioteca de Alejandría fue fundada por Ptolomeo I alrededor del 295 a.C. y llegó a albergar entre 400 000 y 700 000 rollos de papiro.","Contrariamente al mito popular, no fue destruida en un solo incendio: sufrió daños durante el asedio de Julio César (48 a.C.), un terremoto en 365 d.C. y recortes presupuestarios progresivos.","Su institución hermana, el Serapeo, sobrevivió hasta el 391 d.C., cuando fue destruido durante los disturbios religiosos ordenados por el obispo Teófilo de Alejandría."];

DEEP_DIVES['h11'].es = ["La Peste Negra (1347-1353) mató entre 75 y 200 millones de personas en Eurasia, eliminando entre el 30 % y el 60 % de la población europea.","La pandemia fue causada por la bacteria Yersinia pestis, transmitida por pulgas que viajaban en ratas negras a lo largo de las rutas comerciales.","Paradójicamente, la despoblación masiva mejoró las condiciones de los supervivientes: los salarios subieron, la servidumbre retrocedió y se aceleró la innovación tecnológica para compensar la falta de mano de obra."];

DEEP_DIVES['h12'].es = ["Los samuráis constituían la clase guerrera del Japón feudal desde el siglo XII hasta la abolición del sistema de castas en 1876 durante la era Meiji.","Además de guerreros, muchos samuráis eran poetas, calígrafos y filósofos: el bushido (camino del guerrero) exigía tanto dominio marcial como refinamiento cultural.","El último gran enfrentamiento samurái fue la Rebelión de Satsuma en 1877, cuando guerreros tradicionalistas se alzaron contra la modernización del ejército imperial — un episodio que inspiró numerosas obras de ficción."];

DEEP_DIVES['h13'].es = ["La Piedra Rosetta fue descubierta en 1799 por soldados franceses durante la campaña de Napoleón en Egipto, cerca de la ciudad de Rashid (Rosetta).","Contiene el mismo decreto en tres escrituras: jeroglíficos egipcios, escritura demótica y griego antiguo, lo que permitió descifrar los jeroglíficos por comparación.","Jean-François Champollion logró descifrar los jeroglíficos en 1822, abriendo la puerta a toda la egiptología moderna — la piedra se conserva hoy en el Museo Británico."];

DEEP_DIVES['h14'].es = ["Pompeya fue sepultada bajo metros de ceniza y piedra pómez tras la erupción del Vesubio el 24 de agosto del 79 d.C., preservando la ciudad en un estado extraordinario.","Las excavaciones, iniciadas en 1748, revelaron calles, frescos, grafitis, tabernas e incluso moldes de los cuerpos de las víctimas congelados en sus últimos instantes.","Pompeya nos ofrece una ventana única a la vida cotidiana romana: desde la publicidad electoral pintada en las paredes hasta los menús de las termas y los burdeles."];

DEEP_DIVES['h15'].es = ["Gengis Kan unificó las tribus mongolas en 1206 y construyó el mayor imperio terrestre contiguo de la historia, que se extendía de Corea a Europa Central.","A pesar de su reputación de conquistador brutal, Gengis Kan instauró la libertad religiosa, un sistema postal eficiente (el Yam) y un código legal escrito (el Yasaq).","Estudios genéticos sugieren que aproximadamente el 0,5 % de la población mundial masculina desciende directamente de Gengis Kan — unos 16 millones de hombres."];

DEEP_DIVES['h16'].es = ["La Revolución Francesa comenzó en 1789 con la toma de la Bastilla y transformó radicalmente la estructura política y social de Francia y de Europa entera.","La guillotina, adoptada como método de ejecución «humanitario» en 1792, se convirtió en símbolo del Terror — periodo en el que más de 16 000 personas fueron ejecutadas.","Los ideales revolucionarios de libertad, igualdad y fraternidad inspiraron movimientos democráticos en todo el mundo y sentaron las bases del concepto moderno de derechos humanos."];

DEEP_DIVES['h17'].es = ["La Ruta de la Seda era una red de rutas comerciales que conectaba China con el Mediterráneo desde el siglo II a.C. hasta el siglo XV.","Además de seda, se intercambiaban especias, metales preciosos, cerámicas, papel y pólvora — pero también ideas, religiones y enfermedades.","La Ruta de la Seda facilitó la difusión del budismo hacia China, del islam hacia Asia Central y de la peste negra hacia Europa — un ejemplo temprano de globalización."];

DEEP_DIVES['h18'].es = ["Los mayas desarrollaron un sistema matemático vigesimal (base 20) y fueron una de las primeras civilizaciones en concebir el concepto del cero como número.","Su calendario, el Cuenta Larga, era tan preciso que calculaba el año solar con un error de solo 17,31 segundos — más exacto que el calendario gregoriano.","Contrariamente al mito popular, la civilización maya no desapareció: más de 6 millones de descendientes mayas viven hoy en Guatemala, México y Belice, conservando sus lenguas y tradiciones."];

DEEP_DIVES['h19'].es = ["El Muro de Berlín dividió la ciudad durante 28 años (1961-1989), separando familias y simbolizando la división ideológica de la Guerra Fría.","Al menos 140 personas murieron intentando cruzar el Muro, que estaba protegido por torres de vigilancia, alambradas, minas y una franja de muerte de 100 metros.","Su caída el 9 de noviembre de 1989 fue en gran parte accidental: un portavoz del gobierno de la RDA anunció prematuramente la apertura de fronteras, provocando una avalancha masiva de ciudadanos."];

DEEP_DIVES['h20'].es = ["Leonardo da Vinci fue un genio polifacético del Renacimiento: pintor, escultor, ingeniero, anatomista, músico, arquitecto e inventor.","Sus cuadernos contienen diseños de máquinas voladoras, tanques de guerra, escafandras y robots — conceptos adelantados varios siglos a su época.","La Mona Lisa, su obra más célebre, se encuentra detrás de un cristal blindado en el Louvre y recibe más de 10 millones de visitantes al año — es probablemente el cuadro más famoso del mundo."];

DEEP_DIVES['h21'].es = ["La escritura cuneiforme, inventada en Sumeria hacia el 3400 a.C., es uno de los sistemas de escritura más antiguos conocidos.","Se grababa con un estilete en tablillas de arcilla húmeda — el nombre «cuneiforme» proviene del latín cuneus (cuña) por la forma de las marcas.","Miles de tablillas cuneiformes han sobrevivido hasta hoy gracias a la durabilidad de la arcilla cocida, preservando registros comerciales, leyes, poemas y recetas de cerveza."];

DEEP_DIVES['h22'].es = ["Los gladiadores romanos rara vez luchaban a muerte: eran inversiones costosas, entrenados durante años y alimentados con dietas especiales ricas en cebada.","Los combates seguían reglas estrictas supervisadas por un árbitro, y los gladiadores famosos gozaban de una popularidad comparable a la de las estrellas del deporte actual.","Un gladiador caído podía pedir clemencia (missio) y sobrevivir si había luchado con valor — la señal del pulgar hacia abajo que conocemos del cine es probablemente un invento moderno."];

DEEP_DIVES['h23'].es = ["Cleopatra hablaba al menos nueve idiomas y fue la primera gobernante ptolemaica en aprender egipcio — sus antecesores solo hablaban griego.","Lejos de la imagen de seductora frívola, Cleopatra era una hábil estratega política que negoció alianzas con Julio César y Marco Antonio para preservar la independencia de Egipto.","Su muerte en el 30 a.C. marcó el fin del Egipto faraónico y el comienzo de la dominación romana sobre todo el Mediterráneo oriental."];

DEEP_DIVES['h24'].es = ["Los vikingos llegaron a América del Norte alrededor del año 1000 d.C., casi 500 años antes que Cristóbal Colón.","El asentamiento de L'Anse aux Meadows, en Terranova (Canadá), es la única colonia vikinga confirmada arqueológicamente en el continente americano.","Los vikingos llamaron a estas tierras Vinland (tierra del vino) por las uvas silvestres que encontraron — pero abandonaron la colonia tras pocos años debido a conflictos con los pueblos indígenas."];

DEEP_DIVES['h25'].es = ["La Gran Pirámide de Guiza, construida hacia el 2560 a.C., fue la estructura más alta del mundo durante más de 3 800 años, hasta la construcción de la catedral de Lincoln en 1311.","Sus 2,3 millones de bloques de piedra caliza, de unas 2,5 toneladas cada uno, fueron transportados y colocados con una precisión milimétrica que aún desconcierta a los ingenieros modernos.","Contrariamente al mito, las pirámides no fueron construidas por esclavos sino por trabajadores asalariados que vivían en aldeas cercanas y recibían raciones de pan y cerveza."];

DEEP_DIVES['h26'].es = ["El Imperio Romano, en su apogeo bajo Trajano (117 d.C.), se extendía desde Escocia hasta Mesopotamia y albergaba entre 60 y 70 millones de habitantes.","Los romanos construyeron más de 80 000 km de carreteras pavimentadas, muchas de las cuales sirvieron de base para las redes viarias europeas modernas.","La caída del Imperio Romano de Occidente en 476 d.C. no fue un evento repentino sino un proceso gradual de fragmentación política, presión migratoria y crisis económica."];

DEEP_DIVES['h27'].es = ["La imprenta de tipos móviles, inventada por Gutenberg hacia 1440, transformó radicalmente la difusión del conocimiento en Europa.","Antes de la imprenta, copiar un libro a mano requería meses de trabajo; la imprenta reducía ese tiempo a días, democratizando el acceso a la información.","La Biblia de Gutenberg (1455) fue el primer libro impreso en masa en Occidente — se conservan 49 ejemplares, cada uno valorado en varios millones de euros."];

DEEP_DIVES['h28'].es = ["El antiguo Egipto veneró a los gatos durante milenios: la diosa Bastet, representada con cabeza felina, simbolizaba la protección del hogar y la fertilidad.","Matar a un gato, incluso accidentalmente, podía castigarse con la pena de muerte — y los gatos eran momificados con el mismo cuidado que los humanos.","Cuando moría un gato doméstico, los miembros de la familia se afeitaban las cejas en señal de duelo — una práctica documentada por el historiador griego Heródoto."];

DEEP_DIVES['h29'].es = ["La Guerra de los Cien Años (1337-1453) entre Francia e Inglaterra duró en realidad 116 años e incluyó largos periodos de tregua.","Juana de Arco, una campesina analfabeta de 17 años, lideró las tropas francesas en una serie de victorias decisivas antes de ser capturada, juzgada por herejía y quemada viva en 1431.","La guerra aceleró la transición del feudalismo al Estado-nación moderno y popularizó el uso de la artillería con pólvora, que volvió obsoletas las fortificaciones medievales."];

DEEP_DIVES['h30'].es = ["Las Cruzadas fueron una serie de expediciones militares y religiosas entre 1096 y 1291, destinadas a recuperar Tierra Santa del control musulmán.","Más allá de la guerra, las Cruzadas provocaron un intenso intercambio cultural: los europeos descubrieron el azúcar, las especias, los números arábigos y nuevas técnicas médicas y arquitectónicas.","El impacto económico fue considerable: las Cruzadas impulsaron el comercio mediterráneo y enriquecieron ciudades como Venecia, Génova y Pisa, sentando las bases del capitalismo comercial europeo."];

// ── SPACE sp1-sp30 ──

DEEP_DIVES['sp1'].es = ["Venus tarda 243 días terrestres en completar una rotación sobre su eje, pero solo 225 días en orbitar el Sol — su día es más largo que su año.","Además, Venus gira en sentido retrógrado (de este a oeste), por lo que el Sol sale por el oeste y se pone por el este.","Las nubes de ácido sulfúrico de Venus reflejan tanta luz solar que es el planeta más brillante visto desde la Tierra, conocido como «lucero del alba» o «estrella vespertina»."];

DEEP_DIVES['sp2'].es = ["La densidad media de Saturno es de 0,687 g/cm³, inferior a la del agua (1 g/cm³), lo que teóricamente le permitiría flotar.","Sus famosos anillos están compuestos principalmente de hielo y roca, y se extienden hasta 282 000 km del planeta, pero tienen un grosor de apenas 10 metros.","Saturno posee al menos 146 lunas confirmadas — la más grande, Titán, tiene una atmósfera densa y lagos de metano líquido en su superficie."];

DEEP_DIVES['sp3'].es = ["En el núcleo del Sol, los fotones son absorbidos y reemitidos tantas veces que tardan entre 10 000 y 170 000 años en alcanzar la superficie.","Este proceso se llama «camino aleatorio» (random walk): cada fotón recorre una distancia microscópica antes de ser absorbido por otro átomo.","Una vez en la superficie, la luz viaja en línea recta y tarda solo 8 minutos y 20 segundos en llegar a la Tierra, recorriendo 150 millones de kilómetros."];

DEEP_DIVES['sp4'].es = ["La Voyager 1, lanzada el 5 de septiembre de 1977, es el objeto fabricado por el ser humano más lejano de la Tierra, a más de 24 000 millones de km del Sol.","Lleva a bordo un disco dorado con sonidos, música e imágenes de la Tierra, concebido como mensaje para posibles civilizaciones extraterrestres.","A pesar de la distancia, sigue comunicándose con la Tierra: sus señales de radio, viajando a la velocidad de la luz, tardan más de 22 horas en llegar."];

DEEP_DIVES['sp5'].es = ["El Olympus Mons es un volcán escudo de 21,9 km de altura y 600 km de diámetro — su base cubriría la totalidad de Francia.","Su enorme tamaño se explica por la ausencia de tectónica de placas en Marte: el punto caliente volcánico permaneció fijo durante millones de años, acumulando lava.","A pesar de su altura, la pendiente del Olympus Mons es tan suave (5°) que un observador en su base no podría ver la cima — quedaría oculta por la curvatura del horizonte."];

DEEP_DIVES['sp6'].es = ["La nieve de CO₂ en Marte fue detectada por la sonda Mars Reconnaissance Orbiter en 2012 mediante su espectrómetro infrarrojo.","Las partículas de hielo seco se subliman (pasan de sólido a gas) antes de tocar el suelo, creando un fenómeno de «nieve fantasma» única en el sistema solar.","Los polos marcianos están cubiertos por casquetes permanentes de hielo de agua y CO₂ cuyo avance y retroceso estacional es visible desde la Tierra con un telescopio potente."];

DEEP_DIVES['sp7'].es = ["La Luna se aleja de la Tierra a un ritmo de 3,8 cm por año debido a las fuerzas de marea que transfieren energía rotacional de la Tierra a la órbita lunar.","Hace 4 500 millones de años, la Luna estaba mucho más cerca y los días terrestres duraban solo 5 horas — las mareas eran gigantescas.","Dentro de unos 600 millones de años, la Luna estará tan lejos que no cubrirá completamente el disco solar, poniendo fin a los eclipses totales de Sol."];

DEEP_DIVES['sp8'].es = ["En 2009, astrónomos del Instituto Max Planck detectaron etil formiato y ácido cianhídrico en la nube Sagitario B2, cerca del centro de la Vía Láctea.","El etil formiato es la molécula responsable del aroma de las frambuesas y del sabor del ron — de ahí la curiosa descripción del «olor del espacio».","En realidad, el espacio interplanetario tiene otro olor: los astronautas describen un olor metálico a carne quemada en sus trajes tras las caminatas espaciales, causado por átomos de oxígeno atómico."];

DEEP_DIVES['sp9'].es = ["Las estrellas de neutrones se forman cuando una estrella masiva colapsa al final de su vida, comprimiendo su núcleo hasta una densidad inimaginable.","Una cucharadita de su materia pesaría alrededor de mil millones de toneladas — equivalente al peso del monte Fuji concentrado en un volumen diminuto.","Algunas estrellas de neutrones giran a velocidades vertiginosas: los púlsares más rápidos completan más de 700 rotaciones por segundo."];

DEEP_DIVES['sp10'].es = ["Los agujeros negros son regiones del espacio-tiempo donde la gravedad es tan intensa que nada, ni siquiera la luz, puede escapar una vez cruzado el horizonte de sucesos.","En 2019, el proyecto Event Horizon Telescope capturó la primera imagen directa de un agujero negro, situado en el centro de la galaxia M87, a 55 millones de años luz.","Según la relatividad general, el tiempo se ralentiza cerca de un agujero negro: un observador externo vería a un objeto caer cada vez más lento, sin cruzar nunca el horizonte."];

DEEP_DIVES['sp11'].es = ["La Estación Espacial Internacional orbita la Tierra a unos 408 km de altitud y viaja a 27 600 km/h, completando una vuelta cada 90 minutos.","Sus tripulantes experimentan 16 amaneceres y 16 atardeceres cada día — la ISS es visible a simple vista como un punto luminoso que cruza el cielo nocturno.","La ISS es el objeto más caro jamás construido por la humanidad: su coste total supera los 150 000 millones de dólares, financiados por 15 países."];

DEEP_DIVES['sp12'].es = ["Un año-luz equivale a unos 9,46 billones de kilómetros — la distancia que la luz recorre en un año viajando a 300 000 km/s.","La estrella más cercana al Sol, Próxima Centauri, está a 4,24 años-luz. Con la tecnología actual, un viaje hasta allí tomaría más de 70 000 años.","El universo observable tiene un radio de unos 46 000 millones de años-luz, pero su tamaño real podría ser infinito — solo podemos ver la luz que ha tenido tiempo de llegar hasta nosotros."];

DEEP_DIVES['sp13'].es = ["La nébulosa del Boomerang, situada a 5 000 años-luz de la Tierra, tiene una temperatura de −272 °C, apenas un grado por encima del cero absoluto.","Esta temperatura extrema se debe a la rápida expansión del gas que emite la estrella central, un fenómeno similar al enfriamiento que se produce al abrir una lata de aerosol.","El cero absoluto (−273,15 °C o 0 kelvin) es inalcanzable según las leyes de la termodinámica, pero los científicos han logrado enfriar átomos hasta una milmillonésima de grado por encima."];

DEEP_DIVES['sp14'].es = ["Las estrellas de neutrones tienen un diámetro de apenas 20 km pero una masa equivalente a 1,4 veces la del Sol.","Su campo magnético es billones de veces más intenso que el de la Tierra — suficiente para reorganizar los átomos y crear una superficie de hierro cristalino.","Los magnetares, un tipo especial de estrella de neutrones, emiten destellos de rayos gamma tan potentes que uno situado a medio camino de la Vía Láctea podría dañar la capa de ozono terrestre."];

DEEP_DIVES['sp15'].es = ["La Voyager 1 entró en el espacio interestelar en agosto de 2012, convirtiéndose en el primer objeto humano en abandonar la heliosfera.","Su fuente de energía, un generador termoeléctrico de radioisótopos de plutonio-238, pierde potencia gradualmente — los científicos estiman que dejará de funcionar hacia 2025-2030.","La placa dorada a bordo incluye saludos en 55 idiomas, sonidos de la naturaleza, música de Bach, Mozart y Chuck Berry, y 116 imágenes codificadas de la Tierra."];

DEEP_DIVES['sp16'].es = ["El Olympus Mons entró en erupción por última vez hace unos 25 millones de años, pero los científicos no descartan que pueda estar aún activo en su interior.","Su caldera, de 80 km de ancho, contiene seis cráteres superpuestos formados por erupciones sucesivas a lo largo de millones de años.","La baja gravedad de Marte (38 % de la terrestre) es la razón principal por la que las montañas marcianas pueden alcanzar alturas imposibles en la Tierra."];

DEEP_DIVES['sp17'].es = ["La Luna tarda exactamente el mismo tiempo en rotar sobre su eje que en orbitar la Tierra (27,3 días), un fenómeno llamado rotación síncrona.","Esta sincronización no es una coincidencia: las fuerzas de marea terrestres frenaron gradualmente la rotación lunar hasta bloquearla en su posición actual.","El lado oculto de la Luna, fotografiado por primera vez por la sonda soviética Luna 3 en 1959, tiene una corteza más gruesa y muchos menos mares (llanuras de lava) que el lado visible."];

DEEP_DIVES['sp18'].es = ["La Gran Mancha Roja de Júpiter es un anticiclón persistente observado desde al menos 1665 — ha durado más que cualquier fenómeno meteorológico terrestre.","Su tamaño ha disminuido durante el último siglo: pasó de poder contener 3 Tierras a apenas 1,3 en la actualidad, aunque su viento sigue soplando a más de 640 km/h.","Júpiter no tiene superficie sólida: bajo las nubes hay capas de hidrógeno gaseoso, líquido y finalmente hidrógeno metálico a presiones de millones de atmósferas."];

DEEP_DIVES['sp19'].es = ["Se estima que el universo observable contiene unas 2 billones (2 × 10¹²) de galaxias, cada una con miles de millones de estrellas.","El número total de estrellas ronda los 10²⁴ (un cuatrillón), mientras que los granos de arena de la Tierra se estiman en unos 7,5 × 10¹⁸.","A pesar de estas cifras vertiginosas, el universo está compuesto en un 99,9999 % de vacío — la materia es una excepción extraordinariamente rara."];

DEEP_DIVES['sp20'].es = ["El sonido necesita un medio material (aire, agua, metal) para propagarse — en el vacío del espacio, no hay moléculas que puedan transmitir las ondas.","Sin embargo, en 2022 la NASA publicó una «sonificación» de datos del telescopio Chandra: ondas de presión en el gas caliente del cúmulo de Perseo, traducidas a frecuencias audibles.","Las nebulosas y los cúmulos de gas sí transmiten vibraciones, pero a frecuencias tan bajas (un Si bemol, 57 octavas por debajo del do central) que ningún oído humano podría detectarlas."];

DEEP_DIVES['sp21'].es = ["Plutón fue descubierto en 1930 por Clyde Tombaugh y clasificado como planeta durante 76 años hasta su reclasificación como planeta enano por la UAI en 2006.","La decisión fue polémica: Plutón no cumple el tercer criterio de planeta (haber limpiado su órbita de otros objetos), ya que comparte el cinturón de Kuiper con miles de cuerpos similares.","La sonda New Horizons reveló en 2015 que Plutón tiene montañas de hielo de agua de 3 500 m, glaciares de nitrógeno y una fina atmósfera de metano — mucho más complejo de lo esperado."];

DEEP_DIVES['sp22'].es = ["Los anillos de Saturno están compuestos en un 99 % de hielo de agua, con partículas que van desde granos de arena hasta bloques del tamaño de una casa.","Aunque parecen sólidos, los anillos tienen un grosor de apenas 10 metros de media — una estructura increíblemente delgada en proporción a su extensión de 282 000 km.","Estudios recientes sugieren que los anillos podrían tener solo 100 millones de años — relativamente jóvenes en la escala cósmica — y que podrían desaparecer dentro de otros 100 millones."];

DEEP_DIVES['sp23'].es = ["La Vía Láctea contiene entre 100 000 y 400 000 millones de estrellas y tiene un diámetro de unos 100 000 años-luz.","Nuestro sistema solar se encuentra en el brazo de Orión, a unos 26 000 años-luz del centro galáctico, y tarda 230 millones de años en completar una órbita.","En el centro de la Vía Láctea se encuentra Sagitario A*, un agujero negro supermasivo con una masa de 4 millones de soles, cuya primera imagen fue capturada en 2022."];

DEEP_DIVES['sp24'].es = ["Los cometas son cuerpos de hielo, polvo y roca que orbitan el Sol en trayectorias elípticas muy alargadas, procedentes del cinturón de Kuiper o la nube de Oort.","Al acercarse al Sol, el hielo se sublima y forma la característica cola, que siempre apunta en dirección opuesta al Sol debido a la presión de la radiación solar.","El cometa Halley, visible cada 75-76 años, ha sido observado desde al menos el 240 a.C. y su próximo paso será en 2061."];

DEEP_DIVES['sp25'].es = ["Marte tiene dos lunas diminutas, Fobos y Deimos, nombradas así por los hijos del dios Ares (Marte) en la mitología griega: el Miedo y el Terror.","Fobos se acerca a Marte 1,8 cm por año y será destruido por las fuerzas de marea en unos 50 millones de años, formando posiblemente un anillo temporal.","Ambas lunas son probablemente asteroides capturados por la gravedad marciana, dada su forma irregular y su composición similar a los asteroides del cinturón principal."];

DEEP_DIVES['sp26'].es = ["La galaxia de Andrómeda (M31) es la galaxia espiral más cercana a la Vía Láctea, a unos 2,5 millones de años-luz de distancia.","Andrómeda y la Vía Láctea se acercan a 110 km/s y colisionarán dentro de unos 4 500 millones de años, fusionándose en una galaxia elíptica gigante.","A pesar de la colisión galáctica, es muy improbable que estrellas individuales choquen entre sí: las distancias interestelares son tan enormes que las galaxias se atravesarán como fantasmas."];

DEEP_DIVES['sp27'].es = ["La materia oscura constituye aproximadamente el 27 % del universo, pero no emite ni absorbe luz — su existencia se deduce de sus efectos gravitacionales sobre la materia visible.","Las galaxias rotan demasiado rápido para la masa visible que contienen: sin materia oscura, se desintegrarían — esta fue la primera evidencia de su existencia.","A pesar de décadas de investigación, aún no se ha detectado directamente una partícula de materia oscura — es uno de los mayores misterios de la física moderna."];

DEEP_DIVES['sp28'].es = ["El telescopio espacial James Webb, lanzado en diciembre de 2021, es el observatorio más potente jamás puesto en órbita, con un espejo de 6,5 metros de diámetro.","Orbita en el punto de Lagrange L2, a 1,5 millones de km de la Tierra, donde su parasol de 5 capas lo protege del calor del Sol.","Sus primeras imágenes revelaron galaxias formadas apenas 300 millones de años después del Big Bang — las más antiguas jamás observadas."];

DEEP_DIVES['sp29'].es = ["El Big Bang no fue una explosión en el espacio, sino una expansión del propio espacio-tiempo a partir de un estado de densidad y temperatura infinitas hace 13 800 millones de años.","La radiación cósmica de fondo, descubierta accidentalmente en 1965 por Penzias y Wilson, es el «eco» del Big Bang y es visible en todas las direcciones del cielo.","El universo sigue expandiéndose y esa expansión se está acelerando, impulsada por una fuerza misteriosa llamada energía oscura, que constituye el 68 % del contenido total del universo."];

DEEP_DIVES['sp30'].es = ["Las exoplanetas son planetas que orbitan estrellas distintas al Sol. Desde el primer descubrimiento confirmado en 1995, se han catalogado más de 5 600.","El método más común de detección es el de tránsito: cuando un planeta pasa delante de su estrella, la luz de esta disminuye ligeramente, revelando el tamaño y la órbita del planeta.","Algunos exoplanetas se encuentran en la «zona habitable» de su estrella, donde las temperaturas permiten la existencia de agua líquida — un requisito clave para la vida tal como la conocemos."];

// ── ARTS ar1-ar30 ──

DEEP_DIVES['ar1'].es = ["La Mona Lisa mide apenas 77 × 53 cm — mucho más pequeña de lo que la mayoría imagina — y está protegida por un cristal antibalas en el Louvre.","Leonardo da Vinci trabajó en ella durante al menos cuatro años (1503-1507) y probablemente nunca la consideró terminada — se la llevó consigo a Francia.","La técnica del sfumato, que da al cuadro su característica suavidad, consiste en superponer decenas de capas translúcidas de pintura, cada una de apenas unas micras de espesor."];

DEEP_DIVES['ar2'].es = ["La Capilla Sixtina fue pintada por Miguel Ángel entre 1508 y 1512, trabajando de pie sobre un andamio inclinado a 20 metros de altura.","Contrariamente al mito popular, Miguel Ángel no pintó tumbado boca arriba — trabajaba de pie con los brazos levantados, una postura que le causó graves problemas cervicales.","El techo contiene más de 300 figuras humanas y nueve escenas del Génesis — la más famosa, La Creación de Adán, se ha convertido en una de las imágenes más reproducidas del mundo."];

DEEP_DIVES['ar3'].es = ["La Noche Estrellada fue pintada por Van Gogh en junio de 1889 desde su habitación en el asilo de Saint-Rémy-de-Provence, en plena crisis mental.","Los remolinos del cielo podrían representar la turbulencia atmosférica: matemáticos han demostrado que las espirales de Van Gogh siguen patrones de flujo turbulento con una precisión sorprendente.","Van Gogh vendió un solo cuadro en vida (El viñedo rojo) por 400 francos. Hoy, sus obras se cotizan en cientos de millones de dólares."];

DEEP_DIVES['ar4'].es = ["El Guernica de Picasso (1937) denuncia el bombardeo de la ciudad vasca de Guernica durante la Guerra Civil Española por la aviación nazi e italiana.","Mide 3,49 × 7,77 metros y está pintado únicamente en blanco, negro y gris — los colores del duelo y de las fotografías de prensa de la época.","Picasso se negó a que el cuadro regresara a España mientras durara la dictadura franquista — el Guernica estuvo en el MoMA de Nueva York hasta 1981, seis años después de la muerte de Franco."];

DEEP_DIVES['ar5'].es = ["La arquitectura gótica se caracteriza por el arco ojival, la bóveda de crucería y los arbotantes, que permitieron construir catedrales de alturas sin precedentes.","Estas innovaciones estructurales trasladaron el peso de los muros a pilares externos, liberando las paredes para instalar enormes vidrieras que inundaban de luz el interior.","Notre-Dame de París, comenzada en 1163, tardó casi dos siglos en completarse — su aguja, añadida en el siglo XIX por Viollet-le-Duc, se derrumbó durante el incendio de 2019."];

DEEP_DIVES['ar6'].es = ["La proporción áurea (φ ≈ 1,618) aparece en numerosas obras de arte, desde el Partenón hasta los cuadros de Salvador Dalí.","También se encuentra en la naturaleza: las espirales de los girasoles, las conchas de nautilus y las galaxias espirales siguen patrones relacionados con la secuencia de Fibonacci.","Algunos historiadores del arte cuestionan que los artistas antiguos usaran conscientemente la proporción áurea — en muchos casos podría ser una coincidencia o una proyección moderna."];

DEEP_DIVES['ar7'].es = ["El impresionismo nació en 1874 cuando Monet, Renoir, Degas y otros expusieron fuera del Salón oficial, desafiando las convenciones académicas de la época.","El nombre del movimiento proviene de una crítica despectiva al cuadro de Monet Impresión, sol naciente — el término «impresionista» era inicialmente un insulto.","Los impresionistas pintaban al aire libre (en plein air) para captar los efectos fugaces de la luz natural, una práctica facilitada por la invención de los tubos de pintura portátiles."];

DEEP_DIVES['ar8'].es = ["El origami tradicional japonés se practica con una sola hoja de papel cuadrada, sin cortes ni pegamento, siguiendo reglas geométricas precisas.","Las matemáticas del plegado de papel han encontrado aplicaciones en ingeniería: los paneles solares del telescopio James Webb se pliegan como origami para caber en el cohete.","La grulla de papel (tsuru) es el símbolo más conocido del origami: según la tradición japonesa, plegar mil grullas (senbazuru) concede un deseo."];

DEEP_DIVES['ar9'].es = ["La fotografía fue inventada simultáneamente por Niépce y Daguerre en Francia y Fox Talbot en Inglaterra entre 1826 y 1839.","La primera fotografía conocida, Vista desde la ventana en Le Gras de Niépce, requirió una exposición de aproximadamente 8 horas.","La fotografía revolucionó el arte: liberó a la pintura de su función documental, abriendo el camino al impresionismo, el expresionismo y la abstracción."];

DEEP_DIVES['ar10'].es = ["La Novena Sinfonía de Beethoven (1824) fue la primera gran sinfonía en incluir un coro y solistas vocales, rompiendo con todas las convenciones del género.","Beethoven estaba completamente sordo cuando la compuso y no pudo oír la ovación del público en su estreno — un músico tuvo que girarlo para que viera los aplausos.","El Himno a la Alegría, su movimiento final, fue adoptado como himno de la Unión Europea en 1985 — probablemente la melodía clásica más universalmente reconocida."];

DEEP_DIVES['ar11'].es = ["El teatro griego nació en el siglo V a.C. en Atenas como parte de las festividades en honor a Dionisio, dios del vino y la fertilidad.","Las tragedias de Esquilo, Sófocles y Eurípides exploraban temas universales como el destino, la justicia y el conflicto entre lo individual y lo colectivo.","Los anfiteatros griegos, como el de Epidauro, tenían una acústica tan perfecta que un murmullo en el escenario podía oírse en la última fila, a 60 metros de distancia."];

DEEP_DIVES['ar12'].es = ["El Renacimiento italiano (siglos XIV-XVII) fue un periodo de explosión artística, científica y cultural que transformó Europa desde sus raíces medievales.","Florencia, bajo el mecenazgo de los Médicis, fue su epicentro: Brunelleschi, Botticelli, Leonardo, Miguel Ángel y Rafael trabajaron allí en la misma época.","La perspectiva lineal, sistematizada por Brunelleschi hacia 1420, permitió representar la profundidad tridimensional en una superficie plana — un avance que revolucionó la pintura occidental."];

DEEP_DIVES['ar13'].es = ["La caligrafía árabe es considerada una de las formas artísticas más refinadas del islam, ya que la representación figurativa está tradicionalmente restringida.","Existen más de 100 estilos caligráficos, desde el anguloso kufi hasta el fluido nastaliq, cada uno con reglas proporcionales estrictas.","La caligrafía decora mezquitas, manuscritos y objetos cotidianos, convirtiendo la palabra escrita en un arte visual que trasciende la simple comunicación."];

DEEP_DIVES['ar14'].es = ["El surrealismo, fundado por André Breton en 1924, buscaba liberar la creatividad del pensamiento racional mediante el automatismo psíquico y la exploración del inconsciente.","Salvador Dalí, René Magritte y Max Ernst crearon obras que desafían la lógica: relojes blandos, pipas que no son pipas y paisajes oníricos imposibles.","Las técnicas surrealistas — como el cadáver exquisito, el frottage y la escritura automática — influyeron profundamente en la publicidad, el cine y el diseño gráfico del siglo XX."];

DEEP_DIVES['ar15'].es = ["El ballet clásico se codificó en la corte de Luis XIV de Francia en el siglo XVII — el propio Rey Sol fue bailarín y creó la primera academia de danza en 1661.","Los cinco posiciones básicas de los pies en ballet fueron establecidas por Pierre Beauchamp, maître de ballet de Luis XIV, y siguen siendo la base de la técnica actual.","El ballet sobre puntas, donde las bailarinas se sostienen sobre las puntas de los pies, no apareció hasta principios del siglo XIX con Marie Taglioni en La Sílfide (1832)."];

DEEP_DIVES['ar16'].es = ["El jazz nació a finales del siglo XIX en Nueva Orleans, donde las tradiciones musicales africanas se fusionaron con el blues, el ragtime y la música de las bandas de desfile.","La improvisación es la esencia del jazz: los músicos crean melodías espontáneas sobre progresiones armónicas compartidas, convirtiendo cada interpretación en un acto único e irrepetible.","Louis Armstrong, Duke Ellington y Miles Davis transformaron el jazz en un arte universal que influyó decisivamente en el rock, el funk, el hip-hop y la música electrónica."];

DEEP_DIVES['ar17'].es = ["El cine fue inventado por los hermanos Lumière, que proyectaron la primera película pública el 28 de diciembre de 1895 en el Grand Café de París.","La llegada de un tren a la estación, una de sus primeras películas, supuestamente provocó el pánico entre los espectadores que creyeron que el tren iba a salir de la pantalla.","Georges Méliès, un mago de profesión, fue el primer cineasta en usar efectos especiales: su Viaje a la Luna (1902) es considerada la primera película de ciencia ficción."];

DEEP_DIVES['ar18'].es = ["La escultura griega clásica alcanzó un nivel de realismo anatómico que no se igualaría hasta el Renacimiento, más de 1 500 años después.","La mayoría de las esculturas griegas que conocemos son copias romanas en mármol — los originales eran a menudo de bronce y fueron fundidos para reutilizar el metal.","Las estatuas griegas no eran blancas: estaban pintadas con colores vivos — rojo, azul, oro — que se perdieron con el tiempo, creando el mito del mármol puro y austero."];

DEEP_DIVES['ar19'].es = ["El art déco floreció entre las décadas de 1920 y 1930, combinando geometría, lujo y modernidad en arquitectura, moda, joyería y diseño industrial.","El Empire State Building, el Chrysler Building y el teatro Paramount de Times Square son iconos del art déco arquitectónico que definieron el perfil de Nueva York.","El movimiento fusionó influencias del cubismo, el constructivismo ruso, el arte egipcio y las artes decorativas japonesas — un eclecticismo deliberado que celebraba la era de las máquinas."];

DEEP_DIVES['ar20'].es = ["El arte rupestre de las cuevas de Lascaux (Francia), datado en unos 17 000 años, representa bisontes, caballos y ciervos con una maestría técnica que sigue asombrando.","Las pinturas utilizaban pigmentos naturales — óxidos de hierro para el rojo, manganeso para el negro — mezclados con grasa animal y aplicados con pinceles, sopletes y las propias manos.","Lascaux fue cerrada al público en 1963 porque la respiración de los visitantes deterioraba las pinturas — hoy se puede visitar una réplica exacta, Lascaux IV."];

DEEP_DIVES['ar21'].es = ["La ópera nació en Florencia a finales del siglo XVI, cuando un grupo de intelectuales (la Camerata Fiorentina) intentó recrear el drama musical de la Grecia antigua.","La primera ópera conservada completa es Euridice de Jacopo Peri (1600), aunque la forma alcanzó su madurez con Monteverdi y su Orfeo (1607).","Desde sus orígenes elitistas en las cortes italianas, la ópera se democratizó en el siglo XIX gracias a compositores como Verdi y Puccini, que escribieron para un público popular."];

DEEP_DIVES['ar22'].es = ["El arte pop surgió en los años 1950-60 como reacción al expresionismo abstracto, incorporando imágenes de la cultura popular, la publicidad y los medios de comunicación.","Andy Warhol elevó objetos cotidianos como latas de sopa Campbell y botellas de Coca-Cola a la categoría de arte, cuestionando las fronteras entre arte elevado y cultura de masas.","Roy Lichtenstein se inspiró directamente en los cómics, reproduciendo viñetas con la técnica de puntos Ben-Day a gran escala — una ironía sobre la reproducción mecánica del arte."];

DEEP_DIVES['ar23'].es = ["El flamenco es un arte que combina cante, baile y guitarra, originado en Andalucía entre las comunidades gitanas, moriscas y judías del sur de España.","Fue declarado Patrimonio Cultural Inmaterial de la Humanidad por la UNESCO en 2010, reconociendo su profundidad emocional y su complejidad rítmica.","El duende, concepto clave del flamenco, describe un estado de emoción intensa y autenticidad que trasciende la técnica — Federico García Lorca lo definió como un poder misterioso que todos sienten y ningún filósofo explica."];

DEEP_DIVES['ar24'].es = ["La cerámica es una de las artes más antiguas de la humanidad: las primeras piezas conocidas, halladas en China, tienen más de 20 000 años.","La porcelana china, inventada durante la dinastía Tang (siglo VII), fue tan valiosa en Europa que se la conocía como «oro blanco» — los europeos tardaron siglos en descifrar su fórmula.","La técnica del kintsugi japonés repara las cerámicas rotas con oro, celebrando las fracturas como parte de la historia del objeto en lugar de ocultarlas."];

DEEP_DIVES['ar25'].es = ["La arquitectura islámica se distingue por el uso de arabescos, mocárabes, arcos de herradura y jardines interiores que evocan el paraíso coránico.","La Alhambra de Granada es una obra maestra de esta tradición: sus patios, fuentes y decoraciones geométricas crean un juego de luz, agua y espacio de una belleza hipnótica.","La prohibición parcial de las imágenes figurativas en el islam impulsó un desarrollo extraordinario de la ornamentación geométrica y la caligrafía como formas de expresión artística."];

DEEP_DIVES['ar26'].es = ["El muralismo mexicano (1920-1970) fue un movimiento artístico con fines sociales y políticos liderado por Diego Rivera, David Alfaro Siqueiros y José Clemente Orozco.","Sus obras monumentales, pintadas en edificios públicos, narraban la historia de México, la lucha de las clases populares y la identidad mestiza del país.","El muralismo influyó directamente en el arte callejero y el grafiti contemporáneo, estableciendo el precedente de llevar el arte fuera de los museos y a las calles."];

DEEP_DIVES['ar27'].es = ["La música clásica india (raga) es uno de los sistemas musicales más complejos del mundo, con más de 300 ragas codificados, cada uno asociado a una emoción y un momento del día.","A diferencia de la música occidental, el raga no tiene partitura fija: el músico improvisa dentro de un marco melódico y rítmico (tala) durante actuaciones que pueden durar horas.","Ravi Shankar popularizó el sitar en Occidente en los años 60, influyendo en músicos como George Harrison de los Beatles y generando un interés duradero por la música india."];

DEEP_DIVES['ar28'].es = ["El grabado en madera (xilografía), inventado en China hacia el siglo II, fue la primera técnica de impresión de imágenes y textos en la historia.","Albrecht Dürero elevó la xilografía a la categoría de arte mayor en el Renacimiento europeo con obras como El Apocalipsis (1498), de un detalle y expresividad sin precedentes.","La técnica inspiró siglos después el manga japonés: las estampas ukiyo-e de Hokusai y Hiroshige influyeron directamente en el estilo visual del cómic japonés moderno."];

DEEP_DIVES['ar29'].es = ["El land art surgió en los años 1960 como rechazo a la comercialización del arte, creando obras efímeras directamente en el paisaje natural.","Spiral Jetty de Robert Smithson (1970), una espiral de roca y sal de 460 metros en el Gran Lago Salado de Utah, es su obra más emblemática.","El land art cuestiona la propiedad del arte, su permanencia y su relación con la naturaleza — muchas obras son accesibles solo en persona y cambian con el tiempo y las estaciones."];

DEEP_DIVES['ar30'].es = ["El arte digital abarca desde la pintura digital y el modelado 3D hasta el arte generativo creado por inteligencia artificial y los NFT.","El primer «arte por computadora» reconocido fue creado en los años 1960 por artistas como Vera Molnár y Harold Cohen, pioneros en el uso de algoritmos como herramientas creativas.","La irrupción de la IA generativa ha reavivado el debate sobre la autoría artística: ¿puede una máquina ser creativa, o simplemente recombina patrones de obras humanas existentes?"];

// ── INVENTIONS inv1-inv30 ──

DEEP_DIVES['inv1'].es = ["La rueda no fue inventada para el transporte sino para la alfarería: los primeros tornos de alfarero aparecieron en Mesopotamia hacia el 3500 a.C.","Las primeras ruedas para vehículos aparecieron unos 300 años después, en la estepa póntica (actual Ucrania), como discos macizos de madera sin radios.","Curiosamente, las civilizaciones precolombinas conocían la rueda pero solo la usaban en juguetes — la ausencia de animales de tiro la hacía poco práctica para el transporte."];

DEEP_DIVES['inv2'].es = ["La imprenta de tipos móviles fue inventada en China por Bi Sheng hacia 1040 d.C., cuatro siglos antes que Gutenberg.","Sin embargo, los miles de caracteres chinos hacían poco prácticos los tipos móviles, por lo que la xilografía siguió dominando en Asia oriental.","Gutenberg combinó los tipos móviles metálicos con una prensa de tornillo adaptada de las prensas de vino, creando un sistema revolucionario para los alfabetos europeos de pocas letras."];

DEEP_DIVES['inv3'].es = ["La brújula magnética fue inventada en China durante la dinastía Han (siglo II a.C.) para la adivinación geomántica (feng shui), no para la navegación.","Su uso marítimo no se documenta hasta el siglo XI en China y el XII en Europa — transformando la navegación oceánica y posibilitando la era de los descubrimientos.","El polo magnético terrestre no coincide con el polo geográfico y se desplaza constantemente — actualmente migra hacia Siberia a unos 55 km por año."];

DEEP_DIVES['inv4'].es = ["La bombilla incandescente no fue inventada por Edison: al menos 22 inventores trabajaron en lámparas eléctricas antes que él, incluidos Humphry Davy y Joseph Swan.","La contribución de Edison fue crear una bombilla práctica y duradera (más de 1 200 horas) y, sobre todo, diseñar todo el sistema eléctrico para alimentarla: centrales, cables e interruptores.","La primera central eléctrica comercial del mundo, la Pearl Street Station de Edison en Manhattan, se inauguró en 1882 y suministraba electricidad a 85 clientes."];

DEEP_DIVES['inv5'].es = ["El teléfono fue patentado por Alexander Graham Bell el 14 de febrero de 1876, apenas dos horas antes que su rival Elisha Gray presentara un documento similar.","Antonio Meucci, un inventor italiano, había desarrollado un prototipo funcional años antes pero no pudo pagar la tasa de renovación de su patente provisional.","En 2002, el Congreso de EE.UU. reconoció oficialmente la contribución de Meucci a la invención del teléfono, sin invalidar la patente de Bell."];

DEEP_DIVES['inv6'].es = ["La penicilina fue descubierta por accidente en 1928 cuando Alexander Fleming observó que un moho (Penicillium notatum) mataba bacterias en una placa de Petri contaminada.","Fleming no logró purificar la sustancia: fueron Howard Florey y Ernst Boris Chain quienes la transformaron en medicamento utilizable en 1940.","La penicilina salvó millones de vidas durante la Segunda Guerra Mundial y abrió la era de los antibióticos — pero Fleming advirtió desde su discurso del Nobel sobre el riesgo de resistencia bacteriana."];

DEEP_DIVES['inv7'].es = ["La pólvora fue inventada en China durante el siglo IX por alquimistas taoístas que buscaban el elixir de la inmortalidad — un irónico giro del destino.","Los chinos la usaron primero para fuegos artificiales y señales antes de aplicarla a armas: las primeras «lanzas de fuego» aparecieron en el siglo X.","La pólvora llegó a Europa en el siglo XIII a través de la Ruta de la Seda y transformó radicalmente la guerra, volviendo obsoletas las armaduras y los castillos medievales."];

DEEP_DIVES['inv8'].es = ["El motor de vapor, perfeccionado por James Watt en 1769, fue el catalizador de la Revolución Industrial y transformó la manufactura, el transporte y la minería.","Watt no inventó el motor de vapor: mejoró el diseño de Thomas Newcomen añadiendo un condensador separado que triplicó la eficiencia energética.","La unidad de potencia «vatio» (watt) lleva su nombre, y el concepto de «caballo de vapor» fue creado por él mismo para comercializar sus máquinas comparándolas con caballos de tiro."];

DEEP_DIVES['inv9'].es = ["El microondas fue inventado por accidente en 1945 cuando Percy Spencer, ingeniero de Raytheon, notó que una barra de chocolate se había derretido en su bolsillo junto a un magnetrón.","El primer horno microondas comercial, el Radarange (1947), pesaba 340 kg, medía 1,80 m de alto y costaba el equivalente actual de unos 60 000 dólares.","Las microondas no calientan desde fuera hacia dentro: excitan las moléculas de agua del alimento, generando calor por fricción molecular — por eso los alimentos secos no se calientan bien."];

DEEP_DIVES['inv10'].es = ["Internet nació como ARPANET en 1969, una red militar estadounidense que conectaba cuatro universidades para compartir recursos informáticos.","El primer mensaje enviado por ARPANET fue «LO» — debía ser «LOGIN» pero el sistema se bloqueó después de las dos primeras letras.","Internet y la World Wide Web no son lo mismo: Internet es la infraestructura de red, mientras que la Web (inventada por Tim Berners-Lee en 1989) es un servicio que funciona sobre ella."];

DEEP_DIVES['inv11'].es = ["El GPS (Sistema de Posicionamiento Global) fue desarrollado por el ejército estadounidense en los años 1970 y liberado para uso civil en 1983 tras el derribo de un avión coreano que se había desviado de su ruta.","El sistema funciona con una constelación de al menos 24 satélites que orbitan a 20 200 km de altitud: un receptor necesita señales de al menos 4 satélites para calcular su posición.","Los relojes atómicos a bordo de los satélites GPS deben corregir los efectos de la relatividad general de Einstein — sin esta corrección, la posición se desviaría unos 10 km por día."];

DEEP_DIVES['inv12'].es = ["El velcro fue inventado en 1941 por el ingeniero suizo George de Mestral tras observar cómo los frutos del cardo (bardana) se enganchaban a su ropa y al pelo de su perro.","Tardó ocho años en perfeccionar el sistema y patentarlo en 1955 — inicialmente fue ridiculizado por la industria textil que lo consideraba poco elegante.","La NASA adoptó el velcro para las misiones espaciales porque funciona en gravedad cero: permite fijar objetos, herramientas y hasta comida dentro de las naves."];

DEEP_DIVES['inv13'].es = ["La aspirina, sintetizada por Felix Hoffmann en 1897, tiene su origen en la corteza de sauce, utilizada como analgésico desde la antigua Sumeria hace 4 000 años.","El ácido acetilsalicílico es uno de los medicamentos más consumidos del mundo: se estima que se toman 100 000 millones de comprimidos al año.","Además de aliviar el dolor, la aspirina tiene propiedades anticoagulantes que reducen el riesgo de infarto — un efecto secundario descubierto décadas después de su comercialización."];

DEEP_DIVES['inv14'].es = ["El avión fue inventado por los hermanos Wright, que realizaron el primer vuelo motorizado controlado el 17 de diciembre de 1903 en Kitty Hawk, Carolina del Norte.","El primer vuelo duró apenas 12 segundos y cubrió 36 metros — menos que la envergadura de un Boeing 747 moderno.","Los Wright resolvieron el problema clave del vuelo — el control direccional — inspirándose en cómo las aves tuercen las puntas de sus alas, un mecanismo que llamaron «torsión alar»."];

DEEP_DIVES['inv15'].es = ["La dinamita fue inventada por Alfred Nobel en 1867 al descubrir que la nitroglicerina, altamente inestable, podía estabilizarse absorbiéndola en tierra de diatomeas.","Nobel amasó una fortuna con la dinamita pero se horrorizó al leer su propio obituario prematuro, que lo llamaba «el mercader de la muerte» — esto lo llevó a crear los Premios Nobel.","Los Premios Nobel se otorgan desde 1901 en Física, Química, Medicina, Literatura y Paz — el de Economía fue añadido en 1969 por el Banco de Suecia."];

DEEP_DIVES['inv16'].es = ["El papel fue inventado en China por Cai Lun en el año 105 d.C., utilizando corteza de morera, cáñamo, trapos viejos y redes de pesca triturados.","Durante siglos, los chinos mantuvieron el secreto de su fabricación — los árabes lo aprendieron en 751 tras capturar a artesanos chinos en la batalla de Talas.","Antes del papel, se escribía sobre papiro (Egipto), pergamino (piel animal), tablillas de arcilla (Mesopotamia) y bambú (China) — todos mucho más caros y pesados."];

DEEP_DIVES['inv17'].es = ["La vacuna fue inventada por Edward Jenner en 1796 al demostrar que la inoculación con viruela bovina protegía contra la mortal viruela humana.","El término «vacuna» viene de vacca (vaca en latín), en referencia al virus bovino utilizado por Jenner.","La viruela es la única enfermedad humana erradicada de la naturaleza: la OMS declaró su erradicación en 1980, tras una campaña mundial de vacunación que comenzó en 1967."];

DEEP_DIVES['inv18'].es = ["Los Post-it nacieron de un adhesivo «fallido»: en 1968, Spencer Silver en 3M creó un pegamento que se despegaba fácilmente sin dejar residuos.","Durante años nadie supo qué hacer con ese adhesivo inútil, hasta que en 1974 su colega Art Fry lo usó para marcar las páginas de su himnario sin dañarlas.","Los Post-it se comercializaron en 1980 y se convirtieron en un fenómeno mundial: hoy se fabrican en más de 60 colores y formas, y se venden en más de 100 países."];

DEEP_DIVES['inv19'].es = ["El transistor fue inventado en 1947 en los Laboratorios Bell por John Bardeen, Walter Brattain y William Shockley, quienes recibieron el Nobel de Física en 1956.","Reemplazó a los tubos de vacío: más pequeño, más rápido, más fiable y con mucho menos consumo energético, hizo posible la electrónica moderna.","Un procesador actual contiene miles de millones de transistores, cada uno más pequeño que un virus — la miniaturización sigue la Ley de Moore, que predice la duplicación cada dos años."];

DEEP_DIVES['inv20'].es = ["El refrigerador doméstico se popularizó en los años 1920, sustituyendo las neveras de hielo que dependían de entregas regulares de bloques congelados.","Los primeros refrigeradores usaban gases tóxicos como el amoníaco y el cloruro de metilo — el freón, inventado en 1930, fue la solución segura hasta que se descubrió que destruía la capa de ozono.","La refrigeración transformó la dieta humana: por primera vez en la historia, la comida podía conservarse durante semanas, reduciendo el desperdicio y las enfermedades alimentarias."];

DEEP_DIVES['inv21'].es = ["La máquina de vapor atmosférica de Thomas Newcomen (1712) fue la primera máquina capaz de convertir calor en trabajo mecánico de forma práctica.","Se usó principalmente para bombear agua de las minas de carbón — un problema que ni los molinos de viento ni los caballos podían resolver a la escala necesaria.","La eficiencia de la máquina de Newcomen era inferior al 1 %, pero su impacto fue revolucionario: demostró que las máquinas podían reemplazar la fuerza animal y humana."];

DEEP_DIVES['inv22'].es = ["El telescopio fue patentado por Hans Lippershey en 1608, pero Galileo fue quien lo apuntó al cielo en 1609, descubriendo las lunas de Júpiter y los cráteres de la Luna.","Estos descubrimientos apoyaron la teoría heliocéntrica de Copérnico y desafiaron la visión geocéntrica de la Iglesia — lo que le valió a Galileo un juicio por herejía.","Los telescopios modernos como el James Webb observan en infrarrojo y pueden detectar galaxias formadas poco después del Big Bang, a más de 13 000 millones de años-luz."];

DEEP_DIVES['inv23'].es = ["La batería eléctrica fue inventada por Alessandro Volta en 1800, apilando discos alternos de zinc y cobre separados por cartón empapado en salmuera.","La «pila voltaica» fue la primera fuente estable de corriente eléctrica continua, abriendo el camino a la electroquímica y el electromagnetismo.","Las baterías de litio-ion, inventadas en los años 1980, almacenan hasta 10 veces más energía que las de plomo-ácido y son la base de los teléfonos móviles, los portátiles y los coches eléctricos."];

DEEP_DIVES['inv24'].es = ["El caucho vulcanizado fue descubierto por Charles Goodyear en 1839 al dejar caer accidentalmente una mezcla de caucho y azufre sobre una estufa caliente.","Antes de la vulcanización, el caucho natural se derretía con el calor y se agrietaba con el frío — el proceso de Goodyear lo hizo elástico, resistente y duradero.","Goodyear murió endeudado en 1860 sin haber ganado casi nada de su invento — la empresa Goodyear Tire, fundada 38 años después, adoptó su nombre como homenaje póstumo."];

DEEP_DIVES['inv25'].es = ["El código Morse fue desarrollado por Samuel Morse y Alfred Vail en 1838 como sistema de comunicación para el telégrafo eléctrico.","La señal de socorro SOS (· · · — — — · · ·) fue elegida en 1906 no por significar «Save Our Souls» sino por ser la secuencia más fácil de transmitir y reconocer.","El telégrafo fue la primera tecnología capaz de transmitir información más rápido que un mensajero físico — redujo la comunicación transatlántica de semanas a minutos."];

DEEP_DIVES['inv26'].es = ["La anestesia quirúrgica fue demostrada públicamente por primera vez en 1846 por William Morton, que administró éter dietílico a un paciente en el Hospital General de Massachusetts.","Antes de la anestesia, las operaciones se realizaban con el paciente consciente, sujeto por asistentes — la velocidad del cirujano era la principal virtud médica.","El evento se conoce como «Ether Day» y la sala donde tuvo lugar, el Ether Dome, se conserva como monumento histórico — una de las mayores revoluciones de la historia de la medicina."];

DEEP_DIVES['inv27'].es = ["La máquina de escribir comercial fue patentada por Christopher Latham Sholes en 1868 y fabricada por Remington a partir de 1873.","El teclado QWERTY fue diseñado para separar las letras más frecuentes y evitar que los martillos mecánicos se trabaran — una solución a un problema que ya no existe pero que seguimos usando.","Mark Twain fue uno de los primeros autores en entregar un manuscrito mecanografiado a una editorial: Las aventuras de Tom Sawyer (1876)."];

DEEP_DIVES['inv28'].es = ["El hormigón armado fue patentado por Joseph Monier en 1867 al insertar una malla de hierro dentro del hormigón, combinando la resistencia a compresión de uno con la resistencia a tracción del otro.","Los romanos ya usaban una forma de hormigón (opus caementicium) que incluía ceniza volcánica — el Panteón de Roma, con su cúpula de hormigón no armado, se mantiene en pie tras 2 000 años.","El hormigón es el material más utilizado del mundo después del agua: se producen unos 4 300 millones de toneladas al año, y su fabricación genera el 8 % de las emisiones globales de CO₂."];

DEEP_DIVES['inv29'].es = ["El Kevlar fue descubierto en 1965 por Stephanie Kwolek, una química de DuPont que investigaba fibras ligeras para neumáticos.","Es cinco veces más resistente que el acero por unidad de peso y se utiliza en chalecos antibalas, cascos militares, cuerdas de alta resistencia y velas de competición.","Kwolek casi descartó la solución turbia que produjo en el laboratorio, pero insistió en hilarla — ese momento de perseverancia cambió el curso de la ciencia de los materiales."];

DEEP_DIVES['inv30'].es = ["El marcapasos cardíaco implantable fue desarrollado por Wilson Greatbatch en 1958 — también por accidente: instaló una resistencia equivocada en un circuito y el dispositivo comenzó a emitir pulsos rítmicos.","El primer marcapasos fue implantado en Arne Larsson en 1958 en Suecia — Larsson sobrevivió a su cirujano y vivió hasta los 86 años con 26 marcapasos diferentes.","Los marcapasos modernos pesan menos de 30 gramos, duran hasta 15 años y algunos modelos pueden monitorizarse remotamente por bluetooth desde el teléfono del paciente."];

// ── WORLD w1-w30 ──

DEEP_DIVES['w1'].es = ["Rusia es tan extensa que abarca 11 husos horarios — cuando amanece en Kaliningrado, ya es de noche en Kamchatka.","Con 17,1 millones de km², su superficie terrestre es ligeramente inferior a la de Plutón (17,6 millones de km²), un dato que sorprende incluso a los geógrafos.","Siberia alberga el lago Baikal, que contiene el 20 % del agua dulce no congelada del planeta y alcanza una profundidad de 1 642 metros."];

DEEP_DIVES['w2'].es = ["Islandia es uno de los pocos territorios del mundo sin mosquitos, a pesar de tener abundante agua y veranos relativamente templados.","La razón es climática: las oscilaciones térmicas rápidas y frecuentes de Islandia interrumpen el ciclo reproductivo del mosquito, que necesita aguas estancadas estables.","Islandia tampoco tiene ejército ni reptiles nativos — y su policía rara vez porta armas, dado que el país tiene una de las tasas de criminalidad más bajas del mundo."];

DEEP_DIVES['w3'].es = ["Suiza obliga por ley a tener al menos dos cobayas si se posee una — un animal gregario no puede vivir solo sin sufrir estrés psicológico.","Esta ley de 2008 forma parte de una de las legislaciones de protección animal más estrictas del mundo, que también prohíbe los anzuelos vivos para la pesca.","Existe incluso un servicio de «alquiler de cobayas» en Suiza para propietarios cuya compañera ha muerto, evitando un ciclo infinito de compras."];

DEEP_DIVES['w4'].es = ["Canadá posee más lagos que todos los demás países del mundo juntos: unos 879 800, que cubren el 9 % de su superficie.","El Gran Lago de los Esclavos, en los Territorios del Noroeste, es tan profundo (614 m) que podría sumergir la Torre Eiffel con espacio de sobra.","Canadá tiene la costa más larga del mundo (243 000 km) y una densidad de población tan baja que la mayoría de sus habitantes viven a menos de 150 km de la frontera estadounidense."];

DEEP_DIVES['w5'].es = ["Noruega tiene más de 1 000 fiordos, valles glaciares inundados por el mar que pueden alcanzar profundidades de más de 1 300 metros.","El fiordo de Sogn, el más largo de Noruega (204 km), es también el más profundo de Europa — sus acantilados verticales se elevan hasta 1 700 m sobre el agua.","Los fiordos se formaron durante las glaciaciones del Pleistoceno, cuando glaciares de kilómetros de espesor erosionaron valles en forma de U que el mar inundó al retirarse el hielo."];

DEEP_DIVES['w6'].es = ["Australia es el único país que es también un continente, con una superficie de 7,7 millones de km² — casi tan grande como Europa.","El interior australiano, conocido como Outback, es tan árido y despoblado que la densidad de población del país es de apenas 3 habitantes por km².","Australia alberga 21 de las 25 serpientes más venenosas del mundo, así como arañas, medusas y pulpos letales — pero los ataques mortales son sorprendentemente raros."];

DEEP_DIVES['w7'].es = ["El río Amazonas transporta más agua que los siguientes siete ríos más caudalosos del mundo juntos — su caudal medio es de 209 000 m³ por segundo.","Su cuenca hidrográfica cubre 6,9 millones de km², casi el tamaño de Australia, y alberga el 10 % de todas las especies conocidas del planeta.","La desembocadura del Amazonas es tan amplia que la isla de Marajó, situada en ella, es más grande que Suiza."];

DEEP_DIVES['w8'].es = ["El Vaticano, con 0,44 km² y unos 800 habitantes, es el estado independiente más pequeño del mundo — cabe entero dentro del Coliseo romano.","A pesar de su tamaño, tiene su propia oficina de correos, estación de radio, periódico, ferrocarril (300 m de vías) y fuerza de seguridad (la Guardia Suiza).","El Vaticano genera ingresos a través de los museos (6 millones de visitantes al año), sellos postales, publicaciones y donaciones de los 1 400 millones de católicos del mundo."];

DEEP_DIVES['w9'].es = ["La Antártida es el continente más frío, más seco, más ventoso y más elevado de la Tierra — su altitud media supera los 2 300 metros.","Contiene el 70 % del agua dulce del planeta en forma de hielo: si se derritiera por completo, el nivel del mar subiría unos 60 metros.","A pesar de las temperaturas extremas (récord de −89,2 °C), la Antártida alberga vida: pingüinos, focas, krill y más de 1 000 especies de hongos y líquenes."];

DEEP_DIVES['w10'].es = ["El Mar Muerto, situado entre Israel, Palestina y Jordania, es el punto más bajo de la superficie terrestre, a 430 metros bajo el nivel del mar.","Su salinidad (34 %) es casi 10 veces la del océano, lo que permite flotar sin esfuerzo — pero también impide toda forma de vida macroscópica.","El Mar Muerto se encoge unos 1,2 metros por año debido a la desviación de sus afluentes para riego — podría desaparecer por completo antes de 2050 si no se toman medidas."];

DEEP_DIVES['w11'].es = ["Japón está compuesto por 6 852 islas, pero el 97 % de su población vive en las cuatro principales: Honshū, Hokkaidō, Kyūshū y Shikoku.","Japón experimenta unos 1 500 terremotos perceptibles al año y está situado en el «Cinturón de Fuego del Pacífico», donde convergen cuatro placas tectónicas.","La cultura japonesa del preparacionismo ante desastres es ejemplar: los edificios modernos son antisísmicos y los simulacros de evacuación se practican desde la infancia."];

DEEP_DIVES['w12'].es = ["El desierto del Sahara es el desierto cálido más grande del mundo, con 9,2 millones de km² — casi tan grande como Estados Unidos.","Hace apenas 6 000 años, el Sahara era verde y fértil, con ríos, lagos y una fauna abundante — un periodo conocido como el «Sahara verde» o «periodo húmedo africano».","Solo el 25 % del Sahara está cubierto de dunas de arena (erg): el resto es roca (hamada), grava (reg) y mesetas — la imagen del desierto de arena infinita es una simplificación."];

DEEP_DIVES['w13'].es = ["El monte Everest, con 8 849 metros, es la montaña más alta del mundo medida desde el nivel del mar — pero no la más alta desde su base.","Ese honor corresponde al Mauna Kea en Hawái: mide 10 203 metros desde su base submarina, aunque solo 4 207 m sobresalen del agua.","Más de 6 000 personas han alcanzado la cima del Everest desde la primera ascensión de Hillary y Tenzing en 1953 — pero más de 300 han muerto en el intento."];

DEEP_DIVES['w14'].es = ["Venecia está construida sobre 118 pequeñas islas conectadas por más de 400 puentes, en una laguna del mar Adriático.","La ciudad se hunde gradualmente (1-2 mm/año) mientras el nivel del mar sube — el sistema de barreras MOSE, inaugurado en 2020, protege la laguna de las inundaciones.","Venecia fue durante siglos una potencia marítima y comercial que rivalizaba con el Imperio Bizantino y controlaba las rutas comerciales entre Europa y Oriente."];

DEEP_DIVES['w15'].es = ["La Gran Barrera de Coral australiana es la mayor estructura biológica del planeta: se extiende más de 2 300 km y es visible desde el espacio.","Está compuesta por más de 2 900 arrecifes individuales y alberga 1 500 especies de peces, 400 tipos de coral y 4 000 especies de moluscos.","El blanqueamiento masivo causado por el calentamiento del agua amenaza gravemente su supervivencia — episodios en 2016, 2017, 2020 y 2024 han afectado a más del 60 % de los corales."];

DEEP_DIVES['w16'].es = ["Finlandia es el país con más saunas per cápita del mundo: unas 3,3 millones para 5,5 millones de habitantes — más saunas que coches.","El sauna finlandés no es un lujo sino una parte integral de la cultura: históricamente, las mujeres daban a luz en saunas y los difuntos eran preparados allí para el entierro.","En 2020, la tradición del sauna finlandés fue inscrita en la lista del Patrimonio Cultural Inmaterial de la UNESCO."];

DEEP_DIVES['w17'].es = ["Bolivia tiene dos capitales: Sucre (capital constitucional y sede del poder judicial) y La Paz (sede del gobierno y del poder legislativo).","La Paz, a 3 640 m de altitud, es la capital administrativa más alta del mundo — y su aeropuerto internacional de El Alto, a 4 061 m, es uno de los más elevados del planeta.","El Salar de Uyuni boliviano, el mayor desierto de sal del mundo (10 582 km²), contiene la mayor reserva mundial de litio, mineral esencial para las baterías de vehículos eléctricos."];

DEEP_DIVES['w18'].es = ["Etiopía utiliza un calendario propio de 13 meses (12 de 30 días más uno de 5 o 6 días) que lleva entre 7 y 8 años de retraso respecto al gregoriano.","Etiopía es también la cuna del café: según la leyenda, un pastor llamado Kaldi observó que sus cabras se ponían hiperactivas tras comer bayas de un arbusto.","Addis Abeba, su capital, significa «nueva flor» en amárico y alberga la sede de la Unión Africana — es considerada la capital diplomática de África."];

DEEP_DIVES['w19'].es = ["Bután mide su prosperidad no por el PIB sino por el Índice de Felicidad Nacional Bruta, un concepto introducido por el rey Jigme Singye Wangchuck en 1972.","Bután es el único país del mundo con un balance de carbono negativo: sus bosques absorben más CO₂ del que emite todo el país.","El turismo está regulado mediante una tarifa diaria mínima de 200 dólares por visitante, lo que limita el turismo de masas y financia servicios públicos gratuitos como la sanidad y la educación."];

DEEP_DIVES['w20'].es = ["Mongolia es el país con menor densidad de población del mundo: apenas 2 habitantes por km² en un territorio de 1,5 millones de km².","La tradición nómada sigue viva: un tercio de la población vive en ger (yurtas) y se desplaza estacionalmente con sus rebaños de caballos, yaks y ovejas.","La capital Ulán Bator es la más fría del mundo, con temperaturas invernales que alcanzan los −40 °C, y concentra casi la mitad de la población del país."];

DEEP_DIVES['w21'].es = ["Los Países Bajos deben su nombre al hecho de que un tercio del país se encuentra por debajo del nivel del mar, protegido por un sofisticado sistema de diques y pólderes.","El Plan Delta, construido tras la catastrófica inundación de 1953 que mató a 1 836 personas, es una de las mayores obras de ingeniería hidráulica de la historia.","Sin los diques y sistemas de bombeo, ciudades como Ámsterdam, Róterdam y La Haya estarían bajo agua — los holandeses llevan más de 800 años luchando contra el mar."];

DEEP_DIVES['w22'].es = ["Indonesia es el mayor archipiélago del mundo: más de 17 000 islas repartidas en 5 100 km de longitud, con más de 270 millones de habitantes.","Alberga la mayor biodiversidad marina del planeta y bosques tropicales que son el último refugio del orangután, el rinoceronte de Java y el dragón de Komodo.","Indonesia tiene más volcanes activos que cualquier otro país (130) y se encuentra en el Cinturón de Fuego del Pacífico, una de las zonas sísmicas más activas del mundo."];

DEEP_DIVES['w23'].es = ["Groenlandia, la isla más grande del mundo (2,16 millones de km²), está cubierta en un 80 % por un casquete de hielo de hasta 3 km de espesor.","A pesar de su tamaño, su población es de apenas 56 000 personas — la mayor parte concentrada en la costa occidental, libre de hielo.","El nombre «Groenlandia» (Tierra Verde) fue acuñado por Erik el Rojo hacia el 985 d.C., probablemente como estrategia de marketing para atraer colonos vikingos."];

DEEP_DIVES['w24'].es = ["Madagascar se separó de África hace unos 160 millones de años y de la India hace 88 millones, lo que explica su biodiversidad única.","El 90 % de sus especies animales y vegetales no se encuentran en ningún otro lugar del planeta — incluidos los lémures, los camaleones y los baobabs.","La deforestación ha destruido el 90 % de los bosques originales de Madagascar, amenazando un ecosistema irreemplazable — es una de las prioridades de conservación más urgentes del mundo."];

DEEP_DIVES['w25'].es = ["Chile es el país más largo y estrecho del mundo: 4 300 km de norte a sur pero solo 177 km de ancho de media.","Su geografía extrema incluye el desierto más árido del mundo (Atacama), glaciares patagónicos, la cordillera de los Andes y la Isla de Pascua a 3 700 km de la costa.","El desierto de Atacama es tan seco y estéril que la NASA lo utiliza como análogo de Marte para probar rovers y equipos de exploración."];

DEEP_DIVES['w26'].es = ["Nueva Zelanda fue el último gran territorio habitable en ser colonizado por humanos: los polinesios (maoríes) llegaron entre los siglos XIII y XIV.","Su aislamiento de 85 millones de años dio lugar a especies únicas como el kiwi, el tuátara (un reptil de la era de los dinosaurios) y el kakapo (el único loro no volador del mundo).","Nueva Zelanda fue el primer país del mundo en conceder el voto a las mujeres en 1893, 27 años antes que Estados Unidos."];

DEEP_DIVES['w27'].es = ["Nigeria es el país más poblado de África con más de 220 millones de habitantes y se prevé que supere a Estados Unidos antes de 2050.","Con más de 500 lenguas habladas, Nigeria es uno de los países lingüísticamente más diversos del mundo — el inglés es la lengua oficial pero el pidgin es la lingua franca popular.","Nollywood, la industria cinematográfica nigeriana, produce más películas al año que Hollywood y es la segunda del mundo por volumen, tras Bollywood."];

DEEP_DIVES['w28'].es = ["Islandia obtiene prácticamente el 100 % de su electricidad de fuentes renovables: geotermia (65 %) e hidroeléctrica (35 %).","La isla se encuentra sobre la dorsal mesoatlántica, donde las placas tectónicas norteamericana y euroasiática se separan, generando una intensa actividad geotérmica y volcánica.","Los islandeses calientan sus casas, piscinas e incluso aceras con agua geotérmica bombeada directamente del subsuelo — un sistema limpio y casi gratuito."];

DEEP_DIVES['w29'].es = ["Singapur es una ciudad-Estado de apenas 733 km² con 5,9 millones de habitantes, una de las densidades de población más altas del mundo.","A pesar de su tamaño, Singapur es la cuarta plaza financiera mundial y tiene uno de los PIB per cápita más altos del planeta.","La isla ha aumentado su superficie un 25 % desde la independencia en 1965 mediante la construcción de terrenos ganados al mar con arena importada de países vecinos."];

DEEP_DIVES['w30'].es = ["Egipto no es solo pirámides y desierto: el 95 % de su población vive a lo largo del valle y el delta del Nilo, una estrecha franja de tierra fértil.","El Nilo, con 6 650 km, disputa al Amazonas el título de río más largo del mundo — la medición depende de dónde se sitúe exactamente la fuente de cada río.","La presa de Asuán, terminada en 1970, controla las inundaciones del Nilo y genera electricidad, pero también atrapó el limo fértil que alimentaba la agricultura egipcia desde la Antigüedad."];

// ── LANGUAGE l1-l30 ──

DEEP_DIVES['l1'].es = ["El mandarín es la lengua más hablada del mundo como lengua materna, con más de 920 millones de hablantes nativos.","El chino mandarín es tonal: una misma sílaba puede tener cuatro significados diferentes según la entonación — por ejemplo, mā (madre), má (cáñamo), mǎ (caballo), mà (insultar).","El sistema de escritura chino no es un alfabeto sino un sistema logográfico: cada carácter representa una palabra o morfema, y existen más de 50 000 caracteres, aunque 3 000 bastan para la lectura cotidiana."];

DEEP_DIVES['l2'].es = ["El esperanto fue creado en 1887 por el oculista polaco Ludwik Zamenhof como lengua universal para fomentar la paz y la comprensión entre pueblos.","Su gramática tiene solo 16 reglas sin excepciones y su vocabulario se basa en raíces latinas, germánicas y eslavas — se estima que se puede aprender 5 veces más rápido que cualquier idioma natural.","Hoy cuenta con entre 100 000 y 2 millones de hablantes y tiene su propia literatura, música, congresos anuales e incluso hablantes nativos (niños criados en esperanto)."];

DEEP_DIVES['l3'].es = ["La palabra «salario» proviene del latín salarium, la ración de sal que recibían los legionarios romanos como parte de su paga.","La sal era tan valiosa en la Antigüedad que se usaba como moneda de cambio — de ahí también la expresión «no valer su sal» (no merecer su sueldo).","Las rutas de la sal (viae salariae) eran arterias comerciales vitales en el Imperio Romano y dieron nombre a ciudades como Salzburgo (castillo de la sal) en Austria."];

DEEP_DIVES['l4'].es = ["La palabra «berserk» proviene de los guerreros vikingos llamados berserkers, que entraban en un estado de trance furioso durante la batalla.","Algunos historiadores creen que este frenesí se inducía mediante el consumo de hongos alucinógenos (Amanita muscaria) o simplemente mediante rituales de exaltación colectiva.","Los berserkers luchaban sin armadura, mordiendo sus escudos y aullando — su ferocidad aterrorizaba tanto a enemigos como a aliados."];

DEEP_DIVES['l5'].es = ["Tras la conquista normanda de 1066, el francés se convirtió en la lengua de la corte, la ley y la aristocracia inglesa durante más de 300 años.","Esto explica por qué los animales vivos tienen nombres anglosajones (cow, sheep, pig) pero sus carnes tienen nombres franceses (beef, mutton, pork) — los campesinos criaban, los nobles comían.","Unas 10 000 palabras francesas entraron en el inglés durante este periodo, incluyendo justice, parliament, fashion, restaurant y la propia palabra «language»."];

DEEP_DIVES['l6'].es = ["La abreviatura OK apareció por primera vez el 23 de marzo de 1839 en el Boston Morning Post como broma ortográfica de «Oll Korrect» (All Correct mal escrito a propósito).","La moda de las abreviaturas humorísticas era viral en la prensa estadounidense de los años 1830 — pero solo OK sobrevivió para convertirse en la palabra más universalmente comprendida del mundo.","La campaña presidencial de Martin Van Buren en 1840, apodado «Old Kinderhook», popularizó OK al usarlo como eslogan — el doble sentido aseguró su difusión masiva."];

DEEP_DIVES['l7'].es = ["El albanés es una de las lenguas más aisladas de Europa: constituye por sí solo una rama entera de la familia indoeuropea, sin parientes cercanos conocidos.","Su alfabeto actual, basado en el latino, fue estandarizado recién en 1908 en el Congreso de Manastir — antes se escribía con caracteres griegos, árabes o cirílicos según la región.","El albanés conserva palabras de un sustrato preindoeuropeo que podrían ser vestigios de la antigua lengua iliria, hablada en los Balcanes antes de la llegada de los romanos."];

DEEP_DIVES['l8'].es = ["La palabra «emoji» proviene del japonés e (絵, imagen) y moji (文字, carácter) — no tiene relación etimológica con la palabra inglesa «emotion», aunque la coincidencia es notable.","Los primeros emojis fueron creados en 1999 por Shigetaka Kurita para el operador japonés NTT DoCoMo: eran 176 iconos de 12×12 píxeles diseñados para mejorar la comunicación por SMS.","En 2015, el emoji «cara llorando de risa» (😂) fue elegido «palabra del año» por el Oxford Dictionary — el primer pictograma en recibir ese honor en la historia."];

DEEP_DIVES['l9'].es = ["La palabra «whisky» proviene del gaélico irlandés uisce beatha, que significa literalmente «agua de vida» — el mismo concepto que aquavit en escandinavo y eau-de-vie en francés.","La destilación del whisky fue probablemente introducida en Escocia e Irlanda por monjes que habían aprendido la técnica en el Mediterráneo para producir perfumes y medicinas.","La diferencia entre «whisky» (escocés) y «whiskey» (irlandés y americano) no es solo ortográfica: refleja tradiciones de destilación, ingredientes y procesos de envejecimiento diferentes."];

DEEP_DIVES['l10'].es = ["El inglés ha tomado más del 30 % de su vocabulario del francés, principalmente tras la conquista normanda de 1066, cuando el francés se convirtió en lengua de prestigio en Inglaterra.","Palabras como beef (bœuf), parliament (parlement), justice y fashion son todas de origen francés — la coexistencia de sinónimos anglosajones y franceses enriqueció enormemente el vocabulario inglés.","Esta dualidad persiste hoy: los registros formales del inglés usan preferentemente palabras de origen francés/latino, mientras que el habla cotidiana conserva las raíces germánicas."];

DEEP_DIVES['l11'].es = ["El finés no tiene género gramatical: el pronombre hän se usa tanto para «él» como para «ella», sin distinción.","El finés no pertenece a la familia indoeuropea sino a la familia urálica, emparentado con el estonio y el húngaro — aunque las similitudes con este último son muy lejanas.","El finés es una lengua aglutinante con 15 casos gramaticales: una sola palabra puede expresar lo que en español requiere una frase entera — por ejemplo, talossanikin significa «también en mi casa»."];

DEEP_DIVES['l12'].es = ["El latín, considerado una lengua muerta, sigue siendo la lengua oficial del Vaticano y se usa en documentos papales, inscripciones y ceremonias.","La influencia del latín en las lenguas romances (español, francés, italiano, portugués, rumano) es tan profunda que un hablante de cualquiera de ellas puede reconocer cientos de palabras latinas.","Wikipedia tiene una versión completa en latín (Vicipaedia) con más de 130 000 artículos, y el Vaticano tiene un cajero automático con instrucciones en latín."];

DEEP_DIVES['l13'].es = ["El euskera (vasco) es la única lengua preindoeuropea que sobrevive en Europa occidental, sin relación conocida con ninguna otra familia lingüística del mundo.","Su origen es un misterio: se habla en el País Vasco desde antes de la llegada de los celtas, los romanos y los indoeuropeos — posiblemente desde el Neolítico.","El euskera utiliza un sistema ergativo-absolutivo (raro en Europa) y forma palabras por aglutinación: etxe (casa), etxea (la casa), etxean (en la casa), etxearen (de la casa)."];

DEEP_DIVES['l14'].es = ["El árabe se escribe de derecha a izquierda y su alfabeto de 28 letras cambia de forma según su posición en la palabra (inicio, medio, final o aislada).","El árabe es la quinta lengua más hablada del mundo con más de 420 millones de hablantes, y es lengua oficial en 26 países.","La contribución del árabe al vocabulario español es inmensa: más de 4 000 palabras castellanas tienen origen árabe, incluyendo almohada, alfombra, azúcar, alcalde y hasta la exclamación ¡ojalá! (inshallah)."];

DEEP_DIVES['l15'].es = ["El idioma con más hablantes nativos es el mandarín (920 millones), pero el inglés es la lengua más hablada en total (1 500 millones incluyendo no nativos).","El inglés es lengua oficial o cooficial en 67 países y es la lingua franca de la ciencia, la aviación, la diplomacia y la tecnología.","Sin embargo, se estima que unas 3 000 de las 7 000 lenguas del mundo desaparecerán antes de 2100 — una cada dos semanas — llevándose consigo conocimientos culturales irremplazables."];

DEEP_DIVES['l16'].es = ["La onomatopeya varía enormemente entre idiomas: un gallo dice «quiquiriquí» en español, «cocoricó» en francés, «cock-a-doodle-doo» en inglés y «kokekokkō» en japonés.","Estas diferencias no son caprichosas: cada lengua filtra los sonidos según su propio sistema fonológico, adaptando los ruidos naturales a patrones de sílabas y sonidos familiares.","Los lingüistas estudian las onomatopeyas como ejemplo de motivación fonética parcial — un raro caso donde el sonido de la palabra guarda cierta relación con su significado."];

DEEP_DIVES['l17'].es = ["El Braille fue inventado en 1824 por Louis Braille, un joven francés de 15 años que había quedado ciego tras un accidente en el taller de su padre.","El sistema se basa en celdas de 6 puntos en relieve que permiten 63 combinaciones, representando letras, números, signos de puntuación y notación musical.","Braille se inspiró en un sistema militar de escritura nocturna creado por Charles Barbier para que los soldados pudieran comunicarse sin luz — lo simplificó y adaptó para uso civil."];

DEEP_DIVES['l18'].es = ["La lengua de signos no es universal: cada país o región tiene su propia lengua de signos con gramática, vocabulario y sintaxis propios.","La lengua de signos americana (ASL) tiene más similitudes con la lengua de signos francesa (LSF) que con la lengua de signos británica (BSL), debido a su origen histórico común.","Las lenguas de signos son lenguas naturales completas, no simples traducciones del idioma oral — tienen su propia poesía, humor, juegos de palabras y dialectos regionales."];

DEEP_DIVES['l19'].es = ["Los palíndromos (palabras o frases que se leen igual al derecho y al revés) existen en casi todos los idiomas: «reconocer» en español, «kayak» en inglés, «saippuakivikauppias» en finés.","El palíndromo finés saippuakivikauppias (vendedor de piedra pómez) es uno de los más largos del mundo en una sola palabra, con 19 letras.","En latín, el cuadrado mágico SATOR-ROTAS es un palíndromo bidimensional del siglo I que se lee igual en cuatro direcciones — su significado sigue siendo debatido."];

DEEP_DIVES['l20'].es = ["El sánscrito es una de las lenguas más antiguas del mundo documentado, con textos (los Vedas) que datan del 1500 a.C. aproximadamente.","Es la lengua litúrgica del hinduismo y una de las 22 lenguas oficiales de la India, aunque apenas tiene hablantes nativos en la actualidad.","La gramática del sánscrito, codificada por Pāṇini en el siglo IV a.C., es tan precisa y sistemática que los lingüistas computacionales la consideran un precursor de los lenguajes de programación."];

DEEP_DIVES['l21'].es = ["El coreano utiliza el hangul, un alfabeto diseñado en 1443 por el rey Sejong el Grande específicamente para que el pueblo llano pudiera leer y escribir.","Antes del hangul, los coreanos usaban caracteres chinos (hanja), accesibles solo para la élite letrada — el hangul democratizó la alfabetización.","El hangul es considerado uno de los sistemas de escritura más lógicos y eficientes del mundo: sus 24 letras básicas representan las posiciones de la lengua y los labios al pronunciarlas."];

DEEP_DIVES['l22'].es = ["El swahili es una lengua bantú con fuerte influencia árabe que sirve como lingua franca en gran parte de África oriental, hablada por más de 100 millones de personas.","Es lengua oficial en Tanzania, Kenia, Uganda y la República Democrática del Congo, y fue la primera lengua africana añadida a Google Translate.","El swahili «hakuna matata» (no hay problema), popularizado por El Rey León de Disney, es una expresión real usada cotidianamente en África oriental."];

DEEP_DIVES['l23'].es = ["La palabra «algoritmo» proviene del nombre del matemático persa Al-Juarismi (siglo IX), cuya obra Kitab al-jabr dio también origen a la palabra «álgebra».","Al-Juarismi introdujo los numerales indo-arábigos en el mundo islámico y europeo, reemplazando gradualmente el sistema romano y revolucionando las matemáticas.","Hoy, los algoritmos son la base de la informática moderna: desde los motores de búsqueda hasta la inteligencia artificial, todo se reduce a secuencias de instrucciones lógicas."];

DEEP_DIVES['l24'].es = ["El portugués es la sexta lengua más hablada del mundo con 260 millones de hablantes, distribuidos entre Brasil, Portugal, Mozambique, Angola y otros seis países.","Brasil concentra el 80 % de los lusófonos del mundo — el portugués brasileño y el europeo difieren en pronunciación, vocabulario y gramática, comparables a las diferencias entre el español de España y el de Latinoamérica.","El portugués y el español son mutuamente inteligibles en un 89 % del vocabulario, lo que permite una comprensión básica entre hablantes sin formación previa."];

DEEP_DIVES['l25'].es = ["Los jeroglíficos egipcios fueron descifrados en 1822 por Jean-François Champollion gracias a la Piedra Rosetta, que contenía el mismo texto en jeroglíficos, demótico y griego.","El sistema jeroglífico combinaba logogramas (signos que representan palabras) y fonogramas (signos que representan sonidos), lo que lo hacía excepcionalmente complejo.","Los antiguos egipcios tenían tres sistemas de escritura diferentes: jeroglífico (ceremonial), hierático (administrativo) y demótico (cotidiano) — una complejidad que contribuyó al olvido de los jeroglíficos."];

DEEP_DIVES['l26'].es = ["La palabra «robot» fue acuñada por el escritor checo Karel Čapek en su obra R.U.R. (Robots Universales Rossum) de 1920, derivada del checo robota (trabajo forzado).","En la obra, los robots son seres biológicos fabricados, no máquinas — la asociación con máquinas mecánicas vino después, con el auge de la ciencia ficción y la automatización industrial.","Isaac Asimov popularizó el término «robótica» y formuló las Tres Leyes de la Robótica en 1942, que siguen siendo referencia ética en el debate sobre la inteligencia artificial."];

DEEP_DIVES['l27'].es = ["El hawaiano tiene solo 13 letras (8 consonantes y 5 vocales), lo que lo convierte en uno de los alfabetos más cortos del mundo.","A pesar de su fonología simple, el hawaiano es una lengua rica en metáforas y conceptos sin equivalente directo en otros idiomas, como aloha (amor, compasión, hola, adiós) y ohana (familia extendida).","El hawaiano estuvo al borde de la extinción en los años 1980, con menos de 2 000 hablantes nativos — los programas de inmersión lingüística han recuperado la lengua, que hoy se enseña en escuelas y universidades."];

DEEP_DIVES['l28'].es = ["El náhuatl, lengua de los aztecas, ha dejado numerosas palabras en el español y el inglés: chocolate (xocolātl), tomate (tomatl), aguacate (āhuacatl) y chicle (tzictli).","Aguacate proviene de āhuacatl, que en náhuatl significa «testículo» — una referencia a la forma del fruto que los colonizadores españoles adoptaron sin conocer su significado original.","El náhuatl sigue siendo hablado por más de 1,7 millones de personas en México, lo que lo convierte en la lengua indígena más hablada del país."];

DEEP_DIVES['l29'].es = ["La tipografía Times New Roman fue creada en 1931 para el periódico The Times de Londres por Stanley Morison y Victor Lardent, con el objetivo de maximizar la legibilidad en columnas estrechas.","Se convirtió en la fuente predeterminada de Microsoft Word durante décadas, lo que la hizo ubicua en documentos académicos, legales y administrativos de todo el mundo.","En 2023, muchas universidades y empresas la han sustituido por fuentes como Calibri o Arial — pero su legado como la fuente más leída de la historia es indiscutible."];

DEEP_DIVES['l30'].es = ["La Real Academia Española (RAE), fundada en 1713, vela por la unidad del español con su lema «Limpia, fija y da esplendor».","El español es la segunda lengua materna más hablada del mundo (490 millones de nativos), por detrás del mandarín y por delante del inglés.","Cada país hispanohablante tiene su propia academia de la lengua, y las 23 academias trabajan juntas en la Asociación de Academias de la Lengua Española para mantener la coherencia del idioma."];

// ── FOOD f1-f30 ──

DEEP_DIVES['f1'].es = ["Las primeras patatas fritas documentadas aparecen en textos españoles del siglo XVII, no en Bélgica ni en Francia como suele creerse.","La disputa entre belgas y franceses por la paternidad de las «frites» nunca ha sido zanjada definitivamente — ambos países las consideran patrimonio cultural propio.","La patata llegó a Europa desde Perú en el siglo XVI y fue inicialmente rechazada por los europeos, que la consideraban venenosa o alimento para animales."];

DEEP_DIVES['f2'].es = ["La miel no caduca porque su bajo contenido en agua, alta acidez y producción natural de peróxido de hidrógeno impiden el crecimiento bacteriano.","Arqueólogos han encontrado vasijas de miel en tumbas egipcias de 3 000 años de antigüedad que seguían siendo perfectamente comestibles.","Las abejas deben visitar unos 2 millones de flores y recorrer más de 88 000 km para producir un solo kilo de miel."];

DEEP_DIVES['f3'].es = ["La salsa Worcestershire fue creada accidentalmente por los farmacéuticos John Lea y William Perrins en Worcester, Inglaterra, hacia 1837.","La mezcla encargada por un gobernador colonial resultó tan desagradable que la abandonaron en una bodega — al probarla dos años después, la fermentación la había transformado en una salsa exquisita.","Su receta sigue siendo secreta, pero se sabe que contiene vinagre, melaza, anchoas, tamarindo, ajo, cebolla y especias — la fermentación es la clave de su sabor complejo."];

DEEP_DIVES['f4'].es = ["Los pistachos son técnicamente frutas, no frutos secos, y pertenecen a la misma familia botánica (Anacardiaceae) que los mangos y los anacardos.","Irán es el mayor productor mundial de pistachos, seguido de Estados Unidos (California) — juntos representan más del 70 % de la producción global.","Los pistachos se abren solos cuando maduran en el árbol: la cáscara se hiende con un «clic» audible — los cultivadores iraníes los llaman «la nuez sonriente»."];

DEEP_DIVES['f5'].es = ["El chocolate era una bebida amarga, fría y especiada consumida por los mayas y aztecas durante ceremonias religiosas y como moneda de cambio.","Los granos de cacao eran tan valiosos que los aztecas los usaban como dinero: un pavo costaba 100 granos y un esclavo, 1 000.","El chocolate con leche fue inventado en 1875 por el suizo Daniel Peter, que tuvo la idea de añadir leche condensada de su vecino Henri Nestlé — naciendo así una industria multimillonaria."];

DEEP_DIVES['f6'].es = ["Las zanahorias eran originalmente blancas, amarillas o moradas — la variedad naranja fue seleccionada por horticultores holandeses en el siglo XVII.","La leyenda dice que fue un homenaje a la Casa de Orange, pero los historiadores creen que fue simplemente porque la variedad naranja era más dulce y menos amarga.","Las zanahorias moradas originales están regresando a los mercados como producto gourmet — contienen antocianinas, los mismos antioxidantes presentes en los arándanos."];

DEEP_DIVES['f7'].es = ["El café es la segunda mercancía más comercializada del mundo después del petróleo, y más de 2 000 millones de tazas se consumen cada día en el planeta.","La leyenda atribuye su descubrimiento a un pastor etíope llamado Kaldi que notó que sus cabras se ponían hiperactivas tras comer las bayas de un arbusto.","Finlandia es el mayor consumidor de café per cápita del mundo, con unos 12 kg por persona al año — los finlandeses incluso tienen una pausa café legalmente protegida en el trabajo."];

DEEP_DIVES['f8'].es = ["Las fresas no son bayas en el sentido botánico — son «falsos frutos»: la parte roja es en realidad el receptáculo floral, y los verdaderos frutos son los puntitos de la superficie.","En cambio, los plátanos, los aguacates, las sandías y los kiwis son botánicamente bayas, porque se desarrollan a partir de un solo ovario con semillas incrustadas.","Esta clasificación sorprendente se debe a que la botánica define «baya» de forma muy precisa: un fruto carnoso derivado de un solo ovario que contiene semillas en su interior."];

DEEP_DIVES['f9'].es = ["La capsaicina, molécula responsable del picante, no produce quemaduras reales: engaña a los receptores TRPV1 de la lengua haciéndoles enviar una falsa señal de calor al cerebro.","Los mamíferos evitan el picante, pero las aves no poseen receptores TRPV1 — las plantas de chile evolucionaron para que los pájaros dispersen sus semillas sin ser comidas por mamíferos.","La escala Scoville mide el picante: un pimiento jalapeño alcanza 8 000 unidades, mientras que el Carolina Reaper supera los 2 200 000 — más de 200 veces más picante."];

DEEP_DIVES['f10'].es = ["El Nutella fue inventado en 1946 por Pietro Ferrero en Alba, Italia, como solución a la escasez de cacao en la posguerra: añadió avellanas del Piamonte para estirar el chocolate.","Hoy se producen unas 365 000 toneladas de Nutella al año, y la empresa Ferrero consume el 25 % de la producción mundial de avellanas.","Si se apilaran todos los tarros de Nutella vendidos en un año, la torre resultante mediría 200 veces la altura del monte Everest."];

DEEP_DIVES['f11'].es = ["Los europeos creyeron durante siglos que los tomates eran venenosos, principalmente porque su acidez disolvía el plomo de los platos de estaño, envenenando a los aristócratas.","El tomate, originario de Mesoamérica, llegó a Europa en el siglo XVI como planta ornamental antes de convertirse en ingrediente culinario en Italia hacia el siglo XVIII.","Italia consume hoy más de 6 millones de toneladas de tomates al año — la salsa de tomate es probablemente la contribución culinaria más influyente del Nuevo Mundo al Viejo."];

DEEP_DIVES['f12'].es = ["Las galletas de la fortuna no tienen nada de chinas: fueron inventadas en Japón y popularizadas en Estados Unidos por inmigrantes japoneses a principios del siglo XX.","Durante la Segunda Guerra Mundial, los japoneses-estadounidenses fueron internados en campos y sus negocios de galletas fueron retomados por empresarios chinos — lo que creó la asociación con la cocina china.","Hoy se fabrican más de 3 000 millones de galletas de la fortuna al año, casi exclusivamente para el mercado estadounidense — en China son prácticamente desconocidas."];

DEEP_DIVES['f13'].es = ["El chocolate blanco no es técnicamente chocolate porque no contiene sólidos de cacao — solo manteca de cacao, azúcar y leche.","La manteca de cacao es la grasa natural del grano de cacao, responsable de la textura fundente del chocolate — pero sin los sólidos, no hay sabor a chocolate.","El primer chocolate blanco comercial fue el Milkybar de Nestlé, lanzado en 1936 en el Reino Unido — inicialmente fue rechazado por los puristas del chocolate."];

DEEP_DIVES['f14'].es = ["El sushi no era originalmente un plato japonés refinado: nació en el sudeste asiático como método de conservación del pescado en arroz fermentado.","El arroz se descartaba inicialmente y solo se comía el pescado preservado — el nigiri-zushi (pescado sobre arroz) tal como lo conocemos fue inventado en Edo (Tokio) en el siglo XIX.","En Japón, convertirse en maestro sushiya requiere un aprendizaje de al menos 10 años: tres años solo para aprender a cocinar el arroz perfectamente."];

DEEP_DIVES['f15'].es = ["La vainilla es la segunda especia más cara del mundo después del azafrán — una vaina de vainilla natural puede costar más de 500 dólares el kilo.","Proviene de una orquídea (Vanilla planifolia) originaria de México, polinizada naturalmente por una abeja endémica — fuera de México, cada flor debe polinizarse a mano.","El 99 % del «sabor vainilla» usado en la industria alimentaria es sintético (vanillina), derivado de la madera, el petróleo o incluso de secreciones de castor (castóreo)."];

DEEP_DIVES['f16'].es = ["El wasabi auténtico es una de las plantas más difíciles de cultivar: crece solo en lechos de ríos de montaña a temperaturas estables entre 8 y 20 °C.","El 95 % del wasabi servido fuera de Japón es en realidad rábano picante teñido de verde con colorante — el wasabi real cuesta más de 200 euros el kilo.","El wasabi genuino se ralla justo antes de servir porque pierde su sabor en 15 minutos — un lujo que incluso muchos restaurantes japoneses no pueden permitirse."];

DEEP_DIVES['f17'].es = ["El champán solo puede llamarse así si procede de la región de Champagne, en el noreste de Francia — todo lo demás es «vino espumoso» o «cava».","El monje Dom Pérignon no inventó el champán: la efervescencia era un defecto no deseado. Su contribución fue perfeccionar el ensamblaje de uvas y el uso de tapones de corcho.","Una botella de champán contiene unas 49 millones de burbujas y la presión interior es de 6 atmósferas — el triple de la presión de un neumático de coche."];

DEEP_DIVES['f18'].es = ["El pan es uno de los alimentos más antiguos: se han encontrado restos de pan de 14 000 años en un yacimiento jordano, anterior a la agricultura.","La fermentación del pan con levadura fue probablemente descubierta por accidente en el antiguo Egipto, donde la masa olvidada empezó a crecer sola gracias a levaduras ambientales.","Francia consume más de 10 000 millones de baguettes al año, y la baguette fue inscrita en el Patrimonio Cultural Inmaterial de la UNESCO en 2022."];

DEEP_DIVES['f19'].es = ["El azafrán es la especia más cara del mundo: se necesitan 150 000 flores de azafrán (Crocus sativus) para obtener un kilo, recolectadas a mano una por una.","Cada flor produce solo tres estigmas rojos, que deben recogerse al amanecer antes de que el sol las abra completamente — es una cosecha extremadamente laboriosa.","Irán produce el 90 % del azafrán mundial, pero la mejor calidad es disputada por los productores de La Mancha (España) y Cachemira (India)."];

DEEP_DIVES['f20'].es = ["El umami, el quinto sabor básico junto con dulce, salado, ácido y amargo, fue descubierto en 1908 por el químico japonés Kikunae Ikeda al estudiar el dashi (caldo de alga kombu).","Ikeda aisló el glutamato monosódico como la molécula responsable y lo comercializó como el condimento Ajinomoto — hoy uno de los aditivos más usados del mundo.","El umami está presente en alimentos ricos en glutamato: parmesano, tomates maduros, salsa de soja, anchoas, setas shiitake y jamón ibérico."];

DEEP_DIVES['f21'].es = ["La pizza margherita fue creada en 1889 en Nápoles por el pizzero Raffaele Esposito en honor a la reina Margherita de Italia, usando los colores de la bandera: tomate (rojo), mozzarella (blanco) y albahaca (verde).","Sin embargo, los napolitanos ya comían pizzas similares desde al menos un siglo antes — la visita real simplemente oficializó un plato popular.","La Associazione Verace Pizza Napoletana certifica las pizzerías que siguen las reglas tradicionales: masa fermentada 24h, mozzarella di bufala, tomate San Marzano y horno de leña a 485 °C durante 60-90 segundos."];

DEEP_DIVES['f22'].es = ["El curry no es una especia sino una mezcla variable que puede incluir cúrcuma, comino, cilantro, jengibre, pimienta, canela, cardamomo y decenas de otras especias.","La palabra «curry» fue popularizada por los británicos en la India colonial — en la cocina india real, cada plato tiene su propia mezcla específica de especias (masala).","El curry japonés, traído por los británicos en el siglo XIX, se ha convertido en uno de los platos más populares de Japón — servido con arroz, es tan cotidiano como el ramen."];

DEEP_DIVES['f23'].es = ["El aguacate fue domesticado en Mesoamérica hace más de 5 000 años — su nombre proviene del náhuatl āhuacatl, que significa «testículo», por su forma.","Los grandes mamíferos prehistóricos (megafauna) dispersaban las semillas de aguacate al ingerirlos enteros — su extinción debería haber condenado al aguacate, pero la intervención humana lo salvó.","México produce un tercio del aguacate mundial, principalmente en el estado de Michoacán, donde los carteles del narcotráfico han llegado a controlar parte de la lucrativa industria."];

DEEP_DIVES['f24'].es = ["El queso existe desde hace al menos 7 500 años: restos de queso se han encontrado en vasijas neolíticas en Polonia y Croacia.","Su invención fue probablemente accidental: la leche transportada en estómagos de animales (que contienen cuajo) se coaguló naturalmente durante un viaje.","Francia produce más de 1 600 variedades de queso — el general De Gaulle dijo célebremente: «¿Cómo se puede gobernar un país que tiene 246 variedades de queso?» (la cifra era conservadora)."];

DEEP_DIVES['f25'].es = ["El té es la bebida más consumida del mundo después del agua, con más de 3 000 millones de tazas diarias.","Todo el té (verde, negro, blanco, oolong) proviene de la misma planta, Camellia sinensis — la diferencia está en el grado de oxidación de las hojas tras la cosecha.","La ceremonia del té japonesa (chanoyu) es mucho más que preparar una bebida: es una práctica filosófica y artística que encarna los principios zen de armonía, respeto, pureza y tranquilidad."];

DEEP_DIVES['f26'].es = ["El maíz fue domesticado en México hace unos 9 000 años a partir de una planta silvestre llamada teosinte, que apenas se parece al maíz moderno.","La transformación del teosinte en maíz es considerada una de las mayores proezas de selección genética de la historia humana — los agricultores mesoamericanos multiplicaron por 10 el tamaño de la mazorca.","Hoy el maíz es el cereal más producido del mundo (1 200 millones de toneladas/año), superando al trigo y al arroz — se utiliza en alimentos, biocarburantes, plásticos y más de 4 000 productos industriales."];

DEEP_DIVES['f27'].es = ["El aceite de oliva es la base de la dieta mediterránea, declarada Patrimonio Inmaterial de la Humanidad por la UNESCO en 2013.","Algunos olivos del Mediterráneo tienen más de 2 000 años de antigüedad y siguen produciendo aceitunas — son los árboles frutales más longevos del mundo.","España es el mayor productor mundial de aceite de oliva, con más del 40 % de la producción global — solo la provincia de Jaén produce más aceite que toda Grecia."];

DEEP_DIVES['f28'].es = ["Los insectos comestibles son consumidos por más de 2 000 millones de personas en el mundo, con más de 2 100 especies catalogadas como alimento.","Los grillos producen la misma cantidad de proteínas que el ganado bovino usando 12 veces menos alimento y emitiendo 100 veces menos gases de efecto invernadero.","La Unión Europea autorizó en 2023 la comercialización de cuatro especies de insectos como alimento, incluyendo el grillo doméstico y la larva del gusano de la harina."];

DEEP_DIVES['f29'].es = ["El chile más picante del mundo en 2024 es el Pepper X, creado por Ed Currie con 2 693 000 unidades Scoville — superando al Carolina Reaper.","Para comparar: un jalapeño alcanza 8 000 Scoville, una salsa tabasco 5 000, y el spray de pimienta policial oscila entre 2 y 5 millones de Scoville.","Los amantes del picante extremo experimentan una descarga de endorfinas similar a la de una montaña rusa — el cerebro interpreta el dolor como peligro y responde liberando analgésicos naturales."];

DEEP_DIVES['f30'].es = ["La fermentación es una de las técnicas culinarias más antiguas: el pan, el queso, el vino, la cerveza, el yogur, el kimchi y la salsa de soja son todos productos fermentados.","Los alimentos fermentados contienen probióticos que benefician la flora intestinal — estudios recientes vinculan un microbioma sano con mejor inmunidad, salud mental y digestión.","La cerveza más antigua conocida tiene unos 13 000 años: los Natufios del Levante elaboraban una bebida fermentada de trigo y cebada antes de inventar la agricultura propiamente dicha."];

// ── SPORTS sp01-sp030 ──

DEEP_DIVES['sp01'].es = ["Los Juegos Olímpicos antiguos se celebraron en Olimpia (Grecia) cada cuatro años durante más de 1 100 años, del 776 a.C. al 393 d.C.","Los atletas competían desnudos y las mujeres casadas tenían prohibido asistir — las competidoras femeninas tenían sus propios juegos, los Heraia, en honor a Hera.","Los Juegos modernos fueron restaurados por Pierre de Coubertin en 1896 en Atenas, con 241 atletas de 14 países — hoy participan más de 10 000 atletas de 200 naciones."];

DEEP_DIVES['sp02'].es = ["El fútbol es el deporte más popular del mundo, con más de 4 000 millones de aficionados y 270 millones de jugadores activos.","Las reglas modernas fueron codificadas en 1863 en Londres por la Football Association — antes, cada escuela inglesa jugaba con sus propias reglas.","La FIFA tiene 211 países miembros, más que las Naciones Unidas (193) — el fútbol es literalmente el idioma más universal del planeta."];

DEEP_DIVES['sp03'].es = ["El maratón moderno conmemora la legendaria carrera de Filípides desde Maratón hasta Atenas (42,195 km) en 490 a.C. para anunciar la victoria sobre los persas.","Sin embargo, los historiadores dudan de esta leyenda: Heródoto describe un corredor que recorrió 240 km hasta Esparta para pedir refuerzos, no los 42 km hasta Atenas.","La distancia oficial de 42,195 km se fijó en los Juegos de Londres de 1908 para que la carrera terminara frente al palco real — antes, cada maratón tenía una longitud diferente."];

DEEP_DIVES['sp04'].es = ["El cricket es el segundo deporte más seguido del mundo con 2 500 millones de aficionados, principalmente en India, Pakistán, Australia e Inglaterra.","Un partido de Test Cricket puede durar hasta cinco días, con pausas para el té — es probablemente el deporte más largo del mundo.","India es la superpotencia económica del cricket: la Indian Premier League (IPL) genera más ingresos que muchas ligas de fútbol europeas."];

DEEP_DIVES['sp05'].es = ["El baloncesto fue inventado en 1891 por James Naismith, un profesor canadiense de educación física que necesitaba un deporte de interior para el invierno.","Los primeros aros eran cestas de melocotones colgadas a 3,05 metros de altura — alguien tenía que subir una escalera para recuperar la pelota tras cada canasta.","La NBA se fundó en 1946 y se ha convertido en una de las ligas deportivas más valiosas del mundo, con franquicias valoradas en miles de millones de dólares."];

DEEP_DIVES['sp06'].es = ["El surf fue inventado por los polinesios hace al menos 3 000 años y era una actividad sagrada en la antigua Hawái, reservada a la nobleza.","El duque hawaiano Kahanamoku introdujo el surf en Australia y California a principios del siglo XX, convirtiéndolo en un fenómeno mundial.","El surf debutó como deporte olímpico en Tokio 2020 y las olas de los Juegos de París 2024 se disputaron en Tahití, a 15 000 km de la capital francesa."];

DEEP_DIVES['sp07'].es = ["El rugby debe su nombre a la escuela de Rugby (Inglaterra), donde en 1823 el estudiante William Webb Ellis supuestamente cogió el balón con las manos durante un partido de fútbol.","Esta historia es probablemente apócrifa, pero el trofeo de la Copa del Mundo de Rugby lleva el nombre de Webb Ellis en su honor.","La haka, danza guerrera maorí interpretada por los All Blacks de Nueva Zelanda antes de cada partido, se ha convertido en uno de los momentos más icónicos del deporte mundial."];

DEEP_DIVES['sp08'].es = ["El tenis moderno nació en 1873 cuando el mayor Walter Wingfield patentó un juego llamado «Sphairistikè» que se jugaba en césped — el nombre no cuajó, pero el deporte sí.","Wimbledon, el torneo más antiguo del mundo (desde 1877), sigue exigiendo que los jugadores vistan de blanco y se juega exclusivamente sobre hierba natural.","El servicio más rápido jamás registrado fue de 263,4 km/h por Sam Groth en 2012 — la pelota tarda apenas 0,4 segundos en cruzar la pista."];

DEEP_DIVES['sp09'].es = ["El ajedrez se originó en la India hacia el siglo VI como chaturanga, un juego que simulaba una batalla entre cuatro divisiones del ejército indio.","La pieza de la reina era originalmente un «consejero» débil que solo se movía un cuadrado en diagonal — su transformación en la pieza más poderosa del tablero ocurrió en la Europa del siglo XV.","El número de partidas de ajedrez posibles supera el número de átomos en el universo observable — se estima en 10^120, conocido como el número de Shannon."];

DEEP_DIVES['sp010'].es = ["La Fórmula 1 es el deporte motorizado más caro del mundo: un equipo de primer nivel gasta entre 150 y 200 millones de dólares por temporada.","Los coches de F1 generan tanta fuerza aerodinámica que teóricamente podrían circular boca abajo en un túnel a velocidades superiores a 160 km/h.","Michael Schumacher y Lewis Hamilton comparten el récord de 7 campeonatos mundiales — una rivalidad numérica que define dos eras del automovilismo."];

DEEP_DIVES['sp011'].es = ["El béisbol es conocido como el «pasatiempo nacional» de Estados Unidos y tiene raíces que se remontan a juegos de bate y pelota del siglo XVIII.","Un lanzador profesional puede enviar la pelota a más de 160 km/h — el bateador tiene menos de 0,4 segundos para decidir si golpea o no.","Japón, Corea del Sur, Cuba y la República Dominicana tienen ligas de béisbol tan competitivas que rivalizan con la MLB estadounidense en nivel técnico."];

DEEP_DIVES['sp012'].es = ["La natación competitiva ha sido parte de los Juegos Olímpicos desde 1896, pero los primeros estilos eran variaciones del braza — el crol no se generalizó hasta los años 1900.","Michael Phelps es el atleta olímpico más laureado de la historia con 28 medallas (23 de oro), un récord que probablemente no se superará en décadas.","Los trajes de baño de poliuretano fueron prohibidos en 2010 tras provocar una avalancha de récords mundiales — se consideró que convertían la competición en una carrera tecnológica."];

DEEP_DIVES['sp013'].es = ["El yoga, aunque hoy se practica principalmente como ejercicio físico, es una disciplina espiritual india de más de 5 000 años de antigüedad.","Existen decenas de estilos: hatha (posturas y respiración), vinyasa (flujo continuo), bikram (a 40 °C), kundalini (energía y meditación) y ashtanga (secuencias fijas).","Estudios científicos han demostrado que la práctica regular de yoga reduce el estrés, la ansiedad, la presión arterial y el dolor crónico, y mejora la flexibilidad y el equilibrio."];

DEEP_DIVES['sp014'].es = ["El golf moderno nació en Escocia en el siglo XV — el rey Jacobo II lo prohibió en 1457 porque distraía a los soldados del entrenamiento con arco.","Una pelota de golf tiene entre 300 y 500 hoyuelos que reducen la resistencia aerodinámica y permiten que vuele hasta 2,5 veces más lejos que una esfera lisa.","El Augusta National Golf Club, sede del Masters, no admitió mujeres hasta 2012 y no tuvo un miembro afroamericano hasta 1990 — un reflejo de la historia segregacionista del deporte."];

DEEP_DIVES['sp015'].es = ["Las artes marciales asiáticas tienen miles de años de historia: el kung-fu shaolín se practica desde el siglo VI, el judo fue codificado en 1882 y el taekwondo en 1955.","Bruce Lee revolucionó las artes marciales al crear el Jeet Kune Do, una filosofía que rechazaba los estilos rígidos en favor de la adaptabilidad — «sé como el agua».","Las artes marciales mixtas (MMA) combinan técnicas de boxeo, lucha libre, jiu-jitsu brasileño, muay thai y otras disciplinas — el UFC se ha convertido en una de las organizaciones deportivas más lucrativas del mundo."];

DEEP_DIVES['sp016'].es = ["El ciclismo profesional incluye las tres grandes vueltas: el Tour de Francia (desde 1903), el Giro de Italia (1909) y la Vuelta a España (1935).","El Tour de Francia recorre más de 3 500 km en 23 etapas durante 3 semanas — los ciclistas queman entre 5 000 y 8 000 calorías diarias durante la carrera.","La historia del ciclismo está manchada por el dopaje: la era de Lance Armstrong reveló un sistema organizado que afectaba a la mayoría de los equipos profesionales."];

DEEP_DIVES['sp017'].es = ["El Ironman es la prueba de triatlón más exigente: 3,8 km de natación, 180 km de ciclismo y un maratón completo (42,195 km), todo en un solo día.","El récord actual del Ironman de Hawái está por debajo de las 7 horas y 30 minutos — una hazaña de resistencia humana que parecía imposible hace apenas 20 años.","El primer Ironman se celebró en Hawái en 1978 con solo 15 participantes — hoy participan miles de atletas en decenas de Ironman por todo el mundo."];

DEEP_DIVES['sp018'].es = ["Serena Williams es considerada la mejor tenista de todos los tiempos, con 23 títulos de Grand Slam en la era abierta — un récord en categoría individual.","Williams dominó el tenis femenino durante más de dos décadas, transformando el deporte con su potencia atlética y su servicio devastador.","Más allá del deporte, Williams se ha convertido en un icono cultural y empresarial, rompiendo barreras raciales y de género en un deporte históricamente elitista."];

DEEP_DIVES['sp019'].es = ["El fútbol es el único deporte practicado en todos los países reconocidos por la ONU — la FIFA tiene más países miembros (211) que las Naciones Unidas (193).","La Copa del Mundo de la FIFA es el evento deportivo más visto del planeta: la final de 2022 en Qatar fue seguida por más de 1 500 millones de espectadores.","El fútbol femenino crece exponencialmente: el Mundial femenino de 2023 en Australia atrajo más de 1 900 millones de espectadores acumulados."];

DEEP_DIVES['sp020'].es = ["El servicio más rápido jamás registrado en tenis fue de 263,4 km/h, logrado por Sam Groth en un challenger en 2012.","A esa velocidad, la pelota cruza los 23,77 metros de la pista en apenas 0,32 segundos — más rápido de lo que un ojo humano puede seguir.","Los avances en materiales de raqueta (grafito, fibra de carbono) han aumentado drásticamente la potencia de los servicios en las últimas décadas."];

DEEP_DIVES['sp021'].es = ["El boxeo es uno de los deportes más antiguos del mundo: representaciones de combates de puños aparecen en relieves sumerios del 3000 a.C.","Muhammad Ali, considerado el mejor boxeador de la historia, no solo dominó el ring sino que se convirtió en símbolo de la lucha por los derechos civiles al negarse a ir a Vietnam.","El combate Alí-Foreman «Rumble in the Jungle» (Kinshasa, 1974) es considerado el evento deportivo más importante del siglo XX y fue visto por mil millones de personas."];

DEEP_DIVES['sp022'].es = ["El hockey sobre hielo es el deporte nacional de Canadá, donde se practica desde los años 1870 en lagos y ríos congelados.","El puck (disco) puede alcanzar velocidades superiores a 170 km/h — los porteros llevan más de 20 kg de protecciones y aun así sufren impactos frecuentes.","La Stanley Cup, el trofeo más antiguo del deporte profesional norteamericano (desde 1893), tiene la tradición de que cada jugador del equipo campeón puede llevarse la copa a casa durante un día."];

DEEP_DIVES['sp023'].es = ["La escalada deportiva debutó en los Juegos Olímpicos de Tokio 2020 con tres disciplinas: velocidad, bloque y dificultad.","La escalada de velocidad es la más espectacular: los atletas suben un muro de 15 metros en menos de 5 segundos — más rápido que un sprint de Usain Bolt.","El bouldering (bloque) se practica sin cuerda a baja altura sobre colchonetas — exige más resolución de problemas que resistencia, convirtiendo la escalada en un deporte tanto mental como físico."];

DEEP_DIVES['sp024'].es = ["El ping-pong (tenis de mesa) es el deporte con más practicantes del mundo: más de 300 millones de jugadores activos, la mayoría en China.","La pelota puede alcanzar 170 km/h en el servicio y 9 000 revoluciones por minuto de efecto — los jugadores profesionales reaccionan en milisegundos.","China ha dominado el tenis de mesa olímpico como ningún otro país en ningún otro deporte: ha ganado el 85 % de todas las medallas de oro en juego desde 1988."];

DEEP_DIVES['sp025'].es = ["El skateboarding nació en California en los años 1950 cuando surfistas buscaron replicar la sensación de las olas en el asfalto colocando ruedas bajo tablas de madera.","Tony Hawk realizó el primer «900» (dos giros y medio en el aire) en 1999, un momento que definió toda una generación y llevó el skate a la cultura mainstream.","El skateboarding debutó como deporte olímpico en Tokio 2020 — la ganadora de la categoría femenina de calle tenía solo 13 años, la medallista olímpica más joven de la historia de Japón."];

DEEP_DIVES['sp026'].es = ["El rugby a siete (rugby sevens) se juega con 7 jugadores por equipo en partidos de 14 minutos — es la versión olímpica del rugby, incluida desde Río 2016.","Nueva Zelanda y Fiyi son las potencias dominantes: Fiyi ganó el oro en las dos primeras ediciones olímpicas, un hito para una nación de menos de un millón de habitantes.","El rugby sevens es especialmente popular en Hong Kong, donde el torneo anual (Hong Kong Sevens) atrae a 40 000 espectadores y es uno de los mayores eventos deportivos de Asia."];

DEEP_DIVES['sp027'].es = ["La gimnasia artística combina fuerza, flexibilidad, coordinación y gracia en aparatos como barra fija, paralelas, suelo y salto.","Simone Biles es la gimnasta más laureada de la historia con 37 medallas mundiales — ha inventado movimientos tan difíciles que llevan su nombre y que nadie más puede ejecutar.","En Tokio 2020, Biles se retiró de varias finales por «twisties» (pérdida de orientación en el aire), abriendo un debate global sobre salud mental en el deporte de élite."];

DEEP_DIVES['sp028'].es = ["El sumo es el deporte nacional de Japón, con rituales sintoístas de más de 1 500 años: los luchadores lanzan sal para purificar el ring (dohyō) antes de cada combate.","Los sumotoris profesionales (rikishi) siguen un régimen estricto: viven en establos (heya), se levantan a las 5 h, entrenan en ayunas y comen chanko-nabe (un estofado calórico) para ganar peso.","Solo 72 luchadores han alcanzado el rango supremo de yokozuna en toda la historia del sumo — un título que implica no solo victoria sino también dignidad y gracia."];

DEEP_DIVES['sp029'].es = ["El parkour fue creado en los años 1990 por David Belle en los suburbios de París, inspirado en los métodos de entrenamiento militar de su padre, Raymond Belle.","La disciplina consiste en desplazarse de un punto a otro de la manera más fluida y eficiente posible, superando obstáculos urbanos con saltos, escaladas y equilibrios.","El parkour fue reconocido como disciplina deportiva por varias federaciones nacionales de gimnasia, aunque sus practicantes debaten si debería competirse o mantenerse como arte libre."];

DEEP_DIVES['sp030'].es = ["Los e-sports (deportes electrónicos) mueven más de 1 500 millones de dólares al año y atraen a más de 500 millones de espectadores en todo el mundo.","Los jugadores profesionales entrenan 8-12 horas diarias, tienen psicólogos deportivos, nutricionistas y coaches — su vida se asemeja a la de cualquier atleta de élite.","League of Legends, Dota 2, CS2 y Valorant ofrecen premios de torneos que superan los 40 millones de dólares — más que muchos torneos de golf o tenis profesional."];

// ── CELEBRITIES cel1-cel30 ──

DEEP_DIVES['cel1'].es = ["Cleopatra hablaba al menos nueve idiomas y fue la primera soberana ptolemaica en aprender egipcio — una política estratégica para ganarse al pueblo.","Su relación con Julio César y Marco Antonio fue tanto romántica como diplomática: Cleopatra buscaba aliados para preservar la independencia de Egipto frente a Roma.","Su suicidio en el 30 a.C. — según la leyenda, mediante la mordedura de un áspid — marcó el fin de la era faraónica y el comienzo del Egipto romano."];

DEEP_DIVES['cel2'].es = ["Albert Einstein publicó cuatro artículos revolucionarios en 1905, su annus mirabilis: sobre el efecto fotoeléctrico, el movimiento browniano, la relatividad especial y la equivalencia masa-energía (E=mc²).","Einstein era un estudiante mediocre en las materias que no le interesaban pero excepcional en física y matemáticas — el mito de que era mal estudiante es una simplificación.","Tras huir de la Alemania nazi en 1933, Einstein se estableció en Princeton y escribió la famosa carta a Roosevelt que impulsó el Proyecto Manhattan — una decisión que lamentó profundamente."];

DEEP_DIVES['cel3'].es = ["Leonardo da Vinci era vegetariano, zurdo, disléxico probable y escribía en espejo — hay que leer sus cuadernos reflejados para descifrarlos.","Diseñó máquinas voladoras, tanques, escafandras, robots y puentes portátiles siglos antes de que la tecnología permitiera construirlos.","Nunca publicó sus descubrimientos científicos: sus 7 200 páginas de notas permanecieron inéditas durante siglos, lo que retrasó avances que podrían haber cambiado la historia."];

DEEP_DIVES['cel4'].es = ["Marie Curie fue la primera persona en recibir dos Premios Nobel en disciplinas diferentes: Física (1903) y Química (1911).","Sus cuadernos de laboratorio siguen siendo tan radiactivos que deben consultarse con ropa protectora y se guardan en cajas forradas de plomo en la Bibliothèque Nationale de París.","Curie murió en 1934 de anemia aplásica causada por su exposición prolongada a la radiación — en su época, los peligros de la radiactividad eran desconocidos."];

DEEP_DIVES['cel5'].es = ["Nikola Tesla patentó más de 300 inventos, incluyendo la corriente alterna, el motor de inducción y los fundamentos de la radio y el control remoto.","Tesla fue eclipsado en vida por Edison, su rival, que dominaba el negocio y la prensa — Tesla murió solo y arruinado en una habitación de hotel de Nueva York en 1943.","Tesla imaginó el wifi, los drones y la energía inalámbrica más de un siglo antes de que existieran — sus visiones futuristas lo han convertido en icono de la cultura geek."];

DEEP_DIVES['cel6'].es = ["Frida Kahlo sufrió poliomielitis a los 6 años y un terrible accidente de autobús a los 18 que le causó fracturas múltiples y dolor crónico de por vida.","Su obra pictórica es profundamente autobiográfica: 55 de sus 143 cuadros son autorretratos que exploran el dolor, la identidad, el cuerpo y la mexicanidad.","Kahlo fue redescubierta en los años 1980 como icono feminista y LGBTQ+ — hoy es la artista latinoamericana más cotizada del mundo."];

DEEP_DIVES['cel7'].es = ["William Shakespeare escribió 37 obras de teatro, 154 sonetos e inventó más de 1 700 palabras inglesas, incluyendo «eyeball», «lonely» y «assassination».","Se sabe muy poco de su vida personal — existe un periodo de siete años (1585-1592) conocido como «los años perdidos» del que no hay ningún documento.","Algunos académicos dudan de que Shakespeare escribiera realmente sus obras, proponiendo candidatos como el conde de Oxford o Francis Bacon — un debate que sigue abierto."];

DEEP_DIVES['cel8'].es = ["Napoleón Bonaparte no era bajo: medía 1,69 m, por encima de la media francesa de la época (1,64 m).","Fue un genio militar y administrativo: el Código Napoleónico, la meritocracia, el sistema métrico y el banco de Francia son legados que perduran hasta hoy.","Exiliado a Santa Helena, Napoleón murió en 1821 — análisis modernos sugieren que murió de cáncer de estómago, aunque la hipótesis del envenenamiento por arsénico no se ha descartado del todo."];

DEEP_DIVES['cel9'].es = ["Mahatma Gandhi lideró el movimiento de independencia de la India mediante la resistencia no violenta (ahimsa) y la desobediencia civil.","Su Marcha de la Sal en 1930 — 388 km a pie para protestar contra el monopolio británico de la sal — movilizó a millones de indios y debilitó la legitimidad del dominio colonial.","Gandhi fue asesinado en 1948 por un extremista hindú que consideraba que sus políticas de conciliación con los musulmanes eran una traición — su muerte conmocionó al mundo entero."];

DEEP_DIVES['cel10'].es = ["Martin Luther King Jr. pronunció su célebre discurso «I Have a Dream» ante 250 000 personas en Washington D.C. en agosto de 1963.","Inspirado por Gandhi, King abogó por la resistencia no violenta contra la segregación racial — su liderazgo fue clave para la aprobación del Civil Rights Act de 1964.","King recibió el Nobel de la Paz en 1964 con solo 35 años y fue asesinado en Memphis en 1968 — su legado sigue siendo el pilar del movimiento por los derechos civiles."];

DEEP_DIVES['cel11'].es = ["Coco Chanel revolucionó la moda femenina al liberar a la mujer del corsé, popularizar los pantalones, el vestido negro y el perfume Chanel N°5.","Chanel creó un estilo que combinaba elegancia y comodidad — tomó prestados elementos del guardarropa masculino y los transformó en símbolos de independencia femenina.","Su pasado durante la ocupación nazi — mantuvo relaciones con oficiales alemanes — es una faceta controvertida que la marca Chanel prefiere minimizar."];

DEEP_DIVES['cel12'].es = ["Stephen Hawking fue diagnosticado con esclerosis lateral amiotrófica (ELA) a los 21 años y le dieron dos años de vida — sobrevivió 55 años más.","Su libro Breve historia del tiempo (1988) vendió más de 10 millones de ejemplares y acercó la física teórica al gran público como ningún otro antes.","Hawking demostró que los agujeros negros emiten radiación (radiación de Hawking), un descubrimiento que unió la mecánica cuántica y la relatividad general por primera vez."];

DEEP_DIVES['cel13'].es = ["Nelson Mandela pasó 27 años en prisión por luchar contra el apartheid en Sudáfrica — 18 de ellos en la isla de Robben Island.","Tras su liberación en 1990, Mandela negoció el fin pacífico del apartheid y fue elegido primer presidente negro de Sudáfrica en 1994.","Su capacidad de perdón y reconciliación — simbolizada por la Comisión de Verdad y Reconciliación — evitó una guerra civil y le valió el Nobel de la Paz en 1993."];

DEEP_DIVES['cel14'].es = ["Steve Jobs cofundó Apple en un garaje en 1976, fue expulsado de su propia empresa en 1985 y regresó en 1997 para transformarla en la marca más valiosa del mundo.","El iPhone (2007) no fue el primer smartphone, pero Jobs lo convirtió en un objeto de deseo que redefinió la industria tecnológica y la cultura digital.","Jobs era conocido por su perfeccionismo obsesivo: rechazaba prototipos por defectos invisibles y dedicaba meses al diseño de detalles que la mayoría de usuarios nunca notarían."];

DEEP_DIVES['cel15'].es = ["Simone de Beauvoir publicó El segundo sexo en 1949, un ensayo fundacional del feminismo moderno que analiza la condición de la mujer como construcción social.","Su relación con Jean-Paul Sartre fue un pacto de libertad radical: pareja intelectual y sentimental durante 51 años, nunca vivieron juntos ni se casaron.","Beauvoir rechazó la Legión de Honor francesa pero aceptó el premio Goncourt — su influencia en el feminismo, la filosofía existencialista y la literatura del siglo XX es inmensa."];

DEEP_DIVES['cel16'].es = ["Elon Musk cofundó PayPal, fundó SpaceX, dirige Tesla y adquirió Twitter (renombrado X) — una diversificación empresarial sin precedentes en la era moderna.","SpaceX logró en 2020 lo que ninguna empresa privada había conseguido: enviar astronautas a la Estación Espacial Internacional, rompiendo el monopolio de las agencias espaciales gubernamentales.","Musk es una figura polarizante: admirado por su visión tecnológica pero criticado por su gestión de redes sociales y sus declaraciones polémicas."];

DEEP_DIVES['cel17'].es = ["Malala Yousafzai recibió un disparo en la cabeza por parte de un talibán en 2012, a los 15 años, por defender el derecho de las niñas a la educación en Pakistán.","Sobrevivió milagrosamente y se convirtió en la persona más joven en recibir el Premio Nobel de la Paz en 2014, a los 17 años.","Hoy, la Fundación Malala trabaja en 10 países para garantizar el acceso a la educación de las niñas — Malala se graduó de Oxford en 2020."];

DEEP_DIVES['cel18'].es = ["Charles Darwin publicó El origen de las especies en 1859, presentando la teoría de la evolución por selección natural que transformó nuestra comprensión de la vida.","Darwin dudó durante 20 años antes de publicar, temeroso de las implicaciones religiosas — fue la competencia de Alfred Russel Wallace, que había llegado a conclusiones similares, lo que lo decidió.","La evolución es una de las teorías más sólidas de la ciencia moderna, respaldada por la genética, la paleontología, la biología molecular y la observación directa de la selección natural."];

DEEP_DIVES['cel19'].es = ["Ada Lovelace es considerada la primera programadora de la historia: en 1843 escribió un algoritmo para la máquina analítica de Charles Babbage, un siglo antes de los primeros ordenadores.","Lovelace fue hija del poeta Lord Byron, pero nunca lo conoció — su madre la orientó hacia las matemáticas precisamente para alejarla de la poesía y la imaginación paterna.","Lovelace previó que las máquinas podrían crear música y arte, no solo calcular — una visión profética que anticipó la inteligencia artificial."];

DEEP_DIVES['cel20'].es = ["Usain Bolt es el ser humano más rápido de la historia: su récord de 9,58 segundos en 100 metros (Berlín, 2009) sigue imbatido.","En su momento de máxima velocidad, Bolt alcanzó los 44,72 km/h — y lo hizo siendo significativamente más alto (1,95 m) que la mayoría de velocistas.","Bolt ganó 8 medallas olímpicas de oro consecutivas en 3 Juegos (2008-2016) y se retiró invicto en finales olímpicas — una dominación sin precedentes en el atletismo."];

DEEP_DIVES['cel21'].es = ["Pablo Picasso produjo más de 50 000 obras a lo largo de su carrera de 80 años — pinturas, esculturas, cerámicas, grabados y dibujos.","Picasso cofundó el cubismo con Georges Braque, descomponiendo los objetos en formas geométricas y mostrando múltiples perspectivas simultáneamente — una revolución visual.","El Guernica (1937), su denuncia del bombardeo de la ciudad vasca, es considerado uno de los alegatos más poderosos contra la guerra jamás pintados."];

DEEP_DIVES['cel22'].es = ["Mozart compuso su primera obra a los 5 años y su primera sinfonía a los 8 — fue el niño prodigio más célebre de la historia de la música.","Produjo más de 600 obras en solo 35 años de vida, incluyendo 41 sinfonías, 27 conciertos para piano y óperas como Las bodas de Fígaro y La flauta mágica.","Mozart murió a los 35 años en la pobreza y fue enterrado en una fosa común en Viena — la causa exacta de su muerte sigue siendo debatida por los historiadores médicos."];

DEEP_DIVES['cel23'].es = ["Greta Thunberg comenzó su huelga escolar por el clima en agosto de 2018, sentándose sola frente al Parlamento sueco con un cartel — tenía 15 años.","Su movimiento Fridays for Future se extendió a 150 países e inspiró a millones de jóvenes a manifestarse por la acción climática.","Thunberg ha sido elogiada como la voz de una generación y criticada como símbolo de activismo vacío — en ambos casos, ha obligado al mundo a hablar de la crisis climática."];

DEEP_DIVES['cel24'].es = ["Juana de Arco, una campesina analfabeta de 17 años, afirmó oír voces divinas que la instaban a liberar Francia de la ocupación inglesa durante la Guerra de los Cien Años.","Lideró tropas francesas en varias victorias decisivas, incluyendo la liberación de Orleans en 1429, que cambió el curso de la guerra.","Capturada por los borgoñones, vendida a los ingleses y condenada por herejía, fue quemada viva en Rouen en 1431 — fue canonizada como santa en 1920."];

DEEP_DIVES['cel25'].es = ["Wangari Maathai fue la primera mujer africana en recibir el Premio Nobel de la Paz (2004) por su lucha por el medio ambiente y los derechos de las mujeres en Kenia.","Fundó el Movimiento del Cinturón Verde en 1977, que ha plantado más de 50 millones de árboles en África y empoderado a miles de mujeres rurales.","Maathai fue encarcelada, golpeada y amenazada de muerte por su activismo — pero nunca cedió, convirtiéndose en símbolo de la resistencia pacífica africana."];

DEEP_DIVES['cel26'].es = ["Copernico fue el primero en proponer un modelo heliocéntrico completo del sistema solar en 1543, desafiando 1 400 años de geocentrismo ptolemaico.","Su obra De revolutionibus orbium coelestium fue publicada poco antes de su muerte — según la leyenda, recibió el primer ejemplar impreso en su lecho de muerte.","La revolución copernicana tardó más de un siglo en aceptarse plenamente: Galileo fue condenado por la Iglesia en 1633 por defender el heliocentrismo."];

DEEP_DIVES['cel27'].es = ["Pelé, considerado por muchos el mejor futbolista de la historia, marcó 1 283 goles en su carrera — un récord que ningún otro jugador ha igualado oficialmente.","Ganó tres Copas del Mundo con Brasil (1958, 1962, 1970) — el único jugador en lograr esa hazaña — y fue declarado «tesoro nacional» por el gobierno brasileño.","Pelé popularizó el fútbol en Estados Unidos jugando en el New York Cosmos en los años 1970, preparando el terreno para la creación de la MLS."];

DEEP_DIVES['cel28'].es = ["Rosa Parks se negó a ceder su asiento a un pasajero blanco en un autobús de Montgomery, Alabama, el 1 de diciembre de 1955.","Su arresto desencadenó un boicot de autobuses de 381 días liderado por Martin Luther King Jr. — un acto de desobediencia civil que transformó el movimiento por los derechos civiles.","Parks no fue la primera en negarse: Claudette Colvin lo hizo nueve meses antes, pero los líderes del movimiento eligieron a Parks por su imagen respetable — la historia es más compleja de lo que parece."];

DEEP_DIVES['cel29'].es = ["Alan Turing es considerado el padre de la informática teórica: su concepto de «máquina de Turing» (1936) definió los fundamentos de la computación moderna.","Durante la Segunda Guerra Mundial, Turing lideró el equipo que descifró el código Enigma de los nazis en Bletchley Park, acortando la guerra en al menos dos años según los historiadores.","Turing fue perseguido por su homosexualidad, condenado por «indecencia grave» en 1952 y sometido a castración química — se suicidó en 1954 a los 41 años. El gobierno británico le otorgó un perdón póstumo en 2013."];

DEEP_DIVES['cel30'].es = ["Beyoncé ha ganado más premios Grammy que cualquier otro artista en la historia, con más de 30 gramófonos dorados.","Su álbum visual Lemonade (2016) exploró la infidelidad, la raza y el empoderamiento femenino negro, trascendiendo la música para convertirse en un fenómeno cultural.","Beyoncé controla todos los aspectos de su carrera — dirección artística, coreografía, producción, negocios — redefiniendo lo que significa ser artista en la era digital."];

// ── FICTION fic1-fic30 ──

DEEP_DIVES['fic1'].es = ["Sherlock Holmes fue creado por Arthur Conan Doyle en 1887 y se convirtió en el personaje de ficción más adaptado de la historia, con más de 250 películas y series.","Conan Doyle detestaba a su personaje y lo mató en Las cataratas de Reichenbach (1893) — la protesta pública fue tan intensa que se vio obligado a resucitarlo 10 años después.","Los métodos deductivos de Holmes inspiraron avances reales en la criminología: la policía adoptó técnicas de observación y análisis forense influidas por la ficción."];

DEEP_DIVES['fic2'].es = ["Harry Potter fue rechazado por 12 editoriales antes de que Bloomsbury lo publicara en 1997, con una tirada inicial de solo 500 ejemplares.","La saga ha vendido más de 500 millones de ejemplares, ha sido traducida a 80 idiomas y ha generado un universo de películas, parques temáticos y productos valorado en más de 25 000 millones de dólares.","J.K. Rowling escribió gran parte del primer libro en cafeterías de Edimburgo mientras vivía de prestaciones sociales como madre soltera — una historia de superación tan famosa como la propia saga."];

DEEP_DIVES['fic3'].es = ["El Señor de los Anillos fue escrito por J.R.R. Tolkien entre 1937 y 1949 como secuela de El Hobbit, pero se convirtió en una obra maestra de la literatura fantástica.","Tolkien, filólogo de Oxford, creó idiomas completos (élfico sindarin y quenya) antes de escribir la historia — las lenguas inspiraron el mundo, no al revés.","La trilogía cinematográfica de Peter Jackson (2001-2003) ganó 17 premios Oscar y transformó Nueva Zelanda en destino turístico, generando más de 3 000 millones en taquilla."];

DEEP_DIVES['fic4'].es = ["Don Quijote de la Mancha (1605-1615) de Cervantes es considerada la primera novela moderna y el libro más traducido del mundo después de la Biblia.","Cervantes escribió la segunda parte en parte como respuesta a una continuación apócrifa escrita por un autor desconocido bajo el seudónimo de Avellaneda.","Don Quijote parodia las novelas de caballerías pero trasciende la sátira: su exploración de la locura, el idealismo y la realidad ha inspirado a filósofos de Unamuno a Foucault."];

DEEP_DIVES['fic5'].es = ["Star Wars fue rechazado por todos los estudios de Hollywood excepto Fox, y George Lucas tuvo que financiar parte de la producción con su propio dinero.","Lucas se inspiró en los monomitos de Joseph Campbell (El héroe de las mil caras), los samuráis de Kurosawa y la Flash Gordon de los años 1930.","La saga ha generado más de 70 000 millones de dólares en total (películas, merchandising, parques) — es la franquicia de entretenimiento más lucrativa de la historia."];

DEEP_DIVES['fic6'].es = ["Frankenstein de Mary Shelley (1818) es considerada la primera novela de ciencia ficción — escrita cuando la autora tenía apenas 18 años.","Shelley la concibió durante un verano lluvioso en Suiza, como parte de un reto de historias de terror con Lord Byron y Percy Shelley.","La novela plantea cuestiones éticas sobre la creación artificial de vida que siguen siendo centrales en los debates sobre inteligencia artificial y biotecnología."];

DEEP_DIVES['fic7'].es = ["Batman fue creado en 1939 por Bob Kane y Bill Finger, aunque Finger — quien diseñó el traje, el nombre y la personalidad — no recibió crédito oficial hasta 2015.","A diferencia de la mayoría de superhéroes, Batman no tiene superpoderes: su fuerza reside en su inteligencia, su entrenamiento y su fortuna — un héroe humano.","The Dark Knight Returns de Frank Miller (1986) reinventó el personaje como un antihéroe oscuro y complejo, transformando el cómic de superhéroes en literatura adulta."];

DEEP_DIVES['fic8'].es = ["Alicia en el País de las Maravillas (1865) fue escrita por Lewis Carroll, pseudónimo del matemático Charles Dodgson, para la hija de un colega de Oxford.","El libro está lleno de juegos lógicos, paradojas matemáticas y sátiras políticas disfrazadas de absurdo infantil — opera en múltiples niveles de lectura.","Las adaptaciones de Disney (1951 y 2010) popularizaron una versión suavizada — el original de Carroll es mucho más extraño, oscuro y filosóficamente provocador."];

DEEP_DIVES['fic9'].es = ["Drácula de Bram Stoker (1897) se inspiró en el folclore vampírico de Europa del Este y posiblemente en Vlad Tepes, el príncipe rumano del siglo XV.","Stoker investigó durante años la historia y la geografía de Transilvania, aunque nunca visitó Rumanía — el castillo de Drácula es una creación literaria.","Drácula ha generado más de 1 000 adaptaciones cinematográficas, convirtiéndolo en el personaje de ficción más filmado después de Sherlock Holmes."];

DEEP_DIVES['fic10'].es = ["1984 de George Orwell (1949) introdujo conceptos como Gran Hermano, neolengua, doblepensar y policía del pensamiento en el vocabulario común.","Orwell escribió la novela mientras agonizaba de tuberculosis en una isla escocesa — murió siete meses después de su publicación.","Las ventas de 1984 se disparan cada vez que un escándalo de vigilancia gubernamental sacude la opinión pública — fue bestseller en 2013 tras las revelaciones de Snowden y en 2017 tras la llegada de Trump."];

DEEP_DIVES['fic11'].es = ["Los mangas japoneses representan un mercado de más de 6 000 millones de dólares anuales y se leen de derecha a izquierda en su formato original.","Osamu Tezuka, creador de Astro Boy (1952), es considerado el padre del manga moderno — introdujo los ojos grandes y las narrativas complejas que definen el estilo.","One Piece de Eiichiro Oda ha vendido más de 500 millones de copias, convirtiéndolo en la serie de manga más vendida de la historia."];

DEEP_DIVES['fic12'].es = ["El Principito de Antoine de Saint-Exupéry (1943) es el libro más traducido del mundo después de la Biblia y el Corán, con versiones en más de 300 idiomas.","Saint-Exupéry, piloto de guerra, desapareció durante una misión de reconocimiento en 1944 — los restos de su avión fueron encontrados en el Mediterráneo en 2004.","La frase «lo esencial es invisible a los ojos» se ha convertido en una de las citas literarias más universales, citada en contextos que van de la filosofía al marketing."];

DEEP_DIVES['fic13'].es = ["James Bond fue creado por Ian Fleming en 1953, inspirándose en espías reales que conoció durante su trabajo en la inteligencia naval británica.","El agente 007 ha sido interpretado por 7 actores diferentes en 25 películas oficiales que han recaudado más de 7 000 millones de dólares en taquilla.","Fleming eligió el nombre James Bond del autor de un libro de ornitología del Caribe — quería un nombre lo más anodino y poco memorable posible."];

DEEP_DIVES['fic14'].es = ["El Quijote inventó la novela polifónica: múltiples voces, puntos de vista y niveles de realidad se entrelazan en una estructura que anticipó la literatura posmoderna.","Sancho Panza no es simplemente un contrapunto cómico: su evolución a lo largo de la novela es tan profunda como la de Don Quijote — ambos se influyen mutuamente.","La frase «tilting at windmills» (luchar contra molinos de viento) se usa en decenas de idiomas para describir batallas contra enemigos imaginarios — un legado lingüístico universal."];

DEEP_DIVES['fic15'].es = ["Los superhéroes modernos nacieron en 1938 con la aparición de Superman en Action Comics #1, creado por Jerry Siegel y Joe Shuster, dos adolescentes de Cleveland.","Siegel y Shuster vendieron los derechos de Superman por 130 dólares — el personaje ha generado desde entonces miles de millones en productos y entretenimiento.","Superman fue concebido como inmigrante (de Krypton) que se integra en su país de adopción — una metáfora de la experiencia de los inmigrantes judíos en Estados Unidos."];

DEEP_DIVES['fic16'].es = ["Game of Thrones (Juego de Tronos) de George R.R. Martin se inspira en la Guerra de las Rosas inglesas (Lancaster vs York) y en las intrigas de los Borgia.","La serie de HBO (2011-2019) se convirtió en el fenómeno televisivo más grande de su era, con audiencias de más de 19 millones por episodio en su última temporada.","Martin lleva más de 13 años escribiendo el sexto libro (Vientos de Invierno) — la espera se ha convertido en un meme cultural y una fuente de frustración para millones de lectores."];

DEEP_DIVES['fic17'].es = ["Cien años de soledad de Gabriel García Márquez (1967) es la obra cumbre del realismo mágico latinoamericano y una de las novelas más influyentes del siglo XX.","García Márquez vendió su coche y empeñó los electrodomésticos de su esposa para poder escribir la novela durante 18 meses sin interrupciones.","La novela narra siete generaciones de la familia Buendía en el pueblo ficticio de Macondo — una metáfora de la historia de América Latina."];

DEEP_DIVES['fic18'].es = ["Los cuentos de los hermanos Grimm (1812) no eran originalmente para niños: contenían violencia, crueldad y temas adultos que fueron suavizados en ediciones posteriores.","En la versión original de Cenicienta, las hermanastras se cortan los dedos de los pies para que les quepa el zapato — y palomas les arrancan los ojos al final como castigo.","Walt Disney transformó estos cuentos oscuros en películas familiares, creando las versiones edulcoradas que la mayoría del mundo conoce hoy."];

DEEP_DIVES['fic19'].es = ["Pikachu, la mascota de Pokémon, no fue el protagonista original: los creadores querían a Clefairy, pero Pikachu fue elegido por ser más atractivo visualmente.","Pokémon ha generado más de 100 000 millones de dólares desde su creación en 1996, convirtiéndolo en la franquicia de medios más lucrativa de todos los tiempos.","El nombre Pokémon es una contracción de Pocket Monsters (monstruos de bolsillo) — el juego original fue creado por Satoshi Tajiri, un niño coleccionista de insectos."];

DEEP_DIVES['fic20'].es = ["El Hobbit fue publicado en 1937 como cuento para niños y tuvo tanto éxito que el editor pidió una secuela — Tolkien tardó 12 años en escribir El Señor de los Anillos.","Tolkien se inspiró en las mitologías nórdica, celta y finlandesa (el Kalevala) para crear la Tierra Media — quería dar a Inglaterra una mitología propia.","Los hobbits están inspirados en los ingleses rurales del siglo XIX: amantes de la buena comida, del jardín y de la tranquilidad — un reflejo del propio Tolkien."];

DEEP_DIVES['fic21'].es = ["Las Mil y Una Noches es una recopilación de cuentos árabes, persas e indios que incluye historias universalmente conocidas como Aladino, Simbad y Ali Baba.","La estructura de cajas chinas (cuentos dentro de cuentos) fue revolucionaria: Sheherezade narra historias durante 1001 noches para evitar su ejecución por el sultán.","Aladino y Alí Babá no figuraban en los manuscritos originales: fueron añadidos por el traductor francés Antoine Galland en el siglo XVIII, basándose en un cuentista sirio."];

DEEP_DIVES['fic22'].es = ["El manga Naruto de Masashi Kishimoto ha vendido más de 250 millones de copias y ha influido en toda una generación de artistas y creadores en el mundo entero.","La historia de un ninja marginado que sueña con ser líder de su aldea resuena con temas universales de perseverancia, amistad y superación personal.","Naruto introdujo la cultura ninja japonesa a millones de lectores occidentales, generando un interés real por la historia y la mitología japonesas."];

DEEP_DIVES['fic23'].es = ["Astérix, creado por Goscinny y Uderzo en 1959, es el cómic francés más exitoso de la historia, con más de 390 millones de álbumes vendidos en todo el mundo.","Cada álbum parodia un país o cultura diferente a través del prisma galo, con juegos de palabras que son una pesadilla para los traductores.","El parque Astérix, cerca de París, compite directamente con Disneyland — una rara victoria cultural europea frente a la hegemonía del entretenimiento estadounidense."];

DEEP_DIVES['fic24'].es = ["La Divina Comedia de Dante Alighieri (1320) es considerada una de las mayores obras de la literatura universal y fundó la lengua italiana literaria.","El poema describe un viaje por el Infierno, el Purgatorio y el Paraíso, con descripciones tan vívidas que influyeron en las representaciones artísticas del más allá durante siglos.","Dante escribió en toscano vulgar en lugar de latín — una decisión revolucionaria que democratizó la literatura y sentó las bases del italiano moderno."];

DEEP_DIVES['fic25'].es = ["Spider-Man fue creado por Stan Lee y Steve Ditko en 1962 como un superhéroe adolescente con problemas cotidianos — una novedad radical en el género.","Peter Parker era tímido, tenía problemas de dinero y era acosado en el instituto — un héroe con el que los lectores jóvenes podían identificarse por primera vez.","Spider-Man es el superhéroe más popular del mundo en merchandising y ha protagonizado más de 10 películas que han recaudado conjuntamente más de 8 000 millones de dólares."];

DEEP_DIVES['fic26'].es = ["Hamlet de Shakespeare (1600) es la obra de teatro más representada y estudiada de la historia, con el monólogo «ser o no ser» como texto dramático más famoso del mundo.","La obra explora la duda, la venganza, la locura y la mortalidad con una profundidad psicológica que anticipó el psicoanálisis de Freud por tres siglos.","Hamlet ha sido interpretado por los mayores actores de cada generación — desde Richard Burbage en 1601 hasta Benedict Cumberbatch en 2015."];

DEEP_DIVES['fic27'].es = ["El Pequeño Príncipe ha sido adaptado a más de 300 idiomas y dialectos, incluyendo lenguas en peligro de extinción como el toba y el maya lacandón.","Saint-Exupéry ilustró personalmente el libro con acuarelas — sus dibujos aparentemente simples son parte integral de la obra y tan famosos como el texto.","La rosa del Principito es generalmente interpretada como un símbolo de Consuelo Suncín, la esposa salvadoreña de Saint-Exupéry — una relación apasionada y tormentosa."];

DEEP_DIVES['fic28'].es = ["Miyazaki Hayao, fundador del Studio Ghibli, es considerado el Walt Disney japonés — sus películas han ganado un Oscar y son tesoros culturales.","El viaje de Chihiro (2001) ganó el Oscar a Mejor Película de Animación y el Oso de Oro en Berlín — la única película animada en conseguir ambos premios.","Miyazaki se ha retirado y vuelto al trabajo al menos cuatro veces — su perfeccionismo y su pasión por la animación tradicional (dibujada a mano) lo distinguen en una era digital."];

DEEP_DIVES['fic29'].es = ["Los Miserables de Victor Hugo (1862) es una de las novelas más largas y ambiciosas de la literatura universal, con más de 1 500 páginas.","Hugo interrumpió la escritura durante 12 años (1848-1860) por su exilio político — retomó la novela en la isla de Guernesey con una visión aún más social y humanista.","El musical basado en la novela (1985) es el espectáculo más longevo de la historia del West End de Londres, con más de 13 000 representaciones."];

DEEP_DIVES['fic30'].es = ["Mafalda, creada por el argentino Quino en 1964, es la tira cómica más influyente de América Latina — una niña de 6 años que cuestiona la política, la sociedad y la condición humana.","Quino dejó de dibujar Mafalda en 1973 para evitar que se volviera repetitiva — una decisión que preservó la frescura y la relevancia del personaje durante décadas.","La UNICEF adoptó a Mafalda como defensora de los derechos de los niños, y sus tiras se han traducido a más de 30 idiomas."];

// ── GAMING gam1-gam30 ──

DEEP_DIVES['gam1'].es = ["Pong (1972) de Atari no fue el primer videojuego, pero fue el primero en tener éxito comercial — sus máquinas recreativas se averiaban porque las cajas se llenaban de monedas.","El primer videojuego reconocido es Tennis for Two (1958), creado por el físico William Higinbotham en un osciloscopio del laboratorio nacional de Brookhaven.","Pong era tan simple que su manual de instrucciones decía: «Evita perder la pelota para conseguir una puntuación alta» — una época en que la simplicidad era virtud."];

DEEP_DIVES['gam2'].es = ["Super Mario Bros. (1985) salvó la industria del videojuego tras la crisis de 1983, que había reducido el mercado estadounidense de 3 200 a 100 millones de dólares.","Shigeru Miyamoto creó a Mario como un carpintero (luego fontanero) porque los bigotes eran más fáciles de animar que una boca con los píxeles disponibles en la NES.","Mario es el personaje de videojuego más reconocido del mundo — ha aparecido en más de 200 juegos y ha vendido más de 800 millones de copias en total."];

DEEP_DIVES['gam3'].es = ["Minecraft, creado por Markus «Notch» Persson en 2009, es el videojuego más vendido de la historia con más de 300 millones de copias.","El juego no tiene objetivos fijos: los jugadores construyen, exploran y sobreviven en un mundo infinito generado proceduralmente — una libertad creativa sin precedentes.","Microsoft compró Minecraft en 2014 por 2 500 millones de dólares — hoy se usa en escuelas de todo el mundo como herramienta educativa para enseñar programación, arquitectura y colaboración."];

DEEP_DIVES['gam4'].es = ["La Game Boy de Nintendo (1989) vendió más de 118 millones de unidades a pesar de tener una pantalla monocroma y un procesador inferior a sus competidores.","Tetris, incluido con la Game Boy, fue creado en 1984 por el programador soviético Alexei Pajitnov en un ordenador del gobierno — los derechos fueron objeto de una guerra legal internacional.","La Game Boy era tan robusta que un ejemplar sobrevivió a un bombardeo durante la Guerra del Golfo y sigue funcionando — se exhibe en la Nintendo World Store de Nueva York."];

DEEP_DIVES['gam5'].es = ["World of Warcraft (2004) de Blizzard alcanzó 12 millones de suscriptores mensuales en su apogeo, convirtiéndolo en el MMORPG más exitoso de la historia.","La economía virtual de WoW es tan compleja que economistas la han estudiado como modelo de mercado: la inflación, la especulación y el comercio siguen patrones del mundo real.","En 2005, una plaga virtual (Corrupted Blood) se propagó accidentalmente por el juego, matando a miles de personajes — epidemiólogos usaron el incidente para estudiar la propagación de pandemias."];

DEEP_DIVES['gam6'].es = ["The Legend of Zelda (1986) fue revolucionario por ofrecer un mundo abierto no lineal donde el jugador podía explorar libremente — un concepto adelantado a su época.","Shigeru Miyamoto se inspiró en sus exploraciones de niño por las colinas y cuevas de Kioto para crear Hyrule — un mundo diseñado para evocar la sensación de descubrimiento.","Breath of the Wild (2017) redefinió el género de mundo abierto con una física emergente donde casi todo es interactivo — fue elegido Juego del Año por unanimidad."];

DEEP_DIVES['gam7'].es = ["Pokémon Rojo y Azul (1996) vendieron más de 31 millones de copias y lanzaron una franquicia que supera los 100 000 millones de dólares — la más lucrativa del entretenimiento.","Satoshi Tajiri creó Pokémon inspirándose en su infancia coleccionando insectos en los campos de Tokio — la mecánica de captura y colección nació de esa pasión.","Pokémon GO (2016) generó un fenómeno social global: millones de personas salieron a la calle a capturar Pokémon virtuales, causando accidentes de tráfico y trespassing en masa."];

DEEP_DIVES['gam8'].es = ["Grand Theft Auto V (2013) es el producto de entretenimiento más rentable de la historia: ha generado más de 8 000 millones de dólares, superando a cualquier película, libro o álbum.","Su mundo abierto de Los Santos (basado en Los Ángeles) es tan detallado que incluye un mercado de valores funcional que responde a las acciones de los jugadores en línea.","La serie GTA ha sido objeto de intensas polémicas por su violencia y su sátira de la sociedad estadounidense — sus críticos la acusan de glorificar el crimen, sus defensores la defienden como sátira social."];

DEEP_DIVES['gam9'].es = ["Los esports mueven más de 1 800 millones de dólares al año y la final del Mundial de League of Legends atrae más espectadores que el Super Bowl.","Los jugadores profesionales entrenan 8-14 horas diarias, tienen nutricionistas, psicólogos deportivos y contratos millonarios — su vida es comparable a la de un atleta olímpico.","Corea del Sur es la superpotencia de los esports: los jugadores profesionales son celebridades nacionales y las partidas se retransmiten en canales de televisión dedicados."];

DEEP_DIVES['gam10'].es = ["Pac-Man (1980) fue diseñado por Toru Iwatani para atraer a un público femenino en las salas recreativas, dominadas por juegos de guerra y deportes.","La forma de Pac-Man se inspiró en una pizza a la que le faltaba un trozo — los fantasmas tienen nombres y personalidades: Blinky persigue, Pinky embosca, Inky es impredecible y Clyde va a su aire.","Pac-Man generó más de 2 500 millones de dólares en monedas en los años 80 — fue el primer personaje de videojuego en tener merchandising oficial."];

DEEP_DIVES['gam11'].es = ["Dark Souls (2011) popularizó el género «soulslike»: juegos de acción-RPG conocidos por su dificultad extrema y su diseño de mundo interconectado.","Hidetaka Miyazaki, su director, se inspiró en libros de fantasía en inglés que no entendía del todo — rellenaba los vacíos con su imaginación, creando una narrativa intencionalmente fragmentaria.","La frase «You Died» se ha convertido en un meme cultural que simboliza la perseverancia ante el fracaso — toda una filosofía de diseño que ha influido en cientos de juegos posteriores."];

DEEP_DIVES['gam12'].es = ["Tetris es el juego más universal de la historia: se ha vendido en más de 500 millones de copias en todas las plataformas, desde el Game Boy hasta los smartphones.","Su creador Alexei Pajitnov no ganó nada durante años porque los derechos pertenecían al gobierno soviético — solo empezó a cobrar regalías tras la caída de la URSS.","Estudios científicos han demostrado que jugar a Tetris reduce los síntomas de estrés postraumático y las ansias de adicción — el fenómeno se conoce como «efecto Tetris»."];

DEEP_DIVES['gam13'].es = ["La PlayStation de Sony (1994) nació de una colaboración fallida con Nintendo: Sony iba a fabricar un periférico de CD para la SNES, pero Nintendo rompió el acuerdo — y Sony decidió crear su propia consola.","La primera PlayStation vendió más de 102 millones de unidades y derrocó a Nintendo como líder del mercado, inaugurando la era del CD y los gráficos 3D.","La rivalidad Sony-Nintendo-Microsoft ha impulsado la innovación tecnológica más rápida en la historia del entretenimiento electrónico."];

DEEP_DIVES['gam14'].es = ["Fortnite Battle Royale (2017) pasó de ser un modo de juego secundario a un fenómeno cultural global con más de 400 millones de cuentas registradas.","Epic Games generó más de 5 000 millones de dólares solo en 2018 con un juego gratuito — monetizado exclusivamente mediante cosméticos (skins, bailes, emotes).","Fortnite organizó conciertos virtuales con Travis Scott, Ariana Grande y Eminem que atrajeron a decenas de millones de espectadores simultáneos — difuminando la frontera entre videojuego y plataforma de entretenimiento."];

DEEP_DIVES['gam15'].es = ["Space Invaders (1978) fue tan popular en Japón que causó una escasez nacional de monedas de 100 yenes — el gobierno tuvo que acuñar más para satisfacer la demanda.","El juego introdujo conceptos ahora universales: puntuaciones guardadas, enemigos con patrones de ataque y dificultad creciente a medida que avanza la partida.","Space Invaders generó más de 13 000 millones de dólares en su vida útil y es considerado el juego que lanzó la edad dorada de las recreativas."];

DEEP_DIVES['gam16'].es = ["Animal Crossing: New Horizons (2020) vendió 44 millones de copias, impulsado por el confinamiento de la pandemia de COVID-19.","El juego simula la vida en una isla tropical sin objetivos ni violencia — se juega en tiempo real y cambia con las estaciones y la hora del día.","Animal Crossing se convirtió en un espacio social: los jugadores celebraron bodas, graduaciones y hasta mítines políticos virtuales durante los confinamientos."];

DEEP_DIVES['gam17'].es = ["Doom (1993) popularizó el shooter en primera persona y creó la cultura del modding: id Software liberó el motor del juego para que los jugadores crearan sus propios niveles.","El juego fue tan adictivo en las oficinas que empresas como Intel lo prohibieron en sus ordenadores por la caída de productividad.","Doom ha sido portado a prácticamente todo dispositivo con pantalla: calculadoras, relojes inteligentes, pruebas de embarazo e incluso tractores John Deere."];

DEEP_DIVES['gam18'].es = ["The Sims (2000) de Will Wright es el juego de simulación de vida más vendido de la historia, con más de 200 millones de copias en toda la saga.","Wright se inspiró en la pérdida de su casa en un incendio: mientras la reconstruía, empezó a pensar en un juego sobre la arquitectura y las relaciones humanas cotidianas.","Los Sims tienen su propio idioma inventado, el simlish, compuesto de balbuceos sin significado — artistas como Katy Perry y The Black Eyed Peas han grabado canciones en simlish."];

DEEP_DIVES['gam19'].es = ["Final Fantasy VII (1997) es el RPG japonés más influyente de la historia: sus cinemáticas, su historia emocional y su banda sonora elevaron el género a la categoría de arte.","La muerte de Aerith es uno de los momentos más impactantes de la historia del videojuego — miles de jugadores intentaron durante años encontrar una forma de evitarla.","El remake en varias partes (desde 2020) reimagina el juego original con gráficos modernos y mecánicas expandidas, generando un debate apasionado sobre la fidelidad a la obra original."];

DEEP_DIVES['gam20'].es = ["Roblox (2006) cuenta con más de 70 millones de usuarios activos diarios, la mayoría menores de 16 años — es tanto una plataforma de juegos como un motor de creación.","Los creadores de juegos en Roblox pueden ganar dinero real: los más exitosos ganan millones de dólares al año mediante la moneda virtual Robux.","La plataforma ha sido criticada por problemas de seguridad infantil y prácticas de monetización agresivas dirigidas a niños — un debate recurrente sobre la responsabilidad de las plataformas digitales."];

DEEP_DIVES['gam21'].es = ["El primer speedrun documentado es de Doom en 1994 — hoy, el speedrunning es una subcultura global con eventos caritativos como Games Done Quick que recaudan millones.","Los speedrunners explotan bugs, glitches y atajos no previstos por los desarrolladores para terminar juegos en fracciones del tiempo normal.","Super Mario 64 se puede completar en menos de 7 minutos con las técnicas más avanzadas — un juego diseñado para docenas de horas de juego."];

DEEP_DIVES['gam22'].es = ["Wii Sports (2006) de Nintendo vendió más de 82 millones de copias y convirtió a la Wii en un fenómeno social que atrajo a jugadores no tradicionales — abuelos, familias y no gamers.","El control por movimiento fue tan intuitivo que causó accidentes: televisores rotos y mandos estrellados se volvieron virales en los primeros meses.","La Wii demostró que la innovación en la interfaz puede ser más disruptiva que la potencia gráfica — una lección que Nintendo sigue aplicando con la Switch."];

DEEP_DIVES['gam23'].es = ["Half-Life (1998) revolucionó el FPS narrativo: en lugar de cinemáticas separadas, la historia se cuenta durante el gameplay, sin interrumpir nunca el control del jugador.","Su secuela Half-Life 2 (2004) introdujo el motor Source y la física realista en los shooters, elevando el estándar técnico de toda la industria.","Half-Life 3 es el juego más esperado y nunca anunciado de la historia — la ausencia de secuela se ha convertido en el meme más duradero del mundo del gaming."];

DEEP_DIVES['gam24'].es = ["Among Us (2018) pasó desapercibido durante dos años hasta que streamers de Twitch lo popularizaron en 2020 — llegó a 500 millones de jugadores activos mensuales.","El juego de deducción social (inspirado en Mafia y Los Hombres Lobo) demostró que un concepto simple con la plataforma adecuada puede convertirse en fenómeno global.","La palabra «sus» (sospechoso), popularizada por Among Us, entró en el vocabulario cotidiano de toda una generación — un ejemplo de cómo los videojuegos moldean el lenguaje."];

DEEP_DIVES['gam25'].es = ["Elden Ring (2022) de FromSoftware y George R.R. Martin vendió más de 20 millones de copias en su primer año, combinando la dificultad de Dark Souls con un mundo abierto épico.","Martin escribió la mitología y el trasfondo del mundo (The Lands Between), mientras Miyazaki diseñó el gameplay y la narrativa fragmentaria característica de sus obras.","Elden Ring ganó el Game Award al Juego del Año 2022 y revitalizó el debate sobre la accesibilidad en los videojuegos: ¿un juego debería adaptarse a todos o preservar su visión artística?"];

DEEP_DIVES['gam26'].es = ["La Nintendo Switch (2017) es una consola híbrida que se puede usar como portátil o conectar a la televisión — ha vendido más de 140 millones de unidades.","The Legend of Zelda: Tears of the Kingdom (2023) vendió más de 10 millones de copias en tres días, batiendo récords de la propia Nintendo.","La filosofía de Nintendo — «la jugabilidad antes que los gráficos» — le ha permitido competir contra Sony y Microsoft con hardware significativamente menos potente."];

DEEP_DIVES['gam27'].es = ["El ajedrez en línea experimentó un boom sin precedentes tras el éxito de la serie Gambito de Dama (2020): Chess.com duplicó sus usuarios en semanas.","Las plataformas de ajedrez en línea como Chess.com y Lichess cuentan con más de 100 millones de usuarios combinados.","El ajedrez se considera cada vez más un esport: los torneos en línea atraen a cientos de miles de espectadores y los streamers de ajedrez son celebridades en Twitch."];

DEEP_DIVES['gam28'].es = ["Undertale (2015) fue creado casi íntegramente por una sola persona, Toby Fox, y se convirtió en un fenómeno indie con millones de copias vendidas.","El juego subvierte las convenciones del RPG: el jugador puede completar toda la aventura sin matar a ningún enemigo, eligiendo la compasión sobre la violencia.","La banda sonora, compuesta por Fox, es una de las más aclamadas del medio — Megalovania se ha convertido en un himno de la cultura gamer."];

DEEP_DIVES['gam29'].es = ["La realidad virtual en videojuegos despegó con el Oculus Rift (2016) y el PlayStation VR, pero el Meta Quest 2 (2020) democratizó el acceso con un precio asequible.","Half-Life: Alyx (2020) demostró que la VR puede ofrecer experiencias narrativas comparables a los mejores juegos tradicionales — fue aclamado como un hito del medio.","Los desafíos de la VR persisten: náuseas por movimiento, aislamiento social y fatiga visual limitan las sesiones de juego — la tecnología sigue madurando."];

DEEP_DIVES['gam30'].es = ["La industria del videojuego genera más ingresos que el cine y la música combinados: más de 180 000 millones de dólares anuales en 2024.","Los juegos móviles representan más del 50 % de los ingresos totales — Candy Crush, Genshin Impact y PUBG Mobile dominan un mercado de 3 000 millones de jugadores.","La IA generativa está transformando el desarrollo de juegos: desde la creación de contenido procedural hasta los NPC con conversaciones naturales — el futuro del medio está en plena mutación."];

// ── CINEMA cin1-cin30 ──

DEEP_DIVES['cin1'].es = ["Los hermanos Lumière proyectaron la primera película pública el 28 de diciembre de 1895 en el Grand Café de París ante 33 espectadores que pagaron 1 franco cada uno.","La llegada de un tren a la estación supuestamente causó pánico entre los espectadores — aunque esta anécdota es probablemente exagerada, refleja el impacto del nuevo medio.","Los Lumière creían que el cine no tenía futuro comercial: «El cine es una invención sin porvenir», declaró Auguste Lumière — una de las peores predicciones de la historia."];

DEEP_DIVES['cin2'].es = ["Ciudadano Kane (1941) de Orson Welles es considerada la mejor película de todos los tiempos en innumerables listas — Welles la dirigió, protagonizó y coescribió con solo 25 años.","La película introdujo técnicas revolucionarias: planos secuencia, profundidad de campo extrema, iluminación expresionista y una estructura narrativa no lineal.","William Randolph Hearst, el magnate de la prensa en quien está basado Charles Foster Kane, intentó destruir la película comprando todas las copias — fracasó, pero perjudicó su distribución."];

DEEP_DIVES['cin3'].es = ["Bollywood produce más de 1 500 películas al año, superando ampliamente a Hollywood, y su audiencia supera los 3 000 millones de espectadores en todo el mundo.","Las películas de Bollywood suelen durar 3 horas e incluyen números musicales, romance, acción y drama familiar — un formato que refleja la cultura india del entretenimiento total.","El nombre «Bollywood» combina Bombay (actual Mumbai) y Hollywood — pero la industria india tiene tradiciones cinematográficas que preceden a las de Hollywood en varias décadas."];

DEEP_DIVES['cin4'].es = ["Alfred Hitchcock, el «maestro del suspense», dirigió más de 50 películas y desarrolló técnicas narrativas que siguen siendo estudiadas en todas las escuelas de cine.","Su cameo en cada una de sus películas se convirtió en un juego para los espectadores — una tradición de autorreferencia que anticipó la cultura del «easter egg».","Psycho (1960) rompió todas las reglas: mató a su protagonista en el primer tercio, mostró un inodoro en pantalla por primera vez y utilizó la música de Bernard Herrmann para crear terror puro."];

DEEP_DIVES['cin5'].es = ["Star Wars: Una nueva esperanza (1977) fue rechazada por todos los estudios excepto Fox, y George Lucas cedió su salario de director a cambio de los derechos de merchandising — una decisión que lo convirtió en multimillonario.","Industrial Light & Magic, fundada por Lucas para los efectos especiales, revolucionó la industria y ganó más de 30 premios Oscar.","La saga Star Wars ha generado más de 70 000 millones de dólares en total, convirtiéndose en la franquicia de entretenimiento más valiosa de la historia."];

DEEP_DIVES['cin6'].es = ["Studio Ghibli, fundado por Miyazaki e Isao Takahata en 1985, ha producido algunas de las películas de animación más aclamadas de la historia.","El viaje de Chihiro (2001) es la única película de animación que ha ganado simultáneamente el Oscar y el Oso de Oro de Berlín.","Miyazaki rechaza la animación digital y dibuja cada fotograma a mano — una filosofía artesanal que convierte cada película en una hazaña de paciencia y dedicación."];

DEEP_DIVES['cin7'].es = ["Titanic (1997) de James Cameron fue la primera película en superar los 1 000 millones de dólares en taquilla y mantuvo el récord 12 años hasta Avatar (2009).","Cameron construyó una réplica del Titanic a tamaño casi real en un estudio de México — el presupuesto se disparó a 200 millones, el más alto de la época.","La escena de Jack y Rose en la proa del barco se convirtió en una de las imágenes más icónicas y parodiadas de la historia del cine."];

DEEP_DIVES['cin8'].es = ["El cine mudo no era realmente silencioso: las proyecciones se acompañaban de orquestas, pianistas o efectos sonoros en vivo.","Charlie Chaplin, Buster Keaton y Harold Lloyd fueron las primeras estrellas globales del cine — su comedia física trascendía las barreras lingüísticas.","La transición al cine sonoro (1927) acabó con la carrera de muchos actores del cine mudo cuyas voces no correspondían a su imagen — un drama retratado en Cantando bajo la lluvia."];

DEEP_DIVES['cin9'].es = ["La trilogía de El Señor de los Anillos de Peter Jackson se filmó íntegramente en Nueva Zelanda durante 438 días consecutivos — las tres películas se rodaron simultáneamente.","El retorno del Rey (2003) ganó los 11 premios Oscar a los que estaba nominado — un récord compartido solo con Ben-Hur y Titanic.","Las películas transformaron la economía neozelandesa: el turismo «hobbit» genera cientos de millones de dólares anuales y el país se promociona oficialmente como «la Tierra Media»."];

DEEP_DIVES['cin10'].es = ["Akira Kurosawa es considerado uno de los directores más influyentes de la historia — sus películas de samuráis inspiraron directamente Star Wars, Los Siete Magníficos y El Rey León.","Los siete samuráis (1954) estableció la estructura narrativa del «equipo de héroes reunidos para una misión» que sigue siendo la base de innumerables películas de acción.","George Lucas reconoció abiertamente que La fortaleza escondida (1958) de Kurosawa fue la inspiración directa de Star Wars — los droides C-3PO y R2-D2 están basados en dos campesinos de la película."];

DEEP_DIVES['cin11'].es = ["El MCU (Marvel Cinematic Universe) ha generado más de 30 000 millones de dólares en taquilla con más de 30 películas interconectadas desde Iron Man (2008).","Kevin Feige diseñó un modelo de narración transmedia sin precedentes: cada película funciona individualmente pero contribuye a una trama global que abarca años.","Avengers: Endgame (2019) se convirtió brevemente en la película más taquillera de la historia con 2 800 millones de dólares — superando el récord de Avatar."];

DEEP_DIVES['cin12'].es = ["La Nouvelle Vague francesa (años 1960) revolucionó el cine mundial: Godard, Truffaut, Rohmer y Varda rechazaron las convenciones del cine comercial para crear un lenguaje más libre y personal.","Jean-Luc Godard rompió todas las reglas narrativas: jump cuts, miradas a cámara, diálogos improvisados y mezcla de ficción y documental.","La Nouvelle Vague demostró que se podía hacer cine con poco dinero y mucha creatividad — influyó directamente en Scorsese, Coppola, Tarantino y todo el cine independiente moderno."];

DEEP_DIVES['cin13'].es = ["Los efectos especiales digitales nacieron con Tron (1982), pero fue Jurassic Park (1993) de Spielberg el que demostró que los CGI podían crear criaturas fotorrealistas.","Los dinosaurios de Jurassic Park combinaban animatrónicos de Stan Winston y CGI de ILM — la mezcla era tan convincente que cambió el cine para siempre.","Hoy, más del 90 % de los planos de una película de superhéroes contienen CGI — una dependencia que genera debates sobre la pérdida de artesanía en el cine."];

DEEP_DIVES['cin14'].es = ["Parasite (2019) de Bong Joon-ho fue la primera película en lengua no inglesa en ganar el Oscar a la Mejor Película, rompiendo una barrera de 92 años.","La película ganó cuatro premios Oscar (Película, Director, Guion Original, Película Internacional) — un logro sin precedentes para el cine asiático.","Bong Joon-ho declaró en su discurso: «Una vez que superas la barrera de los subtítulos, descubres muchas más películas increíbles» — una frase que se hizo viral."];

DEEP_DIVES['cin15'].es = ["Walt Disney creó el primer largometraje de animación de la historia occidental: Blancanieves y los siete enanitos (1937), que costó 1,5 millones de dólares de la época.","Los críticos de Hollywood lo llamaron «la locura de Disney» durante la producción — pero Blancanieves recaudó 8 millones y estableció Disney como imperio del entretenimiento.","Disney Studios ha producido más de 60 largometrajes de animación y genera más de 80 000 millones de dólares anuales entre cine, parques, merchandising y streaming."];

DEEP_DIVES['cin16'].es = ["El cine de terror japonés (J-Horror) influyó profundamente en Hollywood con películas como Ringu (1998) y Ju-On (2002), que fueron adaptadas como The Ring y The Grudge.","El J-Horror se distingue por su horror psicológico y atmosférico: fantasmas femeninos de pelo largo, tecnología maldita y amenazas invisibles que no se pueden combatir.","La cultura del miedo japonesa tiene raíces en los yūrei (fantasmas) y los yōkai (espíritus) del folclore, transmitidos durante siglos a través del teatro kabuki y los cuentos kaidan."];

DEEP_DIVES['cin17'].es = ["2001: Una odisea del espacio (1968) de Stanley Kubrick es considerada la película de ciencia ficción más influyente jamás filmada — y una de las más enigmáticas.","Kubrick colaboró con Arthur C. Clarke: la película y la novela se desarrollaron simultáneamente, cada una influyendo en la otra.","La secuencia del «Star Gate» y el final con el monolito siguen generando interpretaciones 55 años después — Kubrick se negó siempre a explicar su significado."];

DEEP_DIVES['cin18'].es = ["Pixar revolucionó la animación con Toy Story (1995), la primera película íntegramente creada por ordenador — un logro técnico que nadie creía posible.","Steve Jobs compró Pixar a Lucasfilm en 1986 por 10 millones de dólares — la vendió a Disney 20 años después por 7 400 millones.","El modelo narrativo de Pixar — historias emocionales universales para todas las edades — ha generado 15 películas que han recaudado más de 14 000 millones de dólares."];

DEEP_DIVES['cin19'].es = ["El cine neorrealista italiano (1940-50) filmaba en escenarios reales con actores no profesionales, retratando la pobreza y las dificultades de la posguerra.","Ladrón de bicicletas (1948) de Vittorio De Sica es su obra maestra: un padre desempleado busca desesperadamente su bicicleta robada por las calles de Roma.","El neorrealismo influyó en la Nouvelle Vague francesa, el Cinema Novo brasileño y prácticamente todo el cine independiente posterior — demostró que la realidad podía ser más dramática que la ficción."];

DEEP_DIVES['cin20'].es = ["Avatar (2009) de James Cameron fue la primera película en superar los 2 000 millones de dólares en taquilla y revolucionó el cine 3D y la captura de movimiento.","Cameron desarrolló una tecnología de captura de movimiento que permitía ver las escenas CGI en tiempo real durante el rodaje — una innovación que cambió la producción cinematográfica.","El mundo de Pandora fue inspirado por ecosistemas bioluminiscentes reales — la película generó un fenómeno llamado «depresión post-Avatar» entre espectadores que querían vivir en ese mundo."];

DEEP_DIVES['cin21'].es = ["El cine coreano experimentó una explosión internacional en los años 2000-2020 con directores como Bong Joon-ho, Park Chan-wook y Lee Chang-dong.","Old Boy (2003) de Park Chan-wook ganó el Gran Premio en Cannes y demostró que el cine coreano podía combinar violencia estilizada con profundidad emocional y filosófica.","El éxito de Parasite y la serie El Juego del Calamar consolidaron la «ola coreana» (hallyu) como fuerza cultural global, junto con el K-pop y los K-dramas."];

DEEP_DIVES['cin22'].es = ["El Padrino (1972) de Francis Ford Coppola es considerada una de las mejores películas jamás filmadas — Paramount quería despedir a Coppola durante el rodaje.","Marlon Brando se metió algodón en las mejillas para darle a Don Corleone su característica mandíbula — una decisión que definió al personaje más icónico de la historia del cine de gángsters.","La trilogía generó más de 900 millones de dólares y estableció el modelo del drama criminal épico que sigue imitándose medio siglo después."];

DEEP_DIVES['cin23'].es = ["Los Oscar se entregan desde 1929, cuando la primera ceremonia duró apenas 15 minutos y los ganadores eran conocidos de antemano.","La estatuilla de oro mide 34 cm, pesa 3,9 kg y está hecha de bronce recubierto de oro de 24 quilates — su valor material es de unos 1 000 dólares.","Solo tres películas han ganado los «Big Five» (Película, Director, Actor, Actriz, Guion): Sucedió una noche (1934), Alguien voló sobre el nido del cuco (1975) y El silencio de los corderos (1991)."];

DEEP_DIVES['cin24'].es = ["La animación japonesa (anime) es una industria de más de 25 000 millones de dólares que abarca todos los géneros y edades, no solo infantil.","Akira (1988) fue la película que introdujo el anime al público occidental con su animación revolucionaria, su violencia y su complejidad narrativa.","Netflix, Crunchyroll y otros servicios de streaming han globalizado el anime: series como Demon Slayer, Jujutsu Kaisen y Attack on Titan rivalizan con las producciones occidentales en audiencia."];

DEEP_DIVES['cin25'].es = ["Quentin Tarantino empezó como dependiente de un videoclub — su enciclopédico conocimiento del cine alimenta sus guiones, plagados de referencias y homenajes.","Pulp Fiction (1994) revitalizó la carrera de John Travolta, popularizó la narrativa no lineal y redefinió el diálogo cinematográfico como arte en sí mismo.","Tarantino ha declarado que se retirará tras su décima película — la novena, Érase una vez en Hollywood (2019), fue un homenaje nostálgico al Los Ángeles de 1969."];

DEEP_DIVES['cin26'].es = ["Los documentales han evolucionado de formato educativo a género artístico y comercial: películas como Fahrenheit 9/11 y Free Solo han recaudado más de 100 millones.","El documental participativo, donde el cineasta se involucra en la historia (Michael Moore, Werner Herzog), ha difuminado las fronteras entre objetividad y subjetividad.","Las plataformas de streaming han revitalizado el documental: series como Making a Murderer, Tiger King y The Last Dance han alcanzado audiencias masivas."];

DEEP_DIVES['cin27'].es = ["El cine de Wes Anderson se distingue por su simetría visual, paletas de colores pastel, planos cenitales y un humor seco e idiosincrásico.","El Gran Hotel Budapest (2014) es su película más exitosa — su estética de «casa de muñecas» ha influido en la fotografía, la moda y el diseño gráfico contemporáneos.","Anderson es uno de los pocos directores cuyo estilo visual es inmediatamente reconocible — una marca artística tan potente que «wesandersoniano» se ha convertido en adjetivo."];

DEEP_DIVES['cin28'].es = ["El cine africano, liderado por Ousmane Sembène (Senegal) y Djibril Diop Mambéty, ha luchado durante décadas contra la falta de financiación y distribución.","Nollywood (Nigeria) ha resuelto el problema con un modelo de bajo coste y alta producción: más de 2 500 películas al año, distribuidas en DVD y streaming.","El Festival de Cine de Cannes ha otorgado la Palma de Oro a películas africanas y árabes, reconociendo voces que durante mucho tiempo fueron ignoradas por la industria occidental."];

DEEP_DIVES['cin29'].es = ["Christopher Nolan es conocido por películas que desafían la percepción del tiempo: Memento (hacia atrás), Inception (sueños dentro de sueños), Tenet (inversión temporal) e Interstellar (dilatación temporal).","Nolan prefiere los efectos prácticos a los digitales: para Interstellar hizo crecer campos de maíz reales, y para Tenet grabó la explosión de un avión real.","Oppenheimer (2023) le valió su primer Oscar a Mejor Director y recaudó más de 950 millones — demostrando que el cine de autor puede ser también un éxito masivo."];

DEEP_DIVES['cin30'].es = ["El streaming ha transformado la distribución cinematográfica: Netflix, Disney+, Amazon Prime y Apple TV+ producen más contenido original que todos los estudios de Hollywood juntos.","En 2023, el streaming superó por primera vez a la taquilla como principal fuente de ingresos de la industria cinematográfica.","El debate «cine vs streaming» divide a los cineastas: Spielberg y Nolan defienden la experiencia de la sala oscura, mientras que otros celebran la democratización del acceso al cine."];

// ── MUSIC mus1-mus30 ──

DEEP_DIVES['mus1'].es = ["La flauta de Hohle Fels, tallada en hueso de buitre hace 43 000 años, es el instrumento musical más antiguo conocido — demuestra que la música precede a la civilización.","La flauta tiene cinco agujeros y produce una escala pentatónica — los mismos intervalos usados hoy en el blues, el rock y la música tradicional de todo el mundo.","La existencia de instrumentos tan antiguos sugiere que la música no es un lujo cultural sino una necesidad biológica profunda, ligada a la cohesión social y la supervivencia del grupo."];

DEEP_DIVES['mus2'].es = ["Beethoven compuso su Novena Sinfonía (1824) estando completamente sordo — nunca pudo escuchar la obra más aclamada de su vida.","En el estreno, el público aplaudió de pie durante varios minutos, pero Beethoven, de espaldas, no lo supo hasta que una cantante lo giró para que viera la ovación.","El Himno a la Alegría del cuarto movimiento fue adoptado como himno de la Unión Europea en 1985 — un símbolo de unidad que trasciende naciones y culturas."];

DEEP_DIVES['mus3'].es = ["El blues nació en el Delta del Misisipi a finales del siglo XIX, como expresión musical del sufrimiento de los afroamericanos tras la esclavitud.","La estructura del blues (12 compases, acordes I-IV-V, blue notes) es la base del rock and roll, el jazz, el R&B, el funk y el hip-hop — prácticamente toda la música popular moderna.","Robert Johnson, leyenda del blues, supuestamente vendió su alma al diablo en un cruce de caminos a cambio de su talento — murió a los 27 años, inaugurando el «Club de los 27»."];

DEEP_DIVES['mus4'].es = ["Los Beatles son el grupo más exitoso de la historia con más de 600 millones de discos vendidos — transformaron la música, la moda, la cultura y la política de los años 60.","Lennon y McCartney escribieron más de 180 canciones juntos, aunque muchas fueron compuestas individualmente — el crédito conjunto fue un pacto acordado al inicio del grupo.","La separación de los Beatles en 1970 fue un trauma cultural global: fans lloraron en la calle y las teorías sobre las causas de la ruptura siguen siendo debatidas hoy."];

DEEP_DIVES['mus5'].es = ["El hip-hop nació en el Bronx de Nueva York en los años 1970, cuando DJ Kool Herc empezó a aislar los breakbeats de los discos de funk para que los B-boys bailaran.","Los cuatro elementos del hip-hop son: DJing, MCing (rap), breakdance y graffiti — una cultura completa nacida de las comunidades afroamericanas y latinas marginalizadas.","Hoy el hip-hop es el género musical más escuchado del mundo en streaming, y su influencia se extiende a la moda, el lenguaje, el cine y la política."];

DEEP_DIVES['mus6'].es = ["Mozart compuso más de 600 obras antes de morir a los 35 años — un promedio de una obra nueva cada tres semanas durante toda su vida adulta.","A los 5 años ya componía, a los 8 escribió su primera sinfonía y a los 12 su primera ópera — su genio precoz no tiene equivalente en la historia de la música.","La causa de su muerte sigue siendo un misterio: más de 100 diagnósticos diferentes han sido propuestos, desde envenenamiento hasta fiebre reumática y triquinosis."];

DEEP_DIVES['mus7'].es = ["El reggae nació en Jamaica a finales de los años 1960 como evolución del ska y el rocksteady, impregnado de la espiritualidad rastafari.","Bob Marley convirtió el reggae en un movimiento global: sus canciones de libertad, justicia y amor lo transformaron en el artista más influyente del Tercer Mundo.","La canción One Love de Marley fue declarada «canción del milenio» por la BBC — su mensaje de unidad sigue resonando décadas después de su muerte en 1981."];

DEEP_DIVES['mus8'].es = ["La música electrónica nació en los años 1950 con compositores como Stockhausen y Pierre Schaeffer, que manipulaban sonidos grabados y sintetizadores experimentales.","El sintetizador Moog (1964) democratizó la electrónica: Wendy Carlos popularizó el instrumento con su álbum Switched-On Bach (1968).","El techno nació en Detroit en los años 1980, la house en Chicago y el drum and bass en Londres — tres ciudades postindustriales que canalizaron su energía en la pista de baile."];

DEEP_DIVES['mus9'].es = ["El K-pop se ha convertido en un fenómeno global liderado por BTS, BLACKPINK y Stray Kids — la industria genera más de 10 000 millones de dólares anuales.","Los idols del K-pop pasan por años de entrenamiento intensivo (canto, baile, idiomas, actuación) antes de debutar — un sistema que ha sido comparado con academias militares del entretenimiento.","BTS fue el primer grupo de K-pop en llenar estadios en todo el mundo y en hablar ante la Asamblea General de la ONU — un soft power cultural sin precedentes para Corea del Sur."];

DEEP_DIVES['mus10'].es = ["El vinilo de 33 RPM fue introducido por Columbia Records en 1948, permitiendo grabar hasta 25 minutos por cara — una revolución que hizo posible el concepto de álbum.","El formato LP (Long Play) permitió a los artistas crear obras cohesivas de 40-50 minutos en lugar de singles sueltos — nació el álbum como forma artística.","A pesar de la era digital, las ventas de vinilos han crecido cada año desde 2006: en 2023 se vendieron más de 40 millones de discos de vinilo en EE.UU."];

DEEP_DIVES['mus11'].es = ["El flamenco combina cante (voz), toque (guitarra) y baile en una expresión artística nacida en Andalucía entre las comunidades gitanas, moriscas y judías.","El compás (ritmo) del flamenco puede ser extremadamente complejo: la bulería tiene un ciclo de 12 tiempos con acentos irregulares que desafían la notación occidental.","El duende, esa emoción intensa que trasciende la técnica, es el santo grial del flamenco — Lorca lo describió como un poder que se siente pero no se puede explicar."];

DEEP_DIVES['mus12'].es = ["Spotify, lanzado en 2008, transformó la industria musical: pasó de vender álbumes a vender acceso, pagando a los artistas fracciones de céntimo por reproducción.","Con más de 600 millones de usuarios, Spotify ha democratizado el acceso a la música pero ha reducido drásticamente los ingresos de los artistas independientes.","Los algoritmos de recomendación de Spotify (Discover Weekly, Release Radar) han creado un nuevo intermediario entre artistas y oyentes — la curación humana ha cedido terreno a la IA."];

DEEP_DIVES['mus13'].es = ["Freddie Mercury tenía un rango vocal de cuatro octavas y una técnica que los científicos han comparado con la de los cantantes de ópera — algo inusual en el rock.","Bohemian Rhapsody (1975) fue rechazada por la discográfica por ser demasiado larga y experimental — se convirtió en una de las canciones más icónicas de la historia.","El concierto de Queen en Live Aid (1985) ante 72 000 personas en Wembley es considerado la mejor actuación en directo de la historia del rock."];

DEEP_DIVES['mus14'].es = ["La guitarra eléctrica fue desarrollada en los años 1930 para que los guitarristas de jazz pudieran ser escuchados sobre las secciones de viento.","La Fender Telecaster (1950) y la Gibson Les Paul (1952) establecieron los dos arquetipos de guitarra eléctrica que dominan el rock desde hace más de 70 años.","Jimi Hendrix reinventó la guitarra eléctrica con feedback, distorsión y wah-wah — su interpretación del himno estadounidense en Woodstock (1969) es uno de los momentos más icónicos del siglo XX."];

DEEP_DIVES['mus15'].es = ["El piano fue inventado por Bartolomeo Cristofori en Florencia hacia 1700 — su nombre original era «gravicembalo col piano e forte» (clave con suave y fuerte).","El piano es el instrumento más versátil: puede tocar melodía, armonía y ritmo simultáneamente, lo que lo convierte en el instrumento por excelencia para la composición.","Un piano de cola de concierto Steinway cuesta más de 150 000 euros y contiene más de 12 000 piezas — cada instrumento se fabrica artesanalmente durante más de un año."];

DEEP_DIVES['mus16'].es = ["Michael Jackson vendió más de 400 millones de discos, con Thriller (1982) como el álbum más vendido de la historia: más de 70 millones de copias.","El moonwalk, presentado durante la interpretación de Billie Jean en 1983, se convirtió en el paso de baile más imitado del mundo.","Jackson transformó el videoclip en forma artística con Thriller (1983), un cortometraje de 14 minutos dirigido por John Landis que revolucionó MTV y la industria musical."];

DEEP_DIVES['mus17'].es = ["El jazz nació en Nueva Orleans a principios del siglo XX, fusionando tradiciones musicales africanas, blues, ragtime y música de desfile.","La improvisación es su esencia: los músicos crean melodías espontáneas sobre progresiones armónicas compartidas, convirtiendo cada actuación en irrepetible.","Miles Davis reinventó el jazz al menos cinco veces en su carrera: bebop, cool jazz, hard bop, jazz modal (Kind of Blue) y fusión (Bitches Brew)."];

DEEP_DIVES['mus18'].es = ["La ópera nació en Florencia a finales del siglo XVI como intento de recrear el drama musical de la Grecia antigua.","Las voces de ópera se clasifican en seis rangos: soprano, mezzosoprano, contralto (mujeres) y tenor, barítono, bajo (hombres) — cada rol exige una técnica vocal específica.","Luciano Pavarotti popularizó la ópera en los años 1990 con Los Tres Tenores y el uso de sus arias en la publicidad — la ópera dejó de ser un arte exclusivamente elitista."];

DEEP_DIVES['mus19'].es = ["La música country nació en los Apalaches del sur de EE.UU. como fusión de folk irlandés y escocés, blues afroamericano y gospel.","Nashville, Tennessee, se convirtió en la capital del country gracias al programa de radio Grand Ole Opry (desde 1925) — la emisión de radio más longeva de la historia de EE.UU.","Johnny Cash, el «hombre de negro», fue un rebelde que trascendió el country: tocó en prisiones, luchó contra la adicción y colaboró con artistas de rock y punk."];

DEEP_DIVES['mus20'].es = ["La samba es el género musical emblemático de Brasil, nacido en las comunidades afrobrasileñas de Río de Janeiro a principios del siglo XX.","El Carnaval de Río, con sus escuelas de samba (cada una con hasta 4 000 participantes), es el mayor espectáculo musical del mundo.","La bossa nova, fusión de samba y jazz creada por João Gilberto y Tom Jobim en los años 1950, se convirtió en uno de los géneros brasileños más influyentes a nivel internacional."];

DEEP_DIVES['mus21'].es = ["David Bowie se reinventó constantemente durante cinco décadas: Ziggy Stardust, Aladdin Sane, el Thin White Duke — cada álbum era un nuevo personaje y un nuevo género.","Su álbum Blackstar, publicado dos días antes de su muerte en 2016, fue un adiós artístico deliberado: sus letras y su estética reflejaban la aceptación de la mortalidad.","Bowie influenció no solo la música sino la moda, el arte, el cine y las actitudes hacia la identidad de género — fue uno de los primeros artistas en desafiar abiertamente las normas binarias."];

DEEP_DIVES['mus22'].es = ["El tango nació en los barrios portuarios de Buenos Aires y Montevideo a finales del siglo XIX, fusionando ritmos africanos, milonga criolla y habanera cubana.","Inicialmente considerado música de los bajos fondos, el tango fue rechazado por la alta sociedad hasta que triunfó en París — solo entonces Buenos Aires lo adoptó como símbolo nacional.","Carlos Gardel, el «zorzal criollo», popularizó el tango a nivel mundial en los años 1920-30 — su muerte en un accidente aéreo en 1935 lo convirtió en leyenda eterna."];

DEEP_DIVES['mus23'].es = ["El punk nació en 1976 con los Ramones en Nueva York y los Sex Pistols en Londres — una reacción visceral contra el rock progresivo pretencioso y la conformidad social.","Los Sex Pistols duraron apenas 2 años y medio y grabaron un solo álbum (Never Mind the Bollocks), pero cambiaron la cultura musical, la moda y la actitud de toda una generación.","El punk demostró que cualquiera podía hacer música sin formación técnica: el DIY (hazlo tú mismo) se convirtió en filosofía vital y estética."];

DEEP_DIVES['mus24'].es = ["Taylor Swift es la artista que más rápido ha generado 1 000 millones de dólares con una sola gira (The Eras Tour, 2023-2024) — la gira más lucrativa de la historia.","Swift regrabó sus primeros álbumes (versiones «Taylor's Version») para recuperar la propiedad de su música — un precedente que empoderó a artistas de toda la industria.","Su influencia trasciende la música: el «efecto Taylor Swift» impacta en las economías locales de las ciudades donde actúa y en la participación electoral de los jóvenes."];

DEEP_DIVES['mus25'].es = ["Bach compuso más de 1 100 obras, incluyendo cantatas, fugas, conciertos y partitas — una producción monumental que abarca todos los géneros de su época.","Olvidado durante casi un siglo tras su muerte en 1750, Bach fue redescubierto por Mendelssohn en 1829 — hoy es considerado uno de los compositores más importantes de la historia.","La música de Bach tiene una estructura matemática tan perfecta que ha sido enviada al espacio en la sonda Voyager como representación de la inteligencia humana."];

DEEP_DIVES['mus26'].es = ["El reggaetón nació en Puerto Rico en los años 1990 como fusión de reggae jamaicano, hip-hop latino y dembow — un ritmo que se hizo global en los 2000.","Daddy Yankee popularizó el género con Gasolina (2004), pero fue Despacito de Luis Fonsi y Daddy Yankee (2017) la que lo convirtió en fenómeno mundial con más de 8 000 millones de vistas.","El reggaetón ha transformado la industria musical global: el español es ahora la segunda lengua del pop mundial, con Bad Bunny como el artista más escuchado del planeta en Spotify."];

DEEP_DIVES['mus27'].es = ["Woodstock (1969) reunió a más de 400 000 personas durante tres días en una granja de Nueva York — se convirtió en el símbolo de la contracultura de los años 60.","Jimi Hendrix, Janis Joplin, The Who, Santana y Sly & the Family Stone actuaron ante un público que transformó un festival caótico en un momento de paz y comunidad.","Woodstock fue un desastre logístico: las carreteras colapsaron, la comida y el agua escasearon, y la lluvia convirtió los campos en barrizales — pero la música y el espíritu colectivo lo redimieron todo."];

DEEP_DIVES['mus28'].es = ["Adele vendió más de 120 millones de discos con una fórmula aparentemente simple: una voz extraordinaria, letras emocionales sobre el desamor y arreglos minimalistas.","Su álbum 21 (2011) es uno de los más vendidos del siglo XXI con más de 31 millones de copias — dominó las listas durante meses en decenas de países.","Adele es una de las pocas artistas que pueden vender millones de álbumes físicos en la era del streaming — una anomalía que demuestra el poder de la conexión emocional."];

DEEP_DIVES['mus29'].es = ["La cumbia nació en Colombia como fusión de ritmos africanos, indígenas y europeos, y se ha expandido por toda Latinoamérica con variantes locales en cada país.","La cumbia argentina, la cumbia villera, la cumbia sonidera mexicana y la chicha peruana son adaptaciones regionales que reflejan las realidades sociales de cada contexto.","La cumbia digital, fusionada con electrónica, ha encontrado un público global en el siglo XXI — festivales de todo el mundo programan artistas de cumbia junto a DJs de techno y house."];

DEEP_DIVES['mus30'].es = ["La inteligencia artificial puede ahora componer música en cualquier estilo: herramientas como Suno, Udio y MusicLM generan canciones completas a partir de una descripción textual.","El debate sobre la IA en la música es intenso: ¿es creación o plagio algorítmico? ¿Puede una máquina expresar emociones que no siente?","Algunos artistas usan la IA como herramienta creativa (Brian Eno, Holly Herndon) mientras que otros la rechazan — la industria musical enfrenta su mayor transformación desde la invención del fonógrafo."];

// ── MYTHOLOGY myth1-myth30 ──

DEEP_DIVES['myth1'].es = ["Zeus, rey de los dioses del Olimpo, era un mujeriego compulsivo que se transformaba en cisne, toro, lluvia de oro y hasta hormiga para seducir a mortales y diosas.","Sus numerosas aventuras amorosas engendraron héroes (Heracles, Perseo, Helena) y provocaron la ira de su esposa Hera, cuya venganza caía siempre sobre las amantes, no sobre Zeus.","El rayo de Zeus no era solo un arma sino un símbolo de justicia divina — los griegos consideraban que los lugares alcanzados por un rayo eran sagrados."];

DEEP_DIVES['myth2'].es = ["El Valhalla nórdico era el paraíso de los guerreros caídos en combate, donde festejaban y luchaban eternamente hasta el Ragnarök, la batalla del fin del mundo.","Las valkirias, guerreras divinas, elegían a los más valientes entre los muertos en batalla para llevarlos al Valhalla — un destino más honorable que el frío y gris Hel.","El Ragnarök no es solo destrucción: tras la batalla final donde mueren la mayoría de los dioses, el mundo renace purificado — un ciclo de muerte y renovación."];

DEEP_DIVES['myth3'].es = ["El Minotauro, mitad hombre mitad toro, habitaba el laberinto de Creta diseñado por Dédalo — cada año devoraba siete jóvenes y siete doncellas atenienses.","Teseo mató al Minotauro con ayuda del hilo de Ariadna, que le permitió encontrar la salida del laberinto — luego abandonó a Ariadna en la isla de Naxos.","El mito puede reflejar un hecho histórico: la dominación cretense sobre Atenas, que exigía tributos humanos, y la posterior liberación ateniense."];

DEEP_DIVES['myth4'].es = ["Quetzalcóatl, la serpiente emplumada, era uno de los dioses principales del panteón azteca y mesoamericano — asociado al viento, la sabiduría y la estrella de la mañana.","La leyenda de su regreso por el este fue supuestamente aprovechada por Hernán Cortés para presentarse como el dios que volvía — aunque esta versión es discutida por los historiadores modernos.","Quetzalcóatl aparece en las culturas olmeca, teotihuacana, tolteca y azteca con diferentes nombres pero funciones similares — un dios panmesoamericano que perduró más de 2 000 años."];

DEEP_DIVES['myth5'].es = ["Odiseo (Ulises) tardó 10 años en regresar a Ítaca tras la Guerra de Troya, enfrentando cíclopes, sirenas, la hechicera Circe y la ira de Poseidón.","La Odisea de Homero (siglo VIII a.C.) es el primer relato de aventuras de la literatura occidental y el modelo de toda narrativa de viaje y retorno.","La astucia de Odiseo — su «inteligencia práctica» (metis) — lo distingue de los héroes musculosos: es el prototipo del héroe que triunfa con su ingenio."];

DEEP_DIVES['myth6'].es = ["Anubis, el dios egipcio con cabeza de chacal, presidía el embalsamamiento y guiaba a los muertos al inframundo para el juicio de Osiris.","En el pesaje del corazón, Anubis colocaba el corazón del difunto en un platillo de la balanza y la pluma de Maat (verdad) en el otro — si el corazón era más pesado, el monstruo Ammit lo devoraba.","Los antiguos egipcios momificaban a los muertos para preservar el cuerpo como receptáculo del ka (fuerza vital) — el proceso duraba 70 días e incluía la extracción del cerebro por la nariz."];

DEEP_DIVES['myth7'].es = ["El Rey Arturo, Excalibur, la Tabla Redonda y la búsqueda del Santo Grial son los mitos fundacionales de la literatura caballeresca europea.","No existe evidencia histórica de un rey Arturo real, aunque podría estar basado en un líder britano del siglo V o VI que luchó contra las invasiones sajonas.","Las historias artúricas evolucionaron durante siglos: Chrétien de Troyes añadió a Lancelot y el Grial, Mallory compiló Le Morte d'Arthur (1485) y T.H. White las reinventó en el siglo XX."];

DEEP_DIVES['myth8'].es = ["Prometeo robó el fuego a los dioses para dárselo a los humanos — Zeus lo castigó encadenándolo a una roca donde un águila le devoraba el hígado cada día, que se regeneraba cada noche.","El mito de Prometeo es una metáfora del conocimiento y la tecnología: un regalo que empodera pero que conlleva consecuencias imprevistas.","Mary Shelley tituló su novela Frankenstein; o el moderno Prometeo — una comparación entre el titán que desafió a los dioses y el científico que desafía la naturaleza."];

DEEP_DIVES['myth9'].es = ["Los dragones aparecen en las mitologías de todo el mundo: serpientes voladoras en China, dragones que escupen fuego en Europa, serpientes emplumadas en Mesoamérica.","En Oriente, los dragones son criaturas benéficas asociadas al agua, la lluvia y la prosperidad — en Occidente son bestias malvadas que acumulan tesoros y devoran doncellas.","Algunos paleontólogos sugieren que los mitos de dragones se inspiraron en fósiles de dinosaurios y grandes reptiles que las civilizaciones antiguas encontraban sin poder explicar."];

DEEP_DIVES['myth10'].es = ["Atenea, diosa de la sabiduría y la guerra estratégica, nació adulta y armada de la cabeza de Zeus tras un terrible dolor de cabeza.","A diferencia de Ares (dios de la guerra brutal), Atenea representaba la guerra inteligente: estrategia, planificación y victoria mediante el ingenio.","La ciudad de Atenas lleva su nombre tras un concurso con Poseidón: ella ofreció el olivo (alimento, aceite, madera) mientras él ofreció una fuente de agua salada — los atenienses eligieron el olivo."];

DEEP_DIVES['myth11'].es = ["Thor, el dios nórdico del trueno, no era el rubio musculoso de Marvel: las fuentes vikingas lo describen pelirrojo, con barba espesa y un apetito insaciable.","Su martillo Mjölnir fue forjado por los enanos Sindri y Brokkr — el mango era demasiado corto debido a una apuesta de Loki con los enanos, que resultó en su distracción.","Thor era el dios más popular entre los vikingos comunes: protector de los humanos contra los gigantes, patrón de los campesinos y los marineros."];

DEEP_DIVES['myth12'].es = ["Isis, diosa egipcia de la magia y la maternidad, reconstruyó el cuerpo desmembrado de su esposo Osiris (cortado en 14 pedazos por su hermano Seth) y lo resucitó brevemente para concebir a Horus.","El culto a Isis se extendió por todo el Mediterráneo romano y perduró hasta el siglo VI — algunos historiadores ven paralelos entre Isis con Horus y la Virgen María con Jesús.","Isis representaba el poder femenino en su forma más completa: esposa devota, madre protectora y maga suprema — un arquetipo que trasciende la mitología egipcia."];

DEEP_DIVES['myth13'].es = ["La caja de Pandora no era originalmente una caja sino un pithos (gran vasija de almacenamiento) — la confusión viene de una traducción errónea de Erasmo en el siglo XVI.","Según Hesíodo, Zeus envió a Pandora como castigo por el robo del fuego de Prometeo — al abrir la vasija, liberó todos los males del mundo, pero dejó la esperanza dentro.","El mito plantea una pregunta filosófica: ¿la esperanza fue retenida como consuelo para la humanidad o como el peor de los males, que prolonga el sufrimiento?"];

DEEP_DIVES['myth14'].es = ["Ganesh, el dios hindú con cabeza de elefante, es el patrón de los inicios, la sabiduría y la eliminación de obstáculos — toda oración hindú comienza invocándolo.","Según la leyenda, Shiva le cortó la cabeza a Ganesh sin saber que era su hijo, y la reemplazó con la del primer animal que encontró: un elefante.","Ganesh es una de las deidades más veneradas del mundo: su festividad (Ganesh Chaturthi) reúne a millones de devotos en India y en la diáspora hindú."];

DEEP_DIVES['myth15'].es = ["Las sirenas de la mitología griega no eran mujeres con cola de pez sino mujeres-pájaro cuyo canto irresistible atraía a los marineros hacia las rocas.","La representación como mujeres-pez surgió en la Edad Media, probablemente por confusión con los tritones y las melusinas del folclore europeo.","Odiseo es el único mortal que escuchó el canto de las sirenas y sobrevivió: se hizo atar al mástil de su barco mientras sus marineros se tapaban los oídos con cera."];

DEEP_DIVES['myth16'].es = ["Amaterasu, diosa del sol en la mitología japonesa, se encerró en una cueva tras una disputa con su hermano Susanoo, sumiendo el mundo en la oscuridad.","Los demás dioses la atrajeron fuera con una danza y un espejo de bronce — ese espejo es uno de los tres tesoros sagrados del emperador de Japón.","La familia imperial japonesa afirma descender directamente de Amaterasu — una genealogía divina que otorga al emperador un estatus sagrado único entre las monarquías modernas."];

DEEP_DIVES['myth17'].es = ["El Arca de Noé tiene paralelos en mitologías de todo el mundo: el Utnapishtim sumerio, el Manu hindú, el Deucalión griego y el Nüwa chino sobrevivieron a diluvios similares.","Los geólogos creen que estas leyendas podrían basarse en inundaciones reales, como el desbordamiento del Mar Negro hace 7 600 años, que sumergió vastas regiones habitadas.","Las dimensiones del Arca descritas en el Génesis (137 × 23 × 14 metros) coinciden sorprendentemente con las proporciones óptimas para la estabilidad de un barco según la ingeniería naval moderna."];

DEEP_DIVES['myth18'].es = ["Heracles (Hércules) realizó los Doce Trabajos como penitencia por haber matado a su familia en un acceso de locura provocado por Hera.","Los trabajos incluyen hazañas imposibles: matar al león de Nemea (cuya piel era invulnerable), limpiar los establos de Augías y robar las manzanas de oro de las Hespérides.","Heracles es el héroe semidivino por excelencia: hijo de Zeus y una mortal, sus aventuras simbolizan la lucha humana por superar lo imposible y alcanzar la inmortalidad."];

DEEP_DIVES['myth19'].es = ["Loki, el dios embaucador nórdico, no era un dios sino un jötun (gigante) adoptado por los Æsir — su naturaleza ambigua lo convierte en el personaje más complejo del panteón nórdico.","Loki engendró criaturas monstruosas: el lobo Fenrir, la serpiente Jörmungandr y Hel, gobernante del inframundo — también dio a luz al caballo de ocho patas Sleipnir tras transformarse en yegua.","En el Ragnarök, Loki lidera el ejército de los muertos contra los dioses — su traición final sella el destino del mundo nórdico."];

DEEP_DIVES['myth20'].es = ["El Popol Vuh, libro sagrado de los mayas quichés, narra la creación del mundo y de la humanidad: los dioses fracasaron con el barro y la madera antes de crear al hombre de maíz.","Los Héroes Gemelos Hunahpú e Ixbalanqué descendieron a Xibalbá (el inframundo maya) y vencieron a los señores de la muerte mediante astucia y juego de pelota.","El Popol Vuh fue transcrito en caracteres latinos por un maya quiché en el siglo XVI — sin esa transcripción, gran parte de la mitología maya se habría perdido."];

DEEP_DIVES['myth21'].es = ["Medusa, una de las tres Gorgonas, tenía serpientes por cabellos y convertía en piedra a quien la mirara — fue decapitada por Perseo con ayuda de Atenea.","En versiones más antiguas, Medusa era un monstruo de nacimiento, pero Ovidio la convirtió en una bella sacerdotisa castigada por Atenea tras ser violada por Poseidón en su templo.","La cabeza de Medusa, incluso decapitada, conservaba su poder petrificante — Perseo la usó como arma y después la entregó a Atenea, que la montó en su escudo (la égida)."];

DEEP_DIVES['myth22'].es = ["Los kami japoneses no son exactamente dioses sino espíritus o fuerzas divinas que habitan en la naturaleza: rocas, árboles, ríos, montañas y fenómenos naturales.","El sintoísmo reconoce yaoyorozu no kami (ocho millones de kami), una expresión que significa literalmente «una infinidad» de espíritus sagrados.","Los torii, las puertas rojas de los santuarios sintoístas, marcan la transición entre el mundo profano y el sagrado — el más famoso es el de Itsukushima, que parece flotar sobre el mar."];

DEEP_DIVES['myth23'].es = ["Anansi, la araña embaucadora de la mitología ashanti (Ghana), es uno de los personajes más importantes del folclore africano y caribeño.","Anansi usa su astucia para vencer a enemigos más fuertes: engaña al leopardo, la serpiente pitón y al avispero, demostrando que la inteligencia supera a la fuerza bruta.","Los esclavos africanos llevaron las historias de Anansi al Caribe y América, donde evolucionaron en los cuentos de Brer Rabbit y otras tradiciones orales afroamericanas."];

DEEP_DIVES['myth24'].es = ["El Mahabharata, la epopeya hindú más larga del mundo (100 000 estrofas), narra la guerra entre dos familias primas: los Pandavas y los Kauravas.","El Bhagavad Gita, insertado en el Mahabharata, es un diálogo filosófico entre el príncipe Arjuna y el dios Krishna sobre el deber, la acción y la naturaleza del ser.","El Mahabharata contiene toda la sabiduría de la India antigua: derecho, filosofía, mitología, astronomía y ética — se dice que «lo que no está en el Mahabharata no existe»."];

DEEP_DIVES['myth25'].es = ["El hombre lobo (licántropo) aparece en mitologías de todo el mundo: el rey Licaón fue transformado en lobo por Zeus, y las sagas nórdicas mencionan guerreros úlfhednar que combatían vestidos de pieles de lobo.","En la Europa medieval, los juicios por licantropía eran reales: más de 30 000 casos documentados entre los siglos XV y XVIII — muchos acusados sufrían probablemente porfiria o hipertricosis.","La asociación del hombre lobo con la luna llena es una invención cinematográfica del siglo XX — las fuentes antiguas no mencionan esta conexión."];

DEEP_DIVES['myth26'].es = ["Afrodita, diosa griega del amor y la belleza, nació de la espuma del mar (aphros) formada cuando los genitales de Urano, cortados por Crono, cayeron al agua.","Su cinturón mágico (cestus) hacía irresistible a quien lo portara — incluso Hera se lo pidió prestado para seducir a Zeus.","Afrodita estaba casada con Hefesto, el dios herrero y más feo del Olimpo, pero mantuvo numerosos amantes, incluido Ares, el dios de la guerra — una unión del amor y la violencia."];

DEEP_DIVES['myth27'].es = ["Coyote es el embaucador (trickster) de las mitologías de los pueblos nativos de América del Norte — creador, destructor y bufón en partes iguales.","En algunas tradiciones, Coyote roba el fuego para la humanidad (como Prometeo); en otras, crea accidentalmente la muerte al intentar hacer inmortales a los humanos.","El trickster no es bueno ni malo: representa el caos creativo necesario para que el mundo evolucione — una figura universal presente en casi todas las culturas."];

DEEP_DIVES['myth28'].es = ["Las Moiras griegas (Parcas romanas) eran tres hermanas que controlaban el destino de todos los mortales: Cloto hilaba el hilo de la vida, Láquesis medía su longitud y Átropos lo cortaba.","Ni siquiera Zeus podía alterar las decisiones de las Moiras — el destino era la fuerza suprema del universo griego, superior a los propios dioses.","La idea de tres diosas del destino es sorprendentemente universal: las Nornas nórdicas (Urd, Verdandi, Skuld) cumplen funciones casi idénticas en la mitología germánica."];

DEEP_DIVES['myth29'].es = ["El Golem de Praga, según la leyenda, fue creado en el siglo XVI por el rabino Löw a partir de arcilla del río Moldava para proteger a los judíos de la persecución.","El Golem cobraba vida al inscribir la palabra emet (verdad) en su frente — para desactivarlo, bastaba borrar una letra, dejando met (muerte).","La leyenda del Golem es considerada precursora de los relatos de inteligencia artificial: una creación que sirve a su creador hasta que escapa a su control."];

DEEP_DIVES['myth30'].es = ["Los mitos de creación del mundo varían enormemente: desde un huevo cósmico (China, Finlandia) hasta un océano primordial (Egipto, India) o un vacío primigenio (nórdico, griego).","El Enuma Elish babilónico narra cómo Marduk crea el mundo a partir del cuerpo de la diosa Tiamat — un combate cósmico que refleja la lucha del orden contra el caos.","Todas las culturas necesitan un relato de origen: los mitos de creación no son explicaciones científicas sino respuestas existenciales a las preguntas «¿de dónde venimos?» y «¿por qué existimos?»."];

// ── PSYCHOLOGY psy1-psy30 ──

DEEP_DIVES['psy1'].es = ["El efecto Dunning-Kruger describe cómo las personas con menos competencia en un tema tienden a sobreestimar sus habilidades, mientras que los expertos tienden a subestimarlas.","Este sesgo no es simple arrogancia: la incompetencia impide reconocer la propia incompetencia — se necesita cierto nivel de conocimiento para evaluar lo que no se sabe.","El efecto tiene implicaciones profundas en la política, la medicina y las redes sociales, donde las opiniones más seguras suelen ser las menos informadas."];

DEEP_DIVES['psy2'].es = ["El efecto placebo demuestra que el simple hecho de creer que un tratamiento funciona puede producir mejoras reales y medibles en la salud.","Estudios muestran que placebos más caros funcionan mejor que los baratos, las inyecciones placebo superan a las pastillas placebo, y los placebos de color funcionan diferente según la cultura.","Aún más sorprendente: el efecto placebo funciona incluso cuando el paciente sabe que está tomando un placebo — el ritual del tratamiento en sí tiene poder terapéutico."];

DEEP_DIVES['psy3'].es = ["El sesgo de confirmación nos lleva a buscar, interpretar y recordar selectivamente la información que confirma nuestras creencias preexistentes.","Este sesgo es tan poderoso que personas con opiniones opuestas pueden leer el mismo estudio y sentir que ambas posiciones han sido confirmadas.","Las redes sociales amplifican el sesgo de confirmación creando burbujas de filtro: los algoritmos muestran contenido que refuerza nuestras creencias, aislándonos de perspectivas diferentes."];

DEEP_DIVES['psy4'].es = ["La disonancia cognitiva, teorizada por Leon Festinger en 1957, es la incomodidad que sentimos cuando nuestras creencias contradicen nuestras acciones.","Para reducir esta tensión, tendemos a cambiar nuestras creencias en lugar de nuestras acciones — por ejemplo, un fumador que minimiza los riesgos del tabaco en lugar de dejar de fumar.","Festinger descubrió este fenómeno infiltrándose en una secta que predijo el fin del mundo: cuando la profecía falló, los miembros reforzaron su fe en lugar de abandonarla."];

DEEP_DIVES['psy5'].es = ["El experimento de Milgram (1961) demostró que personas comunes podían administrar lo que creían eran descargas eléctricas letales simplemente porque una autoridad se lo ordenaba.","El 65 % de los participantes aplicaron la descarga máxima (450 voltios) a un actor que gritaba de dolor — un resultado que conmocionó al mundo y planteó preguntas sobre la obediencia ciega.","Milgram diseñó el experimento para entender cómo ciudadanos normales participaron en el Holocausto — demostró que la obediencia a la autoridad es un comportamiento humano universal, no una anomalía."];

DEEP_DIVES['psy6'].es = ["La pirámide de Maslow (1943) organiza las necesidades humanas en cinco niveles: fisiológicas, seguridad, pertenencia, estima y autorrealización.","La idea es que no se pueden satisfacer las necesidades superiores sin cubrir las inferiores — pero la vida real muestra excepciones: artistas que crean en la pobreza o activistas que arriesgan su seguridad por ideales.","Maslow reconoció las limitaciones de su modelo hacia el final de su vida y propuso un sexto nivel: la autotrascendencia, donde el individuo se dedica a algo más grande que sí mismo."];

DEEP_DIVES['psy7'].es = ["El efecto espectador describe cómo la probabilidad de que alguien ayude en una emergencia disminuye cuando hay más personas presentes.","El caso de Kitty Genovese (1964), supuestamente ignorada por 38 vecinos mientras era asesinada, popularizó el concepto — aunque investigaciones posteriores revelaron que la historia fue exagerada por la prensa.","La difusión de responsabilidad explica el fenómeno: cada persona asume que otro actuará, lo que resulta en que nadie lo hace — un sesgo social con consecuencias a veces fatales."];

DEEP_DIVES['psy8'].es = ["La memoria humana no funciona como una grabación fiel: cada vez que recordamos algo, reconstruimos el recuerdo, lo que puede introducir distorsiones y falsos recuerdos.","Elizabeth Loftus demostró que es posible implantar recuerdos falsos con simples sugerencias — sus investigaciones transformaron el sistema judicial al cuestionar la fiabilidad de los testimonios.","Los flashbulb memories (recuerdos vívidos de eventos impactantes) parecen perfectos pero son igual de susceptibles a la distorsión — creemos recordar exactamente, pero los detalles cambian con el tiempo."];

DEEP_DIVES['psy9'].es = ["El condicionamiento clásico fue descubierto por Pavlov a principios del siglo XX al observar que sus perros salivaban al oír una campana que habían asociado con la comida.","Este mecanismo explica muchas respuestas emocionales automáticas: el miedo a un sonido, la nostalgia de una canción o las náuseas provocadas por un olor asociado a una mala experiencia.","La publicidad explota masivamente el condicionamiento clásico: asociar un producto con emociones positivas (música, paisajes, personas atractivas) para crear una respuesta de deseo automática."];

DEEP_DIVES['psy10'].es = ["La inteligencia emocional (IE), popularizada por Daniel Goleman en 1995, incluye la autoconciencia, la autorregulación, la empatía, la motivación y las habilidades sociales.","Estudios sugieren que la IE puede predecir el éxito profesional y personal mejor que el cociente intelectual (CI), especialmente en roles de liderazgo y trabajo en equipo.","La IE no es innata sino que puede desarrollarse: la meditación, la terapia y la práctica consciente de la empatía mejoran significativamente la regulación emocional."];

DEEP_DIVES['psy11'].es = ["El síndrome del impostor afecta a un 70 % de las personas en algún momento de su vida: la sensación de no merecer su éxito y el miedo a ser «desenmascarado» como fraude.","Fue descrito por primera vez en 1978 por las psicólogas Pauline Clance e Iman Ames al estudiar a mujeres exitosas que atribuían sus logros a la suerte.","Paradójicamente, el síndrome del impostor es más común entre personas altamente competentes — los menos capaces rara vez lo experimentan (véase el efecto Dunning-Kruger)."];

DEEP_DIVES['psy12'].es = ["La teoría del apego de John Bowlby establece que la calidad del vínculo entre un bebé y su cuidador principal moldea las relaciones afectivas durante toda la vida adulta.","Mary Ainsworth identificó tres estilos de apego: seguro (66 %), ansioso-ambivalente (20 %) e inseguro-evitativo (14 %) — un cuarto estilo, desorganizado, fue añadido posteriormente.","El apego seguro en la infancia se asocia con mayor autoestima, relaciones más estables y mejor regulación emocional en la edad adulta — pero los estilos inseguros pueden modificarse con terapia."];

DEEP_DIVES['psy13'].es = ["La psicología positiva, fundada por Martin Seligman en 1998, estudia lo que hace florecer a las personas en lugar de centrarse solo en la patología.","El modelo PERMA de Seligman identifica cinco pilares del bienestar: emociones Positivas, Engagement (compromiso), Relaciones, Meaning (sentido) y Achievement (logro).","La gratitud, la meditación mindfulness y los actos de bondad son intervenciones de psicología positiva con eficacia demostrada para aumentar el bienestar subjetivo."];

DEEP_DIVES['psy14'].es = ["La procrastinación no es pereza sino un problema de regulación emocional: evitamos tareas que generan emociones negativas (ansiedad, aburrimiento, frustración).","El cerebro prefiere la gratificación inmediata (scrollear el móvil) a la recompensa diferida (terminar un proyecto) — un sesgo evolutivo que era útil para la supervivencia pero contraproducente hoy.","Las técnicas más eficaces contra la procrastinación incluyen la regla de los 2 minutos, la técnica Pomodoro y la autocompasión — castigarse por procrastinar solo empeora el ciclo."];

DEEP_DIVES['psy15'].es = ["Los sueños lúcidos son aquellos en los que el soñador es consciente de estar soñando y puede influir en el desarrollo del sueño.","Estudios con resonancia magnética han confirmado que los sueños lúcidos son un estado real de conciencia, diferente tanto del sueño normal como de la vigilia.","Técnicas como la verificación de realidad, el diario de sueños y la meditación MILD pueden aumentar la frecuencia de sueños lúcidos — un campo en expansión en la neurociencia."];

DEEP_DIVES['psy16'].es = ["El efecto halo hace que una impresión positiva en un aspecto (atractivo físico, por ejemplo) influya en la evaluación de otros aspectos no relacionados (inteligencia, honestidad).","Estudios muestran que las personas atractivas reciben sentencias judiciales más leves, mejores notas y más ofertas de empleo — un sesgo inconsciente con consecuencias reales.","El efecto inverso también existe: el efecto «cuernos» (horn effect) hace que un rasgo negativo contamine la percepción global de una persona."];

DEEP_DIVES['psy17'].es = ["La terapia cognitivo-conductual (TCC) es la psicoterapia con más evidencia científica: parte del principio de que los pensamientos distorsionados generan emociones negativas y conductas disfuncionales.","La TCC enseña a identificar y cuestionar pensamientos automáticos negativos para reemplazarlos por interpretaciones más realistas y adaptativas.","Es eficaz para la depresión, la ansiedad, el TOC, las fobias, el TEPT y muchos otros trastornos — y sus beneficios se mantienen a largo plazo, a diferencia de algunos tratamientos farmacológicos."];

DEEP_DIVES['psy18'].es = ["La neuroplasticidad es la capacidad del cerebro para reorganizar sus conexiones neuronales a lo largo de toda la vida — no solo en la infancia como se creía antes.","Aprender un idioma, tocar un instrumento o meditar regularmente puede cambiar físicamente la estructura del cerebro, aumentando la densidad de materia gris en las áreas involucradas.","La neuroplasticidad ofrece esperanza para la rehabilitación tras lesiones cerebrales: zonas sanas pueden aprender a asumir funciones de zonas dañadas, aunque el proceso es lento y exigente."];

DEEP_DIVES['psy19'].es = ["El efecto ancla hace que la primera información que recibimos sobre un tema influya desproporcionadamente en nuestros juicios posteriores.","En una negociación, quien hace la primera oferta establece el ancla: todas las contraofertas se moverán en torno a ese punto de referencia inicial.","Los precios «antes/después» en las rebajas explotan el efecto ancla: el precio original (aunque sea ficticio) hace que el descuento parezca mayor de lo que realmente es."];

DEEP_DIVES['psy20'].es = ["Sigmund Freud, padre del psicoanálisis, propuso que el inconsciente, los sueños y las experiencias infantiles moldean la personalidad adulta.","Muchas de sus teorías específicas (complejo de Edipo, envidia del pene, interpretación de los sueños) han sido cuestionadas o refutadas por la psicología moderna.","Sin embargo, la idea central de Freud — que tenemos procesos mentales inconscientes que influyen en nuestro comportamiento — está ampliamente respaldada por la neurociencia contemporánea."];

DEEP_DIVES['psy21'].es = ["El flow, descrito por Mihaly Csikszentmihalyi, es un estado de concentración total en el que la persona pierde la noción del tiempo y experimenta una satisfacción profunda.","El flow ocurre cuando el nivel de dificultad de una tarea coincide con el nivel de habilidad de la persona — demasiado fácil produce aburrimiento, demasiado difícil produce ansiedad.","Músicos, atletas, programadores y artistas describen experiencias de flow similares — un estado universal que Csikszentmihalyi vinculó directamente con la felicidad."];

DEEP_DIVES['psy22'].es = ["El experimento de la prisión de Stanford (1971) de Philip Zimbardo dividió a estudiantes en «guardias» y «prisioneros» — en días, los guardias se volvieron sádicos y los prisioneros sumisos.","El experimento fue cancelado tras seis días (de los 14 previstos) cuando los abusos se volvieron extremos — demostró el poder de los roles sociales sobre el comportamiento individual.","Sin embargo, investigaciones recientes cuestionan la validez del estudio: Zimbardo instruyó activamente a los guardias para que fueran duros, lo que sesga los resultados."];

DEEP_DIVES['psy23'].es = ["Los introvertidos no son tímidos ni antisociales: simplemente recobran energía en soledad, mientras que los extrovertidos la obtienen de la interacción social.","Carl Jung introdujo la distinción introversión/extroversión en 1921 — no como categorías rígidas sino como un espectro donde la mayoría de personas se sitúa en algún punto intermedio (ambivertidos).","Susan Cain, en su libro El poder de los introvertidos (2012), argumentó que la sociedad occidental sobrevalorar la extroversión ha marginado a un tercio de la población que piensa y crea mejor en silencio."];

DEEP_DIVES['psy24'].es = ["La aversión a la pérdida, descubierta por Kahneman y Tversky, muestra que perder 100 € duele psicológicamente el doble de lo que alegra ganar 100 €.","Este sesgo explica comportamientos irracionales: conservar inversiones perdedoras, evitar cambios positivos por miedo a perder lo actual, o comprar seguros excesivos.","Kahneman recibió el Nobel de Economía en 2002 por demostrar que los humanos no somos agentes racionales — nuestras decisiones están sistemáticamente sesgadas."];

DEEP_DIVES['psy25'].es = ["La meditación mindfulness, derivada de prácticas budistas, reduce el estrés, la ansiedad y la depresión según cientos de estudios revisados por pares.","La práctica modifica el cerebro de forma medible: aumenta el grosor del córtex prefrontal (planificación, autocontrol) y reduce la actividad de la amígdala (miedo, estrés).","Solo 8 semanas de meditación regular (programa MBSR) producen cambios significativos en el bienestar psicológico — un resultado comparable a los antidepresivos para la depresión leve a moderada."];

DEEP_DIVES['psy26'].es = ["El efecto Pygmalion (o profecía autocumplida) muestra que las expectativas de un profesor sobre sus alumnos influyen directamente en el rendimiento de estos.","Rosenthal y Jacobson (1968) dijeron a profesores que ciertos alumnos (elegidos al azar) eran «excepcionalmente brillantes» — al final del año, esos alumnos habían mejorado significativamente más que los demás.","Este efecto no se limita al aula: en el trabajo, en la pareja y en la crianza, las expectativas que proyectamos sobre los demás moldean su comportamiento real."];

DEEP_DIVES['psy27'].es = ["El trastorno de estrés postraumático (TEPT) fue reconocido oficialmente en 1980, aunque se describía desde la Antigüedad como «corazón de soldado» o «neurosis de guerra».","El TEPT no solo afecta a veteranos de guerra: accidentes, agresiones, catástrofes y traumas infantiles pueden desencadenarlo — afecta al 6-9 % de la población en algún momento de su vida.","La terapia EMDR (desensibilización y reprocesamiento por movimientos oculares) y la exposición prolongada son los tratamientos más eficaces, con tasas de remisión superiores al 80 %."];

DEEP_DIVES['psy28'].es = ["La creatividad no es un don reservado a los artistas sino una capacidad cognitiva universal que combina pensamiento divergente (generar ideas) y convergente (evaluarlas y seleccionarlas).","Los momentos «eureka» suelen ocurrir durante actividades relajantes (ducha, paseo, sueño) porque el cerebro en modo difuso conecta ideas distantes que el pensamiento focalizado no puede.","Estudios muestran que las restricciones pueden potenciar la creatividad: los límites obligan a pensar de forma no convencional — la libertad total puede paralizar más que inspirar."];

DEEP_DIVES['psy29'].es = ["La teoría de la autodeterminación (Deci y Ryan) identifica tres necesidades psicológicas básicas: autonomía, competencia y conexión social.","Cuando estas tres necesidades están satisfechas, las personas experimentan motivación intrínseca, bienestar y crecimiento personal — su frustración produce apatía, ansiedad y malestar.","Esta teoría explica por qué el dinero no motiva a largo plazo: la motivación extrínseca (recompensas, castigos) erosiona la motivación intrínseca cuando sustituye el sentido de autonomía."];

DEEP_DIVES['psy30'].es = ["Los sesgos cognitivos son atajos mentales que el cerebro usa para tomar decisiones rápidas — útiles en la sabana africana, pero a menudo engañosos en el mundo moderno.","Kahneman distingue entre el Sistema 1 (rápido, intuitivo, automático) y el Sistema 2 (lento, analítico, esforzado) — la mayoría de nuestras decisiones las toma el Sistema 1 sin que nos demos cuenta.","Conocer nuestros sesgos no nos inmuniza contra ellos: el sesgo del punto ciego nos hace creer que somos menos sesgados que los demás — la autoconciencia es necesaria pero insuficiente."];

// ── OCEANS ocean1-ocean30 ──

DEEP_DIVES['ocean1'].es = ["Los océanos cubren el 71 % de la superficie terrestre pero más del 80 % permanece inexplorado — conocemos mejor la superficie de Marte que el fondo de nuestros mares.","La fosa de las Marianas, el punto más profundo del océano (10 994 m), podría sumergir el Everest con más de 2 km de margen.","Solo tres personas han alcanzado el fondo de la fosa de las Marianas: Jacques Piccard y Don Walsh en 1960, y James Cameron en 2012."];

DEEP_DIVES['ocean2'].es = ["El Gran Arrecife de Coral australiano es la estructura biológica más grande del planeta: 2 300 km de longitud, visible desde el espacio.","Alberga más de 1 500 especies de peces, 400 tipos de coral, 4 000 especies de moluscos y 240 especies de aves — un ecosistema de biodiversidad incomparable.","El blanqueamiento masivo causado por el calentamiento oceánico ha afectado a más del 60 % de los corales en episodios cada vez más frecuentes — su supervivencia a largo plazo está amenazada."];

DEEP_DIVES['ocean3'].es = ["Las corrientes oceánicas funcionan como una cinta transportadora global (circulación termohalina) que distribuye calor, nutrientes y oxígeno por todo el planeta.","La Corriente del Golfo transporta más agua que todos los ríos del mundo juntos y mantiene la Europa occidental hasta 10 °C más cálida de lo que le correspondería por su latitud.","El debilitamiento de la circulación termohalina por el deshielo del Ártico podría alterar drásticamente el clima europeo — un escenario que los climatólogos vigilan con preocupación."];

DEEP_DIVES['ocean4'].es = ["Las ballenas azules son los animales más grandes que han existido jamás: hasta 30 metros de largo y 180 toneladas — su corazón es del tamaño de un coche pequeño.","Solo su lengua pesa tanto como un elefante, y un bebé de ballena azul nace midiendo 7 metros y gana 90 kg por día durante el primer año.","La caza industrial redujo su población de 300 000 a menos de 5 000 en el siglo XX — la prohibición de 1966 ha permitido una lenta recuperación hasta unos 15 000 ejemplares."];

DEEP_DIVES['ocean5'].es = ["El océano produce más del 50 % del oxígeno que respiramos, principalmente a través del fitoplancton — organismos microscópicos que también absorben enormes cantidades de CO₂.","Los océanos han absorbido el 30 % del CO₂ emitido por la humanidad, lo que provoca su acidificación — el pH del agua ha bajado un 30 % desde la era preindustrial.","La acidificación dificulta la formación de conchas y esqueletos calcáreos, amenazando a corales, moluscos y plancton — organismos que forman la base de la cadena alimentaria marina."];

DEEP_DIVES['ocean6'].es = ["Los pulpos tienen tres corazones, sangre azul (basada en cobre, no en hierro), nueve cerebros (un central y uno en cada tentáculo) y pueden cambiar de color en milisegundos.","Son los invertebrados más inteligentes: abren tarros, resuelven laberintos, reconocen a personas individuales y se han fugado de acuarios abriendo tapas y recorriendo pasillos.","Los pulpos tienen una vida trágicamente corta (1-5 años): la hembra muere tras cuidar sus huevos durante semanas sin comer, y el macho muere poco después del apareamiento."];

DEEP_DIVES['ocean7'].es = ["Los tiburones existen desde hace más de 400 millones de años — han sobrevivido a cinco extinciones masivas, incluyendo la que eliminó a los dinosaurios.","A pesar de su reputación, los tiburones matan menos de 10 personas al año, mientras que los humanos matamos más de 100 millones de tiburones anuales, principalmente por sus aletas.","El olfato del tiburón es extraordinario: puede detectar una gota de sangre diluida en 100 litros de agua y seguir rastros olfativos a kilómetros de distancia."];

DEEP_DIVES['ocean8'].es = ["La isla de plástico del Pacífico (Great Pacific Garbage Patch) se extiende sobre 1,6 millones de km², tres veces la superficie de Francia.","No es una isla sólida sino una zona de alta concentración de microplásticos suspendidos en el agua — invisible desde la superficie pero devastadora para la vida marina.","Cada año, entre 8 y 12 millones de toneladas de plástico llegan al océano — al ritmo actual, habrá más plástico que peces en el mar para 2050."];

DEEP_DIVES['ocean9'].es = ["Las medusas llevan más de 600 millones de años en los océanos — son más antiguas que los dinosaurios, los tiburones e incluso que los árboles.","La medusa inmortal (Turritopsis dohrnii) puede revertir su ciclo de vida y volver al estado de pólipo juvenil cuando envejece o se estresa — teóricamente, puede vivir para siempre.","Las proliferaciones masivas de medusas están aumentando por el calentamiento oceánico, la sobrepesca de sus depredadores y la contaminación — en algunas zonas, amenazan la pesca y las centrales eléctricas."];

DEEP_DIVES['ocean10'].es = ["Las fuentes hidrotermales del fondo oceánico albergan ecosistemas que no dependen del sol sino de la quimiosíntesis — bacterias que convierten compuestos químicos volcánicos en energía.","Descubiertas en 1977, estas comunidades incluyen gusanos tubícolas de 2 metros, camarones ciegos y cangrejos que prosperan a 400 °C de temperatura y presiones aplastantes.","Las fuentes hidrotermales son candidatas como cuna de la vida: sus condiciones químicas podrían haber generado las primeras moléculas orgánicas hace 3 800 millones de años."];

DEEP_DIVES['ocean11'].es = ["Las mareas son causadas principalmente por la atracción gravitatoria de la Luna y, en menor medida, del Sol — la diferencia entre marea alta y baja puede superar los 16 metros en la Bahía de Fundy (Canadá).","Las mareas no son simples subidas y bajadas: generan corrientes poderosas que moldean las costas, alimentan los ecosistemas intermareales y mueven millones de toneladas de sedimentos.","La energía mareomotriz es una fuente renovable prometedora: la central de La Rance en Francia genera electricidad desde 1966 aprovechando las mareas del Canal de la Mancha."];

DEEP_DIVES['ocean12'].es = ["Los arrecifes de coral ocupan menos del 0,1 % del fondo oceánico pero albergan el 25 % de todas las especies marinas — son la selva tropical del mar.","Los corales no son plantas sino animales (pólipos) que viven en simbiosis con algas microscópicas (zooxantelas) — el coral proporciona refugio y las algas producen alimento mediante fotosíntesis.","Cuando el agua se calienta, los corales expulsan sus algas simbióticas y pierden su color (blanqueamiento) — si el estrés persiste, el coral muere."];

DEEP_DIVES['ocean13'].es = ["Los tsunamis pueden viajar a más de 800 km/h en mar abierto (la velocidad de un avión) pero solo miden centímetros de altura — al acercarse a la costa, se ralentizan y se elevan.","El tsunami de 2004 en el océano Índico mató a más de 230 000 personas en 14 países — fue causado por un terremoto de magnitud 9,1 frente a Sumatra.","Los sistemas de alerta de tsunamis del Pacífico utilizan boyas de presión en el fondo del mar que detectan cambios de nivel oceánico y emiten alertas en minutos."];

DEEP_DIVES['ocean14'].es = ["Las ballenas jorobadas cantan las canciones más complejas del reino animal: secuencias de sonidos que duran hasta 20 minutos y se repiten durante horas.","Todas las ballenas jorobadas de una misma zona cantan la misma canción, que evoluciona gradualmente durante la temporada — una «cultura musical» que se transmite entre individuos.","Los cantos se propagan entre poblaciones a miles de kilómetros: una canción nueva puede viajar de Australia a la Polinesia Francesa en pocos años."];

DEEP_DIVES['ocean15'].es = ["El calamar gigante (Architeuthis dux) puede alcanzar los 13 metros de longitud y posee los ojos más grandes del reino animal: hasta 27 cm de diámetro.","Durante siglos fue considerado una leyenda (el Kraken nórdico), hasta que se filmó por primera vez un ejemplar vivo en su hábitat natural en 2004.","El calamar gigante lucha contra los cachalotes en las profundidades: las marcas de ventosas en la piel de los cachalotes atestiguan combates épicos en la oscuridad abisal."];

DEEP_DIVES['ocean16'].es = ["El Mar de los Sargazos, en el Atlántico Norte, es el único mar sin costas: delimitado por corrientes oceánicas, alberga masas flotantes de algas sargazo.","Las anguilas europeas y americanas recorren miles de kilómetros para reproducirse exclusivamente en el Mar de los Sargazos — luego mueren, y sus larvas hacen el viaje de vuelta solas.","El misterio de la reproducción de las anguilas desconcertó a los científicos durante siglos: Freud y Aristóteles intentaron encontrar sus órganos reproductores sin éxito."];

DEEP_DIVES['ocean17'].es = ["Los manglares son bosques costeros tropicales que actúan como guarderías de peces, barreras contra tormentas y sumideros de carbono extraordinarios.","Un manglar puede almacenar hasta 10 veces más carbono que un bosque terrestre de la misma superficie — su destrucción libera enormes cantidades de CO₂.","Se ha perdido más del 35 % de los manglares del mundo en los últimos 50 años debido a la acuicultura, el desarrollo costero y la contaminación."];

DEEP_DIVES['ocean18'].es = ["El pez payaso y la anémona de mar tienen una de las relaciones simbióticas más conocidas del océano: el pez limpia los parásitos de la anémona y ella lo protege con sus tentáculos urticantes.","Los peces payaso son inmunes al veneno de su anémona gracias a una capa de moco especial — cada especie de pez payaso se asocia con especies específicas de anémona.","Todos los peces payaso nacen machos y el individuo dominante del grupo se transforma en hembra — Nemo habría tenido una historia muy diferente si Pixar hubiera seguido la biología real."];

DEEP_DIVES['ocean19'].es = ["La bioluminiscencia marina es producida por miles de especies: medusas, peces abisales, calamares, dinoflagelados y bacterias que generan luz mediante reacciones químicas.","En las profundidades donde no llega la luz solar (más del 90 % del volumen oceánico), la bioluminiscencia es la forma de comunicación dominante: atraer presas, confundir depredadores y encontrar pareja.","Las bahías bioluminiscentes (como Mosquito Bay en Puerto Rico) brillan con un resplandor azul-verde cuando se agita el agua — un espectáculo creado por millones de dinoflagelados."];

DEEP_DIVES['ocean20'].es = ["Las tortugas marinas existen desde hace 100 millones de años y navegan miles de kilómetros usando el campo magnético terrestre como GPS biológico.","Las hembras vuelven a la playa exacta donde nacieron para poner sus huevos, décadas después — un sistema de orientación que la ciencia aún no comprende del todo.","La temperatura del nido determina el sexo de las crías: más calor produce más hembras — el calentamiento global podría crear poblaciones con un desequilibrio sexual fatal."];

DEEP_DIVES['ocean21'].es = ["El Triángulo de las Bermudas, entre Miami, Bermudas y Puerto Rico, tiene fama de tragar barcos y aviones — pero estadísticamente, su tasa de accidentes no es superior a la de otras zonas de tráfico marítimo intenso.","Las explicaciones propuestas incluyen erupciones de metano del fondo marino (que reducirían la densidad del agua), corrientes impredecibles y tormentas tropicales súbitas.","El mito fue popularizado por el escritor Charles Berlitz en 1974 — investigaciones posteriores revelaron que muchos de los «desapariciones misteriosas» habían sido exageradas o inventadas."];

DEEP_DIVES['ocean22'].es = ["Los delfines duermen con medio cerebro a la vez (sueño unihemisférico) para poder seguir respirando y vigilar a los depredadores — mantienen un ojo abierto.","Su ecolocalización es más precisa que cualquier sonar artificial: pueden detectar un objeto del tamaño de una pelota de golf a 100 metros de distancia.","Los delfines tienen nombres propios: cada individuo desarrolla un silbido firma único que los demás usan para llamarlo — una forma de comunicación individual rarísima en el reino animal."];

DEEP_DIVES['ocean23'].es = ["La Corriente del Golfo transporta más de 30 millones de metros cúbicos de agua por segundo — más que todos los ríos del mundo combinados.","Sin la Corriente del Golfo, ciudades como Londres y París tendrían temperaturas comparables a las de Labrador en Canadá, a la misma latitud.","Los científicos vigilan signos de debilitamiento de esta corriente debido al deshielo de Groenlandia — un cambio que tendría consecuencias climáticas graves para Europa y América del Norte."];

DEEP_DIVES['ocean24'].es = ["Las profundidades abisales (más de 4 000 m) son un mundo de oscuridad total, presiones aplastantes y temperaturas cercanas a 0 °C — y sin embargo, están llenas de vida.","Los peces abisales tienen adaptaciones extraordinarias: mandíbulas extensibles, estómagos elásticos, órganos bioluminiscentes y metabolismos extremadamente lentos.","El pez rape abisal macho se fusiona físicamente con la hembra al encontrarla: pierde sus órganos y se convierte en un apéndice reproductor permanente — la estrategia reproductiva más extrema de la naturaleza."];

DEEP_DIVES['ocean25'].es = ["El Océano Ártico se calienta cuatro veces más rápido que el resto del planeta — el hielo marino de verano podría desaparecer completamente antes de 2050.","La pérdida de hielo ártico afecta al albedo (reflectividad) terrestre: el agua oscura absorbe más calor que el hielo blanco, acelerando el calentamiento en un círculo vicioso.","La apertura de rutas marítimas árticas (Paso del Noroeste, Ruta del Mar del Norte) genera intereses geopolíticos entre Rusia, EE.UU., Canadá, China y la UE."];

DEEP_DIVES['ocean26'].es = ["Las olas más grandes del mundo se forman en Nazaré, Portugal, donde un cañón submarino de 5 km de profundidad concentra la energía del oleaje atlántico.","El récord de la ola más grande jamás surfeada fue establecido en Nazaré: más de 26 metros (un edificio de 8 pisos), una hazaña que desafía los límites humanos.","Las olas gigantes (rogue waves o olas vagabundas) fueron consideradas mitos de marineros hasta que sensores satelitales confirmaron su existencia en los años 1990."];

DEEP_DIVES['ocean27'].es = ["Las praderas de posidonia (Posidonia oceanica) del Mediterráneo producen más oxígeno que la selva amazónica por metro cuadrado y almacenan grandes cantidades de carbono.","Una pradera de posidonia en las Islas Baleares se considera el organismo vivo más grande (y posiblemente más antiguo) del mundo: tiene más de 100 000 años.","La posidonia está protegida en la UE como hábitat prioritario, pero sigue amenazada por el fondeo de embarcaciones, la contaminación y el desarrollo costero."];

DEEP_DIVES['ocean28'].es = ["Los cachalotes pueden sumergirse a más de 2 000 metros de profundidad y contener la respiración durante 90 minutos — los mamíferos buceadores más extremos del planeta.","Su cerebro, el más grande del reino animal (8 kg), produce clics de ecolocalización que alcanzan los 230 decibelios — el sonido más fuerte producido por cualquier animal.","Los cachalotes tienen una cultura de clan: diferentes grupos usan dialectos de clics distintos y se transmiten técnicas de caza entre generaciones."];

DEEP_DIVES['ocean29'].es = ["El océano profundo contiene más del 90 % del espacio habitable de la Tierra, pero hemos explorado menos del 5 % de este vasto dominio.","Las llanuras abisales, vastas extensiones planas del fondo oceánico, son los hábitats más grandes y menos conocidos del planeta.","La minería de los fondos marinos (nódulos polimetálicos, sulfuros hidrotermales) genera un debate feroz entre la industria minera y los conservacionistas — los daños a estos ecosistemas serían irreversibles."];

DEEP_DIVES['ocean30'].es = ["Los océanos absorben el 90 % del exceso de calor causado por el cambio climático — sin ellos, la temperatura atmosférica sería mucho más alta.","El nivel del mar ha subido 20 cm desde 1900 y la velocidad de subida se acelera: se prevén entre 30 cm y 1 metro adicionales para 2100 según los escenarios.","Ciudades costeras como Miami, Yakarta, Shanghái y Bombay albergan a cientos de millones de personas amenazadas por la subida del nivel del mar — la adaptación costera es uno de los mayores desafíos del siglo XXI."];

// ── RECORDS rec1-rec30 ──

DEEP_DIVES['rec1'].es = ["La persona que ha vivido más años de forma verificada fue Jeanne Calment (Francia), que murió en 1997 a los 122 años y 164 días.","Calment nació en 1875, conoció a Van Gogh, vivió dos guerras mundiales y la invención de la televisión, el avión, el ordenador e Internet.","Los supercentenarios (110+ años) son extremadamente raros: en cualquier momento dado, solo hay unas 300-400 personas en todo el mundo que han alcanzado esa edad."];

DEEP_DIVES['rec2'].es = ["El hombre más alto de la historia documentada fue Robert Wadlow (EE.UU.), que alcanzó 2,72 metros antes de morir a los 22 años en 1940.","Su crecimiento continuo se debía a una hiperplasia de la glándula pituitaria que producía niveles anormales de hormona del crecimiento.","Wadlow necesitaba muletas para caminar y usaba zapatos de talla 76 — pese a su fama, era conocido por su carácter amable y gentil."];

DEEP_DIVES['rec3'].es = ["Usain Bolt posee el récord de los 100 metros lisos (9,58 s) y los 200 metros (19,19 s), ambos establecidos en el Mundial de Berlín 2009.","A su velocidad máxima, Bolt alcanzó 44,72 km/h — pero curiosamente, su salida era más lenta que la de sus rivales; su ventaja estaba en la fase de velocidad máxima.","Los biomecánicos calculan que el límite teórico humano para los 100 metros está entre 9,27 y 9,40 segundos — pero nadie se ha acercado al récord de Bolt en más de 15 años."];

DEEP_DIVES['rec4'].es = ["El edificio más alto del mundo es el Burj Khalifa en Dubái, con 828 metros y 163 pisos — su punta es visible a más de 95 km de distancia.","La construcción empleó a más de 12 000 trabajadores y usó 330 000 m³ de hormigón — la diferencia de temperatura entre la base y la cima puede superar los 10 °C.","El Jeddah Tower en Arabia Saudita (en construcción) está diseñado para superar los 1 000 metros — la carrera por el rascacielos más alto continúa."];

DEEP_DIVES['rec5'].es = ["El avión más rápido jamás construido fue el North American X-15, que alcanzó 7 274 km/h (Mach 6,7) en 1967 — un récord para aviones tripulados que sigue vigente.","El avión comercial más rápido fue el Concorde (2 180 km/h), retirado en 2003 — cruzaba el Atlántico en 3 horas y media, la mitad que un avión convencional.","Boom Supersonic desarrolla el Overture, un avión supersónico que promete vuelos transatlánticos en 3,5 horas para la década de 2030 — el sucesor espiritual del Concorde."];

DEEP_DIVES['rec6'].es = ["La temperatura más alta registrada en la Tierra fue 56,7 °C en el Valle de la Muerte (California) el 10 de julio de 1913 — aunque algunos meteorólogos cuestionan esta medición.","La más baja fue -89,2 °C en la estación Vostok (Antártida) el 21 de julio de 1983 — tan frío que el acero se vuelve frágil como vidrio.","El lugar habitado más frío del mundo es Oymyakón, en Siberia, donde se han registrado -67,7 °C — los habitantes dejan los motores de sus coches encendidos toda la noche."];

DEEP_DIVES['rec7'].es = ["El animal más rápido del mundo es el halcón peregrino, que alcanza más de 380 km/h en picado — el vertebrado más veloz del planeta.","En tierra, el guepardo alcanza 112 km/h en sprints cortos, pero un antílope americano (berrendo) puede mantener 90 km/h durante kilómetros — la velocidad sostenida más alta.","El animal más rápido del mar es el pez vela (Istiophorus), que alcanza 110 km/h — una velocidad comparable a la de un coche en autopista."];

DEEP_DIVES['rec8'].es = ["El objeto artificial más lejano de la Tierra es la sonda Voyager 1, lanzada en 1977, que se encuentra a más de 24 000 millones de km del Sol.","A pesar de su distancia, Voyager 1 sigue transmitiendo datos a la Tierra — la señal tarda más de 22 horas en llegar, viajando a la velocidad de la luz.","La sonda lleva un disco de oro con sonidos e imágenes de la Tierra: música de Bach, saludos en 55 idiomas y fotografías de la humanidad — un mensaje para posibles civilizaciones extraterrestres."];

DEEP_DIVES['rec9'].es = ["El récord de apnea estática (sin respirar bajo el agua, inmóvil) supera los 24 minutos — una hazaña que desafía la comprensión de la fisiología humana.","Los apneístas entrenan para reducir su consumo de oxígeno y tolerar altos niveles de CO₂ — el reflejo de inmersión mamífero (bradicardia, vasoconstricción) es la clave fisiológica.","La apnea profunda supera los 130 metros de profundidad: a esa presión, los pulmones se comprimen al tamaño de un puño y la sangre se concentra en los órganos vitales."];

DEEP_DIVES['rec10'].es = ["El libro más vendido de la historia es la Biblia, con más de 5 000 millones de copias distribuidas — seguida del Corán y Don Quijote.","El Principito de Saint-Exupéry es el libro más traducido después de textos religiosos, con versiones en más de 300 idiomas y dialectos.","Harry Potter y la piedra filosofal (1997) ha vendido más de 120 millones de copias en un solo volumen — el libro de ficción más vendido de las últimas décadas."];

DEEP_DIVES['rec11'].es = ["El vuelo espacial más largo fue el de Valeri Polyakov, que pasó 437 días consecutivos en la estación Mir (1994-1995) — más de 14 meses en gravedad cero.","Los efectos del vuelo espacial prolongado incluyen pérdida ósea, atrofia muscular, redistribución de fluidos y cambios en la visión — desafíos que la NASA debe resolver antes de viajar a Marte.","El récord acumulado pertenece a Gennady Padalka, con 879 días en el espacio repartidos en cinco misiones — el equivalente a casi dos años y medio."];

DEEP_DIVES['rec12'].es = ["El récord de velocidad terrestre es de 1 228 km/h (Mach 1,016), establecido por Andy Green en el ThrustSSC en 1997 — el primer vehículo terrestre en romper la barrera del sonido.","El proyecto Bloodhound intentó superar los 1 600 km/h pero fue abandonado por falta de financiación — la búsqueda de velocidad extrema sigue siendo costosísima.","Los salt flats de Bonneville (Utah) y Black Rock Desert (Nevada) son las pistas naturales más utilizadas para récords de velocidad terrestre."];

DEEP_DIVES['rec13'].es = ["La obra de arte más cara jamás vendida fue el Salvator Mundi, atribuido a Leonardo da Vinci, por 450 millones de dólares en 2017.","La autenticidad del Salvator Mundi es debatida por algunos expertos, lo que no impidió que alcanzara un precio récord — el mercado del arte desafía la lógica económica.","La obra de arte de un artista vivo más cara fue una escultura de Jeff Koons vendida por 91 millones de dólares en 2019."];

DEEP_DIVES['rec14'].es = ["El animal más longevo conocido es el tiburón de Groenlandia: un ejemplar fue datado en 512 años, lo que lo convierte en el vertebrado más antiguo del planeta.","La almeja Arctica islandica «Ming» fue datada en 507 años antes de ser accidentalmente matada por los científicos que la estudiaban — un final irónico para el animal más viejo conocido.","Las esponjas de cristal antárticas podrían vivir más de 10 000 años, aunque su edad exacta es difícil de determinar — los límites de la longevidad animal siguen siendo desconocidos."];

DEEP_DIVES['rec15'].es = ["El terremoto más potente registrado fue el de Valdivia, Chile, en 1960: magnitud 9,5 en la escala de Richter — generó un tsunami que cruzó el Pacífico hasta Japón.","El terremoto desplazó la costa chilena varios metros hacia el Pacífico y liberó una energía equivalente a 178 000 millones de toneladas de TNT.","Chile es uno de los países más sísmicos del mundo, situado en el Cinturón de Fuego del Pacífico — sus estrictas normas de construcción antisísmica salvan miles de vidas."];

DEEP_DIVES['rec16'].es = ["El récord de flexiones en 24 horas es de más de 46 000, logrado por Charles Servizio en 1993 — una media de 32 flexiones por minuto durante un día entero.","Los récords de resistencia física desafían la comprensión médica: maratones de baile de 126 horas, natación continua de más de 50 horas y ayunos verificados de más de 380 días.","El Guinness World Records existe desde 1955: fue creado para resolver debates en pubs irlandeses — el propio libro se ha convertido en uno de los más vendidos de la historia."];

DEEP_DIVES['rec17'].es = ["El mayor diamante en bruto jamás encontrado fue el Cullinan (1905, Sudáfrica): 3 106 quilates (621 gramos), del que se tallaron las joyas más grandes de la Corona Británica.","La Estrella de África (Cullinan I, 530 quilates) está engastada en el cetro real británico y es el mayor diamante tallado en talla de pera del mundo.","Los diamantes no son raros: lo que mantiene su precio alto es el control de la oferta por la industria — los diamantes sintéticos, químicamente idénticos, cuestan una fracción del precio."];

DEEP_DIVES['rec18'].es = ["El río Amazonas tiene el mayor caudal del mundo: 209 000 m³/s en su desembocadura — más que los siguientes siete ríos más caudalosos juntos.","La cuenca amazónica cubre 6,9 millones de km², casi tan grande como Australia, y su selva produce el 20 % del oxígeno del planeta.","El Amazonas no tiene ni un solo puente en toda su longitud de 6 400 km — la selva circundante es tan densa que no existe infraestructura terrestre que lo cruce."];

DEEP_DIVES['rec19'].es = ["La canción más reproducida en Spotify es Blinding Lights de The Weeknd, con más de 4 000 millones de reproducciones.","Una reproducción en Spotify genera entre 0,003 y 0,005 dólares para el artista — para ganar un salario mínimo mensual, un músico necesitaría más de 250 000 reproducciones al mes.","El algoritmo de Spotify ha creado un nuevo tipo de canción: intros cortas (menos de 5 segundos), estribillos inmediatos y duración reducida (2-3 minutos) para maximizar las reproducciones."];

DEEP_DIVES['rec20'].es = ["La Gran Muralla China se extiende más de 21 000 km incluyendo todas sus ramificaciones — no es visible a simple vista desde el espacio, contrariamente al mito popular.","Su construcción se prolongó durante más de 2 000 años (desde el siglo VII a.C. hasta el XVII d.C.) y costó la vida a millones de trabajadores.","La muralla no fue eficaz como barrera militar: fue atravesada varias veces por invasores, incluyendo los mongoles de Gengis Khan y los manchúes que fundaron la dinastía Qing."];

DEEP_DIVES['rec21'].es = ["El volcán más activo del mundo es el Kīlauea en Hawái, que ha estado en erupción casi continua desde 1983 — ha destruido más de 700 estructuras.","La erupción más mortífera de la historia fue la del Tambora (Indonesia) en 1815: mató a 71 000 personas y causó el «año sin verano» de 1816 en todo el hemisferio norte.","El supervolcán de Yellowstone, bajo el parque nacional, tiene una cámara magmática de 60 km de largo — una erupción masiva podría afectar al clima global durante décadas."];

DEEP_DIVES['rec22'].es = ["El animal más pesado que ha existido es la ballena azul (180 toneladas) — ningún dinosaurio se acercó a ese peso.","El animal terrestre más pesado fue el Argentinosaurus, un saurópodo de unas 70 toneladas — aun así, menos de la mitad del peso de una ballena azul.","El insecto más pesado es el escarabajo Goliat, que puede pesar hasta 100 gramos — en la era del Carbonífero, los insectos alcanzaban tamaños mucho mayores gracias a niveles de oxígeno más altos."];

DEEP_DIVES['rec23'].es = ["El objeto más lejano visible a simple vista es la galaxia de Andrómeda, a 2,5 millones de años-luz — la luz que vemos salió de allí antes de que existieran los humanos.","El telescopio James Webb ha detectado galaxias a más de 13 000 millones de años-luz, formadas apenas 300 millones de años después del Big Bang.","La distancia más lejana que podremos observar jamás es de 46 000 millones de años-luz (borde del universo observable) — más allá, la luz no ha tenido tiempo de llegar a nosotros."];

DEEP_DIVES['rec24'].es = ["El partido de tenis más largo de la historia duró 11 horas y 5 minutos, repartidos en tres días: John Isner venció a Nicolas Mahut 70-68 en el quinto set en Wimbledon 2010.","Tras este maratón, Wimbledon introdujo el tie-break en el quinto set a 12-12 — una regla que no habría sido necesaria sin este partido histórico.","Ambos jugadores sufrieron lesiones tras el partido y Mahut perdió su siguiente encuentro en apenas una hora — el coste físico del récord fue devastador."];

DEEP_DIVES['rec25'].es = ["El mayor concierto de la historia reunió a 3,5 millones de personas para ver a Rod Stewart en Copacabana (Río de Janeiro) en la Nochevieja de 1994.","Jean-Michel Jarre ha dado varios de los conciertos más masivos de la historia, incluyendo 2,5 millones en la Défense (París) y 3,5 millones en Moscú.","La tecnología de streaming ha redefinido el concepto de «concierto más grande»: Travis Scott reunió a 12 millones de espectadores simultáneos en un concierto virtual dentro de Fortnite."];

DEEP_DIVES['rec26'].es = ["La velocidad máxima alcanzada por un ser humano fue 39 897 km/h, lograda por la tripulación del Apollo 10 durante la reentrada atmosférica en 1969.","En la superficie terrestre, el récord de velocidad humana sin vehículo es el de Usain Bolt: 44,72 km/h durante los 100 metros lisos.","Felix Baumgartner alcanzó 1 357 km/h (Mach 1,25) durante su salto estratosférico desde 39 km de altitud en 2012 — el primer humano en romper la barrera del sonido sin vehículo."];

DEEP_DIVES['rec27'].es = ["El mayor organismo vivo del planeta es un hongo (Armillaria ostoyae) en Oregón que se extiende por 965 hectáreas bajo tierra — tiene más de 8 000 años.","El organismo individual más pesado es un álamo temblón clonal llamado Pando en Utah: un bosque de 47 000 árboles conectados por un único sistema de raíces, con un peso estimado de 6 000 toneladas.","Las secuoyas gigantes de California son los árboles más voluminosos: el General Sherman tiene un tronco de 1 487 m³ — el equivalente de un edificio de 5 plantas."];

DEEP_DIVES['rec28'].es = ["El humano que más idiomas ha dominado de forma verificable fue el cardenal Giuseppe Mezzofanti (1774-1849), que hablaba con fluidez entre 30 y 40 idiomas.","Los hiperpolíglotas modernos como Alexander Arguelles y Richard Simcott dominan más de 50 idiomas, aunque el nivel varía entre fluido y básico.","La mayoría de las personas pueden aprender un nuevo idioma a cualquier edad: el mito del «periodo crítico» absoluto ha sido matizado por la investigación moderna."];

DEEP_DIVES['rec29'].es = ["El puente más largo del mundo es el viaducto de Danyang-Kunshan (China), con 164,8 km — conecta Shanghái con Nankín y es una obra de ingeniería sin precedentes.","El puente colgante más largo es el puente de los Dardanelos «1915 Çanakkale» en Turquía (2 023 m de vano central), inaugurado en 2022.","Los puentes romanos, construidos hace 2 000 años con arcos de piedra, siguen en uso en muchas partes de Europa — una demostración de la durabilidad de la ingeniería antigua."];

DEEP_DIVES['rec30'].es = ["La mayor explosión de origen humano antes de la bomba atómica fue la explosión de Halifax (Canadá) en 1917: un barco cargado de municiones devastó la ciudad, matando a 2 000 personas.","La mayor explosión nuclear fue la Tsar Bomba soviética (1961): 50 megatones de TNT — la onda expansiva dio tres vueltas a la Tierra y las ventanas se rompieron a 900 km.","La explosión más potente en la historia terrestre fue el impacto del asteroide Chicxulub hace 66 millones de años: equivalente a 10 000 millones de bombas de Hiroshima, que provocó la extinción de los dinosaurios."];

// ── QUOTES quote1-quote30 ──

DEEP_DIVES['quote1'].es = ["«Solo sé que no sé nada» es la frase más famosa de Sócrates, aunque probablemente nunca la dijo exactamente así — es una interpretación de Platón en la Apología.","La paradoja socrática plantea que la verdadera sabiduría comienza con el reconocimiento de la propia ignorancia — un principio fundacional de la filosofía occidental.","Sócrates no dejó escritos: todo lo que sabemos de él proviene de sus discípulos, principalmente Platón y Jenofonte, que pudieron idealizar o distorsionar su pensamiento."];

DEEP_DIVES['quote2'].es = ["«Pienso, luego existo» (Cogito, ergo sum) de Descartes (1637) es el punto de partida de la filosofía moderna: la única certeza que resiste la duda total.","Descartes llegó a esta conclusión tras dudar de todo: los sentidos, las matemáticas, la realidad misma — pero no podía dudar de que estaba dudando, lo que probaba su existencia.","Esta frase marcó el giro subjetivo de la filosofía: del mundo exterior al mundo interior, de la metafísica a la epistemología — un cambio que sigue definiendo el pensamiento occidental."];

DEEP_DIVES['quote3'].es = ["«El fin justifica los medios» se atribuye a Maquiavelo, pero nunca escribió esa frase exacta — es una simplificación de El Príncipe (1513).","Maquiavelo argumentaba que un gobernante debe ser pragmático y estar dispuesto a actuar sin escrúpulos morales para mantener el Estado — un realismo político revolucionario para su época.","El Príncipe fue escrito como manual para Lorenzo de Médicis, pero su legado va mucho más allá: fundó la ciencia política moderna al separar la moral de la política."];

DEEP_DIVES['quote4'].es = ["«Ser o no ser, esa es la cuestión» es el monólogo más famoso de la literatura universal, pronunciado por Hamlet en la obra de Shakespeare (1600).","Hamlet reflexiona sobre el suicidio y el sentido de la existencia: ¿es mejor sufrir los males de la vida o acabar con ellos mediante la muerte?","El monólogo ha sido interpretado de mil maneras: como reflexión filosófica, como cobardía disfrazada de profundidad, como crisis existencial moderna — su ambigüedad es su grandeza."];

DEEP_DIVES['quote5'].es = ["«Dios ha muerto» de Nietzsche (La gaya ciencia, 1882) no es una declaración atea sino un diagnóstico cultural: la sociedad occidental ha dejado de creer en los valores cristianos.","Para Nietzsche, la muerte de Dios no era motivo de celebración sino de angustia: sin fundamento trascendente, ¿cómo distinguir el bien del mal? ¿Cómo dar sentido a la vida?","La respuesta de Nietzsche fue el Übermensch (superhombre): un ser capaz de crear sus propios valores y vivir sin muletas metafísicas — una idea frecuentemente malinterpretada."];

DEEP_DIVES['quote6'].es = ["«Eureka!» (¡Lo encontré!) fue supuestamente gritado por Arquímedes al descubrir en su bañera el principio del desplazamiento de líquidos en el siglo III a.C.","El rey Hierón le había pedido verificar si su corona era de oro puro sin dañarla — Arquímedes comprendió que podía medir el volumen sumergiendo la corona en agua.","La anécdota de Arquímedes corriendo desnudo por las calles de Siracusa es probablemente legendaria, pero el principio científico es real y sigue siendo fundamental en la física."];

DEEP_DIVES['quote7'].es = ["«El Estado soy yo» (L'État, c'est moi), atribuido a Luis XIV de Francia, encarna el absolutismo monárquico — aunque los historiadores dudan de que realmente lo dijera.","Luis XIV centralizó el poder de forma sin precedentes, construyó Versalles como símbolo de su autoridad y reinó 72 años — el reinado más largo de la historia europea.","Paradójicamente, su bisnieto Luis XVI perdió la cabeza en la guillotina durante la Revolución Francesa — del poder absoluto a la ejecución pública en tres generaciones."];

DEEP_DIVES['quote8'].es = ["«Dadme un punto de apoyo y moveré el mundo» es atribuido a Arquímedes para ilustrar el principio de la palanca — una de las máquinas simples fundamentales de la física.","La palanca multiplica la fuerza aplicada: con una palanca suficientemente larga, una persona podría teóricamente levantar cualquier peso — el principio es real, la aplicación cósmica es metafórica.","Arquímedes fue uno de los mayores científicos de la Antigüedad: inventó la polea compuesta, el tornillo sin fin y máquinas de guerra que defendieron Siracusa contra los romanos."];

DEEP_DIVES['quote9'].es = ["«La imaginación es más importante que el conocimiento» de Einstein refleja su método de trabajo: los experimentos mentales (Gedankenexperiment) fueron su herramienta principal.","Einstein imaginó perseguir un rayo de luz a los 16 años — esa fantasía adolescente lo llevó a la relatividad especial una década después.","La frase subraya que el conocimiento es limitado por lo que ya sabemos, mientras que la imaginación puede explorar lo desconocido — una filosofía de la ciencia profundamente creativa."];

DEEP_DIVES['quote10'].es = ["«Veni, vidi, vici» (Vine, vi, vencí) fue el mensaje que Julio César envió al Senado romano tras su rápida victoria en la batalla de Zela (47 a.C.).","La brevedad del mensaje era deliberada: César quería mostrar que la victoria había sido tan fácil que no merecía más de tres palabras.","César era un maestro de la comunicación política: sus Comentarios sobre la Guerra de las Galias son tanto obras literarias como propaganda personal brillantemente construida."];

DEEP_DIVES['quote11'].es = ["«Que coman pasteles» (Qu'ils mangent de la brioche), atribuido a María Antonieta, nunca fue dicho por ella — la anécdota aparece en Rousseau antes de que María Antonieta llegara a Francia.","La frase simboliza la desconexión de la aristocracia con el sufrimiento del pueblo — un tópico que alimentó la propaganda revolucionaria.","María Antonieta fue ejecutada en 1793 a los 37 años — su imagen de reina frívola y derrochadora ha sido parcialmente rehabilitada por los historiadores modernos."];

DEEP_DIVES['quote12'].es = ["«El conocimiento es poder» (Scientia potentia est) se atribuye a Francis Bacon (1597), quien argumentaba que el saber empírico permitía dominar la naturaleza.","Bacon fue el padre del método científico moderno: observación, hipótesis, experimentación y verificación — un proceso que revolucionó la manera de conocer el mundo.","La frase adquiere un significado nuevo en la era digital: los datos son el nuevo poder, y quien controla la información controla la sociedad."];

DEEP_DIVES['quote13'].es = ["«Un pequeño paso para el hombre, un gran salto para la humanidad» fue dicho por Neil Armstrong al pisar la Luna el 20 de julio de 1969.","Armstrong afirmó haber dicho «un pequeño paso para un hombre» (a man), pero la grabación es ambigua — la partícula «a» se perdió en la transmisión o nunca fue pronunciada.","La frase fue preparada de antemano por Armstrong, quien la mantuvo en secreto incluso de la NASA — un momento de elocuencia personal en el mayor evento tecnológico de la historia."];

DEEP_DIVES['quote14'].es = ["«La única cosa que debemos temer es el miedo mismo» fue dicho por Franklin D. Roosevelt en su discurso inaugural de 1933, en plena Gran Depresión.","Roosevelt buscaba restaurar la confianza de una nación paralizada por el pánico bancario: el miedo colectivo era tan destructivo como la crisis económica misma.","El New Deal de Roosevelt transformó el papel del gobierno federal en la economía — sus programas de empleo público y regulación bancaria establecieron el Estado de bienestar moderno en EE.UU."];

DEEP_DIVES['quote15'].es = ["«I have a dream» (Tengo un sueño) fue pronunciado por Martin Luther King Jr. el 28 de agosto de 1963 ante 250 000 personas en Washington D.C.","La parte más memorable del discurso fue improvisada: Mahalia Jackson gritó «¡Cuéntales lo del sueño, Martin!» y King abandonó su texto preparado.","El discurso aceleró la aprobación del Civil Rights Act (1964) y del Voting Rights Act (1965) — dos leyes que transformaron la sociedad estadounidense."];

DEEP_DIVES['quote16'].es = ["«Lo esencial es invisible a los ojos» del Principito de Saint-Exupéry (1943) es una de las citas literarias más universales, usada en contextos que van de la filosofía al marketing.","La frase la pronuncia el zorro al Principito al enseñarle el significado de la amistad: «Solo se ve bien con el corazón».","Saint-Exupéry era piloto de guerra y desapareció durante una misión en 1944 — su obra literaria refleja una búsqueda constante de sentido en un mundo violento."];

DEEP_DIVES['quote17'].es = ["«Sapere aude» (Atrévete a saber) fue adoptado por Kant en 1784 como lema de la Ilustración — una llamada a pensar por uno mismo sin recurrir a la autoridad de otros.","La frase original es de Horacio (siglo I a.C.), pero Kant la convirtió en el grito de batalla de la razón autónoma contra la superstición, el dogma y la tradición ciega.","La Ilustración transformó Occidente: separación de poderes, derechos humanos, libertad de prensa, educación pública y método científico son hijos directos de este movimiento."];

DEEP_DIVES['quote18'].es = ["«El infierno son los otros» (L'enfer, c'est les autres) de Jean-Paul Sartre (Huis clos, 1944) no significa que las personas sean malas, sino que la mirada del otro nos define y nos limita.","En la obra, tres personajes muertos descubren que su castigo eterno no es fuego ni tormentos sino la presencia perpetua de los otros, sin posibilidad de estar solos.","Sartre fue el padre del existencialismo francés: la existencia precede a la esencia, somos libres de elegir y responsables de nuestras elecciones — una filosofía de libertad radical."];

DEEP_DIVES['quote19'].es = ["«La pluma es más poderosa que la espada» de Edward Bulwer-Lytton (1839) argumenta que la escritura, la comunicación y las ideas tienen más impacto que la fuerza militar.","La historia confirma esta idea: las obras de Voltaire, Marx, Paine y Luther transformaron sociedades enteras sin ejércitos — las revoluciones nacen primero en los textos.","En la era digital, la frase adquiere nueva fuerza: un tweet, un vídeo viral o un artículo pueden movilizar a millones de personas en horas."];

DEEP_DIVES['quote20'].es = ["«Conócete a ti mismo» (Gnōthi seauton) estaba inscrito en el templo de Apolo en Delfos — un mandato que Sócrates adoptó como principio filosófico fundamental.","El autoconocimiento es la base de la ética socrática: solo quien se conoce puede actuar con virtud, porque la ignorancia de uno mismo es la raíz de todos los males.","La psicología moderna confirma esta intuición: la metacognición (pensar sobre el propio pensamiento) es una de las habilidades más importantes para el bienestar y la toma de decisiones."];

DEEP_DIVES['quote21'].es = ["«Carpe diem» (Aprovecha el día) de Horacio (Odas, 23 a.C.) no es una invitación al hedonismo sino al disfrute consciente del presente ante la certeza de la muerte.","La frase completa es «Carpe diem, quam minimum credula postero» — aprovecha el día, confiando lo menos posible en el mañana.","Robin Williams inmortalizó la expresión en El club de los poetas muertos (1989), conectando la poesía latina con la rebeldía adolescente y la urgencia de vivir."];

DEEP_DIVES['quote22'].es = ["«El poder corrompe, y el poder absoluto corrompe absolutamente» fue escrito por Lord Acton en 1887 en una carta sobre la infalibilidad papal.","Acton era católico pero se opuso al dogma de la infalibilidad del papa — su frase trasciende el contexto religioso y se aplica a toda forma de poder sin control.","La separación de poderes (legislativo, ejecutivo, judicial) propuesta por Montesquieu es la respuesta institucional a esta observación: ningún poder debe ser absoluto."];

DEEP_DIVES['quote23'].es = ["«La vida es lo que pasa mientras estás ocupado haciendo otros planes» apareció en la canción Beautiful Boy de John Lennon (1980), pero versiones anteriores existen desde los años 1950.","Lennon escribió la canción para su hijo Sean y fue asesinado pocas semanas después de su publicación — una coincidencia trágica que otorgó a la frase un significado profético.","La cita captura una verdad psicológica: nuestra obsesión por planificar el futuro nos impide vivir el presente — un tema central de la filosofía budista y la psicología positiva."];

DEEP_DIVES['quote24'].es = ["«No es la especie más fuerte la que sobrevive, ni la más inteligente, sino la que mejor responde al cambio» se atribuye erróneamente a Darwin.","Darwin nunca escribió esta frase: fue formulada por Leon Megginson, un profesor de administración, en 1963 como interpretación libre de El origen de las especies.","Sin embargo, la idea captura la esencia de la selección natural: la adaptabilidad, no la fuerza bruta, es la clave de la supervivencia — un principio válido tanto en biología como en los negocios."];

DEEP_DIVES['quote25'].es = ["«La locura es hacer lo mismo una y otra vez esperando resultados diferentes» se atribuye falsamente a Einstein — no hay ninguna evidencia de que la dijera.","La frase aparece por primera vez en un folleto de Narcóticos Anónimos de 1981 — su atribución a Einstein es un ejemplo clásico de cita apócrifa.","Las citas falsas son un fenómeno antiguo: atribuir una frase a una autoridad reconocida le otorga credibilidad instantánea — algo que las redes sociales han amplificado exponencialmente."];

DEEP_DIVES['quote26'].es = ["«Hasta la victoria siempre» es la frase icónica del Che Guevara, convertida en eslogan revolucionario en toda América Latina y más allá.","Guevara fue médico, guerrillero, ministro y finalmente mártir: ejecutado en Bolivia en 1967, su imagen se convirtió en el póster más reproducido del siglo XX.","Su legado divide profundamente: héroe de la revolución para unos, símbolo de violencia política para otros — la realidad histórica es más compleja que el mito."];

DEEP_DIVES['quote27'].es = ["«Elemental, mi querido Watson» nunca fue dicho por Sherlock Holmes en los libros de Arthur Conan Doyle — la frase fue inventada para las adaptaciones teatrales y cinematográficas.","Holmes dice «Elementary» en varias ocasiones y se dirige a «mi querido Watson», pero nunca combina ambas expresiones en una sola frase.","Es una de las citas falsas más famosas de la historia de la ficción — junto con «Play it again, Sam» (nunca dicho en Casablanca) y «Luke, yo soy tu padre» (ligeramente diferente en Star Wars)."];

DEEP_DIVES['quote28'].es = ["«Solo los muertos han visto el final de la guerra» se atribuye erróneamente a Platón — fue escrito por el filósofo George Santayana en 1922.","Santayana también escribió «Aquellos que no recuerdan el pasado están condenados a repetirlo» — una de las citas más citadas en contextos políticos e históricos.","El error de atribución persiste porque dar a Platón la autoría de una frase sobre la guerra le otorga una autoridad milenaria que Santayana, menos conocido, no posee."];

DEEP_DIVES['quote29'].es = ["«Sé el cambio que deseas ver en el mundo» se atribuye a Gandhi, pero nunca dijo esta frase exacta — es una paráfrasis simplificada de sus escritos.","Lo que Gandhi escribió es más matizado: que si cambiamos nosotros mismos, cambiamos el mundo, porque somos parte inseparable de él — una idea de transformación interior más profunda que un eslogan.","Las citas simplificadas de grandes pensadores son un fenómeno moderno: reducen ideas complejas a frases compartibles, perdiendo matices esenciales."];

DEEP_DIVES['quote30'].es = ["«Ars longa, vita brevis» (El arte es largo, la vida breve) de Hipócrates (siglo V a.C.) no hablaba del arte sino de la medicina: dominar el oficio requiere más tiempo del que dura una vida.","La frase completa incluye: «la oportunidad es fugaz, la experiencia engañosa, el juicio difícil» — un resumen de la condición humana en una sola oración.","La expresión se ha universalizado: se aplica a cualquier disciplina donde la maestría exige décadas de práctica — música, escritura, ciencia, artesanía."];

// ── LAWS law1-law30 ──

DEEP_DIVES['law1'].es = ["La Ley de Murphy («Todo lo que puede salir mal, saldrá mal») no es una ley científica sino un adagio del ingeniero Edward Murphy, formulado en 1949 durante pruebas de desaceleración en la base Edwards.","Murphy culpó a un técnico que había instalado todos los sensores al revés — su frustración se convirtió en un principio universal de ingeniería: diseña asumiendo que los errores ocurrirán.","La ley tiene una aplicación seria: la ingeniería de seguridad y la aviación diseñan sistemas redundantes precisamente porque asumen que cualquier fallo posible acabará ocurriendo."];

DEEP_DIVES['law2'].es = ["La Ley de Moore (1965) predice que el número de transistores en un microchip se duplica aproximadamente cada dos años, doblando la potencia informática.","Gordon Moore, cofundador de Intel, formuló esta observación como tendencia empírica, no como ley física — y ha resultado asombrosamente precisa durante más de 50 años.","Los físicos predicen el fin de la Ley de Moore porque los transistores se acercan al tamaño atómico — las alternativas incluyen computación cuántica, fotónica y chips 3D."];

DEEP_DIVES['law3'].es = ["La Ley de Pareto (regla 80/20) establece que el 80 % de los efectos proviene del 20 % de las causas — formulada por Vilfredo Pareto al estudiar la distribución de la riqueza en Italia.","Esta proporción aparece en contextos sorprendentes: el 20 % de los clientes genera el 80 % de los ingresos, el 20 % de los bugs causa el 80 % de los fallos, el 20 % del guardarropa se usa el 80 % del tiempo.","La ley no es exacta (puede ser 70/30 o 90/10) pero el principio es robusto: concentrar esfuerzos en los pocos factores que generan la mayor parte del impacto es una estrategia universalmente eficaz."];

DEEP_DIVES['law4'].es = ["La Ley de Godwin (1990) establece que cuanto más se prolonga una discusión en Internet, más se acerca a 1 la probabilidad de que alguien haga una comparación con Hitler o el nazismo.","Mike Godwin formuló esta ley como un experimento memético: quería demostrar que los memes culturales se propagan como virus, y su propia ley se convirtió en el mejor ejemplo.","Godwin ha precisado que su ley no invalida todas las comparaciones con el nazismo — las comparaciones legítimas existen, pero las hiperbólicas trivializan la historia."];

DEEP_DIVES['law5'].es = ["La Ley de Parkinson (1955) establece que «el trabajo se expande hasta llenar el tiempo disponible para completarlo» — formulada por Cyril Northcote Parkinson sobre la burocracia británica.","Parkinson observó que el número de funcionarios del Almirantazgo británico creció un 78 % entre 1914 y 1928, mientras la flota se reducía un 67 % — la burocracia crecía independientemente de la carga real.","La ley se aplica a la productividad personal: fijar plazos más cortos obliga a ser más eficiente — las tareas que «deberían» llevar una semana a menudo se completan en un día si el plazo lo exige."];

DEEP_DIVES['law6'].es = ["La Ley de Hofstadter establece que «las cosas siempre tardan más de lo que esperas, incluso cuando tienes en cuenta la Ley de Hofstadter» — una paradoja autoreferencial deliberada.","Douglas Hofstadter la formuló en Gödel, Escher, Bach (1979) en el contexto de la inteligencia artificial y la complejidad de los proyectos — su recursividad captura un sesgo humano profundo.","Esta ley explica por qué los proyectos de software, las obras públicas y las reformas siempre se retrasan: subestimamos la complejidad incluso cuando sabemos que la subestimamos."];

DEEP_DIVES['law7'].es = ["La Ley de Metcalfe establece que el valor de una red es proporcional al cuadrado del número de usuarios — 10 usuarios generan 100 conexiones potenciales, 100 usuarios generan 10 000.","Esta ley explica el crecimiento explosivo de redes sociales y plataformas: cada nuevo usuario aumenta el valor para todos los demás, creando un efecto de bola de nieve.","Facebook, WhatsApp y TikTok son ejemplos perfectos: su valor no reside en la tecnología sino en la masa crítica de usuarios — una vez alcanzada, es casi imposible que un competidor la desplace."];

DEEP_DIVES['law8'].es = ["La primera ley de la termodinámica establece que la energía no se crea ni se destruye, solo se transforma — un principio fundamental de la física.","Esta ley implica que es imposible crear una máquina de movimiento perpetuo del primer tipo: no se puede obtener energía de la nada.","La segunda ley (la entropía siempre aumenta) es aún más implacable: toda transformación energética genera desperdicio — el universo tiende inevitablemente hacia el desorden."];

DEEP_DIVES['law9'].es = ["La Ley de Cunningham establece que la mejor manera de obtener la respuesta correcta en Internet no es hacer una pregunta sino publicar una respuesta incorrecta.","Ward Cunningham (creador del primer wiki) formuló esta observación sobre la naturaleza humana: las personas son más propensas a corregir errores que a responder preguntas.","Este principio se aplica en redes sociales, foros y Wikipedia — la necesidad de corregir al otro es un impulso más fuerte que la generosidad de compartir conocimiento."];

DEEP_DIVES['law10'].es = ["La Ley de Benford establece que en conjuntos de datos numéricos naturales, el dígito 1 aparece como primer dígito el 30 % de las veces, no el 11 % que esperaríamos si la distribución fuera uniforme.","Esta distribución logarítmica aparece en datos tan diversos como poblaciones de ciudades, cotizaciones bursátiles, caudales de ríos y declaraciones de impuestos.","Las autoridades fiscales y los auditores usan la Ley de Benford para detectar fraudes: los datos fabricados tienden a tener una distribución de dígitos demasiado uniforme, delatando la manipulación."];

DEEP_DIVES['law11'].es = ["Las tres leyes de Newton (1687) revolucionaron la física: inercia, F=ma y acción-reacción — con ellas se puede explicar desde la caída de una manzana hasta la órbita de los planetas.","Newton formuló estas leyes en los Principia Mathematica, considerado el libro científico más importante jamás publicado.","Las leyes de Newton funcionan perfectamente a escalas humanas, pero fallan a velocidades cercanas a la luz (donde rige la relatividad de Einstein) y a escalas subatómicas (donde rige la mecánica cuántica)."];

DEEP_DIVES['law12'].es = ["La Ley de Brandolini (principio de asimetría del bullshit) establece que desmentir una falsedad requiere un orden de magnitud más esfuerzo que producirla.","En la era de la desinformación, esta ley explica por qué los bulos se propagan más rápido que las correcciones: una mentira se tuitea en segundos, desmentirla requiere investigación, datos y argumentos.","Los verificadores de hechos (fact-checkers) luchan contra esta asimetría a diario — pero sus correcciones alcanzan a una fracción de la audiencia que vio la información falsa original."];

DEEP_DIVES['law13'].es = ["La Ley de la gravedad de Newton (1687) establece que todos los cuerpos se atraen con una fuerza proporcional al producto de sus masas e inversamente proporcional al cuadrado de la distancia.","Newton supuestamente concibió la idea al ver caer una manzana — la anécdota es probablemente exagerada pero ilustra su genio: conectó un fenómeno cotidiano con el movimiento de los planetas.","Einstein corrigió a Newton con la relatividad general (1915): la gravedad no es una fuerza sino una curvatura del espacio-tiempo causada por la masa — un concepto radicalmente diferente."];

DEEP_DIVES['law14'].es = ["La Ley de Sturgeon establece que «el 90 % de todo es basura» — una generalización provocadora formulada por el escritor de ciencia ficción Theodore Sturgeon en los años 1950.","Sturgeon respondía a los críticos que despreciaban la ciencia ficción señalando que el 90 % de cualquier campo (literatura, cine, academia) es igualmente mediocre — la calidad siempre es la excepción.","La ley se aplica especialmente bien a Internet, donde la abundancia de contenido diluye la calidad: encontrar el 10 % valioso es el verdadero desafío de la era digital."];

DEEP_DIVES['law15'].es = ["La Ley de Goodhart establece que «cuando una medida se convierte en objetivo, deja de ser una buena medida» — formulada por el economista Charles Goodhart en 1975.","Los hospitales que optimizan las listas de espera rechazan pacientes complejos; las escuelas que optimizan los exámenes enseñan para el test — la métrica se cumple pero el objetivo real se pierde.","En tecnología, esta ley explica los problemas de las métricas de redes sociales: optimizar para «engagement» produce contenido adictivo y polarizante, no necesariamente valioso."];

DEEP_DIVES['law16'].es = ["La Ley de Hanlon aconseja «no atribuir a la malicia lo que puede explicarse por la incompetencia» — un principio de caridad interpretativa muy útil en la vida cotidiana.","En las organizaciones, la mayoría de los problemas no son conspiraciones sino errores de comunicación, falta de información o malas decisiones tomadas con buenas intenciones.","Aplicar esta ley reduce la paranoia y el conflicto: asumir incompetencia antes que malicia facilita la resolución de problemas y preserva las relaciones."];

DEEP_DIVES['law17'].es = ["La Ley de Brooks establece que «añadir personas a un proyecto de software retrasado lo retrasa aún más» — formulada por Fred Brooks en The Mythical Man-Month (1975).","Los nuevos miembros necesitan formación, la comunicación se vuelve más compleja (n personas generan n(n-1)/2 canales) y el trabajo de coordinación supera el beneficio de los recursos adicionales.","Esta ley sigue siendo ignorada por los gestores de proyectos medio siglo después — es uno de los principios más citados y menos aplicados de la ingeniería del software."];

DEEP_DIVES['law18'].es = ["La Ley de Amara establece que «tendemos a sobreestimar el efecto de una tecnología a corto plazo y a subestimarlo a largo plazo».","Internet, los smartphones y la IA siguieron exactamente este patrón: burbujas de expectativas excesivas seguidas de desilusión, antes de transformar silenciosamente la sociedad.","La ley explica los ciclos de hype tecnológico (Gartner Hype Cycle): entusiasmo, desilusión, adopción real — la tecnología que realmente importa no es la que genera más titulares al principio."];

DEEP_DIVES['law19'].es = ["La Ley de Amdahl establece que la mejora máxima de un sistema está limitada por la fracción que no puede ser paralelizada — si el 25 % de una tarea es secuencial, duplicar los procesadores solo mejora un 33 %.","Esta ley es fundamental en informática: añadir más CPUs tiene rendimientos decrecientes porque siempre existe un cuello de botella secuencial.","El principio se aplica más allá de la informática: en cualquier proceso, identificar y optimizar el cuello de botella es más eficaz que mejorar las partes que ya funcionan bien."];

DEEP_DIVES['law20'].es = ["La Ley de Zipf establece que en cualquier idioma, la frecuencia de una palabra es inversamente proporcional a su rango: la segunda más frecuente aparece la mitad de veces que la primera, la tercera un tercio, etc.","En español, «de» es la palabra más frecuente (7 % de todas las palabras), seguida de «la», «que», «el» y «en» — las 100 palabras más comunes cubren más del 50 % de cualquier texto.","La ley de Zipf aparece en fenómenos dispares: tamaño de ciudades, distribución de ingresos, visitas a páginas web — una universalidad que los matemáticos aún no explican completamente."];

DEEP_DIVES['law21'].es = ["La navaja de Ockham (siglo XIV) establece que, entre dos explicaciones igualmente válidas, la más simple es probablemente la correcta.","Guillermo de Ockham no buscaba la simplicidad por estética sino por eficacia: las explicaciones innecesariamente complejas introducen más posibilidades de error.","La navaja de Ockham es un principio guía de la ciencia moderna: las teorías más elegantes (E=mc², la selección natural) suelen ser las más poderosas."];

DEEP_DIVES['law22'].es = ["La Ley de los rendimientos decrecientes establece que añadir más de un factor productivo (trabajo, capital) eventualmente produce incrementos cada vez menores de resultado.","El primer fertilizante en un campo mejora mucho la cosecha, el segundo algo menos, el tercero apenas — más allá de cierto punto, añadir más empeora la situación.","Esta ley explica por qué más horas de trabajo no siempre significan más productividad: después de cierto umbral, la fatiga reduce la calidad y la creatividad."];

DEEP_DIVES['law23'].es = ["La Ley de Fitts establece que el tiempo para alcanzar un objetivo con el cursor depende de la distancia al objetivo y de su tamaño — a mayor distancia o menor tamaño, más tiempo.","Esta ley de 1954 es fundamental en diseño de interfaces: los botones importantes deben ser grandes y estar cerca del cursor — es la razón por la que los menús de macOS están en el borde de la pantalla.","Cada vez que un botón te parece fácil de pulsar o un menú se siente intuitivo, probablemente un diseñador ha aplicado la Ley de Fitts sin que lo sepas."];

DEEP_DIVES['law24'].es = ["La Ley de Dunbar establece que un ser humano puede mantener relaciones sociales estables con un máximo de unas 150 personas.","Robin Dunbar correlacionó el tamaño del neocórtex de los primates con el tamaño de sus grupos sociales y extrapoló para los humanos — 150 aparece en tribus, compañías militares y pueblos tradicionales.","Las redes sociales permiten tener miles de «amigos» pero las investigaciones confirman que el círculo de relaciones significativas sigue siendo de unas 150, con 5 íntimos y 15 cercanos."];

DEEP_DIVES['law25'].es = ["La Ley de Campbell establece que cuanto más se usa un indicador cuantitativo para tomar decisiones sociales, más sujeto está a la corrupción y más distorsiona los procesos que pretende medir.","Los ránkings universitarios son un ejemplo perfecto: las universidades optimizan los criterios medidos (publicaciones, selectividad) en lugar de mejorar la educación real.","La solución no es eliminar las métricas sino usar múltiples indicadores, cambiarlos periódicamente y complementarlos con evaluaciones cualitativas."];

DEEP_DIVES['law26'].es = ["La paradoja de Fermi pregunta: si el universo es tan grande y antiguo, ¿dónde están todas las civilizaciones extraterrestres? — formulada por el físico Enrico Fermi en 1950.","Estadísticamente, deberían existir miles de civilizaciones avanzadas en nuestra galaxia — pero no hemos detectado ninguna señal, lo que constituye el «Gran Silencio».","Las explicaciones van desde la hipótesis del «Gran Filtro» (las civilizaciones se autodestruyen) hasta la del «Zoo» (nos observan sin intervenir) — ninguna es satisfactoria."];

DEEP_DIVES['law27'].es = ["La Ley de Say establece que «la oferta crea su propia demanda» — un principio de la economía clásica que Keynes cuestionó durante la Gran Depresión.","Say argumentaba que producir bienes genera los ingresos necesarios para comprarlos — pero Keynes demostró que el ahorro excesivo puede romper este ciclo, causando recesiones.","El debate Say vs Keynes sigue vivo: los liberales confían en el mercado (oferta), los keynesianos en el estímulo estatal (demanda) — la mayoría de las economías modernas combinan ambos enfoques."];

DEEP_DIVES['law28'].es = ["La Ley de Gresham establece que «la moneda mala expulsa a la buena» — cuando dos monedas coexisten, la gente gasta la de menor valor y acumula la de mayor valor.","En la historia, esto se observó cuando los gobiernos adulteraban las monedas de oro y plata: los ciudadanos guardaban las monedas puras y circulaban las degradadas.","El principio se aplica más allá de la economía: en plataformas digitales, el contenido de baja calidad tiende a expulsar al de alta calidad cuando ambos compiten por la misma atención."];

DEEP_DIVES['law29'].es = ["La Ley de Peter (1969) establece que «en una jerarquía, todo empleado tiende a ascender hasta su nivel de incompetencia» — un principio que explica la mediocridad organizacional.","Un empleado excelente en su puesto es promovido hasta alcanzar un puesto donde no es competente — y allí se queda, porque ya no merece otra promoción.","La solución propuesta es la «inversión de Peter»: promover aleatoriamente produce mejores resultados estadísticos que promover por mérito pasado, porque el talento en un puesto no predice el talento en el siguiente."];

DEEP_DIVES['law30'].es = ["La Ley de Lindy establece que la esperanza de vida futura de una idea, libro o tecnología es proporcional a su edad actual — lo que ha durado mucho probablemente durará mucho más.","Un libro que lleva 200 años imprimiéndose probablemente seguirá otros 200 — mientras que un bestseller reciente tiene menos probabilidades de sobrevivir una generación.","Nassim Taleb popularizó esta idea: la tecnología más antigua (ruedas, libros, lápices) suele ser más robusta que la más reciente — la novedad no implica superioridad."];

// ── TALES tale1-tale30 ──

DEEP_DIVES['tale1'].es = ["Cenicienta es uno de los cuentos más universales del mundo: más de 500 versiones existen en culturas de todos los continentes, la más antigua es la china Ye Xian (siglo IX).","En la versión de los hermanos Grimm, las hermanastras se cortan los dedos de los pies para que les quepa el zapato — las palomas delatan la sangre y les arrancan los ojos al final.","El zapato de cristal podría ser un error de traducción de Perrault: «verre» (cristal) en lugar de «vair» (piel de ardilla) — un debate que nunca ha sido zanjado definitivamente."];

DEEP_DIVES['tale2'].es = ["Caperucita Roja es un cuento de advertencia cuyas versiones más antiguas, anteriores a Perrault (1697), terminaban con el lobo devorando a la niña sin rescate posible.","La versión de los Grimm (1812) añadió al cazador que abre el vientre del lobo para salvar a Caperucita y a la abuela — una resolución moral ausente en el original francés.","Los psicoanalistas interpretan el cuento como una alegoría sexual: el lobo representa el depredador masculino y la caperuza roja la transición de la infancia a la pubertad."];

DEEP_DIVES['tale3'].es = ["Las fábulas de Esopo (siglo VI a.C.) son las más antiguas y difundidas de Occidente: la tortuga y la liebre, la cigarra y la hormiga, el lobo con piel de cordero.","Esopo era supuestamente un esclavo frigio que obtuvo su libertad gracias a su ingenio — pero su existencia histórica es incierta y muchas fábulas atribuidas a él son posteriores.","La fábula como género moralizante existe en todas las culturas: el Panchatantra indio (200 a.C.) influyó en las fábulas árabes, que a su vez influyeron en las europeas de La Fontaine."];

DEEP_DIVES['tale4'].es = ["Hansel y Gretel refleja el horror real de las hambrunas medievales europeas, donde el abandono de niños era una práctica documentada durante las crisis alimentarias.","La casa de dulces es una trampa que representa la seducción del exceso: la bruja ofrece abundancia para atraer, engordar y devorar — una metáfora del peligro de la gula y la codicia.","Los Grimm suavizaron el cuento en ediciones sucesivas: en la versión original, era la madre biológica (no la madrastra) quien abandonaba a los niños — demasiado perturbador incluso para el siglo XIX."];

DEEP_DIVES['tale5'].es = ["Las Mil y Una Noches es una compilación de cuentos persas, árabes e indios cuya versión más antigua conocida data del siglo VIII — fue ampliada durante siglos por diferentes narradores.","La estructura de cajas chinas (cuentos dentro de cuentos dentro de cuentos) prefigura la metaficción postmoderna por más de un milenio.","Aladino y Ali Baba, los cuentos más famosos, no figuraban en los manuscritos originales: fueron añadidos por el traductor francés Antoine Galland en 1704 a partir de un cuentista sirio."];

DEEP_DIVES['tale6'].es = ["La Bella y la Bestia fue escrita por primera vez por Gabrielle-Suzanne de Villeneuve en 1740, luego abreviada por Jeanne-Marie Leprince de Beaumont en 1756.","El cuento es una alegoría sobre el matrimonio arreglado: la Bella aprende a amar a un esposo impuesto al descubrir sus cualidades interiores — un mensaje consolador para las jóvenes de la época.","La versión de Disney (1991) fue la primera película de animación nominada al Oscar a la Mejor Película — un logro que elevó el cine de animación a la categoría de arte para todas las edades."];

DEEP_DIVES['tale7'].es = ["El Gato con Botas de Perrault (1697) es un cuento sobre la astucia y la movilidad social: un gato astuto transforma a su amo pobre en marqués mediante engaños y manipulación.","El cuento celebra la inteligencia práctica sobre la nobleza de nacimiento — un tema subversivo en la Francia absolutista de Luis XIV.","Variantes del gato astuto existen en culturas de todo el mundo: desde el zorro japonés (kitsune) hasta el Anansi africano — el embaucador que usa su ingenio para vencer a los poderosos."];

DEEP_DIVES['tale8'].es = ["Blancanieves de los Grimm (1812) tiene raíces que podrían remontarse a la historia real de Margarethe von Waldeck, una condesa alemana del siglo XVI envenenada por motivos políticos.","El espejo mágico simboliza la obsesión narcisista por la belleza y la juventud — un tema que resuena hoy tanto como en el siglo XIX.","Los siete enanitos no tenían nombres individuales hasta la película de Disney (1937): Grumpy, Sleepy, Bashful, Happy, Sneezy, Dopey y Doc son creaciones de Hollywood."];

DEEP_DIVES['tale9'].es = ["Pinocho, escrito por Carlo Collodi en 1883, era originalmente una historia moralizante y bastante oscura: Pinocho es ahorcado en el capítulo 15 — los lectores exigieron una continuación.","La nariz que crece al mentir no es solo un recurso cómico sino una metáfora de la transparencia: en el mundo del cuento, la mentira es imposible de ocultar.","La versión de Disney (1940) suavizó enormemente la historia: el Pinocho original es desobediente, cruel y violento — un niño que necesita disciplina, no magia."];

DEEP_DIVES['tale10'].es = ["La sirenita de Hans Christian Andersen (1837) no tiene un final feliz: la sirenita no consigue el amor del príncipe y se transforma en espuma de mar en lugar de obtener un alma inmortal.","Andersen escribió el cuento como alegoría de su amor no correspondido por Edvard Collin — el dolor del sacrificio y la transformación refleja su propia experiencia sentimental.","La versión de Disney (1989) cambió el final trágico por un matrimonio feliz — una decisión que transformó una fábula sobre el sufrimiento en una historia de empoderamiento femenino (parcial)."];

DEEP_DIVES['tale11'].es = ["El patito feo de Andersen (1843) es la historia autobiográfica del propio autor: un niño danés pobre, feo y ridiculizado que se convirtió en el escritor de cuentos más famoso del mundo.","La metáfora de la transformación — de patito rechazado a cisne admirado — es tan poderosa que «patito feo» se ha convertido en expresión universal para describir una transformación positiva.","Andersen sufrió toda su vida de inseguridades y nunca encontró el amor correspondido — sus cuentos más bellos nacieron del dolor y la soledad."];

DEEP_DIVES['tale12'].es = ["Los cuentos de hadas no eran para niños: eran relatos orales para adultos transmitidos durante siglos junto al fuego, llenos de violencia, sexo y crueldad.","Charles Perrault (1697) y los hermanos Grimm (1812) los recopilaron y suavizaron para un público burgués — Disney completó la sanitización en el siglo XX.","Autores como Angela Carter, Neil Gaiman y la serie Once Upon a Time han recuperado la oscuridad original de los cuentos, demostrando que su poder reside en los temas adultos que abordan."];

DEEP_DIVES['tale13'].es = ["Robin Hood, el forajido que robaba a los ricos para dar a los pobres, aparece por primera vez en baladas inglesas del siglo XIII — pero su existencia histórica nunca ha sido probada.","Las primeras versiones lo presentan como un yeoman (campesino libre), no como un noble desposeído — la aristocratización del personaje es posterior.","Robin Hood encarna un arquetipo universal: el rebelde justo que desafía la autoridad corrupta — una figura que reaparece en cada generación, de Zorro a V de Vendetta."];

DEEP_DIVES['tale14'].es = ["Rapunzel fue recopilado por los Grimm en 1812, pero versiones similares existen en la tradición persa (Rudaba) y la napolitana (Petrosinella, 1634) desde siglos antes.","La torre sin puerta es un símbolo del encierro femenino y el control parental excesivo — el cabello como escalera representa la conexión prohibida con el mundo exterior.","En la versión original de los Grimm, Rapunzel queda embarazada del príncipe durante sus visitas secretas — un detalle eliminado en ediciones posteriores por considerarse inapropiado."];

DEEP_DIVES['tale15'].es = ["La leyenda de la Llorona, presente en toda Latinoamérica, narra la historia de una mujer que ahoga a sus hijos y vaga eternamente llorando y buscándolos.","Sus orígenes podrían remontarse a la diosa azteca Cihuacóatl o a la Malinche — la leyenda fusiona elementos prehispánicos y coloniales.","La Llorona funciona como cuento de advertencia: los niños no deben acercarse al agua de noche, y las mujeres que desobedecen las normas sociales sufren castigos eternos."];

DEEP_DIVES['tale16'].es = ["Pedro y el lobo de Prokófiev (1936) fue compuesto como obra pedagógica para enseñar a los niños los instrumentos de la orquesta: cada personaje es representado por un instrumento diferente.","Pedro es la cuerda, el pájaro la flauta, el pato el oboe, el gato el clarinete, el abuelo el fagot, el lobo las trompas y los cazadores los timbales y el bombo.","La obra se ha convertido en una de las piezas de música clásica más interpretadas del mundo y ha sido narrada por celebridades de David Bowie a Sofía Vergara."];

DEEP_DIVES['tale17'].es = ["El Rey Midas, según la mitología griega, pidió a Dioniso el poder de convertir en oro todo lo que tocara — un deseo que pronto se convirtió en maldición.","No podía comer, beber ni abrazar a su hija sin convertirlos en metal inerte — una parábola sobre la codicia y las consecuencias imprevistas de los deseos materiales.","La expresión «tener el toque de Midas» se usa hoy para describir a alguien que todo lo que toca se convierte en éxito — un uso irónico que olvida el aspecto trágico del mito original."];

DEEP_DIVES['tale18'].es = ["Barba Azul de Perrault (1697) narra la historia de un noble que asesina a sus esposas y guarda sus cuerpos en una habitación prohibida.","El cuento es una advertencia sobre la curiosidad femenina (la esposa desobedece la prohibición) pero también una denuncia de la violencia doméstica y el poder masculino sin límites.","Barba Azul tiene paralelos históricos: Gilles de Rais (siglo XV), compañero de Juana de Arco y asesino en serie, y Enrique VIII, que ejecutó a dos de sus seis esposas."];

DEEP_DIVES['tale19'].es = ["La tortuga y la liebre de Esopo enseña que la constancia vence al talento cuando el talento se confía demasiado — una de las lecciones más citadas de la literatura universal.","La fábula tiene raíces filosóficas profundas: la paradoja de Zenón sobre Aquiles y la tortuga plantea la imposibilidad teórica de que el rápido alcance al lento, un problema matemático serio.","En el mundo moderno, la fábula se aplica a las carreras profesionales, las startups y el aprendizaje: la persistencia supera al talento natural cuando este carece de disciplina."];

DEEP_DIVES['tale20'].es = ["Los cuentos de Nasrudín (también Nasreddin o Joha) son fábulas humorísticas de la tradición islámica protagonizadas por un sabio-loco que enseña mediante paradojas y absurdos.","Nasrudín existe en las tradiciones turca, persa, árabe y centroasiática desde el siglo XIII — sus historias se transmiten oralmente y varían según la región.","Sus cuentos funcionan en múltiples niveles: son chistes superficiales para los niños, lecciones morales para los adultos y koans filosóficos para los buscadores espirituales."];

DEEP_DIVES['tale21'].es = ["La Bella Durmiente tiene versiones que preceden a Perrault y los Grimm: la más antigua conocida, Sol, Luna y Talía de Basile (1634), es mucho más oscura.","En la versión de Basile, el rey no despierta a la princesa con un beso sino que la viola mientras duerme — ella se despierta nueve meses después al dar a luz gemelos.","La evolución del cuento refleja el cambio de las normas sociales: cada época suaviza los elementos más perturbadores para adaptarlos a su propia sensibilidad moral."];

DEEP_DIVES['tale22'].es = ["Los cuentos africanos de Anansi la araña se extendieron por el Caribe y América a través de la trata de esclavos, transformándose en las historias de Brer Rabbit en el sur de EE.UU.","Anansi siempre vence a oponentes más fuertes mediante la astucia — para los esclavos, estas historias eran metáforas de supervivencia y resistencia contra el poder opresor.","Las tradiciones orales africanas transmitían no solo entretenimiento sino conocimiento, historia, valores y estrategias de supervivencia — los cuentos eran bibliotecas vivientes."];

DEEP_DIVES['tale23'].es = ["Jack y las habichuelas mágicas es un cuento inglés del siglo XVIII donde un niño escala un tallo gigante hasta un castillo en las nubes habitado por un ogro.","Jack roba el oro, la gallina de los huevos de oro y el arpa mágica del ogro — y lo mata cortando el tallo — un héroe moralmente ambiguo que triunfa mediante el robo y el asesinato.","El cuento ha sido interpretado como alegoría de la movilidad social, la conquista de lo imposible y la victoria del ingenio sobre la fuerza bruta."];

DEEP_DIVES['tale24'].es = ["El flautista de Hamelín (1284) podría basarse en un hecho histórico real: la desaparición de 130 niños de la ciudad alemana de Hameln.","Las teorías incluyen una emigración masiva hacia Europa del Este (colonización germánica), una epidemia de peste, o un reclutamiento forzado de niños para las Cruzadas.","El cuento advierte sobre las consecuencias de no cumplir las promesas: la ciudad no pagó al flautista por librarla de las ratas, y él se llevó a los niños como venganza."];

DEEP_DIVES['tale25'].es = ["Los hermanos Grimm no inventaron sus cuentos: los recopilaron de tradiciones orales alemanas — aunque los modificaron significativamente para adaptarlos a su público.","Jacob y Wilhelm Grimm eran filólogos y lingüistas que buscaban preservar el folclore germánico — su diccionario de alemán, no los cuentos, era la obra que consideraban más importante.","Las siete ediciones de los Cuentos de los Grimm (1812-1857) muestran una progresiva suavización: madres convertidas en madrastras, violencia atenuada y moralejas reforzadas."];

DEEP_DIVES['tale26'].es = ["Pulgarcita de Andersen (1835) narra la historia de una niña diminuta nacida de una flor que pasa por secuestros, matrimonios forzados y penurias antes de encontrar su lugar.","El cuento refleja la vulnerabilidad de los seres pequeños en un mundo dominado por los grandes — y la perseverancia necesaria para encontrar un hogar donde ser aceptado.","Andersen escribía para los marginados, los diferentes y los incomprendidos — sus cuentos más famosos hablan de identidad, pertenencia y la búsqueda de un lugar en el mundo."];

DEEP_DIVES['tale27'].es = ["Momotarō (el niño melocotón) es el cuento popular más famoso de Japón: un niño nacido de un melocotón gigante parte a derrotar a los oni (demonios) con la ayuda de un perro, un mono y un faisán.","El cuento enseña valores japoneses tradicionales: valentía, lealtad, generosidad y trabajo en equipo — Momotarō recompensa a sus compañeros animales que se unieron a él por su amabilidad.","Momotarō fue usado como propaganda durante la Segunda Guerra Mundial para representar a Japón luchando contra los «demonios» occidentales — un uso político que desnaturalizó un cuento infantil."];

DEEP_DIVES['tale28'].es = ["Baba Yaga es la bruja del folclore eslavo que vive en una cabaña sobre patas de gallina en lo profundo del bosque ruso.","No es simplemente malvada: Baba Yaga puede ayudar o destruir a quien la visita, según su comportamiento — es una guardiana de umbrales entre el mundo de los vivos y el de los muertos.","La cabaña sobre patas de gallina podría basarse en las construcciones elevadas de los pueblos fineses y siberianos, diseñadas para proteger las provisiones de los animales y la humedad."];

DEEP_DIVES['tale29'].es = ["El Popol Vuh maya narra cómo los dioses crearon a los humanos de maíz tras fracasar con el barro y la madera — la humanidad es literalmente «gente de maíz».","Los Héroes Gemelos (Hunahpú e Ixbalanqué) descienden al inframundo (Xibalbá) y vencen a los señores de la muerte mediante juegos, trucos y sacrificio.","El Popol Vuh fue transcrito secretamente por un maya quiché en el siglo XVI para preservar la tradición oral de la destrucción colonial — sin él, gran parte de la cosmología maya se habría perdido."];

DEEP_DIVES['tale30'].es = ["Los cuentos de Sheherezade en Las Mil y Una Noches son el ejemplo más famoso de narrativa como supervivencia: contar historias literalmente le salva la vida noche tras noche.","El poder de la narración es un tema universal: desde las fogatas prehistóricas hasta los podcasts modernos, contar historias es la forma más antigua y eficaz de transmitir conocimiento y emociones.","Las Mil y Una Noches influyeron en la literatura mundial: Borges, Proust, Rushdie y García Márquez reconocieron su deuda con la estructura y la magia narrativa de Sheherezade."];

// ── DINOSAURS dino1-dino30 ──

DEEP_DIVES['dino1'].es = ["Los dinosaurios dominaron la Tierra durante más de 165 millones de años — los humanos llevamos apenas 300 000 años, una fracción insignificante en comparación.","Se extinguieron hace 66 millones de años tras el impacto de un asteroide de 10 km de diámetro en Chicxulub (actual México), que provocó un invierno global y extinguió al 75 % de las especies.","Sin embargo, los dinosaurios no desaparecieron del todo: las aves son dinosaurios terópodos que sobrevivieron a la extinción — técnicamente, vivimos rodeados de dinosaurios."];

DEEP_DIVES['dino2'].es = ["El Tyrannosaurus rex medía hasta 12 metros de largo, pesaba unas 8 toneladas y poseía la mordedura más potente de todos los animales terrestres conocidos: más de 5 800 kg de fuerza.","Sus brazos diminutos siguen siendo un misterio evolutivo: algunas hipótesis sugieren que servían para sujetar presas durante el apareamiento o para levantarse del suelo.","El T. rex no podía correr a la velocidad que muestra Jurassic Park: estudios biomecánicos sugieren una velocidad máxima de unos 20 km/h — rápido para su tamaño, pero no un velocista."];

DEEP_DIVES['dino3'].es = ["El Velociraptor real era mucho más pequeño que el de Jurassic Park: apenas medía 2 metros de largo y 50 cm de alto — del tamaño de un pavo grande.","Tenía plumas y probablemente se parecía más a un ave depredadora que a un reptil escamoso — la imagen cinematográfica es científicamente incorrecta.","Los «raptores» de Jurassic Park están basados en el Deinonychus, un pariente mayor y más impresionante — Spielberg usó el nombre Velociraptor porque le parecía más dramático."];

DEEP_DIVES['dino4'].es = ["Los saurópodos (Brachiosaurus, Argentinosaurus, Diplodocus) fueron los animales más grandes que han caminado sobre la Tierra: hasta 40 metros de largo y 70 toneladas.","Para mantener su enorme cuerpo, comían hasta 400 kg de vegetación al día — su largo cuello les permitía alcanzar copas de árboles inaccesibles para otros herbívoros.","No masticaban: tragaban piedras (gastrolitos) que trituraban la vegetación en su estómago, como hacen hoy las aves — un método digestivo heredado de sus ancestros dinosaurios."];

DEEP_DIVES['dino5'].es = ["El Triceratops, con sus tres cuernos y su escudo óseo, era uno de los herbívoros más formidables del Cretácico — vivió junto al T. rex y era probablemente su presa principal.","Su escudo craneal no era solo defensivo: pudo servir para la termorregulación (como las orejas de un elefante) y para el reconocimiento entre individuos de la misma especie.","Fósiles muestran marcas de mordeduras de T. rex en escudos de Triceratops — evidencia directa de combates entre los dos iconos del Cretácico."];

DEEP_DIVES['dino6'].es = ["El Stegosaurus tenía un cerebro del tamaño de una nuez (70 gramos) para un cuerpo de 5 toneladas — una de las ratios cerebro/cuerpo más bajas de todos los dinosaurios.","Sus placas dorsales no eran armadura sino probablemente reguladores térmicos: vascularizadas, podían absorber o irradiar calor según la orientación al sol.","Vivió hace 155 millones de años, 80 millones de años antes que el T. rex — el Stegosaurus está más lejos en el tiempo del T. rex que el T. rex de nosotros."];

DEEP_DIVES['dino7'].es = ["El Spinosaurus fue el mayor dinosaurio depredador conocido: hasta 15 metros de largo, superando al T. rex — y era semiacuático, el único dinosaurio carnívoro adaptado a la vida en el agua.","Su vela dorsal de hasta 1,8 metros de alto servía probablemente para la termorregulación, la exhibición sexual o la intimidación de rivales.","Fósiles recientes revelaron una cola aplanada como la de un tritón, confirmando que el Spinosaurus nadaba y cazaba peces y tiburones en los ríos del Cretácico norteafricano."];

DEEP_DIVES['dino8'].es = ["Los pterosaurios no eran dinosaurios sino reptiles voladores emparentados: el Quetzalcoatlus, con 10-12 metros de envergadura, fue el animal volador más grande de la historia.","A pesar de su tamaño, el Quetzalcoatlus pesaba solo unos 250 kg gracias a sus huesos huecos — como los de las aves modernas, sus descendientes evolutivos.","Los pterosaurios dominaron los cielos durante 160 millones de años antes de extinguirse junto con los dinosaurios — las aves, más pequeñas y adaptables, ocuparon su nicho ecológico."];

DEEP_DIVES['dino9'].es = ["Los primeros fósiles de dinosaurio fueron identificados científicamente en 1824 por William Buckland (Megalosaurus) — antes, se creía que eran huesos de gigantes o dragones.","Richard Owen acuñó el término «dinosaurio» (lagarto terrible) en 1842 para agrupar a estos reptiles extintos de tamaño descomunal.","La «manía de los dinosaurios» del siglo XIX generó una feroz rivalidad entre los paleontólogos Othniel Marsh y Edward Cope (la «Guerra de los Huesos»), que descubrieron más de 130 especies nuevas."];

DEEP_DIVES['dino10'].es = ["El Ankylosaurus era un tanque viviente: cubierto de placas óseas y equipado con una maza caudal capaz de romper los huesos de un T. rex.","Pesaba hasta 6 toneladas y medía 8 metros de largo — su armadura lo protegía de los depredadores más grandes de su época.","La maza caudal estaba formada por vértebras fusionadas y huesos dérmicos que podían generar un impacto equivalente al de un coche a 50 km/h."];

DEEP_DIVES['dino11'].es = ["Los dinosaurios con plumas no son una excepción sino la norma: la mayoría de los terópodos (el grupo que incluye al T. rex) tenían algún tipo de plumaje.","El Sinosauropteryx (1996) fue el primer dinosaurio con plumas confirmadas — su descubrimiento en China revolucionó nuestra comprensión de la evolución de las aves.","Las plumas no evolucionaron para volar sino para el aislamiento térmico y la exhibición sexual — el vuelo fue una adaptación secundaria."];

DEEP_DIVES['dino12'].es = ["El asteroide de Chicxulub liberó una energía equivalente a 10 000 millones de bombas de Hiroshima al impactar en la actual península de Yucatán hace 66 millones de años.","El impacto generó tsunamis de 1 500 metros, incendios forestales globales, lluvia ácida y un invierno nuclear que redujo la temperatura media del planeta 15 °C durante años.","Sin esta extinción masiva, los mamíferos habrían seguido siendo pequeños y nocturnos — la desaparición de los dinosaurios abrió el camino a la evolución de los primates y, eventualmente, los humanos."];

DEEP_DIVES['dino13'].es = ["El Diplodocus, con sus 27 metros de largo, usaba su cola como un látigo supersónico: los cálculos indican que la punta podía romper la barrera del sonido, produciendo un estallido audible.","Su cuello de 6 metros no se elevaba verticalmente (como en las ilustraciones clásicas) sino que se mantenía horizontal, barriendo grandes extensiones de vegetación baja.","Un Diplodocus adulto ponía huevos del tamaño de un balón de fútbol — la diferencia de tamaño entre la cría (1 metro) y el adulto (27 metros) es una de las mayores del reino animal."];

DEEP_DIVES['dino14'].es = ["El Archaeopteryx (hace 150 millones de años) es considerado el eslabón entre dinosaurios y aves: tenía plumas y alas como un ave, pero dientes, garras y cola ósea como un reptil.","Solo se han encontrado 12 fósiles de Archaeopteryx, todos en las calizas de Solnhofen (Baviera, Alemania) — una preservación excepcional debida a las condiciones anóxicas de la laguna donde vivían.","El debate sobre si el Archaeopteryx volaba realmente o solo planeaba sigue abierto — sus plumas asimétricas sugieren capacidad de vuelo, pero su estructura ósea era más primitiva que la de las aves modernas."];

DEEP_DIVES['dino15'].es = ["Los mosasaurios no eran dinosaurios sino reptiles marinos gigantes del Cretácico: el Mosasaurus alcanzaba los 17 metros y era el depredador supremo de los mares.","Estaban más emparentados con los lagartos y las serpientes que con los dinosaurios — su cuerpo hidrodinámico y sus mandíbulas articuladas recuerdan a las serpientes actuales.","Los plesiosaurios (cuello largo) y los ictiosaurios (forma de delfín) tampoco eran dinosaurios — la distinción es importante para entender la diversidad de reptiles del Mesozoico."];

DEEP_DIVES['dino16'].es = ["La paleontología moderna usa escáneres CT, análisis isotópicos, biomecánica computacional y ADN antiguo para reconstruir la biología de los dinosaurios con una precisión antes impensable.","Se puede estimar la velocidad de un dinosaurio a partir de sus huellas, su temperatura corporal a partir de la química de sus huesos, e incluso su color a partir de los melanosomas de sus plumas fosilizadas.","El Sinosauropteryx fue el primer dinosaurio cuyo color fue determinado científicamente: tenía un patrón de rayas naranjas y blancas con una máscara oscura alrededor de los ojos."];

DEEP_DIVES['dino17'].es = ["Los huevos de dinosaurio más grandes conocidos son los del Macroelongatoolithus, con hasta 60 cm de largo — pero eran relativamente pequeños en comparación con el tamaño del adulto.","Los saurópodos gigantes ponían huevos del tamaño de un balón porque la cáscara no podía ser más gruesa sin impedir el intercambio gaseoso — una limitación física que frenaba el tamaño del huevo.","Nidos fosilizados de Maiasaura (buena madre lagarto) revelan que algunos dinosaurios cuidaban a sus crías, les llevaban comida y protegían el nido — un comportamiento más parecido al de las aves que al de los reptiles."];

DEEP_DIVES['dino18'].es = ["El Giganotosaurus, descubierto en Argentina en 1993, rivalizaba con el T. rex en tamaño: hasta 13 metros de largo y 8 toneladas.","Vivió 30 millones de años antes que el T. rex y en otro continente (Sudamérica vs Norteamérica) — nunca se encontraron, contrariamente a lo que sugiere Jurassic World.","Los carcarodontosaurios (familia del Giganotosaurus) tenían dientes como cuchillos de carne, diseñados para cortar y desgarrar en lugar de triturar huesos como el T. rex."];

DEEP_DIVES['dino19'].es = ["Los dinosaurios vivieron en los tres periodos del Mesozoico: Triásico (252-201 Ma), Jurásico (201-145 Ma) y Cretácico (145-66 Ma) — cada uno con faunas muy diferentes.","Los primeros dinosaurios del Triásico eran pequeños y bípedos (como el Eoraptor, de 1 metro) — la diversificación masiva llegó tras la extinción del Triásico-Jurásico.","Más especies de dinosaurios vivieron en el Cretácico que en cualquier otro periodo — paradójicamente, fue justo antes de su extinción cuando alcanzaron su máxima diversidad."];

DEEP_DIVES['dino20'].es = ["El Parasaurolophus tenía una cresta hueca de hasta 1 metro de largo que funcionaba como una trompeta natural, produciendo sonidos graves que podían oírse a kilómetros.","Simulaciones por ordenador han recreado el sonido que producía: un tono grave y resonante, como un trombón — probablemente usado para comunicarse con su manada y atraer parejas.","Los hadrosaurios (dinosaurios pico de pato) eran los herbívoros más comunes del Cretácico tardío: vivían en manadas y tenían baterías dentales de más de 1 000 dientes para triturar vegetación dura."];

DEEP_DIVES['dino21'].es = ["Los raptores (dromeosaurios) cazaban con una garra retráctil en forma de hoz en cada pie, usada para apuñalar y desgarrar a sus presas.","El Utahraptor, el mayor raptor conocido (7 metros de largo), tenía garras de hasta 24 cm — era un depredador formidable del Cretácico temprano.","Evidencias fósiles sugieren que algunos raptores cazaban en grupo: un fósil de Deinonychus fue encontrado junto a un Tenontosaurus, sugiriendo un ataque coordinado."];

DEEP_DIVES['dino22'].es = ["Los dinosaurios no eran todos enormes: el Microraptor medía solo 77 cm y pesaba 1 kg — tenía cuatro alas con plumas y planeaba entre los árboles como una ardilla voladora.","El Compsognathus, del tamaño de un pollo, fue uno de los dinosaurios más pequeños — su velocidad y agilidad le permitían cazar insectos y pequeños lagartos.","La diversidad de tamaños era inmensa: desde el Microraptor de 1 kg hasta el Argentinosaurus de 70 toneladas, un rango de masa corporal incomparable en la historia de los vertebrados."];

DEEP_DIVES['dino23'].es = ["El desierto de Gobi (Mongolia) es uno de los yacimientos de dinosaurios más ricos del mundo: allí se descubrieron los primeros nidos, el Velociraptor y el Protoceratops.","El famoso fósil de los «dinosaurios luchando» muestra un Velociraptor y un Protoceratops atrapados en combate mortal, preservados por una tormenta de arena hace 80 millones de años.","Las expediciones de Roy Chapman Andrews al Gobi en los años 1920 inspiraron el personaje de Indiana Jones — Andrews era un aventurero y explorador que desafió desiertos, bandidos y tormentas."];

DEEP_DIVES['dino24'].es = ["Los dinosaurios polares existían: fósiles de dinosaurios se han encontrado en Alaska y en la Antártida, regiones que en el Mesozoico eran boscosas pero experimentaban meses de oscuridad.","Estos dinosaurios probablemente eran de sangre caliente (endotermos) o al menos tenían un metabolismo más alto que los reptiles actuales para sobrevivir a las bajas temperaturas y la oscuridad invernal.","El debate sobre la termorregulación de los dinosaurios ha evolucionado: la mayoría de los paleontólogos creen ahora que eran mesotermos (entre sangre fría y caliente), como los atunes actuales."];

DEEP_DIVES['dino25'].es = ["El ámbar báltico y birmano ha preservado plumas de dinosaurios con un detalle microscópico extraordinario — incluyendo la cola emplumada de un celurosaurio de 99 millones de años.","Desgraciadamente, extraer ADN de dinosaurios del ámbar es imposible: el ADN se degrada completamente en menos de 7 millones de años — Jurassic Park seguirá siendo ficción.","Sin embargo, las proteínas fósiles son más resistentes que el ADN: colágeno de T. rex de 68 millones de años ha sido identificado, revelando parentesco molecular con las aves actuales."];

DEEP_DIVES['dino26'].es = ["El Pachycephalosaurus tenía un cráneo con una cúpula ósea de 25 cm de espesor — durante décadas se creyó que la usaba para golpearse cabeza contra cabeza como las cabras monteses.","Estudios recientes sugieren que la cúpula era demasiado frágil para impactos frontales: probablemente la usaba para golpear los flancos de rivales o como exhibición visual.","Muchos dinosaurios con crestas, cuernos y ornamentos craneales los usaban principalmente para el reconocimiento entre especies y la selección sexual, no para el combate."];

DEEP_DIVES['dino27'].es = ["Los terópodos evolucionaron desde los dinosaurios carnívoros bípedos del Triásico hasta las aves modernas — una transición documentada por cientos de fósiles intermedios.","La transición incluye la miniaturización progresiva, el desarrollo de plumas, la fusión de huesos, la reducción de la cola y la aparición del esternón quillado para el vuelo.","Las aves son dinosaurios: taxonómicamente, un gorrión está más emparentado con un T. rex que un T. rex con un Triceratops — una realidad que desafía la intuición pero es sólida científicamente."];

DEEP_DIVES['dino28'].es = ["Los coprolitos (heces fosilizadas) de dinosaurios revelan su dieta: restos de plantas, huesos triturados, escamas de pez e incluso parásitos intestinales.","Un coprolito de T. rex encontrado en Saskatchewan contenía fragmentos de hueso de un ceratópsido joven — evidencia directa de que trituraba huesos, algo que su dentición ya sugería.","Los coprolitos también revelan los ecosistemas: el tipo de plantas digeridas indica el clima, la altitud y la estación del año en que vivió el dinosaurio."];

DEEP_DIVES['dino29'].es = ["La paleontología de dinosaurios se ha diversificado enormemente: China ha aportado más especies nuevas que cualquier otro país en las últimas dos décadas.","La formación de Yixian (provincia de Liaoning) ha producido cientos de fósiles extraordinarios de dinosaurios emplumados, aves primitivas y mamíferos del Cretácico temprano.","La democratización de la paleontología ha permitido que países como Argentina, Marruecos, Mongolia y Brasil hagan descubrimientos que transforman nuestra comprensión de la evolución de los dinosaurios."];

DEEP_DIVES['dino30'].es = ["Los dinosaurios no se extinguieron: hay más de 10 000 especies de aves vivas, todas descendientes directas de los terópodos — técnicamente, los dinosaurios siguen entre nosotros.","Un pollo comparte más ADN con un T. rex que un T. rex con un Triceratops — la clasificación moderna coloca a las aves dentro del clado Dinosauria.","La próxima vez que veas un gorrión, un cuervo o un colibrí, recuerda que estás observando a un dinosaurio vivo: 66 millones de años de evolución, pero dinosaurio al fin y al cabo."];

// ── RELIGION rel1-rel30 ──

DEEP_DIVES['rel1'].es = ["El cristianismo es la religión más extendida del mundo con unos 2 400 millones de fieles, repartidos entre catolicismo, protestantismo y ortodoxia.","Nació como una secta judía en la Palestina romana del siglo I y se convirtió en religión oficial del Imperio Romano en el 380 d.C. bajo el emperador Teodosio.","La Biblia cristiana es el libro más traducido de la historia (más de 700 idiomas completos) y el más vendido con más de 5 000 millones de ejemplares distribuidos."];

DEEP_DIVES['rel2'].es = ["El islam, con unos 1 900 millones de fieles, es la segunda religión del mundo y la de más rápido crecimiento — se prevé que iguale al cristianismo hacia 2060.","Fundado por el profeta Mahoma en el siglo VII en Arabia, el islam se basa en cinco pilares: la profesión de fe, la oración (5 veces al día), la limosna, el ayuno del Ramadán y la peregrinación a La Meca.","El Corán, texto sagrado del islam, fue revelado en árabe y los musulmanes consideran que solo puede ser plenamente comprendido en esa lengua — las traducciones se consideran interpretaciones."];

DEEP_DIVES['rel3'].es = ["El hinduismo, con más de 1 200 millones de seguidores, es la religión organizada más antigua del mundo, con textos (los Vedas) que datan de al menos 1500 a.C.","No tiene un fundador único ni un dogma central: es un conjunto de tradiciones filosóficas, rituales y espirituales que comparten conceptos como karma, dharma, samsara y moksha.","El hinduismo reconoce miles de deidades que son manifestaciones de una realidad última (Brahman) — las tres principales son Brahma (creador), Vishnu (preservador) y Shiva (destructor/transformador)."];

DEEP_DIVES['rel4'].es = ["El budismo fue fundado por Siddhartha Gautama (el Buda) en la India del siglo V a.C. tras alcanzar la iluminación bajo un árbol bodhi a los 35 años.","Las Cuatro Nobles Verdades son su base: la vida es sufrimiento (dukkha), el sufrimiento nace del deseo, el cese del deseo libera del sufrimiento, y el camino es el Noble Óctuple Sendero.","El budismo no requiere fe en un dios creador: es más una filosofía práctica que una religión teísta — su objetivo es liberar al individuo del ciclo de renacimientos (samsara)."];

DEEP_DIVES['rel5'].es = ["El judaísmo, con unos 15 millones de practicantes, es la más antigua de las tres grandes religiones abrahámicas (judaísmo, cristianismo, islam).","La Torá (cinco libros de Moisés) es el texto sagrado central, complementado por el Talmud — una vasta colección de comentarios, debates y leyes rabínicas.","El judaísmo ha influido desproporcionadamente en la civilización occidental: el monoteísmo, los Diez Mandamientos, el concepto de justicia social y el día de descanso semanal son legados judíos."];

DEEP_DIVES['rel6'].es = ["El sintoísmo es la religión indígena de Japón, basada en la veneración de los kami (espíritus de la naturaleza, ancestros y fenómenos naturales).","No tiene fundador, escrituras sagradas centrales ni dogma moral fijo — es una práctica ritual centrada en la pureza, la armonía con la naturaleza y el respeto a los ancestros.","La mayoría de los japoneses practican simultáneamente el sintoísmo y el budismo: nacen sintoístas y mueren budistas, una coexistencia religiosa rara en el mundo."];

DEEP_DIVES['rel7'].es = ["El sijismo, fundado por Guru Nanak en el Punjab (India) en el siglo XV, cuenta con unos 30 millones de seguidores y es la quinta religión más grande del mundo.","Los sijs creen en un único Dios sin forma, en la igualdad de todos los seres humanos y en el servicio comunitario — sus templos (gurdwaras) ofrecen comida gratis a cualquier persona.","Los cinco artículos de fe (las cinco K) incluyen el kesh (cabello sin cortar, cubierto por un turbante), el kara (brazalete de acero) y el kirpan (daga ceremonial)."];

DEEP_DIVES['rel8'].es = ["El Ramadán es el mes sagrado del islam durante el cual los musulmanes ayunan desde el amanecer hasta el atardecer — unos 1 900 millones de personas participan cada año.","El ayuno (sawm) no es solo privación de comida y bebida: incluye abstinencia de tabaco, relaciones sexuales y comportamientos negativos como la mentira y la ira.","El iftar (comida para romper el ayuno al anochecer) es un momento comunitario y festivo — las familias y vecinos se reúnen, y los más ricos ofrecen comida a los necesitados."];

DEEP_DIVES['rel9'].es = ["La Reforma Protestante comenzó en 1517 cuando Martín Lutero clavó sus 95 tesis en la puerta de la iglesia de Wittenberg, cuestionando la venta de indulgencias por la Iglesia Católica.","Lutero argumentaba que la salvación se obtiene solo por la fe (sola fide) y la Escritura (sola scriptura), no por las obras ni la mediación de la Iglesia.","La Reforma fragmentó el cristianismo occidental en miles de denominaciones (luteranos, calvinistas, anglicanos, bautistas, metodistas) y provocó guerras religiosas que devastaron Europa durante un siglo."];

DEEP_DIVES['rel10'].es = ["La meditación es una práctica común a muchas tradiciones espirituales: el budismo (vipassana, zen), el hinduismo (yoga, mantra), el islam (dhikr), el cristianismo (contemplación) y el judaísmo (hitbodedut).","Estudios neurocientíficos confirman que la meditación regular modifica la estructura del cerebro: aumenta la materia gris en áreas de atención y empatía, y reduce la actividad de la amígdala (estrés).","El mindfulness occidental, derivado de la meditación budista, se ha extendido a hospitales, escuelas y empresas — un fenómeno de secularización de prácticas religiosas milenarias."];

DEEP_DIVES['rel11'].es = ["Los Diez Mandamientos, compartidos por el judaísmo y el cristianismo, establecen reglas éticas fundamentales: no matar, no robar, no mentir, honrar a los padres.","Según la Biblia, fueron entregados por Dios a Moisés en el monte Sinaí, grabados en tablas de piedra — un momento fundacional de la ley moral occidental.","Los Mandamientos influyeron en los códigos legales occidentales durante milenios — la separación entre ley religiosa y civil es un logro relativamente reciente de la Ilustración."];

DEEP_DIVES['rel12'].es = ["La Meca, en Arabia Saudita, es la ciudad más sagrada del islam: hacia ella rezan los musulmanes cinco veces al día y a ella peregrinan al menos una vez en la vida (hajj).","La Kaaba, el cubo negro en el centro de la Gran Mezquita, es la estructura más sagrada del islam — según la tradición, fue construida por Abraham e Ismael.","El hajj anual reúne a más de 2 millones de peregrinos de todo el mundo: es la mayor reunión anual de seres humanos y un símbolo de la igualdad ante Dios."];

DEEP_DIVES['rel13'].es = ["El concepto de karma existe en el hinduismo, el budismo, el jainismo y el sijismo: cada acción tiene consecuencias que afectan a la presente y a las futuras vidas.","El karma no es un sistema de castigo divino sino una ley natural de causa y efecto: las acciones positivas generan frutos positivos, y viceversa.","En Occidente, el karma se ha simplificado como «lo que va, vuelve», perdiendo su complejidad filosófica original — en el budismo, por ejemplo, la intención detrás de la acción es más importante que la acción misma."];

DEEP_DIVES['rel14'].es = ["El Vaticano, sede de la Iglesia Católica, es el estado independiente más pequeño del mundo: 0,44 km² con unos 800 habitantes.","El papa es a la vez jefe de Estado del Vaticano y líder espiritual de los 1 400 millones de católicos del mundo — una doble función única en la política mundial.","La Capilla Sixtina, con los frescos de Miguel Ángel, es tanto una obra maestra del arte como un lugar sagrado: en ella se celebran los cónclaves para elegir al nuevo papa."];

DEEP_DIVES['rel15'].es = ["El taoísmo, fundado en China por Laozi (siglo VI a.C.), enseña a vivir en armonía con el Tao (el camino), la fuerza primordial que subyace a toda la realidad.","El yin y el yang representan la interdependencia de los opuestos: luz y oscuridad, masculino y femenino, acción y reposo — no son fuerzas contrarias sino complementarias.","El Tao Te King de Laozi es uno de los textos más traducidos del mundo: su filosofía de no-acción (wu wei) influyó en la medicina, las artes marciales, la estética y la política chinas."];

DEEP_DIVES['rel16'].es = ["Las Cruzadas (1096-1291) fueron expediciones militares cristianas para recuperar Tierra Santa del control musulmán — provocaron siglos de conflicto entre Oriente y Occidente.","Más allá de lo religioso, las Cruzadas tuvieron motivaciones políticas y económicas: control de rutas comerciales, tierras y poder — el fervor religioso era a menudo un pretexto.","Los cruzados trajeron de vuelta a Europa conocimientos árabes en matemáticas, medicina, astronomía y filosofía — una transferencia cultural involuntaria que aceleró el Renacimiento."];

DEEP_DIVES['rel17'].es = ["El jainismo, una de las religiones más antiguas de la India, lleva el principio de no violencia (ahimsa) a su extremo: los monjes jainistas barren el suelo para no pisar insectos y usan mascarillas para no inhalar microorganismos.","El jainismo tiene unos 4,5 millones de seguidores, principalmente en India, pero su influencia filosófica es enorme: Gandhi fue profundamente influido por la ahimsa jainista.","Los templos jainistas son de una belleza extraordinaria: el complejo de Ranakpur (Rajastán) tiene 1 444 columnas de mármol, cada una tallada de forma única — una obra maestra de la arquitectura india."];

DEEP_DIVES['rel18'].es = ["Las religiones africanas tradicionales, practicadas por más de 100 millones de personas, veneran a ancestros, espíritus de la naturaleza y un Dios creador supremo.","El vudú (vodou), lejos del estereotipo hollywoodense, es una religión compleja originaria de África occidental que llegó a Haití y Luisiana con los esclavos.","Las religiones afroamericanas (candomblé en Brasil, santería en Cuba, vudú en Haití) fusionaron las tradiciones africanas con el catolicismo colonial, creando sincretismos únicos."];

DEEP_DIVES['rel19'].es = ["El confucianismo no es estrictamente una religión sino una filosofía ética y social basada en las enseñanzas de Confucio (551-479 a.C.) sobre la armonía social, el respeto filial y la virtud.","Los cinco vínculos confucianos (gobernante-súbdito, padre-hijo, marido-mujer, hermano mayor-menor, amigo-amigo) definieron la estructura social china durante más de 2 000 años.","El confucianismo sigue influyendo profundamente en las sociedades de Asia oriental: la importancia de la educación, el respeto a los mayores y la armonía social son valores confucianos."];

DEEP_DIVES['rel20'].es = ["Los manuscritos del Mar Muerto, descubiertos entre 1947 y 1956 en las cuevas de Qumrán (Israel), contienen los textos bíblicos más antiguos conocidos — algunos datan del siglo III a.C.","Los más de 900 manuscritos incluyen fragmentos de casi todos los libros del Antiguo Testamento y textos desconocidos de la secta de los esenios.","Su descubrimiento transformó la comprensión del judaísmo del Segundo Templo y los orígenes del cristianismo — revelaron la diversidad religiosa de la Palestina anterior a Jesús."];

DEEP_DIVES['rel21'].es = ["La Inquisición fue un sistema judicial eclesiástico creado en el siglo XII para combatir la herejía — su forma más conocida, la Inquisición española (1478-1834), persiguió a conversos, protestantes y supuestas brujas.","Contrariamente al estereotipo, la Inquisición española condenó a muerte a unas 3 000-5 000 personas en 356 años — una cifra terrible pero inferior a la de los tribunales civiles contemporáneos.","La «Leyenda Negra» protestante exageró los excesos de la Inquisición con fines propagandísticos — la realidad histórica es más matizada pero sigue siendo un capítulo oscuro de la historia religiosa."];

DEEP_DIVES['rel22'].es = ["El zoroastrismo, fundado por Zaratustra en la antigua Persia (siglo VI a.C. o antes), fue la primera gran religión monoteísta del mundo.","Sus conceptos de cielo, infierno, juicio final, resurrección de los muertos y lucha cósmica entre el bien y el mal influyeron profundamente en el judaísmo, el cristianismo y el islam.","Hoy cuenta con solo 120 000-200 000 practicantes (parsis en India, zoroastrianos en Irán) — una de las religiones más antiguas del mundo al borde de la extinción."];

DEEP_DIVES['rel23'].es = ["Los monasterios budistas tibetanos son centros de estudio, meditación y preservación cultural donde los monjes pueden pasar décadas memorizando textos y practicando la meditación.","Los mandalas de arena tibetanos se crean durante semanas con granos de arena coloreada y luego se destruyen deliberadamente — una meditación sobre la impermanencia de todas las cosas.","El Dalái Lama, líder espiritual del budismo tibetano, vive en exilio en India desde 1959 tras la invasión china del Tíbet — su figura combina liderazgo religioso, político y moral."];

DEEP_DIVES['rel24'].es = ["La Navidad (25 de diciembre) no corresponde a la fecha real del nacimiento de Jesús — fue elegida en el siglo IV para coincidir con las fiestas romanas del Sol Invicto y las Saturnales.","Muchas tradiciones navideñas son de origen pagano: el árbol (germánico), el acebo (celta), los regalos (Saturnales romanas) y Papá Noel (mezcla de San Nicolás y tradiciones nórdicas).","La comercialización de la Navidad comenzó en el siglo XIX: el Santa Claus rojo fue popularizado por Coca-Cola en los años 1930, aunque su imagen ya existía antes."];

DEEP_DIVES['rel25'].es = ["El bahá'ísmo, fundado en Irán en 1863 por Bahá'u'lláh, enseña la unidad de Dios, la unidad de las religiones y la unidad de la humanidad.","Con unos 8 millones de seguidores en más de 200 países, es una de las religiones más geográficamente extendidas del mundo.","Los bahá'ís son perseguidos en Irán desde la revolución de 1979: más de 200 han sido ejecutados y miles encarcelados — la mayor minoría religiosa perseguida del país."];

DEEP_DIVES['rel26'].es = ["Los textos sagrados más antiguos del mundo son los Vedas hindúes, transmitidos oralmente durante milenios antes de ser escritos — los Rigveda datan de al menos 1500 a.C.","La Epopeya de Gilgamesh sumeria (2100 a.C.) contiene una versión del diluvio universal anterior a la bíblica — lo que sugiere que el relato de Noé tiene raíces mesopotámicas.","El Avesta zoroastriano, la Torá judía, el Tipitaka budista y el Corán islámico son otros textos sagrados que han moldeado civilizaciones enteras durante milenios."];

DEEP_DIVES['rel27'].es = ["La cábala es la tradición mística del judaísmo que busca comprender la naturaleza de Dios y el universo a través de interpretaciones esotéricas de la Torá.","El Árbol de la Vida cabalístico (10 sefirot conectadas por 22 senderos) representa la estructura de la realidad divina y ha influido en la filosofía, el ocultismo y el arte occidentales.","Madonna, el agua de cábala y las pulseras rojas han popularizado una versión simplificada de esta tradición milenaria — los rabinos ortodoxos generalmente desaprueban esta comercialización."];

DEEP_DIVES['rel28'].es = ["Las peregrinaciones son comunes a casi todas las religiones: La Meca (islam), Jerusalén (judaísmo, cristianismo, islam), Varanasi (hinduismo), Bodh Gaya (budismo), Santiago de Compostela (catolicismo).","El Camino de Santiago ha experimentado un renacimiento espectacular: de 2 000 peregrinos en 1985 a más de 400 000 en 2023 — muchos lo recorren por razones espirituales, deportivas o de búsqueda personal.","Las peregrinaciones combinan lo sagrado con lo práctico: históricamente fueron motores económicos, rutas de intercambio cultural y catalizadores del desarrollo de infraestructuras."];

DEEP_DIVES['rel29'].es = ["El ateísmo y el agnosticismo están en crecimiento en muchas sociedades occidentales: en Europa, más del 25 % de la población se declara sin religión.","El «nuevo ateísmo» de Richard Dawkins, Sam Harris y Christopher Hitchens generó un debate público intenso sobre el papel de la religión en la sociedad moderna.","Sin embargo, la secularización no es universal: la religión crece en África, Asia y América Latina — la geografía de la fe está cambiando, no desapareciendo."];

DEEP_DIVES['rel30'].es = ["El diálogo interreligioso ha avanzado significativamente en el siglo XXI: encuentros entre el papa Francisco, líderes musulmanes, judíos y budistas buscan la convivencia pacífica.","El Documento de Abu Dabi (2019), firmado por el papa Francisco y el gran imán Ahmed al-Tayeb, declaró que la diversidad religiosa es «querida por Dios» — un hito en las relaciones islamo-cristianas.","El desafío del siglo XXI no es eliminar las diferencias religiosas sino aprender a convivir con ellas: la tolerancia, el respeto mutuo y el conocimiento del otro son las claves de la paz interreligiosa."];
 
// ── FALLBACK : les deep dives sans traduction espagnole affichent l'anglais ──
Object.keys(DEEP_DIVES).forEach(function(k){
  if(!DEEP_DIVES[k].es) DEEP_DIVES[k].es = DEEP_DIVES[k].en;
});
